// 자동 생성 - vi 번역만. id(원본번호)로 topik_core.js와 연결
const TOPIK_LANG_VI = {"1":{"word":"cửa hàng","meaning":"Nơi trưng bày và bán các sản phẩm với quy mô nhỏ."},"2":{"word":"giá","meaning":"Số tiền phải trả để mua một món đồ nào đó."},"3":{"word":"đồ nội thất","meaning":"Các vật dụng lớn như giường, bàn, tủ được đặt trong nhà để sinh hoạt hoặc làm việc."},"4":{"word":"gần","meaning":"Khoảng cách giữa hai vật không xa, ở một cự ly ngắn."},"5":{"word":"đi","meaning":"Di chuyển từ nơi này đến một nơi khác."},"6":{"word":"dạy","meaning":"Truyền đạt kiến thức hoặc kỹ năng cho người khác để họ học hỏi."},"7":{"word":"túi xách","meaning":"Một vật chứa mềm dẻo thường có quai, dùng để đựng đồ."},"8":{"word":"nhẹ","meaning":"Có rất ít trọng lượng, dễ dàng nâng hoặc di chuyển."},"9":{"word":"ca sĩ","meaning":"Người biểu diễn âm nhạc bằng giọng hát của mình, thường trước khán giả."},"10":{"word":"bài hát","meaning":"Bài hát được nhiều người Hàn Quốc yêu thích."},"11":{"word":"giữa","meaning":"Điểm ở vị trí cách đều hoặc gần như cách đều tất cả các phía hoặc các điểm cuối trong một không gian hay vật thể."},"12":{"word":"mùa thu","meaning":"Một trong bốn mùa trong năm, diễn ra sau mùa hè và trước mùa đông, khi lá cây thường đổi màu."},"13":{"word":"nhất","meaning":"Từ dùng để chỉ mức độ cao nhất hoặc ưu việt nhất so với tất cả các đối tượng khác trong một nhóm."},"14":{"word":"gia đình","meaning":"Một nhóm người có quan hệ họ hàng, thường bao gồm cha, mẹ và con cái, sống chung dưới một mái nhà."},"15":{"word":"loại","meaning":"Từ dùng để chỉ một kiểu hoặc một loại cụ thể trong một nhóm lớn các vật hoặc sự vật tương tự."},"16":{"word":"có","meaning":"Giữ một vật trong tay hoặc làm chủ một thứ gì đó như tài sản của mình."},"17":{"word":"sườn","meaning":"Phần xương sườn ngắn của động vật như bò, heo, gà và phần thịt dính vào xương, được dùng làm nguyên liệu hoặc món ăn."},"18":{"word":"canh sườn bò","meaning":"Món canh nóng truyền thống của Hàn Quốc làm từ sườn bò hầm với nước dùng trong, thường ăn kèm với cơm."},"19":{"word":"chuyển xe","meaning":"Xuống một phương tiện giao thông công cộng và lên một phương tiện khác ngay lập tức để tiếp tục hành trình."},"20":{"word":"quả hồng","meaning":"Một loại trái cây tròn, màu đỏ cam, vỏ mịn, mọc trên cây và thường được ăn vào mùa thu."},"21":{"word":"cảm lạnh","meaning":"Một bệnh phổ biến gây ho, hắt hơi, sổ mũi và đôi khi đau họng."},"22":{"word":"sự cảm ơn","meaning":"Lời bày tỏ lòng biết ơn khi ai đó làm điều tốt cho bạn hoặc tặng bạn thứ gì đó."},"23":{"word":"giá cả","meaning":"Số tiền cần trả để mua một món đồ trong cửa hàng."},"24":{"word":"giống nhau","meaning":"Không có sự khác biệt giữa hai hoặc nhiều vật, người."},"25":{"word":"cùng nhau","meaning":"Hai hoặc nhiều người/vật thực hiện điều gì đó cùng lúc hoặc cùng địa điểm."},"26":{"word":"chó","meaning":"Một loài động vật bốn chân phổ biến, thường sủa và được con người nuôi làm thú cưng hoặc để bảo vệ."},"27":{"word":"cái","meaning":"Từ dùng để chỉ số lượng cá thể của các vật phẩm như trái cây, đồ vật nhỏ hoặc hộp đựng."},"28":{"word":"đó","meaning":"Một địa điểm hoặc vị trí cụ thể không phải nơi người nói hoặc người nghe đang đứng."},"29":{"word":"phòng khách","meaning":"Khu vực sinh hoạt chung chính trong nhà, thường có ghế sofa và TV, nơi các thành viên gia đình tụ tập."},"30":{"word":"sức khỏe","meaning":"Tình trạng thể chất và tinh thần của một người khi họ cảm thấy khỏe mạnh, năng động và không bệnh tật hay đau đớn."},"31":{"word":"bên kia, phía đối diện","meaning":"Nơi đối diện trực tiếp với một cái gì đó, thường có một con đường hoặc không gian ở giữa."},"32":{"word":"tòa nhà, công trình","meaning":"Một công trình có tường và mái để con người sinh sống hoặc chứa đồ vật."},"33":{"word":"đi bộ","meaning":"Di chuyển về phía trước bằng cách đặt một chân trước chân kia với tốc độ đều đặn, luôn giữ ít nhất một chân trên mặt đất."},"34":{"word":"treo, mắc","meaning":"Gắn một vật gì đó lên cao để nó lơ lửng."},"35":{"word":"được treo, bị mắc","meaning":"Được gắn lên cao để lơ lửng hoặc bị vướng vào và giữ chặt bởi một cái gì đó."},"36":{"word":"cái, điều","meaning":"Một danh từ phụ thuộc dùng để chỉ một vật hoặc sự việc không được xác định rõ ràng."},"37":{"word":"trò chơi","meaning":"Một hoạt động giải trí có cấu trúc, có luật chơi, mà mọi người tham gia để giải trí hoặc cạnh tranh."},"38":{"word":"mùa đông","meaning":"Khoảng thời gian lạnh nhất trong năm, khi nhiệt độ xuống thấp, ngày ngắn và thường có tuyết rơi."},"39":{"word":"tiếp tục, liên tục","meaning":"Thực hiện một hành động hoặc để một sự việc xảy ra mà không có bất kỳ khoảng dừng hoặc gián đoạn nào."},"40":{"word":"ở, có mặt (kính ngữ)","meaning":"(Kính ngữ) Dùng để chỉ việc người lớn tuổi hoặc cấp trên đang ở một nơi nào đó."},"41":{"word":"mùa","meaning":"Một trong bốn khoảng thời gian chính của năm, như xuân, hạ, thu, đông, có đặc điểm tự nhiên riêng."},"42":{"word":"kế hoạch","meaning":"Ý tưởng chi tiết hoặc các bước đã sắp xếp để làm hoặc hoàn thành điều gì đó trong tương lai."},"43":{"word":"thịt","meaning":"Phần cơ và các bộ phận khác có thể ăn được từ cơ thể động vật, dùng làm thực phẩm."},"44":{"word":"chọn","meaning":"Lựa chọn một hoặc nhiều thứ/hành động từ nhiều lựa chọn có sẵn, thường sau khi suy nghĩ cẩn thận."},"45":{"word":"biết ơn","meaning":"Có cảm giác trân trọng, đánh giá cao hành động hoặc món quà mà ai đó đã trao tặng."},"46":{"word":"mèo","meaning":"Một loài động vật nhỏ, lông mềm, có ria và đuôi, thường được nuôi làm thú cưng."},"47":{"word":"đói","meaning":"Có cảm giác trống rỗng trong dạ dày và mong muốn mạnh mẽ được ăn thức ăn."},"48":{"word":"quê hương","meaning":"Nơi một người được sinh ra và lớn lên, thường gắn liền với nhiều kỷ niệm."},"49":{"word":"nơi","meaning":"Một khu vực vật lý hoặc một điểm cụ thể trong không gian mà có thể nhìn thấy hoặc chỉ ra."},"50":{"word":"học","meaning":"Hoạt động học hỏi hoặc tiếp thu kiến thức thông qua việc đọc, tham gia lớp học hoặc thực hành một kỹ năng."},"51":{"word":"công viên","meaning":"Nơi có nhiều cây xanh, hoa và cỏ, thường dùng để mọi người nghỉ ngơi hoặc tập thể dục."},"52":{"word":"cuốn vở","meaning":"Quyển sách có các trang giấy trắng hoặc kẻ dòng dùng để viết hoặc vẽ."},"53":{"word":"sân bay","meaning":"Khu vực rộng lớn có đường băng và các tòa nhà để máy bay cất cánh, hạ cánh và hành khách lên xuống."},"54":{"word":"trái cây","meaning":"Phần ngọt, thường có màu sắc của cây hoặc thực vật, chứa hạt và có thể ăn được."},"55":{"word":"ổn, không sao","meaning":"Diễn tả tình trạng không có vấn đề, hư hại hay nguy hiểm, cho thấy sự tốt đẹp hoặc chấp nhận được."},"56":{"word":"phòng học","meaning":"Căn phòng trong trường học hoặc đại học nơi học sinh tập trung để học từ giáo viên."},"57":{"word":"giao thông","meaning":"Sự di chuyển của nhiều xe ô tô, xe tải hoặc xe buýt trên đường, thường là chậm hoặc dừng lại."},"58":{"word":"chín","meaning":"Số tự nhiên đứng sau số tám và đứng trước số mười."},"59":{"word":"tham quan, ngắm cảnh","meaning":"Hành động đi xem các công trình nổi tiếng, phong cảnh đẹp hoặc sự kiện thú vị ở một địa điểm cụ thể."},"60":{"word":"giày","meaning":"Vật dụng mang ở chân, thường đi theo đôi, che phủ bàn chân và đôi khi cả mắt cá chân, thường làm bằng da hoặc vải."},"61":{"word":"chín mươi","meaning":"Số đại diện cho giá trị của chín mươi đơn vị."},"62":{"word":"tháng chín","meaning":"Tháng thứ chín trong năm, sau tháng tám và trước tháng mười."},"63":{"word":"quốc tịch","meaning":"Mối liên hệ chính thức giữa một người với một quốc gia cụ thể."},"64":{"word":"cuốn, quyển","meaning":"Từ dùng để đếm số lượng sách hoặc ấn phẩm có nhiều trang được đóng lại."},"65":{"word":"tai","meaning":"Bộ phận trên đầu dùng để nghe và giữ thăng bằng."},"66":{"word":"quýt","meaning":"Một loại trái cây họ cam quýt nhỏ, ngọt, vỏ mỏng và dễ bóc."},"67":{"word":"đó, ấy","meaning":"Từ dùng để chỉ người hoặc vật ở xa người nói hoặc gần người nghe, hoặc đã được nhắc đến."},"68":{"word":"cái đó","meaning":"Từ dùng để chỉ một vật, con vật hoặc một ý tưởng đã được nhắc đến trước đó."},"69":{"word":"ừ","meaning":"Lời nói thể hiện sự đồng ý hoặc xác nhận."},"70":{"word":"vì vậy, do đó","meaning":"Từ dùng để giới thiệu kết quả hoặc hậu quả trực tiếp của điều đã nói trước đó."},"71":{"word":"vì vậy","meaning":"Từ dùng để giới thiệu lời giải thích hoặc ý chính của điều vừa được nói đến."},"72":{"word":"thế thì","meaning":"Từ dùng để chỉ bước tiếp theo hoặc kết quả sẽ xảy ra sau khi một điều kiện hoặc sự kiện cụ thể diễn ra."},"73":{"word":"tuy nhiên","meaning":"Từ dùng để giới thiệu một ý tưởng mới, thông tin bổ sung, hoặc chuyển đề tài đã thảo luận."},"74":{"word":"thế thì","meaning":"Từ dùng để nối một sự kiện hoặc phát biểu với sự kiện hoặc phát biểu tiếp theo một cách hợp lý về thời gian hoặc kết quả."},"75":{"word":"tất nhiên","meaning":"Từ cảm thán thể hiện sự đồng ý mạnh mẽ, sự ngạc nhiên, hoặc hỏi một câu khi câu trả lời đã rõ ràng."},"76":{"word":"là như thế","meaning":"Tính từ dùng để mô tả cái gì đó hoặc ai đó đúng theo một cách nhất định, hoặc để xác nhận một sự thật là đúng."},"77":{"word":"nhưng mà","meaning":"Từ dùng để giới thiệu một ý tưởng đối lập hoặc một sự thật tương phản sau một phát biểu trước đó, chỉ ra sự khác biệt hoặc một sự thay đổi."},"78":{"word":"cái bát","meaning":"Vật dụng có dạng tròn, miệng mở, thường làm bằng gốm sứ hoặc thủy tinh, dùng để đựng thức ăn hoặc chất lỏng."},"79":{"word":"và","meaning":"Từ dùng để nối hai hoặc nhiều sự vật, hành động, hoặc ý tưởng lại với nhau, cho thấy chúng có liên quan hoặc nối tiếp nhau."},"80":{"word":"vẽ","meaning":"Tạo ra một hình ảnh hoặc bức tranh trên bề mặt như giấy hoặc vải bằng các dụng cụ như bút chì, bút mực hoặc cọ."},"81":{"word":"bức tranh","meaning":"Hình ảnh được tạo ra trên một bề mặt phẳng bằng bút chì màu, sơn, hoặc các vật liệu mỹ thuật khác, hoặc một bức ảnh chụp bằng máy ảnh."},"82":{"word":"hôm kia","meaning":"Ngày cụ thể đã diễn ra hai ngày đầy đủ trước thời điểm hiện tại."},"83":{"word":"bên đó","meaning":"Một từ dùng để chỉ phương hướng không gần người nói hoặc người/đơn vị đang đối thoại một cách lịch sự."},"84":{"word":"rạp chiếu phim","meaning":"Địa điểm công cộng dùng để trình chiếu phim hoặc tổ chức các buổi biểu diễn nghệ thuật."},"85":{"word":"khu vực lân cận","meaning":"Vùng xung quanh một địa điểm nào đó."},"86":{"word":"bài viết","meaning":"Các ký hiệu hoặc chữ được viết ra để truyền đạt thông tin."},"87":{"word":"À, cái này thì...","meaning":"Từ dùng để biểu thị sự ngập ngừng, không chắc chắn khi trả lời."},"88":{"word":"thứ Sáu","meaning":"Ngày thứ Sáu trong tuần, trước ngày cuối tuần."},"89":{"word":"thời hạn","meaning":"Khoảng thời gian nhất định từ lúc bắt đầu đến lúc kết thúc."},"90":{"word":"chờ đợi","meaning":"Dừng lại, không di chuyển để chờ một việc gì đó xảy ra hoặc một ai đó đến."},"91":{"word":"tâm trạng","meaning":"Trạng thái tinh thần hoặc cảm xúc của một người."},"92":{"word":"vui vẻ","meaning":"Có cảm giác vui mừng, phấn khởi."},"93":{"word":"ký túc xá","meaning":"Nơi ở chung dành cho sinh viên hoặc công nhân, thường có nhiều phòng và các tiện nghi dùng chung."},"94":{"word":"tàu hỏa","meaning":"Phương tiện giao thông gồm nhiều toa nối nhau, chạy trên đường ray để chở khách hoặc hàng hóa."},"95":{"word":"đường","meaning":"Bề mặt cứng, phẳng hoặc vệt đánh dấu nối hai nơi, dùng để đi bộ hoặc lái xe."},"96":{"word":"dài","meaning":"Có kích thước lớn từ đầu này đến đầu kia, khiến một vật trải rộng ra xa."},"97":{"word":"kimbap","meaning":"Món ăn Hàn Quốc làm bằng cách cuộn cơm nấu chín, rau và thịt trong lá rong biển khô, sau đó cắt thành từng khoanh tròn."},"98":{"word":"kimchi","meaning":"Món ăn truyền thống của Hàn Quốc làm từ rau củ lên men như cải thảo và củ cải, nêm gia vị ớt bột, tỏi và gừng, thường có màu đỏ và cay."},"99":{"word":"canh kim chi","meaning":"Món súp nóng của Hàn Quốc được nấu bằng cách đun sôi cải thảo lên men, đậu phụ và đôi khi là thịt trong nước dùng cay, hơi đỏ."},"100":{"word":"sạch sẽ","meaning":"Không có bụi bẩn hay vết nhơ."},"101":{"word":"nhất định","meaning":"Diễn tả điều gì đó hoàn toàn cần thiết và không thể thiếu."},"102":{"word":"hoa","meaning":"Bộ phận ở đầu thân cây có hình dáng, màu sắc và mùi hương độc đáo hoặc loại cây tạo ra bộ phận đó."},"103":{"word":"tắt","meaning":"Làm cho đèn, lửa hoặc máy móc ngừng phát ra ánh sáng, nhiệt hoặc chuyển động."},"104":{"word":"kết thúc","meaning":"Để một việc gì đó hoàn thành cho đến lúc cuối cùng."},"105":{"word":"tôi","meaning":"Từ dùng để một người tự xưng khi nói hoặc hành động."},"106":{"word":"ra ngoài","meaning":"Di chuyển từ bên trong ra bên ngoài một khu vực hoặc không gian."},"107":{"word":"mọc","meaning":"Cái gì đó bắt đầu xuất hiện hoặc phát triển, như râu trên mặt."},"108":{"word":"đất nước","meaning":"Một vùng đất rộng lớn có chính phủ riêng và nhiều người sống chung."},"109":{"word":"cây","meaning":"Một loại thực vật có thân cứng, cành và lá."},"110":{"word":"xấu","meaning":"Không tốt, không đạt yêu cầu."},"111":{"word":"đi ra","meaning":"Di chuyển từ bên trong ra bên ngoài hoặc trở nên nhìn thấy được."},"112":{"word":"sau này","meaning":"Một thời điểm trong tương lai, diễn ra sau một sự kiện khác hoặc hiện tại."},"113":{"word":"ngày","meaning":"Khoảng thời gian hai mươi bốn giờ, từ nửa đêm đến nửa đêm hôm sau."},"114":{"word":"thời tiết","meaning":"Các điều kiện bên ngoài như nắng, mưa, gió hoặc nhiệt độ ở một nơi và thời điểm cụ thể."},"115":{"word":"ngày tháng","meaning":"Một ngày cụ thể được biểu thị bằng số trong tháng và năm trên lịch."},"116":{"word":"Namdaemun (Cổng thành Nam)","meaning":"Một cổng thành gỗ lịch sử lớn, là địa danh nổi tiếng ở thành phố Seoul."},"117":{"word":"em trai","meaning":"Người con trai sinh sau mình nhưng có cùng cha mẹ."},"118":{"word":"Namsan (núi Namsan)","meaning":"Một ngọn núi nổi tiếng ở trung tâm Seoul, thường có tháp truyền thông cao."},"119":{"word":"đàn ông","meaning":"Một người thuộc giới tính nam đã trưởng thành."},"120":{"word":"chồng","meaning":"Người đàn ông đã kết hôn với một người phụ nữ."},"121":{"word":"ban ngày","meaning":"Khoảng thời gian từ lúc mặt trời mọc cho đến lúc mặt trời lặn."},"122":{"word":"thấp","meaning":"Có độ cao hoặc vị trí gần mặt đất, không cao."},"123":{"word":"suối","meaning":"Dòng nước tự nhiên nhỏ hơn sông, chảy qua một con đường trên đất."},"124":{"word":"năm sau","meaning":"Năm kế tiếp sau năm hiện tại."},"125":{"word":"rơi","meaning":"Di chuyển từ trên cao xuống dưới, thường dùng cho mưa hoặc tuyết."},"126":{"word":"ngày mai","meaning":"Ngày kế tiếp ngay sau ngày hôm nay."},"127":{"word":"mì lạnh","meaning":"Món mì truyền thống của Hàn Quốc được phục vụ trong nước dùng lạnh, thường ăn kèm thịt, trứng và rau."},"128":{"word":"bạn","meaning":"Đại từ dùng để chỉ người hoặc những người đang được nói chuyện trực tiếp."},"129":{"word":"quá","meaning":"Diễn tả mức độ hoặc số lượng vượt quá mức bình thường hoặc phù hợp."},"130":{"word":"rộng","meaning":"Có khoảng cách lớn từ bên này sang bên kia, chiếm một diện tích lớn."},"131":{"word":"đặt vào","meaning":"Đặt một vật gì đó vào một không gian nhất định."},"132":{"word":"bốn","meaning":"Từ dùng để chỉ số lượng nhiều hơn ba một đơn vị và ít hơn năm một đơn vị."},"133":{"word":"vâng","meaning":"Từ dùng để thể hiện sự đồng ý, xác nhận hoặc để đáp lại lời nói của người khác một cách lịch sự."},"134":{"word":"bốn","meaning":"Con số tự nhiên sau số ba, biểu thị số lượng là bốn."},"135":{"word":"năm","meaning":"Đơn vị thời gian gồm 365 hoặc 366 ngày, được chia thành mười hai tháng."},"136":{"word":"bài hát","meaning":"Một tác phẩm âm nhạc có lời ca, thường dùng để hát."},"137":{"word":"quán karaoke","meaning":"Nơi được trang bị máy hát karaoke để mọi người có thể hát theo lời bài hát."},"138":{"word":"chơi","meaning":"Dành thời gian tham gia vào các hoạt động vui vẻ, giải trí mà không có mục đích nghiêm túc."},"139":{"word":"bóng rổ","meaning":"Môn thể thao thi đấu giữa hai đội, mỗi đội năm người, với mục tiêu ném bóng vào rổ của đối phương để ghi điểm."},"140":{"word":"cao","meaning":"Có chiều dài hoặc khoảng cách lớn từ mặt đất hoặc một mức cơ sở lên phía trên."},"141":{"word":"ai","meaning":"Đại từ dùng để hỏi về một người mà người nói không biết hoặc không xác định."},"142":{"word":"chị","meaning":"Từ một người em trai dùng để gọi hoặc xưng hô với chị gái hoặc chị họ lớn tuổi hơn mình."},"143":{"word":"mắt","meaning":"Bộ phận trên khuôn mặt người hoặc động vật dùng để nhìn."},"144":{"word":"tuyết","meaning":"Nước đóng băng màu trắng, mềm, rơi từ trời xuống và thường phủ trắng mặt đất vào mùa lạnh."},"145":{"word":"tin tức","meaning":"Thông tin về các sự kiện mới nhất và tình hình thời sự được báo cáo qua các phương tiện truyền thông."},"146":{"word":"muộn","meaning":"Đến một địa điểm hoặc bắt đầu một hành động sau thời gian đã định hoặc dự kiến."},"147":{"word":"tất cả","meaning":"Chỉ toàn bộ mọi thứ hoặc một hành động hoàn tất, không còn gì."},"148":{"word":"đi về","meaning":"Đi đến một nơi nào đó và sau đó quay trở lại địa điểm ban đầu."},"149":{"word":"đi","meaning":"Thường xuyên di chuyển đến một địa điểm cụ thể như trường học hoặc nơi làm việc."},"150":{"word":"khác","meaning":"Có những đặc điểm hoặc tính chất không giống với cái khác."},"151":{"word":"khác","meaning":"Chỉ một người hoặc vật không phải là cái đã được nhắc đến hoặc xem xét trước đó."},"152":{"word":"chân","meaning":"Bộ phận dài từ thân người hoặc động vật, dùng để đứng, đi hoặc chạy."},"153":{"word":"năm","meaning":"Số đếm tự nhiên liền sau số bốn và liền trước số sáu."},"154":{"word":"lại","meaning":"Thực hiện một hành động hoặc sự kiện lần thứ hai, hoặc một lần nữa."},"155":{"word":"tiếp theo","meaning":"Điều hoặc sự việc sẽ xảy ra ngay sau một cái khác."},"156":{"word":"từ","meaning":"Đơn vị ngôn ngữ nhỏ nhất, độc lập, có một ý nghĩa hoặc chức năng nhất định."},"157":{"word":"đóng","meaning":"Di chuyển cửa, cửa sổ hoặc nắp để che kín một lỗ hổng."},"158":{"word":"tháng","meaning":"Đơn vị thời gian dùng để đo khoảng thời gian khoảng 30 ngày."},"159":{"word":"ngọt","meaning":"Có vị giống như mật ong hoặc đường."},"160":{"word":"thuốc lá","meaning":"Lá khô của một loại cây thường được cắt, chế biến và hút trong điếu thuốc."},"161":{"word":"câu trả lời","meaning":"Một lời nói hoặc văn bản được đưa ra để đáp lại một câu hỏi hoặc yêu cầu."},"162":{"word":"đại sứ quán","meaning":"Tòa nhà chính thức ở nước ngoài nơi đại diện ngoại giao của một quốc gia làm việc và cư trú."},"163":{"word":"đại học","meaning":"Một cơ sở giáo dục bậc cao mà học sinh tốt nghiệp cấp ba theo học."},"164":{"word":"trường đại học","meaning":"Một cơ sở giáo dục đại học nơi sinh viên học lấy bằng sau khi tốt nghiệp cấp ba."},"165":{"word":"sinh viên","meaning":"Người đang theo học tại một cơ sở giáo dục đại học sau khi tốt nghiệp cấp ba."},"166":{"word":"cuộc trò chuyện","meaning":"Sự trao đổi lời nói hoặc ý tưởng giữa hai người trở lên."},"167":{"word":"thêm","meaning":"Diễn tả sự tăng lên về số lượng hoặc mức độ."},"168":{"word":"nóng","meaning":"Có nhiệt độ cao trong không khí hoặc trên vật thể, khiến người ta đổ mồ hôi."},"169":{"word":"thư viện","meaning":"Nơi cất giữ nhiều sách báo và tài liệu khác để mọi người đọc hoặc mượn."},"170":{"word":"giúp đỡ","meaning":"Hỗ trợ ai đó về mặt thể chất hoặc thực tế khi họ cần làm gì đó hoặc gặp khó khăn."},"171":{"word":"sự đến","meaning":"Thời điểm một người hoặc phương tiện cuối cùng đến một địa điểm cụ thể sau một chuyến đi."},"172":{"word":"Đức","meaning":"Một quốc gia lớn ở Trung Âu, nổi tiếng với văn hóa và các di tích lịch sử đặc sắc."},"173":{"word":"tiền","meaning":"Các đồng xu kim loại và giấy bạc mà mọi người dùng để mua đồ và dịch vụ."},"174":{"word":"quay","meaning":"Di chuyển theo một vòng tròn quanh một điểm nào đó."},"175":{"word":"trở về","meaning":"Đến lại nơi mình đã ở trước đó hoặc trở lại trạng thái đó."},"176":{"word":"giúp","meaning":"Hỗ trợ ai đó để công việc trở nên dễ dàng hơn hoặc giải quyết vấn đề."},"177":{"word":"Dongdaemun","meaning":"Một tòa nhà cổng lớn, lịch sử nằm ở thành phố Seoul, từng là lối vào chính của bức tường thành cổ."},"178":{"word":"em","meaning":"Người nhỏ tuổi hơn trong số anh chị em ruột hoặc họ hàng."},"179":{"word":"trong lúc, trong thời gian","meaning":"Một khoảng thời gian từ khi bắt đầu đến khi kết thúc một sự kiện hoặc hoạt động nào đó."},"180":{"word":"trở thành, thành","meaning":"Thay đổi từ một trạng thái hoặc điều kiện này sang một trạng thái hoặc điều kiện khác."},"181":{"word":"canh tương đậu","meaning":"Một món canh Hàn Quốc nóng hổi, đậm đà được nấu từ tương đậu lên men với rau, đậu phụ và đôi khi có thịt."},"182":{"word":"hai","meaning":"Từ chỉ số lượng một cộng một, thường đứng trước danh từ."},"183":{"word":"hai","meaning":"Giá trị số học đứng sau một và trước ba, thường dùng khi đếm."},"184":{"word":"phía sau, đằng sau","meaning":"Hướng đối diện với hướng mà một người hoặc vật đang đối mặt."},"185":{"word":"phim truyền hình, kịch","meaning":"Một thể loại chương trình truyền hình hoặc biểu diễn sân khấu kể một câu chuyện với xung đột cảm xúc và các sự kiện gay cấn."},"186":{"word":"dâng, biếu (kính ngữ)","meaning":"Kính cẩn trao hoặc cung cấp một thứ gì đó cho người khác."},"187":{"word":"nghe","meaning":"Tập trung sự chú ý của tai vào một âm thanh hoặc điều gì đó được nói ra."},"188":{"word":"tốn, mất (tiền)","meaning":"Một hoạt động hoặc món đồ khiến một khoản tiền cụ thể bị mất đi để thanh toán."},"189":{"word":"cầm, mang, xách","meaning":"Cầm hoặc có một vật gì đó trong tay hoặc trên tay để mang đi."},"190":{"word":"đi vào, vào","meaning":"Di chuyển từ bên ngoài vào bên trong một không gian hoặc cấu trúc nào đó."},"191":{"word":"đi vào, vào","meaning":"Di chuyển từ bên ngoài vào bên trong một không gian, thường là đến gần người nói."},"192":{"word":"leo núi, đi bộ đường dài","meaning":"Hoạt động đi bộ lên xuống đồi núi để tập thể dục hoặc giải trí."},"193":{"word":"ấm áp","meaning":"Có nhiệt độ dễ chịu, không quá cao."},"194":{"word":"con gái","meaning":"Một người con gái trong mối quan hệ với bố mẹ."},"195":{"word":"dâu tây","meaning":"Một loại trái cây nhỏ, ngọt, màu đỏ, có hạt li ti trên bề mặt và một lớp lá xanh trên đỉnh."},"196":{"word":"lúc, khi","meaning":"Một khoảnh khắc hoặc một khoảng thời gian cụ thể mà điều gì đó xảy ra hoặc tồn tại."},"197":{"word":"Tteokbokki","meaning":"Một món bánh gạo cay phổ biến của Hàn Quốc, được làm từ bánh gạo, rau và các loại gia vị như tương ớt gochujang."},"198":{"word":"lại, nữa","meaning":"Diễn tả việc gì đó xảy ra thêm một lần nữa hoặc có thêm một thứ gì đó."},"199":{"word":"mì ramen, mì gói","meaning":"Một món ăn phổ biến gồm mì ăn liền được phục vụ trong nước dùng nóng, thường được ăn kèm với rau hoặc thịt."},"200":{"word":"Nga, Liên bang Nga","meaning":"Một quốc gia rộng lớn nằm giữa Đông Âu và Siberia, là quốc gia lớn nhất thế giới với thủ đô là Moscow."},"201":{"word":"con (dùng cho số lượng động vật)","meaning":"Từ dùng sau số đếm để chỉ số lượng cụ thể của các loài vật có thân thể."},"202":{"word":"uống","meaning":"Đưa chất lỏng vào miệng và nuốt xuống, thường là từ cốc hoặc chai."},"203":{"word":"tâm hồn","meaning":"Phần bên trong của con người, nơi chứa đựng suy nghĩ, cảm xúc và ý chí."},"204":{"word":"bốn mươi","meaning":"Số lượng biểu thị con số 40."},"205":{"word":"mười nghìn","meaning":"Số lượng biểu thị con số 10.000."},"206":{"word":"gặp gỡ","meaning":"Hai hay nhiều người cùng đến một địa điểm để nhìn thấy hoặc giao tiếp với nhau."},"207":{"word":"làm, tạo ra","meaning":"Chế tạo, xây dựng hoặc khiến một cái gì đó mới tồn tại từ các bộ phận hay nguyên liệu."},"208":{"word":"nhiều","meaning":"Diễn tả số lượng hoặc số người lớn."},"209":{"word":"nhiều","meaning":"Ở một số lượng, mức độ hoặc tần suất đáng kể."},"210":{"word":"lời nói","meaning":"Đơn vị ngôn ngữ, có thể là nói hoặc viết, mang ý nghĩa và tạo thành một phần của câu."},"211":{"word":"đừng, chớ","meaning":"Từ dùng để chỉ dẫn một hành động cụ thể nên tránh hoặc chấm dứt."},"212":{"word":"Malaysia","meaning":"Một quốc gia ở Đông Nam Á, nổi tiếng với các bãi biển, rừng nhiệt đới và dân số đa văn hóa."},"213":{"word":"lời nói (kính ngữ)","meaning":"Hình thức tôn kính của lời nói hoặc giao tiếp bằng lời, đặc biệt khi đề cập đến phát biểu của người khác."},"214":{"word":"trong, trong sạch","meaning":"Diễn tả điều gì đó như nước hoặc không khí không có bụi bẩn, vẩn đục hoặc vật cản, cho phép ánh sáng đi qua."},"215":{"word":"vị","meaning":"Cảm giác mà thức ăn hoặc đồ uống tạo ra khi đưa vào miệng."},"216":{"word":"không ngon","meaning":"Mô tả thức ăn hay đồ uống tạo cảm giác không dễ chịu khi ăn."},"217":{"word":"ngon","meaning":"Mô tả thức ăn hay đồ uống tạo cảm giác rất dễ chịu khi ăn."},"218":{"word":"đúng","meaning":"Chỉ sự việc chính xác, thật hoặc phù hợp hoàn hảo với một mục đích."},"219":{"word":"mỗi ngày","meaning":"Diễn tả một hành động hoặc sự việc xảy ra vào mỗi ngày, không có ngoại lệ."},"220":{"word":"cay","meaning":"Mô tả thức ăn gây cảm giác nóng rát ở lưỡi và miệng."},"221":{"word":"đầu","meaning":"Phần trên cùng của cơ thể người hoặc động vật, bao gồm mặt và tóc."},"222":{"word":"ăn","meaning":"Đưa thức ăn vào miệng và nuốt xuống dạ dày."},"223":{"word":"trước tiên","meaning":"Chỉ một hành động xảy ra vào lúc bắt đầu một chuỗi, trước bất kỳ điều gì khác."},"224":{"word":"xa","meaning":"Khi có một khoảng cách vật lý lớn giữa hai địa điểm."},"225":{"word":"ngầu","meaning":"Diễn tả người, vật hoặc hành động trông rất thu hút hoặc ấn tượng, gây sự ngưỡng mộ."},"226":{"word":"thực đơn","meaning":"Một bảng kê các món ăn và giá cả mà nhà hàng cung cấp."},"227":{"word":"mấy ngày","meaning":"Số lượng ngày không xác định, hoặc dùng để hỏi ngày trong tháng."},"228":{"word":"người","meaning":"Từ dùng để đếm số người."},"229":{"word":"mấy","meaning":"Từ dùng để hỏi về số lượng hoặc chỉ số lượng ít không xác định."},"230":{"word":"tất cả","meaning":"Chỉ toàn bộ số người hoặc vật trong một nhóm, không bỏ sót bất kỳ ai hoặc cái gì."},"231":{"word":"ngày kia","meaning":"Ngày sau ngày mai."},"232":{"word":"không biết","meaning":"Không có kiến thức hoặc sự hiểu biết về một người, vật hay sự việc."},"233":{"word":"mũ","meaning":"Vật đội trên đầu, thường dùng để bảo vệ hoặc trang trí."},"234":{"word":"cổ","meaning":"Bộ phận hẹp nối đầu với thân của người hoặc động vật."},"235":{"word":"thứ Năm","meaning":"Ngày trong tuần, sau thứ Tư và trước thứ Sáu."},"236":{"word":"nhà tắm công cộng","meaning":"Nơi hoặc phòng dùng để tắm rửa toàn thân bằng nước."},"237":{"word":"cơ thể","meaning":"Toàn bộ cấu trúc vật lý của một sinh vật sống, bao gồm tất cả các bộ phận nhìn thấy được."},"238":{"word":"không thể","meaning":"Diễn tả một hành động hoặc công việc không thể thực hiện được."},"239":{"word":"kém, không thể","meaning":"Diễn tả việc không có kỹ năng hoặc không có khả năng thực hiện một hành động nào đó."},"240":{"word":"Mông Cổ","meaning":"Một quốc gia lớn ở Đông Á, nổi tiếng với thảo nguyên rộng lớn và văn hóa du mục."},"241":{"word":"nặng","meaning":"Có trọng lượng lớn, khó nâng hoặc mang vác."},"242":{"word":"gì, nào","meaning":"Từ dùng để hỏi về thông tin cụ thể nhằm xác định một sự vật, sự việc hoặc thuộc tính."},"243":{"word":"gì","meaning":"Từ dùng để chỉ một sự vật hoặc sự việc không xác định."},"244":{"word":"cửa, cổng","meaning":"Một vật cản có thể di chuyển, dùng để ra vào một không gian hoặc khu vực."},"245":{"word":"văn hóa","meaning":"Tổng thể những giá trị, phong tục, tín ngưỡng và nghệ thuật chung của một nhóm người."},"246":{"word":"hỏi","meaning":"Nói chuyện với ai đó để tìm kiếm thông tin hoặc nhận được câu trả lời."},"247":{"word":"nước","meaning":"Một chất lỏng trong suốt, không màu, không mùi, không vị, là thành phần chính của sông, hồ, biển."},"248":{"word":"đồ vật, vật dụng","meaning":"Một thứ cụ thể, có hình dạng và chất liệu nhất định, có thể cầm nắm hoặc sử dụng."},"249":{"word":"gì","meaning":"Là dạng nói rút gọn của từ \"무엇\", dùng để hỏi về một sự vật hay sự việc không biết."},"250":{"word":"Mỹ, Hoa Kỳ","meaning":"Một quốc gia lớn nằm ở Bắc Mỹ, nổi tiếng với lá cờ có các ngôi sao và sọc."},"251":{"word":"sự hối lỗi","meaning":"Là cảm giác buồn bã hoặc xấu hổ khi nhận ra mình đã làm sai điều gì đó với người khác."},"252":{"word":"tiệm làm tóc","meaning":"Là cửa hàng nơi mọi người đến để cắt, tạo kiểu, nhuộm tóc và đôi khi là các dịch vụ làm đẹp khác."},"253":{"word":"phần dưới","meaning":"Là vị trí thấp nhất của một vật hoặc vị trí ngay bên dưới một vật hay bề mặt khác."},"254":{"word":"thay đổi","meaning":"Làm cho một vật trở nên khác với trước đây, hoặc thay thế một vật bằng một vật khác."},"255":{"word":"chuối","meaning":"Là một loại trái cây nhiệt đới dài, cong, có vỏ màu vàng và phần thịt màu trắng mềm, ngọt, dễ bóc vỏ."},"256":{"word":"biển","meaning":"Là một vùng nước mặn rất rộng lớn bao phủ phần lớn bề mặt Trái Đất, thường có sóng và sinh vật biển."},"257":{"word":"gió","meaning":"Là sự chuyển động của không khí gây ra bởi sự thay đổi áp suất khí quyển hoặc bởi con người hay máy móc."},"258":{"word":"ngay lập tức","meaning":"Diễn tả hành động hoặc sự việc xảy ra không chậm trễ, tức thì."},"259":{"word":"bận rộn","meaning":"Có nhiều việc phải làm và ít thời gian rảnh rỗi, thường dẫn đến cảm giác vội vã."},"260":{"word":"quần","meaning":"Là một loại trang phục mặc ở phần dưới cơ thể, che phủ từng chân riêng biệt từ thắt lưng trở xuống."},"261":{"word":"bảo tàng","meaning":"Là một tòa nhà nơi lưu giữ và trưng bày các hiện vật quý giá hoặc thú vị về lịch sử, nghệ thuật hoặc khoa học cho công chúng."},"262":{"word":"bên ngoài","meaning":"Là phía nằm vượt ra ngoài một đường giới hạn hoặc ranh giới."},"263":{"word":"nửa","meaning":"Một trong hai phần bằng nhau của một tổng thể."},"264":{"word":"lớp","meaning":"Một nhóm học sinh học cùng nhau trong trường học."},"265":{"word":"vui mừng","meaning":"Cảm thấy vui và ấm áp khi gặp hoặc tương tác với ai đó."},"266":{"word":"nhận","meaning":"Lấy một thứ gì đó mà người khác đã đưa hoặc gửi."},"267":{"word":"chân","meaning":"Bộ phận thấp nhất của cơ thể người, dùng để đứng, đi lại và đá."},"268":{"word":"đêm","meaning":"Khoảng thời gian từ lúc mặt trời lặn đến lúc mặt trời mọc, khi trời tối."},"269":{"word":"cơm","meaning":"Hạt gạo đã nấu chín, thường là màu trắng và mềm, là món ăn chính."},"270":{"word":"phòng","meaning":"Không gian được bao quanh bởi các bức tường, dùng để ở hoặc làm việc."},"271":{"word":"kỳ nghỉ học","meaning":"Khoảng thời gian trường học đóng cửa và học sinh được nghỉ học."},"272":{"word":"bụng","meaning":"Phần mềm và tròn của cơ thể người, nơi chứa và xử lý thức ăn."},"273":{"word":"tàu","meaning":"Cấu trúc lớn nổi trên mặt nước, dùng để vận chuyển người hoặc hàng hóa."},"274":{"word":"quả lê","meaning":"Một loại trái cây hình tròn với vỏ màu vàng nhạt, thịt trắng, mọng nước và ngọt."},"275":{"word":"diễn viên","meaning":"Người đóng vai nhân vật trong truyện, biểu diễn trên sân khấu hoặc màn ảnh để phục vụ khán giả."},"276":{"word":"học","meaning":"Tiếp thu kiến thức hoặc kỹ năng mới thông qua việc lắng nghe, đọc sách hoặc luyện tập thường xuyên."},"277":{"word":"một trăm","meaning":"Số lượng cụ thể được biểu thị bằng chữ số 100, bằng mười bộ mười đơn vị."},"278":{"word":"một triệu","meaning":"Số lượng cụ thể được biểu thị bằng chữ số 1.000.000, bằng một nghìn bộ một nghìn đơn vị."},"279":{"word":"trung tâm thương mại","meaning":"Một tòa nhà rất lớn nơi mọi người có thể mua nhiều loại sản phẩm khác nhau như quần áo, mỹ phẩm và đồ gia dụng, được bán ở các khu riêng biệt."},"280":{"word":"xe buýt","meaning":"Một phương tiện giao thông lớn được thiết kế để chở hành khách theo tuyến đường cố định và thu phí."},"281":{"word":"lần","meaning":"Đơn vị dùng để đếm số lần một hành động hoặc sự việc đã xảy ra."},"282":{"word":"số","meaning":"Một dãy chữ số hoặc ký hiệu được in trên vật thể như vé hoặc hộ chiếu, dùng để nhận dạng cụ thể."},"283":{"word":"Việt Nam","meaning":"Một quốc gia nằm ở Đông Nam Á, nổi tiếng với bờ biển dài, các thành phố sôi động và lịch sử phong phú."},"284":{"word":"không/chẳng... lắm","meaning":"Từ dùng để diễn tả rằng một điều gì đó tồn tại hoặc xảy ra ở mức độ rất nhỏ."},"285":{"word":"bệnh","meaning":"Tình trạng cơ thể hoặc tinh thần của một người không khỏe mạnh, thường khiến họ cảm thấy yếu ớt, mệt mỏi hoặc đau đớn."},"286":{"word":"cái chai","meaning":"Vật đựng thường làm bằng thủy tinh hoặc nhựa, có cổ dài và hẹp, dùng để chứa chất lỏng hoặc bột."},"287":{"word":"bệnh viện","meaning":"Một tòa nhà lớn nơi người bệnh hoặc bị thương đến để được điều trị y tế và thường ở lại để hồi phục."},"288":{"word":"gửi","meaning":"Làm cho một vật, như thư hay bưu kiện, di chuyển từ một nơi đến một địa điểm khác."},"289":{"word":"nhìn, xem","meaning":"Dùng mắt để nhận biết hoặc quan sát một vật hay một người ở trước mặt."},"290":{"word":"hơn, thêm","meaning":"Từ dùng để chỉ một mức độ hoặc số lượng lớn hơn so với một vật hoặc điều khác."},"291":{"word":"thông thường, bình thường","meaning":"Chất lượng phổ biến, không có gì đặc biệt hoặc khác lạ."},"292":{"word":"bút bi","meaning":"Một dụng cụ viết phân tán mực bằng cách sử dụng sự quay của một viên bi nhỏ ở đầu."},"293":{"word":"mùa xuân","meaning":"Mùa chuyển tiếp giữa mùa đông và mùa hè."},"294":{"word":"gọi","meaning":"Phát ra tiếng hoặc gọi tên một người để thu hút sự chú ý của họ."},"295":{"word":"bố mẹ, cha mẹ","meaning":"Những người nam và nữ đã sinh ra và nuôi dưỡng một người."},"296":{"word":"Busan","meaning":"Một thành phố lớn nằm ở bờ biển phía đông nam Hàn Quốc, nổi tiếng với cảng lớn và bãi biển."},"297":{"word":"nhà bếp","meaning":"Một khu vực hoặc căn phòng trong tòa nhà nơi các bữa ăn được chuẩn bị bằng thiết bị nấu nướng."},"298":{"word":"lời thỉnh cầu, yêu cầu","meaning":"Hành động lịch sự đề nghị ai đó làm hoặc cho bạn điều gì."},"299":{"word":"vị","meaning":"Từ dùng để chỉ hoặc đếm người một cách lịch sự."},"300":{"word":"phút","meaning":"Đơn vị đo thời gian bằng 60 giây."},"301":{"word":"lửa","meaning":"Hiện tượng cháy kèm theo nhiệt, ánh sáng và khói."},"302":{"word":"bulgogi","meaning":"Món ăn Hàn Quốc nổi tiếng làm từ thịt bò hoặc thịt heo thái mỏng nướng."},"303":{"word":"thổi","meaning":"Khiến không khí hoặc hơi di chuyển có lực."},"304":{"word":"mưa","meaning":"Nước rơi từ trên trời xuống thành giọt."},"305":{"word":"bibimbap","meaning":"Món ăn Hàn Quốc gồm cơm trộn với nhiều loại rau củ, thịt và trứng."},"306":{"word":"đắt","meaning":"Có giá trị tiền bạc cao, cần nhiều tiền để mua."},"307":{"word":"máy bay","meaning":"Phương tiện giao thông có cánh, bay trên bầu trời để chở người hoặc hàng hóa."},"308":{"word":"mượn","meaning":"Nhận một vật hoặc tiền từ người khác với cam kết sẽ trả lại sau."},"309":{"word":"nhanh","meaning":"Di chuyển hoặc hoàn thành một việc trong thời gian ngắn."},"310":{"word":"nhanh","meaning":"Với tốc độ cao hoặc trong thời gian ngắn."},"311":{"word":"bánh mì","meaning":"Một loại thực phẩm làm từ bột mì, thường được nướng và ăn."},"312":{"word":"bốn","meaning":"Số tự nhiên liền sau số ba."},"313":{"word":"quả táo","meaning":"Một loại trái cây tròn, vỏ màu đỏ hoặc xanh, thịt trắng, ăn được."},"314":{"word":"kết bạn","meaning":"Bắt đầu làm quen và dành thời gian với người khác để hình thành mối quan hệ bạn bè."},"315":{"word":"mua","meaning":"Thanh toán tiền để có được quyền sở hữu một vật gì đó."},"316":{"word":"người","meaning":"Một loài vật có khả năng tư duy, tạo ra và sử dụng ngôn ngữ, công cụ, sống trong xã hội."},"317":{"word":"tình yêu","meaning":"Một cảm xúc mạnh mẽ, nồng ấm của sự gắn bó và quan tâm sâu sắc dành cho người khác."},"318":{"word":"văn phòng","meaning":"Một căn phòng trong tòa nhà nơi mọi người làm việc, thường là các công việc giấy tờ, hành chính."},"319":{"word":"bốn mươi","meaning":"Số tự nhiên bằng bốn lần mười."},"320":{"word":"sử dụng","meaning":"Hành động đưa một vật hay phương pháp vào thực hiện theo mục đích của nó."},"321":{"word":"tháng Tư","meaning":"Tháng thứ tư trong năm theo lịch dương, sau tháng Ba và trước tháng Năm."},"322":{"word":"khoảng cách","meaning":"Khoảng trống hay không gian nằm giữa hai vật thể hoặc hai địa điểm."},"323":{"word":"nước ngọt có ga","meaning":"Một loại đồ uống có vị ngọt, trong suốt, có nhiều bọt khí và thường có vị chanh hoặc tắc."},"324":{"word":"từ điển","meaning":"Sách hoặc công cụ kỹ thuật số liệt kê các từ theo thứ tự bảng chữ cái cùng với ý nghĩa của chúng."},"325":{"word":"ảnh","meaning":"Hình ảnh được chụp bằng máy ảnh để lưu giữ khoảnh khắc, con người hoặc phong cảnh trong thế giới thực."},"326":{"word":"núi","meaning":"Một dạng địa hình tự nhiên rất lớn, nhô cao rõ rệt so với khu vực xung quanh, thường có đỉnh."},"327":{"word":"đi dạo","meaning":"Hành động đi bộ chậm rãi, thư thái, thường là ngoài trời, để giải trí hoặc tập thể dục."},"328":{"word":"tuổi","meaning":"Từ dùng để chỉ số năm kể từ khi một người sinh ra."},"329":{"word":"sống","meaning":"Trạng thái tồn tại, thở, vận động và trải nghiệm các sự kiện hàng ngày một cách liên tục."},"330":{"word":"ba","meaning":"Số lượng được biểu thị bằng chữ số '3', đứng sau số hai và trước số bốn."},"331":{"word":"Samgyetang","meaning":"Món ăn làm từ gà non nhồi nhân sâm, gạo nếp, táo tàu,... rồi hầm."},"332":{"word":"ba mươi","meaning":"Số lượng được biểu thị bằng chữ số '30', lớn hơn hai mươi chín mười đơn vị và đứng trước ba mươi mốt."},"333":{"word":"tháng ba","meaning":"Tháng thứ ba trong năm, theo sau tháng hai và có ba mươi mốt ngày."},"334":{"word":"suy nghĩ","meaning":"Quá trình hình thành ý tưởng hoặc ý kiến trong tâm trí, hoặc ý tưởng nảy sinh từ quá trình đó."},"335":{"word":"sinh nhật","meaning":"Ngày kỷ niệm một năm ra đời của người lớn tuổi hoặc người có địa vị, dùng với ý kính trọng."},"336":{"word":"sinh nhật","meaning":"Ngày kỷ niệm một năm ra đời của một người."},"337":{"word":"cuộc sống","meaning":"Trạng thái tồn tại và cách một người thực hiện các hoạt động hằng ngày của mình."},"338":{"word":"tắm vòi sen","meaning":"Hành động làm sạch cơ thể bằng cách đứng dưới dòng nước chảy từ vòi hoa sen trong phòng tắm."},"339":{"word":"ba mươi","meaning":"Số tự nhiên đứng sau hai mươi chín và đứng trước ba mươi mốt."},"340":{"word":"Seoul","meaning":"Thủ đô và thành phố lớn nhất của Hàn Quốc, nổi tiếng với nhiều tòa nhà cao tầng và di tích lịch sử."},"341":{"word":"nhà sách","meaning":"Cửa hàng hoặc cơ sở lớn nơi nhiều tài liệu in ấn được sắp xếp gọn gàng trên kệ để mọi người mua."},"342":{"word":"quà","meaning":"Một vật phẩm mà một người tặng cho người khác mà không mong nhận lại tiền, thường vào những dịp đặc biệt."},"343":{"word":"giáo viên","meaning":"Người hướng dẫn học sinh học những điều mới ở trường học hoặc nơi khác."},"344":{"word":"lời giải thích","meaning":"Những lời nói hoặc chữ viết để làm cho điều gì đó rõ ràng hoặc dễ hiểu."},"345":{"word":"ba","meaning":"Số tự nhiên đứng sau hai và đứng trước bốn."},"346":{"word":"rửa mặt","meaning":"Hành động làm sạch phần mặt của bạn bằng nước."},"347":{"word":"ba","meaning":"Số tự nhiên liền sau số hai và liền trước số bốn."},"348":{"word":"giới thiệu","meaning":"Hành động làm cho ai đó hoặc cái gì đó được người khác biết đến lần đầu tiên."},"349":{"word":"muối","meaning":"Chất bột tinh thể màu trắng, có vị mặn, thường dùng để nêm nếm thức ăn."},"350":{"word":"tay","meaning":"Bộ phận cơ thể ở cuối cánh tay, dùng để cầm nắm, chỉ trỏ và chạm vào."},"351":{"word":"khách","meaning":"Người đến thăm hoặc sử dụng dịch vụ, sản phẩm của một nơi nào đó."},"352":{"word":"mua sắm","meaning":"Hoạt động đi đến các cửa hàng để xem và mua đồ."},"353":{"word":"dưa hấu","meaning":"Loại quả to, tròn, vỏ màu xanh có sọc đen, ruột đỏ và nhiều nước."},"354":{"word":"tiết học","meaning":"Khoảng thời gian mà học sinh học một môn học cụ thể từ giáo viên."},"355":{"word":"bơi lội","meaning":"Hoạt động di chuyển cơ thể trong nước bằng tay và chân."},"356":{"word":"bể bơi","meaning":"Khu vực nhân tạo chứa đầy nước để mọi người tập thể dục hoặc vui chơi."},"357":{"word":"thứ Tư","meaning":"Ngày thứ tư trong tuần, sau thứ Ba và trước thứ Năm."},"358":{"word":"sổ tay","meaning":"Một cuốn sổ nhỏ mang theo để ghi chép những điều cần thiết một cách đơn giản."},"359":{"word":"bài tập về nhà","meaning":"Bài tập mà giáo viên giao cho học sinh làm ở nhà sau giờ học."},"360":{"word":"rượu","meaning":"Đồ uống có cồn, khi uống vào có thể làm con người thư giãn hoặc say."},"361":{"word":"nghỉ ngơi","meaning":"Ngừng mọi hoạt động để thư giãn cơ thể, thường là ngồi hoặc nằm xuống."},"362":{"word":"dễ","meaning":"Không khó để thực hiện, có thể hoàn thành nhanh chóng và không gặp nhiều khó khăn."},"363":{"word":"siêu thị","meaning":"Cửa hàng lớn nơi khách hàng có thể mua nhiều loại thực phẩm và đồ dùng gia đình."},"364":{"word":"hai mươi","meaning":"Số tự nhiên liền sau mười chín."},"365":{"word":"trượt tuyết","meaning":"Môn thể thao mùa đông dùng ván dài gắn vào chân để trượt trên tuyết."},"366":{"word":"buồn","meaning":"Cảm thấy không vui, thường thể hiện qua nước mắt hoặc nét mặt ủ rũ."},"367":{"word":"giờ","meaning":"Từ dùng sau số để chỉ một thời điểm cụ thể trong ngày."},"368":{"word":"thời gian","meaning":"Khoảng liên tục của các sự việc diễn ra, được đo bằng đồng hồ."},"369":{"word":"chua","meaning":"Vị mạnh, gắt, giống như vị chanh, thường làm mặt nhăn lại."},"370":{"word":"mát mẻ","meaning":"Cảm giác dễ chịu, không nóng bức, thường làm cho con người cảm thấy sảng khoái."},"371":{"word":"tháng Mười","meaning":"Tháng thứ mười trong một năm dương lịch."},"372":{"word":"sự bắt đầu","meaning":"Khoảnh khắc hoặc hành động đầu tiên khi một việc gì đó mới mẻ bắt đầu."},"373":{"word":"chợ","meaning":"Nơi công cộng thường nhộn nhịp, có nhiều quầy hàng, nơi mọi người tụ tập để mua bán các mặt hàng khác nhau."},"374":{"word":"tòa thị chính","meaning":"Một tòa nhà công cộng lớn nơi các quan chức chính quyền địa phương làm việc và người dân đến để giải quyết các thủ tục hành chính."},"375":{"word":"sai bảo","meaning":"Đưa ra chỉ thị cho người khác, khiến họ thực hiện một nhiệm vụ hoặc mang thứ gì đó đến cho mình."},"376":{"word":"kỳ thi","meaning":"Một hình thức đánh giá chính thức mà mọi người trả lời câu hỏi để thể hiện kiến thức của mình, thường trong môi trường học tập."},"377":{"word":"nhà hàng","meaning":"Một tòa nhà hoặc căn phòng nơi mọi người ngồi vào bàn để ăn thức ăn được chuẩn bị và phục vụ bởi nhân viên."},"378":{"word":"bữa ăn","meaning":"Lượng thức ăn mà một người ăn vào một thời điểm cụ thể trong ngày, như buổi sáng, buổi trưa hoặc buổi tối."},"379":{"word":"đi (giày)","meaning":"Đặt một vật dụng để đi vào chân hoặc cẳng chân, như giày dép, vớ."},"380":{"word":"báo","meaning":"Một ấn phẩm định kỳ cung cấp thông tin về các sự kiện mới đang diễn ra trên thế giới cho độc giả."},"381":{"word":"giày","meaning":"Những vật dụng được làm từ chất liệu như da hoặc vải mà mọi người mang vào chân để che và bảo vệ chân."},"382":{"word":"thất lễ","meaning":"Một hành động hoặc lời nói không lịch sự và có thể gây khó chịu cho người khác."},"383":{"word":"không thích","meaning":"Khi cảm thấy có phản ứng tiêu cực mạnh mẽ đối với điều gì đó, khiến mình không hài lòng hoặc muốn tránh xa."},"384":{"word":"ghét","meaning":"Có cảm giác không đồng tình mạnh mẽ với một người, vật hoặc hoạt động, thường thể hiện bằng cách tránh né hoặc nhăn mặt."},"385":{"word":"mười","meaning":"Số đếm liền sau số chín và đứng trước số mười một, thường được biểu thị bằng các chữ số 1 và 0."},"386":{"word":"một trăm nghìn","meaning":"Một số lượng lớn bằng một trăm lần một nghìn, được viết là 100.000."},"387":{"word":"tháng mười hai","meaning":"Tháng thứ mười hai và cũng là tháng cuối cùng của năm."},"388":{"word":"tháng mười một","meaning":"Tháng thứ mười một của năm, đứng sau tháng mười và trước tháng cuối cùng."},"389":{"word":"nhạt","meaning":"Khi thức ăn thiếu vị mặn hoặc gia vị, khiến nó có hương vị nhẹ hoặc không đậm đà."},"390":{"word":"rẻ","meaning":"Có chi phí tiền tệ thấp so với các mặt hàng tương tự khác."},"391":{"word":"viết","meaning":"Tạo thành chữ cái, từ hoặc ký hiệu trên một bề mặt bằng bút, chì hoặc công cụ khác."},"392":{"word":"sử dụng","meaning":"Thực hiện hành động với một vật thể hoặc máy móc, như máy tính, để đạt được một kết quả cụ thể."},"393":{"word":"đắng","meaning":"Mô tả một cảm giác vị giác trong miệng sắc và khó chịu, giống như một số loại thuốc hoặc cà phê."},"394":{"word":"ông/bà","meaning":"Một kính ngữ được dùng sau tên người để thể hiện sự tôn trọng hoặc lịch sự khi xưng hô."},"395":{"word":"rửa","meaning":"Làm cho sạch sẽ bằng cách dùng nước hoặc chất tẩy rửa."},"396":{"word":"à, ồ","meaning":"Từ dùng để biểu lộ sự ngạc nhiên, đau đớn hoặc hiểu ra điều gì đó."},"397":{"word":"em bé, trẻ sơ sinh","meaning":"Con người còn rất nhỏ, đang trong giai đoạn bú sữa mẹ."},"398":{"word":"vợ","meaning":"Người phụ nữ đã kết hôn với một người đàn ông."},"399":{"word":"không phải, không đúng","meaning":"Diễn tả sự phủ định, không đúng hoặc không phải như vậy."},"400":{"word":"không, không ạ","meaning":"Từ dùng để phủ định, từ chối hoặc trả lời tiêu cực."},"401":{"word":"dưới, bên dưới","meaning":"Vị trí thấp hơn một mức độ hoặc tiêu chuẩn nào đó."},"402":{"word":"việc làm bán thời gian","meaning":"Công việc mà một người làm trong một số giờ giới hạn mỗi ngày hoặc mỗi tuần."},"403":{"word":"đẹp","meaning":"Có hình thức hoặc chất lượng tuyệt vời, gây ấn tượng mạnh và cảm giác ngưỡng mộ."},"404":{"word":"bố, cha","meaning":"Người đàn ông là phụ huynh của một đứa trẻ."},"405":{"word":"trẻ em, đứa trẻ","meaning":"Con người còn nhỏ, chưa trưởng thành."},"406":{"word":"kem","meaning":"Món tráng miệng lạnh, ngọt, làm từ sữa, kem và đường."},"407":{"word":"chú","meaning":"Từ dùng để gọi hoặc xưng hô với người đàn ông ở thế hệ của cha mẹ mình."},"408":{"word":"rất","meaning":"Từ biểu thị mức độ cực kỳ cao hoặc hoàn toàn của một sự vật, sự việc."},"409":{"word":"cô, bác","meaning":"Từ dùng để gọi hoặc xưng hô với người phụ nữ ở thế hệ của cha mẹ mình."},"410":{"word":"vẫn, chưa","meaning":"Từ biểu thị rằng một sự việc nào đó vẫn chưa xảy ra hoặc chưa kết thúc cho đến thời điểm hiện tại."},"411":{"word":"buổi sáng","meaning":"Khoảng thời gian từ khi mặt trời mọc đến gần trưa, khi trời bắt đầu sáng."},"412":{"word":"chung cư","meaning":"Tòa nhà dân cư cao tầng, được xây dựng để nhiều hộ gia đình có thể sống độc lập."},"413":{"word":"đau, ốm","meaning":"Trạng thái cơ thể cảm thấy khó chịu, gây ra cảm giác quằn quại hoặc muốn nghỉ ngơi."},"414":{"word":"chín","meaning":"Số đếm lớn hơn tám và nhỏ hơn mười, viết là 9."},"415":{"word":"chín mươi","meaning":"Số đếm bằng chín lần mười, viết là 90."},"416":{"word":"trong","meaning":"Không gian hoặc khu vực nằm bên trong giới hạn hoặc bức tường của một vật thể, địa điểm nào đó."},"417":{"word":"không","meaning":"Từ dùng để phủ định một hành động, trạng thái hoặc tính chất nào đó."},"418":{"word":"kính mắt","meaning":"Vật dụng đeo trên mặt, có hai thấu kính trong suốt đặt trước mắt, giúp người đeo nhìn rõ hơn."},"419":{"word":"Hướng dẫn","meaning":"Thông tin hoặc chỉ dẫn được cung cấp để giúp mọi người tìm đường, hiểu biết hoặc nhận tin tức quan trọng."},"420":{"word":"Chào","meaning":"Từ dùng để chào hỏi khi gặp mặt hoặc tạm biệt khi chia tay."},"421":{"word":"Bình an","meaning":"Từ dùng khi chia tay, mong người ở lại được an toàn, khỏe mạnh."},"422":{"word":"Ngồi","meaning":"Đặt trọng lượng cơ thể lên mông và giữ phần thân trên thẳng đứng trên một vật gì đó hoặc trên sàn."},"423":{"word":"Biết","meaning":"Có thông tin hoặc kiến thức về một sự vật, tình huống qua học hỏi, kinh nghiệm hoặc suy nghĩ."},"424":{"word":"Thông báo","meaning":"Cho ai đó biết về các sự kiện, tin tức hoặc tình huống bằng cách nói hoặc viết."},"425":{"word":"Trước","meaning":"Hướng hoặc vị trí mà một người đang đối mặt."},"426":{"word":"Bóng chày","meaning":"Môn thể thao được chơi giữa hai đội trên sân với gậy, bóng và găng tay, trong đó người chơi đánh bóng và chạy quanh các chốt."},"427":{"word":"Khoảng","meaning":"Từ dùng để chỉ một số lượng hoặc phép đo không chính xác nhưng rất gần với giá trị thực."},"428":{"word":"Thuốc","meaning":"Một chất, thường ở dạng viên hoặc lỏng, mà mọi người uống hoặc thoa lên cơ thể để cảm thấy khỏe hơn hoặc hồi phục sau bệnh tật."},"429":{"word":"Hiệu thuốc","meaning":"Cửa hàng hoặc một phần của cửa hàng nơi các chuyên gia được đào tạo chuẩn bị và cấp phát thuốc cho những người cần vì lý do sức khỏe."},"430":{"word":"Lời hẹn","meaning":"Sự thỏa thuận bằng lời nói hoặc văn bản để gặp ai đó vào thời gian cụ thể hoặc để làm điều gì đó cho ai đó."},"431":{"word":"nào","meaning":"Từ dùng đứng trước danh từ để hỏi chọn hoặc xác định một vật, địa điểm, người cụ thể trong số nhiều lựa chọn."},"432":{"word":"đâu","meaning":"Từ dùng để hỏi về địa điểm, vị trí cụ thể của một vật hoặc một người."},"433":{"word":"nào","meaning":"Từ dùng đứng trước danh từ để hỏi hoặc chỉ một lựa chọn hay loại cụ thể nào đó trong một nhóm."},"434":{"word":"thế nào","meaning":"Từ dùng để hỏi về tình trạng, chất lượng hoặc cách thức của sự vật hay con người."},"435":{"word":"khó","meaning":"Khi một công việc hay vấn đề cần nhiều nỗ lực, kỹ năng hoặc thời gian để hoàn thành hay hiểu được."},"436":{"word":"mẹ","meaning":"Người phụ nữ đã sinh ra con cái."},"437":{"word":"mau","meaning":"Di chuyển hoặc hành động với tốc độ nhanh và không lãng phí thời gian."},"438":{"word":"hôm qua","meaning":"Ngày diễn ra ngay trước ngày hiện tại."},"439":{"word":"một trăm triệu","meaning":"Một đơn vị số lượng lớn được biểu thị bằng chữ số 1 theo sau bởi tám số 0 (100.000.000)."},"440":{"word":"chị","meaning":"Từ dùng bởi nữ giới để gọi hoặc xưng hô với chị gái hoặc chị họ lớn tuổi hơn mình."},"441":{"word":"khi nào","meaning":"Một khoảng thời gian mà người nói không biết."},"442":{"word":"mặt","meaning":"Phần phía trước của đầu bao gồm mắt, mũi và miệng."},"443":{"word":"bao nhiêu","meaning":"Số lượng, giá cả hoặc mức độ mà người nói không biết rõ."},"444":{"word":"bao nhiêu","meaning":"Từ dùng để hỏi về mức độ, phạm vi hoặc kích thước của một sự vật."},"445":{"word":"không có","meaning":"Không tồn tại hoặc không hiện diện trong thực tế."},"446":{"word":"máy lạnh","meaning":"Thiết bị dùng để làm giảm nhiệt độ không khí bên trong phòng hoặc tòa nhà."},"447":{"word":"hộ chiếu","meaning":"Sổ chính thức nhỏ do chính phủ cấp để chứng minh quốc tịch của một người và cho phép họ đi du lịch đến các quốc gia khác."},"448":{"word":"đây","meaning":"Từ dùng để chỉ địa điểm hoặc vị trí chính xác mà người nói đang ở."},"449":{"word":"tám","meaning":"Giá trị số đứng sau bảy và trước chín."},"450":{"word":"em gái","meaning":"Thành viên nữ trong gia đình có cùng cha mẹ và sinh ra sau mình."},"451":{"word":"tám mươi","meaning":"Giá trị số bằng mười lần tám."},"452":{"word":"nhiều","meaning":"Có số lượng lớn, không phải chỉ một."},"453":{"word":"mọi người","meaning":"Từ dùng để xưng hô với tất cả những người có mặt trong một nhóm hoặc khán giả cụ thể."},"454":{"word":"mùa hè","meaning":"Khoảng thời gian nóng nhất trong năm, đặc trưng bởi ngày dài và thời tiết thường nóng bức."},"455":{"word":"alo","meaning":"Từ dùng khi nghe điện thoại hoặc gọi người khác để gây chú ý."},"456":{"word":"sáu","meaning":"Số đếm tự nhiên đứng sau số năm."},"457":{"word":"phụ nữ","meaning":"Người trưởng thành thuộc giới tính nữ."},"458":{"word":"du lịch","meaning":"Hoạt động đi từ nơi này đến nơi khác, thường là xa, với mục đích giải trí hoặc công tác."},"459":{"word":"công ty du lịch","meaning":"Công ty cung cấp dịch vụ đặt vé, khách sạn và tổ chức các chuyến đi cho khách du lịch."},"460":{"word":"ga","meaning":"Nơi tàu hỏa, tàu điện hoặc xe buýt dừng lại để hành khách lên hoặc xuống."},"461":{"word":"kịch","meaning":"Loại hình nghệ thuật biểu diễn trực tiếp trên sân khấu, trong đó các diễn viên đóng vai và kể chuyện."},"462":{"word":"luyện tập","meaning":"Hành động lặp lại một hoạt động hoặc kỹ năng để đạt được sự thành thạo."},"463":{"word":"bút chì","meaning":"Dụng cụ viết hoặc vẽ, thường có lõi than chì bọc trong gỗ."},"464":{"word":"mười","meaning":"Số đếm tự nhiên đứng sau số chín."},"465":{"word":"mở","meaning":"Làm cho cái gì đó như cửa, nắp không còn đóng kín, cho phép vào hoặc lấy ra."},"466":{"word":"chìa khóa","meaning":"Dụng cụ nhỏ bằng kim loại dùng để mở hoặc khóa một ổ khóa."},"467":{"word":"chăm chỉ","meaning":"Với thái độ làm việc hết sức cố gắng, nỗ lực."},"468":{"word":"số không","meaning":"Giá trị số học biểu thị sự không có, sự vắng mặt của số lượng."},"469":{"word":"Vương quốc Anh","meaning":"Một quốc gia hải đảo ở châu Âu, bao gồm Anh, Scotland, Wales và Bắc Ireland."},"470":{"word":"tiếng Anh","meaning":"Một ngôn ngữ có nhiều người nói trên thế giới, được viết bằng bảng chữ cái và dùng trong sách vở, giao tiếp."},"471":{"word":"phim","meaning":"Một câu chuyện được kể bằng hình ảnh động và âm thanh, được chiếu trên màn hình lớn cho mọi người xem."},"472":{"word":"rạp chiếu phim","meaning":"Nơi chiếu phim, được trang bị cơ sở vật chất cho phép nhiều người cùng xem."},"473":{"word":"diễn viên điện ảnh","meaning":"Người đóng vai nhân vật trong phim và được nhiều người biết đến."},"474":{"word":"bên cạnh","meaning":"Vị trí hoặc khu vực ngay sát một người hoặc vật khác."},"475":{"word":"vâng","meaning":"Tiếng hoặc từ ngắn gọn thể hiện sự đồng ý hoặc xác nhận."},"476":{"word":"đẹp, xinh đẹp","meaning":"Có vẻ ngoài rất dễ chịu, khiến người nhìn cảm thấy vui vẻ, thích thú."},"477":{"word":"năm","meaning":"Số nguyên lớn hơn bốn một đơn vị."},"478":{"word":"hôm nay","meaning":"Ngày cụ thể đang diễn ra, từ sáng đến tối."},"479":{"word":"đến","meaning":"Di chuyển từ một nơi khác đến vị trí hiện tại của người nói hoặc của sự việc."},"480":{"word":"cam","meaning":"Một loại trái cây hình tròn, có vỏ dày màu cam, nhiều nước và vị ngọt chua."},"481":{"word":"bên phải","meaning":"Phía đối diện với bên trái của cơ thể."},"482":{"word":"anh","meaning":"Từ một cô gái dùng để gọi hoặc xưng hô với anh trai ruột hoặc anh họ của mình."},"483":{"word":"năm mươi","meaning":"Số tự nhiên bằng năm lần mười, đứng sau bốn mươi chín và trước năm mươi mốt."},"484":{"word":"tháng năm","meaning":"Tháng thứ năm trong năm dương lịch, có ba mươi mốt ngày, thường gắn liền với mùa hoa nở."},"485":{"word":"buổi sáng","meaning":"Khoảng thời gian từ lúc mặt trời mọc cho đến giữa trưa."},"486":{"word":"buổi chiều","meaning":"Khoảng thời gian từ sau giữa trưa cho đến khi mặt trời lặn vào buổi tối."},"487":{"word":"đi lên","meaning":"Di chuyển từ vị trí thấp hơn đến vị trí cao hơn."},"488":{"word":"năm nay","meaning":"Khoảng thời gian mười hai tháng đang diễn ra, từ ngày một tháng một đến ngày ba mốt tháng mười hai."},"489":{"word":"quần áo","meaning":"Những vật làm bằng vải hoặc chất liệu khác mà con người mặc lên người để che thân, giữ ấm hoặc trang trí."},"490":{"word":"Ồ!","meaning":"Từ cảm thán dùng để biểu lộ sự ngạc nhiên, phấn khích hoặc ấn tượng mạnh mẽ khi nhìn hoặc nghe thấy điều gì đó."},"491":{"word":"tại sao","meaning":"Là từ dùng để hỏi về nguyên nhân hoặc mục đích của một hành động hay sự việc."},"492":{"word":"nước ngoài","meaning":"Một quốc gia hoặc lãnh thổ khác, không phải nơi mình sinh sống hoặc đến từ."},"493":{"word":"ngoại ngữ","meaning":"Ngôn ngữ của một đất nước khác."},"494":{"word":"người nước ngoài","meaning":"Người không phải công dân của quốc gia mà họ đang ở."},"495":{"word":"bên trái","meaning":"Phía hoặc hướng ngược lại với bên phải."},"496":{"word":"nấu ăn","meaning":"Hoạt động chế biến thực phẩm bằng cách áp dụng nhiệt, hoặc món ăn đã được chuẩn bị."},"497":{"word":"ngày trong tuần","meaning":"Một trong bảy khoảng thời gian có tên gọi lặp đi lặp lại trong một tuần, ví dụ thứ Hai hoặc thứ Bảy."},"498":{"word":"dạo gần đây","meaning":"Khoảng thời gian hiện tại hoặc những ngày gần nhất tính đến thời điểm nói."},"499":{"word":"chúng ta","meaning":"Đại từ dùng để chỉ người nói và người nghe, hoặc một nhóm người bao gồm người nói và người nghe."},"500":{"word":"ô","meaning":"Vật dụng có thể gấp gọn, có hình vòm, dùng để che mưa hoặc nắng."},"501":{"word":"sữa","meaning":"Chất lỏng màu trắng do động vật cái có vú tiết ra, thường được dùng làm đồ uống hoặc trong chế biến thực phẩm."},"502":{"word":"bưu điện","meaning":"Tòa nhà nơi mọi người có thể gửi thư và bưu phẩm, mua tem."},"503":{"word":"tem thư","meaning":"Một mảnh giấy nhỏ dán lên thư từ để chứng tỏ đã trả cước phí bưu điện."},"504":{"word":"tập thể dục","meaning":"Hoạt động thể chất như chạy bộ, nâng tạ, được thực hiện để cải thiện hoặc duy trì sức khỏe và thể lực."},"505":{"word":"sân vận động","meaning":"Một khu đất rộng có trang bị các thiết bị và tiện nghi để chơi thể thao hoặc vui chơi."},"506":{"word":"giày thể thao","meaning":"Loại giày thường làm bằng vật liệu mềm có đế cao su, được thiết kế cho các hoạt động thể chất như chạy hoặc chơi thể thao."},"507":{"word":"lái xe","meaning":"Hành động điều khiển và định hướng một phương tiện như ô tô hoặc xe buýt từ nơi này đến nơi khác."},"508":{"word":"khóc","meaning":"Chảy nước mắt từ mắt, thường kèm theo tiếng động biểu hiện sự buồn bã, đau đớn hoặc cảm xúc mạnh."},"509":{"word":"cười","meaning":"Tạo ra âm thanh và biểu cảm khuôn mặt như miệng mở, mắt sáng, thể hiện sự vui vẻ hoặc thích thú."},"510":{"word":"won","meaning":"Đơn vị tiền tệ chính thức của Hàn Quốc, được thể hiện bằng tiền giấy và tiền xu với các giá trị cụ thể."},"511":{"word":"tháng","meaning":"Một trong mười hai khoảng thời gian mà một năm được chia thành, ví dụ như tháng Giêng hoặc tháng Mười Hai."},"512":{"word":"thứ Hai","meaning":"Ngày làm việc hoặc đi học chính thức đầu tiên sau cuối tuần, thường được hiển thị trên lịch là T2 hoặc Th."},"513":{"word":"trên","meaning":"Vị trí cao hơn một vật khác hoặc trực tiếp ở phía trên vật đó."},"514":{"word":"nổi tiếng","meaning":"Một người, địa điểm hoặc sự vật được nhiều người nhận biết và biết đến."},"515":{"word":"tháng sáu","meaning":"Đây là tháng thứ sáu trong năm, thường là lúc mùa hè bắt đầu ở bán cầu bắc."},"516":{"word":"sáu","meaning":"Đây là số tự nhiên tiếp theo số năm và đứng trước số bảy."},"517":{"word":"sáu mươi","meaning":"Đây là số tự nhiên bằng mười lần số sáu."},"518":{"word":"ngân hàng","meaning":"Đây là một tổ chức tài chính nơi mọi người gửi tiền, vay tiền và thực hiện các giao dịch khác."},"519":{"word":"ừm","meaning":"Từ này được dùng để thể hiện sự suy nghĩ, do dự hoặc cân nhắc điều gì đó."},"520":{"word":"đồ uống","meaning":"Đây là bất kỳ loại chất lỏng nào khác ngoài nước lọc, được dùng để giải khát hoặc thưởng thức."},"521":{"word":"thức ăn","meaning":"Đây là bất kỳ chất nào như thịt, rau, hoặc bánh mì mà con người hoặc động vật ăn để sống và phát triển."},"522":{"word":"âm nhạc","meaning":"Đây là những âm thanh được sắp xếp theo nhịp điệu, giai điệu và hòa âm để con người nghe giải trí hoặc thể hiện cảm xúc."},"523":{"word":"bác sĩ","meaning":"Đây là người có chuyên môn được đào tạo để khám bệnh, chẩn đoán và điều trị cho người bệnh."},"524":{"word":"ghế","meaning":"Đây là một món đồ nội thất có lưng tựa và bốn chân, được thiết kế cho một người ngồi."},"525":{"word":"này","meaning":"Từ này dùng để chỉ một người, vật hoặc ý tưởng cụ thể ở gần người nói."},"526":{"word":"hai","meaning":"Đây là số tự nhiên tiếp theo số một và đứng trước số ba."},"527":{"word":"cái này","meaning":"Từ dùng để chỉ một đồ vật, con vật hoặc người ở gần người nói."},"528":{"word":"lát nữa","meaning":"Sau một khoảng thời gian ngắn kể từ hiện tại."},"529":{"word":"tên","meaning":"Từ hoặc cụm từ dùng để gọi, nhận biết một người, con vật, địa điểm hoặc vật thể."},"530":{"word":"lần này","meaning":"Khoảng thời gian hoặc dịp cụ thể đang diễn ra."},"531":{"word":"hai mươi","meaning":"Số lượng tương đương với hai lần mười đơn vị, viết là 20."},"532":{"word":"câu chuyện","meaning":"Lời nói hoặc bài viết dùng để kể cho người khác nghe về một sự việc, hiện tượng, kinh nghiệm hay suy nghĩ."},"533":{"word":"tháng Hai","meaning":"Tháng thứ hai trong lịch dương, thường có 28 hoặc 29 ngày."},"534":{"word":"lý do","meaning":"Nguyên nhân hoặc lời giải thích khiến một sự việc xảy ra hoặc tồn tại theo một cách nào đó."},"535":{"word":"phía này","meaning":"Hướng gần người nói, một vị trí gần đó hoặc một cá nhân đang đứng rất gần."},"536":{"word":"Indonesia","meaning":"Một quốc gia lớn ở Đông Nam Á gồm hàng nghìn hòn đảo, nổi tiếng với khí hậu ấm áp và văn hóa đa dạng."},"537":{"word":"suất ăn","meaning":"Lượng thức ăn cụ thể dành cho một người, thường được bày trên đĩa."},"538":{"word":"lời chào","meaning":"Lời nói hoặc hành động, như cúi chào hoặc vẫy tay, dùng để nhận ra ai đó khi gặp hoặc chia tay."},"539":{"word":"Incheon","meaning":"Incheon là một thành phố cảng lớn nằm ở bờ biển phía tây Hàn Quốc, nổi tiếng với sân bay quốc tế."},"540":{"word":"Internet","meaning":"Internet là một hệ thống mạng máy tính toàn cầu giúp người dùng truy cập thông tin, giao tiếp và chia sẻ nội dung số."},"541":{"word":"công việc","meaning":"Công việc là một hoạt động đòi hỏi nỗ lực tinh thần hoặc thể chất để đạt được mục tiêu nào đó hoặc kiếm tiền."},"542":{"word":"một","meaning":"\"Một\" là số lượng biểu thị một vật thể hoặc một đơn vị duy nhất."},"543":{"word":"ngày","meaning":"\"Ngày\" là một chu kỳ 24 giờ hoàn chỉnh, hoặc khoảng thời gian có ánh sáng giữa mặt trời mọc và lặn."},"544":{"word":"bảy","meaning":"\"Bảy\" là số lượng được biểu thị bằng chữ số 7."},"545":{"word":"Nhật Bản","meaning":"Nhật Bản là một quốc gia hải đảo ở Đông Á, nổi tiếng với văn hóa độc đáo và công nghệ tiên tiến."},"546":{"word":"thức dậy","meaning":"\"Thức dậy\" là hành động chuyển từ tư thế nằm hoặc ngồi sang tư thế thẳng đứng, hoặc để chỉ việc một sự kiện nào đó xảy ra."},"547":{"word":"Chủ Nhật","meaning":"Chủ Nhật là ngày cuối cùng trong chuỗi bảy ngày của tuần, thường là ngày nghỉ ngơi."},"548":{"word":"tháng Một","meaning":"Tháng Một là tháng đầu tiên trong mười hai tháng của một năm, thường mang theo không khí lạnh giá."},"549":{"word":"một tuần","meaning":"\"Một tuần\" là một khoảng thời gian liên tục gồm bảy ngày."},"550":{"word":"sớm","meaning":"\"Sớm\" là xảy ra hoặc đến trước thời điểm thông thường hoặc dự kiến."},"551":{"word":"bảy mươi","meaning":"Đây là số đếm biểu thị tổng của bảy nhóm mười."},"552":{"word":"đọc","meaning":"Nhìn vào chữ viết hoặc biểu tượng và hiểu ý nghĩa của chúng, đôi khi bằng cách nói to."},"553":{"word":"miệng","meaning":"Bộ phận trên khuôn mặt dùng để ăn uống và phát ra âm thanh."},"554":{"word":"mặc","meaning":"Khoác hoặc trùm quần áo lên cơ thể."},"555":{"word":"có","meaning":"Tồn tại ở một vị trí cụ thể hoặc sở hữu một vật nào đó."},"556":{"word":"ngủ","meaning":"Nghỉ ngơi với đôi mắt nhắm và cơ thể bất động, thường là nằm xuống trong một thời gian dài."},"557":{"word":"ô tô","meaning":"Một loại phương tiện bốn bánh di chuyển trên đường, thường dùng để chở người hoặc hàng hóa."},"558":{"word":"xe đạp","meaning":"Phương tiện có hai bánh mà một người đẩy bằng cách đạp bàn đạp bằng chân."},"559":{"word":"thường xuyên","meaning":"Diễn tả một hành động hoặc sự việc xảy ra lặp đi lặp lại nhiều lần."},"560":{"word":"năm ngoái","meaning":"Khoảng thời gian mười hai tháng ngay trước năm hiện tại."},"561":{"word":"nhỏ","meaning":"Có kích thước vật lý ít hơn mức trung bình hoặc điển hình của loại đó."},"562":{"word":"cái cốc","meaning":"Vật chứa nhỏ dùng để uống nước, trà, v.v."},"563":{"word":"tốt, giỏi","meaning":"Theo cách thức thành thạo, thành công hoặc đúng đắn."},"564":{"word":"lỗi, sai lầm","meaning":"Một hành động hoặc sự hiểu biết không đúng, hoặc thực hiện điều gì đó một cách không chính xác."},"565":{"word":"giỏi, làm tốt","meaning":"Thực hiện một hoạt động một cách thành thạo, đạt được trình độ cao."},"566":{"word":"giấc ngủ","meaning":"Trạng thái mà một người nhắm mắt, cơ thể bất động và tâm trí nghỉ ngơi, thường trong vài giờ."},"567":{"word":"một lát, chốc lát","meaning":"Trong một khoảng thời gian rất ngắn."},"568":{"word":"một lúc, tạm thời","meaning":"Trong một khoảng thời gian ngắn."},"569":{"word":"dùng bữa, ăn (kính ngữ)","meaning":"Người đáng kính đưa thức ăn vào miệng và nuốt để thỏa mãn cơn đói."},"570":{"word":"miến trộn (Hàn Quốc)","meaning":"Một món ăn Hàn Quốc làm từ miến khoai lang trộn với các loại rau củ, thịt... thái mỏng xào."},"571":{"word":"địa điểm, nơi chốn","meaning":"Một khu vực hoặc vị trí cụ thể, như công viên, tòa nhà, hoặc căn phòng, nơi một cái gì đó tồn tại hoặc một sự kiện xảy ra."},"572":{"word":"không thú vị, chán","meaning":"Một tình huống, câu chuyện hoặc hoạt động không làm mọi người giải trí hoặc giữ được sự chú ý của họ, khiến họ cảm thấy thờ ơ."},"573":{"word":"thú vị, hay","meaning":"Một tình huống, câu chuyện hoặc hoạt động thu hút sự chú ý của mọi người hoặc khiến họ cười và cảm thấy được giải trí."},"574":{"word":"kia, đó","meaning":"Đại từ dùng để chỉ một vật hoặc người ở xa cả người nói và người nghe."},"575":{"word":"kia","meaning":"Từ dùng để chỉ người hoặc vật ở xa người nói."},"576":{"word":"Này","meaning":"Thán từ dùng để thu hút sự chú ý của ai đó, thường đi kèm cử chỉ chỉ tay."},"577":{"word":"cái kia","meaning":"Từ dùng để chỉ một vật thể cụ thể ở xa cả người nói và người nghe."},"578":{"word":"đằng kia","meaning":"Từ dùng để chỉ một địa điểm hoặc khu vực ở xa người nói."},"579":{"word":"buổi tối","meaning":"Khoảng thời gian mặt trời lặn hoặc đã lặn, thường là lúc mọi người dùng bữa chính cuối cùng trong ngày."},"580":{"word":"phía kia","meaning":"Từ dùng để chỉ một phía hoặc hướng cụ thể ở xa người nói."},"581":{"word":"ít","meaning":"Có số lượng, khối lượng hoặc mức độ không nhiều."},"582":{"word":"cựu","meaning":"Dùng để chỉ người đã từng giữ một vị trí hay chức vụ cụ thể nhưng hiện tại không còn."},"583":{"word":"chuyên ngành","meaning":"Môn học chính mà một sinh viên đại học hoặc cao đẳng tập trung nghiên cứu sâu."},"584":{"word":"điện thoại","meaning":"Thiết bị có nút hoặc màn hình mà mọi người dùng để nói chuyện với người không ở gần."},"585":{"word":"số điện thoại","meaning":"Một dãy số duy nhất mà ai đó nhập hoặc quay để liên lạc với một thiết bị hoặc người cụ thể."},"586":{"word":"bữa trưa","meaning":"Bữa ăn chính mà mọi người thường ăn vào khoảng giữa trưa, sau bữa sáng và trước bữa tối."},"587":{"word":"trạm dừng","meaning":"Địa điểm quy định dọc theo tuyến đường để các phương tiện giao thông công cộng như xe buýt, tàu hỏa đón và trả khách."},"588":{"word":"thật sự","meaning":"Từ dùng để diễn tả điều gì đó là rất đúng hoặc ở mức độ cao."},"589":{"word":"tôi (khiêm tốn)","meaning":"Đại từ ngôi thứ nhất dùng để chỉ bản thân một cách khiêm tốn hoặc lịch sự khi nói chuyện với người khác."},"590":{"word":"nhất","meaning":"Từ dùng để diễn tả một sự vật, sự việc đạt đến mức độ cao nhất hoặc tốt nhất trong số tất cả."},"591":{"word":"đảo Jeju","meaning":"Một hòn đảo lớn và nổi tiếng nằm ngoài khơi bờ biển phía nam bán đảo Triều Tiên."},"592":{"word":"một chút","meaning":"Từ chỉ một lượng nhỏ hoặc mức độ nhẹ của một cái gì đó."},"593":{"word":"yên tĩnh","meaning":"Mô tả một nơi hoặc tình huống có rất ít hoặc không có âm thanh, tiếng ồn."},"594":{"word":"tốt nghiệp","meaning":"Việc hoàn thành thành công chương trình học tại trường hoặc đại học và nhận bằng cấp."},"595":{"word":"một chút","meaning":"Từ dùng để diễn tả một mức độ nhỏ hoặc để làm cho lời yêu cầu, đề nghị trở nên nhẹ nhàng, lịch sự hơn."},"596":{"word":"nhân viên","meaning":"Người làm việc cho một công ty, doanh nghiệp hoặc tổ chức khác và nhận lương cho công việc của mình."},"597":{"word":"tốt","meaning":"Mô tả một điều gì đó dễ chịu, đáng mong muốn hoặc đạt tiêu chuẩn cao."},"598":{"word":"thích","meaning":"Có cảm tình tốt hoặc thấy hài lòng về một người hoặc một vật gì đó."},"599":{"word":"xin lỗi","meaning":"Cảm thấy hối hận hoặc có lỗi vì đã làm sai điều gì đó."},"600":{"word":"tuần","meaning":"Khoảng thời gian gồm bảy ngày liên tiếp."},"601":{"word":"cho","meaning":"Đưa một vật gì đó cho người khác."},"602":{"word":"chủ yếu","meaning":"Diễn tả điều gì đó chiếm phần lớn nhất hoặc xảy ra trong khoảng thời gian nhiều nhất."},"603":{"word":"cuối tuần","meaning":"Hai ngày thứ Bảy và Chủ Nhật sau những ngày làm việc trong tuần."},"604":{"word":"ngủ (kính ngữ)","meaning":"Nằm xuống, nhắm mắt và nghỉ ngơi để phục hồi sức khỏe (dùng cho người lớn tuổi hoặc đáng kính)."},"605":{"word":"nội trợ","meaning":"Người phụ nữ quản lý công việc gia đình, chăm sóc chồng con và nhà cửa."},"606":{"word":"địa chỉ","meaning":"Thông tin cụ thể về vị trí một tòa nhà hoặc nơi ở, nơi làm việc, bao gồm tên đường, thành phố và quốc gia."},"607":{"word":"nước ép","meaning":"Đồ uống dạng lỏng có vị ngọt hoặc chua, được ép từ trái cây hoặc rau củ."},"608":{"word":"chủ","meaning":"Người sở hữu một vật thể hoặc tài sản."},"609":{"word":"tuần lễ","meaning":"Khoảng thời gian dài bảy ngày liên tục."},"610":{"word":"sự chuẩn bị","meaning":"Hành động sắp xếp hoặc làm mọi thứ sẵn sàng trước cho một sự kiện, hoạt động hoặc hành động trong tương lai."},"611":{"word":"trong","meaning":"Một danh từ phụ thuộc dùng để chỉ thời điểm một sự việc đang diễn ra."},"612":{"word":"Trung Quốc","meaning":"Tên một quốc gia rộng lớn nằm ở Đông Á."},"613":{"word":"ví","meaning":"Một vật dụng nhỏ, thường làm bằng da hoặc vải, dùng để đựng tiền, thẻ và giấy tờ tùy thân."},"614":{"word":"bây giờ","meaning":"Thời điểm hiện tại, khoảnh khắc đang xảy ra."},"615":{"word":"qua","meaning":"Di chuyển vượt qua một điểm hoặc một khoảng thời gian kết thúc."},"616":{"word":"tháng trước","meaning":"Khoảng thời gian khoảng ba mươi ngày ngay trước tháng hiện tại."},"617":{"word":"tuần trước","meaning":"Khoảng thời gian bảy ngày ngay trước tuần hiện tại."},"618":{"word":"năm ngoái","meaning":"Khoảng thời gian mười hai tháng ngay trước năm hiện tại."},"619":{"word":"sống","meaning":"Tiếp tục tồn tại ở một nơi hoặc trong một tình trạng cụ thể trong một khoảng thời gian."},"620":{"word":"cục tẩy","meaning":"Một vật nhỏ bằng cao su hoặc nhựa dùng để xóa vết bút chì hoặc bút mực."},"621":{"word":"tàu điện ngầm","meaning":"Một hệ thống tàu hỏa vận chuyển hành khách chủ yếu chạy dưới lòng đất trong thành phố."},"622":{"word":"ga tàu điện ngầm","meaning":"Một địa điểm cụ thể nơi tàu điện ngầm dừng lại để hành khách lên xuống."},"623":{"word":"Nghề nghiệp","meaning":"Hoạt động thường xuyên mà một người làm để kiếm sống, thường đòi hỏi các kỹ năng chuyên biệt."},"624":{"word":"Nhân viên","meaning":"Người làm việc cho một công ty hoặc tổ chức và nhận tiền lương định kỳ."},"625":{"word":"Câu hỏi","meaning":"Hành động hỏi một điều gì đó mà mình không biết hoặc muốn biết."},"626":{"word":"Nhà","meaning":"Cấu trúc do người hoặc động vật xây dựng để bảo vệ khỏi lạnh, nóng, v.v., và làm nơi ở."},"627":{"word":"Mặn","meaning":"Chỉ thức ăn hoặc đồ uống có vị natri clorua mạnh, thường gây khát."},"628":{"word":"Hướng, phía","meaning":"Một khu vực hoặc vị trí cụ thể nằm tương đối với trung tâm hoặc vật thể khác, thường chỉ định một hướng chung."},"629":{"word":"Đóng","meaning":"Dùng một vật có bề mặt cụ thể tác động mạnh lên một bề mặt khác để tạo ra dấu ấn hoặc hình ảnh."},"630":{"word":"Thật, rất","meaning":"Từ dùng trước một từ miêu tả khác để nhấn mạnh mức độ mạnh mẽ hoặc phạm vi của một điều gì đó."},"631":{"word":"Dưa vàng","meaning":"Loại quả màu vàng, hình bầu dục, có sọc trắng trên vỏ, thường được ăn sống, có vị ngọt và mọng nước."},"632":{"word":"Cửa sổ","meaning":"Một ô trống trên tường hoặc mái nhà được làm để không khí hoặc ánh sáng đi vào."},"633":{"word":"Tìm thấy","meaning":"Thành công xác định vị trí của một vật hoặc người sau khi đã tích cực tìm kiếm."},"634":{"word":"Tìm kiếm","meaning":"Tích cực cố gắng xác định vị trí một vật hoặc người bằng cách kiểm tra kỹ các nơi hoặc đặt câu hỏi."},"635":{"word":"sách","meaning":"Vật dùng để đọc, thường là các trang giấy có in chữ và hình ảnh được đóng thành tập."},"636":{"word":"bàn học","meaning":"Món đồ nội thất có mặt phẳng, thường có ngăn kéo, dùng để viết, đọc hoặc sử dụng máy tính."},"637":{"word":"lần đầu","meaning":"Thời điểm hoặc trình tự xuất hiện trước tất cả những cái khác."},"638":{"word":"nghìn","meaning":"Một số lượng biểu thị bởi con số 1.000, gấp mười lần một trăm."},"639":{"word":"mười triệu","meaning":"Một số lượng rất lớn biểu thị bởi con số 10.000.000, bằng một trăm lần một trăm nghìn."},"640":{"word":"chậm rãi","meaning":"Di chuyển hoặc hành động với tốc độ thư thả, mất nhiều thời gian để hoàn thành một việc."},"641":{"word":"dọn dẹp","meaning":"Hành động loại bỏ bụi bẩn, rác hoặc sự lộn xộn khỏi một nơi để làm cho nó gọn gàng và sạch sẽ."},"642":{"word":"lời mời","meaning":"Yêu cầu bằng văn bản hoặc lời nói để ai đó đến một sự kiện, một bữa tiệc hoặc một địa điểm cụ thể."},"643":{"word":"sô-cô-la","meaning":"Món ăn ngọt, màu sẫm, được làm bằng cách trộn bột ca cao, sữa, đường và các nguyên liệu khác."},"644":{"word":"nhảy","meaning":"Di chuyển cơ thể theo nhịp điệu, thường là theo nhạc, như một hình thức biểu cảm hoặc giải trí."},"645":{"word":"bóng đá","meaning":"Môn thể thao đồng đội chơi với một quả bóng giữa hai đội gồm mười một cầu thủ."},"646":{"word":"chúc mừng","meaning":"Hành động bày tỏ niềm vui và sự hoan nghênh đối với một dịp vui, thành tựu của ai đó."},"647":{"word":"sự khởi hành","meaning":"Hành động rời một nơi nào đó để bắt đầu một chuyến đi hoặc hoạt động."},"648":{"word":"điệu nhảy","meaning":"Một chuỗi các chuyển động nhịp nhàng của cơ thể, thường được thực hiện theo nhạc để giải trí hoặc biểu diễn."},"649":{"word":"nhảy, múa","meaning":"Di chuyển cơ thể theo nhịp điệu của âm nhạc, thường mang tính biểu diễn hoặc biểu cảm."},"650":{"word":"lạnh, rét","meaning":"Có nhiệt độ thấp, gây ra cảm giác thiếu ấm áp."},"651":{"word":"sở thích","meaning":"Một hoạt động mà một người thực hiện thường xuyên để giải trí và thư giãn, đặc biệt trong thời gian rảnh rỗi."},"652":{"word":"tầng","meaning":"Một trong các mặt sàn của một tòa nhà, được xây dựng theo chiều ngang."},"653":{"word":"đánh, đập","meaning":"Tác động vật lý vào một vật gì đó một cách nhanh chóng và mạnh mẽ, thường gây ra âm thanh hoặc sự dịch chuyển."},"654":{"word":"váy","meaning":"Một loại trang phục mặc từ thắt lưng trở xuống, che phủ một phần hoặc toàn bộ chân, thường được phụ nữ mặc."},"655":{"word":"bạn bè","meaning":"Một người mà mình có mối quan hệ thân thiết, thường dành thời gian vui vẻ bên nhau và hỗ trợ lẫn nhau."},"656":{"word":"sự tử tế","meaning":"Phẩm chất tốt bụng, hào phóng và quan tâm đến người khác, thường thể hiện qua lời nói hoặc hành động giúp đỡ."},"657":{"word":"thân thiết","meaning":"Mối quan hệ giữa những người thường xuyên gặp gỡ, nói chuyện dễ dàng và thích làm mọi việc cùng nhau vì họ hiểu nhau rất rõ."},"658":{"word":"bảy","meaning":"Số tự nhiên đứng sau số sáu và trước số tám."},"659":{"word":"Bảy mươi","meaning":"Số tự nhiên được biểu thị bằng chữ số 70, đứng sau số sáu mươi chín."},"660":{"word":"Tháng bảy","meaning":"Tháng thứ bảy trong năm, sau tháng sáu và trước tháng tám, thường có thời tiết nóng bức."},"661":{"word":"Bảng đen","meaning":"Một tấm bảng, thường có màu xanh đậm hoặc đen, dùng để viết bằng phấn."},"662":{"word":"Giường","meaning":"Một món đồ nội thất, thường gồm khung và nệm mềm, dùng để ngủ hoặc nghỉ ngơi."},"663":{"word":"Thẻ","meaning":"Một mảnh giấy hoặc nhựa nhỏ, phẳng, hình chữ nhật, dùng để định danh, thanh toán hoặc chơi trò chơi."},"664":{"word":"Máy ảnh","meaning":"Thiết bị quang học dùng ống kính để chụp và ghi lại ảnh tĩnh hoặc video."},"665":{"word":"Canada","meaning":"Một quốc gia rộng lớn ở phía bắc Bắc Mỹ, có thủ đô là Ottawa."},"666":{"word":"Cà phê","meaning":"Đồ uống được pha từ hạt cà phê đã rang, xay và đun sôi, hoặc bột của nó."},"667":{"word":"Quán cà phê","meaning":"Một cửa hàng được thiết kế cho khách hàng nói chuyện hoặc nghỉ ngơi, thường là khi uống cà phê hoặc trà."},"668":{"word":"Máy tính","meaning":"Một thiết bị điện tử có màn hình và bàn phím, có khả năng xử lý dữ liệu, thực hiện tính toán và hiển thị thông tin."},"669":{"word":"Cốc","meaning":"Một đồ dùng hình trụ, thường có quai, dùng để chứa và uống đồ uống."},"670":{"word":"Bánh kem","meaning":"Một loại thực phẩm ngọt làm từ bột mì, đường và trứng, thường được trang trí bằng kem và phục vụ trong các bữa tiệc."},"671":{"word":"bật","meaning":"Làm cho một thiết bị hoạt động hoặc phát ra ánh sáng."},"672":{"word":"mũi","meaning":"Bộ phận trên khuôn mặt của người hoặc động vật, nằm giữa hai mắt và phía trên miệng, dùng để ngửi và thở."},"673":{"word":"buổi hòa nhạc","meaning":"Một sự kiện công cộng nơi các nhạc sĩ biểu diễn nhạc sống cho khán giả."},"674":{"word":"Coca-Cola","meaning":"Một loại nước ngọt có ga màu đen, vị ngọt và mùi thơm đặc trưng."},"675":{"word":"lớn","meaning":"Có kích thước rộng rãi hoặc phát triển về chiều cao hay chiều rộng."},"676":{"word":"chiều cao","meaning":"Số đo từ dưới lên trên của một người hoặc vật."},"677":{"word":"cháy","meaning":"Bị lửa thiêu hủy hoặc biến thành tro do nhiệt độ cao và ngọn lửa."},"678":{"word":"lên (xe)","meaning":"Bước vào hoặc leo lên một phương tiện để di chuyển từ nơi này đến nơi khác."},"679":{"word":"bóng bàn","meaning":"Một trò chơi trong nhà với hai hoặc bốn người chơi dùng vợt nhỏ đánh bóng qua lưới trên một mặt bàn cứng."},"680":{"word":"Thái Lan","meaning":"Một quốc gia nằm ở bán đảo Đông Dương, Đông Nam Á."},"681":{"word":"Taekwondo","meaning":"Một môn võ và thể thao chiến đấu của Hàn Quốc, nổi bật với các cú đá nhanh, cao và đòn tay mạnh mẽ."},"682":{"word":"taxi","meaning":"Một loại xe ô tô có tài xế mà bạn trả tiền để chở bạn đến một địa điểm cụ thể."},"683":{"word":"Bến xe","meaning":"Nơi tập trung nhiều phương tiện giao thông như xe buýt, tàu hỏa hoặc máy bay dừng lại để đón và trả khách."},"684":{"word":"Quần vợt","meaning":"Một môn thể thao dùng vợt đánh bóng qua lưới trên sân hình chữ nhật, thường chơi giữa hai hoặc bốn người."},"685":{"word":"Ti vi","meaning":"Thiết bị điện tử có màn hình và loa, dùng để xem các chương trình truyền hình hoặc phim ảnh."},"686":{"word":"Thứ Bảy","meaning":"Ngày thứ sáu trong tuần, sau thứ Sáu và trước Chủ Nhật, thường là ngày bắt đầu cuối tuần."},"687":{"word":"Tan sở","meaning":"Việc rời khỏi nơi làm việc sau khi hoàn thành công việc trong ngày."},"688":{"word":"Đặc biệt","meaning":"Có sự khác biệt đáng chú ý so với thông thường, nổi bật hoặc được coi trọng hơn."},"689":{"word":"Đặc biệt","meaning":"Hơn hẳn những thứ khác hoặc hơn những gì bình thường; đáng chú ý hơn."},"690":{"word":"Áo phông","meaning":"Loại áo đơn giản, tay ngắn, không cổ hoặc không cúc, thường mặc cho phần thân trên."},"691":{"word":"Bữa tiệc","meaning":"Buổi tụ họp xã hội của nhiều người để vui chơi, kỷ niệm hoặc một dịp đặc biệt nào đó."},"692":{"word":"Cánh tay","meaning":"Bộ phận của cơ thể người nối liền từ vai đến bàn tay."},"693":{"word":"Tám","meaning":"Con số tiếp theo số bảy và đứng trước số chín."},"694":{"word":"Bán","meaning":"Đổi một vật gì đó, quyền lợi hoặc công sức lấy tiền."},"695":{"word":"tám mươi","meaning":"Số đếm sau bảy mươi chín và trước tám mươi mốt."},"696":{"word":"tháng Tám","meaning":"Tháng thứ tám trong năm, sau tháng Bảy và trước tháng Chín."},"697":{"word":"cửa hàng tiện lợi","meaning":"Cửa hàng nhỏ mở cửa trong nhiều giờ, bán đồ uống, đồ ăn vặt và các mặt hàng thiết yếu hàng ngày."},"698":{"word":"thư, lá thư","meaning":"Văn bản viết tay hoặc in ấn dùng để truyền đạt thông tin hoặc cảm xúc cho người nhận."},"699":{"word":"nho","meaning":"Loại trái cây nhỏ, có màu tím, mọc thành chùm, vị ngọt và hơi chua."},"700":{"word":"vé","meaning":"Một mảnh giấy hoặc thẻ nhỏ cho phép người nào đó vào cửa, đi xe hoặc xem biểu diễn."},"701":{"word":"Pháp","meaning":"Một quốc gia ở Tây Âu, nổi tiếng với nghệ thuật, ẩm thực và các địa danh như Tháp Eiffel."},"702":{"word":"chương trình","meaning":"Danh sách các kế hoạch hoặc chi tiết của một sự kiện."},"703":{"word":"sự mệt mỏi","meaning":"Trạng thái cơ thể cảm thấy rất cần nghỉ ngơi hoặc ngủ vì đã tiêu hao năng lượng."},"704":{"word":"đàn piano","meaning":"Một loại nhạc cụ tạo ra âm thanh khi dùng ngón tay gõ hoặc nhấn vào các phím đen trắng của nó."},"705":{"word":"nở hoa","meaning":"(Dùng cho hoa) cánh hoa mở ra, khoe trọn hình dáng và màu sắc."},"706":{"word":"sự cần thiết, nhu cầu","meaning":"Tình trạng một điều gì đó là thiết yếu mà một người phải có, đạt được hoặc hoàn thành."},"707":{"word":"hộp bút","meaning":"Một hộp nhỏ hoặc túi dùng để đựng dụng cụ viết như bút, bút chì và cục tẩy."},"708":{"word":"một","meaning":"Số nguyên dương đầu tiên, biểu thị một vật hoặc một đơn vị."},"709":{"word":"làm","meaning":"Thực hiện một hành động, hoạt động hoặc động tác nhất định."},"710":{"word":"một ngày","meaning":"Khoảng thời gian 24 giờ từ nửa đêm đến nửa đêm tiếp theo."},"711":{"word":"nhà trọ","meaning":"Một ngôi nhà riêng nơi mọi người trả tiền để thuê phòng trong một khoảng thời gian và đôi khi cũng được cung cấp bữa ăn."},"712":{"word":"nhưng, tuy nhiên","meaning":"Từ dùng để giới thiệu một câu nói thể hiện sự khác biệt hoặc ý tưởng đối lập với thông tin vừa được đưa ra."},"713":{"word":"trường học","meaning":"Một tòa nhà hoặc tổ chức nơi trẻ em và thanh thiếu niên đến để học bài và tiếp thu kiến thức."},"714":{"word":"học sinh, sinh viên","meaning":"Người thường xuyên theo học tại một nơi học tập để tiếp thu kiến thức."},"715":{"word":"thẻ sinh viên","meaning":"Một thẻ nhựa có ảnh và tên để chứng minh một người đang theo học tại một cơ sở giáo dục."},"716":{"word":"một","meaning":"Biểu thị một thực thể, vật phẩm hoặc cá nhân duy nhất, không hơn số lượng đó."},"717":{"word":"rảnh rỗi, nhàn rỗi","meaning":"Khi một người không có việc gì phải làm và có thể thư giãn hoặc giải trí."},"718":{"word":"Hàn Quốc","meaning":"Một quốc gia nằm trên bán đảo ở Đông Á, được nhận biết bởi lá cờ và truyền thống văn hóa riêng biệt."},"719":{"word":"Hanbok","meaning":"Trang phục truyền thống đặc trưng của Hàn Quốc, thường được mặc trong các dịp lễ đặc biệt hoặc kỷ niệm."},"720":{"word":"bà","meaning":"Người phụ nữ là mẹ của cha hoặc mẹ của mẹ mình, hoặc cách gọi một người phụ nữ lớn tuổi."},"721":{"word":"ông","meaning":"Người đàn ông là cha của cha hoặc cha của mẹ mình, hoặc cách gọi một người đàn ông lớn tuổi."},"722":{"word":"cùng nhau","meaning":"Ở chung một chỗ hoặc cùng thực hiện một hành động tại cùng một thời điểm với người hoặc vật khác."},"723":{"word":"anh (trai)","meaning":"Từ dùng bởi người nam để gọi hoặc chỉ người anh ruột hoặc anh họ lớn tuổi hơn mình."},"724":{"word":"số, tập","meaning":"Từ dùng kèm với số để chỉ một ấn phẩm cụ thể (như tạp chí, sách) trong một loạt số đã được đánh số."},"725":{"word":"khách sạn","meaning":"Tòa nhà lớn có nhiều phòng cho thuê để khách ở lại, ăn uống và sử dụng các dịch vụ khác khi đi du lịch hoặc xa nhà."},"726":{"word":"một mình","meaning":"Trong trạng thái tách biệt hoàn toàn khỏi người hoặc vật khác, thường là tự mình làm việc gì đó mà không có sự giúp đỡ."},"727":{"word":"thứ Ba","meaning":"Ngày thứ hai trong tuần, nằm giữa thứ Hai và thứ Tư."},"728":{"word":"nhà vệ sinh","meaning":"Căn phòng có bồn cầu để giải quyết nhu cầu vệ sinh cá nhân và bồn rửa tay."},"729":{"word":"công ty","meaning":"Một tổ chức kinh doanh bao gồm nhiều người làm việc cùng nhau để sản xuất hàng hóa hoặc cung cấp dịch vụ nhằm mục đích tạo ra lợi nhuận."},"730":{"word":"nhân viên công ty","meaning":"Người có công việc thường xuyên là làm việc tại văn phòng cho một doanh nghiệp hoặc tổ chức."},"731":{"word":"cuộc họp","meaning":"Một buổi gặp gỡ để nhiều người cùng thảo luận, chia sẻ thông tin hoặc đưa ra quyết định chung."},"732":{"word":"sau","meaning":"Diễn ra hoặc xuất hiện ở một thời điểm muộn hơn một sự kiện hoặc khoảnh khắc cụ thể."},"733":{"word":"kỳ nghỉ","meaning":"Một khoảng thời gian đã được lên kế hoạch để nghỉ làm hoặc nghỉ học, dùng để nghỉ ngơi, đi du lịch hoặc thực hiện các hoạt động cá nhân."},"734":{"word":"âm u","meaning":"Khi bầu trời có nhiều mây đen hoặc xám nhạt, khiến ánh nắng mặt trời trở nên mờ nhạt hoặc bị che khuất."},"735":{"word":"khó khăn","meaning":"Khi một hoạt động đòi hỏi nhiều sức lực thể chất hoặc tinh thần, khiến một người cảm thấy rất mệt mỏi hoặc căng thẳng."},"736":{"word":"gần","meaning":"Ở một vị trí hoặc di chuyển sao cho chỉ có một khoảng cách ngắn giữa các vật thể hoặc người."},"737":{"word":"thỉnh thoảng","meaning":"Xảy ra hoặc diễn ra chỉ một vài lần, không thường xuyên."},"738":{"word":"mảnh mai","meaning":"Có chiều rộng hoặc đường kính rất nhỏ so với chiều dài hoặc kích thước tổng thể."},"739":{"word":"đầy","meaning":"Với một số lượng hoặc khối lượng đạt đến dung tích tối đa."},"740":{"word":"chỉ","meaning":"Vươn ngón tay, bàn tay hoặc vật khác về phía một cái gì đó để cho biết vị trí hoặc hướng của nó."},"741":{"word":"ngực","meaning":"Phần phía trước của cơ thể người hoặc động vật, nằm giữa cổ và bụng."},"742":{"word":"cái kéo","meaning":"Một dụng cụ có hai lưỡi sắc bén nối với nhau ở giữa, dùng để cắt giấy, vải hoặc tóc bằng cách mở và đóng tay cầm."},"743":{"word":"mang đi","meaning":"Cầm lấy vật gì đó và di chuyển nó đến một nơi khác, xa khỏi vị trí hiện tại."},"744":{"word":"mang đến, mang lại","meaning":"Đi đến một nơi khác để lấy đồ vật rồi mang về chỗ mình đang ở hoặc chỗ người nói."},"745":{"word":"mỗi, riêng từng cái","meaning":"Chỉ mỗi một trong số nhiều đối tượng, được xem xét riêng biệt."},"746":{"word":"đơn giản","meaning":"Có ít phần, ít bước, dễ hiểu hoặc không cần nhiều công sức để làm."},"747":{"word":"một cách đơn giản","meaning":"Làm việc gì đó một cách không phức tạp, nhanh gọn, không cần nhiều chi tiết."},"748":{"word":"đồ ăn vặt, bữa ăn nhẹ","meaning":"Món ăn nhẹ được ăn giữa các bữa chính để đỡ đói hoặc chỉ để thưởng thức."},"749":{"word":"nước tương","meaning":"Một loại nước chấm màu đen, vị mặn, dùng để nêm nếm hoặc chấm thức ăn."},"750":{"word":"y tá, điều dưỡng viên","meaning":"Người có chuyên môn, được đào tạo để chăm sóc người bệnh hoặc người bị thương, thường làm việc ở bệnh viện hoặc phòng khám."},"751":{"word":"màu nâu","meaning":"Màu giống màu đất hoặc màu của lá cây khô."},"752":{"word":"thay quần áo","meaning":"Cởi bỏ quần áo đang mặc và thay bằng quần áo khác."},"753":{"word":"thuốc cảm","meaning":"Loại thuốc dạng viên hoặc lỏng dùng để làm giảm các triệu chứng của bệnh cảm như sổ mũi, ho, đau họng."},"754":{"word":"nhắm (mắt)","meaning":"Khép hai mí mắt lại với nhau để không nhìn thấy gì, thường dùng khi ngủ hoặc nghỉ ngơi."},"755":{"word":"gội","meaning":"Làm sạch tóc bằng nước và xà phòng hoặc dầu gội."},"756":{"word":"khoai tây","meaning":"Một loại củ tròn mọc dưới đất, có vỏ màu nâu nhạt và ruột màu vàng nhạt."},"757":{"word":"đột nhiên","meaning":"Diễn ra hoặc xảy ra một cách nhanh chóng mà không có cảnh báo trước."},"758":{"word":"sông","meaning":"Một dòng nước tự nhiên rộng chảy qua đất liền, thường đổ ra biển hoặc hồ."},"759":{"word":"chó con","meaning":"Một con chó còn rất nhỏ, thường có kích thước bé và tính cách tinh nghịch."},"760":{"word":"mạnh","meaning":"Có nhiều sức mạnh thể chất hoặc năng lượng, hoặc có khả năng chịu đựng lực lớn mà không bị hỏng."},"761":{"word":"có, mang","meaning":"Giữ, sở hữu một cái gì đó, hoặc cầm nó trong tay."},"762":{"word":"trả, hoàn trả","meaning":"Hoàn lại những gì mình đã vay mượn."},"763":{"word":"tháng (đơn vị đếm)","meaning":"Đơn vị dùng để đếm thời gian khoảng 30 ngày, thường được thể hiện trên lịch."},"764":{"word":"cái, thứ","meaning":"Từ dùng để chỉ một vật, ý tưởng hoặc tình huống không cụ thể."},"765":{"word":"đường, phố","meaning":"Lối đi công cộng trong thị trấn hoặc thành phố, thường có các tòa nhà hai bên, nơi xe cộ và người đi lại."},"766":{"word":"khoảng cách","meaning":"Lượng không gian vật lý phân chia hai người, địa điểm hoặc vật thể."},"767":{"word":"gương","meaning":"Một vật làm bằng kính phẳng, sáng bóng, dùng để phản chiếu hình ảnh của người hoặc vật."},"768":{"word":"hầu hết, gần như","meaning":"Diễn tả mức độ, số lượng gần đạt đến mức hoàn toàn nhưng chưa hẳn là vậy."},"769":{"word":"từ chối","meaning":"Hành động không chấp nhận một yêu cầu, đề nghị hoặc lời mời."},"770":{"word":"lời nói dối, nói dối","meaning":"Lời nói không đúng sự thật nhằm lừa gạt hoặc đánh lừa người khác."},"771":{"word":"lo lắng, sự lo lắng","meaning":"Trạng thái cảm thấy không yên tâm, sợ hãi về một điều xấu có thể xảy ra."},"772":{"word":"đi qua, băng qua","meaning":"Di chuyển từ một bên sang bên đối diện của một con đường, khu vực hoặc vật cản."},"773":{"word":"băng qua, vượt qua","meaning":"Di chuyển qua một vật hoặc không gian để đến phía đối diện."},"774":{"word":"đi bộ","meaning":"Di chuyển bằng chân, đặt chân này trước chân kia để đến một nơi khác."},"775":{"word":"đi bộ đến","meaning":"Di chuyển bằng chân, đặt chân này trước chân kia để đến gần vị trí của người nói hoặc một địa điểm cụ thể."},"776":{"word":"bước chân","meaning":"Hành động nâng một chân lên và đặt về phía trước để tiến lên."},"777":{"word":"kiểm tra, sự kiểm tra","meaning":"Việc xem xét kỹ lưỡng để đánh giá, xác định tính đúng đắn, hiệu quả hoặc sự phù hợp với tiêu chuẩn."},"778":{"word":"màu đen","meaning":"Một màu rất tối, giống như bầu trời đêm không có ánh sáng hoặc màu mực đen."},"779":{"word":"màu đen","meaning":"Màu tối nhất, giống như màu mực tàu hoặc bầu trời đêm không ánh sáng."},"780":{"word":"bên ngoài, bề mặt","meaning":"Phần bên ngoài hoặc bề mặt có thể nhìn thấy của một vật thể."},"781":{"word":"lười biếng","meaning":"Không muốn làm việc hay hoạt động, chỉ thích nghỉ ngơi hoặc không làm gì cả."},"782":{"word":"kết quả","meaning":"Điều xảy ra hoặc được tạo ra ở cuối một hành động, sự kiện hoặc quá trình."},"783":{"word":"sự vắng mặt","meaning":"Tình trạng một người không có mặt ở nơi mà họ được mong đợi, như trường học hoặc nơi làm việc."},"784":{"word":"sự quyết tâm, sự quyết định","meaning":"Hành động kiên định chọn một con đường hoặc phương hướng hành động sau khi suy nghĩ kỹ lưỡng."},"785":{"word":"quyết định","meaning":"Lựa chọn cụ thể mà một người đưa ra từ nhiều khả năng, định hướng cho các hành động trong tương lai."},"786":{"word":"hôn nhân, sự kết hôn","meaning":"Sự kết nối chính thức giữa hai người thành vợ chồng, thường được tổ chức bằng một sự kiện đặc biệt."},"787":{"word":"lễ cưới","meaning":"Một sự kiện chính thức nơi hai người trở thành vợ chồng, với khách mời đến chứng kiến lời thề và các hoạt động ăn mừng."},"788":{"word":"trận đấu, cuộc thi đấu","meaning":"Một sự kiện có tổ chức mà trong đó các cá nhân hoặc đội thi đấu để giành chiến thắng theo các quy tắc nhất định."},"789":{"word":"cảnh sát","meaning":"Lực lượng giữ gìn trật tự xã hội và bảo vệ người dân, tài sản khỏi tội phạm; hoặc cơ quan chính phủ phụ trách các nhiệm vụ đó."},"790":{"word":"đồn cảnh sát, sở cảnh sát","meaning":"Tòa nhà nơi các sĩ quan cảnh sát làm việc và nơi mọi người trình báo tội phạm hoặc tìm kiếm sự giúp đỡ."},"791":{"word":"phong cảnh","meaning":"Khung cảnh thiên nhiên hoặc những gì có thể nhìn thấy được từ một địa điểm."},"792":{"word":"kinh nghiệm","meaning":"Sự từng trải, hiểu biết hoặc kỹ năng có được qua việc làm hoặc chứng kiến."},"793":{"word":"cầu thang","meaning":"Cấu trúc gồm nhiều bậc nối tiếp nhau, dùng để đi lên hoặc đi xuống giữa các tầng."},"794":{"word":"trứng gà","meaning":"Vật hình bầu dục có vỏ cứng do gà đẻ ra, thường dùng làm thực phẩm."},"795":{"word":"tính toán","meaning":"Việc thực hiện các phép tính số học để tìm ra tổng, số lượng hoặc kết quả."},"796":{"word":"đầu","meaning":"Bộ phận trên cùng của cơ thể người, chứa não và khuôn mặt, có thể cúi xuống hoặc ngẩng lên."},"797":{"word":"trường cấp ba","meaning":"Cơ sở giáo dục dành cho học sinh từ khoảng 14 đến 18 tuổi, trước khi vào đại học."},"798":{"word":"học sinh cấp ba","meaning":"Người đang theo học tại trường cấp ba, thường trong độ tuổi từ 14 đến 18."},"799":{"word":"cô","meaning":"Chị hoặc em gái của bố."},"800":{"word":"lo lắng","meaning":"Trạng thái suy nghĩ sâu sắc về một vấn đề khó khăn, gây ra sự bận tâm hoặc buồn phiền."},"801":{"word":"xe buýt tốc hành","meaning":"Loại xe khách lớn chạy đường dài giữa các thành phố với tốc độ cao và ít điểm dừng."},"802":{"word":"hỏng hóc","meaning":"Tình trạng máy móc hoặc thiết bị không hoạt động đúng cách hoặc ngừng hoạt động hoàn toàn."},"803":{"word":"tương ớt Gochujang","meaning":"Một loại gia vị đặc trưng của Hàn Quốc, có màu đỏ sẫm, được làm chủ yếu từ bột ớt."},"804":{"word":"sửa chữa","meaning":"Làm cho một vật bị hư hỏng hoặc không hoạt động trở lại trạng thái bình thường."},"805":{"word":"ngay lập tức","meaning":"Diễn tả việc gì đó sẽ xảy ra hoặc đến trong một thời gian rất ngắn kể từ hiện tại."},"806":{"word":"quả bóng","meaning":"Một vật hình tròn thường được dùng trong thể thao hoặc trò chơi để ném, đá hoặc đánh."},"807":{"word":"công chức","meaning":"Người được nhà nước hoặc thành phố tuyển dụng để thực hiện các nhiệm vụ phục vụ người dân."},"808":{"word":"nhà máy","meaning":"Một tòa nhà lớn hoặc một khu gồm nhiều tòa nhà nơi máy móc sản xuất hàng hóa trên quy mô lớn."},"809":{"word":"miễn phí","meaning":"Cái gì đó được nhận mà không phải trả tiền, không tốn sức lực hay công sức."},"810":{"word":"ngày nghỉ lễ","meaning":"Một ngày cụ thể trong năm mà hầu hết mọi người không phải đi làm hoặc đi học, thường để kỷ niệm một sự kiện quan trọng."},"811":{"word":"quá khứ","meaning":"Toàn bộ các sự kiện, hành động và thời gian đã xảy ra và không còn tiếp diễn nữa."},"812":{"word":"bánh kẹo","meaning":"Một phần nhỏ thức ăn, thường là ngọt hoặc mặn, được ăn giữa các bữa ăn chính."},"813":{"word":"mối quan hệ","meaning":"Cách thức cụ thể mà hai hoặc nhiều người, nhóm hoặc vật thể được gắn kết hoặc ảnh hưởng lẫn nhau."},"814":{"word":"du lịch","meaning":"Hoạt động đi thăm và ngắm nhìn nhiều địa điểm thú vị, thường là một phần của chuyến đi giải trí."},"815":{"word":"khách du lịch","meaning":"Người đi đến một nơi nào đó để tham quan, nghỉ ngơi hoặc giải trí."},"816":{"word":"điểm du lịch","meaning":"Một nơi có cảnh đẹp hoặc có ý nghĩa đặc biệt, thu hút nhiều người đến tham quan."},"817":{"word":"sự quan tâm","meaning":"Tình cảm hoặc suy nghĩ hướng về một người, sự việc nào đó."},"818":{"word":"quảng cáo","meaning":"Thông tin giới thiệu sản phẩm, dịch vụ hoặc sự kiện nhằm thu hút người mua hoặc người tham gia."},"819":{"word":"Gwangju","meaning":"Tên một thành phố lớn ở phía tây nam Hàn Quốc."},"820":{"word":"sách giáo khoa","meaning":"Sách dùng để giảng dạy và học tập các môn học trong trường học."},"821":{"word":"giáo viên","meaning":"Người làm nghề dạy học ở trường học."},"822":{"word":"giáo sư","meaning":"Người có học vị cao, giảng dạy và nghiên cứu tại trường đại học."},"823":{"word":"giáo dục","meaning":"Quá trình dạy và học nhằm truyền đạt kiến thức, kỹ năng và rèn luyện nhân cách."},"824":{"word":"chi phí đi lại","meaning":"Tiền phải trả cho việc di chuyển từ nơi này đến nơi khác, như vé xe buýt, vé tàu hoặc tiền xăng."},"825":{"word":"tai nạn giao thông","meaning":"Sự cố va chạm bất ngờ giữa các phương tiện hoặc giữa phương tiện với người/vật thể khác trên đường, gây thiệt hại hoặc thương tích."},"826":{"word":"sự trao đổi","meaning":"Hành động đưa một vật cho ai đó và nhận lại một vật khác từ họ."},"827":{"word":"nhà thờ","meaning":"Đây là một tòa nhà có cây thánh giá trên đỉnh, nơi các tín đồ Thiên Chúa giáo tụ tập để cầu nguyện và thờ phượng."},"828":{"word":"mây","meaning":"Đó là tập hợp các giọt nước nhỏ hoặc hạt băng lơ lửng trên bầu trời, thường có màu trắng hoặc xám."},"829":{"word":"canh","meaning":"Món ăn lỏng được nấu bằng cách đun sôi thịt, cá hoặc rau củ với nhiều nước."},"830":{"word":"trong nước","meaning":"Chỉ những gì xảy ra, tồn tại hoặc được đặt bên trong biên giới chính thức của một quốc gia."},"831":{"word":"mì","meaning":"Món ăn làm từ bột được cắt hoặc ép thành sợi dài, mỏng, thường được luộc và dùng với nước dùng hoặc nước sốt."},"832":{"word":"quốc tế","meaning":"Thuộc về hoặc liên quan đến nhiều quốc gia khác nhau trên thế giới."},"833":{"word":"quân nhân","meaning":"Người mặc quân phục, được huấn luyện để chiến đấu hoặc bảo vệ đất nước trong quân đội."},"834":{"word":"to","meaning":"Chỉ một vật có đường kính lớn hoặc chiều ngang rộng."},"835":{"word":"nướng","meaning":"Làm chín thức ăn bằng nhiệt khô trong lò hoặc trên lửa cho đến khi ăn được, thường tạo ra bề mặt vàng nâu."},"836":{"word":"tò mò","meaning":"Có mong muốn mạnh mẽ muốn biết hoặc tìm hiểu về một điều gì đó."},"837":{"word":"bông tai","meaning":"Một món trang sức trang trí được đeo gắn vào dái tai hoặc vành tai."},"838":{"word":"yêu mến","meaning":"Bày tỏ tình cảm và sự dịu dàng đối với một con vật nhỏ, em bé hoặc đồ vật vì chúng trông đáng yêu."},"839":{"word":"Dễ thương","meaning":"Có vẻ ngoài nhỏ nhắn, đáng yêu, khiến người khác cảm thấy ấm áp, yêu mến."},"840":{"word":"Phiền phức","meaning":"Chỉ sự việc, công việc gây khó chịu, mất công sức hoặc làm mình bực mình."},"841":{"word":"Quy tắc","meaning":"Luật lệ được đặt ra để nhiều người cùng tuân theo."},"842":{"word":"Cái đó","meaning":"Từ dùng để chỉ vật, con vật hoặc ý tưởng cụ thể đã được đề cập hoặc đang ở gần người nghe."},"843":{"word":"Nơi đó","meaning":"Từ dùng để chỉ một địa điểm cụ thể, không gần người nói."},"844":{"word":"Ngày đó","meaning":"Một khoảng thời gian cụ thể (một ngày) trong quá khứ hoặc tương lai đang được nhắc đến."},"845":{"word":"Cứ thế, chỉ là","meaning":"Chỉ việc làm gì đó không có lý do hay mục đích cụ thể, hoặc giữ nguyên trạng thái ban đầu."},"846":{"word":"Y nguyên, như cũ","meaning":"Chỉ trạng thái giữ nguyên hiện trạng hoặc vị trí ban đầu của vật, không thay đổi hay sửa đổi gì."},"847":{"word":"Trong thời gian đó, bấy lâu nay","meaning":"Khoảng thời gian đã trôi qua từ một sự việc cụ thể trong quá khứ cho đến thời điểm hiện tại."},"848":{"word":"Khi đó, lúc đó","meaning":"Một thời điểm hoặc giai đoạn cụ thể trong quá khứ hoặc tương lai đã được nhắc đến."},"849":{"word":"Nhưng, tuy nhiên","meaning":"Từ dùng để giới thiệu một ý đối lập hoặc một tình huống khác với điều vừa được đề cập."},"850":{"word":"Do đó, vì vậy","meaning":"Từ dùng để chỉ ra rằng câu tiếp theo là kết quả hoặc hệ quả trực tiếp của thông tin phía trước."},"851":{"word":"như vậy","meaning":"Từ dùng để chỉ người hay vật có tính chất hoặc đặc điểm đã được nói đến trước đó."},"852":{"word":"nhớ","meaning":"Cảm thấy buồn và ao ước được gặp lại hoặc có lại một người hay một vật đã xa cách."},"853":{"word":"thôi","meaning":"Dùng để ra lệnh hoặc đề nghị dừng một hành động hoặc hoạt động ngay lập tức."},"854":{"word":"nghỉ việc","meaning":"Quyết định dừng tham gia một công việc, trường học hoặc hoạt động nào đó."},"855":{"word":"vị ấy","meaning":"Đại từ dùng để chỉ một người cụ thể một cách kính trọng, đặc biệt khi người đó không có mặt."},"856":{"word":"ngừng","meaning":"Một hiện tượng tự nhiên đang diễn ra (như mưa, gió, tuyết) dừng lại hoàn toàn."},"857":{"word":"cũng khó nói","meaning":"Từ cảm thán dùng để bày tỏ thái độ không chắc chắn hoặc phân vân trước một câu hỏi hay yêu cầu."},"858":{"word":"chữ viết","meaning":"Hình thức, kiểu dáng của các ký tự được viết ra."},"859":{"word":"chữ cái","meaning":"Một dấu hiệu nhỏ, riêng biệt được vẽ hoặc in ra để đại diện cho một âm thanh hoặc một phần của từ trong hệ thống chữ viết."},"860":{"word":"ngay lập tức","meaning":"Từ chỉ một hành động sẽ xảy ra trong thời gian rất ngắn từ bây giờ, hoặc đã xảy ra cách đây không lâu."},"861":{"word":"cấm","meaning":"Một quy định hoặc lệnh chính thức tuyên bố một hoạt động hoặc hành động nào đó hoàn toàn không được phép."},"862":{"word":"khẩn cấp","meaning":"Tình huống hoặc công việc cần được giải quyết ngay lập tức và hành động nhanh chóng vì sự chậm trễ có thể gây ra vấn đề."},"863":{"word":"nuôi","meaning":"Chăm sóc, cho ăn uống và chú ý để cây cối, động vật hoặc tóc phát triển lớn hơn."},"864":{"word":"dầu","meaning":"Chất lỏng trơn, dễ cháy và không hòa lẫn với nước."},"865":{"word":"vui mừng","meaning":"Thể hiện sự hài lòng hoặc niềm vui lớn thông qua cười, nói hoặc hành động."},"866":{"word":"niềm vui","meaning":"Cảm giác hài lòng sâu sắc và vui vẻ tích cực làm tâm trạng phấn khởi."},"867":{"word":"ký ức","meaning":"Tập hợp những trải nghiệm, sự kiện và thông tin trong quá khứ mà một người có thể nhớ lại."},"868":{"word":"nhớ lại","meaning":"Làm cho một sự kiện, người hoặc thông tin trong quá khứ trở nên rõ ràng trong tâm trí bạn."},"869":{"word":"nhiệt độ","meaning":"Số đo lượng năng lượng nhiệt mà một nơi hoặc vật thể có, cho biết nó ấm hay mát."},"870":{"word":"phóng viên","meaning":"Người có công việc tìm kiếm thông tin về các sự kiện, con người và viết bài hoặc kể chuyện cho báo chí, TV, hoặc đài phát thanh."},"871":{"word":"nhà ga tàu hỏa","meaning":"Tòa nhà hoặc khu vực nơi mọi người lên xuống tàu hỏa, và tàu hỏa đến hoặc khởi hành."},"872":{"word":"vé tàu hỏa","meaning":"Mảnh giấy hoặc thẻ nhỏ chứng minh bạn đã trả tiền để đi trên tàu hỏa."},"873":{"word":"ho","meaning":"Âm thanh đột ngột, lớn và luồng không khí mạnh thoát ra từ miệng và họng, thường do bị kích thích."},"874":{"word":"đàn ghi-ta","meaning":"Nhạc cụ có dây, thường có sáu dây, được chơi bằng cách gảy hoặc gảy phím."},"875":{"word":"cơ hội","meaning":"Thời điểm hoặc dịp thích hợp để làm một việc gì đó."},"876":{"word":"căng thẳng","meaning":"Trạng thái tập trung tinh thần cao độ hoặc lo lắng, không thể thư giãn."},"877":{"word":"chiều dài","meaning":"Kích thước từ một đầu đến đầu kia của vật thể, thường là cạnh dài nhất."},"878":{"word":"rong biển","meaning":"Loại thực vật lá xanh hoặc sẫm màu mọc dưới biển, thường được ăn dưới dạng sấy khô thành lá mỏng."},"879":{"word":"sâu","meaning":"Có khoảng cách lớn từ bề mặt xuống đáy hoặc từ mép trước vào trong."},"880":{"word":"sâu","meaning":"Ở một mức độ xa xuống dưới bề mặt hoặc xa vào trong một không gian kín."},"881":{"word":"màu đen","meaning":"Màu tối nhất có thể, giống như bầu trời đêm không ánh sáng hoặc mực đen."},"882":{"word":"đen","meaning":"Có màu tối nhất, giống như bầu trời đêm không sao, phản chiếu rất ít ánh sáng."},"883":{"word":"gọt","meaning":"Bỏ lớp vỏ bên ngoài của thứ gì đó hoặc vỏ trái cây bằng dụng cụ như dao."},"884":{"word":"bất ngờ","meaning":"Xảy ra đột ngột khiến ai đó giật mình hoặc thể hiện sự ngạc nhiên, kinh ngạc."},"885":{"word":"sạch sẽ","meaning":"Không có bụi bẩn, ở trạng thái không bị bẩn."},"886":{"word":"tỉnh giấc","meaning":"Ngừng ngủ và trở nên hoàn toàn tỉnh táo, nhận biết xung quanh."},"887":{"word":"lấy ra","meaning":"Di chuyển một vật từ bên trong ra bên ngoài."},"888":{"word":"kẹo cao su","meaning":"Một loại kẹo dẻo dùng để nhai nhưng không nuốt."},"889":{"word":"bó hoa","meaning":"Nhiều bông hoa được bó lại với nhau."},"890":{"word":"bình hoa","meaning":"Đồ dùng trang trí dùng để cắm hoa."},"891":{"word":"tiệm hoa","meaning":"Cửa hàng chuyên bán các loại hoa tươi và cây cảnh."},"892":{"word":"mơ","meaning":"Trải qua những hình ảnh, âm thanh, cảm giác trong lúc ngủ."},"893":{"word":"giấc mơ","meaning":"Hiện tượng tinh thần xuất hiện trong lúc ngủ, bao gồm hình ảnh, âm thanh, cảm giác."},"894":{"word":"cắt đứt","meaning":"Làm cho một vật đang liên tục bị tách thành nhiều phần bằng cách cắt hoặc kéo mạnh."},"895":{"word":"sôi","meaning":"Trạng thái chất lỏng đạt nhiệt độ cao, tạo ra bọt khí và bốc hơi mạnh."},"896":{"word":"đun sôi","meaning":"Làm cho chất lỏng đạt đến nhiệt độ cao, khiến nó sủi bọt mạnh và bốc hơi."},"897":{"word":"kết thúc","meaning":"Phần cuối cùng của một hoạt động, sự kiện hoặc đối tượng, nơi nó dừng lại hoặc kết thúc."},"898":{"word":"hoàn thành","meaning":"Hoàn tất một hoạt động hoặc nhiệm vụ thành công, đưa nó đến điểm kết thúc."},"899":{"word":"cài","meaning":"Đưa một vật vào một chỗ trống hoặc lên một bộ phận cơ thể sao cho vừa vặn và bám chặt."},"900":{"word":"chia","meaning":"Tách một vật hoặc một nhóm thành nhiều phần nhỏ hơn và thường là phân phát các phần đó cho nhiều người."},"901":{"word":"phần còn lại","meaning":"Phần còn lại sau khi một phần nào đó đã được sử dụng hoặc hoàn thành."},"902":{"word":"tuổi","meaning":"Số năm một người hoặc một sinh vật đã tồn tại kể từ khi sinh ra."},"903":{"word":"xuất hiện","meaning":"Có thể nhìn thấy được sau khi đã ẩn đi hoặc chưa từng xuất hiện."},"904":{"word":"bốn ngày","meaning":"Khoảng thời gian kéo dài trong bốn ngày liên tiếp."},"905":{"word":"câu cá","meaning":"Hoạt động dùng dụng cụ chuyên biệt để bắt cá."},"906":{"word":"bay","meaning":"Di chuyển trong không khí, thường là bằng cánh hoặc động cơ."},"907":{"word":"thon thả","meaning":"Chỉ dáng người dài, thanh mảnh và có rất ít mỡ thừa."},"908":{"word":"người khác","meaning":"Người không phải là mình hoặc không có mối quan hệ thân thiết."},"909":{"word":"để lại","meaning":"Để lại một phần của cái gì đó mà không dùng hết."},"910":{"word":"nam nữ","meaning":"Gộp chung cả người giới tính nam và người giới tính nữ."},"911":{"word":"còn lại","meaning":"Một phần hoặc một lượng nào đó vẫn còn sau khi đã sử dụng hoặc lấy đi."},"912":{"word":"nam giới","meaning":"Người có đặc điểm sinh học thuộc giới tính nam."},"913":{"word":"phía nam","meaning":"Hướng đối diện với hướng bắc trên la bàn hoặc bản đồ."},"914":{"word":"nam sinh","meaning":"Học sinh có giới tính nam đang học tại một trường học hoặc cơ sở giáo dục."},"915":{"word":"khỏi bệnh","meaning":"Tình trạng bệnh tật hoặc vết thương được chữa lành và trở lại khỏe mạnh."},"916":{"word":"tốt hơn","meaning":"Ở trạng thái có chất lượng, hiệu quả hoặc sức khỏe tốt hơn so với cái khác hoặc so với trước."},"917":{"word":"giấc ngủ trưa","meaning":"Một khoảng thời gian ngắn ngủ hoặc nghỉ ngơi vào ban ngày."},"918":{"word":"khoa nội","meaning":"Chuyên khoa y tế nghiên cứu và điều trị các bệnh bên trong cơ thể bằng thuốc, không phẫu thuật."},"919":{"word":"ra","meaning":"Đưa ra hoặc đặt một câu hỏi, bài tập, hoặc nhiệm vụ nào đó."},"920":{"word":"đi xuống","meaning":"Di chuyển từ vị trí cao hơn đến vị trí thấp hơn."},"921":{"word":"xuống","meaning":"Di chuyển từ vị trí cao xuống vị trí thấp hơn, hướng về phía người nói hoặc điểm tham chiếu."},"922":{"word":"nội dung","meaning":"Những thông tin, ý tưởng, chi tiết chính có trong một tài liệu, bài nói hoặc phương tiện truyền thông."},"923":{"word":"nồi","meaning":"Nồi là dụng cụ hình tròn, sâu lòng, thường có nắp và tay cầm, dùng để nấu ăn."},"924":{"word":"mùi","meaning":"Mùi là một chất lượng cụ thể của vật mà mũi có thể cảm nhận, có thể dễ chịu hoặc khó chịu."},"925":{"word":"tủ lạnh","meaning":"Tủ lạnh là một thiết bị hình hộp dùng để bảo quản thực phẩm ở nhiệt độ thấp."},"926":{"word":"các bạn","meaning":"“Các bạn” là từ dùng để chỉ nhiều người khi người nói chuyện trực tiếp với họ."},"927":{"word":"vượt quá","meaning":"Vượt quá nghĩa là đi qua hoặc ở trên một giới hạn, thời gian hay mức độ nhất định."},"928":{"word":"ngã","meaning":"Ngã là hành động đột ngột mất thăng bằng và rơi xuống mặt đất."},"929":{"word":"bốn","meaning":"Bốn là số lượng được biểu thị bằng ba cộng một."},"930":{"word":"cà vạt","meaning":"Cà vạt là một dải vải dài được đeo quanh cổ áo sơ mi, thường thắt nút ở phía trước."},"931":{"word":"thứ tư","meaning":"Thứ tư là vị trí hoặc vật phẩm trong một chuỗi ngay sau thứ ba."},"932":{"word":"màu vàng","meaning":"Màu vàng là màu của chuối hoặc một con gà con."},"933":{"word":"vàng","meaning":"Vàng là tính từ mô tả một màu sắc giống như chanh chín hoặc hoa hướng dương."},"934":{"word":"nỗ lực","meaning":"Nỗ lực là sự cố gắng hoặc năng lượng tập trung để hoàn thành một nhiệm vụ khó khăn."},"935":{"word":"người già","meaning":"Người đã có tuổi, không còn trẻ nữa."},"936":{"word":"quyển vở","meaning":"Một cuốn sách nhỏ gồm các trang giấy trắng dùng để viết hoặc vẽ."},"937":{"word":"màu xanh lá cây","meaning":"Màu giữa vàng và xanh dương, giống màu của cỏ cây."},"938":{"word":"trà xanh","meaning":"Một loại đồ uống được pha từ lá cây trà đã phơi khô, thường có màu xanh nhạt hoặc hơi nâu."},"939":{"word":"ngạc nhiên","meaning":"Có cảm giác bất ngờ hoặc sửng sốt mạnh khi gặp phải điều không mong đợi."},"940":{"word":"trò chơi","meaning":"Hoạt động giải trí mà mọi người, đặc biệt là trẻ em, thực hiện để vui chơi, thường có luật lệ hoặc dùng đồ chơi."},"941":{"word":"trò đùa","meaning":"Một câu chuyện hoặc lời nói ngắn gọn, hài hước nhằm mục đích làm người khác cười."},"942":{"word":"chiều cao","meaning":"Kích thước của một vật thể đo từ đáy đến điểm cao nhất của nó."},"943":{"word":"cao","meaning":"Ở một vị trí cách mặt đất hoặc một bề mặt khác một khoảng cách đáng kể theo chiều thẳng đứng."},"944":{"word":"đặt","meaning":"Đặt vật đang cầm hoặc đang đẩy xuống, không giữ nữa."},"945":{"word":"nhấn","meaning":"Dùng tay hoặc ngón tay tác dụng lực lên một bề mặt hoặc vật thể để làm nó di chuyển hoặc kích hoạt."},"946":{"word":"nước mắt","meaning":"Chất lỏng trong suốt chảy ra từ mắt của người hoặc động vật."},"947":{"word":"nằm","meaning":"Đặt cơ thể của bạn phẳng trên một bề mặt, thường để nghỉ ngơi hoặc ngủ."},"948":{"word":"cảm thấy","meaning":"Nhận biết hoặc trải nghiệm một trạng thái, cảm xúc, hoặc một tác động vật lý thông qua cơ thể."},"949":{"word":"cảm giác","meaning":"Trải nghiệm bên trong về tinh thần hoặc cảm nhận vật lý từ cơ thể."},"950":{"word":"chậm","meaning":"Miêu tả tốc độ di chuyển hoặc xảy ra không nhanh, mất nhiều thời gian."},"951":{"word":"luôn luôn","meaning":"Xảy ra hoặc tồn tại ở mọi lúc, không ngừng nghỉ."},"952":{"word":"tăng","meaning":"Trở nên lớn hơn về kích thước, số lượng hoặc khối lượng theo thời gian."},"953":{"word":"già","meaning":"Trở nên cũ hoặc có tuổi tác cao."},"954":{"word":"năng lực","meaning":"Khả năng hoặc kỹ năng để thực hiện thành công một công việc hoặc nhiệm vụ."},"955":{"word":"cầu","meaning":"Cấu trúc được xây dựng bắc qua sông, khe núi hoặc đường để người và phương tiện có thể đi qua."},"956":{"word":"thứ năm","meaning":"Vị trí sau thứ tư trong một dãy hoặc một chuỗi."},"957":{"word":"sự đa dạng","meaning":"Tình trạng có nhiều loại hoặc yếu tố khác biệt nhau."},"958":{"word":"ngày hôm sau","meaning":"Ngày liền kề sau ngày hiện tại hoặc ngày được nhắc đến."},"959":{"word":"chế độ ăn kiêng","meaning":"Cách ăn uống cụ thể thường được áp dụng để giảm cân hoặc cải thiện sức khỏe."},"960":{"word":"bị thương","meaning":"Trải qua tổn thương về mặt thể chất ở một bộ phận nào đó trên cơ thể."},"961":{"word":"cạn kiệt, hết","meaning":"Sử dụng hoặc tiêu thụ hết hoàn toàn mọi thứ có sẵn, không còn lại gì."},"962":{"word":"lau, đánh bóng","meaning":"Chà xát bề mặt bằng vải hoặc bàn chải để loại bỏ bụi bẩn hoặc làm cho nó mịn và sáng bóng."},"963":{"word":"đơn giản","meaning":"Tình trạng một cái gì đó có ít bộ phận hoặc bước, làm cho nó dễ hiểu hoặc dễ thực hiện."},"964":{"word":"cúc áo, khuy áo","meaning":"Vật nhỏ, thường hình tròn được may vào quần áo để cài qua một lỗ hoặc khuy giúp giữ các bộ phận lại với nhau."},"965":{"word":"lá mùa thu","meaning":"Hiện tượng lá cây chuyển sang màu vàng hoặc đỏ vào mùa thu, hoặc chỉ những chiếc lá đã chuyển màu đó."},"966":{"word":"trứng gà","meaning":"Trứng do gà mái đẻ ra."},"967":{"word":"lịch","meaning":"Tờ giấy hoặc cuốn sách in các tháng, ngày, thứ trong tuần, các mùa, ngày sự kiện, v.v., theo thứ tự ngày tháng."},"968":{"word":"chạy bộ, sự chạy","meaning":"Hoạt động di chuyển nhanh bằng chân, thường có cả hai chân đều nhấc khỏi mặt đất trong một khoảnh khắc."},"969":{"word":"chạy","meaning":"Di chuyển về phía trước một cách nhanh chóng bằng cách đẩy người lên khỏi mặt đất bằng chân, thực hiện các bước nhanh."},"970":{"word":"gà","meaning":"Một loài chim nông trại phổ biến có lông vũ, cánh và mào trên đầu, thường được nuôi để lấy thịt và trứng."},"971":{"word":"thịt gà","meaning":"Đây là thịt của con gà, thường được chế biến và ăn làm thức ăn."},"972":{"word":"giống","meaning":"Chỉ việc có vẻ ngoài hoặc đặc điểm tương tự với người hoặc vật khác."},"973":{"word":"câu trả lời, đáp án","meaning":"Lời nói, hành động hoặc giải pháp đưa ra để phản hồi một câu hỏi, vấn đề hoặc yêu cầu."},"974":{"word":"ngột ngạt, bí bách","meaning":"Cảm thấy khó chịu, bức bối trong lòng hoặc khó thở do thiếu không khí trong lành."},"975":{"word":"thư trả lời, tin nhắn trả lời","meaning":"Thư hoặc tin nhắn được gửi lại cho người đã gửi thông tin trước đó."},"976":{"word":"chiếc (cho xe cộ/máy móc)","meaning":"Từ dùng để đếm các vật thể như xe cộ hoặc máy móc."},"977":{"word":"Daegu (thành phố)","meaning":"Một thành phố lớn nằm ở khu vực miền trung Hàn Quốc."},"978":{"word":"phần lớn, hầu hết","meaning":"Chỉ phần lớn nhất của một nhóm hoặc số lượng, chỉ còn lại một phần nhỏ."},"979":{"word":"Daejeon (thành phố)","meaning":"Một thành phố lớn ở miền trung Hàn Quốc, nổi tiếng về các viện khoa học và công nghệ."},"980":{"word":"trường cao học, sau đại học","meaning":"Cơ sở giáo dục bậc cao nơi sinh viên tiếp tục học sau khi tốt nghiệp đại học để lấy bằng cấp cao hơn."},"981":{"word":"cuộc thi, giải đấu","meaning":"Một sự kiện hoặc cuộc gặp gỡ có tổ chức giữa nhiều người để cạnh tranh hoặc thi đấu."},"982":{"word":"nhà (kính ngữ), quý vị (kính ngữ)","meaning":"Từ dùng để chỉ ngôi nhà hoặc nơi ở của người khác một cách tôn kính."},"983":{"word":"bẩn","meaning":"Có nhiều chất bẩn bám vào như bùn, bụi, làm cho không sạch sẽ hoặc không dễ chịu khi chạm vào."},"984":{"word":"càng","meaning":"Diễn tả mức độ tăng lên, làm cho một cái gì đó trở nên mạnh hơn, lớn hơn hoặc tốt hơn trước."},"985":{"word":"nhờ","meaning":"Sự giúp đỡ hoặc ân huệ từ người khác, hoặc lợi ích từ một việc gì đó mang lại kết quả tốt."},"986":{"word":"ném","meaning":"Dùng tay và cánh tay tạo ra một chuyển động mạnh để đẩy một vật đi trong không khí."},"987":{"word":"đưa đi","meaning":"Một người dẫn dắt người hoặc vật khác từ vị trí hiện tại đến một nơi khác."},"988":{"word":"đưa đến","meaning":"Một người dẫn dắt người hoặc vật khác từ một nơi đến vị trí hiện tại của mình."},"989":{"word":"buổi hẹn hò","meaning":"Cuộc gặp gỡ đã được sắp xếp giữa hai người, thường là nam và nữ có tình cảm lãng mạn, để dành thời gian cùng nhau."},"990":{"word":"độ","meaning":"Đơn vị đo lường cụ thể được biểu thị bằng một con số và ký hiệu vòng tròn nhỏ, dùng để chỉ nhiệt độ hoặc kích thước của một góc."},"991":{"word":"đường","meaning":"Lối đi rộng, có bề mặt cứng, được xây dựng để các phương tiện và người đi lại."},"992":{"word":"thành phố","meaning":"Một khu vực lớn, dân cư đông đúc với nhiều tòa nhà, đường sá và tập trung nhiều hoạt động của con người."},"993":{"word":"sự giúp đỡ","meaning":"Hành động hỗ trợ hoặc phục vụ ai đó đang cần, làm cho công việc của họ trở nên dễ dàng hơn."},"994":{"word":"việc đọc sách","meaning":"Hoạt động nhìn vào các từ ngữ đã viết và hiểu ý nghĩa của chúng, thường là từ sách hoặc màn hình."},"995":{"word":"thịt heo chiên xù","meaning":"Món ăn làm từ thịt heo được thái mỏng, tẩm bột chiên giòn."},"996":{"word":"đá","meaning":"Vật liệu cứng, rắn chắc, tự nhiên trên mặt đất hoặc dùng trong xây dựng."},"997":{"word":"xoay","meaning":"Di chuyển theo một đường tròn hoặc quanh một điểm cố định."},"998":{"word":"trả lại","meaning":"Đưa lại đồ vật đã mượn, đã lấy hoặc đã nhận cho chủ của nó."},"999":{"word":"quay","meaning":"Làm cho một vật thể xoay tròn hoặc quay quanh trục."},"1000":{"word":"khu phố","meaning":"Một khu vực nhỏ nơi mọi người sinh sống, thường là một phần của cộng đồng lớn hơn."},"1001":{"word":"động vật","meaning":"Một sinh vật sống có khả năng di chuyển và ăn các sinh vật khác để duy trì sự sống."},"1002":{"word":"sở thú","meaning":"Nơi nuôi nhốt và trưng bày nhiều loại động vật để mọi người tham quan."},"1003":{"word":"cùng lúc","meaning":"Trạng thái diễn ra vào cùng một thời điểm."},"1004":{"word":"đồng xu","meaning":"Một mảnh kim loại nhỏ, dẹt, tròn, dùng làm tiền tệ để mua bán."},"1005":{"word":"phía đông","meaning":"Hướng mặt trời mọc vào buổi sáng, đối diện với hướng mặt trời lặn."},"1006":{"word":"heo","meaning":"Một loài động vật có thân hình mập mạp, chân ngắn, được nuôi để lấy thịt."},"1007":{"word":"thịt heo","meaning":"Thịt từ con heo được dùng làm thực phẩm."},"1008":{"word":"-bị, -được","meaning":"Hậu tố biểu thị một hành động được thực hiện lên chủ thể hoặc chủ thể biến đổi thành một trạng thái mới."},"1009":{"word":"tương đậu","meaning":"Một loại nước sốt hoặc bột nhão làm từ đậu nành lên men sau khi đậu được dùng làm nước tương."},"1010":{"word":"dày","meaning":"Khoảng cách giữa hai mặt của một vật nào đó lớn."},"1011":{"word":"đặt, để","meaning":"Đặt một vật gì đó xuống một vị trí hoặc địa điểm cụ thể."},"1012":{"word":"đậu phụ","meaning":"Một loại thực phẩm mềm, trắng, hình khối làm từ sữa đậu nành đông đặc, thường được dùng trong nhiều món ăn."},"1013":{"word":"hai ba","meaning":"Chỉ một số lượng nhỏ các mục, thường là hơn một nhưng ít hơn bốn."},"1014":{"word":"đau đầu","meaning":"Cảm giác khó chịu âm ỉ hoặc nhức nhối bên trong đầu."},"1015":{"word":"thứ hai","meaning":"Chỉ mục hoặc vị trí đứng ngay sau mục đầu tiên trong một chuỗi có thứ tự."},"1016":{"word":"phía sau","meaning":"Phần hoặc hướng nằm ở cuối hoặc mặt đối diện của một vật gì đó, xa phía trước."},"1017":{"word":"cuối cùng, rốt cuộc","meaning":"Từ dùng để diễn tả một sự kiện xảy ra sau một thời gian dài chờ đợi hoặc mong đợi."},"1018":{"word":"ghé qua, tạt qua","meaning":"Dừng chân ngắn gọn, không chính thức tại một địa điểm hoặc nơi của một người nào đó khi đang trên đường đi đến nơi khác."},"1019":{"word":"nghe thấy","meaning":"Âm thanh đi vào tai và được cảm nhận."},"1020":{"word":"lưng","meaning":"Phần phía sau cơ thể người, đối diện với ngực."},"1021":{"word":"thiết kế","meaning":"Hình thức, cấu trúc hoặc bố cục theo kế hoạch của một vật thể."},"1022":{"word":"riêng","meaning":"Ở trạng thái tách rời, không cùng với cái khác."},"1023":{"word":"mồ hôi","meaning":"Chất lỏng trong suốt, mặn tiết ra qua da khi nóng, bệnh hoặc lo lắng."},"1024":{"word":"đất","meaning":"Bề mặt rắn chắc trên cùng của Trái Đất."},"1025":{"word":"rời đi","meaning":"Di chuyển khỏi một nơi nào đó, không ở lại nữa."},"1026":{"word":"làm ồn","meaning":"Nói chuyện một cách liên tục và ồn ào, gây ra tiếng động lớn."},"1027":{"word":"bánh tteok","meaning":"Món ăn làm từ gạo hoặc ngũ cốc được hấp hoặc giã, thường có hình dạng và món ăn khác nhau ở Hàn Quốc."},"1028":{"word":"tteokguk","meaning":"Món canh làm bằng cách cắt bánh gạo garaetteok thành lát mỏng và đun sôi trong nước dùng trong."},"1029":{"word":"rơi","meaning":"Một vật di chuyển nhanh từ nơi cao xuống nơi thấp hơn, thường là chạm vào bề mặt."},"1030":{"word":"hoặc","meaning":"Dùng để đưa ra hai hoặc nhiều lựa chọn, cho biết chỉ một trong số đó là đúng."},"1031":{"word":"giống nhau","meaning":"Hai hay nhiều vật không có gì khác biệt về hình dáng, tính chất."},"1032":{"word":"như nhau, đều","meaning":"Theo cách mà hai hay nhiều vật không có chút khác biệt nào về hình dáng, số lượng hay chất lượng."},"1033":{"word":"thông minh, lanh lợi","meaning":"Có khả năng nhanh chóng tiếp thu kiến thức mới, giải quyết vấn đề và diễn đạt ý tưởng rõ ràng."},"1034":{"word":"thẳng, thẳng tắp, ngay ngắn","meaning":"Ở vị trí thẳng hàng, không cong, không vẹo, hoặc di chuyển theo một đường thẳng."},"1035":{"word":"béo, mập","meaning":"Có thân hình to và dày, thường do có nhiều mỡ."},"1036":{"word":"chạy","meaning":"Di chuyển nhanh bằng cách nhấc và đặt chân xuống liên tục, thường có lúc cả hai chân không chạm đất."},"1037":{"word":"chạy đi, chạy đến","meaning":"Di chuyển nhanh chóng đến một địa điểm cụ thể bằng cách chạy."},"1038":{"word":"nóng","meaning":"Có nhiệt độ rất cao, có thể gây cảm giác bỏng khi chạm vào."},"1039":{"word":"mở (mắt)","meaning":"Mở mí mắt ra để nhìn thấy xung quanh."},"1040":{"word":"ý nghĩa, nghĩa","meaning":"Nội dung hoặc thông điệp mà một từ ngữ, ký hiệu hoặc hành động muốn truyền đạt."},"1041":{"word":"đài, radio","meaning":"Thiết bị điện tử thu tín hiệu sóng qua không khí và chuyển đổi thành âm thanh như nhạc hoặc tiếng nói."},"1042":{"word":"nhà hàng","meaning":"Một cơ sở có bàn ghế nơi mọi người chọn món và trả tiền cho các bữa ăn do nhân viên chế biến."},"1043":{"word":"sân","meaning":"Một khu đất trống thường có cỏ, nằm cạnh nhà hoặc tòa nhà."},"1044":{"word":"khô","meaning":"Mất đi chất lỏng và trở nên hoàn toàn không còn ẩm ướt."},"1045":{"word":"làng, thôn","meaning":"Một nhóm nhỏ nhà cửa và các công trình nơi mọi người sinh sống, thường ở vùng nông thôn và nhỏ hơn thành phố."},"1046":{"word":"đón","meaning":"Hành động đi đến một nơi nào đó, như sân bay hoặc nhà ga, để chào đón người đang đến."},"1047":{"word":"cuối cùng","meaning":"Vật hoặc khoảnh khắc xuất hiện ở điểm kết thúc của một chuỗi hoặc dãy, không có gì theo sau nó."},"1048":{"word":"hoàn thành, kết thúc","meaning":"Đưa một hoạt động, nhiệm vụ hoặc khoảng thời gian đến kết luận hoàn chỉnh của nó."},"1049":{"word":"siêu thị","meaning":"Một cửa hàng lớn nơi mọi người chọn nhiều loại thực phẩm và đồ gia dụng từ các kệ hàng và thanh toán tại quầy thu ngân."},"1050":{"word":"rượu makgeolli","meaning":"Một loại đồ uống có cồn truyền thống của Hàn Quốc, thường có màu trắng sữa, được làm bằng cách lên men gạo."},"1051":{"word":"bị tắc, bị chặn","meaning":"Khi một lối đi hoặc lỗ hổng bị lấp đầy hoặc cản trở hoàn toàn, ngăn không cho bất cứ thứ gì đi qua."},"1052":{"word":"bánh xếp","meaning":"Món bánh được làm bằng cách nhào bột, cán mỏng và gói nhân thịt băm, rau củ, v.v., bằng bột."},"1053":{"word":"nếu","meaning":"Từ dùng để giới thiệu một tình huống hoặc điều kiện có thể xảy ra, quyết định kết quả của một sự kiện khác."},"1054":{"word":"nếu","meaning":"Từ dùng để gợi ý một tình huống tương lai có thể xảy ra, gây ra một hậu quả khác."},"1055":{"word":"chạm, sờ","meaning":"Dùng tay hoặc một bộ phận khác trên cơ thể để tiếp xúc và cảm nhận bề mặt của vật gì đó."},"1056":{"word":"truyện tranh, phim hoạt hình","meaning":"Hình ảnh thể hiện cuộc sống con người một cách hài hước, kể chuyện về xã hội hoặc dựa trên trí tưởng tượng, hay sách tập hợp các hình ảnh đó."},"1057":{"word":"quân cờ, quân","meaning":"Vật nhỏ thường có hình dạng đặc biệt, được người chơi di chuyển trên bàn cờ để đánh dấu vị trí hoặc tiến độ trong trận đấu."},"1058":{"word":"cuối (kỳ, giai đoạn)","meaning":"Điểm kết thúc hoặc phần cuối của một khoảng thời gian hoặc sự kiện cụ thể."},"1059":{"word":"lắp ráp, ghép","meaning":"Ghép nối các bộ phận đã được tách rời lại với nhau vào đúng vị trí của chúng."},"1060":{"word":"hằng năm, mỗi năm","meaning":"Xảy ra hoặc diễn ra một lần trong mỗi chu kỳ 365 ngày."},"1061":{"word":"buộc, thắt","meaning":"Buộc hai đầu dây, sợi hoặc vải lại với nhau, thường bằng cách tạo nút thắt hoặc hình nơ."},"1062":{"word":"hằng tháng, mỗi tháng","meaning":"Xảy ra lặp đi lặp lại trong mỗi khoảng thời gian khoảng 30 ngày liên tiếp."},"1063":{"word":"rất, vô cùng","meaning":"Ở một mức độ hoặc mức độ lớn, cho thấy một mức độ cường độ cao đối với điều gì đó."},"1064":{"word":"hằng tuần, mỗi tuần","meaning":"Xảy ra lặp đi lặp lại trong mỗi khoảng thời gian bảy ngày liên tiếp."},"1065":{"word":"phòng vé","meaning":"Nơi tại rạp hát, sân vận động hoặc địa điểm khác mà mọi người mua vé vào cửa cho một sự kiện."},"1066":{"word":"bia","meaning":"Đồ uống có cồn được làm từ ngũ cốc mạch nha, hoa bia, men và nước, thường có bọt khi rót."},"1067":{"word":"tóc","meaning":"Sợi mỏng mọc trên da đầu người."},"1068":{"word":"xa","meaning":"Ở một khoảng cách lớn, không gần."},"1069":{"word":"dừng lại","meaning":"Không tiếp tục hoạt động hay di chuyển nữa."},"1070":{"word":"phong cách","meaning":"Vẻ bề ngoài, phong thái hay trang phục toát lên sự thanh lịch và đẹp đẽ."},"1071":{"word":"đeo","meaning":"Đặt một vật lên vai hoặc lưng để mang đi."},"1072":{"word":"ghi chú","meaning":"Việc viết lại một cách đơn giản những điều cần nhớ hoặc cần thông báo cho người khác."},"1073":{"word":"tin nhắn","meaning":"Thông tin được viết hoặc nói mà một người gửi cho người khác."},"1074":{"word":"thư điện tử","meaning":"Hệ thống gửi và nhận thông tin số qua mạng máy tính."},"1075":{"word":"ngày lễ","meaning":"Những ngày đặc biệt trong năm của một quốc gia hay văn hóa, thường có các truyền thống hoặc lễ kỷ niệm riêng."},"1076":{"word":"muỗi","meaning":"Loài côn trùng nhỏ biết bay, hút máu người hoặc động vật."},"1077":{"word":"tất cả","meaning":"Chỉ toàn bộ số lượng hoặc mỗi một cá thể trong một nhóm."},"1078":{"word":"dáng vẻ","meaning":"Vẻ bề ngoài hoặc hình dạng của một người hay vật được nhìn thấy."},"1079":{"word":"phục vụ","meaning":"Dùng để chỉ việc giúp đỡ hoặc phục vụ một người quan trọng với thái độ tôn kính."},"1080":{"word":"hình dạng","meaning":"Dáng vẻ bên ngoài, đường nét của một vật hoặc sự vật."},"1081":{"word":"gom","meaning":"Đem nhiều thứ riêng lẻ lại thành một nhóm hoặc tại một chỗ."},"1082":{"word":"tụ tập","meaning":"Nhiều người hoặc vật từ các nơi khác nhau đến và ở chung một chỗ."},"1083":{"word":"buổi gặp mặt","meaning":"Một sự kiện đã được sắp xếp để một nhóm người đến cùng một nơi với một mục đích chung."},"1084":{"word":"thiếu","meaning":"Có ít hơn những gì cần thiết hoặc mong đợi."},"1085":{"word":"dây chuyền","meaning":"Một món đồ trang sức, thường có hạt hoặc mặt dây chuyền, được đeo quanh cổ."},"1086":{"word":"khăn quàng cổ","meaning":"Một dải vải ấm dài được quấn quanh cổ để giữ ấm cho người."},"1087":{"word":"giọng nói","meaning":"Âm thanh phát ra từ miệng của một người khi họ nói, hát hoặc tạo ra các âm thanh khác."},"1088":{"word":"tắm","meaning":"Hành động làm sạch cơ thể bằng cách ngồi hoặc nằm trong bồn nước."},"1089":{"word":"mục đích","meaning":"Lý do mà một việc gì đó được thực hiện hoặc tạo ra, thường được hình dung như một đích đến cần đạt tới."},"1090":{"word":"xấu xí","meaning":"Mô tả một người hoặc vật không đẹp mắt hoặc khó nhìn."},"1091":{"word":"củ cải","meaning":"Một loại rau củ có màu trắng, vị cay nhẹ, thường dùng ăn sống hoặc nấu chín."},"1092":{"word":"cân nặng","meaning":"Số đo cho biết vật thể nặng bao nhiêu, được đo bằng lực hấp dẫn."},"1093":{"word":"hoa dâm bụt","meaning":"Một loài hoa nở từ mùa hè đến mùa thu, có cánh hoa hình chuông rộng màu trắng, tím hoặc đỏ."},"1094":{"word":"miễn phí","meaning":"Không phải trả bất kỳ khoản tiền nào khi nhận hoặc sử dụng dịch vụ, hàng hóa."},"1095":{"word":"đầu gối","meaning":"Khớp nối ở giữa chân, nằm giữa đùi và cẳng chân, giúp chân gập lại."},"1096":{"word":"đáng sợ","meaning":"Diễn tả điều gì đó làm cho người khác cảm thấy rất sợ hãi hoặc kinh hoàng."},"1097":{"word":"rất","meaning":"Diễn tả một mức độ cao hoặc cường độ lớn của một đặc tính nào đó."},"1098":{"word":"câu hỏi","meaning":"Một câu hỏi yêu cầu phải có câu trả lời, thường trong bài kiểm tra hoặc bài tập."},"1099":{"word":"cá","meaning":"Một loài động vật sống hoàn toàn dưới nước, di chuyển bằng vây và lấy oxy từ nước bằng mang."},"1100":{"word":"tất nhiên","meaning":"Được dùng để khẳng định một điều gì đó là chắc chắn đúng hoặc hiển nhiên, không cần phải bàn cãi."},"1101":{"word":"hỏi","meaning":"Đặt một câu hỏi hoặc yêu cầu thông tin đến ai đó bằng lời nói hoặc văn bản."},"1102":{"word":"trượt chân","meaning":"Vô tình bị mất thăng bằng và ngã xuống do bề mặt đi lại bị trơn trượt."},"1103":{"word":"tương lai","meaning":"Thời gian sẽ đến sau hiện tại."},"1104":{"word":"trước","meaning":"Vào thời điểm trước khi điều gì đó xảy ra hoặc cần thiết."},"1105":{"word":"bảo tàng mỹ thuật","meaning":"Tòa nhà dùng để trưng bày công khai các tác phẩm nghệ thuật như tranh, tượng."},"1106":{"word":"canh rong biển","meaning":"Món canh truyền thống của Hàn Quốc được nấu từ rong biển khô, thường ăn vào dịp sinh nhật hoặc sau khi sinh."},"1107":{"word":"mét","meaning":"Đơn vị đo chiều dài tiêu chuẩn, bằng một trăm xen-ti-mét."},"1108":{"word":"tin, tin tưởng","meaning":"Chấp nhận điều gì đó là thật hoặc tin vào sự thật, khả năng của một người hay lời nói."},"1109":{"word":"bột mì","meaning":"Bột mịn, mềm được làm từ hạt ngũ cốc như lúa mì, dùng để làm bánh mì, bánh ngọt và các món ăn khác."},"1110":{"word":"đẩy","meaning":"Dùng lực tác động vào vật hoặc người để chúng rời xa mình hoặc mở ra."},"1111":{"word":"bên ngoài, ngoài","meaning":"Không gian hoặc khu vực ở phía ngoài."},"1112":{"word":"phía bên ngoài","meaning":"Phần không gian hoặc bề mặt không nằm trong một khu vực hoặc vật thể cụ thể."},"1113":{"word":"bị thay đổi","meaning":"Trở nên khác biệt so với trạng thái hoặc hình thức trước đó."},"1114":{"word":"sàn, đáy","meaning":"Phần phẳng và rộng ở dưới cùng của một không gian hoặc vật thể."},"1115":{"word":"bãi biển","meaning":"Nơi đất liền tiếp giáp với biển hoặc khu vực gần đó."},"1116":{"word":"mong muốn","meaning":"Có một ước muốn mạnh mẽ về một điều gì đó sẽ xảy ra trong tương lai."},"1117":{"word":"ngắm nhìn","meaning":"Hướng mắt nhìn về phía một vật hoặc một cảnh một cách chăm chú."},"1118":{"word":"thoa","meaning":"Dùng tay hoặc dụng cụ để trải hoặc xoa một chất lỏng hoặc bán lỏng lên bề mặt."},"1119":{"word":"đàn vi-ô-lông","meaning":"Một loại nhạc cụ dây có thân gỗ, cần cong và bốn dây, được chơi bằng cách dùng vĩ kéo."},"1120":{"word":"tiếng vỗ tay","meaning":"Âm thanh tạo ra khi mọi người vỗ hai bàn tay vào nhau nhiều lần để thể hiện sự tán thành hoặc vui thích."},"1121":{"word":"sự đối lập","meaning":"Tình trạng hoàn toàn trái ngược hoặc hướng ngược lại so với cái khác."},"1122":{"word":"nhất định","meaning":"Diễn tả một hành động hoặc sự việc sẽ xảy ra mà không có bất kỳ nghi ngờ hay thất bại nào."},"1123":{"word":"quần đùi","meaning":"Một loại quần ngắn, thường dài đến đầu gối hoặc ngắn hơn."},"1124":{"word":"nhẫn","meaning":"Một món đồ trang sức hình tròn, thường làm bằng kim loại và đeo ở ngón tay."},"1125":{"word":"món ăn kèm","meaning":"Các món ăn phụ nhỏ được chế biến từ rau củ hoặc thịt, dùng kèm với món chính trong bữa ăn."},"1126":{"word":"viết chính tả","meaning":"Ghi lại lời nói thành chữ viết trên giấy bằng bút hoặc bút chì khi có người đọc."},"1127":{"word":"ngón chân","meaning":"Là các ngón nhỏ nằm ở phía trước bàn chân người."},"1128":{"word":"lòng bàn chân","meaning":"Là phần mặt phẳng phía dưới bàn chân, dùng để tiếp xúc với mặt đất."},"1129":{"word":"sáng","meaning":"Có nhiều ánh sáng, làm cho mọi vật dễ nhìn thấy."},"1130":{"word":"vừa rồi","meaning":"Chỉ một khoảng thời gian rất ngắn ngay trước khi nói hoặc một hành động vừa diễn ra."},"1131":{"word":"cửa ra vào","meaning":"Là vật chắn có thể đóng mở, thường hình chữ nhật, dùng để che lối vào một căn phòng."},"1132":{"word":"chuyến thăm","meaning":"Việc đi đến một nơi nào đó hoặc gặp gỡ một người nào đó trong một khoảng thời gian ngắn."},"1133":{"word":"phương pháp","meaning":"Là cách thức hoặc quy trình cụ thể để thực hiện một việc gì đó nhằm đạt được mục tiêu."},"1134":{"word":"phát sóng","meaning":"Hoạt động truyền tải âm thanh hoặc hình ảnh qua sóng vô tuyến hoặc cáp để nhiều người cùng xem hoặc nghe."},"1135":{"word":"đài phát sóng","meaning":"Nơi sản xuất và phát sóng các chương trình cho đài truyền hình hoặc đài phát thanh để công chúng theo dõi."},"1136":{"word":"hướng","meaning":"Là phía mà một người hoặc vật thể di chuyển đến, ví dụ như phía trước, phía sau, bên trái hoặc bên phải."},"1137":{"word":"số lần","meaning":"Từ dùng để chỉ mức độ nhân lên của một số lượng hoặc giá trị."},"1138":{"word":"giao hàng","meaning":"Hành động vận chuyển các mặt hàng như thức ăn hoặc bưu kiện từ một địa điểm đến tay người nhận."},"1139":{"word":"cầu lông","meaning":"Một môn thể thao dùng vợt đánh quả cầu lông qua lưới cao."},"1140":{"word":"cải thảo","meaning":"Một loại rau có lá to, màu xanh và trắng, thường dùng để làm kim chi."},"1141":{"word":"rối loạn tiêu hóa","meaning":"Tình trạng chức năng tiêu hóa bị rối loạn, gây tiêu chảy hoặc đau bụng."},"1142":{"word":"rắn","meaning":"Loài bò sát thân dài, không chân, di chuyển bằng cách trườn mình trên mặt đất."},"1143":{"word":"thói quen","meaning":"Một hành động hay cách ứng xử được thực hiện thường xuyên, gần như tự động."},"1144":{"word":"vứt bỏ","meaning":"Làm cho một vật không còn có giá trị sử dụng và bỏ đi, hoặc từ bỏ một người hay một vật hoàn toàn."},"1145":{"word":"thứ","meaning":"Từ dùng sau số đếm để chỉ thứ tự của sự vật hoặc sự việc trong một dãy."},"1146":{"word":"bộ","meaning":"Từ dùng để đếm một bộ quần áo hoàn chỉnh, như một bộ vest hay một bộ đồ ngủ."},"1147":{"word":"kiếm tiền","meaning":"Nhận tiền công khi hoàn thành công việc hoặc cung cấp dịch vụ cho người khác."},"1148":{"word":"đã","meaning":"Từ dùng để diễn tả rằng một việc gì đó đã xảy ra hoặc hoàn thành vào thời điểm sớm hơn dự kiến, gây ngạc nhiên."},"1149":{"word":"cởi","meaning":"Lấy vật đội, mặc, mang ra khỏi cơ thể."},"1150":{"word":"bức tường","meaning":"Cấu trúc phẳng, vững chắc, cao, tạo thành một mặt của căn phòng hoặc tòa nhà."},"1151":{"word":"thay đổi","meaning":"Trở nên khác đi so với ban đầu về hình dáng, hình thức hoặc tính chất."},"1152":{"word":"luật sư","meaning":"Người chuyên cung cấp tư vấn pháp lý và biện hộ cho người khác trước tòa án."},"1153":{"word":"ngôi sao","meaning":"Điểm sáng có thể nhìn thấy trên bầu trời đêm, thực chất là một thiên thể lớn tự phát sáng."},"1154":{"word":"thăm bệnh","meaning":"Hành động đến thăm một người đang bị ốm hoặc nằm viện."},"1155":{"word":"màu tím","meaning":"Màu sắc là sự pha trộn giữa màu xanh lam và màu đỏ."},"1156":{"word":"nhìn thấy","meaning":"Một vật hoặc cảnh vật tự nhiên xuất hiện trước mắt mà không có ai cố ý đưa ra."},"1157":{"word":"cho xem","meaning":"Hành động đưa một vật ra để người khác có thể nhìn thấy."},"1158":{"word":"ôn tập","meaning":"Hành động học lại tài liệu đã học trước đó để củng cố kiến thức hoặc ghi nhớ."},"1159":{"word":"đông đúc","meaning":"Chật chội, có quá nhiều người hoặc vật trong một không gian, gây khó khăn cho việc di chuyển hoặc nhìn rõ."},"1160":{"word":"xào","meaning":"Chế biến thức ăn trong chảo trên lửa với một ít dầu hoặc mỡ, thường bằng cách đảo nhanh cho đến khi chín."},"1161":{"word":"cơm chiên","meaning":"Món ăn được chế biến bằng cách trộn cơm với rau củ thái nhỏ và đôi khi có thịt, rồi xào chung trên chảo nóng."},"1162":{"word":"phong bì","meaning":"Vật chứa bằng giấy phẳng có nắp đậy, dùng để đựng và gửi thư hoặc tài liệu."},"1163":{"word":"gặp","meaning":"Chỉ việc đến gặp người lớn tuổi hoặc cấp trên để nói chuyện hoặc chào hỏi một cách kính trọng."},"1164":{"word":"xấu hổ","meaning":"Cảm thấy khó xử, muốn che giấu bản thân, thường thể hiện bằng cách đỏ mặt, tránh giao tiếp bằng mắt."},"1165":{"word":"mềm mại","meaning":"Miêu tả một chất liệu hoặc bề mặt có kết cấu trơn tru, nhẹ nhàng, tạo cảm giác dễ chịu khi chạm vào, không thô ráp hay cứng nhắc."},"1166":{"word":"ghen tị","meaning":"Cảm thấy mong muốn có được những gì người khác đang sở hữu hoặc những hoàn cảnh may mắn của họ."},"1167":{"word":"no","meaning":"Miêu tả trạng thái bụng cảm thấy căng tròn và hài lòng sau khi đã ăn hoặc uống một lượng lớn thức ăn, đồ uống."},"1168":{"word":"vợ chồng","meaning":"Hai người, thường là một nam và một nữ, kết hôn chính thức và sống chung với nhau trong một mối quan hệ trọn đời."},"1169":{"word":"phần","meaning":"Một trong các thành phần tạo nên tổng thể; một trong những phần mà tổng thể được chia ra."},"1170":{"word":"vợ","meaning":"Người phụ nữ đã chính thức kết hôn và gắn bó cuộc đời mình với một người đàn ông."},"1171":{"word":"người giàu","meaning":"Người sở hữu rất nhiều tiền bạc và tài sản có giá trị."},"1172":{"word":"trưởng phòng","meaning":"Người đứng đầu một bộ phận hoặc phòng ban cụ thể trong một công ty hoặc tổ chức."},"1173":{"word":"thiếu hụt","meaning":"Tình trạng không có đủ một thứ gì đó cần thiết."},"1174":{"word":"chăm chỉ","meaning":"Liên tục làm việc chăm chỉ và cẩn thận trong các nhiệm vụ mà không lãng phí thời gian."},"1175":{"word":"gửi","meaning":"Đưa một cái gì đó đi từ một nơi này đến một nơi khác, thường qua bưu điện."},"1176":{"word":"phía bắc","meaning":"Hướng ngược lại với phía nam, thường ở trên cùng của bản đồ."},"1177":{"word":"rõ ràng","meaning":"Dễ dàng nhìn thấy, nghe thấy hoặc hiểu được mà không có bất kỳ sự nhầm lẫn nào."},"1178":{"word":"món bột","meaning":"Các món ăn Hàn Quốc làm từ bột như mì hoặc bánh gạo, thường được bán trên đường phố."},"1179":{"word":"bầu không khí","meaning":"Cảm giác chung hoặc tâm trạng mà một địa điểm hay tình huống mang lại cho những người có mặt ở đó."},"1180":{"word":"màu hồng","meaning":"Một sắc đỏ nhạt, thường thấy ở hoa như hoa anh đào hoặc đồ ngọt như kẹo bông."},"1181":{"word":"đáng thương","meaning":"Ở trong một trạng thái buồn bã hoặc không may mắn khiến người khác cảm thấy thương cảm."},"1182":{"word":"sự bất an","meaning":"Cảm giác lo lắng hoặc hồi hộp về một điều gì đó có thể xảy ra, thường khiến một người cảm thấy bồn chồn."},"1183":{"word":"sự bất tiện","meaning":"Trạng thái hoặc tình huống gây ra khó khăn, rắc rối, hoặc làm mọi việc kém dễ dàng hoặc thoải mái hơn."},"1184":{"word":"đỏ","meaning":"Có màu sắc giống màu của máu hoặc ớt chín."},"1185":{"word":"dính","meaning":"Gắn chặt vào một bề mặt và ở lại đó."},"1186":{"word":"dán","meaning":"Làm cho một vật gì đó gắn vào một bề mặt khác, thường bằng keo hoặc băng dính."},"1187":{"word":"áo blouse","meaning":"Một loại áo nhẹ, thường rộng rãi, được phụ nữ mặc ở phần thân trên."},"1188":{"word":"sự so sánh","meaning":"Việc xem xét hai hay nhiều thứ để tìm ra điểm giống và khác nhau."},"1189":{"word":"xà phòng","meaning":"Chất dùng để làm sạch cơ thể hoặc quần áo bằng cách tạo bọt với nước."},"1190":{"word":"trống","meaning":"Một không gian không chứa gì hoặc không có ai ở trong."},"1191":{"word":"video","meaning":"Bản ghi lại hình ảnh chuyển động và âm thanh có thể xem trên màn hình."},"1192":{"word":"bí mật","meaning":"Một điều ẩn giấu mà người khác không biết."},"1193":{"word":"tương tự","meaning":"Hai hay nhiều thứ không hoàn toàn giống nhau nhưng có nhiều điểm tương đồng."},"1194":{"word":"tòa nhà","meaning":"Một công trình kiến trúc cố định có tường và mái để che chở cho con người hoặc các hoạt động của họ."},"1195":{"word":"rơi","meaning":"Di chuyển xuống một cách đột ngột, thường là vào nước, hoặc bị tách ra khỏi một nhóm/vị trí."},"1196":{"word":"màu đỏ","meaning":"Màu giống như màu của quả táo chín hoặc ớt đỏ."},"1197":{"word":"đỏ","meaning":"Có màu đỏ tươi đậm như màu máu hoặc ớt chín."},"1198":{"word":"giặt","meaning":"Làm sạch các đồ vải như quần áo hoặc chăn ga bằng nước và xà phòng/chất tẩy rửa."},"1199":{"word":"đồ giặt","meaning":"Những bộ quần áo, khăn tắm và các vật dụng vải khác cần được làm sạch hoặc vừa được làm sạch."},"1200":{"word":"tiệm bánh mì","meaning":"Một cửa hàng hoặc tiệm nơi bánh mì tươi, bánh ngọt và các loại bánh nướng khác được làm và bán."},"1201":{"word":"rút ra","meaning":"Di chuyển một vật ra khỏi vị trí hoặc nơi nó được gắn vào."},"1202":{"word":"nhổ","meaning":"Kéo một vật gì đó bị kẹt ra khỏi nơi nó đang ở."},"1203":{"word":"ngã tư","meaning":"Một điểm cụ thể nơi hai con đường giao nhau, tạo thành bốn hướng hoặc lối đi riêng biệt."},"1204":{"word":"bốn mùa","meaning":"Các khoảng thời gian riêng biệt trong năm bao gồm xuân, hạ, thu và đông."},"1205":{"word":"tai nạn","meaning":"Một sự kiện không theo kế hoạch và không mong muốn gây ra tổn hại, thương tích hoặc hư hỏng."},"1206":{"word":"sự thật","meaning":"Một sự việc thực sự đã xảy ra hoặc đang diễn ra."},"1207":{"word":"kinh doanh","meaning":"Một nỗ lực có tổ chức để sản xuất hoặc trao đổi hàng hóa, dịch vụ để lấy tiền hoặc giá trị khác."},"1208":{"word":"cỡ","meaning":"Kích thước tổng thể, độ lớn hoặc mức độ của một vật thể hoặc người, thường cho biết nó lớn hay nhỏ."},"1209":{"word":"giám đốc","meaning":"Người điều hành và lãnh đạo cao nhất của một công ty hoặc tổ chức, chịu trách nhiệm về định hướng và hoạt động chung của nó."},"1210":{"word":"kẹo","meaning":"Một loại bánh kẹo nhỏ, cứng và ngọt, thường được làm từ đường."},"1211":{"word":"ba ngày","meaning":"Thời gian dài ba ngày liên tiếp."},"1212":{"word":"thịt","meaning":"Phần mềm của cơ thể, chủ yếu là cơ và mỡ, bao phủ xương."},"1213":{"word":"ngã ba","meaning":"Nơi ba con đường giao nhau, tạo thành ba hướng đi khác nhau."},"1214":{"word":"thịt ba chỉ nướng","meaning":"Món ăn làm từ những lát thịt lợn ba chỉ dày, thường được nướng trên vỉ."},"1215":{"word":"bác, chú","meaning":"Người anh hoặc em trai của bố."},"1216":{"word":"giải thưởng","meaning":"Vật có giá trị như cúp, huy chương hoặc tiền, được trao cho người thành công trong cuộc thi hoặc làm việc tốt."},"1217":{"word":"hộp","meaning":"Vật chứa thường làm bằng bìa cứng, gỗ hoặc nhựa, có nắp, dùng để đựng hoặc mang đồ vật."},"1218":{"word":"vết thương","meaning":"Dấu vết trên da hoặc cơ thể do bị cắt, trầy xước hoặc tổn thương, thường gây đau hoặc chảy máu."},"1219":{"word":"xà lách","meaning":"Một loại rau xanh có lá rộng, nhăn, thường được dùng để cuốn thức ăn."},"1220":{"word":"sản phẩm","meaning":"Vật phẩm được sản xuất ra để bán hoặc tiêu thụ."},"1221":{"word":"chim","meaning":"Động vật có lông vũ, cánh và hai chân, thường bay và đẻ trứng."},"1222":{"word":"mới","meaning":"Chỉ một cái gì đó vừa được tạo ra, mua sắm hoặc trải nghiệm lần đầu tiên, chưa từng có trước đây."},"1223":{"word":"mới","meaning":"Diễn tả một hành động làm cho cái gì đó xuất hiện lần đầu tiên hoặc trở lại trạng thái mới mẻ."},"1224":{"word":"mới mẻ","meaning":"Có tính chất khác biệt so với những cái đã có hoặc chưa từng tồn tại."},"1225":{"word":"bình minh","meaning":"Khoảng thời gian trong ngày khi bóng tối bắt đầu tan dần và ánh sáng mặt trời đầu tiên xuất hiện trên bầu trời."},"1226":{"word":"năm mới","meaning":"Ngày hoặc khoảng thời gian khi chu kỳ lịch hàng năm bắt đầu lại, thường được đánh dấu bằng các lễ kỷ niệm đặc biệt."},"1227":{"word":"màu","meaning":"Thuộc tính của một vật thể làm cho nó có vẻ ngoài với một sắc thái nhất định, chẳng hạn như đỏ, xanh dương hoặc xanh lá cây, khi ánh sáng phản chiếu từ nó."},"1228":{"word":"màu sắc","meaning":"Vẻ ngoài trực quan của một vật thể được xác định bởi cách nó phản chiếu ánh sáng, làm cho nó có vẻ ngoài màu đỏ, xanh dương hoặc xanh lá cây."},"1229":{"word":"bánh mì kẹp","meaning":"Một loại thức ăn được làm bằng cách đặt thịt, phô mai, rau hoặc các nhân khác giữa hai lát bánh mì."},"1230":{"word":"nhớ ra","meaning":"Khi một sự kiện, người hoặc thông tin trong quá khứ đột nhiên xuất hiện trong tâm trí bạn."},"1231":{"word":"xuất hiện","meaning":"Bắt đầu tồn tại hoặc xuất hiện một cách rõ ràng, thường là lần đầu tiên."},"1232":{"word":"cá","meaning":"Một loài động vật sống dưới nước, thường có vây và vảy, và thở bằng mang."},"1233":{"word":"ba bốn","meaning":"Một số lượng nhỏ hơn năm nhưng lớn hơn hai."},"1234":{"word":"đứng","meaning":"Đặt chân trên mặt đất và giữ cơ thể ở tư thế thẳng đứng (đối với người hoặc động vật)."},"1235":{"word":"vội vàng, khẩn trương","meaning":"Làm gì đó một cách nhanh chóng vì không có nhiều thời gian."},"1236":{"word":"ngăn kéo","meaning":"Một bộ phận hình hộp của bàn hoặc tủ có thể kéo ra để đựng đồ."},"1237":{"word":"lẫn nhau, với nhau","meaning":"Diễn tả một hành động hoặc cảm xúc mà hai hay nhiều người hoặc vật hướng về phía nhau."},"1238":{"word":"tài liệu, hồ sơ","meaning":"Một hoặc nhiều tờ giấy có thông tin chính thức được viết hoặc in trên đó."},"1239":{"word":"dịch vụ","meaning":"Hành động giúp đỡ ai đó, hoặc một tiện ích mà một tổ chức cung cấp cho mọi người."},"1240":{"word":"phương Tây","meaning":"Các quốc gia nằm ở phía tây châu Á, chẳng hạn như ở châu Âu và Bắc Mỹ."},"1241":{"word":"phía Tây, hướng Tây","meaning":"Hướng mà mặt trời lặn vào buổi tối."},"1242":{"word":"trộn, pha trộn","meaning":"Đặt các thứ khác nhau lại với nhau để chúng trở thành một chất hoặc một nhóm."},"1243":{"word":"tiền bối","meaning":"Người có kinh nghiệm hơn và giữ vị trí cao hơn mình vì họ bắt đầu sự nghiệp trong cùng lĩnh vực sớm hơn."},"1244":{"word":"mát mẻ, se lạnh","meaning":"Diễn tả nhiệt độ dễ chịu, không nóng nhưng cũng không lạnh."},"1245":{"word":"vận động viên, cầu thủ","meaning":"Người tham gia một môn thể thao hoặc trò chơi, thường là thi đấu với người khác."},"1246":{"word":"lựa chọn, sự lựa chọn","meaning":"Hành động chọn một thứ trong số những thứ có sẵn."},"1247":{"word":"quạt điện","meaning":"Máy có cánh quay để tạo gió và làm mát không khí."},"1248":{"word":"rửa bát","meaning":"Hoạt động làm sạch các đồ dùng nhà bếp dơ bẩn bằng nước và xà phòng."},"1249":{"word":"Tết Nguyên đán (Hàn Quốc)","meaning":"Ngày lễ lớn của Hàn Quốc, rơi vào mùng một Tết âm lịch, khi các gia đình sum họp và thực hiện các nghi lễ truyền thống."},"1250":{"word":"seolleongtang","meaning":"Món súp truyền thống của Hàn Quốc, nấu từ xương bò hầm lâu cho đến khi nước dùng có màu trắng đục."},"1251":{"word":"đường","meaning":"Chất ngọt màu trắng, thường ở dạng tinh thể nhỏ, dùng để nêm nếm thức ăn và đồ uống."},"1252":{"word":"đảo","meaning":"Một mảnh đất được bao quanh hoàn toàn bởi nước."},"1253":{"word":"buồn, thất vọng, tiếc nuối","meaning":"Cảm thấy buồn hoặc thất vọng khi một sự kiện mong đợi không xảy ra hoặc khi ai đó rời đi."},"1254":{"word":"họ","meaning":"Tên gia đình được truyền từ cha mẹ sang con cái."},"1255":{"word":"tính cách","meaning":"Những đặc điểm về hành vi, suy nghĩ và cảm xúc thường thấy ở một người, tạo nên sự độc đáo của họ."},"1256":{"word":"thành công","meaning":"Khoảnh khắc hạnh phúc khi đạt được mục tiêu khó khăn hoặc một ý định quan trọng."},"1257":{"word":"điểm số, thành tích học tập","meaning":"Con số hoặc chữ cái cho biết kết quả học tập của học sinh trong một môn học hoặc bài kiểm tra."},"1258":{"word":"quý danh, tên (kính ngữ)","meaning":"Từ dùng để chỉ tên của một người một cách kính trọng, đặc biệt khi hỏi hoặc nói về tên của người khác."},"1259":{"word":"tuổi","meaning":"Từ dùng để chỉ số năm một người đã sống từ khi sinh ra."},"1260":{"word":"thế giới","meaning":"Toàn bộ trái đất, bao gồm các lục địa, đại dương và mọi sinh vật sống trên đó."},"1261":{"word":"mạnh","meaning":"Có nhiều sức mạnh thể chất, có thể di chuyển vật nặng hoặc chống chịu va đập."},"1262":{"word":"lễ lạy ngày Tết","meaning":"Hành động quỳ lạy, cúi đầu chạm đất để chào hỏi người lớn tuổi vào dịp Tết Nguyên Đán."},"1263":{"word":"thế gian","meaning":"Toàn bộ quả địa cầu nơi con người sinh sống và mọi trải nghiệm, tương tác diễn ra trong cuộc sống."},"1264":{"word":"dựng, làm cho đứng","meaning":"Làm cho một vật hoặc một người từ vị trí nằm hoặc ngồi chuyển sang tư thế thẳng đứng."},"1265":{"word":"giặt giũ","meaning":"Hành động làm sạch quần áo hoặc vải bằng nước và xà phòng để loại bỏ bụi bẩn và vết ố."},"1266":{"word":"máy giặt","meaning":"Thiết bị điện dùng nước và chuyển động quay để giặt sạch quần áo bẩn mà không cần giặt bằng tay."},"1267":{"word":"tiệm giặt ủi","meaning":"Nơi kinh doanh cung cấp dịch vụ giặt sạch quần áo, có thể có nhân viên hoặc khách hàng tự giặt."},"1268":{"word":"trung tâm","meaning":"Một tòa nhà hoặc địa điểm chính nơi cung cấp một bộ dịch vụ cụ thể hoặc diễn ra một hoạt động chính."},"1269":{"word":"xăngtimét","meaning":"Đơn vị nhỏ dùng để đo chiều dài, bằng một phần trăm của mét."},"1270":{"word":"thứ ba","meaning":"Từ chỉ vị trí liền sau vị trí thứ hai trong một chuỗi số."},"1271":{"word":"con bò","meaning":"Động vật nuôi lớn, thường có lông màu nâu hoặc đen trắng, được nuôi để lấy sữa hoặc thịt."},"1272":{"word":"thịt bò","meaning":"Phần thịt đỏ cắt từ con bò, được chế biến và ăn như một loại thực phẩm."},"1273":{"word":"âm thanh, tiếng","meaning":"Sóng âm thanh được tai nghe thấy, tạo ra khi một vật thể rung động."},"1274":{"word":"tiểu thuyết","meaning":"Một câu chuyện hư cấu dài, thường được đóng thành sách, kể về các nhân vật và sự kiện tưởng tượng."},"1275":{"word":"tin tức, tin","meaning":"Thông tin về các sự kiện hiện tại hoặc gần đây, thường được nghe, đọc hoặc xem trên TV hay báo chí."},"1276":{"word":"soju","meaning":"Một loại đồ uống có cồn trong suốt, được sản xuất ở Hàn Quốc, thường được rót vào những chiếc cốc nhỏ để uống."},"1277":{"word":"quý giá, đáng giá","meaning":"Diễn tả điều gì đó có giá trị cao, vì vậy được giữ an toàn, bảo vệ hoặc xử lý hết sức cẩn thận."},"1278":{"word":"ghế sofa","meaning":"Một món đồ nội thất dài, thường được bọc vải, có lưng tựa và tay vịn, nơi nhiều người có thể ngồi hoặc nằm."},"1279":{"word":"bưu kiện","meaning":"Một gói hàng nhỏ, được bọc cẩn thận và gửi qua đường bưu điện."},"1280":{"word":"chuyến dã ngoại, buổi dã ngoại","meaning":"Một chuyến đi chơi ngắn vui vẻ, thường là ngoài trời, nơi một bữa ăn đã chuẩn bị trước được ăn giữa thiên nhiên."},"1281":{"word":"thuốc tiêu hóa","meaning":"Một chất ở dạng viên hoặc chất lỏng mà một người dùng để hỗ trợ dạ dày của họ phân hủy thức ăn."},"1282":{"word":"bên trong, trong","meaning":"Phần của một vật thể hoặc vật chứa nằm bên trong ranh giới hoặc bề mặt bên ngoài của nó."},"1283":{"word":"tốc độ","meaning":"Tốc độ là mức độ nhanh chậm của một vật thể khi di chuyển một quãng đường nhất định trong một khoảng thời gian."},"1284":{"word":"đồ lót","meaning":"Đồ lót là loại quần áo mỏng, nhẹ mặc trực tiếp lên cơ thể bên trong các trang phục khác."},"1285":{"word":"ngón tay","meaning":"Ngón tay là một trong năm bộ phận thon dài, có khớp nối ở cuối bàn tay người."},"1286":{"word":"cháu gái","meaning":"Cháu gái là con gái của con trai hoặc con gái mình."},"1287":{"word":"lòng bàn tay","meaning":"Lòng bàn tay là bề mặt phẳng bên trong của bàn tay, nằm giữa cổ tay và các ngón tay."},"1288":{"word":"khăn tay","meaning":"Khăn tay là một mảnh vải nhỏ, mỏng thường được mang theo để lau chùi."},"1289":{"word":"songpyeon (bánh gạo)","meaning":"Songpyeon là một loại bánh gạo truyền thống của Hàn Quốc, có hình bán nguyệt, thường được làm từ bột nếp, hấp và nhân ngọt."},"1290":{"word":"số","meaning":"Số là một ký hiệu hoặc từ dùng để biểu thị một lượng, được dùng để đếm hoặc sắp xếp các vật."},"1291":{"word":"khăn","meaning":"Khăn là một mảnh vải mềm, có khả năng thấm hút, dùng để lau khô cơ thể hoặc các bề mặt khác."},"1292":{"word":"công sức","meaning":"Công sức là nỗ lực về thể chất hoặc tinh thần mà ai đó bỏ ra cho một công việc khó khăn, thường gây mệt mỏi."},"1293":{"word":"phẫu thuật","meaning":"Phẫu thuật là một thủ thuật y tế mà một chuyên gia mở hoặc thay đổi cơ thể người để điều trị chấn thương hoặc bệnh tật."},"1294":{"word":"đồ bơi","meaning":"Đồ bơi là trang phục chuyên dụng được thiết kế để mặc khi ngâm mình trong nước để bơi lội."},"1295":{"word":"bộ đũa thìa","meaning":"Dụng cụ ăn uống truyền thống của Hàn Quốc gồm đũa và thìa."},"1296":{"word":"canh Sundubu","meaning":"Một món canh hầm cay của Hàn Quốc làm từ đậu phụ non rất mềm, thường được ăn khi còn nóng hổi."},"1297":{"word":"thứ tự","meaning":"Cách sắp xếp hoặc diễn ra của các sự vật, hiện tượng theo một trật tự nhất định, hoặc thời điểm đến lượt hành động của ai đó."},"1298":{"word":"thìa","meaning":"Một dụng cụ ăn uống có hình bầu dục nhỏ ở một đầu và tay cầm, dùng để xúc thức ăn lỏng hoặc mềm."},"1299":{"word":"quán bar","meaning":"Nơi công cộng mà mọi người tụ tập để uống đồ uống có cồn, thường có âm nhạc hoặc giải trí."},"1300":{"word":"số","meaning":"Ký hiệu bằng chữ viết hoặc lời nói dùng để biểu thị số lượng, dùng để đếm, đo lường hoặc nhận biết."},"1301":{"word":"thở","meaning":"Hành động hít không khí vào và đẩy không khí ra khỏi cơ thể."},"1302":{"word":"năm mươi","meaning":"Số lượng tương đương với năm nhóm mười đơn vị, tức là 50."},"1303":{"word":"hai mươi","meaning":"Số lượng tương đương với hai nhóm mười đơn vị, tức là 20."},"1304":{"word":"tự mình","meaning":"Tự thực hiện một hành động nào đó mà không cần sự giúp đỡ hay hướng dẫn của người khác."},"1305":{"word":"áo len","meaning":"Loại áo ấm được đan từ len hoặc vải mềm khác, mặc ở phần thân trên, đặc biệt vào thời tiết lạnh."},"1306":{"word":"khăn quàng cổ","meaning":"Một mảnh vải dài hoặc hình vuông được quàng quanh cổ, đầu hoặc vai, thường để giữ ấm hoặc trang trí."},"1307":{"word":"giày trượt băng","meaning":"Đây là thiết bị dùng để trượt băng, có lưỡi kim loại gắn dưới đế giày."},"1308":{"word":"khu trượt tuyết","meaning":"Đây là một khu vực rộng lớn, thường ở trên núi tuyết, nơi mọi người đến để trượt ván trên tuyết."},"1309":{"word":"ngôi sao","meaning":"Người nổi tiếng hoặc vận động viên thể thao rất được yêu thích."},"1310":{"word":"căng thẳng","meaning":"Cảm giác áp lực hoặc lo lắng mạnh mẽ khiến một người cảm thấy mệt mỏi hoặc khó tập trung."},"1311":{"word":"mì Ý","meaning":"Một món ăn Ý phổ biến làm từ sợi mì dài, mỏng, thường ăn kèm với sốt."},"1312":{"word":"thể thao","meaning":"Một hoạt động cần đến sức khỏe và kỹ năng, thường được chơi theo đội hoặc cá nhân để giải trí hoặc thi đấu."},"1313":{"word":"đau buồn","meaning":"Thể hiện sự không vui hoặc đau khổ sâu sắc, thường bằng cách khóc hoặc trông ủ rũ."},"1314":{"word":"nỗi buồn","meaning":"Cảm giác không vui hoặc đau khổ sâu sắc, thường được thể hiện bằng nước mắt hoặc vẻ mặt ủ rũ."},"1315":{"word":"thói quen","meaning":"Một hành động hoặc hành vi thường ngày mà một người làm thường xuyên và tự động, không cần suy nghĩ nhiều."},"1316":{"word":"thành phố","meaning":"Một khu vực đông dân cư với nhiều tòa nhà, đường xá và chính quyền địa phương."},"1317":{"word":"lịch trình","meaning":"Một bảng liệt kê các công việc hoặc sự kiện được sắp xếp theo thời gian."},"1318":{"word":"đồng hồ","meaning":"Một thiết bị dùng để hiển thị giờ và phút hiện tại, thường có mặt số và kim hoặc số điện tử."},"1319":{"word":"nông thôn","meaning":"Nơi có nhiều cánh đồng, cây cối, ít nhà cửa và xa các thành phố lớn."},"1320":{"word":"ồn ào","meaning":"Phát ra nhiều tiếng động lớn, khó chịu khiến người khác khó nghe được điều khác."},"1321":{"word":"nội thành","meaning":"Khu vực trung tâm của một thành phố, nơi có nhiều hoạt động thương mại và hành chính."},"1322":{"word":"công dân","meaning":"Người chính thức sống ở một thành phố hoặc quốc gia cụ thể và có các quyền, trách nhiệm ở đó."},"1323":{"word":"mẹ chồng","meaning":"Người phụ nữ đã sinh ra chồng của một người đã kết hôn."},"1324":{"word":"thành viên gia đình","meaning":"Những người có quan hệ huyết thống hoặc hôn nhân, thường sống chung một nhà."},"1325":{"word":"nguội đi","meaning":"Từ trạng thái nóng hoặc ấm dần mất nhiệt và trở nên bớt nóng hơn."},"1326":{"word":"bánh mì sandwich","meaning":"Loại bánh mì mềm, nướng từ bột, thường có hình chữ nhật và được cắt thành nhiều lát mỏng."},"1327":{"word":"giấm","meaning":"Chất lỏng trong suốt hoặc màu nâu nhạt, có vị và mùi chua gắt, thường dùng để nêm nếm thức ăn hoặc bảo quản."},"1328":{"word":"bàn ăn","meaning":"Một món đồ nội thất có mặt phẳng, thường có bốn chân, nơi mọi người tụ tập để dùng bữa."},"1329":{"word":"thực phẩm","meaning":"Bất kỳ món nào con người hoặc động vật ăn hoặc uống để có năng lượng và duy trì sự sống."},"1330":{"word":"chú rể","meaning":"Người đàn ông sắp kết hôn hoặc vừa mới kết hôn, thường mặc trang phục đặc biệt trong buổi lễ."},"1331":{"word":"cô dâu","meaning":"Người phụ nữ sắp kết hôn hoặc vừa mới kết hôn."},"1332":{"word":"giấy tờ tùy thân","meaning":"Giấy tờ cá nhân có ảnh, tên và thông tin khác để chứng minh danh tính."},"1333":{"word":"tươi, tươi sống","meaning":"Mô tả thực phẩm như rau củ quả vừa mới thu hoạch, vẫn còn ngon và giữ được trạng thái tự nhiên."},"1334":{"word":"đơn đăng ký, sự đăng ký","meaning":"Hành động chính thức yêu cầu điều gì đó, thường bằng cách điền vào một biểu mẫu."},"1335":{"word":"tín hiệu, hiệu lệnh","meaning":"Dấu hiệu hoặc hành động như cử chỉ tay hay đèn báo, cho biết điều gì đang xảy ra hoặc cần phải làm gì."},"1336":{"word":"đèn giao thông","meaning":"Hệ thống đèn đỏ, vàng, xanh đặt ở ngã tư đường để điều khiển giao thông."},"1337":{"word":"tuần trăng mật","meaning":"Chuyến đi nghỉ đặc biệt của một cặp vợ chồng ngay sau khi kết hôn."},"1338":{"word":"chất lên, xếp lên","meaning":"Đặt đồ vật như hành lý hoặc hàng hóa lên phương tiện vận chuyển để di chuyển."},"1339":{"word":"lỗi, sai lầm","meaning":"Một hành động hoặc quyết định không đúng, thường do vô tình."},"1340":{"word":"thất bại","meaning":"Tình huống khi một người cố gắng làm gì đó nhưng không đạt được kết quả mong muốn."},"1341":{"word":"trồng","meaning":"Đặt hạt giống hoặc cây non xuống đất để chúng có thể bén rễ và phát triển."},"1342":{"word":"buồn chán","meaning":"Cảm thấy không có gì thú vị để làm, khiến thời gian trôi qua chậm chạp."},"1343":{"word":"quá mức","meaning":"Ở mức độ rất mạnh, rộng hoặc vượt quá mức bình thường."},"1344":{"word":"đóng gói","meaning":"Bọc đồ vật bằng giấy, vải hoặc vật liệu khác, hoặc cho đồ vào túi để chuẩn bị cho chuyến đi."},"1345":{"word":"cãi nhau","meaning":"Tranh cãi bằng lời nói giận dữ hoặc vật lộn về thể chất với người khác."},"1346":{"word":"gạo","meaning":"Hạt nhỏ, thường màu trắng, ăn được từ một loại cây thường trồng dưới nước, thường được nấu chín và ăn như lương thực chính."},"1347":{"word":"se lạnh","meaning":"Mô tả không khí hoặc thời tiết khá mát mẻ, khiến người ta cảm thấy hơi run rẩy hoặc cần mặc thêm quần áo ấm."},"1348":{"word":"xếp chồng","meaning":"Đặt nhiều thứ lên nhau thành từng lớp."},"1349":{"word":"thái","meaning":"Dùng dao hoặc dụng cụ sắc bén để chia thức ăn hoặc các vật khác thành những phần nhỏ hơn."},"1350":{"word":"đội","meaning":"Đặt một vật như mũ, nón hoặc tóc giả lên đầu."},"1351":{"word":"rác","meaning":"Những vật hoặc vật liệu không mong muốn mà người ta vứt bỏ, như thức ăn cũ, chai rỗng hoặc đồ hỏng."},"1352":{"word":"thùng rác","meaning":"Một vật chứa, thường có nắp, nơi mọi người bỏ những vật không muốn giữ nữa."},"1353":{"word":"nhai","meaning":"Dùng răng để nghiền thức ăn hoặc các vật khác thành miếng nhỏ hơn trong miệng."},"1354":{"word":"cô gái","meaning":"Một người phụ nữ trẻ, chưa lập gia đình."},"1355":{"word":"vừa nãy","meaning":"Diễn tả một sự việc, hành động xảy ra cách đây không lâu, thường có dấu vết hoặc hậu quả còn hiện hữu."},"1356":{"word":"phát thanh viên","meaning":"Người nói vào micro hoặc ống kính máy quay để đưa tin hoặc trình bày chương trình cho khán giả."},"1357":{"word":"không","meaning":"Từ cảm thán dùng để bày tỏ sự không đồng ý, từ chối hoặc ngạc nhiên."},"1358":{"word":"con trai","meaning":"Người nam giới là con của bố mẹ."},"1359":{"word":"phía dưới","meaning":"Phần hoặc khu vực của một vật gì đó gần mặt đất hơn hoặc ở mức thấp hơn so với phần khác."},"1360":{"word":"có lẽ","meaning":"Từ biểu thị một điều gì đó không chắc chắn và có thể xảy ra theo nhiều cách khác nhau."},"1361":{"word":"bất cứ","meaning":"Từ dùng để chỉ một người hoặc vật nào đó không cụ thể, không được xác định rõ ràng."},"1362":{"word":"bất cứ cái gì","meaning":"Một vật, một việc không cụ thể hoặc không được xác định rõ ràng."},"1363":{"word":"dù thế nào đi nữa","meaning":"Từ nhấn mạnh rằng một tình huống hoặc kết quả cụ thể sẽ xảy ra hoặc đúng, bất kể điều kiện khó khăn hay nỗ lực lớn đến đâu."},"1364":{"word":"bố (kính ngữ)","meaning":"Từ kính trọng dùng để gọi hoặc chỉ người cha ruột hoặc bố chồng/vợ."},"1365":{"word":"bố","meaning":"Từ thân mật, gần gũi mà trẻ em dùng để gọi người cha của mình."},"1366":{"word":"cô","meaning":"Từ thường dùng để gọi hoặc chỉ người phụ nữ đã kết hôn hoặc trung niên, thường dùng bởi người trẻ tuổi hơn."},"1367":{"word":"nhạc cụ","meaning":"Vật dùng để tạo ra âm thanh có giai điệu, ví dụ như đàn guitar hay đàn piano."},"1368":{"word":"sương mù","meaning":"Hiện tượng hơi nước ngưng tụ thành những hạt nhỏ li ti lơ lửng gần mặt đất, làm giảm tầm nhìn."},"1369":{"word":"thông báo","meaning":"Lời nhắn hoặc văn bản cung cấp thông tin cụ thể cho một nhóm người, thường được công bố công khai."},"1370":{"word":"ôm","meaning":"Đặt tay quanh một người hoặc vật và giữ chặt vào người mình."},"1371":{"word":"không thành công","meaning":"Khi một nỗ lực hay kế hoạch không đạt được kết quả tích cực như mong đợi."},"1372":{"word":"an toàn","meaning":"Tình trạng không có nguy hiểm hay rủi ro gây hại."},"1373":{"word":"bên trong","meaning":"Không gian hoặc khu vực nằm trong giới hạn của một vật thể hoặc địa điểm."},"1374":{"word":"phù hợp","meaning":"Thỏa mãn một tiêu chuẩn, điều kiện hoặc mức độ nhất định mà không quá mức hay không đủ."},"1375":{"word":"tìm hiểu","meaning":"Thu thập thông tin hoặc chi tiết cụ thể về điều gì đó, thường bằng cách tra cứu hoặc hỏi."},"1376":{"word":"phía trước","meaning":"Phần của một vật thể hoặc vị trí hướng về phía trước hoặc nằm ở rìa dẫn đầu."},"1377":{"word":"trẻ con","meaning":"Một người còn rất nhỏ, chưa phải là người lớn."},"1378":{"word":"người yêu","meaning":"Người mà một ai đó có mối quan hệ tình cảm lãng mạn và thân mật."},"1379":{"word":"album","meaning":"Một cuốn sách dùng để lưu giữ ảnh hoặc tập hợp các bài hát được phát hành cùng nhau."},"1380":{"word":"Này!","meaning":"Một tiếng kêu hoặc lời cảm thán dùng để thu hút sự chú ý của ai đó một cách nhanh chóng."},"1381":{"word":"rau củ","meaning":"Các bộ phận của cây như lá, thân, rễ được trồng để ăn."},"1382":{"word":"một chút","meaning":"Ở một mức độ nhỏ hoặc không đáng kể."},"1383":{"word":"dược sĩ","meaning":"Người có chuyên môn được đào tạo và cấp phép để bào chế và phân phát thuốc tại nhà thuốc."},"1384":{"word":"yếu","meaning":"Không có sức mạnh, năng lượng hoặc dễ dàng bị đánh bại."},"1385":{"word":"mỏng","meaning":"Có khoảng cách rất nhỏ từ bề mặt này đến bề mặt đối diện."},"1386":{"word":"tất","meaning":"Vật dụng dùng để mang vào chân, thường che mắt cá và đôi khi cao hơn."},"1387":{"word":"bộ vest","meaning":"Bộ quần áo trang trọng bao gồm áo khoác và quần hoặc váy đồng bộ."},"1388":{"word":"món ăn phương Tây","meaning":"Thức ăn được chế biến theo phương pháp và công thức từ các nước châu Âu."},"1389":{"word":"nhà hàng phương Tây","meaning":"Nơi mọi người đến để mua và ăn các bữa ăn được chế biến theo phong cách ẩm thực châu Âu."},"1390":{"word":"đánh răng","meaning":"Hành động làm sạch răng bằng bàn chải nhỏ và kem đánh răng để loại bỏ thức ăn và mảng bám."},"1391":{"word":"câu chuyện","meaning":"Những lời dùng để kể cho người khác nghe về một sự việc, trạng thái, hiện tượng, kinh nghiệm hay suy nghĩ nào đó."},"1392":{"word":"ơ","meaning":"Tiếng kêu thốt ra từ miệng thể hiện sự ngạc nhiên, suy nghĩ hoặc một câu hỏi."},"1393":{"word":"vai","meaning":"Bộ phận cơ thể nằm giữa phần dưới của cổ và phần trên của cánh tay."},"1394":{"word":"tối","meaning":"Không sáng sủa do thiếu ánh sáng."},"1395":{"word":"thế nào","meaning":"Dùng để hỏi hoặc diễn tả về hình dáng, tình trạng của sự vật, sự việc nào đó."},"1396":{"word":"người lớn","meaning":"Người đã trưởng thành hoàn toàn."},"1397":{"word":"trẻ","meaning":"Ở giai đoạn đầu của cuộc đời hoặc sự phát triển, thường dùng để chỉ một đứa trẻ nhỏ chưa sống được nhiều năm."},"1398":{"word":"trẻ con","meaning":"Một cậu bé hoặc cô bé còn nhỏ tuổi."},"1399":{"word":"trẻ em","meaning":"Con người đang ở giai đoạn đầu của cuộc đời và chưa đến tuổi trưởng thành."},"1400":{"word":"mẹ (kính trọng)","meaning":"Người phụ nữ đáng kính đã sinh ra con cái."},"1401":{"word":"hòa nhập","meaning":"Cùng nhau sinh hoạt, vui chơi, có mối quan hệ thân thiết với người khác."},"1402":{"word":"đêm qua","meaning":"Khoảng thời gian từ lúc mặt trời lặn đến lúc mặt trời mọc của ngày liền trước ngày hôm nay."},"1403":{"word":"ngôn ngữ","meaning":"Hệ thống các âm thanh, ký hiệu hoặc cử chỉ mà con người sử dụng để giao tiếp ý tưởng và cảm xúc với nhau."},"1404":{"word":"luôn luôn, lúc nào cũng","meaning":"Diễn tả việc xảy ra hoặc tồn tại vào mọi thời điểm mà không có ngoại lệ."},"1405":{"word":"đạt được, nhận được","meaning":"Có được thứ gì đó, bằng cách nhận từ người khác hoặc tìm thấy."},"1406":{"word":"đóng băng","meaning":"Chất lỏng chuyển sang trạng thái rắn, như nước biến thành băng, do nhiệt độ rất thấp."},"1407":{"word":"băng","meaning":"Nước bị đông cứng lại và rắn chắc."},"1408":{"word":"mẹ","meaning":"Người phụ nữ là cha mẹ của con trai hoặc con gái, thường dùng với thái độ thân mật."},"1409":{"word":"mông","meaning":"Phần thịt mềm giữa eo và đùi, tiếp xúc với mặt sàn khi ngồi."},"1410":{"word":"thang máy","meaning":"Một căn phòng nhỏ kín di chuyển lên xuống bên trong tòa nhà để chở người hoặc đồ vật giữa các tầng."},"1411":{"word":"đây đó, khắp nơi","meaning":"Một hoặc nhiều địa điểm khác nhau, không được xác định rõ ràng."},"1412":{"word":"nữ giới, phụ nữ","meaning":"Người thuộc giới tính nữ."},"1413":{"word":"hỏi (kính ngữ)","meaning":"Đặt câu hỏi cho người khác một cách rất tôn trọng, thường để lấy thông tin."},"1414":{"word":"nữ sinh","meaning":"Người trẻ tuổi đang đi học và thuộc giới tính nữ."},"1415":{"word":"điểm du lịch","meaning":"Nơi mọi người ghé thăm để nghỉ ngơi hoặc giải trí."},"1416":{"word":"lịch sử","meaning":"Toàn bộ sự kiện quan trọng đã xảy ra trong quá khứ."},"1417":{"word":"quả nhiên","meaning":"Diễn tả sự việc xảy ra đúng như dự đoán hoặc suy nghĩ ban đầu."},"1418":{"word":"kết nối","meaning":"Trạng thái hai hoặc nhiều vật riêng biệt được gắn kết hoặc liên kết với nhau."},"1419":{"word":"liên lạc","meaning":"Việc gửi hoặc nhận thông tin giữa người với người."},"1420":{"word":"thông tin liên lạc","meaning":"Các chi tiết như số điện thoại hoặc địa chỉ email để liên hệ với ai đó."},"1421":{"word":"cuối năm","meaning":"Thời điểm những tuần hoặc ngày cuối cùng của năm dương lịch, thường có các lễ kỷ niệm."},"1422":{"word":"tuổi (kính ngữ)","meaning":"Số năm một người đã sống, dùng để nói một cách kính trọng với người lớn tuổi."},"1423":{"word":"người nổi tiếng","meaning":"Người được nhiều người biết đến và ngưỡng mộ, thường xuất hiện trong phim ảnh, truyền hình hoặc ca nhạc."},"1424":{"word":"kỳ nghỉ lễ liên tiếp","meaning":"Khoảng thời gian nhiều ngày nghỉ lễ chính thức hoặc ngày nghỉ học liên tiếp."},"1425":{"word":"sốt","meaning":"Tình trạng thân nhiệt của cơ thể tăng cao hơn bình thường do bệnh tật."},"1426":{"word":"mở ra","meaning":"Cửa hoặc vật tương tự di chuyển để không còn chặn lối vào hoặc để lộ ra thứ bên trong."},"1427":{"word":"tàu hỏa","meaning":"Là một phương tiện giao thông chạy trên đường ray, gồm nhiều toa nối liền nhau."},"1428":{"word":"mười ngày","meaning":"Là khoảng thời gian có độ dài bằng mười ngày."},"1429":{"word":"bưu thiếp","meaning":"Là một tấm thiếp nhỏ thường có hình ảnh ở một mặt, dùng để gửi thư mà không cần phong bì."},"1430":{"word":"hóa đơn","meaning":"Là một mảnh giấy ghi lại chi tiết về việc giao dịch tiền bạc hoặc hàng hóa."},"1431":{"word":"âm độ","meaning":"Là nhiệt độ thấp hơn 0 độ C, thường được biểu thị bằng dấu âm."},"1432":{"word":"nhà bên cạnh","meaning":"Là ngôi nhà hoặc không gian sống nằm ngay sát bên cạnh nhà mình."},"1433":{"word":"đặt trước","meaning":"Là hành động mua vé hoặc giữ chỗ trước cho một sự kiện, chuyến đi hoặc dịch vụ."},"1434":{"word":"sáu mươi","meaning":"Là số lượng hoặc con số bằng sáu chục."},"1435":{"word":"nghệ thuật","meaning":"Là hoạt động sáng tạo của con người tạo ra các hình thức thị giác, âm nhạc hoặc tác phẩm văn học."},"1436":{"word":"chuẩn bị bài","meaning":"Là việc tự mình học hoặc xem trước bài học trước khi được giảng trên lớp."},"1437":{"word":"đặt chỗ","meaning":"Là hành động sắp xếp để một căn phòng, bàn ăn hoặc khung thời gian được giữ cho việc sử dụng trong tương lai."},"1438":{"word":"cũ","meaning":"Dùng để chỉ những gì đã tồn tại hoặc xảy ra từ nhiều năm về trước."},"1439":{"word":"ngày xưa","meaning":"Khoảng thời gian rất lâu trước hiện tại."},"1440":{"word":"lâu","meaning":"Trong một khoảng thời gian dài."},"1441":{"word":"lâu rồi","meaning":"Tình trạng đã lâu rồi kể từ khi điều gì đó xảy ra."},"1442":{"word":"cũ","meaning":"Đã tồn tại trong nhiều năm, cho thấy dấu hiệu của tuổi tác hoặc đã được sử dụng lâu."},"1443":{"word":"lâu rồi","meaning":"Tình trạng đã lâu rồi kể từ khi điều gì đó xảy ra."},"1444":{"word":"trong thời gian dài","meaning":"Trong một khoảng thời gian dài đáng kể, chỉ một hành động hoặc trạng thái liên tục."},"1445":{"word":"tăng","meaning":"(Giá cả, số liệu, năng lượng, v.v.) trở nên cao hơn hoặc tăng lên."},"1446":{"word":"tay phải","meaning":"Bộ phận cơ thể ở cuối cánh tay, có lòng bàn tay và năm ngón tay, thường dùng để viết hoặc ném, và nằm ở phía đối diện với tim."},"1447":{"word":"dưa chuột","meaning":"Một loại rau có vỏ màu xanh dài, thường được cắt lát và ăn sống trong món salad."},"1448":{"word":"nhiệt độ","meaning":"Một thước đo mức độ nóng hoặc lạnh của vật thể, thường được hiển thị bằng số trên đồng hồ."},"1449":{"word":"đi lên","meaning":"Di chuyển từ một nơi thấp hơn đến một nơi cao hơn."},"1450":{"word":"tăng","meaning":"Làm cho giá cả, số liệu, năng lượng, v.v. trở nên cao hơn hoặc tăng lên."},"1451":{"word":"trân trọng","meaning":"Đây là từ đặt ở cuối thư hoặc tin nhắn trước tên người gửi để thể hiện sự kính trọng."},"1452":{"word":"Thế vận hội Olympic","meaning":"Đây là sự kiện thể thao quốc tế lớn được tổ chức bốn năm một lần với sự tham gia của các vận động viên từ khắp nơi trên thế giới."},"1453":{"word":"đúng","meaning":"Tính từ mô tả một điều gì đó không có lỗi hoặc sai sót, phù hợp chính xác theo quy tắc hoặc sự thật."},"1454":{"word":"móc áo","meaning":"Vật dụng dùng để treo quần áo, giữ cho quần áo không bị nhăn, thường có hình dạng cong hoặc tam giác."},"1455":{"word":"tủ quần áo","meaning":"Đồ nội thất cao, có cửa, dùng để cất giữ quần áo, thường có chỗ treo và kệ."},"1456":{"word":"áo sơ mi","meaning":"Loại áo mặc ở phần thân trên, thường có tay và hàng nút phía trước, thường được mặc bên trong áo khoác."},"1457":{"word":"hoàn toàn","meaning":"Trạng thái hoặc hành động mà mọi phần đều được bao gồm hoặc không thiếu bất cứ điều gì."},"1458":{"word":"vua","meaning":"Người cai trị nam giới của một quốc gia, thường được miêu tả đội vương miện và ngồi trên ngai vàng."},"1459":{"word":"bởi vì","meaning":"Từ dùng để chỉ ra lý do hoặc giải thích cho một hành động hoặc kết quả."},"1460":{"word":"cô đơn","meaning":"Tính từ mô tả cảm giác buồn bã, không vui khi một người không có người khác ở bên và mong muốn có bạn bè."},"1461":{"word":"học thuộc lòng","meaning":"Hành động lặp đi lặp lại việc đọc hoặc nói thông tin cho đến khi có thể nhớ hoàn hảo mà không cần nhìn."},"1462":{"word":"việc ra ngoài","meaning":"Hành động một người rời khỏi bên trong một tòa nhà để dành thời gian ở ngoài trời hoặc nơi khác."},"1463":{"word":"tay trái","meaning":"Bộ phận trên cánh tay của con người, nằm ở phía tim và thường không phải tay thuận để viết."},"1464":{"word":"phí, cước phí","meaning":"Số tiền phải trả để sử dụng một dịch vụ hoặc để vào một địa điểm nào đó."},"1465":{"word":"đầu bếp","meaning":"Người có công việc chuẩn bị và nấu ăn, đặc biệt là trong nhà hàng."},"1466":{"word":"mì Udon","meaning":"Một loại mì sợi dày của Nhật Bản, hoặc món súp được làm từ loại mì này."},"1467":{"word":"đất nước chúng tôi, Hàn Quốc","meaning":"Cách người Hàn Quốc gọi quốc gia của mình, Cộng hòa Hàn Quốc."},"1468":{"word":"trước tiên, ưu tiên","meaning":"Diễn tả việc gì đó được thực hiện ở vị trí đầu tiên hoặc có tầm quan trọng hơn."},"1469":{"word":"quần áo thể thao","meaning":"Trang phục thoải mái được thiết kế để mặc khi tập thể dục hoặc tham gia các hoạt động thể chất."},"1470":{"word":"tài xế, người lái xe","meaning":"Người có công việc hoặc vai trò điều khiển và lái một phương tiện giao thông."},"1471":{"word":"Ulsan","meaning":"Một thành phố công nghiệp lớn nằm ở bờ biển phía đông nam của Hàn Quốc."},"1472":{"word":"tiếng khóc, sự khóc","meaning":"Âm thanh và nước mắt chảy ra khi một người cảm thấy rất buồn hoặc bị tổn thương."},"1473":{"word":"di chuyển, cử động","meaning":"Thay đổi vị trí của một vật hoặc một người từ chỗ này sang chỗ khác."},"1474":{"word":"tiếng cười, sự cười","meaning":"Âm thanh phát ra từ miệng khi một người cảm thấy vui vẻ hoặc thấy điều gì đó buồn cười."},"1475":{"word":"váy liền","meaning":"Loại quần áo dành cho phụ nữ, gồm áo và váy liền thành một mảnh."},"1476":{"word":"mong muốn","meaning":"Có ý nghĩ mạnh mẽ rằng mình muốn nhận được hoặc thấy một điều gì đó xảy ra."},"1477":{"word":"lương tháng","meaning":"Số tiền định kỳ mà người lao động nhận được từ người sử dụng lao động vào cuối mỗi tháng."},"1478":{"word":"phía trên","meaning":"Phần hoặc hướng cao hơn, ở phía trên so với một vật khác."},"1479":{"word":"vị trí","meaning":"Nơi hoặc khu vực cụ thể mà một người hoặc một vật thể được tìm thấy."},"1480":{"word":"nguy hiểm","meaning":"Tình huống mà khả năng xảy ra tai họa hoặc tổn hại cho ai đó hoặc vật gì đó là cao."},"1481":{"word":"kính","meaning":"Vật liệu cứng, trong suốt, dễ vỡ, thường dùng làm cửa sổ hoặc đồ dùng uống nước."},"1482":{"word":"trường mẫu giáo","meaning":"Trường dành cho trẻ nhỏ, thường từ ba đến năm tuổi, để chơi và học trước khi vào trường tiểu học."},"1483":{"word":"du học","meaning":"Việc đi sang một đất nước khác để sinh sống và học tập tại trường học hoặc đại học ở đó."},"1484":{"word":"du học sinh","meaning":"Người trẻ tuổi học tập tại một trường học hoặc đại học ở nước không phải là quê hương của mình."},"1485":{"word":"xu hướng","meaning":"Một phong cách hoặc cách ứng xử phổ biến mà nhiều người bắt đầu theo trong một khoảng thời gian."},"1486":{"word":"cầu vượt đi bộ","meaning":"Một cây cầu được xây dựng để người đi bộ đi qua, thường bắc qua đường phố hoặc đường ray xe lửa."},"1487":{"word":"trò chơi 윷놀이","meaning":"Một trò chơi dân gian truyền thống của Hàn Quốc, dùng bốn que gỗ đặc biệt để di chuyển quân cờ trên bàn."},"1488":{"word":"đồ uống","meaning":"Chất lỏng được con người tiêu thụ để giải khát hoặc thưởng thức."},"1489":{"word":"nhà hàng","meaning":"Nơi công cộng để khách hàng mua và ăn các bữa ăn đã được chế biến sẵn."},"1490":{"word":"nhạc sĩ","meaning":"Người sáng tạo, chơi hoặc biểu diễn âm nhạc, thường dùng nhạc cụ hoặc giọng hát."},"1491":{"word":"ừ","meaning":"Tiếng kêu hoặc lời đáp thông thường dùng để thể hiện sự đồng ý hoặc xác nhận."},"1492":{"word":"ý nghĩa","meaning":"Ý tưởng hoặc khái niệm mà một từ, ký hiệu hoặc hành động đại diện hoặc truyền tải."},"1493":{"word":"răng","meaning":"Một trong những cấu trúc cứng, màu trắng trong miệng, dùng để cắn và nhai thức ăn."},"1494":{"word":"cái này","meaning":"Một vật thể ở gần người nói, được người nói chỉ hoặc cầm."},"1495":{"word":"nơi này","meaning":"Vị trí hoặc khu vực cụ thể mà một người đang ở hoặc chỉ vào."},"1496":{"word":"thắng","meaning":"Đánh bại và làm tốt hơn đối thủ trong một cuộc thi, trận đấu, v.v."},"1497":{"word":"ngày này","meaning":"Khoảng thời gian 24 giờ cụ thể được đề cập đến."},"1498":{"word":"lúc này","meaning":"Thời điểm hoặc khoảng thời gian cụ thể khi một hành động hoặc sự kiện diễn ra."},"1499":{"word":"như thế này","meaning":"Dùng để chỉ một người, sự vật hoặc tình huống giống như những gì vừa được đề cập hoặc chỉ ra."},"1500":{"word":"như thế này","meaning":"Có hình dạng, trạng thái hoặc tính chất giống như những gì đã được thể hiện hoặc mô tả."},"1501":{"word":"sớm","meaning":"Diễn ra hoặc đến trước thời gian thông thường, dự kiến hoặc đã định."},"1502":{"word":"trán","meaning":"Phần trên khuôn mặt người, nằm giữa mắt và chân tóc."},"1503":{"word":"dì","meaning":"Chị hoặc em gái của mẹ."},"1504":{"word":"đã","meaning":"Dùng để chỉ một hành động hoặc sự việc đã hoàn thành hoặc xảy ra trước thời điểm hiện tại hoặc một thời điểm được xác định."},"1505":{"word":"vị này","meaning":"Dùng để chỉ một người ở gần người nói và đang được giới thiệu hoặc chỉ ra."},"1506":{"word":"chăn","meaning":"Tấm vải mềm, lớn dùng để giữ ấm, đặc biệt là để đắp khi ngủ hoặc nghỉ ngơi."},"1507":{"word":"chuyển nhà","meaning":"Hành động di chuyển tất cả tài sản từ nơi ở này sang nơi ở khác."},"1508":{"word":"đồ đạc chuyển nhà","meaning":"Tất cả các vật dụng cá nhân, đồ nội thất và hộp được đóng gói và vận chuyển khi một người thay đổi chỗ ở."},"1509":{"word":"trở lên","meaning":"Chỉ một số lượng hoặc mức độ lớn hơn hoặc bằng một giá trị hoặc tiêu chuẩn cụ thể."},"1510":{"word":"bất thường","meaning":"Điều gì đó không bình thường, không mong đợi hoặc khác so với những gì được coi là bình thường."},"1511":{"word":"sử dụng","meaning":"Hành động dùng một vật, công cụ hay phương tiện để đạt được mục đích nào đó."},"1512":{"word":"khu vực lân cận","meaning":"Một khu vực trong thị trấn hoặc thành phố nơi có nhiều nhà cửa và tòa nhà nằm gần nhau."},"1513":{"word":"trước đây","meaning":"Thời điểm hoặc sự việc đã xảy ra vào một lúc nào đó trong quá khứ."},"1514":{"word":"bây giờ","meaning":"Khoảnh khắc chính xác đang diễn ra ngay tại thời điểm hiện tại."},"1515":{"word":"hai ngày","meaning":"Khoảng thời gian bao gồm một ngày đầy đủ và một ngày đầy đủ khác tiếp theo."},"1516":{"word":"sự hiểu biết","meaning":"Khả năng nắm bắt ý nghĩa hoặc cách thức hoạt động của một điều gì đó một cách rõ ràng."},"1517":{"word":"sau đó","meaning":"Thời gian hoặc sự kiện xảy ra tiếp theo một khoảnh khắc hoặc sự việc cụ thể."},"1518":{"word":"chín","meaning":"(Thức ăn, trái cây) Trở nên mềm, đổi màu hoặc biến đổi do nhiệt để sẵn sàng ăn."},"1519":{"word":"quen thuộc","meaning":"Đã thấy hoặc làm nhiều lần nên cảm thấy bình thường, dễ dàng thực hiện hoặc nhận ra."},"1520":{"word":"sự nổi tiếng","meaning":"Tình trạng được nhiều người biết đến, quan tâm và yêu thích."},"1521":{"word":"nhân sâm","meaning":"Một loại rễ cây dày, màu nhạt, thường được dùng vì các lợi ích sức khỏe truyền thống."},"1522":{"word":"búp bê","meaning":"Một hình tượng nhỏ, thường giống người hoặc động vật, làm từ vật liệu mềm hoặc nhựa, dùng cho trẻ em chơi."},"1523":{"word":"nhật ký","meaning":"Quyển sổ dùng để ghi lại những việc đã xảy ra, suy nghĩ hoặc cảm xúc của một người hàng ngày."},"1524":{"word":"một phần","meaning":"Một bộ phận nhỏ cấu thành nên một tổng thể lớn hơn."},"1525":{"word":"món ăn Nhật","meaning":"Món ăn được chế biến theo phong cách và nguyên liệu truyền thống của Nhật Bản."},"1526":{"word":"nhà hàng Nhật","meaning":"Nơi bán và phục vụ các món ăn truyền thống của Nhật Bản."},"1527":{"word":"đứng dậy","meaning":"Chuyển từ tư thế ngồi hoặc nằm sang tư thế thẳng đứng bằng chân."},"1528":{"word":"mất","meaning":"Không còn sở hữu được thứ gì đó nữa vì nó đã biến mất mà mình không nhận ra."},"1529":{"word":"đánh mất","meaning":"Làm mất một vật nào đó nên không thể tìm thấy lại được nữa."},"1530":{"word":"lối vào","meaning":"Chỗ đi vào hoặc đi ra của một tòa nhà hay khu vực nào đó."},"1531":{"word":"môi","meaning":"Hai phần mềm mại, di động ở bên ngoài miệng của con người."},"1532":{"word":"nhập viện","meaning":"Việc ở lại bệnh viện để được chăm sóc và điều trị bệnh hoặc vết thương."},"1533":{"word":"vé vào cửa","meaning":"Tấm vé cho phép một người đi vào một sự kiện hoặc địa điểm cụ thể."},"1534":{"word":"nhập học","meaning":"Việc chính thức được chấp nhận vào học tại một trường học hoặc cơ sở giáo dục."},"1535":{"word":"quên","meaning":"Không còn nhớ hoặc không thể nhớ lại một điều gì đó đã biết trước đây."},"1536":{"word":"quên","meaning":"Không nhớ hoặc không thể nhớ lại một điều gì đó đã biết."},"1537":{"word":"lá","meaning":"Bộ phận dẹt, thường có màu xanh, mọc từ thân hoặc cành cây."},"1538":{"word":"tự giới thiệu","meaning":"Hành động nói cho người khác biết tên và một số thông tin cá nhân của mình."},"1539":{"word":"thường xuyên, liên tục","meaning":"Diễn ra nhiều lần hoặc trong khoảng thời gian ngắn."},"1540":{"word":"máy bán hàng tự động","meaning":"Máy dùng để mua các mặt hàng nhỏ như đồ ăn nhẹ hoặc đồ uống bằng cách nhét tiền vào."},"1541":{"word":"lớn lên, phát triển","meaning":"Đối với sinh vật sống, trở nên to lớn hơn một phần hoặc toàn bộ."},"1542":{"word":"sự khoe khoang, sự tự hào","meaning":"Lời nói hoặc hành động thể hiện niềm tự hào quá mức về thành tích, tài sản hoặc khả năng của bản thân."},"1543":{"word":"cắt","meaning":"Chia một vật thành hai hoặc nhiều phần bằng dụng cụ sắc nhọn như kéo hoặc dao."},"1544":{"word":"chỗ, vị trí","meaning":"Nơi cụ thể để một người có thể ngồi, hoặc không gian để đặt một vật."},"1545":{"word":"chi tiết","meaning":"Giải thích một điều gì đó bằng cách bao gồm tất cả các sự kiện và thông tin cụ thể, không bỏ sót bất cứ điều gì."},"1546":{"word":"con cái","meaning":"Một người trẻ tuổi, đặc biệt là con trai hoặc con gái của ai đó."},"1547":{"word":"bản thân","meaning":"Toàn bộ thể chất và tinh thần của một người."},"1548":{"word":"tự nhiên","meaning":"Thế giới vật chất xung quanh chúng ta, bao gồm cây cối, động vật, núi, sông và bầu trời."},"1549":{"word":"tự do","meaning":"Trạng thái một người có thể di chuyển, hành động và nói theo ý muốn mà không bị ai khác ngăn cản hay kiểm soát."},"1550":{"word":"mì Jajangmyeon","meaning":"Món mì trộn với sốt đậu tương đen xào thịt và rau củ."},"1551":{"word":"máy bán hàng tự động","meaning":"Thiết bị hình hộp, dùng để mua đồ uống hoặc đồ ăn nhẹ bằng cách cho tiền vào và nhấn nút."},"1552":{"word":"tiệc","meaning":"Buổi tụ họp đông người để ăn mừng một dịp đặc biệt, thường có đồ ăn, thức uống và âm nhạc."},"1553":{"word":"thuận lợi","meaning":"Một công việc hay sự việc diễn ra suôn sẻ, thành công theo mong muốn."},"1554":{"word":"sai","meaning":"Diễn ra không chính xác hoặc không như dự định, dẫn đến vấn đề hoặc kết quả không mong muốn."},"1555":{"word":"làm sai","meaning":"Thực hiện một hành động không đúng cách, gây ra lỗi hoặc kết quả không mong muốn."},"1556":{"word":"đẹp trai","meaning":"Dùng để miêu tả người đàn ông có khuôn mặt và vẻ ngoài ưa nhìn, hấp dẫn."},"1557":{"word":"ngủ","meaning":"Nằm xuống, nhắm mắt và chìm vào trạng thái bất tỉnh trong một khoảng thời gian để nghỉ ngơi."},"1558":{"word":"nắm","meaning":"Giữ chặt một vật gì đó trong tay mà không buông ra."},"1559":{"word":"tạp chí","meaning":"Một ấn phẩm định kỳ chứa nhiều bài viết và hình ảnh màu sắc."},"1560":{"word":"tờ","meaning":"Từ dùng để đếm các vật mỏng, phẳng như giấy hoặc các trang trong sách."},"1561":{"word":"găng tay","meaning":"Vật dùng để đeo vào tay để giữ ấm hoặc bảo vệ, thường có các ngón riêng."},"1562":{"word":"đồ chơi","meaning":"Vật nhỏ mà trẻ em dùng để giải trí, như búp bê hay xe hơi."},"1563":{"word":"mùa mưa","meaning":"Một khoảng thời gian cụ thể trong năm, thường vào mùa hè, khi trời mưa rất nhiều."},"1564":{"word":"hoa hồng","meaning":"Một loài cây có thân gai và hoa đẹp, thường có màu đỏ, hồng hoặc trắng với mùi thơm."},"1565":{"word":"nguyên liệu","meaning":"Những thứ được dùng để tạo ra hoặc xây dựng một vật gì đó."},"1566":{"word":"niềm vui","meaning":"Cảm giác thích thú, dễ chịu khi tham gia hoặc trải nghiệm một điều gì đó."},"1567":{"word":"hắt hơi","meaning":"Hành động đẩy không khí ra khỏi mũi và miệng một cách đột ngột và mạnh mẽ."},"1568":{"word":"cái kia","meaning":"Từ dùng để chỉ một vật ở xa người nói và người nghe."},"1569":{"word":"chỗ kia","meaning":"Từ dùng để chỉ một địa điểm ở xa người nói."},"1570":{"word":"tiền tiết kiệm","meaning":"Hành động gửi tiền vào ngân hàng hoặc số tiền đã được cất giữ."},"1571":{"word":"như thế, loại đó","meaning":"Từ dùng để chỉ người hoặc vật có đặc điểm tương tự với điều đã nói hoặc đã thấy từ xa."},"1572":{"word":"như thế đó, như vậy đó","meaning":"Diễn tả một vật hoặc tình huống có đặc điểm hay hình thức tương tự một ví dụ cụ thể đã được chỉ ra hoặc đề cập, thường là ở xa."},"1573":{"word":"lần trước, bữa trước","meaning":"Khoảng thời gian hoặc sự kiện vừa mới xảy ra, ngay trước thời điểm hiện tại."},"1574":{"word":"vị đó, người đó","meaning":"Đại từ dùng để chỉ một người ở xa một cách lịch sự."},"1575":{"word":"chúng tôi, chúng em","meaning":"Đại từ được người nói dùng để chỉ một nhóm người bao gồm cả mình, khi nói chuyện với người có địa vị cao hơn."},"1576":{"word":"ghi, viết","meaning":"Dùng bút chì hoặc bút mực để tạo chữ cái, từ ngữ hoặc số trên một bề mặt như giấy."},"1577":{"word":"thích hợp, phù hợp","meaning":"Có đặc điểm phù hợp hoặc đúng đắn với một tình huống hay mục đích cụ thể."},"1578":{"word":"toàn bộ, tất cả","meaning":"Từ chỉ toàn bộ số lượng hoặc phạm vi đầy đủ của một sự vật, không thiếu phần nào."},"1579":{"word":"điện","meaning":"Một dạng năng lượng vô hình chảy qua dây dẫn, dùng để thắp sáng, vận hành máy móc và làm nóng đồ vật."},"1580":{"word":"toàn bộ, tất cả","meaning":"Chỉ toàn thể, không bỏ sót một phần nào, hoặc thực hiện một hành động một cách hoàn toàn."},"1581":{"word":"tàu điện ngầm, tàu điện","meaning":"Phương tiện giao thông chạy bằng điện trên đường ray, có khả năng chở nhiều hành khách."},"1582":{"word":"toàn thể, toàn bộ","meaning":"Chỉ toàn bộ một sự vật, bao gồm mọi phần hoặc mọi thành viên, không bỏ sót bất cứ điều gì."},"1583":{"word":"truyền đạt","meaning":"Đưa thông tin, tin tức hoặc lời nhắn từ người này đến người khác."},"1584":{"word":"hoàn toàn không","meaning":"Biểu thị rằng một điều gì đó hoàn toàn không có, không đúng hoặc không xảy ra."},"1585":{"word":"điện thoại","meaning":"Thiết bị dùng để nói chuyện với người khác ở xa, thường có nút bấm và màn hình."},"1586":{"word":"trẻ","meaning":"Có tuổi đời còn ít."},"1587":{"word":"điểm số","meaning":"Giá trị bằng số được đưa ra để thể hiện mức độ hoàn thành tốt một nhiệm vụ, bài kiểm tra hoặc trong một cuộc thi."},"1588":{"word":"giờ ăn trưa","meaning":"Khoảng thời gian trong ngày, thường vào giữa trưa, khi mọi người ngừng hoạt động để ăn bữa chính giữa ngày."},"1589":{"word":"dần dần","meaning":"Diễn tả một quá trình thay đổi hoặc tăng lên từng chút một trong một khoảng thời gian dài, không phải cùng một lúc."},"1590":{"word":"gấp","meaning":"Gập một vật liệu dẻo như giấy hoặc vải để một phần nằm phẳng lên phần khác, tạo thành nếp gấp."},"1591":{"word":"đĩa","meaning":"Đồ vật phẳng, thường tròn, thường làm bằng gốm sứ, dùng để đựng thức ăn khi ăn hoặc phục vụ."},"1592":{"word":"đũa","meaning":"Một cặp que dài, mảnh, thường làm bằng gỗ hoặc kim loại, được dùng cùng nhau trong một tay làm dụng cụ ăn để gắp thức ăn."},"1593":{"word":"trạm dừng","meaning":"Địa điểm phương tiện giao thông công cộng như xe buýt hoặc tàu hỏa dừng lại để đón trả khách."},"1594":{"word":"mức độ","meaning":"Số lượng hoặc cấp độ thể hiện bản chất hay giá trị của một điều gì đó về mức độ tốt hoặc cường độ."},"1595":{"word":"sự sắp xếp, sự dọn dẹp","meaning":"Hành động thu gom hoặc làm gọn gàng những đồ vật đang phân tán hoặc không có trật tự."},"1596":{"word":"cổng chính, cửa chính","meaning":"Cánh cổng hoặc cửa lớn ở phía trước của một tòa nhà, trường học, hay khu vực nào đó."},"1597":{"word":"khu vườn","meaning":"Khoảng sân hoặc bồn hoa trong nhà, nơi trồng cỏ, cây cối, v.v."},"1598":{"word":"quyết định, đặt ra","meaning":"Chọn ra một mục cụ thể hoặc lựa chọn từ một nhóm, hoặc sắp xếp một thời gian hay kế hoạch cụ thể một cách chắc chắn."},"1599":{"word":"sự chính xác","meaning":"Tính chất của một điều gì đó hoàn toàn đúng, không có lỗi, hoặc hoàn toàn phù hợp với thực tế."},"1600":{"word":"bị ướt","meaning":"Trở nên bị bao phủ hoặc ngấm đầy nước hoặc một chất lỏng khác, làm cho bề mặt ẩm ướt và nặng trĩu."},"1601":{"word":"tiêu đề, tựa đề","meaning":"Tên riêng được đặt cho một cuốn sách, bài báo, phim, hoặc bài hát, thường xuất hiện ở đầu hoặc phần mở đầu."},"1602":{"word":"từng chút một, dần dần","meaning":"Liên tục với một số lượng nhỏ."},"1603":{"word":"sự cẩn thận","meaning":"Hành động cẩn trọng trong lời nói, hành vi, v.v., để không gặp rắc rối."},"1604":{"word":"một cách yên tĩnh, nhẹ nhàng","meaning":"Theo cách tạo ra ít hoặc không có âm thanh nghe được, thường là bằng cách di chuyển hoặc nói chuyện với những hành động nhẹ nhàng, không đáng chú ý."},"1605":{"word":"cháu","meaning":"Con của anh, chị, em ruột của mình."},"1606":{"word":"ngủ gật","meaning":"Tạm thời rơi vào trạng thái ngủ nhẹ, thường là không chủ ý và khi đang ngồi, khiến đầu bị gục xuống."},"1607":{"word":"hẹp","meaning":"Là tính từ chỉ không gian có chiều rộng từ bên này sang bên kia không lớn."},"1608":{"word":"loại, kiểu","meaning":"Là cách phân chia đồ vật hoặc con người thành nhóm dựa trên đặc điểm tương tự."},"1609":{"word":"giấy","meaning":"Là vật liệu mỏng, phẳng thường làm từ sợi gỗ, dùng để viết, vẽ hoặc in ấn."},"1610":{"word":"túi, túi đựng","meaning":"Là một vật thường làm bằng vải hoặc da, dùng để đựng tiền và những vật nhỏ có thể mang theo."},"1611":{"word":"đơn đặt hàng, gọi món","meaning":"Là yêu cầu mua sản phẩm, đồ ăn hoặc yêu cầu thực hiện một dịch vụ nào đó."},"1612":{"word":"xung quanh, khu vực xung quanh","meaning":"Là khu vực gần gũi với một người, địa điểm hoặc vật thể cụ thể nào đó."},"1613":{"word":"tiêm, mũi tiêm","meaning":"Là việc đưa thuốc hoặc chất lỏng vào cơ thể người qua da bằng kim nhọn."},"1614":{"word":"chung quanh, quanh","meaning":"Là khu vực tiếp xúc hoặc rất gần với tất cả các phía của một vật gì đó."},"1615":{"word":"đỗ xe, đậu xe","meaning":"Là hành động dừng xe ô tô hoặc phương tiện khác và để nó ở một vị trí nhất định."},"1616":{"word":"bãi đỗ xe, chỗ đậu xe","meaning":"Là khu vực ngoài trời hoặc trong tòa nhà nơi mọi người có thể dừng và để xe của họ."},"1617":{"word":"màu cam","meaning":"Là màu sắc tươi sáng, ấm áp trông giống như sự pha trộn giữa màu đỏ và màu vàng."},"1618":{"word":"chết, qua đời","meaning":"Là khi một sinh vật sống ngừng sống và cơ thể của nó không còn hoạt động nữa."},"1619":{"word":"dây","meaning":"Một vật mỏng, dài dùng để buộc hoặc thắt các thứ lại với nhau."},"1620":{"word":"giảm","meaning":"Trở nên nhỏ hơn về kích thước, số lượng hoặc con số."},"1621":{"word":"giảm bớt","meaning":"Làm cho cái gì đó trở nên nhỏ hơn về kích thước, số lượng hoặc cường độ."},"1622":{"word":"nhặt","meaning":"Dùng tay lấy một vật từ dưới đất hoặc trên một bề mặt lên."},"1623":{"word":"giữa","meaning":"Điểm hoặc khu vực cách đều từ các cạnh ngoài hoặc hai đầu của một cái gì đó."},"1624":{"word":"nhà hàng Trung Quốc","meaning":"Một cơ sở nơi mọi người gọi và ăn các món ăn như mì, há cảo và cơm chiên."},"1625":{"word":"trung tâm","meaning":"Điểm giữa chính xác hoặc khu vực quan trọng nhất của một địa điểm, một vật thể, hoặc một nhóm các thứ."},"1626":{"word":"trung ương","meaning":"Khu vực chính xác ở giữa một không gian, một vật thể, hoặc một nhóm các thứ."},"1627":{"word":"tầm quan trọng","meaning":"Phẩm chất của cái gì đó được đánh giá cao hoặc rất cần thiết, khiến mọi người dành sự suy nghĩ hoặc chú ý nghiêm túc."},"1628":{"word":"trường trung học cơ sở","meaning":"Một cơ sở giáo dục nơi học sinh, thường từ 11 đến 14 tuổi, học sau khi hoàn thành giáo dục tiểu học."},"1629":{"word":"học sinh trung học cơ sở","meaning":"Một người trẻ đang theo học tại một cơ sở giáo dục dành cho trẻ em thường từ 11 đến 14 tuổi."},"1630":{"word":"vui thích","meaning":"Biểu hiện ra bên ngoài sự vui vẻ hoặc thích thú lớn lao thông qua nụ cười, tiếng cười hoặc hành động năng động."},"1631":{"word":"vui vẻ, thú vị","meaning":"Từ dùng để diễn tả một tình huống hoặc hoạt động làm cho người ta cảm thấy vui vẻ, thoải mái."},"1632":{"word":"thưởng thức, tận hưởng","meaning":"Làm một việc gì đó hoặc sử dụng một thứ gì đó một cách thích thú và hài lòng."},"1633":{"word":"sự đến muộn, sự trễ giờ","meaning":"Tình trạng đến một địa điểm hoặc sự kiện sau thời gian đã định."},"1634":{"word":"đi qua, trôi qua","meaning":"Di chuyển qua một điểm hoặc một khoảng thời gian kết thúc."},"1635":{"word":"lần trước","meaning":"Khoảng thời gian hoặc dịp gần đây nhất mà một sự kiện đã xảy ra hoặc một hành động đã được thực hiện."},"1636":{"word":"thua, thất bại","meaning":"Không đạt được chiến thắng trong một trò chơi, cuộc thi hoặc trận chiến."},"1637":{"word":"bản đồ","meaning":"Một hình vẽ hoặc biểu đồ thể hiện các đặc điểm địa lý, đường xá, sông ngòi, tòa nhà của một khu vực từ trên cao."},"1638":{"word":"nhàm chán, tẻ nhạt","meaning":"Cảm thấy buồn tẻ và mệt mỏi vì một hành động hoặc trạng thái nào đó cứ tiếp diễn."},"1639":{"word":"la hét, kêu","meaning":"Phát ra một âm thanh rất lớn bằng giọng nói, thường khi có cảm xúc mạnh như tức giận, phấn khích hoặc sợ hãi."},"1640":{"word":"địa phương, vùng","meaning":"Một khu vực cụ thể trong một quốc gia hoặc vùng đất lớn hơn, có những đặc điểm riêng."},"1641":{"word":"xóa, tẩy","meaning":"Chà xát hoặc lau các dấu vết, chữ viết hoặc hình ảnh khỏi bề mặt cho đến khi chúng không còn nhìn thấy được."},"1642":{"word":"bảo vệ, giữ gìn","meaning":"Canh giữ một người, địa điểm hoặc vật thể để giữ an toàn khỏi nguy hiểm hoặc tổn hại."},"1643":{"word":"dưới lòng đất","meaning":"Là không gian hoặc khu vực nằm bên dưới bề mặt trái đất."},"1644":{"word":"đường hầm","meaning":"Là một lối đi được xây dựng bằng cách đào xuyên qua lòng đất."},"1645":{"word":"nơi làm việc","meaning":"Là địa điểm như văn phòng hoặc nhà máy nơi mọi người đến để thực hiện công việc của mình."},"1646":{"word":"trực tiếp","meaning":"Tự mình làm một việc gì đó hoặc đích thân tham gia mà không thông qua người khác."},"1647":{"word":"thật","meaning":"Là cái đúng với bản chất, không có sự giả dối hay nhân tạo."},"1648":{"word":"đậm","meaning":"Có màu sắc, hương vị, mùi rất rõ ràng, hoặc rất dày và đặc như sương mù."},"1649":{"word":"hành lý","meaning":"Là những đồ vật được gói ghém để di chuyển đến nơi khác."},"1650":{"word":"tiệc tân gia","meaning":"Là một buổi tiệc xã giao được tổ chức để ăn mừng việc chuyển đến nhà mới, nơi khách mời mang theo quà."},"1651":{"word":"việc nhà","meaning":"Là các công việc và nghĩa vụ khác nhau được thực hiện để duy trì nhà cửa, như dọn dẹp, nấu ăn và sắp xếp."},"1652":{"word":"làm","meaning":"Là tạo ra thức ăn, quần áo, tòa nhà, v.v., bằng các nguyên liệu hoặc thành phần cần thiết."},"1653":{"word":"sự khó chịu","meaning":"Là hành động bày tỏ sự tức giận hoặc không thích đối với điều gì đó vì không hài lòng, hoặc trạng thái đó."},"1654":{"word":"đôi","meaning":"Là hai vật dụng được dùng chung hoặc hợp với nhau, như tất hoặc giày."},"1655":{"word":"ngắn","meaning":"Có chiều dài không nhiều, đối lập với dài."},"1656":{"word":"mì Jjamppong","meaning":"Món mì cay Hàn Quốc với sợi mì dai, nước dùng đỏ đậm đà, thường có hải sản và rau củ."},"1657":{"word":"lẩu, món hầm","meaning":"Món ăn Hàn Quốc thịnh soạn thường được nấu trong nồi trên bàn ăn, gồm thịt, rau và đậu phụ trong nước dùng đậm vị."},"1658":{"word":"tăng cân","meaning":"Cơ thể trở nên nặng hơn và lớn hơn theo thời gian, thường do ăn uống."},"1659":{"word":"hấp","meaning":"Nấu chín thức ăn bằng hơi nước nóng, không dùng dầu mỡ hay nước."},"1660":{"word":"trà","meaning":"Đồ uống nóng làm bằng cách ngâm lá, rễ hoặc quả của cây trong nước sôi."},"1661":{"word":"xe ô tô","meaning":"Phương tiện có bánh xe, chạy trên đường để vận chuyển người hoặc hàng hóa."},"1662":{"word":"lạnh","meaning":"Có nhiệt độ thấp, gây cảm giác buốt giá khi chạm vào."},"1663":{"word":"đầy","meaning":"Trạng thái không còn chỗ trống, đã được lấp đầy hoàn toàn."},"1664":{"word":"đá","meaning":"Dùng chân hoặc cẳng chân tác động mạnh vào một vật gì đó."},"1665":{"word":"đeo","meaning":"Đặt hoặc gắn một phụ kiện như đồng hồ hay vòng tay lên người."},"1666":{"word":"lạnh","meaning":"Có cảm giác không ấm áp, nhiệt độ thấp (thường dùng cho không khí, gió)."},"1667":{"word":"thứ tự","meaning":"Vị trí hoặc sự sắp xếp theo một trình tự nhất định."},"1668":{"word":"hiền lành","meaning":"Có tính cách tốt, luôn đối xử tử tế và giúp đỡ người khác."},"1669":{"word":"nước lạnh","meaning":"Nước có nhiệt độ thấp, thường dùng để giải khát hoặc làm mát."},"1670":{"word":"kìm nén","meaning":"Cố gắng giữ lại, không biểu lộ ra ngoài những cảm xúc, hành động hoặc hiện tượng sinh lý."},"1671":{"word":"đi tìm, đến thăm","meaning":"Di chuyển đến một địa điểm cụ thể với mục đích gặp gỡ một người hoặc tham quan một nơi nào đó."},"1672":{"word":"đến thăm, ghé thăm","meaning":"Đến nơi ở hoặc chỗ làm việc của người khác với mục đích gặp gỡ hoặc có việc."},"1673":{"word":"rau củ, rau","meaning":"Các loại thực vật như lá, thân, rễ hoặc quả mà con người dùng làm thức ăn."},"1674":{"word":"giá sách, kệ sách","meaning":"Đồ nội thất có nhiều ngăn hoặc tầng để sắp xếp và lưu trữ sách vở."},"1675":{"word":"đầu tiên, thứ nhất","meaning":"Đứng ở vị trí trước tất cả những cái khác trong một chuỗi hoặc thời gian."},"1676":{"word":"ngày đầu tiên","meaning":"Khoảng thời gian 24 giờ mở đầu trong một chuỗi, ví dụ như khởi đầu một tuần, tháng hoặc năm."},"1677":{"word":"thứ nhất, đầu tiên","meaning":"Là vị trí ở ngay lúc bắt đầu của một chuỗi hoặc nhóm."},"1678":{"word":"thanh niên, người trẻ","meaning":"Một người trẻ tuổi đã trưởng thành về cả thể chất lẫn tinh thần."},"1679":{"word":"quần jean","meaning":"Một loại quần bền chắc, thường có màu xanh, được mặc hàng ngày."},"1680":{"word":"thanh thiếu niên","meaning":"Người ở độ tuổi từ 13 đến 19, chưa phải là người lớn."},"1681":{"word":"nhà tập thể dục","meaning":"Một tòa nhà hoặc căn phòng lớn trong nhà, dùng để chơi thể thao, tập thể dục và các hoạt động thể chất."},"1682":{"word":"nhìn lên","meaning":"Hướng mắt từ dưới lên trên để nhìn một vật hoặc người."},"1683":{"word":"đầu (tháng/năm)","meaning":"Phần đầu tiên của một khoảng thời gian, như những ngày đầu tháng hoặc đầu năm."},"1684":{"word":"giây","meaning":"Một đơn vị thời gian nhỏ, bằng một phần sáu mươi của một phút."},"1685":{"word":"thiệp mời","meaning":"Một tấm thiệp hoặc giấy được viết hoặc in để mời ai đó đến dự một sự kiện."},"1686":{"word":"trường tiểu học","meaning":"Nơi trẻ em đến học các môn cơ bản như đọc, viết và toán trước khi vào cấp hai."},"1687":{"word":"học sinh tiểu học","meaning":"Một đứa trẻ đang theo học tại trường dạy các môn cơ bản như đọc, viết và toán."},"1688":{"word":"màu xanh lá cây","meaning":"Màu sắc giống như màu cỏ đậm, nằm giữa màu xanh dương và màu vàng."},"1689":{"word":"tốt nhất, cao nhất","meaning":"Điểm hoặc mức độ ở vị trí cao nhất tuyệt đối, không có gì vượt qua được về chất lượng hoặc số lượng."},"1690":{"word":"gần đây","meaning":"Khoảng thời gian từ một ngày trong quá khứ không lâu cho đến hiện tại."},"1691":{"word":"Tết Chuseok","meaning":"Đây là một trong những ngày lễ truyền thống lớn của Hàn Quốc, diễn ra vào ngày rằm tháng Tám âm lịch."},"1692":{"word":"quả bóng đá","meaning":"Đây là một loại bóng hình cầu, thường làm bằng da hoặc vật liệu tổng hợp, dùng để đá trong môn bóng đá."},"1693":{"word":"lối ra","meaning":"Đây là một lối đi hoặc cửa được đánh dấu, dùng để thoát ra khỏi một không gian hoặc tòa nhà kín."},"1694":{"word":"đi làm","meaning":"Đây là hành động di chuyển từ nhà đến nơi làm việc để bắt đầu công việc trong ngày."},"1695":{"word":"sự có mặt","meaning":"Đây là việc có mặt tại một địa điểm cụ thể, như lớp học hoặc cuộc họp, khi được yêu cầu."},"1696":{"word":"sự ra vào","meaning":"Đây là hành động đi vào và đi ra khỏi một địa điểm hoặc khu vực cụ thể."},"1697":{"word":"xuất nhập cảnh","meaning":"Đây là các quy trình và quy định liên quan đến việc người dân di chuyển vào và rời khỏi một quốc gia khác."},"1698":{"word":"chuyến công tác","meaning":"Đây là chuyến đi mà một nhân viên thực hiện đến một nơi khác ngoài văn phòng làm việc thông thường vì lý do công việc."},"1699":{"word":"việc đi lại hàng ngày","meaning":"Đây là hành động đi lại hàng ngày giữa nhà và nơi làm việc."},"1700":{"word":"đủ","meaning":"Chỉ việc có một lượng hoặc số lượng vật chất đạt đủ yêu cầu."},"1701":{"word":"sự hủy bỏ","meaning":"Đây là hành động hủy bỏ một kế hoạch hoặc sự kiện đã sắp xếp để nó không xảy ra nữa."},"1702":{"word":"sự có việc làm","meaning":"Đây là hành động tìm được và bắt đầu công việc có lương cho một công ty hoặc cá nhân."},"1703":{"word":"Nha khoa","meaning":"Nơi chuyên khám, chữa bệnh và chăm sóc răng miệng."},"1704":{"word":"Điều trị","meaning":"Việc chăm sóc y tế để giúp người bệnh hoặc bị thương hồi phục."},"1705":{"word":"Kem đánh răng","meaning":"Một loại kem đặc dùng với bàn chải để làm sạch răng."},"1706":{"word":"Gà rán","meaning":"Món ăn làm từ thịt gà được tẩm bột và chiên giòn."},"1707":{"word":"Họ hàng","meaning":"Những người có quan hệ huyết thống hoặc hôn nhân trong cùng một gia đình lớn."},"1708":{"word":"Phòng ngủ","meaning":"Căn phòng trong nhà được trang bị và dùng để ngủ."},"1709":{"word":"Bàn chải đánh răng","meaning":"Dụng cụ nhỏ có cán dài và nhiều lông để làm sạch răng."},"1710":{"word":"Lời khen","meaning":"Lời nói thể hiện sự đánh giá cao về điểm mạnh hoặc thành tích của ai đó."},"1711":{"word":"Cà ri","meaning":"Món ăn có thịt, cá hoặc rau nấu trong nước sốt đậm đà gia vị."},"1712":{"word":"Quán cà phê","meaning":"Nơi kinh doanh đồ uống như cà phê, trà và thường có cả bánh ngọt hoặc đồ ăn nhẹ."},"1713":{"word":"Dao","meaning":"Dụng cụ hoặc vũ khí có lưỡi kim loại sắc gắn vào cán, dùng để cắt, thái hoặc đâm."},"1714":{"word":"Mì Kalguksu","meaning":"Món súp mì của Hàn Quốc với sợi mì dẹt làm từ bột mì cắt bằng tay, thường ăn kèm rau hoặc hải sản."},"1715":{"word":"chơi (nhạc cụ có dây)","meaning":"Phát ra âm thanh từ nhạc cụ có dây bằng cách kéo hoặc gảy."},"1716":{"word":"đôi","meaning":"Từ dùng để chỉ hai vật cùng loại, thường là giày, vớ hoặc găng tay đi cùng nhau."},"1717":{"word":"voi","meaning":"Loài động vật có vú to lớn, có vòi dài và đôi tai lớn, sống ở châu Á và châu Phi."},"1718":{"word":"nước mũi","meaning":"Chất lỏng trong suốt hoặc đặc chảy ra từ mũi khi bị cảm hoặc khóc."},"1719":{"word":"đậu","meaning":"Hạt tròn có vỏ mỏng, thường dùng làm nguyên liệu cho đậu phụ, tương đậu hoặc sữa đậu nành."},"1720":{"word":"kích thước","meaning":"Sự lớn hay nhỏ của một vật, được xác định bằng chiều dài, chiều rộng và chiều cao của nó."},"1721":{"word":"Giáng sinh","meaning":"Ngày lễ kỷ niệm Chúa Giê-su ra đời vào tháng 12 hàng năm, thường có trang trí cây thông và tặng quà."},"1722":{"word":"tiếng lớn","meaning":"Âm thanh vang to, rõ ràng, có thể nghe thấy từ xa hoặc lời nói phát ra với cường độ mạnh."},"1723":{"word":"nuôi","meaning":"Chăm sóc để một sinh vật sống lớn lên và phát triển, bằng cách cung cấp thức ăn và nơi ở."},"1724":{"word":"kilôgam","meaning":"Đơn vị đo khối lượng chuẩn, bằng một nghìn gam."},"1725":{"word":"kilômét","meaning":"Đơn vị đo độ dài chuẩn, bằng một nghìn mét."},"1726":{"word":"pha (thức uống)","meaning":"Trộn một lượng nhỏ bột hoặc chất lỏng vào một lượng lớn chất lỏng khác bằng cách khuấy đều để tạo thành thức uống."},"1727":{"word":"thịt heo chiên chua ngọt","meaning":"Món ăn làm từ thịt heo chiên giòn, sau đó được phủ sốt chua ngọt."},"1728":{"word":"cờ Taegukgi","meaning":"Quốc kỳ của Hàn Quốc, có biểu tượng thái cực đỏ xanh ở giữa và bốn quẻ bát quái ở các góc trên nền trắng."},"1729":{"word":"thái độ","meaning":"Cách một người thể hiện cảm xúc, suy nghĩ của mình qua hành động, nét mặt hoặc tư thế."},"1730":{"word":"chào đời","meaning":"Bắt đầu sự sống khi rời khỏi cơ thể mẹ hoặc trứng."},"1731":{"word":"bão","meaning":"Cơn bão nhiệt đới rất mạnh, có gió lớn và mưa to, thường hình thành ở phía tây Thái Bình Dương."},"1732":{"word":"chuyển phát nhanh","meaning":"Dịch vụ vận chuyển hàng hóa hoặc tài liệu từ người gửi đến người nhận."},"1733":{"word":"sân quần vợt","meaning":"Khu vực hình chữ nhật có vạch kẻ và lưới ở giữa, dùng để chơi môn thể thao quần vợt."},"1734":{"word":"bàn","meaning":"Một món đồ nội thất có mặt phẳng được đỡ bằng chân, dùng để đặt đồ vật hoặc để mọi người ngồi ăn."},"1735":{"word":"thỏ","meaning":"Một loài động vật có tai dài, đuôi ngắn và chân sau phát triển hơn chân trước."},"1736":{"word":"cà chua","meaning":"Một loại quả hình tròn, cỡ nắm tay, chuyển từ màu xanh sang đỏ khi chín."},"1737":{"word":"sổ tiết kiệm","meaning":"Cuốn sổ nhỏ do ngân hàng cấp, ghi lại lịch sử gửi và rút tiền của khách hàng."},"1738":{"word":"cuộc gọi","meaning":"Cuộc trao đổi bằng lời nói với người khác thông qua thiết bị điện tử truyền âm thanh đi xa."},"1739":{"word":"Xuất viện","meaning":"Việc bệnh nhân rời khỏi bệnh viện sau khi điều trị khỏi bệnh hoặc hoàn tất quá trình điều trị."},"1740":{"word":"Chiên ngập dầu","meaning":"Nấu chín thức ăn bằng cách nhúng hoàn toàn vào dầu hoặc mỡ nóng cho đến khi giòn và chín."},"1741":{"word":"Đồ chiên","meaning":"Món ăn được chế biến bằng cách nhúng nguyên liệu (thường có tẩm bột) vào dầu nóng cho chín giòn."},"1742":{"word":"Xe tải","meaning":"Phương tiện cơ giới lớn có động cơ mạnh, được chế tạo để vận chuyển hàng hóa nặng trên đường bộ."},"1743":{"word":"Đặc biệt","meaning":"Theo một cách quan trọng, cụ thể hoặc khác biệt hơn bình thường, nhằm nhấn mạnh một điều gì đó."},"1744":{"word":"Chắc chắn","meaning":"Diễn tả cái gì đó rất bền, vững vàng, khó bị hư hỏng hoặc cơ thể khỏe mạnh, có sức đề kháng tốt."},"1745":{"word":"Bật","meaning":"Khởi động thiết bị điện tử hoặc máy móc bằng cách xoay hoặc nhấn công tắc."},"1746":{"word":"Sai","meaning":"Không chính xác, không đúng với sự thật, điều lệ hoặc những gì được mong đợi."},"1747":{"word":"Đội","meaning":"Một nhóm người cùng thực hiện một công việc, hoạt động hoặc cùng chung một mục tiêu."},"1748":{"word":"Màu xanh lam","meaning":"Màu của bầu trời quang đãng hoặc biển cả."},"1749":{"word":"Xanh lam","meaning":"Diễn tả màu sắc tươi sáng và sống động như bầu trời mùa thu trong xanh hoặc biển sâu."},"1750":{"word":"Được bán","meaning":"Vật phẩm được trao cho khách hàng để đổi lấy tiền, thay đổi quyền sở hữu từ người bán sang người mua."},"1751":{"word":"mở ra, trải ra","meaning":"Làm cho một vật đang gấp, cuộn hoặc đóng được mở rộng ra."},"1752":{"word":"tiện lợi, sự tiện lợi","meaning":"Tính chất dễ dàng, thuận tiện trong việc sử dụng hoặc thực hiện, giúp tiết kiệm thời gian và công sức."},"1753":{"word":"sự thoải mái, sự dễ chịu","meaning":"Tình trạng cơ thể và tinh thần cảm thấy thư giãn, bình yên, không có bất kỳ đau đớn, lo lắng hay khó khăn nào."},"1754":{"word":"ốm, bệnh (kính ngữ)","meaning":"Từ dùng để nói về người lớn tuổi hoặc người được kính trọng khi họ không được khỏe, bị bệnh."},"1755":{"word":"thoải mái, tiện lợi, dễ chịu","meaning":"Khi cơ thể hoặc tinh thần của một người cảm thấy thư giãn, không có khó khăn hay căng thẳng."},"1756":{"word":"bình thường, thường ngày","meaning":"Khoảng thời gian hoặc trạng thái mà mọi việc diễn ra một cách đều đặn, điển hình, không phải là sự kiện đặc biệt."},"1757":{"word":"ngày thường, ngày trong tuần","meaning":"Bất kỳ ngày nào từ thứ Hai đến thứ Sáu, khi hầu hết mọi người đi làm hoặc đi học."},"1758":{"word":"đóng gói, bao bì","meaning":"Hành động bọc một vật bằng giấy, nhựa hoặc hộp để chuẩn bị mang đi, gửi đi hoặc làm quà tặng."},"1759":{"word":"xanh (biếc, tươi)","meaning":"Màu xanh trong và sống động như bầu trời thu trong xanh, đại dương sâu thẳm hoặc cỏ cây tươi tốt."},"1760":{"word":"sâu, say (ngủ)","meaning":"Từ diễn tả hành động ngủ hoặc nghỉ ngơi một cách đầy đủ, sâu sắc để phục hồi sức khỏe sau mệt mỏi."},"1761":{"word":"tháo, gỡ, nới lỏng","meaning":"Đưa một thứ gì đó đã bị buộc, thắt hoặc xoắn trở lại trạng thái ban đầu của nó."},"1762":{"word":"phong cảnh, cảnh quan","meaning":"Toàn bộ những gì có thể nhìn thấy trên một khu vực rộng lớn, chẳng hạn như cây cối, núi, sông và các tòa nhà."},"1763":{"word":"chảo rán","meaning":"Một dụng cụ nấu ăn bằng kim loại, nông, tròn, có tay cầm dài, dùng để chiên xào thức ăn bằng dầu."},"1764":{"word":"máu","meaning":"Chất lỏng màu đỏ lưu thông trong cơ thể người hoặc động vật, có vai trò cung cấp oxy, dinh dưỡng và vận chuyển chất thải."},"1765":{"word":"nở","meaning":"Khi hoa hoặc cây mở ra hoàn toàn các cánh hoặc lá, phô bày màu sắc của chúng."},"1766":{"word":"bánh pizza","meaning":"Món bánh mì dẹt, hình tròn, được nướng chín và phủ sốt cà chua, phô mai cùng nhiều nguyên liệu khác."},"1767":{"word":"bầu trời","meaning":"Không gian bao la, vô tận trải rộng phía trên mặt đất."},"1768":{"word":"màu xanh da trời","meaning":"Màu xanh pha trắng, giống như màu của bầu trời quang đãng."},"1769":{"word":"hậu tố -하다","meaning":"Phần nhỏ được thêm vào cuối một số danh từ để tạo ra từ mới diễn tả hành động hoặc trạng thái."},"1770":{"word":"phí trọ","meaning":"Số tiền phải trả định kỳ để ăn ở tại nhà của người khác."},"1771":{"word":"màu trắng","meaning":"Màu của tuyết hoặc sữa tươi."},"1772":{"word":"trắng","meaning":"Có màu sắc tương tự tuyết mới rơi hoặc sữa, là màu sáng nhất trong bảng màu."},"1773":{"word":"học kỳ","meaning":"Một trong những giai đoạn (thường là hai hoặc ba) mà một năm học ở trường phổ thông hoặc đại học được chia ra để học tập."},"1774":{"word":"khối lớp","meaning":"Cấp độ học tập trong một trường học mà học sinh hoàn thành trong một năm, ví dụ khối lớp một hoặc khối lớp năm."},"1775":{"word":"Trung tâm","meaning":"Một cơ sở tư nhân nơi học sinh đến học thêm các môn học hoặc kỹ năng."},"1776":{"word":"Sông Hàn","meaning":"Một con sông lớn chảy qua Seoul, Hàn Quốc, có nhiều cầu và công viên dọc hai bên bờ."},"1777":{"word":"Hangeul","meaning":"Hệ thống chữ viết riêng biệt được dùng để viết tiếng Hàn."},"1778":{"word":"Một hai","meaning":"Chỉ một số lượng nhỏ và không xác định, thường là một hoặc hai."},"1779":{"word":"Một lần","meaning":"Diễn ra vào một dịp hoặc một trường hợp duy nhất."},"1780":{"word":"Món ăn Hàn Quốc","meaning":"Phong cách ẩm thực và các món ăn đặc trưng có nguồn gốc từ Hàn Quốc."},"1781":{"word":"Nhà hàng Hàn Quốc","meaning":"Nơi mọi người có thể mua và thưởng thức các món ăn đặc trưng của Hàn Quốc."},"1782":{"word":"Nhà truyền thống Hàn Quốc","meaning":"Một ngôi nhà truyền thống của Hàn Quốc hoặc một ngôi nhà được xây dựng theo phong cách đó."},"1783":{"word":"Một ly","meaning":"Một lượng chất lỏng được phục vụ trong một đồ đựng để tiêu thụ."},"1784":{"word":"Sự chiêu đãi","meaning":"Hành động một người trả toàn bộ chi phí cho bữa ăn hoặc giải trí của một nhóm người khác."},"1785":{"word":"Giảm giá","meaning":"Việc giảm bớt chi phí thông thường của một mặt hàng hoặc dịch vụ, làm cho việc mua nó trở nên rẻ hơn."},"1786":{"word":"Hàng không","meaning":"Hoạt động di chuyển hoặc vận chuyển đồ vật qua không khí bằng máy bay hoặc phương tiện hàng không khác."},"1787":{"word":"vé máy bay","meaning":"Đây là giấy tờ xác nhận quyền được đi máy bay của một người cho một hành trình cụ thể."},"1788":{"word":"luôn luôn","meaning":"Từ dùng để chỉ sự việc xảy ra vào mọi lúc hoặc không bỏ sót lần nào."},"1789":{"word":"mặt trời","meaning":"Đây là thiên thể sáng chói chiếu sáng và sưởi ấm Trái Đất."},"1790":{"word":"hằng năm","meaning":"Từ dùng để chỉ sự việc xảy ra khi kết thúc mỗi chu kỳ mười hai tháng."},"1791":{"word":"nước ngoài","meaning":"Khu vực hoặc quốc gia nằm ở bên ngoài biên giới của một nước, thường là qua biển hoặc đại dương."},"1792":{"word":"du lịch nước ngoài","meaning":"Chuyến đi hoặc cuộc hành trình đến một quốc gia nằm ở bên ngoài biên giới, thường là qua biển."},"1793":{"word":"bánh hamburger","meaning":"Món ăn làm từ bánh mì tròn cắt đôi, bên trong thường có thịt nướng và các nguyên liệu khác."},"1794":{"word":"ánh nắng","meaning":"Ánh sáng tự nhiên và hơi ấm chiếu từ bầu trời xuống vào ban ngày."},"1795":{"word":"hành động","meaning":"Một việc cụ thể mà con người hoặc động vật làm, có thể được người khác nhìn thấy."},"1796":{"word":"hạnh phúc","meaning":"Trạng thái cảm thấy hài lòng và vui vẻ trong cuộc sống."},"1797":{"word":"sự kiện","meaning":"Một dịp được tổ chức có kế hoạch, nơi nhiều người tụ tập vì một mục đích đặc biệt."},"1798":{"word":"eo","meaning":"Phần hẹp trên cơ thể người, nằm giữa phần dưới xương sườn và phần trên của chân."},"1799":{"word":"chia tay","meaning":"Sau khi ở cùng nhau, mỗi người đi về một hướng riêng."},"1800":{"word":"phòng tập gym","meaning":"Một địa điểm có trang thiết bị đặc biệt để mọi người đến tập thể dục và giữ gìn sức khỏe."},"1801":{"word":"lưỡi","meaning":"Bộ phận mềm, dài, màu đỏ nằm trong miệng của người hoặc động vật, dùng để nếm, nói, nuốt."},"1802":{"word":"tiền mặt","meaning":"Loại tiền tệ bằng giấy hoặc kim loại, không phải séc hay trái phiếu, dùng để thanh toán trực tiếp."},"1803":{"word":"hiện tại","meaning":"Khoảng thời gian đang diễn ra ngay lúc này, không phải quá khứ hay tương lai."},"1804":{"word":"anh em","meaning":"Từ dùng để chỉ chung anh và em trai trong một gia đình."},"1805":{"word":"hổ","meaning":"Một loài động vật ăn thịt lớn, có lông màu vàng nâu và các sọc đen."},"1806":{"word":"hồ","meaning":"Một vùng nước ngọt rộng lớn hoàn toàn được bao quanh bởi đất liền."},"1807":{"word":"liệu","meaning":"Từ dùng để hỏi nhằm gợi ý một khả năng nhỏ rằng điều gì đó có thể đúng hoặc xảy ra."},"1808":{"word":"hồng trà","meaning":"Loại trà được làm từ lá cây trà đã ủ và sấy khô, khi pha có màu đỏ và hương thơm."},"1809":{"word":"cơn giận","meaning":"Cảm xúc mạnh mẽ, khó chịu khi điều gì đó không công bằng hoặc tồi tệ xảy ra."},"1810":{"word":"họa sĩ","meaning":"Người tạo ra các bức tranh và bản vẽ bằng màu sắc, cọ hoặc các công cụ khác."},"1811":{"word":"tức giận","meaning":"Cảm thấy khó chịu, bực bội trong lòng khi có chuyện không vừa ý hoặc không công bằng xảy ra."},"1812":{"word":"nổi giận","meaning":"Bày tỏ cảm xúc tức giận ra bên ngoài bằng cách lớn tiếng, cau mày hoặc hành động hung hăng với người khác."},"1813":{"word":"hoa lệ","meaning":"Rất được trang trí công phu, nhiều màu sắc hoặc chi tiết, thường trông đắt tiền và hấp dẫn."},"1814":{"word":"mỹ phẩm","meaning":"Các loại kem, bột hoặc chất lỏng mà mọi người dùng thoa lên da, mặt hoặc tóc để trông đẹp hơn."},"1815":{"word":"sự chào đón","meaning":"Hành động chào hỏi nồng nhiệt và thân thiện dành cho một người vừa đến, thường bằng nụ cười hoặc vòng tay rộng mở."},"1816":{"word":"bệnh nhân","meaning":"Người bị bệnh hoặc bị thương và đang được chăm sóc y tế từ bác sĩ hoặc bệnh viện."},"1817":{"word":"đổi tiền","meaning":"Hành động đổi tiền của một quốc gia lấy tiền của một quốc gia khác, thường được thực hiện tại quầy giao dịch đặc biệt."},"1818":{"word":"lần","meaning":"Đơn vị dùng để đếm số lần một sự việc xảy ra hoặc số lượng các lần xuất hiện khác nhau."},"1819":{"word":"màu xám","meaning":"Màu sắc ở giữa đen và trắng, tương tự màu của tro."},"1820":{"word":"thành viên","meaning":"Người chính thức thuộc về một câu lạc bộ, tổ chức hoặc nhóm và thường có các quyền hoặc nghĩa vụ đặc biệt."},"1821":{"word":"vạch sang đường","meaning":"Một tuyến đường được đánh dấu trên mặt đường để người đi bộ có thể đi qua."},"1822":{"word":"hậu bối","meaning":"Người bắt đầu sự nghiệp trong cùng lĩnh vực sau mình, hoặc người có cấp bậc/thâm niên thấp hơn trong một tổ chức."},"1823":{"word":"xuất sắc, tuyệt vời","meaning":"Rất tốt, rất giỏi hoặc có chất lượng cao nhất, đáng được khen ngợi."},"1824":{"word":"hơn hẳn, nhiều hơn","meaning":"Dùng để chỉ sự khác biệt lớn, đáng kể giữa hai thứ, làm cho một thứ tốt hơn hoặc nhiều hơn đáng kể."},"1825":{"word":"phòng chờ, phòng nghỉ","meaning":"Một căn phòng được sắp xếp để mọi người nghỉ ngơi trong thời gian ngắn."},"1826":{"word":"điện thoại di động","meaning":"Một chiếc điện thoại nhỏ, không dây có thể mang theo và sử dụng."},"1827":{"word":"ngày nghỉ lễ","meaning":"Một ngày đặc biệt khi hầu hết mọi người không đi làm hoặc đi học, thường để kỷ niệm hoặc các sự kiện quốc gia."},"1828":{"word":"giấy vụn, giấy bỏ đi","meaning":"Loại giấy không còn sử dụng được, đã bị vứt đi."},"1829":{"word":"thùng rác","meaning":"Đồ dùng để bỏ các vật phẩm không mong muốn và rác thải vào."},"1830":{"word":"chảy","meaning":"Đối với chất lỏng như nước, di chuyển từ nơi cao xuống thấp hoặc đi qua một vị trí nhất định."},"1831":{"word":"lắc, rung, vẫy","meaning":"Di chuyển một vật nhanh chóng từ bên này sang bên kia hoặc lên xuống, thường làm cho nó rung hoặc chao đảo."},"1832":{"word":"làm đổ, làm chảy, chảy","meaning":"Làm cho chất lỏng hoặc các hạt nhỏ rò rỉ ra hoặc rơi xuống."},"1833":{"word":"hy vọng","meaning":"Một niềm tin mạnh mẽ rằng điều tốt đẹp sẽ xảy ra hoặc một kết quả mong muốn là có thể."},"1834":{"word":"màu trắng","meaning":"Màu của tuyết hoặc sữa."},"1835":{"word":"sức mạnh","meaning":"Khả năng vật lý để nâng, đẩy hoặc di chuyển vật nặng."},"1836":{"word":"chăm sóc","meaning":"Trồng và chăm sóc cây cối để chúng phát triển tốt."},"1837":{"word":"sự nghèo đói","meaning":"Tình trạng không có đủ tiền, thức ăn và các nhu yếu phẩm cơ bản."},"1838":{"word":"khả năng","meaning":"Trạng thái mà một điều gì đó có thể xảy ra, tồn tại hoặc được thực hiện."},"1839":{"word":"đầy","meaning":"Một vật chứa đựng được hết mức có thể, không còn chỗ trống."},"1840":{"word":"đầy ắp","meaning":"Với một lượng hoặc số lượng đạt đến mức tối đa."},"1841":{"word":"ngứa","meaning":"Cảm giác muốn gãi trên da."},"1842":{"word":"chiều ngang","meaning":"Hướng hoặc đường thẳng kéo dài từ bên này sang bên kia, không phải từ trên xuống dưới."},"1843":{"word":"bột","meaning":"Nhiều mảnh nhỏ, khô của một chất, có thể rắc và trông giống bụi."},"1844":{"word":"che","meaning":"Đặt thứ gì đó lên hoặc phía trước một vật, làm cho nó không nhìn thấy được."},"1845":{"word":"khí ga","meaning":"Một chất giống không khí, không ở dạng rắn hoặc lỏng, thường chảy qua đường ống và có thể đốt cháy để tạo nhiệt."},"1846":{"word":"bếp ga","meaning":"Thiết bị nhà bếp đốt nhiên liệu cung cấp qua đường ống để tạo nhiệt chuẩn bị thức ăn."},"1847":{"word":"Máy tạo độ ẩm","meaning":"Thiết bị dùng để phun hơi nước vào không khí, làm tăng độ ẩm trong phòng."},"1848":{"word":"Sự tham gia","meaning":"Hành động chính thức trở thành một phần của một nhóm hoặc tổ chức nào đó, thường là bằng cách đăng ký."},"1849":{"word":"Thành viên","meaning":"Người đã đăng ký để trở thành một phần của một nhóm hoặc thường xuyên nhận một dịch vụ sau khi trả phí."},"1850":{"word":"Đồ gia dụng","meaning":"Các loại máy móc điện tử như tủ lạnh, máy giặt, tivi mà người ta sử dụng trong nhà cho các công việc hàng ngày."},"1851":{"word":"Gia đình","meaning":"Một nhóm người, thường là cha, mẹ và con cái, sống chung dưới một mái nhà và có quan hệ huyết thống hoặc hôn nhân."},"1852":{"word":"Da (động vật)","meaning":"Vật liệu bền và dẻo được làm từ da động vật đã qua xử lý, thường dùng để làm áo khoác, giày dép hoặc túi xách."},"1853":{"word":"Mỗi","meaning":"Chỉ mọi người hoặc mọi vật trong một nhóm, được xem xét riêng lẻ."},"1854":{"word":"Mỗi người","meaning":"Chỉ tình huống mọi người hoặc mọi vật trong một nhóm tự mình thực hiện một hành động, không làm cùng nhau."},"1855":{"word":"Độ nêm nếm","meaning":"Lượng gia vị cụ thể, như muối, có trong thức ăn mà người ta có thể kiểm tra bằng cách nếm thử."},"1856":{"word":"Biển hiệu","meaning":"Một tấm phẳng bằng gỗ, kim loại hoặc nhựa, có chữ hoặc hình ảnh, treo bên ngoài tòa nhà để chỉ tên hoặc mục đích của nó."},"1857":{"word":"Sự chăm sóc bệnh nhân","meaning":"Hoạt động của một người chăm sóc những người bị ốm hoặc bị thương, thường là ở bệnh viện, để giúp họ hồi phục."},"1858":{"word":"Thay","meaning":"Tháo một vật cũ ra và đặt một vật khác hoặc vật mới vào vị trí của nó."},"1859":{"word":"cơn khát","meaning":"Đây là cảm giác khó chịu khi miệng bị khô và muốn uống nước."},"1860":{"word":"-cảm","meaning":"Đây là hậu tố dùng để chỉ nhận thức hoặc trạng thái cảm xúc mạnh mẽ về một điều gì đó."},"1861":{"word":"giác quan; cảm giác","meaning":"Đây là khả năng của cơ thể để nhận biết các thứ như thị giác, thính giác, xúc giác, vị giác hoặc khứu giác, hoặc sự hiểu biết trực giác về điều gì đó."},"1862":{"word":"quấn; cuốn","meaning":"Hành động dùng dây, vải hoặc vật tương tự cuốn quanh một vật khác."},"1863":{"word":"giám sát; sự giám sát","meaning":"Việc kiểm tra, theo dõi và chỉ đạo để đảm bảo mọi việc diễn ra đúng quy định hoặc kế hoạch."},"1864":{"word":"cảm động","meaning":"Cảm giác xúc động mạnh mẽ, ngưỡng mộ hoặc ấm áp mà ai đó trải qua sau khi chứng kiến hoặc nghe thấy điều gì đó lay động."},"1865":{"word":"đầy cảm động; gây xúc động","meaning":"Miêu tả một điều gì đó, như câu chuyện hoặc màn trình diễn, khiến người ta cảm thấy xúc động mạnh mẽ và ngưỡng mộ."},"1866":{"word":"thưởng thức","meaning":"Hành động quan sát, lắng nghe hoặc thấu hiểu một cách cẩn thận các tác phẩm nghệ thuật, âm nhạc hoặc văn học và tận hưởng vẻ đẹp hay ý nghĩa của chúng."},"1867":{"word":"cảm xúc","meaning":"Một trạng thái tâm lý mạnh mẽ bên trong con người như vui, buồn, giận, sợ hãi, thường được thể hiện qua nét mặt hoặc hành động."},"1868":{"word":"nước sông","meaning":"Chất lỏng chảy trong một dòng nước ngọt tự nhiên lớn xuyên qua đất liền."},"1869":{"word":"giảng viên; giáo viên","meaning":"Người hướng dẫn người khác về một môn học hoặc kỹ năng cụ thể, thường trong lớp học hoặc môi trường công cộng."},"1870":{"word":"liên kiều","meaning":"Một loại cây bụi nở hoa màu vàng tươi vào đầu mùa xuân, thường thấy trước khi lá xanh của nó xuất hiện."},"1871":{"word":"quang đãng","meaning":"Khi mây hoặc sương mù tan đi và bầu trời trở nên nắng ráo, trong xanh."},"1872":{"word":"cá nhân","meaning":"Một người hoặc một sự vật được xem xét một mình, không phải là một phần của nhóm."},"1873":{"word":"cá nhân","meaning":"Thuộc về hoặc liên quan đến một người cụ thể, không phải của chung mọi người."},"1874":{"word":"nó","meaning":"Từ dùng để chỉ một người cụ thể, thường là người trẻ hơn hoặc người thân thiết, không có mặt ở đó."},"1875":{"word":"ngược","meaning":"Ở vị trí mà phần trên trở thành phần dưới, hoặc di chuyển theo hướng ngược lại với bình thường."},"1876":{"word":"tiền thối","meaning":"Số tiền mà nhân viên thu ngân trả lại cho khách hàng đã thanh toán nhiều hơn giá trị thực của món đồ."},"1877":{"word":"bọt","meaning":"Một giọt chất lỏng rỗng, tròn, chứa không khí bên trong."},"1878":{"word":"đường ngang","meaning":"Điểm giao nhau của đường bộ và đường sắt, nơi xe cộ và người đi bộ trên đường băng qua đường ray."},"1879":{"word":"sự khô","meaning":"Tình trạng không có nước hoặc chất lỏng, hoặc có rất ít."},"1880":{"word":"giẻ lau","meaning":"Một miếng vải dùng để lau chùi vết bẩn hoặc nước."},"1881":{"word":"đen","meaning":"Có màu tối nhất, giống như bầu trời đêm không sao hoặc màu than đá."},"1882":{"word":"tìm kiếm","meaning":"Hành động tìm kỹ lưỡng qua nhiều mục hoặc nguồn để tìm thông tin hoặc đối tượng cụ thể."},"1883":{"word":"xem xét","meaning":"Hành động xem xét một cách cẩn thận nội dung nào đó để tìm ra sai sót hoặc đánh giá tính phù hợp."},"1884":{"word":"nỗi sợ","meaning":"Cảm giác khó chịu mạnh mẽ khi nhận thấy nguy hiểm hoặc mối đe dọa."},"1885":{"word":"áo khoác","meaning":"Áo mặc ngoài cùng để giữ ấm hoặc bảo vệ cơ thể khỏi thời tiết bên ngoài."},"1886":{"word":"niêm yết","meaning":"Hành động công khai thông báo, thông tin để nhiều người có thể xem."},"1887":{"word":"bảng thông báo","meaning":"Một tấm bảng phẳng, thường được gắn trên tường, dùng để dán các thông báo, tin nhắn cho mọi người đọc."},"1888":{"word":"chỉ vừa đủ","meaning":"Diễn tả việc đạt được điều gì đó một cách khó khăn, hoặc chỉ có một lượng rất nhỏ."},"1889":{"word":"cuối cùng","meaning":"Kết quả hoặc điều được quyết định sau khi mọi việc khác đã được xem xét và hoàn thành."},"1890":{"word":"thanh toán","meaning":"Hành động trả tiền hoặc sử dụng thẻ để mua hàng hóa, dịch vụ."},"1891":{"word":"sân vận động","meaning":"Địa điểm có sức chứa lớn, có nhiều chỗ ngồi, dùng để tổ chức các sự kiện thể thao hoặc hòa nhạc."},"1892":{"word":"Cung Gyeongbok","meaning":"Một cung điện hoàng gia cổ kính và lớn tại Seoul, Hàn Quốc, nổi bật với kiến trúc truyền thống và khuôn viên đẹp."},"1893":{"word":"chi phí","meaning":"Số tiền cần chi tiêu để thực hiện một hoạt động hoặc mua sắm vật phẩm."},"1894":{"word":"phòng bảo vệ","meaning":"Căn phòng hoặc khu vực nhỏ nơi nhân viên bảo vệ làm việc để trông coi và đảm bảo an ninh cho một khu vực."},"1895":{"word":"trường hợp","meaning":"Một sự việc hoặc một tình huống cụ thể diễn ra."},"1896":{"word":"kinh tế","meaning":"Hệ thống sản xuất, phân phối và tiêu thụ hàng hóa, dịch vụ trong một quốc gia hoặc khu vực."},"1897":{"word":"có tính kinh tế","meaning":"Liên quan đến nền kinh tế của một quốc gia hoặc một cá nhân."},"1898":{"word":"cảnh sát","meaning":"Người làm nhiệm vụ giữ gìn trật tự và an ninh xã hội, ngăn chặn tội phạm."},"1899":{"word":"bên cạnh","meaning":"Vị trí rất gần với người hoặc vật nào đó, thường trong tầm tay."},"1900":{"word":"thung lũng","meaning":"Một vùng đất dài và trũng giữa các ngọn đồi hoặc núi, thường có sông hoặc suối chảy qua."},"1901":{"word":"hợp đồng","meaning":"Một văn bản thỏa thuận chính thức giữa hai hoặc nhiều bên, quy định các điều khoản và nghĩa vụ."},"1902":{"word":"tiền đặt cọc","meaning":"Số tiền ban đầu trả trước khi mua một món đồ giá trị lớn như nhà hoặc xe, phần còn lại sẽ trả sau."},"1903":{"word":"tài khoản ngân hàng","meaning":"Hồ sơ ghi lại số tiền một người đã gửi và rút tại một tổ chức tài chính."},"1904":{"word":"khách hàng","meaning":"Người thường xuyên mua hàng hóa hoặc sử dụng dịch vụ từ một cửa hàng hoặc doanh nghiệp."},"1905":{"word":"khoai lang","meaning":"Loại củ có vỏ màu nâu hoặc đỏ, ruột màu vàng, có vị ngọt và bùi."},"1906":{"word":"cung điện cổ","meaning":"Một tòa nhà hoặc quần thể kiến trúc lớn, đẹp đẽ ở Hàn Quốc nơi vua hoặc hoàng hậu từng sinh sống."},"1907":{"word":"Thú nhận; thổ lộ","meaning":"Hành động tiết lộ một bí mật, một lỗi lầm hoặc tình cảm sâu kín của bản thân."},"1908":{"word":"Khó khăn; vất vả; gian khổ","meaning":"Giai đoạn gặp nhiều khó khăn, chịu đựng vất vả về thể chất hoặc tinh thần."},"1909":{"word":"Tốc độ cao; cao tốc","meaning":"Trạng thái chuyển động với tốc độ cực kỳ nhanh, thường di chuyển quãng đường dài trong thời gian ngắn."},"1910":{"word":"Ớt","meaning":"Một loại quả dài, thường có màu đỏ hoặc xanh khi chín, nổi tiếng với vị cay và thường dùng làm gia vị trong món ăn."},"1911":{"word":"Bột ớt","meaning":"Bột gia vị cay được làm từ ớt khô giã nhỏ."},"1912":{"word":"Khó khăn; nan giải","meaning":"Một tình huống hoặc vấn đề thử thách khiến việc tiến hành hay hoàn thành một công việc trở nên khó khăn."},"1913":{"word":"Ngay sau đó; ngay lập tức","meaning":"Diễn tả một sự kiện hoặc hành động xảy ra chỉ một lát sau một sự kiện trước đó, hầu như không có khoảng dừng."},"1914":{"word":"Thẳng; trực tiếp","meaning":"Di chuyển hoặc hướng theo một đường thẳng không bị gián đoạn từ điểm này sang điểm khác, không có đường cong hay đường vòng."},"1915":{"word":"Đều đặn; đồng đều; đầy đủ","meaning":"Theo cách mà mọi bộ phận hoặc mọi người đều nhận được phần bằng nhau hoặc được bao phủ đồng nhất, không thiên vị hay mất cân bằng."},"1916":{"word":"Ngõ; hẻm","meaning":"Con đường dài và hẹp nằm giữa các ngôi nhà."},"1917":{"word":"Đường ngõ; đường hẻm","meaning":"Lối đi hẹp giữa các ngôi nhà."},"1918":{"word":"Gôn; golf","meaning":"Một trò chơi được chơi trên sân cỏ rộng với nhiều lỗ, trong đó người chơi dùng gậy dài đánh bóng vào lỗ."},"1919":{"word":"gấu","meaning":"Đây là một loài động vật lớn, có thân hình to, lông dài và thường có màu nâu hoặc đen."},"1920":{"word":"đẹp","meaning":"Mang những phẩm chất rất dễ chịu cho mắt nhìn, thường có vẻ tinh tế, duyên dáng hoặc thẩm mỹ."},"1921":{"word":"nhân","meaning":"Tính tổng khi một số được cộng lặp lại nhiều lần."},"1922":{"word":"khắp nơi","meaning":"Chỉ nhiều địa điểm khác nhau trong một khu vực nhất định, thể hiện sự phân bố rộng khắp."},"1923":{"word":"số không","meaning":"Ký hiệu số 0, đại diện cho sự vắng mặt của số lượng hoặc giá trị."},"1924":{"word":"không gian","meaning":"Một khu vực hoặc thể tích trống có sẵn cho một cái gì đó tồn tại, hoặc thứ gì đó đang chiếm chỗ."},"1925":{"word":"công cộng","meaning":"Mô tả một cái gì đó được mở cho tất cả mọi người trong một cộng đồng sử dụng hoặc quan sát."},"1926":{"word":"địa điểm công cộng","meaning":"Một địa điểm như công viên, đường phố hoặc thư viện, nơi nhiều người có thể tụ tập, đi qua hoặc ghé thăm tự do."},"1927":{"word":"tiền điện nước","meaning":"Các khoản phí định kỳ cho các dịch vụ thiết yếu như điện, nước, gas được sử dụng trong gia đình hoặc văn phòng."},"1928":{"word":"không khí","meaning":"Hỗn hợp khí vô hình bao quanh Trái đất mà các sinh vật hít vào phổi để thở."},"1929":{"word":"chung","meaning":"Khi hai hoặc nhiều người hoặc nhóm cùng nhau làm việc hoặc sở hữu một cái gì đó, chia sẻ trách nhiệm hoặc quyền sở hữu."},"1930":{"word":"xây dựng","meaning":"Quá trình xây dựng các công trình lớn như đường sá, nhà cửa hoặc cầu cống, thường có nhiều công nhân và máy móc hạng nặng."},"1931":{"word":"công thức","meaning":"Một tập hợp các ký hiệu và chữ cái dùng trong toán học để biểu thị một quy tắc hoặc mối quan hệ giữa các đại lượng."},"1932":{"word":"buổi biểu diễn","meaning":"Một buổi trình diễn âm nhạc, khiêu vũ hoặc kịch nghệ trước công chúng."},"1933":{"word":"nhà hát","meaning":"Một tòa nhà hoặc không gian rộng lớn được thiết kế để khán giả thưởng thức các buổi kịch, hòa nhạc hoặc múa trực tiếp."},"1934":{"word":"công chúa","meaning":"Con gái của vua và hoàng hậu, thường đội vương miện và mặc trang phục lộng lẫy trong các câu chuyện."},"1935":{"word":"điện thoại công cộng","meaning":"Một chiếc điện thoại đặt ở nơi công cộng, thường trong bốt hoặc trên giá đỡ, được sử dụng bằng cách bỏ tiền xu vào."},"1936":{"word":"tính chung","meaning":"Một đặc điểm hoặc yếu tố được nhiều người, vật hoặc sự việc chia sẻ hoặc có cùng cách thức."},"1937":{"word":"điểm chung","meaning":"Một đặc điểm hay yếu tố mà nhiều người, vật hoặc sự việc cùng có."},"1938":{"word":"nỗi sợ hãi","meaning":"Một cảm xúc rất mạnh mẽ và khó chịu xuất phát từ mối nguy hiểm, khiến người ta muốn chạy trốn hoặc la hét."},"1939":{"word":"phòng ban","meaning":"Một đơn vị hoặc bộ phận chuyên biệt trong một tổ chức lớn hơn như công ty, trường học hoặc cửa hàng."},"1940":{"word":"sự làm việc quá sức","meaning":"Tình trạng mệt mỏi hoặc bệnh tật nghiêm trọng do làm việc quá nhiều, đôi khi dẫn đến kiệt sức hoặc ngã quỵ."},"1941":{"word":"môn học","meaning":"Một lĩnh vực nghiên cứu hoặc kiến thức cụ thể mà học sinh, sinh viên học tại trường."},"1942":{"word":"sự ăn quá nhiều","meaning":"Hành động tiêu thụ lượng thức ăn nhiều hơn mức cơ thể cần, thường khiến dạ dày cảm thấy đầy tức khó chịu."},"1943":{"word":"sự phóng đại","meaning":"Việc nói hay thể hiện một điều gì đó lớn hơn, quan trọng hơn sự thật."},"1944":{"word":"trưởng phòng","meaning":"Người đứng đầu một phòng ban hoặc một nhóm nhân viên trong công ty, quản lý và đưa ra quyết định về công việc của họ."},"1945":{"word":"quá trình","meaning":"Một chuỗi các bước hoặc hành động diễn ra theo thời gian để đạt được một kết quả hoặc giải thích cách một điều gì đó phát triển."},"1946":{"word":"khoa học","meaning":"Phương pháp nghiên cứu thế giới tự nhiên thông qua quan sát cẩn thận và thử nghiệm để hiểu cách mọi vật hoạt động."},"1947":{"word":"nhà khoa học","meaning":"Người nghiên cứu thế giới tự nhiên và thực hiện các thí nghiệm để khám phá sự thật và kiến thức mới."},"1948":{"word":"khán giả","meaning":"Một nhóm người tập trung tại một địa điểm để xem một buổi biểu diễn, vở kịch hoặc sự kiện khác."},"1949":{"word":"không liên quan","meaning":"Hai sự vật hoặc vấn đề tồn tại riêng biệt và không ảnh hưởng đến nhau."},"1950":{"word":"bất kể","meaning":"Không bị ảnh hưởng hoặc ngăn cản bởi một yếu tố nào đó khi thực hiện hành động hoặc đưa ra quyết định."},"1951":{"word":"liên quan","meaning":"Hai sự vật hoặc vấn đề có mối ràng buộc, ảnh hưởng lẫn nhau."},"1952":{"word":"việc xem","meaning":"Hành động đến xem một buổi biểu diễn, phim hoặc triển lãm để thưởng thức hoặc tìm hiểu thông tin."},"1953":{"word":"khách tham quan","meaning":"Người đến một địa điểm cụ thể để xem một sự kiện, buổi biểu diễn hoặc triển lãm."},"1954":{"word":"sự liên quan","meaning":"Mối kết nối hoặc sự ảnh hưởng giữa hai hay nhiều sự vật, vấn đề."},"1955":{"word":"quản lý","meaning":"Đây là hoạt động trông coi, sắp xếp để mọi thứ hoặc con người hoạt động đúng đắn, có trật tự."},"1956":{"word":"quan sát","meaning":"Hành động chú ý xem xét kỹ lưỡng để nhận ra chi tiết và thu thập thông tin."},"1957":{"word":"cảnh tượng","meaning":"Toàn bộ những gì có thể nhìn thấy tại một nơi và thời điểm cụ thể, tạo nên một bức tranh sống động."},"1958":{"word":"vô cùng","meaning":"Từ dùng để chỉ mức độ lớn, mạnh, vượt xa mức bình thường hoặc mong đợi."},"1959":{"word":"tiết học","meaning":"Khoảng thời gian cụ thể trong ngày học mà học sinh học một môn nhất định."},"1960":{"word":"ngoại ô","meaning":"Khu vực dân cư, thường có nhà cửa và sân vườn, nằm ở bên ngoài trung tâm thành phố."},"1961":{"word":"phương tiện giao thông","meaning":"Bất kỳ xe cộ hoặc hệ thống nào như xe buýt, tàu hỏa, ô tô dùng để chở người hoặc đồ vật từ nơi này đến nơi khác."},"1962":{"word":"phương tiện đi lại","meaning":"Dịch vụ cụ thể giúp mọi người di chuyển đến một địa điểm, chẳng hạn như vé xe buýt hoặc chuyến bay đã đặt."},"1963":{"word":"kiều bào","meaning":"Người cùng một quốc gia nhưng đang sinh sống ở một quốc gia khác."},"1964":{"word":"quận","meaning":"Một đơn vị hành chính cấp dưới trong một thành phố hoặc tỉnh."},"1965":{"word":"điểm tham quan","meaning":"Điều thú vị hoặc ấn tượng mà mọi người đến xem hoặc trải nghiệm, như một tòa nhà nổi tiếng hay một buổi biểu diễn công cộng."},"1966":{"word":"lỗ","meaning":"Khoảng trống hoặc không gian chưa được lấp đầy, xuyên qua hoặc vào trong một vật thể rắn."},"1967":{"word":"đậm đà, bùi","meaning":"Diễn tả hương vị của thức ăn hoặc đồ uống có vị ngon, sâu, đậm đà, thường liên quan đến mùi rang hoặc lên men."},"1968":{"word":"khu vực","meaning":"Một trong nhiều khu vực được chia dựa trên các tiêu chuẩn hoặc đặc điểm nhất định."},"1969":{"word":"mua sắm","meaning":"Hành động có được một vật phẩm hoặc dịch vụ bằng cách trả tiền để đổi lấy nó."},"1970":{"word":"cấu trúc","meaning":"Cách các bộ phận của một cái gì đó được xây dựng, lắp ráp hoặc tổ chức để tạo thành một tổng thể."},"1971":{"word":"cụ thể","meaning":"Rõ ràng, không chung chung và có thể nhìn thấy hoặc chạm vào trực tiếp thay vì chỉ là một ý tưởng."},"1972":{"word":"tìm kiếm","meaning":"Tìm kiếm hoặc cố gắng đạt được điều gì đó mong muốn hay cần thiết."},"1973":{"word":"quốc gia","meaning":"Một vùng đất rộng lớn nơi người dân sống dưới sự quản lý của chính phủ riêng và thường chia sẻ một nền văn hóa chung."},"1974":{"word":"quốc kỳ","meaning":"Một mảnh vải có màu sắc và thiết kế đặc trưng, đại diện cho một quốc gia cụ thể và thường được treo trên cột."},"1975":{"word":"chuyến bay nội địa","meaning":"Những chuyến bay bằng máy bay di chuyển trong phạm vi biên giới của cùng một quốc gia."},"1976":{"word":"quốc gia","meaning":"Diễn tả một cơ quan, địa điểm hoặc tổ chức thuộc sở hữu và được hỗ trợ bởi chính phủ trung ương của một quốc gia."},"1977":{"word":"nước dùng","meaning":"Phần chất lỏng của súp, canh hoặc món hầm, thường còn lại sau khi đã lấy hết các nguyên liệu rắn."},"1978":{"word":"công dân","meaning":"Những người cư trú hợp pháp trong biên giới một quốc gia và được công nhận là thành viên của quốc gia đó."},"1979":{"word":"Tiếng Hàn","meaning":"Tiếng Hàn là ngôn ngữ chính được người dân Hàn Quốc sử dụng để giao tiếp và viết lách."},"1980":{"word":"quân đội","meaning":"Quân đội là một tổ chức lớn gồm nhiều người được huấn luyện để chiến đấu và bảo vệ đất nước."},"1981":{"word":"nhịn đói","meaning":"Nhịn đói là tình trạng không ăn uống trong thời gian dài, gây suy yếu thể chất nghiêm trọng."},"1982":{"word":"gót giày","meaning":"Gót giày là phần cứng, thường cao hơn ở phía sau của chiếc giày."},"1983":{"word":"khuyên bảo","meaning":"Khuyên bảo là gợi ý cho ai đó rằng một điều gì đó là lựa chọn tốt hoặc đưa ra một món đồ để họ nhận."},"1984":{"word":"kính gửi","meaning":"Kính gửi là từ ngữ lịch sự dùng để xưng hô trong thư từ hoặc tài liệu chính thức, thể hiện sự tôn trọng."},"1985":{"word":"đều đặn","meaning":"Đều đặn là việc xảy ra hoặc được thực hiện theo một mẫu cố định và có thể dự đoán được."},"1986":{"word":"bạn gái","meaning":"Bạn gái là người phụ nữ có mối quan hệ tình cảm yêu thương và gắn bó với một người."},"1987":{"word":"dù vậy","meaning":"Dù vậy là từ dùng để chỉ rằng điều gì đó vẫn đúng hoặc xảy ra, bất chấp một tuyên bố trước đó có thể gợi ý điều ngược lại."},"1988":{"word":"gam","meaning":"Gam là một đơn vị nhỏ dùng để đo khối lượng, ví dụ như một lượng nhỏ thịt hoặc bột."},"1989":{"word":"làm như vậy","meaning":"Làm như vậy là thực hiện một hành động hoặc cư xử đúng theo cách đã được đề cập trước đó."},"1990":{"word":"nhóm","meaning":"Nhóm là một tập hợp gồm nhiều người hoặc vật được liên kết với nhau vì một mục đích chung."},"1991":{"word":"dừng lại","meaning":"Kết thúc một hành động hoặc hoạt động đang thực hiện."},"1992":{"word":"chỉ, cứ","meaning":"Diễn tả hành động hoặc trạng thái một cách đơn giản, không có gì đặc biệt."},"1993":{"word":"hôm kia","meaning":"Ngày trước ngày hôm qua."},"1994":{"word":"trong số đó","meaning":"Chỉ một thứ hoặc một người cụ thể trong một nhóm lớn."},"1995":{"word":"mà này, nhưng mà","meaning":"Dùng để giới thiệu một chủ đề mới hoặc thay đổi hướng nói chuyện."},"1996":{"word":"công việc, sự làm việc","meaning":"Việc thực hiện các nhiệm vụ được giao tại nơi làm việc."},"1997":{"word":"cơ bắp","meaning":"Một bộ phận mềm trong cơ thể, co thắt và giãn ra để tạo ra sự chuyển động."},"1998":{"word":"thứ Sáu","meaning":"Ngày thứ năm trong tuần, sau thứ Năm và trước thứ Bảy."},"1999":{"word":"vàng","meaning":"Một kim loại quý, sáng bóng, màu vàng, thường được dùng làm trang sức và tiền xu."},"2000":{"word":"số tiền, khoản tiền","meaning":"Tổng số tiền cụ thể cần thiết hoặc phải trả cho một thứ gì đó."},"2001":{"word":"cấm hút thuốc","meaning":"Lời chỉ dẫn hoặc biển báo không cho phép hút thuốc lá ở một khu vực nhất định."},"2002":{"word":"kẻ, vẽ","meaning":"Dùng bút hoặc công cụ khác tạo ra một đường hoặc dấu vết trên bề mặt."},"2003":{"word":"tích cực","meaning":"Có thái độ lạc quan, hy vọng vào những điều tốt đẹp sẽ xảy ra."},"2004":{"word":"-máy, -thiết bị","meaning":"Hậu tố dùng để tạo danh từ chỉ một thiết bị thực hiện hành động của động từ gốc."},"2005":{"word":"máy móc","meaning":"Một thiết bị có các bộ phận chuyển động, dùng năng lượng để thực hiện một công việc cụ thể."},"2006":{"word":"cơ quan","meaning":"Một tổ chức hoặc đơn vị được thành lập với mục đích cụ thể, thường là phục vụ cộng đồng."},"2007":{"word":"dụng cụ, thiết bị","meaning":"Các đồ vật hoặc thiết bị được dùng để thực hiện một công việc hoặc hoạt động nào đó."},"2008":{"word":"kỷ niệm","meaning":"Hành động ghi nhớ một sự kiện hoặc nhân vật quan trọng trong quá khứ để nhiều người cùng nhớ đến."},"2009":{"word":"quà lưu niệm","meaning":"Một món đồ nhỏ được mua hoặc giữ lại để gợi nhớ về một địa điểm, sự kiện hoặc chuyến đi cụ thể."},"2010":{"word":"chức năng","meaning":"Nhiệm vụ hoặc công việc cụ thể mà một thứ gì đó được thiết kế hoặc mong đợi sẽ thực hiện."},"2011":{"word":"bò","meaning":"Di chuyển về phía trước bằng tay và đầu gối, giữ thân thể sát mặt đất."},"2012":{"word":"kỳ vọng","meaning":"Cảm giác mong đợi mạnh mẽ về một sự kiện hoặc kết quả mà một người tin rằng sẽ xảy ra hoặc hy vọng sẽ xảy ra."},"2013":{"word":"tựa vào, dựa vào","meaning":"Đặt một phần cơ thể hoặc vật thể vào vật khác để lấy điểm tựa hoặc hỗ trợ."},"2014":{"word":"cầu nguyện","meaning":"Hành động nói chuyện với thần linh hoặc đấng siêu nhiên, thường để xin giúp đỡ hoặc bày tỏ lòng biết ơn."},"2015":{"word":"kỳ thi cuối kỳ","meaning":"Đây là bài kiểm tra quan trọng được thực hiện vào cuối một học kỳ hoặc khóa học."},"2016":{"word":"tài xế","meaning":"Người điều khiển các loại phương tiện giao thông như xe buýt, taxi."},"2017":{"word":"bài báo","meaning":"Một bản tin hay câu chuyện được viết và đăng trên báo chí, tạp chí hoặc trang web."},"2018":{"word":"kỹ thuật viên","meaning":"Người lao động có kỹ năng chuyên môn trong việc bảo trì, sửa chữa hoặc vận hành thiết bị phức tạp."},"2019":{"word":"trí nhớ","meaning":"Khả năng của não bộ để lưu trữ và gợi lại thông tin, sự kiện hoặc kinh nghiệm đã xảy ra."},"2020":{"word":"doanh nghiệp","meaning":"Một tổ chức kinh doanh sản xuất hàng hóa hoặc cung cấp dịch vụ, thường có nhiều nhân viên và nhà đầu tư."},"2021":{"word":"tiêu chuẩn","meaning":"Quy tắc, nguyên tắc hoặc mức độ chất lượng được dùng để đánh giá, đo lường hoặc đưa ra quyết định về điều gì đó."},"2022":{"word":"cơ sở, nền tảng","meaning":"Những yếu tố ban đầu thiết yếu hoặc nguyên tắc quan trọng nhất tạo nên nền móng cho một cái gì đó lớn hơn."},"2023":{"word":"khác, khác nữa","meaning":"Dùng để chỉ những mục, người hoặc vấn đề khác ngoài những điều đã được nêu ra."},"2024":{"word":"khẩn cấp","meaning":"Tình huống nghiêm trọng, nguy hiểm hoặc vấn đề cần được giải quyết ngay lập tức và nhanh chóng."},"2025":{"word":"dài tay","meaning":"Phần của quần áo như áo sơ mi hoặc áo khoác che kín cánh tay từ vai đến cổ tay."},"2026":{"word":"dài","meaning":"Có khoảng cách lớn từ đầu này đến đầu kia, hoặc kéo dài trong một khoảng thời gian đáng kể."},"2027":{"word":"hơi nước","meaning":"Một đám mây nhỏ gồm các giọt nước bay lên từ nước nóng hoặc các chất lỏng nóng khác."},"2028":{"word":"bóc vỏ","meaning":"Hành động loại bỏ lớp vỏ bên ngoài của trái cây, trứng hoặc thứ gì đó bằng tay."},"2029":{"word":"gọn gàng","meaning":"Miêu tả một nơi hoặc vật được sắp xếp ngăn nắp, không có sự lộn xộn hay bẩn thỉu."},"2030":{"word":"chớp","meaning":"Diễn tả ánh sáng bật tắt rất nhanh hoặc mắt nhắm mở nhanh chóng."},"2031":{"word":"vỡ","meaning":"Tình trạng một vật cứng như thủy tinh hoặc gốm sứ bị rơi hoặc va đập mạnh làm nó tách thành nhiều mảnh."},"2032":{"word":"tắt","meaning":"Khi ngọn lửa, đám cháy hoặc nguồn sáng ngừng cháy hoặc chiếu sáng, làm cho khu vực đó trở nên tối."},"2033":{"word":"vỏ","meaning":"Lớp bao phủ bên ngoài của trái cây, rau củ, v.v., thường không dai."},"2034":{"word":"đuôi","meaning":"Bộ phận cơ thể dài, linh hoạt nhô ra từ phía sau của động vật, thường dùng để giữ thăng bằng hoặc giao tiếp."},"2035":{"word":"nhúc nhích","meaning":"Diễn tả việc một người hoặc vật hoàn toàn đứng yên, không có bất kỳ cử động nhỏ nào."},"2036":{"word":"cắm","meaning":"Đẩy một vật dài hoặc mỏng vào một khe hở hẹp hoặc bề mặt để nó đứng hoặc giữ chắc chắn bên trong."},"2037":{"word":"họa tiết hoa","meaning":"Một thiết kế hoặc in ấn trên vải, giấy hoặc các bề mặt khác có hình ảnh hoa, lá và cây cỏ."},"2038":{"word":"chặt","meaning":"Từ miêu tả cách tác động lực ép rất mạnh, làm cho vật gì đó được giữ chặt hoặc dính chặt."},"2039":{"word":"khá","meaning":"Chỉ mức độ đáng kể, nhiều hơn một chút nhưng không đến mức cực đoan."},"2040":{"word":"đều đặn","meaning":"Chỉ việc thực hiện một hành động liên tục, với tốc độ hoặc mức độ không đổi trong thời gian dài."},"2041":{"word":"mật ong","meaning":"Chất lỏng ngọt, sánh, màu vàng óng do ong tạo ra và dự trữ trong tổ."},"2042":{"word":"sợi dây","meaning":"Vật liệu mỏng, mềm dẻo, thường là sợi xoắn, dùng để buộc, gói hoặc kéo đồ vật."},"2043":{"word":"bị gián đoạn","meaning":"Khi một con đường, kết nối hoặc dòng chảy liên tục của cái gì đó đột ngột dừng lại, không thể tiếp tục được nữa."},"2044":{"word":"bị đứt","meaning":"Khi một vật dài, mỏng như dây thừng, dây điện hoặc sợi chỉ bị tách ra thành hai hoặc nhiều mảnh."},"2045":{"word":"kéo","meaning":"Làm cho một vật di chuyển bằng cách giữ và khiến nó trượt theo hoặc di chuyển tới gần."},"2046":{"word":"cuối cùng","meaning":"Chỉ một sự việc hoặc hành động xảy ra sau một thời gian dài, hoặc là bước cuối cùng trong một chuỗi."},"2047":{"word":"bữa ăn","meaning":"Thời điểm đã định trong ngày để mọi người ăn các món đã chuẩn bị."},"2048":{"word":"bao phủ","meaning":"Khi nhiều mây xuất hiện trên bầu trời, làm cho trời trở nên tối hoặc u ám."},"2049":{"word":"vận chuyển","meaning":"Mang hoặc chuyển đồ vật từ một địa điểm này đến một địa điểm khác, thường bằng tay hoặc xe cộ."},"2050":{"word":"món rau trộn","meaning":"Món ăn Hàn Quốc làm từ các loại rau có thể ăn được, được nấu chín và nêm nếm gia vị."},"2051":{"word":"lá cây","meaning":"Đây là bộ phận thường xanh, dẹt, mọc trên thân hoặc cành của cây."},"2052":{"word":"xấu đi","meaning":"Trở nên kém chất lượng hơn, không tốt bằng hoặc ở trong tình trạng không mong muốn so với trước."},"2053":{"word":"tốt hơn","meaning":"Thay đổi sang trạng thái mong muốn hơn, khỏe mạnh hơn hoặc hoạt động hiệu quả hơn."},"2054":{"word":"dao bỏ túi","meaning":"Một con dao nhỏ thường được cất trong túi."},"2055":{"word":"xuất hiện","meaning":"Để một đối tượng vô hình nào đó hiện ra bên ngoài."},"2056":{"word":"lá rụng","meaning":"Là những chiếc lá cây đã khô, đổi màu và rụng khỏi cành, thường phủ đầy mặt đất vào mùa thu."},"2057":{"word":"lò sưởi","meaning":"Một thiết bị độc lập, thường bằng kim loại, dùng gỗ hoặc nhiên liệu khác để tạo nhiệt và sưởi ấm căn phòng."},"2058":{"word":"hệ thống sưởi","meaning":"Hệ thống hoặc quá trình cung cấp hơi ấm cho một tòa nhà hoặc không gian kín, thường trong thời tiết lạnh."},"2059":{"word":"bay đi","meaning":"Di chuyển trong không trung và rời khỏi một địa điểm, thường biến mất khỏi tầm nhìn."},"2060":{"word":"cũ kỹ","meaning":"Mô tả một vật đã được sử dụng lâu ngày và có dấu hiệu hao mòn như bạc màu, rách hoặc hỏng hóc."},"2061":{"word":"nam giới","meaning":"Một người trưởng thành thuộc giới tính nam."},"2062":{"word":"phía nam","meaning":"Một trong bốn điểm chính của la bàn, đối diện với phía bắc, thường chỉ hướng về phía xích đạo."},"2063":{"word":"Nam Mỹ","meaning":"Một lục địa rộng lớn nằm giữa Thái Bình Dương và Đại Tây Dương."},"2064":{"word":"phía nam","meaning":"Vùng đất nằm ở phía dưới hoặc gần đường biên giới phía nam của một khu vực hoặc quốc gia."},"2065":{"word":"xa lạ","meaning":"Có cảm giác mới mẻ hoặc chưa từng thấy hay trải nghiệm trước đây."},"2066":{"word":"sinh, đẻ","meaning":"Hành động của người phụ nữ hoặc con vật cái đẩy em bé hoặc con non ra khỏi cơ thể mình."},"2067":{"word":"trong vòng","meaning":"Chỉ giới hạn thời gian hoặc không gian mà một sự vật, sự việc diễn ra hoặc được chứa đựng."},"2068":{"word":"suốt, luôn luôn","meaning":"Liên tục, từ đầu đến cuối một khoảng thời gian nhất định."},"2069":{"word":"tháng sau","meaning":"Khoảng thời gian khoảng 30 ngày ngay sau tháng hiện tại."},"2070":{"word":"đặt xuống","meaning":"Đặt một vật đang cầm từ vị trí cao xuống một bề mặt bên dưới."},"2071":{"word":"đưa ra ngoài","meaning":"Làm cho một người hoặc vật di chuyển từ không gian kín ra bên ngoài."},"2072":{"word":"hướng nội","meaning":"Mô tả người thường trầm tính, thích ở một mình hoặc với một vài người thân thiết, và ít khi thể hiện cảm xúc ra ngoài."},"2073":{"word":"trao, trả","meaning":"Trao một vật hoặc tiền cho người khác, đặc biệt khi đó là cái phải trả hoặc được yêu cầu."},"2074":{"word":"năm sau nữa","meaning":"Khoảng thời gian mười hai tháng cụ thể sau năm tới."},"2075":{"word":"Ngày kia","meaning":"Đó là ngày sau ngày mai, tức là hai ngày kể từ bây giờ."},"2076":{"word":"Đông lạnh","meaning":"Trạng thái của một chất, thường là thực phẩm hoặc nước, được làm cho rất rắn và cứng bằng nhiệt độ cực lạnh để bảo quản."},"2077":{"word":"Làm mát","meaning":"Hệ thống hoặc thiết bị làm giảm nhiệt độ bên trong phòng hoặc tòa nhà bằng cách thổi không khí mát."},"2078":{"word":"Lạnh lùng","meaning":"Giữ bình tĩnh và đưa ra quyết định mà không thể hiện cảm xúc cá nhân mạnh mẽ, ngay cả trong tình huống khó khăn."},"2079":{"word":"Phơi","meaning":"Đặt các vật ướt hoặc quần áo lên dây hoặc giá phơi ngoài trời để chúng khô ráo."},"2080":{"word":"Rộng rãi","meaning":"Đến được hoặc ảnh hưởng đến một số lượng lớn nơi chốn hoặc người."},"2081":{"word":"Diện tích","meaning":"Khoảng không gian hoặc bề mặt mà một địa điểm hoặc vật thể chiếm giữ."},"2082":{"word":"Đổ","meaning":"Một vật đang đứng nghiêng về một phía hoặc rơi xuống."},"2083":{"word":"Vượt qua","meaning":"Nhảy qua một nơi cao để tiến lên."},"2084":{"word":"Thập niên","meaning":"Một khoảng thời gian mười năm, ví dụ như từ năm 1980 đến 1989."},"2085":{"word":"Màu vàng","meaning":"Màu sắc của quả chuối hoặc quả chanh."},"2086":{"word":"Tuyến đường","meaning":"Lộ trình hoặc hướng cố định mà một phương tiện như xe buýt hoặc tàu hỏa đi theo lặp đi lặp lại từ nơi này đến nơi khác."},"2087":{"word":"bản đồ tuyến đường","meaning":"Bản đồ thể hiện lộ trình di chuyển và các điểm dừng của phương tiện giao thông."},"2088":{"word":"người cao tuổi và người khuyết tật","meaning":"Những người lớn tuổi hoặc những người gặp khó khăn khi di chuyển do bệnh tật, thương tích."},"2089":{"word":"máy tính xách tay","meaning":"Một loại máy tính nhỏ gọn, có màn hình và bàn phím gắn liền, được thiết kế để mang đi và sử dụng ở nhiều nơi."},"2090":{"word":"tan chảy","meaning":"Tình trạng băng, tuyết trở thành nước khi được làm nóng."},"2091":{"word":"bản ghi âm","meaning":"Âm thanh (giọng nói, tiếng hát) được thu lại và lưu trữ dưới dạng dữ liệu điện tử để phát lại sau."},"2092":{"word":"máy ghi âm","meaning":"Thiết bị dùng để thu và lưu trữ âm thanh (lời nói, nhạc) nhằm phát lại sau này."},"2093":{"word":"công viên giải trí","meaning":"Nơi có nhiều trò chơi và phương tiện giải trí để tham quan, vui chơi."},"2094":{"word":"sân chơi","meaning":"Khu vực ngoài trời dành cho trẻ em, có trang bị các trò chơi như xích đu, cầu trượt, hố cát để chúng vui chơi."},"2095":{"word":"nông dân","meaning":"Người làm nghề trồng trọt hoặc chăn nuôi để kiếm sống."},"2096":{"word":"nông nghiệp","meaning":"Việc trồng trọt trên đất đai và chăn nuôi động vật để sản xuất lương thực, thực phẩm và nguyên vật liệu."},"2097":{"word":"cao lên","meaning":"Độ cao từ dưới lên trên tăng lên."},"2098":{"word":"nâng cao","meaning":"Làm cho vật gì đó cao hơn về mặt vật lý, hoặc tăng vị trí/mức độ của nó."},"2099":{"word":"kính ngữ","meaning":"Những từ ngữ hoặc cấu trúc ngữ pháp đặc biệt dùng để thể hiện sự tôn trọng đối với người lớn tuổi hoặc có địa vị cao hơn."},"2100":{"word":"yên tâm","meaning":"Khi những lo lắng, băn khoăn của một người biến mất hoặc được xoa dịu."},"2101":{"word":"bỏ lỡ, đánh mất","meaning":"Không nắm giữ được thứ gì đó, hoặc không kịp lên xe, tham gia một sự kiện."},"2102":{"word":"vùng mắt","meaning":"Phần da trên mặt của một người nằm gần và bên dưới mắt."},"2103":{"word":"bệnh về mắt","meaning":"Tình trạng bệnh lý gây đỏ, đau hoặc khó nhìn ở mắt."},"2104":{"word":"chói mắt","meaning":"Khi ánh sáng rất mạnh chiếu thẳng vào mắt làm khó nhìn."},"2105":{"word":"người tuyết","meaning":"Một hình người được làm từ những quả cầu tuyết lớn xếp chồng lên nhau ở ngoài trời."},"2106":{"word":"ném tuyết","meaning":"Một trò chơi vui vẻ trong đó mọi người ném những quả cầu tuyết nén vào nhau."},"2107":{"word":"tăng lên, mở rộng","meaning":"Làm cho kích thước, số lượng hoặc quy mô của thứ gì đó trở nên lớn hơn."},"2108":{"word":"tăng lên","meaning":"Số lượng hoặc quy mô của thứ gì đó trở nên lớn hơn."},"2109":{"word":"ngủ nướng","meaning":"Hành động nằm trên giường và nghỉ ngơi lâu hơn bình thường, đặc biệt là đến quá buổi sáng."},"2110":{"word":"hậu tố kính ngữ","meaning":"Một hậu tố được gắn vào tên hoặc chức danh của một người để thể hiện sự lịch sự và tôn trọng."},"2111":{"word":"bàn là","meaning":"Thiết bị điện có mặt phẳng kim loại nóng dùng để ủi phẳng quần áo."},"2112":{"word":"sự là ủi","meaning":"Hành động dùng bàn là ủi quần áo cho phẳng và hết nếp nhăn."},"2113":{"word":"quán trà","meaning":"Nơi truyền thống để uống đồ uống nóng như cà phê hoặc trà, thường có phong cách cổ điển."},"2114":{"word":"tải xuống","meaning":"Hành động đưa một tệp hoặc chương trình kỹ thuật số từ hệ thống máy tính từ xa về thiết bị cá nhân."},"2115":{"word":"sự ân cần","meaning":"Tình cảm hoặc sự thể hiện lòng tốt và sự quan tâm chân thành đối với người khác."},"2116":{"word":"băm nhỏ","meaning":"Dùng dao hoặc dụng cụ cắt thực phẩm thành những mảnh rất nhỏ, đều nhau."},"2117":{"word":"sự may mắn","meaning":"Kết quả tích cực không ngờ trong một tình huống lẽ ra có thể tồi tệ, mang lại cảm giác nhẹ nhõm."},"2118":{"word":"may mắn thay","meaning":"Diễn ra theo cách tạo ra kết quả tích cực, đặc biệt khi mọi thứ dường như sẽ diễn biến xấu."},"2119":{"word":"cứng rắn","meaning":"Mô tả một vật khó bị bẻ cong, vỡ hoặc thay đổi hình dạng."},"2120":{"word":"vị ngọt","meaning":"Vị đặc trưng cảm nhận được trong miệng khi ăn các loại thực phẩm như đường, mật ong hoặc trái cây chín."},"2121":{"word":"tóc ngắn","meaning":"Kiểu tóc ngắn của phụ nữ thường dài đến dưới tai hoặc ngang vai."},"2122":{"word":"đơn vị","meaning":"Một lượng cụ thể được dùng làm tiêu chuẩn để biểu thị số lượng, ví dụ như kilôgam cho khối lượng hoặc mét cho chiều dài."},"2123":{"word":"khuyết điểm","meaning":"Một đặc điểm tiêu cực khiến một người hay một vật kém tốt, hữu ích hoặc hiệu quả hơn."},"2124":{"word":"ngăn nắp, chỉnh tề","meaning":"Có vẻ ngoài sạch sẽ, được sắp xếp cẩn thận và gọn gàng."},"2125":{"word":"khu phức hợp, khu dân cư","meaning":"Một nhóm nhiều tòa nhà được xây dựng gần nhau, tạo thành một cộng đồng có quy hoạch thống nhất."},"2126":{"word":"đoàn thể, tổ chức","meaning":"Một tổ chức gồm những người cùng tập hợp vì một mục tiêu chung."},"2127":{"word":"đóng lại, khép lại (tự động)","meaning":"Cửa, cửa sổ hoặc lối mở di chuyển vào vị trí che kín, ngăn chặn lối vào hoặc tầm nhìn."},"2128":{"word":"gắn, treo, đính","meaning":"Nối một vật vào một vật khác, thường là treo lên hoặc cố định chắc chắn vào bề mặt."},"2129":{"word":"yêu cầu, đề nghị","meaning":"Bày tỏ mong muốn nhận được một thứ gì đó hoặc muốn người khác thực hiện một hành động cụ thể cho mình."},"2130":{"word":"thay đổi, trở nên khác","meaning":"Trở nên khác biệt rõ rệt so với trạng thái, vẻ ngoài hoặc điều kiện trước đó."},"2131":{"word":"đô la","meaning":"Một loại tiền tệ chính thức được sử dụng ở nhiều quốc gia, thường được ký hiệu bằng '$'."},"2132":{"word":"ngọt ngào, ngọt","meaning":"Có vị dễ chịu giống đường hoặc mật ong, thường mang lại cảm giác vui thích."},"2133":{"word":"nhúng, ngâm","meaning":"Đặt vật gì đó hoàn toàn hoặc một phần vào chất lỏng, có thể trong chốc lát hoặc để ngâm lâu hơn."},"2134":{"word":"được đựng, được chứa","meaning":"Một vật được đặt hoặc để bên trong một vật chứa."},"2135":{"word":"đựng","meaning":"Đặt một vật gì đó vào trong một vật chứa để nó ở bên trong."},"2136":{"word":"năm ngày","meaning":"Khoảng thời gian kéo dài đúng năm ngày."},"2137":{"word":"cà rốt","meaning":"Một loại rau củ có màu cam, vị ngọt, thường được dùng làm thức ăn."},"2138":{"word":"bạn","meaning":"Đại từ dùng để chỉ người mà mình đang nói chuyện trực tiếp."},"2139":{"word":"đương nhiên","meaning":"Điều gì đó rõ ràng là đúng, hợp lý và không cần phải giải thích thêm."},"2140":{"word":"đương nhiên","meaning":"Một cách chắc chắn, không thể khác được và ai cũng biết."},"2141":{"word":"ngay lập tức","meaning":"Diễn ra không chút chậm trễ, ngay tại thời điểm hiện tại."},"2142":{"word":"sự lúng túng","meaning":"Trạng thái bối rối, không thoải mái, thường xảy ra khi gặp điều bất ngờ hoặc khó xử."},"2143":{"word":"chạm","meaning":"Đặt tay hoặc một vật nào đó tiếp xúc vật lý với một vật khác."},"2144":{"word":"thân cây","meaning":"Phần chính dài và mảnh của cây, thường mọc thẳng đứng và nâng đỡ lá hoặc hoa."},"2145":{"word":"áp vào","meaning":"Đưa một vật, một bộ phận cơ thể hoặc một bề mặt tiếp xúc vật lý với vật khác."},"2146":{"word":"ghê gớm","meaning":"Có mức độ mạnh mẽ, dữ dội hoặc gây ấn tượng vượt xa mức bình thường."},"2147":{"word":"Thành phố lớn","meaning":"Một thành phố có quy mô lớn với dân số đông, là trung tâm chính trị, kinh tế và văn hóa."},"2148":{"word":"Cổng chính, cửa lớn","meaning":"Một cái cửa lớn, thường ở phía trước nhà hoặc tòa nhà, dùng để mở ra và đóng lại cho người ra vào."},"2149":{"word":"Phân, đại tiện","meaning":"Chất thải rắn từ cơ thể được thải ra qua hậu môn sau khi thức ăn được tiêu hóa."},"2150":{"word":"Đối tượng, chủ thể","meaning":"Người hoặc vật cụ thể đang được quan sát, nghiên cứu hoặc đặc biệt chú ý trong một hoạt động."},"2151":{"word":"Thay thế, thay mặt","meaning":"Việc một người hay vật đảm nhận trách nhiệm hoặc vị trí của một người hay vật khác."},"2152":{"word":"Năm sáu, năm hoặc sáu","meaning":"Một số lượng ước chừng nhỏ, chỉ khoảng năm hoặc sáu đơn vị."},"2153":{"word":"Công chúng, đại chúng","meaning":"Một tập hợp đông đảo nhiều người."},"2154":{"word":"Bài hát đại chúng, nhạc phổ biến","meaning":"Một bài hát có lời được nhiều người biết đến, nghe và thường hát theo."},"2155":{"word":"Giao thông công cộng","meaning":"Các phương tiện như xe buýt, tàu điện, tàu điện ngầm mà nhiều người có thể sử dụng để đi lại cùng nhau với một khoản phí."},"2156":{"word":"Tổng vệ sinh, dọn dẹp lớn","meaning":"Hoạt động dọn dẹp nhà cửa một cách kỹ lưỡng, lau chùi sàn nhà, bề mặt và sắp xếp mọi vật dụng cho thật ngăn nắp."},"2157":{"word":"Nói chung, nhìn chung","meaning":"Dùng để chỉ rằng điều gì đó xảy ra hoặc đúng trong hầu hết các trường hợp, chỉ có một vài ngoại lệ."},"2158":{"word":"Tổng thống","meaning":"Người được bầu làm lãnh đạo chính và đại diện quốc gia."},"2159":{"word":"đại diện","meaning":"Người hoặc vật được chọn để đại diện cho một nhóm, một tổ chức hoặc là ví dụ điển hình cho một loại."},"2160":{"word":"tiêu biểu, điển hình","meaning":"Chỉ đặc điểm của một sự vật, sự việc mà qua đó có thể nhìn thấy được những nét chung của cả một loại, một nhóm."},"2161":{"word":"đối mặt","meaning":"Hướng phần thân trước của mình về phía một người hoặc vật nào đó để nhìn trực tiếp."},"2162":{"word":"Hàn Quốc, Đại Hàn Dân Quốc","meaning":"Tên gọi chính thức của một quốc gia nằm ở phía nam bán đảo Triều Tiên, thuộc khu vực Đông Á."},"2163":{"word":"cỡ lớn, loại lớn","meaning":"Chỉ một vật có kích thước hoặc quy mô lớn hơn hẳn so với những vật cùng loại."},"2164":{"word":"bị bẩn, bị dơ","meaning":"Bị bao phủ bởi bụi bẩn, bùn, vết ố, hoặc các chất không sạch khác, khiến cho vật đó trông thấy rõ là bị dơ."},"2165":{"word":"thêm vào, cộng thêm","meaning":"Gộp một lượng vật phẩm hoặc con số vào một lượng khác để tổng số trở nên lớn hơn."},"2166":{"word":"chưa, ít hơn","meaning":"Chỉ một lượng ít hơn mức thông thường hoặc một trạng thái chưa đạt đến mức độ hoàn chỉnh, mong muốn."},"2167":{"word":"lấy bớt, giảm bớt","meaning":"Loại bỏ một phần của vật gì đó từ một lượng lớn hơn, khiến cho lượng còn lại trông thấy rõ là ít đi."},"2168":{"word":"che, đậy, phủ","meaning":"Đặt một vật lên trên một vật khác để che khuất hoặc bảo vệ vật bên dưới."},"2169":{"word":"nơi, chỗ","meaning":"Chỉ một địa điểm cụ thể hoặc một tình huống nhất định mà ở đó một sự việc xảy ra hoặc tồn tại."},"2170":{"word":"bị bỏng","meaning":"Da hoặc mô bị tổn thương do nhiệt độ cao, lửa hoặc vật nóng, thường gây đỏ rát hoặc phồng rộp."},"2171":{"word":"đưa đi","meaning":"Mang theo người hoặc vật nuôi cùng đi đến một nơi nào đó."},"2172":{"word":"chần","meaning":"Cho thức ăn, thường là rau, vào nước rất nóng trong một thời gian ngắn rồi lấy ra."},"2173":{"word":"tỉnh","meaning":"Một khu vực hành chính lớn trong một quốc gia, có chính quyền địa phương riêng."},"2174":{"word":"dụng cụ","meaning":"Vật dùng để thực hiện một công việc hoặc nhiệm vụ cụ thể."},"2175":{"word":"kẻ trộm","meaning":"Người lấy tài sản của người khác một cách bí mật mà không được phép hoặc không trả tiền."},"2176":{"word":"chạy trốn","meaning":"Nhanh chóng rời khỏi một nơi hoặc tình huống nguy hiểm để tránh bị bắt hoặc làm hại."},"2177":{"word":"sách vở","meaning":"Tập hợp các bản in được đóng thành quyển, mô tả một tư tưởng, cảm xúc, câu chuyện, v.v."},"2178":{"word":"hộp cơm","meaning":"Hộp đựng thức ăn đơn giản, tiện lợi để mang theo."},"2179":{"word":"trung tâm thành phố","meaning":"Khu vực thương mại và kinh doanh chính ở giữa một thành phố lớn."},"2180":{"word":"đồ gốm","meaning":"Đồ vật làm bằng đất sét được nhào nặn, tạo hình, phơi khô và nung ở nhiệt độ cao."},"2181":{"word":"con dấu","meaning":"Vật dùng để in một thiết kế hoặc ký tự độc đáo lên bề mặt, thường là giấy."},"2182":{"word":"giữa chừng","meaning":"Tại một thời điểm nào đó trong một chuyến đi hoặc hoạt động, không phải lúc bắt đầu hay kết thúc."},"2183":{"word":"bệnh cúm","meaning":"Một bệnh truyền nhiễm cấp tính ở đường hô hấp do vi rút cúm gây ra, thường có các triệu chứng sốt, ho, đau họng, chảy nước mũi và đau nhức cơ thể."},"2184":{"word":"tiếng Đức","meaning":"Ngôn ngữ chính thức được sử dụng ở Đức, Áo, Thụy Sĩ và một số quốc gia lân cận."},"2185":{"word":"sinh nhật đầu tiên","meaning":"Lễ kỷ niệm đặc biệt được tổ chức khi một em bé tròn một tuổi."},"2186":{"word":"nhận lại","meaning":"Hành động nhận lại một đồ vật hoặc thứ gì đó đã đưa cho người khác."},"2187":{"word":"chăm sóc","meaning":"Hành động trông nom và bảo vệ ai đó hoặc thứ gì đó để đảm bảo họ an toàn và có mọi thứ cần thiết."},"2188":{"word":"đi loanh quanh","meaning":"Di chuyển từ nơi này sang nơi khác trong một khu vực, thường là đi bộ, không có một lộ trình cụ thể."},"2189":{"word":"phía đông","meaning":"Một trong bốn hướng chính trên la bàn, là hướng mặt trời mọc vào buổi sáng."},"2190":{"word":"phường, khu phố","meaning":"Một đơn vị hành chính cơ bản của thành phố ở Hàn Quốc, tương đương với phường hoặc khu phố."},"2191":{"word":"hình tròn","meaning":"Một hình dạng đường cong khép kín, không có góc và tất cả các điểm trên đường cong đều cách đều tâm."},"2192":{"word":"tròn","meaning":"Miêu tả một vật có hình dạng như hình tròn hoặc hình cầu, có đường cong đều khắp."},"2193":{"word":"đồng nghiệp","meaning":"Người cùng làm việc trong một cơ quan, tổ chức hoặc cùng nghề nghiệp với mình."},"2194":{"word":"phía đông, miền đông","meaning":"Phần hoặc khu vực của một địa điểm nằm ở hướng mặt trời mọc vào buổi sáng."},"2195":{"word":"Câu lạc bộ","meaning":"Một nhóm người có cùng sở thích hoặc mục đích."},"2196":{"word":"Phương Đông","meaning":"Từ dùng để chỉ các quốc gia và nền văn hóa ở phía đông châu Á, như Trung Quốc, Nhật Bản và Hàn Quốc."},"2197":{"word":"Động tác","meaning":"Cách một cơ thể hoặc vật thể thay đổi vị trí hoặc thực hiện một hoạt động cụ thể."},"2198":{"word":"Cựu học sinh","meaning":"Những người đã học cùng một trường."},"2199":{"word":"Hội cựu học sinh","meaning":"Một buổi tụ họp của những người đã tốt nghiệp cùng một trường."},"2200":{"word":"Câu lạc bộ sở thích","meaning":"Một nhóm người cùng chung sở thích và tập hợp lại với nhau."},"2201":{"word":"Quay về","meaning":"Đến lại một nơi mà mình đã rời đi trước đó."},"2202":{"word":"Lấy lại","meaning":"Lấy lại thứ đã mất hoặc khôi phục lại trạng thái ban đầu."},"2203":{"word":"Độ dày","meaning":"Kích thước đo khoảng cách giữa hai bề mặt đối diện của một vật thể."},"2204":{"word":"Thuốc đau đầu","meaning":"Thuốc viên hoặc dạng lỏng dùng để giảm đau đầu."},"2205":{"word":"Tròn","meaning":"Miêu tả một vật thể có đường cong mềm mại ở tất cả các mặt, không có góc nhọn hay cạnh thẳng."},"2206":{"word":"Khô ráo","meaning":"Trạng thái mà một vật không còn chứa chất lỏng, đặc biệt là nước, và không cảm thấy ẩm ướt."},"2207":{"word":"chuyến đi dạo bằng ô tô","meaning":"Một chuyến đi chơi bằng ô tô nhằm thư giãn, ngắm cảnh."},"2208":{"word":"máy sấy tóc","meaning":"Thiết bị dùng động cơ thổi khí nóng để làm khô tóc ướt."},"2209":{"word":"váy đầm","meaning":"Trang phục liền thân, thường dành cho phụ nữ, che phủ từ vai đến chân."},"2210":{"word":"nghe","meaning":"Hoạt động sử dụng tai để nhận biết âm thanh hoặc hiểu lời nói."},"2211":{"word":"cho nghe","meaning":"Trình bày một điều gì đó (như câu chuyện, bài hát) để người khác có thể nghe hoặc cảm nhận."},"2212":{"word":"bước vào","meaning":"Di chuyển từ bên ngoài vào một không gian khép kín, như một tòa nhà."},"2213":{"word":"đáp ứng","meaning":"Lắng nghe và thực hiện mong muốn hoặc lời thỉnh cầu của người khác."},"2214":{"word":"thứ bậc","meaning":"Vị trí cụ thể trong một danh sách có thứ tự, hoặc một loại mà các mục thuộc về."},"2215":{"word":"vân vân","meaning":"Dùng ở cuối danh sách để chỉ rằng còn có những mục tương tự khác chưa được kể tên."},"2216":{"word":"đăng ký","meaning":"Việc chính thức ghi tên hoặc thông tin của mình vào danh sách cho một sự kiện, khóa học, hoặc dịch vụ."},"2217":{"word":"học phí","meaning":"Số tiền phải trả khi đăng ký một khóa học, trường học hoặc chương trình chính thức nào đó."},"2218":{"word":"giấy đăng ký","meaning":"Một tài liệu hoặc mảnh giấy chính thức xác nhận việc một người hoặc vật đã được đăng ký."},"2219":{"word":"quần áo leo núi","meaning":"Đây là loại quần áo chuyên dụng dành cho người đi leo núi, được thiết kế để mang lại sự thoải mái và bảo vệ."},"2220":{"word":"kỹ thuật số","meaning":"Đây là công nghệ biến đổi các hiện tượng như thời gian, âm thanh thành dạng số để xử lý và hiển thị."},"2221":{"word":"hái / ngắt","meaning":"Hành động dùng tay lấy trái cây, hoa hoặc vật gì đó ra khỏi cây hoặc nơi nó gắn liền."},"2222":{"word":"đi theo / theo sau","meaning":"Di chuyển hoặc đi bộ phía sau một người hoặc vật khác, đi cùng hướng."},"2223":{"word":"do đó / vì vậy","meaning":"Từ dùng để giới thiệu một câu nói diễn đạt kết quả hợp lý từ những gì đã được nói hoặc làm trước đó."},"2224":{"word":"đi theo / theo đến","meaning":"Di chuyển cùng với một người hoặc vật khác, đến cùng một địa điểm cùng lúc hoặc sau đó."},"2225":{"word":"riêng rẽ / riêng biệt","meaning":"Diễn tả các vật hoặc người không kết hợp hoặc nhóm lại với nhau, mà tồn tại hoặc di chuyển như những đơn vị riêng lẻ."},"2226":{"word":"theo / tuân theo","meaning":"Di chuyển hoặc đi sau một người hoặc vật gì đó, đi cùng hướng hoặc đến cùng một địa điểm."},"2227":{"word":"reng reng / ting ting","meaning":"Từ mô phỏng tiếng chuông của xe đạp, chuông cửa, điện thoại, báo thức, v.v., khi chúng kêu."},"2228":{"word":"vừa vặn / chính xác","meaning":"Diễn tả một điều gì đó vừa khít hoặc phù hợp mà không có bất kỳ sai lệch nào, hoàn toàn đúng hoặc chuẩn xác."},"2229":{"word":"cứng","meaning":"Chỉ vật liệu hoặc vật thể không dễ bị uốn cong hoặc thay đổi hình dạng khi có lực tác dụng."},"2230":{"word":"dưới đất / lòng đất","meaning":"Khu vực nằm bên dưới bề mặt nhìn thấy của trái đất."},"2231":{"word":"thỉnh thoảng","meaning":"Diễn tả một hành động hoặc sự việc xảy ra không thường xuyên mà chỉ vào một vài thời điểm nhất định."},"2232":{"word":"rời đi","meaning":"Di chuyển khỏi một nơi hoặc một người nào đó, làm cho khoảng cách giữa họ tăng lên."},"2233":{"word":"nổi lên","meaning":"Giữ ở trạng thái lơ lửng trong chất lỏng hoặc khí mà không chìm, thường di chuyển nhẹ nhàng trên bề mặt hoặc trong không khí."},"2234":{"word":"nhớ lại","meaning":"Mang một hình ảnh, ký ức hoặc suy nghĩ từ quá khứ trở lại trong tâm trí."},"2235":{"word":"run rẩy","meaning":"Rung lắc liên tục và nhanh trong một phạm vi nhỏ, thường do sợ hãi hoặc lạnh."},"2236":{"word":"run","meaning":"Di chuyển nhỏ, nhanh và không chủ ý, thường do sợ hãi, lạnh hoặc phấn khích."},"2237":{"word":"đánh rơi","meaning":"Thả vật đang cầm, khiến nó rơi xuống dưới do trọng lực lên một bề mặt thấp hơn."},"2238":{"word":"cũng","meaning":"Dùng để giới thiệu một yếu tố hoặc ý tưởng bổ sung, tương tự hoặc liên quan đến điều đã được đề cập trước đó."},"2239":{"word":"rõ ràng","meaning":"Nhận thức một điều gì đó một cách rành mạch và dễ hiểu, không có sự mơ hồ hay lẫn lộn."},"2240":{"word":"đục","meaning":"Tạo một lỗ hoặc lối đi xuyên qua một bề mặt hoặc vật thể rắn."},"2241":{"word":"chạy","meaning":"Di chuyển với tốc độ nhanh bằng cách bước nhanh liên tục, sao cho cả hai chân đều rời khỏi mặt đất trong thời gian ngắn."},"2242":{"word":"xuất sắc","meaning":"Sở hữu những phẩm chất hoặc khả năng tốt hơn hẳn so với đa số những thứ hoặc người khác."},"2243":{"word":"nhảy xuống","meaning":"Di chuyển cơ thể từ một nơi cao xuống thấp bằng cách nhảy."},"2244":{"word":"nhảy qua","meaning":"Nhảy lên để vượt qua một chướng ngại vật hoặc một khoảng cách."},"2245":{"word":"nổi, bay lên","meaning":"Ở trên bề mặt nước mà không chìm, hoặc nhẹ nhàng bay lên không trung."},"2246":{"word":"con giáp","meaning":"Biểu tượng động vật như rồng hay hổ đại diện cho năm sinh của một người trong văn hóa Á Đông."},"2247":{"word":"chanh vàng","meaning":"Một loại quả nhỏ, hình bầu dục, màu vàng tươi, vỏ dày và nước rất chua, thường dùng trong đồ uống hoặc thức ăn."},"2248":{"word":"xe cho thuê","meaning":"Dịch vụ mà bạn trả tiền để tạm thời sử dụng một chiếc xe hơi trong một thời gian ngắn."},"2249":{"word":"đăng nhập","meaning":"Hành động nhập ID cá nhân và mật mã để truy cập hệ thống máy tính hoặc tài khoản trực tuyến."},"2250":{"word":"rô-bốt","meaning":"Một cỗ máy có khả năng di chuyển và thực hiện công việc tự động, đôi khi được chế tạo trông giống con người hoặc động vật."},"2251":{"word":"-tỉ lệ","meaning":"Hậu tố biểu thị tần suất xảy ra hoặc số lượng của một điều gì đó so với tổng số."},"2252":{"word":"nhịp điệu","meaning":"Một chuỗi âm thanh hoặc chuyển động đều đặn, lặp đi lặp lại, như nhịp của âm nhạc hay bước nhảy."},"2253":{"word":"ruy băng","meaning":"Một dải vải dài, hẹp, thường làm bằng lụa hoặc satin, dùng để buộc nơ trên quà tặng hoặc trong tóc."},"2254":{"word":"tỏi","meaning":"Một loại rau củ có nhiều tép tròn kết thành vòng tròn, có mùi đặc trưng và được dùng rộng rãi để nêm nếm hoặc làm món ăn kèm."},"2255":{"word":"ma-ra-tông","meaning":"Một cuộc thi chạy đường dài, thường khoảng 42 kilômét, trên đường công cộng."},"2256":{"word":"xoa bóp","meaning":"Hành động dùng tay xoa, bóp, ấn vào cơ thể để thư giãn hoặc giảm căng cơ."},"2257":{"word":"chuột máy tính","meaning":"Một thiết bị cầm tay nhỏ dùng để điều khiển con trỏ và tương tác với màn hình máy tính."},"2258":{"word":"tùy ý","meaning":"Theo cách mà người nào đó có thể làm chính xác điều mình muốn, không bị giới hạn."},"2259":{"word":"tấm lòng","meaning":"Tính cách bên trong của một người được thể hiện qua hành động tử tế và quan tâm đến người khác."},"2260":{"word":"micrô","meaning":"Thiết bị điện tử dùng để thu âm thanh và khuếch đại hoặc ghi lại chúng."},"2261":{"word":"đúng lúc","meaning":"Một sự việc xảy ra vào đúng thời điểm tiện lợi hoặc thích hợp, thường là ngẫu nhiên."},"2262":{"word":"vừa mới","meaning":"Diễn tả một hành động xảy ra ngay lập tức, cách đây rất ít thời gian."},"2263":{"word":"một cách bừa bãi","meaning":"Diễn tả hành động làm việc gì đó một cách cẩu thả, thô bạo hoặc không có kế hoạch."},"2264":{"word":"con út","meaning":"Người được sinh ra cuối cùng trong một gia đình hoặc một nhóm."},"2265":{"word":"chặn","meaning":"Đặt vật gì đó hoặc một phần cơ thể vào một lối đi hoặc lỗ hở, ngăn không cho cái gì đi qua."},"2266":{"word":"cái gậy","meaning":"Một mảnh gỗ, nhựa hoặc kim loại dài, mỏng, thường dùng để hỗ trợ, đánh hoặc khuấy."},"2267":{"word":"chuyến cuối","meaning":"Đây là chuyến xe buýt, xe lửa hoặc tàu điện ngầm cuối cùng trong ngày trước khi ngừng hoạt động."},"2268":{"word":"đủ, trọn","meaning":"Diễn tả một khoảng thời gian hoặc số lượng đã được hoàn thành hoặc lấp đầy mà không thiếu bất kỳ phần nào."},"2269":{"word":"cuộc gặp gỡ, sự gặp mặt","meaning":"Là dịp hai hay nhiều người cùng đến một nơi để gặp gỡ, nói chuyện hoặc dành thời gian bên nhau."},"2270":{"word":"sự hài lòng","meaning":"Cảm giác dễ chịu khi mong muốn hoặc nhu cầu của một người đã được đáp ứng đầy đủ, tạo ra sự bình yên."},"2271":{"word":"hài lòng, thỏa đáng","meaning":"Diễn tả một điều gì đó đủ tốt để đáp ứng nhu cầu hoặc mong đợi của ai đó, gây ra cảm giác dễ chịu và bình yên."},"2272":{"word":"tăng lên, trở nên nhiều hơn","meaning":"Khi số lượng hoặc lượng của một cái gì đó ngày càng lớn hơn và phong phú hơn."},"2273":{"word":"cuộn, cuốn","meaning":"Hành động cuộn một vật mỏng và rộng để một đầu cuộn vào phần còn lại."},"2274":{"word":"phơi khô, làm khô","meaning":"Loại bỏ hơi ẩm ra khỏi một vật để vật đó trở nên khô ráo."},"2275":{"word":"nói, kỹ năng nói","meaning":"Hành động sử dụng giọng nói để tạo thành từ và âm thanh, chia sẻ suy nghĩ hoặc thông tin với người khác."},"2276":{"word":"đón tiếp, chào đón","meaning":"Gặp gỡ người vừa đến và thể hiện sự chấp nhận lịch sự đối với sự hiện diện của họ."},"2277":{"word":"bị đánh, bị đòn","meaning":"Bị tác động lực gây đau đớn từ bên ngoài hoặc phải chịu hình phạt về thể xác."},"2278":{"word":"đối diện, phía đối diện","meaning":"Vị trí trực tiếp ở phía trước và đối mặt với một thứ khác, có khoảng trống giữa chúng."},"2279":{"word":"chào đón","meaning":"Đón nhận hoặc chào mừng sự xuất hiện của ai đó hay một sự kiện nào đó."},"2280":{"word":"giao phó","meaning":"Giao một vật gì đó hoặc một công việc nào đó cho người khác để họ chịu trách nhiệm lo liệu."},"2281":{"word":"đảm nhận","meaning":"Chấp nhận và bắt đầu thực hiện một nhiệm vụ hoặc một trách nhiệm nào đó."},"2282":{"word":"ngửi","meaning":"Sử dụng mũi để phát hiện và nhận biết mùi của một vật gì đó."},"2283":{"word":"trận đòn","meaning":"Sự đánh đập hoặc hình phạt bằng roi vọt."},"2284":{"word":"treo","meaning":"Gắn một vật từ một điểm cao để phần dưới của nó được treo lơ lửng tự do."},"2285":{"word":"vị cay","meaning":"Cảm giác nóng bỏng trong miệng khi ăn một số loại thức ăn, thường do ớt gây ra."},"2286":{"word":"maeuntang","meaning":"Một món canh nóng của Hàn Quốc với nước dùng chứa hải sản, rau và tương ớt hoặc bột ớt."},"2287":{"word":"cửa hàng","meaning":"Một tòa nhà hoặc một phần của tòa nhà nơi các mặt hàng được bày bán cho mọi người mua."},"2288":{"word":"căng tin","meaning":"Một cửa hàng nhỏ hoặc quầy hàng bán đồ trong các cơ sở hoặc tổ chức."},"2289":{"word":"hết vé","meaning":"Tình trạng tất cả các mặt hàng hoặc vé có sẵn cho một sự kiện đã được mua hết và không còn gì."},"2290":{"word":"chân trần","meaning":"Bàn chân không đi tất hoặc giày dép."},"2291":{"word":"bụi","meaning":"Các hạt đất khô hoặc vật chất nhỏ li ti bay lơ lửng trong không khí hoặc đọng trên bề mặt."},"2292":{"word":"say xe","meaning":"Tình trạng chóng mặt và buồn nôn do chuyển động khi đi xe, tàu, máy bay, v.v."},"2293":{"word":"tuyệt vời","meaning":"Rất đẹp, ấn tượng hoặc hấp dẫn đến mức gây ra sự ngưỡng mộ sâu sắc."},"2294":{"word":"vết bầm","meaning":"Dấu hiệu sẫm màu hoặc có màu trên da xuất hiện sau khi va chạm, cho thấy mạch máu dưới da bị vỡ."},"2295":{"word":"thực đơn","meaning":"Một tấm bảng ghi các món ăn và giá cả mà nhà hàng cung cấp."},"2296":{"word":"giấy ghi chú","meaning":"Một tập giấy nhỏ trắng dùng để viết những tin nhắn hoặc lời nhắc ngắn gọn."},"2297":{"word":"giai điệu","meaning":"Một chuỗi âm thanh âm nhạc được sắp xếp theo một trật tự nhất định tạo ra một trình tự dễ nhận biết và thường xuyên dễ chịu."},"2298":{"word":"bề mặt","meaning":"Phần bên ngoài phẳng hoặc phần lộ ra của một vật thể, như tường hoặc bàn."},"2299":{"word":"diện tích","meaning":"Tổng không gian phẳng mà một bề mặt hoặc hình dạng chiếm giữ."},"2300":{"word":"phỏng vấn","meaning":"Cuộc gặp chính thức giữa hai người, một người hỏi và một người trả lời, thường để xin việc hoặc nhập học."},"2301":{"word":"giấy phép","meaning":"Một tài liệu hoặc thẻ chính thức cấp quyền cho ai đó làm một việc gì đó, như lái xe hoặc hành nghề."},"2302":{"word":"cá cơm","meaning":"Một loại cá biển lưng xanh đen, bụng trắng bạc, chủ yếu được ăn khô hoặc ướp muối."},"2303":{"word":"danh sách","meaning":"Một bảng hoặc tài liệu ghi lại tên của những người liên quan đến một vấn đề nào đó."},"2304":{"word":"danh thiếp","meaning":"Một mảnh giấy nhỏ in tên, nghề nghiệp, địa chỉ, số liên lạc, v.v., của một người để giới thiệu bản thân."},"2305":{"word":"một vài","meaning":"Một số lượng không xác định, nhỏ."},"2306":{"word":"màn hình","meaning":"Thiết bị điện tử có màn hình hiển thị hình ảnh và văn bản, thường được kết nối với máy tính."},"2307":{"word":"mẫu","meaning":"Một thiết kế hoặc loại sản phẩm cụ thể được sản xuất, như ô tô hoặc điện thoại."},"2308":{"word":"cát","meaning":"Những hạt đá nhỏ, rời rạc, thường được tìm thấy với số lượng lớn trên bãi biển hoặc sa mạc."},"2309":{"word":"gương mẫu","meaning":"Một người hoặc vật rất tốt hoặc đúng đắn đến mức người khác nên noi theo."},"2310":{"word":"mũ","meaning":"Một loại trang phục đội trên đầu, thường để giữ ấm, chống nắng hoặc làm đẹp."},"2311":{"word":"tuyển mộ","meaning":"Hành động tìm kiếm và mời người tham gia một tổ chức, một nhóm hoặc để lấp đầy một vị trí."},"2312":{"word":"thứ Năm","meaning":"Ngày trong tuần đứng sau thứ Tư và trước thứ Sáu."},"2313":{"word":"danh mục","meaning":"Một chuỗi tên, tiêu đề, v.v., được viết theo một thứ tự nhất định."},"2314":{"word":"điểm đến","meaning":"Nơi cuối cùng mà một người đang đi hoặc cố gắng đến."},"2315":{"word":"mục tiêu","meaning":"Điều mình muốn đạt được hoặc hướng tới để hoàn thành một mục đích nào đó."},"2316":{"word":"lén lút, bí mật","meaning":"Một cách kín đáo, không để người khác biết hoặc nhận ra."},"2317":{"word":"cân nặng, trọng lượng cơ thể","meaning":"Số đo về độ nặng của cơ thể người, thường được đo bằng cân."},"2318":{"word":"mệt mỏi rã rời, đau nhức cơ thể","meaning":"Tình trạng cơ thể mệt mỏi, đau nhức toàn thân do làm việc quá sức hoặc vận động nhiều."},"2319":{"word":"cử chỉ, điệu bộ","meaning":"Hành động di chuyển tay, đầu hoặc các bộ phận khác của cơ thể để thể hiện cảm xúc hoặc truyền đạt thông tin."},"2320":{"word":"miêu tả, mô tả","meaning":"Việc dùng lời nói để kể lại một cách chi tiết về hình dáng, âm thanh, mùi vị hay cảm giác của một sự vật, sự việc nào đó."},"2321":{"word":"hoa văn, họa tiết","meaning":"Hình dạng xuất hiện trên bề mặt của một vật thể."},"2322":{"word":"sân khấu","meaning":"Nơi biểu diễn được nâng cao lên một chút so với chỗ ngồi của khán giả, dùng cho các buổi trình diễn như kịch, múa, hòa nhạc."},"2323":{"word":"nắng nóng gay gắt, cái nóng như thiêu đốt","meaning":"Thời tiết rất nóng nực và khó chịu trong mùa hè, khiến cơ thể dễ đổ mồ hôi."},"2324":{"word":"mộ, nấm mồ","meaning":"Nơi chôn cất thi hài hoặc xương cốt của người đã khuất dưới lòng đất."},"2325":{"word":"sợ hãi, e sợ","meaning":"Cảm thấy một sự lo lắng, bất an mạnh mẽ khi có điều gì đó nguy hiểm hoặc khó chịu ở gần, khiến bạn muốn tránh né."},"2326":{"word":"thương mại, mậu dịch","meaning":"Hoạt động kinh doanh mua bán hàng hóa giữa các khu vực hoặc các quốc gia khác nhau."},"2327":{"word":"múa","meaning":"Múa là một hình thức nghệ thuật biểu diễn mà con người di chuyển cơ thể theo nhịp điệu và âm nhạc."},"2328":{"word":"vô điều kiện","meaning":"Diễn ra hoặc thực hiện một điều gì đó mà không có bất kỳ yêu cầu hay giới hạn nào."},"2329":{"word":"lưu trú","meaning":"Dành thời gian ban đêm hoặc vài đêm tại một nơi ở tạm thời như khách sạn, nhà nghỉ."},"2330":{"word":"buộc","meaning":"Dùng dây hoặc vật tương tự để cố định một vật, hoặc tập hợp nhiều vật lại thành một khối."},"2331":{"word":"cửa hàng văn phòng phẩm","meaning":"Cửa hàng bán các vật dụng dùng để viết, học tập như bút, giấy, vở."},"2332":{"word":"cửa hàng văn phòng phẩm","meaning":"Nơi kinh doanh, bán các vật dụng như giấy, bút, vở và các đồ dùng khác để viết hoặc học tập."},"2333":{"word":"ngữ pháp","meaning":"Hệ thống các quy tắc về cách sắp xếp và kết hợp từ ngữ để tạo thành câu có ý nghĩa trong một ngôn ngữ."},"2334":{"word":"thăm bệnh","meaning":"Hành động đến thăm một người đang bị ốm, thường là ở nhà hoặc bệnh viện, để an ủi và động viên."},"2335":{"word":"yêu cầu thông tin","meaning":"Một yêu cầu thông tin, thường dưới dạng câu hỏi, để tìm hiểu thêm về một chủ đề hoặc tình huống cụ thể."},"2336":{"word":"tin nhắn","meaning":"Một tin nhắn ngắn được gửi qua điện thoại di động."},"2337":{"word":"câu","meaning":"Một đơn vị ngôn ngữ hoàn chỉnh, diễn đạt một ý tưởng trọn vẹn, thường bắt đầu bằng chữ hoa và kết thúc bằng dấu câu."},"2338":{"word":"văn học","meaning":"Các tác phẩm sáng tạo bằng văn bản như truyện, kịch, thơ, thể hiện ý tưởng và cảm xúc, thường được coi là một hình thức nghệ thuật."},"2339":{"word":"Di sản văn hóa","meaning":"Những vật phẩm, công trình kiến trúc hoặc địa điểm có giá trị lịch sử và văn hóa từ quá khứ."},"2340":{"word":"Dính, bám, vấy","meaning":"Bị một chất lỏng hoặc vật thể nhỏ khác dính hoặc bám vào bề mặt."},"2341":{"word":"-phẩm, -vật","meaning":"Tiếp vĩ ngữ dùng để chỉ sản phẩm được làm ra hoặc trồng trọt để bán hoặc sử dụng."},"2342":{"word":"Bờ nước, ven sông/hồ/biển","meaning":"Phần đất nằm sát mép sông, hồ hoặc biển."},"2343":{"word":"Giá cả","meaning":"Mức chi phí cần thiết để mua hàng hóa và dịch vụ nói chung trên thị trường."},"2344":{"word":"Cắn","meaning":"Dùng răng kẹp chặt hoặc cắt đứt một vật gì đó."},"2345":{"word":"Lùi lại, rút lui","meaning":"Di chuyển ra phía sau hoặc rời khỏi một vị trí, tình huống nào đó."},"2346":{"word":"Lùi bước, lùi lại","meaning":"Dịch chuyển cơ thể hoặc bước chân về phía sau để tạo khoảng trống hoặc tránh né."},"2347":{"word":"Bị cắn, bị chích","meaning":"Bị răng của động vật hoặc vòi của côn trùng xuyên vào da gây ra đau nhói."},"2348":{"word":"Tiếng nước","meaning":"Âm thanh do dòng nước chảy, mưa rơi hoặc sóng vỗ tạo ra."},"2349":{"word":"Thuốc nước","meaning":"Thuốc ở dạng lỏng, có thể uống được để chữa bệnh."},"2350":{"word":"Câu hỏi, vấn đề","meaning":"Lời nói hoặc câu viết nhằm mục đích tìm kiếm thông tin hoặc làm rõ điều gì đó."},"2351":{"word":"nhạc kịch","meaning":"Một loại hình sân khấu trình diễn câu chuyện thông qua ca hát, thoại, diễn xuất và nhảy múa."},"2352":{"word":"người Mỹ","meaning":"Người sinh ra hoặc sống ở Hợp chúng quốc Hoa Kỳ."},"2353":{"word":"trơn trượt","meaning":"Bề mặt quá nhẵn hoặc ẩm ướt khiến mọi vật dễ trượt, khó đứng vững hoặc đi lại mà không mất thăng bằng."},"2354":{"word":"trì hoãn","meaning":"Dời một nhiệm vụ được giao hoặc một sự kiện đã lên kế hoạch đến một thời điểm hoặc ngày sau đó."},"2355":{"word":"dưới","meaning":"Thuật ngữ này mô tả một số lượng hoặc độ tuổi nhỏ hơn một con số đã nêu, không bao gồm chính con số đó."},"2356":{"word":"vị thành niên","meaning":"Người chưa đạt đến độ tuổi trưởng thành theo pháp luật."},"2357":{"word":"nụ cười","meaning":"Một biểu cảm khuôn mặt mà khóe miệng hướng lên, thường thể hiện sự vui vẻ hoặc thân thiện."},"2358":{"word":"mỹ thuật","meaning":"Sự sáng tạo các đối tượng đẹp hoặc có ý nghĩa như tranh vẽ, tác phẩm điêu khắc và bản vẽ."},"2359":{"word":"thợ làm tóc","meaning":"Người có công việc là cắt và tạo kiểu tóc cho mọi người tại tiệm hoặc cửa hàng."},"2360":{"word":"mỹ nhân","meaning":"Một người phụ nữ được coi là rất dễ nhìn."},"2361":{"word":"tiệm làm tóc","meaning":"Nơi mọi người đến để cắt, tạo kiểu hoặc nhuộm tóc, và đôi khi để chăm sóc da mặt khác."},"2362":{"word":"hẹn hò giấu mặt","meaning":"Một cuộc gặp gỡ xã giao được sắp xếp giữa hai người chưa từng gặp nhau, thường với mục đích lãng mạn."},"2363":{"word":"Trò chơi dân gian","meaning":"Đây là một trò chơi hoặc hoạt động được truyền lại qua nhiều thế hệ trong một nền văn hóa cụ thể, thường được chơi vào các ngày lễ."},"2364":{"word":"Tắc nghẽn, kẹt (xe)","meaning":"Chỉ tình trạng bị giữ lại trong một hàng dài hoặc di chuyển rất chậm, như xe cộ trên đường đông đúc."},"2365":{"word":"Đáng ghét, đáng giận","meaning":"Cảm thấy giận dữ hoặc không chấp thuận ai đó hay điều gì đó vì hành động hoặc sự hiện diện của họ."},"2366":{"word":"Và, cũng như","meaning":"Từ dùng để nối hai vật, hành động hoặc ý tưởng khác nhau, cho thấy chúng có liên quan hoặc xảy ra cùng lúc."},"2367":{"word":"Gạch chân","meaning":"Một đường liên tục được vẽ trực tiếp bên dưới một từ hoặc cụm từ trong văn bản để nhấn mạnh hoặc chú ý đặc biệt."},"2368":{"word":"Điều, việc","meaning":"Từ dùng để chỉ sự thật, kết quả hoặc nội dung cụ thể của một hành động hay suy nghĩ vừa được trình bày."},"2369":{"word":"Cái giỏ, cái rổ","meaning":"Một vật chứa bên trong rỗng, được làm bằng cách đan tre, nhựa, v.v."},"2370":{"word":"Cái kim","meaning":"Một dụng cụ rất mỏng, nhọn có một lỗ nhỏ ở một đầu, dùng để xỏ chỉ qua vải để may."},"2371":{"word":"Nước biển","meaning":"Chất lỏng mặn có trong các đại dương và biển trên thế giới, thường di chuyển thành sóng."},"2372":{"word":"Cờ vây","meaning":"Một trò chơi mà hai người lần lượt đặt các quân cờ trắng và đen lên một bàn cờ hình vuông có các đường ngang và dọc để phân định thắng thua."},"2373":{"word":"Kẻ ngốc, người ngu ngốc","meaning":"Người hành động rất ngu ngốc hoặc nói những điều vô nghĩa, cho thấy sự thiếu khôn ngoan."},"2374":{"word":"Tảng đá, đá","meaning":"Một mảnh vật liệu khoáng chất lớn, cứng là một phần tự nhiên của bề mặt Trái đất hoặc núi non."},"2375":{"word":"bánh xe","meaning":"Một vật hình tròn quay quanh một trục trung tâm, giúp các phương tiện như ô tô hay xe đạp di chuyển."},"2376":{"word":"nền tảng","meaning":"Lớp dưới cùng hoặc bề mặt cơ bản mà trên đó một cái gì đó được xây dựng, vẽ hoặc đặt, thường ảnh hưởng đến diện mạo tổng thể của nó."},"2377":{"word":"đêm (đơn vị đếm)","meaning":"Đơn vị dùng để chỉ số đêm lưu trú hoặc ở lại một nơi nào đó."},"2378":{"word":"tiến sĩ","meaning":"Bằng cấp cao nhất do một trường đại học cấp, hoặc người đã nhận được bằng cấp này."},"2379":{"word":"trả lại","meaning":"Hành động trả lại một thứ đã mượn hoặc nhận."},"2380":{"word":"trăng bán nguyệt","meaning":"Hình dạng của mặt trăng nhìn thấy trên bầu trời đêm khi nó xuất hiện dưới dạng một hình bán nguyệt sáng, cong hoàn hảo."},"2381":{"word":"từ trái nghĩa","meaning":"Một từ biểu thị ý nghĩa hoàn toàn trái ngược hoặc ngược lại với một từ khác."},"2382":{"word":"phía đối diện","meaning":"Vị trí hoặc hướng trực tiếp đối diện hoặc hoàn toàn ngược lại với một điểm hoặc khu vực cụ thể khác."},"2383":{"word":"cách nói thân mật","meaning":"Một dạng giao tiếp sử dụng các biểu hiện rất không trang trọng và quen thuộc, thường được nói giữa bạn bè, gia đình hoặc những người cùng tuổi hoặc địa vị."},"2384":{"word":"mặt khác","meaning":"Cụm từ dùng để giới thiệu một ý tưởng tương phản hoặc đối lập, cho phép so sánh hai tình huống hoặc quan điểm khác nhau."},"2385":{"word":"lặp lại","meaning":"Hành động thực hiện cùng một công việc nhiều lần."},"2386":{"word":"bột nhào","meaning":"Một hỗn hợp đặc, mềm được tạo ra bằng cách kết hợp bột mì với nước hoặc các chất lỏng khác, sau đó được tạo hình và nấu để làm các món ăn như bánh mì hoặc mì."},"2387":{"word":"băng cá nhân","meaning":"Một loại băng dán nhỏ, có miếng đệm mềm ở giữa, dùng để che và bảo vệ vết thương nhỏ trên da."},"2388":{"word":"áo ngắn tay","meaning":"Loại quần áo có phần tay áo ngắn đến khuỷu tay hoặc trên khuỷu tay."},"2389":{"word":"phải lòng","meaning":"Bắt đầu có tình cảm sâu sắc và sự thu hút lãng mạn mạnh mẽ với ai đó một cách đột ngột."},"2390":{"word":"cấp phát","meaning":"Hành động chính thức cung cấp hoặc trao một thứ gì đó có tính chất trang trọng như thẻ, tài liệu hoặc chứng chỉ."},"2391":{"word":"phát triển","meaning":"Quá trình trở nên lớn hơn, tốt hơn về thể chất, cảm xúc, trí tuệ, v.v."},"2392":{"word":"phát minh","meaning":"Một thiết bị, quy trình hoặc ý tưởng mới do ai đó tạo ra và chưa từng tồn tại trước đó."},"2393":{"word":"mắt cá chân","meaning":"Khớp nối phần chân dưới của bạn với bàn chân."},"2394":{"word":"phát âm","meaning":"Cách mà một từ hoặc một ngôn ngữ được nói ra thành tiếng."},"2395":{"word":"phát triển","meaning":"Quá trình một thứ gì đó dần dần lớn mạnh, cải thiện hoặc trở nên tiên tiến hơn."},"2396":{"word":"công bố","meaning":"Một tuyên bố chính thức cung cấp thông tin cho công chúng hoặc một bài nói chuyện trang trọng trước khán giả về một chủ đề."},"2397":{"word":"phát hành","meaning":"Hành động sản xuất sách, báo, tạp chí để bán hoặc phân phối, hoặc chính thức cấp phát tài liệu, chứng chỉ."},"2398":{"word":"thắp sáng","meaning":"Làm cho một nơi tối trở nên sáng sủa bằng đèn, đuốc hoặc nguồn sáng khác."},"2399":{"word":"đạp","meaning":"Đặt chân xuống hoặc lên một vật gì đó."},"2400":{"word":"hạt dẻ","meaning":"Một loại hạt tròn, vỏ màu nâu bóng, có thể ăn được, mọc trong vỏ gai trên cây."},"2401":{"word":"khuya","meaning":"Mô tả một thời điểm hoặc hoạt động diễn ra rất lâu sau khi mặt trời lặn và hầu hết mọi người đang nghỉ ngơi."},"2402":{"word":"suốt đêm","meaning":"Khoảng thời gian từ tối đến sáng khi mặt trời mọc."},"2403":{"word":"màu hạt dẻ","meaning":"Màu giống như vỏ của hạt dẻ đã chín."},"2404":{"word":"bát cơm","meaning":"Một cái bát nhỏ, tròn, thường làm bằng gốm, dùng để đựng và ăn cơm."},"2405":{"word":"nồi cơm điện","meaning":"Một thiết bị điện trong nhà bếp dùng để nấu cơm bằng cách đun nóng gạo với nước."},"2406":{"word":"công ty phát sóng","meaning":"Một tổ chức sản xuất và phát sóng các chương trình truyền hình hoặc radio đến đông đảo khán giả."},"2407":{"word":"cách thức","meaning":"Một quy trình, cách tiếp cận hoặc kiểu cách đặc trưng dùng để làm việc gì đó hoặc để sống."},"2408":{"word":"giọt","meaning":"Một lượng chất lỏng rất nhỏ, có hình tròn."},"2409":{"word":"sự cản trở","meaning":"Một hành động gây trở ngại hoặc làm gián đoạn ai đó hoặc điều gì đó tiếp diễn một cách bình thường."},"2410":{"word":"đói","meaning":"Cảm thấy cần hoặc mong muốn ăn thức ăn, thường có tiếng kêu trong bụng."},"2411":{"word":"bóng chuyền","meaning":"Một môn thể thao đồng đội, trong đó các cầu thủ dùng tay đánh một quả bóng lớn qua lưới cao để bóng rơi vào phần sân của đối phương."},"2412":{"word":"ba lô","meaning":"Một loại túi vải có hai dây đeo, dùng để đeo trên vai và lưng khi mang đồ đạc, thường dùng khi đi bộ đường dài hoặc đi học."},"2413":{"word":"du lịch ba lô","meaning":"Hình thức du lịch tự túc, chi phí thấp, chỉ mang theo một chiếc ba lô."},"2414":{"word":"tiễn","meaning":"Hành động đi cùng ai đó đến nơi họ khởi hành, như nhà ga hoặc sân bay, để nói lời tạm biệt khi họ rời đi."},"2415":{"word":"bố trí","meaning":"Hành động sắp xếp hoặc đặt người, vật phẩm vào một vị trí hoặc thứ tự nhất định."},"2416":{"word":"pin","meaning":"Một thiết bị nhỏ lưu trữ và cung cấp năng lượng điện cho các thiết bị như điện thoại, đèn pin hoặc điều khiển từ xa."},"2417":{"word":"đường biển","meaning":"Cách thức gửi hàng hóa hoặc thư từ bằng tàu thuyền qua đường biển."},"2418":{"word":"một trăm","meaning":"Số đếm bằng mười lần mười, được viết là 1-0-0."},"2419":{"word":"bụng","meaning":"Phần bên trong cơ thể nơi thức ăn đi vào sau khi ăn, nằm ở vùng ngực dưới."},"2420":{"word":"nấm","meaning":"Một loại thực vật mọc ở nơi ẩm ướt, râm mát hoặc trên cây mục, thường có hình dạng giống cây dù và được dùng làm nguyên liệu chế biến món ăn."},"2421":{"word":"bơ","meaning":"Một sản phẩm thực phẩm mềm, màu vàng, chứa chất béo, được làm từ sữa hoặc kem đánh đông, thường dùng để phết bánh mì hoặc nấu ăn."},"2422":{"word":"nút","meaning":"Một thiết bị trên thiết bị điện tử được vận hành bằng cách dùng ngón tay nhấn vào."},"2423":{"word":"tia chớp","meaning":"Ánh sáng lóe lên rất nhanh và sáng rực trên bầu trời khi có sấm chớp."},"2424":{"word":"sự dịch","meaning":"Việc chuyển đổi từ ngữ hoặc văn bản từ ngôn ngữ này sang ngôn ngữ khác mà vẫn giữ nguyên ý nghĩa gốc."},"2425":{"word":"số nhà","meaning":"Một số hoặc mã số cụ thể dùng để xác định vị trí của một tòa nhà hoặc mảnh đất trên đường phố hoặc bản đồ."},"2426":{"word":"phiếu số","meaning":"Một mảnh giấy có ghi số, thường dùng để xếp hàng hoặc đợi đến lượt."},"2427":{"word":"hình phạt","meaning":"Điều gì đó không dễ chịu mà một người phải chịu đựng vì đã làm điều sai trái hoặc vi phạm quy tắc."},"2428":{"word":"tiền phạt","meaning":"Một khoản tiền mà một người phải trả như một hình phạt vì đã vi phạm pháp luật hoặc quy tắc."},"2429":{"word":"tội phạm","meaning":"Một hành động bất hợp pháp hoặc chống lại luật pháp, có thể dẫn đến việc bị bắt giữ hoặc chịu hậu quả pháp lý."},"2430":{"word":"pháp luật","meaning":"Một hệ thống các quy tắc chính thức mà một quốc gia hoặc cộng đồng sử dụng để điều chỉnh hành động của các thành viên, mà mọi người phải tuân theo."},"2431":{"word":"quy luật","meaning":"Một nguyên tắc cố định mô tả cách mọi thứ trong thế giới luôn vận hành hoặc cách mọi người được mong đợi hành động."},"2432":{"word":"cởi","meaning":"Kéo quần áo hoặc vật che phủ ra khỏi người hoặc vật thể."},"2433":{"word":"ban công","meaning":"Một không gian nhô ra có mái che và không có tường, thường thấy ở các căn hộ hoặc nhà kiểu phương Tây."},"2434":{"word":"ghế dài","meaning":"Một loại ghế dài cho nhiều người ngồi, thường được đặt ở công viên hoặc nơi công cộng."},"2435":{"word":"chuông","meaning":"Một vật rỗng, thường làm bằng kim loại, phát ra âm thanh rõ ràng khi bị va đập hoặc rung lắc."},"2436":{"word":"thắt lưng","meaning":"Một dải vật liệu, thường là da hoặc vải, đeo quanh eo để giữ quần hoặc làm vật trang trí."},"2437":{"word":"đồng hồ treo tường","meaning":"Một dụng cụ dùng để xem giờ, được thiết kế để treo cao trên mặt phẳng của một căn phòng."},"2438":{"word":"giấy dán tường","meaning":"Tấm vật liệu trang trí được dán lên các mặt bên trong của căn phòng để che phủ chúng."},"2439":{"word":"sự thay đổi","meaning":"Hành động làm cho một điều gì đó khác đi so với trạng thái ban đầu của nó."},"2440":{"word":"táo bón","meaning":"Một tình trạng mà người bệnh gặp khó khăn trong việc đào thải chất thải ra khỏi cơ thể."},"2441":{"word":"sự thay đổi","meaning":"Một trường hợp đáng chú ý khi một cái gì đó trở nên khác biệt về trạng thái hoặc hình thức."},"2442":{"word":"theo, tùy theo","meaning":"Được dùng sau một danh từ để chỉ rằng các vật phẩm hoặc người được phân chia thành nhóm hoặc xử lý từng cái một dựa trên danh từ đó."},"2443":{"word":"đặc biệt, riêng","meaning":"Dùng để chỉ một điều gì đó khác thường, không phải là thông thường hay có ý nghĩa quan trọng."},"2444":{"word":"lời đặc biệt","meaning":"Lời nói đặc biệt hoặc đáng chú ý mà một người bày tỏ, thường dùng trong các cách diễn đạt phủ định mang ý khiêm tốn."},"2445":{"word":"biệt danh","meaning":"Một tên gọi không chính thức mà một người được gọi, khác với tên thật của họ."},"2446":{"word":"chuyện đặc biệt","meaning":"Một sự việc bất thường hoặc một sự kiện có thay đổi đáng chú ý."},"2447":{"word":"phòng bệnh","meaning":"Một căn phòng trong bệnh viện nơi người bệnh hoặc người bị thương ở lại để được chăm sóc và nghỉ ngơi."},"2448":{"word":"báo cáo","meaning":"Hành động trình bày hoặc cung cấp thông tin, kết quả hay cập nhật một cách chính thức cho ai đó."},"2449":{"word":"bản báo cáo","meaning":"Một tài liệu chính thức trình bày thông tin, kết quả nghiên cứu hoặc tình trạng hiện tại về một chủ đề cụ thể."},"2450":{"word":"bảo quản","meaning":"Hành động hoặc hệ thống giữ gìn đồ vật ở một nơi an toàn hoặc được chỉ định để sử dụng trong tương lai."},"2451":{"word":"ví dụ","meaning":"Một trường hợp hoặc phần cụ thể của cái gì đó được đưa ra để giúp giải thích, chứng minh hoặc đại diện cho một ý tưởng hay nhóm lớn hơn."},"2452":{"word":"tiền thưởng","meaning":"Một khoản tiền thưởng thêm, một món quà hoặc điều tốt lành được trao ngoài những gì được mong đợi hoặc thường nhận."},"2453":{"word":"sự bõ công","meaning":"Kết quả tốt đẹp hoặc cảm giác hài lòng mà một người nhận được sau khi làm một việc gì đó."},"2454":{"word":"ngày rằm","meaning":"Ngày cụ thể đánh dấu giữa tháng âm lịch, khi mặt trăng tròn đầy."},"2455":{"word":"trăng tròn","meaning":"Pha của mặt trăng khi nó xuất hiện dưới dạng một đĩa tròn, được chiếu sáng hoàn toàn trên bầu trời đêm."},"2456":{"word":"lúa mạch","meaning":"Một loại cây ngũ cốc có thân dài và hạt có râu, thường được trồng để làm thức ăn, bia hoặc thức ăn gia súc."},"2457":{"word":"đá quý","meaning":"Một loại đá quý, thường được cắt và đánh bóng, dùng để làm đồ trang sức như nhẫn, vòng cổ hoặc hoa tai vì vẻ đẹp và sự lấp lánh của nó."},"2458":{"word":"người đi bộ","meaning":"Người di chuyển bằng chân, đặc biệt là ở khu vực có phương tiện giao thông, như trên vỉa hè hoặc đường phố."},"2459":{"word":"bảo hiểm","meaning":"Một hệ thống mà người ta trả tiền định kỳ cho một công ty để được bồi thường khi xảy ra tai nạn, bệnh tật hoặc sự kiện không mong muốn."},"2460":{"word":"bảo vệ","meaning":"Hành động giữ cho ai đó hoặc vật gì đó an toàn khỏi bị tổn hại, hư hỏng hoặc nguy hiểm."},"2461":{"word":"phúc, may mắn","meaning":"Những điều tốt đẹp, kết quả thuận lợi hoặc sự kiện thành công xảy ra trong cuộc sống của một người, mang lại hạnh phúc hoặc lợi ích."},"2462":{"word":"hành lang","meaning":"Lối đi dài trong một tòa nhà, nơi có các cửa phòng mở ra."},"2463":{"word":"sao chép","meaning":"Hành động tạo ra một bản sao hoặc bản tái tạo y hệt của một tài liệu, hình ảnh hoặc âm thanh."},"2464":{"word":"máy photocopy","meaning":"Một thiết bị lớn dùng để tạo ra các bản sao giấy chính xác của tài liệu hoặc hình ảnh bằng cách quét chúng."},"2465":{"word":"quả đào","meaning":"Một loại trái cây mùa hè tròn, có màu hồng hoặc trắng, vị ngọt và có một hạt lớn ở giữa."},"2466":{"word":"việc dùng thuốc","meaning":"Hành động nuốt viên thuốc hoặc chất lỏng vào cơ thể để điều trị bệnh."},"2467":{"word":"đau bụng","meaning":"Cảm giác khó chịu hoặc đau nhức ở bên trong bụng."},"2468":{"word":"bản thân, người liên quan","meaning":"Cá nhân cụ thể đang được đề cập hoặc thảo luận trong một tình huống."},"2469":{"word":"điểm tham quan, cảnh đẹp","meaning":"Những đặc điểm, sự kiện hoặc đối tượng tại một địa điểm mà mọi người thấy hấp dẫn và thú vị khi quan sát."},"2470":{"word":"bowling","meaning":"Một trò chơi được chơi bằng cách lăn một quả bóng nặng dọc theo một làn đường hẹp để hạ gục một nhóm mười vật thể cao, mỏng gọi là pin."},"2471":{"word":"công chuyện","meaning":"Một việc nhỏ cần phải làm, thường là phải đi đâu đó để giải quyết."},"2472":{"word":"phục vụ, tình nguyện","meaning":"Hành động tự nguyện dành thời gian và sức lực để giúp đỡ người khác hoặc cộng đồng mà không mong đợi được trả công."},"2473":{"word":"túi, bao","meaning":"Vật đựng làm bằng giấy hoặc nhựa dùng để chứa đồ vật."},"2474":{"word":"gặp (kính ngữ)","meaning":"Đến gặp và trò chuyện với người lớn tuổi hoặc người có địa vị cao hơn một cách kính trọng."},"2475":{"word":"phòng, bộ phận","meaning":"Một đơn vị nhỏ được chia ra trong một tổ chức theo chức năng hoặc nhiệm vụ."},"2476":{"word":"gánh nặng, áp lực","meaning":"Cảm giác nặng nề về tinh thần hoặc cảm xúc do một nhiệm vụ khó khăn, yêu cầu quá nhiều hoặc một nghĩa vụ gây ra."},"2477":{"word":"bất động sản","meaning":"Đất đai và những công trình xây dựng kiên cố trên đó, có thể sở hữu, mua bán."},"2478":{"word":"ghen tị, ngưỡng mộ","meaning":"Cảm thấy không vui khi người khác có điều tốt mà mình cũng mong muốn có được."},"2479":{"word":"gãy","meaning":"Một vật cứng, rắn như xương hoặc que gỗ bị nứt và tách ra thành hai hoặc nhiều mảnh."},"2480":{"word":"thể hiện, phô trương","meaning":"Cố ý bộc lộ một phẩm chất, kỹ năng hoặc hành vi cụ thể, thường để thu hút sự chú ý hoặc tạo ấn tượng."},"2481":{"word":"bố mẹ, cha mẹ","meaning":"Hai người lớn chính, thường là một nam và một nữ, đã nuôi dưỡng một đứa trẻ."},"2482":{"word":"phu nhân, bà","meaning":"Một người phụ nữ trưởng thành đã kết hôn hợp pháp với một người đàn ông."},"2483":{"word":"cha con","meaning":"Mối quan hệ giữa một người cha và con của mình."},"2484":{"word":"nhà giàu","meaning":"Gia đình có rất nhiều tài sản và của cải."},"2485":{"word":"cái quạt","meaning":"Một dụng cụ dùng để tạo gió làm mát."},"2486":{"word":"bốt","meaning":"Loại giày cao cổ che phủ bàn chân và một phần cẳng chân."},"2487":{"word":"thân phụ","meaning":"Cách gọi trang trọng để chỉ người cha."},"2488":{"word":"phía bắc","meaning":"Một trong bốn hướng chính, đối diện với hướng nam."},"2489":{"word":"miền Bắc","meaning":"Phần phía trên của một quốc gia hoặc khu vực."},"2490":{"word":"chia cắt","meaning":"Sự chia tách đất nước và con người thành các phần riêng biệt."},"2491":{"word":"tách rời","meaning":"Hành động làm cho hai hoặc nhiều vật thể hoặc bộ phận di chuyển ra xa nhau."},"2492":{"word":"rõ ràng","meaning":"Một cách dễ dàng nhận thấy hoặc hiểu được, không có sự không chắc chắn."},"2493":{"word":"sự thất lạc","meaning":"Tình trạng một vật phẩm biến mất khỏi sự sở hữu của ai đó và không thể tìm thấy."},"2494":{"word":"đồ thất lạc","meaning":"Các vật phẩm mà ai đó đã đánh mất và được tìm thấy."},"2495":{"word":"phấn","meaning":"Vật liệu màu trắng hoặc có màu, hình que mềm, dùng để viết hoặc vẽ trên bảng."},"2496":{"word":"tiền tố phủ định \"bất-\"","meaning":"Một tiền tố thêm vào trước một từ để tạo nghĩa phủ định, tức là \"không\" hoặc \"thiếu\" chất lượng đó."},"2497":{"word":"sự bất quy tắc","meaning":"Tình trạng các hành động hoặc sự kiện không theo một lịch trình hoặc sắp xếp cố định."},"2498":{"word":"sự mất cân bằng","meaning":"Tình huống các bộ phận của một cái gì đó không bằng nhau về kích thước, số lượng hoặc tầm quan trọng."},"2499":{"word":"sự bất mãn","meaning":"Cảm giác không vui hoặc không hài lòng khi một tình huống hoặc điều gì đó không đáp ứng được mong đợi."},"2500":{"word":"sự không hài lòng","meaning":"Cảm giác không vui hoặc khó chịu vì một điều gì đó không đáp ứng được mong đợi, thường thể hiện qua vẻ mặt buồn bã."},"2501":{"word":"không hài lòng, không thỏa đáng","meaning":"Cảm thấy không vui hoặc khó chịu vì một điều gì đó không đạt yêu cầu hay mong đợi."},"2502":{"word":"tiếng Pháp","meaning":"Ngôn ngữ chủ yếu được nói, đọc và viết ở một quốc gia châu Âu và nhiều nơi khác trên thế giới."},"2503":{"word":"sự không hoàn chỉnh, sự không hoàn hảo","meaning":"Tình trạng một cái gì đó chưa hoàn thành, thiếu bộ phận hoặc có khuyết điểm."},"2504":{"word":"lời phàn nàn, sự than phiền","meaning":"Những lời nói hoặc chữ viết thể hiện sự không vui hoặc khó chịu của một người về điều gì đó."},"2505":{"word":"đông đúc, tấp nập","meaning":"Có rất nhiều người, xe cộ, v.v., tụ tập ở một nơi, gây ra tình trạng chen chúc."},"2506":{"word":"sưng, sưng lên","meaning":"Trở nên to hơn, tròn hơn hoặc phồng lên do tích tụ chất lỏng hoặc mô."},"2507":{"word":"rót","meaning":"Làm cho chất lỏng hoặc bột chảy từ vật chứa này sang vật chứa khác."},"2508":{"word":"tiệc tự chọn","meaning":"Kiểu bữa ăn mà nhiều món ăn được bày trên bàn dài, cho phép mọi người tự lấy lượng thức ăn mình muốn."},"2509":{"word":"phí","meaning":"Từ tố đứng sau một danh từ để chỉ số tiền cần phải chi trả cho một thứ gì đó hoặc một hoạt động."},"2510":{"word":"mật khẩu","meaning":"Một dãy số hoặc cụm từ bí mật mà một người tạo ra để bảo vệ tài khoản ngân hàng, máy tính, v.v."},"2511":{"word":"xoa","meaning":"Thực hiện hành động ma sát hai vật hoặc bộ phận cơ thể vào nhau."},"2512":{"word":"lối thoát hiểm","meaning":"Cửa thoát ra ngoài nhanh chóng khi có tai nạn bất ngờ xảy ra."},"2513":{"word":"chi phí","meaning":"Tổng số tiền mà một người phải chi để có được hoặc hoàn thành một việc gì đó."},"2514":{"word":"thị thực","meaning":"Dấu hoặc giấy tờ chính thức thường dán vào hộ chiếu, cho phép một người nhập cảnh hoặc ở lại một quốc gia khác trong một khoảng thời gian nhất định."},"2515":{"word":"tránh ra","meaning":"Di chuyển cơ thể sang một bên để người hoặc vật khác có thể đi qua hoặc nhìn rõ hơn."},"2516":{"word":"vitamin","meaning":"Một lượng nhỏ chất tự nhiên có trong thực phẩm hoặc được uống dưới dạng viên, cần thiết cho cơ thể để phát triển và khỏe mạnh."},"2517":{"word":"so sánh","meaning":"Kiểm tra hai hoặc nhiều vật phẩm hoặc người để xem chúng có những điểm chung hoặc khác biệt như thế nào."},"2518":{"word":"chuyến bay","meaning":"Sự di chuyển của một phương tiện hàng không, như máy bay, qua không trung từ nơi này đến nơi khác."},"2519":{"word":"sân bay","meaning":"Nơi có đầy đủ các tiện ích để máy bay có thể cất cánh, hạ cánh và đỗ."},"2520":{"word":"chỗ trống","meaning":"Vị trí trên ghế, băng ghế hoặc phương tiện mà một người có thể ngồi nhưng hiện tại không có ai đang ngồi."},"2521":{"word":"cầu nguyện","meaning":"Nói chuyện với thần linh hoặc đấng thiêng liêng để xin giúp đỡ, bày tỏ lòng biết ơn hoặc đưa ra yêu cầu."},"2522":{"word":"chải","meaning":"Dùng dụng cụ có răng mỏng, cứng kéo qua tóc để làm cho tóc gọn gàng."},"2523":{"word":"ánh sáng","meaning":"Năng lượng làm cho vật thể trở nên nhìn thấy được, biểu hiện dưới dạng sự sáng chói hoặc ánh lấp lánh."},"2524":{"word":"rơi","meaning":"Rơi khỏi vị trí của nó hoặc bị chìm vào trong chất lỏng hay vật chất mềm."},"2525":{"word":"màu đỏ","meaning":"Màu giống như quả táo chín hoặc ớt đỏ."},"2526":{"word":"trở nên đỏ","meaning":"Thay đổi màu sắc sang màu giống như máu hoặc quả táo chín."},"2527":{"word":"mút","meaning":"Hút cái gì đó vào miệng bằng cách tạo ra lực hút, giống như với đồ ngọt."},"2528":{"word":"giật","meaning":"Lấy đi một vật từ tay hoặc quyền sở hữu của người khác một cách mạnh mẽ và nhanh chóng."},"2529":{"word":"xương","meaning":"Chất cứng hỗ trợ cơ thể người hoặc động vật và được bao phủ bởi thịt."},"2530":{"word":"hôn nhẹ","meaning":"Chạm nhẹ, nhanh bằng môi lên người hoặc vật khác, thường là lên má."},"2531":{"word":"rễ","meaning":"Phần của cây thường mọc dưới đất, giúp cây đứng vững và hút nước, chất dinh dưỡng từ đất."},"2532":{"word":"rắc, rải, tưới","meaning":"Làm cho một vật gì đó nhỏ hoặc lỏng văng ra, rơi xuống nhiều nơi."},"2533":{"word":"bong gân","meaning":"Bị thương ở khớp, như mắt cá chân hoặc cổ tay, do bị xoắn đột ngột gây đau và sưng."},"2534":{"word":"(hậu tố chỉ người làm nghề)","meaning":"Hậu tố được thêm vào sau một từ để chỉ người làm một công việc hoặc thực hiện một hoạt động nào đó."},"2535":{"word":"sự kiện, vụ việc","meaning":"Một sự việc cụ thể xảy ra, đặc biệt là sự việc bất thường, quan trọng hoặc không mấy dễ chịu."},"2536":{"word":"lời xin lỗi, sự xin lỗi","meaning":"Lời nói hoặc hành động bày tỏ sự hối tiếc về một lỗi lầm đã gây ra."},"2537":{"word":"hòa đồng, có tính xã giao","meaning":"Tính cách của người thích giao tiếp và dễ dàng tương tác với nhiều người khác."},"2538":{"word":"chàng trai, người đàn ông (cá tính mạnh)","meaning":"Một người đàn ông trưởng thành, thường được dùng để gợi ý sự mạnh mẽ hoặc dũng cảm."},"2539":{"word":"biến mất","meaning":"Không còn nhìn thấy hoặc hiện diện nữa, trở nên không thể tìm thấy."},"2540":{"word":"công việc văn phòng, nghiệp vụ","meaning":"Các hoạt động liên quan đến điều hành, quản lý giấy tờ hoặc sử dụng máy tính trong một nơi làm việc."},"2541":{"word":"văn phòng, cơ quan","meaning":"Một căn phòng hoặc tòa nhà cụ thể nơi mọi người làm các công việc chuyên môn của họ."},"2542":{"word":"vật thể, sự vật","meaning":"Bất kỳ thứ gì không sống, mà bạn có thể nhìn và chạm vào, như một cái bàn hay một quả bóng."},"2543":{"word":"đời tư","meaning":"Tình trạng giữ kín thông tin và cuộc sống cá nhân khỏi sự can thiệp của người khác."},"2544":{"word":"doanh nhân","meaning":"Người khởi nghiệp và điều hành một công ty với mục đích kinh doanh sản phẩm hoặc dịch vụ để kiếm lời."},"2545":{"word":"cách sử dụng","meaning":"Hướng dẫn hoặc các bước chỉ dẫn cách thức vận hành đúng một công cụ, máy móc hoặc thiết bị."},"2546":{"word":"phòng tắm hơi","meaning":"Một căn phòng nhỏ, thường bằng gỗ, được làm nóng ở nhiệt độ rất cao để mọi người ngồi thư giãn và ra mồ hôi."},"2547":{"word":"trang web","meaning":"Tập hợp các trang kỹ thuật số và nội dung liên quan trên internet mà bạn có thể xem trên màn hình máy tính hoặc điện thoại."},"2548":{"word":"ký tên","meaning":"Hành động viết tên hoặc một dấu đặc biệt lên tài liệu giấy hoặc kỹ thuật số để thể hiện sự đồng ý hoặc xác nhận."},"2549":{"word":"sư tử","meaning":"Một loài động vật lớn và hung dữ, con đực có bờm quanh mặt và cổ."},"2550":{"word":"riêng tư","meaning":"Diễn tả điều gì đó thuộc về một người hoặc một nhóm nhỏ, không dành cho nhiều người khác biết hoặc thấy."},"2551":{"word":"từ điển","meaning":"Một cuốn sách hoặc công cụ điện tử liệt kê các từ theo thứ tự bảng chữ cái và giải thích ý nghĩa của mỗi từ."},"2552":{"word":"trước","meaning":"Mô tả điều gì đó diễn ra hoặc được sắp xếp vào thời điểm sớm hơn một sự kiện chính khác."},"2553":{"word":"tiệm chụp ảnh","meaning":"Một căn phòng hoặc địa điểm kinh doanh nơi mọi người đến để chụp ảnh, thường với ánh sáng và máy ảnh đặc biệt."},"2554":{"word":"anh chị em họ","meaning":"Thành viên trong gia đình là con của cô, chú, bác của bạn, có nghĩa là cả hai đều có chung ông bà."},"2555":{"word":"điều, mục","meaning":"Một điểm hoặc chi tiết cụ thể cần được xem xét hoặc thảo luận, thường là một phần trong danh sách."},"2556":{"word":"xã hội","meaning":"Một nhóm lớn người sống cùng nhau một cách có tổ chức, có chung phong tục và luật lệ."},"2557":{"word":"người điều hành, MC","meaning":"Người dẫn dắt một cuộc họp hoặc thảo luận, đảm bảo mọi người đều có lượt phát biểu."},"2558":{"word":"xã hội","meaning":"Liên quan đến cách mọi người sống và tương tác với nhau trong các nhóm."},"2559":{"word":"xóa, loại bỏ","meaning":"Hành động loại bỏ hoặc gỡ bỏ thứ gì đó, ví dụ như xóa tập tin trên máy tính."},"2560":{"word":"đỉnh núi, chóp núi","meaning":"Điểm cao nhất của một ngọn núi, thường là một đỉnh nhọn có thể đứng được."},"2561":{"word":"ngành, công nghiệp","meaning":"Tập hợp các doanh nghiệp và nhà máy tham gia sản xuất sản phẩm hoặc cung cấp dịch vụ cụ thể."},"2562":{"word":"sống lại, qua khỏi","meaning":"Trở lại cuộc sống hoặc hồi phục sau một tình huống rất nguy hiểm, ví dụ như sống sót sau tai nạn."},"2563":{"word":"giết người, vụ giết người","meaning":"Hành vi phạm pháp cố ý gây ra cái chết của một người khác."},"2564":{"word":"khẽ, nhẹ, hơi","meaning":"Di chuyển hoặc làm điều gì đó với một lượng rất nhỏ hoặc gần như không gây tiếng động."},"2565":{"word":"tăng cân, béo lên","meaning":"Tăng thêm trọng lượng cơ thể, làm cho kích thước thể chất của một người tăng lên rõ rệt."},"2566":{"word":"xem xét, quan sát kỹ","meaning":"Nhìn một vật gì đó rất cẩn thận và kỹ lưỡng, thường là bằng cách di chuyển hoặc lật nó, để hiểu rõ hoặc tìm thông tin."},"2567":{"word":"quan sát","meaning":"Nhìn kỹ xung quanh hoặc một vật gì đó để tìm kiếm hoặc để cảnh giác."},"2568":{"word":"cuộc sống","meaning":"Trạng thái tồn tại và tất cả những trải nghiệm từ khi sinh ra đến khi chết của một người hoặc con vật."},"2569":{"word":"luộc","meaning":"Đặt thức ăn vào nước và đun sôi cho chín."},"2570":{"word":"trên","meaning":"Chỉ vị trí cao hơn hoặc phần phía trên của một vật."},"2571":{"word":"bàn ăn","meaning":"Một đồ nội thất có mặt phẳng và chân, thường dùng để đặt thức ăn và dùng bữa."},"2572":{"word":"không liên quan","meaning":"Khi hai sự vật không có mối liên hệ, không ảnh hưởng đến nhau hoặc không quan trọng với nhau."},"2573":{"word":"tư vấn","meaning":"Một buổi gặp mặt nơi một người nói chuyện với chuyên gia để nhận lời khuyên hoặc thông tin về một vấn đề."},"2574":{"word":"đối phương","meaning":"Người ở phía bên kia trong một cuộc thi, trò chơi hoặc tranh luận."},"2575":{"word":"lẽ thường","meaning":"Những sự thật hoặc hiểu biết mà hầu hết mọi người trong xã hội đều biết hoặc đồng ý, giúp họ đưa ra phán đoán hợp lý."},"2576":{"word":"chiếu phim","meaning":"Hành động trình chiếu một bộ phim hoặc video trên màn hình lớn để mọi người xem."},"2577":{"word":"cửa hàng","meaning":"Một tòa nhà hoặc phòng nơi trưng bày và bán các mặt hàng như thực phẩm, quần áo cho khách hàng."},"2578":{"word":"trạng thái","meaning":"Cách thức cụ thể mà một thứ hoặc một người xuất hiện hoặc tồn tại tại một thời điểm nhất định."},"2579":{"word":"hỏng, hư hại","meaning":"Trở nên không còn tốt, bị hư hại hoặc trở nên không khỏe mạnh."},"2580":{"word":"tình hình, tình huống","meaning":"Toàn bộ các sự kiện và sự thật đang xảy ra xung quanh một người hoặc một sự việc tại một thời điểm nhất định."},"2581":{"word":"mới, một cách mới mẻ","meaning":"Theo một cách tươi mới, hoàn toàn khác hoặc vừa mới hình thành."},"2582":{"word":"mẹ kế","meaning":"Người phụ nữ kết hôn với cha của một đứa trẻ sau khi mẹ ruột của đứa trẻ đó đã mất hoặc ly hôn."},"2583":{"word":"tôm","meaning":"Một loài giáp xác nhỏ sống dưới nước, có lưng cong, râu dài và nhiều chân."},"2584":{"word":"nhà mới","meaning":"Một ngôi nhà vừa mới được xây dựng hoặc một gia đình vừa mới bắt đầu sinh sống."},"2585":{"word":"dép xăng đan","meaning":"Loại giày dép nhẹ có quai giữ đế vào chân, để lộ hầu hết bàn chân."},"2586":{"word":"-sinh, học viên","meaning":"Hậu tố dùng để chỉ một người đang học tập hoặc tích lũy kinh nghiệm trong một lĩnh vực cụ thể."},"2587":{"word":"ngày tháng năm sinh","meaning":"Ngày, tháng và năm chính xác mà một người được sinh ra."},"2588":{"word":"tóc thẳng","meaning":"Mái tóc thẳng tự nhiên và chưa từng được uốn xoăn."},"2589":{"word":"chi phí sinh hoạt","meaning":"Số tiền cần thiết để chi trả cho các nhu cầu hàng ngày của một người như ăn uống, chỗ ở và đi lại."},"2590":{"word":"đồ dùng sinh hoạt","meaning":"Các vật dụng gia đình mà mọi người thường xuyên sử dụng cho việc chăm sóc cá nhân, vệ sinh hoặc duy trì cuộc sống hàng ngày."},"2591":{"word":"dầu gội","meaning":"Một loại chất lỏng dùng để gội sạch tóc và da đầu."},"2592":{"word":"phía tây","meaning":"Hướng mà mặt trời lặn vào buổi chiều."},"2593":{"word":"ba bốn","meaning":"Một số lượng nhỏ, khoảng từ ba đến bốn cái hoặc người."},"2594":{"word":"chữ ký","meaning":"Tên riêng được viết theo cách đặc trưng của một người, thường dùng để xác nhận hoặc đồng ý trên văn bản."},"2595":{"word":"miền tây","meaning":"Vùng địa lý nằm ở phía tây, nơi mặt trời thường lặn."},"2596":{"word":"vụng về","meaning":"Không khéo léo, làm việc gì đó một cách khó khăn hoặc mắc nhiều lỗi do thiếu kinh nghiệm hay kỹ năng."},"2597":{"word":"dầu mỏ","meaning":"Một loại dầu màu đen tự nhiên chảy ra từ lòng đất, được dùng làm nhiên liệu cho xe cộ hoặc nhà máy."},"2598":{"word":"đường kẻ","meaning":"Một vệt dài, mỏng hoặc dải liên tục kéo dài trên một bề mặt hoặc tạo thành ranh giới."},"2599":{"word":"kính râm","meaning":"Loại kính có tròng màu sẫm dùng để bảo vệ mắt khỏi ánh nắng chói chang."},"2600":{"word":"hẹn trước","meaning":"Một cuộc hẹn hoặc kế hoạch đã được sắp xếp và cam kết từ trước."},"2601":{"word":"Tết Nguyên Đán (Hàn Quốc)","meaning":"Ngày lễ truyền thống lớn nhất của Hàn Quốc, rơi vào ngày đầu tiên của âm lịch."},"2602":{"word":"sách hướng dẫn","meaning":"Tài liệu cung cấp thông tin và chỉ dẫn về cách sử dụng, lắp ráp hoặc vận hành một sản phẩm hay hệ thống."},"2603":{"word":"khảo sát","meaning":"Một bộ câu hỏi được đặt ra cho một nhóm người để thu thập ý kiến hoặc thông tin của họ."},"2604":{"word":"phiếu khảo sát","meaning":"Tài liệu chứa các câu hỏi được sử dụng để tiến hành nghiên cứu hoặc điều tra."},"2605":{"word":"tiêu chảy","meaning":"Tình trạng đi ngoài phân lỏng hoặc rất lỏng một cách thường xuyên."},"2606":{"word":"nhà thờ Công giáo","meaning":"Tòa nhà lớn, thường tráng lệ, được người Công giáo sử dụng để thực hiện các nghi lễ tôn giáo."},"2607":{"word":"họ tên","meaning":"Tên đầy đủ của một người, bao gồm cả họ và tên riêng."},"2608":{"word":"giới tính","meaning":"Sự phân loại một sinh vật là nam hoặc nữ dựa trên các đặc điểm thể chất hoặc vai trò xã hội."},"2609":{"word":"sự thành thật, sự cần mẫn","meaning":"Phẩm chất của người luôn làm việc chăm chỉ, cẩn thận và đáng tin cậy."},"2610":{"word":"người trưởng thành","meaning":"Người đã hoàn thành sự phát triển và đạt đến tuổi chịu trách nhiệm pháp lý, không còn là trẻ em."},"2611":{"word":"thế kỷ","meaning":"Khoảng thời gian một trăm năm."},"2612":{"word":"đếm","meaning":"Nói các con số theo thứ tự để xác định tổng số lượng các vật phẩm."},"2613":{"word":"tinh tế, lịch lãm","meaning":"Có vẻ ngoài, hành động hoặc thiết kế rất sang trọng, trang nhã và hiện đại."},"2614":{"word":"chiều dọc","meaning":"Hướng thẳng đứng từ trên xuống dưới hoặc từ dưới lên trên."},"2615":{"word":"năm tháng","meaning":"Khoảng thời gian trôi qua, khiến mọi thứ thay đổi và phát triển."},"2616":{"word":"giảm giá","meaning":"Khoảng thời gian mà các cửa hàng bán sản phẩm với giá thấp hơn bình thường."},"2617":{"word":"chất tẩy rửa","meaning":"Hóa chất dạng lỏng hoặc bột dùng với nước để làm sạch quần áo, chén đĩa hoặc các bề mặt."},"2618":{"word":"rửa xe","meaning":"Hành động làm sạch bụi bẩn bên ngoài hoặc bên trong xe ô tô."},"2619":{"word":"đồ giặt","meaning":"Quần áo, khăn hoặc các loại vải khác đang chờ được giặt hoặc vừa mới giặt xong."},"2620":{"word":"bộ","meaning":"Tập hợp nhiều vật phẩm hoặc món đồ thuộc về nhau, thường được bán cùng nhau hoặc tạo thành một nhóm hoàn chỉnh."},"2621":{"word":"xăng-ti-mét","meaning":"Một đơn vị đo chiều dài nhỏ, bằng một phần trăm của mét."},"2622":{"word":"áo sơ mi","meaning":"Một loại quần áo mặc ở phần trên cơ thể, thường có cổ, tay áo và hàng cúc phía trước."},"2623":{"word":"cơ sở","meaning":"Một tiếp tố được thêm vào cuối một từ để chỉ một tòa nhà hoặc khu vực cụ thể nơi một hoạt động nhất định diễn ra."},"2624":{"word":"tiểu-","meaning":"Một tiền tố được thêm vào đầu một từ để chỉ rằng cái gì đó không lớn về kích thước hoặc phạm vi."},"2625":{"word":"cảm nghĩ","meaning":"Những ý tưởng và phản ứng cá nhân mà một người có sau khi trải nghiệm điều gì đó."},"2626":{"word":"buổi hẹn hò giấu mặt","meaning":"Một cuộc gặp gỡ được sắp xếp giữa hai người chưa từng gặp nhau trước đây, thường là do bạn bè giới thiệu."},"2627":{"word":"nhà hát nhỏ","meaning":"Một nhà hát có quy mô nhỏ."},"2628":{"word":"nước muối","meaning":"Nước có hòa tan muối, thường dùng để ngâm, rửa hoặc bảo quản thực phẩm."},"2629":{"word":"mưa rào","meaning":"Lượng nước lớn từ mây rơi xuống nhanh chóng trong thời gian ngắn."},"2630":{"word":"khử trùng","meaning":"Hành động dùng thuốc hoặc chất lỏng để tiêu diệt vi khuẩn gây hại trên bề mặt hoặc vết thương."},"2631":{"word":"thuốc sát trùng","meaning":"Loại thuốc dạng lỏng hoặc kem dùng để bôi lên da hoặc vật dụng nhằm tiêu diệt vi khuẩn có hại."},"2632":{"word":"tay áo","meaning":"Phần của áo che cánh tay của người mặc."},"2633":{"word":"tin đồn","meaning":"Thông tin chưa được xác nhận về một người hay sự kiện, thường lan truyền nhanh chóng từ người này sang người khác."},"2634":{"word":"lính cứu hỏa","meaning":"Người chuyên nghiệp được đào tạo để dập tắt đám cháy lớn và giúp đỡ người dân thoát khỏi tình huống nguy hiểm."},"2635":{"word":"trạm cứu hỏa","meaning":"Tòa nhà chuyên dụng nơi những người lính cứu hỏa làm việc và cất giữ các phương tiện, thiết bị khẩn cấp."},"2636":{"word":"nước tiểu","meaning":"Chất thải dạng lỏng màu vàng, được cơ thể đào thải ra từ bàng quang."},"2637":{"word":"tiểu thuyết gia","meaning":"Người có nghề nghiệp là sáng tác và viết các câu chuyện hư cấu dài, thường được xuất bản thành sách."},"2638":{"word":"tiểu thuyết","meaning":"Cuốn sách chứa một câu chuyện hư cấu dài về những người và sự kiện tưởng tượng, dùng để đọc."},"2639":{"word":"xúc xích","meaning":"Một loại thực phẩm làm từ thịt xay nhuyễn, thường có gia vị và được nén thành hình trụ."},"2640":{"word":"khoa nhi","meaning":"Chuyên khoa y tế dành riêng cho việc khám, chăm sóc và điều trị bệnh cho trẻ sơ sinh và trẻ nhỏ."},"2641":{"word":"thời gian cần thiết","meaning":"Khoảng thời gian phải mất để hoàn thành một nhiệm vụ hoặc di chuyển một quãng đường."},"2642":{"word":"điều ước","meaning":"Một ý nghĩ chân thành hoặc mong muốn mãnh liệt về một điều gì đó sẽ xảy ra hoặc trở thành hiện thực trong tương lai."},"2643":{"word":"sự tiêu hóa","meaning":"Quá trình phân hủy thức ăn thành các chất dinh dưỡng trong dạ dày và hấp thụ chúng."},"2644":{"word":"tục ngữ","meaning":"Một câu nói ngắn gọn, truyền tải bài học kinh nghiệm từ người xưa."},"2645":{"word":"buồn bực, khó chịu","meaning":"Cảm giác rất buồn hoặc thất vọng khi mọi việc không như ý hoặc nghe lời nói không hay."},"2646":{"word":"túi xách tay","meaning":"Một chiếc túi nhỏ dùng để mang theo bằng tay."},"2647":{"word":"mu bàn tay","meaning":"Phần trên của bàn tay, đối diện với lòng bàn tay."},"2648":{"word":"cổ tay","meaning":"Khớp nối linh hoạt giữa cánh tay và bàn tay."},"2649":{"word":"đồng hồ đeo tay","meaning":"Một chiếc đồng hồ nhỏ được thiết kế để đeo ở cổ tay."},"2650":{"word":"tay chân","meaning":"Hai chi trên và hai chi dưới của cơ thể, được sử dụng để di chuyển hoặc thực hiện các công việc."},"2651":{"word":"vỗ tay","meaning":"Âm thanh tạo ra khi hai bàn tay vỗ vào nhau liên tục và nhanh chóng."},"2652":{"word":"cháu trai","meaning":"Con trai của con trai hoặc con gái của mình."},"2653":{"word":"khéo léo","meaning":"Khả năng làm việc gì đó rất tốt, thường thể hiện qua sự tỉ mỉ và kỹ thuật."},"2654":{"word":"tiệc chia tay","meaning":"Buổi tiệc được tổ chức để tạm biệt một người sắp rời đi hoặc thay đổi công việc."},"2655":{"word":"chùm","meaning":"Một nhóm tự nhiên các vật như hoa hoặc quả (nho) mọc tụ lại trên cùng một cành."},"2656":{"word":"thịt bò","meaning":"Phần thịt màu đỏ từ con bò được chế biến và dùng làm thực phẩm."},"2657":{"word":"buổi diễn","meaning":"Một màn trình diễn hoặc sự kiện công cộng được xem để giải trí, thường có ca hát, nhảy múa hoặc ảo thuật."},"2658":{"word":"trung tâm thương mại","meaning":"Một tòa nhà lớn chứa nhiều loại cửa hàng và nhà hàng khác nhau, nơi mọi người có thể đi bộ để mua sắm."},"2659":{"word":"trung tâm mua sắm","meaning":"Một khu vực tập trung nhiều cửa hàng khác nhau, đôi khi ở các tòa nhà riêng biệt, để mọi người đến mua sắm các mặt hàng."},"2660":{"word":"Thủy (trong thứ Tư)","meaning":"Là yếu tố 'nước' (水) được dùng trong từ 'thứ Tư' (수요일), một ngày trong tuần."},"2661":{"word":"chuyện phiếm","meaning":"Cuộc trò chuyện bình thường, không trang trọng về các chủ đề đời thường hoặc không quá nghiêm túc."},"2662":{"word":"phương tiện","meaning":"Cách thức hoặc công cụ cụ thể mà một người sử dụng để đạt được kết quả hoặc mục tiêu nhất định."},"2663":{"word":"hệ thống cấp nước","meaning":"Là hệ thống ống và vòi dẫn nước vào các tòa nhà để sử dụng hàng ngày."},"2664":{"word":"thủ đô","meaning":"Là thành phố quan trọng nhất của một quốc gia, nơi thường đặt các cơ quan chính phủ."},"2665":{"word":"số lượng","meaning":"Một con số cụ thể hoặc tổng số đo được của một thứ gì đó, ví dụ như số lượng vật phẩm hay lượng chất lỏng."},"2666":{"word":"sửa chữa","meaning":"Hành động khắc phục hoặc làm cho một vật thể bị hỏng, hư hại hoặc trục trặc hoạt động đúng trở lại."},"2667":{"word":"giấc ngủ","meaning":"Trạng thái tự nhiên khi mắt người nhắm lại, cơ thể nghỉ ngơi và họ chìm vào vô thức, thường kéo dài vài giờ."},"2668":{"word":"thuốc ngủ","meaning":"Những viên thuốc nhỏ hoặc viên nang mà một người uống để dễ dàng chìm vào trạng thái nghỉ ngơi tự nhiên hơn."},"2669":{"word":"sửa quần áo","meaning":"Hành động vá hoặc sửa đổi quần áo, ví dụ như khâu vết rách, vá lỗ hoặc điều chỉnh độ dài của một bộ quần áo."},"2670":{"word":"phí dịch vụ","meaning":"Một khoản tiền bổ sung được trả cho một dịch vụ hoặc giao dịch cụ thể, ngoài chi phí cơ bản của hàng hóa."},"2671":{"word":"thu nhập","meaning":"Số tiền mà một người thường xuyên nhận được từ công việc hoặc đầu tư, dùng để sinh hoạt."},"2672":{"word":"nhập khẩu","meaning":"Các sản phẩm hoặc hàng hóa được đưa vào một quốc gia từ một quốc gia khác, thường là để bán hoặc phân phối."},"2673":{"word":"sửa đổi","meaning":"Hành động thực hiện thay đổi đối với một tài liệu, kế hoạch hoặc bài viết để cải thiện hoặc làm cho nó chính xác hơn."},"2674":{"word":"sưu tập","meaning":"Sở thích hoặc hoạt động thu thập nhiều vật phẩm tương tự lại với nhau, như tem, tiền xu hoặc tác phẩm nghệ thuật, và giữ chúng."},"2675":{"word":"xuất khẩu","meaning":"Việc gửi hàng hóa, sản phẩm từ một nước ra nước ngoài để bán hoặc phân phối."},"2676":{"word":"séc","meaning":"Một tờ giấy có giá trị như tiền mặt, dùng để rút số tiền ghi trên đó từ ngân hàng."},"2677":{"word":"toán học","meaning":"Môn học nghiên cứu về số lượng, hình dạng, không gian và các mối quan hệ thông qua phép tính và giải quyết vấn đề."},"2678":{"word":"lưu trú","meaning":"Hành động ở lại một nơi nào đó như khách sạn, nhà trọ trong một hoặc nhiều đêm."},"2679":{"word":"phí lưu trú","meaning":"Số tiền phải trả để ở lại tạm thời tại một địa điểm như khách sạn, nhà nghỉ."},"2680":{"word":"chỗ ở","meaning":"Nơi trú ngụ hoặc tòa nhà mà một người sống hoặc ở tạm thời, như khách sạn, nhà nghỉ."},"2681":{"word":"khoảnh khắc","meaning":"Một khoảng thời gian rất ngắn."},"2682":{"word":"ly rượu","meaning":"Cái ly hoặc chén nhỏ dùng để uống rượu."},"2683":{"word":"trốn","meaning":"Đặt mình vào một vị trí mà người khác không thể dễ dàng tìm thấy hoặc nhìn thấy."},"2684":{"word":"rừng","meaning":"Một vùng đất rộng lớn có nhiều cây cối và các loại thực vật khác mọc dày đặc."},"2685":{"word":"bị khản tiếng","meaning":"Giọng nói trở nên yếu, trầm và khó nghe do mệt mỏi hoặc nói nhiều."},"2686":{"word":"suỵt!","meaning":"Từ dùng để yêu cầu người khác giữ im lặng hoặc ngừng gây tiếng ồn."},"2687":{"word":"siêu thị","meaning":"Một cửa hàng lớn bán nhiều loại thực phẩm, đồ gia dụng và các mặt hàng thiết yếu hàng ngày."},"2688":{"word":"thứ hai mươi","meaning":"Vị trí hoặc vật thể ở số hai mươi trong một dãy hoặc một chuỗi."},"2689":{"word":"chân váy","meaning":"Một loại trang phục che phần dưới cơ thể, thường được phụ nữ mặc."},"2690":{"word":"phong cách","meaning":"Cách thức đặc trưng mà một người thực hiện điều gì đó hoặc cách họ ăn mặc, tạo kiểu."},"2691":{"word":"vớ da","meaning":"Trang phục bằng vật liệu co giãn ôm sát chân và bàn chân, thường do phụ nữ mặc."},"2692":{"word":"dép đi trong nhà","meaning":"Một loại giày mềm, nhẹ được thiết kế để mang bên trong nhà hoặc tòa nhà."},"2693":{"word":"hơi ẩm","meaning":"Các hạt chất lỏng nhỏ, thường là nước, có trong không khí hoặc trên bề mặt."},"2694":{"word":"độ ẩm","meaning":"Lượng hơi nước có trong không khí tại một thời điểm và địa điểm cụ thể."},"2695":{"word":"ẩm ướt","meaning":"Khi không khí chứa nhiều nước và cảm thấy nặng nề hoặc dính."},"2696":{"word":"hành khách","meaning":"Người đi trên xe ô tô, xe buýt, tàu hỏa hoặc máy bay nhưng không điều khiển phương tiện đó."},"2697":{"word":"tiếp viên","meaning":"Người làm việc giúp đỡ hành khách và thực hiện các nhiệm vụ trên tàu, máy bay hoặc phương tiện công cộng khác."},"2698":{"word":"thăng chức","meaning":"Hành động được chuyển lên một vị trí cao hơn tại nơi làm việc của mình."},"2699":{"word":"Sự lên xe","meaning":"Hành động đi lên phương tiện giao thông công cộng như xe buýt, tàu hỏa để bắt đầu chuyến đi."},"2700":{"word":"Vé xe/tàu","meaning":"Mảnh giấy nhỏ hoặc thẻ điện tử cho phép một người đi lại bằng phương tiện giao thông công cộng."},"2701":{"word":"Thơ","meaning":"Một loại hình nghệ thuật văn học, thường là những câu chữ có vần điệu hoặc nhịp điệu nhất định."},"2702":{"word":"Thời điểm, giờ","meaning":"Một khoảnh khắc cụ thể hoặc một điểm chính xác trên đồng hồ khi một việc gì đó xảy ra."},"2703":{"word":"Thời điểm thích hợp","meaning":"Khoảng thời gian hoặc cơ hội phù hợp để thực hiện một việc gì đó."},"2704":{"word":"Xe buýt nội thành","meaning":"Phương tiện giao thông công cộng lớn chạy theo tuyến cố định trong một thị trấn hoặc thành phố."},"2705":{"word":"Thời đại, kỷ nguyên","meaning":"Một khoảng thời gian dài trong lịch sử được biết đến với những sự kiện, nhân vật hoặc cách sống đặc trưng."},"2706":{"word":"Đĩa CD","meaning":"Một đĩa nhỏ, phẳng, tròn, sáng bóng dùng để lưu trữ âm thanh, hình ảnh hoặc dữ liệu kỹ thuật số."},"2707":{"word":"Cơ sở vật chất, tiện nghi","meaning":"Một tòa nhà, thiết bị hoặc dịch vụ được cung cấp cho một mục đích cụ thể như trường học, bệnh viện."},"2708":{"word":"Bố chồng","meaning":"Người cha của chồng mình."},"2709":{"word":"Ngoại ô, vùng ngoại thành","meaning":"Khu vực có nhà cửa và các tòa nhà nhỏ hơn nằm ngay bên ngoài một thị trấn hoặc thành phố lớn."},"2710":{"word":"Xe buýt liên tỉnh","meaning":"Phương tiện giao thông công cộng lớn chở người đi lại quãng đường dài giữa các thị trấn và thành phố khác nhau."},"2711":{"word":"thị trưởng","meaning":"Người đứng đầu chính quyền một thành phố hoặc thị xã, được bầu ra để quản lý."},"2712":{"word":"nhà chồng","meaning":"Gia đình của người chồng, nơi người vợ về sống sau khi kết hôn."},"2713":{"word":"tập thơ","meaning":"Cuốn sách tập hợp nhiều bài thơ của một hoặc nhiều tác giả."},"2714":{"word":"đề thi","meaning":"Tờ giấy có in các câu hỏi dùng để kiểm tra kiến thức của học sinh, thí sinh."},"2715":{"word":"bát đĩa","meaning":"Những vật dụng như chén, đĩa, đũa, muỗng dùng để ăn uống."},"2716":{"word":"khu phố ẩm thực","meaning":"Khu vực có nhiều nhà hàng, quán ăn tập trung gần nhau."},"2717":{"word":"thực phẩm","meaning":"Các mặt hàng như rau củ, thịt, đồ đóng gói dùng để chế biến và ăn uống."},"2718":{"word":"chi phí ăn uống","meaning":"Số tiền dùng để mua thức ăn hoặc ăn uống ở ngoài."},"2719":{"word":"lượng thức ăn","meaning":"Khối lượng hoặc số lượng thức ăn mà một người ăn trong một bữa."},"2720":{"word":"dầu ăn","meaning":"Chất lỏng béo thường dùng để chiên, xào, nấu thức ăn."},"2721":{"word":"ngộ độc thực phẩm","meaning":"Bệnh xảy ra do ăn phải thức ăn bị ôi thiu hoặc nhiễm khuẩn."},"2722":{"word":"cửa hàng thực phẩm","meaning":"Cửa hàng chuyên bán các loại thực phẩm tươi sống hoặc đóng gói."},"2723":{"word":"sau bữa ăn","meaning":"Khoảng thời gian sau khi ăn cơm xong."},"2724":{"word":"làm nguội, làm mát","meaning":"Làm cho một vật hoặc không khí đang nóng trở nên bớt nóng hơn."},"2725":{"word":"dây thần kinh","meaning":"Sợi mỏng trong cơ thể truyền thông điệp từ não đến các cơ và cơ quan."},"2726":{"word":"trình báo, báo cáo","meaning":"Hành động chính thức thông báo sự việc đã xảy ra cho cơ quan có thẩm quyền như cảnh sát."},"2727":{"word":"kỳ diệu, lạ lùng","meaning":"Gây ra cảm giác ngạc nhiên và thán phục vì điều gì đó rất khác thường, đặc biệt hoặc giống như phép thuật."},"2728":{"word":"hào hứng, phấn khích","meaning":"Cảm thấy rất vui vẻ và tràn đầy năng lượng, thường khiến người ta mỉm cười, cười đùa và vận động."},"2729":{"word":"tòa soạn báo","meaning":"Tổ chức thu thập thông tin, viết bài và in báo hàng ngày để chia sẻ với công chúng."},"2730":{"word":"giấy báo","meaning":"Tờ giấy lớn có in chữ và hình ảnh, dùng để thông báo tin tức thời sự cho mọi người."},"2731":{"word":"linh mục, cha xứ","meaning":"Người đàn ông có chức vụ lãnh đạo trong một số nhà thờ Công giáo, có quyền thực hiện các nghi lễ tôn giáo."},"2732":{"word":"thân phận, địa vị","meaning":"Vị trí hoặc địa vị được công nhận của một người trong một nhóm hoặc xã hội, thường thể hiện qua giấy tờ chính thức."},"2733":{"word":"quý ông","meaning":"Người đàn ông cư xử lịch sự, tôn trọng người khác và thường ăn mặc chỉnh tề."},"2734":{"word":"tín dụng, sự tín nhiệm","meaning":"Niềm tin rằng ai đó đáng tin cậy và sẽ giữ lời hứa, đặc biệt trong các vấn đề tài chính."},"2735":{"word":"người mới","meaning":"Người vừa mới bắt đầu làm việc ở một công ty hoặc tham gia một nhóm nào đó."},"2736":{"word":"tân sinh viên","meaning":"Học sinh hoặc sinh viên vừa mới nhập học năm đầu tiên ở một trường học."},"2737":{"word":"đơn đăng ký","meaning":"Một tài liệu in sẵn hoặc trang điện tử có chỗ trống để điền thông tin khi muốn yêu cầu điều gì đó."},"2738":{"word":"cơ thể","meaning":"Toàn bộ cấu trúc vật lý của người hoặc động vật, bao gồm xương, nội tạng và da."},"2739":{"word":"tân hôn","meaning":"Giai đoạn đầu tiên sau khi hai người kết hôn."},"2740":{"word":"cặp đôi mới cưới","meaning":"Một cặp vợ chồng vừa mới kết hôn cách đây không lâu."},"2741":{"word":"chỉ","meaning":"Sợi vật liệu rất dài và mảnh, thường được cuộn thành cuộn, dùng để may vá hoặc buộc đồ vật."},"2742":{"word":"trong nhà","meaning":"Không gian hoặc khu vực nằm bên trong các bức tường của một tòa nhà."},"2743":{"word":"năng lực","meaning":"Khả năng hoặc sự thành thạo của một người được thể hiện khi họ hoàn thành tốt các nhiệm vụ khó khăn."},"2744":{"word":"được chất lên","meaning":"Đồ vật hoặc hàng hóa được đặt cẩn thận hoặc chất lên một phương tiện vận chuyển như tàu, xe hơi hoặc xe lửa."},"2745":{"word":"thất vọng","meaning":"Cảm giác buồn bã hoặc hụt hẫng khi một kỳ vọng nào đó không được đáp ứng."},"2746":{"word":"thực tế","meaning":"Diễn tả điều gì đó thật sự xảy ra hoặc tồn tại, chứ không phải chỉ là ý tưởng hay câu chuyện."},"2747":{"word":"sự mất tích","meaning":"Tình trạng một người hoặc một vật không còn được tìm thấy hay quan sát nữa."},"2748":{"word":"thỏa thích","meaning":"Theo ý muốn, không giới hạn."},"2749":{"word":"sự ngán","meaning":"Cảm giác không còn thích hoặc muốn làm một việc gì đó."},"2750":{"word":"-tâm","meaning":"Hậu tố chỉ tính cách, phẩm chất hoặc động lực nội tâm của một người."},"2751":{"word":"nghiêm trọng","meaning":"Tình trạng hoặc vấn đề có mức độ nghiêm trọng rõ rệt, cần được chú ý ngay lập tức và có thể gây ra hậu quả xấu."},"2752":{"word":"tâm lý","meaning":"Cách một người suy nghĩ và hành động, bị ảnh hưởng bởi những ý nghĩ và cảm xúc bên trong có thể quan sát được qua hành vi của họ."},"2753":{"word":"tươi","meaning":"Chỉ thức ăn hoặc cây cối còn mới, đầy sức sống, chưa có dấu hiệu héo úa hoặc hư hỏng."},"2754":{"word":"đi tiểu","meaning":"Thải nước tiểu ra khỏi cơ thể, đặc biệt là khi không kiểm soát được (tè dầm)."},"2755":{"word":"đôi, cặp","meaning":"Hai vật giống hệt nhau hoặc được dùng chung với nhau, ví dụ như hai chiếc tất hoặc hai chiếc giày."},"2756":{"word":"cặp song sinh","meaning":"Hai em bé hoặc trẻ em được sinh ra từ cùng một người mẹ vào cùng một thời điểm."},"2757":{"word":"chất đống","meaning":"Nhiều vật được đặt chồng lên nhau, tạo thành một chồng cao hoặc một đống."},"2758":{"word":"thối, mục","meaning":"Vật liệu hữu cơ như thức ăn hoặc gỗ bị phân hủy theo thời gian, thay đổi màu sắc, trở nên mềm và có mùi khó chịu."},"2759":{"word":"làm đổ","meaning":"Khiến chất lỏng vô tình chảy ra khỏi vật chứa và tràn ra một bề mặt."},"2760":{"word":"đổ, tràn ra","meaning":"Một lượng lớn chất lỏng hoặc nhiều vật nhỏ đột ngột rơi xuống hoặc chảy ra mạnh mẽ từ một vật nào đó."},"2761":{"word":"viết","meaning":"Hành động tạo ra chữ cái, từ và câu trên giấy hoặc màn hình bằng bút hoặc bàn phím để tạo thành văn bản nhìn thấy được."},"2762":{"word":"được viết","meaning":"Các dấu hiệu như chữ cái hoặc ký hiệu được hình thành trên một bề mặt."},"2763":{"word":"được dùng, được sử dụng","meaning":"Một vật liệu hoặc món đồ được đưa vào phục vụ để đạt được một mục đích nào đó."},"2764":{"word":"quét","meaning":"Làm sạch bề mặt bằng cách dùng dụng cụ như chổi đẩy bụi bẩn hoặc các vật lỏng lẻo đi."},"2765":{"word":"hạt","meaning":"Một phần nhỏ, cứng của cây có khả năng phát triển thành cây mới."},"2766":{"word":"mỗi, từng","meaning":"Hậu tố này biểu thị các mục được phân phối hoặc hành động được thực hiện theo từng lượng riêng biệt, giống nhau."},"2767":{"word":"em bé","meaning":"Một đứa trẻ sơ sinh hoặc còn rất nhỏ, thường được bế hoặc nằm trong nôi."},"2768":{"word":"tiết kiệm, dành dụm","meaning":"Giữ lại một thứ gì đó, như tiền bạc hoặc tài nguyên, thay vì tiêu xài hay sử dụng hết, để nó vẫn còn có sẵn."},"2769":{"word":"không, không phải","meaning":"Một từ hoặc âm thanh dùng trong giao tiếp đời thường để thể hiện sự không đồng ý hoặc từ chối điều gì đó."},"2770":{"word":"tầng dưới","meaning":"Tầng lầu của một tòa nhà nằm ngay bên dưới tầng mà một người đang đứng."},"2771":{"word":"người dưới quyền","meaning":"Người có địa vị hoặc chức vụ thấp hơn người khác, hoặc làm việc dưới sự chỉ đạo của người khác."},"2772":{"word":"nhà dưới","meaning":"Ngôi nhà hoặc căn hộ ở tầng dưới của một tòa nhà, hoặc nhà ở phía dưới (dọc theo dốc, v.v.) so với nhà mình."},"2773":{"word":"tiếc, đáng tiếc","meaning":"Cảm thấy buồn hoặc tiếc nuối vì một điều tốt đẹp sắp kết thúc, hoặc một mong muốn không được thỏa mãn trọn vẹn."},"2774":{"word":"châu Á","meaning":"Lục địa lớn nhất trên Trái Đất, nằm chủ yếu ở phần phía đông và phía bắc bán cầu, là nơi có nhiều quốc gia."},"2775":{"word":"em bé, đứa trẻ","meaning":"Một người còn nhỏ, chưa trưởng thành, thường đang chơi hoặc học tập."},"2776":{"word":"ôi trời, ái chà","meaning":"Tiếng kêu thốt ra đột ngột để biểu lộ sự ngạc nhiên, đau đớn, hoặc lo lắng sâu sắc."},"2777":{"word":"ý tưởng","meaning":"Một kế hoạch, đề xuất hoặc cách làm mới nảy sinh trong tâm trí của ai đó."},"2778":{"word":"bữa sáng, cơm sáng","meaning":"Bữa ăn đầu tiên mà một người ăn sau khi thức dậy vào buổi sáng."},"2779":{"word":"sáng tối, sáng và tối","meaning":"Khoảng thời gian mặt trời mọc và khoảng thời gian mặt trời lặn, được coi là cùng nhau."},"2780":{"word":"châu Phi","meaning":"Một lục địa rất lớn nằm ở phía nam châu Âu, nổi tiếng với phong cảnh và động vật hoang dã đa dạng."},"2781":{"word":"nỗi đau, sự đau đớn","meaning":"Cảm giác khó chịu về thể chất gây ra sự không thoải mái hoặc phiền muộn, thường cảm thấy khi một bộ phận cơ thể bị thương hoặc bệnh."},"2782":{"word":"thứ chín","meaning":"Vị trí đứng ngay sau thứ tám trong một chuỗi số hoặc danh sách."},"2783":{"word":"bắt tay","meaning":"Hành động nắm tay nhau giữa hai người, thường là để chào hỏi, tạm biệt hoặc thể hiện sự đồng ý."},"2784":{"word":"khoa mắt","meaning":"Khoa chuyên chữa trị các bệnh hoặc tổn thương liên quan đến mắt."},"2785":{"word":"sách hướng dẫn","meaning":"Ấn phẩm nhỏ cung cấp thông tin, chỉ dẫn về một địa điểm, sản phẩm hoặc hoạt động."},"2786":{"word":"người hướng dẫn","meaning":"Người có nhiệm vụ chỉ dẫn cho khách tham quan hoặc hướng dẫn mọi người đến chỗ ngồi."},"2787":{"word":"bảng hướng dẫn","meaning":"Tấm bảng dùng để đăng các thông báo hoặc thông tin về một điều gì đó."},"2788":{"word":"phòng ngủ chính","meaning":"Căn phòng chính trong nhà, nơi chủ nhà hoặc cặp vợ chồng ngủ."},"2789":{"word":"lời hỏi thăm","meaning":"Lời nói dùng để hỏi thăm hoặc thể hiện sự quan tâm đến sức khỏe, hạnh phúc hoặc tình trạng hiện tại của một người."},"2790":{"word":"sắc mặt","meaning":"Màu sắc và vẻ bề ngoài tự nhiên của làn da trên khuôn mặt, có thể thay đổi tùy theo sức khỏe hoặc tâm trạng."},"2791":{"word":"sự an tâm","meaning":"Cảm giác thoải mái và an toàn khi sự lo lắng hoặc sợ hãi đã được loại bỏ hoặc giảm bớt."},"2792":{"word":"thuốc nhỏ mắt","meaning":"Dạng thuốc lỏng được nhỏ cẩn thận từ một chai nhỏ vào mắt để điều trị kích ứng hoặc bệnh."},"2793":{"word":"dây an toàn","meaning":"Dải vật liệu được thắt ngang cơ thể người trong ô tô hoặc máy bay để giữ chặt người đó ở vị trí."},"2794":{"word":"sự ổn định","meaning":"Trạng thái mà một vật giữ được thăng bằng và vững chắc, không rung lắc, di chuyển hoặc đổ."},"2795":{"word":"không","meaning":"Từ dùng để phủ định một hành động, sự việc hoặc tình trạng."},"2796":{"word":"trứng","meaning":"Vật nhỏ có vỏ bao bọc, do các loài chim, bò sát, côn trùng đẻ ra, bên trong chứa con non đang phát triển."},"2797":{"word":"dị ứng","meaning":"Phản ứng mạnh của cơ thể với một số chất lạ như phấn hoa, bụi hoặc thức ăn, gây ra các triệu chứng như hắt hơi, phát ban hoặc sưng tấy."},"2798":{"word":"được biết đến","meaning":"Thông tin hoặc sự thật lan truyền rộng rãi để nhiều người biết đến."},"2799":{"word":"tìm ra","meaning":"Thành công tìm kiếm hoặc điều tra để biết được thông tin cụ thể hoặc sự thật bị ẩn giấu."},"2800":{"word":"nghe hiểu","meaning":"Hiểu được ý nghĩa của lời nói hoặc thông điệp đã được truyền đạt."},"2801":{"word":"ung thư","meaning":"Một căn bệnh nguy hiểm do các tế bào bất thường phát triển nhanh và không kiểm soát trong cơ thể, thường hình thành khối u và làm tổn thương các cơ quan."},"2802":{"word":"Ôi! Á!","meaning":"Thán từ dùng để thể hiện sự ngạc nhiên, lo lắng hoặc cảm giác khó chịu đột ngột."},"2803":{"word":"tương lai","meaning":"Khoảng thời gian chưa đến sau thời điểm hiện tại, đại diện cho những sự kiện hoặc tình huống sắp tới."},"2804":{"word":"trước sau","meaning":"Chỉ mặt trước và mặt sau của một vật, hoặc các sự kiện xảy ra trước và sau một thời điểm."},"2805":{"word":"tóc mái","meaning":"Phần tóc trên đầu một người buông xuống phủ trán."},"2806":{"word":"nhà đối diện","meaning":"Ngôi nhà nằm ở phía đối diện hoặc trực tiếp đối mặt với một ngôi nhà khác."},"2807":{"word":"Em bé","meaning":"Một đứa trẻ con người rất nhỏ, thường là còn đang học đi học nói."},"2808":{"word":"Thú cưng","meaning":"Con vật được nuôi trong nhà để bầu bạn, giải trí chứ không phải để làm việc, như chó, mèo hay chim."},"2809":{"word":"Phụ kiện","meaning":"Những món đồ nhỏ dùng để trang trí như vòng cổ, vòng tay hay hoa tai, giúp người mặc trông đẹp hơn."},"2810":{"word":"Khung ảnh","meaning":"Một khung phẳng, thường làm bằng gỗ, kim loại hoặc nhựa, dùng để giữ và trưng bày ảnh hoặc tác phẩm nghệ thuật."},"2811":{"word":"Cảnh đêm","meaning":"Cảnh vật hiện ra khi nhìn một thành phố hoặc phong cảnh sau khi trời tối, thường có nhiều ánh đèn lấp lánh."},"2812":{"word":"Làm thêm giờ","meaning":"Việc ở lại nơi làm việc và thực hiện công việc trong thời gian dài sau giờ làm việc bình thường."},"2813":{"word":"Ngoài trời","meaning":"Khu vực không nằm trong tòa nhà, nơi mọi người có thể cảm nhận trực tiếp ánh nắng hoặc gió."},"2814":{"word":"Sơ đồ đường đi","meaning":"Một bản vẽ phác thảo chỉ đường đến một địa điểm, làm nổi bật các con đường chính và tòa nhà quan trọng."},"2815":{"word":"Dược phẩm","meaning":"Các chất được bào chế dưới dạng viên, chất lỏng hoặc kem mà con người dùng để chữa bệnh, giảm đau hoặc duy trì sức khỏe."},"2816":{"word":"Cừu","meaning":"Động vật nuôi ở nông trại có lớp lông dày, mềm, thường được nuôi để lấy lông, thịt hoặc sữa."},"2817":{"word":"Cả hai","meaning":"Từ dùng để chỉ hai phần hoặc vật đối diện nhau, như bên trái và bên phải."},"2818":{"word":"Lượng","meaning":"Tổng số đo hoặc phần của một cái gì đó, như thể tích chất lỏng hoặc số lượng vật phẩm."},"2819":{"word":"gia vị","meaning":"Vật dùng để nêm nếm thức ăn cho ngon hơn."},"2820":{"word":"dương lịch","meaning":"Hệ thống tính ngày tháng, năm dựa trên chu kỳ chuyển động của Trái Đất quanh Mặt Trời."},"2821":{"word":"bắp cải","meaning":"Một loại rau có lá dày cuộn thành búp tròn, thường dùng để nấu ăn."},"2822":{"word":"nhường nhịn","meaning":"Hành động để người khác làm trước, hoặc cho người khác cái mình đang có."},"2823":{"word":"ô che nắng","meaning":"Vật dụng giống ô nhưng dùng để che nắng, tạo bóng râm."},"2824":{"word":"định dạng","meaning":"Một cách sắp xếp hoặc phương pháp đã định sẵn để trình bày thông tin."},"2825":{"word":"hai bên","meaning":"Hai phía hoặc vị trí nằm trực tiếp cạnh một vật."},"2826":{"word":"cả hai","meaning":"Hai phần hoặc khu vực riêng biệt thuộc một cặp."},"2827":{"word":"hành tây","meaning":"Một loại rau củ hình tròn, có mùi hăng đặc trưng, thường dùng làm gia vị."},"2828":{"word":"đứa bé này","meaning":"Từ gọi tắt để chỉ một đứa trẻ đang có mặt hoặc đang được nói đến."},"2829":{"word":"-ngữ","meaning":"Hậu tố kết hợp với tên quốc gia hoặc dân tộc để chỉ ngôn ngữ của họ."},"2830":{"word":"vi phạm","meaning":"Cố ý không tuân theo một quy tắc, luật lệ hoặc thỏa thuận đã được đặt ra."},"2831":{"word":"lúc nào không hay","meaning":"Diễn tả việc xảy ra hoặc thay đổi một cách nhanh chóng, không ngờ tới."},"2832":{"word":"làm thế nào","meaning":"Tình trạng không biết phải làm gì hay xử lý tình huống như thế nào."},"2833":{"word":"khó khăn","meaning":"Tình huống hoặc công việc đòi hỏi nhiều nỗ lực, kỹ năng hoặc sức lực để vượt qua hoặc hoàn thành."},"2834":{"word":"ôi","meaning":"Thán từ dùng để bày tỏ sự ngạc nhiên, sốc hoặc nhận ra điều gì đó đột ngột."},"2835":{"word":"hôm qua","meaning":"Ngày lịch đầy đủ ngay trước ngày lịch hiện tại."},"2836":{"word":"chóng mặt","meaning":"Cảm giác đầu quay cuồng như sắp mất thăng bằng hoặc ngã xuống."},"2837":{"word":"từ vựng","meaning":"Toàn bộ tập hợp các từ được sử dụng trong một ngôn ngữ cụ thể hoặc bởi một người khi nói hoặc viết."},"2838":{"word":"hừm","meaning":"Âm thanh phát ra khi thở mạnh để thể hiện sự nhẹ nhõm, thất vọng hoặc kiệt sức."},"2839":{"word":"đồi","meaning":"Vùng đất cao hơn mặt đất xung quanh một chút, dốc như một ngọn núi nhỏ."},"2840":{"word":"vết bẩn","meaning":"Dấu vết có thể nhìn thấy hoặc vùng bị đổi màu còn lại trên bề mặt, thường do chất lỏng đổ hoặc bụi bẩn."},"2841":{"word":"nhanh chóng","meaning":"Thực hiện hành động ngay lập tức và không chậm trễ."},"2842":{"word":"một lượng nào đó","meaning":"Tình trạng không có nhiều về số lượng hoặc mức độ."},"2843":{"word":"cõng","meaning":"Mang hoặc ẵm một người nào đó trên lưng mình bằng cách giữ bằng tay hoặc buộc bằng thứ gì đó."},"2844":{"word":"công việc","meaning":"Những hoạt động hoặc nhiệm vụ cụ thể mà một người thực hiện thường xuyên như một phần của việc làm hoặc trách nhiệm của họ."},"2845":{"word":"loại bỏ","meaning":"Làm cho một thứ gì đó không còn tồn tại hoặc không còn hiện diện nữa, thường là bằng cách loại bỏ hoàn toàn."},"2846":{"word":"biến mất","meaning":"Một thứ gì đó không còn nhìn thấy hoặc không còn hiện diện, không thể tìm thấy được nữa."},"2847":{"word":"không có","meaning":"Diễn tả sự thiếu vắng của một sự vật, triệu chứng hoặc điều kiện nào đó."},"2848":{"word":"mấy hôm trước","meaning":"Một khoảng thời gian ngắn trong quá khứ, thường là chỉ hai hoặc ba ngày trước thời điểm hiện tại."},"2849":{"word":"thang cuốn","meaning":"Một hệ thống bậc thang di chuyển được, dùng để đưa người lên hoặc xuống giữa các tầng trong một tòa nhà."},"2850":{"word":"nữ","meaning":"Giới tính sinh học có khả năng sinh con hoặc đẻ trứng, hoặc một người nhận dạng là phụ nữ."},"2851":{"word":"hơn","meaning":"Tiếp vị ngữ thêm vào một số để chỉ rằng số lượng thực tế lớn hơn một chút so với số đã nêu."},"2852":{"word":"thời gian rảnh rỗi","meaning":"Khoảng thời gian mà một người không bận rộn với các nhiệm vụ hàng ngày bắt buộc hoặc công việc được trả lương, cho phép họ theo đuổi sở thích cá nhân."},"2853":{"word":"nhà trọ","meaning":"Một tòa nhà hoặc cơ sở cung cấp chỗ ngủ tạm thời và đôi khi là bữa ăn cho du khách với một khoản phí."},"2854":{"word":"coi như","meaning":"Suy nghĩ về ai đó hoặc điều gì đó theo một cách cụ thể hoặc có một ý kiến nhất định về họ."},"2855":{"word":"thứ tám","meaning":"Từ dùng để chỉ vị trí hoặc thứ tự đứng sau thứ bảy trong một dãy số hoặc chuỗi."},"2856":{"word":"mụn trứng cá","meaning":"Tình trạng viêm da nhỏ thường xuất hiện ở tuổi dậy thì, kèm theo sưng đỏ trên mặt, cơ thể."},"2857":{"word":"mùa hè","meaning":"Khoảng thời gian nóng nhất trong năm, thường kéo dài từ mùa xuân đến mùa thu, đặc trưng bởi ngày dài và nhiệt độ cao."},"2858":{"word":"kì nghỉ hè","meaning":"Khoảng thời gian nghỉ ngơi từ công việc hoặc học tập, thường vào những tháng nóng nhất, để thư giãn hoặc du lịch."},"2859":{"word":"mình ơi","meaning":"Từ dùng để gọi vợ hoặc chồng một cách thân mật, yêu thương."},"2860":{"word":"thứ sáu","meaning":"Từ dùng để chỉ vị trí hoặc thứ tự đứng sau thứ năm trong một dãy số hoặc chuỗi."},"2861":{"word":"sự dư dả","meaning":"Trạng thái có thêm thời gian, tiền bạc hoặc không gian mà không cần dùng đến ngay."},"2862":{"word":"dư dả; thong thả","meaning":"Có đủ thời gian hoặc nguồn lực để làm việc gì đó nên tỏ ra bình tĩnh và không vội vàng."},"2863":{"word":"người phụ nữ","meaning":"Một người thuộc giới tính nữ đã trưởng thành."},"2864":{"word":"hỏi (kính ngữ); thưa hỏi","meaning":"Đặt câu hỏi với người lớn tuổi hoặc cấp trên một cách kính trọng."},"2865":{"word":"nhà sử học","meaning":"Người có công việc nghiên cứu và viết về các sự kiện và con người từ các thời đại trước."},"2866":{"word":"mang tính lịch sử","meaning":"Liên quan đến quá khứ và có ý nghĩa quan trọng trong việc tìm hiểu lịch sử nhân loại."},"2867":{"word":"vai trò","meaning":"Là vị trí, chức năng hay nhiệm vụ mà một người hoặc một vật đảm nhận trong một hệ thống hoặc tình huống cụ thể."},"2868":{"word":"hằng năm","meaning":"Chỉ một điều gì đó xảy ra hoặc được tính toán trong suốt thời gian của một năm."},"2869":{"word":"thuốc mỡ","meaning":"Là một chất mềm, mịn được xoa lên da để chữa lành hoặc bảo vệ vết thương."},"2870":{"word":"nghiên cứu","meaning":"Là quá trình điều tra kỹ lưỡng và có hệ thống để khám phá thông tin hoặc hiểu biết mới."},"2871":{"word":"sự hoãn","meaning":"Là hành động trì hoãn một sự kiện, kế hoạch hoặc thời hạn đến một ngày sau đó hoặc một thời điểm không xác định trong tương lai."},"2872":{"word":"diễn xuất","meaning":"Là kỹ năng hoặc màn trình diễn của một người thể hiện nhân vật trong một vở kịch, phim ảnh hoặc chương trình bằng cách sử dụng giọng nói, cơ thể và cảm xúc của họ."},"2873":{"word":"màu xanh lá mạ","meaning":"Là màu xanh nhạt gần với màu vàng, giống như màu của mầm lúa non hoặc hạt đậu."},"2874":{"word":"người yêu","meaning":"Là hai người có tình cảm đặc biệt dành cho nhau, thường được nhìn thấy bên nhau."},"2875":{"word":"sự gia hạn","meaning":"Là hành động làm cho một điều gì đó kéo dài thêm thời gian hoặc phạm vi."},"2876":{"word":"biểu diễn","meaning":"Là hoạt động tạo ra âm nhạc bằng cách chơi một nhạc cụ hoặc hát một bài hát cho mọi người nghe."},"2877":{"word":"buổi hòa nhạc","meaning":"Là một buổi tụ tập công khai nơi các nhạc công hoặc ca sĩ tạo ra âm nhạc để nhiều người thưởng thức."},"2878":{"word":"mềm","meaning":"Mô tả thứ gì đó mềm mại khi chạm vào, dễ nhai hoặc dễ uốn cong mà không bị gãy."},"2879":{"word":"kết trái","meaning":"Cây hoặc cây ăn quả tạo ra quả."},"2880":{"word":"móc chìa khóa","meaning":"Một vòng nhỏ hoặc chuỗi dùng để giữ nhiều chìa khóa lại với nhau."},"2881":{"word":"thứ mười","meaning":"Vị trí trong một dãy hoặc chuỗi ngay sau thứ chín."},"2882":{"word":"số không","meaning":"Kí hiệu số học chỉ sự không có gì hoặc không có số lượng."},"2883":{"word":"thông minh","meaning":"Có khả năng hiểu nhanh những ý tưởng khó và giải quyết vấn đề dễ dàng."},"2884":{"word":"video","meaning":"Một bản ghi hình ảnh chuyển động và thường có âm thanh, được hiển thị trên màn hình."},"2885":{"word":"trên không độ","meaning":"Nhiệt độ cao hơn điểm đóng băng của nước."},"2886":{"word":"dinh dưỡng","meaning":"Các chất cần thiết mà sinh vật hấp thụ từ thức ăn để phát triển, khỏe mạnh và có năng lượng."},"2887":{"word":"chất bổ sung dinh dưỡng","meaning":"Một loại thuốc viên hoặc chất lỏng được uống để bổ sung các chất cần thiết cho cơ thể mà có thể thiếu trong chế độ ăn uống thông thường."},"2888":{"word":"anh hùng","meaning":"Một người thể hiện lòng dũng cảm lớn và làm những việc anh dũng mà người khác ngưỡng mộ và kính trọng."},"2889":{"word":"mãi mãi","meaning":"Trong suốt mọi thời gian, không có kết thúc hay dừng lại."},"2890":{"word":"ảnh hưởng","meaning":"Tác động mạnh mẽ mà một điều gì đó gây ra đối với điều khác hoặc người khác, tạo ra sự thay đổi rõ rệt."},"2891":{"word":"ví dụ","meaning":"Một trường hợp hoặc tình huống cụ thể được dùng để minh họa cho một quy tắc, ý tưởng chung."},"2892":{"word":"phép lịch sự","meaning":"Cách cư xử thể hiện sự tôn trọng và quan tâm đến người khác trong các tình huống xã hội."},"2893":{"word":"tiền gửi","meaning":"Hành động giao phó tiền cho một tổ chức tài chính như ngân hàng, hoặc số tiền đó."},"2894":{"word":"phòng ngừa","meaning":"Hành động thực hiện các bước để ngăn chặn điều gì đó có hại hoặc không mong muốn xảy ra."},"2895":{"word":"dự báo","meaning":"Một thông báo mô tả những gì có khả năng xảy ra trong tương lai dựa trên thông tin hiện tại."},"2896":{"word":"dự kiến","meaning":"Một niềm tin hoặc suy nghĩ mạnh mẽ về những gì sẽ xảy ra hoặc cách ai đó sẽ hành động."},"2897":{"word":"hội trường cưới","meaning":"Một tòa nhà hoặc căn phòng lớn được trang trí đặc biệt nơi một cặp đôi tổ chức lễ cưới."},"2898":{"word":"lễ nghi","meaning":"Cách cư xử và nói chuyện đúng mực, tôn trọng khi tương tác với người khác trong xã hội."},"2899":{"word":"phép tắc","meaning":"Tập hợp các quy tắc và phong tục được chấp nhận về cách mọi người nên cư xử và nói chuyện trong các tình huống xã hội khác nhau để thể hiện sự tôn trọng."},"2900":{"word":"lịch trình","meaning":"Một sự sắp xếp cụ thể hoặc một sự kiện đã được định sẵn sẽ diễn ra vào một thời điểm hoặc địa điểm nhất định trong tương lai."},"2901":{"word":"dự đoán","meaning":"Nêu ra điều ai đó tin rằng sẽ xảy ra trong tương lai sau khi xem xét thông tin hoặc xu hướng hiện tại."},"2902":{"word":"chẳng hạn","meaning":"Từ dùng trước khi đưa ra một mục, sự kiện hoặc người cụ thể để giải thích hoặc làm rõ một ý tưởng chung."},"2903":{"word":"truyện cổ tích","meaning":"Một câu chuyện được truyền miệng qua nhiều thế hệ, thường kể về các sự kiện lịch sử, điều kỳ diệu hoặc bài học đạo đức."},"2904":{"word":"năm","meaning":"Số đếm liền sau số bốn và liền trước số sáu."},"2905":{"word":"khu vui chơi điện tử","meaning":"Một địa điểm công cộng có nhiều máy trò chơi điện tử hoạt động bằng đồng xu, nơi mọi người có thể giải trí."},"2906":{"word":"rất lâu","meaning":"Diễn tả điều gì đó tiếp diễn trong một khoảng thời gian rất dài, không kết thúc sớm."},"2907":{"word":"lâu","meaning":"Chỉ một khoảng thời gian đáng kể, có thể là nhiều phút, giờ hoặc năm."},"2908":{"word":"bên phải","meaning":"Phía tay phải của một người, đối lập với bên trái."},"2909":{"word":"vịt","meaning":"Một loài chim nước có màng chân và mỏ dẹt, thường bơi lội trên mặt nước hoặc đi lại vụng về trên cạn."},"2910":{"word":"mực ống","meaning":"Một loài động vật thân mềm sống dưới biển, có đầu rõ ràng, mười xúc tu và có thể phun mực khi bị đe dọa."},"2911":{"word":"xe máy","meaning":"Một loại xe hai bánh có động cơ và tay lái, người lái ngồi dạng chân để điều khiển, dùng để vận chuyển trên đường."},"2912":{"word":"opera","meaning":"Một loại hình nghệ thuật sân khấu mà các diễn viên hát một câu chuyện với nhạc đệm của dàn nhạc, thường mặc trang phục đặc biệt trên sân khấu."},"2913":{"word":"officetel","meaning":"Một dạng căn hộ kết hợp giữa văn phòng và chỗ ở, thường có phòng ngủ, bếp và phòng tắm."},"2914":{"word":"sự hiểu lầm","meaning":"Tình trạng một người giải thích sai những gì người khác nói hoặc làm, dẫn đến sai sót trong suy nghĩ."},"2915":{"word":"toàn bộ","meaning":"Diễn tả sự bao gồm mọi phần hoặc mọi người trong một nhóm mà không bỏ sót ai."},"2916":{"word":"toàn thân","meaning":"Chỉ tất cả các bộ phận trên cơ thể của người hay động vật, từ đầu đến chân."},"2917":{"word":"suối nước nóng","meaning":"Hồ nước tự nhiên nóng lên do chảy từ lòng đất, thường được dùng để tắm hoặc chữa bệnh."},"2918":{"word":"năm nay","meaning":"Khoảng thời gian mười hai tháng mà người nói đang sống trong đó."},"2919":{"word":"bước lên","meaning":"Đi hoặc trèo lên một vị trí cao hơn và đứng vững trên đó."},"2920":{"word":"đặt lên","meaning":"Đặt một vật từ vị trí thấp hơn lên trên một bề mặt hoặc vật khác."},"2921":{"word":"đúng đắn","meaning":"Diễn tả hành động hoặc lời nói công bằng, trung thực và phù hợp với những gì được coi là tốt và đúng mực."},"2922":{"word":"mùa hè năm nay","meaning":"Mùa nóng trong năm hiện tại, khi thời tiết trở nên ấm áp hoặc nắng nóng."},"2923":{"word":"chuyển","meaning":"Di chuyển một vật hoặc một người từ vị trí này sang một vị trí khác."},"2924":{"word":"trang phục","meaning":"Cách một người ăn mặc hoặc vẻ ngoài của họ khi mặc quần áo."},"2925":{"word":"rượu vang","meaning":"Đồ uống có cồn được làm bằng cách lên men nước nho, thường được uống trong ly có chân."},"2926":{"word":"hoàn thành","meaning":"Tình trạng một công việc, dự án hoặc tác phẩm đã được làm xong hoàn toàn và không còn gì cần phải làm thêm."},"2927":{"word":"khứ hồi","meaning":"Là chuyến đi từ một địa điểm đến một địa điểm khác rồi quay trở lại điểm xuất phát."},"2928":{"word":"ngoài","meaning":"Dùng để chỉ những thứ không thuộc về hoặc không được bao gồm trong một nhóm hay sự vật đã được nhắc đến."},"2929":{"word":"khoa ngoại","meaning":"Là bộ phận trong bệnh viện nơi các bác sĩ chuyên điều trị bệnh tật hoặc vết thương bằng cách phẫu thuật cắt vào cơ thể bệnh nhân."},"2930":{"word":"ngoại giao","meaning":"Là hoạt động quản lý các mối quan hệ và giao tiếp giữa các quốc gia khác nhau."},"2931":{"word":"nhà ngoại giao","meaning":"Là một viên chức đại diện cho đất nước mình trong các cuộc thảo luận và đàm phán với các quốc gia khác."},"2932":{"word":"ngoại hình","meaning":"Là vẻ bề ngoài của một người hay một vật, bao gồm khuôn mặt, vóc dáng và trang phục."},"2933":{"word":"ở lại qua đêm","meaning":"Là việc một người không về nhà hoặc nơi ở thường xuyên của mình để ngủ lại qua đêm."},"2934":{"word":"bên ngoài","meaning":"Là phần hoặc bề mặt phía ngoài của một vật, một công trình hay một khu vực."},"2935":{"word":"cậu","meaning":"Là anh hoặc em trai của mẹ mình."},"2936":{"word":"mợ","meaning":"Là vợ của anh hoặc em trai mẹ mình."},"2937":{"word":"ăn ngoài","meaning":"Là việc ăn một bữa tại nhà hàng hoặc nơi khác có phục vụ đồ ăn, thay vì ăn ở nhà."},"2938":{"word":"áo khoác ngoài","meaning":"Là một loại quần áo dài, dày, có tay, được mặc bên ngoài các trang phục khác để giữ ấm, đặc biệt khi ở ngoài trời lạnh."},"2939":{"word":"bà ngoại","meaning":"Mẹ của mẹ mình."},"2940":{"word":"ông ngoại","meaning":"Bố của mẹ mình."},"2941":{"word":"chân trái","meaning":"Bộ phận cuối của chân bên trái, dùng để đứng, đi và đá."},"2942":{"word":"nệm trải sàn","meaning":"Một tấm đệm dày, mềm làm bằng bông hoặc vật liệu khác, được trải trên sàn để ngủ."},"2943":{"word":"yoga","meaning":"Một phương pháp luyện tập bao gồm các tư thế thể chất, cách thở đặc biệt và thiền định để cải thiện sức khỏe thể chất và tinh thần."},"2944":{"word":"sữa chua","meaning":"Một loại thực phẩm mềm, sánh mịn được làm từ sữa lên men, thường ăn kèm với trái cây hoặc chất tạo ngọt."},"2945":{"word":"công thức nấu ăn","meaning":"Một danh sách nguyên liệu và hướng dẫn từng bước bằng văn bản để chuẩn bị một món ăn."},"2946":{"word":"phòng tắm","meaning":"Một căn phòng trong nhà có bồn cầu, bồn rửa mặt và thường có vòi hoa sen hoặc bồn tắm để rửa cơ thể."},"2947":{"word":"-dùng cho","meaning":"Hậu tố chỉ rằng một vật phẩm được thiết kế hoặc dành riêng cho một nhóm người hoặc một tình huống cụ thể."},"2948":{"word":"rồng","meaning":"Một loài vật tưởng tượng có thân hình giống rắn lớn, có sừng trên đầu và móng vuốt sắc nhọn ở bốn chân."},"2949":{"word":"lòng dũng cảm","meaning":"Phẩm chất đối mặt với nỗi sợ hãi, đau đớn hoặc nguy hiểm mà không tỏ ra yếu đuối hay muốn chạy trốn."},"2950":{"word":"tiền tiêu vặt","meaning":"Một khoản tiền nhỏ, thường được cấp định kỳ cho trẻ em hoặc học sinh, để chi tiêu cho các vật dụng cá nhân nhỏ."},"2951":{"word":"đồ dùng","meaning":"Những vật dụng cần thiết để dùng trong một hoạt động hoặc công việc cụ thể."},"2952":{"word":"giếng","meaning":"Một cái hố sâu đào xuống đất để lấy nước sinh hoạt."},"2953":{"word":"ưu tiên","meaning":"Tình trạng một việc, người hoặc hành động được xử lý trước tiên."},"2954":{"word":"ưu tú","meaning":"Mức độ kỹ năng, thành tích hoặc chất lượng cao, nổi bật hơn những thứ khác."},"2955":{"word":"tình cờ","meaning":"Xảy ra mà không có kế hoạch hay chủ đích trước, thường dẫn đến kết quả bất ngờ."},"2956":{"word":"u uất","meaning":"Trạng thái rất buồn bã và thiếu năng lượng, thường khiến người đó trở nên khép kín."},"2957":{"word":"tình bạn","meaning":"Mối quan hệ thân thiết, hỗ trợ lẫn nhau giữa những người quý mến và quan tâm sâu sắc đến nhau."},"2958":{"word":"vũ trụ","meaning":"Không gian bao la và vô tận bên ngoài bầu khí quyển của Trái Đất, chứa đựng các vì sao, hành tinh và thiên hà."},"2959":{"word":"thùng thư","meaning":"Hộp dùng để gửi hoặc nhận thư từ, bưu kiện, thường thấy trên đường phố hoặc trước nhà."},"2960":{"word":"bên phải","meaning":"Hướng hoặc phía nằm ở bên phải của một người hoặc vật."},"2961":{"word":"bưu điện","meaning":"Hệ thống hoặc dịch vụ vận chuyển và gửi nhận thư từ, bưu kiện."},"2962":{"word":"bưu phẩm","meaning":"Các tài liệu, thiệp hoặc vật phẩm nhỏ được dịch vụ bưu chính vận chuyển và gửi đến một địa chỉ cụ thể."},"2963":{"word":"hộp thư","meaning":"Một chiếc hộp nhỏ dùng để nhận thư từ, bưu phẩm, thường được treo ở tường hoặc cổng nhà."},"2964":{"word":"rẽ phải","meaning":"Hành động điều khiển phương tiện hoặc bản thân chuyển hướng sang phía bên phải."},"2965":{"word":"vận may","meaning":"Những sự việc tốt hay xấu xảy ra một cách ngẫu nhiên với một người, thường dẫn đến kết quả thuận lợi hoặc bất lợi."},"2966":{"word":"lượng vận động","meaning":"Tổng lượng hoạt động thể chất mà một người thực hiện nhằm giữ gìn sức khỏe hoặc nâng cao thể lực."},"2967":{"word":"vận động viên","meaning":"Người chuyên rèn luyện thể chất để tham gia thi đấu trong các môn thể thao như chạy, bơi hoặc chơi bóng."},"2968":{"word":"số phận","meaning":"Chuỗi các sự kiện được tin rằng sẽ xảy ra với một người, đã được định sẵn và không thể thay đổi."},"2969":{"word":"bằng lái xe","meaning":"Giấy phép do chính phủ cấp, chứng nhận một người đã vượt qua các bài kiểm tra và được phép điều khiển phương tiện giao thông."},"2970":{"word":"reo","meaning":"Phát ra âm thanh vang vọng, đặc biệt là tiếng chuông hoặc tín hiệu điện thoại."},"2971":{"word":"làm cho khóc","meaning":"Khiến ai đó rơi nước mắt, thường là do buồn bã, đau đớn hoặc cảm xúc mạnh."},"2972":{"word":"người lớn tuổi hơn","meaning":"Người có tuổi tác hoặc địa vị xã hội cao hơn, thường được mọi người tôn trọng."},"2973":{"word":"-viện","meaning":"Hậu tố thường chỉ một cơ sở chuyên biệt hoặc một tổ chức chính thức, như trường học hoặc trung tâm nghiên cứu."},"2974":{"word":"ban đầu","meaning":"Từ dùng để chỉ trạng thái hoặc bản chất của sự vật, sự việc khi chúng mới bắt đầu hoặc chưa bị thay đổi."},"2975":{"word":"căn hộ studio","meaning":"Một căn phòng nhỏ dùng để vừa ngủ, vừa sinh hoạt và thường có cả khu vực nấu ăn."},"2976":{"word":"con khỉ","meaning":"Một loài động vật giống người, có đuôi dài, mặt và mông trần, giỏi leo cây."},"2977":{"word":"nguyên nhân","meaning":"Sự việc hoặc điều kiện làm cho một điều khác xảy ra hoặc hình thành."},"2978":{"word":"tháng","meaning":"Một khoảng thời gian trong lịch, thường khoảng 30 ngày, là một trong mười hai phần tạo nên một năm."},"2979":{"word":"World Cup","meaning":"Một giải thi đấu thể thao lớn toàn cầu nơi các đội từ nhiều quốc gia khác nhau tranh tài để giành cúp vô địch."},"2980":{"word":"tiền thuê hàng tháng","meaning":"Khoản tiền trả cho chủ nhà hoặc chủ phòng định kỳ mỗi tháng để được ở hoặc sử dụng."},"2981":{"word":"chuyện gì vậy?","meaning":"Một tình huống bất ngờ làm người ta bối rối hoặc đặt câu hỏi \"Tại sao lại thế này?\"."},"2982":{"word":"thứ hạng","meaning":"Vị trí hoặc cấp bậc của một đối tượng trong một danh sách hoặc cuộc thi."},"2983":{"word":"tầng trên","meaning":"Tầng của một tòa nhà nằm ngay phía trên tầng trệt hoặc một phần khác."},"2984":{"word":"vì, quan tâm đến","meaning":"Làm việc gì đó nhằm mục đích giúp đỡ, bảo vệ hoặc mang lại lợi ích cho ai đó hoặc cái gì đó."},"2985":{"word":"đoạn văn trên","meaning":"Phần văn bản đã xuất hiện trước đó trên cùng một trang hoặc tài liệu."},"2986":{"word":"cấp trên, người lớn hơn","meaning":"Người giữ vị trí hoặc cấp bậc cao hơn người khác, thường trong môi trường làm việc hoặc xã hội."},"2987":{"word":"Du thuyền","meaning":"Một loại tàu lớn được thiết kế để chở khách đi du lịch, tham quan và giải trí trên biển hoặc sông."},"2988":{"word":"Châu Âu","meaning":"Một trong bảy châu lục trên thế giới, nằm ở bán cầu bắc, phía tây châu Á."},"2989":{"word":"Có phí","meaning":"Yêu cầu phải trả một khoản tiền để sử dụng dịch vụ hoặc được phép truy cập."},"2990":{"word":"Hài hước","meaning":"Tính chất gây cười, làm cho người khác vui vẻ hoặc bật cười."},"2991":{"word":"Di vật","meaning":"Những đồ vật cũ được để lại từ thời xa xưa, có giá trị lịch sử hoặc văn hóa."},"2992":{"word":"Di tích","meaning":"Những vết tích vật chất từ quá khứ như kiến trúc, đồ vật, cho thấy cuộc sống của người xưa."},"2993":{"word":"Địa điểm di tích","meaning":"Nơi tập trung nhiều di tích lịch sử, khảo cổ học để nghiên cứu và tham quan."},"2994":{"word":"Tỷ lệ","meaning":"Hậu tố dùng để chỉ tỷ lệ, mức độ hoặc phần trăm của một sự việc, hiện tượng."},"2995":{"word":"Ối!","meaning":"Thán từ biểu lộ sự ngạc nhiên, sợ hãi hoặc đau đớn một cách đột ngột."},"2996":{"word":"Bạc","meaning":"Một kim loại quý, có màu trắng bạc, bóng loáng, thường dùng làm đồ trang sức hoặc tiền xu."},"2997":{"word":"Âm lịch","meaning":"Hệ thống lịch dựa trên chu kỳ chuyển động của mặt trăng, khác với dương lịch."},"2998":{"word":"Giọng nói","meaning":"Tiếng nói phát ra từ miệng của con người khi nói, hát hoặc phát ra các âm điệu."},"2999":{"word":"Thức ăn","meaning":"Thứ để ăn hoặc uống vào cơ thể để duy trì sự sống và sức khỏe."},"3000":{"word":"Buổi hòa nhạc","meaning":"Một sự kiện mà các nhạc sĩ biểu diễn nhạc cụ hoặc hát cho khán giả nghe."},"3001":{"word":"Uống rượu","meaning":"Hành động uống các loại đồ uống có chứa cồn như bia, rượu vang hoặc rượu mạnh."},"3002":{"word":"Phòng cấp cứu","meaning":"Một phòng trong bệnh viện, v.v., được trang bị thiết bị sơ cứu cho bệnh nhân."},"3003":{"word":"Cổ vũ","meaning":"Hành động la hét, vỗ tay hoặc trưng bày biểu ngữ để khích lệ một đội, nghệ sĩ hoặc cá nhân."},"3004":{"word":"Ý kiến","meaning":"Suy nghĩ hoặc ý tưởng riêng của một người về một vấn đề nào đó, thường được thể hiện bằng lời nói hoặc văn bản."},"3005":{"word":"Thảo luận","meaning":"Hành động hai hoặc nhiều người cùng nói chuyện về một chủ đề để chia sẻ ý tưởng, tìm giải pháp hoặc đưa ra quyết định."},"3006":{"word":"Đây đó","meaning":"Nhiều địa điểm hoặc nơi chốn không được xác định rõ ràng."},"3007":{"word":"Có nét ngoại lai","meaning":"Mô tả điều gì đó trông, cảm thấy hoặc nghe rất khác biệt và thú vị vì nó đến từ một nơi xa lạ."},"3008":{"word":"Dẫn dắt","meaning":"Khiến một cái gì đó hoặc ai đó tiến về phía trước bằng cách nắm giữ và kéo đi, hoặc chỉ dẫn một nhóm người bằng cách cho họ biết đường đi."},"3009":{"word":"Di chuyển","meaning":"Hành động thay đổi vị trí của một người hoặc đi từ nơi này sang nơi khác."},"3010":{"word":"Lát nữa","meaning":"Vào một thời điểm trong tương lai gần, sau khi thời điểm hiện tại đã trôi qua."},"3011":{"word":"vì vậy, do đó","meaning":"Từ dùng để chỉ nguyên nhân hoặc kết quả của một sự việc đã được nói đến."},"3012":{"word":"làm như thế này","meaning":"Hành động hoặc cư xử theo một cách thức nào đó vừa được thể hiện hoặc mô tả."},"3013":{"word":"đủ thứ, đủ loại","meaning":"Từ dùng để chỉ nhiều sự vật hay vấn đề khác nhau, không liên quan đến nhau."},"3014":{"word":"sơ yếu lý lịch, CV","meaning":"Một tài liệu ghi lại thông tin cá nhân, quá trình học vấn và kinh nghiệm làm việc của một người."},"3015":{"word":"đạt được, hoàn thành, tạo thành","meaning":"Đạt được một mục tiêu hoặc ước mơ mong muốn, hoặc tạo thành một cái gì đó."},"3016":{"word":"được thực hiện, được tạo thành","meaning":"Một ước mơ hay mục tiêu trở thành hiện thực, hoặc một vật được tạo nên từ các yếu tố."},"3017":{"word":"thẻ tên, bảng tên","meaning":"Một tấm thẻ ghi tên hoặc chức danh của một người."},"3018":{"word":"phía này, lối này","meaning":"Chỉ phương hướng về phía người nói hoặc vị trí được chỉ ra."},"3019":{"word":"chừng này, đến đây (ngừng)","meaning":"Từ dùng để chỉ số lượng, mức độ hiện tại của một việc gì đó, thường mang ý nghĩa dừng lại ở đây."},"3020":{"word":"thư điện tử, email","meaning":"Một tin nhắn kỹ thuật số được gửi và nhận qua máy tính và mạng, thường chứa văn bản và tệp tin."},"3021":{"word":"hình ảnh, ấn tượng","meaning":"Một ấn tượng hoặc cảm giác về điều gì đó hiện ra trong tâm trí."},"3022":{"word":"khoa tai mũi họng","meaning":"Một phòng khám y tế nơi các bác sĩ khám và điều trị các vấn đề liên quan đến tai, mũi và họng."},"3023":{"word":"khác giới","meaning":"Người thuộc giới tính khác với mình."},"3024":{"word":"nhà hàng xóm","meaning":"Ngôi nhà nằm ngay bên cạnh hoặc rất gần nhà mình."},"3025":{"word":"tiền lãi","meaning":"Khoản tiền bổ sung phải trả khi vay hoặc được nhận khi cho vay một số tiền gốc."},"3026":{"word":"trở xuống","meaning":"Chỉ một số lượng hoặc giá trị nhỏ hơn hoặc bằng một giới hạn nhất định."},"3027":{"word":"thành thạo","meaning":"Học tập và luyện tập nhiều lần cho đến khi hiểu rõ và có thể thực hiện tốt một việc gì đó."},"3028":{"word":"dân số","meaning":"Tổng số cá thể sinh sống trong một khu vực địa lý cụ thể hoặc vùng miền."},"3029":{"word":"Ấn Độ","meaning":"Một quốc gia lớn nằm ở Nam Á, nổi tiếng với nền văn hóa đa dạng và lịch sử cổ đại."},"3030":{"word":"trà sâm","meaning":"Một loại đồ uống nóng được pha bằng cách ngâm rễ cây sâm trong nước nóng, có hương vị đất đặc trưng."},"3031":{"word":"ấn tượng","meaning":"Cảm giác hoặc hình ảnh còn đọng lại trong tâm trí bạn sau khi gặp một người hoặc trải nghiệm một điều gì đó."},"3032":{"word":"ấn tượng","meaning":"Diễn tả điều gì đó rất tốt, nổi bật hoặc khiến người khác cảm thấy ngưỡng mộ."},"3033":{"word":"cuộc đời","meaning":"Toàn bộ khoảng thời gian từ khi một người sinh ra cho đến khi họ mất, bao gồm tất cả những trải nghiệm của họ."},"3034":{"word":"in ấn","meaning":"Hành động đưa chữ hoặc hình ảnh lên giấy hoặc các bề mặt khác bằng máy móc."},"3035":{"word":"ăn liền","meaning":"Loại thức ăn, đồ uống đã được chế biến sẵn, có thể dùng ngay hoặc chỉ cần thêm nước sôi."},"3036":{"word":"lòng tốt, sự hào phóng","meaning":"Thái độ ấm áp, rộng rãi, sẵn sàng giúp đỡ và chia sẻ của con người đối với người khác."},"3037":{"word":"số người","meaning":"Tổng số người có mặt trong một nhóm hoặc một địa điểm cụ thể."},"3038":{"word":"phỏng vấn","meaning":"Buổi gặp gỡ chính thức giữa hai người, trong đó một người đặt câu hỏi để thu thập thông tin hoặc tuyển dụng."},"3039":{"word":"ngày","meaning":"Khoảng thời gian 24 giờ, hoặc khoảng thời gian có ánh sáng mặt trời."},"3040":{"word":"thứ bảy","meaning":"Chỉ vị trí hoặc thứ tự đứng ngay sau thứ sáu trong một dãy hoặc hàng."},"3041":{"word":"thông thường, bình thường","meaning":"Không có gì đặc biệt hay khác biệt, theo lẽ thường."},"3042":{"word":"tiếng Nhật","meaning":"Hệ thống từ ngữ và quy tắc được người Nhật Bản sử dụng để nói và viết."},"3043":{"word":"người Nhật","meaning":"Một người thuộc quốc tịch Nhật Bản hoặc đến từ đất nước Nhật Bản."},"3044":{"word":"cố ý, cố tình","meaning":"Làm một việc gì đó có chủ đích, có lý do rõ ràng, không phải ngẫu nhiên."},"3045":{"word":"cuộc sống hàng ngày","meaning":"Những hoạt động và thói quen mà một người thường làm mỗi ngày."},"3046":{"word":"tiếng Nhật","meaning":"Cách người dân Nhật Bản giao tiếp bằng lời nói và chữ viết."},"3047":{"word":"việc làm","meaning":"Là một vị trí hoặc công việc mà một người thực hiện để kiếm tiền."},"3048":{"word":"nhất định","meaning":"Ở một mức độ, số lượng hay tiêu chuẩn đã được xác định hoặc quy định."},"3049":{"word":"lịch trình","meaning":"Là kế hoạch chi tiết về thời gian, địa điểm và các hoạt động sẽ thực hiện trong một khoảng thời gian."},"3050":{"word":"bảng lịch trình","meaning":"Là một danh sách hoặc bảng ghi lại các sự kiện, hoạt động được sắp xếp theo thời gian cụ thể."},"3051":{"word":"bình minh","meaning":"Là hiện tượng mặt trời bắt đầu xuất hiện trên đường chân trời vào buổi sáng."},"3052":{"word":"đoàn người","meaning":"Là một nhóm người cùng đi chung với nhau đến một địa điểm nào đó."},"3053":{"word":"đọc","meaning":"Là hoạt động nhìn và hiểu ý nghĩa của các ký hiệu viết."},"3054":{"word":"nhập cảnh","meaning":"Là hành động đi vào lãnh thổ của một quốc gia khác."},"3055":{"word":"khẩu vị","meaning":"Là cảm giác muốn ăn hoặc khả năng cảm nhận hương vị thức ăn."},"3056":{"word":"phí vào cửa","meaning":"Là số tiền cần phải trả để được phép đi vào một địa điểm nào đó."},"3057":{"word":"kỳ thi tuyển sinh","meaning":"Là một bài kiểm tra để đánh giá và quyết định xem một người có đủ điều kiện vào học tại một cơ sở giáo dục hay không."},"3058":{"word":"lễ nhập học","meaning":"Là buổi lễ được tổ chức để chào đón các học sinh hoặc sinh viên mới gia nhập một cơ sở giáo dục."},"3059":{"word":"nối","meaning":"Làm cho hai hoặc nhiều vật tiếp xúc, gắn liền với nhau."},"3060":{"word":"thước kẻ","meaning":"Một dụng cụ phẳng, thẳng, có vạch số, dùng để kẻ đường thẳng hoặc đo chiều dài."},"3061":{"word":"Nào!","meaning":"Từ dùng để thúc giục ai đó bắt đầu một hành động hoặc để thu hút sự chú ý của họ."},"3062":{"word":"chữ","meaning":"Ký hiệu hoặc dấu hiệu viết dùng để biểu thị một khái niệm hoặc âm thanh trong một ngôn ngữ viết."},"3063":{"word":"xe cá nhân","meaning":"Xe ô tô thuộc sở hữu của một cá nhân, dùng cho mục đích đi lại riêng."},"3064":{"word":"tư cách","meaning":"Những điều kiện cần thiết mà một người phải đáp ứng để được công nhận phù hợp cho một vai trò hoặc hoạt động cụ thể."},"3065":{"word":"bản thân","meaning":"Chính người đó, không phải ai khác."},"3066":{"word":"con cái","meaning":"Người con do cha mẹ sinh ra và đang được nuôi dưỡng."},"3067":{"word":"tự động","meaning":"Mô tả một máy móc hoặc hệ thống tự khởi động và hoạt động mà không cần sự điều khiển trực tiếp của con người."},"3068":{"word":"tài liệu","meaning":"Những thông tin, giấy tờ hoặc vật phẩm được thu thập và sử dụng cho một mục đích cụ thể như học tập hay xây dựng."},"3069":{"word":"chỗ","meaning":"Một điểm hoặc khu vực cụ thể mà một người có thể ngồi xuống hoặc một vật gì đó có thể được đặt."},"3070":{"word":"chị em","meaning":"Mối quan hệ giữa một người phụ nữ và chị/em gái của mình."},"3071":{"word":"chi tiết","meaning":"Mô tả thông tin, kế hoạch có nhiều sự thật nhỏ, chi tiết cụ thể và điểm chính xác."},"3072":{"word":"sự tự tin","meaning":"Niềm tin vào khả năng, phẩm chất của bản thân mình hoặc vào một điều gì đó."},"3073":{"word":"tự do","meaning":"Không bị kiểm soát, ràng buộc bởi quy tắc hay giới hạn, có thể hành động, suy nghĩ theo ý muốn."},"3074":{"word":"màu tím","meaning":"Một màu tối được tạo ra bằng cách pha trộn ánh sáng đỏ và xanh lam, thường thấy ở nho hoặc hoa."},"3075":{"word":"việc soạn thảo","meaning":"Hành động tạo ra một tài liệu, báo cáo hoặc thư chính thức bằng cách đưa từ ngữ và thông tin lên trang giấy hoặc màn hình."},"3076":{"word":"chú","meaning":"Em trai của bố."},"3077":{"word":"thím","meaning":"Vợ của em trai bố."},"3078":{"word":"nhà chú thím","meaning":"Ngôi nhà nơi chú (em trai của bố) và thím (vợ của chú) sinh sống."},"3079":{"word":"tiền lẻ","meaning":"Khoản tiền nhỏ, thường là tiền xu hoặc tờ bạc mệnh giá thấp, được trả lại cho khách sau khi thanh toán."},"3080":{"word":"bãi cỏ","meaning":"Một khu đất trống được bao phủ bởi nhiều cây cỏ xanh ngắn, thường được cắt tỉa gọn gàng."},"3081":{"word":"khóa","meaning":"Dùng chìa khóa hoặc chốt để cố định cửa, cửa sổ hoặc vật chứa, ngăn không cho mở ra."},"3082":{"word":"bị khóa","meaning":"Tình trạng cửa hoặc cửa sổ đã được chốt khóa, không thể mở ra bằng cách đẩy hoặc kéo."},"3083":{"word":"đồ ngủ","meaning":"Đồ ngủ là quần áo mềm mại, thoải mái mà người ta mặc khi đi ngủ."},"3084":{"word":"ăn thịt, săn mồi","meaning":"Ăn thịt là hành động một con vật săn bắt và ăn một con vật khác để sống."},"3085":{"word":"bị bắt, bị tóm","meaning":"Bị bắt là khi một người bị người khác giữ lại, thường là vì họ đã làm sai điều gì đó."},"3086":{"word":"-trường, -sân, -chỗ","meaning":"Hậu tố này chỉ một khu vực mở hoặc một địa điểm nơi một hành động hoặc sự kiện cụ thể diễn ra."},"3087":{"word":"ưu nhược điểm","meaning":"Ưu nhược điểm là những mặt tốt và mặt xấu của một người hoặc một sự vật."},"3088":{"word":"tương lai","meaning":"Tương lai là tất cả thời gian sẽ xảy ra sau hiện tại."},"3089":{"word":"tang lễ, đám tang","meaning":"Tang lễ là một loạt các nghi thức được tổ chức cho người đã khuất, bao gồm việc chôn cất hoặc hỏa táng."},"3090":{"word":"mùa mưa","meaning":"Mùa mưa là khoảng thời gian trong năm khi mưa lớn kéo dài nhiều ngày liên tục."},"3091":{"word":"cảnh","meaning":"Cảnh là một khoảnh khắc cụ thể hoặc một phần của vở kịch, bộ phim hoặc sự kiện đời thực có thể nhìn thấy."},"3092":{"word":"hoa hồng","meaning":"Hoa hồng là một loài cây phổ biến có thân gai và hoa thơm, thường có màu đỏ, hồng hoặc trắng, được trồng trong vườn."},"3093":{"word":"trường thọ, sống lâu","meaning":"Trường thọ là trạng thái sống qua một số năm rất dài."},"3094":{"word":"vật trang trí, đồ trang trí","meaning":"Vật trang trí là một đối tượng hoặc đặc điểm được thêm vào cái gì đó để làm cho nó trông hấp dẫn hoặc đẹp hơn."},"3095":{"word":"ưu điểm","meaning":"Một đặc tính tốt hay vượt trội giúp cái gì đó trở nên tốt hơn hoặc thành công hơn."},"3096":{"word":"học bổng","meaning":"Khoản tiền được trao cho học sinh, sinh viên để hỗ trợ việc học tập, thường là do có thành tích học tập tốt."},"3097":{"word":"đo","meaning":"Dùng dụng cụ như thước hoặc cân để tìm ra kích thước, số lượng hoặc trọng lượng chính xác của cái gì đó."},"3098":{"word":"áo khoác","meaning":"Loại áo mặc bên ngoài, ngắn, có tay và mở phía trước."},"3099":{"word":"sự theo học","meaning":"Trạng thái là học sinh, sinh viên chính thức và đang theo học tại một trường học hay đại học."},"3100":{"word":"tái chế","meaning":"Hành động biến đổi các vật phẩm đã qua sử dụng như giấy hoặc nhựa thành sản phẩm mới thay vì vứt bỏ chúng."},"3101":{"word":"mứt","meaning":"Món phết ngọt làm từ trái cây, thường được nấu với đường, mọi người thường phết lên bánh mì hoặc bánh mì nướng."},"3102":{"word":"người kia","meaning":"Một cách gọi thân mật hoặc chỉ người đang đứng ở đằng kia."},"3103":{"word":"này","meaning":"Từ cảm thán dùng để thu hút sự chú ý của người khác hoặc để ngập ngừng trước khi nói."},"3104":{"word":"chiều tối","meaning":"Khoảng thời gian trong ngày khi mặt trời lặn và bầu trời bắt đầu tối, ngay trước khi màn đêm buông xuống."},"3105":{"word":"làm thế","meaning":"Thực hiện một hành động hoặc cư xử theo một cách vừa được chỉ ra hoặc đề cập."},"3106":{"word":"rẻ","meaning":"Giá bán của một thứ gì đó thấp, không tốn nhiều tiền để mua."},"3107":{"word":"cái cân","meaning":"Thiết bị dùng để đo trọng lượng của vật."},"3108":{"word":"tác giả","meaning":"Người đã viết một tác phẩm như sách, bài báo hay kịch."},"3109":{"word":"sự tiết kiệm","meaning":"Hành động giữ lại tiền, của cải bằng cách chi tiêu một cách tằn tiện."},"3110":{"word":"có tính chất","meaning":"Hậu tố gắn vào danh từ để tạo thành tính từ, biểu thị sự liên quan hoặc có tính chất giống danh từ gốc."},"3111":{"word":"ít nhất","meaning":"Dùng để chỉ số lượng hoặc mức độ nhỏ nhất có thể hoặc chắc chắn, có thể cao hơn."},"3112":{"word":"sự thích nghi","meaning":"Hành động thay đổi hành vi hoặc cơ thể để phù hợp với tình huống hoặc môi trường mới."},"3113":{"word":"được ghi","meaning":"Chữ, số hoặc ký hiệu xuất hiện trên bề mặt như giấy, do bút hoặc công cụ tương tự tạo ra."},"3114":{"word":"toàn quốc","meaning":"Toàn bộ diện tích đất đai hoặc toàn bộ lãnh thổ của một quốc gia."},"3115":{"word":"mang tính toàn quốc","meaning":"Mô tả điều gì đó có mặt hoặc xảy ra trên khắp toàn bộ diện tích vật lý của một quốc gia."},"3116":{"word":"ngày hôm trước","meaning":"Khoảng thời gian 24 giờ ngay trước một ngày hoặc sự kiện cụ thể."},"3117":{"word":"sự chuyển giao","meaning":"Hành động đưa hoặc di chuyển vật gì đó, như một món đồ hoặc thông tin, từ người này hoặc nơi này sang người khác hoặc nơi khác."},"3118":{"word":"tầm nhìn","meaning":"Khung cảnh mà ai đó có thể nhìn thấy từ một nơi cụ thể, như một tòa nhà cao tầng hoặc một căn phòng có cửa sổ."},"3119":{"word":"chuyên môn","meaning":"Lĩnh vực mà một người có kiến thức và kinh nghiệm sâu rộng."},"3120":{"word":"chuyên gia","meaning":"Người có kiến thức, kinh nghiệm và kỹ năng sâu rộng trong một lĩnh vực cụ thể."},"3121":{"word":"cửa hàng chuyên doanh","meaning":"Cửa hàng chỉ bán một loại sản phẩm hoặc thực phẩm cụ thể."},"3122":{"word":"truyền thuyết","meaning":"Câu chuyện cổ được truyền miệng qua nhiều thế hệ, thường kể về những nhân vật anh hùng hoặc sự kiện kỳ diệu."},"3123":{"word":"hợp đồng jeonse","meaning":"Hệ thống thuê nhà đặc trưng của Hàn Quốc, người thuê trả một khoản tiền đặt cọc lớn và không phải trả tiền thuê hàng tháng."},"3124":{"word":"trưng bày","meaning":"Hành động đặt các vật phẩm như tác phẩm nghệ thuật hoặc sản phẩm ở nơi công cộng để mọi người đến xem."},"3125":{"word":"triển lãm","meaning":"Sự kiện hoặc địa điểm công cộng nơi nhiều đồ vật như tranh, tượng hoặc sản phẩm mới được trưng bày cho mọi người xem."},"3126":{"word":"dành riêng","meaning":"Dành riêng cho một người, một nhóm hoặc một mục đích cụ thể, không cho phép người khác sử dụng."},"3127":{"word":"nguồn điện","meaning":"Năng lượng hoặc nguồn cung cấp điện giúp máy móc, đèn và các thiết bị điện tử khác hoạt động."},"3128":{"word":"toàn bộ thành viên","meaning":"Tất cả các cá nhân có mặt trong một nhóm."},"3129":{"word":"điện tử","meaning":"Liên quan đến các thiết bị sử dụng dòng điện qua mạch để xử lý thông tin hoặc thực hiện chức năng."},"3130":{"word":"lò vi sóng","meaning":"Thiết bị nhà bếp dùng để làm nóng thức ăn nhanh chóng bằng sóng điện từ."},"3131":{"word":"từ điển điện tử","meaning":"Đây là thiết bị nhỏ gọn, di động dùng để tra cứu nghĩa của từ bằng kỹ thuật số."},"3132":{"word":"chiến tranh","meaning":"Đây là cuộc xung đột vũ trang quy mô lớn giữa các quốc gia hoặc nhóm, gây ra sự tàn phá."},"3133":{"word":"truyền thống","meaning":"Đây là phong tục, tín ngưỡng hoặc cách cư xử đã tồn tại lâu đời và được truyền từ thế hệ này sang thế hệ khác."},"3134":{"word":"truyền thống","meaning":"Từ này dùng để chỉ một cái gì đó dựa trên phong tục, tín ngưỡng hoặc tập quán lâu đời đã được thực hiện qua nhiều thế hệ."},"3135":{"word":"chùa","meaning":"Đây là một công trình hoặc quần thể công trình lớn, nơi các nhà sư Phật giáo sống và mọi người đến cầu nguyện."},"3136":{"word":"cúi chào","meaning":"Đây là hành động gập người hoặc cúi đầu về phía trước từ eo như một cử chỉ thể hiện sự tôn trọng, chào hỏi hoặc thờ cúng."},"3137":{"word":"câu, đoạn","meaning":"Đây là một phần nhỏ, thường được đánh số trong một chương sách hoặc đoạn nhạc, thường thấy trong các văn bản tôn giáo."},"3138":{"word":"tuyệt đối","meaning":"Từ này dùng để chỉ một cái gì đó hoàn chỉnh, toàn bộ hoặc không có bất kỳ nghi ngờ, giới hạn hay ngoại lệ nào."},"3139":{"word":"tuyệt đối không, nhất định không","meaning":"Từ này dùng để nhấn mạnh rằng một điều gì đó sẽ không bao giờ xảy ra hoặc không được phép thực hiện."},"3140":{"word":"tiết kiệm","meaning":"Đây là việc sử dụng tiền bạc, thời gian hoặc tài nguyên một cách cẩn thận để tránh lãng phí và giữ lại cho tương lai."},"3141":{"word":"người trẻ, thanh niên","meaning":"Từ này dùng để chỉ một người ở độ tuổi trẻ."},"3142":{"word":"-cửa hàng, -tiệm (hậu tố)","meaning":"Hậu tố này được thêm vào sau một từ để chỉ một tòa nhà hoặc địa điểm nơi mọi người mua sắm."},"3143":{"word":"chấm","meaning":"Một vết nhỏ, hình tròn dùng để đánh dấu."},"3144":{"word":"nhân viên bán hàng","meaning":"Người làm việc trong cửa hàng, giúp đỡ khách hàng và thu tiền."},"3145":{"word":"dần dần","meaning":"Diễn tả sự thay đổi hoặc phát triển từ từ, từng bước một qua thời gian."},"3146":{"word":"áo khoác","meaning":"Loại áo mặc bên ngoài phần thân trên, thường ngắn hơn áo khoác dài và có khóa kéo hoặc nút cài."},"3147":{"word":"tiếp nhận","meaning":"Hành động nhận các hồ sơ, giấy tờ hoặc yêu cầu từ người khác hoặc tổ chức."},"3148":{"word":"khuấy","meaning":"Dùng vật gì đó di chuyển theo vòng tròn để trộn đều chất lỏng, bột..."},"3149":{"word":"tình cảm","meaning":"Cảm giác yêu mến, gắn bó thân thiết và ấm áp dành cho một người hoặc một sinh vật nào đó."},"3150":{"word":"đáp án đúng","meaning":"Câu trả lời hoặc lời giải đúng cho một vấn đề hay câu hỏi."},"3151":{"word":"thật sự","meaning":"Dùng để nhấn mạnh rằng một điều gì đó là sự thật hoặc để tăng cường ý nghĩa của lời nói."},"3152":{"word":"thông tin","meaning":"Những dữ liệu, tin tức hoặc kiến thức thu thập được về một sự việc, hiện tượng nào đó."},"3153":{"word":"máy lọc nước","meaning":"Thiết bị dùng để làm sạch nước uống, loại bỏ các chất bẩn và độc hại để nước an toàn khi sử dụng."},"3154":{"word":"tinh thần","meaning":"Là tổng thể những suy nghĩ, tình cảm, ý chí tạo nên bản chất, thái độ của một người đối với cuộc sống hoặc một vấn đề cụ thể."},"3155":{"word":"bận tối mắt tối mũi","meaning":"Diễn tả trạng thái một người quá bận rộn hoặc choáng váng đến mức không thể suy nghĩ rõ ràng hoặc không biết mình đang làm gì."},"3156":{"word":"cuống quýt","meaning":"Diễn tả một hành động được thực hiện nhanh chóng và không có trật tự hay suy nghĩ nhiều, như thể đang rất bận rộn hoặc lo lắng."},"3157":{"word":"trưa","meaning":"Thời điểm chính xác là mười hai giờ giữa ban ngày, khi mặt trời thường ở điểm cao nhất trên bầu trời."},"3158":{"word":"số lượng quy định","meaning":"Số lượng người hoặc vật được xác định trước, giới hạn cho một tổ chức hoặc vị trí."},"3159":{"word":"tiệm thịt","meaning":"Nơi kinh doanh mà thịt tươi sống được cắt thành từng miếng và bán cho mọi người."},"3160":{"word":"âu phục","meaning":"Một bộ quần áo đồng điệu, thường là áo khoác và quần dài hoặc váy, được mặc cho các sự kiện quan trọng hoặc công việc chuyên nghiệp."},"3161":{"word":"chính trị","meaning":"Các hành động và cuộc thảo luận liên quan đến việc điều hành một quốc gia, thành phố hoặc nhóm, thường bao gồm bỏ phiếu, lập quy tắc và bầu cử lãnh đạo."},"3162":{"word":"khoa chỉnh hình","meaning":"Chuyên khoa y tế điều trị các vấn đề về xương, khớp, cơ và cột sống, như gãy xương, chấn thương hoặc đau nhức, thường bằng phẫu thuật hoặc bó bột."},"3163":{"word":"chính xác","meaning":"Theo một cách hoàn toàn đúng và không có bất kỳ sai sót nào, đạt được mục tiêu hoặc phép đo chính xác."},"3164":{"word":"thứ","meaning":"Một phần từ được đặt trước một số để chỉ vị trí của nó trong một chuỗi, ví dụ như vị trí 'thứ nhất' hoặc 'thứ hai'."},"3165":{"word":"của tôi","meaning":"Một từ rút gọn được dùng để chỉ ra rằng một vật phẩm hoặc người thuộc về người nói."},"3166":{"word":"cung cấp","meaning":"Hành động làm cho một cái gì đó có sẵn cho ai đó, như đưa cho họ một vật hoặc trình bày một ý tưởng để họ sử dụng."},"3167":{"word":"tiệm bánh mì","meaning":"Một cửa hàng sản xuất và bán bánh mì, bánh ngọt và các loại bánh nướng khác."},"3168":{"word":"đúng cách","meaning":"Theo đúng quy tắc, tiêu chuẩn hoặc hình thức được yêu cầu."},"3169":{"word":"đúng giờ","meaning":"Vào thời điểm chính xác theo lịch trình, không sớm cũng không muộn."},"3170":{"word":"đề xuất","meaning":"Một ý kiến hay kế hoạch được đưa ra để người khác xem xét hoặc thảo luận."},"3171":{"word":"nộp","meaning":"Hành động chính thức đưa một tài liệu, vật phẩm hoặc công việc cho người có thẩm quyền hoặc theo yêu cầu cụ thể."},"3172":{"word":"sản phẩm","meaning":"Một vật phẩm được làm ra, sản xuất hoặc nuôi trồng, thường để bán cho người tiêu dùng."},"3173":{"word":"điều kiện","meaning":"Những yêu cầu hoặc hoàn cảnh cụ thể cần phải có hoặc được đáp ứng để một điều gì đó xảy ra hoặc đúng."},"3174":{"word":"chạy bộ","meaning":"Hoạt động thể dục bằng cách chạy chậm với tốc độ vừa phải để duy trì sức khỏe."},"3175":{"word":"áo ghi lê","meaning":"Một loại quần áo không tay, che thân trên, thường được mặc bên ngoài áo sơ mi."},"3176":{"word":"nấu ăn","meaning":"Quá trình chuẩn bị và làm chín thức ăn bằng cách sử dụng nhiệt, như chiên, nướng hoặc luộc."},"3177":{"word":"gia vị","meaning":"Một chất như muối, tiêu, rau thơm hoặc gia vị được thêm vào thức ăn để cải thiện hoặc thay đổi hương vị."},"3178":{"word":"điều tra","meaning":"Hành động tìm kiếm thông tin hoặc kiểm tra kỹ lưỡng một vấn đề hoặc sự việc."},"3179":{"word":"tổ tiên","meaning":"Tổ tiên là những người đã sống nhiều đời trước và là nguồn gốc của chúng ta."},"3180":{"word":"lời khuyên","meaning":"Lời khuyên là những ý kiến hoặc gợi ý được đưa ra để giúp người khác quyết định hoặc giải quyết vấn đề."},"3181":{"word":"sự tôn trọng","meaning":"Sự tôn trọng là cảm giác ngưỡng mộ sâu sắc đối với ai đó vì khả năng, phẩm chất hoặc thành tựu của họ."},"3182":{"word":"buồn ngủ","meaning":"Buồn ngủ là cảm thấy mệt mỏi và muốn nhắm mắt nghỉ ngơi, thường khiến mí mắt sụp xuống."},"3183":{"word":"sinh viên tốt nghiệp","meaning":"Sinh viên tốt nghiệp là người đã hoàn thành xuất sắc chương trình học tại trường và nhận bằng cấp."},"3184":{"word":"lễ tốt nghiệp","meaning":"Lễ tốt nghiệp là một sự kiện trang trọng nơi học sinh, sinh viên nhận bằng sau khi hoàn thành chương trình học."},"3185":{"word":"tôn giáo","meaning":"Tôn giáo là một hệ thống các niềm tin và thực hành, thường liên quan đến việc thờ cúng thần linh, ảnh hưởng đến cách sống của con người."},"3186":{"word":"cốc giấy","meaning":"Cốc giấy là một vật đựng đồ uống nhẹ, dùng một lần, làm từ bìa cứng hoặc bột gỗ nén."},"3187":{"word":"cả ngày","meaning":"Cả ngày là toàn bộ khoảng thời gian từ lúc mặt trời mọc buổi sáng cho đến khi mặt trời lặn vào buổi tối."},"3188":{"word":"tổng hợp, toàn diện","meaning":"Tổng hợp mô tả một điều gì đó bao gồm nhiều phần hoặc yếu tố khác nhau, tạo thành một bộ sưu tập hoặc cái nhìn tổng thể hoàn chỉnh."},"3189":{"word":"chỗ ngồi","meaning":"Chỗ ngồi là một vị trí cụ thể được thiết kế cho một người để ngồi, thường có trong xe cộ, nhà hát hoặc khu vực công cộng."},"3190":{"word":"phía bên trái","meaning":"Phía bên trái là mặt nằm cùng hướng với phía tây khi một người quay mặt về hướng bắc."},"3191":{"word":"rẽ trái","meaning":"Hành động điều khiển phương tiện hoặc cơ thể quay về phía bên trái."},"3192":{"word":"tuần","meaning":"Khoảng thời gian liên tục gồm bảy ngày."},"3193":{"word":"trao đổi","meaning":"Cùng lúc đưa cái gì đó cho người khác và nhận lại cái gì đó từ họ."},"3194":{"word":"cư dân","meaning":"Người có nơi ở cố định trong một khu vực, thị trấn hoặc tòa nhà cụ thể."},"3195":{"word":"nhà bếp","meaning":"Nơi trong nhà hoặc tòa nhà dùng để chuẩn bị, nấu nướng và thường là rửa chén bát."},"3196":{"word":"chính yếu","meaning":"Quan trọng nhất, trung tâm nhất hoặc nổi bật nhất trong một tập hợp."},"3197":{"word":"trạm xăng","meaning":"Nơi người lái xe dừng lại để mua xăng hoặc dầu diesel cho phương tiện của mình."},"3198":{"word":"sự chú ý","meaning":"Trạng thái tập trung tinh thần, quan sát cẩn thận để tránh xảy ra điều không mong muốn."},"3199":{"word":"nhân vật chính","meaning":"Người trung tâm trong một câu chuyện, bộ phim hoặc vở kịch, là trọng tâm của mọi sự kiện."},"3200":{"word":"chủ đề","meaning":"Vấn đề trung tâm được nói đến trong một cuộc trò chuyện hoặc nghiên cứu."},"3201":{"word":"vé đậu xe","meaning":"Một loại giấy tờ cho phép phương tiện được đỗ ở một khu vực nhất định trong khoảng thời gian xác định."},"3202":{"word":"phí đậu xe","meaning":"Số tiền mà người lái xe phải trả để đỗ phương tiện của mình ở một khu vực nhất định trong một khoảng thời gian."},"3203":{"word":"cháo","meaning":"Một món ăn được làm bằng cách nấu gạo hoặc ngũ cốc với nhiều nước cho đến khi đặc lại."},"3204":{"word":"cái chết","meaning":"Khoảnh khắc sự sống của một sinh vật kết thúc hoàn toàn và cơ thể ngừng hoạt động."},"3205":{"word":"giết, giết chết","meaning":"Làm cho một sinh vật sống ngừng thở và hoạt động vĩnh viễn."},"3206":{"word":"vật dụng chuẩn bị","meaning":"Những đồ vật hoặc vật tư cần thiết được thu thập và mang theo cho một hoạt động hoặc chuyến đi cụ thể."},"3207":{"word":"nhảy dây","meaning":"Một trò chơi mà người chơi dùng dây dài quay và nhảy qua."},"3208":{"word":"sọc, kẻ sọc","meaning":"Một kiểu thiết kế hình ảnh gồm các đường song song có màu sắc hoặc sắc thái khác nhau lặp lại trên một bề mặt."},"3209":{"word":"nhà sư, sư thầy","meaning":"Người đàn ông sống đời tu hành theo giáo lý Phật giáo, thường cạo đầu và mặc áo cà sa, thường trú tại chùa."},"3210":{"word":"đã qua sử dụng, hàng cũ","meaning":"Tình trạng của một món đồ không còn mới, đã có dấu hiệu sử dụng hoặc đã cũ vì được sản xuất đã lâu."},"3211":{"word":"xe đã qua sử dụng, xe cũ","meaning":"Một chiếc ô tô đã được sử dụng trong một khoảng thời gian và có thể hơi cũ hoặc hao mòn."},"3212":{"word":"tiếng Trung Quốc","meaning":"Ngôn ngữ được nói bởi người dân ở Trung Quốc và nhiều người ở các nơi khác trên thế giới."},"3213":{"word":"người Trung Quốc","meaning":"Người có quốc tịch Trung Quốc hoặc sinh ra ở đất nước đó."},"3214":{"word":"trình độ trung cấp","meaning":"Mức độ kỹ năng hoặc kiến thức cao hơn cơ bản nhưng chưa đạt đến mức chuyên gia hoặc phát triển cao."},"3215":{"word":"sự ngừng, sự đình chỉ","meaning":"Hành động làm cho một cái gì đó ngừng hoạt động hoặc di chuyển, có thể trong một thời gian ngắn hoặc vĩnh viễn."},"3216":{"word":"miền Trung, Trung Bộ","meaning":"Khu vực địa lý nằm ở phần giữa của một vùng lớn hơn hoặc một quốc gia."},"3217":{"word":"giữa tháng","meaning":"Khoảng thời gian nằm ở giữa một tháng, thường là từ ngày 10 đến ngày 20."},"3218":{"word":"món ăn Trung Quốc, ẩm thực Trung Quốc","meaning":"Phong cách món ăn có nguồn gốc từ Trung Quốc, thường được nhận biết qua các món xào, mì và cơm."},"3219":{"word":"trung tâm, đầu não","meaning":"Một địa điểm quan trọng, thường là một thành phố, nơi có nhiều hoạt động hoặc kinh doanh diễn ra, trở thành điểm tập trung chính của một khu vực."},"3220":{"word":"xe cỡ trung","meaning":"Một loại ô tô lớn hơn xe nhỏ gọn nhưng nhỏ hơn xe cỡ lớn, được thiết kế để chở người."},"3221":{"word":"chuột","meaning":"Một loài gặm nhấm nhỏ có lông màu xám sẫm và đuôi dài, thường sống ở nơi tối tăm, gần nhà người."},"3222":{"word":"tức là, nghĩa là","meaning":"Từ được dùng khi người nói hoặc người viết giải thích một điều gì đó một cách đơn giản hơn hoặc cụ thể hơn, ngay sau câu nói đầu tiên."},"3223":{"word":"ngay lập tức, tức thì","meaning":"Xảy ra hoặc được thực hiện ngay tại thời điểm đó, không có bất kỳ sự tạm dừng hay chờ đợi nào."},"3224":{"word":"niềm vui, sự thích thú","meaning":"Một cảm xúc rất hạnh phúc thường khiến ai đó mỉm cười, cười đùa hoặc cảm thấy nhẹ nhõm."},"3225":{"word":"sự tăng lên, sự gia tăng","meaning":"Quá trình mà số lượng, kích thước hoặc con số của một thứ gì đó trở nên lớn hơn hoặc nhiều hơn."},"3226":{"word":"giấy chứng nhận, chứng chỉ","meaning":"Một mảnh giấy hoặc tài liệu chính thức xác nhận một sự thật, thành tích hoặc trình độ."},"3227":{"word":"triệu chứng","meaning":"Dấu hiệu hoặc cảm giác trên cơ thể cho thấy một bệnh tật hoặc tình trạng không khỏe."},"3228":{"word":"triệu chứng","meaning":"Những thay đổi có thể nhìn thấy hoặc cảm nhận được trên cơ thể người bệnh, cho thấy sự hiện diện và phát triển của bệnh tật."},"3229":{"word":"tri giác, nhận thức","meaning":"Khả năng hoặc quá trình nhận biết và hiểu được sự vật, hiện tượng xung quanh thông qua các giác quan."},"3230":{"word":"quá mức, thái quá","meaning":"Vượt quá giới hạn bình thường, hợp lý về số lượng, hành động hoặc chất lượng."},"3231":{"word":"ngày xưa, quá khứ","meaning":"Khoảng thời gian, sự kiện và trải nghiệm đã xảy ra trước thời điểm hiện tại."},"3232":{"word":"lặn","meaning":"Mặt trời hoặc mặt trăng dần dần khuất xuống dưới đường chân trời vào cuối ngày."},"3233":{"word":"sự hướng dẫn","meaning":"Hành động chỉ bảo, dẫn dắt, hoặc hỗ trợ ai đó trong một công việc hoặc lĩnh vực nào đó."},"3234":{"word":"chất béo","meaning":"Một chất mềm, nhờn được tìm thấy trong cơ thể động vật và một số thực phẩm, dùng để dự trữ năng lượng."},"3235":{"word":"mái nhà","meaning":"Cấu trúc che phủ phía trên cùng của một tòa nhà, bảo vệ khỏi mưa và nắng."},"3236":{"word":"khu vực, vùng","meaning":"Một phần đất hoặc địa điểm cụ thể, thường được đánh dấu bằng các đặc điểm hoặc ranh giới nhất định."},"3237":{"word":"đơn đăng ký, sự ứng tuyển","meaning":"Hành động nộp hồ sơ hoặc bày tỏ nguyện vọng tham gia vào một vị trí, tổ chức hoặc chương trình nào đó."},"3238":{"word":"bừa bộn, dơ bẩn","meaning":"Tình trạng một nơi hoặc vật có nhiều đồ đạc không mong muốn, vết bẩn hoặc không được sắp xếp gọn gàng, tạo cảm giác lộn xộn, mất vệ sinh."},"3239":{"word":"dây kéo","meaning":"Bộ phận dùng để đóng mở quần áo, túi xách, v.v., làm từ hai hàng răng kim loại hoặc nhựa có thể cài vào nhau."},"3240":{"word":"người đi làm","meaning":"Người có công việc ổn định và kiếm tiền từ việc thực hiện nhiệm vụ trong một tổ chức hoặc công ty."},"3241":{"word":"đi thẳng","meaning":"Hành động di chuyển về phía trước mà không rẽ trái hay rẽ phải."},"3242":{"word":"giấy chẩn đoán","meaning":"Văn bản do bác sĩ cấp, ghi rõ tình trạng sức khỏe của bệnh nhân sau khi khám."},"3243":{"word":"chân thành","meaning":"Tình cảm hoặc suy nghĩ thật lòng được thể hiện qua lời nói và hành động."},"3244":{"word":"khám bệnh","meaning":"Hành động bác sĩ kiểm tra cơ thể bệnh nhân để tìm ra bệnh hoặc kiểm tra sức khỏe."},"3245":{"word":"thuốc giảm đau","meaning":"Loại thuốc dùng để làm giảm bớt cơn đau nhức hoặc khó chịu về thể chất."},"3246":{"word":"vào đại học","meaning":"Việc đăng ký và bắt đầu học tại một trường đại học hoặc cao đẳng sau khi hoàn thành cấp học thấp hơn."},"3247":{"word":"tiến hành","meaning":"Sự tiếp diễn hoặc phát triển liên tục của một sự kiện hay dự án từ khi bắt đầu đến khi hoàn thành."},"3248":{"word":"người dẫn chương trình","meaning":"Người điều hành cuộc họp hoặc dẫn dắt một chương trình trên truyền hình hoặc đài phát thanh."},"3249":{"word":"chất lượng","meaning":"Đặc tính nội tại của một sự vật, chẳng hạn như thuộc tính, giá trị, công dụng hay cấp độ."},"3250":{"word":"nhặt","meaning":"Dùng ngón tay hoặc ngón chân nhặt lấy một vật nào đó lên."},"3251":{"word":"tiền thuê nhà","meaning":"Số tiền phải trả định kỳ để được ở trong một ngôi nhà hoặc căn hộ không thuộc sở hữu của mình."},"3252":{"word":"gia đình","meaning":"Một nhóm người có cùng huyết thống hoặc kết hôn với nhau, thường sống chung trong một nhà."},"3253":{"word":"sự tập trung","meaning":"Hành động dồn mọi sự chú ý và suy nghĩ vào một việc cụ thể nào đó."},"3254":{"word":"đan","meaning":"Dùng sợi để làm thành vải hoặc vật dụng như áo, khăn bằng cách đan hoặc móc."},"3255":{"word":"vắt, nặn","meaning":"Dùng tay hoặc ngón tay ấn mạnh để chất chứa bên trong chảy ra ngoài."},"3256":{"word":"-giá, -trị","meaning":"Hậu tố gắn sau số đếm để chỉ giá trị bằng tiền hoặc kích thước của một vật."},"3257":{"word":"trang","meaning":"Một mặt phẳng của vật hoặc một tờ giấy trong sách, thường có số thứ tự in trên đó."},"3258":{"word":"thẳng","meaning":"Một cách không cong hoặc không gấp khúc, theo một đường liên tục."},"3259":{"word":"khoảng, chừng","meaning":"Hậu tố gắn vào sau số đếm, thời gian hoặc vị trí để chỉ sự không chính xác, ước chừng."},"3260":{"word":"đâm, chọc","meaning":"Nhanh chóng đưa một vật nhọn, như kim hoặc dao, vào vật khác, gây ra vết hoặc lỗ nhỏ."},"3261":{"word":"chườm","meaning":"Việc đặt một miếng vải nóng hoặc lạnh, hoặc túi chườm đá lên vùng bị đau để điều trị bệnh."},"3262":{"word":"xé, làm rách","meaning":"Dùng lực kéo mạnh làm một vật bị tách ra thành nhiều mảnh riêng biệt, thường để lại các cạnh không đều."},"3263":{"word":"bị rách, rách","meaning":"Vật như giấy hay vải bị tách ra thành từng mảnh, có cạnh lởm chởm."},"3264":{"word":"xe cộ, phương tiện giao thông","meaning":"Máy móc có bánh xe và động cơ, dùng để di chuyển người hoặc hàng hóa từ nơi này đến nơi khác."},"3265":{"word":"làn đường","meaning":"Một phần của đường lớn được kẻ vạch rõ ràng, nơi các phương tiện giao thông di chuyển theo hàng."},"3266":{"word":"chuẩn bị, dọn (bàn ăn)","meaning":"Sắp xếp các món đồ hoặc món ăn một cách có tổ chức cho một mục đích cụ thể, ví dụ như dọn đồ ăn và dụng cụ lên bàn để ăn."},"3267":{"word":"thực đơn, bảng giá món ăn","meaning":"Bảng liệt kê các món ăn mà nhà hàng cung cấp và giá cả của chúng."},"3268":{"word":"sự khác biệt","meaning":"Đặc điểm hoặc phẩm chất có thể nhận thấy, cho thấy hai hoặc nhiều thứ không giống nhau."},"3269":{"word":"điểm khác biệt","meaning":"Các đặc điểm hay phẩm chất khác nhau khi so sánh hai hay nhiều vật thể."},"3270":{"word":"sự tán thành, sự đồng ý","meaning":"Việc mọi người nói \"có\" hoặc thể hiện sự chấp thuận đối với một kế hoạch, đề xuất hoặc phát biểu."},"3271":{"word":"sự tham gia","meaning":"Hành động gia nhập và có mặt trong một sự kiện, hoạt động hoặc nhóm."},"3272":{"word":"sự tham khảo","meaning":"Tài liệu, sách báo, hình ảnh dùng để tìm kiếm thông tin hoặc ý tưởng."},"3273":{"word":"dầu mè","meaning":"Chất lỏng màu nâu nhạt được chiết xuất từ hạt mè nhỏ, thường dùng làm gia vị trong ẩm thực Hàn Quốc."},"3274":{"word":"sự tham dự","meaning":"Việc một người có mặt tại một cuộc họp, lớp học hoặc sự kiện có tổ chức khác."},"3275":{"word":"cửa sổ","meaning":"Phần khoét trên tường hoặc mái nhà để lấy ánh sáng hoặc không khí."},"3276":{"word":"cạnh cửa sổ","meaning":"Vị trí ngay sát bên cửa sổ."},"3277":{"word":"nhà kho","meaning":"Tòa nhà lớn dùng để cất giữ hàng hóa hoặc vật liệu trong thời gian dài."},"3278":{"word":"quầy giao dịch","meaning":"Một ô cửa hoặc quầy nhỏ được tạo ra để giao tiếp giữa bên trong và bên ngoài, thường là để bán vé hoặc thực hiện giao dịch."},"3279":{"word":"ngoài cửa sổ","meaning":"Khu vực hoặc cảnh vật có thể nhìn thấy từ bên ngoài qua cửa sổ."},"3280":{"word":"sự xấu hổ","meaning":"Cảm giác khó chịu khi nhận ra mình đã làm điều gì đó ngớ ngẩn, thường khiến mặt đỏ bừng hoặc muốn che giấu."},"3281":{"word":"lấp đầy","meaning":"Làm cho một vật chứa hoặc không gian trở nên đầy đủ, hoặc cung cấp những gì cần thiết để hoàn thiện điều gì đó."},"3282":{"word":"cặp sách","meaning":"Loại túi đựng, thường được học sinh đeo sau lưng, dùng để chứa sách vở và đồ dùng học tập."},"3283":{"word":"chuẩn bị","meaning":"Thu thập và sắp xếp tất cả các vật dụng cần thiết cho một chuyến đi hoặc hoạt động cụ thể."},"3284":{"word":"cô gái chưa chồng","meaning":"Người phụ nữ trưởng thành chưa kết hôn."},"3285":{"word":"sự kê đơn","meaning":"Hành động hoặc công thức chỉ định thuốc để điều trị bệnh."},"3286":{"word":"đơn thuốc","meaning":"Giấy tờ ghi rõ công thức hướng dẫn pha chế thuốc để điều trị bệnh."},"3287":{"word":"sấm","meaning":"Âm thanh lớn, ầm ầm vang vọng trên bầu trời sau khi có tia chớp lóe sáng trong cơn bão."},"3288":{"word":"thiên thần","meaning":"Một sinh vật linh thiêng, thường được miêu tả có hình dáng giống người, với đôi cánh và vầng hào quang trên đầu."},"3289":{"word":"trần nhà","meaning":"Bề mặt phẳng phía trên cùng của một căn phòng."},"3290":{"word":"thiên tài","meaning":"Người có khả năng trí tuệ hoặc kỹ năng vượt trội, có thể làm được những điều phi thường mà người khác khó làm được."},"3291":{"word":"mùa","meaning":"Một trong những giai đoạn chính của năm, như xuân, hạ, thu, đông, được đánh dấu bằng sự thay đổi thời tiết và thiên nhiên."},"3292":{"word":"đường sắt","meaning":"Hệ thống đường ray bằng kim loại trên mặt đất để tàu hỏa chạy qua, nối liền các địa điểm khác nhau."},"3293":{"word":"cái nhìn đầu tiên","meaning":"Khoảnh khắc đầu tiên nhìn thấy một người hay một vật."},"3294":{"word":"tuyết đầu mùa","meaning":"Lần đầu tiên tuyết rơi và phủ trắng mặt đất vào đầu mùa đông."},"3295":{"word":"ấn tượng đầu tiên","meaning":"Cảm nhận hoặc suy nghĩ ban đầu về một người hay một vật khi gặp hoặc nhìn thấy lần đầu tiên."},"3296":{"word":"máy hút bụi","meaning":"Thiết bị điện dùng để làm sạch bằng cách hút bụi hoặc các mảnh rác nhỏ."},"3297":{"word":"cầu hôn","meaning":"Hành động một người hỏi người khác có muốn trở thành vợ hoặc chồng của mình hay không."},"3298":{"word":"thể lực","meaning":"Khả năng của cơ thể một người để thực hiện các hoạt động hoặc chống lại sự kiệt sức trong một khoảng thời gian."},"3299":{"word":"hoa văn kẻ ô","meaning":"Một kiểu hoa văn gồm các ô vuông nhỏ, thường có màu sắc xen kẽ nhau, tạo thành thiết kế trên vải hoặc các bề mặt khác."},"3300":{"word":"bị khó tiêu","meaning":"Cảm thấy khó chịu, nặng bụng do thức ăn không được tiêu hóa tốt."},"3301":{"word":"trải nghiệm","meaning":"Việc tự mình tham gia trực tiếp vào một sự kiện hay hoạt động, từ đó hình thành sự hiểu biết của bản thân."},"3302":{"word":"sơ cấp","meaning":"Giai đoạn học tập hoặc mức độ khó ban đầu, phù hợp với người mới bắt đầu."},"3303":{"word":"màu xanh lá cây","meaning":"Một trong các màu nằm giữa vàng và xanh dương, ví dụ như màu của cỏ."},"3304":{"word":"quê mùa","meaning":"Có vẻ ngoài, đặc biệt là trong trang phục hoặc phong thái, không hợp thời trang hoặc mang nét đặc trưng của vùng kém phát triển."},"3305":{"word":"súng","meaning":"Một thiết bị, thường được cầm tay, dùng để phóng các vật nhỏ, chuyển động nhanh qua nòng bằng cách sử dụng thuốc nổ."},"3306":{"word":"quay phim, chụp ảnh","meaning":"Quá trình ghi lại hình ảnh động hoặc tĩnh bằng thiết bị chuyên dụng, như quay phim hoặc chụp ảnh."},"3307":{"word":"cao cấp nhất","meaning":"Mức độ chất lượng cao nhất của một thứ gì đó."},"3308":{"word":"tốt nhất","meaning":"Kết quả tốt nhất hoặc khả quan nhất có thể, hoặc nỗ lực tối đa mà một người có thể bỏ ra."},"3309":{"word":"tối thiểu","meaning":"Mức độ, số lượng hoặc lượng nhỏ nhất có thể hoặc được cho phép."},"3310":{"word":"kỷ niệm","meaning":"Một hình ảnh, ý tưởng hoặc cảm giác từ quá khứ mà một người lưu giữ trong tâm trí."},"3311":{"word":"sự tiến cử","meaning":"Hành động giới thiệu hoặc tiến cử một người hoặc vật gì đó phù hợp với điều kiện nhất định."},"3312":{"word":"sự phỏng đoán","meaning":"Một ý kiến hoặc câu trả lời được đưa ra khi không có đủ thông tin hoặc sự thật."},"3313":{"word":"sân bóng đá","meaning":"Một khu vực rộng lớn ngoài trời, thường có cỏ, với hai khung thành ở hai đầu, nơi hai đội thi đấu bằng cách đá bóng."},"3314":{"word":"lễ hội","meaning":"Một sự kiện hoặc lễ kỷ niệm công cộng, thường có âm nhạc, đồ ăn, biểu diễn và trang trí, được tổ chức để đánh dấu một dịp đặc biệt hoặc thời điểm quan trọng."},"3315":{"word":"xuất cảnh","meaning":"Hành động một người làm thủ tục kiểm tra chính thức, như ở sân bay, để rời khỏi quốc gia hiện tại của họ."},"3316":{"word":"đầy đủ","meaning":"Ở mức độ hoặc số lượng cần thiết hoặc mong muốn, không thiếu hụt hay muốn thêm."},"3317":{"word":"say","meaning":"Tình trạng một người đã uống quá nhiều đồ uống có cồn, khiến họ cảm thấy chóng mặt, nói không rõ ràng hoặc mất thăng bằng."},"3318":{"word":"sở thích","meaning":"Khuynh hướng của tâm trí mà một người thích hoặc muốn làm, hoặc xu hướng như vậy."},"3319":{"word":"gạch, đánh dấu","meaning":"Làm cho một đường tiếp xúc với cái gì đó bằng lực, hoặc vẽ một đường như bằng bút."},"3320":{"word":"phương pháp điều trị","meaning":"Tập hợp các hành động hoặc thuốc cụ thể được bác sĩ sử dụng để giúp một người hồi phục sau bệnh tật hoặc chấn thương."},"3321":{"word":"trả, thanh toán, tổ chức","meaning":"Đưa tiền để đổi lấy hàng hóa hoặc dịch vụ, hoặc sắp xếp và thực hiện một sự kiện như lễ kỷ niệm hoặc kỳ thi."},"3322":{"word":"kích thước, số đo","meaning":"Chiều dài, chiều rộng hoặc chiều sâu cụ thể của một vật thể hoặc bộ phận cơ thể, được xác định bằng cách sử dụng một công cụ như thước đo."},"3323":{"word":"dọn dẹp, dẹp","meaning":"Di chuyển đồ vật đang lộn xộn hoặc cản đường đến đúng vị trí của chúng, làm cho khu vực gọn gàng và trống trải."},"3324":{"word":"phô mai","meaning":"Một loại thực phẩm làm từ sữa, giàu protein, được chế biến bằng cách tách chất rắn từ sữa rồi sấy khô và ủ lên men."},"3325":{"word":"ruột","meaning":"Tiền tố được thêm vào trước danh từ để chỉ mối quan hệ gia đình là ruột thịt, do sinh ra, không phải do hôn nhân hoặc nhận nuôi."},"3326":{"word":"con gái ruột","meaning":"Con gái mà mình đã sinh ra."},"3327":{"word":"ngăn, khoang","meaning":"Một không gian được chia ra và bao bọc với kích thước hoặc hình dạng nhất định trong một không gian hoặc cấu trúc lớn hơn như tòa nhà, tàu hỏa, giá sách, để phục vụ một mục đích cụ thể."},"3328":{"word":"lớn lên, to ra, trầm trọng hơn","meaning":"Trở nên lớn hơn về quy mô vật lý, số lượng hoặc tầm quan trọng, như một vật nhỏ phồng lên hoặc một tình huống leo thang."},"3329":{"word":"rèm cửa","meaning":"Một mảnh vải hoặc vật liệu khác được treo để che cửa sổ hoặc cửa ra vào, dùng để chắn ánh sáng hoặc tạo sự riêng tư."},"3330":{"word":"góc, khúc cua","meaning":"Một chỗ ngoặt hoặc khúc cua trên đường."},"3331":{"word":"hài kịch","meaning":"Một buổi biểu diễn hoặc câu chuyện, như phim hoặc kịch, sử dụng các sự kiện và trò đùa vui nhộn để khiến mọi người mỉm cười và bật cười."},"3332":{"word":"tuyến đường, lộ trình","meaning":"Một đường hoặc sắp xếp cụ thể các địa điểm mà một người theo để đi đến đâu đó hoặc thực hiện một hoạt động, như lái xe hoặc chạy bộ."},"3333":{"word":"áo khoác, áo choàng","meaning":"Một loại quần áo ấm, dài, thường dài đến đầu gối, mặc bên ngoài để bảo vệ cơ thể khỏi thời tiết lạnh."},"3334":{"word":"sân (thể thao)","meaning":"Một khu vực bằng phẳng, hình chữ nhật có vạch kẻ trên mặt đất, nơi các môn thể thao như bóng rổ hoặc quần vợt được chơi."},"3335":{"word":"chảy máu cam","meaning":"Hiện tượng máu chảy ra từ lỗ mũi của người, đôi khi do chấn thương hoặc khô mũi."},"3336":{"word":"căn hộ chung cư","meaning":"Một loại nhà ở thuộc sở hữu tư nhân trong một tòa nhà lớn, thường được dùng cho những chuyến đi nghỉ dưỡng."},"3337":{"word":"khụ khụ","meaning":"Từ mô phỏng âm thanh khi một người ho liên tục, thường để làm sạch họng."},"3338":{"word":"hát ngâm nga","meaning":"Hành động hát một bài hát bằng cách tạo ra âm thanh qua mũi và ngậm miệng lại."},"3339":{"word":"đường lớn","meaning":"Con đường rộng rãi và to lớn."},"3340":{"word":"bác","meaning":"Người anh trai của bố mình."},"3341":{"word":"bác gái","meaning":"Vợ của anh trai bố mình."},"3342":{"word":"cổ điển","meaning":"Thuộc về những tác phẩm nghệ thuật, âm nhạc hoặc văn học đã được đánh giá cao và ngưỡng mộ từ rất lâu."},"3343":{"word":"nụ hôn","meaning":"Hành động chạm môi vào người hoặc vật khác, thường để thể hiện tình yêu hoặc lời chào."},"3344":{"word":"bàn","meaning":"Một món đồ nội thất có mặt phẳng trên cùng, thường dùng để đặt đồ vật hoặc ngồi xung quanh."},"3345":{"word":"sự lên tàu/xe","meaning":"Hành động đi vào và ổn định vị trí bên trong một phương tiện lớn như máy bay, tàu hỏa hoặc tàu thủy trước khi khởi hành."},"3346":{"word":"hành khách","meaning":"Người đi trên một phương tiện như xe buýt, tàu hỏa hoặc máy bay nhưng không điều khiển hoặc làm việc trên đó."},"3347":{"word":"đưa đi, cho đi nhờ","meaning":"Đưa ai đó đi đến một nơi khác bằng phương tiện giao thông."},"3348":{"word":"làm nổ, làm vỡ","meaning":"Tác động làm cho một vật bị vỡ tung ra."},"3349":{"word":"lông, tóc","meaning":"Những sợi mềm mọc trên da của người hoặc động vật."},"3350":{"word":"phủi, rũ bỏ","meaning":"Lắc mạnh một vật để loại bỏ bụi bẩn hoặc các hạt nhỏ bám trên bề mặt."},"3351":{"word":"băng keo, băng dính","meaning":"Một dải vật liệu dài, mỏng, thường có một mặt dính, dùng để dán hoặc nối các vật lại với nhau."},"3352":{"word":"thổ","meaning":"Một chữ Hán có nghĩa là đất, được dùng để chỉ ngày thứ Bảy (토요일) trong tuần."},"3353":{"word":"thảo luận, tranh luận","meaning":"Cuộc trao đổi ý kiến về một vấn đề cụ thể, thường có nhiều quan điểm khác nhau, nhằm hiểu rõ hơn hoặc đưa ra quyết định."},"3354":{"word":"nôn, ói","meaning":"Đẩy thức ăn hoặc chất lỏng trong dạ dày ra ngoài qua miệng một cách không tự chủ."},"3355":{"word":"hoàn toàn (không)","meaning":"Dùng với từ phủ định để nhấn mạnh sự vắng mặt hoặc việc không xảy ra của một điều gì đó."},"3356":{"word":"thùng, hộp, xô","meaning":"Vật chứa hình tròn hoặc sâu, thường làm bằng nhựa hoặc kim loại, dùng để đựng chất lỏng hoặc đồ vật."},"3357":{"word":"thông tin liên lạc, truyền thông","meaning":"Việc gửi và nhận tin nhắn, thông tin hoặc tín hiệu giữa các cá nhân, địa điểm hoặc thiết bị."},"3358":{"word":"phiên dịch","meaning":"Hoạt động một người nghe một ngôn ngữ và nói lại ngay lập tức bằng một ngôn ngữ khác."},"3359":{"word":"Thống nhất","meaning":"Sự hợp nhất hai hay nhiều phần, quốc gia hoặc nhóm riêng biệt thành một thể hoàn chỉnh duy nhất."},"3360":{"word":"Mũm mĩm","meaning":"Miêu tả cơ thể của ai đó có vẻ tròn trịa và đầy đặn một cách đáng yêu, không gầy."},"3361":{"word":"Thông, dẫn","meaning":"Không khí, chất lỏng hoặc ánh sáng di chuyển tự do qua một khe hở, hoặc một con đường dẫn từ nơi này đến nơi khác."},"3362":{"word":"Năng khiếu, sở trường","meaning":"Một kỹ năng hoặc tài năng đặc biệt mà một người sở hữu và rất giỏi."},"3363":{"word":"Đặc tính, thuộc tính","meaning":"Một phẩm chất hoặc thuộc tính độc đáo giúp nhận dạng một người, vật thể hoặc địa điểm."},"3364":{"word":"Đặc điểm, nét đặc trưng","meaning":"Một phẩm chất đáng chú ý hoặc quan trọng làm cho một người, động vật hoặc vật thể khác biệt so với những thứ khác."},"3365":{"word":"Chắc chắn, không sai","meaning":"Một trạng từ dùng để khẳng định rằng điều gì đó sẽ xảy ra hoặc là đúng với sự đảm bảo tuyệt đối, không có chỗ cho nghi ngờ."},"3366":{"word":"Lúc rảnh rỗi, tranh thủ","meaning":"Làm một hoạt động từng chút một trong những khoảng thời gian ngắn khi không bận rộn với các công việc chính khác."},"3367":{"word":"Hành lá","meaning":"Một loại rau dài, mảnh, có lá xanh rỗng và gốc trắng, thường được thái nhỏ và dùng để nêm thức ăn."},"3368":{"word":"Đào, khoét","meaning":"Dùng tay hoặc công cụ để tạo ra một cái lỗ hoặc loại bỏ vật liệu khỏi mặt đất hoặc vật thể rắn khác."},"3369":{"word":"Sóng biển, sóng","meaning":"Một dải nước nhấp nhô trên bề mặt biển hoặc hồ di chuyển về phía bờ, thường có bọt trắng ở đỉnh."},"3370":{"word":"Màu xanh dương","meaning":"Một trong ba màu cơ bản, thường được liên tưởng đến bầu trời và biển cả."},"3371":{"word":"uốn","meaning":"Uốn là kiểu tóc được tạo bằng cách sử dụng hóa chất để làm cho tóc xoăn hoặc gợn sóng và giữ được lâu."},"3372":{"word":"kẹp hồ sơ","meaning":"Kẹp hồ sơ là một vật dụng cứng dùng để đựng và sắp xếp gọn gàng các giấy tờ, tài liệu."},"3373":{"word":"trạm cảnh sát","meaning":"Trạm cảnh sát là một cơ sở nhỏ của cảnh sát tại địa phương, nơi các sĩ quan công an làm nhiệm vụ hỗ trợ người dân và xử lý các vụ việc trong khu vực."},"3374":{"word":"bán hàng","meaning":"Bán hàng là hoạt động trao đổi hàng hóa hoặc dịch vụ để lấy tiền từ người mua."},"3375":{"word":"thời trang","meaning":"Thời trang là phong cách ăn mặc, phụ kiện hoặc cách thể hiện bản thân được nhiều người ưa chuộng và áp dụng tại một thời điểm nhất định."},"3376":{"word":"quần lót","meaning":"Quần lót là loại trang phục mỏng, thường rất ngắn, được mặc bên trong ở phần dưới cơ thể."},"3377":{"word":"phần trăm","meaning":"Phần trăm là một đơn vị biểu thị một số lượng hoặc tỷ lệ theo thang 100, thường được ký hiệu là %."},"3378":{"word":"trang","meaning":"Trang là một mặt của tờ giấy phẳng trong sách, tạp chí hoặc tài liệu."},"3379":{"word":"phía","meaning":"Phía là một bề mặt, một khu vực nhất định của một vật thể, một địa điểm hoặc một bên trong cuộc tranh luận."},"3380":{"word":"kén ăn","meaning":"Kén ăn là thói quen chỉ ăn một số loại thực phẩm nhất định mà không ăn đa dạng các loại khác cần thiết cho sức khỏe."},"3381":{"word":"đánh giá","meaning":"Đánh giá là hành động xem xét kỹ lưỡng để nhận định về chất lượng, mức độ quan trọng hoặc giá trị của một người hoặc một vật nào đó."},"3382":{"word":"từ bỏ","meaning":"Từ bỏ là hành động ngừng cố gắng đạt được điều gì đó, hoặc thôi không muốn sở hữu hay tuyên bố điều gì đó, nhất là khi gặp khó khăn."},"3383":{"word":"rượu vang","meaning":"Đồ uống có cồn được làm từ nước ép nho lên men."},"3384":{"word":"cái nĩa","meaning":"Dụng cụ ăn uống có cán và vài răng nhọn ở một đầu, dùng để xiên thức ăn."},"3385":{"word":"bao gồm","meaning":"Tình trạng một thứ được làm thành một phần của thứ gì đó lớn hơn hoặc một tổng số."},"3386":{"word":"thác nước","meaning":"Hiện tượng tự nhiên nơi sông hoặc suối chảy qua vách đá dốc và đổ xuống."},"3387":{"word":"bảng","meaning":"Sự sắp xếp thông tin trực quan được tổ chức thành lưới các hàng và cột, thường được vẽ hoặc in."},"3388":{"word":"dấu hiệu","meaning":"Một vật thể, biểu tượng hoặc chữ viết dễ nhìn thấy để cung cấp thông tin hoặc nhận dạng cái gì đó."},"3389":{"word":"nét mặt","meaning":"Trạng thái trên khuôn mặt thể hiện cảm xúc, suy nghĩ của một người."},"3390":{"word":"biển báo","meaning":"Một tấm bảng có dấu hiệu cụ thể để thông báo cho công chúng một sự thật nào đó."},"3391":{"word":"biểu hiện","meaning":"Hành động thể hiện hoặc truyền đạt suy nghĩ, cảm xúc hoặc ý tưởng, thường bằng lời nói, cử chỉ hoặc thay đổi trên khuôn mặt."},"3392":{"word":"keo","meaning":"Chất đặc, dính dùng để gắn kết các vật lại với nhau."},"3393":{"word":"được tháo","meaning":"Trở lại trạng thái ban đầu sau khi bị buộc, bị cột hoặc bị rối."},"3394":{"word":"chất lượng","meaning":"Các đặc tính khiến một vật trở nên tốt, xấu hoặc chấp nhận được, có thể thấy hoặc trải nghiệm khi sử dụng."},"3395":{"word":"bóng bay","meaning":"Một vật làm bằng túi lớn bơm khí nhẹ hơn không khí để bay lên cao."},"3396":{"word":"phong tục","meaning":"Thói quen hay cách cư xử truyền thống đặc trưng của một xã hội, địa phương hoặc thời gian cụ thể."},"3397":{"word":"máy in","meaning":"Thiết bị dùng để in chữ, hình ảnh hoặc bản vẽ từ máy tính ra giấy."},"3398":{"word":"nhựa","meaning":"Vật liệu tổng hợp nhẹ, bền và có thể đúc thành nhiều hình dạng, vật thể khác nhau."},"3399":{"word":"sự mệt mỏi","meaning":"Cảm giác cực kỳ kiệt sức hoặc uể oải, thường khiến một người không thể làm tốt công việc hoặc cảm thấy tràn đầy năng lượng."},"3400":{"word":"da","meaning":"Lớp bao phủ bên ngoài mềm mại của cơ thể người hoặc động vật, bảo vệ cơ thể khỏi thế giới bên ngoài."},"3401":{"word":"nghỉ mát mùa hè","meaning":"Khoảng thời gian trong những tháng nóng bức khi mọi người đi đến một nơi mát mẻ hơn để nghỉ ngơi và tận hưởng."},"3402":{"word":"tránh","meaning":"Cố gắng để những điều không mong muốn hoặc khó khăn không xảy ra với bản thân."},"3403":{"word":"thiệt hại","meaning":"Tổn thương vật chất hoặc thương tích gây ra cho người, vật hoặc địa điểm, làm giảm giá trị hoặc công dụng của nó."},"3404":{"word":"nạn nhân","meaning":"Người phải chịu thiệt hại về tính mạng, thân thể, tài sản hoặc danh tiếng."},"3405":{"word":"từng cái một","meaning":"Xử lý, đếm hoặc kiểm tra từng mục riêng biệt theo thứ tự."},"3406":{"word":"nhà trọ","meaning":"Hệ thống một người trả tiền để sống trong nhà người khác, được cung cấp phòng ngủ và thường là cả bữa ăn."},"3407":{"word":"trắng","meaning":"Màu sắc giống như tuyết mới hoặc sữa, phản chiếu tất cả các màu ánh sáng và trông sáng nhất."},"3408":{"word":"xuống xe","meaning":"Hành động rời khỏi một phương tiện giao thông như xe buýt hoặc tàu hỏa."},"3409":{"word":"ngáp","meaning":"Hành động mở miệng rộng không tự chủ, sau đó hít thở sâu khi buồn ngủ, mệt mỏi hoặc no."},"3410":{"word":"ha ha","meaning":"Âm thanh mà con người phát ra khi họ thấy điều gì đó buồn cười hoặc thú vị."},"3411":{"word":"-học","meaning":"Một hậu tố chỉ một lĩnh vực kiến thức hoặc sự nghiên cứu sâu rộng về một chủ đề cụ thể."},"3412":{"word":"khoa","meaning":"Một bộ phận cụ thể trong trường đại học hoặc cao đẳng chuyên về giảng dạy và nghiên cứu một môn học cụ thể."},"3413":{"word":"học tập","meaning":"Quá trình tiếp thu kiến thức hoặc kỹ năng mới thông qua việc đọc sách, tham gia lớp học hoặc thực hành."},"3414":{"word":"học giả","meaning":"Người có nhiều kiến thức về một chủ đề cụ thể và thường xuyên nghiên cứu chi tiết hoặc viết về nó."},"3415":{"word":"tiếng Hàn","meaning":"Hệ thống giao tiếp, cả nói và viết, được sử dụng bởi người dân Hàn Quốc."},"3416":{"word":"tiếng Hàn","meaning":"Hệ thống giao tiếp, cả nói và viết, được sử dụng bởi người dân Hàn Quốc."},"3417":{"word":"người Hàn Quốc","meaning":"Một cá nhân sinh ra ở Hàn Quốc hoặc mang quốc tịch Hàn Quốc."},"3418":{"word":"một thời gian","meaning":"Trong một khoảng thời gian giới hạn hoặc không quá dài."},"3419":{"word":"một thời","meaning":"Một khoảng thời gian nào đó trong quá khứ."},"3420":{"word":"Hán văn","meaning":"Hệ thống chữ viết truyền thống của Trung Quốc cổ đại, thường thấy trong các văn bản và tài liệu lịch sử."},"3421":{"word":"tiếng thở dài","meaning":"Hành động hít một hơi thật sâu rồi thở ra thật mạnh, thường để thể hiện sự mệt mỏi, buồn chán hoặc nhẹ nhõm."},"3422":{"word":"chữ Hán","meaning":"Ký hiệu chữ viết phức tạp có nguồn gốc từ Trung Quốc cổ đại, đại diện cho một từ hoặc ý tưởng."},"3423":{"word":"một bên","meaning":"Một phần hoặc khu vực cụ thể của một vật thể hoặc không gian, khác biệt với các phần khác."},"3424":{"word":"một lúc lâu","meaning":"Một khoảng thời gian khá dài, thường là liên tục."},"3425":{"word":"cửa hàng giảm giá","meaning":"Một cơ sở thương mại nơi sản phẩm được bán với giá thấp hơn bình thường cho khách hàng."},"3426":{"word":"đỗ","meaning":"Trạng thái đạt được tiêu chuẩn yêu cầu trong một kỳ thi, cuộc thi hoặc đơn đăng ký."},"3427":{"word":"tổng cộng","meaning":"Số tiền hoặc số lượng cuối cùng sau khi tất cả các số hoặc số lượng riêng lẻ đã được cộng lại."},"3428":{"word":"gộp lại","meaning":"Đem nhiều vật phẩm hoặc nhóm riêng lẻ kết hợp lại thành một đơn vị lớn hơn, duy nhất."},"3429":{"word":"vé máy bay","meaning":"Số tiền cụ thể mà một người phải trả để đi lại bằng máy bay từ nơi này đến nơi khác."},"3430":{"word":"giải pháp","meaning":"Hành động tìm ra một câu trả lời rõ ràng hoặc cách hiệu quả để khắc phục một vấn đề hoặc tình huống khó khăn."},"3431":{"word":"bình minh","meaning":"Hiện tượng mặt trời bắt đầu xuất hiện trên đường chân trời vào buổi sáng."},"3432":{"word":"hải sản","meaning":"Các loài động vật hoặc thực vật sống ở biển như cá, cua, nghêu, được dùng làm thức ăn."},"3433":{"word":"bãi biển","meaning":"Nơi đất liền và biển gặp nhau hoặc khu vực gần đó."},"3434":{"word":"hải sản","meaning":"Các loài sinh vật sống dưới biển có thể ăn được như cá, động vật có vỏ, dùng để chế biến món ăn."},"3435":{"word":"bãi tắm","meaning":"Khu vực bãi biển bằng phẳng, rộng lớn, dùng để tắm biển và giải trí."},"3436":{"word":"túi xách","meaning":"Một loại túi nhỏ phụ nữ thường cầm tay hoặc đeo qua vai."},"3437":{"word":"ánh nắng","meaning":"Các tia sáng và hơi ấm trực tiếp chiếu từ mặt trời xuống Trái Đất."},"3438":{"word":"-đến","meaning":"Tiếp vĩ ngữ gắn vào tên địa điểm, chỉ phương tiện hoặc người đang đi tới địa điểm đó."},"3439":{"word":"hội trường sự kiện","meaning":"Tòa nhà hoặc căn phòng lớn được chỉ định để tổ chức các sự kiện đặc biệt, buổi biểu diễn hoặc cuộc họp công cộng."},"3440":{"word":"may mắn","meaning":"Điều tốt lành hoặc may mắn xảy ra một cách ngẫu nhiên."},"3441":{"word":"nước hoa","meaning":"Chất lỏng có mùi thơm dễ chịu, thường được làm từ tinh dầu, dùng để xịt lên cơ thể hoặc quần áo."},"3442":{"word":"hướng về","meaning":"Di chuyển hoặc quay người, hoặc chỉ một vật gì đó về một hướng cụ thể hoặc một điểm đến."},"3443":{"word":"sự cho phép","meaning":"Hành động chấp thuận hoặc đồng ý với yêu cầu của ai đó, cho phép họ làm điều gì đó."},"3444":{"word":"thắt lưng","meaning":"Một dải vật liệu dài được đeo quanh eo để giữ quần áo hoặc làm vật trang trí."},"3445":{"word":"bắp đùi","meaning":"Phần thịt dày ở phía trên chân, từ hông đến đầu gối."},"3446":{"word":"lối vào","meaning":"Cánh cửa hoặc không gian mở ở phía trước nơi bạn đi vào một tòa nhà hoặc ngôi nhà."},"3447":{"word":"hiện đại","meaning":"Khoảng thời gian đang diễn ra ngay bây giờ, bao gồm các sự kiện và phong cách sống hiện tại."},"3448":{"word":"hình thái","meaning":"Vẻ bề ngoài có thể nhìn thấy hoặc cấu trúc vật lý cụ thể của một vật."},"3449":{"word":"quả óc chó","meaning":"Loại quả có vỏ cứng, bên trong là nhân béo ngậy, thường dùng làm thực phẩm."},"3450":{"word":"bí ngô","meaning":"Một loại quả lớn, tròn, vỏ cứng màu cam, thường dùng để ăn hoặc trang trí."},"3451":{"word":"số phòng","meaning":"Các chữ số hoặc chữ cái dùng để xác định một không gian cụ thể bên trong tòa nhà."},"3452":{"word":"hoặc","meaning":"Từ dùng để chỉ sự lựa chọn một trong hai hoặc nhiều điều được đưa ra."},"3453":{"word":"chịu đựng","meaning":"Phải trải qua một điều gì đó khó khăn, vất vả hoặc đau đớn nghiêm trọng."},"3454":{"word":"trang chủ","meaning":"Trang chính xuất hiện đầu tiên khi bạn truy cập một trang web trên máy tính hoặc điện thoại."},"3455":{"word":"thứ ba","meaning":"Ngày thứ ba trong tuần, sau thứ hai và trước thứ tư."},"3456":{"word":"màn hình","meaning":"Bề mặt phẳng của thiết bị điện tử như tivi, máy tính, điện thoại, nơi hiển thị hình ảnh và chữ."},"3457":{"word":"chậu hoa","meaning":"Đồ vật thường làm bằng đất sét hoặc nhựa dùng để trồng cây."},"3458":{"word":"trang điểm","meaning":"Việc sử dụng mỹ phẩm như phấn, son, kem lên mặt để thay đổi diện mạo."},"3459":{"word":"bàn trang điểm","meaning":"Loại bàn có ngăn kéo và gương, thường dùng để trang điểm hoặc làm tóc."},"3460":{"word":"hỏa hoạn","meaning":"Sự cố nguy hiểm khi lửa và khói bùng cháy nhanh chóng, gây thiệt hại hoặc phá hủy."},"3461":{"word":"tiền tệ","meaning":"Tiền giấy hoặc tiền xu mà một quốc gia chính thức sử dụng để mua bán."},"3462":{"word":"hòa giải","meaning":"Hành động chấm dứt tranh cãi và bỏ qua những cảm xúc tiêu cực đối với người khác."},"3463":{"word":"xác nhận","meaning":"Hành động kiểm tra kỹ lưỡng điều gì đó để đảm bảo nó đúng sự thật hoặc chính xác."},"3464":{"word":"hoàn tiền","meaning":"Số tiền mà cửa hàng hoặc công ty trả lại cho bạn khi bạn trả lại hàng hoặc hủy dịch vụ."},"3465":{"word":"kỳ ảo","meaning":"Mô tả một điều gì đó rất tốt, ấn tượng hoặc tuyệt vời, giống như trong giấc mơ."},"3466":{"word":"ga trung chuyển","meaning":"Trạm dừng nơi mọi người xuống một phương tiện giao thông công cộng và lên một phương tiện khác để tiếp tục chuyến đi."},"3467":{"word":"tiệc chào mừng","meaning":"Buổi tiệc được tổ chức để chào đón những người mới đến hoặc thành viên mới."},"3468":{"word":"tỷ giá hối đoái","meaning":"Giá mà tiền tệ của một quốc gia được mua hoặc bán bằng tiền tệ của một quốc gia khác."},"3469":{"word":"sáng rõ","meaning":"Mô tả một nơi hoặc vật phát ra hoặc phản chiếu nhiều ánh sáng, giúp dễ dàng nhìn thấy."},"3470":{"word":"hoạt động","meaning":"Hành động di chuyển cơ thể để thực hiện một việc gì đó."},"3471":{"word":"sôi nổi","meaning":"Mô tả người hoặc vật tràn đầy năng lượng, thường xuyên di chuyển hoặc tham gia nhiều hành động sôi nổi."},"3472":{"word":"rộng mở","meaning":"Từ dùng để diễn tả trạng thái cửa, v.v. được mở hoàn toàn."},"3473":{"word":"gỏi cá sống","meaning":"Món ăn làm từ các lát cá hoặc hải sản tươi, chưa nấu chín, thường ăn kèm với nước chấm."},"3474":{"word":"hội phí","meaning":"Khoản tiền định kỳ mà mọi người đóng để trở thành thành viên của một câu lạc bộ, nhóm hoặc tổ chức."},"3475":{"word":"tiệc công ty","meaning":"Buổi tụ họp xã hội, thường có bữa ăn và đồ uống, dành cho đồng nghiệp từ cùng công ty hoặc nhóm để dành thời gian cùng nhau."},"3476":{"word":"phòng họp","meaning":"Một không gian hoặc căn phòng được chỉ định bên trong tòa nhà nơi một nhóm người tụ tập để thảo luận và lập kế hoạch."},"3477":{"word":"chủ tịch","meaning":"Người chủ trì một cuộc họp, chịu trách nhiệm xử lý các công việc của cuộc họp đó."},"3478":{"word":"số lần","meaning":"Số lượng các dịp mà một hành động hoặc sự kiện diễn ra."},"3479":{"word":"hiệu quả","meaning":"Kết quả tốt đẹp đạt được sau khi thực hiện một việc gì đó."},"3480":{"word":"nửa sau","meaning":"Phần cuối cùng hoặc phần thứ hai rõ ràng của một sự kiện, trò chơi hoặc giai đoạn."},"3481":{"word":"món tráng miệng","meaning":"Món ăn ngọt như bánh ngọt hoặc trái cây được phục vụ và ăn vào cuối bữa ăn."},"3482":{"word":"tiêu","meaning":"Một loại gia vị phổ biến làm từ quả khô, thường được nghiền thành mảnh nhỏ màu đen hoặc trắng và rắc lên thức ăn để tăng thêm hương vị cay nồng."},"3483":{"word":"sự hối hận","meaning":"Cảm giác buồn bã và thường khó chịu do mong muốn rằng điều gì đó trong quá khứ đã xảy ra hoặc được thực hiện theo một cách khác."},"3484":{"word":"mùa du lịch","meaning":"Giai đoạn mà nhiều người đi nghỉ mát hoặc đi du lịch."},"3485":{"word":"tính di động","meaning":"Đặc tính của một vật làm cho nó đủ nhỏ hoặc nhẹ để một người có thể dễ dàng mang theo bên mình."},"3486":{"word":"sự nghỉ ngơi","meaning":"Khoảng thời gian một người ngừng làm việc hoặc hoạt động để thư giãn, ngủ hoặc hồi phục sức lực."},"3487":{"word":"sự tạm nghỉ học","meaning":"Khoảng thời gian tạm thời mà một học sinh hoặc sinh viên chính thức ngừng đến trường hoặc đại học, thường là có sự cho phép."},"3488":{"word":"chảy đi","meaning":"Dành cho chất lỏng như nước, v.v., di chuyển về phía trước đến một nơi thấp hơn."},"3489":{"word":"trắng","meaning":"Có màu sáng nhất có thể, giống như tuyết mới rơi, sữa hoặc một tờ giấy trắng."},"3490":{"word":"sự hy sinh","meaning":"Hành động từ bỏ điều gì đó quý giá như thời gian, tiền bạc hoặc mong muốn cá nhân, để mang lại lợi ích cho người khác hoặc đạt được một kết quả quan trọng hơn."},"3491":{"word":"-gia","meaning":"Hậu tố gắn vào danh từ để chỉ một người có kỹ năng hoặc chuyên môn cao trong một lĩnh vực cụ thể."},"3492":{"word":"khả năng","meaning":"Tình trạng hoặc điều có thể xảy ra hoặc là đúng, dù không chắc chắn."},"3493":{"word":"chìm","meaning":"Vật đang ở trên mặt nước hoặc trong nước di chuyển xuống đến đáy."},"3494":{"word":"khoảng, chừng","meaning":"Hậu tố gắn vào số lượng hoặc số đếm để chỉ một con số ước lượng, không chính xác."},"3495":{"word":"đèn đường","meaning":"Cột cao có đèn sáng ở trên, được đặt dọc theo đường phố để chiếu sáng vào ban đêm."},"3496":{"word":"chắn, ngăn chặn","meaning":"Đặt vật cản hoặc hành động để cản trở sự di chuyển hoặc lối đi của ai đó/vật gì đó."},"3497":{"word":"chia, cắt","meaning":"Làm cho một vật nguyên vẹn tách ra thành hai hoặc nhiều phần riêng biệt, thường là bằng cách cắt."},"3498":{"word":"phân biệt","meaning":"Xem xét hoặc suy nghĩ cẩn thận về các sự vật khác nhau để thấy được sự khác biệt giữa chúng."},"3499":{"word":"yên, lặng lẽ","meaning":"Ở trạng thái không có chuyển động hoặc âm thanh, hoặc một cách bình tĩnh và không bị quấy rầy."},"3500":{"word":"đứng yên, giữ yên","meaning":"Giữ cơ thể ở một vị trí cố định, không thực hiện bất kỳ chuyển động nào."},"3501":{"word":"bất động, yên lặng","meaning":"Không có bất kỳ chuyển động hoặc xáo trộn vật lý nào."},"3502":{"word":"hạn hán","meaning":"Một thời kỳ dài khi một vùng nhận được rất ít mưa, khiến đất đai khô cằn và cây cối chết."},"3503":{"word":"lời bài hát","meaning":"Những từ ngữ được hát hoặc nói trong một bài ca."},"3504":{"word":"chủ hộ","meaning":"Người lớn chính trong gia đình chịu trách nhiệm chu cấp và lãnh đạo các thành viên khác."},"3505":{"word":"giả định","meaning":"Một ý kiến hoặc điều được cho là đúng để bắt đầu suy nghĩ hoặc thảo luận."},"3506":{"word":"nội trợ","meaning":"Người phụ nữ quản lý nhà cửa và chăm sóc gia đình mà không làm việc bên ngoài."},"3507":{"word":"mang đến","meaning":"Mang một vật gì đó từ nơi này đến nơi khác, thường là để đưa cho ai đó."},"3508":{"word":"cành cây","meaning":"Một phần thân gỗ của cây vươn ra từ thân chính, có lá hoặc nhánh nhỏ hơn."},"3509":{"word":"đồ giả","meaning":"Vật trông giống đồ thật nhưng không phải là hàng chính hãng hay đích thực."},"3510":{"word":"giá trị","meaning":"Phẩm chất của một vật khiến nó được mong muốn hoặc hữu ích, thường liên quan đến giá tiền."},"3511":{"word":"giá trị quan","meaning":"Niềm tin cốt lõi của một người về điều gì là tốt, xấu, quan trọng hay đúng đắn, ảnh hưởng đến lựa chọn và hành động của họ."},"3512":{"word":"Công giáo","meaning":"Một tôn giáo lớn của Cơ đốc giáo mà các tín đồ công nhận Giáo hoàng ở Rome là lãnh đạo tinh thần."},"3513":{"word":"các nước","meaning":"Chỉ tất cả các quốc gia riêng lẻ, mỗi quốc gia có chính phủ và dân số riêng."},"3514":{"word":"sự quyết tâm","meaning":"Một quyết định mạnh mẽ và kiên định để đạt được mục tiêu hoặc đối mặt với tình huống khó khăn mà không từ bỏ."},"3515":{"word":"các loại","meaning":"Dùng để chỉ nhiều loại khác nhau trong cùng một nhóm, thể hiện sự đa dạng rộng lớn."},"3516":{"word":"-trong","meaning":"Tiếp vĩ ngữ gắn với một đơn vị thời gian để chỉ toàn bộ độ dài của khoảng thời gian đó."},"3517":{"word":"gan","meaning":"Một cơ quan lớn, màu nâu đỏ nằm bên trong cơ thể, đóng vai trò chủ chốt trong tiêu hóa và loại bỏ các chất độc hại khỏi máu."},"3518":{"word":"khoảng, giữa","meaning":"Khoảng không gian hoặc thời gian tồn tại ngăn cách hai điểm hoặc sự kiện riêng biệt."},"3519":{"word":"khoảng cách","meaning":"Một khoảng thời gian hoặc không gian vật lý ngăn cách hai vật, điểm hoặc sự kiện."},"3520":{"word":"sự can thiệp","meaning":"Khi ai đó hoặc điều gì đó ngăn chặn hoặc thay đổi một hành động hay tình huống không phát triển như lẽ ra phải vậy."},"3521":{"word":"khó khăn lắm, suýt nữa","meaning":"Diễn tả một hành động đạt được với rất nhiều khó khăn, suýt chút nữa thì thất bại."},"3522":{"word":"tha thiết, khẩn thiết","meaning":"Cảm thấy hoặc thể hiện một mong muốn hoặc khát vọng rất mạnh mẽ và nghiêm túc, thường thể hiện rõ qua hành động hoặc biểu cảm tập trung của một người."},"3523":{"word":"gián tiếp","meaning":"Mô tả điều gì đó không xảy ra một cách thẳng thắn hoặc trực tiếp, mà liên quan đến các bước hoặc sự vật khác ở giữa."},"3524":{"word":"ngứa, buồn","meaning":"Cảm thấy một sự khó chịu nhẹ hoặc cảm giác ngứa ran trên da hoặc bên trong một bộ phận cơ thể, khiến một người muốn gãi hoặc xoa nó."},"3525":{"word":"tiện lợi, đơn giản","meaning":"Mô tả một thứ được thiết kế với ít bộ phận hoặc ít bước, làm cho nó nhanh chóng và dễ dàng cho ai đó sử dụng hoặc hiểu."},"3526":{"word":"thỉnh thoảng, đôi khi","meaning":"Diễn tả một sự kiện hoặc hành động xảy ra vào những thời điểm không đều đặn, không thường xuyên nhưng đôi khi có khoảng cách rõ rệt giữa các lần xuất hiện."},"3527":{"word":"bị giam cầm","meaning":"Bị giữ hoặc không thể thoát ra khỏi một không gian kín."},"3528":{"word":"mâu thuẫn","meaning":"Sự khác biệt nghiêm trọng giữa các ý kiến, người hoặc nhóm đối lập, gây ra căng thẳng và đấu tranh."},"3529":{"word":"bị nứt, bị tách ra","meaning":"Một vật thể hoặc bề mặt rắn xuất hiện vết nứt hoặc bị chia thành hai hay nhiều phần."},"3530":{"word":"ngày càng","meaning":"Diễn tả sự vật, sự việc liên tục phát triển, thay đổi hoặc tăng cường theo thời gian."},"3531":{"word":"bài cảm tưởng","meaning":"Bài viết thể hiện suy nghĩ, cảm xúc và ý kiến cá nhân về một tác phẩm hoặc trải nghiệm nào đó."},"3532":{"word":"sự giảm bớt","meaning":"Quá trình số lượng, kích thước hoặc mức độ của một cái gì đó trở nên nhỏ hơn hoặc ít hơn trước."},"3533":{"word":"sự giám sát","meaning":"Hành động quan sát chặt chẽ và liên tục một người hoặc địa điểm để theo dõi hành động của họ."},"3534":{"word":"bọc, che chở","meaning":"Đặt vật liệu xung quanh một vật hoặc người, hoặc phủ lên bề mặt để bảo vệ hoặc che giấu."},"3535":{"word":"nhà tù","meaning":"Nơi giam giữ những người vi phạm pháp luật."},"3536":{"word":"giấu, che giấu","meaning":"Đặt cái gì đó ở nơi không thể nhìn thấy hoặc dễ dàng tìm thấy bởi người khác."},"3537":{"word":"dám, cả gan","meaning":"Thực hiện một hành động với sự dũng cảm hoặc táo bạo lớn, thường là một cách có thể bị coi là bất lịch sự hoặc mạo hiểm."},"3538":{"word":"đột ngột, bất ngờ","meaning":"Xảy ra hoặc xuất hiện rất nhanh chóng mà không có cảnh báo hoặc dự đoán trước."},"3539":{"word":"Rẻ","meaning":"Có giá thành thấp, không tốn nhiều tiền để mua hoặc sử dụng."},"3540":{"word":"Kẻ cướp","meaning":"Người phạm tội lấy trộm tiền hoặc đồ vật có giá trị của người khác hoặc một địa điểm bằng cách đe dọa bạo lực."},"3541":{"word":"Lượng mưa","meaning":"Lượng nước đo được từ khí quyển xuống bề mặt Trái đất, dưới dạng giọt nước, bông tuyết hoặc mưa đá."},"3542":{"word":"Sự cưỡng ép","meaning":"Hành động buộc ai đó làm điều gì đó trái với ý muốn của họ, thường bằng cách đe dọa hoặc gây áp lực mạnh mẽ."},"3543":{"word":"Bài giảng","meaning":"Một buổi nói chuyện giáo dục trang trọng do một người nói trình bày cho một nhóm người nghe, thường để dạy về một chủ đề cụ thể."},"3544":{"word":"Giảng đường","meaning":"Một căn phòng lớn trong trường học hoặc đại học nơi giáo viên giảng bài cho nhiều sinh viên cùng một lúc."},"3545":{"word":"Sự cưỡng chế","meaning":"Hành động buộc ai đó thực hiện một hành động hoặc nhiệm vụ trái với mong muốn hoặc không có sự đồng ý của họ, thường thông qua áp lực thể chất hoặc tâm lý."},"3546":{"word":"Sự nhấn mạnh","meaning":"Hành động dành sự quan trọng hoặc chú ý đặc biệt cho một từ, cụm từ hoặc ý tưởng cụ thể."},"3547":{"word":"Các loại","meaning":"Bao gồm nhiều kiểu, loại hoặc phong cách khác nhau của đồ vật hoặc yếu tố trong một nhóm."},"3548":{"word":"Trang bị","meaning":"Sắp xếp hoặc chuẩn bị tất cả các vật dụng, công cụ hoặc điều kiện cần thiết cho một mục đích hoặc sự kiện cụ thể."},"3549":{"word":"Ếch","meaning":"Một loài động vật nhỏ màu xanh hoặc nâu, có đôi chân sau dài để nhảy, sống cả dưới nước và trên cạn."},"3550":{"word":"Khái niệm","meaning":"Kiến thức hoặc suy nghĩ chung về một sự kiện, ý tưởng hoặc đối tượng cụ thể, được hình thành qua nhiều ví dụ hoặc đặc điểm."},"3551":{"word":"gấp","meaning":"Xếp quần áo hoặc vải thành từng lớp gọn gàng."},"3552":{"word":"con kiến","meaning":"Một loài côn trùng nhỏ có sáu chân, sống thành đàn lớn và thường mang vác những mảnh thức ăn lớn hơn nó nhiều."},"3553":{"word":"phát triển","meaning":"Nỗ lực bền bỉ để tạo ra một thứ hoặc khả năng mới, hoặc để mở rộng và củng cố một thứ đã tồn tại."},"3554":{"word":"mở cửa","meaning":"Hành động làm cho một địa điểm hoặc không gian có thể tiếp cận được để mọi người vào hoặc sử dụng."},"3555":{"word":"cá nhân; riêng lẻ","meaning":"Chỉ một người hoặc một vật duy nhất, được coi là khác biệt và tách rời khỏi những thứ khác trong một nhóm."},"3556":{"word":"cải thiện; cải tiến","meaning":"Hành động làm cho chất lượng, điều kiện hoặc hiệu quả của một thứ tốt hơn, thường dẫn đến một trạng thái mong muốn hơn."},"3557":{"word":"cá tính","meaning":"Tập hợp các phẩm chất hoặc đặc điểm độc đáo làm cho một người khác biệt so với những người khác."},"3558":{"word":"tổ chức","meaning":"Sắp xếp và trình bày một sự kiện, cuộc họp hoặc cuộc thi tại một địa điểm cụ thể để mọi người tham dự."},"3559":{"word":"cải cách","meaning":"Hành động thực hiện những thay đổi đáng kể đối với một hệ thống, luật pháp hoặc thực tiễn để làm cho nó công bằng, hiệu quả hơn."},"3560":{"word":"-khách (hậu tố)","meaning":"Hậu tố gắn vào danh từ để chỉ người đến một địa điểm cụ thể hoặc tham gia vào một hoạt động nào đó."},"3561":{"word":"khách quan","meaning":"Mô tả điều gì đó dựa trên sự thật và có thể được nhìn thấy hoặc đo lường bởi bất kỳ ai, không bị ảnh hưởng bởi cảm xúc hoặc ý kiến cá nhân."},"3562":{"word":"khổng lồ; to lớn","meaning":"Mô tả điều gì đó có kích thước hoặc quy mô cực kỳ lớn, lớn hơn nhiều so với mức bình thường hoặc điển hình."},"3563":{"word":"thu gom","meaning":"Tập hợp hoặc mang vào những thứ đã phân tán hoặc đã xong, như mùa màng từ cánh đồng hoặc quần áo khô từ dây phơi."},"3564":{"word":"giúp đỡ","meaning":"Cung cấp sự hỗ trợ hoặc giúp đỡ về thể chất cho người khác để công việc hoặc nỗ lực của họ dễ dàng hoàn thành hơn."},"3565":{"word":"giao dịch","meaning":"Hoạt động trao đổi hàng hóa, dịch vụ hoặc tiền bạc giữa các bên, thường vì lợi ích chung."},"3566":{"word":"đối tác kinh doanh","meaning":"Người hoặc tổ chức mà một công ty thường xuyên mua hoặc bán hàng hóa/dịch vụ."},"3567":{"word":"nhện","meaning":"Một loài động vật nhỏ có tám chân, thường giăng tơ để bắt côn trùng làm thức ăn."},"3568":{"word":"rùa","meaning":"Một loài động vật có mai cứng trên lưng, cổ và chân có thể rụt vào trong mai."},"3569":{"word":"người ăn xin","meaning":"Người không có nhà cửa hoặc tiền bạc, phải đi xin thức ăn hoặc tiền từ người khác trên đường phố."},"3570":{"word":"lời nói dối","meaning":"Những điều được nói ra mà người nói biết là không đúng sự thật, thường là để lừa dối người khác."},"3571":{"word":"đi qua","meaning":"Đi ngang qua một địa điểm hoặc dừng lại ở đó một thời gian ngắn trên đường đến nơi khác."},"3572":{"word":"thô ráp","meaning":"Miêu tả một bề mặt hoặc kết cấu không mịn màng, không bằng phẳng, thường có cảm giác gồ ghề hoặc nhám."},"3573":{"word":"đáng lo ngại","meaning":"Cảm thấy sợ hãi và bồn chồn rằng điều gì đó tồi tệ có thể xảy ra."},"3574":{"word":"bên kia","meaning":"Chỉ một vị trí ở phía đối diện hoặc xuyên qua một cái gì đó."},"3575":{"word":"trao, đưa","meaning":"Đưa một vật gì đó cho người khác bằng tay."},"3576":{"word":"trao cho, đưa cho","meaning":"Dùng tay đặt một vật gì đó vào tay người khác."},"3577":{"word":"chạm vào, động vào","meaning":"Chạm nhẹ vào một vật hoặc một người, hay làm phiền sự yên tĩnh của ai đó."},"3578":{"word":"sự xây dựng","meaning":"Hoạt động xây dựng và lắp ráp các công trình kiến trúc lớn như nhà cửa, cầu đường."},"3579":{"word":"pin","meaning":"Vật nhỏ tạo ra điện, thường dùng trong các thiết bị như máy ảnh, đài hoặc đèn pin."},"3580":{"word":"vớt","meaning":"Lấy một vật gì đó ra khỏi mặt nước hoặc chất lỏng."},"3581":{"word":"kiến trúc","meaning":"Kỹ năng và công việc thiết kế, quy hoạch các công trình xây dựng."},"3582":{"word":"xắn lên, cuộn lên","meaning":"Kéo hoặc gấp phần nào đó của quần áo, giấy tờ hay vật liệu lên trên."},"3583":{"word":"thu gom, thu lại","meaning":"Gom hoặc nhặt những thứ đang trải ra vào một nơi."},"3584":{"word":"vắt qua, bắc qua","meaning":"Trải dài hoặc vắt ngang qua một khu vực, hay đặt vật gì đó lên trên một cách lỏng lẻo."},"3585":{"word":"kiểm tra, thanh tra","meaning":"Một hoạt động kiểm tra hoặc xem xét kỹ lưỡng để tìm lỗi hoặc xác nhận tiêu chuẩn."},"3586":{"word":"sợ, khiếp sợ","meaning":"Trải qua một cảm xúc lo lắng hoặc sợ hãi mạnh mẽ khi nghĩ rằng điều gì đó nguy hiểm sắp xảy ra."},"3587":{"word":"vẻ bề ngoài, ngoại hình","meaning":"Đây là hình dáng, diện mạo bên ngoài của một người hay vật mà người khác có thể nhìn thấy."},"3588":{"word":"cua","meaning":"Một loài động vật biển có vỏ cứng, mười chân và hai càng lớn, thường di chuyển ngang."},"3589":{"word":"hơn nữa, vả lại","meaning":"Từ dùng để thêm một ý hoặc một điều nữa vào những gì đã được đề cập trước đó."},"3590":{"word":"mùa đông","meaning":"Khoảng thời gian lạnh nhất trong năm, thường có tuyết, băng và ngày ngắn hơn."},"3591":{"word":"sự động viên, sự khích lệ","meaning":"Lời nói hoặc hành động giúp ai đó cảm thấy mạnh mẽ và tự tin để tiếp tục làm một việc gì đó."},"3592":{"word":"trải qua, gánh chịu","meaning":"Trực tiếp sống và cảm nhận những gì xảy ra trong một tình huống hoặc sự kiện khó khăn."},"3593":{"word":"chịu đựng, chống đỡ","meaning":"Giữ vững và không bỏ cuộc khi đối mặt với điều gì đó khó khăn hoặc đau đớn."},"3594":{"word":"tham quan học tập, chuyến đi thực tế","meaning":"Một chuyến thăm có tổ chức của một nhóm người, thường là học sinh, đến một nơi cụ thể để học hỏi thông qua quan sát."},"3595":{"word":"quan điểm, ý kiến","meaning":"Những gì một người nghĩ về một chủ đề hoặc tình huống cụ thể, thường được thể hiện bằng lời nói hoặc hành động."},"3596":{"word":"sự nghỉ làm, sự vắng mặt tại nơi làm việc","meaning":"Tình trạng một người không đến nơi làm việc theo lịch trình mà họ phải thực hiện các nhiệm vụ hàng ngày."},"3597":{"word":"kết luận","meaning":"Ý tưởng hoặc phát biểu cuối cùng đạt được sau khi cân nhắc kỹ lưỡng tất cả các sự thật hoặc ý tưởng trong một cuộc thảo luận."},"3598":{"word":"trận chung kết, vòng chung kết","meaning":"Trận đấu hoặc cuộc thi cuối cùng trong một giải đấu để quyết định người thắng cuộc giữa hai đối thủ hoặc đội còn lại."},"3599":{"word":"tuyệt đối không","meaning":"Dùng để nhấn mạnh rằng một điều gì đó sẽ không xảy ra hoặc không đúng trong bất kỳ trường hợp nào."},"3600":{"word":"kết hợp","meaning":"Hành động hoặc trạng thái hai hay nhiều vật riêng biệt được nối lại với nhau để tạo thành một thể thống nhất."},"3601":{"word":"sảnh cưới","meaning":"Nơi đặc biệt được thiết kế và trang trí để tổ chức các buổi lễ kết hôn."},"3602":{"word":"khiêm tốn","meaning":"Đức tính không khoe khoang về bản thân hoặc không nghĩ mình quan trọng hơn người khác."},"3603":{"word":"chồng chéo","meaning":"Tình trạng một vật che một phần vật khác hoặc hai sự việc xảy ra cùng một lúc."},"3604":{"word":"ranh giới","meaning":"Đường hoặc mép rõ ràng phân chia hai khu vực hoặc lãnh thổ khác nhau."},"3605":{"word":"lời cảnh báo","meaning":"Dấu hiệu, âm thanh hoặc thông điệp được đưa ra để báo cho ai đó về nguy hiểm tiềm tàng hoặc vấn đề sắp xảy ra."},"3606":{"word":"kinh tế","meaning":"Tình hình hoạt động sản xuất, trao đổi và tiêu dùng của một quốc gia hoặc khu vực."},"3607":{"word":"kinh nghiệm làm việc","meaning":"Tổng hợp tất cả các công việc và trải nghiệm làm việc mà một người đã tích lũy trong cuộc đời lao động của mình."},"3608":{"word":"quản lý","meaning":"Hành động điều hành một doanh nghiệp, công ty hoặc tổ chức bằng cách sắp xếp, kiểm soát và giám sát các hoạt động của nó."},"3609":{"word":"cạnh tranh","meaning":"Hành động hai hay nhiều người hoặc nhóm cố gắng đạt được cùng một mục tiêu hoặc thành công hơn nhau."},"3610":{"word":"năng lực cạnh tranh","meaning":"Khả năng hoặc lợi thế giúp một người, sản phẩm hoặc công ty hoạt động tốt hơn những đối thủ khác trong một lĩnh vực cụ thể."},"3611":{"word":"năng lực kinh tế","meaning":"Khả năng tạo ra của cải và ảnh hưởng về mặt tài chính của một cá nhân, công ty hoặc quốc gia."},"3612":{"word":"xu hướng","meaning":"Một hành động, suy nghĩ hoặc hiện tượng có thiên hướng nghiêng về một hướng nhất định."},"3613":{"word":"nguyên cớ","meaning":"Một sự kiện hoặc hoàn cảnh cụ thể đóng vai trò là nguyên nhân hoặc điểm khởi đầu cho một điều gì đó xảy ra."},"3614":{"word":"máy tính cầm tay","meaning":"Một thiết bị điện tử nhỏ có các nút và màn hình, dùng để thực hiện nhanh các phép tính toán học."},"3615":{"word":"quầy tính tiền","meaning":"Khu vực tại cửa hàng hoặc ngân hàng nơi mọi người xếp hàng để thanh toán các khoản tiền."},"3616":{"word":"tầng lớp","meaning":"Một hệ thống sắp xếp người hoặc vật thành các cấp độ khác nhau dựa trên tầm quan trọng, địa vị hoặc quyền lực của họ."},"3617":{"word":"quê hương","meaning":"Đất nước nơi một người sinh ra và lớn lên, hoặc nơi họ coi là quê nhà của mình."},"3618":{"word":"cao cấp","meaning":"Mức độ chất lượng rất tốt, thường có thiết kế tinh xảo và được làm từ vật liệu cao cấp."},"3619":{"word":"sang trọng","meaning":"Có vẻ ngoài thanh lịch, tiện nghi và đắt tiền, cho thấy chất lượng vượt trội và tay nghề tinh xảo."},"3620":{"word":"cổ đại","meaning":"Một thời kỳ lịch sử tồn tại nhiều thế kỷ trước, đặc trưng bởi các nền văn minh sơ khai và văn hóa riêng biệt."},"3621":{"word":"cô độc","meaning":"Tình trạng hoàn toàn một mình, đôi khi có thể khiến một người cảm thấy buồn bã hoặc bị cô lập với người khác."},"3622":{"word":"cấp cao","meaning":"Một cấp độ hoặc trình độ tương đối cao."},"3623":{"word":"cá thu","meaning":"Một loại cá biển có nhiều thịt, lưng màu xanh vân sóng và bụng màu trắng."},"3624":{"word":"cá voi","meaning":"Một loài động vật có vú khổng lồ sống dưới biển, thở bằng lỗ phun nước và có vây đuôi rất khỏe."},"3625":{"word":"sự cân nhắc, sự xem xét","meaning":"Hành động suy nghĩ kĩ lưỡng về các sự thật hoặc khả năng trước khi đưa ra quyết định."},"3626":{"word":"biết ơn, cảm ơn","meaning":"Cảm thấy lòng biết ơn, sự cảm kích đối với ai đó đã làm điều tốt hoặc giúp đỡ mình."},"3627":{"word":"cao su","meaning":"Một vật liệu dẻo, đàn hồi, thường được dùng để làm những vật có thể co giãn, nảy hoặc chống nước."},"3628":{"word":"thơm bùi, béo bùi","meaning":"Có vị thơm ngon, bùi bùi giống như hạt rang, thường thấy trong các món ăn có một chút dầu mỡ."},"3629":{"word":"sự tĩnh lặng, sự yên tĩnh","meaning":"Trạng thái thanh bình khi có rất ít tiếng động và không có gì chuyển động."},"3630":{"word":"đặc trưng, riêng biệt","meaning":"Mang những phẩm chất hoặc đặc điểm chỉ thuộc về riêng một người, một địa điểm hoặc một vật nào đó mà không chia sẻ với ai khác."},"3631":{"word":"quê hương, bản quán","meaning":"Nơi mình sinh ra và lớn lên, hoặc nơi có quan hệ sâu sắc với bản thân."},"3632":{"word":"cổ điển, kinh điển","meaning":"Một tác phẩm nghệ thuật, văn học hoặc âm nhạc được coi là xuất sắc và quan trọng trong một thời gian dài, vẫn còn giá trị cao đến ngày nay."},"3633":{"word":"cố định","meaning":"Chỉ cái gì được giữ chặt ở một vị trí và không di chuyển, hoặc một giá trị không thay đổi, luôn ổn định."},"3634":{"word":"sự cố chấp, sự bướng bỉnh","meaning":"Việc không chịu thay đổi ý kiến hoặc kế hoạch của mình, ngay cả khi gặp khó khăn hoặc sự phản đối từ người khác."},"3635":{"word":"tầng cao","meaning":"Các tầng trên của một tòa nhà cao."},"3636":{"word":"nỗi đau","meaning":"Cảm giác khó chịu hoặc trạng thái đau đớn về thể xác hay tinh thần."},"3637":{"word":"đau đớn","meaning":"Cảm thấy rất khó chịu, đau xót trong cơ thể hoặc trong lòng."},"3638":{"word":"bản nhạc","meaning":"Một tác phẩm âm nhạc được trình bày bằng giọng hát hoặc nhạc cụ."},"3639":{"word":"ngũ cốc","meaning":"Các loại hạt từ cây trồng như lúa, ngô, lúa mì dùng làm thức ăn."},"3640":{"word":"thẳng","meaning":"Không có đường cong, không bị cong hay gập lại."},"3641":{"word":"ngay lập tức","meaning":"Diễn ra hoặc làm việc gì đó không chần chừ, không trì hoãn."},"3642":{"word":"khá tốt","meaning":"Làm việc gì đó ở mức độ tương đối tốt hoặc giỏi."},"3643":{"word":"khung thành","meaning":"Khu vực được chỉ định để ghi điểm trong các môn thể thao như bóng đá, khúc côn cầu."},"3644":{"word":"ngáy","meaning":"Phát ra âm thanh lớn khi ngủ, thường qua mũi hoặc miệng."},"3645":{"word":"sự đồng cảm","meaning":"Khả năng hiểu và chia sẻ cảm xúc của người khác."},"3646":{"word":"sự công khai","meaning":"Việc làm cho thông tin hoặc điều gì đó được biết đến rộng rãi và mọi người có thể xem hoặc nghe."},"3647":{"word":"tấn công","meaning":"Hành động dùng sức mạnh hoặc bạo lực để chống lại ai đó hoặc thứ gì đó."},"3648":{"word":"cung cấp","meaning":"Số lượng của một thứ gì đó được làm cho có sẵn hoặc được cung cấp để mọi người sử dụng hoặc mua."},"3649":{"word":"bát","meaning":"Một đồ đựng hình tròn, miệng mở, thường dùng để đựng thức ăn như cơm."},"3650":{"word":"cộng đồng","meaning":"Một nhóm người có cùng ý thức hệ hoặc mục tiêu."},"3651":{"word":"lịch sự","meaning":"Thể hiện cách cư xử tốt và tôn trọng người khác qua lời nói và hành động của mình."},"3652":{"word":"công nghiệp","meaning":"Toàn bộ các doanh nghiệp và nhà máy sản xuất hàng hóa hoặc cung cấp dịch vụ trong một quốc gia hoặc khu vực."},"3653":{"word":"công cộng","meaning":"Liên quan đến chính phủ hoặc cộng đồng, dành cho tất cả mọi người chứ không chỉ một vài cá nhân."},"3654":{"word":"thông báo","meaning":"Hành động thông báo cho nhiều người biết một thông tin nhất định."},"3655":{"word":"ô nhiễm","meaning":"Các chất hoặc điều kiện có hại làm tổn thương môi trường tự nhiên hoặc gây ra vấn đề cho sinh vật sống."},"3656":{"word":"tiêu dùng quá mức","meaning":"Việc chi quá nhiều tiền vào những thứ không cần thiết, sử dụng tài nguyên nhiều hơn mức cần."},"3657":{"word":"quá tốc độ","meaning":"Lái xe hoặc di chuyển nhanh hơn giới hạn cho phép, có thể thấy qua chuyển động nhanh của phương tiện hoặc biển cảnh báo."},"3658":{"word":"quả nhiên","meaning":"Từ này dùng để thể hiện rằng một điều gì đó thực sự đúng như người ta đã tin tưởng."},"3659":{"word":"dạy kèm","meaning":"Một buổi học riêng giữa một học sinh và một giáo viên."},"3660":{"word":"nhiệm vụ","meaning":"Một công việc cụ thể hoặc hoạt động mà ai đó được yêu cầu thực hiện hoặc hoàn thành."},"3661":{"word":"khoa học","meaning":"Liên quan đến việc nghiên cứu thế giới tự nhiên thông qua quan sát và thí nghiệm để tìm ra sự thật."},"3662":{"word":"tòa nhà","meaning":"Hậu tố được thêm vào để chỉ một công trình lớn hoặc địa điểm được thiết kế cho một mục đích nhất định."},"3663":{"word":"quan điểm","meaning":"Hậu tố kết hợp với một từ để mô tả cách một người nghĩ hoặc hiểu một ý tưởng hoặc thế giới."},"3664":{"word":"người liên quan","meaning":"Một cá nhân có vai trò hoặc liên kết trực tiếp với một sự kiện, tình huống hoặc nhóm cụ thể."},"3665":{"word":"mối quan tâm","meaning":"Một chủ đề hoặc hoạt động cụ thể mà ai đó thích nghĩ đến, nói về hoặc thực hiện."},"3666":{"word":"quan điểm","meaning":"Góc độ hoặc vị trí cụ thể mà một người xem xét một vấn đề hoặc tình huống."},"3667":{"word":"vô cớ","meaning":"Diễn tả một hành động hoặc sự việc xảy ra mà không có lý do chính đáng hoặc mục đích rõ ràng."},"3668":{"word":"sự đau khổ","meaning":"Một cảm giác khó chịu sâu sắc về nỗi đau hoặc sự bất hạnh lớn mà một người phải chịu đựng."},"3669":{"word":"đau khổ","meaning":"Biểu hiện sự đau đớn dữ dội, lo lắng hoặc bất hạnh, thường qua việc khóc hoặc nét mặt buồn."},"3670":{"word":"khổ sở","meaning":"Mô tả một tình trạng hoặc trải nghiệm mang lại sự khó chịu về tinh thần hoặc thể chất và nỗi buồn sâu sắc."},"3671":{"word":"bắt nạt, quấy rầy","meaning":"Làm cho người khác cảm thấy khó chịu, khổ sở hoặc bị tổn thương một cách có chủ ý."},"3672":{"word":"tuyệt vời, vĩ đại","meaning":"Rất ấn tượng, lớn lao hoặc đáng kinh ngạc đến mức gây ra sự ngạc nhiên và ngưỡng mộ."},"3673":{"word":"trong trường, nội bộ trường học","meaning":"Thuộc về hoặc diễn ra bên trong khuôn viên trường học."},"3674":{"word":"sự luân phiên, ca trực","meaning":"Sự sắp xếp mà các cá nhân hoặc nhóm khác nhau thay phiên nhau thực hiện một nhiệm vụ, thường theo các khoảng thời gian nhất định."},"3675":{"word":"giao lưu, trao đổi","meaning":"Quá trình hai hoặc nhiều nhóm, cá nhân chia sẻ ý tưởng, thông tin hoặc đối tượng, có ảnh hưởng lẫn nhau."},"3676":{"word":"đồng phục học sinh","meaning":"Một bộ trang phục được chọn riêng để tất cả học sinh mặc khi đến một cơ sở giáo dục cụ thể."},"3677":{"word":"sự giáo dưỡng, văn hóa","meaning":"Sự hiểu biết rộng về nhiều lĩnh vực như văn hóa, nghệ thuật, lịch sử, giúp con người có cách ứng xử tinh tế và thái độ sống đúng đắn."},"3678":{"word":"chi phí giáo dục, học phí","meaning":"Số tiền chi trả cho việc học tập, mua sách hoặc các hoạt động liên quan đến việc học khác."},"3679":{"word":"nhà giáo, nhà giáo dục","meaning":"Người làm nghề chính là giúp đỡ người khác tiếp thu kiến thức và phát triển kỹ năng, thường trong môi trường giáo dục."},"3680":{"word":"hiệu trưởng","meaning":"Người đứng đầu quản lý hành chính của một cơ sở giáo dục, chịu trách nhiệm về toàn bộ việc điều hành và nhân sự của trường."},"3681":{"word":"giáo trình, tài liệu học tập","meaning":"Sách, tài liệu, bản ghi âm hoặc các vật phẩm vật lý hoặc kỹ thuật số khác được chuẩn bị để hỗ trợ ai đó tiếp thu kiến thức hoặc kỹ năng."},"3682":{"word":"sự thay thế, sự hoán đổi","meaning":"Hành động loại bỏ một vật hoặc người và đưa một vật hoặc người khác vào vị trí của nó."},"3683":{"word":"phương châm của trường","meaning":"Một câu ngắn gọn nêu lên mục tiêu hoặc lý tưởng giáo dục của một trường học."},"3684":{"word":"lăn","meaning":"Di chuyển bằng cách quay tròn liên tục trên một bề mặt, thường dùng cho vật tròn."},"3685":{"word":"mua hàng","meaning":"Hành động nhận một món đồ hoặc dịch vụ bằng cách trả tiền cho nó."},"3686":{"word":"sự phân biệt","meaning":"Hành động nhận diện và công nhận những đặc điểm riêng biệt để tách biệt một vật hoặc người này với vật hoặc người khác."},"3687":{"word":"uốn cong","meaning":"Làm cho một vật hoặc bộ phận cơ thể đang thẳng trở nên cong hoặc gấp khúc, thường bằng cách tác dụng lực."},"3688":{"word":"sự phân loại","meaning":"Hành động sắp xếp vật hoặc người thành các phần hoặc loại riêng biệt dựa trên các đặc điểm chung của chúng."},"3689":{"word":"góc","meaning":"Phần bên trong của góc hoặc nơi hai bề mặt gặp nhau."},"3690":{"word":"cấu tạo","meaning":"Một tổng thể được hình thành từ nhiều bộ phận hoặc yếu tố khác nhau."},"3691":{"word":"thế hệ cũ","meaning":"Một nhóm người đã sống và trưởng thành trong thời kỳ trước, thường có quan điểm và trải nghiệm khác với những người thuộc thế hệ sau."},"3692":{"word":"sự ràng buộc","meaning":"Hành động giới hạn hoặc kiềm chế sự tự do trong suy nghĩ hoặc hành động của một người."},"3693":{"word":"sự cứu hộ","meaning":"Hành động giải thoát ai đó hoặc cái gì đó khỏi nguy hiểm."},"3694":{"word":"cứu","meaning":"Bảo vệ ai đó hoặc cái gì đó khỏi nguy hiểm, tổn hại hoặc mất mát."},"3695":{"word":"Ngày lễ quốc gia","meaning":"Đây là một ngày đặc biệt trong năm được cả nước kỷ niệm, thường mọi người không làm việc hoặc đi học."},"3696":{"word":"Sản phẩm nội địa","meaning":"Sản phẩm này được sản xuất hoặc trồng trọt bên trong lãnh thổ của một quốc gia."},"3697":{"word":"Nước ngoài","meaning":"Đây là khu vực nằm ngoài biên giới địa lý của một quốc gia."},"3698":{"word":"Hôn nhân quốc tế","meaning":"Đây là sự kết hôn giữa hai người có quốc tịch khác nhau."},"3699":{"word":"Tuyến bay quốc tế","meaning":"Đây là tuyến đường dành cho các phương tiện giao thông như máy bay, tàu thủy đi lại giữa các quốc gia."},"3700":{"word":"Quốc tế hóa","meaning":"Đây là quá trình làm cho một sự vật, ý tưởng hoặc văn hóa trở nên phổ biến và được chấp nhận trên toàn thế giới."},"3701":{"word":"Hoa cúc","meaning":"Đây là một loài hoa thường nở vào mùa thu, có nhiều cánh màu trắng hoặc vàng và mùi thơm dịu."},"3702":{"word":"Quốc hội","meaning":"Đây là cơ quan lập pháp chính của một quốc gia, nơi các đại biểu được bầu họp để thảo luận và ban hành luật."},"3703":{"word":"Huyện","meaning":"Đây là một đơn vị hành chính địa phương, thường lớn hơn thành phố nhưng nhỏ hơn tỉnh."},"3704":{"word":"Chỗ","meaning":"Từ này dùng để chỉ một vị trí hoặc khu vực cụ thể trong không gian."},"3705":{"word":"Quân sự","meaning":"Từ này chỉ những gì liên quan đến lực lượng vũ trang, binh lính, vũ khí hoặc quốc phòng của một quốc gia."},"3706":{"word":"Cứng lại","meaning":"Biến đổi từ trạng thái mềm hoặc lỏng sang trạng thái rắn chắc, khó uốn cong hoặc làm vỡ."},"3707":{"word":"cứng lại, rắn lại","meaning":"Trở nên cứng và rắn chắc, không dễ di chuyển, uốn cong hay thay đổi."},"3708":{"word":"nhất quyết, cố tình","meaning":"Một hành động được thực hiện với ý chí mạnh mẽ, thường là khi không thực sự cần thiết."},"3709":{"word":"đường hầm","meaning":"Một lối đi dài được đào xuyên qua đất hoặc đá dưới lòng đất."},"3710":{"word":"uốn cong, gập","meaning":"Khiến một bộ phận cơ thể hoặc vật thể trở nên cong hoặc gập lại thay vì thẳng."},"3711":{"word":"-quyền (tiếp vĩ ngữ)","meaning":"Một hậu tố thêm vào sau danh từ để chỉ quyền lợi hoặc sự cho phép đặc biệt của một người."},"3712":{"word":"quyền lực","meaning":"Khả năng kiểm soát con người và sự kiện, thường là do địa vị chính thức hoặc sức mạnh lớn."},"3713":{"word":"quyền lợi","meaning":"Sự đảm bảo pháp lý hoặc đạo đức cho phép một người có hoặc làm điều gì đó mà không bị ngăn cản."},"3714":{"word":"uy tín, quyền uy","meaning":"Sự tôn trọng và tin cậy cao được dành cho một người do kiến thức, địa vị hoặc ảnh hưởng của họ."},"3715":{"word":"khuyên bảo, khuyến nghị","meaning":"Hành động gợi ý điều gì đó cho người khác hoặc cố gắng thuyết phục họ làm điều đó."},"3716":{"word":"về nhà, về đến nhà","meaning":"Hành động một người trở về nhà hoặc nơi ở của mình."},"3717":{"word":"về nước","meaning":"Hành động một người trở về quốc gia mình sinh ra hoặc là công dân sau khi ở nước ngoài."},"3718":{"word":"ma quỷ, hồn ma","meaning":"Một linh hồn được cho là còn lại sau khi một người chết đi."},"3719":{"word":"quý giá","meaning":"Từ dùng để chỉ đồ vật có giá trị lớn, quan trọng hoặc hiếm có, được mong muốn nhiều."},"3720":{"word":"quý","meaning":"Từ dùng để chỉ người có địa vị xã hội cao, được tôn trọng hoặc đồ vật hiếm có, không dễ tìm thấy."},"3721":{"word":"quy mô","meaning":"Kích thước tổng thể, phạm vi hoặc mức độ của một sự vật, sự kiện hay hoạt động."},"3722":{"word":"quy định","meaning":"Điều khoản hoặc luật lệ được đặt ra để mọi người tuân theo."},"3723":{"word":"cân bằng","meaning":"Trạng thái giữ cho vật thể không bị nghiêng lệch về một phía."},"3724":{"word":"ít ra","meaning":"Dùng để chỉ một điều nhỏ nhặt nhưng vẫn được xem là tốt hơn so với tình huống xấu hơn có thể xảy ra."},"3725":{"word":"xích đu","meaning":"Một chỗ ngồi treo bằng dây hoặc xích, thường được dùng để đu đưa qua lại."},"3726":{"word":"bóng râm","meaning":"Vùng tối được tạo ra khi một vật thể che khuất ánh sáng trực tiếp từ mặt trời hoặc nguồn sáng khác."},"3727":{"word":"không mấy","meaning":"Một phó từ dùng để nhấn mạnh ý 'không nhiều lắm' hoặc 'ở mức độ nhỏ', thường đi kèm với các từ phủ định."},"3728":{"word":"người","meaning":"Từ dùng để gọi người đối diện một cách nhẹ nhàng hoặc trang trọng, thường trong thơ ca, bài hát hoặc thư từ."},"3729":{"word":"biểu đồ","meaning":"Một loại sơ đồ thể hiện thông tin hoặc số liệu bằng đường, cột hoặc hình dạng để dễ so sánh."},"3730":{"word":"đúng vậy","meaning":"Một từ cảm thán dùng để bày tỏ sự đồng ý hoàn toàn với điều người khác vừa nói."},"3731":{"word":"tạm ổn","meaning":"Diễn tả việc một tình huống hoặc công việc được xử lý hoặc hoàn thành mà không quá xuất sắc nhưng cũng không gặp vấn đề đáng kể."},"3732":{"word":"cũng tạm","meaning":"Diễn tả một vật hoặc tình huống có thể chấp nhận hoặc hài lòng được, dù không đạt tiêu chuẩn cao."},"3733":{"word":"Đúng rồi!","meaning":"Một từ cảm thán dùng để xác nhận một điều gì đó là đúng hoặc thể hiện sự thấu hiểu hoàn toàn."},"3734":{"word":"đằng đó","meaning":"Chỉ một địa điểm hoặc hướng cụ thể xa người nói, biểu thị sự di chuyển về phía đó."},"3735":{"word":"nỗi nhớ","meaning":"Cảm xúc khao khát mãnh liệt muốn gặp hoặc ở bên ai đó/điều gì đó đang vắng mặt hoặc đã mất."},"3736":{"word":"bóng","meaning":"Một vùng tối xuất hiện phía sau một vật thể khi vật đó chặn ánh sáng."},"3737":{"word":"sách tranh","meaning":"Một loại ấn phẩm, thường dành cho trẻ nhỏ, chứa nhiều tranh vẽ hoặc ảnh và từ ngữ đơn giản trên mỗi trang."},"3738":{"word":"chừng đó","meaning":"Chỉ một số lượng, kích thước hoặc mức độ cụ thể của điều gì đó đã được nhìn thấy hoặc hiểu từ một câu nói trước đó."},"3739":{"word":"đúng là","meaning":"Một phó từ dùng để khẳng định mạnh mẽ rằng một phát biểu là hoàn toàn đúng hoặc chính xác, không hề phóng đại."},"3740":{"word":"mãi đến lúc đó","meaning":"Diễn tả một tình huống hoặc hành động cuối cùng xảy ra vào một thời điểm cụ thể, chứ không phải trước thời điểm chính xác đó."},"3741":{"word":"đến thế","meaning":"Dùng để nhấn mạnh mức độ cao hoặc số lượng lớn của một phẩm chất, làm cho nó trở nên rất tuyệt vời hoặc đáng kể."},"3742":{"word":"sự khắc phục","meaning":"Hành động giải quyết thành công một tình huống, vấn đề hoặc thử thách khó khăn và vượt qua nó."},"3743":{"word":"cực kỳ","meaning":"Dùng để nhấn mạnh mức độ cao hoặc tính chất đặc biệt của một sự vật, sự việc."},"3744":{"word":"căn cứ","meaning":"Là tập hợp các sự kiện hoặc ý tưởng để củng cố vững chắc một lập luận hoặc quyết định."},"3745":{"word":"vùng ngoại ô","meaning":"Là những khu dân cư nằm xung quanh rìa của một thành phố lớn."},"3746":{"word":"thời cận đại","meaning":"Giai đoạn lịch sử kéo dài từ vài thế kỷ trước đến ngày nay, đặc trưng bởi những phát minh mới và sự thay đổi của xã hội."},"3747":{"word":"gần đây","meaning":"Là khoảng thời gian vừa mới trôi qua, thường dùng để chỉ các sự kiện hoặc tình huống xảy ra cách đây không lâu."},"3748":{"word":"người lao động","meaning":"Là người thực hiện một công việc, thường là lao động chân tay, để đổi lấy tiền lương."},"3749":{"word":"căn bản","meaning":"Là phần cốt lõi và thiết yếu nhất của một sự vật, từ đó tất cả các yếu tố khác đều bắt nguồn hoặc phụ thuộc."},"3750":{"word":"căn bản","meaning":"Mô tả cái gì đó là cốt lõi tuyệt đối hoặc yếu tố thiết yếu nhất, từ đó mọi thứ khác phát sinh."},"3751":{"word":"nỗi lo","meaning":"Là cảm giác sợ hãi và lo âu rằng điều gì đó tồi tệ có thể xảy ra."},"3752":{"word":"gãi","meaning":"Dùng móng tay hoặc vật nhọn để cọ xát vào cái gì đó hoặc ai đó."},"3753":{"word":"năm nay","meaning":"Là khoảng thời gian mười hai tháng đang diễn ra, từ ngày 1 tháng 1 đến ngày 31 tháng 12."},"3754":{"word":"tài chính","meaning":"Là hoạt động quản lý tiền bạc, tín dụng và đầu tư, đặc biệt là của các công ty lớn hoặc chính phủ."},"3755":{"word":"cấm","meaning":"Ra lệnh hoặc quy định chính thức rằng một điều gì đó không được phép hoặc không được thực hiện."},"3756":{"word":"đột ngột, nhanh chóng","meaning":"Xảy ra với tốc độ lớn và thay đổi một cách đột ngột, rõ rệt về số lượng, mức độ hoặc hướng."},"3757":{"word":"nhanh chóng, cấp tốc","meaning":"Diễn ra với tốc độ rất nhanh, khiến sự việc hoàn thành hoặc tiến triển trong thời gian ngắn."},"3758":{"word":"tăng nhanh, tăng vọt","meaning":"Sự gia tăng một cách nhanh chóng trong một khoảng thời gian ngắn."},"3759":{"word":"vội vàng, khẩn trương","meaning":"Thực hiện hành động một cách vội vã, khẩn trương, có thể không báo trước hoặc trong tình huống cấp bách."},"3760":{"word":"ngày kỷ niệm","meaning":"Ngày đặc biệt hàng năm để tưởng nhớ và kỷ niệm một sự kiện đã xảy ra trong quá khứ, như đám cưới hoặc thành lập."},"3761":{"word":"đạo Cơ Đốc, Cơ Đốc giáo","meaning":"Một tôn giáo thờ một Thiên Chúa và tin Chúa Giê-su là Con của Thiên Chúa."},"3762":{"word":"cây cột, cột","meaning":"Một cấu trúc cao, vững chắc, đứng thẳng để chống đỡ mái nhà hoặc một phần của tòa nhà."},"3763":{"word":"ghi chép, hồ sơ","meaning":"Thông tin bằng văn bản hoặc được lưu trữ về một sự kiện hoặc sự thật, được giữ lại để có thể xem lại sau này."},"3764":{"word":"nền tảng, cơ sở","meaning":"Phần thấp nhất dùng để chống đỡ một cấu trúc hoặc ý tưởng chính mà dựa vào đó để xây dựng những thứ khác."},"3765":{"word":"cơ bản, căn bản","meaning":"Những điểm khởi đầu hoặc sự thật quan trọng và đơn giản nhất mà một người cần biết trước khi học sâu hơn."},"3766":{"word":"cơ bản, căn bản","meaning":"Diễn tả điều gì đó cần thiết và tạo thành phần quan trọng nhất để mọi thứ khác phát triển từ đó."},"3767":{"word":"quyên góp","meaning":"Hành động tự nguyện cho tiền hoặc vật chất để giúp đỡ người khác, tổ chức từ thiện hay cộng đồng."},"3768":{"word":"kỹ thuật","meaning":"Khả năng được rèn luyện và học hỏi để thực hiện một công việc nào đó một cách thành thạo."},"3769":{"word":"doanh nhân","meaning":"Người sáng lập và quản lý một doanh nghiệp mới, chấp nhận rủi ro tài chính với hy vọng kiếm lời."},"3770":{"word":"sự đóng góp","meaning":"Việc làm hoặc điều được đưa ra bởi cá nhân, nhóm hay vật thể nhằm giúp đạt được mục tiêu hoặc cải thiện tình hình."},"3771":{"word":"năng lượng, sức lực","meaning":"Sức mạnh và sự sinh động giúp một người hoặc con vật hoạt động, di chuyển hoặc làm việc."},"3772":{"word":"nghiêng","meaning":"Một vật thể di chuyển hoặc ở vị trí không thẳng đứng hoặc không bằng phẳng mà tạo thành một góc."},"3773":{"word":"nghiêng","meaning":"Khiến một vật thể, như đầu hoặc vật khác, di chuyển vào một vị trí xiên hoặc tạo thành một góc."},"3774":{"word":"nguồn gốc","meaning":"Điểm thời gian hoặc địa điểm cụ thể mà một cái gì đó lần đầu tiên bắt đầu hoặc xuất hiện."},"3775":{"word":"phép màu, điều kỳ diệu","meaning":"Một sự kiện đáng ngạc nhiên và tuyệt vời, dường như không thể giải thích bằng các quy luật tự nhiên và thường mang lại kết quả tích cực."},"3776":{"word":"hiện có, có sẵn","meaning":"Diễn tả một cái gì đó đã tồn tại, có mặt hoặc đang được sử dụng ở thời điểm hiện tại."},"3777":{"word":"vươn vai, duỗi người","meaning":"Hành động kéo căng chân tay và lưng sau khi thức dậy hoặc ngồi lâu, thường là vươn tay lên đầu."},"3778":{"word":"đã kết hôn","meaning":"Một người đã chính thức bước vào một mối quan hệ hôn nhân hợp pháp với người khác."},"3779":{"word":"kế hoạch","meaning":"Việc suy nghĩ và chuẩn bị cẩn thận về cách thực hiện một việc gì đó hoặc điều gì sẽ xảy ra trong tương lai."},"3780":{"word":"khí hậu","meaning":"Điều kiện khí quyển đặc trưng dài hạn của một khu vực cụ thể, bao gồm nhiệt độ, lượng mưa và gió."},"3781":{"word":"ven đường","meaning":"Phần đất hoặc khu vực ngay bên cạnh đường phố hoặc lối đi nơi các phương tiện di chuyển."},"3782":{"word":"đường phố","meaning":"Con đường công cộng trong thành phố hoặc thị trấn có các tòa nhà dọc hai bên, nơi phương tiện và người đi lại."},"3783":{"word":"độ sâu","meaning":"Sự đo lường khoảng cách mà một vật thể hoặc khu vực kéo dài xuống dưới từ bề mặt trên cùng hoặc cạnh phía trước của nó."},"3784":{"word":"khắt khe","meaning":"Đòi hỏi những điều kiện rất cụ thể hoặc những phẩm chất chính xác không dễ dàng để đáp ứng."},"3785":{"word":"lý do","meaning":"Những sự thật hoặc hoàn cảnh cơ bản dẫn đến việc một sự kiện hoặc hành động xảy ra."},"3786":{"word":"bóc ăn","meaning":"Tháo bỏ lớp vỏ bên ngoài của thức ăn, chẳng hạn như trái cây hoặc hạt, và sau đó ăn phần ăn được."},"3787":{"word":"trải","meaning":"Trải thứ gì đó ra phẳng trên một bề mặt, chẳng hạn như vải hoặc ga trải giường, để nó che phủ khu vực đó."},"3788":{"word":"được trải","meaning":"Được trải phẳng ra trên sàn nhà hoặc một bề mặt nào đó."},"3789":{"word":"tối om","meaning":"Trạng thái hoàn toàn không có ánh sáng, khiến không thể nhìn thấy bất cứ thứ gì xung quanh."},"3790":{"word":"nhấp nháy","meaning":"Đối với một nguồn sáng, chẳng hạn như đèn, liên tục bật tắt hoặc mờ đi rồi sáng lên nhanh chóng."},"3791":{"word":"mè","meaning":"Hạt nhỏ, dẹt, có dầu, thường dùng để chế biến món ăn hoặc rắc lên thực phẩm."},"3792":{"word":"vỡ","meaning":"Làm cho một vật thể như bát đĩa, cốc tách bị nứt hoặc vỡ ra từng mảnh."},"3793":{"word":"nhận ra","meaning":"Đột nhiên hiểu ra hoặc nhận thức được một điều gì đó mà trước đây mình chưa rõ."},"3794":{"word":"làm vỡ","meaning":"Tác động mạnh làm cho một vật bị vỡ ra thành nhiều mảnh nhỏ hoặc xuất hiện vết nứt."},"3795":{"word":"cắn","meaning":"Dùng răng ép mạnh vào một vật gì đó để làm vỡ, tách rời hoặc để lại dấu."},"3796":{"word":"tỉnh lại","meaning":"Thoát khỏi trạng thái ngủ, say rượu hay hôn mê để trở lại trạng thái tỉnh táo, có ý thức."},"3797":{"word":"đánh thức","meaning":"Làm cho người đang ngủ thoát khỏi giấc ngủ và trở nên tỉnh táo."},"3798":{"word":"bẻ","meaning":"Dùng lực làm cho một vật dài, mỏng như cành cây, bông hoa bị gãy gập hoặc tách rời khỏi phần chính."},"3799":{"word":"ôm","meaning":"Vòng tay qua người nào đó và giữ chặt họ sát vào cơ thể để thể hiện tình cảm hoặc an ủi."},"3800":{"word":"chặt","meaning":"Biểu thị hành động được thực hiện một cách chắc chắn, không lỏng lẻo hoặc với sự chính xác tuyệt đối."},"3801":{"word":"đỉnh","meaning":"Phần cao nhất của một vật thể nào đó, đặc biệt là vật đứng thẳng."},"3802":{"word":"tỉ mỉ","meaning":"Rất cẩn thận, kỹ lưỡng, chú ý đến từng chi tiết nhỏ và đảm bảo mọi việc được thực hiện chính xác."},"3803":{"word":"kỹ lưỡng","meaning":"Mô tả hành động làm việc rất cẩn thận, chú ý đến từng chi tiết nhỏ để không bỏ sót điều gì."},"3804":{"word":"đếm (bằng ngón tay)","meaning":"Dùng các ngón tay để thể hiện hoặc theo dõi số lượng, thường bằng cách gập từng ngón một."},"3805":{"word":"được chọn, được xếp hạng","meaning":"Được lựa chọn hoặc đặt vào một nhóm đặc biệt, thường được công nhận là một trong những người hoặc vật tốt nhất, quan trọng nhất."},"3806":{"word":"bị cắm, được găm","meaning":"Bị đẩy hoặc giữ cố định vào một vật hay bề mặt nào đó để nó ở yên tại chỗ."},"3807":{"word":"cắm hoa","meaning":"Hoạt động nghệ thuật lựa chọn và sắp xếp hoa, cây xanh vào bình để tạo thành một tác phẩm trang trí đẹp mắt."},"3808":{"word":"cánh hoa","meaning":"Một trong những phần mềm mại, đầy màu sắc tạo nên phần bên ngoài dễ thấy của một bông hoa."},"3809":{"word":"vay","meaning":"Lấy tiền hoặc đồ vật của người khác để dùng tạm rồi sẽ trả lại."},"3810":{"word":"gói ghém, sắp xếp","meaning":"Đặt nhiều đồ vật vào hộp hoặc túi một cách gọn gàng, thường là để di chuyển hoặc đi du lịch."},"3811":{"word":"trang trí, tô điểm","meaning":"Làm cho một cái gì đó trở nên hấp dẫn hơn bằng cách thêm đồ vật đẹp hoặc thay đổi hình thức bên ngoài."},"3812":{"word":"bền bỉ, kiên trì","meaning":"Mô tả một việc gì đó diễn ra hoặc tiếp tục đều đặn với tốc độ hoặc cường độ như nhau, không ngừng nghỉ hay thay đổi."},"3813":{"word":"lời quở trách, lời mắng","meaning":"Những lời nặng nề mà ai đó nói khi tức giận về hành động hoặc thái độ không đúng của người khác."},"3814":{"word":"quỳ","meaning":"Hạ thấp cơ thể và đặt đầu gối xuống đất, thường để bày tỏ sự tôn kính hoặc phục tùng."},"3815":{"word":"Mơ, nằm mơ","meaning":"Trải nghiệm một loạt suy nghĩ, hình ảnh hoặc cảm xúc trong tâm trí khi đang ngủ."},"3816":{"word":"Giấc mơ","meaning":"Thế giới tưởng tượng hoặc trạng thái tinh thần nơi các suy nghĩ và hình ảnh xuất hiện khi một người đang ngủ."},"3817":{"word":"Gật đầu","meaning":"Di chuyển đầu lên xuống, thường để thể hiện sự đồng ý, hiểu biết hoặc chào hỏi."},"3818":{"word":"Liên tục, không ngừng","meaning":"Diễn tả điều gì đó tiếp diễn mà không có bất kỳ sự tạm dừng hay ngừng lại nào, xảy ra mọi lúc."},"3819":{"word":"Liên tục, không ngừng","meaning":"Theo cách mà điều gì đó xảy ra hoặc tiếp diễn mọi lúc, không có bất kỳ sự dừng lại hay gián đoạn nào."},"3820":{"word":"Bị kéo lê, bị lôi","meaning":"Di chuyển trên một bề mặt trong khi tiếp xúc, thường do quá dài hoặc quá nặng."},"3821":{"word":"Kéo, lôi","meaning":"Tác dụng lực lên một vật hoặc người, khiến vật hoặc người đó di chuyển lại gần mình hơn."},"3822":{"word":"Ôm chặt, ôm","meaning":"Vòng tay ôm chắc chắn một người hoặc vật, giữ họ rất sát vào cơ thể mình."},"3823":{"word":"Vô tận, không giới hạn","meaning":"Diễn tả điều gì đó không có giới hạn hoặc điểm kết thúc, dường như kéo dài mãi mãi."},"3824":{"word":"Vô tận, không ngừng","meaning":"Theo một cách tiếp diễn mà không dừng lại hoặc đạt đến điểm cuối cùng."},"3825":{"word":"Bị kẹt, bị mắc kẹt","meaning":"Bị giữ chặt trong một không gian giữa hai vật, khiến khó rút ra."},"3826":{"word":"Chen vào, xen vào","meaning":"Cố gắng đi vào một không gian hoặc hàng người, phương tiện một cách mạnh mẽ, thường là không được phép."},"3827":{"word":"gài, xỏ","meaning":"Đưa một vật vào một khe hẹp hoặc lỗ hổng để cố định hoặc kết nối nó lại."},"3828":{"word":"bị kẹt, mắc kẹt","meaning":"Bị mắc vào một khoảng trống hoặc khe hở và bị giữ chặt lại không rơi ra được."},"3829":{"word":"khiến sởn gai ốc","meaning":"Gây ra cảm giác lạnh hoặc sợ hãi đột ngột lan khắp da, thường khiến lông tóc dựng đứng."},"3830":{"word":"gây ra, ảnh hưởng","meaning":"Trở thành nguyên nhân hoặc nguồn gốc gây ra sự lo lắng hoặc tình huống khó chịu cho người khác."},"3831":{"word":"được chia, phân chia","meaning":"Được tách ra hoặc trở nên riêng biệt thành nhiều phần hoặc nhóm khác nhau."},"3832":{"word":"song song, sát bên nhau","meaning":"Hai hoặc nhiều vật/người được đặt song song, gần nhau và cùng hướng về một phía."},"3833":{"word":"tùy thuộc vào","meaning":"Kết quả hoặc đặc điểm của một tình huống hoàn toàn được quyết định bởi một điều kiện cụ thể hoặc hành động của một người."},"3834":{"word":"mắng mỏ, quở trách","meaning":"Nói chuyện một cách kiên quyết và không đồng tình với người đã hành xử sai, khiến họ nhận ra lỗi của mình."},"3835":{"word":"cành cây","meaning":"Một phần thân gỗ chắc chắn mọc ra từ thân chính của cây hoặc thực vật, thường mang theo các cành nhỏ hơn, lá và hoa."},"3836":{"word":"bướm","meaning":"Một loài côn trùng biết bay, nổi tiếng với thân mảnh và hai cặp cánh rộng, thường có màu sắc rực rỡ, hay được thấy giữa những bông hoa."},"3837":{"word":"bước ra, ra mặt","meaning":"Tự mình di chuyển từ một không gian kín hoặc vị trí thụ động ra một khu vực công cộng hoặc đóng vai trò tích cực trong một tình huống."},"3838":{"word":"tiến lên, tiến tới","meaning":"Di chuyển vật lý theo một hướng cụ thể hoặc đạt được tiến bộ trong một quá trình hoặc hoạt động."},"3839":{"word":"náo loạn","meaning":"Tình trạng mất trật tự, ồn ào và lộn xộn trên diện rộng."},"3840":{"word":"khó xử","meaning":"Cảm thấy không thoải mái, lúng túng vì ở trong tình huống khó khăn, bất tiện."},"3841":{"word":"cánh","meaning":"Bộ phận trên cơ thể chim, côn trùng hoặc máy bay giúp chúng bay được."},"3842":{"word":"bay đi","meaning":"Bị gió làm cho vật nhẹ bay rời khỏi vị trí ban đầu và biến mất."},"3843":{"word":"phấp phới","meaning":"Bị gió làm cho vật thể như cờ chuyển động lượn sóng trong không khí nhưng vẫn ở nguyên chỗ."},"3844":{"word":"bay lượn","meaning":"Di chuyển trong không khí theo nhiều hướng khác nhau, không theo một đường thẳng."},"3845":{"word":"bay đến","meaning":"Một sinh vật có cánh di chuyển trong không khí từ nơi này đến một điểm khác."},"3846":{"word":"sắc bén","meaning":"Có đầu nhọn hoặc cạnh mỏng, rất dễ cắt hoặc xuyên qua."},"3847":{"word":"anh chị em","meaning":"Con trai và con gái cùng cha mẹ."},"3848":{"word":"nam bắc","meaning":"Hai hướng đối diện nhau, một hướng là phía bắc và một hướng là phía nam."},"3849":{"word":"lãng phí","meaning":"Hành động sử dụng tiền bạc, thời gian hoặc vật liệu một cách không cần thiết, không mang lại kết quả hữu ích."},"3850":{"word":"giảm","meaning":"Làm cho một cái gì đó hoặc một mức độ nào đó trở nên thấp hơn hoặc ít đi."},"3851":{"word":"đặt ra, bày ra","meaning":"Lấy một vật từ bên trong ra và đặt nó ở nơi mở hoặc bên ngoài để có thể nhìn thấy hoặc tiếp cận được."},"3852":{"word":"nhìn ra ngoài","meaning":"Hướng tầm nhìn từ một không gian bên trong, qua cửa sổ hoặc khe hở, ra môi trường bên ngoài."},"3853":{"word":"nhìn xuống","meaning":"Hướng mắt từ một vị trí cao hơn để quan sát một vật hoặc điểm ở phía dưới."},"3854":{"word":"đậu xuống, hạ xuống","meaning":"Tiếp đất hoặc ổn định cơ thể trên một bề mặt, thường sau khi di chuyển từ trên cao xuống."},"3855":{"word":"đưa ra, thò ra","meaning":"Di chuyển một bộ phận cơ thể như cánh tay hoặc bàn tay ra xa khỏi mình vào không gian trống."},"3856":{"word":"vứt bỏ, bỏ mặc","meaning":"Vứt đi một vật không mong muốn hoặc rời bỏ một người/vật mà không còn chăm sóc hay chú ý nữa."},"3857":{"word":"bên trong, nội bộ","meaning":"Không gian hoặc khu vực tồn tại trong giới hạn hoặc bức tường của một vật thể hay tòa nhà."},"3858":{"word":"đề cử, đưa ra","meaning":"Trình bày một người hoặc một ý tưởng để xem xét hoặc công khai, thường là đặt họ vào vị trí nổi bật."},"3859":{"word":"trong và ngoài","meaning":"Thuật ngữ này đề cập đến cả khu vực bên trong ranh giới và khu vực trực tiếp xung quanh một địa điểm hoặc vật thể."},"3860":{"word":"đuổi ra, tống cổ","meaning":"Cưỡng bức một người hoặc động vật rời khỏi một tòa nhà hoặc khu vực."},"3861":{"word":"nước lạnh","meaning":"Chất lỏng có nhiệt độ thấp, thường được phục vụ với đá hoặc giữ trong tủ lạnh."},"3862":{"word":"rộng lượng, bao dung","meaning":"Sẵn lòng cho tiền bạc, thời gian hoặc giúp đỡ người khác, hoặc rất thấu hiểu và tha thứ lỗi lầm."},"3863":{"word":"bên kia","meaning":"Chỗ ở phía đối diện, vượt qua một ranh giới hoặc chướng ngại vật nào đó."},"3864":{"word":"vô cùng","meaning":"Được dùng để nhấn mạnh mức độ cao của một sự việc hoặc tính chất nào đó."},"3865":{"word":"dư dả","meaning":"Có nhiều hơn mức cần thiết, thường dùng cho tiền bạc, thời gian hoặc vật phẩm."},"3866":{"word":"rộng ra","meaning":"Trở nên lớn hơn về bề ngang hoặc diện tích, như một con đường hay không gian."},"3867":{"word":"mở rộng","meaning":"Làm cho một cái gì đó trở nên lớn hơn về bề ngang hoặc diện tích."},"3868":{"word":"chuyển giao","meaning":"Chuyển giao vật phẩm hoặc trách nhiệm từ người này sang người khác."},"3869":{"word":"vượt qua","meaning":"Đi qua, vượt qua một thời gian, giai đoạn hoặc giới hạn nào đó."},"3870":{"word":"làm đổ","meaning":"Khiến vật gì đó đang đứng thẳng bị ngã xuống đất."},"3871":{"word":"ngả về phía","meaning":"Vật đang đứng bị nghiêng hoặc ngả về phía người nói."},"3872":{"word":"tràn","meaning":"Khi chất lỏng chứa đầy và chảy tràn ra ngoài, hoặc dòng sông vượt quá bờ."},"3873":{"word":"hình vuông","meaning":"Hình có bốn cạnh bằng nhau và bốn góc vuông."},"3874":{"word":"cư dân mạng","meaning":"Người hoạt động trên không gian mạng như Internet."},"3875":{"word":"thằng","meaning":"Từ dùng để gọi một người (thường là nam giới) hoặc một con vật một cách thân mật, suồng sã hoặc đôi khi hơi tiêu cực."},"3876":{"word":"năm","meaning":"Khoảng thời gian mười hai tháng từ tháng Một đến tháng Mười Hai, thường được biểu thị bằng một con số."},"3877":{"word":"lao động","meaning":"Sức lực thể chất hoặc tinh thần mà con người bỏ ra để sản xuất hàng hóa hoặc dịch vụ, thường là một công việc."},"3878":{"word":"người lao động","meaning":"Người kiếm sống bằng tiền công hoặc thu nhập có được từ việc làm một công việc nào đó."},"3879":{"word":"lườm","meaning":"Nhìn ai đó hoặc cái gì đó bằng ánh mắt giận dữ, thù địch hoặc rất tập trung."},"3880":{"word":"làm tan chảy","meaning":"Biến một vật thể đông cứng (như băng, tuyết) thành chất lỏng bằng cách tác động nhiệt."},"3881":{"word":"ghi hình","meaning":"Hành động lưu lại hình ảnh và âm thanh từ một chương trình phát sóng hoặc sự kiện trực tiếp để có thể xem lại sau này."},"3882":{"word":"lô-gic","meaning":"Một hệ thống tư duy mà các ý tưởng liên kết với nhau một cách rõ ràng, hợp lý và chính xác."},"3883":{"word":"lô-gic","meaning":"Có tính chất hợp lý, rõ ràng và có trật tự trong cách các phần kết nối với nhau."},"3884":{"word":"thảo luận","meaning":"Hoạt động trao đổi ý kiến về một chủ đề cụ thể để chia sẻ quan điểm hoặc tìm kiếm giải pháp."},"3885":{"word":"tranh luận","meaning":"Một cuộc đối thoại có tính chất trang trọng hoặc sự bất đồng gay gắt giữa những người có ý kiến khác nhau về một vấn đề."},"3886":{"word":"đáng ngạc nhiên","meaning":"Gây ra cảm giác kinh ngạc, thán phục hoặc vui sướng bất ngờ vì điều gì đó đặc biệt tốt đẹp hoặc độc đáo."},"3887":{"word":"trêu chọc","meaning":"Dùng lời nói hay hành động để khiến người khác thấy bối rối, tức giận hoặc để mua vui."},"3888":{"word":"chọc ghẹo","meaning":"Dùng những lời nói hay hành động nhẹ nhàng, tinh nghịch để đùa vui với ai đó."},"3889":{"word":"nông dân","meaning":"Người có công việc chính là trồng trọt hoặc chăn nuôi trên một mảnh đất."},"3890":{"word":"công việc đồng áng","meaning":"Các công việc và hoạt động liên quan đến việc trồng trọt hoặc chăn nuôi trên đất nông nghiệp."},"3891":{"word":"nông sản","meaning":"Các loại thực phẩm như gạo, rau, củ, quả được sản xuất từ hoạt động nông nghiệp."},"3892":{"word":"nông nghiệp","meaning":"Ngành nghề và hoạt động trồng cây, nuôi con vật để sản xuất lương thực, sợi, và các sản phẩm khác phục vụ con người."},"3893":{"word":"nông thôn","meaning":"Khu vực đất đai xa thành phố lớn, thường có nhiều cánh đồng hoặc rừng cây, nơi người dân sống trong cộng đồng nhỏ."},"3894":{"word":"đặt để","meaning":"Đặt một vật ở một vị trí cụ thể và để nó ở yên đó mà không di chuyển hay tác động gì thêm."},"3895":{"word":"để yên","meaning":"Đặt một vật vào một vị trí và không làm gì thêm, không can thiệp vào nó."},"3896":{"word":"não","meaning":"Cơ quan mềm màu xám nằm bên trong đầu người hoặc động vật, điều khiển suy nghĩ, cảm xúc, ký ức và các chức năng của cơ thể."},"3897":{"word":"chị (kính trọng)","meaning":"Cách gọi người phụ nữ lớn tuổi hơn mình (dùng bởi người nam), thể hiện sự tôn trọng."},"3898":{"word":"qua đời","meaning":"Từ dùng để nói về việc một người nào đó đã chết một cách lịch sự, trang trọng."},"3899":{"word":"ánh nhìn","meaning":"Hướng hoặc đường nhìn của ai đó, thường tập trung nhanh vào một điều gì đó."},"3900":{"word":"đồng tử","meaning":"Phần màu đen nằm ở trung tâm nhãn cầu."},"3901":{"word":"mở mắt","meaning":"Tách mi mắt trên và mi mắt dưới ra để có thể nhìn thấy."},"3902":{"word":"ánh mắt","meaning":"Nét biểu cảm hiện rõ trong đôi mắt của một người, thể hiện cảm xúc hoặc ý định của họ."},"3903":{"word":"lông mày","meaning":"Dãy lông ngắn mọc trên phần xương gồ lên phía trên mỗi mắt."},"3904":{"word":"trước mắt","meaning":"Khu vực không gian nằm ngay phía trước mắt của một người."},"3905":{"word":"sự nhạy bén","meaning":"Khả năng nhanh chóng nhận ra và hiểu được cảm xúc chưa được nói ra của người khác hoặc tình huống hiện tại."},"3906":{"word":"đặt nằm","meaning":"Đặt một người hoặc vật xuống bề mặt sao cho cơ thể họ ở tư thế nằm ngang."},"3907":{"word":"thong thả","meaning":"Không vội vã hay lo lắng nhiều, thường thể hiện sự từ tốn và hành động không nhanh chóng."},"3908":{"word":"béo ngậy","meaning":"Có vị hoặc kết cấu đậm đà do nhiều chất béo hoặc dầu, có thể gây cảm giác nặng nề hoặc ngán trong miệng."},"3909":{"word":"bày ra","meaning":"Đặt các vật phẩm, đồ đạc... thành một hàng hoặc trải ra."},"3910":{"word":"xếp hàng","meaning":"Hình thành một hàng dài hoặc một chuỗi người hoặc vật, đứng hoặc được đặt liên tiếp nhau."},"3911":{"word":"kéo dài, kéo giãn","meaning":"Làm cho một vật gì đó dài hoặc rộng hơn kích thước ban đầu bằng cách kéo hai đầu của nó."},"3912":{"word":"cuối thu","meaning":"Thời điểm cuối cùng của mùa thu."},"3913":{"word":"cuối đông","meaning":"Giai đoạn cuối cùng của mùa đông."},"3914":{"word":"cuối xuân","meaning":"Giai đoạn cuối cùng của mùa xuân."},"3915":{"word":"bị chậm trễ","meaning":"Một sự kiện hoặc hành động xảy ra sau thời gian đã định hoặc dự kiến."},"3916":{"word":"cuối hè","meaning":"Giai đoạn cuối cùng của mùa hè."},"3917":{"word":"trì hoãn","meaning":"Cố ý làm cho một sự kiện hoặc hành động xảy ra vào một thời điểm muộn hơn."},"3918":{"word":"ông/bà/anh/chị","meaning":"Từ dùng sau tên hoặc chức danh để thể hiện sự lịch sự và tôn trọng khi xưng hô trực tiếp."},"3919":{"word":"lại gần, tiếp cận","meaning":"Di chuyển về phía một vật hoặc một người, rút ngắn khoảng cách vật lý."},"3920":{"word":"bước tới gần","meaning":"Thực hiện một động tác chân để giảm khoảng cách giữa bản thân và một vật hoặc người khác."},"3921":{"word":"đến gần, tiến lại","meaning":"Một vật hoặc người di chuyển từ xa về phía một điểm hoặc người cụ thể, rút ngắn khoảng cách giữa họ."},"3922":{"word":"ghé thăm, đến chơi","meaning":"Đến một địa điểm hoặc nhà của ai đó trong một thời gian ngắn rồi rời đi."},"3923":{"word":"tỉa, gọt","meaning":"Làm cho cái gì đó gọn gàng, sạch sẽ hơn bằng cách cắt bỏ hoặc điều chỉnh những phần không cần thiết."},"3924":{"word":"xử lý, giải quyết","meaning":"Thực hiện, điều khiển hoặc quản lý một công việc, vấn đề hay đối tượng nào đó."},"3925":{"word":"không khác gì, y hệt","meaning":"Có những đặc điểm hoặc hình thức hoàn toàn giống nhau, không có sự phân biệt."},"3926":{"word":"ủi, là","meaning":"Dùng bàn là hoặc dụng cụ nóng khác để làm phẳng các nếp nhăn trên quần áo hoặc vải vóc."},"3927":{"word":"chỉ, duy chỉ","meaning":"Diễn tả sự giới hạn, rằng điều gì đó chỉ đúng trong một trường hợp cụ thể hoặc có một ngoại lệ."},"3928":{"word":"ngậm, khép","meaning":"Đưa hai mép lại gần nhau hoặc đóng lại hoàn toàn để không còn khoảng trống, thường dùng cho miệng hoặc mắt."},"3929":{"word":"hơi, ít nhiều","meaning":"Ở một mức độ nhỏ hoặc vừa phải, không quá nhiều nhưng đủ để nhận thấy."},"3930":{"word":"đa số, số đông","meaning":"Một số lượng lớn người hoặc vật, thường chiếm phần lớn trong một tập hợp."},"3931":{"word":"lời hứa, cam kết","meaning":"Một lời hứa hoặc sự cam đoan chắc chắn, nghiêm túc với bản thân hoặc người khác về việc sẽ làm hay không làm điều gì đó."},"3932":{"word":"cãi nhau, tranh cãi","meaning":"Trao đổi những lời lẽ giận dữ, bất đồng với ai đó, hoặc có sự xô xát, tranh giành với người khác."},"3933":{"word":"may mắn, đáng mừng","meaning":"Mang lại cảm giác may mắn hoặc đáng mừng vì tình hình không tệ như dự kiến."},"3934":{"word":"duy nhất, chỉ","meaning":"Dùng để chỉ rõ rằng chỉ có một số lượng cụ thể nào đó, không hơn không kém, thường là một món đồ hoặc một khoảng thời gian ngắn."},"3935":{"word":"giai đoạn","meaning":"Một phần hoặc thời kỳ riêng biệt trong một quá trình hoặc chuỗi sự kiện."},"3936":{"word":"khách quen","meaning":"Người thường xuyên lui tới cùng một cửa hàng, nhà hàng để mua sắm hoặc sử dụng dịch vụ."},"3937":{"word":"ngắn hạn","meaning":"Khoảng thời gian không dài, diễn ra trong một thời gian ngắn."},"3938":{"word":"đơn độc","meaning":"Ở một mình hoặc thực hiện một mình, không có sự tham gia của người khác."},"3939":{"word":"kiểm soát","meaning":"Hành động của cơ quan chức năng để đảm bảo tuân thủ quy tắc và ngăn chặn hành vi sai trái."},"3940":{"word":"đơn thuần","meaning":"Một cách dễ dàng, không phức tạp, chỉ tập trung vào một khía cạnh."},"3941":{"word":"khu phức hợp","meaning":"Một khu vực có nhiều tòa nhà hoặc công trình cùng mục đích được xây dựng gần nhau."},"3942":{"word":"an ủi","meaning":"Làm cho ai đó đang buồn, khóc hoặc đau cảm thấy dễ chịu hơn bằng lời nói hoặc hành động nhẹ nhàng."},"3943":{"word":"chạy đi","meaning":"Di chuyển nhanh bằng chân theo một hướng cụ thể, hướng tới một địa điểm."},"3944":{"word":"lao vào","meaning":"Di chuyển về phía ai đó hoặc cái gì đó một cách bất ngờ và nhanh chóng, thường với ý định mạnh mẽ hoặc háo hức."},"3945":{"word":"chạy đến","meaning":"Di chuyển nhanh bằng chân từ xa, hướng về phía người nói hoặc người quan sát."},"3946":{"word":"khác","meaning":"Theo một cách không giống với cái khác, hoặc như một yếu tố bổ sung."},"3947":{"word":"treo","meaning":"Được treo hoặc gắn cố định vào một vật khác, thường là trên bề mặt của nó."},"3948":{"word":"ánh trăng","meaning":"Ánh sáng dịu nhẹ tự nhiên phát ra từ mặt trăng vào ban đêm."},"3949":{"word":"sự đạt được","meaning":"Việc hoàn thành thành công một mục tiêu, nhiệm vụ hoặc kế hoạch sau khi đã nỗ lực."},"3950":{"word":"trốn thoát","meaning":"Nhanh chóng rời đi khỏi một nơi nguy hiểm, tình huống khó khăn hoặc sự truy bắt để giành tự do."},"3951":{"word":"đạt đến","meaning":"Đến một điểm, mức độ hoặc số lượng cụ thể, thường là điểm cuối hoặc tổng số."},"3952":{"word":"mòn","meaning":"Trở nên mỏng hơn, nhỏ hơn hoặc hư hại dần do sử dụng liên tục hoặc ma sát theo thời gian."},"3953":{"word":"tường","meaning":"Cấu trúc thẳng đứng, thường làm bằng gạch, đá, gỗ, dùng để bao quanh, phân chia khu vực hoặc tạo sự riêng tư."},"3954":{"word":"ngày hôm sau","meaning":"Từ địa phương chỉ ngày kế tiếp, ngày sau đó."},"3955":{"word":"sự phụ trách","meaning":"Nhiệm vụ hoặc công việc cụ thể mà một người được giao để giám sát hoặc quản lý trong một tổ chức."},"3956":{"word":"người phụ trách","meaning":"Cá nhân được giao nhiệm vụ quản lý hoặc giám sát một công việc, dự án hoặc lĩnh vực cụ thể."},"3957":{"word":"thanh đạm","meaning":"Có hương vị nhẹ nhàng, không béo ngậy, không đậm đà quá mức (thường dùng cho thức ăn)."},"3958":{"word":"chăn","meaning":"Vật dùng để đắp giữ ấm cơ thể, thường làm bằng vải mềm, dày."},"3959":{"word":"giáo viên chủ nhiệm","meaning":"Người phụ trách và hướng dẫn một lớp học cụ thể trong suốt năm học."},"3960":{"word":"câu trả lời","meaning":"Lời nói hoặc văn bản được đưa ra để hồi đáp một câu hỏi hoặc yêu cầu."},"3961":{"word":"mỗi, trên","meaning":"Một hậu tố gắn vào sau một từ để chỉ tỉ lệ hoặc số lượng cho mỗi đơn vị."},"3962":{"word":"kéo","meaning":"Dùng lực tác động vào một vật để đưa nó lại gần mình hơn hoặc di chuyển theo một hướng cụ thể."},"3963":{"word":"tự tin, đĩnh đạc","meaning":"Thể hiện niềm tin vững chắc vào khả năng và giá trị của bản thân, thường qua tư thế thẳng thắn và lời nói rõ ràng."},"3964":{"word":"tạm thời, trong một thời gian","meaning":"Mô tả điều gì đó sẽ xảy ra hoặc tồn tại trong một khoảng thời gian không xác định, không quá dài, bắt đầu từ bây giờ."},"3965":{"word":"lúc đó, thời điểm đó","meaning":"Chỉ thời điểm một sự kiện đã xảy ra trong quá khứ, đặc biệt là một điểm đã được nhắc đến hoặc ngụ ý trước đó."},"3966":{"word":"trong ngày, cùng ngày","meaning":"Mô tả điều gì đó diễn ra hoặc kết thúc trong khoảng thời gian một ngày duy nhất từ bình minh đến hoàng hôn."},"3967":{"word":"trúng thưởng, trúng số","meaning":"Sự kiện khi tấm vé hoặc con số cụ thể của ai đó được chọn ngẫu nhiên để nhận phần thưởng hoặc tiền."},"3968":{"word":"bị, chịu","meaning":"Phải chịu đựng nỗi đau hoặc thiệt hại không mong muốn."},"3969":{"word":"đại-, lớn","meaning":"Một tiền tố đặt ở đầu một từ khác để chỉ rằng sự vật có kích thước hoặc quy mô đáng kể."},"3970":{"word":"giá cả, chi phí","meaning":"Số tiền hoặc vật phẩm khác phải trả để có được hàng hóa hoặc dịch vụ."},"3971":{"word":"đại khái","meaning":"Không đi sâu vào chi tiết, chỉ tập trung vào các phần chính."},"3972":{"word":"đa phần","meaning":"Chỉ sự việc xảy ra theo lẽ thường hoặc chiếm phần lớn trong một tổng thể."},"3973":{"word":"quy mô lớn","meaning":"Chỉ cái gì đó liên quan đến số lượng lớn người hoặc vật, hoặc diễn ra trên một khu vực rộng lớn."},"3974":{"word":"khí quyển","meaning":"Lớp khí bao quanh Trái Đất, bao gồm không khí chúng ta hít thở."},"3975":{"word":"sự chờ đợi","meaning":"Hành động nán lại một chỗ cho đến khi có việc xảy ra hoặc người nào đó đến."},"3976":{"word":"doanh nghiệp lớn","meaning":"Một doanh nghiệp có quy mô lớn với nhiều nhân viên và số vốn lớn."},"3977":{"word":"giữa ban ngày","meaning":"Khoảng thời gian ban ngày sáng rõ khi mặt trời lên cao."},"3978":{"word":"đa số","meaning":"Phần lớn hơn hoặc số lượng lớn hơn khi so sánh với tổng số người hoặc vật."},"3979":{"word":"vô cùng","meaning":"Chỉ mức độ rất cao, vượt trội hơn bình thường, làm cho sự việc nổi bật."},"3980":{"word":"dàn ý","meaning":"Nội dung tóm tắt các ý chính một cách ngắn gọn, không đi vào chi tiết."},"3981":{"word":"số lượng lớn","meaning":"Một số lượng hoặc khối lượng lớn."},"3982":{"word":"đại lộ","meaning":"Một con đường công cộng rộng, thường thấy trong thành phố, có hàng cây trồng dọc hai bên."},"3983":{"word":"đại diện","meaning":"Người hoặc vật đảm nhiệm vai trò, vị trí của người hoặc vật khác."},"3984":{"word":"sự đối lập","meaning":"Tình trạng hai hoặc nhiều bên, ý kiến chống đối mạnh mẽ lẫn nhau, thường thể hiện qua tranh cãi."},"3985":{"word":"sự tương phản","meaning":"Sự khác biệt rõ rệt giữa hai hay nhiều vật khi được đặt cạnh nhau hoặc so sánh."},"3986":{"word":"sự phòng bị","meaning":"Hành động sắp xếp và chuẩn bị mọi thứ trước cho một sự kiện trong tương lai hoặc một vấn đề tiềm ẩn."},"3987":{"word":"đại sứ","meaning":"Một nhà ngoại giao cấp cao đại diện cho chính phủ nước mình ở một quốc gia khác, thường làm việc tại đại sứ quán."},"3988":{"word":"lời thoại","meaning":"Những lời nói cụ thể mà diễn viên thể hiện từ kịch bản trong một vở kịch, phim điện ảnh hoặc chương trình truyền hình."},"3989":{"word":"đối tượng","meaning":"Một cá nhân hoặc nhóm được chọn hoặc chỉ định rõ ràng để nhận một hành động, nghiên cứu hoặc lợi ích cụ thể."},"3990":{"word":"sự ứng phó","meaning":"Hành động hoặc phản ứng được thực hiện để đáp lại một sự kiện hoặc tuyên bố cụ thể."},"3991":{"word":"sự tiếp đãi","meaning":"Hành động niềm nở chào đón khách vào nhà hoặc cơ sở của mình, thường là bằng cách mời đồ ăn thức uống."},"3992":{"word":"sự đối chiếu","meaning":"Hành động xem xét kỹ lưỡng hai hoặc nhiều vật để tìm ra điểm khác biệt hoặc tương đồng của chúng."},"3993":{"word":"văn hóa đại chúng","meaning":"Tập hợp các ý tưởng, hoạt động và đối tượng như âm nhạc, phim ảnh, thời trang được hầu hết mọi người trong xã hội yêu thích và chia sẻ."},"3994":{"word":"biện pháp đối phó","meaning":"Một hành động hoặc kế hoạch cụ thể được tạo ra để giải quyết vấn đề hoặc ngăn chặn tình huống khó khăn trở nên tồi tệ hơn."},"3995":{"word":"đối phó","meaning":"Hành động đối phó, xử lý một vấn đề hoặc tình huống khó khăn nảy sinh."},"3996":{"word":"thay thế","meaning":"Việc dùng một cái khác thay cho cái đã có hoặc cái dự định ban đầu."},"3997":{"word":"cho vay","meaning":"Việc cho phép ai đó sử dụng tiền hoặc một vật phẩm (như sách) trong một khoảng thời gian nhất định với điều kiện phải trả lại."},"3998":{"word":"đại khái","meaning":"Một cách nhanh chóng, không chú ý nhiều đến từng chi tiết nhỏ hoặc không làm cho nó hoàn toàn chính xác."},"3999":{"word":"đập","meaning":"Một công trình xây dựng chắn ngang sông hoặc biển để kiểm soát lượng nước và sản xuất điện."},"4000":{"word":"hơn nữa","meaning":"Dùng để bổ sung thêm thông tin làm cho điều đã nói trước đó trở nên mạnh mẽ hoặc quan trọng hơn."},"4001":{"word":"làm bẩn","meaning":"Làm cho một vật gì đó (như quần áo hoặc sàn nhà) trở nên không sạch sẽ do bị dính bùn, bụi bẩn hoặc chất khác."},"4002":{"word":"cùng với","meaning":"Cùng tồn tại hoặc tham gia với người hoặc nhóm khác, thường làm điều gì đó hoặc sống ở cùng một nơi."},"4003":{"word":"thậm chí còn hơn","meaning":"Dùng để nhấn mạnh rằng một điều gì đó đã tăng lên một mức độ hoặc phạm vi cao hơn trước đây."},"4004":{"word":"hơn thế nữa","meaning":"Dùng để giới thiệu thêm thông tin đặc biệt quan trọng hoặc gây ngạc nhiên, dựa trên những gì vừa nói."},"4005":{"word":"cái nóng","meaning":"Cảm giác thể chất không thoải mái do nhiệt độ cao, thường khiến cơ thể đổ mồ hôi nhiều, đặc biệt vào mùa hè."},"4006":{"word":"đức","meaning":"Phẩm chất tốt đẹp, cao quý của con người, thể hiện sự hiểu biết và chấp nhận người khác."},"4007":{"word":"ơn","meaning":"Sự giúp đỡ hoặc ưu ái mà người khác đã mang lại."},"4008":{"word":"thêm vào","meaning":"Gắn hoặc thêm một phần khác vào một vật hoặc lời nói đã có."},"4009":{"word":"cục","meaning":"Một vật rắn, không có hình dạng xác định, tách ra từ một thể lớn hơn."},"4010":{"word":"được che phủ","meaning":"Có vật gì đó được đặt lên trên, khiến vật bên dưới không còn nhìn thấy."},"4011":{"word":"hâm nóng","meaning":"Làm cho thức ăn hoặc vật gì đó ấm hoặc nóng lên."},"4012":{"word":"trộm cắp","meaning":"Hành vi lén lút lấy tài sản của người khác mà không được sự cho phép."},"4013":{"word":"rốt cuộc","meaning":"Từ dùng để nhấn mạnh sự thắc mắc, bối rối trong câu hỏi hoặc câu phủ định."},"4014":{"word":"trở lại","meaning":"Quay về vị trí hoặc trạng thái ban đầu, hoặc làm ngược lại điều đã làm."},"4015":{"word":"trái lại","meaning":"Diễn tả một sự việc xảy ra hoàn toàn khác hoặc trái ngược với điều đã nghĩ hoặc mong đợi."},"4016":{"word":"thớt","meaning":"Một tấm gỗ hoặc nhựa phẳng, dùng để kê khi thái hoặc băm thức ăn bằng dao."},"4017":{"word":"sự bỏ trốn","meaning":"Hành động nhanh chóng rời khỏi một nơi hoặc tình huống nguy hiểm để thoát thân."},"4018":{"word":"bỏ trốn","meaning":"Rời khỏi một nơi hoặc tình huống nguy hiểm một cách nhanh chóng để tìm sự an toàn."},"4019":{"word":"hoàn toàn không","meaning":"Dùng để nhấn mạnh sự phủ định hoặc sự không thể hiểu, không thể làm được điều gì đó."},"4020":{"word":"sự đưa vào","meaning":"Việc lần đầu tiên đưa một hệ thống, sản phẩm hoặc ý tưởng mới vào sử dụng."},"4021":{"word":"không cách nào","meaning":"Dùng để diễn tả việc không thể đạt được hoặc làm được điều gì đó dù đã cố gắng hết sức."},"4022":{"word":"thử thách","meaning":"Một nhiệm vụ hoặc tình huống khó khăn, đòi hỏi sức mạnh, kỹ năng hoặc sự quyết tâm của một người."},"4023":{"word":"chất độc","meaning":"Một chất có thể gây hại nghiêm trọng, hủy hoại sự sống hoặc làm suy yếu sức khỏe."},"4024":{"word":"độc lập","meaning":"Trạng thái tự do, không bị kiểm soát, ảnh hưởng hoặc phụ thuộc vào người khác."},"4025":{"word":"độc giả","meaning":"Người đọc và hiểu các chữ viết trong sách, báo hoặc các văn bản khác."},"4026":{"word":"độc đáo","meaning":"Rất đặc biệt và khác biệt so với những cái khác cùng loại, có những phẩm chất riêng biệt."},"4027":{"word":"nồng","meaning":"Có tác dụng mạnh mẽ và dữ dội, thường dùng để chỉ mùi, vị hoặc tính chất của chất lỏng."},"4028":{"word":"gửi trả lại","meaning":"Gửi một người hoặc một vật trở lại nơi xuất phát hoặc người gửi ban đầu."},"4029":{"word":"hòn đá","meaning":"Một viên đá nhỏ có thể cầm vừa trong một tay."},"4030":{"word":"ngoảnh lại","meaning":"Hành động quay đầu hoặc thân người để nhìn thứ gì đó đã ở phía sau."},"4031":{"word":"quay lại","meaning":"Thay đổi hướng đi hoặc hướng nhìn để đi hoặc nhìn về phía ngược lại."},"4032":{"word":"cùng khóa","meaning":"Người thuộc cùng một khóa học hoặc cùng một giai đoạn trong công việc, cuộc sống."},"4033":{"word":"động cơ","meaning":"Lý do bên trong khiến một người bắt đầu hoặc thực hiện một hành động cụ thể."},"4034":{"word":"Đông Nam Á","meaning":"Khu vực nằm ở phía đông nam của châu Á, bao gồm các quốc gia như Việt Nam, Thái Lan, Indonesia."},"4035":{"word":"bốn phương","meaning":"Bốn hướng chính: đông, tây, nam và bắc."},"4036":{"word":"người châu Á","meaning":"Người có nguồn gốc từ các quốc gia ở Đông Á như Hàn Quốc, Trung Quốc hoặc Nhật Bản."},"4037":{"word":"video","meaning":"Hình ảnh chuyển động thường có âm thanh, được hiển thị trên màn hình máy tính, điện thoại hoặc tivi."},"4038":{"word":"bài hát thiếu nhi","meaning":"Một bài hát đơn giản, vui tươi, thường dành cho trẻ em nghe hoặc hát."},"4039":{"word":"đồng nghĩa","meaning":"Sự giống nhau về ý nghĩa giữa hai hoặc nhiều từ."},"4040":{"word":"giống hệt","meaning":"Không có sự khác biệt nào giữa hai hoặc nhiều vật, hoàn toàn giống nhau."},"4041":{"word":"kiều bào","meaning":"Người cùng một quốc gia hoặc cùng dân tộc nhưng đang sinh sống ở nước ngoài."},"4042":{"word":"truyện cổ tích","meaning":"Một câu chuyện truyền thống dành cho trẻ em, thường có các yếu tố thần kỳ và kết thúc có hậu."},"4043":{"word":"truyện thiếu nhi","meaning":"Một cuốn sách kể những câu chuyện dành cho trẻ em."},"4044":{"word":"rất","meaning":"Từ biểu thị mức độ cao, rất rõ rệt của tính chất hoặc hành động."},"4045":{"word":"cố gắng hết sức","meaning":"Cố gắng tối đa để đạt được mức độ hoặc số lượng cao nhất có thể."},"4046":{"word":"trả lại, khôi phục","meaning":"Làm cho một cái gì đó trở lại trạng thái trước đó hoặc lấy lại cái gì đó đã mất."},"4047":{"word":"quay về, trở về","meaning":"Di chuyển từ vị trí hiện tại trở lại nơi đã từng ở trước đó."},"4048":{"word":"hồi sinh, làm sống lại","meaning":"Làm cho một cái gì đó đang chết, yếu hoặc không hoạt động trở nên mạnh mẽ, hoạt động hoặc sống lại."},"4049":{"word":"hồi sinh, sống lại","meaning":"Một cái gì đó đang chết, yếu hoặc không hoạt động tự trở nên mạnh mẽ, hoạt động hoặc sống lại."},"4050":{"word":"sự lặp lại","meaning":"Hành động lặp lại cùng một lời nói hoặc sự kiện, hoặc một sự kiện xảy ra liên tục."},"4051":{"word":"bộ não, não","meaning":"Một cơ quan nằm bên trong hộp sọ, quản lý các chức năng cảm nhận, suy nghĩ, hành động và ghi nhớ."},"4052":{"word":"nổi bật, rõ rệt","meaning":"Rất dễ nhìn thấy hoặc nhận ra vì nó nổi trội hơn hẳn những thứ xung quanh."},"4053":{"word":"gõ, đập nhẹ","meaning":"Dùng tay hoặc vật gì đó đánh nhẹ và lặp đi lặp lại lên một bề mặt, thường để gây ra tiếng động hoặc thu hút sự chú ý."},"4054":{"word":"nỗi sợ hãi, sự sợ hãi","meaning":"Cảm giác lo lắng hoặc hoảng sợ mạnh mẽ, khó chịu khi cảm thấy có nguy hiểm hoặc điều gì đó tồi tệ có thể xảy ra."},"4055":{"word":"sợ, khiếp sợ","meaning":"Cảm thấy lo lắng, hoảng sợ mạnh mẽ trước một điều gì đó nguy hiểm hoặc không may có thể xảy ra."},"4056":{"word":"đáng sợ, kinh sợ","meaning":"Có cảm giác lo lắng, hoảng sợ mạnh mẽ vì một điều gì đó nguy hiểm hoặc không may có vẻ sẽ xảy ra."},"4057":{"word":"quấn, choàng","meaning":"Đặt một vật gì đó dài, như quần áo, quanh một bộ phận cơ thể hoặc một vật khác."},"4058":{"word":"nhìn quanh, nhìn ngó nghiêng","meaning":"Nhanh chóng quay đầu nhìn khắp xung quanh, thường là do lo lắng hoặc đang tìm kiếm thứ gì đó."},"4059":{"word":"vài, đôi ba","meaning":"Chỉ một số lượng nhỏ các vật, thường là hai hoặc ba."},"4060":{"word":"nhìn quanh, xem xét xung quanh","meaning":"Quay đầu để nhìn ngắm mọi vật xung quanh một người hoặc một vật thể."},"4061":{"word":"bao quanh, vây quanh","meaning":"Tạo thành một vòng hoặc ranh giới hoàn chỉnh xung quanh một vật hoặc người khác."},"4062":{"word":"bị bao quanh, được bao quanh","meaning":"Bị hoặc được các vật khác tạo thành một vòng hoặc ranh giới hoàn chỉnh xung quanh."},"4063":{"word":"chu vi, vành","meaning":"Độ dài của đường viền bên ngoài một hình hoặc vật thể khép kín."},"4064":{"word":"tổ","meaning":"Cấu trúc do chim, côn trùng hoặc động vật khác xây bằng cành cây, lá để đẻ trứng và nuôi con."},"4065":{"word":"muộn, chậm trễ","meaning":"Xảy ra hoặc được thực hiện sau thời điểm thích hợp đã trôi qua."},"4066":{"word":"theo sau, đi theo","meaning":"Đi hoặc đuổi theo phía sau một người nào đó."},"4067":{"word":"tụt hậu","meaning":"Phát triển chậm hơn hoặc có chất lượng, trình độ thấp hơn so với người khác hay cái khác."},"4068":{"word":"tụt lại","meaning":"Đi chậm hơn hoặc tiến bộ kém hơn người khác nên ở vị trí thấp hơn hoặc xa hơn."},"4069":{"word":"lục soát","meaning":"Dùng tay tìm kiếm thứ gì đó đã giấu trong túi xách hay đồ vật nào đó."},"4070":{"word":"lật ngược","meaning":"Làm cho một mặt nào đó đang úp xuống hoặc hướng vào trong trở nên ngửa lên hoặc hướng ra ngoài."},"4071":{"word":"phía sau","meaning":"Phần mặt hoặc vị trí đối diện với mặt trước của một vật hay không gian nào đó."},"4072":{"word":"ngõ hẻm","meaning":"Con đường nhỏ hẹp nằm phía sau một con đường lớn."},"4073":{"word":"dáng vẻ sau lưng","meaning":"Hình dáng của người hay vật khi nhìn từ phía sau."},"4074":{"word":"cửa sau","meaning":"Cửa ra vào hoặc lối thoát hiểm nằm ở phía sau của một tòa nhà, nhà ở hoặc khu vực có hàng rào."},"4075":{"word":"núi sau","meaning":"Ngọn núi hoặc khu đất cao nằm ở phía sau của một ngôi làng hoặc nhà ở."},"4076":{"word":"ra vào","meaning":"Nhiều người hoặc nhiều vật liên tục đi vào rồi đi ra một nơi nào đó."},"4077":{"word":"giặt khô","meaning":"Phương pháp giặt quần áo bằng dung dịch hóa chất đặc biệt thay vì nước, thường do dịch vụ chuyên nghiệp thực hiện."},"4078":{"word":"lộ ra","meaning":"Điều gì đó đang bị che giấu hoặc chưa được biết đến bỗng trở nên hiển nhiên hoặc được công chúng biết đến mà không cần cố ý cho thấy."},"4079":{"word":"bày lộ","meaning":"Làm cho một điều gì đó đã được giấu kín hoặc không rõ ràng trở nên hiển hiện hoặc được nhiều người biết đến một cách cố ý."},"4080":{"word":"hiếm, hiếm hoi","meaning":"Chỉ việc gì đó xảy ra, tồn tại hoặc được tìm thấy không thường xuyên hoặc ở rất ít nơi."},"4081":{"word":"vững tâm, yên tâm","meaning":"Cảm thấy được trấn an, yên lòng nhờ có niềm tin vào một điều gì đó."},"4082":{"word":"vọng đến, nghe thấy","meaning":"Âm thanh hoặc thông tin truyền qua không khí và đến tai, thường là từ một khoảng cách xa."},"4083":{"word":"mắc (bệnh), bị (bệnh)","meaning":"Bị nhiễm hoặc mắc phải một căn bệnh nào đó, ví dụ như bị cảm lạnh hoặc một bệnh nhẹ."},"4084":{"word":"được cầm, được nâng","meaning":"Một vật được tay hoặc một vật khác nâng lên và giữ trên cao."},"4085":{"word":"nhìn vào, xem xét kỹ","meaning":"Hướng mắt nhìn kỹ vào một lỗ hổng hoặc bề mặt để xem bên trong hoặc phía sau nó có gì."},"4086":{"word":"cho vào, đưa vào","meaning":"Cho phép hoặc khiến một người nào đó đi vào một tòa nhà hoặc không gian kín."},"4087":{"word":"bị bắt gặp, bị phát hiện","meaning":"Đang làm một việc gì đó lén lút mà đột nhiên bị người khác nhìn thấy."},"4088":{"word":"đăng ký, đăng bạ","meaning":"Hành động ghi lại quyền hoặc cơ sở thực tế về tài sản của cá nhân như đất đai hoặc nhà cửa vào sổ đăng ký theo quy trình tài liệu pháp lý, hoặc bản ghi đó."},"4089":{"word":"xuất hiện, ra mắt","meaning":"Hành động một người hoặc vật đi vào một nơi hoặc trở nên hiển thị lần đầu tiên."},"4090":{"word":"nhà thiết kế","meaning":"Người tạo ra các bản kế hoạch hoặc bản vẽ cho cách một thứ gì đó như quần áo, tòa nhà hoặc đồ họa sẽ trông như thế nào và được tạo ra ra sao."},"4091":{"word":"con gái","meaning":"Từ dùng để gọi hoặc nhắc đến con gái của người khác với thái độ tôn kính."},"4092":{"word":"đi theo","meaning":"Di chuyển liên tục phía sau người hoặc vật khác, bám sát họ mọi lúc mọi nơi."},"4093":{"word":"rót","meaning":"Làm cho chất lỏng hoặc vật nhỏ chảy từ vật chứa này sang vật chứa khác."},"4094":{"word":"truy cứu","meaning":"Hỏi nhiều câu hỏi chi tiết về một vấn đề để tìm ra sự thật hoặc bày tỏ sự không hài lòng."},"4095":{"word":"khác","meaning":"Chỉ một vật, người hoặc ý tưởng không phải là cái đang được tập trung vào."},"4096":{"word":"mặt đất","meaning":"Bề mặt đất không bị che phủ bởi bất cứ thứ gì."},"4097":{"word":"đậu phộng","meaning":"Một loại hạt màu nâu đỏ, có vị béo, mọc trong đất, bên trong vỏ dày và lớp vỏ lụa mỏng."},"4098":{"word":"bụi bẩn","meaning":"Một lớp bụi hoặc vật liệu không sạch màu sẫm có thể nhìn thấy, bám trên bề mặt như da hoặc quần áo."},"4099":{"word":"thỉnh thoảng","meaning":"Xảy ra hoặc diễn ra vào những thời điểm khác nhau, không thường xuyên, chứ không phải liên tục."},"4100":{"word":"đánh","meaning":"Tạo ra sự tiếp xúc vật lý mạnh mẽ bằng tay, chân hoặc vật thể vào người hoặc vật."},"4101":{"word":"đến từ","meaning":"Di chuyển ra khỏi một địa điểm cụ thể và đến một địa điểm khác về mặt vật lý."},"4102":{"word":"đám","meaning":"Một tập hợp nhiều cá thể, thường là người hoặc động vật, tụ tập gần nhau và di chuyển hoặc hành động như một đơn vị."},"4103":{"word":"gỡ","meaning":"Tách một vật đang dính hoặc nối liền ra khỏi cái khác."},"4104":{"word":"lại một lần nữa","meaning":"Thể hiện một sự việc hoặc hành động xảy ra thêm một lần nữa sau khi đã xảy ra."},"4105":{"word":"phân","meaning":"Chất thải có mùi hôi được thải ra từ cơ thể người hoặc động vật sau khi tiêu hóa."},"4106":{"word":"nắp","meaning":"Một bộ phận riêng biệt, có thể tháo rời, dùng để che đậy miệng của hộp, chai hoặc vật đựng khác."},"4107":{"word":"rõ ràng","meaning":"Miêu tả điều gì đó được định nghĩa rõ ràng đến mức có thể dễ dàng nhìn thấy hoặc nhận ra, không mờ nhạt hay không chắc chắn."},"4108":{"word":"bị thủng","meaning":"Một lỗ hoặc đường thông xuất hiện trong vật thể rắn, cho phép ánh sáng hoặc chất lỏng đi qua."},"4109":{"word":"chạy ra","meaning":"Người hoặc động vật di chuyển rất nhanh từ một không gian kín ra một khu vực mở."},"4110":{"word":"chạy nhảy chơi đùa","meaning":"Trẻ em hoặc động vật di chuyển đầy năng lượng và vui vẻ trong một không gian rộng, thường là nhảy hoặc đuổi bắt nhau."},"4111":{"word":"chạy loanh quanh","meaning":"Người hoặc động vật di chuyển rất nhanh từ chỗ này sang chỗ khác trong một khu vực, thường bằng cách đi nhanh hoặc nhảy nhỏ."},"4112":{"word":"nhảy vào","meaning":"Chạy nhanh và đột ngột vào một nơi nào đó."},"4113":{"word":"múc","meaning":"Dùng đồ vật để lấy chất lỏng, đặc biệt là nước."},"4114":{"word":"xé","meaning":"Kéo một phần của vật gì đó ra khỏi phần chính, thường tạo ra một cạnh rách."},"4115":{"word":"sân vườn","meaning":"Một khoảng đất trống cạnh nhà, thường có cỏ và cây cối."},"4116":{"word":"theo ý muốn","meaning":"Theo như những gì đã quyết định hoặc mong muốn."},"4117":{"word":"sự bất ngờ","meaning":"Điều gì đó xảy ra đột ngột và gây ngạc nhiên vì không được dự đoán trước."},"4118":{"word":"bất ngờ","meaning":"Theo cách mà mọi người cảm thấy ngạc nhiên vì không được dự đoán trước."},"4119":{"word":"bị nhìn thấy","meaning":"Xuất hiện trước mắt người khác, được nhìn thấy."},"4120":{"word":"đai, thắt lưng","meaning":"Một dải vải hoặc vật liệu khác dùng để quấn quanh eo."},"4121":{"word":"đeo (thắt lưng)","meaning":"Quấn hoặc cài một vật như thắt lưng hay đai quanh cơ thể, đặc biệt là quanh eo."},"4122":{"word":"lượng","meaning":"Số hoặc kích thước tổng thể của một thứ có thể đếm hoặc đo được."},"4123":{"word":"thấu kính, ống kính","meaning":"Một dụng cụ bằng thủy tinh hoặc pha lê được cắt lõm hoặc lồi để làm vật thể trông lớn hơn hoặc nhỏ hơn."},"4124":{"word":"-lực","meaning":"Từ ngữ đứng sau một danh từ để chỉ sức mạnh thể chất hoặc tinh thần cần thiết để hoàn thành một nhiệm vụ."},"4125":{"word":"-phí","meaning":"Từ ngữ đứng sau một danh từ để chỉ số tiền phải trả để đổi lấy một dịch vụ hoặc vật phẩm."},"4126":{"word":"điều khiển từ xa","meaning":"Một thiết bị điện tử cầm tay nhỏ dùng để gửi tín hiệu điều khiển các máy khác từ xa, ví dụ như tivi."},"4127":{"word":"lít","meaning":"Đơn vị dùng để đo thể tích chất lỏng như nước, sữa."},"4128":{"word":"một cách bừa bãi","meaning":"Diễn tả hành động làm mà không suy nghĩ, không cẩn thận hoặc không có kiểm soát."},"4129":{"word":"mãi, vô thời hạn","meaning":"Diễn tả một hành động hoặc trạng thái tiếp diễn trong thời gian rất dài mà không có điểm dừng rõ ràng."},"4130":{"word":"mắt (cây)","meaning":"Phần lồi hoặc hõm trên thân cây, tre, nơi chồi hoặc lá mọc ra."},"4131":{"word":"phù hợp, thích hợp","meaning":"Miêu tả một vật hay địa điểm vừa vặn, đúng đắn và thích hợp cho một mục đích hay tình huống cụ thể."},"4132":{"word":"đáng lẽ ra, lẽ ra","meaning":"Diễn tả một hành động nên được thực hiện theo cách đúng đắn, hoặc một kết quả xứng đáng được nhận."},"4133":{"word":"sự chuẩn bị, sự sắp xếp","meaning":"Hành động chuẩn bị sẵn sàng hoặc sắp xếp các nguồn lực cho một mục đích hoặc sự kiện trong tương lai."},"4134":{"word":"sàn nhà","meaning":"Bề mặt phẳng bên trong phòng mà mọi người đi lại, thường làm bằng gỗ hoặc gạch."},"4135":{"word":"sự kết thúc, phần cuối","meaning":"Bước hoặc giai đoạn cuối cùng của một sự kiện, nhiệm vụ hoặc dự án, nơi mọi thứ được hoàn thành."},"4136":{"word":"ma túy","meaning":"Chất cấm gây ra những thay đổi mạnh mẽ trong cơ thể và tâm trí con người, thường dẫn đến nghiện ngập và tổn hại nghiêm trọng."},"4137":{"word":"thái độ, tâm thế","meaning":"Cách một người nghĩ và cảm nhận về một nhiệm vụ hoặc tình huống, điều này định hình rõ ràng hành động và phản ứng của họ."},"4138":{"word":"thỏa thích, hết mình","meaning":"Diễn tả một hành động được thực hiện không giới hạn hay kiềm chế, cho phép một người làm theo mong muốn của mình."},"4139":{"word":"quyết tâm","meaning":"Quyết định một cách kiên định sẽ thực hiện một hành động hoặc theo đuổi một mục tiêu nào đó."},"4140":{"word":"đáy lòng","meaning":"Nơi sâu thẳm nhất trong trái tim hoặc suy nghĩ của một người."},"4141":{"word":"đối diện","meaning":"Chỉ tư thế hai hoặc nhiều vật thể, người quay mặt về phía nhau."},"4142":{"word":"đụng phải","meaning":"Bất ngờ gặp gỡ ai đó hoặc điều gì đó, hoặc hai vật chạm vào nhau."},"4143":{"word":"tương tự","meaning":"Tình trạng hai hoặc nhiều điều gì đó hoàn toàn giống nhau hoặc được thực hiện theo cùng một cách."},"4144":{"word":"ma sát","meaning":"Lực xảy ra khi hai bề mặt chuyển động hoặc cố gắng chuyển động qua nhau, làm chúng nóng lên hoặc làm chậm chuyển động."},"4145":{"word":"cứ như","meaning":"Dùng để diễn tả một điều gì đó trông hoặc cảm thấy giống hệt một điều khác, dù nó có thể không phải là thật."},"4146":{"word":"cuối cùng","meaning":"Từ dùng để chỉ một điều gì đó đã xảy ra sau một thời gian dài hoặc nhiều nỗ lực, kết thúc một quá trình."},"4147":{"word":"thực ra thì","meaning":"Diễn tả tình huống thực tế hoặc cảm nhận tại một thời điểm cụ thể khác với những gì đã mong đợi."},"4148":{"word":"mơ hồ","meaning":"Khi một điều gì đó không rõ ràng, không chi tiết hoặc không được xác định cụ thể, gây khó hiểu."},"4149":{"word":"dễ dàng","meaning":"Một thứ hoặc ai đó được coi là không khó, không mạnh mẽ hoặc không thách thức, dễ dàng để quản lý hoặc vượt qua."},"4150":{"word":"kín chỗ","meaning":"Khi một địa điểm như xe buýt, rạp hát hoặc nhà hàng đã được lấp đầy hoàn toàn, không còn chỗ trống."},"4151":{"word":"điểm tuyệt đối","meaning":"Là số điểm cao nhất có thể đạt được trong một thang điểm cụ thể."},"4152":{"word":"giai đoạn cuối","meaning":"Là thời kỳ hoặc giai đoạn cuối cùng của một quá trình, tình trạng hoặc bệnh tật, thường báo hiệu sự kết thúc."},"4153":{"word":"sạch sẽ","meaning":"Mô tả một hành động được thực hiện một cách rất gọn gàng, ngăn nắp và không để lại vết bẩn hay sự lộn xộn nào."},"4154":{"word":"trộn (cơm vào canh)","meaning":"Hành động cho cơm đã nấu vào bát canh hoặc nước dùng rồi khuấy đều để ăn."},"4155":{"word":"cãi vã","meaning":"Tình huống hai hay nhiều người tranh cãi, bất đồng với nhau, thường với giọng điệu to tiếng và cảm xúc tiêu cực."},"4156":{"word":"can ngăn","meaning":"Hành động xen vào một cuộc bất đồng hoặc đánh nhau giữa mọi người để chấm dứt nó và ngăn chặn tương tác tiêu cực."},"4157":{"word":"im lặng","meaning":"Mô tả một hành động hoặc cử động được thực hiện mà không phát ra tiếng động hay nói một lời nào."},"4158":{"word":"giọng điệu","meaning":"Cách thức, phong cách hoặc âm điệu riêng biệt mà một người sử dụng khi nói, có thể tiết lộ thái độ hoặc cảm xúc của họ."},"4159":{"word":"tấm lòng","meaning":"Chỉ những cảm xúc, suy nghĩ và tình cảm bên trong của một người, thường liên quan đến tính cách."},"4160":{"word":"thỏa thích","meaning":"Một người thực hiện một hoạt động một cách tự do trong thời gian dài, cảm thấy hoàn toàn hài lòng."},"4161":{"word":"tùy ý","meaning":"Một người hành động hoặc lựa chọn hoàn toàn theo mong muốn của mình, không bị ai sai khiến."},"4162":{"word":"bị hỏng","meaning":"Một đồ vật hoặc máy móc ngừng hoạt động đúng cách, thường có dấu hiệu các bộ phận bị rời ra hoặc không còn chức năng."},"4163":{"word":"do dự","meaning":"Không quyết định ngay được điều gì đó, cứ nghĩ đi nghĩ lại."},"4164":{"word":"làm hỏng, phá hỏng","meaning":"Làm cho một việc gì đó đang tốt đẹp hoặc đã được chuẩn bị kỹ càng trở nên tồi tệ hoặc không thành công."},"4165":{"word":"phá sản, sụp đổ","meaning":"Một doanh nghiệp hoàn toàn ngừng hoạt động hoặc một người mất hết tất cả tài sản."},"4166":{"word":"cả hai vợ chồng cùng đi làm","meaning":"Tình trạng cả vợ và chồng đều đi làm để kiếm tiền."},"4167":{"word":"đối mặt, đương đầu","meaning":"Trực tiếp đối diện với một người hoặc một tình huống khó khăn, thường là để chống lại hoặc phản đối."},"4168":{"word":"chính tả","meaning":"Hệ thống các quy tắc được thiết lập để viết từ đúng trình tự chữ cái."},"4169":{"word":"đoán đúng, trả lời đúng","meaning":"Chỉ ra hoặc nói đúng câu trả lời cho một câu hỏi hoặc một câu đố."},"4170":{"word":"treo, bám víu","meaning":"Một vật hoặc người bị treo lơ lửng từ một điểm phía trên, hoặc giữ chặt vào cái gì đó để không bị rơi."},"4171":{"word":"sức hút, quyến rũ","meaning":"Một phẩm chất đặc biệt khiến một người hoặc vật trở nên hấp dẫn, thu hút người khác."},"4172":{"word":"mỗi lần, mọi lần","meaning":"Một hành động hoặc sự việc xảy ra lặp đi lặp lại, không bỏ sót một lần nào."},"4173":{"word":"phương tiện truyền thông","meaning":"Một hệ thống hoặc loại vật liệu, như giấy, màn hình hoặc sóng âm, được sử dụng để truyền tải thông tin hoặc giải trí đến mọi người."},"4174":{"word":"nhất, tột cùng","meaning":"Dùng để nhấn mạnh mức độ cao nhất hoặc vị trí đầu tiên/cuối cùng của một cái gì đó."},"4175":{"word":"đọng lại","meaning":"Chỉ sự xuất hiện và tụ lại của các giọt nước nhỏ như sương hay nước mắt trên bề mặt nào đó."},"4176":{"word":"tóc","meaning":"Phần sợi mọc trên da đầu của con người."},"4177":{"word":"trong đầu","meaning":"Không gian bên trong hộp sọ, nơi chứa đựng suy nghĩ, ký ức và ý tưởng của con người."},"4178":{"word":"lưu lại, ở lại","meaning":"Ở lại một nơi nào đó trong một khoảng thời gian nhất định, không rời đi."},"4179":{"word":"ở lại, lưu lại","meaning":"Dừng lại và có mặt tại một địa điểm trong một khoảng thời gian nhất định."},"4180":{"word":"ngập ngừng, do dự","meaning":"Tỏ ra không chắc chắn, chậm chạp hoặc trì hoãn hành động hay lời nói."},"4181":{"word":"kiếm sống, mưu sinh","meaning":"Kiếm đủ tiền hoặc tài nguyên để trang trải các nhu cầu cơ bản như ăn uống và chỗ ở."},"4182":{"word":"thức ăn (cho động vật), mồi","meaning":"Thức ăn mà con người cung cấp cho động vật, đặc biệt là vật nuôi hoặc động vật trong môi trường nuôi nhốt."},"4183":{"word":"cho ăn","meaning":"Đưa thức ăn vào miệng của người hoặc động vật để họ tiêu thụ."},"4184":{"word":"bị ăn thịt","meaning":"Bị một sinh vật khác tiêu thụ làm thức ăn."},"4185":{"word":"xa cách, trở nên xa cách","meaning":"Trở nên cách xa về mặt khoảng cách vật lý hoặc trong mối quan hệ, tình cảm."},"4186":{"word":"lành lặn, nguyên vẹn","meaning":"Ở trong tình trạng hoàn hảo, không bị tổn thương, hư hại hay bệnh tật."},"4187":{"word":"tùy tiện","meaning":"Tự ý làm theo ý thích của mình mà không theo quy tắc hay sự cho phép nào."},"4188":{"word":"gâu gâu","meaning":"Từ tượng thanh mô phỏng tiếng chó sủa."},"4189":{"word":"ngừng","meaning":"Đối với một cái gì đó đang chuyển động, chảy hoặc diễn ra, thì hoàn toàn kết thúc và trở nên bất động."},"4190":{"word":"huy chương","meaning":"Một vật hình tròn bằng vàng, bạc hoặc đồng, được trao làm giải thưởng hoặc để kỷ niệm."},"4191":{"word":"lấp đầy","meaning":"Đặt vật liệu vào một khoảng trống hoặc khe hở cho đến khi nó đầy hoặc được che phủ."},"4192":{"word":"con dâu","meaning":"Người phụ nữ kết hôn với con trai của một người."},"4193":{"word":"phỏng vấn","meaning":"Một cuộc thảo luận chính thức trong đó một người hỏi người khác để lấy thông tin hoặc lời khuyên."},"4194":{"word":"cạo râu","meaning":"Hành động cắt bỏ lông hoặc râu rất sát da, thường là trên mặt, bằng một lưỡi dao sắc."},"4195":{"word":"miễn","meaning":"Được phép không làm điều gì đó theo yêu cầu hoặc thoát khỏi nguy hiểm hoặc tình huống xấu."},"4196":{"word":"giấy phép","meaning":"Một văn bản hoặc thẻ chính thức chứng minh bạn có quyền hợp pháp để làm một việc cụ thể."},"4197":{"word":"tên","meaning":"Từ dùng để gọi hoặc nhận biết một người, vật, sự vật, hoặc tác phẩm."},"4198":{"word":"mệnh lệnh","meaning":"Một chỉ dẫn cụ thể do người có thẩm quyền đưa ra mà những người khác phải tuân theo."},"4199":{"word":"danh dự","meaning":"Sự công nhận và tôn vinh mà một người nhận được vì phẩm chất tốt đẹp hoặc thành tựu của họ."},"4200":{"word":"rõ ràng","meaning":"Dễ hiểu hoặc dễ thấy, không có sự lẫn lộn hay nghi ngờ."},"4201":{"word":"nào đó","meaning":"Từ dùng trước họ để chỉ một người mà không rõ tên đầy đủ hoặc không muốn nêu tên."},"4202":{"word":"gây quỹ","meaning":"Hành động kêu gọi và thu gom tiền từ nhiều người cho một mục đích hoặc dự án cụ thể."},"4203":{"word":"tập trung","meaning":"Nhiều người hoặc động vật di chuyển và đến cùng một nơi, tạo thành một nhóm."},"4204":{"word":"sau một thời gian dài","meaning":"Một trạng từ diễn tả sự việc xảy ra khi đã lâu rồi từ lần cuối nó xảy ra."},"4205":{"word":"phiêu lưu","meaning":"Một trải nghiệm thú vị và đôi khi nguy hiểm, thường liên quan đến việc đi đến những nơi mới hoặc đối mặt với những thử thách mới."},"4206":{"word":"cổ họng","meaning":"Đường đi bên trong phía sau miệng và trong cổ, nơi thức ăn đi xuống và không khí đi qua."},"4207":{"word":"khát nước","meaning":"Cảm thấy rất muốn uống nước vì miệng và cổ họng khô."},"4208":{"word":"mục sư","meaning":"Người lãnh đạo các buổi lễ nhà thờ Thiên Chúa giáo và hướng dẫn mọi người trong đức tin của họ."},"4209":{"word":"tính mạng","meaning":"Khoảng thời gian tự nhiên mà một người, động vật hoặc thực vật tồn tại và phát triển trước khi chết."},"4210":{"word":"phần","meaning":"Phần mà mỗi người được nhận khi nhiều người chia sẻ một cái gì đó."},"4211":{"word":"dồn","meaning":"Đẩy hoặc khiến cái gì đó di chuyển đến một hướng hoặc vị trí mong muốn."},"4212":{"word":"không nhận ra","meaning":"Nhìn một người hoặc vật quen thuộc mà không biết đó là ai hoặc cái gì, thường do sự thay đổi theo thời gian."},"4213":{"word":"đổ xô đến","meaning":"Nhiều người hoặc vật di chuyển đến một địa điểm cụ thể, tạo thành một đám đông."},"4214":{"word":"kéo đến","meaning":"Nhiều người hoặc động vật đến một địa điểm nào đó cùng một lúc, thường là nhanh chóng và từ xa."},"4215":{"word":"bị dồn","meaning":"Bị đẩy hoặc di chuyển đến một hướng hoặc vị trí nhất định."},"4216":{"word":"vóc dáng","meaning":"Hình dạng và đường nét cơ thể của một người, đặc biệt là khi nhìn từ bên ngoài."},"4217":{"word":"bên trong cơ thể","meaning":"Các cơ quan, dịch và xương nằm bên trong da và xương của một người hoặc động vật."},"4218":{"word":"thân","meaning":"Phần giữa của cơ thể người hoặc động vật, bao gồm ngực và bụng, không tính đầu và các chi."},"4219":{"word":"rất","meaning":"Ở mức độ cao, mạnh mẽ hoặc đáng kể, thường gợi ý một cảm giác hoặc tình huống rõ rệt."},"4220":{"word":"đinh","meaning":"Một mảnh kim loại nhỏ, mỏng, có đầu nhọn và mặt phẳng trên cùng, dùng để đóng ghép các vật lại với nhau."},"4221":{"word":"xấu xí","meaning":"Trông không hấp dẫn hoặc không có vẻ đẹp đặc biệt khi người khác nhìn vào."},"4222":{"word":"xấu tính","meaning":"Hành động một cách tàn nhẫn hoặc không tốt bụng, thể hiện tính cách gây khó chịu hoặc tổn thương cho người khác."},"4223":{"word":"không kém gì","meaning":"Có chất lượng hoặc khả năng ngang bằng, thậm chí vượt trội so với một người hoặc tiêu chuẩn nào đó."},"4224":{"word":"hết sạch","meaning":"Bao gồm tất cả mọi thứ, không chừa lại một phần nào."},"4225":{"word":"vô-","meaning":"Tiền tố dùng để chỉ sự thiếu vắng hoặc không có một đặc tính, trạng thái nào đó."},"4226":{"word":"sự thờ ơ","meaning":"Trạng thái không thể hiện bất kỳ sự quan tâm hay lo lắng nào đối với một điều hoặc một người."},"4227":{"word":"không liên quan","meaning":"Chỉ việc hai sự vật, sự việc hoàn toàn không có mối liên hệ nào với nhau."},"4228":{"word":"vũ khí","meaning":"Vật dùng để tấn công, phòng thủ hoặc gây sát thương như dao, súng, gươm."},"4229":{"word":"đổ sập","meaning":"Công trình xây dựng như nhà cửa, tường bỗng nhiên bị vỡ và rơi xuống đất."},"4230":{"word":"oi bức","meaning":"Thời tiết nóng và có độ ẩm cao, gây cảm giác khó chịu, oi ả."},"4231":{"word":"tới tận","meaning":"Từ dùng để nhấn mạnh một con số hoặc số lượng lớn một cách bất ngờ hoặc ấn tượng."},"4232":{"word":"khoảng","meaning":"Khoảng thời gian gần một thời điểm cụ thể nào đó trong ngày, tháng hoặc năm."},"4233":{"word":"sự quá sức","meaning":"Việc làm gì đó vượt quá khả năng hoặc giới hạn của bản thân, hoặc không hợp lý."},"4234":{"word":"an toàn","meaning":"Thực hiện một việc gì đó mà không gặp phải bất kỳ nguy hiểm, tổn hại nào."},"4235":{"word":"sự bỏ qua, sự coi thường","meaning":"Hành động cố ý không quan tâm, không chú ý hoặc không tôn trọng ai đó/điều gì đó."},"4236":{"word":"sự vô nghĩa","meaning":"Trạng thái một hành động hoặc đối tượng không có mục đích, giá trị, không mang lại kết quả hoặc lợi ích rõ rệt."},"4237":{"word":"cầu vồng","meaning":"Một vòm màu sắc tươi sáng xuất hiện trên bầu trời khi ánh nắng chiếu qua những giọt mưa."},"4238":{"word":"sự vô trách nhiệm","meaning":"Trạng thái không chịu trách nhiệm hoặc không làm tròn trách nhiệm đối với một nhiệm vụ hoặc vấn đề liên quan."},"4239":{"word":"lặng lẽ, âm thầm","meaning":"Làm việc gì đó mà không phát ra tiếng động hay nói lời nào."},"4240":{"word":"bị buộc, bị cột","meaning":"Được cố định hoặc thắt chặt bằng dây thừng, sợi dây hoặc vật liệu tương tự."},"4241":{"word":"-văn (hậu tố)","meaning":"Hậu tố cho biết từ chính là một loại tài liệu hoặc văn bản được viết."},"4242":{"word":"chợt, đột nhiên","meaning":"Một điều gì đó xảy ra hoặc xuất hiện rất nhanh và không có bất kỳ cảnh báo nào."},"4243":{"word":"văn minh","meaning":"Một nhóm người lớn đã phát triển một xã hội phức tạp với văn hóa, thành phố và lối sống chung."},"4244":{"word":"văn bản, tài liệu","meaning":"Giấy tờ có thông tin được viết ra để sử dụng cho mục đích nào đó hoặc làm bằng chứng xác minh sự thật."},"4245":{"word":"vấn đề, điểm yếu","meaning":"Một tình huống hoặc vấn đề khó khăn cần được giải quyết hoặc thay đổi."},"4246":{"word":"(thuộc) văn hóa","meaning":"Liên quan đến phong tục, tín ngưỡng, nghệ thuật và lối sống chung của một nhóm người hoặc xã hội cụ thể."},"4247":{"word":"chôn","meaning":"Đặt cái gì đó vào một cái hố trong đất rồi lấp đất hoặc vật liệu khác lên để che phủ hoàn toàn."},"4248":{"word":"dính, vấy bẩn","meaning":"Bị một chất lỏng hoặc chất khác bám vào bề mặt, để lại dấu vết hoặc lớp phủ trên đó."},"4249":{"word":"bị chôn vùi, bị lấp","meaning":"Bị một chất như đất, cát hoặc tuyết phủ kín hoàn toàn đến mức không còn nhìn thấy được nữa."},"4250":{"word":"màu vẽ, thuốc màu","meaning":"Chất lỏng hoặc chất đặc có màu sắc dùng để vẽ tranh hoặc thêm màu lên bề mặt."},"4251":{"word":"sóng, gợn sóng","meaning":"Chuyển động lên xuống của bề mặt nước, thường do gió hoặc vật thể rơi xuống gây ra."},"4252":{"word":"hơi ẩm, độ ẩm","meaning":"Một lượng nhỏ chất lỏng, thường là nước, khiến vật gì đó cảm thấy ẩm ướt."},"4253":{"word":"nhuộm màu, lên màu","meaning":"Thay đổi màu sắc hoặc vẻ ngoài bằng cách hấp thụ một màu mới, thường từ chất lỏng hoặc ánh sáng."},"4254":{"word":"dưới nước, trong nước","meaning":"Không gian hoặc khu vực nằm hoàn toàn bên dưới bề mặt của một khối nước."},"4255":{"word":"vật chất","meaning":"Bất kỳ thứ gì có khối lượng và chiếm không gian, tạo nên mọi thứ xung quanh chúng ta."},"4256":{"word":"vật chất","meaning":"Liên quan đến tài sản vật chất hoặc thế giới hữu hình, chứ không phải tư tưởng, cảm xúc hay tinh thần."},"4257":{"word":"vón cục, kết tụ, tập hợp","meaning":"Các mảnh nhỏ hoặc bộ phận riêng lẻ tập hợp lại gần nhau và tạo thành một khối lớn hơn, rắn chắc."},"4258":{"word":"gì chứ, cái gì (thán từ)","meaning":"Một từ hoặc âm thanh dùng để thể hiện sự ngạc nhiên nhẹ hoặc để hỏi lại làm rõ điều vừa nghe."},"4259":{"word":"mini","meaning":"Sự vật có kích thước nhỏ hơn so với tiêu chuẩn thông thường."},"4260":{"word":"truyền thông","meaning":"Các phương tiện như truyền hình, đài phát thanh hay internet dùng để truyền bá thông tin, giải trí đến nhiều người."},"4261":{"word":"lưu luyến","meaning":"Cảm giác luyến tiếc dai dẳng, khó buông bỏ một điều gì đó đã qua."},"4262":{"word":"sự ghét bỏ","meaning":"Cảm xúc giận dữ, bất mãn mạnh mẽ đối với một người hay sự vật nào đó."},"4263":{"word":"âm ấm","meaning":"Có nhiệt độ hơi ấm, không lạnh cũng không nóng."},"4264":{"word":"chưa kịp","meaning":"Dùng để chỉ một việc gì đó chưa được thực hiện hay chưa được hiểu rõ vào một thời điểm nhất định."},"4265":{"word":"điên","meaning":"Có suy nghĩ và hành vi khác thường, không giống người bình thường, thường do rối loạn tinh thần."},"4266":{"word":"đạt","meaning":"Đạt được một mức độ hay tiêu chuẩn nào đó."},"4267":{"word":"chưa kết hôn","meaning":"Người trưởng thành chưa lập gia đình."},"4268":{"word":"dân tộc","meaning":"Một nhóm người lớn có chung ngôn ngữ, văn hóa, lịch sử và truyền thống."},"4269":{"word":"dân chủ","meaning":"Hệ thống chính quyền mà người dân bầu ra lãnh đạo và có tiếng nói trong việc định hình xã hội."},"4270":{"word":"niềm tin","meaning":"Sự tin tưởng mạnh mẽ vào sự trung thực, khả năng hoặc sự thật của một người hay một điều gì đó."},"4271":{"word":"bị đẩy, bị xô","meaning":"Được di chuyển khỏi vị trí ban đầu do tác động của một lực hoặc vật gì đó."},"4272":{"word":"milimet","meaning":"Đơn vị đo chiều dài rất nhỏ, bằng một phần nghìn mét."},"4273":{"word":"đáy, mặt dưới cùng","meaning":"Phần thấp nhất hoặc mặt dưới của một vật, chẳng hạn như đế giày."},"4274":{"word":"cái gáo","meaning":"Vỏ cứng rỗng của một loại cây, thường được cắt đôi để dùng làm bát hoặc muỗng múc nước, thức ăn."},"4275":{"word":"mong ước, nguyện vọng","meaning":"Điều mong muốn mạnh mẽ hoặc hy vọng rằng điều gì đó sẽ xảy ra."},"4276":{"word":"đáng mong muốn, nên làm","meaning":"Được coi là đúng đắn, tốt đẹp hoặc phù hợp trong một tình huống nhất định."},"4277":{"word":"đưa tiễn, hộ tống","meaning":"Đi cùng một người đến điểm đến cuối cùng hoặc điểm khởi hành của họ, thường để đảm bảo an toàn hoặc nói lời tạm biệt."},"4278":{"word":"sửa lại, chỉnh lại","meaning":"Sửa chữa hoặc điều chỉnh để làm cho cái gì đó thẳng, đúng hoặc không còn sai lệch."},"4279":{"word":"ngay thẳng, đúng đắn","meaning":"Ở trạng thái thẳng, không cong vẹo hoặc theo một cách đúng đắn, chính xác."},"4280":{"word":"sát, gần sát","meaning":"Diễn tả hành động hoặc trạng thái ở rất gần nhau, không có hoặc rất ít khoảng cách."},"4281":{"word":"dâng, cống hiến","meaning":"Trao một vật gì đó cho ai hoặc một nhóm người, thường là quà tặng, biểu hiện sự tận tâm hoặc để tưởng nhớ."},"4282":{"word":"đóng (đinh), cắm (vào)","meaning":"Dùng lực tác động làm cho một vật đi sâu vào một vật khác, chẳng hạn như đóng đinh."},"4283":{"word":"Hộp","meaning":"Vật chứa thường có hình vuông hoặc chữ nhật, làm bằng vật liệu như giấy hay gỗ, dùng để đựng đồ vật."},"4284":{"word":"Đóng vào, cắm vào","meaning":"Bị vật gì đó xuyên vào hoặc ghim chặt sâu vào một bề mặt hay vật khác."},"4285":{"word":"Nửa giá","meaning":"Mức giá của một món hàng hoặc dịch vụ chỉ bằng 50% giá gốc."},"4286":{"word":"Vui mừng đón, hoan nghênh","meaning":"Thể hiện sự vui vẻ, hài lòng khi gặp lại người thân quen hoặc khi điều tốt đẹp xảy ra."},"4287":{"word":"Phản đối, phản kháng","meaning":"Sự chống đối hoặc phản ứng không đồng tình mạnh mẽ của nhiều người đối với một thay đổi hay sự kiện."},"4288":{"word":"Kiểm điểm, tự kiểm điểm","meaning":"Hành động suy nghĩ kỹ lưỡng về những việc làm và suy nghĩ trong quá khứ của bản thân để học hỏi và sửa đổi."},"4289":{"word":"Phản ánh","meaning":"Việc một sự vật, hiện tượng thể hiện hoặc đại diện cho những đặc điểm, tình trạng của sự vật, hiện tượng khác."},"4290":{"word":"Phản ứng","meaning":"Sự thay đổi có thể nhận thấy trong hành vi, cơ thể hoặc chất, xảy ra ngay sau một sự kiện."},"4291":{"word":"Lớp trưởng, tổ trưởng","meaning":"Người đại diện hoặc phụ trách một nhóm nhỏ được tổ chức cho một mục đích nhất định."},"4292":{"word":"Nhấp nháy, lấp lánh","meaning":"Ánh sáng nhỏ liên tục xuất hiện rồi lại biến mất nhanh chóng, tạo ra hiệu ứng lấp lánh."},"4293":{"word":"Lấp lánh, óng ánh","meaning":"Từ mô tả sự vật hoặc bề mặt liên tục phát ra những tia sáng nhỏ, nhanh, khiến nó trông rất sáng và thu hút."},"4294":{"word":"Lấp lánh, chiếu sáng","meaning":"Ánh sáng nhỏ xuất hiện và biến mất trong chốc lát; hoặc làm cho ánh sáng xuất hiện như vậy."},"4295":{"word":"trả hàng, hoàn trả hàng","meaning":"Việc trả lại một món hàng đã mua và nhận lại số tiền đã thanh toán."},"4296":{"word":"chấp nhận, tiếp nhận","meaning":"Đồng ý và tiếp nhận một điều gì đó hoặc một đề nghị, một điều kiện mới."},"4297":{"word":"đế lót, giá đỡ","meaning":"Vật dùng để kê bên dưới một thứ khác nhằm mục đích nâng đỡ hoặc bảo vệ bề mặt."},"4298":{"word":"bước chân","meaning":"Âm thanh tạo ra khi chân chạm đất lúc đi, hoặc cách thức và tốc độ đi bộ."},"4299":{"word":"khám phá, phát hiện","meaning":"Hành động tìm ra một điều gì đó chưa được biết đến hoặc chưa được tìm thấy lần đầu tiên."},"4300":{"word":"bước chân","meaning":"Sự di chuyển của bàn chân khi một người đi, thường dùng để chỉ lối đi hoặc sự hiện diện của họ ở một nơi."},"4301":{"word":"gót chân","meaning":"Phần sau cùng của bàn chân người."},"4302":{"word":"đầu ngón chân","meaning":"Phần cuối của ngón chân."},"4303":{"word":"mu bàn chân","meaning":"Bề mặt phía trên của bàn chân, là bộ phận nằm giữa mắt cá chân và các ngón chân."},"4304":{"word":"phát sinh, xảy ra","meaning":"Thời điểm hoặc quá trình một sự việc bắt đầu tồn tại, xuất hiện hoặc diễn ra lần đầu tiên."},"4305":{"word":"dấu chân","meaning":"Dấu vết trên mặt đất do bàn chân hoặc giày để lại."},"4306":{"word":"móng chân","meaning":"Phần cứng và mỏng gắn ở đầu ngón chân, có chức năng bảo vệ các đầu ngón chân."},"4307":{"word":"buổi trình bày","meaning":"Một sự kiện mà mọi người thể hiện công việc hoặc biểu diễn trước khán giả."},"4308":{"word":"làm sáng tỏ","meaning":"Điều tra một điều gì đó còn ẩn giấu hoặc chưa biết để đưa sự thật hoặc chi tiết ra ánh sáng."},"4309":{"word":"được làm sáng tỏ","meaning":"Một điều gì đó trước đây bị ẩn giấu hoặc chưa biết trở nên rõ ràng hoặc được người khác hiểu."},"4310":{"word":"bị giẫm lên","meaning":"Bị chân ấn xuống bề mặt, gây áp lực hoặc làm phẳng."},"4311":{"word":"ngày đêm","meaning":"Toàn bộ khoảng thời gian, bao gồm cả giờ sáng và giờ tối không ngừng nghỉ."},"4312":{"word":"thức suốt đêm","meaning":"Giữ mình tỉnh táo và hoạt động trong suốt thời gian ban đêm, thường để làm một công việc cụ thể."},"4313":{"word":"thức trắng đêm","meaning":"Giữ mình tỉnh táo và hoạt động trong suốt thời gian ban đêm, thường là để làm việc hoặc học tập."},"4314":{"word":"nửa đêm","meaning":"Thời điểm giữa đêm."},"4315":{"word":"vị cơm","meaning":"Hương vị của cơm hấp."},"4316":{"word":"hướng","meaning":"Con đường hoặc chiều hướng mà một cái gì đó đi theo, thường được chỉ dẫn bằng một biển báo hướng tới một địa điểm cụ thể."},"4317":{"word":"sàn phòng","meaning":"Bề mặt phẳng phía dưới bên trong một không gian kín nơi mọi người đi lại hoặc đặt đồ đạc."},"4318":{"word":"phương án","meaning":"Một danh sách các bước chi tiết hoặc một phương pháp cụ thể được đề xuất để đạt được mục tiêu hoặc giải quyết vấn đề."},"4319":{"word":"phòng ngừa","meaning":"Việc ngăn không cho một điều xấu hay hiện tượng tiêu cực nào đó xảy ra."},"4320":{"word":"phông nền","meaning":"Khung cảnh ở phía sau một vật thể hay một sự kiện nào đó."},"4321":{"word":"rốn","meaning":"Phần lõm hoặc lồi nhỏ ở giữa bụng người, nơi cuống rốn từng được gắn vào."},"4322":{"word":"thấm","meaning":"Chất lỏng, màu sắc hoặc mùi hương dần dần lan vào và trở thành một phần của vật liệu hay chất nào đó."},"4323":{"word":"sự quan tâm","meaning":"Hành động suy nghĩ cẩn thận về nhu cầu và cảm xúc của người khác để giúp đỡ hoặc đối xử tử tế với họ."},"4324":{"word":"no bụng","meaning":"Tình trạng không muốn ăn thêm nữa vì đã ăn đủ."},"4325":{"word":"giao hàng","meaning":"Quá trình chuyển các mặt hàng hoặc hàng hóa từ một địa điểm này đến một địa điểm khác, thường là qua một dịch vụ."},"4326":{"word":"vợ/chồng","meaning":"Người mà mình đã kết hôn hợp pháp, cùng chia sẻ cuộc sống và mái ấm."},"4327":{"word":"nhổ","meaning":"Hành động đẩy mạnh một thứ gì đó, thường là chất lỏng hoặc thức ăn, ra khỏi miệng."},"4328":{"word":"chịu đựng","meaning":"Giữ vững hoặc mạnh mẽ chống lại một tình huống khó khăn hoặc lực vật lý mà không từ bỏ."},"4329":{"word":"luân phiên","meaning":"Thực hiện các hành động theo thứ tự, khi một người hoặc vật hành động rồi đến người hoặc vật khác, và cứ thế thay đổi."},"4330":{"word":"phiền phức","meaning":"Liên quan đến nhiều bước hoặc sự phức tạp khiến một công việc trở nên khó chịu hoặc khó hoàn thành."},"4331":{"word":"sầm uất, nhộn nhịp","meaning":"Chỉ một nơi có nhiều người, cửa hàng, đèn chiếu sáng và hoạt động liên tục, rất sống động."},"4332":{"word":"con ong","meaning":"Một loài côn trùng bay có thân sọc, thường màu vàng và đen, có thể chích gây đau."},"4333":{"word":"bật dậy, phắt dậy","meaning":"Mô tả hành động đột ngột và nhanh chóng đứng thẳng dậy."},"4334":{"word":"côn trùng, con bọ","meaning":"Một sinh vật rất nhỏ, thường có sáu chân và râu, bò hoặc bay."},"4335":{"word":"mở ra, banh ra, nới rộng","meaning":"Di chuyển hai phần của một vật ra xa nhau hơn, hoặc làm cho một khoảng trống rộng hơn."},"4336":{"word":"rộng ra, nới rộng","meaning":"Khoảng trống giữa hai vật trở nên lớn hơn."},"4337":{"word":"diễn ra, xảy ra","meaning":"Một sự kiện hoặc bữa tiệc được tổ chức hoặc xảy ra."},"4338":{"word":"khởi sự, bắt đầu, mở ra","meaning":"Thiết lập và bắt đầu một hoạt động, dự án hoặc sự kiện quy mô lớn."},"4339":{"word":"phạm vi","meaning":"Toàn bộ khu vực hoặc giới hạn mà một cái gì đó có thể được tìm thấy hoặc hoạt động."},"4340":{"word":"tội phạm, thủ phạm","meaning":"Người đã thực hiện một hành vi bất hợp pháp."},"4341":{"word":"pháp luật, luật pháp","meaning":"Hệ thống các quy tắc do chính phủ ban hành mà mọi người trong một quốc gia phải tuân theo."},"4342":{"word":"tòa án","meaning":"Một tòa nhà hoặc nơi thẩm phán lắng nghe các lập luận và đưa ra quyết định về các vụ án pháp lý."},"4343":{"word":"pháp lý","meaning":"Liên quan đến pháp luật hoặc tuân thủ các quy tắc do chính phủ ban hành."},"4344":{"word":"thoát khỏi, ra khỏi","meaning":"Rời khỏi một không gian, tình huống hoặc phạm vi nào đó."},"4345":{"word":"gối","meaning":"Vật mềm dùng để kê đầu khi nằm nghỉ hoặc ngủ."},"4346":{"word":"tổ chức, đãi","meaning":"Sắp xếp, thực hiện một bữa tiệc hoặc làm một việc tốt cho người khác."},"4347":{"word":"cây lúa","meaning":"Loại cây thân xanh mọc ở ruộng nước, cho hạt gạo ăn được."},"4348":{"word":"hay thay đổi, thất thường","meaning":"Tâm trạng, ý kiến hoặc hành vi của một người thay đổi thường xuyên và đột ngột không có lý do rõ ràng."},"4349":{"word":"biến động","meaning":"Sự thay đổi, dao động đáng kể về số lượng, mức độ hoặc tình trạng."},"4350":{"word":"lời bao biện, lời biện minh","meaning":"Lời nói được đưa ra nhằm tránh bị đổ lỗi hoặc chịu trách nhiệm về một việc làm sai."},"4351":{"word":"đặc biệt, khác biệt","meaning":"Có vẻ khác hẳn hoặc nổi bật một cách rõ rệt so với những thứ khác."},"4352":{"word":"riêng, riêng biệt","meaning":"Mô tả hành động hoặc vật thể được giữ hoặc xử lý độc lập, không chung với một nhóm hoặc đơn vị chính."},"4353":{"word":"bị bệnh, ốm","meaning":"Trải qua tình trạng cơ thể không khỏe mạnh, không hoạt động bình thường."},"4354":{"word":"phổ biến, phân phối","meaning":"Hành động làm cho một cái gì đó được nhiều người biết đến hoặc có sẵn ở nhiều nơi."},"4355":{"word":"bản tin","meaning":"Một thông tin hoặc sự kiện được truyền tải rộng rãi đến công chúng thông qua các phương tiện truyền thông."},"4356":{"word":"trà lúa mạch","meaning":"Loại trà được làm bằng cách đun sôi hạt lúa mạch đã rang."},"4357":{"word":"báu vật","meaning":"Một vật thể rất quý hiếm và có giá trị cao."},"4358":{"word":"chăm sóc","meaning":"Cung cấp sự giúp đỡ, bảo vệ và hỗ trợ cho ai đó hoặc vật gì đó, đảm bảo an toàn và hạnh phúc cho họ."},"4359":{"word":"bồi thường","meaning":"Tiền hoặc hàng hóa được trao cho ai đó để đền bù cho mất mát, tổn hại hoặc dịch vụ họ đã thực hiện."},"4360":{"word":"tiền lương","meaning":"Số tiền mà một người nhận được thường xuyên để đổi lấy việc làm hoặc cung cấp dịch vụ."},"4361":{"word":"an ninh","meaning":"Tình trạng không có nguy hiểm hoặc mối đe dọa, thường đạt được bằng các biện pháp ngăn chặn truy cập hoặc thiệt hại không mong muốn."},"4362":{"word":"bổ sung","meaning":"Hành động thêm vào một thứ gì đó hiện có để làm cho nó hoàn chỉnh hoặc làm cho các phần yếu hơn của nó trở nên mạnh hơn."},"4363":{"word":"bảo đảm","meaning":"Một lời cam kết chắc chắn rằng điều gì đó sẽ xảy ra hoặc một điều kiện cụ thể sẽ được duy trì."},"4364":{"word":"bảo tồn","meaning":"Hành động giữ gìn một thứ gì đó an toàn và trong điều kiện ban đầu, ngăn chặn nó khỏi bị hư hại hoặc mục nát."},"4365":{"word":"hỗ trợ","meaning":"Sự giúp đỡ thiết thực hoặc tiền bạc được cung cấp cho ai đó hoặc vật gì đó để làm cho một nhiệm vụ dễ dàng hơn hoặc giúp trang trải chi phí."},"4366":{"word":"bảo quản","meaning":"Hành động cẩn thận giữ cho một thứ gì đó an toàn khỏi sự phân hủy, hư hỏng hoặc mất mát, để nó duy trì trạng thái hiện có."},"4367":{"word":"bổ sung","meaning":"Hành động thêm vào những gì còn thiếu hoặc đã hết để làm cho đầy đủ trở lại."},"4368":{"word":"trả thù","meaning":"Hành động gây hại cho người khác để đáp trả lại việc họ đã làm hại mình hoặc người thân của mình."},"4369":{"word":"món xào","meaning":"Một món ăn được chế biến bằng cách cho nguyên liệu vào chảo với một ít dầu, đun nóng và đảo đều."},"4370":{"word":"bản năng","meaning":"Một sự thôi thúc mạnh mẽ không học hỏi được hoặc một tập hợp hành vi mà động vật hay con người tự động thực hiện."},"4371":{"word":"nguyên bản","meaning":"Hình thức hoặc bản chất đầu tiên của một sự vật khi nó bắt đầu tồn tại hoặc được tạo ra, trước khi có bất kỳ sự thay đổi nào."},"4372":{"word":"trụ sở chính","meaning":"Tòa nhà hoặc văn phòng chính nơi một tổ chức, công ty lớn hoặc hoạt động được chỉ đạo và kiểm soát."},"4373":{"word":"bản chất","meaning":"Phẩm chất hoặc đặc điểm quan trọng và cơ bản nhất định nghĩa một sự vật thực sự là gì."},"4374":{"word":"má","meaning":"Phần mềm, có thịt ở hai bên mặt người, nằm dưới mắt và cạnh mũi, miệng."},"4375":{"word":"không-, bất-","meaning":"Một phần ngắn được thêm vào đầu một từ để làm cho từ đó mang nghĩa đối lập hoặc thể hiện sự thiếu vắng."},"4376":{"word":"của cải","meaning":"Một bộ sưu tập lớn các vật phẩm có giá trị, tài sản hoặc nguồn lực tài chính thuộc sở hữu của một người hoặc nhóm."},"4377":{"word":"khu vực lân cận","meaning":"Khu vực hoặc vùng không gian ngay xung quanh một địa điểm hoặc vật thể cụ thể."},"4378":{"word":"sự xấu hổ","meaning":"Một cảm giác khó chịu hoặc lúng túng khiến một người muốn che giấu hoặc làm mặt họ đỏ lên."},"4379":{"word":"xấu hổ","meaning":"Thể hiện cảm giác ngại ngùng, lúng túng bằng nét mặt hay cử chỉ, thường là mặt đỏ lên hoặc tránh nhìn thẳng."},"4380":{"word":"nặng nề","meaning":"Cảm thấy có trách nhiệm lớn hoặc áp lực nặng nề, gây ra sự không thoải mái."},"4381":{"word":"đơn vị quân đội","meaning":"Một nhóm quân lính có số lượng nhất định hoặc nơi quân đội đóng quân."},"4382":{"word":"va vào","meaning":"Một vật hoặc người tác động mạnh vào một vật hoặc người khác."},"4383":{"word":"bị va chạm","meaning":"Một vật hoặc người bị một vật khác đang di chuyển đâm hoặc va vào, thường gây ra thiệt hại."},"4384":{"word":"lĩnh vực","meaning":"Một phần riêng biệt hoặc một khu vực được tách ra từ một lĩnh vực lớn hơn."},"4385":{"word":"một phần","meaning":"Diễn tả cái gì đó chỉ bao gồm một đoạn hoặc một khu vực nhất định, không phải toàn bộ."},"4386":{"word":"chấn thương","meaning":"Tổn thương hoặc thiệt hại vật lý đối với cơ thể người, như vết cắt, vết bầm tím, hoặc xương gãy, thường gây đau đớn."},"4387":{"word":"phòng ban","meaning":"Một bộ phận hoặc khu vực riêng biệt trong một tổ chức lớn hơn, có nhiệm vụ và nhân viên cụ thể."},"4388":{"word":"bị vỡ","meaning":"Vật cứng bị vỡ thành nhiều mảnh nhỏ."},"4389":{"word":"phá hủy","meaning":"Tác dụng lực lên một vật thể hoặc cấu trúc khiến nó nứt, vỡ thành nhiều mảnh nhỏ hoặc bị phá hủy."},"4390":{"word":"vị trí","meaning":"Một khu vực hoặc phần cụ thể của một vật thể hoặc cơ thể sống."},"4391":{"word":"tác dụng phụ","meaning":"Đây là những hiện tượng không mong muốn xảy ra ngoài ý muốn do một nguyên nhân nào đó gây ra."},"4392":{"word":"bất chính, gian lận","meaning":"Đây là hành vi không trung thực, không hợp pháp, thường của người có chức quyền, gây ra tình huống không công bằng."},"4393":{"word":"phủ định, phủ nhận","meaning":"Đây là hành động tuyên bố rằng điều gì đó không đúng, không có giá trị hoặc không tồn tại."},"4394":{"word":"tiêu cực, phủ định","meaning":"Đây là trạng thái biểu hiện sự không tán thành, có tác động xấu hoặc thể hiện cái nhìn bi quan."},"4395":{"word":"không chính xác, sai lệch","meaning":"Đây là trạng thái không hoàn toàn đúng hay chính xác, thường khác với dạng đúng hoặc mong đợi."},"4396":{"word":"bộ lạc, bộ tộc","meaning":"Đây là một nhóm người có chung tổ tiên, ngôn ngữ và lối sống, thường sinh sống cùng nhau trong một khu vực nhất định."},"4397":{"word":"bất cẩn, lơ đễnh","meaning":"Đây là trạng thái không dành đủ suy nghĩ hoặc sự chú ý cho việc mình đang làm, có thể dẫn đến sai lầm hoặc tai nạn."},"4398":{"word":"siêng năng, cần cù","meaning":"Đây là cách thực hiện công việc với sự cẩn thận và nỗ lực liên tục, thường làm việc trong thời gian dài không ngừng nghỉ."},"4399":{"word":"Đức Phật","meaning":"Đây là tên gọi của Thích Ca Mâu Ni, người sáng lập ra đạo Phật."},"4400":{"word":"chiên, rán","meaning":"Đây là hành động làm chín thức ăn bằng cách ngâm trong dầu nóng hoặc mỡ nóng."},"4401":{"word":"phụ tùng, linh kiện","meaning":"Đây là những vật nhỏ riêng lẻ được thiết kế để lắp ráp với nhau, tạo thành một cỗ máy, thiết bị hoặc cấu trúc lớn hơn."},"4402":{"word":"Bắc Mỹ","meaning":"Đây là một lục địa lớn ở Bán cầu Bắc, nằm giữa Đại Tây Dương và Thái Bình Dương, phía bắc của Nam Mỹ."},"4403":{"word":"sự tức giận","meaning":"Một cảm xúc mạnh mẽ khi không hài lòng, khiến mặt đỏ bừng, giọng nói cao hơn hoặc cơ thể căng thẳng."},"4404":{"word":"số lượng","meaning":"Mức độ lớn hay nhỏ của một con số, khối lượng, trọng lượng hoặc dung tích."},"4405":{"word":"sự phân loại","meaning":"Hành động sắp xếp các mục hoặc ý tưởng thành các nhóm dựa trên các đặc điểm chung của chúng."},"4406":{"word":"rõ ràng","meaning":"Dễ dàng nhìn thấy, nghe thấy hoặc hiểu được, không còn chỗ cho sự nghi ngờ hay bối rối."},"4407":{"word":"sự phân tích","meaning":"Quá trình xem xét kỹ lưỡng một điều gì đó bằng cách chia nhỏ nó thành các phần để hiểu chi tiết, cấu trúc hoặc ý nghĩa của nó."},"4408":{"word":"địa vị","meaning":"Vị trí thích hợp của một người trong xã hội, thể hiện qua cách sống, hành động và những gì họ sở hữu."},"4409":{"word":"đài phun nước","meaning":"Một công trình thường ở công viên hoặc khu vực công cộng, phun nước lên cao, tạo ra một cảnh tượng đẹp mắt."},"4410":{"word":"lĩnh vực","meaning":"Một bộ phận cụ thể của kiến thức, nghiên cứu hoặc hoạt động chuyên môn."},"4411":{"word":"sự phân bố","meaning":"Cách mà một cái gì đó được trải rộng hoặc sắp xếp trong một không gian cụ thể hoặc giữa một nhóm sự vật."},"4412":{"word":"không thể","meaning":"Tình huống một hành động hoàn toàn không thể thực hiện được hoặc bị cấm rõ ràng."},"4413":{"word":"điều bất khả thi","meaning":"Trạng thái của một điều gì đó hoàn toàn không thể xảy ra hoặc không thể đạt được."},"4414":{"word":"không thể tránh khỏi","meaning":"Khi một tình huống hoặc sự kiện không thể ngăn chặn hoặc bỏ qua được, có nghĩa là nó nhất định phải xảy ra hoặc được chấp nhận."},"4415":{"word":"Phật giáo","meaning":"Phật giáo là một tôn giáo lớn có nguồn gốc từ Ấn Độ, dạy về sự giác ngộ và lòng từ bi."},"4416":{"word":"bất chấp, bất kể","meaning":"Diễn tả việc điều gì đó xảy ra hoặc đúng sự thật dù có một yếu tố cản trở hoặc trái ngược."},"4417":{"word":"ngọn lửa, lửa","meaning":"Ánh sáng màu đỏ hoặc cam phát ra từ vật đang cháy."},"4418":{"word":"gợi lên, khơi dậy","meaning":"Khiến một cảm xúc, ký ức hoặc phản ứng nào đó xuất hiện hoặc trở nên mạnh mẽ."},"4419":{"word":"bất lợi","meaning":"Tình huống hoặc điều kiện khiến ai đó ở vào vị trí yếu hơn hoặc khó khăn hơn."},"4420":{"word":"ngâm","meaning":"Đặt vật vào chất lỏng để vật hút chất lỏng, thường làm vật mềm hơn hoặc nở ra."},"4421":{"word":"bất hợp pháp, trái pháp luật","meaning":"Hành động hoặc sự việc vi phạm quy tắc, luật lệ đã được thiết lập."},"4422":{"word":"ánh lửa","meaning":"Ánh sáng phát ra từ lửa đang cháy."},"4423":{"word":"thổi đến, thổi vào","meaning":"Khi không khí di chuyển nhanh theo một hướng nhất định, thường làm các vật thể lay động."},"4424":{"word":"thiệt thòi, bất lợi","meaning":"Tình trạng hoặc hành động khiến ai đó ở vào vị trí kém thuận lợi hoặc xấu hơn so với người khác."},"4425":{"word":"không đủ, thiếu","meaning":"Trạng thái số lượng hoặc chất lượng của một thứ gì đó không đủ cho một mục đích cụ thể."},"4426":{"word":"không thân thiện, bất lịch sự","meaning":"Hành vi thể hiện sự thiếu ấm áp, lịch sự hoặc sẵn lòng giúp đỡ đối với người khác."},"4427":{"word":"khó chịu","meaning":"Cảm giác không vui, không thoải mái hoặc bực bội nhẹ về một điều gì đó."},"4428":{"word":"bất bình đẳng","meaning":"Tình trạng mà các nhóm hoặc cá nhân khác nhau không có cùng quyền lợi, cơ hội hoặc nguồn lực."},"4429":{"word":"không cần thiết","meaning":"Điều gì đó không được yêu cầu cho một mục đích cụ thể hoặc không thêm giá trị gì."},"4430":{"word":"bất hạnh","meaning":"Trạng thái không hạnh phúc hoặc gặp phải những điều không may mắn."},"4431":{"word":"không chắc chắn","meaning":"Trạng thái mà kết quả hoặc tương lai của một việc gì đó không được biết hoặc không thể dự đoán với sự tự tin."},"4432":{"word":"nắm giữ","meaning":"Nắm lấy một cái gì đó một cách chắc chắn để giữ nó lại hoặc ngăn nó di chuyển."},"4433":{"word":"giữ lại","meaning":"Nắm giữ một vật gì đó một cách chắc chắn để không làm mất nó."},"4434":{"word":"bị bắt","meaning":"Bị ai đó nắm giữ hoặc bắt giữ, thường khi đang cố gắng trốn thoát."},"4435":{"word":"phi-, không- (tiếp đầu ngữ)","meaning":"Một phần của từ được đặt ở đầu một từ khác để tạo ra nghĩa đối lập."},"4436":{"word":"bí quyết","meaning":"Phương pháp riêng hoặc kỹ thuật đặc biệt mà ai đó giữ kín để đạt được thành công."},"4437":{"word":"tương đối","meaning":"Diễn tả điều gì đó bằng cách so sánh với những điều tương tự khác, thay vì đo lường bằng bản thân nó."},"4438":{"word":"bi kịch","meaning":"Một vở kịch hoặc sự kiện có thật gây ra nỗi buồn lớn và đau khổ, thường kết thúc bằng một thảm họa hoặc mất mát lớn."},"4439":{"word":"Hòa","meaning":"Kết thúc một trận đấu mà không bên nào thắng, không bên nào thua."},"4440":{"word":"Sự chỉ trích","meaning":"Việc bày tỏ sự không đồng tình mạnh mẽ, chê bai về hành động hoặc phẩm chất của ai đó."},"4441":{"word":"Ni lông","meaning":"Một loại vật liệu nhựa mỏng, dẻo, thường trong suốt, dùng để bọc hoặc làm túi."},"4442":{"word":"Mãi mới","meaning":"Chỉ thời điểm một việc bắt đầu xảy ra, thường là sau khi một điều kiện nào đó được đáp ứng hoặc sau một thời gian chờ đợi."},"4443":{"word":"Mặc dù","meaning":"Dùng để diễn tả một sự việc, một tình huống không ngăn cản được một sự việc khác xảy ra hoặc một sự thật khác đúng."},"4444":{"word":"Bắt nguồn từ","meaning":"Xuất hiện hoặc bắt đầu tồn tại từ một nguồn, một nguyên nhân hoặc một thời điểm cụ thể."},"4445":{"word":"Kể cả","meaning":"Dùng để giới thiệu một đối tượng hoặc một người đứng đầu, và có các đối tượng hoặc người khác tương tự đi kèm."},"4446":{"word":"Béo phì","meaning":"Tình trạng cơ thể tích trữ quá nhiều mỡ, khiến người đó có kích thước lớn hơn bình thường."},"4447":{"word":"Tiếng hét","meaning":"Âm thanh lớn, chói tai và thường có cao độ cao mà một người phát ra, thường là do sợ hãi, đau đớn bất ngờ hoặc phấn khích tột độ."},"4448":{"word":"Mưa bão","meaning":"Tình trạng thời tiết khắc nghiệt với nhiều mưa và gió mạnh, thường gây cản trở và hư hại."},"4449":{"word":"Bí quyết","meaning":"Cách làm đặc biệt nào đó mà không nhiều người biết đến."},"4450":{"word":"Khẩn cấp","meaning":"Một tình huống nguy hiểm hoặc khó khăn bất ngờ và nghiêm trọng, đòi hỏi phải có hành động nhanh chóng và cấp bách."},"4451":{"word":"phi thường","meaning":"Rất đặc biệt, khác thường, xuất sắc vượt trội so với mức bình thường."},"4452":{"word":"làm rỗng, đổ đi","meaning":"Loại bỏ tất cả đồ vật bên trong để làm cho cái gì đó trở nên không có gì."},"4453":{"word":"chế giễu, cười nhạo","meaning":"Cười hoặc thể hiện sự coi thường, cho rằng ai đó thật ngốc nghếch hoặc đáng buồn cười."},"4454":{"word":"phép ẩn dụ, so sánh","meaning":"Cách dùng đặc điểm của sự vật này để miêu tả sự vật khác, nhằm làm rõ hoặc nhấn mạnh ý nghĩa."},"4455":{"word":"tỉ lệ","meaning":"Mối quan hệ về số lượng giữa hai hoặc nhiều vật thể, hoặc giữa một phần với toàn bộ."},"4456":{"word":"tỉ trọng, tầm quan trọng","meaning":"Mức độ ảnh hưởng, tầm quan trọng hoặc giá trị của một người, vật hay vấn đề nào đó trong một tổng thể."},"4457":{"word":"chiếu sáng","meaning":"Phát ra ánh sáng làm cho một nơi hoặc vật nào đó trở nên sáng rõ."},"4458":{"word":"chiếu, phản chiếu","meaning":"Ánh sáng chiếu rọi vào một nơi hoặc hình ảnh của vật gì đó xuất hiện trên bề mặt khác."},"4459":{"word":"loạng choạng, lảo đảo","meaning":"Đi lại một cách mất thăng bằng, xiêu vẹo sang hai bên như sắp ngã."},"4460":{"word":"sự phê phán, lời phê bình","meaning":"Hành động chỉ ra những điểm sai, không đúng hoặc những mặt yếu kém của một người, ý tưởng hay hành động."},"4461":{"word":"có tính phê phán, phê bình","meaning":"Cách suy nghĩ đánh giá kỹ lưỡng các mặt tốt xấu của vấn đề, không dễ dàng chấp nhận mà xem xét sâu sắc."},"4462":{"word":"cái lược","meaning":"Vật dụng có răng cưa nhỏ dùng để chải tóc cho mượt và gỡ rối."},"4463":{"word":"nước mưa","meaning":"Nước rơi từ trời xuống trong những giọt mưa và đọng lại trên bề mặt hoặc chảy trên mặt đất."},"4464":{"word":"giọt mưa","meaning":"Một giọt nước nhỏ, tròn rơi từ trời xuống trong thời tiết mưa."},"4465":{"word":"nợ","meaning":"Số tiền mà một người phải trả lại vì đã vay mượn."},"4466":{"word":"nặn","meaning":"Dùng tay để ấn, bóp và nhào nặn vật liệu mềm như đất sét thành hình dạng mong muốn."},"4467":{"word":"màu sắc","meaning":"Tính chất của ánh sáng phản xạ từ một vật thể, tạo nên màu sắc cho nó."},"4468":{"word":"tỏa sáng","meaning":"Ánh sáng phát ra một cách rực rỡ."},"4469":{"word":"làm rơi xuống","meaning":"Làm cho ai đó hoặc vật gì đó rơi xuống một nơi sâu như nước hoặc hố."},"4470":{"word":"thoát ra","meaning":"Rời khỏi hoặc đi qua một nơi bị bao bọc, kín đáo để thoát ra ngoài."},"4471":{"word":"ra khỏi","meaning":"Di chuyển từ bên trong hoặc từ chỗ ẩn khuất ra một không gian mở và có thể nhìn thấy được."},"4472":{"word":"đầy đủ","meaning":"Một cách không bỏ sót bất cứ thứ gì, bao gồm tất cả."},"4473":{"word":"bỏ qua","meaning":"Không đưa một vật hay việc gì vào một tập hợp, danh sách theo chủ ý."},"4474":{"word":"bị tước đoạt","meaning":"Một món đồ hoặc tài nguyên bị lấy đi khỏi quyền sở hữu của ai đó bằng vũ lực hoặc không được phép."},"4475":{"word":"cướp đoạt","meaning":"Lấy đi một vật gì đó của người khác bằng vũ lực."},"4476":{"word":"má","meaning":"Phần mềm thịt ở hai bên mặt, nằm dưới mắt và cạnh miệng."},"4477":{"word":"vươn ra, duỗi ra","meaning":"Kéo dài hoặc làm cho cái gì đó đạt đến một phạm vi xa hơn."},"4478":{"word":"bị nhổ, bị rút ra","meaning":"Bị loại bỏ một cách mạnh mẽ ra khỏi vị trí ban đầu bằng cách kéo ra."},"4479":{"word":"gạt ra, hất ra","meaning":"Rụt tay lại mạnh mẽ để không cho người khác nắm giữ."},"4480":{"word":"-công ty, -xã","meaning":"Hậu tố gắn vào để chỉ một tổ chức hoặc công ty sản xuất hoặc cung cấp dịch vụ."},"4481":{"word":"-sĩ, -gia","meaning":"Hậu tố gắn vào từ để chỉ người làm một công việc cụ thể hoặc có kỹ năng nhất định."},"4482":{"word":"cách suy nghĩ, lối suy nghĩ","meaning":"Kiểu mẫu đặc trưng mà một người dùng để xử lý thông tin và hình thành quan điểm."},"4483":{"word":"lừa đảo, gian lận","meaning":"Hành vi lừa dối người khác để chiếm đoạt tiền bạc hoặc tài sản một cách bất chính."},"4484":{"word":"người đàn ông","meaning":"Một nam giới trưởng thành, thường được dùng một cách thân mật hoặc không trang trọng."},"4485":{"word":"săn bắn","meaning":"Hoạt động đuổi bắt và giết động vật hoang dã để lấy thức ăn, thể thao hoặc da."},"4486":{"word":"mua vào, mua gom","meaning":"Mua một số lượng lớn vật phẩm hoặc tài sản bằng cách trả tiền."},"4487":{"word":"đáng yêu","meaning":"Có những phẩm chất khiến người khác cảm thấy trìu mến và yêu mến."},"4488":{"word":"trường hợp","meaning":"Một sự việc hoặc tình huống cụ thể được dùng để minh họa cho một quy tắc hoặc nguyên tắc chung."},"4489":{"word":"bắt giữ","meaning":"Bắt và giữ chặt một con vật hoặc người, không cho chúng thoát ra được."},"4490":{"word":"tư thục","meaning":"Một tổ chức (như trường học) không được chính phủ tài trợ hoặc quản lý."},"4491":{"word":"sa mạc","meaning":"Một vùng đất rộng lớn hầu như không có mưa, thường có nhiều cát hoặc đá."},"4492":{"word":"tử vong","meaning":"Trạng thái cuối cùng khi cơ thể của một sinh vật ngừng hoạt động, không thể cử động hoặc thở được nữa."},"4493":{"word":"công việc văn phòng","meaning":"Một loại công việc mà người làm chủ yếu ngồi làm việc tại bàn, thường với máy tính và tài liệu, trong một tòa nhà."},"4494":{"word":"bốn phía","meaning":"Mọi phía hoặc điểm xung quanh một người hoặc vật, bao gồm phía trước, phía sau, bên trái và bên phải."},"4495":{"word":"trong lịch sử","meaning":"Chỉ việc gì đó xảy ra lần đầu tiên trong toàn bộ lịch sử loài người được ghi lại."},"4496":{"word":"xã luận","meaning":"Một bài viết thể hiện quan điểm hoặc ý kiến của tác giả, được đăng trên báo hoặc tạp chí."},"4497":{"word":"nhỏ nhặt","meaning":"Quá nhỏ hoặc không quan trọng đến mức không cần phải xem xét kỹ lưỡng."},"4498":{"word":"chủ doanh nghiệp","meaning":"Một người hoặc tổ chức điều hành một công ty, bán hàng hóa hoặc cung cấp dịch vụ để kiếm tiền."},"4499":{"word":"câu chuyện, tình huống","meaning":"Những sự kiện hay lý do cụ thể trong quá khứ giải thích cho một tình huống hiện tại."},"4500":{"word":"người dùng","meaning":"Người tương tác hoặc điều khiển một công cụ, máy móc, hệ thống hoặc dịch vụ."},"4501":{"word":"con rể","meaning":"Người đàn ông đã kết hôn với con gái của một người."},"4502":{"word":"mạng, không gian mạng","meaning":"Liên quan đến hoặc diễn ra trong thế giới ảo chung thông qua các máy tính và thiết bị điện tử được kết nối."},"4503":{"word":"hòa thuận, thân thiết","meaning":"Khi mọi người tương tác một cách tử tế, thân thiện và thể hiện sự quan tâm, yêu mến lẫn nhau."},"4504":{"word":"hoàn cảnh, tình hình","meaning":"Tổng hợp các sự kiện, điều kiện và tình huống tồn tại xung quanh ai đó hoặc điều gì đó tại một thời điểm cụ thể."},"4505":{"word":"album ảnh","meaning":"Một cuốn sách đặc biệt dùng để lưu giữ và trưng bày nhiều bức ảnh in."},"4506":{"word":"tuổi dậy thì","meaning":"Giai đoạn trong cuộc đời một người trẻ khi cơ thể trải qua những thay đổi về thể chất và trưởng thành từ trẻ con sang người lớn."},"4507":{"word":"sự việc, tình hình (nghiêm trọng)","meaning":"Một sự kiện khó khăn hoặc nguy hiểm xảy ra và ảnh hưởng đến nhiều thứ hoặc nhiều người."},"4508":{"word":"tiếng địa phương, thổ ngữ","meaning":"Cách nói một ngôn ngữ cụ thể sử dụng các từ và âm thanh đặc biệt, thường đặc trưng cho một vùng nhất định."},"4509":{"word":"đơn xin thôi việc, đơn từ chức","meaning":"Một tuyên bố chính thức, thường là thư, mà người lao động gửi cho người sử dụng lao động để thông báo họ sẽ nghỉ việc."},"4510":{"word":"đời sống xã hội","meaning":"Cách một người sống và tương tác với những người khác trong cộng đồng, trường học hoặc công việc của họ."},"4511":{"word":"đường núi","meaning":"Con đường nhỏ hẹp, uốn lượn qua khu vực đồi núi, rừng cây."},"4512":{"word":"cháy rừng","meaning":"Ngọn lửa lớn bùng phát và lan nhanh không kiểm soát trong khu vực rừng cây."},"4513":{"word":"trong núi","meaning":"Khu vực sâu bên trong núi, xa các khu dân cư, đô thị."},"4514":{"word":"cứu sống","meaning":"Thực hiện hành động để giúp người hoặc vật tránh khỏi cái chết, hoặc làm cho vật gì đó hoạt động trở lại."},"4515":{"word":"cuộc sống gia đình","meaning":"Việc thiết lập một gia đình và cùng nhau sống cuộc sống chung."},"4516":{"word":"sống","meaning":"Tiếp tục tồn tại và trải qua các hoạt động hàng ngày, thường đối mặt với nhiều kinh nghiệm khác nhau."},"4517":{"word":"sống sót","meaning":"Tiếp tục tồn tại và vượt qua một sự kiện nguy hiểm hoặc một giai đoạn khó khăn."},"4518":{"word":"sống đến nay","meaning":"Đã tiếp tục tồn tại trong một khoảng thời gian nhất định cho đến hiện tại."},"4519":{"word":"coi là","meaning":"Quyết định để cái gì đó hoặc ai đó đảm nhận một vị trí, vai trò hoặc mục đích cụ thể."},"4520":{"word":"nuốt","meaning":"Đẩy thức ăn, đồ uống hoặc vật khác từ miệng qua cổ họng xuống dạ dày."},"4521":{"word":"khu thương mại","meaning":"Khu vực trong thành phố có nhiều tòa nhà tập trung các cửa hàng kinh doanh, dịch vụ."},"4522":{"word":"sự liên quan","meaning":"Mối quan hệ hoặc sự liên đới giữa các sự vật, hiện tượng với nhau."},"4523":{"word":"bất kể","meaning":"Diễn tả một hành động hoặc trạng thái không bị ảnh hưởng bởi một điều kiện hay tình huống nào đó."},"4524":{"word":"tiền thưởng","meaning":"Số tiền hoặc vật có giá trị được trao cho người thắng cuộc hoặc đạt thành tích đặc biệt."},"4525":{"word":"phòng tư vấn","meaning":"Nơi riêng tư để mọi người gặp chuyên gia trình bày vấn đề của mình và nhận lời khuyên."},"4526":{"word":"nhân viên tư vấn","meaning":"Người lắng nghe vấn đề của người khác và đưa ra lời khuyên hoặc hướng dẫn."},"4527":{"word":"đáng kể","meaning":"Có số lượng, kích thước hoặc mức độ lớn, dễ nhận thấy."},"4528":{"word":"khá là","meaning":"Diễn tả mức độ hoặc phạm vi đáng chú ý, hơn một chút."},"4529":{"word":"đối phương","meaning":"Người hoặc đội mà một người cạnh tranh trong trò chơi, cuộc chiến hoặc cuộc thảo luận."},"4530":{"word":"tương đối","meaning":"Được mô tả hoặc hiểu bằng cách so sánh với cái khác, chứ không phải tự nó đứng một mình."},"4531":{"word":"bên đối phương","meaning":"Người hoặc nhóm ở phía đối diện, đặc biệt trong một cuộc thi đấu hoặc bất đồng."},"4532":{"word":"thượng lưu","meaning":"Phần trên của một con sông hoặc dòng suối chảy."},"4533":{"word":"nửa đầu năm","meaning":"Khoảng thời gian sáu tháng đầu tiên của một năm dương lịch, từ tháng 1 đến tháng 6."},"4534":{"word":"cấp trên","meaning":"Người có chức vụ hoặc địa vị cao hơn trong công việc và có quyền hạn đối với người khác."},"4535":{"word":"tưởng tượng","meaning":"Hành động hình dung ra điều gì đó không tồn tại hoặc chưa từng trải nghiệm trong tâm trí."},"4536":{"word":"trí tưởng tượng","meaning":"Khả năng nghĩ ra những điều không tồn tại hoặc chưa từng trải nghiệm."},"4537":{"word":"sự tăng lên","meaning":"Sự đi lên về số lượng, mức độ hoặc khối lượng, thể hiện sự cao hơn hoặc lớn hơn."},"4538":{"word":"thương mại","meaning":"Hoạt động mua bán hàng hóa và dịch vụ, đặc biệt là trên quy mô lớn."},"4539":{"word":"biểu tượng","meaning":"Một vật, hình ảnh hoặc hình dạng đại diện cho một ý tưởng hoặc phẩm chất nào đó."},"4540":{"word":"sảng khoái","meaning":"Cảm thấy nhẹ nhàng và trong sạch một cách dễ chịu, giúp tinh thần hoạt bát và minh mẫn hơn."},"4541":{"word":"trên dưới","meaning":"Phần phía trên và phần phía dưới của một cái gì đó, hoặc hướng về chúng."},"4542":{"word":"khoảnh khắc","meaning":"Một khoảng thời gian rất ngắn."},"4543":{"word":"khắc","meaning":"Cắt chữ, hình ảnh hoặc thiết kế vào vật liệu cứng như gỗ hoặc kim loại, làm cho chúng hiện rõ vĩnh viễn trên bề mặt."},"4544":{"word":"con non","meaning":"Một sinh vật rất non mới được sinh ra từ động vật, như mèo con, chó con hoặc chim con."},"4545":{"word":"rò rỉ","meaning":"(Chất lỏng, khí hoặc ánh sáng) đi qua một lỗ nhỏ hoặc khe hở khi đáng lẽ phải được chứa lại, trở nên nhìn thấy được bên ngoài."},"4546":{"word":"rạng sáng","meaning":"Bầu trời trở nên sáng rõ khi mặt trời xuất hiện trên đường chân trời, đánh dấu sự bắt đầu của một ngày mới."},"4547":{"word":"lại, lại một lần nữa","meaning":"Diễn tả việc cảm nhận hoặc trải nghiệm lại một điều gì đó và nhận ra nó một cách mới mẻ, khác biệt so với trước đây."},"4548":{"word":"thức trắng, thức khuya","meaning":"Ở trong trạng thái không ngủ, thức suốt cả đêm."},"4549":{"word":"độc đáo, khác lạ","meaning":"Có vẻ ngoài hoặc cảm giác khác biệt rõ rệt so với cái thông thường, làm cho nó nổi bật."},"4550":{"word":"-sinh","meaning":"Hậu tố chỉ năm sinh hoặc năm con giáp mà một người được sinh ra."},"4551":{"word":"xuất hiện, nảy sinh","meaning":"Một điều gì đó đột ngột hiện ra hoặc bắt đầu tồn tại, trở nên rõ ràng nơi mà trước đó không có."},"4552":{"word":"sức sống, sinh khí","meaning":"Năng lượng, sự tươi tắn trong ánh mắt và các cử động linh hoạt làm cho một người hoặc động vật trông đầy sức khỏe và tinh thần."},"4553":{"word":"hình dáng, ngoại hình","meaning":"Những đặc điểm bên ngoài và hình dạng tổng thể của một người, con vật hoặc đồ vật."},"4554":{"word":"sự lược bỏ, sự bỏ qua","meaning":"Hành động cố ý loại bỏ hoặc không sử dụng một từ, một phần hoặc một mục nào đó."},"4555":{"word":"sinh mệnh, sự sống","meaning":"Trạng thái của một người, động vật hoặc thực vật có khả năng cử động, hít thở, phát triển và phản ứng với môi trường xung quanh."},"4556":{"word":"chương trình phát sóng trực tiếp","meaning":"Chương trình truyền hình hoặc radio được phát sóng và khán giả nhận được ngay tại thời điểm nó đang diễn ra, không có độ trễ hay ghi hình trước."},"4557":{"word":"sản xuất","meaning":"Hành động chế tạo hoặc trồng trọt hàng hóa, nguyên vật liệu, thường là trong nhà máy hoặc trang trại, để sử dụng hoặc bán."},"4558":{"word":"sống động, rõ nét","meaning":"Miêu tả một ký ức hoặc hình ảnh rõ ràng và mạnh mẽ đến mức cảm thấy như nó đang diễn ra ngay bây giờ."},"4559":{"word":"sinh tồn","meaning":"Việc tiếp tục tồn tại hoặc duy trì sự sống, đặc biệt trong hoàn cảnh khó khăn."},"4560":{"word":"se lạnh","meaning":"Miêu tả không khí hoặc thời tiết hơi lạnh, thường mang lại cảm giác dễ chịu chứ không rét buốt."},"4561":{"word":"buồn tủi","meaning":"Cảm thấy rất buồn và đau đớn, thường khi cảm thấy cô đơn hoặc bị đối xử không công bằng."},"4562":{"word":"dần dần","meaning":"Diễn tả việc gì đó xảy ra hoặc thay đổi theo từng bước nhỏ, liên tục trong một khoảng thời gian, không phải cùng một lúc."},"4563":{"word":"người phương Tây","meaning":"Người có nguồn gốc từ các nước ở châu Âu, Bắc Mỹ hoặc châu Úc."},"4564":{"word":"tiếc nuối","meaning":"Cảm thấy buồn nhẹ hoặc thất vọng, đặc biệt khi phải chia tay hoặc khi một điều mong muốn không thành hiện thực."},"4565":{"word":"sách","meaning":"Các bài viết, hình ảnh, v.v., được in và đóng thành tập."},"4566":{"word":"vụng về","meaning":"Thực hiện hành động hoặc công việc một cách kém cỏi, không khéo léo, thường mắc lỗi do thiếu kinh nghiệm hoặc khả năng."},"4567":{"word":"hòa trộn","meaning":"Khi nhiều thứ khác nhau kết hợp lại hoặc được đưa vào cùng nhau để tạo thành một thể thống nhất."},"4568":{"word":"bầu cử","meaning":"Quá trình chính thức để người dân bỏ phiếu hoặc dùng máy móc để chọn ra lãnh đạo hay đại diện của mình trong chính phủ."},"4569":{"word":"quảng cáo","meaning":"Hành động phổ biến rộng rãi một ý tưởng, lợi ích của sản phẩm hoặc một vấn đề nào đó đến nhiều người."},"4570":{"word":"tuyển chọn","meaning":"Việc cẩn thận chọn ra một hoặc nhiều người/vật từ một nhóm lớn hơn dựa trên các tiêu chí cụ thể."},"4571":{"word":"tiên tiến","meaning":"Diễn tả một quốc gia hoặc công nghệ đã phát triển cao, hiện đại và đạt được trình độ đổi mới, tiến bộ xã hội."},"4572":{"word":"nước phát triển","meaning":"Một quốc gia có nền kinh tế mạnh, cơ sở hạ tầng và dịch vụ hiện đại, cùng chất lượng cuộc sống cao cho người dân."},"4573":{"word":"sự ưa thích","meaning":"Việc thích một điều gì đó hơn những điều khác, khiến nó được chọn hoặc mong muốn thường xuyên hơn."},"4574":{"word":"sự thuyết phục","meaning":"Hành động nói chuyện với ai đó để họ thay đổi suy nghĩ hoặc đồng ý với ý kiến của bạn."},"4575":{"word":"hồi hộp, rạo rực","meaning":"Khi tim đập nhanh và bạn cảm thấy một niềm vui nhẹ nhàng trong lồng ngực vì sắp có điều gì đó tốt đẹp xảy ra."},"4576":{"word":"sự thành lập","meaning":"Hành động tạo ra một tổ chức, công ty hoặc thể chế mới ngay từ đầu."},"4577":{"word":"không đời nào, không lẽ nào","meaning":"Một từ dùng để diễn tả sự không tin mạnh mẽ hoặc ngạc nhiên rằng một điều gì đó bất ngờ có thể là sự thật."},"4578":{"word":"sự thiết lập, sự cài đặt","meaning":"Hành động sắp xếp hoặc định nghĩa các chi tiết, điều kiện hoặc quy tắc cụ thể để một việc gì đó xảy ra hoặc hoạt động."},"4579":{"word":"sự lắp đặt","meaning":"Quá trình đặt một thiết bị, chương trình hoặc hệ thống vào vị trí để nó có thể được sử dụng."},"4580":{"word":"độ C, độ bách phân","meaning":"Một cách đo nhiệt độ mà nước đóng băng ở 0 độ và sôi ở 100 độ."},"4581":{"word":"-tính (suffix), tính chất","meaning":"Một phần được thêm vào cuối một từ để chỉ một đặc điểm cụ thể hoặc bản chất cơ bản của một cái gì đó."},"4582":{"word":"thành công","meaning":"Diễn tả một việc gì đó đạt được mục tiêu hoặc kết quả mong muốn và mang lại kết quả tốt đẹp."},"4583":{"word":"thành quả","meaning":"Điều đạt được sau một quá trình làm việc hoặc nỗ lực."},"4584":{"word":"thành lập, thiết lập","meaning":"Việc một thỏa thuận, quan hệ hay điều kiện bắt đầu tồn tại và có hiệu lực."},"4585":{"word":"trưởng thành","meaning":"Tình trạng phát triển đầy đủ về thể chất hoặc tinh thần, thể hiện sự hiểu biết và hành vi của người lớn."},"4586":{"word":"tăng trưởng, phát triển","meaning":"Quá trình tăng lên về kích thước, số lượng hoặc tầm quan trọng theo thời gian."},"4587":{"word":"bảng điểm, phiếu điểm","meaning":"Giấy tờ ghi lại kết quả học tập hoặc điểm số của học sinh trong các môn học."},"4588":{"word":"tính cách, bản tính","meaning":"Đặc điểm hoặc phẩm chất cảm xúc độc đáo khiến một người hoặc vật hành xử theo một cách nhất định."},"4589":{"word":"mang tầm thế giới, đẳng cấp thế giới","meaning":"Được công nhận và ngưỡng mộ bởi nhiều người từ các quốc gia khác nhau trên toàn cầu."},"4590":{"word":"toàn cầu hóa","meaning":"Quá trình các quốc gia và người dân trở nên kết nối hơn thông qua ý tưởng, thương mại và văn hóa."},"4591":{"word":"thuế","meaning":"Số tiền mà người dân và doanh nghiệp phải nộp định kỳ cho chính phủ để chi trả cho các dịch vụ công cộng."},"4592":{"word":"thế hệ","meaning":"Một nhóm người sinh ra và sống cùng thời điểm, thường là cha mẹ và con cái, kéo dài khoảng 25-30 năm."},"4593":{"word":"hộ gia đình","meaning":"Một nhóm người sống chung trong một nhà hoặc một đơn vị cư trú."},"4594":{"word":"thế lực, sức ảnh hưởng","meaning":"Khả năng kiểm soát hoặc gây ảnh hưởng đáng kể đến người khác của một người, nhóm hoặc quốc gia."},"4595":{"word":"hình tam giác","meaning":"Một hình phẳng có ba cạnh thẳng và ba góc nối với nhau."},"4596":{"word":"hội thảo","meaning":"Một cuộc họp nhỏ của một nhóm người để thảo luận về một chủ đề cụ thể hoặc nhận hướng dẫn."},"4597":{"word":"quy mô nhỏ","meaning":"Một cái gì đó chỉ liên quan đến một số lượng hạn chế người, đồ vật hoặc một khu vực nhất định."},"4598":{"word":"thụ động","meaning":"Có xu hướng chấp nhận mọi việc mà không thể hiện nhiều phản ứng hoặc cố gắng tạo ra thay đổi."},"4599":{"word":"cây thông","meaning":"Một loại cây thân gỗ cao, thường xanh, có lá dài mỏng như kim và tạo ra quả nón cứng."},"4600":{"word":"thiếu nữ","meaning":"Một cô gái trẻ chưa đến tuổi trưởng thành."},"4601":{"word":"thiếu niên","meaning":"Một cậu bé còn trẻ và chưa trưởng thành."},"4602":{"word":"thu nhập","meaning":"Tiền mà một cá nhân hoặc công ty nhận được thường xuyên, điển hình từ công việc, đầu tư hoặc các nguồn khác."},"4603":{"word":"hét lên","meaning":"Phát ra âm thanh rất lớn bằng giọng nói của mình, thường để thu hút sự chú ý hoặc bày tỏ cảm xúc mạnh mẽ."},"4604":{"word":"được đồn đại","meaning":"Khi thông tin, thường chưa được xác minh, lan truyền giữa nhiều người về ai đó hoặc điều gì đó, khiến họ được nhắc đến."},"4605":{"word":"xe cứu hỏa","meaning":"Một chiếc xe lớn, thường màu đỏ, có thang, vòi và bồn chứa nước, được sử dụng bởi những người dập tắt đám cháy."},"4606":{"word":"tiêu dùng","meaning":"Hành động mua và sử dụng hàng hóa hoặc dịch vụ, như ăn uống hoặc chạy điện."},"4607":{"word":"người tiêu dùng","meaning":"Người mua sản phẩm hoặc sử dụng dịch vụ từ một doanh nghiệp hay người bán hàng."},"4608":{"word":"số ít","meaning":"Một số lượng nhỏ, không nhiều."},"4609":{"word":"nước sốt","meaning":"Một loại chất lỏng sệt, thường được thêm vào món ăn để tăng hương vị hoặc độ ẩm."},"4610":{"word":"công dụng","meaning":"Tác dụng hoặc lợi ích mà một vật thể hay hành động mang lại để giúp hoàn thành nhiệm vụ."},"4611":{"word":"vô ích","meaning":"Không có tác dụng, không giúp đạt được mục tiêu hay hoàn thành nhiệm vụ nào."},"4612":{"word":"sở hữu","meaning":"Tình trạng một đối tượng hoặc vật phẩm thuộc quyền sở hữu hợp pháp của một người hoặc một nhóm."},"4613":{"word":"tiếng ồn","meaning":"Âm thanh lớn, khó chịu hoặc không mong muốn gây phiền nhiễu."},"4614":{"word":"chất liệu","meaning":"Vật chất dùng để làm ra đồ vật, hoặc nội dung để viết, nói về."},"4615":{"word":"trân trọng","meaning":"Với sự quan tâm và bảo vệ cao độ, coi thứ gì đó hoặc người nào đó là rất quan trọng và quý giá."},"4616":{"word":"vật dụng cá nhân","meaning":"Những món đồ nhỏ như ví, điện thoại, chìa khóa mà một người mang theo bên mình."},"4617":{"word":"cỡ nhỏ","meaning":"Có kích thước hoặc quy mô nhỏ hơn so với các vật thể cùng loại."},"4618":{"word":"lơ là","meaning":"Không chú ý đúng mức hoặc không nỗ lực đầy đủ vào một nhiệm vụ hay một người, thường gây ra vấn đề."},"4619":{"word":"lông mi","meaning":"Phần lông mọc thành hàng nhỏ và ngắn dọc theo mép mi mắt trên và dưới."},"4620":{"word":"bị lừa","meaning":"Tin vào điều sai sự thật mà người khác nói khiến mình làm điều không mong muốn."},"4621":{"word":"tâm tư","meaning":"Suy nghĩ, tình cảm hoặc ý định thật sự không bộc lộ ra ngoài của một người."},"4622":{"word":"lừa dối","meaning":"Làm cho người khác tin vào điều không đúng sự thật, thường để lấy thứ gì đó hoặc gây hại cho họ."},"4623":{"word":"thuộc về","meaning":"Là một thành viên của một nhóm, thể loại, tổ chức cụ thể hoặc nằm trong một khu vực nhất định."},"4624":{"word":"sự giúp đỡ","meaning":"Hành động hỗ trợ hoặc giúp đỡ ai đó đang cần, thường bằng cách làm điều gì đó thực tế."},"4625":{"word":"đầu ngón tay","meaning":"Phần cuối cùng, mềm mại của ngón tay trên bàn tay con người."},"4626":{"word":"dễ dàng","meaning":"Mô tả một hành động hoặc công việc yêu cầu rất ít nỗ lực hoặc kỹ năng để hoàn thành."},"4627":{"word":"nắm tay","meaning":"Nối tay của mình với tay của người khác, thường thể hiện tình bạn hoặc sự hỗ trợ."},"4628":{"word":"tay nắm","meaning":"Một bộ phận cụ thể của đồ vật được thiết kế để người ta cầm bằng tay."},"4629":{"word":"sự sửa sang","meaning":"Hành động chỉnh trang, điều chỉnh hoặc thực hiện các sửa chữa nhỏ để cải thiện vẻ ngoài hoặc tình trạng của thứ gì đó."},"4630":{"word":"móng tay","meaning":"Phần cứng, mỏng ở cuối ngón tay; nó có tác dụng bảo vệ đầu ngón tay."},"4631":{"word":"thiệt hại","meaning":"Tình trạng bị mất mát, hư hỏng hoặc giá trị bị giảm sút, gây ra hậu quả tiêu cực."},"4632":{"word":"thật thà","meaning":"Miêu tả người thể hiện suy nghĩ và cảm xúc thật của mình một cách công khai, không che giấu."},"4633":{"word":"thành thật mà nói","meaning":"Theo cách trực tiếp bộc lộ suy nghĩ hoặc cảm xúc thật của mình mà không giữ lại điều gì."},"4634":{"word":"vọt lên","meaning":"Dâng lên hoặc bùng lên từ dưới lên trên một cách mạnh mẽ hoặc đột ngột."},"4635":{"word":"bê con","meaning":"Động vật non của loài bò, thường có bốn chân, màu nâu hoặc trắng, và sẽ lớn thành bò trưởng thành."},"4636":{"word":"sắt","meaning":"Kim loại màu trắng bạc, có từ tính, được sử dụng rộng rãi cho nhiều mục đích như chế tạo ô tô hoặc tàu thuyền."},"4637":{"word":"nhiều năm","meaning":"Khoảng thời gian bao gồm hơn hai năm nhưng không phải là số lượng năm quá lớn."},"4638":{"word":"vùng thủ đô","meaning":"Một vùng dân cư rộng lớn bao gồm thành phố quan trọng nhất của một quốc gia và tất cả các thị trấn, vùng ngoại ô xung quanh."},"4639":{"word":"vòi nước","meaning":"Thiết bị kim loại có núm hoặc cần gạt gắn vào ống, dùng để điều khiển dòng chảy của chất lỏng."},"4640":{"word":"nước máy","meaning":"Nước chảy ra từ vòi nước bên trong một tòa nhà và được dùng để rửa hoặc uống."},"4641":{"word":"thụ động","meaning":"Miêu tả người hoặc vật không tự mình hành động mà để người khác tác động hoặc để sự việc diễn ra một cách tự nhiên."},"4642":{"word":"chi phí sửa chữa","meaning":"Số tiền cần thiết để đưa một vật bị hỏng trở lại trạng thái hoạt động tốt."},"4643":{"word":"hàng vạn","meaning":"Một số lượng rất lớn, gồm nhiều nhóm mười nghìn đơn vị hoặc người."},"4644":{"word":"nhiều vô kể","meaning":"Có một số lượng hoặc số lượng rất lớn đến mức dường như không thể đếm hết."},"4645":{"word":"tuổi thọ","meaning":"Tổng thời gian một người, động vật hoặc vật thể thường sống hoặc tiếp tục tồn tại."},"4646":{"word":"hàng trăm","meaning":"Một nhóm hoặc số lượng lớn, bao gồm nhiều nhóm một trăm đơn vị hoặc vật phẩm."},"4647":{"word":"điều tra","meaning":"Việc tìm kiếm cẩn thận và kỹ lưỡng các sự thật và bằng chứng để khám phá sự thật về một tội phạm hoặc vấn đề."},"4648":{"word":"thủ tướng","meaning":"Người đứng đầu chính phủ, chịu trách nhiệm điều hành đất nước."},"4649":{"word":"thủ tục","meaning":"Một loạt các bước hoặc hành động chính thức cần được hoàn thành theo một thứ tự cụ thể để làm điều gì đó."},"4650":{"word":"câu đố","meaning":"Một câu hỏi hoặc câu nói được đưa ra dưới dạng một trò chơi cần một câu trả lời thông minh hoặc giàu trí tưởng tượng."},"4651":{"word":"thường xuyên","meaning":"Xảy ra hoặc được thực hiện nhiều lần hoặc trong khoảng thời gian gần nhau, không theo lịch trình cố định."},"4652":{"word":"hàng chục","meaning":"Một nhóm hoặc số lượng lớn, bao gồm nhiều nhóm mười đơn vị hoặc người."},"4653":{"word":"vô số","meaning":"Với một số lượng lớn đến mức không thể hoặc gần như không thể xác định được con số chính xác."},"4654":{"word":"nhu cầu","meaning":"Sự cần thiết hoặc mong muốn của mọi người để mua một số hàng hóa, dịch vụ hoặc tài nguyên với một mức giá cụ thể."},"4655":{"word":"chấp nhận","meaning":"Sự đồng ý tiếp nhận, chấp nhận một điều gì đó."},"4656":{"word":"hàng nhập khẩu","meaning":"Các sản phẩm được mang từ nước ngoài vào một quốc gia để bán."},"4657":{"word":"trình độ","meaning":"Một mức độ, địa vị hoặc khả năng cụ thể mà ai đó hoặc cái gì đó có được."},"4658":{"word":"hàng ngàn","meaning":"Một số lượng hoặc nhóm rất lớn, đại diện cho nhiều đơn vị hàng nghìn cá thể hoặc sự vật."},"4659":{"word":"sự thực hiện","meaning":"Hành động thực hiện một nhiệm vụ hoặc hoàn thành một công việc đã được giao."},"4660":{"word":"quý cô","meaning":"Một người phụ nữ lịch sự, có giáo dục và phong thái trang nhã trong hành động."},"4661":{"word":"cúi","meaning":"Để đầu hoặc thân trên của mình hướng xuống, thường để chào hỏi hoặc đi qua dưới một vật gì đó."},"4662":{"word":"tức thời","meaning":"Điều gì đó xảy ra hoặc tồn tại chỉ trong một thời gian rất ngắn."},"4663":{"word":"thuần khiết","meaning":"Hoàn toàn sạch sẽ, không pha lẫn tạp chất, hoặc không có ý nghĩ xấu."},"4664":{"word":"khoảnh khắc","meaning":"Một khoảnh khắc cực kỳ ngắn ngủi, chỉ trong nháy mắt hoặc một hơi thở."},"4665":{"word":"thứ hạng","meaning":"Danh sách được sắp xếp để thể hiện vị trí của một người hay một vật so với những cái khác, thường từ cao nhất đến thấp nhất."},"4666":{"word":"ngây thơ","meaning":"Tính cách đơn giản, dễ tin, thường vì chưa biết đến những điều phức tạp hay xấu xa trong cuộc sống."},"4667":{"word":"hiền lành","meaning":"Tính cách điềm đạm, tốt bụng và không dễ nổi giận hay thô bạo."},"4668":{"word":"chai rượu","meaning":"Một loại chai thủy tinh dùng để đựng và rót đồ uống có cồn."},"4669":{"word":"tiệc rượu","meaning":"Một buổi tụ tập xã hội nơi mọi người gặp gỡ và cùng nhau uống đồ uống có cồn."},"4670":{"word":"hơi thở","meaning":"Hành động hít không khí vào và thở ra qua mũi hoặc miệng của con người hoặc động vật."},"4671":{"word":"giấu","meaning":"Đặt một vật hoặc một người ở nơi không dễ bị người khác nhìn thấy hoặc phát hiện."},"4672":{"word":"tiếng thở","meaning":"Âm thanh có thể nghe được khi không khí di chuyển vào và ra khỏi cơ thể người hoặc động vật."},"4673":{"word":"chết","meaning":"Ngừng sống, nghĩa là cơ thể không còn hoạt động và không còn sự sống."},"4674":{"word":"nhà sư","meaning":"Một người đàn ông dành cả cuộc đời mình để học hỏi và thực hành giáo lý Phật giáo, thường sống trong chùa và mặc áo cà sa đặc trưng."},"4675":{"word":"công tắc","meaning":"Một bộ phận điều khiển nhỏ, thường là nút bấm hoặc cần gạt, dùng để bật hoặc tắt thiết bị điện hay đèn."},"4676":{"word":"lướt qua","meaning":"Một vật hoặc người di chuyển qua vật khác, tạo ra sự tiếp xúc vật lý rất nhẹ và thoáng qua."},"4677":{"word":"lịch trình","meaning":"Một danh sách kế hoạch hiển thị tất cả các sự kiện, cuộc hẹn hoặc công việc mà ai đó cần làm vào những thời điểm cụ thể."},"4678":{"word":"studio","meaning":"Một căn phòng hoặc tòa nhà được thiết kế đặc biệt để sáng tạo nghệ thuật, thu âm nhạc, chụp ảnh hoặc sản xuất phim."},"4679":{"word":"lén lút","meaning":"Làm gì đó một cách nhanh chóng và kín đáo, không để ai biết hoặc khó nhận ra."},"4680":{"word":"sự đồng ý","meaning":"Lời nói hoặc hành động bày tỏ sự đồng ý hay cho phép làm một việc gì đó."},"4681":{"word":"chiến thắng","meaning":"Kết quả đạt được khi đánh bại đối thủ trong một cuộc thi hay trận đấu."},"4682":{"word":"xe ô tô con","meaning":"Một loại xe ô tô nhỏ dùng để chở người đi lại cá nhân."},"4683":{"word":"thắng thua","meaning":"Kết quả cuối cùng của một cuộc thi đấu, xác định ai là người thắng và ai là người thua."},"4684":{"word":"góc nhìn","meaning":"Cách suy nghĩ, nhìn nhận và đánh giá một sự vật, hiện tượng hoặc vấn đề nào đó."},"4685":{"word":"rau bina","meaning":"Một loại rau có lá xanh đậm, thường được dùng để chế biến các món ăn như canh, xào hoặc luộc."},"4686":{"word":"khổ sở vì","meaning":"Liên tục trải qua một tình huống khó khăn, không dễ chịu, khiến bản thân cảm thấy mệt mỏi hay lo lắng."},"4687":{"word":"nhà chồng","meaning":"Gia đình của người chồng, bao gồm bố mẹ và các thành viên khác."},"4688":{"word":"sự cố gắng","meaning":"Việc nỗ lực làm một điều gì đó, nhất là điều mới mẻ hoặc khó khăn."},"4689":{"word":"héo","meaning":"Thực vật như hoa, cỏ... bị khô đi và mất màu sắc tươi tắn ban đầu."},"4690":{"word":"thị lực","meaning":"Khả năng nhìn rõ các vật thể của mắt."},"4691":{"word":"sê-ri, loạt","meaning":"Một tập hợp các tác phẩm như sách, phim hoặc chương trình truyền hình có liên quan đến nhau và được phát hành hoặc trình chiếu lần lượt."},"4692":{"word":"xi măng","meaning":"Một loại bột khô màu xám, khi trộn với nước sẽ trở nên rất cứng như đá, dùng để làm đường và xây dựng nhà cửa."},"4693":{"word":"bố mẹ chồng","meaning":"Bố và mẹ của chồng một người phụ nữ."},"4694":{"word":"ánh mắt, tầm nhìn","meaning":"Hướng mắt của một người nhìn vào một vật thể hoặc một người khác."},"4695":{"word":"hệ thống","meaning":"Một tập hợp các bộ phận hoặc quy trình được sắp xếp một cách có tổ chức để thực hiện một chức năng cụ thể."},"4696":{"word":"tầm nhìn, thị trường","meaning":"Toàn bộ khu vực hoặc phạm vi mà mắt của một người có thể nhìn thấy cùng một lúc."},"4697":{"word":"nhà thơ","meaning":"Người chuyên viết những tác phẩm văn học ngắn, thường dùng vần điệu và nhịp điệu để bày tỏ cảm xúc hoặc ý tưởng."},"4698":{"word":"thời gian, ngày tháng","meaning":"Khoảng thời gian tính bằng giờ, ngày hoặc tháng trôi qua cho đến khi một việc gì đó xảy ra hoặc hoàn thành."},"4699":{"word":"thời, thời kỳ, thuở","meaning":"Một khoảng thời gian hoặc một giai đoạn cụ thể."},"4700":{"word":"thời điểm","meaning":"Một khoảnh khắc cụ thể hoặc chính xác khi một sự việc xảy ra hoặc được xem xét."},"4701":{"word":"thị trường, nơi công cộng","meaning":"Những nơi công cộng hàng ngày mà mọi người tụ tập, trao đổi hàng hóa hoặc thực hiện các hoạt động thường nhật, như cửa hàng và khu vực chung."},"4702":{"word":"lấy chồng, kết hôn (nữ)","meaning":"Đối với phụ nữ, việc chính thức kết hợp với một người đàn ông làm bạn đời trong một buổi lễ hợp pháp."},"4703":{"word":"sự xem, việc xem","meaning":"Hành động nhìn hoặc theo dõi một chương trình truyền hình, phim ảnh hay buổi phát sóng."},"4704":{"word":"tỉ lệ người xem, tỉ suất người xem","meaning":"Con số hoặc phần trăm thể hiện số lượng người đang xem một chương trình truyền hình hoặc buổi phát sóng cụ thể."},"4705":{"word":"người xem, khán giả","meaning":"Người đang xem một chương trình truyền hình, phim hoặc buổi phát sóng."},"4706":{"word":"trận đấu, cuộc thi đấu","meaning":"Một sự kiện có tổ chức mà trong đó các cá nhân hoặc đội thi đấu với nhau để giành chiến thắng, thường là trong thể thao hoặc biểu diễn."},"4707":{"word":"sự thi hành, việc thực hiện","meaning":"Quá trình đưa một kế hoạch, luật hoặc chính sách vào thực tế hoặc bắt đầu áp dụng."},"4708":{"word":"lương thực, thực phẩm","meaning":"Các loại đồ ăn được con người hoặc động vật sử dụng để duy trì sự sống, thường được thu thập và dự trữ để dùng trong tương lai."},"4709":{"word":"thực vật, cây cối","meaning":"Một sinh vật sống không thể tự di chuyển được, bao gồm cây cỏ và cây thân gỗ."},"4710":{"word":"sự thèm ăn, cảm giác đói","meaning":"Cảm giác thể chất trong dạ dày khiến một người muốn ăn thức ăn."},"4711":{"word":"tân-, mới- (tiền tố)","meaning":"Một phần nhỏ của từ được gắn vào đầu các từ khác để chỉ ra rằng một cái gì đó vừa mới xuất hiện hoặc được tạo ra."},"4712":{"word":"giày, dép","meaning":"Một vật phẩm được mang vào chân để che phủ và bảo vệ chân."},"4713":{"word":"niềm tin, tín niệm","meaning":"Một ý tưởng hoặc nguyên tắc nội tâm vững chắc mà một người cho là hoàn toàn đúng và định hướng cuộc sống của họ."},"4714":{"word":"vị chua","meaning":"Một vị sắc, chát trong thức ăn hoặc đồ uống khiến miệng se lại, như vị chanh."},"4715":{"word":"bí ẩn","meaning":"Điều gì đó rất khó hoặc không thể hiểu, giải thích, thường mang vẻ thần diệu."},"4716":{"word":"sản phẩm mới","meaning":"Mặt hàng hoặc sản phẩm vừa mới được tạo ra và bày bán cho người tiêu dùng."},"4717":{"word":"hoàn cảnh","meaning":"Tình trạng tổng thể cuộc sống của một người đang trải qua, đặc biệt là khi nó khó khăn hoặc không may."},"4718":{"word":"thế hệ mới","meaning":"Một nhóm người sinh ra cùng thời điểm, trẻ hơn đáng kể so với các nhóm lớn tuổi và thường có cách suy nghĩ khác."},"4719":{"word":"đức tin","meaning":"Niềm tin và lòng trung thành mạnh mẽ của một người vào một vị thần hoặc một hệ thống thờ cúng."},"4720":{"word":"sản phẩm mới","meaning":"Một mặt hàng sản xuất vừa mới được tạo ra và đưa ra thị trường để mọi người mua."},"4721":{"word":"thận trọng","meaning":"Phẩm chất hành động hoặc lời nói rất cẩn thận và suy nghĩ kỹ lưỡng để tránh các vấn đề hoặc kết quả xấu."},"4722":{"word":"thuộc về thể chất","meaning":"Liên quan đến cơ thể thực tế của một người và các hành động của nó, chứ không phải suy nghĩ hoặc cảm xúc bên trong."},"4723":{"word":"thần thoại","meaning":"Một câu chuyện bí ẩn về một vị thần hoặc nhân vật giống thần."},"4724":{"word":"cảm giác chân thật","meaning":"Ấn tượng mạnh mẽ rằng điều gì đó đang thực sự xảy ra hoặc có thật, như thể không phải là tưởng tượng hay giấc mơ."},"4725":{"word":"ví dụ thực tế","meaning":"Một trường hợp hoặc ví dụ cụ thể được dùng để làm rõ hoặc chứng minh một ý tưởng hoặc tuyên bố chung."},"4726":{"word":"thực tập","meaning":"Thời gian có cấu trúc bên ngoài lớp học, nơi một người thực hiện các nhiệm vụ và tích lũy kinh nghiệm liên quan trực tiếp đến việc học hoặc công việc tương lai của họ."},"4727":{"word":"thực hiện, tiến hành","meaning":"Việc bắt đầu làm hoặc áp dụng một kế hoạch hay quyết định chính thức."},"4728":{"word":"thất nghiệp","meaning":"Tình trạng một người có khả năng và mong muốn làm việc nhưng không tìm được việc làm có lương."},"4729":{"word":"thực tế, thiết thực","meaning":"Diễn tả cái gì đó hữu ích và hiệu quả trong các tình huống thực tế, giúp đạt được mục tiêu một cách trực tiếp."},"4730":{"word":"thực ra, thật sự thì","meaning":"Từ dùng để giới thiệu một điều bất ngờ hoặc khác với những gì đã ngụ ý hoặc được tin trước đó."},"4731":{"word":"trưởng phòng, quản lý phòng","meaning":"Người giữ vị trí cấp cao và giám sát một đội hoặc lĩnh vực công việc cụ thể trong công ty."},"4732":{"word":"thực tế, trên thực tế","meaning":"Điều kiện thật sự hoặc cách một sự vật xuất hiện hay xảy ra, thể hiện nó như tồn tại trong thế giới chứ không phải là một ý tưởng."},"4733":{"word":"thực hành, thực hiện","meaning":"Hành động thực hiện một kế hoạch hoặc lời hứa bằng cách làm những gì đã được quyết định hoặc suy nghĩ."},"4734":{"word":"bản chất, thực thể","meaning":"Hình thái cơ bản hoặc bản chất thật sự của một cái gì đó tồn tại, có thể được khám phá hoặc nhìn thấy."},"4735":{"word":"thí nghiệm, thử nghiệm","meaning":"Hành động thực hiện một việc gì đó trong thực tế theo một lý thuyết hoặc ý tưởng, trước khi bắt tay vào một nhiệm vụ nhất định."},"4736":{"word":"hiện thực hóa, thực hiện","meaning":"Thời điểm một mục tiêu, giấc mơ hoặc kế hoạch trở thành hiện thực hoặc được đạt được một cách rõ ràng."},"4737":{"word":"thuộc về tâm lý, về mặt tâm lý","meaning":"Mô tả điều gì đó liên quan đến cảm xúc, suy nghĩ của một người và cách bộ não của họ hoạt động, hiểu thế giới."},"4738":{"word":"việc vặt, việc được sai bảo","meaning":"Việc làm theo yêu cầu hoặc lệnh của ai đó, thường là những công việc nhỏ."},"4739":{"word":"thẩm định","meaning":"Việc xem xét, đánh giá kỹ lưỡng giấy tờ, ý tưởng hoặc cá nhân để đưa ra quyết định."},"4740":{"word":"tim","meaning":"Bộ phận cơ bắp nằm trong lồng ngực, có nhiệm vụ bơm máu đi khắp cơ thể."},"4741":{"word":"tâm trạng","meaning":"Trạng thái bên trong về suy nghĩ và cảm xúc của một người."},"4742":{"word":"thậm chí","meaning":"Từ dùng để nhấn mạnh một chi tiết hoặc tình huống bổ sung đáng ngạc nhiên hoặc nghiêm trọng hơn những gì đã được đề cập."},"4743":{"word":"trọng tài","meaning":"Người điều khiển trận đấu thể thao, mặc đồng phục và đưa ra các quyết định chính thức."},"4744":{"word":"hoàn toàn phù hợp","meaning":"Miêu tả một việc hay một vật nào đó hoàn toàn phù hợp hoặc rất thích hợp với ai đó."},"4745":{"word":"đồ rẻ tiền","meaning":"Sản phẩm có giá thành thấp và thường có chất lượng kém."},"4746":{"word":"sự đánh nhau","meaning":"Sự việc hai hay nhiều người đánh, xô đẩy hoặc la hét vào nhau một cách giận dữ."},"4747":{"word":"được gói","meaning":"Một vật nào đó được bao phủ hoàn toàn các mặt bằng vật liệu khác như giấy hoặc vải."},"4748":{"word":"giá rẻ","meaning":"Mức giá thấp hơn so với giá thông thường."},"4749":{"word":"không mấy","meaning":"Từ dùng để đi kèm với thể phủ định, nhằm diễn tả hành động hay trạng thái thiếu cường độ hoặc chất lượng cao."},"4750":{"word":"se lạnh","meaning":"Miêu tả một nơi hoặc không khí bên ngoài có nhiệt độ thấp khó chịu, khiến bạn muốn mặc quần áo ấm hơn."},"4751":{"word":"bắn","meaning":"Làm cho một vật bay đi nhanh và mạnh đến một mục tiêu nào đó."},"4752":{"word":"phơi, hóng","meaning":"Để không khí, gió hoặc ánh nắng mặt trời tiếp xúc trực tiếp với da hoặc mặt trong một thời gian ngắn."},"4753":{"word":"nhức nhối, đau nhức","meaning":"Cảm thấy khó chịu, đau âm ỉ hoặc đau nhói liên tục ở một bộ phận nào đó trên cơ thể."},"4754":{"word":"ngại ngùng, bẽn lẽn","meaning":"Cảm thấy không thoải mái, lúng túng khi bị người khác nhìn hoặc khen ngợi."},"4755":{"word":"vuốt ve, xoa","meaning":"Di chuyển bàn tay mở một cách nhẹ nhàng, lặp đi lặp lại và mềm mại trên đầu người, lông động vật hoặc một bề mặt nhẵn."},"4756":{"word":"đổ, ngã, ngã xuống","meaning":"Người, động vật hoặc vật thể đột ngột mất thăng bằng hoặc ổn định rồi rơi xuống đất."},"4757":{"word":"vị đắng","meaning":"Hương vị mạnh, thường sắc và khó chịu, như cà phê đen hoặc một số loại rau, khiến người ta nhăn mặt."},"4758":{"word":"vô ích, không cần thiết","meaning":"Mô tả một vật hoặc hành động không có mục đích rõ ràng, không hiệu quả hoặc không mang lại lợi ích gì."},"4759":{"word":"một cách vô ích, không cần thiết","meaning":"Mô tả hành động được thực hiện mà không mang lại kết quả hữu ích hoặc lợi thế rõ ràng."},"4760":{"word":"cô đơn, hiu quạnh","meaning":"Diễn tả một người trông buồn bã vì ở một mình, hoặc một nơi trông trống vắng và yên tĩnh không có người."},"4761":{"word":"đội, phủ, đậy","meaning":"Đặt một vật lên trên vật khác để bảo vệ hoặc che giấu, như đậy nắp nồi hoặc đội mũ lên đầu."},"4762":{"word":"đấu vật truyền thống Hàn Quốc, ssireum","meaning":"Một môn thể thao đấu vật truyền thống của Hàn Quốc, nơi hai người đàn ông nắm lấy khăn quấn quanh eo và chân, cố gắng vật ngã đối phương xuống đất."},"4763":{"word":"hạt giống","meaning":"Phần nhỏ cứng của cây, có thể trồng xuống đất để mọc thành cây mới."},"4764":{"word":"dũng cảm, mạnh mẽ","meaning":"Có nhiều sự dũng cảm và quyết tâm, hành động kiên quyết ngay cả trong tình huống khó khăn."},"4765":{"word":"được rửa sạch","meaning":"Bụi bẩn hoặc vết bẩn biến mất khỏi bề mặt khi nước hoặc chất lỏng khác chảy qua, làm cho nó sạch sẽ."},"4766":{"word":"tắm rửa cho","meaning":"Một người dùng nước hoặc chất lỏng khác để loại bỏ bụi bẩn và vết bẩn khỏi người hoặc vật khác, làm cho họ sạch sẽ."},"4767":{"word":"đáng tiếc, phí hoài","meaning":"Cảm thấy tiếc nuối hoặc thất vọng khi một thứ có giá trị bị mất, lãng phí hoặc không thể sử dụng được."},"4768":{"word":"trẻ em","meaning":"Người ở độ tuổi còn nhỏ."},"4769":{"word":"quý tử","meaning":"Một từ trang trọng dùng để gọi con trai của người khác."},"4770":{"word":"có lẽ, có thể là","meaning":"Được dùng để chỉ ra rằng một điều gì đó rất có khả năng xảy ra hoặc đúng, nhưng không hoàn toàn chắc chắn."},"4771":{"word":"người nào đó, ông/bà X","meaning":"Một từ dùng để chỉ một người không xác định hoặc không rõ tên."},"4772":{"word":"dù sao đi nữa","meaning":"Dùng để diễn tả một cảm giác hoặc suy nghĩ vẫn tồn tại hoặc dường như là đúng, bất kể các cân nhắc hoặc khả năng khác."},"4773":{"word":"không một","meaning":"Được dùng trước một cấu trúc phủ định để nhấn mạnh sự vắng mặt hoàn toàn của một điều gì đó."},"4774":{"word":"không rõ ràng","meaning":"Diễn tả một trạng thái hoặc điều kiện không được định rõ."},"4775":{"word":"dù sao đi nữa","meaning":"Từ dùng để tiếp tục câu chuyện hoặc quay lại vấn đề chính, không quan tâm đến những gì đã nói."},"4776":{"word":"sự tiếc nuối","meaning":"Cảm giác buồn hoặc thất vọng vì điều mình mong muốn không thành hiện thực, hoặc muốn mọi thứ khác đi."},"4777":{"word":"hoàn toàn, ngay từ đầu","meaning":"Từ dùng để nhấn mạnh rằng một điều gì đó hoàn toàn không xảy ra, hoặc được thực hiện trọn vẹn ngay từ đầu."},"4778":{"word":"đồng thời, cùng với","meaning":"Từ dùng để diễn tả việc một điều gì đó xảy ra hoặc được thêm vào cùng lúc với điều khác."},"4779":{"word":"À há, À ra thế","meaning":"Thán từ thể hiện sự đột nhiên hiểu ra điều gì đó, tìm được câu trả lời hoặc nhận ra ai đó/cái gì đó."},"4780":{"word":"ác mộng","meaning":"Một giấc mơ đáng sợ hoặc khó chịu."},"4781":{"word":"mùi hôi, mùi thối","meaning":"Một mùi rất nồng và cực kỳ khó chịu."},"4782":{"word":"sự trầm trọng hơn, sự xấu đi","meaning":"Tình huống hoặc vấn đề trở nên nghiêm trọng, tồi tệ hoặc khó khăn hơn so với trước."},"4783":{"word":"được ôm, được bế","meaning":"Được ai đó bế, ôm vào lòng hoặc giữ chặt sát vào người."},"4784":{"word":"mang lại, đem lại","meaning":"Đem lại thành công, kết quả tốt đẹp hoặc lợi ích cho ai đó/tổ chức nào đó."},"4785":{"word":"quầy thông tin, văn phòng thông tin","meaning":"Nơi cung cấp thông tin, bản đồ hoặc hướng dẫn cho du khách, thường ở các địa điểm công cộng."},"4786":{"word":"đáng tiếc, không được như ý","meaning":"Diễn tả một sự việc hoặc tình huống không đạt được kết quả mong muốn, gây khó khăn hoặc đáng tiếc."},"4787":{"word":"đồ nhắm, mồi nhậu","meaning":"Món ăn kèm khi uống rượu, bia."},"4788":{"word":"lấy làm tiếc, thương xót","meaning":"Thể hiện sự buồn bã, tiếc nuối khi chứng kiến điều không may hoặc cơ hội bị bỏ lỡ của người khác."},"4789":{"word":"đáng tiếc, đáng thương","meaning":"Diễn tả tình huống hay cảnh tượng gây ra sự buồn bã hoặc tiếc nuối vì một điều không tốt đã xảy ra hoặc không thể thay đổi được."},"4790":{"word":"trong ngoài, nội ngoại","meaning":"Cả bên trong và bên ngoài của một nơi hoặc một phạm vi nào đó."},"4791":{"word":"cho ngồi, đặt ngồi","meaning":"Bảo hoặc giúp ai đó ngồi xuống ghế, băng ghế hoặc mặt đất."},"4792":{"word":"đoán đúng, đoán trúng","meaning":"Biết được đáp án chính xác hoặc dự đoán đúng."},"4793":{"word":"hiểu và công nhận, thấu hiểu","meaning":"Bày tỏ sự thấu hiểu và trân trọng cảm xúc, nỗ lực hoặc tình huống của người khác qua lời nói hoặc hành động."},"4794":{"word":"chất lượng, bổ ích, phong phú","meaning":"Mô tả nội dung hoặc hoạt động có chất lượng tốt, chi tiết quan trọng hoặc thành phần giá trị."},"4795":{"word":"mắc bệnh, chịu đựng","meaning":"Trải qua các triệu chứng và tác động khó chịu của một bệnh tật trong cơ thể."},"4796":{"word":"ghi nhớ, học thuộc lòng","meaning":"Hành động học và lưu giữ sự kiện, từ ngữ hoặc chi tiết trong đầu để có thể nhớ lại chính xác khi cần."},"4797":{"word":"áp lực, sức ép","meaning":"Lực vật lý liên tục tác dụng lên một bề mặt, hoặc sức ép mạnh mẽ để tác động đến quyết định của ai đó."},"4798":{"word":"con đường phía trước, tiền đồ","meaning":"Con đường hoặc hành trình trải dài phía trước một người, tượng trưng cho tương lai."},"4799":{"word":"sắp sửa, gần kề","meaning":"Có một sự kiện hay một ngày quan trọng nào đó sắp đến."},"4800":{"word":"vùng biển ven bờ","meaning":"Khu vực biển có thể nhìn thấy từ bờ."},"4801":{"word":"trước, trước đó","meaning":"Diễn ra hoặc được thực hiện vào thời điểm trước một sự kiện hoặc thời điểm cụ thể."},"4802":{"word":"đi trước, dẫn trước","meaning":"Di chuyển hoặc ở vị trí phía trước người hoặc vật khác, hoặc tiến bộ hơn người khác."},"4803":{"word":"đặt lên trước, ưu tiên","meaning":"Sắp xếp cho một người hoặc vật dẫn đầu một nhóm, hoặc coi trọng điều gì đó hơn những điều khác."},"4804":{"word":"đi đầu, dẫn đầu","meaning":"Là người đi trước trong một nhóm, hoặc là người đầu tiên bắt đầu một hành động hoặc phong trào."},"4805":{"word":"nỗi lòng, sự lo lắng","meaning":"Cảm giác lo lắng, bồn chồn, nóng ruột về một điều gì đó."},"4806":{"word":"cố gắng, nỗ lực","meaning":"Cố gắng hết sức và bền bỉ để hoàn thành điều gì đó."},"4807":{"word":"tình yêu, tình cảm","meaning":"Một tấm lòng yêu thương mà một người dành cho ai đó hoặc điều gì đó."},"4808":{"word":"số tiền, khoản tiền","meaning":"Một số lượng hoặc tổng số tiền cụ thể."},"4809":{"word":"ban đêm, buổi tối","meaning":"Khoảng thời gian từ lúc mặt trời lặn đến lúc mặt trời mọc khi không nhìn thấy mặt trời và trời tối."},"4810":{"word":"la mắng, khiển trách","meaning":"Lời khiển trách giận dữ hoặc sự thể hiện rõ ràng sự không hài lòng hoặc lo ngại."},"4811":{"word":"meo meo","meaning":"Đây là tiếng kêu đặc trưng của loài mèo."},"4812":{"word":"hở hang","meaning":"Từ dùng để tả trang phục quá lộ liễu, gây cảm giác không đứng đắn hoặc gợi tình."},"4813":{"word":"điểm yếu","meaning":"Một khuyết điểm hoặc sự dễ bị tổn thương cụ thể của một người hoặc sự vật."},"4814":{"word":"đính hôn","meaning":"Lời hứa chính thức giữa hai người rằng họ sẽ kết hôn với nhau."},"4815":{"word":"vợ chưa cưới","meaning":"Người phụ nữ đã đồng ý kết hôn với một người đàn ông cụ thể trong tương lai."},"4816":{"word":"chồng chưa cưới","meaning":"Người đàn ông đã đồng ý kết hôn với một người phụ nữ cụ thể trong tương lai."},"4817":{"word":"sự đoan trang","meaning":"Cách cư xử thể hiện sự bình tĩnh, khiêm tốn, thường không ồn ào hay thu hút sự chú ý."},"4818":{"word":"hai nước","meaning":"Từ dùng để chỉ hai quốc gia cụ thể khi chúng được xem xét hoặc nhắc đến cùng nhau."},"4819":{"word":"lương tâm","meaning":"Cảm giác bên trong giúp một người quyết định giữa hành động tốt và xấu, và khiến họ cảm thấy tồi tệ nếu làm điều sai trái."},"4820":{"word":"nông","meaning":"Từ dùng để tả không gian, như nước trong hồ hoặc đĩa, có khoảng cách từ bề mặt trên cùng đến đáy là ngắn."},"4821":{"word":"trật khớp","meaning":"Xảy ra khi hai vật lẽ ra phải khớp hoàn hảo bị đẩy ra hoặc dịch chuyển khỏi vị trí ban đầu, không còn kết nối đúng cách."},"4822":{"word":"lúc nào không hay","meaning":"Diễn tả một sự kiện hoặc sự trôi qua của thời gian diễn ra quá suôn sẻ hoặc nhanh chóng đến nỗi một người chỉ nhận ra điều đó sau khi nó đã xảy ra."},"4823":{"word":"bóng tối","meaning":"Tình trạng không có ánh sáng, khiến khó hoặc không thể nhìn thấy đồ vật xung quanh."},"4824":{"word":"ngại","meaning":"Cảm thấy không chắc chắn hoặc lo lắng khi phải đối phó với một người nào đó hoặc hoàn thành một công việc nào đó."},"4825":{"word":"thân phụ","meaning":"(Cách gọi kính trọng) Cha của người khác."},"4826":{"word":"ngu ngốc","meaning":"Hành động hoặc nói năng thiếu suy xét, thiếu khôn ngoan, thường khiến người khác thấy vô lý."},"4827":{"word":"trẻ con","meaning":"Từ viết tắt để chỉ một bé trai hoặc bé gái còn nhỏ tuổi."},"4828":{"word":"khó xử","meaning":"Diễn tả tình huống hoặc tương tác cảm thấy không thoải mái, gượng ép, nơi mọi người có thể hành động ngập ngừng hoặc khó giao tiếp suôn sẻ."},"4829":{"word":"dù sao đi nữa","meaning":"Từ dùng để chỉ ra rằng điều vừa nói không quan trọng bằng điều sắp nói, hoặc để quay lại chủ đề trước đó."},"4830":{"word":"thỉnh thoảng","meaning":"Mô tả một sự việc xảy ra không thường xuyên, hoặc không có kế hoạch rõ ràng, như thể nó ngẫu nhiên xảy ra."},"4831":{"word":"có lẽ","meaning":"Người nói cân nhắc các kết quả hoặc hành động khác nhau, thể hiện sự không chắc chắn về những gì sẽ xảy ra."},"4832":{"word":"không hiểu sao","meaning":"Một sự việc xảy ra hoặc một hành động được thực hiện theo cách không thể hiểu rõ hoặc giải thích được."},"4833":{"word":"thật là","meaning":"Dùng để chỉ ra rằng điều gì đó đúng ở một mức độ hoặc mức độ rất lớn, làm cho hành động hoặc trạng thái trở nên mạnh mẽ hơn nhiều."},"4834":{"word":"làm thế nào","meaning":"Thực hiện một hành động hoặc đối phó với một tình huống khi phương pháp giải quyết không rõ ràng ngay lập tức hoặc đặt ra thách thức."},"4835":{"word":"đằng nào thì","meaning":"Dùng để nhấn mạnh rằng một kết quả hoặc tình huống nào đó là không thể tránh khỏi, khiến mọi nỗ lực khác trở nên vô ích."},"4836":{"word":"ngữ điệu","meaning":"Đặc điểm riêng về cách phát âm, nhịp điệu và cao độ khi một người nói một ngôn ngữ, thường thể hiện nguồn gốc hoặc vùng miền của họ."},"4837":{"word":"oan ức","meaning":"Cảm thấy rất đau khổ hoặc căm phẫn vì bị đổ lỗi, trừng phạt hoặc phải chịu đựng một sự việc không công bằng, không đáng phải nhận."},"4838":{"word":"một cách gượng ép","meaning":"Thực hiện một hành động dưới áp lực bên ngoài hoặc mặc dù không muốn, làm cho hành động đó trông không tự nhiên hoặc gượng gạo."},"4839":{"word":"sự đề cập","meaning":"Hành động nói hoặc chỉ ra một cách vắn tắt về một người hay một điều gì đó trong cuộc trò chuyện hoặc văn bản."},"4840":{"word":"truyền thông","meaning":"Hệ thống bao gồm các tổ chức và phương tiện như báo, truyền hình, phát thanh, có nhiệm vụ cung cấp thông tin và tin tức cho đông đảo mọi người."},"4841":{"word":"một ngày nào đó","meaning":"Vào một thời điểm không xác định trong tương lai, khi một sự kiện hoặc hành động sẽ xảy ra mà không có ngày hoặc lịch trình cụ thể."},"4842":{"word":"đặt lên","meaning":"Đặt một thứ gì đó lên trên một thứ khác."},"4843":{"word":"được đãi ăn","meaning":"Ăn hoặc uống thức ăn, đồ uống mà người khác đã mời và trả tiền, không phải tự mình mua."},"4844":{"word":"làm đóng băng","meaning":"Biến một chất lỏng thành thể rắn, thường là bằng cách làm lạnh nó ở nhiệt độ rất thấp, ví dụ như làm nước thành đá."},"4845":{"word":"sự nghiêm khắc","meaning":"Tính chất rất cứng rắn và đòi hỏi cao trong quy tắc hoặc cách hành xử, không cho phép có sự sai lệch hay nới lỏng."},"4846":{"word":"trang nghiêm","meaning":"Thể hiện thái độ rất nghiêm túc và có phẩm giá, thường đi kèm với sự im lặng và cảm giác trang nghiêm, như trong một buổi lễ quan trọng."},"4847":{"word":"khổng lồ, to lớn","meaning":"Diễn tả mức độ, số lượng hay kích thước của một sự vật, sự việc nào đó rất lớn, vượt quá mức bình thường."},"4848":{"word":"ngành, giới (kinh doanh)","meaning":"Lĩnh vực hoạt động mà nhiều người cùng tham gia trong một ngành công nghiệp hoặc thương mại nhất định."},"4849":{"word":"thành tựu, công lao","meaning":"Kết quả đáng kể đạt được nhờ sự nỗ lực và cố gắng trong công việc, nghiên cứu hay các lĩnh vực khác."},"4850":{"word":"công ty, doanh nghiệp","meaning":"Tổ chức sản xuất hàng hóa hoặc cung cấp dịch vụ cho người tiêu dùng."},"4851":{"word":"kỳ lạ, quái gở","meaning":"Diễn tả một sự vật, hành vi hay suy nghĩ khác biệt rất nhiều so với những gì bình thường hoặc mong đợi."},"4852":{"word":"lộn xộn, bừa bãi","meaning":"Trạng thái mọi thứ bị xáo trộn, hư hỏng hoặc hoàn toàn vô tổ chức, trông rất tồi tệ."},"4853":{"word":"vớ vẩn, nhảm nhí, giả dối","meaning":"Thông tin, vật thể hoặc lời nói không có thật, được làm kém chất lượng hoặc không có ý nghĩa hợp lý."},"4854":{"word":"nằm sấp, úp mặt","meaning":"Đặt cơ thể sao cho phần bụng hoặc ngực úp xuống một bề mặt, thường là đầu quay sang một bên."},"4855":{"word":"năng lượng","meaning":"Sức mạnh hoặc phẩm chất giúp người hay vật có thể di chuyển, hoạt động, hoặc tạo ra nhiệt và ánh sáng."},"4856":{"word":"không phải bình thường, không hề","meaning":"Từ dùng để nhấn mạnh mức độ cực kỳ của một sự việc hoặc cảm xúc, thường đi kèm với hình thức phủ định."},"4857":{"word":"điều kiện, hoàn cảnh","meaning":"Những yếu tố cụ thể tồn tại xung quanh một người hoặc sự kiện tại một thời điểm nhất định, có thể ảnh hưởng đến kết quả."},"4858":{"word":"trường cấp ba nữ sinh","meaning":"Ngôi trường dành riêng cho nữ sinh trung học học tập trước khi vào đại học."},"4859":{"word":"nhiều","meaning":"Từ để chỉ một nhóm người hoặc vật có số lượng lớn, không ít."},"4860":{"word":"có hay không","meaning":"Từ dùng để chỉ sự lựa chọn giữa hai khả năng đối lập, thường là có hoặc không."},"4861":{"word":"vẫn","meaning":"Từ chỉ trạng thái, tình huống không thay đổi so với trước đây."},"4862":{"word":"người du lịch","meaning":"Người thường xuyên đi đến nhiều nơi khác nhau, khám phá hoặc để giải trí."},"4863":{"word":"trong lịch sử","meaning":"Chỉ khoảng thời gian hoặc một sự kiện cụ thể đã xảy ra trong toàn bộ quá trình lịch sử được ghi chép lại."},"4864":{"word":"dệt","meaning":"Dùng sợi hoặc vật liệu tương tự để tạo ra vải hoặc cấu trúc bằng cách đan xen chúng vào nhau."},"4865":{"word":"hàng năm","meaning":"Thuộc về hoặc xảy ra mỗi năm một lần, hoặc được tính trong một năm."},"4866":{"word":"mối liên hệ","meaning":"Sự gắn kết hoặc ảnh hưởng lẫn nhau giữa hai hay nhiều sự vật, sự việc."},"4867":{"word":"viện nghiên cứu","meaning":"Một tổ chức hoặc tòa nhà chuyên biệt nơi các nhà khoa học và học giả tiến hành điều tra sâu rộng về các chủ đề cụ thể."},"4868":{"word":"phòng nghiên cứu","meaning":"Một căn phòng hoặc tòa nhà được trang bị để tiến hành các thí nghiệm khoa học, điều tra hoặc nghiên cứu học thuật."},"4869":{"word":"nhà nghiên cứu","meaning":"Người có công việc là tìm hiểu sâu một chủ đề cụ thể để khám phá ra sự thật hoặc ý tưởng mới."},"4870":{"word":"viện nghiên cứu","meaning":"Một tổ chức hoặc cơ sở chuyên biệt nơi các nhà khoa học và học giả tiến hành các cuộc điều tra chi tiết về nhiều chủ đề."},"4871":{"word":"nhà nghiên cứu","meaning":"Người tìm hiểu, nghiên cứu một vấn đề nào đó để khám phá thông tin mới hoặc phát triển các lý thuyết mới."},"4872":{"word":"khói","meaning":"Hơi hoặc vật chất bay lên từ lửa hoặc vật cháy, thường có màu xám hoặc trắng."},"4873":{"word":"diễn viên","meaning":"Người đóng vai nhân vật trong phim, kịch hoặc chương trình truyền hình để biểu diễn trước khán giả."},"4874":{"word":"năm","meaning":"Khoảng thời gian 365 ngày, tương ứng với một chu kỳ quay của Trái Đất quanh Mặt Trời."},"4875":{"word":"độ tuổi","meaning":"Tổng số năm hoặc thời gian mà một người hoặc vật thể đã tồn tại kể từ khi ra đời hoặc được tạo ra."},"4876":{"word":"ao","meaning":"Một vùng nước nhỏ, tĩnh lặng, tự nhiên hoặc nhân tạo, thường nông hơn hồ."},"4877":{"word":"lương năm","meaning":"Tổng số tiền một người nhận được cho công việc của mình trong vòng 12 tháng."},"4878":{"word":"bài phát biểu","meaning":"Một bài trình bày chính thức được nói trước công chúng về một chủ đề cụ thể."},"4879":{"word":"liên tục","meaning":"Trạng thái của một việc xảy ra hoặc tồn tại không ngừng, không gián đoạn, nối tiếp nhau."},"4880":{"word":"yêu đương","meaning":"Mối quan hệ thân mật, tình cảm giữa hai người thông qua việc hẹn hò và dành thời gian cho nhau."},"4881":{"word":"quá hạn","meaning":"Tình trạng một khoản thanh toán hoặc vật phẩm không được trả lại hoặc thanh toán đúng thời hạn đã định."},"4882":{"word":"phí trễ hạn","meaning":"Khoản tiền bổ sung mà bạn phải trả vì không trả lại vật phẩm hoặc không thanh toán đúng hạn."},"4883":{"word":"đạo diễn","meaning":"Là công việc lập kế hoạch và giám sát toàn bộ quá trình thực hiện một bộ phim hay vở kịch."},"4884":{"word":"than tổ ong","meaning":"Một loại than đá ép thành khối hình trụ có lỗ, dùng để đốt làm nhiên liệu sưởi ấm hoặc nấu ăn."},"4885":{"word":"liên hiệp, liên minh","meaning":"Sự kết hợp của nhiều quốc gia, tổ chức hoặc cá nhân lại với nhau vì một mục đích chung."},"4886":{"word":"không khí sôi nổi","meaning":"Bầu không khí hứng khởi, náo nhiệt, tràn đầy năng lượng khi nhiều người cùng tập trung vào một việc gì đó."},"4887":{"word":"quả, trái cây","meaning":"Bộ phận của cây có chứa hạt, thường có vị ngọt và được dùng làm thức ăn, như táo, lê."},"4888":{"word":"nhiệt huyết, đam mê","meaning":"Một động lực mạnh mẽ khiến một người dồn nhiều năng lượng và sự tập trung vào một hoạt động."},"4889":{"word":"sự say mê, sự chuyên tâm","meaning":"Trạng thái tập trung toàn bộ sự chú ý vào một hoạt động nào đó, khiến bạn không để ý đến mọi thứ xung quanh."},"4890":{"word":"nhuộm","meaning":"Quá trình thay đổi màu sắc vĩnh viễn của tóc, vải hoặc các vật liệu khác bằng cách sử dụng chất lỏng đặc biệt."},"4891":{"word":"nhìn trộm, rình xem","meaning":"Nhìn một cách lén lút để người khác không biết hoặc không phát hiện ra."},"4892":{"word":"kinh doanh","meaning":"Hoạt động thường xuyên của một công ty hoặc cửa hàng cung cấp hàng hóa hoặc dịch vụ cho khách hàng và thu tiền."},"4893":{"word":"lĩnh vực, phạm vi","meaning":"Một phần cụ thể của không gian lớn hơn, một chủ đề hoặc một hoạt động có thể được xác định rõ ràng."},"4894":{"word":"vĩnh cửu, mãi mãi","meaning":"Khoảng thời gian tiếp tục tồn tại vô hạn trong tương lai, không bao giờ dừng lại hoặc kết thúc."},"4895":{"word":"ảnh hưởng","meaning":"Khả năng tác động và làm thay đổi suy nghĩ, hành vi của người khác."},"4896":{"word":"linh hồn","meaning":"Phần phi vật chất của một người đã chết, được cho là có thể tồn tại độc lập."},"4897":{"word":"đạo diễn phim","meaning":"Người chỉ đạo chính trong quá trình sản xuất phim, chịu trách nhiệm về các quyết định sáng tạo."},"4898":{"word":"thời xưa","meaning":"Khoảng thời gian rất lâu về trước trong quá khứ."},"4899":{"word":"linh cảm","meaning":"Cảm giác hoặc dự đoán mơ hồ về một điều gì đó sắp xảy ra."},"4900":{"word":"thông báo trước","meaning":"Sự thông tin cho ai đó biết về một sự việc sẽ xảy ra trong tương lai."},"4901":{"word":"dự trữ","meaning":"Số lượng vật chất được giữ lại để dùng khi cần thiết hoặc cho tương lai."},"4902":{"word":"ngân sách","meaning":"Kế hoạch chi tiết về tổng số tiền có được và cách thức chi tiêu trong một khoảng thời gian nhất định."},"4903":{"word":"vòng loại","meaning":"Vòng thi đấu ban đầu để chọn ra những người tham gia vào các vòng chính thức của một cuộc thi."},"4904":{"word":"nghệ sĩ","meaning":"Người sáng tạo hoặc biểu diễn các tác phẩm nghệ thuật như hội họa, điêu khắc, âm nhạc."},"4905":{"word":"có tính nghệ thuật","meaning":"Miêu tả một cái gì đó thể hiện kỹ năng, trí tưởng tượng và vẻ đẹp xuất sắc."},"4906":{"word":"ngoại lệ","meaning":"Một trường hợp hoặc sự việc cụ thể khác biệt so với quy tắc chung hoặc mô hình thông thường."},"4907":{"word":"đi đi lại lại","meaning":"Di chuyển nhiều lần giữa hai nơi hoặc hai người, theo cả hai hướng."},"4908":{"word":"ngày nay","meaning":"Khoảng thời gian đang diễn ra ngay bây giờ, bao gồm ngày hiện tại và quá khứ gần đây."},"4909":{"word":"giải trí","meaning":"Những hoạt động như xem phim, chơi game hay nghe nhạc mà mọi người làm để vui vẻ và giết thời gian."},"4910":{"word":"lâu dài","meaning":"Chỉ một hành động hoặc trạng thái tiếp diễn hoặc kéo dài trong một khoảng thời gian rất đáng kể."},"4911":{"word":"hoàn toàn","meaning":"Làm điều gì đó một cách trọn vẹn bởi một người hoặc một vật, hoặc tập trung hoàn toàn vào một mục đích mà không có bất kỳ thứ nào khác."},"4912":{"word":"lên xuống","meaning":"Di chuyển lặp đi lặp lại từ vị trí thấp lên vị trí cao hơn, rồi lại xuống."},"4913":{"word":"chân phải","meaning":"Bộ phận dưới cùng của chi người chạm đất, nằm ở phía bên phải cơ thể."},"4914":{"word":"ô nhiễm","meaning":"Tình trạng không khí, nước hoặc đất bị lấp đầy các chất độc hại, khiến chúng không an toàn cho sinh vật sống."},"4915":{"word":"chỉ","meaning":"Không có bất kỳ ai hoặc bất kỳ thứ gì khác ngoài cái đó được bao gồm."},"4916":{"word":"ngược lại","meaning":"Dùng để chỉ rằng điều gì đó xảy ra theo cách khác hoặc đối lập với những gì đã nghĩ hoặc mong muốn."},"4917":{"word":"bắp","meaning":"Hạt của cây bắp, có thân cao với lá dài và râu, dùng làm thực phẩm."},"4918":{"word":"đủ loại","meaning":"Mô tả một nhóm lớn các mục khác biệt đáng kể với nhau."},"4919":{"word":"trực tuyến","meaning":"Là trạng thái kết nối máy tính qua mạng internet để truy cập hoặc trao đổi thông tin."},"4920":{"word":"suốt cả ngày","meaning":"Suốt cả một ngày dài, từ lúc mặt trời mọc đến lúc mặt trời lặn mà không ngưng nghỉ."},"4921":{"word":"toàn bộ","meaning":"Chỉ trạng thái mọi phần của một cái gì đó đều được lấp đầy hoặc bao phủ hoàn toàn bởi một thứ cụ thể."},"4922":{"word":"leo lên","meaning":"Hành động di chuyển cơ thể lên cao và vào hoặc trên một phương tiện hay con vật, thường để bắt đầu một chuyến đi."},"4923":{"word":"nhìn lên","meaning":"Hành động ngả đầu ra sau và hướng mắt về phía một vật ở trên cao."},"4924":{"word":"sự hoàn hảo","meaning":"Trạng thái mà một thứ gì đó xuất sắc đến mức không có khuyết điểm, lỗi lầm hoặc khả năng cải thiện nào."},"4925":{"word":"sự đầy đủ","meaning":"Trạng thái mà một vật thể hoặc nhiệm vụ có mọi phần hoặc thành phần cần thiết, không thiếu sót gì."},"4926":{"word":"không hiểu sao","meaning":"Diễn tả khi bạn cảm thấy hoặc hành xử theo một cách nào đó mà không thể xác định rõ nguyên nhân."},"4927":{"word":"nhà ông bà ngoại","meaning":"Ngôi nhà nơi ông bà ngoại (bố mẹ của mẹ mình) sinh sống."},"4928":{"word":"sự cô đơn","meaning":"Cảm giác lẻ loi khi ở một mình trên thế giới này."},"4929":{"word":"bề ngoài","meaning":"Phần nhìn thấy được bên ngoài của một người hoặc một vật thể mà người khác có thể thấy."},"4930":{"word":"con trai duy nhất","meaning":"Đứa trẻ trai duy nhất được sinh ra bởi bố mẹ, không có anh chị em nào."},"4931":{"word":"trang phục ra ngoài","meaning":"Trang phục dùng để mặc khi đi ra ngoài làm việc, giải trí hoặc gặp gỡ người khác, khác với quần áo mặc ở nhà."},"4932":{"word":"hét lên","meaning":"Tạo ra âm thanh rất lớn bằng giọng nói để thể hiện cảm xúc mạnh hoặc thu hút sự chú ý."},"4933":{"word":"bên trái","meaning":"Phía hoặc hướng nằm ở bên tay trái của một người hoặc vật."},"4934":{"word":"này","meaning":"Một từ chỉ định đứng trước danh từ, dùng để chỉ một vật hoặc người cụ thể ở gần, thường kèm theo cảm giác hơi khó chịu hoặc yêu mến."},"4935":{"word":"yêu cầu","meaning":"Hành động nói rõ ràng bạn muốn điều gì đó được trao cho hoặc được thực hiện."},"4936":{"word":"dạo này","meaning":"Một khoảng thời gian ngắn từ trước đến nay, mang ý nghĩa 'những ngày này' hoặc 'gần đây'."},"4937":{"word":"yếu tố","meaning":"Một thành phần hoặc đặc tính riêng biệt kết hợp với những thứ khác để tạo thành một tổng thể, hệ thống hoặc điều kiện lớn hơn."},"4938":{"word":"bản tóm tắt","meaning":"Phiên bản rút gọn của một văn bản hoặc bài nói dài hơn, chỉ chứa những thông tin quan trọng nhất hoặc ý chính."},"4939":{"word":"yếu tố","meaning":"Thứ trực tiếp góp phần tạo ra một kết quả, điều kiện hoặc sự kiện cụ thể."},"4940":{"word":"gần đây","meaning":"Khoảng thời gian hiện tại bao gồm những gì vừa xảy ra và đang diễn ra lúc này."},"4941":{"word":"thỉnh cầu","meaning":"Một sự giao tiếp chính thức hoặc lịch sự với người khác hoặc nhóm người để yêu cầu điều gì đó được cung cấp hoặc hoàn thành."},"4942":{"word":"lời chửi rủa","meaning":"Những lời lẽ xúc phạm hoặc thiếu tôn trọng, dùng để thể hiện sự tức giận hoặc làm người khác cảm thấy tồi tệ."},"4943":{"word":"Khát vọng","meaning":"Cảm giác muốn có được hoặc đạt được điều gì đó một cách mạnh mẽ."},"4944":{"word":"Lòng tham","meaning":"Mong muốn có được quá nhiều tiền bạc, quyền lực hoặc những thứ khác so với nhu cầu thực sự."},"4945":{"word":"Dũng cảm","meaning":"Có tinh thần mạnh mẽ, không sợ hãi khi đối mặt với nguy hiểm hoặc tình huống đáng sợ."},"4946":{"word":"Việc cần giải quyết","meaning":"Chủ đề hoặc nhiệm vụ cụ thể cần được thảo luận hoặc giải quyết trong một cuộc trò chuyện hay cuộc họp."},"4947":{"word":"Mục đích sử dụng","meaning":"Hoạt động hoặc nhiệm vụ cụ thể mà một vật dụng được thiết kế để làm, hoặc lý do thực hiện một hành động."},"4948":{"word":"Sự tha thứ","meaning":"Hành động chọn không còn tức giận hay oán giận ai đó vì họ đã gây hại hoặc mắc lỗi."},"4949":{"word":"Thuật ngữ","meaning":"Tập hợp các từ hoặc cụm từ chuyên biệt mà một nhóm người (ví dụ: bác sĩ, luật sư) sử dụng để nói về công việc của họ."},"4950":{"word":"Khăng khăng","meaning":"Liên tục khẳng định ý kiến hoặc yêu cầu điều gì đó, ngay cả khi người khác không đồng ý."},"4951":{"word":"Mối lo ngại","meaning":"Cảm giác không yên lòng về điều gì đó xấu có thể xảy ra, khiến ai đó băn khoăn hoặc đau khổ."},"4952":{"word":"Buồn cười","meaning":"Điều gì đó khiến người khác bật cười hoặc trông ngớ ngẩn và phi lý."},"4953":{"word":"Sự vô địch","meaning":"Tình trạng trở thành đội hoặc người giỏi nhất khi kết thúc một cuộc thi, thường đi kèm với giải thưởng hoặc cúp."},"4954":{"word":"Thanh lịch","meaning":"Di chuyển hoặc xuất hiện một cách mượt mà, tinh tế và đẹp mắt."},"4955":{"word":"Ngẫu nhiên","meaning":"Sự việc xảy ra bất ngờ, không có kế hoạch hay chủ ý từ trước."},"4956":{"word":"Vận chuyển","meaning":"Hành động di chuyển đồ vật hoặc người từ nơi này đến nơi khác, thường bằng tay hoặc phương tiện."},"4957":{"word":"Vận hành, điều hành","meaning":"Hoạt động có tổ chức nhằm kiểm soát và điều hành cách một doanh nghiệp hoặc tổ chức hoạt động."},"4958":{"word":"Tài xế, lái xe","meaning":"Người điều khiển và lái một phương tiện giao thông như ô tô, xe buýt hoặc xe tải trên đường."},"4959":{"word":"Vận hành (phương tiện)","meaning":"Hoạt động di chuyển của các phương tiện như tàu hỏa, xe buýt trên tuyến đường đã định, chở hành khách hoặc hàng hóa."},"4960":{"word":"Tiếng khóc","meaning":"Âm thanh được tạo ra khi người hoặc động vật buồn, khó chịu hoặc đau đớn, thường kèm theo nước mắt."},"4961":{"word":"Sự chuyển động, cử động","meaning":"Hành động thay đổi vị trí hoặc tư thế, như một bộ phận cơ thể thay đổi góc độ hoặc một vật thể di chuyển trên bề mặt."},"4962":{"word":"Chọc cười, làm buồn cười","meaning":"Khiến một người cười thành tiếng, thường vì điều gì đó hài hước hoặc gây thích thú."},"4963":{"word":"Tiếng cười","meaning":"Âm thanh được tạo ra khi một người cười thành tiếng, thường là khi vui vẻ hoặc thích thú."},"4964":{"word":"Vốn dĩ, vốn là, quá","meaning":"Từ dùng để chỉ mức độ của một sự vật, sự việc vượt xa mức thông thường hoặc điển hình."},"4965":{"word":"-viên","meaning":"Một phần từ thêm vào cuối từ khác để chỉ người là thành viên của một tổ chức cụ thể hoặc thực hiện một công việc nhất định."},"4966":{"word":"Hình tròn, vòng tròn","meaning":"Một hình dạng phẳng bao gồm tất cả các điểm cách đều một điểm trung tâm."},"4967":{"word":"nguyên lý","meaning":"Sự thật cơ bản hoặc quy tắc đã được thiết lập để giải thích cách một hệ thống, máy móc hay ý tưởng được xây dựng hoặc vận hành."},"4968":{"word":"hòa thuận, suôn sẻ","meaning":"Có tính cách dễ chịu, không có xung đột hoặc diễn ra thuận lợi, không gặp khó khăn."},"4969":{"word":"đơn xin","meaning":"Giấy tờ ghi lại thông tin chi tiết dùng để đăng ký vào một công ty, trường học hoặc cơ quan nào đó."},"4970":{"word":"nguyên tắc","meaning":"Quy tắc cơ bản hoặc lẽ phải chung định hướng cho cách hành xử của ai đó hoặc cách thực hiện một việc gì."},"4971":{"word":"cuối tháng","meaning":"Ngày cuối cùng hoặc khoảng thời gian cuối cùng của một trong mười hai kỳ trong một năm."},"4972":{"word":"loại gì","meaning":"Dùng để hỏi về tính chất bất thường hoặc không mong đợi của một đối tượng hay tình huống."},"4973":{"word":"tàm tạm, vừa phải","meaning":"Diễn tả điều gì đó đủ tốt hoặc chấp nhận được, không xuất sắc nhưng cũng không quá tệ."},"4974":{"word":"khủng hoảng, nguy cơ","meaning":"Khoảnh khắc khó khăn hoặc nguy hiểm khi một quyết định quan trọng phải được đưa ra hoặc hành động phải được thực hiện."},"4975":{"word":"vĩ đại","meaning":"Diễn tả người hoặc vật có tầm quan trọng cao, gây ấn tượng hoặc đáng chú ý về chất lượng hay quy mô."},"4976":{"word":"sự an ủi, lời an ủi","meaning":"Hành động hoặc lời nói được đưa ra để làm giảm bớt nỗi buồn, nỗi đau hoặc lo lắng của ai đó."},"4977":{"word":"sự vi phạm","meaning":"Hành động phá vỡ một quy tắc, luật pháp hoặc thỏa thuận đã được thiết lập."},"4978":{"word":"trên dưới, lên xuống","meaning":"Chỉ các chuyển động hoặc vị trí dọc theo một đường thẳng đứng, từ điểm cao hơn xuống điểm thấp hơn và ngược lại."},"4979":{"word":"ủy ban","meaning":"Một nhóm người được chọn để giải quyết một nhiệm vụ cụ thể hoặc đưa ra quyết định trong một tổ chức lớn hơn."},"4980":{"word":"tính nguy hiểm","meaning":"Sự hiện diện của các điều kiện hoặc hành động có thể dễ dàng dẫn đến thương tích, thiệt hại hoặc rắc rối nghiêm trọng."},"4981":{"word":"sự đe dọa","meaning":"Lời nói hoặc cử chỉ gợi ý ai đó sẽ gây hại, thương tích hoặc khó khăn cho người khác."},"4982":{"word":"Nho giáo","meaning":"Một hệ thống giáo lý truyền thống từ Trung Quốc cổ đại hướng dẫn con người về hành vi đúng đắn, tôn trọng gia đình và trật tự xã hội."},"4983":{"word":"đặc biệt, lạ thường","meaning":"Mô tả một hành động hoặc phẩm chất khác biệt đáng kể hoặc mãnh liệt hơn nhiều so với bình thường."},"4984":{"word":"năng lực","meaning":"Phẩm chất giỏi một công việc hoặc nhiệm vụ cụ thể vì có kỹ năng và kiến thức cần thiết."},"4985":{"word":"sự dẫn dắt, sự gợi ý","meaning":"Hành động dẫn dắt hoặc ảnh hưởng đến ai đó hoặc điều gì đó đến một hành động hoặc trạng thái cụ thể."},"4986":{"word":"sự có lợi","meaning":"Trạng thái mang lại lợi ích, thuận lợi hoặc ưu thế."},"4987":{"word":"cửa kính, kính cửa sổ","meaning":"Tấm kính trong suốt lắp vào khung tường hoặc khung cửa để ánh sáng đi vào bên trong."},"4988":{"word":"tài sản thừa kế, di sản","meaning":"Tài sản hoặc của cải được để lại sau khi một người qua đời."},"4989":{"word":"duy nhất","meaning":"Là thứ đơn nhất hoặc cá thể, không có cái tương đương hoặc bạn đồng hành nào khác."},"4990":{"word":"sự duy trì, sự giữ gìn","meaning":"Hành động giữ cho một trạng thái, tình hình hoặc điều kiện nào đó không thay đổi hoặc tiếp tục tồn tại."},"4991":{"word":"lưu loát","meaning":"Diễn đạt một ngôn ngữ một cách dễ dàng, mạch lạc và không bị vấp."},"4992":{"word":"ấu trĩ","meaning":"Hành động hay suy nghĩ đơn giản, ngây ngô, không phù hợp với người lớn."},"4993":{"word":"sự vui vẻ","meaning":"Trạng thái tinh thần thoải mái, vui tươi, thường thể hiện qua nét mặt và hành động."},"4994":{"word":"lưu thông","meaning":"Hoạt động đưa hàng hóa từ nơi sản xuất đến nơi tiêu thụ hoặc sự luân chuyển liên tục của tiền bạc."},"4995":{"word":"loại hình","meaning":"Nhóm các sự vật, hiện tượng được phân loại theo đặc tính, hình dạng hoặc bản chất chung."},"4996":{"word":"sự cám dỗ","meaning":"Sự lôi kéo mạnh mẽ khiến người ta muốn làm điều gì đó hấp dẫn nhưng có thể dẫn đến kết quả tiêu cực."},"4997":{"word":"lục quân","meaning":"Lực lượng quân sự của một quốc gia chiến đấu và hoạt động chủ yếu trên mặt đất."},"4998":{"word":"đất liền","meaning":"Phần bề mặt rắn của trái đất không bị nước bao phủ."},"4999":{"word":"cơ thể","meaning":"Toàn bộ các bộ phận vật lý của một người, bao gồm xương, cơ và da."},"5000":{"word":"thể chất","meaning":"Liên quan đến thân thể, anatomy của con người hoặc cái gì đó có thể nhìn thấy, chạm vào được."},"5001":{"word":"ân huệ","meaning":"Hành động tốt bụng, giúp đỡ người khác, đặc biệt khi họ gặp khó khăn."},"5002":{"word":"đĩa nhạc","meaning":"Một đĩa tròn, phẳng dùng để ghi và phát lại âm thanh, đặc biệt là âm nhạc."},"5003":{"word":"phản hồi","meaning":"Lời nói, chữ viết hoặc hành động được đưa ra sau khi nghe hoặc nhìn thấy điều gì đó."},"5004":{"word":"dự thi","meaning":"Hành động đăng ký tham gia một kỳ thi hoặc việc làm bài kiểm tra đó."},"5005":{"word":"ý đồ","meaning":"Mục tiêu hoặc mục đích cụ thể mà một người đặt ra và muốn thực hiện."},"5006":{"word":"quần áo","meaning":"Những món đồ được mặc trên cơ thể như áo, quần, váy, v.v."},"5007":{"word":"nghĩa vụ","meaning":"Một nhiệm vụ hoặc trách nhiệm mà một người bắt buộc phải thực hiện, thường do quy định hoặc đạo đức."},"5008":{"word":"có tính bắt buộc","meaning":"Điều gì đó cần phải được thực hiện hoặc tuân thủ một cách bắt buộc, không phải do lựa chọn."},"5009":{"word":"nghi vấn","meaning":"Một câu hỏi được đặt ra để tìm kiếm thông tin, hoặc một sự nghi ngờ về điều gì đó."},"5010":{"word":"y phục","meaning":"Bất kỳ món đồ nào mà con người mặc trên cơ thể như áo, quần, váy."},"5011":{"word":"ý muốn","meaning":"Suy nghĩ rõ ràng trong tâm trí về điều mình muốn làm hoặc muốn đạt được."},"5012":{"word":"trang phục","meaning":"Những món đồ đặc biệt được mặc trên cơ thể cho buổi biểu diễn, lễ kỷ niệm hoặc một vai trò cụ thể."},"5013":{"word":"ý thức","meaning":"Trạng thái tỉnh táo, có khả năng suy nghĩ, cảm nhận và nhận biết môi trường xung quanh."},"5014":{"word":"nghi lễ","meaning":"Một loạt các hành động hoặc sự kiện trang trọng được thực hiện theo trình tự đặc biệt trong các dịp tôn giáo hoặc quan trọng."},"5015":{"word":"nghi ngờ","meaning":"Cảm giác không chắc chắn về điều gì đó, hoặc nghĩ rằng ai đó có thể không trung thực."},"5016":{"word":"sự bất ngờ","meaning":"Tình huống xảy ra hoặc xuất hiện điều gì đó không thể đoán trước, thường gây ngạc nhiên."},"5017":{"word":"động lực","meaning":"Sự thôi thúc hoặc ham muốn mạnh mẽ từ bên trong để làm điều gì đó, khiến một người hành động với nhiều năng lượng."},"5018":{"word":"sự phụ thuộc","meaning":"Trạng thái cần sự giúp đỡ hoặc hỗ trợ từ người hoặc vật khác, hoặc hoàn toàn dựa vào đó để hoạt động hoặc tồn tại."},"5019":{"word":"dựa vào","meaning":"Hành động tựa thân mình vào một vật hoặc người khác để giữ vững thăng bằng hoặc được giúp đỡ."},"5020":{"word":"ý chí","meaning":"Sức mạnh tinh thần hoặc nghị lực bên trong cho phép một người tiếp tục cố gắng và đạt được mục tiêu, ngay cả khi đối mặt với khó khăn."},"5021":{"word":"ích kỷ","meaning":"Mô tả người chỉ nghĩ đến nhu cầu, mong muốn và lợi ích của bản thân, thường không quan tâm đến cách hành động của mình ảnh hưởng đến người khác."},"5022":{"word":"ngay sau đó","meaning":"Xảy ra hoặc xuất hiện trong một khoảng thời gian rất ngắn sau khi điều gì đó khác."},"5023":{"word":"trong vòng","meaning":"Chỉ ra rằng điều gì đó sẽ xảy ra hoặc phải được hoàn thành trước khi một khoảng thời gian đã định trôi qua."},"5024":{"word":"hệ tư tưởng","meaning":"Tập hợp các ý tưởng và nguyên tắc trung tâm mà một nhóm hoặc hệ thống tuân theo, định hướng suy nghĩ và hành động của họ."},"5025":{"word":"tháng này","meaning":"Khoảng thời gian 30 ngày hiện tại đang diễn ra, như được thể hiện trên lịch."},"5026":{"word":"nguyên trạng","meaning":"Mô tả một tình huống hoặc đối tượng vẫn giữ nguyên trạng thái hiện tại mà không có bất kỳ thay đổi nào được thực hiện."},"5027":{"word":"lý thuyết","meaning":"Một tập hợp các ý tưởng hoặc nguyên tắc dùng để giải thích sự việc hoặc hiện tượng."},"5028":{"word":"có lợi","meaning":"Đem lại kết quả tốt, cải thiện tình hình hoặc giúp ích cho ai đó."},"5029":{"word":"đạt được","meaning":"Nỗ lực và hoàn thành thành công một mục tiêu hoặc nhiệm vụ khó khăn, làm cho kết quả hiển rõ."},"5030":{"word":"đến, đạt tới","meaning":"Di chuyển từ nơi này đến nơi khác cho đến khi đến được vị trí hoặc địa điểm đã định."},"5031":{"word":"nói, kể, báo cho biết","meaning":"Nói với người khác để giải thích sự thật hoặc cung cấp chi tiết về điều gì đó."},"5032":{"word":"cái gọi là","meaning":"Dùng để chỉ một tên gọi hoặc mô tả được sử dụng phổ biến, dù có thể không hoàn toàn chính xác."},"5033":{"word":"đây đó, khắp nơi","meaning":"Ở hoặc di chuyển đến nhiều nơi hoặc hướng khác nhau trong một khu vực không xác định."},"5034":{"word":"chừng này, đến mức này","meaning":"Dùng để chỉ một kích thước, số lượng hoặc mức độ cụ thể của một cái gì đó có thể quan sát hoặc đo lường."},"5035":{"word":"di dân","meaning":"Những người rời khỏi quê hương để sống vĩnh viễn ở một quốc gia nước ngoài khác."},"5036":{"word":"cắt tóc","meaning":"Hành động cắt ngắn hoặc tạo kiểu tóc cho ai đó bằng kéo hoặc tông đơ."},"5037":{"word":"sự kiện","meaning":"Một sự kiện hoặc bữa tiệc được tổ chức cho nhiều người tham gia."},"5038":{"word":"sự chia ly, chia tay","meaning":"Hành động hai hoặc nhiều người rời xa nhau trong một thời gian dài hoặc vĩnh viễn, thường kèm theo nỗi buồn."},"5039":{"word":"lý tưởng","meaning":"Hoàn hảo, đúng như mong muốn hoặc hy vọng, là mẫu mực tốt nhất có thể."},"5040":{"word":"lý trí","meaning":"Khả năng suy nghĩ và hành động một cách rõ ràng, bình tĩnh mà không bị cảm xúc mạnh mẽ chi phối."},"5041":{"word":"tiếp theo","meaning":"Dùng để chỉ việc một sự kiện xảy ra ngay sau một sự kiện khác, tạo thành một chuỗi liên tục."},"5042":{"word":"được nối liền, tiếp nối","meaning":"Hai hay nhiều thứ nối liền với nhau, tạo thành một đường thẳng, con đường hoặc chuỗi liên tục không bị gián đoạn."},"5043":{"word":"đằng nào thì cũng, đã rồi","meaning":"Dùng để chỉ một việc đã xảy ra trong quá khứ và không thể thay đổi, tạo thành tình hình hiện tại."},"5044":{"word":"ngoại trừ, ngoài ra","meaning":"Dùng để chỉ ra rằng một người, vật hoặc nhóm cụ thể không được bao gồm khi nhắc đến những người khác."},"5045":{"word":"người dùng","meaning":"Người tương tác hoặc vận hành máy móc, chương trình máy tính hoặc dịch vụ trực tuyến."},"5046":{"word":"chẳng bao lâu, ngay sau đó","meaning":"Diễn tả việc một sự kiện xảy ra trong một khoảng thời gian rất ngắn sau một sự kiện hoặc khoảnh khắc trước đó."},"5047":{"word":"lợi nhuận","meaning":"Số tiền một doanh nghiệp kiếm được còn lại sau khi đã trả hết tất cả các chi phí."},"5048":{"word":"di dời, chuyển","meaning":"Việc thay đổi vị trí của một người, vật hoặc địa chỉ từ nơi này sang nơi khác."},"5049":{"word":"cuối cùng thì bây giờ, mãi đến bây giờ","meaning":"Diễn tả một sự kiện hoặc sự hiểu biết chỉ xảy ra vào thời điểm hiện tại, thường sau một thời gian chờ đợi lâu hoặc nhiều nỗ lực."},"5050":{"word":"ngày hôm sau","meaning":"Khoảng thời gian 24 giờ cụ thể ngay sau ngày hiện tại hoặc ngày được nhắc đến."},"5051":{"word":"Lợi ích liên quan","meaning":"Những lợi ích, vấn đề hoặc mối quan hệ mà các cá nhân hay nhóm khác nhau có được trong một tình huống cụ thể."},"5052":{"word":"Ly hôn","meaning":"Việc chấm dứt một cuộc hôn nhân giữa hai người một cách hợp pháp."},"5053":{"word":"Thành thạo, quen tay","meaning":"Trở nên quen thuộc và có thể thực hiện một việc gì đó dễ dàng, không cần suy nghĩ nhiều do đã làm thường xuyên."},"5054":{"word":"Nấu chín, làm chín","meaning":"Chế biến thức ăn sống như thịt hoặc rau củ bằng cách đun nóng để làm cho chúng ăn được."},"5055":{"word":"Con người, loài người","meaning":"Một thành viên của loài Homo sapiens, có khả năng đi thẳng, sử dụng ngôn ngữ phức tạp và có trí tuệ."},"5056":{"word":"Quan hệ con người, quan hệ xã hội","meaning":"Cách thức các cá nhân hoặc nhóm tương tác, giao tiếp và cư xử với nhau."},"5057":{"word":"Bản chất con người, nhân tính","meaning":"Tập hợp những phẩm chất, cảm xúc và cách suy nghĩ cơ bản được cho là có ở tất cả mọi người."},"5058":{"word":"Có tính người, nhân đạo","meaning":"Miêu tả hành động hoặc cách đối xử thể hiện lòng tốt, sự thông cảm và quan tâm đến người khác hoặc các sinh vật khác."},"5059":{"word":"Nhân cách, tính cách","meaning":"Tập hợp các phẩm chất, suy nghĩ và hành vi độc đáo tạo nên một người cụ thể."},"5060":{"word":"Nhân tạo","meaning":"Cái gì đó được con người tạo ra hoặc sản xuất, chứ không phải có sẵn trong tự nhiên."},"5061":{"word":"Nhân lực, sức người","meaning":"Tổng số người có sẵn để làm việc hoặc thực hiện các nhiệm vụ cho một công ty hoặc dự án."},"5062":{"word":"Nhân loại, loài người","meaning":"Toàn bộ những người đang tồn tại trên Trái Đất, được coi là một nhóm lớn hoặc một loài."},"5063":{"word":"nhân vật, người","meaning":"Một người nào đó, hoặc một nhân vật trong truyện, tranh ảnh."},"5064":{"word":"ấn tượng","meaning":"Cảm giác, ý nghĩ mà một người hay một vật để lại trong tâm trí sau khi ta nhìn thấy hoặc trải nghiệm."},"5065":{"word":"tăng giá, tăng lên","meaning":"Việc làm cho số lượng, giá trị, mức độ của một thứ gì đó trở nên cao hơn."},"5066":{"word":"nhận thức","meaning":"Cách hiểu hoặc suy nghĩ của một người về một ý tưởng, sự thật hoặc tình huống cụ thể."},"5067":{"word":"duyên phận, nhân duyên","meaning":"Mối liên hệ đặc biệt giữa người với người, thường được cho là do định mệnh."},"5068":{"word":"trích dẫn","meaning":"Đoạn văn hoặc lời nói được lấy nguyên văn từ một cuốn sách, bài diễn văn hoặc nguồn khác."},"5069":{"word":"nhân tài, người tài","meaning":"Người có năng lực, kỹ năng xuất sắc trong một lĩnh vực cụ thể, thường được các tổ chức trọng dụng."},"5070":{"word":"tình người, lòng trắc ẩn","meaning":"Tình cảm nhân ái, sự quan tâm và thấu hiểu dành cho những người khác."},"5071":{"word":"công nhận, thừa nhận","meaning":"Hành động đồng ý rằng điều gì đó là đúng, có giá trị hoặc có thật, hoặc chấp nhận quyền hay địa vị của ai đó."},"5072":{"word":"được công nhận, được thừa nhận","meaning":"Được người khác chấp nhận hoặc đánh giá cao về phẩm chất, thành tích hay sự tồn tại của mình."},"5073":{"word":"cơ thể người, thân thể","meaning":"Toàn bộ cấu trúc vật lý của một người, bao gồm tất cả các cơ quan và chi."},"5074":{"word":"giảm giá, hạ giá","meaning":"Việc làm cho số lượng, giá trị hoặc mức độ của một thứ gì đó, đặc biệt là chi phí, trở nên thấp hơn."},"5075":{"word":"do, gây ra bởi","meaning":"Diễn tả việc một sự vật, sự việc nào đó xảy ra là kết quả trực tiếp của một nguyên nhân trước đó."},"5076":{"word":"biên độ nhiệt trong ngày","meaning":"Sự khác biệt giữa nhiệt độ cao nhất và thấp nhất trong vòng 24 giờ tại một địa điểm."},"5077":{"word":"trước hết, trước tiên","meaning":"Diễn tả một hành động hoặc bước đi ban đầu cần phải xảy ra ở giai đoạn bắt đầu của một quá trình, trước khi các hành động khác."},"5078":{"word":"khu vực, vùng","meaning":"Một khu vực hoặc phạm vi không gian nhất định."},"5079":{"word":"hạng nhất, số một","meaning":"Thứ bậc hoặc cấp độ đứng đầu trong nhiều thứ."},"5080":{"word":"người thường, người dân bình thường","meaning":"Người dân bình thường không có địa vị, chức vụ hoặc đặc điểm đặc biệt nào."},"5081":{"word":"phổ biến, chung, thông thường","meaning":"Diễn tả một điều gì đó phổ biến rộng rãi hoặc áp dụng cho đa số người hoặc tình huống, chứ không phải đặc thù cho riêng ai hay riêng việc gì."},"5082":{"word":"một phần, bộ phận","meaning":"Một đoạn hoặc mảnh riêng biệt mà khi kết hợp với các phần khác sẽ tạo thành một vật thể hoặc một tổng thể hoàn chỉnh."},"5083":{"word":"cuộc sống hằng ngày, thường nhật","meaning":"Các hành động, sự kiện và trải nghiệm đều đặn, thường xuyên lấp đầy thời gian của ai đó từ ngày này sang ngày khác."},"5084":{"word":"hằng ngày, thường nhật","meaning":"Diễn tả các hành động hoặc sự kiện xảy ra thường xuyên và có thể dự đoán được, tạo thành một khuôn mẫu đều đặn trong trải nghiệm của ai đó."},"5085":{"word":"cuộc đời, đời người","meaning":"Toàn bộ khoảng thời gian một người hoặc một loài vật tồn tại, bắt đầu từ khi sinh ra và kết thúc khi chết."},"5086":{"word":"một công đôi việc","meaning":"Một tình huống mà một hành động hoặc nỗ lực duy nhất đồng thời đạt được hai kết quả mong muốn riêng biệt."},"5087":{"word":"nhân công","meaning":"Người hoặc sức lực cần thiết để hoàn thành một công việc."},"5088":{"word":"ngày giờ","meaning":"Thời điểm cụ thể được định ra để một sự việc xảy ra."},"5089":{"word":"thanh toán một lần","meaning":"Việc trả toàn bộ số tiền nợ hoặc chi phí trong một giao dịch duy nhất, không chia nhỏ ra."},"5090":{"word":"tạm thời","meaning":"Diễn tả cái gì đó chỉ tồn tại hoặc xảy ra trong một thời gian ngắn, không vĩnh viễn."},"5091":{"word":"thường xuyên","meaning":"Diễn tả một hành động hoặc sự việc xảy ra rất thường xuyên, trở thành chuyện bình thường."},"5092":{"word":"nâng dậy","meaning":"Di chuyển một vật hoặc bộ phận cơ thể từ vị trí thấp hoặc nằm ngang lên vị trí cao hoặc thẳng đứng."},"5093":{"word":"từng cái một","meaning":"Thực hiện một hành động đối với từng đối tượng riêng lẻ trong một nhóm."},"5094":{"word":"một loại","meaning":"Diễn tả cái gì đó là một ví dụ thuộc một loại hoặc hạng mục cụ thể."},"5095":{"word":"từ sớm","meaning":"Diễn tả một hành động xảy ra trước thời điểm thông thường hoặc dự kiến."},"5096":{"word":"toàn bộ","meaning":"Chỉ toàn bộ hoặc tổng thể các hạng mục, không bỏ sót bất kỳ phần nào."},"5097":{"word":"sự thống nhất","meaning":"Tình huống mà nhiều thứ, như ý tưởng hoặc kết quả, trùng khớp hoặc hoàn toàn phù hợp với nhau."},"5098":{"word":"dùng một lần","meaning":"Diễn tả một món đồ được sản xuất để chỉ sử dụng một lần rồi bỏ đi."},"5099":{"word":"sản phẩm dùng một lần","meaning":"Đây là những vật phẩm được thiết kế để chỉ sử dụng một lần rồi bỏ đi, ví dụ như cốc giấy hay đồ dùng nhựa."},"5100":{"word":"được đọc","meaning":"Tình trạng chữ viết trở nên rõ ràng và có thể hiểu được bởi người đọc."},"5101":{"word":"cho đọc","meaning":"Làm cho hoặc cho phép người khác nhìn và hiểu văn bản hoặc lời nói."},"5102":{"word":"tiền lương","meaning":"Khoản thanh toán định kỳ mà người lao động nhận được từ người sử dụng lao động để đổi lấy sức lao động hoặc dịch vụ của họ."},"5103":{"word":"nhiệm vụ","meaning":"Công việc hoặc trách nhiệm được giao cho một người."},"5104":{"word":"tạm thời","meaning":"Được thực hiện hoặc quyết định trong một thời gian ngắn, không phải vĩnh viễn."},"5105":{"word":"mang thai","meaning":"Tình trạng một phụ nữ hoặc con vật cái mang thai nhi đang phát triển trong cơ thể từ lúc thụ thai cho đến khi sinh nở."},"5106":{"word":"gửi tiền","meaning":"Hành động gửi một khoản tiền vào tài khoản của mình hoặc tài khoản của người khác tại một tổ chức tài chính."},"5107":{"word":"nhập ngũ","meaning":"Quá trình chính thức một người trở thành thành viên mới của lực lượng vũ trang quốc gia."},"5108":{"word":"nhập liệu","meaning":"Hành động nhập thông tin vào máy tính hoặc thiết bị điện tử khác bằng cách gõ, nói hoặc đặt vào."},"5109":{"word":"gia nhập công ty","meaning":"Hành động chính thức trở thành nhân viên và bắt đầu làm việc cho một doanh nghiệp hoặc tổ chức cụ thể."},"5110":{"word":"thi tuyển sinh","meaning":"Một bài kiểm tra chính thức mà học sinh phải vượt qua để được chấp nhận vào trường học, cao đẳng hoặc đại học."},"5111":{"word":"sự vào cửa","meaning":"Hành động bước vào một tòa nhà hoặc địa điểm, hoặc sự cho phép đi vào một khu vực cụ thể."},"5112":{"word":"lập trường","meaning":"Cách một người nhìn nhận hoặc xem xét một tình huống hoặc vấn đề cụ thể, thường được thể hiện qua lời nói hoặc hành động."},"5113":{"word":"mặc cho","meaning":"Hành động một người đặt quần áo lên cơ thể người khác."},"5114":{"word":"nối tiếp","meaning":"Nhiều sự vật hoặc sự kiện xảy ra theo một chuỗi liên tục, cái này xuất hiện ngay sau cái kia."},"5115":{"word":"bị quên lãng","meaning":"Một điều gì đó đã từng được biết đến hoặc hiện diện trong tâm trí mọi người không còn được nhớ đến hoặc suy nghĩ nữa."},"5116":{"word":"-gia","meaning":"Một hậu tố được thêm vào danh từ để chỉ một người thực hiện một công việc cụ thể, làm việc trong một lĩnh vực nhất định hoặc có một kỹ năng đặc biệt."},"5117":{"word":"chứng chỉ","meaning":"Một giấy tờ hoặc thẻ chính thức chứng minh một người có các kỹ năng cần thiết hoặc sự cho phép hợp pháp để thực hiện một công việc hoặc hoạt động cụ thể."},"5118":{"word":"kích thích","meaning":"Một sự kiện hoặc vật thể gây ra phản ứng thể chất hoặc tinh thần trong một sinh vật sống hoặc hệ thống."},"5119":{"word":"liên tục","meaning":"Mô tả một hành động hoặc sự kiện xảy ra nhiều lần một cách liên tục hoặc thường xuyên."},"5120":{"word":"lớn lên","meaning":"Chiều cao hoặc vóc dáng của một người dần dần trở nên lớn hơn."},"5121":{"word":"tự hào","meaning":"Trải nghiệm cảm giác hạnh phúc mạnh mẽ và sự hài lòng sâu sắc về thành tích của bản thân hoặc thành tích của người mình quan tâm."},"5122":{"word":"phụ đề","meaning":"Văn bản hiển thị ở cuối màn hình hình ảnh, thường là lời thoại hoặc bản dịch của chúng."},"5123":{"word":"vốn","meaning":"Tài sản như tiền bạc hay của cải dùng để kinh doanh hoặc tạo ra của cải."},"5124":{"word":"lòng tự hào","meaning":"Cảm giác hài lòng và tự tôn về bản thân, nhóm hoặc những thành tựu đạt được."},"5125":{"word":"tự tử","meaning":"Hành động cố ý kết thúc sự sống của bản thân."},"5126":{"word":"tư thế","meaning":"Cách mà một người giữ và đặt cơ thể khi đứng, ngồi hoặc di chuyển."},"5127":{"word":"sự tự tin","meaning":"Niềm tin vững chắc vào khả năng và phán đoán của bản thân, thường thể hiện qua thái độ điềm tĩnh và tự chủ."},"5128":{"word":"tự nhiên","meaning":"Diễn ra hoặc xuất hiện một cách không gượng ép, dễ dàng và đúng với trạng thái hay tính chất ban đầu."},"5129":{"word":"tự nhiên","meaning":"Tồn tại hoặc xảy ra trong thế giới vật lý mà không có sự can thiệp hoặc thay đổi của con người."},"5130":{"word":"môi trường tự nhiên","meaning":"Toàn bộ các sự vật sống và không sống như cây cối, động vật, đất đai và nước tồn tại trên Trái Đất mà không do con người tạo ra."},"5131":{"word":"một cách tự nhiên","meaning":"Xảy ra hoặc phát triển mà không cần nỗ lực đặc biệt hay tác động bên ngoài, như thể được mong đợi hoặc tự động."},"5132":{"word":"tài nguyên","meaning":"Nguồn cung cấp những thứ có giá trị như tiền bạc, vật liệu hoặc kỹ năng mà một người hoặc quốc gia có thể sử dụng để đạt được mục tiêu."},"5133":{"word":"lòng tự trọng","meaning":"Cảm giác tôn trọng bản thân và tin vào giá trị hay khả năng của chính mình."},"5134":{"word":"tự túc","meaning":"Việc sinh sống một mình trong một ngôi nhà hoặc căn phòng, không có thành viên gia đình hay bạn cùng phòng và tự lo liệu mọi thứ."},"5135":{"word":"tác giả","meaning":"Người sáng tạo ra các tác phẩm văn học, câu chuyện, bài báo hoặc nội dung văn bản khác để người khác đọc."},"5136":{"word":"sáng tác nhạc","meaning":"Hoạt động sáng tạo sắp xếp các nốt nhạc và âm thanh để tạo thành một bản nhạc mới."},"5137":{"word":"nhạc sĩ","meaning":"Người có công việc là tạo ra các bản nhạc mới, thường bằng cách viết nốt nhạc."},"5138":{"word":"vận hành","meaning":"Trạng thái hoặc quá trình một máy móc hay hệ thống thực hiện nhiệm vụ hoặc hoạt động đã định."},"5139":{"word":"bài văn","meaning":"Hành động tạo ra một tác phẩm viết; hoặc chính tác phẩm viết đó."},"5140":{"word":"công việc","meaning":"Một nhiệm vụ hoặc hoạt động cụ thể mà ai đó đang làm hoặc cần làm, thường là một phần của dự án lớn hơn."},"5141":{"word":"tác dụng","meaning":"Cách một cái gì đó thực hiện mục đích của nó hoặc ảnh hưởng của nó đối với cái khác."},"5142":{"word":"chiến lược","meaning":"Một chuỗi hành động được lên kế hoạch cẩn thận nhằm đạt được mục tiêu cụ thể, thường trong tình huống quân sự hoặc cạnh tranh."},"5143":{"word":"tác phẩm","meaning":"Một vật phẩm, như tranh vẽ, tượng điêu khắc, sách hoặc bài hát, được tạo ra bởi một nghệ sĩ hoặc người có kỹ năng."},"5144":{"word":"rất nhiều","meaning":"Với mức độ hoặc số lượng lớn, lấp đầy hoàn toàn hoặc có rất nhiều thứ gì đó."},"5145":{"word":"lời cằn nhằn","meaning":"Hành động nói về những chuyện nhỏ nhặt một cách vô ích; hoặc những lời nói như vậy."},"5146":{"word":"xuất sắc","meaning":"Diễn tả một người có những đặc điểm hấp dẫn hoặc tài năng ấn tượng khiến người khác rất ngưỡng mộ."},"5147":{"word":"bị cắt","meaning":"Một phần của vật thể nào đó bị tách rời khỏi vật chính do bị vật sắc nhọn cắt qua."},"5148":{"word":"sống sung túc","meaning":"Sống một cuộc sống giàu có, đầy đủ của cải."},"5149":{"word":"bị nhấn chìm","meaning":"Một vật hoặc sinh vật bị chìm hoàn toàn xuống dưới bề mặt chất lỏng như nước."},"5150":{"word":"ngủ thiếp đi","meaning":"Một người hay động vật bắt đầu vào trạng thái nghỉ ngơi sâu, nhắm mắt và nằm yên."},"5151":{"word":"chuồn chuồn","meaning":"Một loài côn trùng bay có thân dài, mảnh, hai cặp cánh trong suốt và mắt rất to, thường thấy bay lượn gần ao hồ."},"5152":{"word":"kéo, giật","meaning":"Nắm chặt một vật bằng tay và dùng lực làm cho nó di chuyển về phía mình."},"5153":{"word":"hôn nhân (nam giới)","meaning":"Phong tục hay nghi lễ khi một người đàn ông chính thức lấy một người phụ nữ làm bạn đời."},"5154":{"word":"bộ trưởng","meaning":"Một quan chức rất quan trọng được chọn để lãnh đạo một trong những bộ chính của chính phủ một quốc gia."},"5155":{"word":"thời gian dài","meaning":"Một khoảng thời gian đáng kể kéo dài nhiều ngày, nhiều tuần hoặc thậm chí nhiều năm."},"5156":{"word":"dài hạn","meaning":"Miêu tả một kế hoạch, mục tiêu hoặc tình huống sẽ phát triển hoặc tiếp diễn trong một khoảng thời gian dài, thường là trong tương lai xa."},"5157":{"word":"trò đùa","meaning":"Một hành động vui đùa hoặc tinh nghịch được thực hiện để làm vui hoặc trêu chọc ai đó, thường là do trẻ em."},"5158":{"word":"con trai cả","meaning":"Người con trai đầu lòng trong một gia đình."},"5159":{"word":"thể loại","meaning":"Đây là một loại hình hoặc phong cách đặc trưng để phân loại sách, phim ảnh, âm nhạc hoặc nghệ thuật."},"5160":{"word":"mẹ vợ","meaning":"Đây là mẹ của người mà bạn kết hôn."},"5161":{"word":"kinh doanh","meaning":"Đây là hoạt động buôn bán hàng hóa hoặc dịch vụ để kiếm lợi nhuận."},"5162":{"word":"khuyết tật","meaning":"Đây là một tình trạng cơ thể hoặc tinh thần làm hạn chế khả năng hoạt động của một người."},"5163":{"word":"người khuyết tật","meaning":"Đây là những người có tình trạng cơ thể hoặc tinh thần khiến họ gặp khó khăn trong một số hoạt động hàng ngày."},"5164":{"word":"bố vợ","meaning":"Đây là bố của người mà bạn kết hôn."},"5165":{"word":"đáng khen","meaning":"Điều này dùng để tả một hành động hoặc thành tựu rất ấn tượng, khiến người khác cảm thấy tự hào và tôn trọng."},"5166":{"word":"lại (tiếp đầu ngữ)","meaning":"Đây là một phần từ được đặt ở đầu một từ khác để chỉ rằng hành động xảy ra lần thứ hai hoặc được thực hiện lại."},"5167":{"word":"tài năng","meaning":"Đây là khả năng tự nhiên cho phép ai đó làm tốt một số việc, như sáng tạo nghệ thuật hoặc biểu diễn âm nhạc."},"5168":{"word":"gạt tàn","meaning":"Đây là một vật đựng nhỏ dùng để chứa tàn thuốc và đầu mẩu thuốc lá."},"5169":{"word":"nhanh chóng","meaning":"Điều này mô tả một hành động diễn ra với tốc độ cao và ít chậm trễ, như thể nó được thực hiện ngay lập tức."},"5170":{"word":"tài sản","meaning":"Đây là tất cả những thứ có giá trị mà một người hoặc tổ chức sở hữu, bao gồm tiền, nhà cửa, đất đai và các tài sản khác."},"5171":{"word":"tái tạo","meaning":"Là quá trình làm cho vật gì bị hỏng hoặc cũ trở nên mới và khỏe mạnh, hoặc là hành động một thiết bị chiếu lại video hay phát lại âm thanh đã được ghi."},"5172":{"word":"vận may","meaning":"Là việc những điều tốt hoặc xấu xảy ra với một người một cách ngẫu nhiên, không phải do nỗ lực của bản thân họ."},"5173":{"word":"ru ngủ","meaning":"Giúp ai đó, thường là trẻ nhỏ hoặc em bé, nằm xuống và nhắm mắt để bắt đầu ngủ."},"5174":{"word":"năm kia","meaning":"Khoảng thời gian cụ thể trong quá khứ, chỉ năm ngay trước năm ngoái."},"5175":{"word":"tài năng","meaning":"Khả năng đặc biệt, thường là do học hỏi, cho phép ai đó thực hiện các hành động khó hoặc các kỳ tích khéo léo rất tốt."},"5176":{"word":"phiên tòa","meaning":"Một buổi xét xử chính thức được tổ chức trong một tòa nhà cụ thể, nơi thẩm phán và đôi khi một nhóm người lắng nghe các sự thật để quyết định xem một người có phạm tội hay không."},"5177":{"word":"sinh viên đang theo học","meaning":"Là người hiện đang đăng ký và theo học tại một trường học, cao đẳng hoặc đại học để được giáo dục."},"5178":{"word":"đồ tái chế","meaning":"Các vật phẩm như chai nhựa, giấy hoặc hộp đựng thủy tinh được thu gom riêng để có thể xử lý và sử dụng tạo ra sản phẩm mới."},"5179":{"word":"tiền tố \"hạ-\"","meaning":"Một tiền tố chỉ ra rằng cái gì đó ở vị trí thấp hơn hoặc ở mức độ thấp hơn."},"5180":{"word":"chất lượng thấp","meaning":"Mô tả một cái gì đó có chất lượng rất kém, không xuất sắc hoặc có ít giá trị."},"5181":{"word":"lãi suất thấp","meaning":"Là một mức lãi suất thấp hoặc tỷ lệ của mức lãi suất đó."},"5182":{"word":"từng người một","meaning":"Đề cập đến từng người hoặc từng vật trong một nhóm, được xem xét hoặc xử lý riêng lẻ."},"5183":{"word":"mức đó, nhiều như vậy","meaning":"Chỉ một mức độ hoặc số lượng nhất định đã được chỉ ra hoặc thể hiện."},"5184":{"word":"lưu trữ, cất giữ","meaning":"Hành động đặt đồ vật vào một nơi cụ thể để giữ an toàn và có thể sử dụng sau này."},"5185":{"word":"tự động, tự nó","meaning":"Diễn ra hoặc hoạt động một cách tự nhiên, không cần sự can thiệp của con người hay tác động bên ngoài."},"5186":{"word":"phạm phải, gây ra","meaning":"Thực hiện một hành động mà thường là sai, gây hại hoặc trái với quy tắc."},"5187":{"word":"kẻ thù, địch","meaning":"Một người hoặc một nhóm có thái độ thù địch hoặc cạnh tranh với người khác, thường tìm cách gây hại."},"5188":{"word":"tích cực, chủ động","meaning":"Thể hiện năng lượng và sự chủ động mạnh mẽ, tham gia với sự nhiệt tình và nỗ lực rõ rệt."},"5189":{"word":"mang tính tích cực, chủ động","meaning":"Miêu tả một người hoặc thái độ thể hiện sự chủ động mạnh mẽ và sự tham gia năng động, thay vì chỉ phản ứng với các sự kiện."},"5190":{"word":"vừa phải, thích hợp","meaning":"Theo một cách phù hợp với tình huống, hoặc ở một mức độ không quá nhiều cũng không quá ít."},"5191":{"word":"năng khiếu, sở trường","meaning":"Khả năng hoặc phẩm chất phù hợp với một công việc nhất định."},"5192":{"word":"trở nên ít hơn, giảm đi","meaning":"Trở nên nhỏ hơn về số lượng hoặc con số, dẫn đến tổng số bị giảm."},"5193":{"word":"áp dụng, ứng dụng","meaning":"Hành động đưa một quy tắc, ý tưởng hoặc phương pháp vào thực tế sử dụng cho một tình huống hoặc mục đích cụ thể."},"5194":{"word":"thâm hụt, lỗ","meaning":"Tình trạng khi số tiền hoặc nguồn lực chi ra nhiều hơn số tiền hoặc nguồn lực thu vào."},"5195":{"word":"thích hợp","meaning":"Có tính chất vừa vặn, đúng đắn, đáp ứng được yêu cầu của một tình huống hoặc mục đích nào đó."},"5196":{"word":"triển khai","meaning":"Quá trình một sự việc dần dần xuất hiện, phát triển hoặc được trình bày theo trình tự."},"5197":{"word":"chuyên môn","meaning":"Thuộc về hoặc liên quan đến một lĩnh vực kiến thức hay kỹ năng cụ thể, đòi hỏi sự học tập và rèn luyện sâu rộng."},"5198":{"word":"nghề chuyên môn","meaning":"Nghề nghiệp đòi hỏi phải có trình độ học vấn cao và kỹ năng đặc biệt để thực hiện các nhiệm vụ cụ thể."},"5199":{"word":"phòng triển lãm","meaning":"Nơi có không gian rộng lớn, thường là trong nhà, dùng để trưng bày các vật phẩm cho nhiều người đến xem."},"5200":{"word":"tiền đề","meaning":"Điều kiện cần có hoặc được thiết lập trước để một sự kiện hay tình huống nhất định có thể xảy ra."},"5201":{"word":"tổng thể","meaning":"Mô tả một sự vật, sự việc khi xem xét tất cả các phần cấu thành của nó cùng lúc, không bỏ sót chi tiết nào."},"5202":{"word":"trước sau","meaning":"Khoảng thời gian ngay trước một sự kiện và khoảng thời gian ngay sau đó."},"5203":{"word":"tuyệt đối","meaning":"Tồn tại một cách hoàn toàn và trọn vẹn, không có khả năng nào khác."},"5204":{"word":"tuyệt vọng","meaning":"Cảm giác mất hết mọi hy vọng, không còn lối thoát hoặc sự giúp đỡ."},"5205":{"word":"một nửa","meaning":"Một trong hai phần bằng nhau khi chia một vật hay một lượng thành hai."},"5206":{"word":"thủ tục","meaning":"Chuỗi các hành động hoặc hướng dẫn được thực hiện theo một trình tự nhất định để đạt được một mục tiêu."},"5207":{"word":"tuổi trẻ","meaning":"Trạng thái tươi trẻ về cả thể chất lẫn tinh thần."},"5208":{"word":"kiểm tra","meaning":"Hành động xem xét cẩn thận một thứ gì đó để tìm lỗi hoặc đảm bảo đạt tiêu chuẩn."},"5209":{"word":"giờ ăn trưa","meaning":"Khoảng thời gian giữa ngày mà mọi người nghỉ ngơi để dùng bữa chính."},"5210":{"word":"lịch sự","meaning":"Có thái độ điềm đạm, cử chỉ nhẹ nhàng và suy nghĩ kỹ lưỡng cho người khác."},"5211":{"word":"tiếp cận","meaning":"Việc đến gần ai đó hoặc cái gì đó, hoặc phương tiện để vào một nơi nào đó hay sử dụng một vật nào đó."},"5212":{"word":"kết nối","meaning":"Thiết lập cho phép hai hoặc nhiều thiết bị điện tử hoặc hệ thống trao đổi dữ liệu."},"5213":{"word":"bước vào","meaning":"Đạt đến thời điểm một giai đoạn hoặc một kỷ nguyên mới rõ ràng bắt đầu."},"5214":{"word":"tiếp xúc","meaning":"Sự tiếp xúc vật lý giữa hai vật thể hoặc bề mặt, đôi khi dẫn đến một sự cố nhỏ."},"5215":{"word":"tiếp nhận","meaning":"Nhận được thông tin, tin tức hoặc gặp gỡ ai đó/cái gì đó một cách trực tiếp."},"5216":{"word":"định kỳ","meaning":"Việc xảy ra lặp đi lặp lại vào những thời điểm hoặc ngày đã định trước."},"5217":{"word":"định kỳ","meaning":"Diễn tả một sự việc xảy ra lặp đi lặp lại vào những thời điểm hoặc ngày đã được xác định."},"5218":{"word":"chính đảng","meaning":"Một nhóm người có cùng ý tưởng hoặc quan điểm chính trị, được thành lập để giành quyền lực và thực hiện lý tưởng của họ."},"5219":{"word":"mặt tiền","meaning":"Phần hướng về phía trước hoặc về phía người nhìn của một vật, cấu trúc, chẳng hạn như mặt chính của một tòa nhà."},"5220":{"word":"hoàn toàn trái ngược","meaning":"Một điều hoặc tình huống hoàn toàn đối lập và khác biệt cơ bản so với một điều khác."},"5221":{"word":"thông tin hóa","meaning":"Sự phát triển của một xã hội nơi dữ liệu số và công nghệ trở thành trung tâm của mọi khía cạnh cuộc sống."},"5222":{"word":"chính phủ","meaning":"Tổ chức chính thức kiểm soát một quốc gia hoặc khu vực, đưa ra quyết định và thiết lập luật pháp cho công dân."},"5223":{"word":"bình thường","meaning":"Tình trạng hoặc trạng thái thông thường và được mong đợi của một sự vật, hoạt động mà không có vấn đề gì."},"5224":{"word":"bình thường","meaning":"Diễn tả điều gì đó thông thường, được mong đợi và hoạt động theo cách bình thường, không có vấn đề."},"5225":{"word":"tấm lòng, sự tận tâm","meaning":"Sự chăm sóc sâu sắc và nỗ lực lớn khi làm việc gì đó, thể hiện mong muốn chân thành để đạt được sự xuất sắc."},"5226":{"word":"chính thức","meaning":"Diễn tả điều gì đó tuân thủ nghiêm ngặt các thủ tục đã thiết lập hoặc được cơ quan có thẩm quyền công nhận là hợp lệ."},"5227":{"word":"tinh thần","meaning":"Diễn tả những gì liên quan đến suy nghĩ, cảm xúc và tâm trí bên trong của một người, khác biệt với cơ thể vật lý."},"5228":{"word":"định nghĩa","meaning":"Sự giải thích ý nghĩa hoặc bản chất của một từ, khái niệm hoặc vật."},"5229":{"word":"thực ra","meaning":"Từ này chỉ ra rằng điều thực sự xảy ra hoặc là sự thật khác với những gì ai đó nghĩ hoặc mong đợi."},"5230":{"word":"ngừng","meaning":"Trạng thái một vật thể hoặc hoạt động trở nên hoàn toàn tĩnh lặng và không tiếp tục nữa."},"5231":{"word":"đình chỉ công tác","meaning":"Đây là hình phạt dành cho công chức khi họ bị tạm dừng làm việc trong một thời gian nhất định và bị cắt hai phần ba tiền lương."},"5232":{"word":"định cư","meaning":"Là việc con người đến một nơi nào đó và bắt đầu sinh sống lâu dài, thường là xây nhà và tạo dựng cộng đồng ở đó."},"5233":{"word":"chính sách","meaning":"Là một kế hoạch hành động có cấu trúc do chính phủ hoặc tổ chức tạo ra để đạt được mục tiêu cụ thể và hướng dẫn hoạt động của mình."},"5234":{"word":"chính trị gia","meaning":"Là người nắm giữ hoặc tìm kiếm chức vụ công, làm việc để đưa ra quyết định và tạo ra luật pháp cho một quốc gia hoặc cộng đồng."},"5235":{"word":"chính trị","meaning":"Liên quan đến hệ thống chính phủ, việc quản lý một quốc gia hoặc các hành động của các nhóm khác nhau cạnh tranh quyền lực."},"5236":{"word":"sữa mẹ","meaning":"Là chất lỏng màu trắng, đục, được tiết ra từ ngực người hoặc động vật sau khi sinh."},"5237":{"word":"-lễ","meaning":"Là một bộ phận từ được thêm vào cuối, chỉ một cuộc tụ họp công cộng với các hoạt động đặc biệt, thường là để vui chơi hoặc kỷ niệm."},"5238":{"word":"-chế phẩm","meaning":"Là một bộ phận từ được thêm vào cuối, chỉ một sản phẩm hoặc vật liệu được sử dụng để gây ra một hiệu ứng cụ thể hoặc thực hiện một hành động cụ thể."},"5239":{"word":"loại bỏ","meaning":"Là hành động lấy thứ gì đó ra khỏi vị trí của nó, làm cho nó không còn hiện diện nữa."},"5240":{"word":"chế độ","meaning":"Là một tập hợp các quy tắc, phong tục và tổ chức được thiết lập chính thức để kiểm soát cách thức hoạt động của một điều gì đó trong xã hội."},"5241":{"word":"đúng lúc","meaning":"Là thời điểm chính xác khi một điều gì đó xảy ra hoặc nên xảy ra."},"5242":{"word":"làm ơn","meaning":"Từ dùng để làm cho yêu cầu nghe lịch sự hơn hoặc để bày tỏ mong muốn mạnh mẽ, chân thành rằng điều gì đó sẽ xảy ra."},"5243":{"word":"khá, đáng kể","meaning":"Từ dùng để chỉ mức độ đáng kể hoặc vượt ngoài mong đợi của một sự việc."},"5244":{"word":"lễ cúng, giỗ","meaning":"Nghi thức dâng đồ ăn để bày tỏ lòng biết ơn đối với thần linh hoặc vong linh người đã khuất."},"5245":{"word":"trình bày, đề xuất","meaning":"Hành động đưa ra một ý tưởng, đối tượng hoặc thông tin để người khác xem xét hoặc suy nghĩ."},"5246":{"word":"hạn chế, ràng buộc","meaning":"Quy tắc hoặc điều kiện kiểm soát hoặc ngăn cản ai đó hoặc vật gì đó hành động hoặc di chuyển tự do."},"5247":{"word":"loại trừ, ngoại trừ","meaning":"Việc cố ý tách một vật hoặc một người ra khỏi một nhóm lớn hơn."},"5248":{"word":"học trò, môn đệ","meaning":"Người nhận sự hướng dẫn từ một giáo viên hoặc tiếp nhận lời dạy của người khác."},"5249":{"word":"chỗ cũ, vị trí ban đầu","meaning":"Vị trí mà một vật hoặc người vốn dĩ đã ở đó."},"5250":{"word":"sản xuất, chế tác","meaning":"Toàn bộ quá trình tạo ra một cái gì đó mới như phim, bài hát hoặc sản phẩm."},"5251":{"word":"giới hạn, hạn chế","meaning":"Ranh giới hoặc quy tắc xác định kiểm soát mức độ, số lượng hoặc sự tự do của một điều gì đó."},"5252":{"word":"nghìn tỉ","meaning":"Một số lượng rất lớn, được biểu thị bằng một chữ số 1 theo sau là mười hai số 0."},"5253":{"word":"mảnh, miếng","meaning":"Một phần nhỏ được tách ra hoặc lấy ra từ một vật lớn hơn."},"5254":{"word":"nhỏ xíu, bé tí","meaning":"Mang kích thước vật lý rất nhỏ bé, thường dùng cho đồ vật hoặc đặc điểm của con người."},"5255":{"word":"giai đoạn đầu","meaning":"Giai đoạn đầu của một sự kiện, bệnh tật hoặc quá trình nào đó."},"5256":{"word":"nài nỉ","meaning":"Liên tục yêu cầu hoặc làm phiền ai đó để đạt được điều mình muốn."},"5257":{"word":"món kho","meaning":"Một món ăn được chế biến bằng cách hầm nhừ các nguyên liệu như cá hoặc rau củ trong nước sốt mặn."},"5258":{"word":"chiếu sáng","meaning":"Hệ thống đèn và thiết bị dùng để làm sáng một khu vực."},"5259":{"word":"thận trọng","meaning":"Hành động một cách cẩn thận để tránh nguy hiểm hoặc sai sót."},"5260":{"word":"thao tác","meaning":"Hành động điều khiển máy móc hoặc thiết bị bằng cách nhấn nút, di chuyển cần gạt để nó hoạt động như mong muốn."},"5261":{"word":"điều chỉnh","meaning":"Hành động thay đổi nhỏ mức độ, số lượng hoặc tình trạng của cái gì đó để đạt được trạng thái mong muốn."},"5262":{"word":"điều chỉnh","meaning":"Hành động thay đổi các sắp xếp hoặc yếu tố, như lịch trình hoặc tranh chấp, để tìm ra giải pháp hoặc thỏa thuận phù hợp."},"5263":{"word":"hòa hợp","meaning":"Sự sắp xếp dễ chịu của các phần, màu sắc hoặc âm thanh khác nhau mà phù hợp tốt với nhau mà không có xung đột."},"5264":{"word":"sự tồn tại","meaning":"Trạng thái của một người, vật thể hoặc khái niệm có thực và có thể nhận thức được trong thế giới."},"5265":{"word":"tôn trọng","meaning":"Cảm giác hoặc hành động thể hiện sự đánh giá cao một người hoặc vật và đối xử với họ một cách trang nghiêm."},"5266":{"word":"cơn buồn ngủ","meaning":"Cảm giác mệt mỏi về thể chất, khiến mí mắt nặng trĩu và đầu gật gù."},"5267":{"word":"hiếm khi, hầu như không","meaning":"Một trạng từ diễn tả một hành động rất ít khi xảy ra hoặc rất khó để hoàn thành."},"5268":{"word":"thu hẹp, làm hẹp lại","meaning":"Làm cho một không gian, con đường hoặc khoảng cách trở nên ít rộng hơn."},"5269":{"word":"mang tính tôn giáo, thuộc về tôn giáo","meaning":"Mô tả điều gì đó liên quan đến tín ngưỡng và thực hành về một vị thần hoặc các vị thần."},"5270":{"word":"bắp chân","meaning":"Phần cơ tròn ở phía sau cẳng chân của người, nằm giữa đầu gối và mắt cá chân."},"5271":{"word":"thỉnh thoảng, đôi khi","meaning":"Một trạng từ diễn tả một hành động hoặc sự kiện xảy ra không đều đặn, xuất hiện lúc này lúc khác."},"5272":{"word":"trái và phải, hai bên","meaning":"Hai phía đối diện hoặc hướng từ một điểm trung tâm, chẳng hạn như trên một con đường hoặc một vật thể."},"5273":{"word":"tội lỗi, tội ác","meaning":"Một hành động bị coi là sai trái về mặt đạo đức hoặc vi phạm nghiêm trọng một quy tắc, thường dẫn đến hình phạt."},"5274":{"word":"mang tính chủ quan, chủ quan","meaning":"Mô tả điều gì đó dựa trên cảm xúc cá nhân hoặc quan điểm cụ thể của một người, chứ không phải dựa trên sự thật khách quan."},"5275":{"word":"nếp nhăn, nếp gấp","meaning":"Những đường nhỏ hoặc nếp gấp hình thành trên một bề mặt, chẳng hạn như da người do tuổi tác, hoặc vải khi nó không phẳng."},"5276":{"word":"nắm đấm","meaning":"Bàn tay với tất cả các ngón tay cuộn chặt vào lòng bàn tay, thường sẵn sàng để đấm hoặc nắm chặt."},"5277":{"word":"sự chú ý, chú mục","meaning":"Hành động quan sát hoặc lắng nghe cẩn thận điều gì đó, khiến mọi người tập trung sự chú ý và suy nghĩ vào nó."},"5278":{"word":"cổ phiếu","meaning":"Một chứng nhận bằng giấy hoặc điện tử cho thấy một người sở hữu một phần nhỏ của một công ty và có thể kiếm hoặc mất tiền từ giá trị của nó."},"5279":{"word":"được cho","meaning":"Một cái gì đó được trao hoặc cung cấp cho ai đó mà họ không cần chủ động yêu cầu."},"5280":{"word":"lập luận","meaning":"Một lời tuyên bố chắc chắn hoặc ý kiến mà một người tin là đúng hoặc nên xảy ra."},"5281":{"word":"khuỵu xuống","meaning":"Đột ngột ngồi xuống hoặc khuỵu xuống đất do mất sức hoặc quá sốc."},"5282":{"word":"ấm đun nước","meaning":"Một dụng cụ có vòi và tay cầm, dùng để đun hoặc rót nước, chất lỏng."},"5283":{"word":"nhà ở","meaning":"Một tòa nhà được xây dựng để con người sinh sống."},"5284":{"word":"cốt truyện","meaning":"Chuỗi sự kiện chính trong một tác phẩm như sách, phim, kịch, cho biết câu chuyện diễn ra thế nào."},"5285":{"word":"liên tục","meaning":"Diễn tả một hành động hoặc trạng thái xảy ra không ngừng nghỉ."},"5286":{"word":"thân cây","meaning":"Phần chính dài của cây mọc từ đất lên, nâng đỡ lá, hoa hoặc quả."},"5287":{"word":"giảm đi","meaning":"Trở nên ít hơn về số lượng, khối lượng hoặc mức độ."},"5288":{"word":"sự nghiện","meaning":"Nhu cầu mạnh mẽ, không thể kiểm soát đối với một thứ gì đó, khiến người ta tiếp tục muốn nó dù có hại."},"5289":{"word":"giai đoạn giữa","meaning":"Giai đoạn ở giữa của một sự kiện, khoảng thời gian hoặc quá trình."},"5290":{"word":"doanh nghiệp vừa và nhỏ","meaning":"Một công ty có quy mô nhỏ hơn so với doanh nghiệp lớn về tài chính, nhân viên, doanh thu, v.v."},"5291":{"word":"lầm bầm","meaning":"Nói nhỏ hoặc nói thầm trong miệng khiến người khác khó nghe thấy."},"5292":{"word":"tầm quan trọng","meaning":"Mức độ quan trọng hoặc có giá trị lớn của một sự vật, sự việc, khiến nó cần được chú ý."},"5293":{"word":"nắm","meaning":"Khép chặt các ngón tay quanh một vật nào đó hoặc siết bàn tay lại thành nắm đấm."},"5294":{"word":"tức thì","meaning":"Mô tả việc gì đó được chuẩn bị hoặc thực hiện ngay lập tức, không có sự trì hoãn hay chuẩn bị trước."},"5295":{"word":"bằng chứng","meaning":"Sự thật, đồ vật hay dấu hiệu dùng để chứng minh điều gì đó là đúng hoặc đã xảy ra."},"5296":{"word":"chứng minh","meaning":"Hành động thể hiện hoặc khẳng định rõ ràng rằng điều gì đó chắc chắn là đúng hoặc chính xác, thường bằng văn bản."},"5297":{"word":"chán ngấy","meaning":"Cảm thấy buồn tẻ, khó chịu do một tình trạng hoặc công việc lặp đi lặp lại."},"5298":{"word":"trái đất","meaning":"Hành tinh lớn hình tròn trong vũ trụ nơi chúng ta sinh sống, với đại dương, đất liền và bầu khí quyển."},"5299":{"word":"vô cùng","meaning":"Diễn tả một sự việc, tình trạng xảy ra ở mức độ cao hơn nhiều so với bình thường hoặc mong đợi."},"5300":{"word":"cho đến nay","meaning":"Mô tả một hành động hoặc trạng thái đã diễn ra từ quá khứ và kéo dài cho đến thời điểm hiện tại."},"5301":{"word":"chi trả","meaning":"Hành động đưa một khoản tiền cho một người hoặc công ty để mua hàng hóa, dịch vụ hoặc trả nợ."},"5302":{"word":"trí tuệ","meaning":"Khả năng học hỏi, tiếp thu ý tưởng mới và sử dụng lý trí để giải quyết vấn đề của một người."},"5303":{"word":"mang theo, sở hữu","meaning":"Giữ hoặc có một cái gì đó bên mình, ví dụ như tiền trong túi."},"5304":{"word":"vác, gánh, đội","meaning":"Mang hoặc đội một vật gì đó trên vai hay trên lưng."},"5305":{"word":"lãnh đạo, người lãnh đạo","meaning":"Người dẫn dắt và điều khiển một nhóm người, ví dụ như một đội hoặc một quốc gia."},"5306":{"word":"đường tắt","meaning":"Con đường ngắn hơn giúp bạn đến một nơi nhanh chóng hơn con đường thông thường."},"5307":{"word":"chi trả, thanh toán","meaning":"Hành động đưa tiền cho ai đó để mua một món đồ hoặc sử dụng một dịch vụ."},"5308":{"word":"chỉ thị, chỉ dẫn","meaning":"Lời nói hoặc văn bản hướng dẫn ai đó cách thực hiện một hành động hoặc nhiệm vụ."},"5309":{"word":"kiến thức","meaning":"Tập hợp các sự thật và kỹ năng mà một người có được thông qua học tập hoặc kinh nghiệm về một chủ đề hay thế giới."},"5310":{"word":"trí thức","meaning":"Người dành nhiều thời gian học tập, suy nghĩ sâu sắc và viết về các ý tưởng phức tạp và xã hội."},"5311":{"word":"địa ngục","meaning":"Nơi mà một người phạm tội bị gửi đến và trừng phạt sau khi chết."},"5312":{"word":"hỗ trợ, giúp đỡ","meaning":"Hành động cung cấp tiền bạc, nguồn lực hoặc sự động viên để giúp ai đó đạt được mục tiêu hoặc vượt qua khó khăn."},"5313":{"word":"địa vị","meaning":"Mức độ quan trọng hoặc vị trí mà một người nắm giữ trong một nhóm hoặc xã hội, thường được thể hiện qua cách người khác đối xử với họ."},"5314":{"word":"chỉ trích, phê bình","meaning":"Hành động chỉ ra một lỗi sai, một sự thật hoặc một vấn đề, thường bằng lời nói hoặc cử chỉ."},"5315":{"word":"chỉ định","meaning":"Hành động chính thức quy định hoặc đặt tên một cái gì đó cho một mục đích hay người cụ thể."},"5316":{"word":"động đất","meaning":"Hiện tượng mặt đất rung chuyển đột ngột và mạnh mẽ, có thể gây đổ nhà cửa, nứt đất."},"5317":{"word":"chi tiêu","meaning":"Tổng số tiền mà một người hoặc công ty dùng để mua hàng hóa, dịch vụ."},"5318":{"word":"mệt mỏi, kiệt sức","meaning":"Cảm thấy rất mệt và không còn sức lực sau khi làm việc vất vả hoặc dùng nhiều năng lượng."},"5319":{"word":"theo dõi, quan sát","meaning":"Nhìn liên tục vào một người hoặc vật để xem điều gì xảy ra hoặc để đảm bảo an toàn cho họ."},"5320":{"word":"tiền giấy","meaning":"Một mảnh giấy phẳng, hình chữ nhật được in đặc biệt, dùng để mua bán."},"5321":{"word":"tầng hầm","meaning":"Khu vực được xây dựng bên dưới không gian sống chính của một tòa nhà, thường có cầu thang đi xuống."},"5322":{"word":"trí tuệ","meaning":"Khả năng hiểu sâu sắc mọi việc và luôn đưa ra những lựa chọn thông minh, hiệu quả trong các tình huống khó khăn."},"5323":{"word":"khôn ngoan","meaning":"Người hiểu rõ các tình huống và đưa ra lựa chọn tốt nhờ kiến thức sâu rộng và kinh nghiệm của mình."},"5324":{"word":"đường thẳng","meaning":"Một đường không cong, đi thẳng."},"5325":{"word":"trực tiếp","meaning":"Liên quan đến một kết nối hoặc tác động xảy ra mà không có bất kỳ bước hay người trung gian nào."},"5326":{"word":"ngay sau khi","meaning":"Thời điểm đến ngay khi một sự kiện kết thúc, không có sự chậm trễ đáng kể."},"5327":{"word":"chẩn đoán","meaning":"Việc bác sĩ kiểm tra để xác định bệnh hoặc vấn đề sức khỏe của một người dựa trên triệu chứng và kết quả xét nghiệm."},"5328":{"word":"rung động","meaning":"Sự chuyển động qua lại nhanh và lặp đi lặp lại của một vật thể từ vị trí ban đầu."},"5329":{"word":"định hướng, con đường sự nghiệp","meaning":"Hướng đi đã định trước về học vấn, đào tạo và công việc mà một người sẽ theo đuổi trong cuộc sống chuyên nghiệp của mình."},"5330":{"word":"chân lý","meaning":"Điều được biết là đúng sự thật và không thể chứng minh là sai."},"5331":{"word":"lời khai, lời trình bày","meaning":"Lời nói hoặc văn bản mà một người đưa ra để cung cấp chi tiết hoặc bằng chứng về một sự việc, đôi khi trong môi trường tòa án hoặc chính thức."},"5332":{"word":"sự thật","meaning":"Sự mô tả chính xác về các sự kiện hoặc tình huống, cho thấy chính xác những gì đã xảy ra hoặc tồn tại."},"5333":{"word":"chân chính, đích thực","meaning":"Miêu tả điều gì đó là bản gốc và đúng như nó vốn có, không giả mạo hay mô phỏng."},"5334":{"word":"nghiêm túc, đứng đắn","meaning":"Hành động thể hiện sự suy nghĩ sâu sắc và quan tâm, đặc biệt về những điều quan trọng, không đùa cợt."},"5335":{"word":"tiến vào, thâm nhập","meaning":"Hành động một người hoặc một công ty di chuyển đến một địa điểm mới hoặc bắt đầu làm việc trong một lĩnh vực khác."},"5336":{"word":"(hậu tố chỉ hành động)","meaning":"Một phần từ nhỏ được thêm vào cuối danh từ để chỉ một hành động cụ thể được thực hiện bằng đối tượng đó."},"5337":{"word":"bệnh tật, bệnh","meaning":"Tình trạng khiến cơ thể hoặc tinh thần không khỏe, gây đau đớn hoặc vấn đề và có các dấu hiệu thể chất rõ ràng."},"5338":{"word":"trật tự","meaning":"Các quy định hoặc sự sắp xếp mà mọi người cần duy trì ở một nơi đông người để tránh hỗn loạn."},"5339":{"word":"sự ghen tuông","meaning":"Cảm giác khó chịu, tức giận khi thấy người mình yêu thương có tình cảm với người khác."},"5340":{"word":"thú vật, dã thú","meaning":"Loài động vật hoang dã, sống ngoài tự nhiên, đôi khi có thể nguy hiểm."},"5341":{"word":"sự phỏng đoán","meaning":"Hành động cố gắng đoán hoặc hiểu một điều gì đó dựa trên một vài thông tin hoặc dấu hiệu có sẵn."},"5342":{"word":"tập đoàn, nhóm","meaning":"Một số người hoặc vật tụ tập lại gần nhau và được coi là một tổng thể thống nhất."},"5343":{"word":"cho vào, nhét vào","meaning":"Đưa một vật từ bên ngoài vào bên trong một vật chứa hoặc đồ vật khác."},"5344":{"word":"tập trung","meaning":"Diễn tả một hành động hoặc hoạt động được thực hiện với sự tập trung và năng lượng cao trong một thời gian hoặc không gian giới hạn."},"5345":{"word":"hành động, việc làm","meaning":"Một hành động hoặc cử chỉ cụ thể được thực hiện bởi một người hoặc một con vật."},"5346":{"word":"sủa","meaning":"Khi một con vật, thường là chó, mở miệng và phát ra âm thanh to, sắc nhọn."},"5347":{"word":"đậm, sẫm","meaning":"Màu sắc trở nên rõ ràng và mạnh mẽ hơn mức bình thường."},"5348":{"word":"vịn, chống, chỉ","meaning":"Đặt tay hoặc một vật nào đó (như gậy) xuống một cách vững chắc để tựa vào hoặc để chỉ một địa điểm cụ thể."},"5349":{"word":"đáng bực mình, gây khó chịu","meaning":"Diễn tả âm thanh, hành động hoặc người nào đó khiến người khác cảm thấy bực bội, khó chịu hoặc hơi tức giận."},"5350":{"word":"số chẵn","meaning":"Số nguyên có thể chia hết cho hai mà không có số dư."},"5351":{"word":"vị mặn","meaning":"Vị mặn là một vị giống như vị của muối."},"5352":{"word":"-thứ","meaning":"Đây là một hậu tố gắn vào sau số hoặc từ để chỉ thứ tự trong một chuỗi."},"5353":{"word":"miếng","meaning":"Miếng là một phần mỏng, dẹt được tách ra từ một vật lớn hơn bằng cách cắt hoặc bẻ."},"5354":{"word":"bị đuổi ra","meaning":"Bị đuổi ra là việc một người hoặc con vật bị buộc phải rời khỏi một nơi bằng vũ lực hoặc trái với ý muốn của họ."},"5355":{"word":"bị truy đuổi","meaning":"Bị truy đuổi là việc một người hoặc con vật chạy nhanh để thoát khỏi sự truy tìm của người khác hoặc con vật khác."},"5356":{"word":"đuổi theo","meaning":"Đuổi theo là đi nhanh sau một người hoặc con vật, cố gắng bắt giữ hoặc đạt được họ."},"5357":{"word":"đuổi theo sau","meaning":"Đuổi theo sau là di chuyển nhanh chóng phía sau ai đó hoặc vật gì đó đã đi trước, cố gắng bắt kịp họ."},"5358":{"word":"đuổi ra","meaning":"Đuổi ra là dùng vũ lực buộc một người hoặc con vật rời khỏi một địa điểm hoặc nhóm."},"5359":{"word":"lẽo đẽo theo sau","meaning":"Lẽo đẽo theo sau là liên tục đi theo một người hoặc con vật, di chuyển đến nhiều nơi khác nhau theo họ."},"5360":{"word":"đuổi tới","meaning":"Đuổi tới là đi nhanh đến vị trí của ai đó, theo sau một người hoặc vật khác."},"5361":{"word":"cau mày","meaning":"Cau mày là nhăn trán và kéo lông mày lại gần nhau, thể hiện sự không hài lòng hoặc lo lắng."},"5362":{"word":"chặt","meaning":"Chặt là dùng rìu hoặc vật sắc bén khác tác động mạnh để cắt hoặc tách gỗ."},"5363":{"word":"được in dấu","meaning":"Được in, đóng dấu, hoặc ghi lại trên một bề mặt."},"5364":{"word":"nhăn mặt","meaning":"Làm cho các cơ trên mặt co lại, tạo thành vẻ mặt không tự nhiên, thường là do đau đớn, khó chịu hoặc không hài lòng."},"5365":{"word":"lòng đường","meaning":"Phần đường dành riêng cho các phương tiện có bánh xe di chuyển."},"5366":{"word":"thà rằng","meaning":"Dùng để bày tỏ sự lựa chọn một điều gì đó dù không hoàn hảo nhưng vẫn tốt hơn những lựa chọn khác không mong muốn."},"5367":{"word":"không nỡ","meaning":"Dùng để diễn tả cảm giác không thể làm hoặc chịu đựng điều gì đó khó khăn, tàn nhẫn hoặc đau lòng."},"5368":{"word":"phân biệt đối xử","meaning":"Sự đối xử không công bằng và khác biệt với một cá nhân hoặc nhóm người dựa trên chủng tộc, giới tính, tuổi tác hoặc đặc điểm khác."},"5369":{"word":"tiền xe","meaning":"Khoản tiền phải trả để sử dụng phương tiện giao thông công cộng như xe buýt, tàu hỏa, hoặc taxi để di chuyển."},"5370":{"word":"làn đường","meaning":"Phần đường được kẻ vạch rõ ràng, nơi các phương tiện giao thông di chuyển theo cùng một hướng."},"5371":{"word":"cấp độ","meaning":"Một cách nhìn nhận hoặc mức độ khác biệt về một vấn đề, giúp hiểu rõ hơn từ một góc độ mới."},"5372":{"word":"dần dần","meaning":"Diễn tả sự việc thay đổi hoặc phát triển một cách chậm rãi, từng chút một theo thời gian."},"5373":{"word":"cửa sổ xe","meaning":"Cửa kính bên hông của các phương tiện như ô tô, tàu hỏa, dùng để nhìn ra ngoài hoặc thông gió."},"5374":{"word":"từng bước","meaning":"Diễn tả sự việc diễn ra hoặc thay đổi một cách chậm rãi, từng bước một qua thời gian."},"5375":{"word":"sự nhầm lẫn","meaning":"Một niềm tin sai lầm hoặc một ý nghĩ không đúng về một tình huống hay sự việc."},"5376":{"word":"người tham dự","meaning":"Người có mặt tại một cuộc họp, hội nghị hoặc sự kiện đặc biệt."},"5377":{"word":"sự tham gia","meaning":"Hành động góp mặt vào một hoạt động, sự kiện hoặc nhóm, thường bằng cách đóng góp hoặc làm gì đó cùng người khác."},"5378":{"word":"thật sự, quả thực","meaning":"Dùng để nhấn mạnh rằng một điều gì đó là đúng, chính xác hoặc có một phẩm chất nhất định."},"5379":{"word":"sự tham khảo","meaning":"Hành động xem xét một nguồn thông tin như sách, tài liệu hoặc hình ảnh để tìm chi tiết hoặc xác nhận sự thật."},"5380":{"word":"sự sáng tác","meaning":"Hành động tạo ra một tác phẩm nghệ thuật, âm nhạc hoặc câu chuyện hoàn toàn mới và độc đáo."},"5381":{"word":"sự sáng tạo","meaning":"Hành động làm cho một cái gì đó chưa từng tồn tại trở nên có mặt, mới mẻ và độc đáo."},"5382":{"word":"tìm ra, phát hiện","meaning":"Tìm thấy hoặc làm lộ ra một cái gì đó bị giấu, mất hoặc chưa từng được biết đến, thường sau khi tìm kiếm."},"5383":{"word":"tìm kiếm khắp nơi","meaning":"Di chuyển liên tục từ nơi này sang nơi khác để tìm kiếm một người, vật hoặc địa điểm cụ thể."},"5384":{"word":"đến thăm (người lớn tuổi/kính trọng)","meaning":"Đi đến nơi có người lớn tuổi hoặc đáng kính để gặp mặt trực tiếp một cách kính cẩn."},"5385":{"word":"kênh (truyền hình/radio)","meaning":"Một tần số hoặc đường truyền cụ thể trên tivi hoặc đài phát thanh để phát sóng các chương trình."},"5386":{"word":"khóa, cài","meaning":"Dùng một thiết bị như chìa khóa, khóa kéo hoặc dây xích để đóng và cố định một vật, ngăn không cho nó mở hoặc di chuyển tự do."},"5387":{"word":"sự chấp nhận","meaning":"Việc chính thức chọn lựa và tiếp nhận một ý tưởng, kế hoạch hoặc vật phẩm để sử dụng."},"5388":{"word":"trách nhiệm","meaning":"Nhiệm vụ hoặc bổn phận mà một người phải thực hiện hoặc gánh vác."},"5389":{"word":"tinh thần trách nhiệm","meaning":"Cảm giác bên trong về bổn phận phải hoàn thành công việc và làm điều đúng đắn."},"5390":{"word":"người phụ trách","meaning":"Người quản lý hoặc giám sát một công việc, dự án hoặc nhóm cụ thể."},"5391":{"word":"chịu trách nhiệm","meaning":"Đảm nhận hoặc gánh vác một nhiệm vụ, bổn phận nào đó."},"5392":{"word":"nhà vô địch","meaning":"Người hoặc đội giành chiến thắng vị trí thứ nhất trong một cuộc thi đấu thể thao hoặc giải đấu khác."},"5393":{"word":"sự xử lý","meaning":"Hành động thực hiện một loạt các bước để giải quyết công việc, vấn đề hoặc thông tin."},"5394":{"word":"sự trừng phạt","meaning":"Hậu quả hoặc hình phạt khó chịu dành cho người đã làm điều sai trái."},"5395":{"word":"lâm vào","meaning":"Vô tình ở trong một tình huống hoặc hoàn cảnh cụ thể, thường là khó khăn."},"5396":{"word":"thiên đường","meaning":"Một nơi yên bình, lý tưởng, nơi mọi người đều hạnh phúc, được cho là nằm trên bầu trời theo nhiều tín ngưỡng tôn giáo."},"5397":{"word":"Công giáo","meaning":"Một tín ngưỡng Kitô giáo toàn cầu do Giáo hoàng lãnh đạo, bao gồm các nghi lễ, nhà thờ và niềm tin cụ thể."},"5398":{"word":"sự chín chắn","meaning":"Trạng thái trở nên có lý trí và suy nghĩ trưởng thành hơn."},"5399":{"word":"triệt để","meaning":"Thực hiện một việc gì đó thật kỹ lưỡng và hoàn chỉnh, không bỏ qua bất cứ chi tiết nào."},"5400":{"word":"đính kèm","meaning":"Vật hoặc tài liệu được gửi kèm theo một cái gì đó khác, như thư hay email."},"5401":{"word":"mối tình đầu","meaning":"Tình cảm lãng mạn đầu tiên mà một người cảm nhận trong đời."},"5402":{"word":"xin","meaning":"Bày tỏ mong muốn một cách trang trọng để ai đó cho hoặc làm một việc gì đó."},"5403":{"word":"hệ thống","meaning":"Một tập hợp các quy tắc, phương pháp hoặc bộ phận được tổ chức làm việc cùng nhau theo một cấu trúc nhất định để đạt được mục tiêu."},"5404":{"word":"thể diện","meaning":"Sự tôn trọng, kính nể mà một người nhận được từ người khác và luôn cố gắng duy trì."},"5405":{"word":"thân nhiệt","meaning":"Lượng nhiệt độ được đo có trong cơ thể của một sinh vật sống."},"5406":{"word":"thể dục dụng cụ","meaning":"Môn thể thao mà người chơi thực hiện các động tác khó về thể chất như nhào lộn, xoay tròn và giữ thăng bằng, thường dùng các dụng cụ đặc biệt."},"5407":{"word":"cân nặng","meaning":"Số đo trọng lượng cơ thể của một người."},"5408":{"word":"đầu-","meaning":"Phần được thêm vào đầu một từ khác để chỉ phần hoặc giai đoạn rất đầu tiên của cái gì đó."},"5409":{"word":"đầu thu","meaning":"Thời gian đầu tiên trong năm khi thời tiết bắt đầu se lạnh và lá cây bắt đầu đổi màu."},"5410":{"word":"đầu đông","meaning":"Thời gian đầu tiên trong năm khi thời tiết bắt đầu trở nên rất lạnh và có thể xuất hiện những dấu hiệu tuyết đầu tiên."},"5411":{"word":"giai đoạn đầu","meaning":"Khoảng thời gian rất sớm khi một việc gì đó bắt đầu hoặc phát triển."},"5412":{"word":"giai đoạn đầu","meaning":"Phần mở đầu của một sự kiện, thường là một trận đấu hay cuộc thi."},"5413":{"word":"người mới bắt đầu","meaning":"Người vừa mới bắt đầu học hoặc làm một kỹ năng hay hoạt động nào đó."},"5414":{"word":"người mới bắt đầu","meaning":"Một cá nhân vừa mới bắt đầu học hoặc làm một kỹ năng, hoạt động cụ thể."},"5415":{"word":"đầu xuân","meaning":"Khoảng thời gian đầu tiên trong năm khi thời tiết trở nên ấm áp hơn và cây cối bắt đầu nảy mầm."},"5416":{"word":"trăng lưỡi liềm","meaning":"Hình ảnh mặt trăng mỏng, cong đặc trưng xuất hiện trên bầu trời đêm trong giai đoạn đầu tiên của nó."},"5417":{"word":"đầu hè","meaning":"Khoảng thời gian đầu tiên trong năm khi thời tiết trở nên nóng đáng kể và ngày dài hơn."},"5418":{"word":"chập tối","meaning":"Khoảng thời gian đầu tiên trong ngày ngay sau khi mặt trời lặn và trước khi trời tối hẳn."},"5419":{"word":"tiêu điểm","meaning":"Điểm cụ thể mà các tia sáng hội tụ để tạo ra hình ảnh rõ nét, hoặc điều chính mà mọi người đang tập trung vào."},"5420":{"word":"sự bồn chồn","meaning":"Cảm giác lo lắng, không yên khiến một người không thể ngồi yên hoặc bình tĩnh, thường thể hiện qua hành động bồn chồn hoặc nét mặt lo âu."},"5421":{"word":"lời mời","meaning":"Lời nhắn bằng văn bản hoặc lời nói yêu cầu ai đó đến một nơi, sự kiện hoặc tham gia vào việc gì đó."},"5422":{"word":"thiệp mời","meaning":"Một thứ được viết ra để mời ai đó đến dự hoặc tham gia vào một sự kiện nào đó."},"5423":{"word":"tổng","meaning":"Chỉ toàn bộ số lượng hoặc tổng số của một thứ gì đó khi tất cả các phần được tính gộp lại."},"5424":{"word":"thủ tướng","meaning":"Người lãnh đạo chính của chính phủ ở một số quốc gia, được chọn để quản lý các công việc của đất nước."},"5425":{"word":"tối đa","meaning":"Mức độ, số lượng hoặc con số lớn nhất có thể đạt được hoặc được cho phép của một điều gì đó."},"5426":{"word":"một cách tối đa","meaning":"Ở mức độ cao nhất hoặc nhiều nhất có thể trong một điều kiện cụ thể."},"5427":{"word":"tối thiểu","meaning":"Mức độ, số lượng hoặc con số nhỏ nhất có thể đạt được hoặc được cho phép của một điều gì đó."},"5428":{"word":"một cách tối thiểu","meaning":"Ở mức độ thấp nhất hoặc ít nhất có thể trong một điều kiện cụ thể."},"5429":{"word":"mới nhất","meaning":"Điều gì đó rất mới và hiện đại nhất, vừa mới xuất hiện hoặc được tạo ra."},"5430":{"word":"cuối cùng","meaning":"Chỉ điểm kết thúc của một chuỗi, quá trình hoặc sự kiện, sau đó không còn gì xảy ra nữa."},"5431":{"word":"đầu tiên","meaning":"Là điểm khởi đầu của một điều gì đó, hoặc xảy ra trước bất kỳ sự kiện hay vật thể nào khác cùng loại."},"5432":{"word":"sự bổ sung","meaning":"Hành động đưa thêm một lượng nào đó vào cái đã có, làm cho tổng số lớn hơn."},"5433":{"word":"cái lạnh","meaning":"Nhiệt độ không khí và môi trường rất thấp, khiến con người run rẩy và tìm kiếm hơi ấm."},"5434":{"word":"sự thúc đẩy","meaning":"Hành động đưa một kế hoạch, dự án hoặc ý tưởng tiến lên một cách vững chắc để thực hiện hoặc đạt được mục tiêu của nó."},"5435":{"word":"thư giới thiệu","meaning":"Đây là một loại văn bản dùng để giới thiệu hoặc tiến cử một người cho một vị trí nhất định."},"5436":{"word":"sự thu hẹp","meaning":"Việc làm cho quy mô, số lượng hoặc phạm vi của một cái gì đó trở nên nhỏ hơn."},"5437":{"word":"đường đi làm","meaning":"Con đường hoặc hành trình mà một người đi từ nhà đến nơi làm việc vào buổi sáng."},"5438":{"word":"sự sinh nở","meaning":"Khoảnh khắc em bé chào đời và rời khỏi cơ thể người mẹ."},"5439":{"word":"xuất thân","meaning":"Nơi, nhóm hoặc hoàn cảnh cụ thể mà một người đến từ đó."},"5440":{"word":"sự tham gia diễn xuất","meaning":"Việc một diễn viên, ca sĩ hay người khác biểu diễn trong một bộ phim, vở kịch hay chương trình truyền hình."},"5441":{"word":"sự xuất bản","meaning":"Quá trình in ấn sách, tạp chí hoặc các tài liệu viết khác và phát hành chúng cho công chúng đọc."},"5442":{"word":"sự xuất hiện","meaning":"Khoảnh khắc một thứ gì đó, như một ý tưởng hay loài vật mới, lần đầu tiên trở nên được nhìn thấy hoặc biết đến."},"5443":{"word":"cú va chạm","meaning":"Lực tác động đột ngột lên một vật thể."},"5444":{"word":"gây sốc","meaning":"Gây ra cảm giác ngạc nhiên, thất vọng hoặc đau khổ đột ngột và rất mạnh mẽ cho ai đó."},"5445":{"word":"lời khuyên","meaning":"Những gợi ý hoặc khuyến nghị hữu ích được đưa ra cho ai đó về những gì họ nên làm trong một tình huống cụ thể."},"5446":{"word":"sự va chạm","meaning":"Sự việc khi hai hoặc nhiều vật đang di chuyển, chẳng hạn như xe cộ, đâm mạnh vào nhau."},"5447":{"word":"việc làm","meaning":"Việc tìm được công việc có lương và bắt đầu làm việc."},"5448":{"word":"thu thập tin tức","meaning":"Việc một phóng viên thu thập thông tin, sự thật để viết bài hoặc làm chương trình."},"5449":{"word":"bên","meaning":"Từ dùng để chỉ một nhóm, tổ chức hoặc cá nhân có liên quan đến một sự việc, vấn đề nào đó."},"5450":{"word":"khía cạnh","meaning":"Một phương diện hoặc khía cạnh riêng biệt của sự vật, ý tưởng hoặc tình huống."},"5451":{"word":"ập đến","meaning":"Chỉ việc bão, gió hoặc tuyết ập đến một cách mạnh mẽ."},"5452":{"word":"rắc","meaning":"Rắc một chất dạng hạt nhỏ hoặc chất lỏng lên bề mặt hoặc vào thức ăn."},"5453":{"word":"con ruột","meaning":"Người con trai do chính mình sinh ra."},"5454":{"word":"cha ruột","meaning":"Người đàn ông là cha đẻ, có quan hệ huyết thống với một đứa trẻ."},"5455":{"word":"mẹ ruột","meaning":"Người phụ nữ là mẹ đẻ, có quan hệ huyết thống với một đứa trẻ."},"5456":{"word":"chị ruột","meaning":"Người chị gái do cùng cha mẹ sinh ra."},"5457":{"word":"anh ruột","meaning":"Người anh trai do cùng cha mẹ sinh ra."},"5458":{"word":"nhà ngoại","meaning":"Nhà của cha mẹ ruột của một người phụ nữ đã có chồng."},"5459":{"word":"nước bọt","meaning":"Chất lỏng trong suốt ở trong miệng người."},"5460":{"word":"sự im lặng","meaning":"Tình trạng không có bất kỳ âm thanh hay tiếng ồn nào."},"5461":{"word":"tối đen","meaning":"Trạng thái không có ánh sáng, khiến không thể nhìn thấy bất cứ thứ gì xung quanh."},"5462":{"word":"chiến dịch","meaning":"Chuỗi hoạt động được lên kế hoạch nhằm quảng bá một sản phẩm, ý tưởng hoặc ứng cử viên chính trị."},"5463":{"word":"rất lớn","meaning":"Miêu tả vật hoặc người có kích thước (chiều rộng, chiều cao hoặc chiều dài) lớn hơn nhiều so với bình thường hoặc mong đợi."},"5464":{"word":"cắt tóc","meaning":"Hành động cắt ngắn tóc của ai đó bằng kéo, hoặc kiểu tóc ngắn sau khi cắt."},"5465":{"word":"giá đỗ","meaning":"Loại rau củ màu trắng, mỏng, có đầu nhỏ màu vàng nhạt, mọc từ đậu xanh và thường được dùng trong salad hoặc món xào."},"5466":{"word":"dễ chịu","meaning":"Miêu tả một nơi hoặc môi trường mang lại cảm giác dễ chịu và thoải mái, thường do nhiệt độ hoặc không khí trong lành."},"5467":{"word":"khò khò","meaning":"Từ mô tả âm thanh thở mạnh, khò khè mà một số người tạo ra từ mũi và cổ họng khi ngủ sâu."},"5468":{"word":"cộp","meaning":"Từ mô tả âm thanh nặng nề, trầm đục phát ra khi vật gì đó lớn hoặc nặng rơi xuống hoặc va chạm mạnh vào bề mặt."},"5469":{"word":"kem","meaning":"Chất béo màu trắng được tách ra từ sữa, dùng làm nguyên liệu cơ bản của bơ, kem lạnh, v.v., hoặc dùng trong nấu ăn."},"5470":{"word":"số tiền lớn","meaning":"Một lượng tiền rất lớn."},"5471":{"word":"con gái lớn","meaning":"Người con gái được sinh ra đầu tiên trong gia đình."},"5472":{"word":"con trai lớn","meaning":"Người con trai được sinh ra đầu tiên trong gia đình."},"5473":{"word":"việc lớn, việc quan trọng","meaning":"Một việc làm quan trọng hoặc khó khăn cần phải giải quyết."},"5474":{"word":"nhà của chú/bác cả","meaning":"Ngôi nhà của người chú hoặc người bác lớn nhất trong gia đình."},"5475":{"word":"chìa khóa","meaning":"Vật dụng bằng kim loại dùng để mở hoặc khóa các ổ khóa của cửa, xe hơi, v.v."},"5476":{"word":"bẩm sinh, trời phú","meaning":"Có sẵn một khả năng hoặc đặc điểm nào đó ngay từ khi sinh ra."},"5477":{"word":"nhận (lương), lãnh (lương)","meaning":"Có được tiền lương hoặc thứ gì đó một cách định kỳ."},"5478":{"word":"bám bẩn, vấy bẩn","meaning":"Bề mặt bị dính hoặc đổi màu do bụi bẩn hay các chất khác bám vào."},"5479":{"word":"bùng cháy, cháy bùng lên","meaning":"Lửa trở nên rất mạnh, với những ngọn lửa sáng và di chuyển nhanh lên phía trên."},"5480":{"word":"người khác","meaning":"Một người nào đó không phải là mình."},"5481":{"word":"sự ra đời, sự sinh ra","meaning":"Thời điểm một em bé hoặc con non chào đời, bắt đầu cuộc sống."},"5482":{"word":"sự thoát hiểm, sự bỏ trốn","meaning":"Hành động nhanh chóng và bí mật rời khỏi một nơi hoặc tình huống nguy hiểm."},"5483":{"word":"Tháp","meaning":"Một cấu trúc cao, hẹp, thường đứng một mình hoặc là một phần của một tòa nhà lớn hơn."},"5484":{"word":"Mặt trời","meaning":"Ngôi sao lớn, sáng chói trên bầu trời, cung cấp ánh sáng và nhiệt cho Trái Đất."},"5485":{"word":"Đốt cháy","meaning":"Làm cho một vật bốc cháy và biến thành tro."},"5486":{"word":"Lựa chọn","meaning":"Chọn một thứ hoặc một phương án trong số nhiều khả năng."},"5487":{"word":"Người giải trí","meaning":"Những người biểu diễn công khai như diễn viên hay ca sĩ để mua vui cho khán giả."},"5488":{"word":"Đường hầm","meaning":"Một lối đi dài, nhân tạo đi dưới lòng đất hoặc xuyên qua núi cho xe cộ hoặc tàu hỏa đi qua."},"5489":{"word":"Vỡ tung","meaning":"Đột ngột bị nứt hoặc nổ tung ra do áp lực, thường kèm theo tiếng động lớn."},"5490":{"word":"Hàm","meaning":"Cấu trúc xương ở mặt người tạo thành miệng và giữ răng."},"5491":{"word":"Trống không","meaning":"Từ dùng để chỉ trạng thái một không gian không có gì cả bên trong."},"5492":{"word":"Bài kiểm tra","meaning":"Một tập hợp các câu hỏi hoặc nhiệm vụ được thiết kế để đánh giá kiến thức, khả năng của ai đó hoặc chất lượng của một thứ gì đó."},"5493":{"word":"Thảo luận","meaning":"Một cuộc trò chuyện chính thức nơi mọi người trao đổi ý tưởng và quan điểm về một chủ đề cụ thể."},"5494":{"word":"Thống kê","meaning":"Các dữ liệu hoặc sự kiện số được thu thập và phân tích để hiển thị thông tin về một điều gì đó."},"5495":{"word":"Sự đi qua, thông qua","meaning":"Hành động di chuyển từ bên này sang bên kia của một ranh giới hoặc chướng ngại vật."},"5496":{"word":"Cơn đau, đau đớn","meaning":"Một cảm giác khó chịu mạnh mẽ về thể chất trong cơ thể."},"5497":{"word":"Sự đi lại, giao thông","meaning":"Sự di chuyển của người, động vật hoặc phương tiện trên đường hoặc qua một khu vực."},"5498":{"word":"Sự nghỉ hưu","meaning":"Giai đoạn một người ngừng làm việc vĩnh viễn, thường là do đã đến tuổi nhất định."},"5499":{"word":"Sự đầu tư","meaning":"Hành động bỏ tiền bạc, thời gian hoặc công sức vào một dự án với hy vọng thu lợi nhuận hoặc lợi ích."},"5500":{"word":"Sự bỏ phiếu","meaning":"Cách thức chính thức để một người bày tỏ sự lựa chọn của mình đối với một ứng cử viên hoặc một phương án."},"5501":{"word":"Đặc biệt, đặc thù","meaning":"Diễn tả một điều gì đó khác biệt đáng kể so với những thứ thông thường, thường do thiết kế, mục đích hoặc khả năng không bình thường."},"5502":{"word":"Cụ thể, nhất định","meaning":"Chỉ một cá nhân, đối tượng hoặc nhóm chính xác trong số nhiều, được phân biệt rõ ràng và không mơ hồ."},"5503":{"word":"Chắc chắn, không sai","meaning":"Khẳng định rằng điều gì đó chắc chắn là đúng hoặc chính xác, không còn chỗ cho sự nghi ngờ."},"5504":{"word":"Khe hở, kẽ hở","meaning":"Một khoảng trống hẹp hoặc vết nứt xuất hiện giữa hai vật thể hoặc trên bề mặt, cho phép ánh sáng hoặc không khí đi qua."},"5505":{"word":"Sự phá hủy","meaning":"Hành động làm hư hại hoặc phá vỡ một thứ gì đó nghiêm trọng đến mức nó không còn tồn tại hoặc không thể sử dụng được nữa."},"5506":{"word":"Đối tác, cộng sự","meaning":"Một người cùng tham gia với một cá nhân hoặc nhóm khác để làm việc chung, chia sẻ hoạt động hoặc theo đuổi mục tiêu chung."},"5507":{"word":"phán đoán","meaning":"Quá trình hình thành ý kiến hoặc đưa ra quyết định sau khi xem xét cẩn thận các sự thật và bằng chứng."},"5508":{"word":"người bán","meaning":"Người hoặc doanh nghiệp cung cấp hàng hóa hoặc dịch vụ cho người khác để đổi lấy tiền."},"5509":{"word":"thẩm phán","meaning":"Viên chức chủ trì tại tòa án, lắng nghe bằng chứng và đưa ra phán quyết trong các tranh chấp pháp lý."},"5510":{"word":"khuỷu tay","meaning":"Khớp nối phần cánh tay trên và cẳng tay, cho phép cánh tay gập lại."},"5511":{"word":"thức ăn nhanh","meaning":"Các bữa ăn như hamburger hay khoai tây chiên được nấu và phục vụ rất nhanh tại nhà hàng."},"5512":{"word":"người hâm mộ","meaning":"Người rất yêu thích hoặc ủng hộ một người nổi tiếng, một đội thể thao hoặc một lĩnh vực cụ thể."},"5513":{"word":"lan rộng","meaning":"Trở nên rộng hơn hoặc dày hơn ở phía dưới so với phía trên."},"5514":{"word":"khá","meaning":"Dùng để chỉ một điều gì đó đúng hoặc xảy ra ở mức độ rõ ràng và đáng chú ý."},"5515":{"word":"xuất bản","meaning":"Tạo ra nhiều bản sao của sách, tạp chí hoặc tác phẩm văn học khác và phát hành chúng cho mọi người mua hoặc đọc."},"5516":{"word":"định kiến","meaning":"Một suy nghĩ hoặc cảm xúc mạnh mẽ, không công bằng về một người hoặc một nhóm người được hình thành trước khi biết họ hoặc có bất kỳ sự thật nào."},"5517":{"word":"tiện lợi","meaning":"Tình huống hoặc vật phẩm giúp một hành động hoặc công việc trở nên đơn giản và dễ thực hiện, tiết kiệm công sức hoặc rắc rối."},"5518":{"word":"dễ dàng","meaning":"Theo một cách suôn sẻ mà không cần hoặc rất ít khó khăn hay nỗ lực."},"5519":{"word":"mở ra, trải ra","meaning":"Được mở hoặc trải ra để lộ rõ cái gì đó."},"5520":{"word":"mở, trải ra","meaning":"Mở hoặc trải vật gì đó như sách hay bản đồ ra cho phẳng và rộng hơn."},"5521":{"word":"đánh giá, nhận xét","meaning":"Lời nói hoặc chữ viết bày tỏ suy nghĩ, nhận định về một người, sản phẩm hay sự kiện."},"5522":{"word":"trung bình","meaning":"Con số thu được bằng cách cộng một nhóm số lại rồi chia tổng đó cho số lượng các số trong nhóm."},"5523":{"word":"bình đẳng","meaning":"Trạng thái mà mọi người đều có quyền lợi, cách đối xử, cơ hội và giá trị như nhau, không có sự khác biệt."},"5524":{"word":"bình thường, tầm thường","meaning":"Có vẻ ngoài hoặc xảy ra theo cách không đặc biệt, độc đáo hay bất ngờ, hòa lẫn với mọi thứ khác."},"5525":{"word":"lúc bình thường, ngày thường","meaning":"Khoảng thời gian mà mọi việc diễn ra theo cách mong đợi hoặc khi một người thực hiện thói quen hàng ngày."},"5526":{"word":"cả đời, suốt đời","meaning":"Toàn bộ thời gian cuộc đời của một người, từ khi sinh ra cho đến khi mất."},"5527":{"word":"hòa bình","meaning":"Tình trạng trong một quốc gia hoặc giữa những người mà không có chiến tranh, xung đột hay cãi vã, cho phép mọi người sống yên ổn cùng nhau."},"5528":{"word":"hòa bình, yên bình","meaning":"Khi một nơi hoặc cảm xúc của một người rất tĩnh lặng và ổn định, không có chiến tranh hay buồn bã."},"5529":{"word":"bãi bỏ, hủy bỏ","meaning":"Khi một quy tắc, hệ thống hoặc kế hoạch chính thức bị loại bỏ hoàn toàn để không còn tồn tại nữa."},"5530":{"word":"ấm cúng, êm ái","meaning":"Khi một nơi hoặc vật gì đó cảm thấy mềm mại và ấm áp dễ chịu, khiến một người cảm thấy thư thái và an toàn."},"5531":{"word":"giấy gói","meaning":"Tấm giấy mỏng, thường có hoa văn hoặc màu sắc đẹp, dùng để bọc quà tặng hoặc các vật phẩm khác."},"5532":{"word":"rộng lớn, đa dạng","meaning":"Chỉ một chủ đề hoặc lĩnh vực có phạm vi bao quát nhiều khía cạnh khác nhau."},"5533":{"word":"bạo lực","meaning":"Hành động dùng sức mạnh vật lý để làm hại, gây thương tích cho người hoặc vật."},"5534":{"word":"bùng nổ (cảm xúc)","meaning":"Sự bộc lộ cảm xúc một cách đột ngột và mạnh mẽ."},"5535":{"word":"tuyết rơi dày","meaning":"Tình trạng tuyết rơi xuống từ trời với lượng rất lớn và tích tụ sâu trên mặt đất."},"5536":{"word":"mưa lớn","meaning":"Tình trạng mưa rơi xuống từ trời với lượng rất lớn và nhanh."},"5537":{"word":"bề mặt","meaning":"Lớp ngoài cùng của một vật thể mà ta có thể nhìn thấy và chạm vào."},"5538":{"word":"tiêu chuẩn","meaning":"Một quy tắc hoặc mức độ cố định dùng để đo lường, đánh giá chất lượng hoặc làm mẫu chung."},"5539":{"word":"ngôn ngữ chuẩn","meaning":"Hình thức ngôn ngữ được coi là đúng và được sử dụng rộng rãi trong giáo dục, giao tiếp chính thức."},"5540":{"word":"bìa sách","meaning":"Lớp ngoài cùng của một cuốn sách, tạp chí hoặc ấn phẩm, thường có tựa đề và thiết kế."},"5541":{"word":"múc","meaning":"Dùng thìa hoặc dụng cụ để lấy một phần thức ăn hoặc chất lỏng từ vật này sang vật khác."},"5542":{"word":"cỏ","meaning":"Loại thực vật thân mềm màu xanh lá, lá hẹp, mọc dày đặc trên mặt đất và thường cần được cắt tỉa."},"5543":{"word":"tuột ra","meaning":"Đồ vật đang bị buộc, bị thắt hoặc bị rối trở lại trạng thái ban đầu."},"5544":{"word":"-phẩm","meaning":"Hậu tố chỉ một vật được tạo ra hoặc trồng để bán hoặc sử dụng."},"5545":{"word":"độ rộng","meaning":"Kích thước từ bên này sang bên kia của một bộ quần áo hoặc một mảnh vải."},"5546":{"word":"ấp","meaning":"Giữ một thứ gì đó sát vào cơ thể, thường bằng tay hoặc cánh, như chim giữ trứng cho ấm."},"5547":{"word":"tỏa ra","meaning":"Mùi hương tỏa ra hoặc lan đi từ một vật."},"5548":{"word":"phong phú","meaning":"Có số lượng rất lớn một thứ gì đó, nhiều hơn mức cần thiết hoặc bình thường."},"5549":{"word":"phong tục","meaning":"Cách ứng xử hoặc làm việc truyền thống đã được người dân ở một khu vực cụ thể thực hành từ lâu."},"5550":{"word":"chuyên nghiệp","meaning":"Người được trả tiền để thực hiện một hoạt động hoặc môn thể thao mà người khác làm để giải trí, thể hiện trình độ kỹ năng cao."},"5551":{"word":"ghi chép","meaning":"Hoạt động ghi lại thông tin hoặc ý tưởng quan trọng, thường trong khi nghe giảng hoặc học tập."},"5552":{"word":"bắt buộc","meaning":"Một điều tuyệt đối phải được thực hiện, có được hoặc hiện diện để đạt được một mục đích cụ thể."},"5553":{"word":"thiết yếu","meaning":"Mô tả một điều vô cùng quan trọng và không thể thiếu, vì nó là nền tảng để một điều khác tồn tại hoặc hoạt động."},"5554":{"word":"nhu yếu phẩm","meaning":"Những thứ rất quan trọng mà một người phải có cho một hoạt động cụ thể hoặc cho cuộc sống hàng ngày."},"5555":{"word":"sự cần thiết","meaning":"Lý do hoặc điều kiện rõ ràng cho thấy tại sao một điều gì đó là hoàn toàn cần thiết và không thể bỏ qua."},"5556":{"word":"cái cớ","meaning":"Việc đưa ra lý do để tránh những điều không mong muốn hoặc che giấu sự thật."},"5557":{"word":"dưới","meaning":"Vị trí hoặc hướng thấp hơn một điểm hoặc vật thể khác."},"5558":{"word":"mà nói","meaning":"Từ dùng để thể hiện sự nhận ra hoặc đồng ý với điều gì đó quan trọng về chủ đề đang được nói đến."},"5559":{"word":"Thượng đế","meaning":"Đấng tối cao được mọi người tôn thờ trong nhiều tôn giáo như là Đấng tạo hóa và cai trị vũ trụ."},"5560":{"word":"quá","meaning":"Một trạng từ dùng để thể hiện rằng điều gì đó đang hiện diện hoặc xảy ra ở mức độ rất cực đoan hoặc lớn bất thường."},"5561":{"word":"dù sao đi nữa","meaning":"Người nói dùng từ này để giới thiệu một chủ đề mới hoặc để xác nhận điều gì đó bất kể những tuyên bố trước đó."},"5562":{"word":"trình độ học vấn","meaning":"Khả năng bao gồm kiến thức hoặc kỹ năng mà một người đã có được thông qua việc học ở trường."},"5563":{"word":"học thuật","meaning":"Một lĩnh vực kiến thức hoặc nghiên cứu cụ thể, thường được theo đuổi ở các trường đại học, như sinh học, lịch sử hoặc văn học."},"5564":{"word":"phụ huynh","meaning":"Người lớn chịu trách nhiệm về một đứa trẻ đang theo học tại một trường học hoặc chương trình giáo dục."},"5565":{"word":"học phí","meaning":"Số tiền phải trả cho một tổ chức để một người nhận được sự giáo dục hoặc hướng dẫn."},"5566":{"word":"đồ dùng học tập","meaning":"Các vật phẩm khác nhau như bút chì, vở và thước kẻ, mà một người sử dụng cho các hoạt động học tập trong môi trường giáo dục."},"5567":{"word":"Hận","meaning":"Hận là cảm giác buồn khổ, tức giận sâu sắc kéo dài vì một chuyện gì đó không công bằng hoặc mất mát."},"5568":{"word":"Giới hạn","meaning":"Giới hạn là điểm cuối cùng hoặc mức tối đa mà một cái gì đó có thể đạt tới hoặc không thể vượt qua."},"5569":{"word":"Chính giữa","meaning":"Chính giữa là điểm hoặc khu vực ở vị trí trung tâm, cách đều tất cả các phía."},"5570":{"word":"Giữa mùa đông","meaning":"Giữa mùa đông là giai đoạn lạnh nhất của mùa đông, thường có nhiệt độ thấp nhất và nhiều tuyết rơi."},"5571":{"word":"Rõ rệt, đáng kể","meaning":"Rõ rệt, đáng kể có nghĩa là một sự thay đổi hoặc khác biệt lớn, dễ nhận thấy."},"5572":{"word":"Giới hạn","meaning":"Giới hạn là điểm dừng hoặc mức tối đa mà một cái gì đó không thể vượt qua."},"5573":{"word":"Mang tính Hàn Quốc","meaning":"Mang tính Hàn Quốc là có những đặc điểm, phong cách hoặc cách sống riêng biệt của Hàn Quốc."},"5574":{"word":"Cùng một lúc","meaning":"Cùng một lúc là nhiều hành động hoặc sự việc xảy ra vào cùng một thời điểm, không tách rời."},"5575":{"word":"Giữa trưa","meaning":"Giữa trưa là thời điểm chính xác ở giữa ngày, thường là khoảng 12 giờ trưa, khi mặt trời lên cao nhất."},"5576":{"word":"Một cái nhìn","meaning":"Một cái nhìn là khả năng nhận biết hoặc hiểu rõ điều gì đó ngay lập tức chỉ bằng một lần nhìn nhanh."},"5577":{"word":"Một hai","meaning":"Một hai là số lượng rất nhỏ, chỉ một vật hoặc hai vật gộp lại."},"5578":{"word":"Một lời, một câu","meaning":"Một lời, một câu là một âm thanh hoặc dấu hiệu riêng biệt dùng để diễn đạt ý nghĩa trong giao tiếp."},"5579":{"word":"nửa đêm","meaning":"Thời điểm ở giữa đêm khuya."},"5580":{"word":"khoảnh khắc","meaning":"Một khoảng thời gian rất ngắn."},"5581":{"word":"giữa hè","meaning":"Thời điểm trung tâm của mùa hè, thường rất nóng."},"5582":{"word":"cao điểm","meaning":"Thời điểm một sự việc đang ở mức độ phát triển mạnh nhất hoặc cao nhất."},"5583":{"word":"hơn nữa","meaning":"Biểu thị sự tăng lên rõ rệt về mức độ, cường độ hoặc phạm vi của một cái gì đó."},"5584":{"word":"mặt khác","meaning":"Dùng để giới thiệu một quan điểm khác hoặc một yếu tố tương phản với điều vừa được đề cập."},"5585":{"word":"trả góp","meaning":"Cách thức thanh toán một món đồ có giá trị bằng nhiều khoản nhỏ định kỳ thay vì trả một lần."},"5586":{"word":"tùy tiện","meaning":"Hành động hoặc nói năng mà không cân nhắc kỹ lưỡng, thiếu sự cẩn trọng hoặc tôn trọng."},"5587":{"word":"người trúng tuyển","meaning":"Người đạt được tư cách hoặc địa vị nhất định bằng cách vượt qua một kỳ thi, kiểm tra hoặc sàng lọc."},"5588":{"word":"hợp lý","meaning":"Mô tả điều gì đó có ý nghĩa và dựa trên lý lẽ và sự thật vững chắc."},"5589":{"word":"thỏa thuận","meaning":"Sự hiểu biết chung hoặc quyết định đạt được giữa hai hoặc nhiều người sau khi thảo luận."},"5590":{"word":"kết hợp","meaning":"Kết hợp các phần hoặc số lượng riêng lẻ lại với nhau để tạo thành một tổng thể lớn hơn."},"5591":{"word":"sự phản đối","meaning":"Hành động thể hiện sự không đồng tình, phản đối mạnh mẽ đối với điều gì đó."},"5592":{"word":"tổn hại","meaning":"Tình trạng bị thiệt hại, tổn thương hoặc gặp điều không tốt."},"5593":{"word":"giải pháp","meaning":"Kế hoạch hoặc biện pháp cụ thể được đưa ra để khắc phục một vấn đề hoặc khó khăn."},"5594":{"word":"hoàn thành","meaning":"Thực hiện và kết thúc thành công một công việc khó khăn hoặc nhiệm vụ."},"5595":{"word":"tương ứng","meaning":"Chỉ cái gì đó có liên quan trực tiếp đến một tình huống, đối tượng hoặc nhóm cụ thể."},"5596":{"word":"có hại","meaning":"Gây ra tổn thương, thiệt hại hoặc tác động tiêu cực đến ai đó hoặc cái gì đó."},"5597":{"word":"sự giải phóng","meaning":"Trạng thái được tự do, không còn bị giam giữ hoặc hạn chế."},"5598":{"word":"sự giải thích","meaning":"Hành động tìm ra và làm rõ ý nghĩa hoặc tầm quan trọng của từ ngữ, biểu tượng hoặc sự kiện."},"5599":{"word":"lời giải thích","meaning":"Mô tả bằng lời nói hoặc văn bản giúp một chủ đề phức tạp dễ hiểu hơn."},"5600":{"word":"sự giải tỏa","meaning":"Hành động loại bỏ một vấn đề khó khăn hoặc tình huống không mong muốn."},"5601":{"word":"bờ biển","meaning":"Nơi đất liền và biển gặp nhau."},"5602":{"word":"gây hại","meaning":"Gây ra ảnh hưởng xấu hoặc làm cho tình trạng của ai đó hoặc cái gì đó trở nên tồi tệ hơn."},"5603":{"word":"cốt lõi","meaning":"Phần quan trọng hoặc cơ bản nhất của một sự vật, sự việc, xung quanh đó mọi thứ khác được xây dựng hoặc phụ thuộc."},"5604":{"word":"ánh nắng","meaning":"Những luồng ánh sáng chói chang và thường ấm áp phát ra từ mặt trời."},"5605":{"word":"sự thi hành","meaning":"Việc dùng hoặc thực hiện quyền lực, quyền hạn hoặc một điều gì đó."},"5606":{"word":"hành vi","meaning":"Một việc cụ thể mà một người thực hiện hoặc tiến hành, có thể quan sát được."},"5607":{"word":"hành chính","meaning":"Hệ thống tổ chức và quản lý các hoạt động, nhiệm vụ chính thức của một chính phủ hoặc tổ chức."},"5608":{"word":"thực hiện","meaning":"Đặt vào hoạt động, tiến hành hoặc hoàn thành một nhiệm vụ, công việc cụ thể."},"5609":{"word":"nhang","meaning":"Một vật được đốt để tạo ra mùi thơm, thường dùng trong đám tang hoặc lễ cúng tổ tiên."},"5610":{"word":"hương thơm","meaning":"Mùi dễ chịu, thơm tho."},"5611":{"word":"sự nâng cao","meaning":"Quá trình làm cho một thứ gì đó trở nên tốt hơn về chất lượng, tình trạng hoặc kỹ năng."},"5612":{"word":"sự cho phép","meaning":"Sự xác nhận hoặc đồng ý chính thức từ một cơ quan có thẩm quyền cho phép ai đó làm gì."},"5613":{"word":"sự chấp nhận","meaning":"Việc không cấm đoán hoặc cho phép một điều gì đó xảy ra, hoặc cho phép ai đó tiến hành một hành động."},"5614":{"word":"khà khà","meaning":"Tiếng cười trầm ấm, nhẹ nhàng phát ra để thể hiện sự vui vẻ hoặc thích thú."},"5615":{"word":"cũ kỹ","meaning":"Đã dùng lâu ngày nên bị hỏng hóc, hao mòn và không còn tốt như ban đầu."},"5616":{"word":"gồ ghề, hiểm trở","meaning":"Đường hoặc bề mặt không bằng phẳng, có nhiều chướng ngại vật, khó đi lại."},"5617":{"word":"đi lang thang, lạc đường","meaning":"Di chuyển không có phương hướng rõ ràng, thường là vì không biết đường."},"5618":{"word":"đếm","meaning":"Xác định số lượng chính xác của vật thể bằng cách gọi tên các con số lần lượt cho từng vật thể."},"5619":{"word":"bơi, bơi lội","meaning":"Di chuyển trong nước bằng cách cử động tay và chân."},"5620":{"word":"người hiện đại","meaning":"Những người sống trong thời đại hiện tại, thường trải nghiệm cuộc sống trong xã hội phát triển công nghệ."},"5621":{"word":"hiện đại, mang tính hiện đại","meaning":"Liên quan hoặc thể hiện phong cách, ý tưởng và công nghệ phổ biến trong thời kỳ hiện tại."},"5622":{"word":"hiện tượng","meaning":"Một sự kiện, sự việc hoặc điều kiện cụ thể có thể được quan sát hoặc nhìn thấy."},"5623":{"word":"thực tế, hiện thực","meaning":"Toàn bộ những gì tồn tại và xảy ra trên thế giới, khác biệt với những gì được tưởng tượng hoặc mong ước."},"5624":{"word":"thực tế, có tính thực tế","meaning":"Nghĩ hoặc hành động theo cách xem xét mọi việc đúng như bản chất của chúng, tập trung vào những gì có thể và thực tiễn."},"5625":{"word":"hiện trường, địa điểm","meaning":"Khu vực vật lý cụ thể nơi một sự kiện xảy ra hoặc công việc/hoạt động được thực hiện."},"5626":{"word":"hợp tác, sự hợp tác","meaning":"Khi nhiều cá nhân hoặc nhóm cùng nhau nỗ lực để đạt được một mục tiêu chung."},"5627":{"word":"sự hợp tác","meaning":"Việc cùng nhau hỗ trợ, giúp đỡ để hoàn thành một nhiệm vụ hoặc công việc."},"5628":{"word":"-kiểu","meaning":"Vĩ tố chỉ một loại, mô hình hoặc cách cấu trúc của cái gì đó."},"5629":{"word":"anh (kính trọng)","meaning":"Từ dùng bởi nam giới để gọi hoặc xưng hô với anh trai hoặc anh họ lớn hơn mình (hình thức kính trọng)."},"5630":{"word":"sự hình thành","meaning":"Quá trình một vật bắt đầu tồn tại hoặc có một cấu trúc, tính chất cụ thể."},"5631":{"word":"hình thức","meaning":"Thiết kế, sắp xếp hoặc cấu trúc bên ngoài cụ thể của một cái gì đó, thường theo một số quy tắc hoặc quy ước."},"5632":{"word":"hoàn cảnh","meaning":"Toàn bộ sự kiện và điều kiện tồn tại vào một thời điểm nhất định và ảnh hưởng đến ai đó hoặc cái gì đó."},"5633":{"word":"lợi ích","meaning":"Điều hữu ích hoặc mong muốn được ban cho ai đó, giúp cuộc sống của họ dễ dàng hoặc dễ chịu hơn."},"5634":{"word":"thiện cảm","meaning":"Cảm xúc tốt đẹp dành cho một đối tượng cụ thể."},"5635":{"word":"sự tò mò","meaning":"Cảm giác mạnh mẽ khiến ai đó muốn khám phá, điều tra hoặc tìm hiểu thông tin mới."},"5636":{"word":"túi áo/quần","meaning":"Một phần giống như túi nhỏ được may vào quần áo, dùng để đựng những vật nhỏ."},"5637":{"word":"hô hấp","meaning":"Quá trình vật lý đưa không khí vào và ra khỏi phổi."},"5638":{"word":"la mắng","meaning":"Nói chuyện với ai đó một cách giận dữ vì họ đã làm điều gì đó sai, thường là với giọng điệu cao hơn."},"5639":{"word":"số lẻ","meaning":"Số nguyên không chia hết cho hai."},"5640":{"word":"quảng bá","meaning":"Hoạt động truyền thông tin về sản phẩm, công ty, hoặc ý tưởng đến nhiều người để tạo cái nhìn tích cực."},"5641":{"word":"lũ lụt","meaning":"Tình trạng một lượng lớn nước bao phủ khu vực đất thường khô ráo."},"5642":{"word":"- hóa","meaning":"Một hậu tố cho biết quá trình thay đổi cái gì đó thành một trạng thái hoặc hình thức cụ thể."},"5643":{"word":"giấy vệ sinh","meaning":"Loại giấy mềm dùng để lau chùi sau khi đi vệ sinh."},"5644":{"word":"chủ đề","meaning":"Ý tưởng hoặc sự việc cụ thể mà mọi người đang nói hoặc viết về."},"5645":{"word":"quang đãng","meaning":"Mô tả thời tiết có nắng, bầu trời ít hoặc không có mây."},"5646":{"word":"ào","meaning":"Mô tả một hành động hoặc cảm giác xảy ra rất nhanh và mạnh mẽ, lan rộng hoặc có tác động lớn."},"5647":{"word":"mở rộng","meaning":"Quá trình làm cho cái gì đó lớn hơn về kích thước, phạm vi hoặc số lượng."},"5648":{"word":"đảm bảo","meaning":"Hành động đảm bảo một món đồ hoặc nguồn lực cần thiết sẵn sàng và có thể được sử dụng."},"5649":{"word":"lan truyền","meaning":"Quá trình một cái gì đó di chuyển từ một nơi ra để bao phủ một khu vực rộng hơn hoặc ảnh hưởng đến nhiều cá nhân hơn."},"5650":{"word":"sự chắc chắn","meaning":"Một niềm tin mạnh mẽ rằng điều gì đó là đúng hoặc hợp lý, giúp một người hành động mà không nghi ngờ."},"5651":{"word":"chắc chắn, xác đáng","meaning":"Diễn tả việc gì đó được biết là đúng hoặc chắc chắn sẽ xảy ra, không còn nghi ngờ gì."},"5652":{"word":"chắc chắn, rõ ràng","meaning":"Diễn tả một hành động được thực hiện một cách không còn nghi ngờ gì, khiến cho mọi thứ trở nên rõ ràng và cụ thể."},"5653":{"word":"mở rộng","meaning":"Quá trình làm cho cái gì đó lớn hơn về kích thước, diện tích hoặc phạm vi."},"5654":{"word":"môi trường","meaning":"Toàn bộ các điều kiện vật lý, sinh vật và ảnh hưởng xung quanh và tác động đến một sinh vật hoặc một nơi."},"5655":{"word":"ảo tưởng, huyễn mộng","meaning":"Điều gì đó dường như có thật nhưng không phải, hoặc một ý tưởng giống như giấc mơ chỉ tồn tại trong trí tưởng tượng và có thể không thể xảy ra trong thực tế."},"5656":{"word":"sức sống, sinh khí","meaning":"Năng lượng thể chất hoặc tinh thần mạnh mẽ làm cho một người hoặc vật trở nên sống động, tràn đầy sức sống và có thể làm được nhiều việc."},"5657":{"word":"năng động, hoạt bát","meaning":"Diễn tả một người hay vận động, tham gia vào nhiều hoạt động và không thích ở yên hoặc nhàn rỗi."},"5658":{"word":"một cách năng nổ, sôi nổi","meaning":"Diễn tả một hành động được thực hiện với nhiều chuyển động, nhiệt huyết hoặc sức mạnh."},"5659":{"word":"tận dụng, sử dụng","meaning":"Hành động tìm kiếm một cách sử dụng thực tế cho cái gì đó hoặc sử dụng tốt một nguồn lực cho một mục đích cụ thể."},"5660":{"word":"hội đàm, cuộc họp","meaning":"Một cuộc họp chính thức nơi mọi người tụ tập, thường là quanh bàn, để thảo luận về các vấn đề quan trọng."},"5661":{"word":"hồi phục, phục hồi","meaning":"Quá trình trở lại trạng thái bình thường hoặc khỏe mạnh sau một bệnh tật, chấn thương hoặc tình huống khó khăn."},"5662":{"word":"hội thoại, đàm thoại","meaning":"Hành động hai hoặc nhiều người nói chuyện với nhau, trao đổi lời nói và ý tưởng, đặc biệt là khi luyện tập một ngôn ngữ nước ngoài."},"5663":{"word":"hiệu quả","meaning":"Là cách làm đạt được kết quả mong muốn hoặc tạo ra tác động mạnh mẽ, rõ rệt."},"5664":{"word":"hiếu thảo","meaning":"Tấm lòng kính trọng và chăm sóc sâu sắc mà con cái dành cho cha mẹ và người lớn tuổi."},"5665":{"word":"hiệu quả","meaning":"Là cách làm việc giúp tiết kiệm thời gian và năng lượng mà vẫn hoàn thành tốt công việc."},"5666":{"word":"con trai hiếu thảo","meaning":"Người con trai thể hiện sự kính trọng và chăm sóc đặc biệt đối với cha mẹ mình."},"5667":{"word":"ứng cử viên","meaning":"Người được đề cử hoặc tự ứng cử vào một vị trí, chức vụ hoặc giải thưởng nào đó."},"5668":{"word":"hối tiếc","meaning":"Diễn tả cảm giác buồn bã khi một hành động hoặc sự kiện trong quá khứ không như ý và muốn thay đổi nó."},"5669":{"word":"huấn luyện","meaning":"Chuỗi hoạt động lặp đi lặp lại nhằm dạy các kỹ năng cụ thể hoặc cải thiện năng lực thể chất, tinh thần."},"5670":{"word":"ăn cắp","meaning":"Lấy tài sản của người khác mà không được phép hoặc không trả tiền."},"5671":{"word":"khu nghỉ dưỡng","meaning":"Nơi thích hợp để thư giãn và chăm sóc sức khỏe."},"5672":{"word":"sự bắt chước","meaning":"Hành động mô phỏng lời nói hoặc hành vi của người khác hoặc động vật, thường để gây cười hoặc chế nhạo."},"5673":{"word":"dòng chảy","meaning":"Sự chuyển động liên tục của chất lỏng, khí, hoặc thậm chí con người, sự vật, thường theo một hướng ổn định."},"5674":{"word":"đen trắng","meaning":"Là sự kết hợp hoặc trạng thái của hai màu đen và trắng."},"5675":{"word":"rung lắc","meaning":"Một vật di chuyển không ổn định, lúc lắc qua lại."},"5676":{"word":"dấu vết","meaning":"Phần còn lại hoặc dấu hiệu cho thấy một vật gì đó đã từng ở đó hoặc đã đi qua."},"5677":{"word":"phổ biến","meaning":"Được nhìn thấy hoặc tìm thấy rất thường xuyên, hoặc xảy ra nhiều ở nhiều nơi."},"5678":{"word":"thường xuyên","meaning":"Một hành động hoặc sự kiện xảy ra nhiều lần hoặc với tần suất cao."},"5679":{"word":"chảy ra","meaning":"Chất lỏng, khí hoặc người di chuyển đều đặn từ bên trong ra bên ngoài."},"5680":{"word":"chảy xuống","meaning":"Nước hoặc chất lỏng khác chảy hoặc rơi xuống một nơi thấp hơn."},"5681":{"word":"đất","meaning":"Vật chất bao phủ bề mặt Trái Đất, bao gồm các hạt nhỏ."},"5682":{"word":"hấp thụ","meaning":"Quá trình một vật liệu ngấm hoặc tiếp nhận hoàn toàn một chất khác, ví dụ như chất lỏng hoặc ánh sáng."},"5683":{"word":"sự hứng thú","meaning":"Cảm giác muốn biết về điều gì đó hoặc tham gia vào một hoạt động vì nó có vẻ thú vị hoặc quan trọng."},"5684":{"word":"thú vị","meaning":"Một điều gì đó thu hút hoàn toàn sự chú ý của một người và khiến họ muốn tìm hiểu thêm."},"5685":{"word":"sự phấn khích","meaning":"Cảm giác hạnh phúc hoặc mong chờ mãnh liệt, thường được thể hiện bằng hơi thở nhanh hoặc cử động nhanh."},"5686":{"word":"tản ra","meaning":"Nhiều vật nhỏ hoặc một nhóm người di chuyển tách rời và đi về các hướng khác nhau."},"5687":{"word":"hết sức, dốc sức","meaning":"Diễn tả việc dùng toàn bộ sức mạnh cơ thể để thực hiện một hành động nào đó."},"5688":{"word":"cố gắng, nỗ lực","meaning":"Dành nhiều năng lượng tinh thần hoặc thể chất vào việc đạt được mục tiêu hay hoàn thành công việc."},"5689":{"word":"yếu ớt, không sức lực","meaning":"Diễn tả việc thực hiện hành động với rất ít năng lượng thể chất, thường trông chậm chạp hoặc không có tinh thần."},"5690":{"word":"mạnh mẽ, đầy sức sống","meaning":"Diễn tả cái gì đó có nhiều năng lượng và sức mạnh thể chất, hoặc một âm thanh đầy đặn và uy lực."},"5691":{"word":"bờ, mép, ven","meaning":"Phần đất nằm dọc theo một vùng nước như sông hoặc hồ."},"5692":{"word":"phố, khu vực (hậu tố)","meaning":"Hậu tố dùng để chỉ một phần cụ thể của thành phố hoặc thị trấn, thường được xác định bởi loại hình nhà cửa hoặc công trình."},"5693":{"word":"giá (hậu tố)","meaning":"Hậu tố dùng để chỉ số tiền mà một thứ gì đó có thể được mua hoặc bán."},"5694":{"word":"thanh nhạc, nhạc ca khúc","meaning":"Một tác phẩm âm nhạc được viết cho một ca sĩ hát đơn và một cây đàn piano, thường dựa trên một bài thơ, được biểu diễn trong một buổi hòa nhạc trang trọng."},"5695":{"word":"chế biến, gia công","meaning":"Chuỗi hành động được sử dụng để thay đổi nguyên liệu thô, như thực phẩm, thành một sản phẩm khác hoặc sản phẩm hoàn chỉnh."},"5696":{"word":"hộ gia đình, gia đình","meaning":"Một nhóm người sống cùng nhau trong một nhà hoặc một đơn vị nhà ở."},"5697":{"word":"càng nhiều càng tốt, hết sức có thể","meaning":"Diễn tả một hành động nên được thực hiện ở mức độ cao nhất hoặc trong phạm vi lớn nhất mà điều kiện cho phép."},"5698":{"word":"mảnh mai, thon dài","meaning":"Diễn tả một vật hoặc bộ phận cơ thể có chiều rộng hoặc chu vi rất nhỏ so với chiều dài của nó."},"5699":{"word":"sợi","meaning":"Đây là một phần vật liệu dài, mỏng và linh hoạt như tóc hoặc chỉ."},"5700":{"word":"cây xanh đường phố","meaning":"Những cây này được trồng dọc theo các con đường để tạo cảnh quan và bóng mát."},"5701":{"word":"che khuất","meaning":"Hành động làm cho cái gì đó khó nhìn thấy bằng cách đặt một vật khác chắn phía trước."},"5702":{"word":"mặt nạ","meaning":"Vật dùng để che mặt, thường là để giấu danh tính hoặc phục vụ cho biểu diễn."},"5703":{"word":"dòng họ","meaning":"Tập hợp tất cả những người có chung tổ tiên, được xem như một nhóm trong suốt lịch sử."},"5704":{"word":"gia trưởng","meaning":"Thuộc về hệ thống hoặc xã hội mà trong đó đàn ông nắm quyền lực chính, thường là người đàn ông lớn tuổi nhất."},"5705":{"word":"việc nhà","meaning":"Các công việc nội trợ, dọn dẹp nhà cửa và chăm sóc gia đình hàng ngày."},"5706":{"word":"sự gia tốc","meaning":"Quá trình làm cho cái gì đó chuyển động hoặc phát triển với tốc độ nhanh hơn nhiều."},"5707":{"word":"gai","meaning":"Một mấu nhọn, sắc bén mọc trên thân hoặc cành của một số loài thực vật."},"5708":{"word":"tan biến","meaning":"Trở nên hoàn toàn không còn hoặc biến mất, đặc biệt là cảm giác như mệt mỏi hay giận dữ."},"5709":{"word":"đàn Gayageum","meaning":"Một loại nhạc cụ dây truyền thống của Hàn Quốc, dài và hẹp, làm bằng gỗ, được chơi bằng cách gảy dây."},"5710":{"word":"nhà","meaning":"Công trình kiến trúc được xây dựng để con người sinh sống, thường có các phòng, mái nhà và tường."},"5711":{"word":"giới âm nhạc","meaning":"Toàn bộ các doanh nghiệp, nghệ sĩ và những người tham gia sản xuất, phân phối các bài hát phổ biến."},"5712":{"word":"mép","meaning":"Phần ngoài cùng hoặc đường giới hạn của một vật thể, nơi nó kết thúc."},"5713":{"word":"sự gia tăng","meaning":"Hành động làm cho gánh nặng, vấn đề hoặc cảm xúc trở nên mạnh hơn hoặc nghiêm trọng hơn."},"5714":{"word":"gọn gàng","meaning":"Theo một cách thức được sắp xếp có trật tự, thẳng hàng và sạch sẽ."},"5715":{"word":"khả năng ca hát","meaning":"Kỹ năng của một người trong việc thể hiện các nốt nhạc chỉ bằng giọng hát của mình."},"5716":{"word":"gia súc","meaning":"Các loài động vật như bò, lợn, hoặc gà được nuôi trong nông trại để phục vụ con người, ví dụ như để lấy thực phẩm hoặc sức lao động."},"5717":{"word":"thủ phạm","meaning":"Người thực hiện hành động gây ra thiệt hại hoặc thương tích rõ ràng cho người khác."},"5718":{"word":"sự quan tâm rộng rãi","meaning":"Sự chú ý của xã hội và được nhiều người yêu thích."},"5719":{"word":"các nơi","meaning":"Một loạt các địa điểm hoặc khu vực địa lý khác nhau."},"5720":{"word":"thỉnh thoảng","meaning":"Xảy ra hoặc xuất hiện với những khoảng thời gian gián đoạn rõ rệt, không liên tục."},"5721":{"word":"ngắn gọn","meaning":"Miêu tả cái gì đó được diễn đạt chỉ bằng những từ hoặc đặc điểm thiết yếu, không có thêm thắt không cần thiết."},"5722":{"word":"đơn giản","meaning":"Miêu tả một vật thể hoặc phong cách có rất ít chi tiết, trang trí hoặc yếu tố phức tạp."},"5723":{"word":"tha thiết","meaning":"Với mong muốn rất mạnh mẽ và sâu sắc về điều gì đó sẽ xảy ra hoặc được nhận."},"5724":{"word":"gián tiếp","meaning":"Trạng thái không trực tiếp mà thông qua một người hoặc vật trung gian khác."},"5725":{"word":"giữ gìn, cất giữ","meaning":"Hành động giữ lại một vật hoặc kỷ niệm quý giá cẩn thận trong một thời gian dài."},"5726":{"word":"mài","meaning":"Làm cho vật gì đó trở nên sắc bén hơn bằng cách ma sát."},"5727":{"word":"cây sậy, cây lau","meaning":"Một loại cây thân rỗng, cao và mỏng, thường mọc thành bụi ở những vùng đất ẩm ướt, đầm lầy."},"5728":{"word":"xúc động, cảm kích","meaning":"Cảm giác vui sướng, biết ơn hoặc ngưỡng mộ mạnh mẽ, sâu sắc đến mức có thể biểu lộ ra ngoài như rơi nước mắt."},"5729":{"word":"bị quấn, bị cuốn","meaning":"Trạng thái bị một sợi dây hoặc chỉ cuộn quanh một vật nào đó."},"5730":{"word":"du dương, ngọt ngào","meaning":"Miêu tả âm thanh, đặc biệt là âm nhạc, nghe rất dễ chịu, êm ái và nhẹ nhàng."},"5731":{"word":"kiểm toán, thanh tra","meaning":"Việc kiểm tra, rà soát cẩn thận các tài liệu, hoạt động để xác định tính hợp lệ hoặc chính xác."},"5732":{"word":"cảm xúc, cảm nghĩ","meaning":"Những cảm giác hoặc suy nghĩ nảy sinh trong lòng khi trải nghiệm điều gì đó."},"5733":{"word":"giàu tình cảm, đa cảm","meaning":"Có khuynh hướng dễ xúc động, dễ bị chi phối bởi tình cảm hoặc hồi ức."},"5734":{"word":"cảm tính, cảm xúc","meaning":"Khả năng cảm nhận sâu sắc vẻ đẹp, nghệ thuật hoặc cảm xúc của người khác."},"5735":{"word":"cảm tính","meaning":"Người hoặc cách suy nghĩ dễ bị ảnh hưởng bởi cảm xúc, trải nghiệm hơn là sự thật."},"5736":{"word":"nhiễm trùng","meaning":"Tình trạng vi khuẩn hoặc mầm bệnh khác xâm nhập vào cơ thể sống, phát triển và gây bệnh."},"5737":{"word":"tính cảm xúc","meaning":"Tính cách, hành vi hay một vấn đề dựa nhiều vào cảm xúc cá nhân hơn là lý trí."},"5738":{"word":"sự thán phục","meaning":"Cảm giác hài lòng và tán thành mạnh mẽ khi một điều gì đó hoặc ai đó rất tốt, đẹp, hoặc tuyệt vời."},"5739":{"word":"thán từ","meaning":"Một từ hoặc âm thanh ngắn, đột ngột dùng để biểu lộ cảm xúc mạnh mẽ hoặc bất ngờ."},"5740":{"word":"Bên A","meaning":"Trong một hợp đồng, đây là bên đầu tiên được nhắc đến, thường là bên có quyền lực hoặc ảnh hưởng hơn."},"5741":{"word":"ngột ngạt","meaning":"Cảm thấy khó chịu, bức bối, bị kìm nén như ở trong không gian chật hẹp hoặc không thể nói lên suy nghĩ của mình."},"5742":{"word":"quý giá","meaning":"Có giá trị cao về mặt tiền bạc hoặc rất quan trọng và được trân trọng bởi mọi người."},"5743":{"word":"cường quốc","meaning":"Một quốc gia có sức mạnh và ảnh hưởng lớn trên thế giới, thường qua kinh tế, quân sự hoặc văn hóa."},"5744":{"word":"hội trường","meaning":"Một căn phòng lớn trong tòa nhà, có nhiều ghế ngồi để mọi người tụ tập xem biểu diễn hoặc nghe diễn thuyết."},"5745":{"word":"cường quốc","meaning":"Một quốc gia có sức mạnh kinh tế hoặc quân sự lớn và lãnh thổ rộng lớn."},"5746":{"word":"cường độ","meaning":"Mức độ hoặc cấp độ hiện diện hay hiệu quả của một cái gì đó, như độ sáng của ánh sáng hay độ lớn của âm thanh."},"5747":{"word":"sự mạnh mẽ","meaning":"Tính chất thể hiện khả năng lớn trong việc thực hiện hành động hoặc gây ra thay đổi một cách rõ rệt."},"5748":{"word":"mạnh mẽ","meaning":"Với thái độ kiên quyết, đầy thuyết phục hoặc bằng một nỗ lực lớn về thể chất, thường được thể hiện qua lời nói hoặc hành động dứt khoát."},"5749":{"word":"mãnh liệt","meaning":"Rất sáng, đậm màu hoặc được cảm nhận sâu sắc, gây ấn tượng mạnh mẽ và lâu dài."},"5750":{"word":"giang sơn","meaning":"Các đặc điểm tự nhiên của một quốc gia hoặc vùng lãnh thổ như sông lớn và núi cao."},"5751":{"word":"bài giảng","meaning":"Một buổi nói chuyện trang trọng do một người trình bày trước một nhóm người nhằm mục đích giảng dạy hoặc cung cấp thông tin về một chủ đề cụ thể."},"5752":{"word":"lượng mưa","meaning":"Lượng nước đo được rơi từ trên trời xuống một khu vực cụ thể trong một khoảng thời gian."},"5753":{"word":"người mạnh","meaning":"Người hoặc nhóm người có sức mạnh thể chất hoặc ảnh hưởng lớn, thường có thể dễ dàng vượt qua người khác."},"5754":{"word":"khóa học","meaning":"Một loạt các buổi nói chuyện hoặc buổi học chính thức về một chủ đề cụ thể, thường là một phần của chương trình học dài hơn."},"5755":{"word":"gió mạnh","meaning":"Không khí di chuyển rất nhanh và có sức mạnh lớn, thường làm cho các vật thể dịch chuyển hoặc rung lắc."},"5756":{"word":"sự củng cố","meaning":"Hành động làm cho một cái gì đó trở nên vững chắc, hiệu quả hoặc có sức đề kháng cao hơn, khiến nó khó bị phá vỡ hoặc đánh bại hơn."},"5757":{"word":"đủ loại","meaning":"Dùng để mô tả nhiều loại hoặc chủng loại khác nhau của một cái gì đó."},"5758":{"word":"khai giảng","meaning":"Thời điểm cụ thể khi một loạt các lớp học hoặc chương trình học chính thức bắt đầu."},"5759":{"word":"cá nhân","meaning":"Mỗi một người trong một nhóm được xem xét riêng lẻ."},"5760":{"word":"nước","meaning":"Đơn vị dùng để đếm các quốc gia hoặc lãnh thổ chính trị độc lập."},"5761":{"word":"lễ khai mạc","meaning":"Một sự kiện trang trọng đánh dấu sự bắt đầu chính thức của một dịp quan trọng, cuộc thi hoặc buổi biểu diễn."},"5762":{"word":"cởi mở","meaning":"Nói về một người dễ dàng chấp nhận những ý tưởng, ý kiến mới hoặc cách suy nghĩ khác biệt mà không có định kiến."},"5763":{"word":"mở","meaning":"Hành động tháo niêm phong một vật chứa, gói hàng, hoặc thời điểm một bộ phim, sản phẩm mới được công khai."},"5764":{"word":"mở","meaning":"Việc thiết lập hoặc tạo ra một cái gì đó mới, như một khóa học, một cơ sở hay một dịch vụ để mọi người sử dụng."},"5765":{"word":"số lượng","meaning":"Tổng số lượng của những thứ riêng biệt có thể được đếm từng cái một."},"5766":{"word":"khai trương","meaning":"Sự kiện chính thức khi một cửa hàng, nhà hàng hoặc công ty mới bắt đầu hoạt động và đón khách hàng."},"5767":{"word":"tóm tắt","meaning":"Một mô tả ngắn gọn trình bày những điểm chính hoặc cấu trúc cơ bản của một văn bản hoặc kế hoạch dài hơn mà không đi sâu vào chi tiết."},"5768":{"word":"chủ nghĩa cá nhân","meaning":"Một cách tư duy nhấn mạnh nhu cầu, mong muốn và sự độc lập của một người hơn là nhu cầu của một nhóm hoặc xã hội."},"5769":{"word":"mở cửa","meaning":"Thời điểm một địa điểm như công viên, bãi biển hoặc tòa nhà lần đầu tiên mở cửa cho mọi người vào và sử dụng."},"5770":{"word":"cải tạo","meaning":"Quá trình thay đổi cấu trúc, chức năng hoặc diện mạo của một vật như tòa nhà hoặc phương tiện để làm cho nó tốt hơn hoặc khác đi."},"5771":{"word":"khai phá","meaning":"Việc tìm tòi, khám phá hoặc phát triển một vùng đất mới, lĩnh vực mới chưa từng có trước đây."},"5772":{"word":"khai thông","meaning":"Sự việc một con đường, tuyến giao thông hoặc phương tiện công cộng mới được mở và bắt đầu cho phép người và xe cộ đi lại."},"5773":{"word":"ghế khán giả","meaning":"Nơi dành cho khán giả ngồi trong nhà hát, rạp chiếu phim hoặc sân vận động."},"5774":{"word":"phòng nghỉ","meaning":"Không gian riêng tư dành cho khách thuê để ngủ và nghỉ ngơi tạm thời trong khách sạn hoặc cơ sở lưu trú khác."},"5775":{"word":"cai quản","meaning":"Chăm sóc và quản lý những người thân thuộc, cấp dưới hoặc thuộc quyền của mình."},"5776":{"word":"đi dạo","meaning":"Đi bộ một cách chậm rãi, thư thái thường là không có mục đích cụ thể, chỉ để giải trí."},"5777":{"word":"đề tài","meaning":"Cái được dùng làm vật liệu, chủ đề để nói, viết, suy nghĩ hoặc làm điều gì đó."},"5778":{"word":"sự kiêu ngạo","meaning":"Thái độ quá tự mãn, tin vào sự vượt trội của bản thân, thường khiến người khác thấy thô lỗ hoặc khinh thường."},"5779":{"word":"sự từ chối","meaning":"Hành động nói hoặc thể hiện rằng mình không muốn chấp nhận, đồng ý hoặc làm một việc gì đó."},"5780":{"word":"dữ dội","meaning":"Miêu tả những thứ như gió hoặc dòng chảy có sức mạnh và cường độ lớn, khó chống lại hoặc chịu đựng."},"5781":{"word":"số tiền lớn","meaning":"Một khoản tiền vô cùng lớn."},"5782":{"word":"người khổng lồ","meaning":"Người có vóc dáng cao lớn hơn rất nhiều so với người bình thường."},"5783":{"word":"cư trú","meaning":"Hành động sống và ở lại liên tục tại một nơi cụ thể như nhà ở hoặc căn hộ trong một khoảng thời gian."},"5784":{"word":"cư dân","meaning":"Người sống thường xuyên tại một quốc gia, thành phố hoặc tòa nhà nhất định."},"5785":{"word":"nỗi lo","meaning":"Tình huống hoặc suy nghĩ gây ra sự lo lắng hoặc phiền muộn cho ai đó."},"5786":{"word":"vụ","meaning":"Một đơn vị dùng để đếm số lượng vụ việc, sự kiện hoặc tài liệu."},"5787":{"word":"kiến quốc","meaning":"Hành động thành lập một quốc gia hoặc nhà nước mới."},"5788":{"word":"mùa khô","meaning":"Khoảng thời gian trong năm ở vùng khí hậu nhiệt đới mà có rất ít hoặc không có mưa."},"5789":{"word":"chứng hay quên","meaning":"Tình trạng một người thường xuyên gặp khó khăn trong việc ghi nhớ mọi thứ hoặc dễ quên thông tin."},"5790":{"word":"ngành xây dựng","meaning":"Ngành nghề liên quan đến việc xây dựng các tòa nhà hoặc đường xá."},"5791":{"word":"số vụ","meaning":"Tổng số lượng các sự kiện hoặc trường hợp cụ thể đã được ghi nhận hoặc quan sát."},"5792":{"word":"đề xuất","meaning":"Một ý tưởng hoặc kế hoạch được đưa ra một cách chính thức để người khác xem xét hoặc thảo luận."},"5793":{"word":"kiến trúc sư","meaning":"Người có công việc là lập kế hoạch, thiết kế và thường giám sát việc xây dựng các tòa nhà."},"5794":{"word":"công trình kiến trúc","meaning":"Một tòa nhà hoặc công trình được xây dựng trên mặt đất."},"5795":{"word":"đá","meaning":"Dùng chân tác động mạnh vào một vật gì đó khiến nó bật ra khỏi vị trí ban đầu."},"5796":{"word":"dáng đi","meaning":"Cách một người di chuyển chân và cơ thể khi đi bộ."},"5797":{"word":"kiếm","meaning":"Một loại vũ khí dài, có lưỡi sắc bén và tay cầm, dùng để cắt hoặc đâm."},"5798":{"word":"khám tổng quát","meaning":"Việc kiểm tra sức khỏe và cơ thể bởi bác sĩ để đảm bảo mọi thứ bình thường hoặc phát hiện vấn đề."},"5799":{"word":"sợ hãi","meaning":"Có cảm giác lo lắng, sợ hãi mạnh mẽ trước một nguy hiểm hoặc sự kiện không mong muốn có thể xảy ra."},"5800":{"word":"vẻ bề ngoài","meaning":"Cách một người hoặc một vật trông bên ngoài, có thể khác với bản chất thật của nó."},"5801":{"word":"nách","meaning":"Phần hõm dưới cánh tay nơi cánh tay nối với vai."},"5802":{"word":"thời gian rảnh","meaning":"Khoảng thời gian một người được tự do làm điều gì đó, thường dùng để chỉ việc không có khoảng thời gian như vậy."},"5803":{"word":"đẳng cấp","meaning":"Mức độ giá trị, chất lượng hoặc địa vị của một người hay một vật."},"5804":{"word":"mãnh liệt","meaning":"Diễn tả một hành động hoặc sự kiện rất mạnh mẽ, tràn đầy năng lượng hoặc cảm xúc, thường kèm theo nhiều chuyển động."},"5805":{"word":"nghi thức","meaning":"Tập hợp các quy tắc hoặc phong tục nghiêm ngặt chi phối hành vi trong một số tình huống xã hội hoặc nghi lễ nhất định."},"5806":{"word":"kết cục","meaning":"Phần cuối cùng của một câu chuyện, cuốn sách hoặc bộ phim nơi tất cả các sự kiện kết thúc và đạt được một giải pháp."},"5807":{"word":"chia tay, sự chia ly","meaning":"Việc hai người hay hai nhóm tách ra khỏi nhau sau một mối quan hệ hoặc liên minh, thường đi kèm với sự buồn bã hoặc bất đồng."},"5808":{"word":"trận chung kết","meaning":"Trận đấu thể thao hoặc cuộc thi diễn ra giữa hai đối thủ cuối cùng để quyết định người chiến thắng chung cuộc của một giải đấu."},"5809":{"word":"quả, thành quả","meaning":"Trạng thái cây cối ra quả, hoặc quả chín; hay còn là kết quả tốt đẹp đạt được sau một quá trình nỗ lực."},"5810":{"word":"phê duyệt, sự chấp thuận","meaning":"Hành động một người có thẩm quyền cấp phép hoặc đồng ý chính thức cho một kế hoạch, yêu cầu hoặc tài liệu bằng cách ký tên hoặc đánh dấu chấp nhận."},"5811":{"word":"mang tính quyết định, quyết định","meaning":"Cái gì đó rất rõ ràng, quan trọng hoặc thuyết phục đến mức giải quyết được tình huống hoặc ảnh hưởng mạnh mẽ đến kết quả cuối cùng."},"5812":{"word":"kiêm, vừa ... vừa ...","meaning":"Dùng để mô tả một vật hoặc một hành động có hai hay nhiều mục đích/chức năng cùng lúc."},"5813":{"word":"kiêm nhiệm, kiêm","meaning":"Thực hiện hoặc chịu trách nhiệm cho hai vai trò, vị trí hoặc nhiệm vụ khác nhau trong cùng một khoảng thời gian."},"5814":{"word":"lớp, tầng, nếp","meaning":"Một tấm, một lớp phủ hoặc một độ dày của vật liệu được đặt chồng lên hoặc dưới một tấm khác, hoặc một phần của vật gì đó được gấp lại."},"5815":{"word":"khoảng, chừng (hậu tố)","meaning":"Hậu tố thêm vào sau thời gian hoặc con số để chỉ rằng số lượng hoặc thời điểm chính xác không được biết, nhưng nó gần với giá trị đó."},"5816":{"word":"sự trôi qua, quá trình","meaning":"Quá trình thời gian trôi đi hoặc chuỗi các sự kiện diễn ra trong một khoảng thời gian, cho thấy một tình huống phát triển như thế nào."},"5817":{"word":"bảo vệ, lính gác","meaning":"Người được thuê hoặc các biện pháp được thực hiện để bảo vệ một địa điểm hoặc người khỏi nguy hiểm, trộm cắp hoặc sự xâm nhập trái phép."},"5818":{"word":"khinh suất, hấp tấp, vội vàng","meaning":"Nói lời hoặc hành động quá nhanh, mà không xem xét những kết quả xấu có thể xảy ra."},"5819":{"word":"người quản lý cấp cao, giám đốc điều hành","meaning":"Người đứng đầu một công ty, chịu trách nhiệm ra quyết định quan trọng và điều hành hoạt động chung."},"5820":{"word":"quản trị kinh doanh","meaning":"Ngành học nghiên cứu cách lập kế hoạch, tổ chức và điều hành các hoạt động của một công ty để đạt hiệu quả cao."},"5821":{"word":"chi tiết, tình tiết","meaning":"Chuỗi các sự việc và tình tiết giải thích chính xác cách một sự kiện đã diễn ra hoặc phát triển."},"5822":{"word":"tỉ lệ cạnh tranh","meaning":"Con số thể hiện số lượng người hoặc đối tượng đang cố gắng giành lấy một số lượng hạn chế các vị trí hoặc món đồ."},"5823":{"word":"có tính cạnh tranh","meaning":"Diễn tả một tình huống mà các cá nhân hoặc nhóm đang tích cực cố gắng làm tốt hơn người khác hoặc giành được cái gì đó trước tiên."},"5824":{"word":"kinh tế học","meaning":"Ngành học nghiên cứu cách con người và xã hội sản xuất, phân phối và sử dụng hàng hóa, dịch vụ."},"5825":{"word":"việc hiếu hỉ, việc hỷ sự","meaning":"Những dịp đặc biệt trong gia đình hoặc xã hội như cưới hỏi, tang lễ, nơi mọi người tụ họp để chia sẻ niềm vui hay nỗi buồn."},"5826":{"word":"Gyeongju","meaning":"Một thành phố ở phía đông nam tỉnh Gyeongsangbuk-do, nổi tiếng là thủ đô cổ của vương quốc Silla và là điểm đến du lịch văn hóa."},"5827":{"word":"Tổng cục Cảnh sát Quốc gia","meaning":"Cơ quan chính phủ chịu trách nhiệm điều hành toàn bộ lực lượng cảnh sát, thi hành luật pháp và giữ gìn trật tự trong một quốc gia."},"5828":{"word":"nhẹ nhàng, vui vẻ, sảng khoái","meaning":"Cảm thấy rất vui vẻ, tràn đầy năng lượng và dễ chịu, khiến bước đi hoặc hành động trở nên nhẹ nhàng, phấn chấn."},"5829":{"word":"phần thưởng, quà tặng khuyến mãi","meaning":"Một món đồ hoặc số tiền mà một người nhận được sau khi thắng một cuộc thi hoặc như một món quà miễn phí từ công ty."},"5830":{"word":"câu chuyện kinh nghiệm, giai thoại cá nhân","meaning":"Một câu chuyện mà một người kể về điều có thật đã xảy ra trong cuộc sống của chính họ."},"5831":{"word":"bảo vệ, hộ tống","meaning":"Hành động giữ an toàn cho một người hoặc địa điểm quan trọng khỏi nguy hiểm bằng cách canh gác cẩn thận."},"5832":{"word":"phường hội, hội hụi","meaning":"Một nhóm nhỏ người thường xuyên góp tiền với nhau để đạt mục tiêu tài chính chung hoặc giúp đỡ lần lượt từng thành viên."},"5833":{"word":"-giới, -ngành","meaning":"Vĩ tố chỉ một nhóm người hoặc một lĩnh vực hoạt động cụ thể."},"5834":{"word":"cấp bậc, cấp","meaning":"Vị trí hoặc mức độ tương đối của sĩ quan cảnh sát, quân nhân, v.v., trong một tổ chức như quân đội hoặc cảnh sát."},"5835":{"word":"phát triển, rèn luyện","meaning":"Hành động làm cho kỹ năng hoặc tài năng tự nhiên của một người trở nên tốt hơn thông qua học hỏi và thực hành."},"5836":{"word":"hệ, ngành, chuỗi","meaning":"Một nhóm các sự vật hoặc người có liên kết chính thức hoặc cùng loại, chẳng hạn như các môn học trong trường học."},"5837":{"word":"có kế hoạch, có chủ đích","meaning":"Mô tả một hành động đã được suy nghĩ và tổ chức cẩn thận từ trước, thường với các bước cụ thể được xác định."},"5838":{"word":"năm cuối cấp (trung học)","meaning":"Năm học cuối cùng mà một học sinh theo học trung học trước khi tốt nghiệp."},"5839":{"word":"cố, đã khuất","meaning":"Dùng trước tên một người để chỉ rằng người đó đã qua đời."},"5840":{"word":"cao-","meaning":"Bộ phận từ được thêm vào đầu một từ khác để chỉ rằng một cái gì đó có tiêu chuẩn vượt trội hoặc số lượng lớn."},"5841":{"word":"hàng đắt tiền, vật phẩm giá trị","meaning":"Một vật có giá trị lớn và cần nhiều tiền để mua."},"5842":{"word":"đầu, đèo","meaning":"Một là bộ phận trên cổ của con người nơi có mặt và não, hai là một gò đất tự nhiên nhỏ hơn núi."},"5843":{"word":"học sinh cấp ba","meaning":"Người đang học tại trường trung học phổ thông."},"5844":{"word":"Cao Câu Ly","meaning":"Một vương quốc hùng mạnh đã tồn tại ở bán đảo Triều Tiên và một phần Trung Quốc trong nhiều thế kỷ."},"5845":{"word":"áp cao","meaning":"Trạng thái áp suất không khí cao hơn so với môi trường xung quanh."},"5846":{"word":"mệt mỏi, kiệt sức","meaning":"Cảm thấy rất mệt mỏi, không còn sức lực để làm việc gì nữa."},"5847":{"word":"độ cao","meaning":"Khoảng cách được đo từ mặt đất trở lên, hoặc một mức độ, trình độ đáng kể."},"5848":{"word":"Cao Ly","meaning":"Một vương triều đã cai trị bán đảo Triều Tiên từ thế kỷ 10 đến thế kỷ 14."},"5849":{"word":"đều, bằng phẳng","meaning":"Có bề mặt hoặc sự sắp xếp nhẵn, đồng đều, không bị lồi lõm hay không cân xứng."},"5850":{"word":"vòng, cái móc","meaning":"Một vật hình tròn hoặc cong, thường dùng để nối các vật với nhau hoặc làm chỗ để cầm."},"5851":{"word":"tố cáo, vạch trần","meaning":"Hành động công khai các sai phạm hoặc hành vi tham nhũng bị che giấu."},"5852":{"word":"tao nhã, thanh lịch","meaning":"Có phong thái, lời nói hoặc hành vi thể hiện sự lịch sự, trang trọng và có gu thẩm mỹ cao."},"5853":{"word":"vất vả, khó nhọc","meaning":"Một công việc hoặc tình huống đòi hỏi nhiều sức lực, gây ra sự khó chịu và mệt mỏi."},"5854":{"word":"khởi kiện, khiếu nại","meaning":"Lời buộc tội chính thức bằng văn bản gửi đến tòa án, thường là để đòi công lý hoặc bồi thường."},"5855":{"word":"trẻ mồ côi","meaning":"Một đứa trẻ không còn cha mẹ hoặc người giám hộ chăm sóc."},"5856":{"word":"trại mồ côi","meaning":"Nơi nuôi dưỡng và chăm sóc những đứa trẻ không còn cha mẹ."},"5857":{"word":"nhiệt độ cao","meaning":"Mức độ nóng bức vượt quá mức bình thường."},"5858":{"word":"cao nguyên","meaning":"Một vùng đất rộng lớn, tương đối bằng phẳng và nằm ở độ cao nhất định."},"5859":{"word":"đọng lại","meaning":"Chất lỏng, mùi hoặc khí tụ lại một chỗ, không chảy đi."},"5860":{"word":"chỉ","meaning":"Dùng để nhấn mạnh rằng số lượng hoặc mức độ là rất ít, không đáng kể hoặc không như mong đợi."},"5861":{"word":"tốt nghiệp trung học phổ thông","meaning":"Người đã hoàn thành chương trình học cấp ba và nhận bằng tốt nghiệp."},"5862":{"word":"giấy thông báo","meaning":"Một tài liệu chính thức dùng để thông báo cho ai đó về một khoản thanh toán, sự kiện hoặc thông tin quan trọng."},"5863":{"word":"chất rắn","meaning":"Một trạng thái vật chất có hình dạng và thể tích xác định, có thể sờ thấy."},"5864":{"word":"trình độ học vấn cao","meaning":"Tình trạng có bằng cấp hoặc kiến thức chuyên sâu từ các bậc học cao."},"5865":{"word":"huyết áp cao","meaning":"Tình trạng khi áp lực của máu lên thành động mạch cao hơn mức bình thường."},"5866":{"word":"ngũ cốc","meaning":"Hạt nhỏ, cứng của các loại cây như lúa, ngô, lúa mì, thường dùng làm thức ăn."},"5867":{"word":"đường cong","meaning":"Đường cong là một đường không thẳng mà uốn lượn."},"5868":{"word":"côn trùng","meaning":"Côn trùng là loài động vật nhỏ bé, thân có nhiều khớp nối, như bướm, chuồn chuồn, ong."},"5869":{"word":"đồ cổ","meaning":"Đồ cổ là vật phẩm rất cũ, thường có giá trị hoặc đẹp, như đồ nội thất hay tác phẩm nghệ thuật."},"5870":{"word":"vấn đề nan giải","meaning":"Vấn đề nan giải là một tình huống hoặc công việc phức tạp, gây căng thẳng và lo lắng cho người giải quyết."},"5871":{"word":"tóc xoăn","meaning":"Tóc xoăn là loại tóc mọc không thẳng mà uốn lượn thành sóng hoặc lọn."},"5872":{"word":"công lao","meaning":"Công lao là thành tích, đóng góp quan trọng hoặc nỗ lực đáng kể của một người."},"5873":{"word":"điểm chung","meaning":"Điểm chung là một lĩnh vực hoặc sự đồng điệu về suy nghĩ, cảm xúc giữa nhiều người."},"5874":{"word":"sự kính trọng","meaning":"Sự kính trọng là cảm giác hoặc hành động thể hiện sự quý mến, nể trọng sâu sắc đối với người khác."},"5875":{"word":"thông báo","meaning":"Thông báo là tin tức được công bố chính thức để nhiều người biết về một việc gì đó."},"5876":{"word":"văn bản thông báo","meaning":"Văn bản thông báo là một tài liệu viết, thường được dán ở nơi công cộng để chính thức thông tin cho mọi người."},"5877":{"word":"cơ sở công cộng","meaning":"Cơ sở công cộng là các tòa nhà hoặc địa điểm do chính phủ cung cấp để mọi người có thể sử dụng, như công viên hay thư viện."},"5878":{"word":"giáo dục công lập","meaning":"Giáo dục công lập là hệ thống dạy và học do nhà nước cung cấp cho học sinh, thường không mất phí trực tiếp."},"5879":{"word":"không quân","meaning":"Lực lượng quân đội chịu trách nhiệm bảo vệ đất nước từ trên không."},"5880":{"word":"khủng long","meaning":"Một loài vật khổng lồ đã sống trên Trái Đất từ rất lâu nhưng nay đã tuyệt chủng."},"5881":{"word":"công văn","meaning":"Văn bản hoặc tài liệu điện tử do cơ quan chính phủ hoặc tổ chức lớn ban hành để truyền đạt thông tin quan trọng."},"5882":{"word":"công trường xây dựng","meaning":"Nơi công nhân xây dựng các công trình như tòa nhà, đường sá bằng máy móc và vật liệu."},"5883":{"word":"ảo tưởng, mơ mộng","meaning":"Những suy nghĩ hoặc câu chuyện tưởng tượng về những điều khó có thể xảy ra trong thực tế."},"5884":{"word":"chính thức","meaning":"Được thực hiện hoặc công bố bởi người có thẩm quyền hoặc tổ chức, tuân thủ đúng các quy định và thủ tục."},"5885":{"word":"thủ công mỹ nghệ","meaning":"Nghề làm ra các vật phẩm trang trí hoặc đồ vật hữu ích bằng tay, ví dụ như đồ gốm, trang sức, vải dệt."},"5886":{"word":"chia sẻ","meaning":"Hành động cho phép người khác sử dụng, sở hữu hoặc biết điều gì đó mà mình có."},"5887":{"word":"lợi ích công cộng","meaning":"Lợi ích và phúc lợi chung của tất cả mọi người trong cộng đồng hoặc xã hội."},"5888":{"word":"công chúng","meaning":"Tất cả những người dân bình thường sống trong một quốc gia hoặc khu vực cụ thể, thường được xem như một nhóm."},"5889":{"word":"không trung","meaning":"Khoảng không gian cao trên mặt đất, nơi các vật có thể bay hoặc lơ lửng trước khi rơi xuống."},"5890":{"word":"chung, phổ biến","meaning":"Điều gì đó có mặt hoặc được thực hiện bởi nhiều người, vật, hoặc nơi khác nhau, không đặc biệt hay bất thường."},"5891":{"word":"công bằng","meaning":"Xử sự với mọi người như nhau, không thiên vị ai cả."},"5892":{"word":"cảm giác sợ hãi","meaning":"Cảm giác rất sợ, làm cho người ta muốn tránh xa nguy hiểm."},"5893":{"word":"kỹ thuật","meaning":"Ngành học và công việc áp dụng khoa học để thiết kế, xây dựng và duy trì máy móc, công trình."},"5894":{"word":"ban, phòng","meaning":"Hậu tố dùng để chỉ một bộ phận hoặc phòng ban chuyên trách trong cơ quan, tổ chức."},"5895":{"word":"phòng, ban","meaning":"Một bộ phận lớn trong công ty hoặc tổ chức, chuyên về một lĩnh vực công việc cụ thể."},"5896":{"word":"táo bạo, quyết đoán","meaning":"Nhanh chóng hành động hoặc lựa chọn mà không sợ hãi hay do dự, dù trong tình huống rủi ro."},"5897":{"word":"đánh giá quá cao","meaning":"Đánh giá hoặc cho rằng ai đó hay cái gì đó có năng lực, quan trọng hơn giá trị thực của họ."},"5898":{"word":"quá mức, thái quá","meaning":"Vượt xa mức độ hợp lý, cần thiết hoặc bình thường."},"5899":{"word":"đa số, quá nửa","meaning":"Số lượng hoặc số người lớn hơn một nửa tổng số."},"5900":{"word":"bao bọc quá mức","meaning":"Bảo vệ ai đó, đặc biệt là trẻ em, quá nhiều khỏi khó khăn, khiến họ không học được cách tự xoay xở."},"5901":{"word":"đánh giá thấp","meaning":"Đánh giá hoặc cho rằng ai đó hay cái gì đó có năng lực, quan trọng kém hơn giá trị thực của họ."},"5902":{"word":"lời nói quá","meaning":"Lời nói làm cho sự việc có vẻ lớn hơn, tốt hơn, tệ hơn hoặc quan trọng hơn thực tế."},"5903":{"word":"uống quá chén","meaning":"Việc uống một lượng rượu bia quá nhiều, gây hại cho sức khỏe."},"5904":{"word":"quá trình","meaning":"Chuỗi các bước hoặc giai đoạn liên tiếp từ khi bắt đầu đến khi hoàn thành một việc gì đó."},"5905":{"word":"quá đáng","meaning":"Có tính chất hoặc mức độ vượt quá giới hạn bình thường, không phù hợp."},"5906":{"word":"-viên","meaning":"Hậu tố dùng để tạo từ chỉ người làm việc hoặc có chức vụ trong cơ quan, tổ chức."},"5907":{"word":"công sở","meaning":"Nơi làm việc của cán bộ, nhân viên nhà nước để thực hiện các công việc hành chính, phục vụ công chúng."},"5908":{"word":"khoan dung","meaning":"Có tấm lòng rộng mở, dễ tha thứ và chấp nhận sự khác biệt của người khác."},"5909":{"word":"liên hệ","meaning":"Thiết lập hoặc chỉ ra mối quan hệ, sự liên quan giữa hai hay nhiều sự vật, hiện tượng."},"5910":{"word":"phong tục","meaning":"Thói quen, cách làm việc hay cư xử truyền thống đã được xã hội chấp nhận và duy trì qua nhiều thế hệ."},"5911":{"word":"sự khoan dung","meaning":"Thái độ chấp nhận sự khác biệt trong tư tưởng, hành vi của người khác hoặc đối xử mềm mỏng, không quá khắt khe."},"5912":{"word":"thành ngữ","meaning":"Cụm từ hay cách diễn đạt mà ý nghĩa của nó không thể suy ra từ nghĩa của từng từ riêng lẻ, mà được hiểu theo nghĩa chung đã thành quen."},"5913":{"word":"khán giả","meaning":"Nhóm người tập trung lại để xem một sự kiện công cộng, buổi biểu diễn hoặc trận đấu thể thao."},"5914":{"word":"cơ quan nhà nước","meaning":"Nơi làm việc của chính quyền để giải quyết các công việc hành chính và phục vụ công ích."},"5915":{"word":"liên quan đến","meaning":"Chỉ việc có một chủ đề hoặc vấn đề cụ thể là điểm chính của một cuộc thảo luận, một cuốn sách hoặc một bộ phim."},"5916":{"word":"định ngữ","meaning":"Từ loại đứng trước danh từ để giới hạn hoặc xác định nghĩa của danh từ đó."},"5917":{"word":"quảng trường","meaning":"Một không gian rộng lớn ở khu vực trung tâm thành phố, nơi nhiều người tụ tập."},"5918":{"word":"quái vật","meaning":"Một sinh vật tưởng tượng to lớn, đáng sợ và thường xấu xí, thường xuất hiện trong truyện và phim ảnh."},"5919":{"word":"môn học","meaning":"Một phần của chương trình học, được sắp xếp có hệ thống về những gì cần học ở trường."},"5920":{"word":"nhà tù","meaning":"Một cơ sở giam giữ và quản lý tội phạm."},"5921":{"word":"phòng giáo viên","meaning":"Một căn phòng trong trường học nơi các giáo viên tập trung để chuẩn bị bài giảng, chấm bài và xử lý công việc hành chính."},"5922":{"word":"đội ngũ giảng dạy","meaning":"Nhóm người thực hiện việc giảng dạy và dẫn dắt các lớp học tại trường học hoặc nơi học tập khác."},"5923":{"word":"Bộ Giáo dục","meaning":"Một bộ của chính phủ quốc gia quản lý tất cả các trường học và chương trình học tập công lập."},"5924":{"word":"sự ham học","meaning":"Khao khát và năng lượng mạnh mẽ mà con người thể hiện trong việc học hỏi và đạt thành tích tốt trong học tập."},"5925":{"word":"mang tính giáo dục","meaning":"Miêu tả điều gì đó giúp một người có được kiến thức mới hoặc phát triển những khả năng hữu ích."},"5926":{"word":"giao thiệp; hẹn hò","meaning":"Hành động hai hoặc nhiều người thường xuyên dành thời gian cho nhau, thường để xây dựng tình bạn hoặc mối quan hệ lãng mạn."},"5927":{"word":"nghề giáo","meaning":"Nghề nghiệp của người dạy học và hướng dẫn học sinh ở trường học."},"5928":{"word":"mang tính giáo huấn","meaning":"Có nội dung răn dạy hoặc đưa ra bài học về cách sống đúng đắn."},"5929":{"word":"đoạn, khúc","meaning":"Một phần nhất định của con đường, tuyến đường hoặc không gian nào đó."},"5930":{"word":"bị nhăn, bị nhàu","meaning":"Bị tạo thành nhiều nếp gấp không đều trên bề mặt, thường làm cho nó trông lộn xộn hoặc không phẳng."},"5931":{"word":"người xem, khán giả","meaning":"Người đứng xem một sự kiện hoặc hoạt động mà không tham gia vào đó."},"5932":{"word":"xe cứu thương","meaning":"Phương tiện đặc biệt dùng để chở người bệnh hoặc người bị thương cấp tốc đến bệnh viện."},"5933":{"word":"nhà ăn tập thể, căng tin","meaning":"Phòng ăn lớn trong trường học hoặc văn phòng, nơi mọi người có thể mua và ăn các bữa ăn."},"5934":{"word":"sự đăng ký dài hạn, đăng ký","meaning":"Việc trả tiền định kỳ để nhận tạp chí, báo hoặc sử dụng dịch vụ trực tuyến."},"5935":{"word":"bằng miệng, nói miệng","meaning":"Diễn đạt bằng lời nói hoặc thông qua việc nói."},"5936":{"word":"người keo kiệt, người bủn xỉn","meaning":"Người không thích tiêu tiền và luôn cố gắng giữ càng nhiều tiền càng tốt."},"5937":{"word":"dậm (chân)","meaning":"Dùng chân đập mạnh xuống đất nhiều lần, thường do tức giận hoặc sốt ruột."},"5938":{"word":"người mua","meaning":"Người bỏ tiền hoặc giá trị khác để đổi lấy hàng hóa hoặc dịch vụ."},"5939":{"word":"sự ngược đãi","meaning":"Việc đối xử tệ bạc hoặc liên tục chỉ trích ai đó, gây ra sự đau khổ cho họ."},"5940":{"word":"tài liệu cần thiết","meaning":"Các loại giấy tờ hoặc hồ sơ cụ thể mà người ta phải cung cấp cho một mục đích nào đó."},"5941":{"word":"sự thành thạo (ngôn ngữ)","meaning":"Kỹ năng nói hoặc viết một ngôn ngữ một cách trôi chảy và chính xác."},"5942":{"word":"sự hình dung, sự lên ý tưởng","meaning":"Hành động tạo ra một hình ảnh chi tiết hoặc bản phác thảo ban đầu cho một dự án hay ý tưởng."},"5943":{"word":"mọi ngóc ngách","meaning":"Chỉ tất cả các không gian nhỏ, khuất hoặc ít rõ ràng bên trong một khu vực lớn."},"5944":{"word":"thành viên","meaning":"Một người chính thức là một phần của một nhóm, tổ chức hoặc gia đình."},"5945":{"word":"sự ve vãn","meaning":"Những hành động để thu hút người khác cho một mối quan hệ gần gũi, thường liên quan đến quà tặng hoặc hành vi đặc biệt."},"5946":{"word":"sự tuyển dụng (nhân sự)","meaning":"Thông báo của nhà tuyển dụng về việc tìm kiếm người để lấp đầy các vị trí trống trong công ty."},"5947":{"word":"sự tìm việc làm","meaning":"Hoạt động tích cực tìm kiếm một vị trí để kiếm tiền hoặc một cơ hội nghề nghiệp."},"5948":{"word":"nạn thiếu việc làm","meaning":"Tình huống khó khăn khi có rất ít vị trí việc làm trống so với số lượng lớn người muốn tìm việc."},"5949":{"word":"người tìm việc","meaning":"Một người đang tích cực tìm kiếm một vị trí để kiếm tiền hoặc một cơ hội nghề nghiệp."},"5950":{"word":"văn phòng quận","meaning":"Tòa nhà nơi các nhân viên chính quyền địa phương quản lý các vấn đề hành chính cho một khu vực cụ thể trong một thành phố."},"5951":{"word":"Cục","meaning":"Một hậu tố chỉ một đơn vị hành chính, một phòng ban hoặc một bộ phận trong một tổ chức lớn hơn."},"5952":{"word":"Nước","meaning":"Một hậu tố chỉ một quốc gia, đặc biệt là một quốc gia tham gia vào một thỏa thuận hoặc một nhóm lớn hơn."},"5953":{"word":"Quốc lộ","meaning":"Một con đường công cộng lớn, thường rộng và trải nhựa, chạy qua một khu vực đất đai rộng lớn và nối các thành phố, vùng miền quan trọng."},"5954":{"word":"Bộ Quốc phòng","meaning":"Cơ quan chính phủ chịu trách nhiệm bảo vệ đất nước và người dân khỏi các mối đe dọa quân sự từ bên ngoài."},"5955":{"word":"Tổng cục Thuế","meaning":"Cơ quan chính phủ chịu trách nhiệm thu tiền thuế từ công dân và doanh nghiệp để tài trợ cho các dịch vụ và chương trình công cộng."},"5956":{"word":"Nhạc truyền thống Hàn Quốc","meaning":"Âm nhạc đặc trưng được tạo ra bởi các nhạc cụ và giọng hát, đã được lưu truyền qua nhiều thế hệ và đại diện cho nghệ thuật âm thanh lịch sử của Hàn Quốc."},"5957":{"word":"Lợi ích quốc gia","meaning":"Những lợi thế hoặc phúc lợi chung được coi là có lợi cho toàn bộ đất nước và người dân, đặc biệt là về an ninh hoặc sức mạnh kinh tế."},"5958":{"word":"Lãnh thổ quốc gia","meaning":"Toàn bộ khu vực địa lý, bao gồm tất cả đất đai, mặt nước và không phận phía trên, thuộc quyền kiểm soát hợp pháp của chính phủ một quốc gia cụ thể."},"5959":{"word":"Cậu","meaning":"Từ dùng để chỉ hoặc gọi một người con trai còn trẻ tuổi."},"5960":{"word":"Quân đội","meaning":"Một nhóm người lớn, có tổ chức, mặc đồng phục, mang vũ khí và huấn luyện để bảo vệ đất nước."},"5961":{"word":"Đây đó","meaning":"Ở nhiều nơi khác nhau, không liên tục hoặc không che phủ toàn bộ một khu vực."},"5962":{"word":"Làm cứng","meaning":"Làm cho một vật mềm trở nên cứng hoặc rắn chắc."},"5963":{"word":"ống khói","meaning":"Cấu trúc hình ống rỗng, cao trên mái nhà hoặc nhà máy để khói hoặc hơi thoát ra."},"5964":{"word":"lăn, lăn đi","meaning":"Di chuyển về phía trước bằng cách xoay tròn liên tục như bánh xe hoặc quả bóng."},"5965":{"word":"cung điện","meaning":"Tòa nhà rất lớn và lộng lẫy, nơi vua hoặc hoàng hậu sinh sống."},"5966":{"word":"cung điện","meaning":"Một quần thể các tòa nhà lớn, tráng lệ nơi vua hoặc hoàng hậu sinh sống."},"5967":{"word":"sự tò mò, tính tò mò","meaning":"Mong muốn mạnh mẽ được biết hoặc tìm hiểu về một điều gì đó."},"5968":{"word":"hoàng cung, cung đình","meaning":"Môi trường, những người và các hoạt động chính thức xung quanh vua hoặc hoàng hậu trong nơi ở chính của họ."},"5969":{"word":"độc đoán, có tính quyền uy","meaning":"Mô tả người yêu cầu sự phục tùng tuyệt đối và ra lệnh mà không giải thích lý do."},"5970":{"word":"lời thì thầm, thì thầm","meaning":"Hành động nói nhỏ vào tai người khác, hoặc tiếng nói nhỏ đó."},"5971":{"word":"lúc đó, tùy lúc, từng lúc","meaning":"Xảy ra hoặc thay đổi tùy theo nhu cầu tại thời điểm cụ thể, không theo một kế hoạch cố định."},"5972":{"word":"có thế thì, để","meaning":"Từ này cho thấy một hành động cần thiết hoặc bắt buộc để một sự kiện cụ thể khác xảy ra."},"5973":{"word":"như thế, như vậy","meaning":"Từ chỉ một cách thức hoặc mức độ nào đó, thường liên quan đến điều vừa được nhắc đến."},"5974":{"word":"nhớ, mong nhớ","meaning":"Cảm thấy buồn hoặc khao khát khi nghĩ về người, nơi chốn hoặc điều gì đó không còn ở bên mình."},"5975":{"word":"do đó","meaning":"Từ này dùng để chỉ một kết quả hoặc sự việc tiếp theo một cách hợp lý từ điều đã được nói."},"5976":{"word":"lưới","meaning":"Một loại vải làm từ dây hoặc sợi được buộc lại với nhau tạo thành các khoảng trống, dùng để bắt hoặc giữ cá hay bóng."},"5977":{"word":"cực-","meaning":"Tiền tố này được đặt trước một từ khác để chỉ ra rằng điều gì đó đang ở điểm cao nhất hoặc thấp nhất, như 'rất nhỏ' hoặc 'rất ít'."},"5978":{"word":"cực đoan","meaning":"Mô tả điều gì đó ở điểm xa nhất có thể so với bình thường hoặc mong đợi, như hai mặt đối lập kéo mạnh ra xa."},"5979":{"word":"nghiêm trọng","meaning":"Mô tả một tình huống xấu hoặc thiệt hại rất lớn, gây ra nhiều đau đớn hoặc sự phá hủy rõ rệt."},"5980":{"word":"cần kiệm","meaning":"Thói quen cẩn thận với tiền bạc và đồ dùng, đảm bảo không lãng phí bất cứ thứ gì và sử dụng đồ vật trong thời gian dài."},"5981":{"word":"lao động","meaning":"Công việc thể chất hoặc tinh thần mà con người thực hiện để sản xuất hàng hóa hoặc cung cấp dịch vụ, thường là bằng cách vận động cơ thể hoặc sử dụng trí óc."},"5982":{"word":"tuyệt vời","meaning":"Mô tả điều gì đó trông rất hấp dẫn và chất lượng cao, khiến mọi người phải ngưỡng mộ."},"5983":{"word":"nguồn gốc","meaning":"Nơi đầu tiên mà một cái gì đó bắt đầu hoặc hình thành, giống như một suối nước nơi nước chảy ra từ lòng đất."},"5984":{"word":"tình hình gần đây","meaning":"Các điều kiện hoặc sự kiện đang xảy ra với ai đó hoặc cái gì đó ngay bây giờ, thường được hỏi để cập nhật thông tin."},"5985":{"word":"tác giả","meaning":"Người tạo ra một tác phẩm viết, như một cuốn sách hoặc một bài báo, bằng cách đặt các từ lên giấy hoặc màn hình."},"5986":{"word":"vết nứt","meaning":"Một đường nứt hoặc vỡ trên bề mặt mà không tách rời hoàn toàn các bộ phận."},"5987":{"word":"điều cấm kỵ","meaning":"Một hành động hoặc chủ đề bị xã hội hoặc văn hóa nghiêm cấm, mọi người thường tránh nhắc đến hoặc làm."},"5988":{"word":"lãi suất","meaning":"Tỷ lệ phần trăm tiền được cộng thêm vào số tiền vay từ ngân hàng hoặc số tiền gửi tiết kiệm."},"5989":{"word":"huy chương vàng","meaning":"Một chiếc huy chương tròn, sáng bóng làm bằng kim loại màu vàng, được trao cho người hoặc đội về nhất trong một cuộc thi."},"5990":{"word":"ngay lập tức","meaning":"Diễn tả một hành động xảy ra trong một khoảnh khắc rất ngắn, dường như kết thúc ngay khi nó bắt đầu."},"5991":{"word":"kim loại","meaning":"Những chất rắn như sắt, vàng hoặc bạc có khả năng dẫn nhiệt và điện tốt, đồng thời có độ bóng đặc trưng."},"5992":{"word":"tiền bạc","meaning":"Các đồng xu và tiền giấy được sử dụng để mua bán hàng hóa hoặc thanh toán dịch vụ."},"5993":{"word":"cấp","meaning":"Một mức độ hoặc phân loại dùng để chỉ địa vị, trình độ hoặc quy mô của một cái gì đó."},"5994":{"word":"mạnh mẽ","meaning":"Diễn tả sự thay đổi hoặc diễn biến xảy ra cực kỳ nhanh chóng và rõ rệt trong một thời gian ngắn."},"5995":{"word":"tăng vọt","meaning":"Sự tăng lên đột ngột và rất nhanh chóng, giống như một đường biểu đồ bất ngờ tăng cao."},"5996":{"word":"tốc độ nhanh","meaning":"Một tốc độ cực kỳ nhanh mà một cái gì đó tiến triển hoặc lan rộng."},"5997":{"word":"bữa ăn học đường","meaning":"Thức ăn được chuẩn bị và cung cấp cho học sinh tại căng tin hoặc nhà ăn của trường trong ngày."},"5998":{"word":"tiền lương","meaning":"Khoản tiền mà một cá nhân nhận được định kỳ từ người sử dụng lao động để bù đắp cho công việc họ đã làm."},"5999":{"word":"sinh khí","meaning":"Sức sống hoặc năng lượng vô hình làm cho một người cảm thấy mạnh mẽ và có khả năng hành động."},"6000":{"word":"kỳ","meaning":"Một khoảng thời gian cụ thể mà một sự kiện, hoạt động hoặc chức vụ chính thức diễn ra, thường được đánh số."},"6001":{"word":"cờ","meaning":"Một mảnh vải, thường hình chữ nhật và có màu sắc, được gắn vào cột hoặc dây, dùng làm biểu tượng cho một quốc gia hoặc nhóm."},"6002":{"word":"-kỳ","meaning":"Yếu tố được thêm vào cuối một từ để mô tả một giai đoạn hoặc khoảng thời gian cụ thể."},"6003":{"word":"cơ quan","meaning":"Một bộ phận của cơ thể sống, như tim hoặc phổi, thực hiện một nhiệm vụ cụ thể để duy trì hoạt động của cơ thể."},"6004":{"word":"tổ chức","meaning":"Một tổ chức hoặc thể chế do nhiều người thành lập vì một mục tiêu chung."},"6005":{"word":"khoang máy bay","meaning":"Khu vực kín bên trong một chiếc máy bay đang bay nơi hành khách và phi hành đoàn ngồi."},"6006":{"word":"sự kỳ vọng","meaning":"Cảm giác mà một người có khi tin rằng điều gì đó tốt đẹp hoặc quan trọng sắp xảy ra, khiến họ mong chờ."},"6007":{"word":"dầu mỡ","meaning":"Đặc tính của thức ăn hoặc bề mặt có nhiều dầu ăn hoặc chất béo tự nhiên, thường trông bóng hoặc cảm thấy trơn."},"6008":{"word":"béo ngậy, màu mỡ","meaning":"Mô tả thức ăn chứa nhiều dầu hoặc chất béo, hoặc đất đai màu mỡ và rất tốt để trồng trọt."},"6009":{"word":"hươu cao cổ","meaning":"Một loài động vật có hai sừng ngắn ở hai bên trán, cổ và chân rất dài."},"6010":{"word":"tuyệt vời; vô lý","meaning":"Mô tả điều gì đó đặc biệt tốt hoặc đẹp đến mức gây ngạc nhiên lớn, hoặc điều gì đó hoàn toàn vô lý đến mức dường như vô nghĩa."},"6011":{"word":"cuối kỳ","meaning":"Khoảng thời gian cuối cùng của một học kỳ, một khóa học hoặc một giai đoạn kinh doanh."},"6012":{"word":"độc đáo, mới lạ","meaning":"Có ý tưởng hoặc phương pháp rất thông minh, bất ngờ và khác thường so với những gì người khác thường nghĩ."},"6013":{"word":"tiền quyên góp","meaning":"Số tiền hoặc vật phẩm được tự nguyện đóng góp để giúp đỡ người khác, một nhóm hoặc một mục đích tốt mà không mong nhận lại."},"6014":{"word":"thời tiết","meaning":"Tình trạng của khí quyển tại một địa điểm và thời điểm cụ thể, bao gồm nắng, mây, gió và nhiệt độ."},"6015":{"word":"Cục Khí tượng","meaning":"Cơ quan quốc gia chuyên quan sát và dự báo thời tiết để cung cấp các thông tin liên quan đến khí tượng."},"6016":{"word":"thế hệ trước","meaning":"Nhóm người đã trưởng thành, được nuôi dưỡng và lớn lên trong một thời kỳ trước thế hệ trẻ hiện tại."},"6017":{"word":"khí thế","meaning":"Dáng vẻ mạnh mẽ, quyết tâm trong hành động của ai đó hoặc sự vật, cho thấy ý chí tiến lên hoặc đạt được mục tiêu."},"6018":{"word":"áp suất khí quyển","meaning":"Trọng lượng của toàn bộ không khí phía trên tác động xuống một điểm cụ thể trên bề mặt Trái Đất."},"6019":{"word":"nhà ngói","meaning":"Ngôi nhà có mái được lợp bằng những viên ngói rộng và phẳng làm từ đất sét, xi măng, kim loại, v.v."},"6020":{"word":"lời cầu nguyện, ước nguyện","meaning":"Ý nghĩ chân thành hoặc lời khẩn cầu hướng tới một sức mạnh thần thánh, hoặc một mong muốn mãnh liệt về một kết quả cụ thể."},"6021":{"word":"trước Công nguyên","meaning":"Chỉ những năm xảy ra trước năm sinh được cho là của Chúa Giê-su, được thể hiện trên dòng thời gian với các số giảm dần về 0."},"6022":{"word":"sau Công nguyên","meaning":"Chỉ những năm xảy ra sau năm sinh được cho là của Chúa Giê-su, được thể hiện trên dòng thời gian với các số tăng dần từ 0."},"6023":{"word":"ngày giỗ","meaning":"Ngày kỷ niệm một năm hoặc nhiều năm ngày mất của một người thân."},"6024":{"word":"điểm xuất phát","meaning":"Vị trí hoặc thời điểm bắt đầu của một hành trình, quá trình hay sự việc nào đó."},"6025":{"word":"hiến tặng","meaning":"Hành động tự nguyện cho đi nội tạng hoặc đồ vật có giá trị cho người khác hoặc tổ chức."},"6026":{"word":"chất khí","meaning":"Một trạng thái của vật chất mà không có hình dạng hay thể tích xác định, tự do lan tỏa trong không gian."},"6027":{"word":"nỗ lực đạt được","meaning":"Cố gắng hết sức để một kết quả cụ thể xảy ra hoặc thực hiện các bước cẩn thận để chắc chắn điều đó thành hiện thực."},"6028":{"word":"thời hạn","meaning":"Thời gian giới hạn đã được định sẵn để hoàn thành một việc gì đó."},"6029":{"word":"du ký","meaning":"Tác phẩm văn học ghi lại những địa điểm đã đi qua và trải nghiệm trong một chuyến đi."},"6030":{"word":"ký hiệu","meaning":"Dấu hiệu hoặc hình vẽ được dùng để đại diện cho một âm thanh, ý tưởng hoặc vật gì đó."},"6031":{"word":"sở thích","meaning":"Sự lựa chọn hoặc khuynh hướng ưa thích của nhiều người đối với một món đồ hoặc phong cách cụ thể."},"6032":{"word":"sự căng thẳng","meaning":"Cảm giác lo lắng tột độ khi chờ đợi một điều gì đó khó khăn hoặc quan trọng sắp xảy ra."},"6033":{"word":"làm kimchi mùa đông","meaning":"Hoạt động truyền thống vào cuối mùa thu hoặc đầu mùa đông để làm và dự trữ một lượng lớn kimchi cho cả gia đình dùng trong những tháng lạnh."},"6034":{"word":"lông vũ","meaning":"Lớp vỏ nhẹ, mềm, phẳng mọc trên cơ thể chim, giúp chúng bay và giữ ấm."},"6035":{"word":"khẽ cử động","meaning":"Từ diễn tả hành động cử động rất nhỏ, tinh vi đến mức khó nhận ra."},"6036":{"word":"chim ác là","meaning":"Một loài chim có lông đen trắng, đuôi dài, thường sống ở thành phố hoặc đồng ruộng."},"6037":{"word":"nháy mắt","meaning":"Hành động nhanh chóng mở và nhắm mí mắt lại, thường là phản xạ hoặc để làm sạch mắt."},"6038":{"word":"nhảy cẫng lên","meaning":"Từ diễn tả dáng vẻ người chân ngắn cùng lúc hai chân bật lên nhảy mạnh mẽ."},"6039":{"word":"sụt xuống","meaning":"Khi một phần mặt đất bất ngờ bị lún hoặc sụt hẳn xuống."},"6040":{"word":"bị gãy","meaning":"Khi một vật cứng hoặc chắc như cành cây đột nhiên bị nứt hoặc gập lại, làm thay đổi hình dạng ban đầu."},"6041":{"word":"vỏ (trứng)","meaning":"Lớp vật liệu cứng bao bọc bên ngoài của trứng, sò ốc và các vật tương tự."},"6042":{"word":"khoảng (hậu tố chỉ thời gian)","meaning":"Hậu tố được thêm vào sau từ chỉ thời gian để biểu thị thời điểm không chính xác mà chỉ là ước chừng."},"6043":{"word":"bắt chéo (chân)","meaning":"Hành động đặt một chân vắt lên chân kia."},"6044":{"word":"ùng ục (tiếng bụng)","meaning":"Từ mô phỏng âm thanh phát ra từ bụng khi đói hoặc khó tiêu."},"6045":{"word":"bé con","meaning":"Từ dùng để gọi một đứa trẻ nhỏ một cách thân mật và đáng yêu."},"6046":{"word":"suốt (một khoảng thời gian)","meaning":"Diễn tả việc duy trì trạng thái thức hoặc hoạt động liên tục từ đầu đến cuối một khoảng thời gian nhất định."},"6047":{"word":"đều đặn, đúng hạn","meaning":"Diễn tả việc thực hiện một hành động một cách thường xuyên và chính xác như mong đợi."},"6048":{"word":"kĩ càng, chặt chẽ","meaning":"Diễn tả việc làm gì đó một cách cẩn thận và hoàn chỉnh, hoặc giữ chặt một cái gì đó."},"6049":{"word":"- mỗi, - một","meaning":"Là hậu tố dùng để chỉ mỗi đơn vị cá thể nhận một lượng cụ thể nào đó."},"6050":{"word":"dáng vẻ, hình dạng","meaning":"Chỉ hình dáng bên ngoài hoặc hình thức có thể nhìn thấy của một vật nào đó."},"6051":{"word":"vị trí cuối cùng","meaning":"Vị trí sau cùng trong một cuộc đua, cuộc thi hoặc chuỗi sự việc."},"6052":{"word":"bất lực, không nhúc nhích","meaning":"Diễn tả tình huống một người không thể di chuyển, chống cự hoặc thay đổi những gì đang xảy ra với mình."},"6053":{"word":"đông cứng ngắc, đóng băng","meaning":"Diễn tả vật gì đó đã trở nên rất cứng và rắn do lạnh cực độ."},"6054":{"word":"rét nàng Bân, đợt rét đầu xuân","meaning":"Một đợt thời tiết lạnh bất thường diễn ra vào đầu mùa xuân, thường gây hại cho cây cối mới nảy mầm."},"6055":{"word":"gật gà gật gù","meaning":"Diễn tả cử động đầu của một người liên tục gật về phía trước và giật ngược trở lại do đang ngủ gật khi ngồi."},"6056":{"word":"la mắng, quở trách","meaning":"Nói với ai đó một cách giận dữ hoặc chỉ trích vì họ đã làm sai điều gì đó."},"6057":{"word":"người có kĩ năng về (hậu tố)","meaning":"Là hậu tố dùng để chỉ người giỏi hoặc chuyên về một hoạt động cụ thể."},"6058":{"word":"khâu, may vá","meaning":"Dùng kim chỉ để nối các mảnh vải hoặc sửa một lỗ thủng trên quần áo."},"6059":{"word":"lôi ra","meaning":"Kéo vật gì đó từ một không gian chật hẹp hoặc ẩn kín ra ngoài."},"6060":{"word":"sự kiên trì","meaning":"Khả năng tiếp tục làm việc khó khăn hoặc theo đuổi mục tiêu trong thời gian dài mà không bỏ cuộc."},"6061":{"word":"ngừng lại","meaning":"Một dòng chảy liên tục hoặc chuỗi sự kiện, người bị dừng lại hoặc bị đứt đoạn."},"6062":{"word":"kéo ra","meaning":"Dùng sức kéo một vật hoặc một người từ bên trong ra bên ngoài."},"6063":{"word":"lôi kéo","meaning":"Làm cho ai đó hoặc thứ gì đó đến gần một địa điểm cụ thể hoặc bị cuốn vào một tình huống nào đó."},"6064":{"word":"kéo lên","meaning":"Làm cho một vật từ vị trí thấp hơn lên vị trí cao hơn, hoặc làm cho chất lượng, trình độ được cải thiện rõ rệt."},"6065":{"word":"kinh khủng","meaning":"Diễn tả một sự kiện hoặc tình huống gây ra sự sốc, ghê tởm hoặc sợ hãi tột độ cho người chứng kiến hoặc nghe thấy."},"6066":{"word":"kết thúc","meaning":"Thực hiện những hành động cuối cùng để hoàn toàn dừng một công việc hoặc dự án."},"6067":{"word":"cái kết","meaning":"Điểm cuối cùng hoặc tình huống mà một việc gì đó hoàn toàn dừng lại hoặc không thể tiếp tục được nữa."},"6068":{"word":"bữa ăn","meaning":"Thời gian cụ thể trong ngày mà mọi người tiêu thụ thức ăn, chẳng hạn như vào buổi sáng, buổi trưa hoặc buổi tối."},"6069":{"word":"riêng","meaning":"Hậu tố này dùng để chỉ ra rằng một hành động hoặc trạng thái chỉ liên quan đến những cá nhân hoặc vật thể được xác định, không bao gồm những người hoặc vật thể khác bên ngoài nhóm của họ."},"6070":{"word":"từng ngày","meaning":"Diễn tả điều gì đó thay đổi hoặc tiến triển liên tục theo mỗi ngày trôi qua, thường là tăng hoặc giảm rõ rệt."},"6071":{"word":"lưu truyền","meaning":"Đi lại từ chỗ này sang chỗ khác hoặc thông tin được lan truyền rộng rãi giữa nhiều người."},"6072":{"word":"dã ngoại","meaning":"Việc đi ra ngoài đến một nơi gần nhà để thư giãn, giải trí trong một thời gian ngắn."},"6073":{"word":"sự liệt kê","meaning":"Việc sắp xếp nhiều vật phẩm hoặc tên theo một trình tự liên tiếp để dễ nhìn hoặc đọc."},"6074":{"word":"la bàn","meaning":"Một dụng cụ nhỏ, tròn có kim từ tính luôn chỉ hướng bắc, dùng để xác định phương hướng."},"6075":{"word":"niềm vui","meaning":"Cảm giác vui sướng, hài lòng sâu sắc mà một người trải nghiệm."},"6076":{"word":"sự lạc quan","meaning":"Thái độ tinh thần mà một người luôn mong đợi những kết quả tốt đẹp và có cái nhìn tích cực về tương lai."},"6077":{"word":"lạc quan","meaning":"Miêu tả người thường mong đợi những điều tốt đẹp xảy ra và thể hiện cái nhìn vui vẻ, tự tin về tương lai."},"6078":{"word":"sự trượt","meaning":"Sự kiện khi một người tham gia kỳ thi hoặc nộp đơn nhưng không được chấp nhận hoặc phê duyệt."},"6079":{"word":"hình vẽ nguệch ngoạc","meaning":"Những hình ảnh hoặc chữ viết đơn giản, không có kế hoạch, được vẽ ngẫu nhiên trên một bề mặt."},"6080":{"word":"sự nản lòng","meaning":"Cảm giác buồn bã sâu sắc và mất hy vọng khi một kết quả mong muốn không đạt được."},"6081":{"word":"thiên đường","meaning":"Một nơi đẹp đẽ và hoàn hảo nơi con người hoàn toàn hạnh phúc và mãn nguyện."},"6082":{"word":"sự thi rớt","meaning":"Hành động không vượt qua được bài kiểm tra hoặc môn học vì không đạt tiêu chuẩn yêu cầu."},"6083":{"word":"lạc quan, yêu đời","meaning":"Người có tính cách luôn nhìn cuộc sống một cách tích cực và tin rằng những điều tốt đẹp sẽ xảy ra."},"6084":{"word":"câu cá","meaning":"Dùng cần câu, dây và lưỡi câu để bắt các sinh vật dưới nước, thường là để làm thức ăn hoặc giải trí."},"6085":{"word":"bãi câu cá, điểm câu cá","meaning":"Một địa điểm cụ thể, thường là gần bờ nước, nơi mọi người đến để câu cá bằng cần và dây."},"6086":{"word":"-khủng hoảng, -thiếu hụt (tiếp tố)","meaning":"Là hậu tố gắn vào danh từ để chỉ sự thiếu hụt nghiêm trọng hoặc tình hình khó khăn, bất ổn."},"6087":{"word":"chuyên mục, mục","meaning":"Một khoảng không gian được chia ra trong báo chí hoặc tài liệu để đăng nội dung nhất định, như quảng cáo."},"6088":{"word":"lan can","meaning":"Một rào chắn bảo vệ gồm thanh ngang được đỡ bởi các trụ, thường thấy dọc cầu thang, ban công hoặc cầu."},"6089":{"word":"bệnh nan y","meaning":"Một tình trạng y tế rất nghiêm trọng mà các bác sĩ cực kỳ khó hoặc không thể chữa khỏi hoàn toàn."},"6090":{"word":"ngày càng, mỗi ngày","meaning":"Chỉ việc sự việc diễn ra hoặc thay đổi liên tục và tăng lên theo từng ngày."},"6091":{"word":"bay vào, bay đến","meaning":"Di chuyển trong không khí bằng cánh và đến bên trong hoặc về phía một khu vực cụ thể."},"6092":{"word":"bay lên, cất cánh","meaning":"Dùng cánh hoặc động cơ để đẩy bản thân bay lên không trung hoặc bầu trời."},"6093":{"word":"Nam Cực","meaning":"Điểm lạnh nhất, cực nam nhất trên Trái Đất, một khối đất lớn bao phủ bởi băng dày."},"6094":{"word":"nam nữ già trẻ, mọi lứa tuổi","meaning":"Chỉ tất cả mọi người, không phân biệt giới tính hay tuổi tác."},"6095":{"word":"xuất chúng","meaning":"Có phẩm chất, tài năng hoặc đặc điểm vượt trội, khác biệt so với người khác."},"6096":{"word":"bí mật","meaning":"Một cách kín đáo, không để người khác biết hoặc nhìn thấy."},"6097":{"word":"màu xanh tím than","meaning":"Một sắc xanh rất đậm, sẫm màu, giống màu đồng phục lính thủy hoặc màu biển sâu."},"6098":{"word":"bé trai","meaning":"Người con còn nhỏ thuộc giới tính nam."},"6099":{"word":"hơn một chút","meaning":"Diễn tả một số lượng hoặc khoảng thời gian nhiều hơn một chút so với con số được nêu ra."},"6100":{"word":"Nam Hàn","meaning":"Tên gọi của đất nước nằm ở phía nam bán đảo Triều Tiên."},"6101":{"word":"hướng nam","meaning":"Hướng mà một tòa nhà hoặc cửa sổ nhìn về phía nam, nơi mặt trời xuất hiện vào giữa trưa."},"6102":{"word":"sự nộp","meaning":"Hành động trả tiền cho một cá nhân hoặc tổ chức vì đã nợ tiền hàng hóa, dịch vụ hoặc thuế."},"6103":{"word":"dẹt","meaning":"Có bề mặt phẳng, ít chiều cao hoặc chiều sâu, trông mịn và đều."},"6104":{"word":"sự bắt cóc","meaning":"Hành động bất hợp pháp dùng vũ lực đưa một người đi, thường là để giữ họ trái với ý muốn của họ."},"6105":{"word":"sự đọc thành tiếng","meaning":"Hành động đọc các từ viết ra từ một văn bản sao cho người khác có thể nghe thấy."},"6106":{"word":"sự lãng mạn","meaning":"Cảm giác hứng thú và kỳ diệu liên quan đến tình yêu, phiêu lưu hoặc vẻ đẹp, thường thấy trong truyện hoặc nghệ thuật."},"6107":{"word":"lãng mạn","meaning":"Chỉ cái gì đó khơi gợi cảm xúc yêu đương, mơ mộng hoặc sự phiêu lưu và vẻ đẹp."},"6108":{"word":"mặt","meaning":"Phần phía trước của đầu người, bao gồm mắt, mũi và miệng."},"6109":{"word":"quen mặt","meaning":"Mô tả một người hoặc vật mà bạn nhận ra vì đã từng thấy trước đây."},"6110":{"word":"từ, từ ngữ","meaning":"Đơn vị ngôn ngữ nhỏ nhất, có thể dùng độc lập, mang nghĩa, âm thanh và chức năng riêng."},"6111":{"word":"cá cược, vụ cá cược","meaning":"Một thỏa thuận mà người thắng cuộc trong trò chơi sẽ nhận được tiền hoặc vật phẩm đã được đồng ý trước."},"6112":{"word":"bước, đặt bước","meaning":"Di chuyển chân về phía trước để tiến lên theo một hướng cụ thể."},"6113":{"word":"giáng xuống, đánh mạnh xuống","meaning":"Đánh một vật gì đó mạnh mẽ bằng một động tác từ trên xuống dưới."},"6114":{"word":"nội tâm, bên trong","meaning":"Phần không thể nhìn thấy trong suy nghĩ, cảm xúc và tính cách của một người."},"6115":{"word":"thốt ra, phun ra","meaning":"Đột nhiên nói ra lời một cách lớn tiếng hoặc mạnh mẽ mà không có kế hoạch."},"6116":{"word":"trình ra, cho xem","meaning":"Lấy một thứ gì đó ra và làm cho nó hiện rõ để người khác nhìn thấy."},"6117":{"word":"quần áo lót, đồ lót","meaning":"Một lớp quần áo mỏng mặc trực tiếp sát da, bên dưới các lớp quần áo khác, thường để giữ ấm."},"6118":{"word":"hệ thống định vị (GPS), định vị","meaning":"Một hệ thống điện tử, thường hiển thị trên màn hình xe hoặc điện thoại, sử dụng tín hiệu vệ tinh để hiển thị bản đồ và cung cấp chỉ dẫn đến một địa điểm cụ thể."},"6119":{"word":"hé lộ, lộ ra","meaning":"Hiện ra một phần hoặc trở nên rõ ràng, thường là lấp ló từ phía sau hoặc xuyên qua một vật khác."},"6120":{"word":"thở ra","meaning":"Đẩy không khí từ bên trong phổi ra ngoài cơ thể qua miệng hoặc mũi."},"6121":{"word":"chi tiết, bảng kê","meaning":"Một bản ghi hoặc danh sách chứa tất cả các phần riêng lẻ hoặc số tiền tài chính tạo nên tổng thể hoặc một hoạt động cụ thể."},"6122":{"word":"mang ra, đem ra","meaning":"Di chuyển một vật từ bên trong phòng hoặc thùng chứa ra một nơi có thể nhìn thấy hoặc sử dụng được ở bên ngoài."},"6123":{"word":"vật chứa, nội dung","meaning":"Tất cả các vật phẩm hoặc chất được lưu trữ bên trong một hộp, túi, chai hoặc bất kỳ loại vật chứa nào khác."},"6124":{"word":"hét lớn, la to","meaning":"Đột nhiên phát ra một âm thanh giọng nói rất lớn, thường do cảm xúc mạnh như giận dữ, đau đớn hoặc phấn khích, hoặc để thu hút sự chú ý."},"6125":{"word":"hơi lạnh, khí lạnh","meaning":"Không khí có nhiệt độ thấp rõ rệt, gây ra cảm giác lạnh buốt đặc trưng khi chạm vào da."},"6126":{"word":"khí hậu lạnh, vùng lạnh","meaning":"Vùng nằm giữa vùng ôn đới và vùng cực, có mùa đông dài và lạnh giá, mùa hè ngắn với nhiệt độ cao."},"6127":{"word":"quá đáng, bất công","meaning":"Một tình huống hoặc hành động được coi là không hợp lý, quá mức hoặc sai trái về mặt đạo đức, khiến người khác cảm thấy đau khổ hoặc bị xúc phạm."},"6128":{"word":"chiều rộng, bề rộng","meaning":"Chiều dài theo chiều ngang của một hình phẳng hoặc một vật thể rộng."},"6129":{"word":"bốn (dùng với từ đếm)","meaning":"Là từ chỉ số lượng \"bốn\", được dùng làm định ngữ trước một số danh từ chỉ đơn vị nhất định (ví dụ: tháng, người)."},"6130":{"word":"nhảy bập bênh (truyền thống Hàn Quốc)","meaning":"Một trò chơi ngoài trời truyền thống của Hàn Quốc, trong đó hai người đứng ở hai đầu đối diện của một tấm ván gỗ dài được cân bằng trên một điểm tựa, thay phiên nhau đẩy người lên cao."},"6131":{"word":"(chỉ nhóm người)","meaning":"Đây là một tiếp tố gắn vào sau một số danh từ để chỉ một tập hợp người, thường ngụ ý một loại hoặc mối quan hệ cụ thể."},"6132":{"word":"vuông","meaning":"Có hình dạng với bốn cạnh thẳng và bốn góc vuông."},"6133":{"word":"mạng","meaning":"Một hệ thống các máy tính hoặc thiết bị liên kết với nhau để chia sẻ thông tin và tài nguyên."},"6134":{"word":"-nữ","meaning":"Tiếp tố được dùng để chỉ người đang được miêu tả là nữ giới."},"6135":{"word":"sinh năm","meaning":"Từ dùng để chỉ năm mà một người được sinh ra."},"6136":{"word":"tuổi già","meaning":"Giai đoạn cuối của cuộc đời con người, khi thể chất và tinh thần bắt đầu suy giảm."},"6137":{"word":"lực lượng lao động","meaning":"Tổng số người có khả năng và sẵn sàng làm việc để kiếm thu nhập trong một khu vực hoặc quốc gia."},"6138":{"word":"người vô gia cư","meaning":"Một người không có nơi ở cố định và thường ngủ ngoài trời hoặc trong các nơi trú ẩn công cộng."},"6139":{"word":"nô lệ","meaning":"Một người bị mua bán như hàng hóa và phải làm theo mọi mệnh lệnh của người chủ."},"6140":{"word":"ráng chiều","meaning":"Ánh sáng nhiều màu sắc, thường là đỏ, cam hoặc tím, xuất hiện trên bầu trời khi mặt trời lặn vào buổi tối."},"6141":{"word":"phụ nữ lớn tuổi chưa chồng","meaning":"Một người phụ nữ đã đến tuổi lập gia đình nhưng vẫn chưa kết hôn."},"6142":{"word":"đàn ông lớn tuổi chưa vợ","meaning":"Một người đàn ông đã đến tuổi lập gia đình nhưng vẫn chưa kết hôn."},"6143":{"word":"sự lộ ra, sự phơi bày","meaning":"Tình trạng bị lộ ra, bị phơi bày ra bên ngoài, có thể nhìn thấy hoặc bị ảnh hưởng."},"6144":{"word":"sự lão hóa","meaning":"Quá trình tự nhiên mà sinh vật dần trở nên già đi và xuất hiện những thay đổi về thể chất."},"6145":{"word":"tuổi già, lúc về già","meaning":"Thời kỳ cuộc đời khi một người đã lớn tuổi."},"6146":{"word":"ruộng, ruộng lúa","meaning":"Đất được tưới tiêu dùng để trồng lúa."},"6147":{"word":"luận văn, bài báo khoa học","meaning":"Bài viết dài trình bày nghiên cứu hoặc quan điểm về một chủ đề cụ thể, thường dùng để lấy bằng cấp hoặc đăng trên tạp chí khoa học."},"6148":{"word":"ruộng đồng, đất nông nghiệp","meaning":"Khu vực đất rộng dùng để trồng các loại cây lương thực hoặc thực vật khác."},"6149":{"word":"bài luận","meaning":"Bài viết trình bày và giải thích suy nghĩ hoặc lập luận về một chủ đề cụ thể, thường dùng để kiểm tra sự hiểu biết."},"6150":{"word":"thằng","meaning":"Từ dùng để chỉ người đàn ông với ý xúc phạm hoặc coi thường."},"6151":{"word":"hộ nông dân, nhà nông","meaning":"Gia đình hoặc nhà ở của những người làm nghề trồng trọt hoặc chăn nuôi để kiếm sống."},"6152":{"word":"nông nghiệp, sự canh tác","meaning":"Hoạt động trồng trọt cây lương thực và chăn nuôi động vật trên đất để sản xuất lương thực và hàng hóa."},"6153":{"word":"nồng độ, mật độ","meaning":"Lượng một chất cụ thể có mặt trong một thể tích hoặc khu vực nhất định của một chất khác."},"6154":{"word":"nông thủy sản","meaning":"Các loại thực phẩm được trồng trọt từ đất liền hoặc khai thác từ biển như rau, quả, cá, hải sản."},"6155":{"word":"nông nhạc","meaning":"Một loại hình biểu diễn truyền thống sôi động của Hàn Quốc, trong đó người ta chơi trống, chiêng và các nhạc cụ khác, thường dành cho lễ kỷ niệm hoặc nghi lễ."},"6156":{"word":"nông sản","meaning":"Các loại cây trồng như ngũ cốc, trái cây và rau củ mà con người canh tác để thu hoạch làm thực phẩm hoặc dùng cho mục đích khác."},"6157":{"word":"nông trại","meaning":"Một khu đất, thường có các tòa nhà, nơi người ta trồng trọt cây cối hoặc nuôi động vật để lấy lương thực hay mục đích thương mại khác."},"6158":{"word":"nông và gia súc","meaning":"Các mặt hàng thực phẩm và nguyên liệu có nguồn gốc từ cây trồng trên ruộng đất hoặc từ động vật được con người chăn nuôi."},"6159":{"word":"thả ra","meaning":"Mở tay hoặc bỏ mọi ràng buộc, cho phép vật đang giữ hoặc sinh vật bị giam cầm di chuyển tự do."},"6160":{"word":"đi vệ sinh","meaning":"Đào thải chất thải của cơ thể như nước tiểu hoặc phân ra ngoài."},"6161":{"word":"vàng ố","meaning":"Có màu sắc giống như chanh hoặc ngô chín, thường trông hơi xỉn hoặc nhạt."},"6162":{"word":"hưởng thụ","meaning":"Trải nghiệm hoặc nhận được lợi ích từ điều gì đó dễ chịu hoặc có lợi."},"6163":{"word":"rò điện","meaning":"Tình trạng dòng điện thoát ra khỏi đường dẫn chính trong dây hoặc thiết bị điện, có thể gây ra tia lửa, giật điện hoặc quá nhiệt."},"6164":{"word":"ngang tầm mắt","meaning":"Chiều cao cụ thể mà mắt của một người thường được đặt khi nhìn thẳng về phía trước."},"6165":{"word":"tuyết bay","meaning":"Những hạt nước đóng băng nhỏ, nhẹ rơi nhẹ nhàng và thưa thớt từ trên trời xuống, thường được gió cuốn đi."},"6166":{"word":"tuyết lở","meaning":"Sự di chuyển đột ngột và mạnh mẽ của một khối lượng lớn nước đóng băng, đá và mảnh vỡ đổ xuống sườn núi một cách nhanh chóng."},"6167":{"word":"sự cau mày","meaning":"Khuôn mặt biểu hiện sự khó chịu, suy nghĩ hoặc không hài lòng bằng cách nhíu hai lông mày lại."},"6168":{"word":"cái liếc mắt","meaning":"Một hành động đưa mắt nhìn nhanh và ngắn gọn về phía ai đó hoặc cái gì đó, thường dùng để gửi một thông điệp hoặc tín hiệu im lặng."},"6169":{"word":"nhận ra","meaning":"Bất ngờ trở nên nhận thức được điều gì đó, thường là một chi tiết tinh tế hoặc sự thật ẩn giấu, thông qua quan sát hoặc cảm giác trực giác."},"6170":{"word":"bị đè","meaning":"Có trọng lượng đè xuống một vật gì đó, khiến nó trở nên phẳng hơn hoặc chặt hơn."},"6171":{"word":"hối hận","meaning":"Cảm thấy buồn bã hoặc tội lỗi sau khi nhận ra mình đã làm điều gì đó sai, mong muốn nó có thể được thay đổi."},"6172":{"word":"chó sói","meaning":"Một loài động vật hoang dã thuộc họ chó, thường lớn hơn cáo, có lông dày, tai nhọn và mõm dài, thường sống theo bầy và nổi tiếng với tiếng hú đặc trưng."},"6173":{"word":"chảy xệ","meaning":"Treo lỏng lẻo không căng, thường có vẻ thấp hơn mức bình thường."},"6174":{"word":"chủ động","meaning":"Mô tả một người hoặc điều gì đó tự mình thực hiện sáng kiến và tham gia mà không cần được bảo hoặc bị ép buộc."},"6175":{"word":"hiệu suất","meaning":"Chất lượng thực hiện một việc gì đó tốt và nhanh chóng, sử dụng ít thời gian, tiền bạc hoặc công sức nhất."},"6176":{"word":"thành thạo","meaning":"Thực hiện một nhiệm vụ hoặc hoạt động rất dễ dàng và chuyên nghiệp, thể hiện trình độ khả năng cao."},"6177":{"word":"đa- (tiếp đầu ngữ)","meaning":"Một phần từ được thêm vào đầu một từ khác để mang nghĩa 'nhiều' hoặc 'một vài'."},"6178":{"word":"khẩn cấp","meaning":"Mô tả một tình huống hoặc nhu cầu đòi hỏi sự chú ý hoặc hành động ngay lập tức vì thời gian đang cạn dần."},"6179":{"word":"đạt đến","meaning":"Đạt được một điểm hoặc một nơi cụ thể sau một hành trình hoặc nỗ lực."},"6180":{"word":"càng nhiều càng tốt","meaning":"Một ý tưởng hay tình huống mà việc có số lượng lớn hơn của một thứ luôn được coi là có lợi hoặc đáng mong muốn hơn."},"6181":{"word":"như thường lệ","meaning":"Thực hiện một điều gì đó theo cách thức hoặc điều kiện y hệt như những lần trước, không có bất kỳ thay đổi nào."},"6182":{"word":"bó, chùm","meaning":"Một tập hợp gồm nhiều vật phẩm được giữ hoặc buộc lại với nhau thành một đơn vị duy nhất."},"6183":{"word":"đa phương diện","meaning":"Mô tả sự tham gia hoặc kiến thức trải rộng trên nhiều lĩnh vực hoặc chủ đề khác nhau."},"6184":{"word":"cai trị, quản lý","meaning":"Quản lý và điều hành các công việc của một quốc gia, tổ chức hoặc nhóm người."},"6185":{"word":"chép miệng, tặc lưỡi","meaning":"Hút và nuốt nước bọt khi muốn ăn món gì đó hoặc khi tiếc nuối vì thức ăn đã hết."},"6186":{"word":"sự đa dạng","meaning":"Một đặc tính có nhiều loại thành phần, hình dạng, màu sắc, v.v."},"6187":{"word":"sự đa dạng hóa","meaning":"Hành động thay đổi một thứ gì đó để bao gồm nhiều loại hoặc kiểu khác nhau, hoặc thêm nhiều sự phong phú hơn vào đó."},"6188":{"word":"lặn, nhảy cầu","meaning":"Hành động nhảy từ một nơi cao xuống nước, hoặc một môn thể thao làm điều này."},"6189":{"word":"kim cương","meaning":"Một loại đá quý trong suốt, rất cứng và sáng bóng, thường được cắt thành hình dạng đặc biệt để làm đồ trang sức."},"6190":{"word":"phim tài liệu","meaning":"Một bộ phim hoặc chương trình truyền hình trình chiếu các sự kiện, địa điểm hoặc con người có thật, cung cấp thông tin thực tế thay vì một câu chuyện hư cấu."},"6191":{"word":"xảy đến, ập đến","meaning":"Một sự việc không mong muốn hoặc bất ngờ đột ngột xảy ra với ai đó hoặc tình huống nào đó."},"6192":{"word":"đoàn, đội","meaning":"Hậu tố được thêm vào sau danh từ để chỉ một nhóm người cùng làm việc hoặc biểu diễn."},"6193":{"word":"gấu (áo/quần)","meaning":"Phần mép của quần áo được gập vào và may lại cho gọn gàng."},"6194":{"word":"Dangun","meaning":"Tên của một vị lãnh đạo huyền thoại cổ đại của Triều Tiên, được cho là đã lập nên vương quốc đầu tiên."},"6195":{"word":"ngắn hạn, thời gian ngắn","meaning":"Một khoảng thời gian không dài."},"6196":{"word":"kết thúc (giai đoạn), hoàn thành (giai đoạn)","meaning":"Việc kết thúc một giai đoạn nhất định của công việc."},"6197":{"word":"thiết bị đầu cuối","meaning":"Một loại máy điện tử, thường có màn hình và nút bấm, dùng để kết nối với hệ thống máy tính lớn hơn để gửi hoặc nhận thông tin."},"6198":{"word":"protein, chất đạm","meaning":"Một chất tự nhiên có trong các loại thực phẩm như thịt, trứng, đậu, giúp cơ thể xây dựng và sửa chữa tế bào."},"6199":{"word":"đơn nhất, thống nhất","meaning":"Mô tả một vật hoặc hệ thống hoàn chỉnh duy nhất, không chia thành nhiều phần, hoặc nhiều phần hợp lại làm một."},"6200":{"word":"đứt đoạn, cắt đứt, gián đoạn","meaning":"Trạng thái một mối quan hệ hoặc kết nối bị cắt đứt hoàn toàn, không còn liên hệ hoặc giao tiếp giữa người hoặc vật."},"6201":{"word":"kết luận, quyết định","meaning":"Một phán đoán cuối cùng hoặc ý kiến chắc chắn mà ai đó đưa ra sau khi xem xét tất cả thông tin có sẵn."},"6202":{"word":"đơn điệu, nhàm chán","meaning":"Mô tả một việc lặp đi lặp lại cùng một kiểu hoặc hành động mà không có nhiều thay đổi, thường gây cảm giác buồn tẻ hoặc không thú vị."},"6203":{"word":"rút ngắn","meaning":"Việc làm cho độ dài hoặc thời gian của một việc gì đó trở nên ngắn hơn."},"6204":{"word":"đoàn kết","meaning":"Tình trạng mọi người hoặc các nhóm làm việc cùng nhau trong sự đồng thuận và hòa hợp, hành động như một thể thống nhất."},"6205":{"word":"cân","meaning":"Dùng dụng cụ để xác định trọng lượng của một vật thể."},"6206":{"word":"khác biệt","meaning":"Làm cho một thứ không giống với thứ khác, hoặc để nhiều thứ thể hiện các hình thức, phương pháp tương phản."},"6207":{"word":"bida","meaning":"Một trò chơi được chơi trên bàn phẳng có các lỗ, người chơi dùng gậy dài để đánh các quả bóng cứng vào lỗ."},"6208":{"word":"chính quyền","meaning":"Một nhóm người trong một tổ chức hoặc quốc gia có quyền lực đưa ra và thực thi các quyết định hoặc quy tắc."},"6209":{"word":"bệnh tiểu đường","meaning":"Một tình trạng sức khỏe mà cơ thể không sản xuất hoặc sử dụng đúng cách chất cần thiết để quản lý đường trong máu, dẫn đến mức đường cao."},"6210":{"word":"cấp bách","meaning":"Mô tả một vấn đề hoặc tình huống đang trực tiếp ở phía trước và cần được xử lý ngay lập tức."},"6211":{"word":"lời dặn dò","meaning":"Một lời yêu cầu chân thành, nơi một người yêu cầu người khác làm điều gì đó quan trọng, thường với giọng điệu nghiêm túc hoặc lo lắng."},"6212":{"word":"đắc cử","meaning":"Khoảnh khắc một người được chính thức chọn vào một vị trí hoặc vai trò chính trị sau khi nhiều người đã bỏ phiếu."},"6213":{"word":"lớn","meaning":"Chỉ vật có kích thước, quy mô lớn nhất khi so sánh với các vật khác cùng loại."},"6214":{"word":"thế hệ","meaning":"Một nhóm người sinh ra và sống cùng thời điểm, hoặc dòng dõi liên tục từ cha mẹ đến con cái qua nhiều năm."},"6215":{"word":"gia đình đông người","meaning":"Một gia đình có nhiều thành viên sống chung với nhau."},"6216":{"word":"đáng tự hào","meaning":"Cảm thấy rất hài lòng và hạnh phúc khi ai đó đạt được thành tích tốt hoặc hành xử trưởng thành."},"6217":{"word":"đối đầu","meaning":"Cuộc gặp gỡ căng thẳng giữa hai bên hoặc hai người đối lập, cố gắng đánh bại hoặc vượt qua đối phương."},"6218":{"word":"lời đáp","meaning":"Một câu nói ngắn gọn để trả lời lại những gì người khác nói."},"6219":{"word":"cây tre","meaning":"Một loại cây thân rỗng, cứng, mọc cao và nhanh, thường có màu xanh và mọc thành bụi dày đặc."},"6220":{"word":"phỏng vấn","meaning":"Cuộc trao đổi chính thức các câu hỏi, câu trả lời và ý kiến giữa hai hoặc nhiều người, thường được phát sóng hoặc công bố rộng rãi."},"6221":{"word":"đời đời","meaning":"Mô tả việc gì đó được truyền lại hoặc tiếp tục từ thế hệ cha mẹ sang thế hệ con cháu, lặp đi lặp lại qua thời gian."},"6222":{"word":"bình đẳng","meaning":"Trạng thái mà hai hoặc nhiều sự vật, người có giá trị, cấp bậc hoặc mức độ ảnh hưởng ngang nhau, không ai hơn ai."},"6223":{"word":"xấp xỉ","meaning":"Mô tả cái gì đó gần đúng về số lượng, kích thước hoặc hình thức nhưng thiếu chi tiết chính xác hoặc độ chuẩn xác tuyệt đối."},"6224":{"word":"lục địa","meaning":"Một khối đất liền rộng lớn được bao quanh bởi đại dương."},"6225":{"word":"đại lý","meaning":"Một cửa hàng bán sản phẩm hoặc dịch vụ cụ thể thay mặt cho một công ty, ví dụ như cửa hàng của nhà cung cấp điện thoại di động."},"6226":{"word":"đầu hói","meaning":"Tình trạng phần đỉnh đầu của một người không có tóc, khiến da đầu lộ ra."},"6227":{"word":"đại từ","meaning":"Đại từ là từ dùng để thay thế cho danh từ hoặc cụm danh từ đã được nhắc đến trước đó."},"6228":{"word":"Rằm tháng Giêng","meaning":"Rằm tháng Giêng là ngày lễ truyền thống của Hàn Quốc vào đêm trăng tròn đầu tiên của năm mới âm lịch."},"6229":{"word":"kịch bản","meaning":"Kịch bản là văn bản ghi lời thoại của diễn viên và mô tả cảnh quay trong một vở kịch hoặc bộ phim."},"6230":{"word":"giải thưởng lớn","meaning":"Giải thưởng lớn là phần thưởng cao quý nhất dành cho người chiến thắng chung cuộc trong một cuộc thi."},"6231":{"word":"phương án thay thế","meaning":"Phương án thay thế là một kế hoạch, ý tưởng hoặc phương pháp khác được đưa ra khi cái cũ không phù hợp hoặc không thể sử dụng."},"6232":{"word":"cho thuê","meaning":"Cho thuê là việc trả tiền để tạm thời sử dụng một món đồ, ví dụ như sách hoặc xe hơi, trong một khoảng thời gian nhất định rồi trả lại."},"6233":{"word":"đối xử","meaning":"Đối xử là cách mà một người hành động hoặc giải quyết vấn đề với người khác, nhóm người hoặc đối tượng, thể hiện qua hành động và lời nói của họ."},"6234":{"word":"liên nhân","meaning":"Liên nhân mô tả các mối tương tác và quan hệ giữa những người khác nhau, như hai cá nhân nói chuyện hoặc làm việc cùng nhau."},"6235":{"word":"tuyển sinh đại học","meaning":"Tuyển sinh đại học là quá trình học sinh chuẩn bị và cố gắng được nhận vào một cơ sở giáo dục đại học sau khi tốt nghiệp cấp ba."},"6236":{"word":"thủ lĩnh","meaning":"Thủ lĩnh là người giữ vị trí chỉ huy cao nhất và ra lệnh cho một nhóm người, như một đơn vị quân đội hoặc một đội."},"6237":{"word":"đối lập","meaning":"Đối lập là mô tả hai điều cho thấy sự khác biệt rất rõ ràng và rõ rệt khi chúng được xem xét hoặc đặt cạnh nhau."},"6238":{"word":"cử nhân","meaning":"Cử nhân là người đã hoàn thành xuất sắc việc học và đạt được bằng cấp từ một cơ sở giáo dục đại học."},"6239":{"word":"đại chúng","meaning":"Được nhiều người biết đến, ưa chuộng hoặc chấp nhận rộng rãi trong xã hội."},"6240":{"word":"sự đại chúng hóa","meaning":"Việc làm cho một cái gì đó trở nên phổ biến, được đông đảo công chúng biết đến và sử dụng."},"6241":{"word":"rốt cuộc","meaning":"Từ dùng để nhấn mạnh trong câu hỏi, thể hiện sự ngạc nhiên hoặc muốn biết rõ nguyên nhân."},"6242":{"word":"táo tàu","meaning":"Một loại quả ngọt, hình dáng giống quả trứng chim nhỏ, vỏ chuyển sang màu đỏ khi chín."},"6243":{"word":"sự sơ tán","meaning":"Hành động di chuyển nhanh chóng mọi người từ nơi nguy hiểm đến một khu vực an toàn hơn."},"6244":{"word":"xe cỡ lớn","meaning":"Một loại phương tiện giao thông rất lớn có bánh xe, thường là xe tải, xe buýt hoặc máy móc xây dựng."},"6245":{"word":"bình luận","meaning":"Một đoạn văn bản ngắn mà ai đó viết và đăng bên dưới một bài viết, video hoặc hình ảnh trên internet."},"6246":{"word":"lắp bắp","meaning":"Nói một cách khó khăn, với nhiều khoảng dừng và lặp lại, không thể phát âm rõ ràng các từ."},"6247":{"word":"vô cùng","meaning":"Đến mức không gì có thể tốt hơn hoặc hơn thế nữa, đạt đến mức độ cao nhất có thể."},"6248":{"word":"bớt đi","meaning":"Về số lượng hoặc mức độ trở nên nhỏ hơn, hoặc không còn lớn hay đáng kể như trước."},"6249":{"word":"nhiễm trùng","meaning":"Vết cắt hoặc vết thương bị nhiễm trùng hoặc trở nên đau hơn, cho thấy dấu hiệu trở nên nghiêm trọng hơn nhiều."},"6250":{"word":"cuộc biểu tình","meaning":"Một sự kiện mà một nhóm người tụ tập ở nơi công cộng để thể hiện sự phản đối mạnh mẽ hoặc ủng hộ một điều gì đó."},"6251":{"word":"đạo","meaning":"Chân lý, nguyên tắc hoặc con đường tu tập mà người ta học hỏi và giác ngộ."},"6252":{"word":"yêu tinh","meaning":"Một sinh vật tinh quái trong văn hóa dân gian Hàn Quốc, thường có sừng hoặc khuôn mặt kỳ dị, hay chơi khăm người."},"6253":{"word":"rìu","meaning":"Một dụng cụ cầm tay dùng để chặt cây hoặc bổ củi."},"6254":{"word":"sự đạt được","meaning":"Hành động đến một nơi cụ thể, một giai đoạn nhất định hoặc hoàn thành thành công một mục tiêu sau nỗ lực."},"6255":{"word":"bị mất trộm","meaning":"Phát hiện ra món đồ của mình bị người khác lén lút lấy đi mà không có sự cho phép."},"6256":{"word":"bán buôn","meaning":"Việc bán hàng hóa với số lượng lớn cho các doanh nghiệp, thay vì bán từng món hàng trực tiếp cho khách hàng."},"6257":{"word":"cờ bạc","meaning":"Hoạt động đặt cược tiền hoặc vật có giá trị vào một trò chơi hay sự kiện không chắc chắn kết quả, với hy vọng giành được nhiều tiền hơn."},"6258":{"word":"đi bộ","meaning":"Hành động di chuyển từ nơi này sang nơi khác bằng cách dùng chân bước đi."},"6259":{"word":"đô thị hóa","meaning":"Quá trình một khu vực thay đổi từ đất trống hoặc làng mạc nhỏ thành nơi có nhiều tòa nhà cao tầng, đường phố và dân cư đông đúc."},"6260":{"word":"người giúp việc","meaning":"Người cung cấp sự hỗ trợ hoặc dịch vụ cho người khác, thường là bằng cách thực hiện các công việc cho họ."},"6261":{"word":"biểu đồ","meaning":"Một bản vẽ sử dụng các đường nét, hình dạng và hình ảnh để trình bày thông tin hoặc sự kiện một cách dễ hiểu."},"6262":{"word":"sự bỏ trốn","meaning":"Hành động nhanh chóng rời đi khỏi một tình huống hoặc nơi khó khăn, nguy hiểm để tránh né nó."},"6263":{"word":"độc lập","meaning":"Không cần sự giúp đỡ hay hướng dẫn từ người khác, thường tự mình làm mọi việc."},"6264":{"word":"phòng riêng","meaning":"Một không gian kín chỉ có một người ở, thường dùng để ngủ hoặc là hình thức phạt."},"6265":{"word":"độc thân","meaning":"Chỉ người không có vợ hoặc chồng."},"6266":{"word":"độc đáo, sáng tạo","meaning":"Chỉ cái gì đó hoàn toàn mới mẻ và xuất phát từ những ý tưởng tươi mới, không sao chép từ bất kỳ điều gì khác."},"6267":{"word":"nổi bật","meaning":"Dễ dàng được nhìn thấy hoặc nhận ra là tốt hơn hoặc quan trọng hơn những thứ khác xung quanh."},"6268":{"word":"khơi dậy, kích thích","meaning":"Làm cho một cảm xúc hoặc phản ứng trở nên mạnh mẽ hơn hoặc xuất hiện ở ai đó."},"6269":{"word":"quay lại, suy ngẫm","meaning":"Thay đổi hướng và di chuyển ngược lại, hoặc suy nghĩ cẩn thận về các sự kiện trong quá khứ."},"6270":{"word":"tòa","meaning":"Từ dùng để đếm các cấu trúc lớn riêng lẻ mà con người sinh sống hoặc làm việc, đặc biệt khi chúng là một phần của một khu phức hợp lớn hơn."},"6271":{"word":"đồng cảm, đồng tình","meaning":"Tình trạng có cùng suy nghĩ với người khác, hoặc suy nghĩ như vậy."},"6272":{"word":"sống chung","meaning":"Hành động cùng sống trong một nhà hoặc một phòng."},"6273":{"word":"hang động","meaning":"Một lỗ tự nhiên lớn, sâu trong lòng đất."},"6274":{"word":"dồn dập","meaning":"Mô tả hành động đập chân xuống đất một cách nhanh chóng, lặp đi lặp lại, thường do sốt ruột hoặc tức giận."},"6275":{"word":"đồng môn","meaning":"Người đã học cùng một trường hoặc cùng một thầy giáo."},"6276":{"word":"sự đồng hành","meaning":"Việc đi cùng, đi kèm với người khác hoặc một nhóm."},"6277":{"word":"động từ","meaning":"Loại từ chỉ hành động, trạng thái của sự vật, sự việc."},"6278":{"word":"tượng đồng","meaning":"Một tác phẩm điêu khắc hình người hoặc vật được làm bằng đồng."},"6279":{"word":"Đông Tây","meaning":"Chỉ các khu vực và nền văn hóa của châu Á (phương Đông) và châu Âu, châu Mỹ (phương Tây)."},"6280":{"word":"động thực vật","meaning":"Toàn bộ các loài động vật và thực vật sống trong một khu vực cụ thể."},"6281":{"word":"sự huy động","meaning":"Hành động tập hợp, thu thập và đưa vào sử dụng các lực lượng, tài nguyên cần thiết."},"6282":{"word":"đồng chí","meaning":"Người có cùng mục tiêu, lý tưởng hoặc quan điểm với mình."},"6283":{"word":"sự đồng hành","meaning":"Việc cùng đi hoặc cùng di chuyển đến một nơi nào đó với người khác."},"6284":{"word":"hướng đông","meaning":"Chỉ một vật thể hay công trình có mặt chính quay về phía mặt trời mọc."},"6285":{"word":"sự đồng hóa","meaning":"Quá trình một cá nhân hoặc một nhóm hòa nhập và trở nên giống với môi trường, văn hóa hoặc chất khác."},"6286":{"word":"nhìn lại","meaning":"Xoay đầu để nhìn về phía sau lưng."},"6287":{"word":"hỏi lại","meaning":"Hỏi một câu hỏi giống nhau lần nữa vì không nghe rõ câu trả lời."},"6288":{"word":"đập thình thịch","meaning":"Tim đập nhanh và mạnh trong lồng ngực do hồi hộp hoặc phấn khích."},"6289":{"word":"cóc","meaning":"Một loài động vật lưỡng cư tương tự ếch nhưng lớn hơn và có da màu nâu sẫm hơn."},"6290":{"word":"đập, gõ, nện","meaning":"Dùng lực đánh mạnh liên tục vào một vật hoặc bề mặt, thường tạo ra tiếng ồn lớn."},"6291":{"word":"sâu đậm, thân thiết","meaning":"Mối quan hệ giữa người với người rất bền chặt, thể hiện sự tin tưởng và lòng trung thành cao."},"6292":{"word":"đần độn, chậm chạp","meaning":"Miêu tả người không nhanh nhạy trong việc tiếp thu điều mới hoặc phản ứng với tình huống."},"6293":{"word":"bao phủ, che phủ","meaning":"Trải rộng khắp một bề mặt, che giấu hoàn toàn những gì bên dưới."},"6294":{"word":"lật úp","meaning":"Làm cho một vật thay đổi vị trí bằng cách lật úp hoặc lật nghiêng nó."},"6295":{"word":"đội, trùm, mặc","meaning":"Đặt một món đồ quần áo hoặc một mảnh vải lên đầu hoặc cơ thể mình."},"6296":{"word":"bị lộn trái","meaning":"Bề mặt bên trong của một vật, như quần áo, trở thành bề mặt bên ngoài."},"6297":{"word":"tụt hậu, lùi lại","meaning":"Di chuyển chậm hơn hoặc tiến bộ kém hơn những người khác trong cuộc đua, nhóm hoặc trong khả năng và sự phát triển."},"6298":{"word":"trằn trọc, lăn trở","meaning":"Liên tục cử động cơ thể từ bên này sang bên kia khi nghỉ ngơi trên giường, thường là vì không ngủ được."},"6299":{"word":"buổi tụ tập sau","meaning":"Một buổi tụ tập thân mật để tiếp tục ăn mừng hoặc giao lưu sau khi sự kiện chính đã kết thúc."},"6300":{"word":"rung lắc dữ dội","meaning":"Làm cho một vật gì đó di chuyển nhanh và mạnh theo nhiều hướng khác nhau, thường là một cách cưỡng bức hoặc mất kiểm soát."},"6301":{"word":"bước lùi","meaning":"Một hành động di chuyển trong đó một người hoặc động vật đặt chân ra sau, khiến cơ thể di chuyển ngược lại."},"6302":{"word":"sự hỗ trợ, sự hậu thuẫn","meaning":"Hành động cung cấp nguồn lực, sự khuyến khích hoặc nền tảng để ai đó hoặc điều gì đó thành công hoặc duy trì sức mạnh."},"6303":{"word":"cánh đồng","meaning":"Một vùng đất bằng phẳng, rộng lớn."},"6304":{"word":"ra vào liên tục","meaning":"Vào một nơi, rồi ra khỏi đó, và lặp lại hành động này nhiều lần trong một khoảng thời gian ngắn."},"6305":{"word":"ngồi yên vị","meaning":"Đặt mình một cách thoải mái trong một không gian kín, thường là với ý định ở lại đó một thời gian."},"6306":{"word":"nhập vào, đưa vào","meaning":"Chuyển một thứ gì đó từ khu vực bên ngoài hoặc từ nước ngoài vào một không gian kín hoặc vào đất nước của mình."},"6307":{"word":"chĩa vào, dí vào","meaning":"Cầm một vật, như vũ khí, và hướng phần phía trước của nó một cách hung hăng về phía một người hoặc mục tiêu."},"6308":{"word":"đẩy vào, thọc vào","meaning":"Di chuyển một vật hoặc một phần cơ thể nhanh chóng và mạnh mẽ vào một không gian hoặc gần hơn với cái gì đó."},"6309":{"word":"sự bại lộ, sự vỡ lở","meaning":"Thời điểm những sự thật hoặc thông tin bị giấu kín được nhiều người biết đến, thường là ngoài ý muốn hoặc trái với mong muốn của ai đó."},"6310":{"word":"cánh đồng, đồng bằng","meaning":"Một vùng đất bằng phẳng, rộng lớn, thường được bao phủ bởi cỏ, cây trồng hoặc các loại cây thấp khác, và thường có ít cây cối."},"6311":{"word":"nhiều, đầy ắp","meaning":"Diễn tả một lượng lớn cái gì đó, thường là đầy hoặc tràn ra khỏi vật chứa."},"6312":{"word":"sự đến trường","meaning":"Hành động đi từ nhà đến trường để học tập."},"6313":{"word":"sự leo núi","meaning":"Hành động leo lên một ngọn núi cao."},"6314":{"word":"nhân vật","meaning":"Cá thể hư cấu, chẳng hạn như người hoặc động vật, xuất hiện và hành động trong một câu chuyện, sách hoặc phim."},"6315":{"word":"đặt chân, giẫm","meaning":"Đặt bàn chân xuống một bề mặt hoặc vật thể một cách vững chắc khi đi bộ hoặc đứng."},"6316":{"word":"buốt, rát","meaning":"Cảm thấy một cảm giác đau nhói, khó chịu trên da, như bị kim châm hoặc nắng gắt."},"6317":{"word":"sự bị tẩy chay, sự bị cô lập","meaning":"Hành động cố ý xa lánh, không cho hòa nhập hoặc quấy rối ai đó mà mình không thích."},"6318":{"word":"đuổi kịp","meaning":"Di chuyển nhanh hơn để đạt đến vị trí ngang bằng với người hoặc vật đang ở phía trước."},"6319":{"word":"vân vân, v.v.","meaning":"Từ dùng để chỉ rằng có những thứ tương tự khác thuộc cùng loại với những thứ đã được liệt kê."},"6320":{"word":"đúng, đột ngột","meaning":"Diễn tả một sự việc xảy ra một cách chính xác hoặc đột ngột, dứt khoát."},"6321":{"word":"kèm theo, gắn liền","meaning":"Được gắn kết về mặt vật lý hoặc được bao gồm một cách tự nhiên như một phần của một vật hoặc nhóm lớn hơn."},"6322":{"word":"đốt (lò sưởi), nhóm (lửa)","meaning":"Đặt vật liệu dễ cháy vào lửa hoặc lò để tạo ra hơi ấm hoặc năng lượng."},"6323":{"word":"bịt","meaning":"Dùng vật gì đó để làm kín một lỗ hoặc vết nứt."},"6324":{"word":"trôi đi","meaning":"Nổi và di chuyển trên mặt nước đang chảy, bị dòng nước cuốn từ nơi này đến nơi khác."},"6325":{"word":"lang thang","meaning":"Di chuyển từ nơi này sang nơi khác mà không có hướng cụ thể hoặc nơi ở cố định."},"6326":{"word":"ồn ào, náo nhiệt","meaning":"Mô tả một nơi hoặc một nhóm người tạo ra nhiều tiếng động lớn và hoạt động sôi nổi, tràn đầy năng lượng."},"6327":{"word":"đảm nhận","meaning":"Trở thành người chịu trách nhiệm cho một nhiệm vụ hoặc nghĩa vụ, đặc biệt là việc khó khăn hoặc không mong muốn."},"6328":{"word":"rộng, bè","meaning":"Mô tả thứ gì đó như vai của một người hoặc miệng mở ra một cách rất đầy đủ hoặc mở rộng."},"6329":{"word":"chát","meaning":"Có một vị làm cho miệng cảm thấy khô và làm môi, lưỡi co lại."},"6330":{"word":"đàng hoàng","meaning":"Hành động một cách đúng đắn về mặt đạo đức và công khai, để có thể thể hiện bản thân và hành động của mình mà không cảm thấy xấu hổ hay tội lỗi."},"6331":{"word":"bạn đồng trang lứa","meaning":"Người có độ tuổi xấp xỉ bằng một người hoặc một nhóm người khác."},"6332":{"word":"rõ ràng","meaning":"Rất dễ nhìn, nghe hoặc ghi nhớ với các chi tiết sắc nét, không bị mờ hay lẫn lộn."},"6333":{"word":"y hệt","meaning":"Dùng để mô tả thứ gì đó giống hoàn hảo hoặc giống hệt một thứ khác, không có bất kỳ sự khác biệt nào."},"6334":{"word":"cốc cốc","meaning":"Từ mô phỏng âm thanh gõ nhẹ, lặp đi lặp lại của một vật lên bề mặt."},"6335":{"word":"rõ ràng","meaning":"Một cách dễ dàng nhận thấy, hiểu hoặc phân biệt với những thứ khác."},"6336":{"word":"đột ngột (dừng)","meaning":"Diễn tả một hành động dừng lại rất bất ngờ và hoàn toàn."},"6337":{"word":"giọt giọt","meaning":"Từ mô phỏng âm thanh hoặc diễn tả chuyển động của các vật lớn hoặc giọt nước rơi liên tục."},"6338":{"word":"chạy đến","meaning":"Di chuyển nhanh bằng chân từ một nơi nào đó để đến vị trí của người nói hoặc người quan sát."},"6339":{"word":"lao ra ngoài","meaning":"Di chuyển từ bên trong ra bên ngoài một cách rất nhanh và vội vã."},"6340":{"word":"lao ra","meaning":"Di chuyển từ một khu vực bên trong ra bên ngoài một cách rất nhanh chóng và vội vã, về phía người quan sát."},"6341":{"word":"nổi","meaning":"Ở trên bề mặt nước hoặc trong không khí mà không chìm xuống hay rơi xuống."},"6342":{"word":"bóc ra xem","meaning":"Mở thứ đã được niêm phong hoặc đóng gói và xem xét bên trong."},"6343":{"word":"thưa thớt","meaning":"Diễn tả điều gì đó xảy ra hoặc xuất hiện chỉ vài lần, với những khoảng thời gian dài không xuất hiện xen kẽ."},"6344":{"word":"làm cho nổi","meaning":"Làm cho một vật nằm trên bề mặt nước hoặc di chuyển trong không khí mà không rơi xuống."},"6345":{"word":"hoa tử đinh hương","meaning":"Một loại cây có lá hình trái tim và những bông hoa nhỏ màu tím nhạt hoặc trắng nở vào mùa xuân, có mùi thơm ngọt ngào."},"6346":{"word":"vợt (thể thao)","meaning":"Một dụng cụ thể thao có tay cầm và khung lưới, dùng để đánh bóng hoặc cầu lông."},"6347":{"word":"mục","meaning":"Phần riêng biệt trong báo, tạp chí hoặc sách để đăng các loại bài viết hoặc thông tin cụ thể."},"6348":{"word":"đấu vật","meaning":"Một môn thể thao mà hai người cố gắng khống chế đối phương bằng cách ôm giữ và quật ngã."},"6349":{"word":"giải trí","meaning":"Khoảng thời gian tự do khỏi công việc hoặc nghĩa vụ, dùng để thực hiện các hoạt động yêu thích như thể thao hay thư giãn."},"6350":{"word":"đường","meaning":"Hậu tố chỉ bề mặt được chuẩn bị đặc biệt để di chuyển hoặc đi lại, thường dùng cho xe cộ hoặc người theo một hướng cụ thể."},"6351":{"word":"luận","meaning":"Hậu tố chỉ một tập hợp các ý tưởng và quy tắc dùng để giải thích cách thức hoạt động của một điều gì đó."},"6352":{"word":"loại","meaning":"Hậu tố chỉ một nhóm các đối tượng hoặc khái niệm tương tự nhau có chung đặc điểm."},"6353":{"word":"khả năng lãnh đạo","meaning":"Năng lực của một người trong việc hướng dẫn một nhóm, đưa ra quyết định và chỉ đường để đạt được mục tiêu chung."},"6354":{"word":"phóng viên","meaning":"Người thu thập thông tin và sự kiện để chia sẻ với mọi người thông qua các phương tiện truyền thông."},"6355":{"word":"thời hạn chót","meaning":"Ngày hoặc giờ cụ thể mà một công việc phải được hoàn thành hoặc nộp."},"6356":{"word":"tê liệt","meaning":"Tình trạng y tế khi một phần hoặc toàn bộ cơ thể mất khả năng cử động hoặc cảm giác."},"6357":{"word":"điểm tích lũy","meaning":"Hệ thống điểm thưởng mà mọi người tích lũy, thường từ hãng hàng không hoặc cửa hàng, để đổi lấy giảm giá hoặc vật phẩm miễn phí."},"6358":{"word":"nốt","meaning":"Từ dùng để biểu thị việc hoàn tất hoặc bổ sung phần còn lại."},"6359":{"word":"marketing","meaning":"Hoạt động quảng bá, giới thiệu và bán sản phẩm hoặc dịch vụ cho khách hàng của một công ty."},"6360":{"word":"màn","meaning":"Một phần của vở kịch hoặc buổi biểu diễn, thường được chia thành nhiều cảnh."},"6361":{"word":"mịt mờ","meaning":"Cảm thấy tuyệt vọng và không có lối thoát, như không có giải pháp hay hướng đi rõ ràng cho tương lai."},"6362":{"word":"bách bệnh","meaning":"Tập hợp tất cả các loại bệnh tật hoặc vấn đề sức khỏe có thể ảnh hưởng đến con người hoặc động vật."},"6363":{"word":"mức độ hài lòng","meaning":"Một thước đo mức độ vừa ý hoặc vui vẻ của mọi người với một sản phẩm, dịch vụ hoặc trải nghiệm."},"6364":{"word":"con cả","meaning":"Người con đầu tiên được sinh ra trong một gia đình có nhiều con."},"6365":{"word":"cuối lời","meaning":"Phần kết thúc của một câu nói ngắn hoặc một câu chuyện."},"6366":{"word":"tài ăn nói","meaning":"Khả năng bẩm sinh để nói chuyện một cách rõ ràng, thuyết phục hoặc hấp dẫn."},"6367":{"word":"đối mặt","meaning":"Đặt hai người hoặc vật ở vị trí gần nhau, đối diện nhau."},"6368":{"word":"cùng khiêng","meaning":"Nâng và vận chuyển một vật thể với hai hoặc nhiều người, mỗi người giữ một phần khác nhau."},"6369":{"word":"để bị dính mưa","meaning":"Khiến cho ai đó hoặc vật gì đó tiếp xúc và bị ướt bởi nước mưa."},"6370":{"word":"mỗi","meaning":"Từ dùng để chỉ riêng lẻ từng cá thể hoặc sự vật trong một nhóm."},"6371":{"word":"Mịn màng","meaning":"Có bề mặt phẳng lì, đều đặn, không thô ráp hay gồ ghề."},"6372":{"word":"Làm cỏ","meaning":"Loại bỏ cỏ dại mọc giữa các cây trồng để chúng phát triển tốt hơn."},"6373":{"word":"Hấp dẫn, quyến rũ","meaning":"Có những phẩm chất khiến một người hoặc một vật trở nên lôi cuốn, dễ chịu hoặc rất thú vị đối với người khác."},"6374":{"word":"Mua bán","meaning":"Việc trao đổi hàng hóa, tài sản lấy tiền hoặc ngược lại."},"6375":{"word":"Mọi việc, mọi sự","meaning":"Tất cả các công việc, sự việc, tình huống cụ thể mà ai đó phải đối mặt hoặc thực hiện."},"6376":{"word":"Gay gắt, dữ dội","meaning":"Mô tả vẻ ngoài, ánh mắt hoặc thái độ rất mạnh mẽ, sắc bén, gây cảm giác đáng sợ hoặc nghiêm khắc."},"6377":{"word":"Khói bụi","meaning":"Khói đen, bồ hóng, thường là chất ô nhiễm không khí, sinh ra từ việc đốt nhiên liệu."},"6378":{"word":"Mua vào","meaning":"Hành động có được một món đồ hoặc tài sản bằng cách trả tiền để sở hữu nó."},"6379":{"word":"Doanh thu, doanh số","meaning":"Tổng số tiền mà một doanh nghiệp thu được từ việc bán sản phẩm hoặc cung cấp dịch vụ cho khách hàng."},"6380":{"word":"Cay ngọt","meaning":"Mô tả hương vị món ăn có sự kết hợp giữa vị ngọt và một chút cay nhẹ, ấm nóng dễ chịu."},"6381":{"word":"Tay không","meaning":"Bàn tay không đeo gì hoặc không cầm nắm thứ gì."},"6382":{"word":"Lời thề, lời cam kết","meaning":"Một lời hứa long trọng, nghiêm túc được đưa ra với sự thành tâm, thường được nói ra hoặc thể hiện bằng hành động."},"6383":{"word":"tiêu đề chính","meaning":"Dòng chữ lớn in đậm ở đầu trang báo hoặc bài viết, giới thiệu nội dung quan trọng nhất."},"6384":{"word":"không xa, chẳng bao lâu nữa","meaning":"Diễn tả một sự kiện hoặc thời điểm trong tương lai sẽ đến rất nhanh chóng, không còn xa nữa."},"6385":{"word":"trông ngon miệng, hấp dẫn","meaning":"Trông có vẻ ngon miệng và kích thích vị giác, khiến người ta muốn ăn."},"6386":{"word":"ngu ngốc, đần độn","meaning":"Chỉ người thiếu phán đoán hoặc trí thông minh, thường thể hiện qua hành động hoặc lời nói."},"6387":{"word":"ngơ ngác, thẫn thờ","meaning":"Diễn tả cách nhìn hoặc nhìn chằm chằm mà không có tiêu điểm cụ thể, trông có vẻ trống rỗng hoặc đang suy nghĩ miên man."},"6388":{"word":"choáng váng, ngẩn ngơ","meaning":"Miêu tả trạng thái tinh thần không rõ ràng, lộn xộn trong suy nghĩ, thường sau một cú sốc hoặc tác động bất ngờ."},"6389":{"word":"nghẹn ứ, nghẹn ngào","meaning":"Cảm giác cổ họng bị tắc nghẽn hoặc có cục vướng, gây khó nói hoặc nuốt, thường do cảm xúc mạnh."},"6390":{"word":"khô cằn, cằn cỗi","meaning":"Miêu tả đất đai hoặc thổ nhưỡng có rất ít nước, dẫn đến cây cối không mọc được hoặc mọc thưa thớt."},"6391":{"word":"melodrama, phim tình cảm bi lụy","meaning":"Thể loại phim hoặc câu chuyện với cảm xúc mãnh liệt, thường mô tả những tình huống đầy đam mê hoặc đau khổ."},"6392":{"word":"bông, cotton","meaning":"Sợi thực vật mềm màu trắng, có thể kéo thành sợi và dệt thành vải để may quần áo."},"6393":{"word":"mì, miến","meaning":"Món ăn làm từ bột, thường là bột mì, được tạo hình thành sợi dài, mỏng rồi nấu chín."},"6394":{"word":"dao cạo, máy cạo râu","meaning":"Dụng cụ có lưỡi rất sắc dùng để loại bỏ lông trên da, đặc biệt là trên mặt."},"6395":{"word":"cửa hàng miễn thuế","meaning":"Đây là cửa hàng nơi khách hàng có thể mua sắm hàng hóa mà không phải trả thuế phụ thu."},"6396":{"word":"phỏng vấn","meaning":"Đây là một buổi gặp mặt chính thức để hỏi đáp và đánh giá sự phù hợp của ai đó cho một công việc hoặc trường học."},"6397":{"word":"miễn trừ","meaning":"Đây là sự cho phép chính thức để không phải thực hiện điều mà người khác bắt buộc phải làm."},"6398":{"word":"diệt vong","meaning":"Đây là sự hủy diệt hoàn toàn khiến một quốc gia, hệ thống hoặc hành tinh không còn tồn tại nữa."},"6399":{"word":"tuyệt chủng","meaning":"Đây là trạng thái mà một loài động vật hoặc thực vật không còn tồn tại trên Trái Đất nữa."},"6400":{"word":"sự vui vẻ","meaning":"Đây là cảm giác hoặc phẩm chất rất hạnh phúc và hoạt bát, thường thể hiện qua nụ cười và thái độ tràn đầy năng lượng."},"6401":{"word":"rõ ràng","meaning":"Đây là cách diễn đạt hoặc thể hiện một điều gì đó rất dễ hiểu và dễ nhìn thấy, không còn nghi ngờ gì."},"6402":{"word":"danh từ","meaning":"Đây là từ dùng để gọi tên người, địa điểm, sự vật hoặc ý tưởng."},"6403":{"word":"thiền định","meaning":"Đây là một phương pháp mà người ta ngồi yên lặng, tập trung tâm trí để thư giãn hoặc suy nghĩ sâu sắc."},"6404":{"word":"danh tiếng","meaning":"Đây là sự nổi tiếng được nhiều người biết đến và đánh giá cao."},"6405":{"word":"địa điểm nổi tiếng","meaning":"Đây là một địa điểm được nhiều người biết đến và ghé thăm vì có nét độc đáo hoặc ý nghĩa lịch sử."},"6406":{"word":"ghi nhớ","meaning":"Đây là hành động ghi nhớ cẩn thận điều gì đó quan trọng để không quên và luôn xem xét nó."},"6407":{"word":"hàng hiệu","meaning":"Sản phẩm có chất lượng rất cao, thường đắt tiền và được sản xuất bởi một công ty nổi tiếng."},"6408":{"word":"rõ ràng","meaning":"Một cách dễ hiểu, chính xác, không gây nhầm lẫn hay không chắc chắn."},"6409":{"word":"tiếng mẹ đẻ","meaning":"Ngôn ngữ đầu tiên mà một người học được từ khi còn nhỏ, thường là từ cha mẹ hoặc trong gia đình."},"6410":{"word":"ngụm","meaning":"Lượng chất lỏng mà một người đưa vào miệng và nuốt một lần."},"6411":{"word":"tóc","meaning":"Những sợi mỏng, dài mọc ra từ da của người và động vật, đặc biệt là trên đầu."},"6412":{"word":"bắt chước","meaning":"Hành động làm hoặc tạo ra cái gì đó giống với một cái khác về hình thức hoặc cách thức."},"6413":{"word":"học sinh gương mẫu","meaning":"Học sinh có hành vi tốt, học hành chăm chỉ và đạt kết quả cao, là tấm gương cho người khác."},"6414":{"word":"nguyên âm","meaning":"Âm được phát ra khi luồng hơi từ phổi đi qua miệng một cách tự do, không bị cản trở."},"6415":{"word":"tất cả","meaning":"Chỉ mọi thứ, mọi bộ phận của một cái gì đó mà không bỏ sót bất cứ điều gì."},"6416":{"word":"mẫu thân","meaning":"Cách gọi lịch sự mẹ của mình hoặc của người khác."},"6417":{"word":"mô hình","meaning":"Vật thể được làm giống như bản gốc nhưng thường có kích thước nhỏ hơn để trưng bày hoặc nghiên cứu."},"6418":{"word":"chứng kiến","meaning":"Việc có mặt và tận mắt nhìn thấy một sự kiện hoặc vụ việc xảy ra."},"6419":{"word":"nhân chứng","meaning":"Người có mặt tại một sự kiện hoặc sự việc và chứng kiến nó xảy ra trực tiếp."},"6420":{"word":"khoản tiền lớn","meaning":"Một số tiền đáng kể được thanh toán hoặc tích lũy một lần, thay vì trả góp nhỏ."},"6421":{"word":"trang trại chăn nuôi","meaning":"Một khu đất rộng lớn có cỏ, nơi nuôi và chăn thả các loài vật như bò, ngựa, cừu."},"6422":{"word":"gỗ","meaning":"Các mảnh từ cây đã đốn hạ được chế biến thành ván hoặc xà để xây dựng hoặc làm đồ vật."},"6423":{"word":"tân ngữ","meaning":"Trong câu, từ hoặc cụm từ nhận hành động của động từ chính."},"6424":{"word":"miệt mài","meaning":"Dồn hết tâm trí và năng lượng vào một hoạt động hoặc nhiệm vụ cụ thể."},"6425":{"word":"dồn, đẩy","meaning":"Đẩy ai đó hoặc cái gì đó rất mạnh theo một hướng, khiến họ/nó di chuyển theo hướng đó."},"6426":{"word":"chăn dắt (gia súc)","meaning":"Hành động hướng dẫn một nhóm gia súc di chuyển đến một nơi cụ thể hoặc dọc theo một con đường nhất định."},"6427":{"word":"mộ","meaning":"Nơi chôn cất người đã khuất, thường được đánh dấu bằng bia đá hoặc ụ đất."},"6428":{"word":"không có gì, vô","meaning":"Tình trạng hoàn toàn không có đối tượng hoặc sự vật nào hiện diện hoặc có thể nhìn thấy."},"6429":{"word":"ổn thỏa, không có vấn đề","meaning":"Mô tả điều gì đó bình thường, không gây chú ý hay tạo ra bất kỳ vấn đề nào."},"6430":{"word":"phá đổ, làm sập","meaning":"Khiến một cái gì đó cao hoặc thẳng đứng đổ sập xuống đất."},"6431":{"word":"lầm lì","meaning":"Có vẻ ngoài nghiêm nghị, ít nói và không thân thiện."},"6432":{"word":"thiếu suy xét","meaning":"Tình trạng hành động hoặc nói năng một cách vội vàng, không suy nghĩ kỹ về hậu quả có thể xảy ra."},"6433":{"word":"miễn phí","meaning":"Được cung cấp mà không phải trả bất kỳ khoản tiền nào."},"6434":{"word":"không dây","meaning":"Chỉ thiết bị hoặc hệ thống truyền nhận tín hiệu hoặc năng lượng mà không cần dùng đến dây vật lý."},"6435":{"word":"không tin tức","meaning":"Tình trạng không có bất kỳ tin nhắn, báo cáo hay thông tin liên lạc nào đến từ một người hoặc về một sự việc."},"6436":{"word":"võ thuật","meaning":"Hệ thống các phương pháp chiến đấu và tự vệ, thường bao gồm các động tác thể chất, đá, đấm và khóa siết."},"6437":{"word":"đáng sợ","meaning":"Trông cực kỳ đáng sợ, khiến người ta cảm thấy hoảng sợ hoặc lo lắng tột độ."},"6438":{"word":"sự dốt nát","meaning":"Sự thiếu kiến thức vì chưa được học, nghe hay nhìn thấy."},"6439":{"word":"vô ý","meaning":"Làm một hành động như thể ngẫu nhiên, không có dấu hiệu đã dự định hay suy nghĩ trước đó."},"6440":{"word":"không phản hồi","meaning":"Tình trạng một người không đưa ra bất kỳ câu trả lời nào, dù nói hay viết, cho một câu hỏi hoặc một tin nhắn."},"6441":{"word":"không người","meaning":"Chỉ một địa điểm, máy móc hoặc hệ thống hoạt động tự động mà không cần có người điều khiển hay vận hành."},"6442":{"word":"đảo hoang","meaning":"Một mảnh đất hoàn toàn được bao quanh bởi nước mà không có người sinh sống."},"6443":{"word":"vô hiệu","meaning":"Tình trạng một văn bản hoặc thỏa thuận không có giá trị pháp lý và không thể sử dụng được."},"6444":{"word":"cũ, để lâu","meaning":"Ở trong tình trạng đã tồn tại một thời gian dài, thường dẫn đến sự thay đổi về chất lượng hoặc hình thức."},"6445":{"word":"lời văn, câu chữ","meaning":"Một đoạn văn bản hoặc cụm từ được sử dụng trong quảng cáo hoặc văn bản khác."},"6446":{"word":"đoạn văn","meaning":"Một phần văn bản riêng biệt bao gồm các câu có liên quan, thường bắt đầu bằng cách thụt đầu dòng hoặc dòng mới."},"6447":{"word":"văn viết, ngôn ngữ viết","meaning":"Ngôn ngữ được sử dụng trong văn bản viết, trái ngược với ngôn ngữ giao tiếp hàng ngày."},"6448":{"word":"câu hỏi (trong bài thi)","meaning":"Một nhiệm vụ hoặc câu hỏi riêng lẻ được đánh số trong bài kiểm tra hoặc khảo sát, yêu cầu trả lời hoặc giải pháp."},"6449":{"word":"cấu trúc câu, mẫu câu","meaning":"Một sự sắp xếp ngữ pháp hoặc cấu trúc từ cụ thể tạo thành một đơn vị ý nghĩa hoàn chỉnh trong ngôn ngữ."},"6450":{"word":"đời sống văn hóa","meaning":"Tổng hợp các hoạt động mà mọi người tham gia để giải trí, như tham quan phòng trưng bày nghệ thuật, xem kịch hoặc dự buổi biểu diễn âm nhạc."},"6451":{"word":"di sản văn hóa","meaning":"Các truyền thống, phong tục, cấu trúc vật chất và hiện vật quan trọng được truyền lại từ các thế hệ trước mà một xã hội trân trọng."},"6452":{"word":"số lượng hàng hóa","meaning":"Tổng số hoặc lượng sản phẩm được sản xuất, có sẵn để mua hoặc lưu trữ."},"6453":{"word":"thừa kế, được thừa hưởng","meaning":"Nhận tiền, tài sản hoặc tước hiệu từ người đã qua đời, hoặc tiếp thu đặc điểm từ cha mẹ."},"6454":{"word":"để lại, truyền lại","meaning":"Giao tiền, tài sản hoặc truyền thống cho người khác, thường là người thân trẻ tuổi hơn, để họ giữ sau khi mình qua đời."},"6455":{"word":"Vật lý","meaning":"Môn khoa học nghiên cứu về vật chất, năng lượng và các định luật tự nhiên."},"6456":{"word":"Đánh bại, đẩy lùi","meaning":"Chiến thắng đối thủ hoặc kẻ địch, khiến họ phải rút lui hoặc đầu hàng."},"6457":{"word":"Giọt nước","meaning":"Một lượng nước rất nhỏ, có hình dạng tròn, đọng lại hoặc rơi xuống."},"6458":{"word":"Hàng hóa, vật phẩm","meaning":"Các đồ vật được sản xuất ra để bán hoặc tiêu dùng."},"6459":{"word":"Rưng rưng, xúc động","meaning":"Cảm thấy xúc động mạnh trong lòng, thường khiến mắt rưng rưng."},"6460":{"word":"Cái đẹp, vẻ đẹp","meaning":"Đặc điểm làm cho một vật thể trở nên hấp dẫn và dễ chịu khi nhìn."},"6461":{"word":"Mỹ nữ, người đẹp","meaning":"Người phụ nữ có vẻ ngoài xinh đẹp nổi bật."},"6462":{"word":"Nhan sắc, vẻ đẹp","meaning":"Vẻ đẹp thu hút của khuôn mặt và cơ thể một người."},"6463":{"word":"Vi sinh vật","meaning":"Sinh vật rất nhỏ mà mắt thường không thể nhìn thấy được."},"6464":{"word":"Trẻ lạc","meaning":"Đứa trẻ bị lạc mất cha mẹ hoặc người giám hộ và không tìm được đường về."},"6465":{"word":"Rong biển","meaning":"Loại thực vật màu xanh đen mọc ở vùng nước nông của biển, thường được phơi khô và dùng để nấu canh."},"6466":{"word":"Thẩm mỹ, làm đẹp","meaning":"Các phương pháp và liệu pháp dùng để cải thiện hoặc duy trì vẻ đẹp thể chất của con người."},"6467":{"word":"thẩm mỹ","meaning":"Liên quan đến cái đẹp và sự cảm nhận, đánh giá những phẩm chất hấp dẫn hoặc nghệ thuật."},"6468":{"word":"nhạy cảm","meaning":"Dễ phản ứng nhanh chóng và mạnh mẽ với những thay đổi nhỏ, sự chạm vào hoặc tác động từ bên ngoài."},"6469":{"word":"homestay","meaning":"Hình thức lưu trú đơn giản, du khách có thể trả tiền để ở lại qua đêm, thường là trong nhà dân hoặc nhà khách nhỏ."},"6470":{"word":"dân gian","meaning":"Những câu chuyện, phong tục, tín ngưỡng và cách thể hiện nghệ thuật truyền thống đã được lưu truyền qua nhiều thế hệ trong một cộng đồng."},"6471":{"word":"dân ca","meaning":"Một giai điệu hoặc bài hát truyền thống có nguồn gốc từ những người dân bình thường ở một vùng cụ thể, thường được truyền miệng và phản ánh văn hóa địa phương."},"6472":{"word":"đáng tin cậy","meaning":"Luôn hành động theo cách mà người khác có thể tin tưởng và dựa vào bạn để thực hiện những gì bạn nói."},"6473":{"word":"tràn vào, ập đến","meaning":"Để một thứ gì đó, như nước hoặc đám đông, di chuyển hoặc chảy về phía trước một cách mạnh mẽ và liên tục, thường là với số lượng lớn."},"6474":{"word":"việc bên ngoài, công việc ngoài xã hội","meaning":"Các nhiệm vụ, công việc hoặc việc làm mà một người thực hiện bên ngoài ngôi nhà của mình, chẳng hạn như công việc văn phòng hoặc nhà máy."},"6475":{"word":"ngắm nhìn, nhìn chăm chú","meaning":"Nhìn một cách ổn định và chăm chú vào một cái gì đó hoặc một ai đó trong một khoảng thời gian dài, thường với suy nghĩ sâu sắc hoặc cảm xúc."},"6476":{"word":"vi-rút","meaning":"Một loại vi sinh vật hoạt động như tác nhân gây bệnh truyền nhiễm trong bệnh cúm, bại liệt, v.v."},"6477":{"word":"chợ từ thiện","meaning":"Một sự kiện công cộng nơi nhiều mặt hàng khác nhau, thường là hàng thủ công hoặc sản phẩm quyên góp, được bán từ nhiều quầy hàng, thường để gây quỹ từ thiện."},"6478":{"word":"hội chợ, triển lãm","meaning":"Một sự kiện công cộng lớn nơi nhiều công ty hoặc nhóm trưng bày sản phẩm, dịch vụ hoặc thành tựu của họ trong các gian hàng lớn."},"6479":{"word":"ngay ngắn","meaning":"Có hình dạng thẳng, đều và không bị cong vênh hay nghiêng lệch."},"6480":{"word":"sự phản bác","meaning":"Việc phủ nhận một ý kiến, lời nói của người khác bằng cách đưa ra lý do cụ thể."},"6481":{"word":"một nửa một nửa","meaning":"Tình trạng chia đều một cái gì đó thành hai phần bằng nhau."},"6482":{"word":"một nửa","meaning":"Một trong hai phần bằng nhau khi một vật được chia đôi."},"6483":{"word":"trái với","meaning":"Làm trái lại hoặc không phù hợp với quy tắc, luật lệ hay mong muốn nào đó."},"6484":{"word":"sự phản kháng","meaning":"Hành động hoặc thái độ công khai không tuân theo mệnh lệnh hay quy tắc đã định."},"6485":{"word":"điểm quay đầu","meaning":"Vị trí cụ thể trong một cuộc đua hoặc cuộc thi mà người tham gia thay đổi hướng và bắt đầu quay trở lại vạch đích."},"6486":{"word":"đỡ","meaning":"Đặt một vật gì đó bên dưới để nâng đỡ, giữ cho vật khác không bị đổ hoặc cao lên."},"6487":{"word":"xuất phát từ","meaning":"Hậu tố gắn vào tên địa danh để chỉ ra rằng một phương tiện hoặc tin tức bắt đầu hành trình từ nơi đó."},"6488":{"word":"bản ballad","meaning":"Một thể loại nhạc phổ biến có giai điệu chậm, nhẹ nhàng, thường thể hiện cảm xúc về tình yêu hoặc nỗi buồn."},"6489":{"word":"nhà phát minh","meaning":"Người đã nghĩ ra và thiết kế một thiết bị, quy trình hoặc sản phẩm hoàn toàn mới chưa từng tồn tại trước đó."},"6490":{"word":"sản phẩm phát minh","meaning":"Một thiết bị, quy trình hoặc sản phẩm mới do ai đó thiết kế và tạo ra lần đầu tiên."},"6491":{"word":"người gửi","meaning":"Người hoặc tổ chức gửi tin nhắn, thư hoặc gói hàng đi cho một người nhận khác."},"6492":{"word":"phát biểu","meaning":"Lời nói mà một người nói ra một cách công khai hoặc trang trọng, thường trong cuộc họp hoặc thảo luận."},"6493":{"word":"phát điện","meaning":"Quá trình chuyển đổi năng lượng thành điện năng."},"6494":{"word":"nhà máy điện","meaning":"Cơ sở công nghiệp lớn nơi năng lượng được chuyển đổi thành điện để cung cấp cho các hộ gia đình và doanh nghiệp."},"6495":{"word":"bước","meaning":"Một lần di chuyển về phía trước bằng một chân hoặc khoảng cách di chuyển được."},"6496":{"word":"người thuyết trình","meaning":"Người đứng trước một nhóm và chia sẻ thông tin, thường dùng phương tiện hỗ trợ trực quan hoặc nói qua micro."},"6497":{"word":"có hiệu lực","meaning":"Thời điểm một quy tắc hoặc quyết định chính thức mới bắt đầu có giá trị và mọi người phải tuân theo."},"6498":{"word":"lên men","meaning":"Quá trình các vi sinh vật nhỏ làm thay đổi đường trong thực phẩm hoặc đồ uống, thường tạo ra bong bóng, mùi mới và hương vị hoặc kết cấu khác biệt."},"6499":{"word":"phát huy","meaning":"Hành động tích cực sử dụng kỹ năng, sức mạnh hoặc khả năng của một người để đạt được điều gì đó rõ rệt."},"6500":{"word":"ngày đêm không nghỉ","meaning":"Xảy ra hoặc tiếp diễn liên tục, không ngừng nghỉ, cả ngày lẫn đêm."},"6501":{"word":"gậy","meaning":"Một khúc gỗ hoặc kim loại dài, dày, thường được cầm trên tay và dùng để đánh một vật, như quả bóng trong thể thao."},"6502":{"word":"người làm truyền hình/phát thanh","meaning":"Người có công việc liên quan đến việc nói hoặc xuất hiện trong các chương trình radio hoặc truyền hình được gửi đến nhiều gia đình."},"6503":{"word":"chống thấm","meaning":"Khả năng hoặc việc xử lý để một vật không bị chất lỏng xuyên qua, giữ cho bên trong khô ráo."},"6504":{"word":"phát sóng","meaning":"Hành động gửi một chương trình truyền hình hoặc phim ra để nhiều người xem trên màn hình của họ."},"6505":{"word":"cái chuông nhỏ","meaning":"Một vật hình tròn nhỏ, thường bằng kim loại, có quả lắc bên trong và phát ra âm thanh khi rung."},"6506":{"word":"cách âm","meaning":"Đặc tính hoặc thiết kế đặc biệt ngăn tiếng ồn xuyên qua, giúp không gian trở nên yên tĩnh."},"6507":{"word":"khán giả","meaning":"Một nhóm người tập trung tại một không gian để xem biểu diễn, nghe diễn giả hoặc quan sát một sự kiện."},"6508":{"word":"lang thang, lạc lối","meaning":"Hành động di chuyển hoặc cảm thấy mất phương hướng không có mục tiêu rõ ràng, về thể chất hoặc tinh thần."},"6509":{"word":"ruộng khô","meaning":"Một khu đất trống bằng phẳng dùng để trồng trọt các loại cây như rau hoặc ngũ cốc, không ngập nước."},"6510":{"word":"khí thải","meaning":"Khói hoặc khí độc hại thoát ra từ ống xả của xe cộ khi động cơ hoạt động."},"6511":{"word":"sắp xếp, bố trí","meaning":"Một thứ tự hoặc vị trí cụ thể mà một nhóm vật phẩm hoặc bộ phận được đặt vào."},"6512":{"word":"thải ra, xả ra","meaning":"Hành động đẩy hoặc đưa một chất gì đó, như khói hoặc chất lỏng, ra khỏi một nơi hoặc nguồn."},"6513":{"word":"bách khoa toàn thư","meaning":"Một cuốn từ điển bao gồm kiến thức về mọi lĩnh vực như nghiên cứu, nghệ thuật, xã hội, văn hóa, v.v."},"6514":{"word":"bách tính, dân chúng","meaning":"Tất cả những cá nhân sống trong một quốc gia cụ thể hoặc dưới sự cai trị của một người."},"6515":{"word":"Bách Tế","meaning":"Tên một trong ba vương quốc cổ đại trên bán đảo Triều Tiên."},"6516":{"word":"đùng đùng","meaning":"Diễn tả hành động thể hiện sự tức giận hoặc thất vọng một cách nhanh chóng và lớn tiếng."},"6517":{"word":"vô lễ","meaning":"Chỉ hành vi không có sự tôn trọng hoặc lịch sự với người khác, đặc biệt là người lớn tuổi."},"6518":{"word":"quá sức","meaning":"Cảm thấy gánh nặng công việc hoặc tình huống quá lớn, không thể xoay sở được."},"6519":{"word":"lần nào cũng","meaning":"Diễn tả việc gì đó xảy ra lặp đi lặp lại không bỏ sót lần nào."},"6520":{"word":"lan ra","meaning":"Chất lỏng hoặc màu sắc di chuyển từ vị trí ban đầu ra rộng hơn hoặc bị dính bẩn, nhòe đi."},"6521":{"word":"đỏ rực","meaning":"Có màu đỏ tươi và đậm, giống màu máu hoặc lửa cháy."},"6522":{"word":"tội phạm","meaning":"Người đã thực hiện hành vi bị pháp luật cấm và có thể bị trừng phạt."},"6523":{"word":"-pháp","meaning":"Tiếp vĩ ngữ chỉ cách thức hoặc hệ thống để làm hay tạo ra điều gì đó."},"6524":{"word":"pháp quy","meaning":"Những quy tắc hoặc mệnh lệnh chính thức được cơ quan có thẩm quyền ban hành mà mọi người phải tuân thủ."},"6525":{"word":"khoa luật","meaning":"Bộ phận hoặc trường học chuyên biệt trong đại học nơi sinh viên học về hệ thống pháp luật và chuẩn bị trở thành luật sư."},"6526":{"word":"Bộ Tư pháp","meaning":"Cơ quan chính phủ chịu trách nhiệm xây dựng và thực thi pháp luật cùng các vấn đề pháp lý của một quốc gia."},"6527":{"word":"hoa anh đào","meaning":"Một loài hoa nhỏ màu hồng hoặc trắng tinh tế, nở vào mùa xuân."},"6528":{"word":"sao chép","meaning":"Viết hoặc vẽ một cái gì đó giống hệt như bản gốc, thường là không có sự cho phép."},"6529":{"word":"gối đầu","meaning":"Đặt đầu hoặc một bộ phận khác của cơ thể lên một vật mềm như gối, thường là khi đi ngủ."},"6530":{"word":"chặt, cắt","meaning":"Dùng dụng cụ sắc bén như dao hoặc cưa để cắt rời hoặc loại bỏ một phần của vật gì đó."},"6531":{"word":"sách/sản phẩm bán chạy nhất","meaning":"Một sản phẩm hoặc cuốn sách được bán nhiều đơn vị nhất trong một khoảng thời gian nhất định."},"6532":{"word":"tia sét","meaning":"Một luồng ánh sáng rất chói trên bầu trời, thường đi kèm với tiếng nổ lớn, xảy ra trong cơn bão."},"6533":{"word":"gạch","meaning":"Một khối cứng hình chữ nhật làm bằng đất sét nung, thường có màu nâu đỏ, dùng để xây tường hoặc nhà."},"6534":{"word":"bồn cầu","meaning":"Thiết bị vệ sinh bằng gốm sứ trong phòng tắm, có nắp và bồn nước, dùng để xả chất thải của con người."},"6535":{"word":"biến hình, hóa thân","meaning":"Quá trình thay đổi rõ ràng để trở thành một hình dạng mới hoặc rất khác biệt."},"6536":{"word":"không thay đổi, vẫn như cũ","meaning":"Luôn giữ nguyên trạng thái như trước, không có sự khác biệt rõ rệt theo thời gian."},"6537":{"word":"không thay đổi, vẫn như trước","meaning":"Làm một việc gì đó theo cách giống hệt như trước, không có sự khác biệt nào."},"6538":{"word":"điều đặc biệt","meaning":"Một điều gì đó lạ lùng, không phổ biến hoặc không tầm thường."},"6539":{"word":"kỳ lạ, khác thường","meaning":"Có tính cách hoặc hành vi khác biệt rõ rệt so với những điều bình thường."},"6540":{"word":"tên bệnh","meaning":"Thuật ngữ cụ thể do các chuyên gia y tế đặt ra để xác định một loại bệnh ảnh hưởng đến người hoặc động vật."},"6541":{"word":"gà con","meaning":"Con chim non vừa mới nở từ trứng, thường có màu vàng và lông tơ mềm mại."},"6542":{"word":"trung tâm y tế dự phòng, trạm y tế","meaning":"Cơ sở do chính phủ điều hành, nơi người dân có thể đến để được chăm sóc y tế cơ bản và thông tin về sức khỏe."},"6543":{"word":"sôi sùng sục, lục bục","meaning":"Từ mô phỏng âm thanh hoặc chuyển động của một lượng nhỏ chất lỏng đang sôi to và liên tục."},"6544":{"word":"bồi thường","meaning":"Tiền hoặc hàng hóa được cung cấp cho một người hoặc nhóm để bù đắp cho tổn thất, thiệt hại hoặc tổn thương mà họ đã phải chịu."},"6545":{"word":"tiền bồi thường","meaning":"Khoản tiền được trả để bù đắp cho ai đó về mất mát hoặc thiệt hại của họ."},"6546":{"word":"chủ nghĩa bảo thủ","meaning":"Một cách tư duy coi trọng truyền thống và các cấu trúc hiện có, thường khiến mọi người chống lại những ý tưởng mới hoặc thay đổi nhanh chóng trong xã hội."},"6547":{"word":"sửa chữa, tu sửa","meaning":"Hành động làm việc trên một món đồ hoặc cấu trúc bị hỏng, hư hại hoặc cũ để làm cho nó hoạt động trở lại hoặc trông mới mẻ hơn."},"6548":{"word":"bảo thủ (tính từ)","meaning":"Mô tả một người hoặc một nhóm người thích những ý tưởng truyền thống và cách làm việc hiện có, thường thể hiện thái độ thận trọng đối với những thay đổi mới."},"6549":{"word":"thuốc bổ","meaning":"Một loại đồ uống, viên thuốc hoặc thực phẩm đặc biệt, thường làm từ thảo dược, mà mọi người sử dụng để tăng cường sức khỏe hoặc phục hồi cơ thể."},"6550":{"word":"chăm sóc trẻ em, nuôi dạy trẻ","meaning":"Hành động trông nom, dạy dỗ và hỗ trợ trẻ nhỏ khi cha mẹ chúng vắng nhà hoặc đi làm."},"6551":{"word":"nồi hơi","meaning":"Máy dùng để đun nước nóng cung cấp nhiệt sưởi ấm hoặc nước nóng sinh hoạt cho nhà ở, tòa nhà."},"6552":{"word":"khăn gói","meaning":"Một mảnh vải vuông thường dùng để gói, mang hoặc trang trí đồ vật bằng cách buộc lại."},"6553":{"word":"bảo đảm","meaning":"Lời cam kết hoặc văn bản chính thức xác nhận rằng điều gì đó sẽ được thực hiện đúng như thỏa thuận, hoặc một sản phẩm sẽ hoạt động tốt trong một thời gian nhất định."},"6554":{"word":"tiền đặt cọc","meaning":"Khoản tiền được trả vào đầu một hợp đồng thuê hoặc dịch vụ, được bên kia giữ và thường được hoàn trả sau nếu các điều kiện được đáp ứng."},"6555":{"word":"phổ quát","meaning":"Dùng để mô tả điều gì đó áp dụng cho mọi người hoặc mọi vật trong một nhóm nhất định, hoặc được hiểu và có mặt trên toàn thế giới."},"6556":{"word":"phổ cập","meaning":"Quá trình mà một điều gì đó từng giới hạn hoặc mới mẻ trở nên phổ biến, được nhiều người trong xã hội chấp nhận hoặc sử dụng rộng rãi."},"6557":{"word":"phí bảo hiểm","meaning":"Khoản tiền định kỳ mà một người trả cho công ty bảo hiểm để được bảo vệ tài chính khi xảy ra tai nạn, bệnh tật hoặc mất mát."},"6558":{"word":"khôi phục","meaning":"Hành động làm cho một thứ đã bị hư hại, hỏng hóc hoặc mất mát trở lại trạng thái ban đầu hoặc hoạt động bình thường."},"6559":{"word":"xổ số","meaning":"Một trò chơi mà mọi người mua vé có số độc đáo, và một vài vé được chọn ngẫu nhiên để trúng giải thưởng, thường là số tiền lớn."},"6560":{"word":"phục chế","meaning":"Quá trình sửa chữa một món đồ cũ hoặc bị hỏng để làm cho nó trông giống như nguyên bản, hoàn chỉnh trở lại."},"6561":{"word":"phúc lợi","meaning":"Sự hỗ trợ do xã hội hoặc chính phủ cung cấp để giúp mọi người duy trì một mức sống tốt, thường bao gồm tiền bạc, nhà ở hoặc chăm sóc sức khỏe."},"6562":{"word":"nhập học lại","meaning":"Hành động một học sinh, sinh viên trở lại học tại trường đại học hoặc cao đẳng sau một thời gian vắng mặt."},"6563":{"word":"phức hợp","meaning":"Từ dùng để chỉ cái gì đó được tạo thành từ nhiều bộ phận hoặc yếu tố khác nhau kết hợp lại."},"6564":{"word":"này, đó","meaning":"Từ dùng trong văn viết hoặc lời nói trang trọng để chỉ điều được nói đến hoặc đang được đề cập."},"6565":{"word":"chính thức, thực sự","meaning":"Trạng thái một việc gì đó được tiến hành một cách nghiêm túc, đầy đủ và toàn diện."},"6566":{"word":"quê hương, tổ quốc","meaning":"Đất nước nơi một người sinh ra, lớn lên hoặc mang quốc tịch và có cảm giác thân thuộc."},"6567":{"word":"mô phỏng, sao chép","meaning":"Làm một thứ gì đó mới bằng cách dựa vào một vật hoặc thiết kế có sẵn để tạo ra sản phẩm tương tự."},"6568":{"word":"phần chính, nội dung chính","meaning":"Phần quan trọng nhất trong một bài viết hoặc bài nói, nơi các ý chính và lập luận được trình bày chi tiết."},"6569":{"word":"tên thật","meaning":"Tên chính thức được ghi trên giấy tờ của một người, không phải là nghệ danh hay biệt danh."},"6570":{"word":"nội dung chính, thân bài","meaning":"Phần văn bản chủ yếu, nội dung cốt lõi của một tài liệu hoặc tác phẩm dài."},"6571":{"word":"noi gương, học theo","meaning":"Làm theo những đức tính hoặc hành động tốt đẹp của người khác, thể hiện sự ngưỡng mộ."},"6572":{"word":"trụ sở chính, công ty mẹ","meaning":"Văn phòng hoặc tòa nhà trung tâm của một công ty hoặc tổ chức, nơi đưa ra các quyết định quan trọng nhất."},"6573":{"word":"vòng chung kết","meaning":"Các giai đoạn cuối cùng của một cuộc thi đấu, nơi các thí sinh xuất sắc nhất tranh tài để tìm ra người chiến thắng cuối cùng."},"6574":{"word":"bản chất, cốt yếu","meaning":"Thuộc về tính chất cơ bản và quan trọng nhất của một sự vật, nếu không có nó thì vật đó sẽ không còn là nó nữa."},"6575":{"word":"người tình nguyện","meaning":"Người dành thời gian, công sức và kỹ năng của mình để giúp đỡ người khác hoặc một mục đích cụ thể mà không nhận thù lao."},"6576":{"word":"phó-","meaning":"Tiếp đầu ngữ chỉ người hoặc vật ở vị trí thứ hai hoặc là trợ lý cho người đứng đầu."},"6577":{"word":"-phần","meaning":"Tiếp vĩ ngữ chỉ một khu vực cụ thể hoặc một bộ phận riêng biệt trong một đối tượng hoặc cấu trúc lớn hơn."},"6578":{"word":"áp đặt","meaning":"Hành động chính thức đặt ra hoặc áp dụng một khoản thuế, phí hoặc nghĩa vụ lên ai đó hoặc cái gì đó."},"6579":{"word":"cảm giác gánh nặng","meaning":"Cảm giác nặng nề trong tâm trí do một nhiệm vụ khó khăn hoặc áp lực lớn để đạt được điều gì đó."},"6580":{"word":"sự vô đạo đức","meaning":"Hành vi hoặc phẩm chất đi ngược lại các quy tắc được chấp nhận về đạo đức và lẽ phải."},"6581":{"word":"trợn mắt","meaning":"Cố tình mở rộng mí mắt để mắt trông lớn hơn, thường là để thể hiện sự tức giận hoặc ngạc nhiên."},"6582":{"word":"trạng từ","meaning":"Từ cung cấp thêm thông tin về động từ, tính từ hoặc một từ loại khác, cho biết cách thức, thời gian, địa điểm hoặc mức độ của hành động."},"6583":{"word":"chói mắt","meaning":"Rất sáng, làm cho mắt bị đau hoặc khó nhìn rõ."},"6584":{"word":"ban cho","meaning":"Hành động trao hoặc gán một thứ gì đó, như quyền hạn, quyền lợi hoặc ý nghĩa đặc biệt, cho một người hoặc một vật."},"6585":{"word":"tầng lớp thượng lưu","meaning":"Một nhóm người trong xã hội sở hữu nhiều tiền và tài sản có giá trị."},"6586":{"word":"giàu có","meaning":"Sở hữu nhiều tiền, tài sản và của cải có giá trị."},"6587":{"word":"sự phủ nhận","meaning":"Hành động từ chối hoặc tuyên bố rằng một điều gì đó là không đúng sự thật."},"6588":{"word":"đột ngột, rõ rệt, đáng kể","meaning":"Diễn tả sự tăng lên hay thay đổi một cách nhanh chóng và rõ ràng trong thời gian ngắn."},"6589":{"word":"nợ, khoản nợ","meaning":"Số tiền mà một người hay tổ chức nhận từ người khác và phải hoàn trả lại."},"6590":{"word":"quá sức, vượt quá khả năng","meaning":"Diễn tả việc một công việc hay nhiệm vụ vượt quá khả năng hoặc sức lực của một người."},"6591":{"word":"phồng lên, nở ra, sưng lên","meaning":"Trở nên lớn hơn về kích thước hoặc thể tích, thường do chứa đầy khí, gas hoặc chất lỏng."},"6592":{"word":"cấp dưới","meaning":"Người có chức vụ hoặc địa vị thấp hơn và làm việc dưới quyền của một người cấp cao hơn."},"6593":{"word":"trống","meaning":"Một nhạc cụ rỗng, tròn, tạo ra âm thanh khi được đánh bằng tay hoặc dùi."},"6594":{"word":"Bắc Cực","meaning":"Điểm cực bắc của Trái Đất, một khu vực rất lạnh thường bị bao phủ bởi băng và tuyết."},"6595":{"word":"Bắc Triều Tiên","meaning":"Tên gọi của đất nước nằm ở phía bắc bán đảo Triều Tiên, phía đông Trung Quốc và phía nam Nga."},"6596":{"word":"hướng bắc","meaning":"Chỉ cửa sổ hoặc mặt của một tòa nhà quay về phía bắc, thường nhận được ít ánh sáng mặt trời trực tiếp."},"6597":{"word":"phần, khẩu phần (hậu tố)","meaning":"Hậu tố dùng sau một số hoặc danh từ để chỉ một phần hoặc một đoạn của tổng thể."},"6598":{"word":"sự tức giận, cơn giận","meaning":"Cảm xúc mạnh mẽ của sự phẫn nộ hoặc bực tức trước một điều gì đó."},"6599":{"word":"phân loại rác","meaning":"Việc phân chia các loại rác thải như giấy, nhựa, thủy tinh để tái chế và sử dụng lại."},"6600":{"word":"bận rộn, tất bật","meaning":"Tình trạng có nhiều việc phải làm, nhiều hoạt động diễn ra liên tục, khiến người ta phải di chuyển nhanh chóng."},"6601":{"word":"điều kỳ diệu, điều bí ẩn","meaning":"Một hiện tượng hoặc sự vật kỳ lạ, khó hiểu đến mức khiến người ta cảm thấy khó hiểu hoặc ngưỡng mộ sâu sắc."},"6602":{"word":"suy thoái kinh tế","meaning":"Giai đoạn kinh tế kém phát triển, các doanh nghiệp gặp khó khăn, nhiều người thất nghiệp và hoạt động thương mại trì trệ."},"6603":{"word":"chỉ, vỏn vẹn","meaning":"Không vượt quá một số lượng hoặc mức độ nhất định nào đó."},"6604":{"word":"ngọn lửa","meaning":"Luồng khí nóng, sáng rực bốc lên từ vật đang cháy."},"6605":{"word":"không may, điềm gở","meaning":"Có cảm giác rằng mình sẽ gặp xui xẻo và điều gì đó tồi tệ sắp xảy ra."},"6606":{"word":"pháo hoa","meaning":"Loại thiết bị bắn ra ánh sáng rực rỡ, nhiều màu sắc và tạo ra tiếng ồn lớn trên bầu trời, thường dùng trong các dịp lễ kỷ niệm."},"6607":{"word":"hư hỏng, xấu","meaning":"Tình trạng xấu, không đạt tiêu chuẩn về chất lượng hoặc về hành vi, đạo đức."},"6608":{"word":"sản phẩm lỗi, hàng lỗi","meaning":"Một mặt hàng bị lỗi hoặc hỏng, không hoạt động đúng chức năng hoặc không đạt tiêu chuẩn mong đợi."},"6609":{"word":"gọi ra, triệu tập","meaning":"Nói lớn hoặc nhắn tin cho ai đó, yêu cầu họ ra khỏi một nơi nào đó hoặc xuất hiện."},"6610":{"word":"gọi vào, mời vào","meaning":"Kêu gọi hoặc mời ai đó đi vào bên trong."},"6611":{"word":"được gọi, được đặt tên","meaning":"Từ dùng để chỉ việc ai đó được người khác gọi bằng một tên hoặc một từ nào đó."},"6612":{"word":"chứng mất ngủ","meaning":"Tình trạng bệnh lý mà một người rất khó đi vào giấc ngủ hoặc duy trì giấc ngủ suốt đêm."},"6613":{"word":"tượng Phật","meaning":"Bức tượng của một vị lãnh đạo tôn giáo, thường được thấy trong các chùa chiền và dùng để thờ cúng."},"6614":{"word":"sự thiếu thành thật","meaning":"Thái độ làm việc hoặc hành động cho thấy sự thiếu nỗ lực thực sự hoặc thiếu ý định trung thực."},"6615":{"word":"sự không tin tưởng, sự ngờ vực","meaning":"Cảm giác nghi ngờ ngăn cản một người tin tưởng hoặc dựa vào người khác hoặc sự vật nào đó."},"6616":{"word":"cảm giác bất an, cảm giác lo lắng","meaning":"Cảm giác lo lắng mạnh mẽ về một sự kiện không chắc chắn, thường gây bồn chồn hoặc căng thẳng."},"6617":{"word":"tăng lên, phình ra","meaning":"Trở nên lớn hơn về số lượng, kích thước hoặc phạm vi, có nhiều hơn so với trước."},"6618":{"word":"bất hạnh, kém may mắn","meaning":"Từ dùng để mô tả một người hoặc một nhóm người gặp phải hoàn cảnh khó khăn, thiếu thốn."},"6619":{"word":"sự bất công","meaning":"Tình huống mà một hành động hoặc đối xử không công bằng hoặc không đúng đắn về mặt đạo đức."},"6620":{"word":"bệnh nan y, bệnh không chữa được","meaning":"Tình trạng bệnh lý nghiêm trọng mà y học không thể loại bỏ hoàn toàn, gây ra các triệu chứng kéo dài."},"6621":{"word":"chỉ số khó chịu","meaning":"Một con số cho biết mức độ người ta có thể cảm thấy khó chịu do thời tiết nóng ẩm."},"6622":{"word":"tính mờ đục","meaning":"Đặc tính của vật liệu không cho ánh sáng đi qua, khiến không thể nhìn thấy vật thể phía bên kia."},"6623":{"word":"không may","meaning":"Diễn tả sự việc hay tình huống xảy ra một cách đáng tiếc, không tốt đẹp."},"6624":{"word":"màu đỏ","meaning":"Một màu sắc giống như màu của ớt chín hoặc máu."},"6625":{"word":"đỏ mặt","meaning":"Khi mặt hoặc da của một người trở nên hồng hoặc đỏ rõ rệt do xấu hổ, giận dữ hoặc nóng."},"6626":{"word":"bút lông","meaning":"Một dụng cụ có nhiều sợi lông gắn vào cán, dùng để vẽ hoặc viết bằng mực, màu nước."},"6627":{"word":"sụp đổ","meaning":"Một tòa nhà hoặc cấu trúc đột ngột đổ nát và rơi xuống đất."},"6628":{"word":"băng gạc","meaning":"Một mảnh vải dài dùng để băng bó vết thương hoặc giữ cố định một bộ phận cơ thể."},"6629":{"word":"thương hiệu","meaning":"Một tên gọi, biểu tượng hoặc thiết kế cụ thể được một công ty sử dụng để nhận diện sản phẩm của mình."},"6630":{"word":"phanh","meaning":"Một bộ phận trên xe cộ hoặc máy móc dùng để giảm tốc độ hoặc dừng hoàn toàn."},"6631":{"word":"blog","meaning":"Một trang nhật ký trực tuyến hoặc trang web nơi một người thường xuyên đăng tải bài viết, ảnh hoặc video về sở thích của mình."},"6632":{"word":"sự bi quan","meaning":"Cách suy nghĩ luôn mong đợi kết quả xấu và thường tỏ ra lo lắng hoặc tin rằng mọi thứ sẽ diễn biến tồi tệ."},"6633":{"word":"bi quan","meaning":"Mô tả một người có xu hướng chỉ mong đợi những điều tồi tệ xảy ra và thường tỏ ra lo lắng hoặc tuyệt vọng."},"6634":{"word":"bồ câu","meaning":"Một loài chim có màu xám hoặc trắng với đôi chân ngắn và đôi cánh lớn, thường thấy ở công viên hoặc đường phố."},"6635":{"word":"bị xiên vẹo, bị lệch","meaning":"Trở nên không thẳng, không ngay ngắn mà bị nghiêng hoặc cong."},"6636":{"word":"tỉ lệ","meaning":"Mối quan hệ giữa hai đại lượng mà khi một đại lượng tăng hoặc giảm thì đại lượng kia cũng thay đổi theo một mức độ nhất định."},"6637":{"word":"phân bón","meaning":"Chất dùng để bón cho cây trồng phát triển tốt hơn."},"6638":{"word":"sai trái, tham nhũng","meaning":"Hành vi không đúng đắn, không hợp đạo đức hoặc vi phạm quy định, pháp luật."},"6639":{"word":"tiền dự phòng, quỹ đen","meaning":"Số tiền dành dụm đặc biệt để sử dụng khi có vấn đề khẩn cấp hoặc bất ngờ xảy ra."},"6640":{"word":"thuốc cấp cứu, thuốc dự phòng","meaning":"Các loại thuốc được giữ sẵn để dùng cho những trường hợp ốm đau, tai nạn đột xuất hoặc tình huống sức khỏe khẩn cấp khác."},"6641":{"word":"thư ký","meaning":"Người có nhiệm vụ thực hiện các công việc văn phòng như soạn thảo văn bản, nghe điện thoại và sắp xếp cuộc họp cho người khác."},"6642":{"word":"mang tính ẩn dụ, ví von","meaning":"Miêu tả ngôn ngữ sử dụng từ ngữ để tạo hình ảnh hoặc so sánh một cách sáng tạo, không theo nghĩa đen."},"6643":{"word":"chật chội, hẹp hòi","meaning":"Miêu tả một không gian quá nhỏ hoặc có chiều rộng hẹp, gây khó khăn khi di chuyển thoải mái."},"6644":{"word":"phê bình, nhận xét","meaning":"Sự phân tích chi tiết một tác phẩm như phim hay sách, thường nêu rõ điểm mạnh và điểm yếu để người khác tham khảo."},"6645":{"word":"tần suất, tần số","meaning":"Số lần mà một sự việc hoặc hiện tượng lặp lại trong một khoảng thời gian nhất định."},"6646":{"word":"ngồi không, nhàn rỗi","meaning":"Dành thời gian một cách thư giãn, không làm gì hoặc làm rất ít việc, chỉ để giết thời gian một cách lười biếng."},"6647":{"word":"thường xuyên","meaning":"Xảy ra nhiều lần, liên tục trong một khoảng thời gian ngắn."},"6648":{"word":"nhà tang lễ","meaning":"Căn phòng dùng để đặt thi thể người đã khuất, để mọi người đến viếng và tiễn đưa trước khi chôn cất hoặc hỏa táng."},"6649":{"word":"chỗ trống","meaning":"Khoảng trống chưa được điền thông tin hoặc chữ viết trên giấy hoặc màn hình."},"6650":{"word":"cầu xin","meaning":"Xin hoặc cầu khẩn ai đó một cách thiết tha để nhận được sự giúp đỡ, thức ăn hoặc thứ gì đó."},"6651":{"word":"trật","meaning":"Đi sai hướng, không trúng vào mục tiêu đã định."},"6652":{"word":"đá bào","meaning":"Món tráng miệng làm từ đá được bào nhuyễn, thường ăn kèm với đậu đỏ, trái cây và các loại topping khác."},"6653":{"word":"sông băng","meaning":"Khối băng khổng lồ, rất dày di chuyển cực chậm trên mặt đất, thường thấy ở vùng núi hoặc gần các cực."},"6654":{"word":"làm rạng danh","meaning":"Làm cho một người, một nhóm hoặc một quốc gia trở nên nổi bật, đáng tự hào và có danh tiếng tốt."},"6655":{"word":"eo hẹp","meaning":"Thời gian hoặc tiền bạc rất ít ỏi, không có dư dả, đòi hỏi phải sắp xếp cẩn thận."},"6656":{"word":"rút ra","meaning":"Dùng lực để lấy một vật thể ra khỏi nơi nó bị mắc kẹt."},"6657":{"word":"bị cướp","meaning":"Bị người khác dùng vũ lực hoặc thủ đoạn lấy đi tài sản hoặc vật sở hữu, khiến bản thân không còn nó nữa."},"6658":{"word":"rõ ràng","meaning":"Dễ dàng nhận thấy hoặc hiểu được, không cần phải giải thích thêm."},"6659":{"word":"nhễ nhại","meaning":"Mồ hôi chảy ra rất nhiều, làm người ướt đẫm."},"6660":{"word":"phô diễn","meaning":"Cố tình thể hiện tài năng, của cải hoặc vẻ đẹp của mình để thu hút sự chú ý của người khác."},"6661":{"word":"nhọn","meaning":"Có đầu rất nhỏ, sắc hoặc cạnh rất mỏng có thể dễ dàng cắt hoặc đâm xuyên qua."},"6662":{"word":"mãn nguyện","meaning":"Cảm thấy hài lòng và hạnh phúc sâu sắc, thường sau khi hoàn thành thành công một nhiệm vụ khó khăn hoặc đạt được điều gì đó quan trọng."},"6663":{"word":"sừng","meaning":"Bộ phận cứng và nhọn mọc ra từ đầu của các loài động vật như bò hoặc hươu."},"6664":{"word":"tư duy","meaning":"Hoạt động của bộ não để hình thành ý tưởng, đưa ra quyết định hoặc giải quyết vấn đề."},"6665":{"word":"giao tiếp xã hội","meaning":"Việc mọi người tương tác với nhau một cách thân thiện, ví dụ tại một buổi tụ tập hoặc bữa tiệc."},"6666":{"word":"giáo dục tư nhân","meaning":"Các buổi học hoặc bài giảng bổ sung mà học sinh nhận được bên ngoài trường học chính thức, thường do phụ huynh chi trả."},"6667":{"word":"chi phí giáo dục tư nhân","meaning":"Số tiền mà phụ huynh chi trả cho các lớp học thêm hoặc dạy kèm riêng mà con cái họ nhận được ngoài giờ học chính quy."},"6668":{"word":"phim cổ trang","meaning":"Một loại phim điện ảnh hoặc chương trình truyền hình kể một câu chuyện lấy bối cảnh thời gian xưa, với các nhân vật mặc trang phục cũ và bối cảnh cổ kính."},"6669":{"word":"hung dữ","meaning":"Trông rất hung hăng hoặc dễ nổi giận, thường thể hiện vẻ đáng sợ hoặc đe dọa."},"6670":{"word":"khách sáo","meaning":"Hành động hoặc nói chuyện một cách rất trang trọng và xa cách, chỉ tập trung vào nhiệm vụ mà không thể hiện cảm xúc cá nhân hay sự thân thiện."},"6671":{"word":"Samulnori","meaning":"Một loại hình âm nhạc truyền thống sôi động của Hàn Quốc, được biểu diễn bởi bốn người chơi các nhạc cụ gõ như chiêng và trống, thường kết hợp với chuyển động."},"6672":{"word":"thường phục","meaning":"Quần áo mặc trong cuộc sống hàng ngày, không phải đồng phục hay lễ phục."},"6673":{"word":"tư tưởng","meaning":"Một quan điểm, cách nhìn nhận về xã hội, chính trị, hoặc một vấn đề nào đó."},"6674":{"word":"hươu","meaning":"Một loài động vật hoang dã có mắt to, lông màu nâu, chân dài, và con đực có sừng, thường sống ở vùng núi."},"6675":{"word":"trên thực tế","meaning":"Dùng để chỉ rằng một việc gì đó trên thực tế đã đạt được hoặc đã tồn tại, dù chưa được xác nhận một cách chính thức."},"6676":{"word":"doanh nghiệp","meaning":"Một tổ chức hoặc một nhóm người sản xuất hàng hóa hoặc cung cấp dịch vụ để tạo ra lợi nhuận."},"6677":{"word":"nhân viên","meaning":"Người làm việc cho một công ty hoặc tổ chức và nhận lương cho công việc của mình."},"6678":{"word":"đền thờ","meaning":"Một tòa nhà hoặc địa điểm linh thiêng nơi mọi người tụ tập để thờ cúng thần linh."},"6679":{"word":"lý do","meaning":"Nguyên nhân hoặc lý do cụ thể để giải thích cho một sự việc hay hành động nào đó."},"6680":{"word":"quà cảm ơn","meaning":"Món quà được tặng để bày tỏ lòng biết ơn hoặc đáp lại ân tình đã nhận được."},"6681":{"word":"thành ngữ bốn chữ","meaning":"Một thành ngữ ngắn gọn, cố định gồm đúng bốn chữ Hán, mang ý nghĩa truyền thống hoặc bài học đạo đức."},"6682":{"word":"tứ chi","meaning":"Các bộ phận dài và nhô ra khỏi cơ thể của người hoặc động vật, như tay và chân, dùng để di chuyển hoặc cầm nắm."},"6683":{"word":"xa xỉ","meaning":"Việc chi tiêu quá nhiều tiền vào những thứ không thiết yếu, đắt đỏ chỉ để hưởng thụ hoặc khoe khoang."},"6684":{"word":"án tử hình","meaning":"Hình phạt cao nhất do tòa án tuyên án, theo đó người phạm tội nghiêm trọng sẽ bị nhà nước tước đoạt mạng sống."},"6685":{"word":"người dẫn chương trình","meaning":"Người điều khiển, dẫn dắt một sự kiện, buổi lễ như đám cưới hoặc hội nghị."},"6686":{"word":"ảm đạm","meaning":"Mô tả một nơi chốn hay tình huống trông hoang vắng, lạnh lẽo, không có chút hơi ấm hay sức sống nào."},"6687":{"word":"xuất xứ","meaning":"Hậu tố dùng để chỉ nơi chốn, khu vực hay quốc gia cụ thể mà một sản phẩm hoặc vật liệu được sản xuất hoặc có nguồn gốc."},"6688":{"word":"vùng núi hẻo lánh","meaning":"Khu vực núi non hẻo lánh, xa xôi, ít người qua lại."},"6689":{"word":"đống","meaning":"Từ dùng để chỉ một số lượng lớn đồ vật được chất chồng lên nhau cao như ngọn núi."},"6690":{"word":"sạt lở đất","meaning":"Hiện tượng một khối lượng lớn đất, đá và mảnh vụn đột ngột di chuyển nhanh chóng xuống sườn núi hoặc đồi."},"6691":{"word":"mưa axit","meaning":"Hiện tượng mưa có chứa các chất độc hại từ ô nhiễm môi trường, gây hại cho cây cối, công trình và nguồn nước."},"6692":{"word":"mộ phần","meaning":"Nơi chôn cất thi hài của người đã khuất, thường được đánh dấu bằng bia đá hoặc đắp đất, đặc biệt là của tổ tiên."},"6693":{"word":"ôxy","meaning":"Nguyên tố không màu, không mùi, có trong không khí và cần thiết cho sự hô hấp và tồn tại của mọi sinh vật sống."},"6694":{"word":"công nghiệp hóa","meaning":"Quá trình phát triển công nghiệp và công nghệ, khiến sản xuất được cơ khí hóa và xã hội có xu hướng tập trung dân số vào các đô thị."},"6695":{"word":"lén lút, rón rén","meaning":"Di chuyển một cách cẩn thận, nhẹ nhàng và không gây tiếng động để tránh bị phát hiện."},"6696":{"word":"nhẹ nhàng, khẽ khàng","meaning":"Làm việc gì đó một cách tinh tế, cẩn thận, ít lực hoặc gần như không gây ra tiếng động."},"6697":{"word":"kiêng cử, tiết chế, hạn chế","meaning":"Cố ý không làm một hành động hoặc không nói một điều gì đó mà mình có thể đã làm hoặc nói."},"6698":{"word":"từng tốp, từng nhóm nhỏ","meaning":"Mô tả nhiều người tụ tập thành các nhóm nhỏ không chính thức, thường là hai, ba hoặc vài người."},"6699":{"word":"-về mặt, -theo khía cạnh","meaning":"Hậu tố thêm vào cuối từ để diễn tả việc nhìn nhận một điều gì đó từ một khía cạnh hoặc trong một ngữ cảnh cụ thể."},"6700":{"word":"nhà tang lễ, nhà có tang","meaning":"Ngôi nhà nơi người thân tập trung và tổ chức tang lễ sau khi một người qua đời."},"6701":{"word":"lễ gặp mặt hai họ","meaning":"Sự kiện được sắp xếp để bố mẹ của cặp đôi sắp kết hôn lần đầu tiên gặp gỡ nhau, thường là tại nhà hàng."},"6702":{"word":"hiền lành, dịu dàng, thân thiện","meaning":"Mô tả người thường nói chuyện nhẹ nhàng, hành động thân thiện và hữu ích, khiến người khác cảm thấy thoải mái."},"6703":{"word":"số lượng đáng kể, phần lớn","meaning":"Tình trạng có một số lượng khá nhiều hoặc với số lượng lớn."},"6704":{"word":"tầng lớp thượng lưu","meaning":"Tầng lớp xã hội có địa vị cao hơn, mức sống cao hơn, v.v."},"6705":{"word":"phần thân trên","meaning":"Phần cơ thể của một người bao gồm đầu, tay, ngực và bụng, tính từ thắt lưng trở lên."},"6706":{"word":"tương trợ, giúp đỡ lẫn nhau","meaning":"Thực hành mà các cá nhân hoặc nhóm khác nhau giúp đỡ nhau để giải quyết khó khăn chung."},"6707":{"word":"Mất mát","meaning":"Tình trạng không còn có hoặc không còn sở hữu một thứ gì đó đã từng có."},"6708":{"word":"Thương mại","meaning":"Có liên quan đến việc sản xuất, mua bán hàng hóa hoặc dịch vụ nhằm mục đích kiếm lời."},"6709":{"word":"Tiền thưởng","meaning":"Một khoản tiền bổ sung được công ty trả cho nhân viên ngoài tiền lương cơ bản, thường để khen thưởng hoặc khuyến khích."},"6710":{"word":"Rạp chiếu phim","meaning":"Phòng lớn, tối với nhiều hàng ghế, nơi công chúng tập trung để xem phim được trình chiếu trên màn hình."},"6711":{"word":"Tham vấn","meaning":"Việc nói chuyện với một hoặc nhiều người để trao đổi ý kiến và thu thập thông tin trước khi quyết định làm gì."},"6712":{"word":"Bày biện món ăn","meaning":"Hành động sắp xếp thức ăn và các vật dụng ăn uống lên bàn, hoặc một bàn ăn đã được chuẩn bị sẵn như vậy."},"6713":{"word":"Nhãn hiệu","meaning":"Tên, hình ảnh hoặc ký hiệu đặc biệt được in hoặc gắn trên sản phẩm để chỉ rõ nhà sản xuất hoặc tên gọi của sản phẩm."},"6714":{"word":"Phiếu quà tặng","meaning":"Thẻ hoặc giấy in được nhận làm quà tặng, có thể dùng để mua hàng hóa hoặc dịch vụ tại một cửa hàng nhất định với giá trị đã được xác định."},"6715":{"word":"Sự tăng lên","meaning":"Sự thay đổi hoặc di chuyển từ mức độ thấp hơn hoặc số lượng ít hơn lên mức độ cao hơn hoặc số lượng lớn hơn."},"6716":{"word":"Đen kịt","meaning":"Màu đen rất đậm, sâu, giống như màu than hoặc bầu trời đêm không có chút ánh sáng nào."},"6717":{"word":"Cô dâu mới","meaning":"Người phụ nữ mới kết hôn trong một khoảng thời gian gần đây."},"6718":{"word":"Mầm cây","meaning":"Một cây non rất nhỏ vừa mới nhú lên khỏi mặt đất."},"6719":{"word":"chua thanh","meaning":"Có vị hơi chua, gây cảm giác hơi rít miệng."},"6720":{"word":"xanh biếc","meaning":"Có màu xanh rất đậm và trong, giống như màu trời trong xanh hoặc biển cả."},"6721":{"word":"trắng tinh","meaning":"Có màu trắng hoàn toàn sáng và sạch, không pha tạp chút màu nào khác, giống như tuyết mới rơi."},"6722":{"word":"màu sắc","meaning":"Đặc tính cụ thể của một vật thể khi nhìn bằng mắt, giúp phân biệt các loại màu như đỏ, vàng, xanh."},"6723":{"word":"suối, nguồn nước","meaning":"Nơi nước trong vắt tự nhiên chảy ra từ lòng đất."},"6724":{"word":"nước suối","meaning":"Nước trong vắt tự nhiên chảy ra từ lòng đất, thường tập trung thành ao nhỏ hoặc dòng chảy."},"6725":{"word":"sự sống","meaning":"Trạng thái còn sống của con người, động vật hay thực vật, có thể vận động, lớn lên và hô hấp."},"6726":{"word":"sống","meaning":"Được đặt trước danh từ chỉ thực phẩm để biểu thị rằng nó chưa được nấu chín hoặc chế biến."},"6727":{"word":"sự sống động","meaning":"Chất lượng làm cho hình ảnh hoặc cảnh vật trở nên tràn đầy năng lượng, chân thực và như có sự chuyển động."},"6728":{"word":"sức sống, sinh lực","meaning":"Sức mạnh nội tại mạnh mẽ giúp con người, động vật hay thực vật duy trì khỏe mạnh, phát triển và tồn tại lâu dài."},"6729":{"word":"sinh vật sống","meaning":"Bất kỳ cá thể nào như động vật, thực vật hay con người, có sự sống, có thể lớn lên, di chuyển và sinh sản."},"6730":{"word":"sinh vật","meaning":"Các loài động vật và thực vật có sự sống trên trái đất."},"6731":{"word":"sản lượng","meaning":"Tổng số lượng sản phẩm hoặc vật liệu được làm ra hay thu hoạch trong một thời gian nhất định."},"6732":{"word":"nước khoáng","meaning":"Nước sạch tự nhiên, chưa qua đun sôi hay tiệt trùng."},"6733":{"word":"cuộc đời","meaning":"Toàn bộ khoảng thời gian một người, con vật hoặc cây cối tồn tại từ khi sinh ra cho đến khi chết đi."},"6734":{"word":"sinh thời","meaning":"Khoảng thời gian một người còn sống và chưa qua đời."},"6735":{"word":"hệ sinh thái","meaning":"Một khu vực cụ thể nơi các loài động vật, thực vật và các yếu tố không sống như đất, nước tương tác với nhau."},"6736":{"word":"thói quen hóa","meaning":"Việc biến một hành động hay hành vi thành một phần thường xuyên trong cuộc sống hàng ngày."},"6737":{"word":"buồn rầu","meaning":"Cảm thấy buồn bã sâu sắc và lặng lẽ, thường khiến người ta muốn khóc."},"6738":{"word":"mở đầu","meaning":"Phần đầu tiên của một bài viết hoặc bài nói, dùng để trình bày chủ đề chính."},"6739":{"word":"đọng hơi nước","meaning":"Khi những giọt nước nhỏ li ti tụ lại trên bề mặt lạnh, làm mờ đi và khó nhìn xuyên qua."},"6740":{"word":"xa cách","meaning":"Khi những người từng thân thiết nay cảm thấy xa lạ, ngại ngùng với nhau, khiến sự tương tác trở nên khó xử."},"6741":{"word":"văn bản","meaning":"Một tài liệu ghi chép chi tiết, được trình bày dưới dạng chữ viết."},"6742":{"word":"dân thường","meaning":"Một người bình thường không có địa vị cao trong xã hội."},"6743":{"word":"ngành dịch vụ","meaning":"Đây là lĩnh vực kinh tế chuyên cung cấp các loại hình dịch vụ cho người khác, không sản xuất hàng hóa vật chất."},"6744":{"word":"đi đi lại lại","meaning":"Hành động đi lại nhiều lần trong một khu vực nhỏ mà không có mục đích rõ ràng."},"6745":{"word":"sự diễn tả","meaning":"Việc kể hoặc viết lại một điều gì đó một cách chi tiết, giải thích sự việc đã xảy ra hay tính chất của nó."},"6746":{"word":"vị ngữ","meaning":"Trong một câu, đây là thành phần cho biết chủ ngữ làm gì hoặc chủ ngữ là gì."},"6747":{"word":"kiểu phương Tây","meaning":"Một phong cách thiết kế hoặc làm việc phổ biến ở các nước châu Âu hoặc Bắc Mỹ."},"6748":{"word":"thư pháp","meaning":"Nghệ thuật viết chữ đẹp bằng bút lông hoặc bút, thường dùng để trưng bày."},"6749":{"word":"phòng làm việc","meaning":"Một căn phòng trong nhà thường có sách và bàn làm việc, dùng để đọc, viết hoặc làm việc một cách yên tĩnh."},"6750":{"word":"hướng Tây","meaning":"Chỉ hướng của một tòa nhà hoặc một phần của tòa nhà nhìn về phía mặt trời lặn vào buổi tối."},"6751":{"word":"chỗ ngồi","meaning":"Tiếp tố này được dùng để chỉ không gian dành cho một người ngồi, thường ở nơi công cộng như sân vận động hay nhà hát."},"6752":{"word":"ba","meaning":"Từ này dùng để chỉ số lượng là ba đơn vị khi đếm một số thứ, ví dụ như khoảng thời gian."},"6753":{"word":"thạc sĩ","meaning":"Đây là một học vị học thuật được cấp cho người đã tốt nghiệp cao học, hoặc chỉ người có học vị đó."},"6754":{"word":"than đá","meaning":"Một loại đá màu đen dễ cháy, được dùng làm nhiên liệu hoặc nguyên liệu trong kỹ thuật hóa học."},"6755":{"word":"buổi xem mắt","meaning":"Cuộc gặp gỡ giữa hai người nam nữ với mục đích tìm hiểu để tiến tới hôn nhân, thường do người mai mối sắp đặt."},"6756":{"word":"vị trí dẫn đầu","meaning":"Vị trí ở phía trước nhất trong một cuộc thi đấu, cuộc đua hoặc một nhóm người, vật."},"6757":{"word":"rõ nét","meaning":"Trạng thái dễ dàng nhìn thấy hoặc nghe thấy vì có đường nét sắc sảo, không bị mờ hay tối."},"6758":{"word":"tàu thuyền","meaning":"Phương tiện vận tải lớn dùng để di chuyển trên mặt nước, chở người hoặc hàng hóa."},"6759":{"word":"kệ","meaning":"Tấm ván dài được gắn trên tường để đặt các đồ vật lên."},"6760":{"word":"tuyển chọn","meaning":"Việc lựa chọn cẩn thận một người hoặc một vật từ một nhóm lớn hơn cho một mục đích cụ thể."},"6761":{"word":"giới thiệu","meaning":"Công khai trưng bày hoặc trình diễn một thứ gì đó mới, như sản phẩm hoặc tác phẩm nghệ thuật, lần đầu tiên trước công chúng."},"6762":{"word":"trả trước","meaning":"Việc thanh toán tiền cho một dịch vụ hoặc sản phẩm trước khi nhận được hoặc sử dụng nó."},"6763":{"word":"tuyên bố","meaning":"Lời khẳng định chính thức, thường là công khai, về một quyết định, ý định hoặc sự thật."},"6764":{"word":"thiện ý","meaning":"Lòng tốt bụng, ý muốn làm điều tốt cho người khác."},"6765":{"word":"định kiến","meaning":"Ý kiến hoặc quan điểm cố định về một người hoặc một sự vật trước khi có sự tìm hiểu kỹ lưỡng, thường dẫn đến cách nhìn nhận không công bằng."},"6766":{"word":"ai đến trước được trước","meaning":"Hệ thống hoặc nguyên tắc mà theo đó người đến sớm nhất sẽ được ưu tiên phục vụ hoặc nhận được vật phẩm, dịch vụ trước."},"6767":{"word":"bẩm sinh","meaning":"Mô tả một đặc điểm, tài năng hoặc tình trạng mà một người có ngay từ khi sinh ra."},"6768":{"word":"sống động","meaning":"Mô tả hình ảnh, cảnh tượng hoặc sự kiện trong quá khứ hiện lên rõ ràng trong tâm trí như đang diễn ra."},"6769":{"word":"việc thiện","meaning":"Hành động giúp đỡ hoặc tử tế đối với người khác mà không mong đợi được đền đáp."},"6770":{"word":"mức độ ưa thích","meaning":"Mức độ mà một người thích một thứ gì đó hơn những lựa chọn khác."},"6771":{"word":"tiền bối và hậu bối","meaning":"Thuật ngữ chung chỉ những người trong một tổ chức gia nhập trước hoặc sau nhau, có sự kính trọng về kinh nghiệm."},"6772":{"word":"thuyết","meaning":"Một tập hợp các ý tưởng có tổ chức nhằm giải thích cách thức hoạt động của một sự vật hoặc lý do xảy ra một hiện tượng."},"6773":{"word":"thiết kế","meaning":"Bản vẽ hoặc kế hoạch chi tiết cho biết cách một cái gì đó sẽ được xây dựng hoặc chế tạo."},"6774":{"word":"sức thuyết phục","meaning":"Khả năng của một lập luận hoặc tuyên bố khiến người khác tin tưởng hoặc đồng ý."},"6775":{"word":"bài văn thuyết minh","meaning":"Một đoạn văn cung cấp thông tin rõ ràng về một chủ đề, giúp người đọc hiểu rõ hơn."},"6776":{"word":"dù cho","meaning":"Được dùng để nhấn mạnh một điều kiện giả định, bất chấp sự thật hay khả năng xảy ra của điều đó."},"6777":{"word":"trằn trọc","meaning":"Trạng thái ngủ không yên, thường xuyên trở mình và thức giấc nhiều lần."},"6778":{"word":"phụng sự","meaning":"Thể hiện sự tôn trọng và chăm sóc lớn lao đối với một người, thường bằng cách phục vụ hoặc hỗ trợ họ."},"6779":{"word":"tinh xảo, tinh tế","meaning":"Có những chi tiết rất nhỏ, phức tạp, hoặc rất nhạy cảm."},"6780":{"word":"hấp thụ, tiêu thụ","meaning":"Việc đưa thức ăn, đồ uống hoặc các chất khác vào cơ thể."},"6781":{"word":"giới tính","meaning":"Loại sinh học hoặc đặc điểm xã hội xác định giới nam hay nữ."},"6782":{"word":"Kinh Thánh","meaning":"Cuốn sách chứa đựng giáo lý và lời dạy của đạo Thiên Chúa giáo."},"6783":{"word":"tiền quyên góp, khoản đóng góp","meaning":"Số tiền được đóng góp vì một mục đích tốt đẹp, từ thiện."},"6784":{"word":"hấp tấp, vội vàng","meaning":"Hành động hoặc quyết định quá nhanh mà không suy nghĩ kỹ, đôi khi gây ra vấn đề."},"6785":{"word":"que diêm","meaning":"Dụng cụ dùng để tạo lửa, thường là một thanh gỗ nhỏ có đầu được phủ chất dễ cháy."},"6786":{"word":"tuổi trưởng thành","meaning":"Giai đoạn trong đời khi một người đạt đến độ tuổi nhất định và được pháp luật coi là người lớn."},"6787":{"word":"hiệu suất, tính năng","meaning":"Khả năng thực hiện công việc của máy móc hoặc người, được đánh giá qua tốc độ, hiệu quả hoặc chất lượng."},"6788":{"word":"hoành tráng, long trọng","meaning":"Rất lớn, ấn tượng và công phu, thường dùng để miêu tả các sự kiện."},"6789":{"word":"viếng mộ tổ tiên","meaning":"Phong tục đi thăm, dọn dẹp mộ tổ tiên để bày tỏ lòng kính trọng đối với người đã khuất."},"6790":{"word":"thành phần","meaning":"Một chất hoặc một yếu tố riêng lẻ được trộn lẫn với những chất khác để tạo thành một tổng thể lớn hơn."},"6791":{"word":"mùa cao điểm","meaning":"Khoảng thời gian trong năm mà có nhiều người mua sản phẩm hoặc sử dụng dịch vụ."},"6792":{"word":"sự thành thật, sự siêng năng","meaning":"Phẩm chất mà một người luôn nỗ lực chân thành và thực hiện lời hứa một cách nhất quán."},"6793":{"word":"một cách thành thật, một cách siêng năng","meaning":"Hành động làm việc gì đó bằng sự nỗ lực chân thành và chăm chỉ bền bỉ."},"6794":{"word":"tấm lòng chân thành, thành ý","meaning":"Sự nỗ lực chân thật hoặc ý định tốt mà một người đặt vào hành động hoặc món quà, điều mà người khác có thể nhận thấy."},"6795":{"word":"thánh nhân, hiền triết","meaning":"Người có trí tuệ phi thường và phẩm chất đạo đức cao cả, thường được coi là người dẫn dắt tinh thần."},"6796":{"word":"bệnh người lớn, bệnh lý lối sống","meaning":"Các vấn đề sức khỏe thường phát triển ở người không còn trẻ, thường do thói quen sinh hoạt hằng ngày."},"6797":{"word":"tính dục, liên quan đến tình dục","meaning":"Liên quan đến sự hấp dẫn thể chất, cảm xúc thân mật hoặc tiếp xúc thể chất giữa các cá nhân."},"6798":{"word":"giáo sĩ, tu sĩ","meaning":"Người làm công việc tôn giáo như mục sư, linh mục, nhà sư, v.v."},"6799":{"word":"thành tựu, thành quả","meaning":"Mục tiêu quan trọng hoặc thử thách mà một người đã hoàn thành hoặc đạt được thành công sau nhiều nỗ lực."},"6800":{"word":"khuynh hướng, xu hướng","meaning":"Cách một người thường hành động hoặc suy nghĩ, có thể quan sát được qua các lựa chọn hoặc sở thích lặp đi lặp lại của họ."},"6801":{"word":"phẫu thuật thẩm mỹ","meaning":"Thủ tục y tế do bác sĩ thực hiện để thay đổi vẻ ngoài của khuôn mặt hoặc các bộ phận cơ thể của một người."},"6802":{"word":"khoa phẫu thuật thẩm mỹ","meaning":"Tòa nhà hoặc văn phòng y tế nơi các bác sĩ thực hiện các thủ thuật để thay đổi vẻ ngoài của khuôn mặt hoặc cơ thể của một người."},"6803":{"word":"thế giới quan","meaning":"Tập hợp các quan điểm và niềm tin cơ bản của một người về thế giới và vị trí của họ trong đó."},"6804":{"word":"vi khuẩn","meaning":"Sinh vật rất nhỏ có thể gây bệnh cho con người hoặc làm hỏng thức ăn."},"6805":{"word":"bạc (tóc)","meaning":"Tóc chuyển sang màu trắng hoặc xám do tuổi tác hoặc các yếu tố khác."},"6806":{"word":"đồ dùng vệ sinh cá nhân","meaning":"Các vật dụng dùng để rửa mặt, gội đầu, hoặc cạo râu như xà phòng, bàn chải đánh răng, khăn tắm, v.v."},"6807":{"word":"chi tiết","meaning":"Những phần nhỏ, cụ thể hoặc thông tin cấu thành một tổng thể lớn hơn."},"6808":{"word":"chế độ thuế","meaning":"Hệ thống các quy định và luật lệ liên quan đến việc thu thuế của một quốc gia."},"6809":{"word":"mãnh liệt, dữ dội","meaning":"Có sức mạnh cực kỳ lớn, cường độ cao và di chuyển với năng lượng mạnh mẽ."},"6810":{"word":"thư giới thiệu","meaning":"Một tài liệu viết cung cấp thông tin về một người, sản phẩm hoặc chủ đề cho những người lần đầu tìm hiểu về nó."},"6811":{"word":"sự ồn ào, xáo động","meaning":"Tình huống ồn ào, náo nhiệt khi mọi người tạo ra nhiều tiếng động hoặc gây ra sự rối loạn."},"6812":{"word":"nổi da gà","meaning":"Hiện tượng những nốt nhỏ li ti nổi lên trên da khi sợ hãi, lạnh hoặc ghê tởm."},"6813":{"word":"bán lẻ","meaning":"Hoạt động bán hàng trực tiếp cho người tiêu dùng cuối cùng, thường với số lượng nhỏ."},"6814":{"word":"sự tiêu thụ","meaning":"Hành động sử dụng hết một thứ gì đó, như năng lượng, tài nguyên hoặc thực phẩm."},"6815":{"word":"mộc mạc, giản dị","meaning":"Tính chất đơn giản, không cầu kỳ, thể hiện sự chân thật và thẳng thắn."},"6816":{"word":"lượng tiêu thụ","meaning":"Tổng số lượng tài nguyên, sản phẩm hoặc dịch vụ được sử dụng hoặc mua."},"6817":{"word":"sự trực thuộc, trực thuộc","meaning":"Tình trạng được liên kết hoặc thuộc về một nhóm, tổ chức hay đội ngũ cụ thể nào đó."},"6818":{"word":"vụ kiện, kiện tụng","meaning":"Một tranh chấp chính thức được một người hoặc một nhóm đưa ra trước tòa án chống lại người khác."},"6819":{"word":"ăn ít, bữa ăn nhỏ","meaning":"Việc ăn uống tiết độ, với lượng thức ăn ít hoặc bữa ăn nhẹ."},"6820":{"word":"nhút nhát, rụt rè","meaning":"Tính cách dễ sợ hãi hoặc ngần ngại hành động vì thiếu dũng khí hay tự tin."},"6821":{"word":"cảm giác bị cô lập","meaning":"Cảm giác không vui khi bị bỏ rơi, không được kết nối hoặc không thuộc về một nhóm nào đó."},"6822":{"word":"chủ sở hữu","meaning":"Người có quyền sở hữu hợp pháp một thứ gì đó như tài sản, đồ vật hay động vật."},"6823":{"word":"trẻ con, người nhỏ tuổi","meaning":"Người có độ tuổi còn nhỏ, thường là trẻ em."},"6824":{"word":"vật sở hữu, bộ sưu tập","meaning":"Một tác phẩm nghệ thuật, cuốn sách hoặc vật có giá trị khác mà ai đó giữ làm tài sản cá nhân."},"6825":{"word":"vị trí, nơi tọa lạc","meaning":"Nơi cụ thể mà một thứ gì đó hoặc một người nào đó được tìm thấy hoặc tồn tại."},"6826":{"word":"năng khiếu, tài năng","meaning":"Khả năng tự nhiên hoặc khuynh hướng mạnh mẽ để làm tốt điều gì đó mà không cần nhiều nỗ lực."},"6827":{"word":"giao tiếp","meaning":"Quá trình mọi người trao đổi ý tưởng, suy nghĩ hoặc cảm xúc với nhau thông qua lời nói, cử chỉ hoặc các phương tiện khác."},"6828":{"word":"tác phẩm nhỏ, tiểu phẩm","meaning":"Một tác phẩm nghệ thuật có kích thước nhỏ hoặc một tác phẩm văn học, âm nhạc ngắn."},"6829":{"word":"xe cỡ nhỏ, xe con","meaning":"Một loại phương tiện giao thông có kích thước nhỏ."},"6830":{"word":"sơ suất, lơ là","meaning":"Khi làm một việc gì đó mà không chú ý đầy đủ, dẫn đến sai sót hoặc kết quả không tốt."},"6831":{"word":"hệ tiêu hóa","meaning":"Tập hợp các cơ quan bên trong cơ thể hoạt động cùng nhau để phân hủy thức ăn và hấp thụ chất dinh dưỡng."},"6832":{"word":"tốc độ, vận tốc","meaning":"Tốc độ di chuyển của một vật thể hoặc người trên một khoảng cách nhất định trong một khoảng thời gian."},"6833":{"word":"thì thầm, nói nhỏ","meaning":"Nói bằng giọng rất nhỏ và liên tục, để người khác không nghe thấy."},"6834":{"word":"liên tục, dồn dập","meaning":"Nhiều sự vật hoặc người xuất hiện hay xảy ra liên tiếp, cái này ngay sau cái kia."},"6835":{"word":"tiếng lóng, từ lóng","meaning":"Những từ và cụm từ không trang trọng, thường được sử dụng bởi một nhóm người cụ thể hoặc trong các cuộc trò chuyện đời thường."},"6836":{"word":"đếm ngón tay","meaning":"Dùng các ngón tay để theo dõi số lượng hoặc đánh dấu thời gian trôi qua, thường là khi háo hức mong chờ điều gì đó."},"6837":{"word":"được liệt vào hàng, được kể đến","meaning":"Được công nhận rộng rãi và được nhắc đến như một trong những ví dụ xuất sắc hoặc quan trọng nhất trong một nhóm hoặc lĩnh vực cụ thể."},"6838":{"word":"hư hại, thiệt hại, tổn thương","meaning":"Sự thay đổi vật lý hoặc tổn thương đối với một vật thể hoặc sinh vật, khiến nó kém hoàn hảo hoặc không thể sử dụng được."},"6839":{"word":"tổn thất","meaning":"Sự mất mát những thứ có giá trị như tiền bạc, tài sản hoặc cơ hội."},"6840":{"word":"cử chỉ tay","meaning":"Hành động dùng tay hoặc ngón tay để truyền đạt thông tin hay cảm xúc mà không cần nói."},"6841":{"word":"độc diễn","meaning":"Buổi biểu diễn hoặc hành động được thực hiện bởi một người duy nhất."},"6842":{"word":"bông","meaning":"Chất liệu mềm, xốp, màu trắng, được lấy từ thực vật, thường dùng làm vải hoặc miếng thấm hút."},"6843":{"word":"vọt lên","meaning":"Chất lỏng hoặc vật tương tự bắn hoặc trào lên với lực và tốc độ mạnh, thường là từ phía dưới."},"6844":{"word":"bay lên","meaning":"Di chuyển lên phía trên không trung, thường một cách nhẹ nhàng hoặc từ từ."},"6845":{"word":"chuyển tiền","meaning":"Hành động gửi tiền thông qua một tổ chức tài chính như ngân hàng."},"6846":{"word":"cuối năm","meaning":"Khoảng thời gian cuối năm hoặc các hoạt động, buổi lễ diễn ra vào thời điểm đó."},"6847":{"word":"hàng","meaning":"Tiếp đầu ngữ gắn vào đơn vị số để chỉ một số lượng lớn nhưng không xác định."},"6848":{"word":"học","meaning":"Việc ngồi trong lớp học và học các môn dưới sự hướng dẫn của giáo viên."},"6849":{"word":"phụ cấp","meaning":"Khoản tiền thêm mà một người nhận được thường xuyên để chi trả cho chi phí hoặc nhiệm vụ cụ thể."},"6850":{"word":"thủ công","meaning":"Cách vận hành máy móc hoặc hệ thống trực tiếp bằng tay và công sức con người, không có cơ chế tự động."},"6851":{"word":"sự đưa vào","meaning":"Việc một bài viết, hình ảnh hay âm nhạc được đưa vào sách, tạp chí hoặc tuyển tập."},"6852":{"word":"sự hoàn thành khóa học","meaning":"Hành động kết thúc thành công tất cả các bài học hoặc bước đào tạo của một chương trình cụ thể."},"6853":{"word":"mặt nước","meaning":"Lớp trên cùng của một khối nước như sông, hồ, biển."},"6854":{"word":"số từ","meaning":"Từ dùng để chỉ một con số cụ thể hoặc thứ tự trong ngôn ngữ."},"6855":{"word":"thủy sản","meaning":"Các loại hàng hóa hoặc tài nguyên có giá trị được đánh bắt hoặc thu hoạch trực tiếp từ biển và đại dương."},"6856":{"word":"hải sản","meaning":"Động vật và thực vật ăn được được đánh bắt từ biển hoặc đại dương và chế biến thành thức ăn."},"6857":{"word":"sự đoạt giải, sự nhận giải","meaning":"Hành động giành được hoặc được trao một giải thưởng, danh hiệu."},"6858":{"word":"thủ khoa, vị trí đứng đầu","meaning":"Vị trí hoặc thành tích cao nhất trong một lĩnh vực, cấp bậc nào đó."},"6859":{"word":"giản dị, mộc mạc","meaning":"Có vẻ ngoài, phong cách hoặc hành vi đơn giản, tự nhiên, không cầu kỳ hay phô trương."},"6860":{"word":"người nhận","meaning":"Người nhận được thư, tin nhắn, email hoặc gói hàng do người khác gửi đến."},"6861":{"word":"râu","meaning":"Lông mọc trên mặt đàn ông, có thể ở trên môi hoặc cằm và má."},"6862":{"word":"lợi nhuận, thu nhập","meaning":"Khoản tiền thu được từ công việc, kinh doanh hoặc đầu tư."},"6863":{"word":"Lợi nhuận","meaning":"Số tiền kiếm được từ hoạt động kinh doanh hoặc đầu tư."},"6864":{"word":"Sự nhút nhát","meaning":"Cảm giác lo lắng, không thoải mái khi ở gần người khác, thường khiến người ta nói nhỏ hoặc tránh giao tiếp bằng mắt."},"6865":{"word":"Hơi nước","meaning":"Dạng khí của nước bốc lên từ chất lỏng rất nóng."},"6866":{"word":"Phương thẳng đứng","meaning":"Hướng từ trên xuống dưới hoặc từ dưới lên trên, tạo một góc 90 độ với mặt đất."},"6867":{"word":"Chất lượng nước","meaning":"Tình trạng của nước, được đánh giá qua độ sạch, trong hoặc mức độ ô nhiễm."},"6868":{"word":"Việc thu thập","meaning":"Hành động tập hợp nhiều vật phẩm tương tự lại một chỗ."},"6869":{"word":"Con số","meaning":"Một lượng được biểu thị bằng con số, là kết quả của việc đo lường hoặc tính toán."},"6870":{"word":"Quy tắc","meaning":"Những hướng dẫn bằng văn bản cho biết những gì mọi người phải hoặc không được làm ở một nơi hoặc tình huống cụ thể."},"6871":{"word":"Tản văn","meaning":"Một đoạn văn ngắn trong đó tác giả chia sẻ suy nghĩ hoặc ý kiến cá nhân về một chủ đề nhất định."},"6872":{"word":"Việc học tập","meaning":"Việc theo đuổi hoặc chuyên tâm vào việc học hỏi, nghiên cứu."},"6873":{"word":"Chuyến đi thực tế","meaning":"Một chuyến đi đặc biệt dành cho học sinh và giáo viên đến một địa điểm khác, thường là để học tập hoặc giải trí."},"6874":{"word":"Thiệt hại do lũ lụt","meaning":"Sự phá hủy và hỗn loạn gây ra cho các tòa nhà, đất đai và tài sản khi một khu vực bị ngập quá nhiều nước."},"6875":{"word":"kỳ thi","meaning":"Một sự kiện chính thức để đánh giá kiến thức hoặc khả năng của một người thông qua các câu hỏi viết hoặc nói."},"6876":{"word":"thí sinh","meaning":"Người đang tham gia một kỳ thi chính thức để đánh giá kiến thức hoặc kỹ năng của mình."},"6877":{"word":"thu hoạch","meaning":"Hành động thu lượm cây trồng đã gieo và nuôi dưỡng, hoặc là các sản phẩm cây trồng đã được thu lượm."},"6878":{"word":"giấc ngủ sâu","meaning":"Một khoảng thời gian nghỉ ngơi rất yên tĩnh và bình yên, trong đó một người không dễ bị làm phiền."},"6879":{"word":"ăn ở","meaning":"Sự cung cấp cả nơi ở và thức ăn cho một người."},"6880":{"word":"sundae","meaning":"Món ăn làm bằng cách nhồi miến, đậu phụ, gạo nếp đã nêm gia vị vào ruột heo rồi hấp."},"6881":{"word":"sự thuần khiết","meaning":"Phẩm chất hoàn toàn không pha lẫn bất cứ thứ gì khác, thể hiện sự trong trẻo hoặc chân thật."},"6882":{"word":"sự tuần hoàn","meaning":"Sự luân chuyển liên tục của một cái gì đó, như chất lỏng hoặc không khí, qua một con đường hoặc hệ thống khép kín."},"6883":{"word":"người thầy","meaning":"Người dạy dỗ và đưa ra hướng dẫn để người khác phát triển."},"6884":{"word":"đèn bàn","meaning":"Một thiết bị gồm chân đế, cột đỡ và nguồn sáng, được thiết kế để chiếu sáng một khu vực cụ thể."},"6885":{"word":"nhóm học tập","meaning":"Một buổi tụ tập của các cá nhân gặp gỡ thường xuyên để cùng nhau tiếp thu kiến thức hoặc phát triển các khả năng cụ thể."},"6886":{"word":"câu chuyện","meaning":"Một bản kể về một loạt các sự kiện, có thể là thật hoặc hư cấu, được kể lại hoặc ghi chép."},"6887":{"word":"thông thái","meaning":"Có sự hiểu biết sâu sắc và sử dụng khả năng phán đoán tốt để đưa ra lựa chọn và xử lý tình huống."},"6888":{"word":"lén lút","meaning":"Hành động chậm rãi và nhẹ nhàng để người khác không biết."},"6889":{"word":"theo thói quen","meaning":"Diễn tả một hành động hoặc hành vi được thực hiện lặp đi lặp lại một cách tự động, không cần suy nghĩ nhiều."},"6890":{"word":"sự tiếp thu","meaning":"Quá trình một người phát triển hoặc đạt được một kỹ năng hoặc sự hiểu biết mới."},"6891":{"word":"sự nhặt được","meaning":"Hành động tìm thấy và nhặt một vật dụng mà người khác đã đánh rơi hoặc để quên."},"6892":{"word":"chiến thắng","meaning":"Kết quả khi một đối thủ hoặc đội đánh bại đối thủ khác, hoặc hoàn thành thành công một thử thách."},"6893":{"word":"thang máy","meaning":"Một thiết bị dạng buồng kín dùng để vận chuyển người hoặc vật lên xuống giữa các tầng trong tòa nhà."},"6894":{"word":"sân ga","meaning":"Khu vực được nâng lên cạnh đường ray hoặc đường bộ để hành khách chờ lên hoặc xuống tàu, xe buýt."},"6895":{"word":"cuộc đấu","meaning":"Sự kiện mà hai hoặc nhiều cá nhân hay đội đối đầu để xác định ai thể hiện tốt hơn."},"6896":{"word":"xe van","meaning":"Một loại xe ô tô lớn có thể chở được nhiều người."},"6897":{"word":"thị giác","meaning":"Khả năng của mắt để nhận biết ánh sáng và tạo hình ảnh về thế giới."},"6898":{"word":"thuộc về thị giác","meaning":"Mô tả bất cứ điều gì có thể được nhận thức hoặc hiểu bằng mắt."},"6899":{"word":"thuộc về thời gian","meaning":"Liên quan đến thời gian hoặc sự tuần tự theo thời gian."},"6900":{"word":"cấp bách","meaning":"Tình huống quan trọng đến mức cần phải được giải quyết ngay lập tức, không chậm trễ."},"6901":{"word":"thời cơ","meaning":"Thời điểm thích hợp hoặc cơ hội thuận lợi để làm một việc gì đó."},"6902":{"word":"ồn ào","meaning":"Có nhiều tiếng động lớn do nhiều người đang di chuyển và trò chuyện nhộn nhịp."},"6903":{"word":"kịch bản","meaning":"Bản kế hoạch viết sẵn cho một bộ phim, vở kịch hoặc chương trình truyền hình, bao gồm lời thoại, hành động và mô tả cảnh quay."},"6904":{"word":"dòng suối","meaning":"Dòng nước chảy trong một con suối nhỏ ở thung lũng hoặc đồng bằng."},"6905":{"word":"ê buốt","meaning":"Cảm thấy một cơn đau nhói, nhức nhối ở bộ phận cơ thể như răng hoặc ngón tay khi tiếp xúc với vật có nhiệt độ rất thấp."},"6906":{"word":"thành phố","meaning":"Thuộc sở hữu hoặc được điều hành bởi chính quyền quản lý một thành phố hoặc thị trấn."},"6907":{"word":"biểu diễn","meaning":"Hành động cho thấy cách vận hành hoặc cách thực hiện một công việc, thường để giải thích cho người khác."},"6908":{"word":"thời sự","meaning":"Các sự kiện quan trọng và chủ đề công cộng đang diễn ra và được thảo luận trên thế giới hiện nay."},"6909":{"word":"buổi chiếu thử","meaning":"Một sự kiện đặc biệt nơi một bộ phim hoặc chương trình truyền hình được chiếu cho một lượng khán giả nhỏ trước khi phát hành rộng rãi."},"6910":{"word":"lễ trao giải","meaning":"Một sự kiện trang trọng nơi mọi người tụ tập để trao giải thưởng, cúp hoặc chứng nhận cho những cá nhân đã đạt được thành tích đặc biệt."},"6911":{"word":"Tốc độ/Vận tốc (tính theo giờ)","meaning":"Là đơn vị đo quãng đường di chuyển trong một giờ."},"6912":{"word":"Tẻ nhạt, chán ngắt","meaning":"Không có gì thú vị, gây nhàm chán hoặc không quan trọng."},"6913":{"word":"Biểu tình, thị uy","meaning":"Hành động tập hợp đông người để thể hiện quan điểm hoặc yêu cầu điều gì đó."},"6914":{"word":"Nghe nhìn","meaning":"Liên quan đến cả âm thanh và hình ảnh, thường dùng trong giáo dục hoặc truyền thông."},"6915":{"word":"Thi thể, xác chết","meaning":"Thân xác của một người đã chết."},"6916":{"word":"Sự giả vờ không biết/không làm","meaning":"Thái độ giả vờ không biết hoặc không liên quan đến một việc gì đó mà mình thực sự biết hoặc đã làm."},"6917":{"word":"Đen kịt, đen thui","meaning":"Có màu đen rất đậm, gần như không có ánh sáng."},"6918":{"word":"-kiểu, -dạng, -cách","meaning":"Từ đứng sau danh từ để chỉ phương pháp, kiểu dáng hoặc đặc điểm của sự vật, sự việc."},"6919":{"word":"Nghi thức, buổi lễ","meaning":"Sự kiện trang trọng hoặc buổi tập hợp công khai được tổ chức cho một dịp đặc biệt."},"6920":{"word":"Cũ rích, nhàm chán, ngán","meaning":"Trở nên nhàm chán, không còn hứng thú vì đã trải nghiệm quá nhiều hoặc quá quen thuộc."},"6921":{"word":"Chế độ ăn uống, thói quen ăn uống","meaning":"Cách thức và thói quen một người tiêu thụ thức ăn và đồ uống hàng ngày."},"6922":{"word":"Khẩu vị, sở thích ăn uống","meaning":"Sở thích hoặc thói quen riêng của một người về các loại thực phẩm mà họ chọn để ăn."},"6923":{"word":"nước uống","meaning":"Nước sạch có thể uống được một cách an toàn để duy trì sự sống."},"6924":{"word":"thói quen ăn uống","meaning":"Cách thức và lựa chọn thường xuyên của một người về thời gian, loại thức ăn và cách họ dùng bữa."},"6925":{"word":"thần, chúa","meaning":"Một đấng tối cao, quyền năng hoặc linh hồn mà con người tin là kiểm soát các phần của thế giới và thường được thờ cúng."},"6926":{"word":"sự cáu kỉnh","meaning":"Trạng thái một người dễ dàng tức giận hoặc khó chịu bởi những điều nhỏ nhặt."},"6927":{"word":"đau dây thần kinh","meaning":"Tình trạng gây ra cảm giác đau nhói, bỏng rát hoặc chói ở một số bộ phận trên cơ thể."},"6928":{"word":"bài hát mới","meaning":"Một bài hát vừa được sáng tác hoặc phát hành gần đây."},"6929":{"word":"mới","meaning":"Tình trạng hoặc điều kiện của cái gì đó hoặc ai đó vừa được giới thiệu hoặc mới bắt đầu."},"6930":{"word":"kỷ lục mới","meaning":"Thành tích hoặc điểm số tốt hơn tất cả các lần trước đó, đại diện cho hiệu suất tốt nhất từng đạt được."},"6931":{"word":"thành phố mới","meaning":"Một khu vực đô thị được quy hoạch và xây dựng từ đầu, thường có các tòa nhà và cơ sở hạ tầng hiện đại, để đáp ứng dân số ngày càng tăng."},"6932":{"word":"Tân La","meaning":"Một thực thể chính trị cổ đại tồn tại trên bán đảo Triều Tiên trong nhiều thế kỷ, nổi tiếng với văn hóa và hiện vật lịch sử đặc trưng."},"6933":{"word":"sự chán ghét, sự ngán ngẩm","meaning":"Cảm giác cực kỳ chán nản hoặc ghê tởm với một điều gì đó hoặc ai đó, thường gây ra cảm giác buồn nôn."},"6934":{"word":"sự phấn khởi, hưng phấn","meaning":"Cảm giác vui vẻ và tràn đầy sức sống khiến một người làm việc hoặc hoạt động với nhiều đam mê và nghị lực."},"6935":{"word":"sự nhanh chóng","meaning":"Đây là trạng thái hoặc tính chất của việc thực hiện một hành động hoặc sự việc nào đó một cách rất nhanh chóng và không có sự chậm trễ."},"6936":{"word":"một cách nhanh chóng","meaning":"Từ này diễn tả việc làm một điều gì đó rất nhanh và không có sự chậm trễ không cần thiết."},"6937":{"word":"thuốc mới","meaning":"Đây là loại thuốc được phát minh gần đây để hỗ trợ điều trị các bệnh tật hoặc tình trạng sức khỏe."},"6938":{"word":"người mới nhậm chức","meaning":"Đây là một người vừa được giao cho một vị trí hoặc trách nhiệm chính thức."},"6939":{"word":"sự mở rộng","meaning":"Đây là quá trình một cái gì đó phát triển lớn hơn về kích thước, số lượng hoặc phạm vi."},"6940":{"word":"thận","meaning":"Đây là một trong hai cơ quan hình hạt đậu trong cơ thể có chức năng lọc máu và loại bỏ chất thải."},"6941":{"word":"một cách thận trọng","meaning":"Từ này diễn tả việc làm một điều gì đó với sự cẩn thận cao độ, suy nghĩ kỹ lưỡng trước khi hành động để tránh sai lầm hoặc rủi ro."},"6942":{"word":"kiểu mới","meaning":"Đây là phiên bản hoặc thiết kế gần đây nhất của một sản phẩm, thường có những cải tiến."},"6943":{"word":"-phòng (hậu tố)","meaning":"Hậu tố này chỉ một không gian hoặc khu vực kín bên trong một tòa nhà được sử dụng cho một chức năng cụ thể."},"6944":{"word":"phòng (đơn vị đếm)","meaning":"Từ này được dùng để chỉ đơn vị đếm các căn phòng, ví dụ như \"một phòng\", \"hai phòng\"."},"6945":{"word":"đáng thất vọng","meaning":"Từ này diễn tả việc gây ra cảm giác buồn bã hoặc thất vọng vì một điều gì đó không diễn ra như mong đợi."},"6946":{"word":"tên thật","meaning":"Đây là tên định danh hợp pháp thực tế của một người, trái ngược với biệt danh hoặc tên giả định."},"6947":{"word":"thực vụ","meaning":"Chỉ công việc hoặc nhiệm vụ thực tế cần làm, không phải lý thuyết hay kế hoạch."},"6948":{"word":"vật thật","meaning":"Là chính đối tượng vật lý thực tế, không phải hình ảnh, mô hình hay bản sao."},"6949":{"word":"thực chất","meaning":"Chỉ giá trị thực hoặc lợi ích thiết thực mà một thứ mang lại, không chỉ vẻ bên ngoài."},"6950":{"word":"thời gian thực","meaning":"Là thời điểm đồng bộ với thời gian thực tế, không có sự chậm trễ."},"6951":{"word":"hệ nghề","meaning":"Chỉ các ngành học hoặc đào tạo nghề nhằm chuẩn bị cho học sinh vào các công việc cụ thể."},"6952":{"word":"tỷ lệ thất nghiệp","meaning":"Là chỉ số phần trăm người trong độ tuổi lao động có khả năng làm việc nhưng không tìm được việc."},"6953":{"word":"người thất nghiệp","meaning":"Là người không có việc làm hoặc đã bị mất việc."},"6954":{"word":"thực dụng","meaning":"Là khía cạnh giúp một thứ có thể được sử dụng hoặc ứng dụng hiệu quả vào thực tế."},"6955":{"word":"tính thực dụng","meaning":"Là mức độ một đồ vật hay phương pháp có thể được sử dụng hiệu quả và thành công trong thực tế."},"6956":{"word":"thực tại","meaning":"Là trạng thái tồn tại thực tế của một vật hay một người trong thế giới, không phải chỉ là ý tưởng hay hư cấu."},"6957":{"word":"thành tích","meaning":"Là kết quả, thành quả hoặc hiệu suất làm việc có thể đo lường được của một cá nhân hay tổ chức."},"6958":{"word":"mất việc làm","meaning":"Là tình trạng một người bị mất việc làm, không còn được công ty hoặc tổ chức trả lương."},"6959":{"word":"lụa","meaning":"Một loại vải mềm, bóng và mịn được làm từ sợi tơ tự nhiên do một số loài sâu tạo ra, thường dùng để may quần áo."},"6960":{"word":"tình hình thực tế","meaning":"Tình trạng và sự thật đang tồn tại của một sự việc, thường trái ngược với điều đã biết hoặc tuyên bố."},"6961":{"word":"thực thi","meaning":"Hành động thực hiện một kế hoạch, mệnh lệnh hoặc ý định để biến nó thành hiện thực."},"6962":{"word":"chuyện có thật","meaning":"Một câu chuyện dựa trên những sự kiện đã thực sự xảy ra trong đời sống, không phải là hư cấu."},"6963":{"word":"tính nghiêm trọng","meaning":"Mức độ quan trọng hoặc nguy hiểm của một vấn đề, tình huống cần được chú ý đặc biệt."},"6964":{"word":"suy xét kỹ lưỡng","meaning":"Hành động suy nghĩ, xem xét cẩn thận và sâu sắc về mọi khía cạnh của một vấn đề trước khi đưa ra quyết định."},"6965":{"word":"khó tính, hằn học","meaning":"Có vẻ mặt không vui và thường có hành vi muốn gây khó dễ hoặc làm hại người khác một chút."},"6966":{"word":"thể xác và tinh thần","meaning":"Toàn bộ một con người, bao gồm cả cơ thể và tâm trí, cảm xúc bên trong."},"6967":{"word":"đêm khuya","meaning":"Khoảng thời gian rất muộn vào ban đêm, khi hầu hết mọi người đã ngủ."},"6968":{"word":"thập tự giá","meaning":"Một biểu tượng hoặc vật thể có hình dạng hai đường thẳng hoặc hai thanh gỗ giao nhau vuông góc."},"6969":{"word":"chín phần mười, khả năng cao","meaning":"Diễn tả một sự việc có khả năng xảy ra rất cao, gần như chắc chắn, chỉ có rất ít ngoại lệ."},"6970":{"word":"ba hoa, buôn chuyện","meaning":"Có thói quen nói ra những bí mật hoặc thông tin không nên tiết lộ một cách dễ dàng, không kín đáo."},"6971":{"word":"mầm, chồi","meaning":"Lá hoặc thân mới nhú ra lần đầu từ hạt hoặc thân cây."},"6972":{"word":"mí mắt đôi","meaning":"Nếp da có thể nhìn thấy ở phần trên của mắt, tạo thành một đường rõ rệt phía trên lông mi."},"6973":{"word":"xe trượt tuyết","meaning":"Phương tiện có ván trượt, dùng để trượt trên tuyết hoặc băng, thường được kéo hoặc dùng để trượt dốc."},"6974":{"word":"nước rút, thủy triều xuống","meaning":"Hiện tượng mực nước biển xuống mức thấp nhất, để lộ ra nhiều bờ biển hơn."},"6975":{"word":"lườm, nhìn trừng trừng","meaning":"Nhìn ai đó với ánh mắt cứng rắn, giận dữ và không rời."},"6976":{"word":"thỏm, lọt thỏm","meaning":"Từ dùng để tả sự vật lún sâu vào bên trong hoặc vừa vặn hoàn toàn vào một chỗ."},"6977":{"word":"nhanh như tên bắn","meaning":"Di chuyển hoặc trôi qua với tốc độ cực nhanh, giống như mũi tên bay đi."},"6978":{"word":"chọc, ngoáy","meaning":"Dùng que, vật nhọn để xuyên qua hoặc đào bới cái gì đó."},"6979":{"word":"đánh gục, làm đổ","meaning":"Làm cho ai đó hoặc vật gì đó đang đứng thẳng đột ngột rơi xuống đất."},"6980":{"word":"nhức nhối, đau rát","meaning":"Cảm thấy một cơn đau nhói, bỏng rát và khó chịu, đặc biệt ở vết thương hoặc phần nhạy cảm của cơ thể."},"6981":{"word":"sự hữu ích, công dụng","meaning":"Phẩm chất của một vật hoặc hành động giúp đạt được mục tiêu hoặc thực hiện một chức năng nào đó."},"6982":{"word":"thói quen chi tiêu","meaning":"Cách thức thường xuyên một người sử dụng tiền của mình để thanh toán cho các khoản chi."},"6983":{"word":"thở phì phò","meaning":"Phát ra tiếng thở mạnh và gấp gáp qua mũi và miệng, thường do tức giận hoặc rất mệt mỏi."},"6984":{"word":"xinh xắn, hài hòa","meaning":"Các vật nhỏ được sắp xếp tinh xảo, hài hòa và trông đáng yêu."},"6985":{"word":"cận nhiệt đới","meaning":"Khu vực địa lý hoặc kiểu khí hậu nằm gần các vùng trung tâm rất nóng của Trái Đất nhưng không nóng bằng."},"6986":{"word":"ID, tên đăng nhập","meaning":"Một tên hoặc mã cụ thể dùng để nhận dạng duy nhất một người hoặc tài khoản họ đang sử dụng, đặc biệt trên hệ thống máy tính."},"6987":{"word":"chập chững","meaning":"Từ diễn tả cách đi của trẻ nhỏ hoặc con vật non, đi chậm rãi, nhẹ nhàng và lắc lư người qua lại."},"6988":{"word":"chín ngày","meaning":"Khoảng thời gian kéo dài chính xác bằng chín lần mặt trời mọc và lặn."},"6989":{"word":"cái ác, sự ác","meaning":"Một thế lực hoặc phẩm chất gây ra sự đau khổ, hủy hoại hoặc bất hạnh sâu sắc cho con người hoặc vạn vật."},"6990":{"word":"ác quỷ, ma quỷ","meaning":"Một linh hồn ma quỷ thần thoại, thường được miêu tả có sừng, đuôi và da đỏ, cám dỗ con người làm điều xấu."},"6991":{"word":"vòng luẩn quẩn, vòng tuần hoàn ác tính","meaning":"Một chuỗi các sự kiện tiêu cực lặp đi lặp lại, trong đó mỗi kết quả xấu lại càng khiến kết quả xấu tiếp theo dễ xảy ra hơn."},"6992":{"word":"ảnh hưởng xấu, tác động tiêu cực","meaning":"Một hiệu ứng hoặc kết quả có hại mà một điều này gây ra cho điều khác, khiến nó trở nên tồi tệ hơn."},"6993":{"word":"lạm dụng, lợi dụng","meaning":"Sử dụng một cái gì đó sai cách hoặc không công bằng, thường là vì lợi ích cá nhân ích kỷ của mình."},"6994":{"word":"ác ý, lòng ác","meaning":"Một tấm lòng độc ác, muốn làm hại người khác."},"6995":{"word":"đề xuất","meaning":"Một ý kiến hoặc kế hoạch được đưa ra để mọi người xem xét, thảo luận và có thể chấp nhận."},"6996":{"word":"sự an tâm","meaning":"Cảm giác bình yên hoặc vui mừng khi một tình huống khó khăn hay đáng lo ngại cuối cùng kết thúc hoặc tốt đẹp hơn."},"6997":{"word":"sự phù hợp hoàn hảo","meaning":"Một thứ gì đó hoàn toàn khớp với nhu cầu hoặc tình huống, như thể được làm riêng cho nó."},"6998":{"word":"dây an toàn","meaning":"Một sợi dây đai buộc ngang người trong xe hoặc máy bay để giữ chặt cơ thể."},"6999":{"word":"cảm giác ổn định","meaning":"Cảm giác mọi thứ vững vàng, chắc chắn và ít có khả năng thay đổi gây ra vấn đề."},"7000":{"word":"ổn định","meaning":"Diễn tả thứ gì đó vững chắc, đều đặn và ít có khả năng đổ vỡ hoặc thay đổi đột ngột."},"7001":{"word":"sự tiết kiệm","meaning":"Phẩm chất cẩn thận và tiết kiệm tiền bạc, tài nguyên, tránh lãng phí."},"7002":{"word":"cơ thể trần truồng","meaning":"Thân thể không mặc bất kỳ quần áo nào."},"7003":{"word":"nhận ra","meaning":"Trở nên ý thức về một điều gì đó trước đây bị che giấu hoặc không biết đến."},"7004":{"word":"tính kiềm","meaning":"Chỉ một chất có độ pH lớn hơn 7, thường có cảm giác xà phòng khi chạm vào."},"7005":{"word":"vách đá","meaning":"Một tảng đá cao và dốc, trông giống như một bức tường."},"7006":{"word":"vượt qua","meaning":"Di chuyển nhanh hơn người hoặc vật phía trước, vượt qua họ để dẫn trước."},"7007":{"word":"nét đáng yêu","meaning":"Hành động hoặc cử chỉ dễ thương, thu hút sự chú ý và tình cảm của người khác."},"7008":{"word":"lòng yêu nước","meaning":"Tình cảm yêu mến, ủng hộ mạnh mẽ đất nước và con người của mình."},"7009":{"word":"phim hoạt hình","meaning":"Một loạt các hình ảnh, bản vẽ hoặc đồ họa máy tính được trình chiếu nhanh chóng để tạo ảo giác chuyển động, thường dùng để kể chuyện."},"7010":{"word":"mơ hồ, không rõ ràng","meaning":"Khó hiểu hoặc có nhiều hơn một nghĩa, khiến việc quyết định hay nhận biết điều gì đó trở nên khó khăn."},"7011":{"word":"thú cưng","meaning":"Dùng để chỉ động vật như chó hoặc mèo được nuôi trong nhà để bầu bạn và giải trí."},"7012":{"word":"chó cưng","meaning":"Một loài động vật có lông, có đuôi và biết sủa, được nuôi trong nhà để bầu bạn và làm vui."},"7013":{"word":"sự ưa chuộng sử dụng","meaning":"Hành động kiên trì lựa chọn và sử dụng một sản phẩm hoặc vật phẩm cụ thể vì nó được ưu tiên hơn những thứ khác."},"7014":{"word":"biệt danh, tên thân mật","meaning":"Một cái tên đặc biệt, thường ngắn hơn hoặc thân mật hơn, được người thân cận đặt cho một người hoặc vật thay vì tên chính thức của họ."},"7015":{"word":"nóng lòng, lo lắng bồn chồn","meaning":"Cảm thấy bứt rứt hoặc lo lắng sâu sắc về điều gì đó có thể xảy ra, thường khiến một người không yên hoặc tỏ rõ sự phiền muộn."},"7016":{"word":"-lượng","meaning":"Hậu tố thêm vào cuối một từ để chỉ tổng số lượng hoặc số tiền liên quan đến từ đó."},"7017":{"word":"chất lỏng","meaning":"Một chất dễ chảy, chiếm hình dạng của vật chứa nó, và không phải là chất rắn hay chất khí, ví dụ như nước hoặc nước ép."},"7018":{"word":"mắng mỏ, la mắng","meaning":"Nói với ai đó, đặc biệt là trẻ em, một cách giận dữ hoặc gay gắt vì họ đã làm điều gì sai, thường là với giọng điệu cao."},"7019":{"word":"tháo vát","meaning":"Có khả năng làm việc gì đó một cách khéo léo, hiệu quả và cẩn thận, thường thể hiện sự quyết đoán."},"7020":{"word":"hoang dã","meaning":"Trạng thái của động vật hoặc thực vật sống và phát triển tự nhiên trong môi trường của chúng, không bị con người nuôi dưỡng hay kiểm soát."},"7021":{"word":"cắm trại","meaning":"Hoạt động nghỉ lại qua đêm hoặc nhiều ngày ngoài trời, thường là trong lều, để thư giãn hoặc huấn luyện."},"7022":{"word":"buổi dã ngoại","meaning":"Một hoạt động ăn uống ngoài trời, mọi người mang đồ ăn đến và thưởng thức trong công viên hoặc vùng quê."},"7023":{"word":"người yếu thế","meaning":"Người hoặc nhóm người không có sức mạnh, quyền lực, tiền bạc hay tài nguyên bằng những người khác."},"7024":{"word":"suy yếu","meaning":"Quá trình làm cho một cái gì đó trở nên kém mạnh mẽ, hiệu quả hoặc quyền lực hơn trước."},"7025":{"word":"dược hiệu","meaning":"Sự cải thiện rõ rệt về sức khỏe của một người sau khi sử dụng một loại thuốc nhất định."},"7026":{"word":"đáng ghét","meaning":"Miêu tả hành vi của một người khiến người khác cảm thấy rất khó chịu hoặc gây ra sự không thích mạnh mẽ."},"7027":{"word":"cô","meaning":"Từ dùng để gọi một người phụ nữ trẻ chưa kết hôn một cách lịch sự hoặc để chỉ con gái."},"7028":{"word":"hai bên gia đình","meaning":"Chỉ hai gia đình có liên quan đến nhau, đặc biệt là gia đình của cô dâu và chú rể."},"7029":{"word":"viện dưỡng lão","meaning":"Một cơ sở chuyên biệt nơi người cao tuổi cần sự giúp đỡ trong các hoạt động hàng ngày được sống và nhận sự chăm sóc liên tục."},"7030":{"word":"Yangban","meaning":"Thành viên của tầng lớp xã hội cao nhất trong xã hội truyền thống Triều Tiên, thường là những người đàn ông có học thức phục vụ trong chính phủ."},"7031":{"word":"hai tay","meaning":"Nghĩa là hai bàn tay của một người, thường dùng để cầm nắm, mang vác hoặc ra hiệu."},"7032":{"word":"lương thực","meaning":"Là đồ ăn thức uống cần thiết để duy trì sự sống."},"7033":{"word":"nuôi dưỡng","meaning":"Là việc chăm sóc, cung cấp thức ăn, giáo dục và bảo vệ con cái hoặc động vật non cho đến khi chúng trưởng thành."},"7034":{"word":"nến","meaning":"Vật có sợi bấc ở giữa, khi đốt cháy sẽ tan chảy sáp và phát ra ánh sáng."},"7035":{"word":"đánh răng","meaning":"Hành động dùng bàn chải và kem để làm sạch răng và loại bỏ thức ăn trong miệng."},"7036":{"word":"sự thông cảm","meaning":"Là hành động chấp nhận hoặc tán thành tình huống hay yêu cầu của người khác."},"7037":{"word":"thân từ","meaning":"Trong một từ biến đổi hình thái, nó là phần cơ bản không thay đổi, các yếu tố khác được thêm vào sau nó."},"7038":{"word":"mờ tối","meaning":"Mô tả cảnh vật hoặc khu vực mà ánh sáng tự nhiên đang dần mất đi, khiến các vật thể trở nên không rõ ràng nhưng chưa hoàn toàn chìm vào bóng tối."},"7039":{"word":"vuốt ve","meaning":"Là dùng tay chạm và lướt nhẹ nhàng qua một cái gì đó."},"7040":{"word":"nhà trẻ","meaning":"Là một cơ sở chuyên biệt nơi trẻ nhỏ được trông nom, vui chơi và học tập trong ngày khi cha mẹ bận rộn."},"7041":{"word":"mẹ","meaning":"Từ dùng để gọi hoặc chỉ người phụ nữ đã có con."},"7042":{"word":"đuôi từ","meaning":"Trong một từ biến đổi, đây là phần thay đổi được gắn vào cuối gốc từ để thể hiện các chức năng ngữ pháp khác nhau."},"7043":{"word":"Trật tự từ","meaning":"Cách sắp xếp các đơn vị ngôn ngữ để tạo thành một câu hoàn chỉnh và có nghĩa."},"7044":{"word":"Ngư nghiệp","meaning":"Ngành kinh doanh hoặc hoạt động đánh bắt hải sản từ biển hoặc hồ để tiêu thụ hoặc bán."},"7045":{"word":"Hòa quyện","meaning":"Các yếu tố khác nhau kết hợp và hài hòa, tạo thành một tổng thể thống nhất."},"7046":{"word":"Từ nguyên","meaning":"Điểm khởi đầu hoặc dạng sớm nhất của một từ, thể hiện cách nghĩa và hình dạng của nó thay đổi theo thời gian."},"7047":{"word":"Ngớ ngẩn, khó tin","meaning":"Cảm thấy quá sốc hoặc ngạc nhiên trước điều gì đó vô lý đến mức không thể nói hoặc phản ứng được."},"7048":{"word":"Bày bừa, làm bừa bộn","meaning":"Khiến một không gian trở nên lộn xộn bằng cách vứt đồ vật lung tung."},"7049":{"word":"Làm sao, cách nào","meaning":"Từ dùng để hỏi hoặc diễn tả cách thức, quá trình một sự việc diễn ra hoặc một hành động được thực hiện."},"7050":{"word":"-giá, -trị (hậu tố)","meaning":"Hậu tố dùng để chỉ giá trị tương đương hoặc số tiền của một vật nào đó."},"7051":{"word":"Ngôn ngữ học","meaning":"Môn học nghiên cứu về hệ thống giao tiếp của con người, các quy tắc, sự phát triển và cách con người sử dụng chúng."},"7052":{"word":"Kìm nén, kiềm chế","meaning":"Ngăn chặn một cảm xúc, suy nghĩ hoặc hành động bộc lộ ra bên ngoài, thường bằng nỗ lực bên trong."},"7053":{"word":"Sự kìm nén, sự kiềm chế","meaning":"Hành động ngăn chặn hoặc giữ không cho điều gì đó phát triển, biểu hiện ra hoặc trở nên rõ ràng."},"7054":{"word":"Nhà báo","meaning":"Người chuyên nghiệp thu thập thông tin và báo cáo cho công chúng thông qua báo chí, truyền hình, đài phát thanh hoặc trang web."},"7055":{"word":"khó chịu, không hài lòng","meaning":"Cảm thấy có chút bực bội hoặc không vừa ý, thường biểu hiện qua nét mặt cau có."},"7056":{"word":"được đặt lên, được để lên","meaning":"Để một vật nào đó được đặt lên trên một vật khác."},"7057":{"word":"đóng băng, đông cứng","meaning":"Chất lỏng hoặc vật có độ ẩm bị đông cứng lại thành đá do không khí lạnh."},"7058":{"word":"bị vướng vào, bị rối vào","meaning":"Dây hoặc sợi bị xoắn và đan xen vào nhau khiến khó gỡ ra hoặc tách rời."},"7059":{"word":"nghiêm khắc, chặt chẽ","meaning":"Một cách rất kiên quyết, tuân thủ đúng các quy tắc và không cho phép ngoại lệ hay sai lệch."},"7060":{"word":"sự làm quá, sự rên la (khi không đau nhiều)","meaning":"Hành động làm quá lên nỗi đau, khó khăn hoặc sự khổ sở, không đúng với thực tế."},"7061":{"word":"ngón tay cái","meaning":"Ngón tay to và ngắn nhất trên bàn tay người, có thể cử động tách biệt khỏi bốn ngón còn lại."},"7062":{"word":"cực kỳ, rất, vô cùng","meaning":"Ở một mức độ hoặc phạm vi rất lớn, làm cho cái gì đó có vẻ lớn hơn hoặc dữ dội hơn bình thường."},"7063":{"word":"nghiêm khắc, nghiêm ngặt","meaning":"Rất kiên quyết và yêu cầu phải tuân thủ đúng các quy tắc, không cho phép sai lệch hay nới lỏng."},"7064":{"word":"-nghiệp (hậu tố)","meaning":"Hậu tố dùng để chỉ một loại hình kinh doanh hoặc lĩnh vực hoạt động thương mại cụ thể."},"7065":{"word":"oa oa, hu hu (tiếng khóc lớn)","meaning":"Âm thanh hoặc cách khóc với tiếng kêu lớn, không kiểm soát và nước mắt tuôn trào."},"7066":{"word":"thể dục nhịp điệu, aerobics","meaning":"Một chương trình tập luyện thể chất mạnh mẽ với các động tác nhịp nhàng, thường được thực hiện theo nhạc để tăng cường cơ thể và tim mạch."},"7067":{"word":"tám ngày","meaning":"Khoảng thời gian kéo dài tám ngày."},"7068":{"word":"về nhiều mặt","meaning":"Xét từ nhiều khía cạnh, góc độ hoặc phương pháp khác nhau của một tình huống hoặc chủ đề."},"7069":{"word":"dư luận","meaning":"Những suy nghĩ, niềm tin hoặc quan điểm chung của một số lượng lớn người về một chủ đề hoặc vấn đề cụ thể."},"7070":{"word":"bà","meaning":"Danh xưng lịch sự dùng trước hoặc sau tên của một người phụ nữ để thể hiện sự tôn trọng."},"7071":{"word":"cáo","meaning":"Một loài động vật tương tự chó nhưng thân hình thon gọn, có bộ lông màu nâu vàng hoặc nâu đỏ, mõm dài nhọn và đuôi dài, rậm."},"7072":{"word":"vẫn như cũ","meaning":"Tiếp tục ở trạng thái hoặc điều kiện giống như trước, không thay đổi hoặc khác biệt theo thời gian."},"7073":{"word":"hành trình","meaning":"Một chuyến đi hoặc một chuyến đi dài, thường có kế hoạch chi tiết về các địa điểm ghé thăm và thời gian di chuyển."},"7074":{"word":"cho đến bây giờ","meaning":"Cho đến thời điểm hiện tại, tiếp tục từ một điểm trước đó."},"7075":{"word":"vai trò","meaning":"Vị trí hoặc chức năng mà một người hoặc một vật đảm nhận trong một sự việc hay hoạt động nào đó."},"7076":{"word":"được kết nối","meaning":"Các bộ phận hoặc yếu tố khác nhau được liên kết với nhau, hoặc được tập hợp và sắp xếp thành một tác phẩm hoàn chỉnh."},"7077":{"word":"diều","meaning":"Một khung nhẹ được phủ bằng giấy hoặc vải, thường có hình kim cương, bay cao trên không khi được kéo bằng một sợi dây dài."},"7078":{"word":"lương hưu","meaning":"Khoản tiền được trả đều đặn cho người đã ngừng làm việc, thường từ chính phủ hoặc người sử dụng lao động cũ."},"7079":{"word":"thả diều","meaning":"Hoạt động giữ một sợi dây dài gắn vào một vật nhẹ và làm cho nó bay cao trên không trung."},"7080":{"word":"sự liên đới","meaning":"Hành động nhiều người cùng làm việc hoặc cùng chịu trách nhiệm."},"7081":{"word":"nhóm tuổi","meaning":"Một nhóm người có cùng độ tuổi hoặc tuổi tương tự nhau."},"7082":{"word":"dịp cuối năm đầu năm","meaning":"Thời gian đặc biệt khoảng cuối tháng Mười Hai và đầu tháng Một, thường có các hoạt động lễ hội và nghỉ ngơi."},"7083":{"word":"liên tưởng","meaning":"Hành động một ý nghĩ, hình ảnh hoặc ký ức gợi nhớ một ý nghĩ, hình ảnh hoặc ký ức khác."},"7084":{"word":"đào tạo","meaning":"Một chương trình có cấu trúc giúp mọi người học hỏi và thực hành kiến thức hoặc kỹ năng mới cho một công việc hoặc mục đích cụ thể."},"7085":{"word":"nghệ thuật biểu diễn","meaning":"Hành động hát, nhảy múa, hoặc biểu diễn trước đông người; hoặc tài năng như vậy."},"7086":{"word":"liên tục","meaning":"Trong nhiều ngày liên tiếp, không ngừng nghỉ."},"7087":{"word":"nhạc công","meaning":"Người tạo ra âm thanh bằng nhạc cụ, thường biểu diễn trước khán giả trên sân khấu."},"7088":{"word":"quanh năm","meaning":"Xảy ra hoặc kéo dài suốt các tháng, từ đầu tháng Một đến cuối tháng Mười Hai."},"7089":{"word":"trung bình hàng năm","meaning":"Một giá trị số biểu thị lượng hoặc tỷ lệ điển hình được đo trong suốt một năm dương lịch."},"7090":{"word":"người nhỏ tuổi hơn","meaning":"Đặc điểm của một người có số tuổi ít hơn so với một người khác."},"7091":{"word":"hàng","meaning":"Một dãy người hoặc vật được sắp xếp theo một đường thẳng."},"7092":{"word":"nhiệt đới","meaning":"Vùng khí hậu nóng ẩm quanh năm, gần đường xích đạo của Trái Đất."},"7093":{"word":"đêm nhiệt đới","meaning":"Hiện tượng đêm mà nhiệt độ không khí không giảm xuống dưới 25 độ C, gây khó chịu cho con người."},"7094":{"word":"mặc cảm tự ti","meaning":"Cảm giác mạnh mẽ cho rằng mình không bằng hoặc không có khả năng như người khác, thường gây ra sự bất an."},"7095":{"word":"phòng đọc sách","meaning":"Một khu vực yên tĩnh trong thư viện hoặc tòa nhà tương tự nơi mọi người ngồi học hoặc đọc tài liệu."},"7096":{"word":"calo","meaning":"Đơn vị năng lượng được giải phóng từ thức ăn, giúp cơ thể hoạt động và di chuyển."},"7097":{"word":"nhiệt liệt","meaning":"Thể hiện sự ủng hộ hoặc nhiệt tình rất mạnh mẽ và đầy đam mê đối với điều gì đó hoặc ai đó."},"7098":{"word":"sự nhiệt tình","meaning":"Cảm giác quan tâm và năng lượng mạnh mẽ thể hiện đối với một hoạt động, ý tưởng hoặc người cụ thể."},"7099":{"word":"nhiệt huyết","meaning":"Một động lực nội tại mạnh mẽ hoặc sự quan tâm sâu sắc khiến một người tận tâm và khao khát làm điều gì đó."},"7100":{"word":"dê","meaning":"Một loài động vật nuôi có sừng, nhỏ hơn bò và có nhiều màu sắc khác nhau."},"7101":{"word":"sáu ngày","meaning":"Khoảng thời gian kéo dài tổng cộng một trăm bốn mươi bốn giờ."},"7102":{"word":"giá trị dinh dưỡng","meaning":"Lượng chất lành mạnh có trong thực phẩm giúp cơ thể con người phát triển và khỏe mạnh."},"7103":{"word":"dưỡng chất","meaning":"Những chất cần thiết cho cơ thể phát triển và duy trì sự sống, có trong thức ăn."},"7104":{"word":"liên hoan phim","meaning":"Sự kiện trình chiếu nhiều bộ phim trong một thời gian nhất định và trao các giải thưởng."},"7105":{"word":"hông, sườn","meaning":"Phần mềm của cơ thể người hoặc động vật nằm giữa xương sườn và hông, dưới cánh tay."},"7106":{"word":"năm thường lệ","meaning":"Năm điển hình hoặc bình thường được dùng làm điểm tham chiếu để so sánh các điều kiện hoặc sự kiện hiện tại."},"7107":{"word":"chương trình giải trí","meaning":"Các chương trình truyền hình như tạp kỹ hoặc thực tế được thiết kế để mang lại niềm vui cho khán giả."},"7108":{"word":"câu ví dụ","meaning":"Một câu văn được cung cấp để minh họa cách sử dụng đúng một từ hoặc cấu trúc ngữ pháp cụ thể."},"7109":{"word":"quà cưới, lễ vật","meaning":"Vật phẩm đặc biệt, thường là trang sức hoặc vật đắt tiền, mà một cặp đôi trao cho nhau trong lễ cưới."},"7110":{"word":"nhạy cảm","meaning":"Rất nhanh nhạy và nổi bật trong việc cảm nhận, phân tích hoặc đánh giá điều gì đó."},"7111":{"word":"tác phẩm nghệ thuật","meaning":"Một vật thể như tranh vẽ, tác phẩm điêu khắc hoặc đồ thủ công được con người tạo ra để đẹp hoặc thể hiện ý tưởng."},"7112":{"word":"ví dụ minh họa","meaning":"Một trường hợp, vật hoặc tình huống cụ thể được chỉ ra để giải thích rõ ràng hơn một ý tưởng, quy tắc hoặc khái niệm chung."},"7113":{"word":"lời tiên tri, dự đoán","meaning":"Hành động nói về một sự kiện trong tương lai dựa trên kiến thức hoặc suy đoán, hoặc lời nói đó."},"7114":{"word":"ngoại lệ, đặc biệt","meaning":"Mang tính chất rất bất thường, khác biệt so với những gì thường xảy ra."},"7115":{"word":"ngày xưa","meaning":"Khoảng thời gian đã trôi qua, không phải bây giờ."},"7116":{"word":"ngày dự kiến","meaning":"Ngày hoặc thời điểm đã được định sẵn cho một sự kiện hoặc hành động nào đó."},"7117":{"word":"câu nói cổ","meaning":"Một câu nói hoặc lời khuyên đã được truyền lại từ xa xưa, chứa đựng kinh nghiệm sống."},"7118":{"word":"anh em (trai gái)","meaning":"Hai anh chị em ruột, một trai một gái."},"7119":{"word":"âm thanh","meaning":"Âm thanh được tạo ra bởi thiết bị điện tử, có thể nghe được qua loa hoặc tai nghe."},"7120":{"word":"kéo dài","meaning":"Tiếp tục trong một khoảng thời gian dài đáng kể mà không kết thúc hay dừng lại nhanh chóng."},"7121":{"word":"lỗi","meaning":"Một nhận định hoặc kiến thức không chính xác."},"7122":{"word":"xu hướng tăng","meaning":"Một mô hình ổn định cho thấy giá trị hoặc số lượng tăng lên theo thời gian."},"7123":{"word":"cắt (ra)","meaning":"Tách một hình dạng hoặc mảnh cụ thể ra khỏi vật liệu lớn hơn, thường bằng kéo."},"7124":{"word":"đủ loại","meaning":"Nhiều loại hoặc đủ mọi thứ."},"7125":{"word":"nước tiểu","meaning":"Chất lỏng màu vàng nhạt thải ra khỏi cơ thể qua bàng quang."},"7126":{"word":"dàn nhạc giao hưởng","meaning":"Một nhóm lớn người cùng chơi nhiều loại nhạc cụ khác nhau, thường biểu diễn trên sân khấu."},"7127":{"word":"sự nóng lên","meaning":"Hiện tượng nhiệt độ trung bình của khí quyển và đại dương trên Trái Đất dần tăng cao."},"7128":{"word":"ôn đới","meaning":"Vùng địa lý trên Trái Đất có khí hậu ôn hòa, không quá nóng hay quá lạnh, với bốn mùa rõ rệt."},"7129":{"word":"ondol","meaning":"Hệ thống sưởi sàn truyền thống của Hàn Quốc, làm ấm bằng cách cho khí nóng hoặc nước nóng chảy bên dưới sàn nhà."},"7130":{"word":"nước nóng","meaning":"Nước đã được làm ấm, dùng để tắm rửa hoặc giặt giũ."},"7131":{"word":"toàn vẹn","meaning":"Ở trạng thái đầy đủ, không thiếu sót, không hư hại hay mất mát."},"7132":{"word":"ôn hòa","meaning":"(Thời tiết) không quá khắc nghiệt, hoặc (tính cách con người) hiền lành, dịu dàng."},"7133":{"word":"vải","meaning":"Vật liệu được dệt hoặc đan từ sợi, dùng để may quần áo, chăn màn."},"7134":{"word":"gián tiếp, uyển chuyển","meaning":"(Cách diễn đạt) nhẹ nhàng, vòng vo để tránh nói thẳng hoặc gây khó chịu."},"7135":{"word":"hoàn công","meaning":"Trạng thái một công trình xây dựng đã được hoàn thành hoàn toàn và sẵn sàng đưa vào sử dụng."},"7136":{"word":"hoàn thành","meaning":"Thời điểm một nhiệm vụ, dự án hoặc quá trình đã đến hồi kết và mọi thứ đã xong."},"7137":{"word":"độ hoàn thiện","meaning":"Mức độ một sản phẩm, tác phẩm được hoàn thành tốt hay hoàn hảo, thể hiện chất lượng và sự sẵn sàng của nó."},"7138":{"word":"chữa khỏi hoàn toàn","meaning":"Trạng thái một người bệnh trở nên hoàn toàn khỏe mạnh trở lại, không còn bệnh tật gì nữa."},"7139":{"word":"sự bình phục hoàn toàn","meaning":"Trạng thái sức khỏe của người bệnh hoặc bị thương phục hồi hoàn toàn."},"7140":{"word":"người bị tẩy chay","meaning":"Người bị một nhóm người cố ý phớt lờ, loại trừ hoặc đối xử tệ bạc."},"7141":{"word":"sự qua lại","meaning":"Việc mọi người thường xuyên đi lại giữa hai nơi hoặc thăm hỏi lẫn nhau."},"7142":{"word":"hoàng tử","meaning":"Con trai của vua hoặc nữ hoàng, hoặc người đứng đầu một quốc gia nhỏ."},"7143":{"word":"con gái một","meaning":"Con gái duy nhất không có anh chị em nào khác."},"7144":{"word":"con trai một","meaning":"Con trai duy nhất không có anh chị em nào khác."},"7145":{"word":"ngoại lai","meaning":"Chỉ những thứ có nguồn gốc từ nước ngoài, không phải địa phương."},"7146":{"word":"từ mượn","meaning":"Từ ngữ được vay mượn và sử dụng từ một ngôn ngữ khác."},"7147":{"word":"ngoại giao","meaning":"Các vấn đề và công việc liên quan đến quan hệ của một quốc gia với các nước khác trên thế giới."},"7148":{"word":"chi phí ăn ngoài","meaning":"Chi phí chi trả cho việc ăn uống tại nhà hàng, quán cà phê thay vì tự nấu ở nhà."},"7149":{"word":"vẻ bề ngoài","meaning":"Hình dáng, màu sắc và các đặc điểm nhìn thấy được từ bên ngoài của một người hay vật."},"7150":{"word":"hướng ngoại","meaning":"Chỉ người có tính cách thích giao tiếp, nói nhiều và dễ dàng bộc lộ suy nghĩ, cảm xúc."},"7151":{"word":"ngoại tệ","meaning":"Đây là tiền của một quốc gia khác được sử dụng trong giao dịch quốc tế."},"7152":{"word":"bí quyết","meaning":"Cách làm một việc gì đó một cách hiệu quả và khéo léo."},"7153":{"word":"đặc vụ","meaning":"Người thực hiện các nhiệm vụ đặc biệt hoặc bí mật cho một tổ chức hay chính phủ."},"7154":{"word":"nhu cầu","meaning":"Cảm giác mạnh mẽ muốn có được hoặc cần phải có điều gì đó."},"7155":{"word":"lời chửi rủa","meaning":"Những lời lẽ giận dữ, thô tục và xúc phạm dùng để nói với người khác."},"7156":{"word":"đồ đựng","meaning":"Một vật dùng để chứa đựng cái gì đó bên trong."},"7157":{"word":"dung lượng","meaning":"Lượng tối đa mà một vật chứa, không gian hoặc thiết bị kỹ thuật số có thể chứa hoặc lưu trữ."},"7158":{"word":"giấy","meaning":"Vật liệu mỏng, phẳng dùng để viết, in hoặc vẽ lên."},"7159":{"word":"mùa mưa","meaning":"Khoảng thời gian trong năm có lượng mưa lớn và kéo dài."},"7160":{"word":"ưu đãi","meaning":"Việc một người hoặc nhóm người nhận được các điều kiện hoặc lợi ích tốt hơn so với người khác."},"7161":{"word":"ngây người","meaning":"Ở trạng thái đứng hoặc nhìn mà không cử động hay biểu lộ suy nghĩ, phản ứng."},"7162":{"word":"chất lượng cao","meaning":"Miêu tả một thứ có tiêu chuẩn rất tốt, thường khỏe mạnh, thuần khiết hoặc hoạt động hiệu quả."},"7163":{"word":"ùa ra, ùn ùn","meaning":"Diễn tả nhiều người hoặc vật cùng lúc di chuyển nhanh và ồn ào."},"7164":{"word":"sự ưu tiên","meaning":"Hành động chọn một điều gì đó là quan trọng nhất và tập trung vào nó hơn những điều khác."},"7165":{"word":"sự xuất sắc, sự ưu tú","meaning":"Trạng thái cực kỳ tốt hoặc có chất lượng rất cao, thường dễ nhận thấy."},"7166":{"word":"bệnh trầm cảm","meaning":"Một tình trạng y tế nghiêm trọng khiến người bệnh cảm thấy rất buồn bã, vô vọng và ít năng lượng trong thời gian dài."},"7167":{"word":"sự do dự, sự thiếu quyết đoán","meaning":"Thói quen không thể đưa ra quyết định nhanh chóng hoặc dứt khoát, thường xuyên thay đổi ý định."},"7168":{"word":"định mệnh, mang tính định mệnh","meaning":"Diễn tả một sự kiện hay cuộc gặp gỡ cảm giác như đã được định trước và sẽ có tác động rất quan trọng đến tương lai."},"7169":{"word":"vận chuyển, sự vận chuyển","meaning":"Hành động di chuyển người hoặc vật, như hàng hóa, từ địa điểm này đến địa điểm khác, thường bằng phương tiện."},"7170":{"word":"ngành vận tải, ngành vận chuyển","meaning":"Lĩnh vực kinh doanh kiếm tiền bằng cách di chuyển người hoặc hàng hóa từ nơi này đến nơi khác bằng các phương tiện như xe tải, tàu hỏa hoặc tàu thuyền."},"7171":{"word":"người lái xe, tài xế","meaning":"Người điều khiển và lái một phương tiện, chẳng hạn như ô tô, xe buýt hoặc xe tải, để di chuyển trên đường."},"7172":{"word":"hàng rào","meaning":"Một cấu trúc được làm từ cột, dây thép hoặc tấm gỗ được xây dựng xung quanh một mảnh đất để đánh dấu ranh giới hoặc giữ vật nuôi/người ở trong/ngoài."},"7173":{"word":"sự oán trách, sự hờn trách","meaning":"Cảm giác cay đắng hoặc tức giận đối với ai đó vì bạn tin rằng họ đã làm điều gì đó không công bằng với bạn."},"7174":{"word":"bản gốc","meaning":"Bản đầu tiên hoặc chính thức của một tài liệu, tác phẩm hoặc vật phẩm, không phải là bản sao."},"7175":{"word":"xuất xứ","meaning":"Nơi sản phẩm, cây cối hoặc động vật được sản xuất, làm ra hoặc có nguồn gốc."},"7176":{"word":"kẻ thù","meaning":"Người hoặc nhóm người có thù oán sâu sắc, cần phải trả thù."},"7177":{"word":"dầu thô","meaning":"Dầu ở trạng thái tự nhiên, chưa qua tinh chế, được khai thác trực tiếp từ lòng đất."},"7178":{"word":"năng lượng hạt nhân","meaning":"Năng lượng mạnh được tạo ra từ việc phân tách hạt nhân nguyên tử, thường dùng để sản xuất điện."},"7179":{"word":"tác phẩm gốc","meaning":"Tác phẩm ban đầu, từ đó các phiên bản hoặc chuyển thể khác được tạo ra."},"7180":{"word":"giám đốc","meaning":"Người đứng đầu hoặc quản lý cao nhất của một tổ chức, cơ sở như bệnh viện hay trường học."},"7181":{"word":"hình tròn","meaning":"Một hình dạng tròn đều, với tất cả các điểm trên chu vi cách đều tâm."},"7182":{"word":"Won Hàn Quốc","meaning":"Đơn vị tiền tệ chính thức của Hàn Quốc, bao gồm tiền giấy và tiền kim loại."},"7183":{"word":"dạ dày","meaning":"Cơ quan tiêu hóa nằm trong bụng, giữa thực quản và ruột non, có chức năng chứa và tiêu hóa thức ăn."},"7184":{"word":"nguy cấp","meaning":"Tình trạng rất nghiêm trọng, nguy hiểm, cần hành động nhanh chóng để ngăn chặn hậu quả xấu."},"7185":{"word":"bất hợp pháp","meaning":"Hành động hoặc hành vi vi phạm pháp luật và có thể bị xử phạt."},"7186":{"word":"vệ sinh","meaning":"Các hoạt động giữ gìn sạch sẽ để phòng ngừa bệnh tật và duy trì sức khỏe."},"7187":{"word":"viêm dạ dày","meaning":"Một bệnh mà niêm mạc bên trong dạ dày bị viêm sưng và gây khó chịu."},"7188":{"word":"chủ yếu","meaning":"Lấy một điều gì đó làm chính, làm trọng tâm để mọi việc khác xoay quanh."},"7189":{"word":"hữu cơ","meaning":"Phương pháp trồng trọt không sử dụng thuốc trừ sâu, phân bón hóa học hoặc hạt giống biến đổi gen."},"7190":{"word":"nguồn gốc","meaning":"Nơi, thời điểm hoặc sự kiện mà một điều gì đó bắt đầu hoặc được tạo ra lần đầu tiên."},"7191":{"word":"triển vọng","meaning":"Trạng thái có hy vọng hoặc tiềm năng thành công trong tương lai."},"7192":{"word":"tương tự","meaning":"Hai hay nhiều vật có nhiều đặc điểm hoặc tính chất chung, làm cho chúng trông hoặc hoạt động gần như giống nhau nhưng không hoàn toàn."},"7193":{"word":"chú ý","meaning":"Một cách cẩn thận và tập trung cao độ để nhận ra từng chi tiết khi nhìn hoặc nghe."},"7194":{"word":"trẻ nhỏ","meaning":"Một đứa trẻ nhỏ tuổi trước khi đến tuổi đi học."},"7195":{"word":"dẻo dai","meaning":"Có khả năng dễ dàng uốn cong, kéo giãn hoặc thay đổi hình dạng mà không bị gãy."},"7196":{"word":"hữu ích","meaning":"Mô tả một vật hoặc thông tin mang lại sự giúp đỡ và làm cho việc thực hiện điều gì đó hoặc đạt được mục tiêu trở nên dễ dàng hơn."},"7197":{"word":"lưu ý","meaning":"Hành động cẩn thận và cảnh giác, chú tâm đến các chi tiết để tránh sai sót hoặc nguy hiểm."},"7198":{"word":"có lợi","meaning":"Mô tả điều gì đó mang lại kết quả tốt hoặc tác động tích cực, giúp cải thiện một người hoặc tình huống một cách rõ rệt."},"7199":{"word":"gen","meaning":"Một phần nhỏ trong tế bào sống mang thông tin di truyền xác định đặc điểm của sinh vật."},"7200":{"word":"rò rỉ","meaning":"Tình trạng chất lỏng, khí hoặc thông tin bị chảy ra, thoát ra khỏi nơi chứa một cách không mong muốn."},"7201":{"word":"tác hại","meaning":"Ảnh hưởng xấu, gây tổn thương hoặc nguy hiểm cho sinh vật và môi trường."},"7202":{"word":"hiệu lực","meaning":"Trạng thái được công nhận chính thức, có thể sử dụng và chấp nhận theo quy định."},"7203":{"word":"thịt","meaning":"Phần cơ và các mô mềm khác của động vật được cắt và chế biến để con người ăn."},"7204":{"word":"điền kinh","meaning":"Một nhóm các môn thể thao bao gồm chạy, nhảy và ném, thường được thực hiện trên sân vận động."},"7205":{"word":"ăn thịt","meaning":"Thói quen hoặc đặc điểm của động vật hoặc người có chế độ ăn chủ yếu hoặc hoàn toàn là thịt."},"7206":{"word":"nuôi dạy con","meaning":"Toàn bộ các hoạt động liên quan đến việc nuôi dưỡng, chăm sóc và giáo dục trẻ nhỏ."},"7207":{"word":"độ bóng","meaning":"Chất lượng bề mặt nhẵn bóng, phản chiếu ánh sáng khiến vật thể trông sáng và được đánh bóng."},"7208":{"word":"đạo đức","meaning":"Tập hợp các nguyên tắc định hình hành vi con người, giúp họ phân biệt hành động đúng sai."},"7209":{"word":"thường lệ","meaning":"Diễn tả một hành động hoặc sự việc xảy ra đều đặn, đúng như mong đợi vì đó là điều thường lệ hoặc tập quán chung."},"7210":{"word":"đe dọa","meaning":"Nói hoặc hành động để ngụ ý gây hại hoặc trừng phạt ai đó nếu họ không tuân theo, khiến họ sợ hãi."},"7211":{"word":"nghỉ hưu","meaning":"Đây là việc một người ngừng công việc hoặc sự nghiệp của mình vĩnh viễn, thường là sau khi đến tuổi già, và không còn làm việc kiếm tiền nữa."},"7212":{"word":"ngâm, đọc ngâm","meaning":"Đây là hành động đọc to một văn bản đã viết, như thơ hoặc lời bài hát, từ trí nhớ hoặc khi đang đọc, thường với một nhịp điệu đặc biệt hoặc biểu cảm."},"7213":{"word":"âm thanh","meaning":"Đây là cái mà tai có thể cảm nhận được khi rung động truyền qua không khí hoặc các chất khác, cho phép người hoặc động vật nghe thấy."},"7214":{"word":"chất lượng âm thanh","meaning":"Đây là những đặc điểm của âm thanh mà người nghe cảm nhận được, mô tả độ rõ ràng, dễ chịu hay méo mó của chúng."},"7215":{"word":"người không có tai nhạc","meaning":"Đây là người không thể nghe hoặc tạo ra đúng các nốt cao thấp bằng giọng của mình khi thể hiện một giai điệu."},"7216":{"word":"cấp cứu","meaning":"Đây là một tình huống đột ngột, rất nghiêm trọng, cần hành động nhanh chóng để ngăn chặn ai đó bị tổn thương hoặc điều gì đó trở nên tồi tệ hơn."},"7217":{"word":"biện pháp cấp cứu, sơ cứu","meaning":"Đây là những hành động nhanh chóng, tức thời được thực hiện để giúp đỡ ai đó trong tình huống nghiêm trọng đột ngột hoặc để ngăn chặn tình hình xấu đi, trước khi có sự giúp đỡ đầy đủ hơn."},"7218":{"word":"người trả lời, người khảo sát","meaning":"Đây là những cá nhân cung cấp thông tin, ý kiến hoặc giải pháp khi được đặt câu hỏi hoặc đưa ra một bảng câu hỏi."},"7219":{"word":"đăng ký tham gia, dự thi","meaning":"Đây là hành động chính thức nộp đơn hoặc tài liệu để tham gia một cuộc thi, xổ số hoặc quy trình tuyển chọn cụ thể."},"7220":{"word":"ứng dụng","meaning":"Đây là hành động lấy một lý thuyết, kiến thức hoặc kỹ thuật và đưa nó vào thực tế để phục vụ một mục đích cụ thể hoặc trong một tình huống đời thực."},"7221":{"word":"đáp ứng, phản ứng, tuân theo","meaning":"Đây là việc phản ứng hoặc hành xử theo một cách cụ thể sau một yêu cầu, câu hỏi hoặc tình huống, thường thể hiện sự đồng ý hoặc tham gia."},"7222":{"word":"khoa y, y khoa","meaning":"Đây là một bộ phận trong trường đại học hoặc tổ chức lớn, chuyên về nghiên cứu sức khỏe con người và thực hành chữa bệnh."},"7223":{"word":"trường y","meaning":"Đây là một cơ sở giáo dục đại học chuyên đào tạo sinh viên về khoa học và thực hành y tế để trở thành bác sĩ."},"7224":{"word":"chăm sóc y tế","meaning":"Đây là các dịch vụ và thủ tục do chuyên gia y tế cung cấp để bảo vệ, duy trì hoặc phục hồi sức khỏe thể chất và tinh thần của một người."},"7225":{"word":"giao tiếp","meaning":"Đây là quá trình trao đổi thông tin, suy nghĩ hoặc cảm xúc giữa các cá nhân, thường thông qua lời nói, chữ viết hoặc ngôn ngữ cơ thể."},"7226":{"word":"từ tượng thanh","meaning":"Đây là từ có cách phát âm mô phỏng hoặc gợi ý âm thanh thực tế mà nó đề cập đến, như \"ding-dong\" cho tiếng chuông."},"7227":{"word":"nhu yếu phẩm cơ bản","meaning":"Đây là ba yếu tố vật chất thiết yếu nhất cho sự sống còn và sinh hoạt hàng ngày của con người: quần áo, thức ăn và chỗ ở."},"7228":{"word":"dược phẩm","meaning":"Đây là các chất được sử dụng để chữa bệnh, giảm khó chịu hoặc ngăn ngừa bệnh tật ở người và động vật."},"7229":{"word":"một cách bất ngờ","meaning":"Từ này dùng để diễn tả điều gì đó xảy ra hoặc xuất hiện trái với những gì đã dự đoán."},"7230":{"word":"ý nghĩa","meaning":"Đây là nội dung sâu sắc chứa đựng trong một lời nói hoặc văn bản, hoặc tầm quan trọng của một sự việc."},"7231":{"word":"từ tượng hình","meaning":"Đây là từ mô tả hình dáng, hành động hoặc trạng thái của sự vật một cách sinh động, ví dụ như \"lấp lánh\", \"lạch bạch\"."},"7232":{"word":"dựa vào","meaning":"Động từ này dùng để chỉ việc thông tin hoặc quyết định xuất phát trực tiếp từ một nguồn, sự thật hoặc quy tắc cụ thể."},"7233":{"word":"y học","meaning":"Đây là lĩnh vực kiến thức và công việc tập trung vào việc chữa bệnh cho con người và ngăn ngừa bệnh tật."},"7234":{"word":"người","meaning":"Từ này dùng làm danh từ phụ thuộc, chỉ một người nào đó đang thực hiện hành động được nhắc đến trước đó, mang sắc thái trang trọng."},"7235":{"word":"này nọ","meaning":"Nhiều điều, nhiều thứ không xác định rõ ràng."},"7236":{"word":"chủ nghĩa ích kỷ","meaning":"Cách suy nghĩ hoặc hành vi chỉ đặt lợi ích và mong muốn của bản thân lên hàng đầu mà không màng đến người khác."},"7237":{"word":"lợi ích","meaning":"Cái có được một cách tích cực như tài sản dư ra, kết quả giúp ích hay tình hình được cải thiện từ một hành động hay giao dịch."},"7238":{"word":"năm sau","meaning":"Khoảng thời gian mười hai tháng ngay sau năm hiện tại hoặc một năm cụ thể đã được đề cập."},"7239":{"word":"kể từ khi","meaning":"Chỉ thời điểm bắt đầu của một khoảng thời gian, cho biết điều gì đó đã xảy ra hoặc tồn tại từ thời điểm đó cho đến hiện tại."},"7240":{"word":"bảy ngày","meaning":"Khoảng thời gian bằng bảy ngày liên tiếp 24 giờ."},"7241":{"word":"mang tính lý thuyết","meaning":"Chỉ cái gì đó dựa trên các nguyên tắc trừu tượng và nghiên cứu, chứ không phải kinh nghiệm thực tế hoặc sự kiện có thể quan sát được."},"7242":{"word":"không thể tả xiết","meaning":"Diễn tả một phẩm chất hoặc số lượng quá lớn hoặc quá mãnh liệt đến mức không thể diễn tả hết bằng lời."},"7243":{"word":"sự cất cánh","meaning":"Hành động của máy bay di chuyển từ mặt đất lên không trung để bắt đầu chuyến bay."},"7244":{"word":"nổi tiếng","meaning":"Được nhiều người biết đến và nhắc đến (dùng cho người, địa điểm hoặc vật)."},"7245":{"word":"giấy một mặt","meaning":"Giấy chỉ được sử dụng một mặt và mặt còn lại để trống, thường dùng để tái sử dụng."},"7246":{"word":"mẫu người lý tưởng","meaning":"Người sở hữu tất cả những phẩm chất và đặc điểm mà ai đó cho là đáng mong muốn nhất cho một đối tác hoặc một người bạn."},"7247":{"word":"lý trí","meaning":"Suy nghĩ và hành động dựa trên lý lẽ, sự thật, không bị cảm xúc chi phối."},"7248":{"word":"Hồi giáo","meaning":"Một tôn giáo thờ phụng một vị thần duy nhất là Allah, có nguồn gốc từ Trung Đông."},"7249":{"word":"tiếp theo","meaning":"Diễn ra hoặc xảy ra ngay sau khi một việc gì đó khác đã kết thúc."},"7250":{"word":"tai nghe","meaning":"Thiết bị nhỏ dùng để đeo vào tai để nghe âm thanh từ một máy phát."},"7251":{"word":"lấy nóng trị nóng","meaning":"Cách giải quyết vấn đề bằng cách dùng chính yếu tố gây ra nó, đặc biệt là dùng đồ nóng để chống lại cái nóng."},"7252":{"word":"kép, đôi","meaning":"Gồm có hai phần hoặc hai lớp giống nhau được kết hợp lại."},"7253":{"word":"chuyển việc","meaning":"Việc rời bỏ công việc hiện tại để bắt đầu công việc mới ở một công ty khác."},"7254":{"word":"lẽ phải, lý lẽ","meaning":"Cách thức hợp lý và có trật tự mà mọi thứ vận hành hoặc được hiểu thông qua suy nghĩ cẩn thận."},"7255":{"word":"tỉ lệ ly hôn","meaning":"Con số thống kê tỉ lệ các cặp vợ chồng ly hôn chính thức trong tổng số các cặp vợ chồng ở một khu vực hoặc thời gian nhất định."},"7256":{"word":"người (dùng đếm số người)","meaning":"Từ dùng để gắn vào số đếm để chỉ số lượng người có mặt."},"7257":{"word":"vệ tinh nhân tạo","meaning":"Vật thể được đưa vào quỹ đạo bởi tên lửa để quan sát, bay quanh một hành tinh như Trái Đất."},"7258":{"word":"lân cận, gần đó","meaning":"Khu vực ở khoảng cách rất gần với một địa điểm cụ thể nào đó."},"7259":{"word":"sự kiên nhẫn","meaning":"Là khả năng giữ bình tĩnh và chờ đợi mà không khó chịu hay buồn bực, ngay cả khi đối mặt với khó khăn."},"7260":{"word":"sinh mạng con người","meaning":"Là mạng sống của con người, đặc biệt khi nói về sự tổn thất hay thiệt hại về người."},"7261":{"word":"khối khoa học xã hội","meaning":"Là chương trình học tập tập trung vào các môn như văn học, lịch sử, triết học và xã hội học, thay vì khoa học hoặc kỹ thuật."},"7262":{"word":"nhân vật nổi bật","meaning":"Là một người được công nhận rộng rãi và được coi là quan trọng trong đời sống công cộng hoặc một lĩnh vực cụ thể."},"7263":{"word":"nhân sự","meaning":"Là nhóm các cá nhân làm việc cho một công ty hoặc tổ chức."},"7264":{"word":"mô tả nhận dạng","meaning":"Là các chi tiết về đặc điểm bên ngoài của một người, như chiều cao, màu tóc, quần áo và đặc điểm khuôn mặt."},"7265":{"word":"sự keo kiệt","meaning":"Là phẩm chất không sẵn lòng cho đi hoặc tiêu tiền, quà tặng hay lời khen một cách rộng rãi."},"7266":{"word":"nhân cách","meaning":"Là những phẩm chất định hình cách một người suy nghĩ, cảm nhận và tương tác với thế giới, thể hiện qua hành động của họ."},"7267":{"word":"chủng tộc","meaning":"Là một nhóm người có chung các đặc điểm thể chất tương tự như màu da, tóc hoặc đặc điểm khuôn mặt."},"7268":{"word":"nhận thức","meaning":"Là hoạt động của não bộ trong việc tiếp nhận thông tin từ thế giới, hiểu nó, ghi nhớ và sử dụng để giải quyết vấn đề."},"7269":{"word":"máy rút tiền tự động","meaning":"Là một máy có màn hình và các nút bấm nơi mọi người có thể lấy tiền mặt hoặc thực hiện các giao dịch ngân hàng khác mà không cần sự giúp đỡ của nhân viên."},"7270":{"word":"bác sĩ thực tập","meaning":"Là bác sĩ nhận đào tạo lâm sàng bằng cách thực sự chăm sóc bệnh nhân sau khi tốt nghiệp trường y và có giấy phép hành nghề."},"7271":{"word":"đám đông","meaning":"Một nhóm lớn người tập trung lại một chỗ."},"7272":{"word":"nhật báo","meaning":"Một loại báo được xuất bản và phát hành hàng ngày."},"7273":{"word":"nhất cử lưỡng tiện","meaning":"Tình huống đạt được hai lợi ích hoặc kết quả tốt từ một hành động duy nhất."},"7274":{"word":"công việc thường ngày","meaning":"Chuỗi các hành động hoặc nhiệm vụ mà một người thực hiện đều đặn mỗi ngày."},"7275":{"word":"tắm nắng","meaning":"Hoạt động ngồi hoặc nằm dưới ánh nắng mặt trời trực tiếp, thường để làm da sạm đi."},"7276":{"word":"bị méo mó","meaning":"Thay đổi hình dạng, trở nên lệch lạc, không đều hoặc bị biến dạng."},"7277":{"word":"nổi lên, dâng lên","meaning":"Một thứ gì đó như nước hoặc bụi bắt đầu chuyển động lên trên hoặc hiện rõ từ một bề mặt phẳng."},"7278":{"word":"hàng đầu, hạng nhất","meaning":"Miêu tả cái gì đó có chất lượng tốt nhất hoặc thuộc loại cao cấp nhất."},"7279":{"word":"điểm hợp lý","meaning":"Một phần cụ thể trong lập luận hoặc ý kiến có ý nghĩa logic và dễ đồng tình."},"7280":{"word":"ghế phổ thông","meaning":"Chỗ ngồi tiêu chuẩn, cơ bản trong phương tiện giao thông công cộng hoặc địa điểm, không phải là lựa chọn đặc biệt hay cao cấp."},"7281":{"word":"đơn phương","meaning":"Mô tả một hành động, quyết định hoặc ý kiến chỉ đến từ và thiên vị một phía hoặc một nhóm mà không xem xét các bên khác."},"7282":{"word":"tạm thời","meaning":"Một khoảng thời gian ngắn."},"7283":{"word":"ngày","meaning":"Một ngày cụ thể trong tháng và năm, cho biết khi nào một sự kiện sẽ hoặc đã xảy ra."},"7284":{"word":"chuyến đi vòng quanh","meaning":"Việc đi lại hoàn toàn quanh một địa điểm cụ thể hoặc toàn bộ thế giới, thường quay trở lại điểm xuất phát."},"7285":{"word":"giai thoại","meaning":"Một câu chuyện ngắn, thú vị về một sự kiện hoặc người có thật, thường được kể để minh họa một quan điểm."},"7286":{"word":"sự cho thuê","meaning":"Một thỏa thuận mà theo đó một người trả tiền để tạm thời sử dụng tài sản của người khác."},"7287":{"word":"thai phụ","meaning":"Người phụ nữ đang mang thai hoặc vừa mới sinh con."},"7288":{"word":"khóe miệng","meaning":"Điểm cụ thể trên mặt một người nơi môi trên và môi dưới gặp nhau ở hai bên."},"7289":{"word":"việc vào phòng","meaning":"Hành động đi vào một căn phòng trong tòa nhà, như phòng khách, phòng học hay phòng bệnh."},"7290":{"word":"vị trí","meaning":"Nơi cụ thể mà một thứ gì đó được đặt hoặc dự kiến đặt, xem xét các lợi thế hoặc bất lợi của nó cho một mục đích."},"7291":{"word":"nướu răng","meaning":"Mô thịt màu hồng bên trong miệng, che xương hàm và giữ chân răng."},"7292":{"word":"vết","meaning":"Một dấu hiệu hình thành khi một cái gì đó chạm hoặc dính vào một cái khác, hoặc một vết thay đổi từ trạng thái ban đầu."},"7293":{"word":"quê hương","meaning":"Vùng đất mà một người sinh ra hoặc mang quốc tịch, nơi họ gọi là quê nhà của mình."},"7294":{"word":"cay nồng","meaning":"Dùng để chỉ thức ăn có vị rất mạnh hoặc gây cảm giác nóng rát trong miệng do các nguyên liệu cay."},"7295":{"word":"quỹ, vốn","meaning":"Số tiền hoặc tài sản được tích lũy hoặc dành riêng cho một mục đích hoặc dự án cụ thể."},"7296":{"word":"cậu (đại từ xưng hô)","meaning":"Đại từ nhân xưng dùng bởi người lớn tuổi hoặc cấp cao hơn để gọi người trẻ hơn hoặc cấp dưới một cách thân mật."},"7297":{"word":"chữ cái, mẫu tự","meaning":"Các ký hiệu viết riêng lẻ tạo nên một hệ thống chữ viết như A, B, C trong tiếng Anh hoặc ㄱ, ㄴ, ㄷ trong tiếng Hàn."},"7298":{"word":"chu đáo, ân cần","meaning":"Có tính cách tử tế và quan tâm, luôn thể hiện sự lo lắng cho hạnh phúc và cảm xúc của người khác."},"7299":{"word":"từ thiện","meaning":"Hành động tự nguyện cung cấp sự giúp đỡ, tiền bạc hoặc hàng hóa để giúp đỡ những người khó khăn."},"7300":{"word":"con cháu, hậu duệ","meaning":"Tất cả các thế hệ tương lai trong gia đình của một người, bao gồm con cái, cháu chắt, v.v."},"7301":{"word":"khoa học tự nhiên","meaning":"Các lĩnh vực học thuật tập trung nghiên cứu thế giới vật chất và các hiện tượng của nó, bao gồm sinh vật sống, vật chất và năng lượng."},"7302":{"word":"thiên tai","meaning":"Một sự kiện nghiêm trọng do các quá trình tự nhiên của Trái Đất gây ra, như động đất, lũ lụt hoặc bão, gây thiệt hại trên diện rộng."},"7303":{"word":"kinh doanh tự do, tự kinh doanh","meaning":"Cách một người tự nuôi sống bản thân bằng cách quản lý doanh nghiệp nhỏ của riêng mình, như một cửa hàng hoặc quán cà phê, thay vì nhận lương từ một công ty lớn."},"7304":{"word":"người kinh doanh tự do, người tự kinh doanh","meaning":"Người tự điều hành doanh nghiệp của mình, chẳng hạn như một cửa hàng nhỏ hoặc nhà hàng, mà không được trả lương bởi một công ty khác."},"7305":{"word":"tia tử ngoại, tia UV","meaning":"Ánh sáng phát ra từ mặt trời, không nhìn thấy được và có bước sóng ngắn."},"7306":{"word":"tự nguyện","meaning":"Hành động tham gia hoặc làm một việc gì đó một cách tự ý, không bị ép buộc."},"7307":{"word":"hoạt động tình nguyện","meaning":"Việc tự nguyện dùng thời gian và công sức của mình để giúp đỡ người khác mà không nhận thù lao."},"7308":{"word":"tình nguyện viên","meaning":"Người tự nguyện dành thời gian và công sức để giúp đỡ người khác mà không mong nhận lại tiền bạc."},"7309":{"word":"tính tự chủ","meaning":"Trạng thái một cá nhân hoặc nhóm có thể tự đưa ra quyết định và hành động mà không bị người khác chỉ đạo."},"7310":{"word":"phụ âm","meaning":"Một âm thanh trong lời nói được tạo ra bằng cách cản trở hoặc thu hẹp luồng hơi từ phổi bằng lưỡi, môi hoặc răng."},"7311":{"word":"đời đời","meaning":"Từ dùng để chỉ sự tiếp nối qua nhiều thế hệ con cháu trong một gia đình, kéo dài rất lâu."},"7312":{"word":"nửa đêm","meaning":"Khoảnh khắc chính xác lúc mười hai giờ đêm, đánh dấu sự chuyển giao từ ngày này sang ngày khác."},"7313":{"word":"sự kiềm chế","meaning":"Hành động tự quản lý cảm xúc, ham muốn hoặc hành động của bản thân để tránh làm những điều có thể hối tiếc."},"7314":{"word":"sự tự chủ","meaning":"Trạng thái hoặc khả năng tự hành động, tự đưa ra lựa chọn mà không bị người khác chỉ đạo hoặc kiểm soát."},"7315":{"word":"bản thân","meaning":"Từ dùng để chỉ đối tượng hoặc chủ thể được nói đến một cách trực tiếp, tách biệt khỏi các yếu tố xung quanh."},"7316":{"word":"tự trị","meaning":"Khả năng một nhóm, thành phố hoặc quốc gia tự quản lý công việc và quy tắc của mình, tự ra quyết định mà không bị kiểm soát bởi một thế lực bên ngoài."},"7317":{"word":"-phẩm","meaning":"Hậu tố dùng để chỉ một tác phẩm được tạo ra bởi một nghệ sĩ hoặc người sáng tạo cụ thể (như tranh vẽ, sách, bài hát)."},"7318":{"word":"sự chia tay","meaning":"Hành động nói lời chúc hoặc chia tay lần cuối với ai đó trước khi bạn hoặc họ rời đi, thường là trong một khoảng thời gian dài."},"7319":{"word":"người soạn thảo","meaning":"Người tạo ra hoặc hoàn thành một văn bản, báo cáo, hay tài liệu nào đó."},"7320":{"word":"kế hoạch ba ngày","meaning":"Một quyết tâm hoặc kế hoạch chỉ giữ được trong thời gian ngắn, không bền vững."},"7321":{"word":"số dư","meaning":"Lượng tiền còn lại trong tài khoản ngân hàng hoặc trong quỹ sau khi đã chi tiêu."},"7322":{"word":"tiền lẻ","meaning":"Tiền xu hoặc tiền giấy có mệnh giá nhỏ dùng để chi trả hoặc đổi tiền."},"7323":{"word":"tàn nhẫn","meaning":"Có hành vi độc ác, gây đau khổ cho người khác mà không có lòng thương xót."},"7324":{"word":"êm ả","meaning":"Diễn tả trạng thái yên tĩnh, thanh bình, không có sự xáo động của mặt nước, không khí hay không gian."},"7325":{"word":"nói mê","meaning":"Hành động phát ra âm thanh hoặc nói chuyện trong khi đang ngủ mà không ý thức được."},"7326":{"word":"chỗ ngủ","meaning":"Nơi hoặc vật dụng dùng để nằm nghỉ, ngủ (ví dụ: chăn, nệm, chiếu)."},"7327":{"word":"im lặng","meaning":"Không nói một lời nào, giữ im lặng hoặc làm việc gì đó một cách yên tĩnh."},"7328":{"word":"chuyện phiếm","meaning":"Cuộc trò chuyện không trang trọng về những chủ đề không quan trọng hoặc không nghiêm túc."},"7329":{"word":"bắt giữ","meaning":"Hành động của cảnh sát hoặc người có thẩm quyền bắt giữ một người và đưa họ đến một nơi khác."},"7330":{"word":"lôi kéo","meaning":"Dùng tay hoặc sức mạnh giữ chặt và di chuyển một vật hoặc một người về phía mình hoặc theo một hướng nhất định."},"7331":{"word":"phát hiện","meaning":"Tìm thấy hoặc nhận ra một điều gì đó bị che giấu, mất tích hoặc khó nhận thấy một cách thành công."},"7332":{"word":"tạp âm","meaning":"Hỗn hợp các âm thanh lớn, ồn ào không mong muốn."},"7333":{"word":"cỏ dại","meaning":"Loài cây hoang dã mọc ở nơi không mong muốn, thường là trong vườn hoặc đồng ruộng."},"7334":{"word":"tạp hóa","meaning":"Tập hợp nhiều loại đồ dùng nhỏ khác nhau dùng hàng ngày, thường được bán cùng nhau trong một khu vực của cửa hàng."},"7335":{"word":"chương","meaning":"Một phần chính được đánh số, dùng để chia một cuốn sách hoặc tài liệu dài thành nhiều phần."},"7336":{"word":"-trưởng, -chủ","meaning":"Hậu tố thêm vào danh từ để chỉ người đứng đầu hoặc người phụ trách chính của một tổ chức hay nhóm."},"7337":{"word":"-sổ, -quyển","meaning":"Hậu tố thêm vào danh từ để chỉ một cuốn sách có các trang trống dùng để viết ghi chú hoặc vẽ."},"7338":{"word":"diễn đàn","meaning":"Nơi chốn hoặc không gian để mọi người tụ họp, thảo luận hoặc trình bày ý kiến."},"7339":{"word":"ruột","meaning":"Cơ quan hình ống dài bên trong cơ thể, nơi thức ăn được xử lý sau khi rời dạ dày."},"7340":{"word":"tương, nước tương","meaning":"Gia vị dạng lỏng, mặn, màu sẫm được làm từ đậu nành và các loại hạt khác, thường dùng trong ẩm thực Đông Á."},"7341":{"word":"-tang lễ","meaning":"Hậu tố gắn với số từ để biểu thị số ngày tổ chức tang lễ và tang gia."},"7342":{"word":"tướng quân","meaning":"Sĩ quan cấp cao chỉ huy nhiều binh lính trong quân đội, thường được nhận biết qua quân phục và phù hiệu đặc biệt."},"7343":{"word":"tài năng đặc biệt","meaning":"Khả năng hoặc kỹ năng nổi bật mà một người có, thường được thể hiện để giải trí hoặc thi đấu."},"7344":{"word":"dài hạn","meaning":"Chỉ điều gì đó kéo dài trong một khoảng thời gian dài, thường là nhiều tháng hoặc nhiều năm."},"7345":{"word":"nội tạng","meaning":"Một bộ phận riêng biệt của cơ thể sống, như tim hoặc gan, thực hiện một chức năng cụ thể."},"7346":{"word":"tuổi trung niên","meaning":"Giai đoạn trong đời người khi không còn trẻ nhưng chưa già, thường khoảng 40 đến 60 tuổi."},"7347":{"word":"nhịp điệu","meaning":"Kiểu âm thanh và sự im lặng lặp đi lặp lại tạo nên chuyển động và cảm giác của âm nhạc."},"7348":{"word":"triển vọng tương lai","meaning":"Khả năng cho những điều tốt đẹp xảy ra hoặc cho ai đó/cái gì đó thành công trong tương lai."},"7349":{"word":"đám tang","meaning":"Nghi lễ chôn cất hoặc hỏa táng một người sau khi họ qua đời."},"7350":{"word":"sắm sửa","meaning":"Hành động thu xếp hoặc mua sắm tất cả những thứ cần thiết cho một sự kiện hoặc công việc."},"7351":{"word":"giỏ mua sắm","meaning":"Vật chứa dùng để đựng đồ mua từ cửa hàng, thường được làm bằng nhựa, vải hoặc vật liệu đan."},"7352":{"word":"thiết bị","meaning":"Tập hợp các công cụ, máy móc hoặc vật dụng cần thiết được sử dụng cho một mục đích hoặc hoạt động cụ thể."},"7353":{"word":"thời gian dài","meaning":"Một khoảng thời gian kéo dài nhiều giờ hoặc có thời lượng đáng kể."},"7354":{"word":"chướng ngại vật","meaning":"Một vật thể hoặc cấu trúc vật lý cản đường, gây khó khăn cho việc di chuyển hoặc hoàn thành công việc."},"7355":{"word":"thiết bị","meaning":"Một máy móc hoặc công cụ nhỏ được thiết kế để thực hiện một công việc hoặc chức năng cụ thể."},"7356":{"word":"sinh viên được học bổng","meaning":"Người học tại trường đại học hoặc cao đẳng mà chi phí giáo dục được đài thọ bởi quỹ của một tổ chức hoặc chính phủ."},"7357":{"word":"thường xuyên, thường gặp","meaning":"Diễn tả việc gì đó xảy ra nhiều lần hoặc xuất hiện liên tục trong một thời gian ngắn."},"7358":{"word":"tái phát triển","meaning":"Quá trình phá bỏ các tòa nhà cũ trong một khu vực và xây dựng các cấu trúc mới hoàn toàn để tạo ra một diện mạo mới."},"7359":{"word":"tồn kho","meaning":"Trạng thái hàng hóa hoặc vật phẩm được giữ trong kho, chưa được bán hoặc sử dụng."},"7360":{"word":"thiên tai, thảm họa","meaning":"Một sự kiện khủng khiếp như lũ lụt, động đất hay hỏa hoạn gây ra nhiều thiệt hại, thương vong."},"7361":{"word":"quỹ, tổ chức","meaning":"Một tổ chức được thành lập để thu thập và quản lý tiền nhằm mục đích từ thiện, hỗ trợ nghiên cứu hoặc tài trợ cho các lợi ích công cộng cụ thể."},"7362":{"word":"tài lực, sức mạnh tài chính","meaning":"Sức mạnh hoặc quyền lực có được từ việc sở hữu khối lượng tài sản lớn."},"7363":{"word":"tài sản, của cải","meaning":"Tập hợp các vật phẩm có giá trị lớn như vàng, trang sức, nhà cửa đắt tiền mà một người hoặc nhóm sở hữu."},"7364":{"word":"tài phiệt, chaebol","meaning":"Một hệ thống rất lớn gồm nhiều công ty khác nhau, thường thuộc sở hữu và kiểm soát bởi một gia đình quyền lực."},"7365":{"word":"nhanh nhẹn, lanh lẹ","meaning":"Di chuyển đột ngột và với tốc độ cao, có khả năng thay đổi hướng dễ dàng."},"7366":{"word":"ôn thi lại, học lại","meaning":"Hành động học tập lại để dự thi một kỳ thi học thuật quan trọng sau khi chưa đạt được kết quả mong muốn trước đó."},"7367":{"word":"tài chính","meaning":"Liên quan đến tiền bạc, thu chi hoặc việc quản lý tiền."},"7368":{"word":"chất liệu","meaning":"Loại vật liệu mà một vật thể được làm ra và cảm giác khi chạm vào bề mặt của nó."},"7369":{"word":"thúc giục","meaning":"Hành động nhắc nhở ai đó liên tục để làm việc gì đó nhanh hơn hoặc đẩy nhanh tiến độ."},"7370":{"word":"sạc lại","meaning":"Quá trình nạp lại năng lượng điện vào pin hoặc phục hồi lại sức lực cho bản thân bằng cách nghỉ ngơi."},"7371":{"word":"làm việc tại nhà","meaning":"Tình huống một người thực hiện công việc của mình trong chính ngôi nhà của mình thay vì đến nơi làm việc bên ngoài."},"7372":{"word":"thiên tai","meaning":"Sự kiện khủng khiếp đột ngột như lũ lụt, động đất, hỏa hoạn lớn, gây ra nhiều thiệt hại hoặc tổn hại."},"7373":{"word":"tái hôn","meaning":"Hành động một người kết hôn với người khác sau khi cuộc hôn nhân trước đó của họ đã kết thúc."},"7374":{"word":"giá thấp","meaning":"Đặc điểm của một mặt hàng hoặc dịch vụ được bán với số tiền nhỏ."},"7375":{"word":"jeogori","meaning":"Trang phục truyền thống của Hàn Quốc dành cho cả nam và nữ, có đặc điểm là ngắn và tay dài, thường được buộc bằng nơ."},"7376":{"word":"áp thấp","meaning":"Áp suất thấp hơn so với các khu vực xung quanh."},"7377":{"word":"ôi không!","meaning":"Từ cảm thán dùng để thể hiện sự thất vọng, kinh ngạc hoặc ngạc nhiên đột ngột khi có điều gì đó không hay xảy ra."},"7378":{"word":"tê bì","meaning":"Trải qua cảm giác lạ, ngứa ran ở một bộ phận cơ thể, thường kèm theo mất cảm giác tạm thời."},"7379":{"word":"tối dần","meaning":"Khi mặt trời lặn xuống và ánh sáng ban ngày dần mất đi, trời chuyển sang tối."},"7380":{"word":"tỉ lệ sinh thấp","meaning":"Tình trạng số lượng trẻ em được sinh ra trong một quốc gia hoặc khu vực rất ít trong một thời gian dài."},"7381":{"word":"suy giảm","meaning":"Sự xuống cấp, kém đi về chất lượng, khả năng hoặc mức độ của một thứ gì đó so với trước."},"7382":{"word":"học vấn thấp","meaning":"Tình trạng có trình độ giáo dục hoặc học vấn ở mức độ thấp."},"7383":{"word":"huyết áp thấp","meaning":"Tình trạng huyết áp của cơ thể thấp hơn mức bình thường."},"7384":{"word":"tiết kiệm định kỳ","meaning":"Khoản tiền được tích lũy dần dần bằng cách gửi vào ngân hàng một cách định kỳ."},"7385":{"word":"tuổi thích hợp","meaning":"Khoảng tuổi được xem là phù hợp hoặc lý tưởng để thực hiện một việc gì đó."},"7386":{"word":"tích lũy","meaning":"Hành động thu thập và cộng thêm những số lượng nhỏ của thứ gì đó, như tiền hoặc điểm, để tổng số lượng tăng lên."},"7387":{"word":"màu đỏ","meaning":"Một trong các màu cơ bản, thường được liên tưởng đến máu hoặc lửa."},"7388":{"word":"làm ướt","meaning":"Khiến một vật bị thấm chất lỏng, thường là nước, trở nên ẩm hoặc ướt sũng."},"7389":{"word":"một cách thích hợp","meaning":"Thực hiện một hành động nào đó theo cách chính xác, đúng đắn và phù hợp với hoàn cảnh hoặc mục đích cụ thể."},"7390":{"word":"sự phù hợp","meaning":"Đặc điểm của một vật thể, tình huống hoặc điều kiện nào đó làm cho nó hoàn toàn đúng hoặc thích đáng cho một mục đích cụ thể."},"7391":{"word":"(hậu tố) triển lãm","meaning":"Hậu tố dùng để tạo danh từ chỉ một cuộc trưng bày công khai các tác phẩm, vật phẩm."},"7392":{"word":"bóng đèn","meaning":"Vật làm bằng thủy tinh bên trong có dây tóc, khi được nối với điện sẽ phát ra ánh sáng."},"7393":{"word":"tiền kỳ, nửa đầu","meaning":"Thời gian ở giai đoạn trước hoặc nửa đầu của một khoảng thời gian nhất định."},"7394":{"word":"năm trước","meaning":"Năm đã qua ngay trước năm hiện tại."},"7395":{"word":"đèn điện","meaning":"Thiết bị phát sáng dùng bóng đèn điện, thường treo trên trần nhà hoặc đặt trên bàn."},"7396":{"word":"chiến lược","meaning":"Kế hoạch tổng thể và chi tiết được đặt ra để đạt được một mục tiêu quan trọng."},"7397":{"word":"điện năng","meaning":"Năng lượng điện được cung cấp để vận hành máy móc và thắp sáng."},"7398":{"word":"tính chuyên môn","meaning":"Tính chất có nhiều kiến thức, kinh nghiệm và kỹ năng trong một lĩnh vực cụ thể."},"7399":{"word":"toàn bộ, tổng thể","meaning":"Bao gồm hoặc liên quan đến tất cả các phần hoặc khía cạnh của một tình huống hay chủ đề."},"7400":{"word":"truyền tải","meaning":"Hành động gửi thông tin, như hình ảnh hoặc tin nhắn, từ nơi này đến nơi khác thông qua mạng hoặc sóng vô tuyến."},"7401":{"word":"phòng triển lãm","meaning":"Một căn phòng lớn hoặc tòa nhà nơi các vật phẩm như tác phẩm nghệ thuật, đồ vật lịch sử được trưng bày cho mọi người xem."},"7402":{"word":"toàn bộ số tiền","meaning":"Toàn bộ số tiền hoặc số lượng của một cái gì đó, không bỏ sót."},"7403":{"word":"sự lây nhiễm","meaning":"Hiện tượng bệnh tật lây lan từ người này sang người khác hoặc từ động vật này sang động vật khác qua tiếp xúc."},"7404":{"word":"bệnh truyền nhiễm","meaning":"Một loại bệnh có thể dễ dàng lây lan từ sinh vật này sang sinh vật khác, thường khiến nhiều người bị bệnh cùng lúc."},"7405":{"word":"cái trước","meaning":"Từ dùng để chỉ điều hoặc người được đề cập đầu tiên khi có hai đối tượng được nhắc đến."},"7406":{"word":"chiến trường","meaning":"Một khu vực hoặc địa điểm cụ thể nơi diễn ra các cuộc xung đột vũ trang hoặc chiến đấu giữa các nhóm người."},"7407":{"word":"hoàn toàn","meaning":"Diễn tả một điều gì đó là tuyệt đối, không có phần nào hoặc khía cạnh nào bị loại trừ."},"7408":{"word":"văn hóa truyền thống","meaning":"Các cách sống, tín ngưỡng, phong tục và hình thức nghệ thuật được truyền lại từ các thế hệ trước cho các thế hệ sau trong một thời gian dài."},"7409":{"word":"chuyển trường","meaning":"Hành động một học sinh rời khỏi một trường để bắt đầu học tại một trường khác."},"7410":{"word":"điển hình","meaning":"Diễn tả một điều gì đó thể hiện rõ ràng các đặc điểm hoặc phẩm chất thông thường được mong đợi ở một loại người hoặc vật cụ thể."},"7411":{"word":"sự chuyển đổi","meaning":"Một sự thay đổi rõ rệt từ trạng thái này, hệ thống này hoặc hướng này sang trạng thái, hệ thống hoặc hướng khác."},"7412":{"word":"bước ngoặt","meaning":"Một thời điểm cụ thể khi một tình huống hoặc cuộc đời của một người thay đổi theo một cách rất quan trọng và thường là không thể đảo ngược."},"7413":{"word":"đi khập khiễng","meaning":"Bước đi không đều hoặc khó khăn, thường là do một chân hoặc bàn chân bị thương hoặc cứng."},"7414":{"word":"vách đá","meaning":"Một mặt đá rất dốc và cao, thường được tìm thấy ở rìa biển hoặc núi."},"7415":{"word":"ướp","meaning":"Ướp là cách bảo quản thực phẩm bằng cách ngâm chúng trong dung dịch muối, giấm hoặc gia vị để giữ được lâu hơn."},"7416":{"word":"đỉnh điểm","meaning":"Đỉnh điểm là mức cao nhất, mạnh nhất hoặc thú vị nhất trong một quá trình, sự kiện hay sự phát triển của một người."},"7417":{"word":"dự đoán","meaning":"Dự đoán là hành động cố gắng cho biết điều gì sẽ xảy ra trong tương lai, thường thông qua dấu hiệu hoặc vật thể đặc biệt."},"7418":{"word":"nhảy","meaning":"Nhảy là hành động bật mình lên và vươn tới một vị trí cao hơn."},"7419":{"word":"tình cảm","meaning":"Tình cảm là cảm giác ấm áp và dịu dàng về sự quan tâm hoặc yêu mến dành cho ai đó, thường được thể hiện qua hành động tử tế hoặc sự gần gũi."},"7420":{"word":"ấm áp, thân mật","meaning":"Miêu tả một âm thanh, cái nhìn hoặc cảm giác khiến mọi người cảm thấy vui vẻ, gần gũi và thân thiện với nhau."},"7421":{"word":"nhân viên chính thức","meaning":"Nhân viên chính thức là người làm việc số giờ cố định mỗi tuần cho một công ty và có công việc ổn định với các phúc lợi đã định."},"7422":{"word":"nghỉ hưu theo tuổi","meaning":"Nghỉ hưu theo tuổi là hành động một người lớn tuổi ngừng công việc vĩnh viễn vì đã đạt đến độ tuổi nhất định do nơi làm việc hoặc pháp luật quy định."},"7423":{"word":"thân ái, thân thiết","meaning":"Miêu tả khi mọi người rất tử tế và thân thiện với nhau, thường thể hiện sự yêu mến qua hành động hoặc lời nói."},"7424":{"word":"đỉnh, chóp","meaning":"Đỉnh là điểm cao nhất của một ngọn núi hoặc một cấu trúc nào đó."},"7425":{"word":"cảm xúc, tình cảm","meaning":"Cảm xúc là một cảm giác nội tâm mạnh mẽ như vui, buồn, tức giận hay sợ hãi mà một người trải nghiệm và thường thể hiện qua nét mặt hoặc hành động."},"7426":{"word":"tận tình, hết lòng","meaning":"Tận tình là làm một việc gì đó với sự chăm sóc chu đáo và nỗ lực chân thành, thường thể hiện rõ qua cách thực hiện hoặc chế tạo chi tiết."},"7427":{"word":"tận tâm, chu đáo","meaning":"Diễn tả một hành động hoặc đối tượng thể hiện sự cố gắng, chu đáo và nghiêm túc từ người thực hiện."},"7428":{"word":"khoa tâm thần","meaning":"Chuyên khoa y tế chuyên về chẩn đoán, điều trị và phòng ngừa các bệnh về suy nghĩ, cảm xúc hoặc hành vi."},"7429":{"word":"tháng Giêng âm lịch","meaning":"Tháng đầu tiên của năm theo chu kỳ mặt trăng, thường diễn ra nhiều lễ hội truyền thống."},"7430":{"word":"công lý","meaning":"Phẩm chất của sự công bằng và đúng đắn, nơi mọi người nhận được sự đối xử bình đẳng và xứng đáng."},"7431":{"word":"mất điện","meaning":"Sự cố đột ngột khi dòng điện ngừng cung cấp đến một tòa nhà hoặc khu vực, làm tắt mọi thiết bị điện."},"7432":{"word":"lịch sự, trang trọng","meaning":"Diễn tả hành vi thể hiện sự tôn trọng sâu sắc và phép tắc đối với người khác, thường qua hành động, tư thế và lời nói."},"7433":{"word":"tắc nghẽn, đình trệ","meaning":"Tình trạng giao thông bị ứ đọng hoặc sự phát triển bị trì trệ không tiến lên được."},"7434":{"word":"chính trị gia","meaning":"Người làm việc trong chính phủ hoặc cố gắng giành được một vị trí trong chính phủ để đưa ra các quyết định ảnh hưởng đến đất nước hoặc thành phố."},"7435":{"word":"tính chính xác","meaning":"Đặc điểm của việc hoàn toàn đúng đắn hoặc chính xác, không có bất kỳ lỗi nào."},"7436":{"word":"-chế (hệ thống)","meaning":"Hậu tố dùng để chỉ một tập hợp các quy tắc hoặc phương pháp có tổ chức về cách thức hoạt động hoặc quản lý một cái gì đó."},"7437":{"word":"-chế (sản xuất tại)","meaning":"Hậu tố được thêm vào tên một quốc gia để chỉ nơi sản phẩm được sản xuất hoặc lắp ráp."},"7438":{"word":"giá đúng, giá phải chăng","meaning":"Số tiền chính xác hoặc thích hợp mà một thứ gì đó thực sự nên có giá hoặc được bán với giá đó."},"7439":{"word":"bánh kẹo","meaning":"Đồ ăn ngọt như kẹo, bánh ngọt, bánh quy, sô cô la, hoặc ngành nghề sản xuất và kinh doanh chúng."},"7440":{"word":"đưa ra, nêu ra","meaning":"Hành động trình bày một vấn đề, câu hỏi hoặc chủ đề để mọi người có thể thảo luận hoặc giải quyết."},"7441":{"word":"giải ngũ, xuất ngũ","meaning":"Hành động chính thức được miễn nghĩa vụ trong quân đội, hải quân hoặc không quân sau một thời gian phục vụ."},"7442":{"word":"tùy tiện, bừa bãi","meaning":"Một cách không có trật tự, liều lĩnh hoặc làm theo ý muốn của bản thân mà không quan tâm đến người khác."},"7443":{"word":"chim én","meaning":"Một loài chim di cư nhỏ, nhanh, lưng đen và bụng trắng, bay đến Hàn Quốc vào mùa xuân và di chuyển về phía nam vào mùa thu."},"7444":{"word":"dược phẩm, thuốc men","meaning":"Các loại thuốc và dược liệu được sản xuất để điều trị bệnh, hoặc ngành công nghiệp sản xuất và kinh doanh chúng."},"7445":{"word":"nhà sản xuất","meaning":"Người phụ trách tài chính, kế hoạch và tổ chức để tạo ra một bộ phim, chương trình, album hoặc tác phẩm sáng tạo khác."},"7446":{"word":"chế tạo, sản xuất","meaning":"Quá trình tạo ra hàng hóa hoặc sản phẩm, thường với số lượng lớn, bằng máy móc trong nhà máy."},"7447":{"word":"ngành sản xuất, ngành chế tạo","meaning":"Lĩnh vực kinh tế liên quan đến việc tạo ra hàng hóa và sản phẩm, thường với số lượng lớn, bên trong các nhà máy."},"7448":{"word":"điều, khoản","meaning":"Một phần được đánh số hoặc chữ cái trong luật, quy tắc hoặc hợp đồng bằng văn bản, nêu rõ một điểm cụ thể."},"7449":{"word":"nhóm, tổ, đội","meaning":"Một số người tập hợp lại với nhau vì một mục đích chung, như làm việc trong một dự án hoặc thi đấu trong một trò chơi."},"7450":{"word":"điêu khắc, tác phẩm điêu khắc","meaning":"Một tác phẩm nghệ thuật được tạo ra bằng cách tạo hình vật liệu như đá, gỗ, kim loại hoặc đất sét thành một hình dạng ba chiều."},"7451":{"word":"nghêu, sò","meaning":"Là loài động vật biển thân mềm có vỏ cứng, thường sống dưới nước hoặc trên bãi biển và được dùng làm thức ăn."},"7452":{"word":"tổ quốc, quê hương","meaning":"Là đất nước nơi một người sinh ra, lớn lên hoặc nơi gia đình đã sinh sống qua nhiều thế hệ."},"7453":{"word":"nhỏ xíu, bé tí","meaning":"Có kích thước rất nhỏ, ít hơn nhiều so với bình thường hoặc mong đợi."},"7454":{"word":"siết, bóp","meaning":"Lấy vật gì đó như dây hoặc vải quấn chặt quanh một vật thể hoặc bộ phận cơ thể làm cho nó bị thắt lại."},"7455":{"word":"công thức nấu ăn","meaning":"Một danh sách các nguyên liệu và các bước hướng dẫn cụ thể cách chế biến một món ăn."},"7456":{"word":"đầu bếp","meaning":"Người có công việc là chuẩn bị và chế biến các bữa ăn, thường làm việc trong nhà hàng hoặc khu vực bếp chuyên nghiệp."},"7457":{"word":"điếu văn","meaning":"Là bài viết hoặc bài phát biểu dùng để tưởng nhớ người đã khuất và ca ngợi những thành tựu của họ trong cuộc sống."},"7458":{"word":"Joseon, Triều Tiên","meaning":"Là một vương quốc lịch sử ở Đông Á tồn tại hơn năm thế kỷ, nổi tiếng với văn hóa và hệ thống xã hội độc đáo."},"7459":{"word":"tiền phúng điếu, tiền viếng","meaning":"Số tiền được trao cho gia đình người đã mất để giúp chi phí tang lễ và thể hiện sự chia sẻ nỗi buồn."},"7460":{"word":"siết chặt, vặn chặt","meaning":"Làm cho một vật hoặc mối nối trở nên chắc chắn hơn, không còn lỏng lẻo, thường bằng cách vặn hoặc kéo."},"7461":{"word":"phi công","meaning":"Người có công việc là vận hành và điều khiển một phương tiện bay như máy bay trên bầu trời."},"7462":{"word":"tổ chức","meaning":"Hành động hình thành một nhóm có hệ thống để đạt được một mục tiêu nhất định, hoặc chính nhóm đó."},"7463":{"word":"nghỉ sớm","meaning":"Việc rời khỏi nơi làm việc hoặc trường học trước thời gian quy định, thường là có phép."},"7464":{"word":"sự kết hợp","meaning":"Kết quả của việc gom nhiều vật phẩm, yếu tố hoặc màu sắc khác nhau lại thành một nhóm mới duy nhất."},"7465":{"word":"tra cứu","meaning":"Hành động tìm kiếm thông tin hoặc chi tiết cụ thể, thường bằng cách truy cập cơ sở dữ liệu hoặc đặt câu hỏi."},"7466":{"word":"kính ngữ","meaning":"Cách nói chuyện sử dụng từ ngữ và cấu trúc ngữ pháp nhất định để thể hiện sự tôn trọng đối với người lớn tuổi hoặc người có địa vị cao hơn."},"7467":{"word":"bị siết cổ","meaning":"Cảm thấy bị bóp nghẹt hoặc siết chặt quanh cổ hoặc một bộ phận cơ thể khác, gây khó khăn khi thở hoặc di chuyển."},"7468":{"word":"cô đặc","meaning":"Nấu một món ăn lỏng trên lửa nhỏ trong thời gian dài để món ăn đặc lại và lượng nước giảm đi rõ rệt."},"7469":{"word":"loài","meaning":"Một nhóm sinh vật sống, như thực vật hoặc động vật, đủ giống nhau để có thể sinh sản và tạo ra con non."},"7470":{"word":"cái chuông","meaning":"Một vật thể kim loại rỗng, thường có hình cốc, tạo ra âm thanh trong trẻo, rung động khi bị đánh."},"7471":{"word":"kết thúc","meaning":"Khoảnh khắc rõ ràng khi một hoạt động hoặc quá trình ngừng hoạt động hoặc di chuyển hoàn toàn."},"7472":{"word":"nội dung thi đấu","meaning":"Một lĩnh vực hoạt động hoặc thi đấu riêng biệt trong một bộ sưu tập lớn hơn, như các môn thể thao khác nhau trong Thế vận hội."},"7473":{"word":"ga cuối","meaning":"Địa điểm cuối cùng trên một tuyến giao thông công cộng nơi tàu hoặc xe buýt kết thúc hành trình và tất cả hành khách phải xuống."},"7474":{"word":"châm ngôn","meaning":"Một cụm từ ngắn gọn, dễ nhớ mà một người dùng để đại diện cho các nguyên tắc hoặc niềm tin định hướng của họ."},"7475":{"word":"thất vọng, chán nản","meaning":"Cảm giác buồn bã, thất vọng khi không đạt được mục tiêu hoặc gặp khó khăn."},"7476":{"word":"cảm giác tội lỗi","meaning":"Cảm giác nặng nề trong lòng khi tin rằng mình đã làm điều gì sai hoặc gây hại cho người khác."},"7477":{"word":"chính, chủ yếu","meaning":"Là bộ phận quan trọng nhất, chiếm đa số hoặc có vai trò quyết định trong một tổng thể."},"7478":{"word":"cổ phiếu, cổ phần","meaning":"Một đơn vị nhỏ trong tổng số vốn của một công ty, có thể mua bán trên thị trường chứng khoán."},"7479":{"word":"giá cổ phiếu","meaning":"Số tiền được hiển thị trên thị trường tài chính để mua hoặc bán một phần nhỏ của công ty."},"7480":{"word":"nơi ở, chỗ ở, cư trú","meaning":"Tòa nhà hoặc khu vực cụ thể mà một người thường xuyên sinh sống và ngủ nghỉ."},"7481":{"word":"chi phí sinh hoạt, chi phí nhà ở","meaning":"Số tiền phải trả định kỳ cho nơi ở, bao gồm tiền thuê nhà, điện, nước và các hóa đơn khác."},"7482":{"word":"khu dân cư, nơi cư trú","meaning":"Tòa nhà, căn hộ hoặc khu vực cụ thể mà một người hoặc gia đình sinh sống ổn định."},"7483":{"word":"chủ trì, tổ chức","meaning":"Việc một cá nhân hoặc tổ chức chịu trách nhiệm chính trong việc lập kế hoạch và điều hành một sự kiện."},"7484":{"word":"chủ quan, quan điểm cá nhân","meaning":"Tính chất của suy nghĩ hoặc phán đoán một người xuất phát từ cảm xúc và cách nhìn riêng, không dựa trên sự thật khách quan."},"7485":{"word":"chu kỳ, định kỳ","meaning":"Khoảng thời gian từ khi một hiện tượng hoặc đặc điểm xuất hiện một lần cho đến khi nó tái xuất hiện lần tiếp theo."},"7486":{"word":"kỷ niệm..., tròn... năm","meaning":"Ngày đặc biệt lặp lại mỗi 12 tháng, đánh dấu một sự kiện quan trọng hoặc khởi đầu của điều gì đó."},"7487":{"word":"sự chủ đạo","meaning":"Đây là vai trò chính và tích cực mà một người hoặc nhóm đảm nhận khi bắt đầu hoặc chỉ đạo một dự án hay hành động."},"7488":{"word":"chủ động","meaning":"Từ này miêu tả người tích cực kiểm soát và chỉ đạo một hành động hoặc dự án."},"7489":{"word":"chính, chủ yếu","meaning":"Đây là việc trở thành phần quan trọng nhất hoặc lý do chính cho một điều gì đó."},"7490":{"word":"người chủ hôn","meaning":"Đây là người chủ trì và điều hành nghi lễ kết hôn, thường bằng cách nói chuyện với cô dâu chú rể và khách mời."},"7491":{"word":"dòng chính, trào lưu chính","meaning":"Đây là những ý tưởng, hoạt động hoặc cách suy nghĩ phổ biến nhất hoặc được chấp nhận rộng rãi nhất trong xã hội."},"7492":{"word":"đồ uống có cồn, rượu bia","meaning":"Đây là các loại đồ uống có chứa cồn và có thể gây say."},"7493":{"word":"nếp nhăn","meaning":"Đây là những đường gấp hoặc nếp nhỏ xuất hiện trên da của ai đó, đặc biệt là trên mặt, thường khi họ già đi."},"7494":{"word":"xoa bóp, nắn bóp","meaning":"Đây là hành động dùng tay ấn và xoa vào một bộ phận cơ thể hoặc vật liệu mềm để giảm căng thẳng hoặc tạo hình."},"7495":{"word":"đầu bếp trưởng","meaning":"Đây là người đầu bếp chính chịu trách nhiệm chuẩn bị thức ăn tại một nhà hàng."},"7496":{"word":"lương thực chính","meaning":"Đây là loại thực phẩm dinh dưỡng chính mà mọi người thường ăn với số lượng lớn, chiếm phần lớn trong các bữa ăn của họ."},"7497":{"word":"công ty cổ phần","meaning":"Đây là một tổ chức kinh doanh lớn tồn tại hợp pháp như một thực thể riêng biệt với những người sở hữu nó."},"7498":{"word":"chủ ngữ","meaning":"Đây là thành phần trong câu gọi tên người hoặc vật thực hiện hành động của động từ."},"7499":{"word":"vai chính","meaning":"Vai trò quan trọng nhất hoặc diễn viên đóng vai trò quan trọng nhất trong một tác phẩm sân khấu, điện ảnh."},"7500":{"word":"chủ nghĩa","meaning":"Hệ thống các tư tưởng, quan điểm, niềm tin làm nền tảng cho một học thuyết hoặc phong trào."},"7501":{"word":"nguyên liệu chính","meaning":"Phần quan trọng nhất hoặc chiếm tỉ lệ lớn nhất trong các thành phần dùng để tạo ra món ăn hoặc sản phẩm."},"7502":{"word":"khu dân cư","meaning":"Vùng hoặc khu vực trong thành phố mà phần lớn là nhà ở của người dân."},"7503":{"word":"khôi ngô","meaning":"Có vẻ ngoài dễ nhìn, ưa nhìn và thu hút."},"7504":{"word":"kéo co","meaning":"Một trò chơi mà hai đội kéo sợi dây dài từ hai phía đối diện, cố gắng kéo đội kia qua vạch phân định."},"7505":{"word":"nối tiếp nhau","meaning":"Theo một hàng liên tục hoặc liên tiếp mà không bị gián đoạn."},"7506":{"word":"xếp hàng","meaning":"Nhiều người hoặc vật sắp xếp thành một hàng thẳng, nối tiếp nhau."},"7507":{"word":"môi giới","meaning":"Dịch vụ giúp hai bên khác nhau đạt được thỏa thuận hoặc hoàn thành giao dịch, thường có phí."},"7508":{"word":"người môi giới","meaning":"Người trung gian giúp hai bên khác nhau đạt được thỏa thuận hoặc hoàn thành giao dịch, thường nhận tiền công."},"7509":{"word":"truyền hình trực tiếp","meaning":"Việc truyền tải hình ảnh và âm thanh trực tiếp từ một sự kiện hoặc địa điểm đến nhiều người thông qua truyền hình hoặc phát thanh."},"7510":{"word":"trung niên","meaning":"Giai đoạn cuộc đời của một người sau tuổi trẻ và trước tuổi già, thường từ khoảng 40 đến 60 tuổi."},"7511":{"word":"lược bỏ (trong văn bản)","meaning":"Hành động cố ý bỏ đi một phần văn bản hoặc lời nói."},"7512":{"word":"trung lập","meaning":"Không ủng hộ hay thiên vị bất kỳ bên nào trong tranh luận, xung đột hay tình huống."},"7513":{"word":"mai mối, làm mối","meaning":"Hoạt động giới thiệu hai người độc thân với nhau với hy vọng họ sẽ hình thành mối quan hệ hoặc kết hôn."},"7514":{"word":"trùng lặp, trùng lại","meaning":"Tình trạng một việc gì đó xuất hiện hoặc xảy ra lại y hệt, hoặc khi hai thứ bao phủ một phần của nhau."},"7515":{"word":"trung thượng (cấp)","meaning":"Một cấp độ hoặc trình độ cao hơn một chút so với cấp trung cấp."},"7516":{"word":"trung tính","meaning":"Trong hóa học, mô tả một chất hoặc dung dịch không có tính axit cũng không có tính kiềm."},"7517":{"word":"thời Trung Cổ","meaning":"Một giai đoạn lịch sử ở châu Âu kéo dài từ thế kỷ 5 đến thế kỷ 15."},"7518":{"word":"coi trọng, chú trọng","meaning":"Hành động dành sự quan tâm đặc biệt hoặc đánh giá cao một điều gì đó."},"7519":{"word":"coi trọng, xem trọng","meaning":"Hành động đối xử với một điều gì đó bằng sự cẩn trọng lớn và dành sự cân nhắc đặc biệt hơn những thứ khác."},"7520":{"word":"đình chỉ, dừng lại","meaning":"Hành động khiến một hoạt động hoặc quá trình ngừng lại, có thể là tạm thời hoặc hoàn toàn."},"7521":{"word":"khoảng (thời gian), vào khoảng","meaning":"Chỉ một khoảng thời gian gần một thời điểm hoặc sự kiện cụ thể, nhưng không chính xác tại điểm đó."},"7522":{"word":"chứng (hậu tố)","meaning":"Một dấu hiệu hoặc cảm giác thể chất trong cơ thể cho thấy một người không khỏe."},"7523":{"word":"chứng từ","meaning":"Một loại giấy tờ dùng làm bằng chứng hoặc xác nhận điều gì đó."},"7524":{"word":"sự căm ghét","meaning":"Cảm xúc rất mạnh mẽ khi ghét bỏ ai đó hoặc điều gì đó."},"7525":{"word":"giấy","meaning":"Từ dùng để chỉ loại vật liệu mỏng, phẳng, dùng để viết, in hoặc gói đồ vật."},"7526":{"word":"tạp chí","meaning":"Từ dùng để chỉ một loại sách mỏng, có bìa mềm, chứa các bài viết và hình ảnh, được xuất bản định kỳ."},"7527":{"word":"làng toàn cầu","meaning":"Khái niệm cho rằng tất cả các quốc gia và con người trên Trái Đất đều kết nối và tương tác dễ dàng, khiến thế giới như một cộng đồng nhỏ."},"7528":{"word":"buông xuống","meaning":"Một hiện tượng tự nhiên trở nên rõ ràng hoặc xuất hiện (ví dụ: mặt trời buông xuống, sương xuống)."},"7529":{"word":"phóng hỏa","meaning":"Đốt cháy một vật gì đó một cách cố ý."},"7530":{"word":"địa lý","meaning":"Khoa học nghiên cứu về các đặc điểm tự nhiên của Trái Đất và cách con người sinh sống, tương tác với các địa điểm khác nhau."},"7531":{"word":"trang báo","meaning":"Một mặt của tờ giấy trong sách, báo hoặc tài liệu in tương tự."},"7532":{"word":"địa danh","meaning":"Từ hoặc cụm từ dùng để xác định một địa điểm cụ thể như thành phố, quốc gia, núi hay sông."},"7533":{"word":"chi nhánh","meaning":"Một bộ phận nhỏ hơn của một công ty hoặc tổ chức lớn hơn, nằm ở một khu vực khác với trụ sở chính."},"7534":{"word":"trên mặt đất","meaning":"Bề mặt của Trái Đất, hoặc khu vực nằm trên mặt đất, không phải dưới lòng đất."},"7535":{"word":"sự kéo dài, sự tiếp diễn","meaning":"Hành động một việc gì đó tiếp tục diễn ra hoặc tồn tại mà không dừng lại trong một khoảng thời gian."},"7536":{"word":"liên tục, kéo dài","meaning":"Diễn ra hoặc tồn tại không có bất kỳ gián đoạn nào trong một khoảng thời gian."},"7537":{"word":"chỉ số","meaning":"Con số cho biết mức độ thay đổi của một điều gì đó, ví dụ như giá cả hay nhiệt độ, so với một thời điểm trước đó."},"7538":{"word":"sự trì hoãn, sự chậm trễ","meaning":"Tình huống một sự kiện hay hành động bắt đầu hoặc xảy ra muộn hơn so với kế hoạch."},"7539":{"word":"đơn đăng ký, đơn xin","meaning":"Tài liệu bằng giấy hoặc kỹ thuật số mà một người điền vào để chính thức yêu cầu một công việc, nhập học hoặc những thứ tương tự."},"7540":{"word":"người đăng ký, người ứng tuyển","meaning":"Người điền đơn để chính thức yêu cầu một công việc, nhập học hoặc những thứ tương tự."},"7541":{"word":"sự cản trở, sự trở ngại","meaning":"Điều gì đó làm chặn đường hoặc làm chậm tiến độ, khiến một hành động hoặc sự kiện khó hoàn thành."},"7542":{"word":"chi nhánh","meaning":"Một tòa nhà vật lý cụ thể hoặc một địa điểm được thành lập nơi một tổ chức hoặc doanh nghiệp lớn hơn thực hiện các hoạt động của mình cách xa trụ sở chính."},"7543":{"word":"điểm, vị trí","meaning":"Một dấu hiệu cụ thể hoặc một khu vực nhỏ có thể nhìn thấy hoặc xác định trong không gian, hoặc một khoảnh khắc cụ thể trong thời gian."},"7544":{"word":"sự ủng hộ, sự hỗ trợ","meaning":"Những hành động thể hiện sự tán thành hoặc giúp đỡ dành cho một người, ý tưởng hoặc nhóm, chẳng hạn như bỏ phiếu hoặc cung cấp nguồn lực."},"7545":{"word":"chỉ số, chỉ thị","meaning":"Một dấu hiệu rõ ràng hoặc con số cụ thể cho thấy sự hiện diện, tình trạng hoặc tiến độ của một điều gì đó khác."},"7546":{"word":"địa hình","meaning":"Các đặc điểm tự nhiên của một khu vực đất đai, như đồi, thung lũng hoặc sự bằng phẳng của nó."},"7547":{"word":"Chức vụ, vị trí","meaning":"Một loại công việc cụ thể hoặc vai trò chính thức mà một người đảm nhận trong một tổ chức."},"7548":{"word":"Trực tiếp, thẳng thắn","meaning":"Mô tả cách nói chuyện hoặc hành động mà một người bày tỏ suy nghĩ một cách thẳng thắn, không do dự hay phức tạp."},"7549":{"word":"Chức vụ, cấp bậc","meaning":"Vị trí xã hội, hành chính được giao cho một người dựa trên nhiệm vụ và trách nhiệm trong công việc của họ."},"7550":{"word":"Ngay trước đó, ngay trước khi","meaning":"Khoảnh khắc chính xác hoặc một khoảng thời gian rất ngắn xảy ra ngay trước khi một sự kiện bắt đầu hoặc một hành động diễn ra."},"7551":{"word":"Ngành nghề, loại hình công việc","meaning":"Một loại hình công việc rộng lớn bao gồm nhiều loại hình nghề nghiệp cụ thể, thường có nhiệm vụ, kỹ năng hoặc đào tạo tương tự."},"7552":{"word":"Máy hút bụi","meaning":"Một thiết bị điện có ống và động cơ dùng để hút bụi và các mảnh vụn nhỏ từ thảm và sàn nhà."},"7553":{"word":"Thăng cấp, thăng chức","meaning":"Hành động chuyển lên một cấp bậc cao hơn hoặc một vị trí chính thức quan trọng hơn trong một công ty hoặc tổ chức."},"7554":{"word":"Mồ hôi lạnh","meaning":"Những giọt mồ hôi xuất hiện trên da, đặc biệt là trên trán, thường do lo lắng, sợ hãi hoặc nỗ lực cực độ, chứ không phải do nóng."},"7555":{"word":"Khám bệnh, điều trị","meaning":"Các hành động được thực hiện bởi bác sĩ hoặc chuyên gia y tế để khám, chẩn đoán và giúp người bệnh hoặc người bị thương hồi phục sức khỏe."},"7556":{"word":"Bữa tiệc thịnh soạn, mâm cao cỗ đầy","meaning":"Một bữa ăn lớn, ấn tượng với nhiều món ăn ngon, thường được dùng trong các dịp lễ đặc biệt."},"7557":{"word":"Phe, trận doanh, phe phái","meaning":"Một nhóm người có cùng niềm tin hoặc mục tiêu, thường đứng về một phía trong một cuộc tranh cãi hoặc vấn đề chính trị."},"7558":{"word":"Xâm nhập, tiến vào, đi vào","meaning":"Hành động di chuyển vào hoặc đến một nơi, hoặc thời điểm bắt đầu tham gia vào một việc gì đó."},"7559":{"word":"sự chân thành","meaning":"Sự thật lòng, không giả dối trong lời nói hay hành động."},"7560":{"word":"bữa cơm (kính ngữ)","meaning":"Từ dùng để chỉ bữa ăn một cách kính trọng, đặc biệt là bữa ăn của người lớn tuổi hoặc cấp trên."},"7561":{"word":"sự tiến hóa","meaning":"Quá trình thay đổi và phát triển dần dần của sinh vật qua hàng triệu năm."},"7562":{"word":"bùn","meaning":"Đất mềm, ướt và dính, thường có sau mưa hoặc gần nguồn nước."},"7563":{"word":"dai","meaning":"Chỉ thức ăn khó nhai hoặc vật liệu bền, khó đứt, khó hỏng."},"7564":{"word":"chán ngán","meaning":"Cảm thấy mệt mỏi hoặc không còn hứng thú với điều gì đó vì đã trải nghiệm quá nhiều."},"7565":{"word":"về chất lượng","meaning":"Liên quan đến chất lượng, loại hình hoặc đặc tính của cái gì đó, không phải số lượng."},"7566":{"word":"bệnh tật","meaning":"Tình trạng cơ thể hoặc tâm trí hoạt động không bình thường, thường có các triệu chứng cụ thể."},"7567":{"word":"giá nhà","meaning":"Số tiền cần thiết để mua một căn nhà ở."},"7568":{"word":"tập thể","meaning":"Chỉ hành động hoặc nỗ lực được thực hiện bởi tất cả các thành viên của một nhóm cùng nhau."},"7569":{"word":"sự tập trung","meaning":"Khả năng dồn hết sự chú ý vào một công việc hoặc suy nghĩ cụ thể mà không bị sao nhãng."},"7570":{"word":"từng nhà","meaning":"Chỉ tất cả các ngôi nhà riêng lẻ, thường được xem xét hoặc ghé thăm từng cái một."},"7571":{"word":"ám ảnh","meaning":"Tình trạng tâm trí bị một điều gì đó thu hút hoàn toàn, không thể thoát ra được."},"7572":{"word":"đè nén","meaning":"Đặt trọng lượng hoặc lực từ trên xuống, khiến một vật bị ép chặt xuống."},"7573":{"word":"bị chà đạp","meaning":"Một vật hoặc người bị chân dẫm đạp nhiều lần, thường gây hư hại hoặc làm bẹp."},"7574":{"word":"ghê tởm","meaning":"Miêu tả điều gì đó trông hoặc cảm thấy rất khó chịu, gây cảm giác ghê sợ hoặc buồn nôn."},"7575":{"word":"phấn khích; tê rần","meaning":"Miêu tả cảm giác hưng phấn mạnh mẽ đột ngột hoặc cảm giác nhói, tê rần như điện giật."},"7576":{"word":"tình yêu đơn phương","meaning":"Tình cảm lãng mạn một phía, khi một người yêu thích người khác nhưng không được đáp lại."},"7577":{"word":"mằn mặn","meaning":"Miêu tả hương vị hơi mặn một cách dễ chịu, thường làm cho món ăn thêm đậm đà."},"7578":{"word":"chia tách","meaning":"Chia một vật thành hai hoặc nhiều mảnh riêng biệt, thường bằng cách tác động lực hoặc kéo ra."},"7579":{"word":"mổ","meaning":"Hành động chim dùng mỏ đập nhanh và liên tục vào vật gì đó, thường để ăn hoặc làm vỡ bề mặt."},"7580":{"word":"mẩu giấy","meaning":"Một mảnh giấy nhỏ dùng để ghi chú hoặc nhắn tin."},"7581":{"word":"tặc lưỡi","meaning":"Âm thanh tạo ra bằng cách tặc lưỡi, thể hiện sự không đồng tình, thương hại hoặc hối tiếc."},"7582":{"word":"cặn bã","meaning":"Phần vật chất còn sót lại ở đáy khi chất lỏng đã được loại bỏ hoặc lọc."},"7583":{"word":"Món hấp","meaning":"Một món ăn được chế biến bằng cách ướp gia vị thịt hoặc rau củ rồi hấp hoặc luộc với một lượng nhỏ nước."},"7584":{"word":"Phòng xông hơi công cộng","meaning":"Nơi có các phòng xông hơi truyền thống và tiện nghi giải trí khác, cho phép khách đến đổ mồ hôi và thư giãn."},"7585":{"word":"Nhói, tê buốt","meaning":"Diễn tả cảm giác buốt nhói, tê rần hoặc cay xè (thường ở mũi khi sắp khóc hoặc xúc động mạnh)."},"7586":{"word":"Bị xé, bị rách","meaning":"Tình trạng một vật liệu như vải hoặc giấy bị kéo đứt hoặc cắt thô bạo, tạo ra một lỗ hở với các cạnh lởm chởm."},"7587":{"word":"Khác biệt, chênh lệch","meaning":"Sự đối lập rõ rệt hoặc đặc điểm riêng biệt khi so sánh hai hoặc nhiều vật phẩm hoặc phẩm chất."},"7588":{"word":"Từng bước, từ từ cẩn thận","meaning":"Mô tả một hành động được thực hiện chậm rãi và cẩn thận, theo một trình tự rõ ràng từng phần một, không vội vàng."},"7589":{"word":"Chặn, ngăn chặn","meaning":"Hành động ngăn cản điều gì đó đi qua hoặc đến một nơi, thường bằng cách đặt một vật cản trên đường đi của nó."},"7590":{"word":"Lễ cúng tổ tiên","meaning":"Nghi lễ truyền thống của Hàn Quốc để tưởng nhớ tổ tiên đã khuất."},"7591":{"word":"Trang phục, phục trang","meaning":"Bộ quần áo và phụ kiện mà một người đang mặc, tạo nên vẻ ngoài tổng thể của họ."},"7592":{"word":"Sự khác biệt hóa","meaning":"Hành động làm cho một thứ trở nên khác biệt hoặc tách biệt rõ ràng so với những thứ cùng loại, thường để làm nổi bật các đặc điểm độc đáo của nó."},"7593":{"word":"Điềm tĩnh, bình tĩnh","meaning":"Diễn tả một người hoặc một tình huống ít chuyển động, âm thanh nhẹ nhàng và có bầu không khí yên bình."},"7594":{"word":"Một cách điềm tĩnh, bình thản","meaning":"Làm điều gì đó một cách ổn định, không vội vàng và không bộc lộ cảm xúc mạnh mẽ."},"7595":{"word":"phó phòng","meaning":"Người giữ chức vụ dưới cấp trưởng phòng, ban trong một cơ quan, công ty."},"7596":{"word":"phần","meaning":"Phần hoặc món đồ được dành riêng hoặc thuộc về một người hay nhóm cụ thể."},"7597":{"word":"việc đeo/mặc","meaning":"Hành động mặc quần áo, đeo thiết bị hoặc phụ kiện lên người."},"7598":{"word":"tách","meaning":"Từ mô phỏng tiếng kêu nhanh, sắc gọn như tiếng máy ảnh chụp hoặc khi hai vật cứng chạm vào nhau."},"7599":{"word":"chân-","meaning":"Tiếp đầu ngữ dùng để chỉ sự vật là thật, nguyên bản hoặc chính gốc, không giả mạo."},"7600":{"word":"người tham gia","meaning":"Người tham gia vào một sự kiện, hoạt động hoặc cuộc thi nào đó."},"7601":{"word":"tinh túy","meaning":"Bản chất hoặc giá trị đặc biệt, đáng thưởng thức nhất của một điều gì đó."},"7602":{"word":"chim sẻ","meaning":"Một loài chim nhỏ có lưng màu nâu và ngực màu trắng xám, thường sống gần khu dân cư."},"7603":{"word":"mới mẻ","meaning":"Diễn tả một ý tưởng, vật phẩm hoặc cách làm rất mới mẻ, độc đáo và chưa từng gặp trước đây."},"7604":{"word":"sự kiên nhẫn","meaning":"Khả năng chờ đợi lâu hoặc chịu đựng những tình huống khó khăn mà không thể hiện sự bực bội."},"7605":{"word":"cá ngừ","meaning":"Một loài cá biển lớn có lưng màu xanh, thịt đỏ đậm thường được đóng hộp hoặc dùng làm món gỏi."},"7606":{"word":"gạo nếp","meaning":"Một loại gạo màu trắng, hạt nhỏ, khi nấu chín sẽ trở nên rất dính và dẻo."},"7607":{"word":"khởi nghiệp","meaning":"Việc bắt đầu và thành lập một công ty, tổ chức hoặc dự án kinh doanh mới."},"7608":{"word":"óc sáng tạo","meaning":"Khả năng của một người trong việc hình thành những ý tưởng, giải pháp hoặc sản phẩm mới mẻ, độc đáo."},"7609":{"word":"sáng tạo","meaning":"Có tính chất mới lạ, độc đáo và thể hiện trí tưởng tượng phong phú."},"7610":{"word":"có tính sáng tạo","meaning":"Hoàn toàn mới mẻ, nguyên bản, được tạo ra từ trí tưởng tượng và không giống bất cứ thứ gì đã từng tồn tại."},"7611":{"word":"tìm đến","meaning":"Di chuyển đến một nơi nào đó rồi ở lại và ổn định trong một khoảng thời gian."},"7612":{"word":"căn","meaning":"Từ dùng để đếm số lượng nhà cửa, tòa nhà."},"7613":{"word":"ăn chay","meaning":"Chế độ ăn uống chỉ bao gồm thực vật, trái cây, ngũ cốc, hạt và các sản phẩm từ sữa, tránh tất cả thịt và cá."},"7614":{"word":"tuyển dụng","meaning":"Hành động tìm kiếm và lựa chọn những người phù hợp để làm việc cho một công ty hoặc tổ chức."},"7615":{"word":"trò chuyện trực tuyến","meaning":"Hoạt động gửi và nhận tin nhắn văn bản giữa nhiều người thông qua mạng internet một cách tức thời."},"7616":{"word":"biện pháp","meaning":"Một hành động hoặc phương pháp cụ thể được nghĩ ra và thực hiện để giải quyết vấn đề hoặc đạt được mục tiêu."},"7617":{"word":"sách nhỏ","meaning":"Một ấn phẩm in ấn có ít trang, thường dùng để cung cấp thông tin hoặc hướng dẫn."},"7618":{"word":"bộ phận","meaning":"Một đơn vị hoặc bộ phận hành chính cụ thể trong một tổ chức lớn, chịu trách nhiệm về các nhiệm vụ hoặc chức năng nhất định."},"7619":{"word":"xử lý, giải quyết","meaning":"Hành động giải quyết hoặc xử lý một người, sự vật hoặc tình huống."},"7620":{"word":"trơn tru, thuận lợi","meaning":"Diễn tả một hành động xảy ra nhanh chóng, dễ dàng và không gặp bất kỳ trở ngại nào."},"7621":{"word":"nghìn, ngàn","meaning":"Số lượng bằng mười lần một trăm, được biểu thị bằng các chữ số '1000'."},"7622":{"word":"duyên trời định, lương duyên","meaning":"Hai người có tính cách và hoàn cảnh hòa hợp hoàn hảo đến mức dường như họ định mệnh phải ở bên nhau."},"7623":{"word":"tự nhiên","meaning":"Trạng thái tự nhiên của một sự vật mà không có sự nhân tạo."},"7624":{"word":"đa dạng, muôn hình vạn trạng","meaning":"Chỉ một tập hợp lớn các mặt hàng hoặc loại mà tất cả đều khác biệt rõ rệt theo nhiều cách."},"7625":{"word":"sắt","meaning":"Một kim loại phổ biến, màu xám bạc, bị nam châm hút và bị gỉ sét khi tiếp xúc với nước."},"7626":{"word":"triệt để, kỹ lưỡng","meaning":"Phẩm chất thực hiện điều gì đó với sự cẩn thận tối đa và chú ý đến từng chi tiết nhỏ, đảm bảo không bỏ sót điều gì."},"7627":{"word":"triết học","meaning":"Ngành học thuật nghiên cứu các câu hỏi cơ bản về cuộc sống, thực tại, kiến thức, đạo đức và sự tồn tại của con người."},"7628":{"word":"nhà triết học","meaning":"Người nghiên cứu sâu sắc và viết về các câu hỏi cơ bản liên quan đến cuộc sống, kiến thức và sự tồn tại."},"7629":{"word":"mang tính triết học, triết lý","meaning":"Mô tả một điều gì đó liên quan đến suy nghĩ sâu sắc về ý nghĩa cuộc sống, kiến thức hoặc sự tồn tại của con người."},"7630":{"word":"thêm vào, bổ sung","meaning":"Hành động cho thêm một thứ gì đó vào một thứ khác, ví dụ như thêm nguyên liệu vào thức ăn."},"7631":{"word":"lời chào đầu tiên","meaning":"Những lời nói hoặc hành động lịch sự để chào hỏi nhau khi gặp mặt lần đầu tiên."},"7632":{"word":"chuyến xe/tàu đầu tiên","meaning":"Chuyến xe buýt hoặc tàu hỏa công cộng chạy sớm nhất vào buổi sáng."},"7633":{"word":"thính giác","meaning":"Khả năng tiếp nhận âm thanh qua tai của người hoặc động vật."},"7634":{"word":"yêu cầu thanh toán, đòi tiền","meaning":"Hành động yêu cầu chính thức ai đó trả tiền cho thứ họ đã nhận hoặc sử dụng."},"7635":{"word":"màu xanh lam, màu xanh","meaning":"Màu của bầu trời quang đãng hoặc biển."},"7636":{"word":"người nghe, thính giả","meaning":"Người lắng nghe, đặc biệt là một chương trình phát thanh hoặc podcast."},"7637":{"word":"tuổi trẻ, thanh xuân","meaning":"Giai đoạn còn trẻ của cuộc đời."},"7638":{"word":"thính giả, người nghe","meaning":"Người theo dõi và lắng nghe các chương trình phát thanh hoặc podcast."},"7639":{"word":"-thể, tập thể, tổ chức","meaning":"Một hậu tố thêm vào sau một từ để chỉ một nhóm có tổ chức hoặc một thực thể có cấu trúc rõ ràng."},"7640":{"word":"cảm nhận thực tế, cảm giác chủ quan","meaning":"Cách một người cảm nhận một điều kiện vật lý, như nhiệt độ, bằng các giác quan của chính mình, có thể khác với số đo thực tế."},"7641":{"word":"vóc dáng, thể trạng","meaning":"Hình dáng và kích thước tổng thể của cơ thể một người."},"7642":{"word":"có hệ thống, một cách có hệ thống","meaning":"Diễn tả một việc gì đó được thực hiện một cách rất có tổ chức và trật tự, thường theo các bước hoặc quy tắc cụ thể."},"7643":{"word":"sự cam chịu","meaning":"Trạng thái chấp nhận một hoàn cảnh khó khăn mà bản thân không thể thay đổi, thường thể hiện bằng việc ngừng mọi nỗ lực."},"7644":{"word":"sự lưu trú","meaning":"Việc ở lại một địa điểm hoặc quốc gia nước ngoài trong một khoảng thời gian nhất định, không nhằm mục đích định cư vĩnh viễn."},"7645":{"word":"giáo dục thể chất","meaning":"Môn học ở trường giúp học sinh học và thực hành các môn thể thao, bài tập nhằm phát triển cơ thể khỏe mạnh."},"7646":{"word":"chứng khó tiêu","meaning":"Trong y học phương Đông, đây là triệu chứng khó tiêu hóa thức ăn."},"7647":{"word":"cơ địa","meaning":"Đặc điểm tự nhiên của cơ thể một người, quyết định cách nó phản ứng với thức ăn, môi trường hoặc bệnh tật khác nhau."},"7648":{"word":"kiểm tra","meaning":"Hành động xem xét một cái gì đó hoặc ai đó để xác nhận sự hiện diện hoặc tính đúng đắn, thường bằng cách đánh dấu vào danh sách."},"7649":{"word":"dáng người","meaning":"Hình dạng hoặc đường nét tổng thể của cấu trúc cơ thể một người."},"7650":{"word":"nến","meaning":"Vật làm bằng sáp có sợi bấc ở giữa, dùng để thắp sáng khi sợi bấc được đốt cháy."},"7651":{"word":"siêu tốc độ","meaning":"Đặc điểm của cái gì đó di chuyển hoặc xảy ra cực kỳ nhanh, với tốc độ vượt xa mức bình thường."},"7652":{"word":"sự vượt quá","meaning":"Trạng thái khi một lượng hoặc số lượng nào đó lớn hơn mức cho phép hoặc mong đợi."},"7653":{"word":"người đứng đầu tiên","meaning":"Chỉ cá nhân giữ một vị trí cụ thể ngay từ đầu, trước bất kỳ ai khác."},"7654":{"word":"tiểu học","meaning":"Cấp độ giáo dục cơ bản dành cho trẻ em nhỏ, thường từ 6 đến 12 tuổi, trước khi vào cấp hai."},"7655":{"word":"tồi tàn, luộm thuộm","meaning":"Có vẻ ngoài cũ kỹ, rách nát, bẩn thỉu, thường gợi lên sự nghèo khó hoặc không được chăm chút."},"7656":{"word":"lần đầu gặp","meaning":"Lần đầu tiên hai người hoặc nhiều người gặp gỡ và nói chuyện với nhau."},"7657":{"word":"tang lễ","meaning":"Nghi thức được tổ chức cho người đã qua đời, nơi mọi người tập trung để tưởng nhớ và bày tỏ sự đau buồn sâu sắc."},"7658":{"word":"đầu tháng","meaning":"Những ngày đầu tiên của một tháng bất kỳ, thường là mười ngày đầu."},"7659":{"word":"thảo nguyên, đồng cỏ","meaning":"Một vùng đất rộng lớn, mở, chủ yếu được bao phủ bởi cỏ tự nhiên và có rất ít hoặc không có cây cối."},"7660":{"word":"chuông cửa","meaning":"Thiết bị gắn cạnh lối vào của một tòa nhà, phát ra âm thanh khi ai đó nhấn nút, báo cho người bên trong biết có người bên ngoài."},"7661":{"word":"tổng- (tiền tố)","meaning":"Một phần từ thêm vào đầu một từ khác để chỉ rằng cái gì đó bao gồm tất cả hoặc phụ trách tất cả."},"7662":{"word":"đàn ông độc thân","meaning":"Một người đàn ông trưởng thành chưa kết hôn."},"7663":{"word":"hiệu trưởng đại học","meaning":"Chức vụ cao nhất lãnh đạo và quản lý một trường đại học hoặc tổ chức giáo dục cấp cao."},"7664":{"word":"tối- (tiền tố)","meaning":"Một phần từ thêm vào đầu một từ khác để chỉ rằng nó ở mức độ cao nhất."},"7665":{"word":"mạnh nhất, vô địch","meaning":"Người, đội hoặc vật thể thể hiện sức mạnh, lực lượng hoặc khả năng lớn nhất so với tất cả những người/vật khác."},"7666":{"word":"sự giảm thiểu","meaning":"Hành động làm giảm số lượng, kích thước hoặc tác động của một cái gì đó để nó trở nên nhỏ nhất hoặc ít nhất có thể."},"7667":{"word":"mẫu mới nhất","meaning":"Là sản phẩm được thiết kế và sản xuất gần đây nhất với những tính năng tiên tiến."},"7668":{"word":"xuất sắc nhất","meaning":"Người hoặc vật được công nhận là có chất lượng, hiệu suất hoặc kỹ năng cao nhất trong một nhóm."},"7669":{"word":"theo đuổi","meaning":"Hành động chủ động cố gắng đạt được mục tiêu hoặc giành được thứ gì đó mong muốn."},"7670":{"word":"sự rơi","meaning":"Hành động rơi từ một nơi cao xuống."},"7671":{"word":"xu hướng","meaning":"Hướng phát triển hoặc thay đổi chung của tình hình, sự kiện hoặc con số theo thời gian."},"7672":{"word":"thu hoạch","meaning":"Hành động thu gom ngũ cốc, nông sản chín từ ruộng đồng vào mùa thu."},"7673":{"word":"tái bút","meaning":"Một tin nhắn hoặc ghi chú bổ sung được viết ở cuối thư sau khi người gửi đã ký tên."},"7674":{"word":"rút thăm","meaning":"Quá trình chọn người thắng cuộc hoặc người tham gia một cách ngẫu nhiên từ nhiều lựa chọn khả thi."},"7675":{"word":"phúc lành","meaning":"Một sự kiện tích cực đặc biệt, một món quà chào mừng hoặc một tình huống hạnh phúc mang lại niềm vui, thành công hoặc sự bảo vệ."},"7676":{"word":"sản phẩm chăn nuôi","meaning":"Các mặt hàng như thịt, sữa, trứng hoặc len thu được từ động vật nuôi trong trang trại."},"7677":{"word":"ngành chăn nuôi","meaning":"Ngành công nghiệp sản xuất sản phẩm bằng cách chế biến nguyên liệu thu được từ việc chăn nuôi gia súc."},"7678":{"word":"xuất bản","meaning":"Hành động làm cho một cuốn sách, tạp chí hoặc tác phẩm viết khác có sẵn cho mọi người mua hoặc đọc."},"7679":{"word":"rút tiền","meaning":"Việc lấy tiền ra khỏi tài khoản ngân hàng hoặc tổ chức tài chính khác."},"7680":{"word":"đầu ra","meaning":"Thông tin, dữ liệu hoặc kết quả vật lý được tạo ra bởi máy tính hoặc thiết bị."},"7681":{"word":"tỷ lệ sinh","meaning":"Thống kê cho biết số lượng trẻ em được sinh ra trong một khu vực nhất định trong một khoảng thời gian."},"7682":{"word":"sự ra đời","meaning":"Sự kiện một em bé được sinh ra từ cơ thể mẹ và bắt đầu cuộc sống."},"7683":{"word":"ra mắt","meaning":"Việc một sản phẩm mới được giới thiệu và đưa ra thị trường để mọi người mua."},"7684":{"word":"cửa ra vào","meaning":"Một cửa hoặc lối đi trong tòa nhà, phòng hoặc hàng rào mà mọi người dùng để đi vào hoặc đi ra."},"7685":{"word":"tham gia thi đấu","meaning":"Việc một vận động viên hoặc đội chính thức tham gia vào một trận đấu thể thao, cuộc thi hoặc sự kiện."},"7686":{"word":"nguồn gốc","meaning":"Nơi hoặc đối tượng mà thông tin hoặc một vật gì đó lần đầu tiên đến từ đó."},"7687":{"word":"hơi đói","meaning":"Cảm giác đói nhẹ trong bụng, báo hiệu đã đến lúc cần ăn một chút gì đó."},"7688":{"word":"nhà xuất bản","meaning":"Một tổ chức chuyên in ấn và phát hành sách, tạp chí hoặc báo cho công chúng."},"7689":{"word":"sự bốc đồng","meaning":"Một cảm giác mạnh mẽ, đột ngột khiến ai đó muốn làm điều gì đó ngay lập tức mà không suy nghĩ nhiều."},"7690":{"word":"sự trung thành","meaning":"Hành vi thể hiện sự cam kết và đáng tin cậy bền vững đối với một người, một ý tưởng hoặc một nhiệm vụ."},"7691":{"word":"sạc điện","meaning":"Hành động cấp điện cho thiết bị điện tử để làm đầy pin."},"7692":{"word":"sự thỏa mãn","meaning":"Trạng thái một người cảm thấy hài lòng vì một nhu cầu, mong muốn hoặc kỳ vọng đã được đáp ứng đầy đủ."},"7693":{"word":"sâu răng","meaning":"Bệnh răng bị hỏng do vi khuẩn gây ra, trông như bị côn trùng ăn."},"7694":{"word":"sung huyết (mắt)","meaning":"Tình trạng lòng trắng mắt chuyển sang màu đỏ do nhiều mạch máu nhỏ hiện rõ."},"7695":{"word":"sự xử lý","meaning":"Cách một người chạm, di chuyển hoặc tương tác với một vật thể, thường thể hiện sự cẩn thận."},"7696":{"word":"sự giành được","meaning":"Hành động chính thức có được hoặc nhận được thứ gì đó như kỹ năng, giấy phép hoặc tài sản."},"7697":{"word":"việc nấu ăn","meaning":"Hành động chuẩn bị và nấu thức ăn."},"7698":{"word":"tỉ lệ có việc làm","meaning":"Con số, thường là phần trăm, cho thấy số người có việc làm được trả lương trong một nhóm cụ thể."},"7699":{"word":"thực hiện","meaning":"Hành động tiến hành hoặc lựa chọn một điều gì đó, như nghỉ ngơi hay một tư thế."},"7700":{"word":"tầng, lớp (hậu tố)","meaning":"Một phân đoạn của xã hội hoặc một bộ phận trong một nhóm, thường được hình dung như các lớp ngang."},"7701":{"word":"kéo, vén","meaning":"Hành động di chuyển rèm cửa để che hoặc mở cửa sổ."},"7702":{"word":"coi là, xem là","meaning":"Hành động xem xét hoặc công nhận điều gì đó có chất lượng hoặc giá trị cao nhất có thể."},"7703":{"word":"tỉ mỉ, kỹ lưỡng","meaning":"Rất cẩn thận, chính xác và chú ý đến từng chi tiết nhỏ, không bỏ sót điều gì."},"7704":{"word":"răng","meaning":"Bộ phận cứng màu trắng nằm bên trong miệng, dùng để cắn và nhai thức ăn."},"7705":{"word":"đau răng","meaning":"Cảm giác đau đớn hoặc khó chịu ở một hoặc nhiều chiếc răng."},"7706":{"word":"cảm giác thân thuộc","meaning":"Cảm giác dễ chịu khi nhận ra ai đó hoặc điều gì đó quen thuộc, khiến mình thoải mái."},"7707":{"word":"thân thuộc, thân cận","meaning":"Có mối liên kết dễ chịu và thoải mái với ai đó hoặc điều gì đó, như đã quen biết từ lâu."},"7708":{"word":"sự thân mật, thân tình","meaning":"Mối liên kết sâu sắc và ấm áp giữa người với người, thường bao gồm việc chia sẻ suy nghĩ, cảm xúc và kinh nghiệm."},"7709":{"word":"cảm giác thân mật","meaning":"Cảm giác kết nối sâu sắc và thoải mái với người khác, cho phép dễ dàng tin tưởng và chia sẻ suy nghĩ."},"7710":{"word":"tình bạn, mối quan hệ","meaning":"Mối liên kết xã hội giữa những người quen biết nhau, có thể nhẹ nhàng hoặc rất bền chặt."},"7711":{"word":"họ hàng, người thân","meaning":"Người có quan hệ huyết thống gần gũi, thường có cùng họ với mình."},"7712":{"word":"người thân, bạn bè, thân hữu","meaning":"Những người có quan hệ họ hàng hoặc quen biết cá nhân với mình."},"7713":{"word":"thân thiện với môi trường","meaning":"Được thiết kế để bảo vệ môi trường tự nhiên và sinh vật, gây ra ít thiệt hại nhất cho hành tinh."},"7714":{"word":"sơn, quét, tô","meaning":"Phủ một chất lỏng, thường để tạo màu hoặc bảo vệ, lên một bề mặt bằng cọ hoặc dụng cụ khác."},"7715":{"word":"xâm lược","meaning":"Hành động quân sự dùng vũ lực chiếm đóng lãnh thổ nước khác một cách trái phép."},"7716":{"word":"ngập lụt","meaning":"Hiện tượng nước dâng cao, tràn vào làm ngập một khu vực, nhà cửa, đường xá."},"7717":{"word":"bình tĩnh","meaning":"Trạng thái giữ được sự bình tĩnh, điềm đạm, không hoảng loạn hay mất kiểm soát cảm xúc khi gặp tình huống khó khăn."},"7718":{"word":"trì trệ","meaning":"Tình trạng hoạt động hoặc phát triển chậm lại, đình trệ, không có tiến triển hay cải thiện, thường dùng cho kinh tế, xã hội."},"7719":{"word":"xâm phạm","meaning":"Hành động làm tổn hại hoặc hạn chế một cách trái phép các quyền, sự riêng tư hoặc tự do của người khác."},"7720":{"word":"caffeine","meaning":"Chất hóa học có trong cà phê, trà và một số đồ uống khác, có tác dụng kích thích giúp cơ thể tỉnh táo và tăng năng lượng."},"7721":{"word":"chuyên mục","meaning":"Một bài viết ngắn bình luận về một chủ đề nhất định, thường xuất hiện định kỳ trên báo, tạp chí."},"7722":{"word":"calo","meaning":"Đơn vị đo lường năng lượng mà thực phẩm cung cấp cho cơ thể con người."},"7723":{"word":"khuôn viên","meaning":"Toàn bộ khu vực đất đai và các công trình kiến trúc của một trường đại học, cao đẳng hoặc trường học."},"7724":{"word":"cặp đôi","meaning":"Hai người có mối quan hệ tình cảm, hoặc một cặp vật dụng đi cùng nhau, hợp nhau."},"7725":{"word":"cholesterol","meaning":"Một chất béo có trong các tế bào hoặc máu của động vật, nếu vượt quá mức cho phép có thể gây xơ vữa động mạch."},"7726":{"word":"mặc cảm","meaning":"Cảm giác tự ti, lo lắng hoặc xấu hổ sâu sắc về một khuyết điểm nào đó của bản thân."},"7727":{"word":"sống mũi","meaning":"Đây là phần cứng phía trên của mũi, nằm giữa hai mắt."},"7728":{"word":"hoạt bát","meaning":"Chỉ tính cách tươi sáng, vui tươi, thường thể hiện sự hạnh phúc qua nụ cười và hành động năng động."},"7729":{"word":"câu đố","meaning":"Một bài kiểm tra kiến thức ngắn, thường không chính thức, gồm các câu hỏi cần được trả lời."},"7730":{"word":"lễ lạy sâu","meaning":"Đây là một cử chỉ truyền thống của người Hàn Quốc thể hiện sự tôn trọng, trong đó người ta quỳ xuống và cúi đầu thật thấp sát đất."},"7731":{"word":"khá lớn","meaning":"Chỉ kích thước khá lớn, dễ nhận thấy nhưng không nhất thiết là khổng lồ."},"7732":{"word":"đục","meaning":"Chỉ trạng thái không trong, mờ đục, thường dùng để miêu tả nước hoặc không khí."},"7733":{"word":"nước ngọt có ga","meaning":"Một loại đồ uống dạng lỏng có nhiều bong bóng nhỏ bên trong, tạo ra tiếng xì khi mở hoặc rót."},"7734":{"word":"tinh bột","meaning":"Một chất dinh dưỡng, thường có trong thực phẩm như bánh mì trắng, gạo hoặc mì ống, mà cơ thể sử dụng để tạo năng lượng."},"7735":{"word":"mặt nạ","meaning":"Vật làm bằng gỗ hoặc vải, đeo lên mặt để che giấu hoặc thay đổi diện mạo."},"7736":{"word":"sự cố","meaning":"Một vấn đề hoặc lỗi không mong muốn khiến cái gì đó bị hỏng, trục trặc hoặc không hoạt động như dự kiến."},"7737":{"word":"bị loại","meaning":"Hành động bị loại khỏi một cuộc thi hoặc quá trình tuyển chọn vì không đáp ứng các tiêu chuẩn yêu cầu."},"7738":{"word":"rụng tóc","meaning":"Tình trạng tóc rụng khỏi đầu một người, đôi khi tạo ra những mảng trống rõ ràng trên da đầu."},"7739":{"word":"phòng thử đồ","meaning":"Một không gian nhỏ kín đáo trong cửa hàng hoặc nơi công cộng để thay hoặc mặc quần áo riêng tư."},"7740":{"word":"múa mặt nạ truyền thống (Hàn Quốc)","meaning":"Một loại hình nghệ thuật biểu diễn truyền thống của Hàn Quốc, trong đó người biểu diễn đeo mặt nạ đặc biệt và nhảy theo nhạc."},"7741":{"word":"rút khỏi, từ bỏ (tư cách thành viên)","meaning":"Hành động chính thức rời khỏi một nhóm, câu lạc bộ hoặc tổ chức mà mình đã từng là thành viên."},"7742":{"word":"tìm kiếm, thăm dò","meaning":"Hành động dò xét và tìm kiếm để khám phá một vật thể hoặc hiện tượng chưa biết."},"7743":{"word":"thám hiểm","meaning":"Hoạt động đi đến những vùng đất xa lạ để tìm hiểu, khám phá những điều mới mẻ."},"7744":{"word":"lỗi, do, tại","meaning":"Lý do hoặc nguyên nhân được đưa ra cho một tình huống xấu, thường ngụ ý rằng người hoặc vật khác phải chịu trách nhiệm."},"7745":{"word":"giấc mơ báo hiệu mang thai","meaning":"Giấc mơ sống động được tin trong văn hóa Hàn Quốc là điềm báo một người phụ nữ sắp có con."},"7746":{"word":"thai nhi","meaning":"Em bé chưa sinh đang phát triển bên trong cơ thể mẹ, thường từ chín tuần sau thụ thai cho đến khi sinh."},"7747":{"word":"năng lượng mặt trời, nhiệt mặt trời","meaning":"Nhiệt và năng lượng trực tiếp từ mặt trời, có thể dùng để làm nóng nước hoặc tạo ra điện."},"7748":{"word":"khu đất, nền đất","meaning":"Một khu vực đất cụ thể, thường trống hoặc đã được dọn sạch, được chọn làm nơi xây nhà, tòa nhà hoặc thị trấn mới."},"7749":{"word":"bày tỏ, giãi bày, thổ lộ","meaning":"Nói rõ ràng suy nghĩ hoặc cảm xúc bên trong mà không giấu giếm, làm cho việc giao tiếp trở nên cởi mở."},"7750":{"word":"khao, đãi","meaning":"Hành động mời thức ăn hoặc đồ uống cho người khác thưởng thức, đặc biệt để kỷ niệm một thành tựu hoặc sự kiện vui vẻ."},"7751":{"word":"áo lông","meaning":"Trang phục được làm từ lông dày và mềm của động vật, dùng để giữ ấm."},"7752":{"word":"dễ tính, thoải mái","meaning":"Có tính cách phóng khoáng, không để tâm đến những chuyện nhỏ nhặt."},"7753":{"word":"khủng bố","meaning":"Hành vi bạo lực nhằm gây hoang mang, sợ hãi lớn trong dân chúng vì mục đích chính trị."},"7754":{"word":"nền tảng, cơ sở","meaning":"Phần thấp nhất dùng để nâng đỡ một cấu trúc hoặc ý tưởng chính để phát triển một cái gì đó."},"7755":{"word":"khúc, miếng","meaning":"Một phần của cái gì đó lớn hơn đã được cắt hoặc bẻ rời ra."},"7756":{"word":"đất","meaning":"Vật chất bao phủ bề mặt Trái Đất, bao gồm các hạt nhỏ."},"7757":{"word":"đất đai","meaning":"Bề mặt rắn của Trái Đất không bị nước che phủ, đặc biệt được xem là tài nguyên để canh tác hoặc xây dựng."},"7758":{"word":"tấn","meaning":"Đơn vị đo khối lượng bằng 1000 kilôgam."},"7759":{"word":"độ rộng, bề rộng","meaning":"Kích thước đo từ phía này sang phía khác hoặc chu vi của một vật."},"7760":{"word":"cuộc","meaning":"Đơn vị dùng để đếm các cuộc điện thoại, thư từ hoặc các hình thức giao tiếp khác."},"7761":{"word":"Cục Thống kê","meaning":"Cơ quan nhà nước chịu trách nhiệm thu thập, sắp xếp và phân tích dữ liệu số về dân số, kinh tế và xã hội của một quốc gia."},"7762":{"word":"lối đi, hành lang","meaning":"Con đường hoặc hành lang hẹp cho phép người hoặc vật di chuyển từ khu vực này sang khu vực khác."},"7763":{"word":"chi phí liên lạc","meaning":"Khoản tiền phải trả cho các dịch vụ như gọi điện, dữ liệu di động và internet để liên lạc với người khác."},"7764":{"word":"kiểm soát","meaning":"Hành động quản lý hoặc hạn chế một điều gì đó như sự di chuyển, quyền truy cập hoặc hoạt động."},"7765":{"word":"đồ hộp","meaning":"Thực phẩm được đóng kín trong hộp kim loại kín khí và bảo quản trong thời gian dài."},"7766":{"word":"việc đi học","meaning":"Việc học sinh thường xuyên đi lại giữa nhà và trường học."},"7767":{"word":"hợp nhất","meaning":"Quá trình kết hợp các bộ phận hoặc nhóm khác nhau thành một thể thống nhất."},"7768":{"word":"tiền tệ","meaning":"Đơn vị tiền được một quốc gia hoặc khu vực phát hành và sử dụng."},"7769":{"word":"rời đi","meaning":"Hành động một người bị buộc phải rời khỏi một địa điểm hoặc khu vực, thường là bởi người có thẩm quyền."},"7770":{"word":"tiền trợ cấp thôi việc","meaning":"Khoản tiền mà một công ty trả cho nhân viên khi họ kết thúc công việc tại công ty đó."},"7771":{"word":"việc gửi bài","meaning":"Hành động gửi một bản thảo đến một tờ báo, tạp chí, v.v., để yêu cầu được đăng."},"7772":{"word":"cằn nhằn","meaning":"Liên tục phàn nàn về điều gì đó bằng giọng nói nhỏ và thấp."},"7773":{"word":"trong suốt","meaning":"Đặc tính của một vật thể hoặc vật liệu cho phép ánh sáng đi qua rõ ràng."},"7774":{"word":"nhà đầu tư","meaning":"Người bỏ tiền vào một doanh nghiệp, dự án hoặc tài sản với hy vọng kiếm lời."},"7775":{"word":"tiếng bộp","meaning":"Từ mô tả âm thanh một vật nặng rơi xuống gây ra tiếng động vang và nặng."},"7776":{"word":"tách tách","meaning":"Từ mô tả nhiều âm thanh nhỏ, nhẹ và nhanh xảy ra liên tiếp."},"7777":{"word":"một tí là","meaning":"Diễn tả một hành động xảy ra rất dễ dàng hoặc thường xuyên, thường vì lý do nhỏ hoặc không rõ ràng."},"7778":{"word":"sưng húp","meaning":"Từ diễn tả một bộ phận cơ thể trở nên lớn hơn và trông phù nề, thường do tích tụ dịch hoặc chấn thương."},"7779":{"word":"bật","meaning":"Dùng sức làm cho một vật căng ra rồi bật nảy lên."},"7780":{"word":"nảy","meaning":"Chỉ việc một vật như lò xo hay quả bóng tự bật lên."},"7781":{"word":"lồi ra","meaning":"Vươn ra ngoài hoặc đột ngột xuất hiện từ bên trong một vật gì đó."},"7782":{"word":"nhạc trot","meaning":"Một thể loại nhạc phổ biến của Hàn Quốc, đặc trưng bởi nhịp điệu hai phách và thường là giọng hát tình cảm, được thế hệ lớn tuổi ưa chuộng."},"7783":{"word":"thông","meaning":"Một thứ đã bị đóng hoặc bị chặn được dọn sạch và trở nên thông suốt."},"7784":{"word":"bài giảng đặc biệt","meaning":"Một buổi trình bày giáo dục tập trung vào một chủ đề cụ thể, thường do một chuyên gia giảng và kéo dài trong một thời gian giới hạn."},"7785":{"word":"đặc biệt","meaning":"Tính chất của một điều gì đó khác với bình thường hoặc thông thường, làm cho nó trở nên quan trọng hoặc đáng chú ý."},"7786":{"word":"đặc sản","meaning":"Một sản phẩm, thường là thực phẩm hoặc đồ thủ công, được sản xuất hoặc trồng đặc trưng ở một vùng cụ thể và nổi tiếng về điều đó."},"7787":{"word":"đặc điểm nổi bật","meaning":"Một đặc tính hay khía cạnh làm cho vật, việc hoặc người đó nổi trội và khác biệt rõ ràng so với những thứ cùng loại."},"7788":{"word":"đặc trưng, riêng có","meaning":"Diễn tả một phẩm chất, phong cách hoặc cách thức chỉ thuộc về một người, nhóm hoặc vật cụ thể, giúp nhận ra chúng."},"7789":{"word":"đặc biệt, dị thường","meaning":"Miêu tả điều gì đó nổi bật rõ rệt vì nó không điển hình hoặc không phổ biến."},"7790":{"word":"dấu vết, biểu hiện nhỏ","meaning":"Một dấu hiệu hoặc sự biểu lộ rất nhỏ cho thấy điều gì đó khác đang tồn tại hoặc đã xảy ra."},"7791":{"word":"thành viên nhóm","meaning":"Một người là thành viên của một nhóm người làm việc cùng nhau."},"7792":{"word":"trưởng nhóm","meaning":"Người đứng đầu một nhóm mà các thành viên thực hiện cùng loại công việc cho một công ty."},"7793":{"word":"phe, phái","meaning":"Một nhóm người nhỏ hơn có cùng quan điểm và thường bất đồng với những người khác trong một tổ chức hoặc cộng đồng lớn hơn."},"7794":{"word":"phá cách, phi thường","meaning":"Miêu tả một hành động hoặc vật phẩm khác biệt rõ rệt so với thông lệ, thường vượt quá giới hạn bình thường."},"7795":{"word":"chui sâu vào, đào sâu vào","meaning":"Đi vào bên trong một cái gì đó một cách sâu sắc."},"7796":{"word":"chôn vùi, vùi lấp","meaning":"Đặt một vật thể hoàn toàn dưới một đống đất, cát hoặc vật liệu khác, làm cho nó bị giấu kín khỏi tầm nhìn."},"7797":{"word":"bị chôn vùi, bị vùi lấp","meaning":"Đối tượng hoặc người bị bao phủ hoàn toàn bởi một lượng lớn vật liệu như tuyết hoặc đất, khiến chúng bị giấu kín."},"7798":{"word":"nắm bắt, hiểu rõ","meaning":"Hành động thu nhận thông tin và tìm hiểu chính xác ý nghĩa của nó hoặc cách thức hoạt động của một tình huống."},"7799":{"word":"kết thúc, tan học/họp","meaning":"Một buổi họp, buổi học hay một buổi tụ tập kết thúc hoàn toàn và những người tham gia rời đi."},"7800":{"word":"khay, mâm; mẻ; ván","meaning":"Một dụng cụ phẳng, nông dùng để nướng hoặc đựng đồ vật, hoặc một đơn vị hoàn chỉnh như một mẻ sản phẩm hay một ván chơi."},"7801":{"word":"bản in, khuôn in","meaning":"Một mảnh vật liệu phẳng như kim loại hay gỗ, có chữ cái hoặc hình ảnh được khắc trên bề mặt, dùng để chuyển mực và tạo bản sao lên giấy."},"7802":{"word":"doanh số, số lượng bán ra","meaning":"Tổng số sản phẩm hoặc hàng hóa đã được khách hàng mua trong một khoảng thời gian nhất định."},"7803":{"word":"nhân viên bán hàng","meaning":"Người có công việc là giới thiệu sản phẩm cho khách hàng và thuyết phục họ mua hàng."},"7804":{"word":"Pansori","meaning":"Một thể loại biểu diễn truyền thống của Hàn Quốc, trong đó một người kể một câu chuyện dài bằng cách thay đổi giọng điệu và cử động cơ thể kịch tính, thường có người đánh trống đi kèm."},"7805":{"word":"bán đi, bán đứt","meaning":"Đưa một vật hoặc một quyền lợi cho người khác sau khi nhận tiền."},"7806":{"word":"khoanh tay, tay trong tay","meaning":"Tư thế hai cánh tay khoanh trước ngực hoặc tư thế một người móc tay vào tay người khác."},"7807":{"word":"đậu đỏ","meaning":"Một loại hạt màu tím sẫm có vị mặn, thường dùng làm nguyên liệu trong cháo, bánh tteok, bánh gạo hoặc bánh mì."},"7808":{"word":"thua, thất bại","meaning":"Trạng thái không giành chiến thắng trong một trò chơi, cuộc thi hoặc cuộc đấu tranh chống lại đối thủ."},"7809":{"word":"đánh, đấm","meaning":"Đánh hoặc đấm liên tục một người hoặc vật một cách mạnh mẽ bằng tay hoặc một vật khác."},"7810":{"word":"buổi trình diễn thời trang, sàn diễn thời trang","meaning":"Một sự kiện mà mọi người trưng bày quần áo và phụ kiện mới bằng cách cho người mẫu đi trên sàn diễn trước khán giả."},"7811":{"word":"thua, bị đánh bại","meaning":"Trong một cuộc thi hay trò chơi, không giành được chiến thắng."},"7812":{"word":"máy fax, fax","meaning":"Thiết bị dùng để gửi bản sao tài liệu qua đường dây điện thoại đến một máy khác để in ra."},"7813":{"word":"loan truyền, lan truyền","meaning":"Làm cho thông tin, tin đồn hoặc ý tưởng được nhiều người biết đến trên một khu vực rộng lớn."},"7814":{"word":"phấp phới, tung bay","meaning":"Vải mỏng hoặc cờ di chuyển nhanh và không đều trong không khí, thường do gió."},"7815":{"word":"bùm","meaning":"Âm thanh đột ngột, lớn khi một vật gì đó vỡ, nổ hoặc thoát khí nhanh chóng."},"7816":{"word":"chuyến, chuyến đi","meaning":"Một hành trình hoặc dịch vụ cụ thể, ví dụ như một chuyến tàu hoặc chuyến bay di chuyển giữa các địa điểm."},"7817":{"word":"tập, bộ","meaning":"Từ dùng để chỉ một tác phẩm nghệ thuật hoàn chỉnh như phim, tác phẩm viết, hoặc chương trình truyền hình."},"7818":{"word":"đau nửa đầu","meaning":"Một loại đau đầu nặng thường gây đau nhói ở một bên đầu, nhạy cảm với ánh sáng và buồn nôn."},"7819":{"word":"thoải mái, yên ổn","meaning":"Ở trong trạng thái thư giãn và dễ chịu về thể chất hoặc tinh thần."},"7820":{"word":"biên tập, chỉnh sửa","meaning":"Hành động xem xét, thay đổi và sắp xếp văn bản, hình ảnh, âm thanh hoặc video để chuẩn bị cho việc xuất bản hoặc phát sóng."},"7821":{"word":"pyeong (đơn vị diện tích)","meaning":"Một đơn vị đo diện tích đất truyền thống của Hàn Quốc, tương đương khoảng 3,3 mét vuông."},"7822":{"word":"công việc trọn đời, nghề nghiệp suốt đời","meaning":"Một công việc hoặc nơi làm việc mà một người có ý định gắn bó trong suốt sự nghiệp cho đến khi nghỉ hưu."},"7823":{"word":"Đồng bằng","meaning":"Đây là một khu vực đất đai rộng lớn, bằng phẳng, không có đồi núi hay thung lũng đáng kể."},"7824":{"word":"Phổi","meaning":"Phổi là hai cơ quan xốp nằm trong lồng ngực giúp con người hô hấp bằng cách hít vào và thở ra không khí."},"7825":{"word":"Phiền toái","meaning":"Đây là hành động gây ra sự bất tiện, khó chịu hoặc thiệt hại cho người khác."},"7826":{"word":"Nước thải","meaning":"Nước thải là nước đã qua sử dụng và bị nhiễm bẩn từ hoạt động của con người, nhà máy hoặc cống rãnh."},"7827":{"word":"Cây (cải)","meaning":"Đây là đơn vị dùng để đếm một cây rau hoàn chỉnh như bắp cải hoặc xà lách."},"7828":{"word":"Cái ôm","meaning":"Đây là hành động đưa tay ôm chặt lấy ai đó hoặc hai người ôm nhau."},"7829":{"word":"Mặt đường","meaning":"Đây là lớp vật liệu rắn như nhựa đường hoặc bê tông được trải lên bề mặt để tạo thành một con đường bằng phẳng."},"7830":{"word":"Quán ăn vỉa hè","meaning":"Đây là một quầy hàng hoặc xe đẩy nhỏ trên lề đường, nơi mọi người có thể mua và ăn các món ăn và đồ uống đơn giản."},"7831":{"word":"Chiều rộng","meaning":"Chiều rộng là kích thước ngang của một vật thể hoặc mặt phẳng."},"7832":{"word":"Bạo lực","meaning":"Từ này dùng để mô tả những hành động hoặc tình huống sử dụng vũ lực để gây tổn thương hoặc thiệt hại cho người khác hoặc đồ vật."},"7833":{"word":"Vụ nổ","meaning":"Đây là một sự bùng phát đột ngột, mạnh mẽ, tạo ra năng lượng và mảnh vỡ lan tỏa nhanh chóng ra ngoài."},"7834":{"word":"Bùng nổ","meaning":"Từ này mô tả cái gì đó bùng phát với lực mạnh mẽ, đột ngột, lan tỏa nhanh chóng hoặc phát triển vô cùng mạnh mẽ."},"7835":{"word":"ăn vô độ","meaning":"Hành động ăn một lượng lớn thức ăn một cách nhanh chóng, vượt quá nhu cầu hoặc khả năng của cơ thể."},"7836":{"word":"pháo nổ","meaning":"Một thiết bị nhỏ khi đốt sẽ phát ra tiếng nổ lớn và ánh sáng, thường dùng trong các dịp lễ kỷ niệm."},"7837":{"word":"bom","meaning":"Một thiết bị phá hủy chứa vật liệu được thiết kế để nổ với lực lớn, gây ra hư hại hoặc phá hủy."},"7838":{"word":"vé","meaning":"Một mảnh giấy hoặc thẻ nhỏ xác nhận bạn đã trả tiền để vào một sự kiện hoặc cho một chuyến đi."},"7839":{"word":"cách ghi","meaning":"Một phương pháp hoặc hệ thống cụ thể để viết xuống âm thanh, từ ngữ hoặc dữ liệu bằng chữ cái, số hoặc ký hiệu."},"7840":{"word":"quy tắc chính tả","meaning":"Một tập hợp các quy tắc được định nghĩa rõ ràng về cách viết các từ trong một ngôn ngữ bằng bảng chữ cái và ký tự của nó."},"7841":{"word":"dấu hiệu","meaning":"Một ký hiệu, đường nét hoặc vật thể vật lý chỉ ra điều gì đó, hoặc giúp nhận diện vị trí hay cảnh báo."},"7842":{"word":"biểu lộ","meaning":"Hành động thể hiện rõ ràng cảm xúc, suy nghĩ hoặc ý tưởng bằng lời nói, cử chỉ khuôn mặt hoặc hành động cơ thể."},"7843":{"word":"màu xanh","meaning":"Một màu sắc trong trẻo và sống động, giống như màu của bầu trời trong xanh, biển sâu hoặc cỏ."},"7844":{"word":"dồi dào","meaning":"Mô tả một lượng lớn của cái gì đó, đặc biệt là thức ăn, nhiều hơn đủ cho những gì cần thiết."},"7845":{"word":"êm ái","meaning":"Khi bạn ấn vào một vật, nó dễ dàng lún vào và có cảm giác mềm mại hoặc đàn hồi."},"7846":{"word":"thật kỹ","meaning":"Diễn tả hành động nấu chín rất kỹ trong chất lỏng nóng, thường kèm theo hơi nước và bong bóng rõ rệt."},"7847":{"word":"Được thả, được trả tự do","meaning":"Thoát khỏi nơi bị giam giữ hoặc bị kiểm soát và được tự do đi lại."},"7848":{"word":"Hạng mục, mặt hàng","meaning":"Từng loại sản phẩm hay đồ vật được liệt kê trong một danh sách chung."},"7849":{"word":"Mùa bội thu, năm được mùa","meaning":"Năm mà mùa màng thu hoạch được rất nhiều, vượt mức bình thường."},"7850":{"word":"Năng lượng gió, phong lực","meaning":"Năng lượng được tạo ra từ sức gió, thường dùng để sản xuất điện."},"7851":{"word":"Phong phú, dồi dào","meaning":"Có số lượng rất nhiều, đầy đủ và dư thừa, làm cho mọi thứ trông đầy đặn."},"7852":{"word":"Sự phong phú, sự sung túc","meaning":"Tình trạng có rất nhiều tài sản, của cải hoặc thức ăn, khiến cuộc sống trở nên thoải mái và đầy đủ."},"7853":{"word":"Phong phú, sung túc, giàu có","meaning":"Có nhiều tài nguyên, tiền bạc hoặc của cải, giúp cuộc sống rất thoải mái và đầy đủ."},"7854":{"word":"Fusion","meaning":"Sự pha trộn, kết hợp hai hay nhiều yếu tố, phong cách khác nhau tạo thành một cái mới, độc đáo."},"7855":{"word":"Chương trình (truyền hình/phát thanh)","meaning":"Một buổi phát sóng cụ thể trên truyền hình hoặc đài phát thanh với lịch trình và nội dung định sẵn."},"7856":{"word":"Phích cắm, đầu cắm","meaning":"Thiết bị nhỏ có các chân kim loại, dùng để nối dây điện với ổ cắm để cấp điện cho thiết bị."},"7857":{"word":"Tiệc chiêu đãi, tiệc cưới","meaning":"Bữa tiệc ăn mừng với đồ ăn và thức uống sau lễ cưới để chúc mừng cặp đôi mới kết hôn."},"7858":{"word":"Sáo","meaning":"Một loại nhạc cụ hơi dài, mỏng, có các lỗ bấm, được thổi để tạo ra âm thanh."},"7859":{"word":"khoa da liễu","meaning":"Đây là chuyên khoa y tế chuyên nghiên cứu và điều trị các bệnh về da."},"7860":{"word":"nở ra, đơm hoa","meaning":"Hoa mở cánh ra, từ nụ phát triển thành bông hoa hoàn chỉnh."},"7861":{"word":"bốc lên, cuộn lên","meaning":"Khói hoặc lửa từ dưới nguồn bay lên không trung và lan rộng ra."},"7862":{"word":"vòng","meaning":"Diễn tả động tác quay vòng theo một quỹ đạo hơi rộng."},"7863":{"word":"-dưới, -phía dưới","meaning":"Hậu tố dùng sau một số từ để chỉ điều gì đó xảy ra dưới sự kiểm soát hoặc ở vị trí thấp hơn cái được đề cập."},"7864":{"word":"khách dự đám cưới","meaning":"Người đến tham dự buổi lễ kết hôn của hai người."},"7865":{"word":"tan học, ra về","meaning":"Hành động học sinh rời khỏi trường sau khi kết thúc giờ học trong ngày."},"7866":{"word":"giảm, sụt giảm","meaning":"Sự giảm sút đáng kể về mức độ, số lượng hoặc giá trị so với điểm cao hơn trước đó."},"7867":{"word":"trong một sớm một chiều","meaning":"Khoảng thời gian rất ngắn một cách bất ngờ, mang tính hình tượng."},"7868":{"word":"từng ngày, mỗi ngày","meaning":"Điều gì đó xảy ra liên tiếp trong mỗi 24 giờ, ngày này qua ngày khác mà không bỏ sót."},"7869":{"word":"suýt nữa, tý nữa","meaning":"Diễn tả một tình huống không mong muốn hoặc thú vị gần như xảy ra nhưng cuối cùng đã không."},"7870":{"word":"nửa cuối năm","meaning":"Giai đoạn sáu tháng từ tháng Bảy đến tháng Mười Hai trong một chu kỳ năm dương lịch."},"7871":{"word":"cuối tháng","meaning":"Khoảng thời gian mười ngày cuối cùng trong một tháng."},"7872":{"word":"dù sao đi nữa","meaning":"Dùng để chuyển sang chủ đề khác hoặc hành động khác, thể hiện rằng vấn đề trước đó không còn quan trọng."},"7873":{"word":"lỗi, khuyết điểm","meaning":"Một vấn đề hoặc điểm yếu nhìn thấy được ở một vật phẩm hay hệ thống, khiến nó không hoạt động hoàn hảo hoặc không hoàn chỉnh."},"7874":{"word":"tầm thường, không đáng kể","meaning":"Diễn tả điều gì đó được coi là có giá trị hoặc hậu quả rất nhỏ, không đáng để chú ý nghiêm túc."},"7875":{"word":"hạ thân, phần dưới cơ thể","meaning":"Phần cơ thể của người hoặc động vật bao gồm chân, hông và mọi thứ bên dưới eo."},"7876":{"word":"cớ sao lại","meaning":"Dùng để bày tỏ sự ngạc nhiên hoặc không may mắn về một lựa chọn hoặc sự kiện cụ thể, tự hỏi tại sao điều đó lại xảy ra."},"7877":{"word":"đi xuống, chiều xuống","meaning":"Miêu tả sự di chuyển hoặc hướng từ một điểm hay cấp độ cao hơn xuống một điểm hay cấp độ thấp hơn."},"7878":{"word":"khóa nhập học","meaning":"Năm mà một nhóm sinh viên bắt đầu học tại một trường đại học hoặc sau đại học."},"7879":{"word":"học vấn","meaning":"Lịch sử giáo dục của một người, bao gồm các trường đã theo học, thường dùng để ám chỉ địa vị hoặc năng lực dựa trên bằng cấp và nơi học."},"7880":{"word":"việc học, học tập","meaning":"Các nhiệm vụ và hoạt động học tập mà học sinh, sinh viên thực hiện tại trường học hoặc đại học."},"7881":{"word":"học vị, bằng cấp","meaning":"Chứng chỉ hoặc danh hiệu chính thức được cấp bởi một trường đại học sau khi một người hoàn thành một khóa học giáo dục đại học."},"7882":{"word":"điểm số","meaning":"Chữ cái hoặc số thể hiện kết quả học tập của học sinh, sinh viên trong một môn học, do giáo viên hoặc giáo sư đánh giá."},"7883":{"word":"thời học sinh","meaning":"Khoảng thời gian một người dành để học tập và trưởng thành tại trường học hoặc đại học."},"7884":{"word":"nhàn rỗi","meaning":"Có nhiều thời gian rảnh và cảm thấy thư giãn, không có việc gì cấp bách phải làm."},"7885":{"word":"một cái nhìn","meaning":"Hành động nhìn hoặc nhận thấy điều gì đó một cách đầy đủ chỉ với một cái nhìn nhanh, không cần kiểm tra kỹ lưỡng."},"7886":{"word":"lơ đễnh","meaning":"Nhìn ra chỗ khác thay vì tập trung vào điều cần thiết, thường là do chú ý đến những việc khác đang xảy ra xung quanh."},"7887":{"word":"một chỗ","meaning":"Một địa điểm được chỉ định là cùng một hoặc một vị trí duy nhất cho một điều gì đó."},"7888":{"word":"bán đảo Triều Tiên","meaning":"Mảnh đất rộng lớn kéo dài từ lục địa châu Á ra biển, nơi có Bắc và Nam Triều Tiên."},"7889":{"word":"một bước","meaning":"Một chuyển động duy nhất được thực hiện bằng cách nhấc một chân và đặt về phía trước, hoặc một khoảng cách nhỏ phía trước người khác."},"7890":{"word":"Đông y Hàn Quốc","meaning":"Một hệ thống các phương pháp điều trị truyền thống của Hàn Quốc sử dụng thảo mộc, châm cứu và các phương pháp tự nhiên khác để cải thiện sức khỏe."},"7891":{"word":"chính giữa","meaning":"Điểm hoặc khu vực trung tâm chính xác của một không gian hoặc địa điểm cụ thể."},"7892":{"word":"vắng vẻ","meaning":"Có rất ít người hoặc vật hiện diện, làm cho khu vực đó trông yên bình và không bận rộn."},"7893":{"word":"thuốc Đông y","meaning":"Một loại thức uống hoặc hợp chất truyền thống được làm từ nhiều loại cây và nguyên liệu tự nhiên khác nhau, được sử dụng ở Hàn Quốc để cải thiện sức khỏe."},"7894":{"word":"thịt bò Hàn Quốc","meaning":"Một loại thịt đặc biệt đến từ giống bò nâu cụ thể được nuôi ở Hàn Quốc, nổi tiếng với chất lượng cao."},"7895":{"word":"phòng khám y học cổ truyền","meaning":"Đây là nơi bệnh nhân được điều trị bằng các phương pháp y học cổ truyền như châm cứu hoặc thuốc bắc."},"7896":{"word":"cùng một chỗ","meaning":"Chỉ một địa điểm hoặc vị trí không thay đổi."},"7897":{"word":"từ Hán-Hàn","meaning":"Từ vựng tiếng Hàn có nguồn gốc từ chữ Hán và thường dùng để biểu thị một ý tưởng hoặc khái niệm."},"7898":{"word":"vắng vẻ, yên tĩnh","meaning":"Mô tả một nơi có ít người hoặc tiếng ồn, tạo cảm giác thanh bình và yên tĩnh."},"7899":{"word":"giới hạn","meaning":"Một ranh giới hoặc điểm tối đa được đặt ra cho một thứ gì đó, ví dụ số lượng hoặc thời gian."},"7900":{"word":"một lần, một lượt","meaning":"Chỉ một hành động hoặc sự kiện xảy ra duy nhất một lần hoặc hoàn thành một chu kỳ."},"7901":{"word":"liếm","meaning":"Di chuyển lưỡi qua bề mặt của vật gì đó, thường để nếm hoặc làm sạch."},"7902":{"word":"hộp, thùng","meaning":"Một vật đựng hình vuông thường dùng để chứa quần áo hoặc đồ vật."},"7903":{"word":"cùng nhau, đồng hành","meaning":"Cùng tồn tại hoặc thực hiện một hoạt động với người khác, chia sẻ trải nghiệm hoặc địa điểm."},"7904":{"word":"tuyết hạt lớn","meaning":"Những bông tuyết lớn, mềm mại rơi từ trên trời xuống khi thời tiết lạnh, thường phủ trắng mặt đất."},"7905":{"word":"cái bẫy, cạm bẫy","meaning":"Một cái hố được đào để bắt động vật."},"7906":{"word":"sự hợp lý, lý trí","meaning":"Cách tiếp cận tình huống hoặc đưa ra lựa chọn dựa trên sự thật và logic rõ ràng thay vì cảm xúc."},"7907":{"word":"Hợp xướng","meaning":"Việc nhiều người cùng hát một bài hát hoặc bản nhạc."},"7908":{"word":"Máy bay","meaning":"Một loại máy móc như máy bay hoặc trực thăng, được thiết kế để bay trong không khí."},"7909":{"word":"Hãng hàng không","meaning":"Một công ty sở hữu và vận hành nhiều máy bay, cho phép mọi người đi lại bằng đường hàng không đến các địa điểm khác nhau."},"7910":{"word":"Cảng","meaning":"Một nơi ở bờ biển hoặc trên sông để tàu thuyền có thể neo đậu an toàn, bốc dỡ hàng hóa hoặc đón trả khách."},"7911":{"word":"Lộ trình","meaning":"Con đường cụ thể được đánh dấu trên không hoặc trên mặt nước mà máy bay và tàu thuyền đi theo để đến đích."},"7912":{"word":"Mục","meaning":"Một phần riêng biệt của thông tin, đối tượng hoặc chủ đề nằm trong một danh sách hoặc bộ sưu tập lớn hơn."},"7913":{"word":"Sa thải","meaning":"Việc người sử dụng lao động chính thức cho nhân viên biết rằng họ không thể tiếp tục làm việc cho công ty và phải nghỉ việc."},"7914":{"word":"Hải quân","meaning":"Lực lượng chiến đấu của một quốc gia hoạt động chủ yếu trên biển, sử dụng tàu chiến và các loại tàu thuyền khác."},"7915":{"word":"Lời giải","meaning":"Thông tin hoặc phương pháp đúng được đưa ra để trả lời một câu hỏi hoặc giải quyết một vấn đề."},"7916":{"word":"Giải thích","meaning":"Lời nói hoặc hành động cung cấp thêm chi tiết để làm rõ điều gì đó hoặc giải quyết hiểu lầm."},"7917":{"word":"Hàng hải","meaning":"Liên quan đến các hoạt động, việc đi lại hoặc điều kiện xảy ra trên bề mặt biển."},"7918":{"word":"Tắm biển","meaning":"Hoạt động xuống nước biển, thường ở bãi biển, để tận hưởng sự mát mẻ hoặc vui đùa."},"7919":{"word":"đại dương","meaning":"Một vùng nước mặn bao la, rộng lớn bao phủ phần lớn bề mặt Trái Đất."},"7920":{"word":"thuốc hạ sốt","meaning":"Loại thuốc dùng để giảm thân nhiệt khi cơ thể bị sốt cao."},"7921":{"word":"đáy biển","meaning":"Bề mặt đất nằm dưới cùng của đại dương hoặc biển."},"7922":{"word":"hack","meaning":"Hành vi xâm nhập trái phép vào hệ thống máy tính hoặc mạng để đánh cắp thông tin hoặc gây hại."},"7923":{"word":"cốt lõi","meaning":"Phần quan trọng nhất hoặc trung tâm của một cái gì đó."},"7924":{"word":"gia đình hạt nhân","meaning":"Gia đình chỉ gồm cha mẹ và các con chưa kết hôn."},"7925":{"word":"ngũ cốc mới","meaning":"Các loại ngũ cốc như gạo hoặc lúa mì vừa được thu hoạch trong mùa này."},"7926":{"word":"dòng","meaning":"Một chuỗi từ, số hoặc ký hiệu viết theo chiều ngang trên trang giấy hoặc màn hình."},"7927":{"word":"người đi đường","meaning":"Người đang đi bộ ngang qua một địa điểm cụ thể."},"7928":{"word":"thơm","meaning":"Có mùi dễ chịu, thoang thoảng hoặc nồng nàn."},"7929":{"word":"hoài niệm","meaning":"Cảm giác khao khát dễ chịu về những điều tốt đẹp đã xảy ra trong quá khứ."},"7930":{"word":"tương lai","meaning":"Khoảng thời gian sẽ đến sau thời điểm hiện tại."},"7931":{"word":"không trung","meaning":"Khoảng không gian rộng lớn phía trên mặt đất, không có vật thể rắn bên trong."},"7932":{"word":"lãng phí","meaning":"Việc sử dụng những thứ quý giá như tiền bạc, thời gian mà không mang lại kết quả hữu ích."},"7933":{"word":"trắng nhợt","meaning":"Có màu rất nhạt, gần giống màu trắng."},"7934":{"word":"sai sự thật","meaning":"Thông tin hoặc lời nói không đúng sự thật, được đưa ra nhằm mục đích lừa dối người khác."},"7935":{"word":"trống trải","meaning":"Cảm thấy trống rỗng, cô đơn vì không có ai ở bên."},"7936":{"word":"sơ hở","meaning":"Một khuyết điểm hoặc lỗi cụ thể trong một hệ thống, kế hoạch hay lập luận, khiến nó dễ bị tấn công hoặc khai thác."},"7937":{"word":"hiến máu","meaning":"Hành động một người tự nguyện cho đi một phần máu của mình để giúp đỡ người bệnh hoặc người bị thương."},"7938":{"word":"rộng thùng thình","meaning":"Trang phục rộng rãi, không ôm sát cơ thể, khiến người mặc cảm thấy thoải mái."},"7939":{"word":"nói xấu","meaning":"Hành động nói những điều tiêu cực hoặc ác ý về người khác, thường là lan truyền tin đồn không đúng sự thật."},"7940":{"word":"đi uổng công","meaning":"Hành động đi đến một nơi nào đó vì một mục đích nhưng cuối cùng không đạt được, khiến chuyến đi trở nên vô ích."},"7941":{"word":"vô ích","meaning":"Một hành động hoặc nỗ lực không mang lại kết quả thành công hoặc thành tựu nào, mặc dù đã bỏ ra công sức."},"7942":{"word":"hụt chân","meaning":"Đặt chân xuống sai chỗ hoặc không đúng như dự kiến, gây ra vấp ngã hoặc mất thăng bằng."},"7943":{"word":"tin đồn thất thiệt","meaning":"Thông tin không đúng sự thật về một người hay một việc gì đó được lan truyền nhanh chóng từ người này sang người khác."},"7944":{"word":"công cốc","meaning":"Công sức đã bỏ ra nhưng không đạt được kết quả như mong muốn."},"7945":{"word":"lúng túng","meaning":"Khó phân biệt giữa hai hoặc nhiều thứ hoặc không thể suy nghĩ rõ ràng về một điều gì đó."},"7946":{"word":"cách mạng","meaning":"Sự thay đổi đột ngột và thường là bạo lực trong cách một quốc gia được cai trị hoặc trong cách mọi người sống và làm việc."},"7947":{"word":"khôn ngoan","meaning":"Có khả năng áp dụng kiến thức và kinh nghiệm để suy nghĩ cẩn thận và đưa ra những lựa chọn đúng đắn, mang lại kết quả tốt."},"7948":{"word":"tính hiện thực","meaning":"Đặc điểm của một ý tưởng hoặc kế hoạch có thể được thực hiện hoặc đạt được trong hoàn cảnh hiện có."},"7949":{"word":"tại chỗ","meaning":"Nơi cụ thể mà một sự kiện hoặc hoạt động đang diễn ra, chứ không phải một địa điểm khác hay xa xôi."},"7950":{"word":"tình hình hiện tại","meaning":"Tình trạng hoặc điều kiện cụ thể mà một tình huống hoặc quá trình đang tồn tại ở thời điểm hiện tại."},"7951":{"word":"mạch máu","meaning":"Ống nhỏ trong cơ thể vận chuyển chất lỏng màu đỏ được tim bơm đến các cơ quan và mô khác nhau."},"7952":{"word":"huyết áp","meaning":"Lực đo được tạo ra bởi hoạt động bơm của tim tác động lên thành trong của các ống lưu thông chất lỏng màu đỏ khắp cơ thể."},"7953":{"word":"máu","meaning":"Chất lỏng màu đỏ chảy trong các mạch máu của cơ thể người hoặc động vật để cung cấp oxy và chất dinh dưỡng, đồng thời vận chuyển chất thải."},"7954":{"word":"nhóm máu","meaning":"Sự phân loại riêng biệt của chất lỏng màu đỏ trong cơ thể người, được xác định bằng các loại như A, B, AB hoặc O."},"7955":{"word":"hợp tác","meaning":"Cùng nhau làm việc hoặc giúp đỡ lẫn nhau để đạt được mục tiêu chung."},"7956":{"word":"hiệp hội","meaning":"Một tổ chức được thành lập bởi những người có cùng mục đích."},"7957":{"word":"-hình","meaning":"Vĩ tố gắn vào sau danh từ để chỉ hình dạng hoặc kiểu dáng của sự vật."},"7958":{"word":"đèn huỳnh quang","meaning":"Ống thủy tinh dài, thẳng, gắn trên trần hoặc tường, phát sáng đều khi có điện chạy qua."},"7959":{"word":"anh rể","meaning":"Chồng của chị gái."},"7960":{"word":"hình thức","meaning":"Chỉ việc thực hiện một hành động hoặc thủ tục chỉ để đáp ứng yêu cầu hoặc phong tục, thường thiếu sự quan tâm thực sự."},"7961":{"word":"tính từ","meaning":"Loại từ dùng để miêu tả đặc điểm, tính chất của danh từ hoặc đại từ."},"7962":{"word":"tệ hại","meaning":"Ở trong tình trạng chất lượng cực kỳ thấp hoặc không đạt yêu cầu, không đáp ứng được tiêu chuẩn."},"7963":{"word":"số / tàu","meaning":"Vĩ tố dùng để chỉ số thứ tự của ấn phẩm hoặc đứng sau tên riêng của một con tàu lớn."},"7964":{"word":"số","meaning":"Chữ số hoặc số nhận dạng cụ thể được in trên tạp chí, báo, hoặc sản phẩm để chỉ thứ tự trong một loạt."},"7965":{"word":"kêu gọi","meaning":"Đề nghị hoặc yêu cầu khẩn thiết sự giúp đỡ, lòng thương xót hoặc sự thông cảm, thường bằng cách bày tỏ cảm xúc sâu sắc."},"7966":{"word":"mưa lớn","meaning":"Lượng mưa rơi xuống rất nhiều trong một thời gian dài."},"7967":{"word":"cuộc gọi","meaning":"Hành động sử dụng tín hiệu, thông báo hoặc thiết bị để yêu cầu ai đó đến một địa điểm cụ thể."},"7968":{"word":"danh xưng","meaning":"Một từ hoặc cụm từ cụ thể dùng để gọi hoặc xưng hô với một người, thường để thể hiện vị trí, mối quan hệ hoặc sự tôn trọng."},"7969":{"word":"từ xưng hô","meaning":"Một từ hay cụm từ ngắn được dùng để gọi hoặc thu hút sự chú ý của người khác một cách lịch sự, như \"thưa ông\" hoặc \"thưa bà\"."},"7970":{"word":"quán nhậu","meaning":"Một địa điểm bình dân, thường có nhiều bàn, nơi mọi người tụ tập để uống đồ uống có cồn và dành thời gian bên bạn bè."},"7971":{"word":"sự xa hoa","meaning":"Tình trạng hoặc vẻ ngoài rất giàu có và thoải mái, được thể hiện qua thiết kế cầu kỳ, vật liệu quý giá và đồ dùng chất lượng cao."},"7972":{"word":"cơ quan hô hấp","meaning":"Một cơ quan trong cơ thể người hoặc động vật có nhiệm vụ thực hiện quá trình hô hấp."},"7973":{"word":"linh hồn","meaning":"Phần vô hình cốt lõi của một người, mang lại sự sống và cảm xúc, đôi khi được hình dung là một năng lượng tồn tại sau khi chết."},"7974":{"word":"sự hỗn loạn","meaning":"Tình trạng có nhiều việc xảy ra cùng lúc một cách không có tổ chức, khiến mọi người khó hiểu hoặc khó biết phải làm gì."},"7975":{"word":"hỗn loạn","meaning":"Diễn tả một tình huống hoặc cảnh tượng có nhiều yếu tố lộn xộn hoặc không rõ ràng, khiến người ta rất khó hiểu chuyện gì đang xảy ra."},"7976":{"word":"lễ cưới","meaning":"Một sự kiện công khai trang trọng trong đó hai người hứa hẹn với nhau và chính thức trở thành vợ chồng, thường có trang phục đặc biệt và khách mời."},"7977":{"word":"hôn nhân","meaning":"Tình trạng pháp lý và xã hội khi hai người được kết nối với nhau thành vợ chồng, thường sau một sự kiện trang trọng."},"7978":{"word":"sự tắc nghẽn","meaning":"Tình trạng có quá nhiều người, phương tiện hoặc vật phẩm tập trung vào một nơi, gây khó khăn cho việc di chuyển và khiến cảnh tượng trở nên rất lộn xộn."},"7979":{"word":"độc thoại","meaning":"Hành động tự nói chuyện một mình mà không có ý định cho người khác nghe."},"7980":{"word":"một mình","meaning":"Ở một mình hoặc trong tình huống không có người hay vật nào khác đi cùng."},"7981":{"word":"màu đỏ","meaning":"Một màu đỏ sẫm như màu ớt chín hay màu máu."},"7982":{"word":"-giày","meaning":"Hậu tố thêm vào sau từ để chỉ một loại vật dụng đi vào chân."},"7983":{"word":"cách nói","meaning":"Phong cách hoặc cách thức một người dùng để diễn đạt suy nghĩ bằng lời nói."},"7984":{"word":"rực rỡ","meaning":"Trông rất nhiều màu sắc, sống động và đẹp mắt, làm cho mọi thứ trông tươi vui và hấp dẫn."},"7985":{"word":"núi lửa","meaning":"Một ngọn núi lớn có lỗ ở đỉnh, thỉnh thoảng phun trào đá nóng chảy, tro và khí ra ngoài."},"7986":{"word":"vết bỏng","meaning":"Vết thương ở da hoặc thịt do nhiệt độ cực cao, điện, hóa chất hoặc bức xạ gây ra."},"7987":{"word":"hỏa táng","meaning":"Quá trình biến thi thể người chết thành tro bằng nhiệt độ cao."},"7988":{"word":"cây cảnh","meaning":"Một loại thực vật mọc từ đất, thường được trồng trong chậu trong nhà, và nở hoa đầy màu sắc."},"7989":{"word":"hóa học","meaning":"Ngành khoa học nghiên cứu về cấu tạo vật chất, cách các chất tương tác và thay đổi vật lý."},"7990":{"word":"hòa hợp","meaning":"Trạng thái mà những người, nhóm hoặc yếu tố khác nhau cùng tồn tại một cách hòa bình và hợp tác mà không có xung đột."},"7991":{"word":"xác suất","meaning":"Khả năng một sự việc nào đó có thể xảy ra, thường được biểu thị bằng số hoặc phần trăm."},"7992":{"word":"sự xác định, sự xác nhận","meaning":"Việc chính thức ấn định một điều gì đó là đã định, là chắc chắn hoặc là đúng."},"7993":{"word":"lục tuần, sinh nhật 60 tuổi","meaning":"Một dịp kỷ niệm đặc biệt khi một người tròn 60 tuổi."},"7994":{"word":"sự thông gió, thông khí","meaning":"Hành động thay đổi không khí bẩn, ngột ngạt thành không khí trong lành."},"7995":{"word":"thời điểm giao mùa","meaning":"Khoảng thời gian khi điều kiện thời tiết dần chuyển từ loại chủ yếu này sang loại khác."},"7996":{"word":"niềm vui sướng, hoan hỉ","meaning":"Một cảm giác hạnh phúc và phấn khích tột độ, thường được thể hiện qua nụ cười hoặc tiếng cười."},"7997":{"word":"rực rỡ, sáng bừng","meaning":"Theo cách tạo ra hoặc phản chiếu nhiều ánh sáng, làm cho một khu vực rất dễ nhìn và rõ ràng."},"7998":{"word":"cung","meaning":"Một khúc gỗ cong hoặc vật liệu tương tự có dây căng giữa hai đầu, dùng để bắn tên."},"7999":{"word":"năng động, sôi nổi, tràn đầy sức sống","meaning":"Khi một bầu không khí, một người hoặc một nơi cảm thấy tràn đầy năng lượng và nhiệt huyết."},"8000":{"word":"sự kích hoạt, sự phục hồi","meaning":"Quá trình làm cho một cái gì đó bắt đầu hoạt động hoặc trở nên mạnh mẽ và hiệu quả hơn."},"8001":{"word":"sự hoạt động tích cực, vai trò nổi bật","meaning":"Những hành động mà một người thực hiện có ý nghĩa hoặc ảnh hưởng trong một tình huống cụ thể."},"8002":{"word":"vàng (kim loại)","meaning":"Một kim loại quý màu vàng, rất được trân trọng vì độ sáng và được dùng để làm trang sức hoặc tiền xu."},"8003":{"word":"vô lý","meaning":"Một sự việc, lời nói hay hành động đến mức không thể hiểu hoặc tin được vì quá thiếu logic, gây cảm giác bối rối, ngạc nhiên."},"8004":{"word":"bụi vàng","meaning":"Hiện tượng thời tiết khi những hạt cát mịn từ sa mạc được gió mang theo bay qua Đông Á, làm bầu trời trở nên mờ ảo, có màu vàng cam."},"8005":{"word":"màu vàng","meaning":"Màu sắc như màu của chuối chín, chanh hoặc phần giữa của hoa hướng dương."},"8006":{"word":"buổi","meaning":"Hậu tố dùng để chỉ một dịp, một buổi tụ họp của nhiều người vì một mục đích cụ thể, thường là để kỷ niệm, thảo luận hoặc chia tay."},"8007":{"word":"sinh nhật thứ 60","meaning":"Dịp kỷ niệm truyền thống khi một người tròn 60 tuổi, thường được đánh dấu bằng một sự kiện đặc biệt."},"8008":{"word":"tiệc mừng thọ 60 tuổi","meaning":"Buổi tiệc kỷ niệm đặc biệt được tổ chức cho một người đã hoàn thành năm thứ sáu mươi của cuộc đời, có gia đình và bạn bè tham dự."},"8009":{"word":"hồi ức","meaning":"Hành động nghĩ về những trải nghiệm, sự kiện hoặc con người trong quá khứ, thường đi kèm với cảm giác yêu mến hoặc nuối tiếc."},"8010":{"word":"quốc gia thành viên","meaning":"Một quốc gia đã chính thức gia nhập một tổ chức quốc tế, đồng ý với các quy định và tham gia vào các hoạt động của tổ chức đó."},"8011":{"word":"sự hoài nghi","meaning":"Cảm giác không chắc chắn hoặc nghi ngờ về tính đúng đắn, sự thật hay giá trị của một điều gì đó."},"8012":{"word":"sự quay","meaning":"Hành động của một vật thể di chuyển theo một đường tròn quanh một trục hoặc một điểm trung tâm."},"8013":{"word":"đồng nhất","meaning":"Mô tả nhiều sự vật, con người hoặc phương pháp khác nhau nhưng tất cả đều giống hệt nhau, không có sự đa dạng hay khác biệt."},"8014":{"word":"sự băng qua","meaning":"Hành động di chuyển hoặc đi bộ từ một phía của một địa điểm, như đường phố hoặc một khu vực đất rộng, sang phía bên kia."},"8015":{"word":"hiếu","meaning":"Sự tôn kính, yêu thương và chăm sóc mà con cái dành cho cha mẹ."},"8016":{"word":"hiếu nữ","meaning":"Người con gái có lòng hiếu thảo, luôn kính trọng và chăm sóc cha mẹ."},"8017":{"word":"công dụng","meaning":"Khả năng tạo ra kết quả tốt hoặc tác dụng tích cực."},"8018":{"word":"hiệu suất","meaning":"Mức độ thực hiện công việc hoặc sản xuất cái gì đó một cách hiệu quả mà ít lãng phí thời gian, công sức."},"8019":{"word":"hậu kỳ","meaning":"Thời kỳ cuối hoặc giai đoạn kết thúc của một khoảng thời gian dài hoặc chuỗi sự kiện."},"8020":{"word":"hậu duệ","meaning":"Con cháu của một người hoặc một dòng họ, bao gồm các thế hệ sau này."},"8021":{"word":"hậu viện","meaning":"Khu vườn hoặc khoảng đất nhỏ ở phía sau của một ngôi nhà."},"8022":{"word":"sau này","meaning":"Một thời điểm hoặc ngày tháng nào đó trong tương lai."},"8023":{"word":"cái sau","meaning":"Trong hai điều được nhắc đến, đây là điều được nói đến hoặc trình bày sau cùng."},"8024":{"word":"hào phóng","meaning":"Sẵn lòng cho đi hoặc chia sẻ nhiều tiền bạc, thời gian, sự giúp đỡ với người khác."},"8025":{"word":"ấm áp","meaning":"Chỉ cảm giác ấm áp nhẹ nhàng, dễ chịu trong không gian vật lý, hoặc sự ấm lòng, thân ái giữa con người."},"8026":{"word":"vụt","meaning":"Từ dùng để miêu tả một hành động nhanh, nhẹ và thường có tính đột ngột hoặc vượt bậc, như nhảy qua hay lớn nhanh."},"8027":{"word":"lau","meaning":"Dùng tay hoặc vật gì đó để chùi sạch chất lỏng hoặc bụi bẩn dính trên bề mặt."},"8028":{"word":"sau này","meaning":"Một khoảng thời gian trong tương lai, thường là một thời gian dài sau hiện tại."},"8029":{"word":"rõ ràng","meaning":"Ở trạng thái có thể nhìn thấy hoặc hiểu được một cách dễ dàng, không bị che khuất hay mờ nhạt."},"8030":{"word":"bay nhẹ nhàng","meaning":"Diễn tả dáng vẻ cánh chim hoặc côn trùng cử động liên tục, nhẹ nhàng khi bay lượn trên không trung."},"8031":{"word":"sự tổn hại","meaning":"Tình trạng bị làm cho hư hỏng, xấu đi về hình thức hoặc giá trị, hoặc bị ảnh hưởng tiêu cực đến danh dự, uy tín."},"8032":{"word":"quấn quanh","meaning":"Làm cho một sợi dây, vải hoặc vật tương tự quấn nhiều vòng quanh một vật thể khác."},"8033":{"word":"bay phấp phới","meaning":"Di chuyển nhanh và nhẹ trong không khí, thường là do gió, như cờ hoặc tóc."},"8034":{"word":"xăng","meaning":"Một loại chất lỏng trong suốt dùng làm nhiên liệu cho ô tô và các động cơ khác để chúng hoạt động."},"8035":{"word":"vèo","meaning":"Từ diễn tả một chuyển động rất nhanh và đột ngột, thường kèm theo âm thanh của không khí xé qua."},"8036":{"word":"trạm dừng chân","meaning":"Nơi được bố trí để người đi đường có thể dừng lại nghỉ ngơi một thời gian ngắn trong hành trình."},"8037":{"word":"làm mờ","meaning":"Gây ra tình trạng một vật vốn rõ ràng hoặc trong suốt trở nên kém rõ rệt, mờ ảo hoặc đục đi."},"8038":{"word":"mờ ảo","meaning":"Diễn tả trạng thái không sáng rõ hoặc không trong suốt, khiến cho việc nhìn khó khăn."},"8039":{"word":"hài lòng, mãn nguyện","meaning":"Cảm thấy vui vẻ, ấm áp vì một điều gì đó tốt đẹp đã xảy ra hoặc kết thúc tốt đẹp."},"8040":{"word":"lộn xộn, rối bời, xáo trộn","meaning":"Bị vứt lộn xộn, không theo thứ tự nào, hoặc bị xáo trộn, không còn giữ nguyên trạng thái ban đầu."},"8041":{"word":"màu đen","meaning":"Màu của bầu trời đêm hoặc mực khi không có ánh sáng."},"8042":{"word":"vết xước, khuyết điểm, lỗi","meaning":"Một dấu vết nhỏ trên bề mặt vật thể như vết xước, vết lõm, làm vật đó kém hoàn hảo hoặc bớt đẹp."},"8043":{"word":"ướt sũng, đẫm","meaning":"Chỉ trạng thái bị thấm đầy, ướt đẫm hoàn toàn, thường là chất lỏng."},"8044":{"word":"hút thuốc","meaning":"Hành động châm một điếu thuốc lá hoặc vật tương tự và hít, thở khói của nó."},"8045":{"word":"sự phấn khích, hứng thú","meaning":"Cảm giác vui vẻ, phấn chấn và tràn đầy năng lượng khiến người ta muốn hát, nhảy múa hoặc ăn mừng."},"8046":{"word":"vui tươi, náo nhiệt, tưng bừng","meaning":"Chỉ một tình huống hoặc không khí tràn ngập niềm vui và sự phấn khởi, khiến mọi người muốn ăn mừng."},"8047":{"word":"hấp dẫn, ly kỳ, thú vị","meaning":"Diễn tả một câu chuyện, sự kiện hoặc trò chơi giữ được sự chú ý hoàn toàn của bạn vì nó rất lôi cuốn và bạn muốn biết điều gì sẽ xảy ra tiếp theo."},"8048":{"word":"ngân nga","meaning":"Phát ra một âm thanh âm nhạc nhẹ nhàng, liên tục bằng miệng ngậm lại, thường là một giai điệu bài hát."},"8049":{"word":"doanh thu phòng vé, thành công thương mại","meaning":"Tình trạng một bộ phim, vở kịch hoặc chương trình thu hút nhiều người xem và kiếm được nhiều tiền."},"8050":{"word":"bay lả tả, tung bay, phân tán","meaning":"Bị thổi hoặc rơi rải rác trên một khu vực rộng lớn, di chuyển theo nhiều hướng khác nhau, giống như lá rụng trong gió."},"8051":{"word":"hỉ nộ ái ố","meaning":"Tập hợp những cảm xúc đa dạng của con người như vui, giận, buồn, vui thích."},"8052":{"word":"tin tốt, tin mừng","meaning":"Một thông tin khiến mọi người vui vẻ hoặc cảm thấy tốt hơn."},"8053":{"word":"gợi ý, ám chỉ","meaning":"Một chút thông tin hoặc đề xuất nhỏ giúp ai đó giải quyết vấn đề hoặc tìm ra câu trả lời."},"8054":{"word":"yếu ớt, yếu đuối","meaning":"Có ít sức lực, thường khiến cơ thể di chuyển chậm chạp, khom lưng hoặc giọng nói yếu ớt."},"8055":{"word":"dồn sức, gắng sức","meaning":"Gồng cơ hoặc dùng sức mạnh cơ thể để tạo áp lực vật lý hoặc nỗ lực hết sức."},"8056":{"word":"tài chính gia đình, kinh tế gia đình","meaning":"Hệ thống quản lý cách một gia đình kiếm và chi tiêu tiền bạc."},"8057":{"word":"vừa vặn, suýt soát","meaning":"Vất vả lắm mới làm hoặc đạt được điều gì đó một cách suýt soát, sau nhiều nỗ lực và gần như thất bại."},"8058":{"word":"mảnh mai, yếu ớt","meaning":"Có dáng người rất mảnh mai và tinh tế, trông có vẻ dễ vỡ hoặc không mạnh mẽ."},"8059":{"word":"giữ thăng bằng, tự chủ","meaning":"Giữ cho cơ thể hoặc một bộ phận của nó thẳng đứng và ổn định, không bị rung lắc hoặc đổ ngã."},"8060":{"word":"ước lượng, ước tính","meaning":"Hành động phỏng đoán kích thước, số lượng hoặc khoảng cách của cái gì đó bằng cách quan sát hơn là đo lường chính xác."},"8061":{"word":"trấn tĩnh, chấn chỉnh","meaning":"Bình tâm suy nghĩ hoặc cảm xúc, thường bằng cách hít thở sâu, hoặc làm cho cái gì đó gọn gàng và ngăn nắp hơn."},"8062":{"word":"tham gia, góp phần","meaning":"Hành động gia nhập một nhóm hoặc hoạt động và đóng vai trò trong đó."},"8063":{"word":"sự vận hành","meaning":"Trạng thái máy móc, hệ thống đang hoạt động và thực hiện chức năng đã định."},"8064":{"word":"vốn dĩ, đã vậy","meaning":"Diễn tả tình trạng vốn đã khó khăn, tồi tệ trước khi có thêm một sự việc khác xảy ra làm cho nó tệ hơn."},"8065":{"word":"làm lắng xuống, làm dịu đi","meaning":"Làm cho các hạt rắn trong chất lỏng rơi xuống đáy hoặc làm cho con người, tình hình bớt lo lắng, căng thẳng."},"8066":{"word":"chọn lọc, phân loại","meaning":"Kiểm tra nhiều thứ và tách riêng những thứ cụ thể ra khỏi một nhóm, thường là vì chúng bị lỗi hoặc khác biệt."},"8067":{"word":"giả sử, ví dụ","meaning":"Được dùng khi đưa ra một tình huống hoặc ý tưởng giả định để minh họa cho một vấn đề."},"8068":{"word":"băng qua, đi ngang qua","meaning":"Di chuyển hoặc kéo dài trực tiếp từ một phía của một khu vực hoặc con đường sang phía đối diện."},"8069":{"word":"cướp, chộp lấy","meaning":"Nhanh chóng lấy thứ gì đó, thường là không được phép, mà vốn dĩ đang trên đường đến hoặc dành cho người khác."},"8070":{"word":"lời dạy, sự chỉ dẫn","meaning":"Sự hướng dẫn hoặc thông tin mà ai đó chia sẻ để giúp người khác học hỏi hoặc hiểu."},"8071":{"word":"thở dốc, hổn hển","meaning":"Miêu tả trạng thái thở rất nhanh và khó khăn, thường là sau khi hoạt động thể chất vất vả."},"8072":{"word":"ảo","meaning":"Thứ gì đó dường như tồn tại và hoạt động như thật nhưng chỉ được tạo ra và trải nghiệm thông qua phần mềm máy tính."},"8073":{"word":"giả thuyết","meaning":"Một mệnh đề được kỳ vọng giải thích một tình huống; một ý tưởng, v.v. trong một nghiên cứu, nhưng vẫn chưa được chứng minh."},"8074":{"word":"sự tham gia, sự góp sức","meaning":"Hành động một cá nhân hoặc nhóm thêm sự hiện diện, hỗ trợ hoặc nỗ lực của họ vào một hoạt động hoặc mục đích hiện có."},"8075":{"word":"sự tăng tốc","meaning":"Quá trình một vật thể di chuyển nhanh hơn, tốc độ tăng lên."},"8076":{"word":"giả tạo, đạo đức giả","meaning":"Miêu tả nụ cười hoặc hành động không chân thật, cố ý che giấu cảm xúc thật."},"8077":{"word":"sự đun nóng, sự gia nhiệt","meaning":"Hành động làm tăng nhiệt độ của một vật thể hay chất nào đó."},"8078":{"word":"đáng thương, tội nghiệp","meaning":"Diễn tả cảm giác thương xót khi ai đó ở trong hoàn cảnh đáng buồn, yếu đuối hoặc khó khăn."},"8079":{"word":"sự cắn rứt (lương tâm)","meaning":"Cảm giác lo lắng, khó chịu sâu sắc khi nhận thấy mình đã làm điều gì sai trái về mặt đạo đức."},"8080":{"word":"sự bỏ nhà đi","meaning":"Hành động một người, đặc biệt là trẻ em hoặc thanh thiếu niên, rời khỏi nhà mà không được phép."},"8081":{"word":"dốc, dựng đứng","meaning":"Miêu tả một bề mặt hoặc con dốc nghiêng rất mạnh và đột ngột, gây khó khăn khi leo hoặc xuống."},"8082":{"word":"áp dụng, gây ra","meaning":"Hướng một lực, áp lực hoặc tác động lên người hoặc vật khác, thường với ý định tạo ra hiệu quả."},"8083":{"word":"sự khắc nghiệt, sự tàn khốc","meaning":"Tính chất miêu tả hành động hoặc điều kiện cực kỳ nghiêm trọng, gây ra đau khổ hoặc khó khăn lớn."},"8084":{"word":"gia huấn, châm ngôn gia đình","meaning":"Câu nói ngắn gọn thể hiện niềm tin và giá trị định hướng cho các thành viên trong một gia đình."},"8085":{"word":"quả thực, thật sự","meaning":"Trạng từ dùng để nhấn mạnh mức độ hoặc tính chính xác đáng kinh ngạc của một tuyên bố."},"8086":{"word":"góc (mặt)","meaning":"Đường nét, điểm gặp nhau của các bề mặt tạo thành hình dạng cụ thể, đặc biệt là trên khuôn mặt."},"8087":{"word":"mọi giới","meaning":"Từ chỉ tất cả các lĩnh vực, ngành nghề hoặc giới hoạt động khác nhau trong xã hội."},"8088":{"word":"mọi tầng lớp xã hội","meaning":"Từ chỉ những người từ nhiều tầng lớp, nghề nghiệp và hoàn cảnh khác nhau trong cộng đồng hoặc xã hội."},"8089":{"word":"riêng rẽ","meaning":"Trạng từ chỉ việc mỗi cá nhân hoặc đối tượng được xem xét hoặc xử lý một cách độc lập, tách rời khỏi một nhóm."},"8090":{"word":"góc","meaning":"Khoảng không gian hoặc hình dạng được tạo thành khi hai đường hoặc hai bề mặt gặp nhau tại một điểm."},"8091":{"word":"khắc nghiệt","meaning":"Diễn tả một xã hội hoặc tình huống thiếu vắng lòng tốt, sự hào phóng hoặc tình người ấm áp."},"8092":{"word":"đặc biệt","meaning":"Miêu tả điều gì đó có tầm quan trọng khác thường hoặc được đối xử với sự chú ý và quan tâm đặc biệt."},"8093":{"word":"đặc biệt","meaning":"Trạng từ chỉ ra rằng một hành động hoặc sự quan sát được thực hiện với tầm quan trọng, sự cẩn thận hoặc cân nhắc lớn hơn bình thường."},"8094":{"word":"kịch bản","meaning":"Bản mô tả chi tiết về lời thoại, hành động của diễn viên và các cảnh trong một bộ phim hoặc vở kịch."},"8095":{"word":"sự thức tỉnh","meaning":"Khoảnh khắc đột ngột khi tâm trí hoàn toàn nhận thức được một sự thật quan trọng hoặc một tình huống mà trước đây chưa từng để ý."},"8096":{"word":"đa dạng","meaning":"Miêu tả một tập hợp nhiều vật thể hiển thị nhiều loại, hình thức hoặc đặc điểm khác nhau."},"8097":{"word":"bỏ qua","meaning":"Vô tình không nhìn thấy, không xem xét hoặc không chú ý đến điều gì đó quan trọng, khiến nó hoàn toàn không được nhận thấy hoặc giải quyết."},"8098":{"word":"buổi tọa đàm","meaning":"Một cuộc gặp gỡ nơi một nhóm người trò chuyện cởi mở về một chủ đề cụ thể, không tuân theo các quy tắc hoặc thủ tục trang trọng."},"8099":{"word":"súc tích","meaning":"Mô tả một điều gì đó bằng rất ít từ hoặc chỉ những điểm chính, làm cho nó dễ hiểu nhanh chóng."},"8100":{"word":"đêm qua","meaning":"Khoảng thời gian khi trời tối và hầu hết mọi người đi ngủ, ngay trước ngày hiện tại."},"8101":{"word":"cán bộ","meaning":"Người giữ vị trí cao trong một tổ chức hoặc công ty và lãnh đạo những người khác."},"8102":{"word":"sự coi như","meaning":"Hành động dán nhãn hoặc xác định ai đó hay điều gì đó thuộc về một nhóm nhất định hoặc có một phẩm chất cụ thể."},"8103":{"word":"gián điệp","meaning":"Người bí mật thu thập thông tin, thường là cho một quốc gia, bằng cách giả vờ là người khác hoặc che giấu danh tính thật của mình."},"8104":{"word":"nhánh","meaning":"Một trong số nhiều phần tách ra và đi theo các hướng khác nhau từ một vật chính hoặc con đường chính."},"8105":{"word":"sự khao khát","meaning":"Một mong muốn mạnh mẽ và bền bỉ về một điều gì đó, khiến một người không ngừng nghĩ về nó hoặc hăng hái làm việc để đạt được nó."},"8106":{"word":"manh mối","meaning":"Một mẩu thông tin hoặc sự hiểu biết giúp ai đó giải quyết một tình huống khó hiểu hoặc quyết định bước tiếp theo."},"8107":{"word":"linh cảm","meaning":"Một sự hiểu biết hoặc nhận thức trực giác về một điều gì đó."},"8108":{"word":"cảm động","meaning":"Cảm thấy những cảm xúc tích cực mạnh mẽ, như niềm vui lớn hoặc lòng biết ơn, đến mức có thể khóc hoặc ngập tràn hạnh phúc."},"8109":{"word":"sự giam giữ","meaning":"Hành động giữ một người ở một nơi cụ thể và ngăn cản họ rời đi, thường bằng cách khóa họ lại."},"8110":{"word":"sự gánh vác","meaning":"Hành động xử lý thành công một tình huống khó khăn, một khối lượng công việc lớn hoặc một trách nhiệm nặng nề."},"8111":{"word":"bao trùm","meaning":"Diễn tả không khí, mùi hương hoặc âm thanh tồn tại ở một nơi nhất định hoặc lan tỏa khắp khu vực."},"8112":{"word":"giảm cân","meaning":"Hành động làm giảm khối lượng hoặc số lượng của một cái gì đó, đặc biệt là trọng lượng cơ thể."},"8113":{"word":"miễn giảm","meaning":"Hành động giảm bớt số tiền phải trả, hình phạt hoặc miễn hoàn toàn nghĩa vụ chi trả."},"8114":{"word":"ấn tượng sâu sắc","meaning":"Cảm giác hoặc ký ức mạnh mẽ còn đọng lại trong lòng sau khi trải nghiệm một điều gì đó đáng nhớ."},"8115":{"word":"xu hướng giảm","meaning":"Dạng biến động trong đó số lượng, khối lượng hoặc kích thước liên tục giảm dần theo thời gian."},"8116":{"word":"sự chấp nhận","meaning":"Hành động chịu đựng một tình huống khó khăn hoặc không dễ chịu mà không kháng cự."},"8117":{"word":"sự nhạy cảm","meaning":"Khả năng dễ dàng cảm nhận hoặc nhận biết những thay đổi nhỏ, cảm xúc hoặc kích thích vật lý."},"8118":{"word":"sự cân nhắc","meaning":"Hành động suy nghĩ cẩn thận về các sự thật hoặc điều kiện nhất định trước khi đưa ra quyết định hay kế hoạch."},"8119":{"word":"lời đường mật","meaning":"Những lời nói nhẹ nhàng, có tính thuyết phục, thường được dùng để lấy lòng hoặc lừa gạt người khác."},"8120":{"word":"cắt giảm nhân sự","meaning":"Hành động giảm số lượng người lao động được tuyển dụng trong một công ty hoặc tổ chức."},"8121":{"word":"sự phát hiện","meaning":"Hành động nhận ra hoặc tìm thấy một cái gì đó trước đây không rõ ràng hoặc không dễ nhận biết."},"8122":{"word":"không dấu vết","meaning":"Một cách không để lại bất kỳ dấu hiệu hoặc bằng chứng nào cho thấy điều gì đó đã xảy ra hay bị thay đổi, như thể bằng phép thuật."},"8123":{"word":"cảm giác chạm","meaning":"Cảm giác mà một vật mang lại khi ta dùng tay chạm vào."},"8124":{"word":"sự cắt giảm","meaning":"Việc làm cho một cái gì đó giảm bớt về số lượng, kích thước hoặc quy mô."},"8125":{"word":"giảm bớt","meaning":"Lấy đi một lượng nhất định từ tổng số, làm cho số lượng ban đầu nhỏ hơn."},"8126":{"word":"cảm hoài","meaning":"Cảm xúc mạnh mẽ hoặc ký ức chợt dấy lên khi nghĩ về những trải nghiệm trong quá khứ hoặc sự kiện quan trọng."},"8127":{"word":"giá trị","meaning":"Số tiền mà một thứ có thể được trao đổi, hoặc tầm quan trọng và sự hữu ích của nó."},"8128":{"word":"vừa mới","meaning":"Diễn tả một việc gì đó vừa mới xảy ra hoặc được thực hiện trong một khoảng thời gian rất ngắn."},"8129":{"word":"cưỡng hiếp","meaning":"Hành vi bạo lực buộc một người khác tham gia vào hoạt động tình dục trái với ý muốn của họ."},"8130":{"word":"thế mạnh","meaning":"Sức mạnh đáng chú ý hoặc sự hiện diện rộng rãi của một cái gì đó trong một tình huống cụ thể."},"8131":{"word":"sự cưỡng ép","meaning":"Tình trạng một người bị buộc phải hành động trái với ý muốn của mình bằng vũ lực, đe dọa hoặc hăm dọa."},"8132":{"word":"kiên cường","meaning":"Có sức mạnh thể chất hoặc tinh thần lớn để tiếp tục vượt qua khó khăn hoặc đối mặt với thử thách."},"8133":{"word":"điểm mạnh","meaning":"Một kỹ năng hoặc phẩm chất cụ thể giúp ai đó hoặc cái gì đó rất giỏi hoặc thành công."},"8134":{"word":"mang tính cưỡng chế","meaning":"Một việc được thực hiện mà không có sự đồng ý của một người, thường là do lệnh hoặc quy tắc từ cơ quan có thẩm quyền."},"8135":{"word":"chính trực","meaning":"Người có tính cách kiên định, trung thực, không bao giờ để những ảnh hưởng xấu làm thay đổi nguyên tắc của mình."},"8136":{"word":"cưỡng hành","meaning":"Hành động thực hiện một kế hoạch hoặc hành động bất chấp khó khăn hoặc sự phản đối mạnh mẽ từ người khác."},"8137":{"word":"khai trương","meaning":"Lễ hoặc ngày chính thức một tòa nhà công cộng mới như bảo tàng hoặc thư viện lần đầu tiên được mở cửa cho mọi người vào sử dụng."},"8138":{"word":"khái quát","meaning":"Miêu tả những ý chính một cách tổng thể mà không đi sâu vào từng chi tiết nhỏ."},"8139":{"word":"hài","meaning":"Một câu chuyện cười ngắn, hành động hài hước hoặc màn trình diễn gây cười nhằm mục đích giải trí cho mọi người."},"8140":{"word":"cải tiến","meaning":"Quá trình làm cho một cái gì đó tốt hơn về chất lượng, điều kiện hoặc hiệu quả, ví dụ như làm cho cây trồng phát triển mạnh hơn hoặc công cụ hoạt động hiệu quả hơn."},"8141":{"word":"khai mạc","meaning":"Lễ khai mạc hoặc sự kiện bắt đầu chính thức của một sự kiện lớn như cuộc thi thể thao, lễ hội hoặc triển lãm."},"8142":{"word":"cá nhân","meaning":"Một cái gì đó tách biệt và khác biệt, áp dụng cho một người hoặc vật cụ thể thay vì một nhóm."},"8143":{"word":"khởi sự","meaning":"Thời điểm hoặc điểm ban đầu mà một hành động, hoạt động hoặc quá trình bắt đầu một cách rõ ràng."},"8144":{"word":"Tin lành","meaning":"Một nhánh chính của Kitô giáo bắt đầu vào thế kỷ 16, các tín đồ thường thờ phượng trong các nhà thờ không có tượng hoặc nghi lễ phức tạp."},"8145":{"word":"sảng khoái","meaning":"Trải nghiệm cảm giác nhẹ nhàng và tràn đầy năng lượng mới mẻ, thường sau khi thức dậy hoặc tắm rửa."},"8146":{"word":"can thiệp","meaning":"Hành động một người hoặc một nhóm tham gia vào một tình huống hoặc vấn đề để cố gắng ảnh hưởng đến kết quả của nó."},"8147":{"word":"Sự chuyển thể, sự cải biên","meaning":"Việc thay đổi một tác phẩm gốc để phù hợp với một hình thức hoặc đối tượng khác."},"8148":{"word":"Sự sửa đổi, sự sửa lại","meaning":"Hành động điều chỉnh nội dung không phù hợp hoặc sai trong một văn bản."},"8149":{"word":"Cá thể, vật thể đơn lẻ","meaning":"Một vật phẩm hoặc sinh vật riêng biệt, độc lập với những loài khác."},"8150":{"word":"Sự cải tổ, sự sắp xếp lại","meaning":"Hành động thay đổi cấu trúc hoặc sự sắp xếp của một cái gì đó để cải thiện chức năng của nó."},"8151":{"word":"Việc kiểm phiếu, việc đếm phiếu","meaning":"Quá trình kiểm tra và tổng hợp các lá phiếu trong một cuộc bầu cử để xác định người chiến thắng."},"8152":{"word":"Nơi xa nhà, đất khách","meaning":"Một địa điểm mà ai đó sống hoặc ở cách xa nơi ở gốc và gia đình của họ."},"8153":{"word":"Khoản tiền khổng lồ, số tiền lớn","meaning":"Một khoản tiền rất lớn."},"8154":{"word":"Sự đi lại, sự di chuyển","meaning":"Cách một người đi lại, đứng hoặc di chuyển cơ thể, thường liên quan đến mức độ dễ dàng hoặc khó khăn khi thực hiện các hành động này."},"8155":{"word":"Nhiều lần, lặp đi lặp lại","meaning":"Nhiều lần liên tiếp, thường để nhấn mạnh một điểm hoặc đảm bảo công việc được hoàn thành kỹ lưỡng."},"8156":{"word":"Tái sinh, được sinh ra lần nữa","meaning":"Trải qua một sự thay đổi hoàn toàn về tính cách hoặc lối sống, như thể bắt đầu một cuộc sống mới."},"8157":{"word":"Dễ dàng, nhẹ nhàng","meaning":"Nhẹ và không đòi hỏi nhiều nỗ lực hoặc sức mạnh để hoàn thành, cho phép một người làm việc đó mà không gặp khó khăn."},"8158":{"word":"Sự đề cập, sự nhắc đến","meaning":"Hành động đưa một chủ đề, người hoặc tên cụ thể vào cuộc trò chuyện hoặc cuộc họp để xem xét."},"8159":{"word":"thiêng liêng","meaning":"Có một sự linh thiêng, thiêng liêng và đáng được tôn kính sâu sắc."},"8160":{"word":"lọc","meaning":"Làm cho chất lỏng hoặc chất lỏng đi qua một màn lọc hoặc vật liệu đặc biệt để loại bỏ các hạt nhỏ không mong muốn."},"8161":{"word":"bỏ bữa","meaning":"Cố ý không ăn vào các bữa ăn thông thường như bữa sáng hoặc bữa tối."},"8162":{"word":"sự ngần ngại","meaning":"Cảm giác nghi ngờ hoặc lo lắng khiến ai đó không muốn làm điều gì đó."},"8163":{"word":"đàn geomungo","meaning":"Một nhạc cụ dây lớn truyền thống của Hàn Quốc có phím, thường được chơi bằng cách gảy dây bằng một cây gậy."},"8164":{"word":"cảm giác từ chối","meaning":"Cảm giác không muốn chấp nhận hoặc đón nhận điều gì đó."},"8165":{"word":"khó chịu","meaning":"Có cảm giác khó chịu ở dạ dày hoặc cảm thấy lúng túng, gượng gạo trong tình huống xã hội."},"8166":{"word":"chống lại","meaning":"Hành động chống lại hoặc không tuân theo một mệnh lệnh, quy tắc hoặc ý muốn."},"8167":{"word":"chướng mắt","meaning":"Khiến ai đó cảm thấy khó chịu hoặc không hài lòng vì điều gì đó trông hoặc nghe có vẻ không đúng."},"8168":{"word":"vĩ mô","meaning":"Liên quan đến việc xem xét mọi thứ ở quy mô lớn hoặc tổng thể, thay vì từng phần riêng lẻ."},"8169":{"word":"hoành tráng","meaning":"Có quy mô rất lớn và ấn tượng, đôi khi có vẻ quá tham vọng hoặc phô trương."},"8170":{"word":"nơi ở","meaning":"Một nơi như nhà hoặc căn hộ mà một người sinh sống."},"8171":{"word":"không ngần ngại","meaning":"Thực hiện một việc gì đó một cách trôi chảy, không có bất kỳ sự ngập ngừng hay cản trở nào."},"8172":{"word":"kiến lập","meaning":"Việc xây dựng một công trình kiến trúc lớn hoặc thành lập một tổ chức, cơ quan."},"8173":{"word":"kiêu căng","meaning":"Có thái độ kiêu ngạo, tự phụ và thường đối xử thiếu tôn trọng với người khác."},"8174":{"word":"sự hời hợt","meaning":"Thái độ thực hiện việc gì đó một cách qua loa, không nghiêm túc hay không chú tâm."},"8175":{"word":"cường tráng","meaning":"Có thể chất khỏe mạnh, vạm vỡ và trông rắn chắc."},"8176":{"word":"lành mạnh","meaning":"Trạng thái tốt đẹp, có lợi cho tinh thần hoặc xã hội, thường liên quan đến đạo đức và giá trị."},"8177":{"word":"kiểm soát","meaning":"Kiểm soát hoặc ngăn chặn điều gì đó đang lan rộng nhanh chóng, không để nó vượt khỏi tầm tay."},"8178":{"word":"mắc bẫy","meaning":"Bị mắc vào một cái bẫy, lưới hay tình huống khó khăn nào đó mà không thoát ra được."},"8179":{"word":"chướng ngại vật","meaning":"Một vật cản trên đường đi hoặc một vấn đề gây khó khăn, cản trở sự tiến bộ."},"8180":{"word":"phù hợp","meaning":"Thích hợp hoặc đúng đắn với một người hay một tình huống cụ thể."},"8181":{"word":"kiệt tác","meaning":"Một tác phẩm nghệ thuật, âm nhạc hoặc văn học được coi là cực kỳ xuất sắc và quan trọng."},"8182":{"word":"ngồi vắt vẻo","meaning":"Đặt cơ thể lên một bề mặt sao cho chỉ một phần nhỏ của mông chạm vào, thường là với chân buông thõng."},"8183":{"word":"hễ một chút là","meaning":"Dù có nguyên nhân nhỏ đến đâu, cũng thường xuyên xảy ra hành động hoặc cảm xúc mạnh."},"8184":{"word":"bắt giữ","meaning":"Hành động cảnh sát bắt một người bị tình nghi là tội phạm và đưa vào giam giữ."},"8185":{"word":"kiểm tra","meaning":"Việc cảnh sát hay lính gác dừng người hoặc phương tiện để kiểm tra kỹ lưỡng tại một địa điểm nhất định."},"8186":{"word":"sự giản dị, tiết kiệm","meaning":"Lối sống đơn giản, cẩn thận trong việc sử dụng tiền bạc và đồ đạc để tránh lãng phí."},"8187":{"word":"kiểm chứng","meaning":"Việc kiểm tra cẩn thận các sự thật hoặc tuyên bố để xác định xem chúng có đúng hoặc chính xác hay không."},"8188":{"word":"Viện kiểm sát","meaning":"Cơ quan nhà nước có nhiệm vụ điều tra tội phạm, thu thập bằng chứng và buộc tội những người bị nghi ngờ phạm tội."},"8189":{"word":"sao nhãng, lơ là","meaning":"Không dành sự quan tâm hoặc chăm sóc đúng mức cho một nhiệm vụ hoặc việc gì đó, khiến nó bị bỏ bê hoặc không được hoàn thành."},"8190":{"word":"việc đăng tải","meaning":"Quá trình đưa một bài viết hoặc tác phẩm vào báo, tạp chí hoặc sách để mọi người đọc."},"8191":{"word":"sự nhắm","meaning":"Hành động chỉ vũ khí hoặc vật thể một cách chính xác về một điểm hoặc vị trí cụ thể."},"8192":{"word":"nhắm vào, chĩa vào","meaning":"Cầm vũ khí hoặc vật thể và định vị nó sao cho hướng thẳng chính xác về một điểm hoặc người cụ thể."},"8193":{"word":"cạnh tranh, thi đấu","meaning":"Tham gia vào một cuộc thi hoặc thử thách với người hoặc nhóm khác để xác định ai thực hiện tốt hơn."},"8194":{"word":"sự cách ly","meaning":"Hành động giữ một người hoặc vật tách biệt khỏi những người hoặc vật khác, thường để ngăn ngừa bệnh lây lan hoặc vì an toàn."},"8195":{"word":"cảm giác thời thế đổi thay","meaning":"Cảm giác như thời gian trôi qua rất nhanh và mọi thứ đã thay đổi rất nhiều chỉ trong một thời gian ngắn, khiến người ta ngạc nhiên."},"8196":{"word":"cách ngôn","meaning":"Một câu nói ngắn gọn, nổi tiếng, thể hiện một sự thật phổ quát hoặc đưa ra lời khuyên."},"8197":{"word":"cách tuần","meaning":"Xảy ra hoặc diễn ra hai tuần một lần, bỏ qua một tuần ở giữa."},"8198":{"word":"chênh lệch","meaning":"Khoảng cách hoặc sự khác biệt rõ rệt giữa hai điểm, con số hoặc tình huống cho thấy sự không bằng nhau."},"8199":{"word":"chắc chắn","meaning":"Sản phẩm hoặc cấu trúc được xây dựng vững chãi, bền chắc, không dễ bị hỏng hoặc xê dịch."},"8200":{"word":"hạt khô","meaning":"Loại quả từ cây, như hạt dẻ, óc chó, bạch quả, v.v., có một hạt bên trong lớp vỏ cứng."},"8201":{"word":"kiến thức","meaning":"Những kinh nghiệm thu được thông qua việc nhìn và nghe, hoặc kiến thức có được từ những điều đó."},"8202":{"word":"mẫu","meaning":"Một vật được tạo ra để trông giống và hoạt động như một vật khác nhằm minh họa chất lượng hoặc hiệu suất của nó."},"8203":{"word":"kiềm chế","meaning":"Hành động được thực hiện để ngăn cản ai đó hoặc thứ gì đó đi quá xa hoặc giành quá nhiều quyền kiểm soát."},"8204":{"word":"so sánh","meaning":"Xem xét hai hoặc nhiều vật hoặc người cạnh nhau để quan sát những điểm tương đồng hoặc khác biệt giữa chúng."},"8205":{"word":"quyết định","meaning":"Hành động đưa ra một lựa chọn chắc chắn về những gì sẽ làm sau khi cân nhắc các khả năng khác nhau."},"8206":{"word":"sự quyết đoán","meaning":"Phẩm chất của một người có thể nhanh chóng và dứt khoát chọn điều cần làm từ nhiều lựa chọn."},"8207":{"word":"sự liên kết","meaning":"Là việc hai hay nhiều điều gì đó có mối quan hệ hoặc gắn bó với nhau."},"8208":{"word":"sự quyết toán","meaning":"Là hành động kiểm tra, tổng kết tất cả các khoản thu chi trong một khoảng thời gian để xác định tình hình tài chính cuối cùng."},"8209":{"word":"vòng chung kết","meaning":"Là trận đấu, vòng thi cuối cùng trong một sự kiện thể thao hoặc cuộc thi để xác định người chiến thắng cuối cùng."},"8210":{"word":"sự thành lập","meaning":"Là hành động tập hợp một số người hoặc bộ phận lại với nhau để tạo thành một đội, câu lạc bộ hoặc tổ chức mới."},"8211":{"word":"sự đoàn kết","meaning":"Là tình trạng một nhóm người có cùng chí hướng tập hợp lại với nhau để tạo nên sự thống nhất và bền chặt."},"8212":{"word":"vạch đích","meaning":"Là đường kẻ đánh dấu điểm kết thúc trong các sự kiện thể thao như cuộc đua."},"8213":{"word":"sự thiếu vắng","meaning":"Là tình trạng thiếu một cách rõ ràng hoặc không đủ số lượng của một thứ gì đó cần phải có."},"8214":{"word":"sự quyết tâm","meaning":"Là một quyết định mạnh mẽ và kiên định để đạt được mục tiêu hoặc thực hiện một hành động, thường thể hiện qua sự nỗ lực tập trung của một người."},"8215":{"word":"nghị quyết","meaning":"Là một quyết định chính thức hoặc tuyên bố chính thức được đưa ra bởi một nhóm hoặc tổ chức sau khi thảo luận, thường được ghi lại bằng văn bản."},"8216":{"word":"khuyết điểm","meaning":"Là một sai sót nhỏ hoặc sự không hoàn hảo dễ nhận thấy ở một vật thể hoặc một đặc điểm cá nhân, làm cho nó kém hoàn hảo."},"8217":{"word":"quyết định","meaning":"Là đạt được một kết quả hoặc kết luận cuối cùng cho một tình huống, thiết lập cách mọi việc sẽ kết thúc."},"8218":{"word":"sự thiếu hụt nghiêm trọng","meaning":"Là tình trạng thiếu hụt nghiêm trọng một thứ gì đó thiết yếu, như thức ăn hoặc chất dinh dưỡng, cản trở sự phát triển hoặc sức khỏe bình thường."},"8219":{"word":"lỗi","meaning":"Một vấn đề hoặc điểm yếu nghiêm trọng trong máy móc hoặc hệ thống làm nó không hoạt động đúng cách."},"8220":{"word":"khiêm tốn","meaning":"Thái độ tôn trọng và không tự cho mình là hơn người khác."},"8221":{"word":"cảnh giác","meaning":"Trạng thái luôn để ý và sẵn sàng nhận ra bất kỳ mối nguy hiểm hay vấn đề nào có thể xuất hiện."},"8222":{"word":"kính cẩn","meaning":"Có thái độ rất nghiêm túc và kính trọng sâu sắc, thường thấy trong các nghi lễ tôn giáo hoặc sự kiện quan trọng."},"8223":{"word":"sự cảnh giác","meaning":"Hành động cẩn thận và quan sát xung quanh để ngăn chặn tai nạn hoặc nguy hiểm bất ngờ."},"8224":{"word":"thông báo cảnh báo","meaning":"Một tấm biển hoặc mảnh giấy có chữ viết thông báo cho mọi người về nguy hiểm hoặc điều họ không nên làm."},"8225":{"word":"công nghiệp nhẹ","meaning":"Ngành sản xuất các sản phẩm như quần áo, thực phẩm và giày dép bằng máy móc không quá lớn hoặc nặng."},"8226":{"word":"cảnh quan","meaning":"Tất cả những gì tự nhiên có thể nhìn thấy từ một nơi cụ thể, thường tạo nên một khung cảnh đẹp."},"8227":{"word":"co thắt","meaning":"Sự co cơ đột ngột, không kiểm soát được và thường gây đau trong cơ thể."},"8228":{"word":"lộ trình","meaning":"Con đường hoặc hướng đi cụ thể mà ai đó di chuyển hoặc vật gì đó đi từ điểm này đến điểm khác."},"8229":{"word":"đấu giá","meaning":"Một sự kiện công khai nơi các mặt hàng được bán cho người trả giá cao nhất, thường bằng cách gọi giá."},"8230":{"word":"khinh bỉ","meaning":"Cảm giác mạnh mẽ cho thấy ai đó hoặc điều gì đó được coi là hoàn toàn vô giá trị và không đáng được tôn trọng."},"8231":{"word":"báo động","meaning":"Âm thanh lớn hoặc tín hiệu nhìn thấy được dùng để báo hiệu nguy hiểm hoặc tình huống khẩn cấp."},"8232":{"word":"hỷ sự","meaning":"Những sự kiện vui vẻ, tốt đẹp đáng được ăn mừng."},"8233":{"word":"coi thường","meaning":"Hành động không coi trọng, đánh giá thấp giá trị hoặc tầm quan trọng của một điều gì đó."},"8234":{"word":"kinh ngạc","meaning":"Trạng thái rất ngạc nhiên hoặc sốc trước một sự việc tồi tệ."},"8235":{"word":"cuộc thi","meaning":"Sự kiện mọi người hoặc các nhóm thể hiện kỹ năng hoặc thực hiện nhiệm vụ để tìm ra người giỏi nhất."},"8236":{"word":"ban quản lý","meaning":"Nhóm người chịu trách nhiệm quản lý và điều hành một doanh nghiệp hoặc công ty."},"8237":{"word":"quá cảnh","meaning":"Hành động dừng lại ở một địa điểm trung gian khi đi từ nơi này đến nơi khác."},"8238":{"word":"kỳ diệu","meaning":"Có những phẩm chất khiến người ta ngạc nhiên và ngưỡng mộ vì quá đẹp đẽ, vĩ đại hoặc đặc biệt."},"8239":{"word":"kinh điển","meaning":"Sách chứa đựng những lời dạy được tôn kính của các vị thánh."},"8240":{"word":"khối kinh tế","meaning":"Nhóm các quốc gia hoặc khu vực có mối liên hệ chặt chẽ thông qua hệ thống thương mại và tài chính."},"8241":{"word":"tính kinh tế","meaning":"Khía cạnh của một kế hoạch hoặc dự án cho thấy nó sẽ mang lại đủ tiền hoặc lợi nhuận để đáng giá."},"8242":{"word":"cảnh giới","meaning":"Một giai đoạn hoặc điểm cụ thể đạt được trong khả năng, sự hiểu biết hoặc trạng thái tinh thần."},"8243":{"word":"sự cứng đờ","meaning":"Tình trạng một bộ phận cơ thể hoặc vật liệu trở nên cứng nhắc, khó uốn cong hoặc cử động dễ dàng."},"8244":{"word":"sự lắng nghe chăm chú","meaning":"Hành động nghe người khác nói một cách tập trung và suy nghĩ cẩn thận."},"8245":{"word":"liếc mắt","meaning":"Hành động nhìn nhanh một người hoặc vật bằng cách chỉ đưa mắt sang một bên mà không quay đầu."},"8246":{"word":"thêm vào, kèm theo","meaning":"Bổ sung một lượng nhỏ thứ gì đó, như gia vị hoặc món ăn kèm, vào món chính."},"8247":{"word":"-gốc","meaning":"Hậu tố dùng để chỉ nguồn gốc gia đình của một người thuộc một quốc gia hoặc nhóm người cụ thể."},"8248":{"word":"sự kế thừa, kế vị","meaning":"Hành động tiếp nhận một vị trí, tước hiệu hoặc tài sản từ người khác, thường là sau khi họ qua đời hoặc nhường lại."},"8249":{"word":"hệ thống, dòng dõi","meaning":"Một tập hợp các bộ phận liên kết hoạt động cùng nhau như một thể thống nhất, hoặc nguồn gốc tổ tiên của một sinh vật."},"8250":{"word":"giá cao","meaning":"Một mức giá lớn phải trả để mua thứ gì đó, khiến nó trở nên đắt tiền."},"8251":{"word":"sự cạn kiệt","meaning":"Tình trạng nguồn cung cấp của một thứ gì đó, như tài nguyên hoặc năng lượng, đã bị sử dụng hết hoàn toàn và không còn lại gì."},"8252":{"word":"cao quý","meaning":"Có phẩm chất đạo đức cao, giá trị lớn hoặc địa vị xã hội cao, xứng đáng được kính trọng sâu sắc."},"8253":{"word":"việc đánh bắt cá","meaning":"Hoạt động đánh bắt động vật dưới nước từ một vùng nước, thường bằng lưới, cần câu hoặc bẫy."},"8254":{"word":"gian nan, khổ nạn","meaning":"Những trải nghiệm cực kỳ khó khăn hoặc đau khổ, gây ra nhiều rắc rối hoặc phiền muộn lớn cho một người."},"8255":{"word":"hầm","meaning":"Nấu thức ăn trong nước sôi nhỏ lửa trong nhiều giờ để nước đặc lại và đậm đà hơn."},"8256":{"word":"mệt mỏi","meaning":"Cảm thấy vô cùng mệt mỏi như thể tất cả năng lượng thể chất và tinh thần đã cạn kiệt."},"8257":{"word":"vất vả","meaning":"Mô tả công việc hoặc nhiệm vụ đòi hỏi nhiều nỗ lực, khiến người ta cảm thấy rất mệt mỏi và kiệt sức."},"8258":{"word":"tuổi già","meaning":"Tình trạng một người ở độ tuổi đã cao hoặc rất cao."},"8259":{"word":"già hóa dân số","meaning":"Tình trạng số lượng người lớn tuổi trong một quốc gia tăng lên đáng kể so với số lượng người trẻ."},"8260":{"word":"đều","meaning":"Theo một cách cân bằng, mọi thứ được phân bổ với số lượng bằng nhau hoặc trải đều, nhất quán."},"8261":{"word":"sự cô lập","meaning":"Tình trạng ở xa những người khác hoặc hoàn toàn bị cắt đứt mọi liên lạc với người hay vật khác."},"8262":{"word":"giày cao su truyền thống","meaning":"Một loại giày truyền thống của Hàn Quốc, thường màu đen hoặc trắng, được làm hoàn toàn từ chất liệu cao su co giãn, chống thấm nước, thường có mũi tròn."},"8263":{"word":"bước ngoặt","meaning":"Một khoảnh khắc hoặc giai đoạn rất quan trọng và khó khăn, nơi phải đưa ra quyết định hoặc thành công hay thất bại sẽ được định đoạt."},"8264":{"word":"đừng nói đến","meaning":"Cách dùng để chỉ rằng nếu một việc nhỏ hoặc dễ cũng không làm được thì một việc lớn hơn, khó hơn liên quan chắc chắn là không thể."},"8265":{"word":"thu nhập cao","meaning":"Một khoản thu nhập lớn."},"8266":{"word":"sự kiên trì","meaning":"Hành động giữ vững một quan điểm, quy tắc hoặc cách làm cụ thể, không có dấu hiệu thay đổi."},"8267":{"word":"nguyên vẹn","meaning":"Diễn tả trạng thái một vật còn nguyên trạng ban đầu, không bị mất mát hay thay đổi gì."},"8268":{"word":"trăn trở","meaning":"Việc suy nghĩ sâu sắc và lo lắng rất nhiều về một vấn đề khó khăn hay quyết định quan trọng."},"8269":{"word":"sáng chế, thiết kế","meaning":"Quá trình tạo ra một ý tưởng, kế hoạch hay vật thể mới thông qua việc suy nghĩ và thiết kế cẩn thận để giải quyết vấn đề."},"8270":{"word":"tồi tệ, khó chịu","meaning":"Diễn tả điều gì đó như mùi hay hành vi của ai đó rất khó chịu, xúc phạm hoặc khó dung thứ."},"8271":{"word":"yên lặng, tĩnh mịch","meaning":"Theo cách rất yên bình, không có tiếng động lớn, chuyển động đột ngột hay sự quấy rầy."},"8272":{"word":"sự thuê mướn","meaning":"Trạng thái một người được công ty hoặc cá nhân trả lương để thực hiện công việc."},"8273":{"word":"việc làm","meaning":"Việc tạo ra các vị trí công việc mới có trả lương, cho phép nhiều người hơn thực hiện công việc cho một công ty hoặc cá nhân."},"8274":{"word":"cấp cao, chức vụ cao","meaning":"Chức vụ hoặc cấp bậc cao."},"8275":{"word":"cố ý, chủ ý","meaning":"Tình trạng một hành động được thực hiện một cách có ý thức và có mục đích, chứ không phải ngẫu nhiên."},"8276":{"word":"người đã khuất","meaning":"Người đã chết."},"8277":{"word":"sự cao trào","meaning":"Trạng thái một điều gì đó như không khí, cảm xúc, trở nên mạnh mẽ, mãnh liệt hoặc đạt đến đỉnh điểm."},"8278":{"word":"khổ tận cam lai","meaning":"Câu nói có nghĩa rằng sau những khó khăn, gian khổ thì nhất định sẽ đến những điều tốt đẹp, hạnh phúc."},"8279":{"word":"nghiên cứu","meaning":"Hành động suy nghĩ và phân tích cẩn thận, sâu sắc một vấn đề để hiểu rõ bản chất của nó."},"8280":{"word":"nỗi khổ","meaning":"Một vấn đề hoặc khó khăn cụ thể gây ra sự phiền muộn, lo lắng cho một người, thường khó giải quyết."},"8281":{"word":"tiếng hét","meaning":"Âm thanh giọng nói lớn, mạnh mẽ do một người tạo ra, thường thể hiện cảm xúc mạnh như giận dữ, sợ hãi hoặc phấn khích."},"8282":{"word":"hoàn cảnh khó khăn","meaning":"Tình huống rất khó chịu và thử thách mà một người khó thoát ra hoặc tìm được giải pháp."},"8283":{"word":"cảnh khốn cùng","meaning":"Tình trạng một người có rất ít hoặc không có tiền, thức ăn và các nhu yếu phẩm cơ bản để sống."},"8284":{"word":"dựng đứng","meaning":"Làm cho một vật gì đó đang thả lỏng trở nên đứng thẳng lên hoặc làm cho giác quan trở nên rất nhạy bén, cảnh giác."},"8285":{"word":"sự nhục nhã","meaning":"Một trải nghiệm gây xấu hổ sâu sắc hoặc khó khăn, khiến một người cảm thấy rất khó chịu và đau đớn tinh thần."},"8286":{"word":"khung thành","meaning":"Cấu trúc có hai cột dọc và một thanh ngang phía trên, thường có lưới, nơi người chơi cố gắng đưa bóng vào để ghi điểm trong các môn thể thao như bóng đá."},"8287":{"word":"vấn đề đau đầu","meaning":"Một vấn đề phức tạp hoặc dai dẳng gây ra sự lo lắng, bực bội hoặc căng thẳng tinh thần lớn cho một người."},"8288":{"word":"thung lũng","meaning":"Một vùng đất thấp, thường dài và hẹp, nằm giữa các ngọn đồi hoặc núi và thường có sông hoặc suối chảy dọc theo đáy."},"8289":{"word":"vấn đề rắc rối","meaning":"Một điều gì đó khó giải quyết và gây ra nhiều phiền toái, rắc rối."},"8290":{"word":"mưng mủ","meaning":"Vết thương hoặc vết loét trên da bị sưng, đau và chứa đầy mủ, cho thấy tình trạng đang xấu đi."},"8291":{"word":"kỹ lưỡng","meaning":"Một cách cẩn thận, chi tiết khi suy nghĩ về một vấn đề nào đó."},"8292":{"word":"nấm mốc","meaning":"Loại nấm nhỏ, thường có màu xanh, đen hoặc trắng, mọc trên thức ăn ẩm ướt hoặc bề mặt."},"8293":{"word":"không gian","meaning":"Liên quan đến không gian vật lý hoặc sự sắp xếp của các vật thể trong không gian."},"8294":{"word":"công khai","meaning":"Được tiến hành một cách minh bạch, cho phép nhiều người thấy hoặc biết, không giữ bí mật."},"8295":{"word":"công khai","meaning":"Sự thật hoặc sự việc được nhiều người biết đến và thường xuyên bàn tán."},"8296":{"word":"công quyền","meaning":"Quyền lực của chính phủ hoặc các cơ quan chức năng để buộc người dân tuân thủ luật pháp và quy định."},"8297":{"word":"chiến lược","meaning":"Kế hoạch chi tiết được lập ra để đạt được mục tiêu hoặc kiểm soát một địa điểm, tình huống cụ thể."},"8298":{"word":"công lao","meaning":"Hành động hoặc thành tựu có ích cho người khác hoặc một tập thể, được ca ngợi và công nhận."},"8299":{"word":"công lập","meaning":"Một tổ chức hoặc cơ sở được chính phủ hỗ trợ tài chính và phục vụ tất cả công dân."},"8300":{"word":"cuộc thi công khai","meaning":"Sự kiện được tổ chức để nhiều người gửi tác phẩm tham gia, sau đó ban giám khảo chọn ra các tác phẩm xuất sắc nhất."},"8301":{"word":"tranh cãi","meaning":"Tình huống hai bên đối lập liên tục đưa ra quan điểm mạnh mẽ và thách thức ý kiến của nhau một cách gay gắt."},"8302":{"word":"khoảng trống","meaning":"Một khu vực chưa được lấp đầy hoặc một khoảng thời gian mà một điều gì đó vắng mặt, không có mặt."},"8303":{"word":"Chủ nghĩa cộng sản","meaning":"Một hệ thống chính trị và kinh tế mà chính phủ kiểm soát mọi tài sản và hàng hóa để phân phối đều cho mọi người."},"8304":{"word":"Hàng công nghiệp","meaning":"Những mặt hàng được sản xuất số lượng lớn bằng máy móc trong các nhà máy, như quần áo, ô tô, hoặc đồ điện tử."},"8305":{"word":"Cuộc tấn công","meaning":"Sự di chuyển chủ động, có kế hoạch của một nhóm nhằm áp đảo đối thủ, thường trong quân sự hoặc thể thao."},"8306":{"word":"Lời hứa tranh cử","meaning":"Lời hứa của một chính trị gia về những việc sẽ làm nếu được bầu, thường được công bố trước công chúng."},"8307":{"word":"Vô cớ, không cần thiết","meaning":"Hành động mà không có mục đích rõ ràng hoặc hữu ích, thường dẫn đến một phản ứng không cần thiết."},"8308":{"word":"Ngôn ngữ chính thức","meaning":"Hệ thống ngôn ngữ mà một quốc gia hoặc nhóm công nhận để sử dụng trong mọi giao tiếp công cộng, như trong chính phủ hoặc trường học."},"8309":{"word":"Thành tích, công lao","meaning":"Một việc làm đáng ngưỡng mộ đạt được nhờ nỗ lực vì lợi ích chung của nhiều người."},"8310":{"word":"Sự công bằng","meaning":"Trạng thái đối xử với mọi người như nhau và tuân thủ các quy tắc mà không thiên vị, đảm bảo kết quả cân bằng."},"8311":{"word":"Tính công bằng","meaning":"Phẩm chất không thiên vị và đối xử công bằng với mọi người, không có thành kiến hay lợi thế đặc biệt."},"8312":{"word":"Sự cùng tồn tại","meaning":"Hai hoặc nhiều nhóm hay sự vật khác nhau cùng tồn tại ở một nơi vào cùng một thời điểm, thường không xung đột."},"8313":{"word":"Vệ sinh công cộng","meaning":"Các biện pháp và thực hành nhằm giữ cho toàn bộ cộng đồng khỏe mạnh và ngăn chặn dịch bệnh lây lan, như hệ thống nước sạch và xử lý chất thải."},"8314":{"word":"Chức vụ công","meaning":"Một vị trí trách nhiệm trong chính phủ hoặc tổ chức nhà nước, nơi một người phục vụ công dân."},"8315":{"word":"đất trống","meaning":"Một khu đất chưa được xây dựng công trình, thường nằm trong thành phố hoặc thị trấn."},"8316":{"word":"ban bố","meaning":"Việc chính thức công bố một đạo luật, hiến pháp hoặc quy định để mọi người biết và tuân theo."},"8317":{"word":"trống rỗng","meaning":"Không có gì bên trong hoặc cảm thấy thiếu vắng một điều gì đó sâu sắc, gây ra cảm giác buồn bã, vô vị."},"8318":{"word":"đóng góp","meaning":"Hành động hoặc điều gì đó được đưa ra để giúp một nhóm, mục đích hoặc dự án thành công hoặc cải thiện."},"8319":{"word":"mạnh dạn","meaning":"Làm điều gì đó với sự dũng cảm và tự tin cao độ, không do dự, ngay cả khi có rủi ro hoặc khó khăn."},"8320":{"word":"quá khích","meaning":"Thể hiện hành vi hoặc ý kiến rất mạnh mẽ, thường là bạo lực, vượt xa những gì được coi là bình thường hoặc chấp nhận được."},"8321":{"word":"bia","meaning":"Một dấu hoặc vật thể cụ thể mà người ta nhắm tới khi bắn cung, ném phi tiêu hoặc cố gắng đánh trúng thứ gì đó."},"8322":{"word":"quá mức","meaning":"Một lượng vật chất hoặc điều gì đó vượt xa mức bình thường hoặc cần thiết."},"8323":{"word":"quá nhạy cảm","meaning":"Đặc điểm phản ứng quá mạnh hoặc quá nhanh với những điều nhỏ nhặt mà hầu hết mọi người không để ý nhiều."},"8324":{"word":"góa phụ","meaning":"Một người phụ nữ có chồng đã mất và chưa tái hôn."},"8325":{"word":"phô trương","meaning":"Hành động thể hiện rõ ràng kỹ năng, tài sản hoặc phẩm chất tốt của mình cho người khác thấy, thường để thu hút sự ngưỡng mộ."},"8326":{"word":"quá nhiệt","meaning":"Tình trạng một cỗ máy trở nên quá nóng có nguy cơ hỏng hóc, hoặc khi một thị trường, hoạt động trở nên cực kỳ căng thẳng và không ổn định."},"8327":{"word":"dư thừa","meaning":"Số lượng nhiều hơn mức cần thiết hoặc có thể tiêu thụ."},"8328":{"word":"quá khen","meaning":"Lời khen ngợi ai đó hay cái gì đó quá mức cần thiết hoặc không đúng với giá trị thực."},"8329":{"word":"quan tài","meaning":"Một chiếc hộp dài, thường bằng gỗ, dùng để đặt thi thể người đã khuất trước khi chôn cất hoặc hỏa táng."},"8330":{"word":"khái niệm","meaning":"Ý tưởng hoặc hình ảnh cơ bản được hình thành trong tâm trí về một điều gì đó hay về thế giới."},"8331":{"word":"người liên quan","meaning":"Người có mối liên hệ trực tiếp với một sự kiện, tình huống hoặc cuộc thảo luận cụ thể."},"8332":{"word":"thông lệ","meaning":"Một cách hành động hoặc làm việc đã được thiết lập, được nhiều người tuân theo vì đã được thực hành từ lâu."},"8333":{"word":"quan chức","meaning":"Người làm việc trong chính phủ với vai trò quản lý hành chính, thường tuân thủ nghiêm ngặt các quy tắc và quy trình."},"8334":{"word":"quan chức","meaning":"Người có chức vụ hoặc quyền hạn trong một tổ chức nhà nước hoặc công cộng."},"8335":{"word":"thuế quan","meaning":"Khoản tiền mà chính phủ thu dưới dạng thuế đối với các sản phẩm được mua hoặc bán từ các quốc gia khác."},"8336":{"word":"sự can thiệp","meaning":"Hành động tham gia hoặc có vai trò trong một tình huống, một cuộc thảo luận hoặc một hoạt động cụ thể."},"8337":{"word":"thành ngữ","meaning":"Mô tả một cách nói mà ý nghĩa kết hợp của các từ hoàn toàn khác so với nghĩa đen của từng từ, thường gây bất ngờ nếu không biết."},"8338":{"word":"khớp","meaning":"Nơi hai xương nối với nhau trong cơ thể, cho phép bộ phận cơ thể uốn cong hoặc xoay."},"8339":{"word":"chức quan","meaning":"Một vị trí công việc chính thức trong ngành dịch vụ công, thường liên quan đến chính phủ."},"8340":{"word":"quan sát","meaning":"Hành động nhìn kỹ hoặc dùng công cụ đặc biệt để nghiên cứu một vật gì đó."},"8341":{"word":"tập quán","meaning":"Một cách làm phổ biến đã được nhiều người trong một nhóm hoặc xã hội tuân theo trong thời gian dài."},"8342":{"word":"tứ lễ","meaning":"Bốn nghi lễ truyền thống quan trọng trong đời người gồm lễ thành niên, lễ cưới, lễ tang và lễ cúng tổ tiên."},"8343":{"word":"rộng lớn","meaning":"Miêu tả một khu vực trải dài rất xa hoặc một chủ đề bao gồm nhiều phần khác nhau."},"8344":{"word":"giải phóng","meaning":"Việc một quốc gia giành lại độc lập từ sự kiểm soát của nước khác, thường được kỷ niệm như một ngày đặc biệt."},"8345":{"word":"thợ mỏ","meaning":"Người làm việc sâu dưới lòng đất để khai thác các loại đá và khoáng sản có giá trị."},"8346":{"word":"ngành khai thác mỏ","meaning":"Hoạt động kinh doanh liên quan đến việc đào sâu vào lòng đất để tìm và loại bỏ các khoáng sản hữu ích."},"8347":{"word":"rộng lớn, bao la","meaning":"Miêu tả một khu vực trải dài vô cùng xa xôi theo mọi hướng, dường như không có giới hạn."},"8348":{"word":"sự đồng cảm","meaning":"Cảm giác hiểu biết và chia sẻ sâu sắc với người khác, thường thể hiện qua biểu hiện và hành động."},"8349":{"word":"sự quấy rối, nhiễu loạn","meaning":"Một hành động hoặc sự kiện phá vỡ hòa bình, trật tự, gây nhầm lẫn hoặc làm cho một việc gì đó hoạt động không đúng."},"8350":{"word":"khéo léo, tinh ranh","meaning":"Miêu tả người hoặc vật rất giỏi trong việc lừa gạt người khác hoặc thực hiện một việc khó theo cách xảo quyệt."},"8351":{"word":"thương lượng","meaning":"Quá trình nói chuyện hoặc thảo luận để đạt được một thỏa thuận giữa hai hay nhiều bên."},"8352":{"word":"chỉnh sửa","meaning":"Hành động làm cho cái gì đó trở nên ngay ngắn, đúng đắn hoặc thẳng hàng hơn, như nắn chỉnh răng."},"8353":{"word":"xảo quyệt","meaning":"Có tính cách lừa dối, dùng mưu mẹo để đạt được lợi ích riêng một cách không trung thực."},"8354":{"word":"hình cầu","meaning":"Một vật thể hình học ba chiều có mọi điểm trên bề mặt cách đều một điểm trung tâm."},"8355":{"word":"ăn xin","meaning":"Hành động đi xin tiền, thức ăn hoặc vật phẩm từ người khác, thường là do nghèo khó."},"8356":{"word":"môn bóng","meaning":"Các loại hình thể thao hoặc trò chơi sử dụng một quả bóng, như bóng đá, bóng rổ."},"8357":{"word":"vò nát","meaning":"Ép hoặc nén một vật gì đó, thường là giấy hoặc vải, làm nó bị nhăn nhúm, biến dạng."},"8358":{"word":"quanh co","meaning":"Miêu tả một con đường, dòng sông hoặc vật thể có nhiều khúc cong, không thẳng."},"8359":{"word":"thoát chết trong gang tấc","meaning":"Tình huống thoát khỏi cái chết hoặc nguy hiểm tột độ một cách kỳ diệu, như từ cõi chết trở về."},"8360":{"word":"hạt cườm","meaning":"Một vật nhỏ, tròn, thường làm bằng thủy tinh hoặc nhựa, dùng để trang trí hoặc chơi."},"8361":{"word":"cái cớ","meaning":"Lí do được đưa ra để che đậy hoặc biện minh cho một việc làm không hay, hoặc để tránh trách nhiệm."},"8362":{"word":"ngôn ngữ nói","meaning":"Hình thức ngôn ngữ được sử dụng trong giao tiếp hàng ngày bằng lời nói giữa mọi người."},"8363":{"word":"cứu giúp","meaning":"Hành động giúp đỡ một người hoặc một vật thoát khỏi nguy hiểm, khó khăn hoặc tình huống xấu."},"8364":{"word":"thiếu hụt lao động","meaning":"Tình trạng các công ty không tìm đủ người lao động để lấp đầy các vị trí tuyển dụng."},"8365":{"word":"đoạn văn","meaning":"Một phần nhỏ của một văn bản dài, có thể là một câu hay vài dòng từ sách, thơ, hoặc bài hát."},"8366":{"word":"cứu trợ","meaning":"Việc cung cấp lương thực, tiền bạc hoặc sự hỗ trợ cần thiết cho những người đang gặp khó khăn hoặc rất cần giúp đỡ."},"8367":{"word":"mang tính cấu trúc","meaning":"Liên quan đến cấu trúc cơ bản hay cách thức tổ chức của một hệ thống, tòa nhà, hoặc tổ chức."},"8368":{"word":"cụ thể hóa","meaning":"Quá trình một ý tưởng, kế hoạch hoặc khái niệm trừu tượng trở nên cụ thể, có hình dạng rõ ràng hoặc hiện thực."},"8369":{"word":"xây dựng","meaning":"Việc tập hợp các vật liệu và lắp ráp chúng lại để tạo nên một cấu trúc hoặc một hệ thống hoàn chỉnh."},"8370":{"word":"giải cứu","meaning":"Hành động đưa một người hoặc một vật ra khỏi nguy hiểm hay tình huống khó khăn, để họ được an toàn."},"8371":{"word":"cố ý","meaning":"Làm một việc gì đó có chủ đích hoặc với ý định mạnh mẽ, dù việc đó có thể không thực sự cần thiết hoặc gây bất tiện."},"8372":{"word":"lỗi thời","meaning":"Có vẻ ngoài hoặc thái độ không còn hợp thời, thể hiện phong tục hoặc ý tưởng đã cũ."},"8373":{"word":"nôn mửa","meaning":"Hành động đẩy thức ăn từ dạ dày ra ngoài qua miệng."},"8374":{"word":"mẫu cũ","meaning":"Một phiên bản sản phẩm hoặc máy móc được sản xuất từ lâu và đã được thay thế bằng các phiên bản mới hơn."},"8375":{"word":"khẩu hiệu","meaning":"Một câu nói ngắn gọn, dễ nhớ, thường dùng để thể hiện yêu cầu, niềm tin hoặc thông điệp chính trị."},"8376":{"word":"cứu trợ","meaning":"Sự giúp đỡ hoặc tài nguyên như lương thực, tiền bạc, chỗ ở được cung cấp cho những người đang gặp khó khăn hoặc cần giúp đỡ."},"8377":{"word":"mang tính quốc gia","meaning":"Liên quan đến toàn bộ một quốc gia, toàn bộ dân số hoặc chính phủ trung ương của nước đó."},"8378":{"word":"biên giới quốc gia","meaning":"Đường phân chia lãnh thổ giữa hai quốc gia."},"8379":{"word":"quốc khố","meaning":"Toàn bộ tiền và tài nguyên tài chính thuộc về chính phủ của một quốc gia."},"8380":{"word":"quân đội quốc gia","meaning":"Lực lượng vũ trang được tổ chức để bảo vệ và phòng thủ đất nước."},"8381":{"word":"trong và ngoài nước","meaning":"Vừa ở trong nước mình vừa ở các nước khác trên thế giới."},"8382":{"word":"quốc lực","meaning":"Sức mạnh và ảnh hưởng tổng thể của một quốc gia trên thế giới, thể hiện qua kinh tế, quân sự hoặc văn hóa."},"8383":{"word":"thủ tướng","meaning":"Viên chức chính phủ cấp cao đứng đầu nội các và quản lý đất nước."},"8384":{"word":"mang tính toàn dân","meaning":"Liên quan hoặc được chia sẻ bởi hầu hết các cá nhân sống trong một quốc gia cụ thể."},"8385":{"word":"quốc phòng","meaning":"Hệ thống và các hành động mà một quốc gia sử dụng để bảo vệ an toàn khỏi các cuộc tấn công hoặc nguy hiểm từ bên ngoài."},"8386":{"word":"quốc bảo","meaning":"Một vật phẩm văn hóa, tác phẩm nghệ thuật hoặc địa điểm lịch sử rất có giá trị và quan trọng thuộc về một quốc gia, được bảo vệ cẩn thận."},"8387":{"word":"kinh phí nhà nước","meaning":"Số tiền do chính phủ cung cấp để hỗ trợ các hoạt động hoặc dự án."},"8388":{"word":"quốc vương","meaning":"Người đứng đầu cao nhất của một quốc gia, thường là nam giới."},"8389":{"word":"cục trưởng","meaning":"Người đứng đầu hoặc quản lý một cục, vụ hoặc phòng ban trong tổ chức nhà nước."},"8390":{"word":"chính sự","meaning":"Các công việc và vấn đề quan trọng liên quan đến sự quản lý, điều hành của một quốc gia."},"8391":{"word":"quốc tế","meaning":"Có liên quan hoặc bao gồm nhiều quốc gia trên thế giới."},"8392":{"word":"sự giới hạn","meaning":"Phạm vi, giới hạn mà một việc nào đó không thể vượt ra ngoài được."},"8393":{"word":"người tài xuất chúng","meaning":"Người nổi bật, xuất sắc vượt trội so với những người khác trong một tập thể."},"8394":{"word":"hạt dẻ nướng","meaning":"Hạt dẻ được rang hoặc nướng chín, có vỏ cứng màu nâu và ruột mềm, ăn được."},"8395":{"word":"đám đông","meaning":"Một nhóm rất nhiều người tụ tập ở một nơi."},"8396":{"word":"sự uốn lượn","meaning":"Những đoạn uốn lượn, khúc khuỷu của đường đi hoặc những giai đoạn thăng trầm trong cuộc đời."},"8397":{"word":"cư xử","meaning":"Hành động hoặc thể hiện thái độ nhất định đối với người khác."},"8398":{"word":"dây cương","meaning":"Dây thừng bện, thường dùng để buộc quanh đầu ngựa, bò để điều khiển chúng."},"8399":{"word":"lăn","meaning":"Làm cho vật có hình tròn hoặc hình trụ di chuyển bằng cách quay tròn trên một bề mặt."},"8400":{"word":"đói khát","meaning":"Chịu đựng hoặc chết vì không có thức ăn trong một thời gian dài."},"8401":{"word":"sự đói khát","meaning":"Trạng thái đau khổ thể xác nghiêm trọng hoặc cái chết do không có đủ thức ăn trong thời gian rất dài."},"8402":{"word":"cuối cùng","meaning":"Là điểm xa nhất, quan trọng nhất hoặc cuối cùng trong một chuỗi các bước hoặc một quá trình dài."},"8403":{"word":"ý tưởng","meaning":"Một gợi ý hoặc chiến lược sáng tạo nảy sinh trong tâm trí để giải quyết vấn đề hoặc đạt được điều gì đó."},"8404":{"word":"xấu","meaning":"Khi bầu trời đầy mây đen, thường có mưa hoặc gió lớn."},"8405":{"word":"phiếu","meaning":"Một mảnh giấy hoặc thẻ nhỏ cho phép bạn nhận dịch vụ, món hàng hoặc được giảm giá đặc biệt."},"8406":{"word":"vùng","meaning":"Một phần cụ thể của một khu vực lớn hơn có các đặc điểm riêng biệt hoặc được chỉ định cho một mục đích sử dụng nhất định."},"8407":{"word":"khuyến nghị","meaning":"Một tuyên bố hoặc lời khuyên được đưa ra để gợi ý hành động tốt nhất nên làm hoặc điều có lợi nên chọn."},"8408":{"word":"quyền lợi","meaning":"Những lợi ích và quyền hợp pháp mà cá nhân hoặc nhóm được phép sở hữu hoặc theo đuổi."},"8409":{"word":"khuyến khích","meaning":"Hành động khuyên bảo ai đó làm điều tốt hoặc có lợi, hoặc hỗ trợ để động viên họ."},"8410":{"word":"súng lục","meaning":"Một loại súng nhỏ, ngắn dùng bằng một tay."},"8411":{"word":"Sự chán nản","meaning":"Cảm giác không hứng thú, buồn tẻ và mệt mỏi, thường khiến người ta không muốn làm gì cả."},"8412":{"word":"Đấm bốc","meaning":"Một môn thể thao mà hai người đeo găng tay đấm vào nhau trong một võ đài."},"8413":{"word":"Quyền hạn","meaning":"Những quyền mà một người có được nhờ vai trò hoặc vị trí của mình."},"8414":{"word":"Quỹ đạo","meaning":"Đường cong mà một vật thể như vệ tinh hoặc hành tinh di chuyển quanh một vật thể lớn hơn, hoặc đường đi nhất định cho phương tiện."},"8415":{"word":"Tấm gương","meaning":"Một người hoặc một vật thể hoàn hảo để noi theo, cho thấy cách ứng xử hoặc điều cần đạt được."},"8416":{"word":"Quy nạp","meaning":"Thuộc về phương pháp suy luận từ các trường hợp cụ thể để rút ra quy tắc chung."},"8417":{"word":"Quý tộc","meaning":"Tầng lớp xã hội có địa vị cao hoặc một người thuộc tầng lớp đó."},"8418":{"word":"Sự sang hèn","meaning":"Sự khác biệt về địa vị, đẳng cấp của con người trong xã hội dựa trên xuất thân, tài sản hay nghề nghiệp."},"8419":{"word":"Hồi hương","meaning":"Hành động quay trở về nơi mình sinh ra hoặc nơi gia đình sinh sống."},"8420":{"word":"Chuẩn mực","meaning":"Một bộ quy tắc hoặc mong đợi được chấp nhận rộng rãi, hướng dẫn cách hành xử của con người trong một nhóm hoặc xã hội."},"8421":{"word":"Kỷ luật","meaning":"Các quy tắc được đặt ra để mọi người tuân thủ nhằm duy trì trật tự trong một xã hội hoặc tổ chức."},"8422":{"word":"Quy định","meaning":"Một quy tắc hoặc mệnh lệnh chính thức do một cơ quan có thẩm quyền ban hành để kiểm soát cách thức thực hiện hoặc cho phép một điều gì đó."},"8423":{"word":"vi khuẩn","meaning":"Một sinh vật rất nhỏ có thể làm thức ăn bị thối hoặc khiến con người mắc bệnh."},"8424":{"word":"trong lúc đó","meaning":"Khoảng thời gian ngắn giữa một sự kiện đã qua và một sự kiện khác."},"8425":{"word":"dù sao thì","meaning":"Từ dùng để chuyển đổi chủ đề hoặc nói một điều gì đó bất kể những gì đã được nói trước đó."},"8426":{"word":"sai trái","meaning":"Không đúng đắn, không hợp lẽ phải hoặc không tuân theo cách thức đúng đắn."},"8427":{"word":"sai lệch","meaning":"Một tình huống, ý tưởng hoặc con đường bị thay đổi và trở nên không tốt hoặc không như dự định ban đầu."},"8428":{"word":"nồng nàn","meaning":"Có mùi hương thơm tho, nồng nàn và dịu nhẹ, tạo cảm giác thư thái, dễ chịu."},"8429":{"word":"vô cùng","meaning":"Rất lớn hoặc rộng đến mức dường như không có điểm kết thúc hay giới hạn nào."},"8430":{"word":"cực điểm","meaning":"Điểm xa nhất hoặc mức độ cao nhất mà một điều gì đó có thể đạt tới."},"8431":{"word":"tối đa hóa","meaning":"Quá trình làm cho một cái gì đó lớn nhất, hiệu quả nhất hoặc mạnh mẽ nhất có thể."},"8432":{"word":"mức độ cực đoan","meaning":"Mức độ cao nhất hoặc điểm mạnh nhất mà một cảm giác hay tình trạng có thể đạt tới."},"8433":{"word":"tính quá khích","meaning":"Mức độ nhiệt tình hoặc hoạt động rất mạnh mẽ, dữ dội và đôi khi gây phiền toái."},"8434":{"word":"số lượng rất ít","meaning":"Một số lượng rất nhỏ."},"8435":{"word":"kịch tính","meaning":"Mô tả sự thay đổi hoặc sự kiện đột ngột, ấn tượng, gây cảm xúc mạnh mẽ như trong một vở kịch."},"8436":{"word":"khoảng, gần","meaning":"Dùng để chỉ một số lượng hoặc con số rất gần với, nhưng không chính xác bằng, số đã nêu."},"8437":{"word":"nền tảng, cơ sở","meaning":"Phần chính yếu và quan trọng nhất, làm chỗ dựa và giữ vững một cấu trúc hoặc một ý tưởng."},"8438":{"word":"sức cơ","meaning":"Khả năng của các bộ phận cơ thể để tạo ra lực, di chuyển hoặc nâng vật nặng."},"8439":{"word":"cần cù, siêng năng","meaning":"Phẩm chất làm việc cẩn thận, đều đặn trong thời gian dài, thể hiện sự nỗ lực lớn trong công việc."},"8440":{"word":"cận thị","meaning":"Tình trạng mắt chỉ có thể nhìn rõ các vật ở gần mà không thể nhìn rõ các vật ở xa."},"8441":{"word":"thêm hoa trên gấm","meaning":"Việc một điều tốt đẹp đã có lại được bổ sung thêm một điều tốt đẹp hơn nữa, khiến mọi thứ trở nên hoàn hảo."},"8442":{"word":"lần đầu nghe thấy","meaning":"Thông tin hoặc tin tức mà một người nghe thấy lần đầu tiên, khiến họ ngạc nhiên."},"8443":{"word":"ngành tài chính","meaning":"Lĩnh vực kinh doanh liên quan đến việc quản lý, cho vay và đầu tư tiền cho cá nhân và các công ty."},"8444":{"word":"vinh quy bái tổ","meaning":"Sự kiện một người trở về quê hương hoặc đất nước sau khi đạt được thành công hoặc vinh dự lớn, thường được chào đón nồng nhiệt."},"8445":{"word":"con cưng","meaning":"Một người trẻ tuổi được cha mẹ yêu thương sâu sắc và bảo vệ cẩn thận, như một viên ngọc quý hay bông hoa mềm yếu."},"8446":{"word":"bận tâm, chỉ chú tâm vào","meaning":"Dồn hết tâm trí và năng lượng vào một công việc khẩn cấp hoặc mối lo lắng duy nhất, thường liên quan đến sự sống còn cơ bản."},"8447":{"word":"cuối cùng, rốt cuộc","meaning":"Diễn tả việc cuối cùng một điều gì đó xảy ra sau một quá trình dài hoặc một chuỗi các sự kiện, thường chỉ kết quả bất ngờ hoặc kịch tính."},"8448":{"word":"tăng vọt, tăng mạnh","meaning":"Sự tăng lên rất nhanh và đột ngột về số lượng, giá cả hoặc mức độ."},"8449":{"word":"giảm mạnh, giảm đột ngột","meaning":"Sự giảm xuống rất nhanh và đột ngột về số lượng, giá cả hoặc mức độ."},"8450":{"word":"dòng chảy xiết, ghềnh nước xiết","meaning":"Dòng nước trong sông hoặc biển chảy với tốc độ và sức mạnh lớn."},"8451":{"word":"biến đổi đột ngột, thay đổi nhanh chóng","meaning":"Sự thay đổi rất nhanh và bất ngờ trong tình huống, hình dáng hoặc điều kiện."},"8452":{"word":"cấp tính","meaning":"Chỉ một tình trạng bệnh lý khởi phát đột ngột, nghiêm trọng và tiến triển nhanh chóng, thường không kéo dài."},"8453":{"word":"nhanh chóng, cấp tốc","meaning":"Diễn tả điều gì đó xảy ra hoặc di chuyển với tốc độ cao, hoàn thành trong thời gian rất ngắn."},"8454":{"word":"tích cực, sự khẳng định","meaning":"Hành động đồng ý với điều gì đó hoặc một thái độ lạc quan, mong đợi kết quả tốt."},"8455":{"word":"niềm tự hào, sự kiêu hãnh","meaning":"Cảm giác hài lòng sâu sắc và kính trọng đối với bản thân hoặc điều mình liên quan, thường do thành tựu hoặc tiêu chuẩn cao."},"8456":{"word":"bài gửi đăng, bài viết","meaning":"Một bài viết như bài báo hoặc tiểu luận mà ai đó gửi để xuất bản trên báo, tạp chí hoặc trang web."},"8457":{"word":"phế quản","meaning":"Hai đường dẫn khí chính trong lồng ngực phân nhánh từ khí quản, mang không khí vào và ra khỏi phổi."},"8458":{"word":"kỹ thuật, kỹ xảo","meaning":"Kỹ năng chuyên biệt và sự thực hiện khéo léo để biểu diễn điều gì đó một cách điêu luyện, thường với phong cách tinh tế, tao nhã."},"8459":{"word":"bỏ phiếu trắng","meaning":"Hành động cố ý không bỏ phiếu hoặc không tham gia vào một quyết định, cuộc bầu cử hay cuộc thi."},"8460":{"word":"quỹ","meaning":"Số tiền được thu thập và dành riêng để sử dụng cho một mục đích cụ thể như kinh doanh, sự kiện hay các hoạt động công ích."},"8461":{"word":"thiết bị","meaning":"Vật thể được chế tạo, thường là điện tử hoặc cơ khí, được dùng cho một mục đích hay nhiệm vụ cụ thể."},"8462":{"word":"sẵn lòng","meaning":"Với thái độ vui vẻ, sẵn sàng làm gì đó mà không chút do dự."},"8463":{"word":"chỉ bấy nhiêu","meaning":"Dùng để thể hiện rằng một lượng hoặc kết quả nào đó rất nhỏ, hạn chế hoặc không đủ, dù đã bỏ ra công sức."},"8464":{"word":"lễ kỷ niệm","meaning":"Buổi tập hợp đặc biệt để mọi người cùng nhau đánh dấu công khai một người, sự kiện hoặc thành tựu quan trọng trong quá khứ."},"8465":{"word":"mang tính chức năng","meaning":"Mô tả một vật được thiết kế hoặc xây dựng để thực hiện công việc hoặc nhiệm vụ dự định một cách hiệu quả và thực tế."},"8466":{"word":"nỗ lực","meaning":"Hành động cố gắng thực hiện một điều gì đó, đặc biệt là điều khó khăn hoặc có thể thất bại."},"8467":{"word":"kỹ năng","meaning":"Mức độ thành thạo hoặc chuyên môn xuất sắc mà một người có được khi thực hiện một hoạt động hoặc nhiệm vụ cụ thể."},"8468":{"word":"sức lực","meaning":"Sức mạnh thể chất và tinh thần mà một người có để thực hiện các hành động và duy trì sự năng động."},"8469":{"word":"khí lưu","meaning":"Là sự chuyển động của không khí theo một hướng cụ thể, hoặc trạng thái cảm xúc chung và không khí tinh thần trong một nhóm người."},"8470":{"word":"tưởng niệm","meaning":"Thể hiện sự đánh giá cao công khai và tưởng nhớ một cách tôn kính đối với một người, sự kiện hoặc thành tựu, thường qua một buổi lễ đặc biệt hoặc tượng đài."},"8471":{"word":"đứng dậy","meaning":"Hành động đứng lên từ tư thế ngồi hoặc nằm."},"8472":{"word":"lừa dối","meaning":"Hành động cố ý khiến người khác tin vào điều không đúng sự thật, thường là để trục lợi."},"8473":{"word":"kỳ lạ","meaning":"Tả sự vật có vẻ ngoài rất khác thường, gây chú ý."},"8474":{"word":"nám da","meaning":"Vết đốm nhỏ như vết bẩn xuất hiện trên mặt."},"8475":{"word":"kỹ thuật","meaning":"Cách thức đặc biệt và thường là có kỹ năng để thực hiện hành động hoặc hoàn thành công việc."},"8476":{"word":"nét mặt","meaning":"Dấu hiệu biểu lộ trên khuôn mặt hoặc tư thế cơ thể của một người, cho thấy cảm xúc hoặc trạng thái hiện tại của họ."},"8477":{"word":"mô tả","meaning":"Hành động giải thích điều gì đó bằng lời nói hoặc chữ viết để người khác dễ hiểu."},"8478":{"word":"kỹ thuật","meaning":"Liên quan đến các phương pháp, công cụ hoặc máy móc cụ thể được sử dụng trong một kỹ năng thực hành hoặc ngành công nghiệp."},"8479":{"word":"tấn công bất ngờ","meaning":"Hành động bất ngờ, thường là đột ngột và mạnh mẽ, khiến đối phương không kịp phòng bị."},"8480":{"word":"nạn đói","meaning":"Tình trạng thiếu thức ăn nghiêm trọng trong thời gian dài, khiến người hoặc động vật trở nên gầy yếu và có thể chết."},"8481":{"word":"kỳ hẹn","meaning":"Sự thỏa thuận chắc chắn hoặc ngày định trước cho một điều gì đó sẽ xảy ra trong tương lai."},"8482":{"word":"bò","meaning":"Di chuyển về phía trước trên mặt đất bằng tay và đầu gối, hoặc với cơ thể rất thấp."},"8483":{"word":"chui vào","meaning":"Di chuyển bằng cách bò hoặc luồn lách để đi vào một nơi hẹp."},"8484":{"word":"bò lên","meaning":"Di chuyển bằng cách bò hoặc luồn lách để đi lên một nơi cao hoặc dốc."},"8485":{"word":"nhất định","meaning":"Diễn tả việc một hành động chắc chắn sẽ xảy ra hoặc được thực hiện, thường sau nhiều nỗ lực hoặc vượt qua trở ngại."},"8486":{"word":"bằng được","meaning":"Diễn tả việc một hành động được hoàn thành hoặc sẽ được hoàn thành bất kể khó khăn nào, thể hiện sự quyết tâm mạnh mẽ."},"8487":{"word":"doanh nghiệp","meaning":"Một tổ chức sản xuất và kinh doanh hàng hóa hoặc dịch vụ nhằm mục đích thu lợi nhuận."},"8488":{"word":"ngó nghiêng","meaning":"Cúi hoặc vươn đầu ra để nhanh chóng quan sát một cái gì đó, thường là lén lút hoặc tò mò, từ sau vật cản hoặc góc khuất."},"8489":{"word":"kỳ lạ","meaning":"Diễn tả cái gì đó có vẻ rất đặc biệt, bất thường hoặc khác lạ một cách bất ngờ so với những gì thường thấy hoặc biết."},"8490":{"word":"bắt nguồn từ","meaning":"Có một điểm khởi đầu hoặc nguyên nhân cụ thể mà từ đó một điều gì đó phát triển hoặc nảy sinh."},"8491":{"word":"tã","meaning":"Một miếng lót mềm, dày bằng vật liệu được trẻ sơ sinh hoặc người không kiểm soát được bàng quang hoặc ruột mặc để thấm chất thải lỏng."},"8492":{"word":"ngất xỉu","meaning":"Tình trạng mất ý thức đột ngột, tạm thời, khiến một người ngã xuống hoặc không phản ứng trong một thời gian ngắn."},"8493":{"word":"tính khí","meaning":"Cách một người thường hành động, cảm nhận và phản ứng với các sự kiện, thường thể hiện qua các hành vi và phản ứng cảm xúc điển hình của họ."},"8494":{"word":"đáng khen","meaning":"Diễn tả một hành động hoặc nỗ lực xứng đáng được tán thành và tôn trọng, thường vì nó chu đáo, dũng cảm hoặc thể hiện sự trưởng thành bất ngờ."},"8495":{"word":"nền tảng, cơ sở","meaning":"Phần dưới cùng vững chắc của một tòa nhà hoặc hệ thống mà mọi thứ khác được xây dựng lên."},"8496":{"word":"phẩm giá, khí chất","meaning":"Một phẩm chất thanh lịch, điềm tĩnh và đáng kính mà một người thể hiện qua cử chỉ hoặc phong thái của mình."},"8497":{"word":"sự tránh né, sự né tránh","meaning":"Hành động cố ý tránh xa một điều gì đó khó chịu, một người nào đó hoặc một nhiệm vụ."},"8498":{"word":"nhất định, chắc chắn","meaning":"Từ dùng để diễn tả một hành động mà ai đó sẽ hoàn thành một cách tuyệt đối, không có khả năng thất bại."},"8499":{"word":"du ký, ký sự du lịch","meaning":"Một câu chuyện được viết hoặc kể lại mô tả những trải nghiệm và quan sát trong một chuyến đi đến một nơi khác."},"8500":{"word":"mặt hàng yêu thích, đồ dùng cá nhân ưa thích","meaning":"Một loại thực phẩm, đồ uống hoặc sản phẩm khác mà mọi người thường xuyên thưởng thức để giải trí, không phải là thứ thiết yếu để sinh tồn."},"8501":{"word":"thân thiết, gắn bó chặt chẽ","meaning":"Mô tả một mối quan hệ hoặc sự kết nối giữa hai hoặc nhiều vật hoặc người rất mạnh mẽ và gắn bó sâu sắc."},"8502":{"word":"thuần hóa, thuần dưỡng","meaning":"Dạy một con vật sống hòa bình với con người và tuân theo mệnh lệnh của họ, thường là làm cho nó bớt hoang dã và dễ quản lý hơn."},"8503":{"word":"thon dài, dài ngoẵng","meaning":"Mô tả một vật hoặc hình dạng dài hơn nhiều ở một chiều so với các chiều khác của nó."},"8504":{"word":"cổ áo","meaning":"Phần vải được gắn xung quanh đường viền cổ áo sơ mi, áo khoác hoặc áo choàng."},"8505":{"word":"trú ngụ, ẩn chứa, thấm đượm","meaning":"Khi một tinh thần, phẩm chất hoặc cảm giác vô hình lắng đọng sâu sắc bên trong một nơi, vật thể hoặc con người, biến nó thành ngôi nhà tinh thần của nó."},"8506":{"word":"lá cờ, cờ","meaning":"Một mảnh vải, thường hình chữ nhật và có thiết kế đặc biệt, được gắn vào một cây sào và dùng làm biểu tượng cho một quốc gia hoặc tổ chức."},"8507":{"word":"sâu, sâu thẳm","meaning":"Diễn tả hành động đi rất xa xuống hoặc rất sâu vào bên trong một cái gì đó, đạt đến một điểm bên trong quan trọng."},"8508":{"word":"xa xăm, mờ mịt","meaning":"Mô tả cái gì đó rất xa về không gian hoặc thời gian, đến mức dường như không thể nhìn thấy hoặc không thể đạt tới."},"8509":{"word":"ngất xỉu, bất tỉnh","meaning":"Đột nhiên mất nhận thức và ngã xuống, không phản ứng trong một thời gian ngắn do sốc, sợ hãi hoặc bệnh tật."},"8510":{"word":"lon, hộp thiếc","meaning":"Vật chứa bằng kim loại, thường có hình trụ, dùng để đựng thức ăn hoặc đồ uống."},"8511":{"word":"muối mè, vừng rang","meaning":"Hạt mè rang đã được xay nhỏ, hoặc gia vị mặn được làm bằng cách trộn bột đó với muối."},"8512":{"word":"khai sáng, giác ngộ","meaning":"Khiến ai đó đột nhiên hiểu ra một sự thật hay ý tưởng quan trọng, như một ánh sáng lóe lên trong tâm trí họ."},"8513":{"word":"ngại, e ngại","meaning":"Không thích hoặc tránh một vấn đề hay điều gì đó vì sợ rằng nó có thể mang lại tổn hại cho bản thân."},"8514":{"word":"ngai ngái, không thoải mái","meaning":"Cảm thấy khó chịu hoặc không tốt vì có điều gì đó đang đè nặng trong tâm trí."},"8515":{"word":"mặc nhiều lớp, mặc chồng nhiều áo","meaning":"Mặc nhiều loại quần áo chồng lên nhau, thường là để giữ ấm."},"8516":{"word":"rối ren, vướng mắc","meaning":"Mô tả tình huống công việc hoặc sự việc trở nên phức tạp, khó giải quyết hoặc không theo ý muốn."},"8517":{"word":"nhéo, véo","meaning":"Dùng ngón tay cái và ngón trỏ siết chặt một chút da hoặc thịt."},"8518":{"word":"tỉ mỉ, cặn kẽ","meaning":"Diễn tả hành động hỏi nhiều câu hỏi cụ thể và không bỏ cuộc cho đến khi nhận được tất cả thông tin."},"8519":{"word":"sự khó coi","meaning":"Hành động hoặc dáng vẻ rất đáng ghét, gây khó chịu cho người khác."},"8520":{"word":"mưu mẹo, mưu kế","meaning":"Một kế hoạch thông minh hoặc xảo quyệt dùng để đạt được điều gì đó, thường bằng cách lừa dối người khác."},"8521":{"word":"mưu tính, hoạch định","meaning":"Suy nghĩ và sắp xếp cẩn thận một phương pháp để làm điều gì đó, thường là việc khó khăn hoặc bí mật."},"8522":{"word":"chặt, mạnh","meaning":"Ở trạng thái ấn xuống hoặc giữ một cách mạnh mẽ, ổn định mà không buông lỏng."},"8523":{"word":"ngọ nguậy, cựa quậy","meaning":"Cử động cơ thể bằng những động tác ngắn, nhanh, uốn éo từ bên này sang bên kia, giống như giun hoặc rắn."},"8524":{"word":"xỏ, luồn","meaning":"Luồn một sợi dây mỏng, như chỉ hoặc dây thép, qua một lỗ nhỏ hoặc một loạt các lỗ."},"8525":{"word":"xuyên thủng","meaning":"Tạo ra một lỗ hoàn toàn xuyên qua một vật thể, đi từ bên này sang bên kia."},"8526":{"word":"đánh rắm, xì hơi","meaning":"Thải khí từ ruột qua hậu môn, thường tạo ra tiếng động và mùi."},"8527":{"word":"dính, nhớt, bết","meaning":"Mô tả một chất bám vào các vật khác và khó gỡ ra, giống như keo hoặc siro."},"8528":{"word":"kiên trì, bền bỉ, dai dẳng","meaning":"Mô tả ai đó hoặc cái gì đó tiếp tục cố gắng hoặc bám trụ trong một thời gian rất dài, từ chối bỏ cuộc ngay cả khi khó khăn."},"8529":{"word":"bị lôi đi, bị kéo đi","meaning":"Bị người hoặc vật khác kéo đi bằng sức mạnh, khiến cơ thể di chuyển trên mặt đất mà không theo ý muốn của mình."},"8530":{"word":"sôi trào, sủi bọt","meaning":"Khi chất lỏng rất nóng, nó tạo ra nhiều bọt và dâng lên, thường bốc hơi."},"8531":{"word":"vô cùng, cực kỳ","meaning":"Diễn tả mức độ một cảm xúc hoặc hành động rất mạnh mẽ, gây ra phản ứng dữ dội."},"8532":{"word":"tạt, đổ lên","meaning":"Làm cho chất lỏng từ vật chứa hoặc tay rơi nhanh và lan rộng lên một bề mặt hoặc người."},"8533":{"word":"lữ khách, người lữ hành","meaning":"Người di chuyển từ nơi này sang nơi khác, thường trong một chuyến đi dài, không có nhà cửa cố định."},"8534":{"word":"ngày tháng, ngày","meaning":"Mỗi một khoảng thời gian trọn vẹn gồm ban ngày và ban đêm, nối tiếp nhau."},"8535":{"word":"uể oải, mệt mỏi","meaning":"Tình trạng cơ thể cảm thấy nặng nề và yếu ớt, khiến người ta muốn nghỉ ngơi và di chuyển chậm chạp."},"8536":{"word":"phấp phới, lay động","meaning":"Vật nhẹ như vải, lá cây chuyển động nhanh và nhẹ nhàng qua lại hoặc lên xuống trong gió nhẹ."},"8537":{"word":"yếu ớt, yếu đuối","meaning":"Có rất ít sức mạnh thể chất, thường trông mỏng manh hoặc dễ mệt mỏi, khó hoàn thành công việc nặng nhọc."},"8538":{"word":"thấp, nhỏ nhẹ","meaning":"Không cao lắm về chiều cao hoặc không quá lớn về âm thanh, trông dịu dàng và khiêm tốn."},"8539":{"word":"lạc đà","meaning":"Một loài động vật lớn sống ở sa mạc, có cổ dài và một hoặc hai bướu lớn trên lưng, được dùng để chở người hoặc hàng hóa."},"8540":{"word":"phá thai, nạo thai","meaning":"Một thủ thuật y tế được thực hiện để chủ động chấm dứt sự phát triển của thai nhi trong tử cung, để em bé không được sinh ra."},"8541":{"word":"lạc hậu","meaning":"Tình trạng đi sau rất xa trong sự phát triển hoặc tiến bộ, đặc biệt so với những nơi khác, thể hiện phương pháp cũ hoặc cơ sở vật chất hiện đại hạn chế."},"8542":{"word":"khó xử, khó xử trí","meaning":"Ở trong một tình thế khó khăn hoặc lúng túng, không biết nên hành động hay nói gì."},"8543":{"word":"trở ngại","meaning":"Là điều gì đó cản trở con đường hoặc gây khó khăn để đạt được mục tiêu."},"8544":{"word":"bất thình lình","meaning":"Một việc gì đó xảy ra hoặc xuất hiện rất đột ngột, không có dấu hiệu báo trước."},"8545":{"word":"từ trước đến nay","meaning":"Diễn tả một sự việc hay trải nghiệm bao trùm toàn bộ khoảng thời gian từ khi sinh ra cho đến hiện tại."},"8546":{"word":"mất thính lực","meaning":"Tình trạng tai khó tiếp nhận âm thanh, khiến chúng trở nên nhỏ hoặc không rõ ràng."},"8547":{"word":"hung hăng","meaning":"Chỉ những hành động hung hăng, không kiểm soát, thường gây hại cho người hoặc vật mà không quan tâm."},"8548":{"word":"chạy loạn","meaning":"Chỉ động vật hoặc người di chuyển rất nhanh và mất kiểm soát, thường gây tán loạn đồ vật hoặc khiến người khác phải tránh."},"8549":{"word":"không sót lại","meaning":"Diễn tả việc hoàn thành một hành động một cách triệt để, không để lại bất kỳ phần, số lượng hay bộ phận nào."},"8550":{"word":"bình đẳng giới","meaning":"Tình trạng trong xã hội mà cả nam và nữ đều có quyền, cơ hội và được đối xử công bằng như nhau."},"8551":{"word":"lạm dụng","meaning":"Sử dụng một chất, quyền lực hoặc nguồn lực một cách sai trái, quá mức hoặc có hại, dẫn đến kết quả tiêu cực."},"8552":{"word":"hiểu rõ","meaning":"Trạng thái đã nắm rõ và chấp nhận một lời giải thích hoặc tình huống là hợp lý."},"8553":{"word":"ngâm thơ","meaning":"Hành động đọc một tác phẩm viết, như thơ hoặc bài phát biểu, một cách rõ ràng và truyền cảm cho người khác nghe."},"8554":{"word":"thất bại","meaning":"Một tình huống mà nỗ lực hoặc sự kiện đã lên kế hoạch diễn ra sai lầm nghiêm trọng, dẫn đến kết quả đáng thất vọng hoặc có vấn đề."},"8555":{"word":"từng cái một, chi tiết","meaning":"Diễn tả việc thực hiện hành động kiểm tra hoặc xử lý từng thứ một một cách kỹ lưỡng, không bỏ sót cái nào."},"8556":{"word":"treo, giăng","meaning":"Đặt một biển hiệu, lá cờ hoặc biểu ngữ lên bề mặt thẳng đứng hoặc cột để nhiều người có thể nhìn thấy."},"8557":{"word":"ném đi, vứt đi","meaning":"Phóng một vật từ trong tay ra với lực mạnh, khiến nó bay đi xa đến một vị trí khác."},"8558":{"word":"bước xuống","meaning":"Di chuyển từ một nơi cao xuống một nơi thấp hơn bằng cách bước chân."},"8559":{"word":"nội địa, đất liền","meaning":"Khu vực địa lý nằm sâu trong đất liền, cách xa biển, đại dương hoặc các vùng nước lớn nối ra biển."},"8560":{"word":"đường xuống dốc","meaning":"Con đường có độ dốc đi xuống."},"8561":{"word":"nội tình, tình tiết bên trong","meaning":"Những chi tiết hoặc bối cảnh bên trong của một vấn đề nào đó mà chưa được tiết lộ."},"8562":{"word":"đuổi ra, đẩy ra","meaning":"Buộc ai đó rời khỏi nơi họ đang ở."},"8563":{"word":"bị đuổi, bị đẩy ra","meaning":"Bị buộc phải rời khỏi nơi mình đang ở."},"8564":{"word":"phun ra, nhả ra","meaning":"Phóng ra một cách mạnh mẽ khí, chất lỏng hoặc chất khác từ một lỗ hở, khiến nó bắn ra ngoài không gian xung quanh."},"8565":{"word":"thực chất, nội dung","meaning":"Chất lượng sâu sắc và vững chắc của một sự vật, làm cho nó mạnh mẽ, đầy đủ và không dễ bị phá vỡ hay thay đổi."},"8566":{"word":"trong lòng, thầm nghĩ","meaning":"Những ý định hoặc cảm xúc thật sự của một người mà không thể hiện ra bên ngoài."},"8567":{"word":"nội tạng","meaning":"Các bộ phận mềm bên trong cơ thể động vật hoặc người, như tim, gan, dạ dày."},"8568":{"word":"nội tại","meaning":"Tồn tại hoặc xảy ra bên trong tâm trí hoặc cảm xúc của một người, không thể hiện ra bên ngoài."},"8569":{"word":"vẫy","meaning":"Di chuyển một bộ phận cơ thể, như cánh tay, nhanh chóng qua lại hoặc từ bên này sang bên kia."},"8570":{"word":"đến","meaning":"Dùng để nối hai con số hoặc sự vật, chỉ khoảng từ cái thứ nhất cho đến cái thứ hai."},"8571":{"word":"trục xuất","meaning":"Buộc một người hoặc vật rời khỏi một nơi hoặc nhóm, hoặc từ chối chấp nhận điều gì đó."},"8572":{"word":"muốn","meaning":"Cảm thấy muốn làm một điều gì đó."},"8573":{"word":"bờ suối","meaning":"Dải đất dọc theo mép một dòng nước nhỏ đang chảy, như suối hoặc rạch."},"8574":{"word":"lạnh nhạt","meaning":"Hành động hoặc nói chuyện một cách không biểu lộ cảm xúc hay quan tâm đến cảm xúc của người khác."},"8575":{"word":"Chiến tranh Lạnh","meaning":"Một giai đoạn dài của sự bất đồng chính trị lớn và cạnh tranh quân sự giữa các quốc gia mà không trực tiếp giao chiến."},"8576":{"word":"bình tĩnh","meaning":"Trạng thái giữ một tâm trí bình tĩnh và hành vi ổn định, không thể hiện cảm xúc mạnh mẽ, ngay cả khi mọi thứ khó khăn."},"8577":{"word":"tàn nhẫn","meaning":"Rất khắc nghiệt và không có bất kỳ lòng trắc ẩn nào đối với người khác, thường gây ra đau khổ hoặc khó khăn."},"8578":{"word":"linh hồn","meaning":"Phần phi vật chất của một người hoặc động vật, được tin là tiếp tục tồn tại sau khi chết, hoặc là nơi cảm xúc và suy nghĩ bắt nguồn."},"8579":{"word":"phơi","meaning":"Trải rộng hoặc treo thứ gì đó ra để làm khô dưới nắng hoặc gió."},"8580":{"word":"bẹt","meaning":"Có hình dạng rộng ra hai bên và không dày hay tròn."},"8581":{"word":"qua lại","meaning":"Đi lại nhiều lần hoặc vượt qua một ranh giới, giới hạn, hay tiêu chuẩn nào đó."},"8582":{"word":"thèm muốn","meaning":"Có mong muốn sở hữu thứ gì đó thuộc về người khác, hoặc coi thường người khác."},"8583":{"word":"rõ ràng","meaning":"Rất rõ ràng và trực tiếp trong lời nói hoặc hành động, không che giấu hay vòng vo."},"8584":{"word":"tuổi già","meaning":"Giai đoạn tuổi tác đã cao."},"8585":{"word":"lòng đỏ trứng","meaning":"Phần màu vàng, hình tròn ở giữa quả trứng, được bao quanh bởi lòng trắng."},"8586":{"word":"vai trò","meaning":"Những hành động và cách cư xử mà một người thực hiện trong một chức năng hoặc nghề nghiệp cụ thể."},"8587":{"word":"nhắm đến","meaning":"Tập trung một cách có chủ đích nỗ lực hoặc ánh mắt vào một đối tượng hay thành tựu cụ thể mà mình rất mong muốn đạt được."},"8588":{"word":"đôi vợ chồng già","meaning":"Một cặp vợ chồng đã lớn tuổi."},"8589":{"word":"lao động và giới chủ","meaning":"Hai nhóm người trong một công ty: một là những người làm công và một là những người điều hành công việc kinh doanh."},"8590":{"word":"sự tức giận","meaning":"Một cảm xúc mạnh mẽ, khó chịu mà một người cảm thấy khi bị bực tức hoặc xúc phạm."},"8591":{"word":"gõ cửa","meaning":"Dùng tay hoặc vật cứng gõ vào cửa hoặc bề mặt khác để gây sự chú ý."},"8592":{"word":"chất thải","meaning":"Là những chất không cần thiết, được cơ thể sống thải ra sau khi hấp thụ dưỡng chất."},"8593":{"word":"nổi giận","meaning":"(Kính trọng) Người lớn tuổi biểu lộ sự không vui hoặc tức giận mạnh mẽ."},"8594":{"word":"bị gỉ","meaning":"Kim loại bị oxy trong không khí làm biến đổi thành màu đỏ hoặc xanh."},"8595":{"word":"tan chảy","meaning":"Chất rắn trở nên mềm hoặc hóa lỏng, chảy xuống."},"8596":{"word":"khu cây xanh","meaning":"Nơi có nhiều cỏ và cây cối mọc tự nhiên hoặc được trồng theo kế hoạch."},"8597":{"word":"sự kiệt sức","meaning":"Tình trạng cơ thể và tinh thần hoàn toàn cạn kiệt năng lượng, không còn chút sức lực nào."},"8598":{"word":"sự tranh cãi","meaning":"Một cuộc tranh cãi hoặc bất đồng ý kiến kéo dài, được nhiều người quan tâm và có quan điểm khác nhau."},"8599":{"word":"bài xã luận","meaning":"Bài viết nêu rõ quan điểm mạnh mẽ của tác giả về một vấn đề, thường được đăng trên báo hoặc tạp chí, nhằm thuyết phục người đọc."},"8600":{"word":"minh chứng","meaning":"Hành động giải thích hoặc thể hiện rõ ràng điều gì đó bằng cách đưa ra lý lẽ, sự thật hoặc thí nghiệm để khẳng định tính đúng đắn."},"8601":{"word":"bình luận","meaning":"Lời giải thích bằng văn bản hoặc lời nói về một sự kiện hoặc tình huống, bao gồm suy nghĩ, nhận định và diễn giải của người nói/viết."},"8602":{"word":"bàn luận","meaning":"Trò chuyện chi tiết về một chủ đề cụ thể với người khác, trao đổi quan điểm để đạt được sự hiểu biết sâu sắc hơn."},"8603":{"word":"Vùng nông thôn và ven biển","meaning":"Những khu vực nông nghiệp và ngư nghiệp, thường nằm bên ngoài các thành phố lớn."},"8604":{"word":"Kính ngữ","meaning":"Hệ thống quy tắc trong ngôn ngữ yêu cầu người nói thay đổi cách dùng từ hoặc mẫu câu tùy theo địa vị xã hội, tuổi tác hoặc mối quan hệ với người nghe."},"8605":{"word":"Hối lộ","meaning":"Tiền bạc hoặc vật có giá trị được bí mật đưa cho người có thẩm quyền để thuyết phục họ hành động không công bằng hoặc ban ơn đặc biệt."},"8606":{"word":"Chết não","meaning":"Tình trạng não bộ của một người ngừng hoạt động vĩnh viễn, dù các cơ quan khác vẫn có thể được duy trì bằng các biện pháp y tế."},"8607":{"word":"Đột quỵ","meaning":"Tình trạng y tế khẩn cấp xảy ra khi nguồn cung cấp máu đến một phần não bị gián đoạn hoặc một mạch máu bị vỡ, gây tổn thương mô não."},"8608":{"word":"Chần vải","meaning":"May nhiều đường thẳng hoặc hoa văn song song qua hai lớp vải có lớp lót mềm ở giữa, nối chúng lại với nhau."},"8609":{"word":"Chị gái","meaning":"Từ người con trai dùng để gọi người chị hoặc em gái ruột/họ của mình."},"8610":{"word":"Rò rỉ","meaning":"Sự thoát ra ngoài không kiểm soát của chất lỏng, khí hoặc vật chất khác từ một vật chứa hoặc đường ống."},"8611":{"word":"Mí mắt","meaning":"Lớp da và cơ mỏng che phía trước mắt khi nhắm lại và kéo lên khi mở ra."},"8612":{"word":"Cảm động rơi nước mắt","meaning":"Miêu tả điều gì đó gây xúc động mạnh mẽ, thường liên quan đến khó khăn hoặc nỗ lực lớn, khiến người ta rơi lệ."},"8613":{"word":"Quan sát kỹ lưỡng","meaning":"Nhìn ai đó hoặc cái gì đó với sự tập trung cao độ và cẩn thận, chú ý đến từng chi tiết hoặc cử động."},"8614":{"word":"Ánh mắt","meaning":"Biểu hiện đặc biệt được truyền tải qua cách mắt của một người thể hiện cảm xúc hoặc phán đoán."},"8615":{"word":"cái lườm","meaning":"Một cái nhìn giận dữ, khó chịu hoặc không tán thành của ai đó."},"8616":{"word":"đột ngột","meaning":"Diễn ra hoặc xuất hiện mà không có bất kỳ dấu hiệu hay sự chuẩn bị nào trước đó, gây ngạc nhiên."},"8617":{"word":"lỏng lẻo","meaning":"Ở trạng thái không chặt chẽ, dễ tuột ra hoặc không còn căng như ban đầu, thường dùng cho dây, nút thắt."},"8618":{"word":"buông thõng","meaning":"Để cái gì đó rủ xuống hoặc treo tự do từ một điểm cao hơn."},"8619":{"word":"oai vệ","meaning":"Miêu tả vẻ ngoài hoặc tư thế của một người trông mạnh mẽ, đĩnh đạc và đáng kính."},"8620":{"word":"giải pháp tối ưu","meaning":"Phương pháp hoặc cách tiếp cận tối ưu được cho là phù hợp và thành công nhất để giải quyết vấn đề."},"8621":{"word":"thông thạo","meaning":"Có trình độ hiểu biết hoặc kỹ năng rất cao trong một lĩnh vực cụ thể, ví dụ như một ngôn ngữ."},"8622":{"word":"giỏi","meaning":"Thể hiện khả năng và năng lực cao khi thực hiện một hành động hoặc trong một lĩnh vực cụ thể."},"8623":{"word":"đa quốc gia","meaning":"Miêu tả một tổ chức có hoạt động, văn phòng hoặc nhà máy đặt tại nhiều quốc gia khác nhau."},"8624":{"word":"thúc giục","meaning":"Nói chuyện một cách mạnh mẽ và liên tục với ai đó để thúc đẩy họ làm điều gì hoặc thú nhận lỗi lầm."},"8625":{"word":"số lượng lớn","meaning":"Một số lượng rất lớn của cái gì đó."},"8626":{"word":"đáng kể","meaning":"Mô tả một hành động hoặc phẩm chất hiện diện một cách khá rõ ràng hoặc có ý nghĩa."},"8627":{"word":"lại lần nữa","meaning":"Diễn tả một hành động được thực hiện hoặc xảy ra sau khi đã từng xảy ra trước đó."},"8628":{"word":"đầm, nện","meaning":"Làm cho vật thể như đất trở nên chắc chắn và chặt chẽ bằng cách nén hoặc đập nhiều lần."},"8629":{"word":"đột ngột, bất ngờ","meaning":"Diễn tả một hành động bắt đầu hoặc xảy ra ngay lập tức mà không có bất kỳ thông báo hay lý do nào trước đó."},"8630":{"word":"đa dạng, phong phú","meaning":"Diễn tả một vật thể hoặc sự kiện có nhiều màu sắc, thể loại hoặc hình thức khác nhau, tạo sự thú vị khi nhìn."},"8631":{"word":"đơn giá","meaning":"Số tiền phải trả hoặc được trả cho một mặt hàng duy nhất hoặc một đơn vị đo lường tiêu chuẩn của sản phẩm."},"8632":{"word":"cự ly ngắn","meaning":"Một khoảng cách không xa."},"8633":{"word":"đoàn kết","meaning":"Trạng thái mọi người cùng hành động hoặc làm việc như một nhóm duy nhất, chia sẻ cùng suy nghĩ và mục tiêu."},"8634":{"word":"theo từng giai đoạn, tuần tự","meaning":"Diễn tả một hành động hoặc sự thay đổi tiến triển chậm rãi theo các giai đoạn hoặc phần riêng biệt, liên tiếp."},"8635":{"word":"từ bỏ, bỏ cuộc","meaning":"Hành động chấp nhận rằng mình không thể đạt được mục tiêu hay mong muốn và do đó ngừng mọi nỗ lực để đạt được nó."},"8636":{"word":"chắc chắn, vững chắc","meaning":"Diễn tả một hành động được thực hiện với sức mạnh đáng kể hoặc theo cách làm cho vật thể rất ổn định và không thể di chuyển."},"8637":{"word":"vỏn vẹn, chỉ có","meaning":"(Dùng để nhấn mạnh) Một số tiền rất nhỏ."},"8638":{"word":"hòa thuận, êm ấm","meaning":"Mối quan hệ giữa các thành viên trong gia đình hoặc nhóm tốt đẹp và hòa bình."},"8639":{"word":"rèn luyện","meaning":"Quá trình luyện tập liên tục để tăng cường thể lực, tinh thần hoặc kỹ năng."},"8640":{"word":"một lần","meaning":"Diễn tả việc gì đó xảy ra chỉ trong một lần duy nhất mà không cần nỗ lực thêm."},"8641":{"word":"điều khoản bổ sung","meaning":"Một điều kiện hoặc ngoại lệ được thêm vào sau một quy định hoặc thỏa thuận chính."},"8642":{"word":"một hơi","meaning":"Diễn tả hành động được thực hiện liên tục từ đầu đến cuối mà không dừng lại, đặc biệt là khi uống hoặc nói."},"8643":{"word":"thời gian ngắn","meaning":"Một khoảng thời gian không dài."},"8644":{"word":"rõ ràng là","meaning":"Diễn tả điều gì đó vượt trội một cách rõ ràng và không thể phủ nhận so với những cái khác."},"8645":{"word":"rõ ràng","meaning":"Diễn tả một ví dụ hoặc bằng chứng quá rõ ràng đến mức có thể nhận thấy hoặc hiểu ngay lập tức."},"8646":{"word":"kiên quyết","meaning":"Thể hiện ý chí hoặc quyết định rất mạnh mẽ thông qua hành động, lời nói hoặc biểu cảm, không có dấu hiệu thay đổi."},"8647":{"word":"nung nóng","meaning":"Làm cho một vật, thường là kim loại, trở nên rất nóng, đôi khi đến mức đổi màu."},"8648":{"word":"dính chặt","meaning":"Một vật hoặc bề mặt bám dính chặt vào một vật khác, khó tách rời."},"8649":{"word":"nóng bừng","meaning":"Trở nên rất nóng (đối với vật) hoặc da mặt đỏ lên do cảm xúc mạnh hay vận động."},"8650":{"word":"bình thản","meaning":"Không biểu lộ cảm xúc mạnh mẽ như lo lắng hay phấn khích, giữ thái độ điềm đạm ngay cả trong tình huống nghiêm trọng."},"8651":{"word":"tài sản thế chấp","meaning":"Tài sản có giá trị được dùng làm vật bảo đảm để trả nợ."},"8652":{"word":"tường rào","meaning":"Cấu trúc cao, vững chắc, thường bằng gạch hoặc gỗ, dùng để phân chia hoặc bảo vệ không gian bên ngoài."},"8653":{"word":"sự đáp lễ","meaning":"Việc tặng quà hoặc thực hiện hành động để đáp lại lòng tốt hoặc món quà đã nhận."},"8654":{"word":"khảo sát thực địa","meaning":"Hoạt động đến trực tiếp một địa điểm để quan sát, thu thập thông tin cho việc nghiên cứu hoặc chuẩn bị."},"8655":{"word":"chính đảng","meaning":"Một nhóm người có cùng ý tưởng và mục đích chính trị."},"8656":{"word":"một cách tự tin","meaning":"Với thái độ mạnh mẽ, đầy tự tin, không hề sợ hãi hay rụt rè."},"8657":{"word":"sự thành bại","meaning":"Kết quả thắng bại hoặc đỗ trượt trong một cuộc thi, kỳ thi hay bầu cử."},"8658":{"word":"đương sự","meaning":"Người có liên quan trực tiếp đến một vấn đề, sự kiện hoặc thỏa thuận nào đó."},"8659":{"word":"sự bối rối","meaning":"Cảm giác lúng túng, ngạc nhiên khi gặp phải tình huống bất ngờ, không biết phải làm gì."},"8660":{"word":"mức","meaning":"Tiếp vị ngữ được gắn sau một số để chỉ mức độ, phạm vi gần với con số đó."},"8661":{"word":"đối","meaning":"Từ dùng để chỉ sự đối đầu hoặc so sánh trực tiếp giữa hai bên."},"8662":{"word":"số lượng lớn","meaning":"Việc xảy ra hoặc có mặt với số lượng lớn cùng một lúc."},"8663":{"word":"tiền thanh toán","meaning":"Khoản tiền phải trả hoặc nhận để đổi lấy hàng hóa hoặc công việc đã hoàn thành."},"8664":{"word":"tài lớn thành muộn","meaning":"Ý nói người có tài năng lớn thường phải trải qua nhiều nỗ lực và thời gian mới đạt được thành công."},"8665":{"word":"táo bạo","meaning":"Có hành động rất dũng cảm, không sợ nguy hiểm hay khó khăn."},"8666":{"word":"đời đời kiếp kiếp","meaning":"Chỉ sự tiếp nối từ thế hệ này sang thế hệ khác, kéo dài mãi mãi."},"8667":{"word":"quy mô lớn","meaning":"Chỉ một sự kiện hay hành động được thực hiện với quy mô rất lớn, liên quan đến nhiều thứ hoặc một phạm vi rộng."},"8668":{"word":"đậu tương","meaning":"Một loại hạt tròn, vỏ mỏng, màu vàng hoặc đen, dùng làm sữa đậu nành hoặc đậu phụ."},"8669":{"word":"cãi lại","meaning":"Nói lại với người lớn hoặc người có quyền theo cách thô lỗ, bất tuân, thể hiện sự bất đồng."},"8670":{"word":"ngay lập tức","meaning":"Diễn tả hành động xảy ra tức thì, không chậm trễ, không báo trước hay do dự."},"8671":{"word":"mùa cao điểm","meaning":"Chỉ một khoảng thời gian cụ thể khi việc kinh doanh rất sôi động, nhiều người mua sắm hoặc tham gia các hoạt động."},"8672":{"word":"thành công lớn","meaning":"Chỉ một kết quả tích cực, lớn lao và bất ngờ, hoặc một vận may đột ngột mang lại nhiều lợi ích."},"8673":{"word":"đại diện","meaning":"Hành động nói hoặc làm thay mặt cho người khác hoặc một nhóm, bày tỏ ý kiến hoặc niềm tin của họ."},"8674":{"word":"đối với Triều Tiên","meaning":"Chỉ điều gì đó (thường là chính sách hoặc hành động) được hướng đến hoặc liên quan đến Triều Tiên."},"8675":{"word":"khóc rống","meaning":"Hành động khóc rất to, mạnh mẽ và ai oán, thường thể hiện sự buồn bã hoặc đau khổ sâu sắc."},"8676":{"word":"quan trọng","meaning":"Chỉ một việc hay sự kiện có tầm quan trọng lớn, đáng chú ý hoặc cần được quan tâm nghiêm túc."},"8677":{"word":"phương án thay thế","meaning":"Một sự lựa chọn, phương pháp hoặc tùy chọn khác có thể được chọn hoặc sử dụng thay cho cái khác."},"8678":{"word":"đại dương","meaning":"Một vùng biển rộng lớn như Thái Bình Dương, Đại Tây Dương, Ấn Độ Dương, Bắc Băng Dương và Nam Băng Dương."},"8679":{"word":"đối ngoại","meaning":"Chỉ các vấn đề như thương mại hoặc ngoại giao liên quan đến các quốc gia khác hoặc diễn ra bên ngoài biên giới một quốc gia."},"8680":{"word":"thành viên","meaning":"Một cá nhân là một phần của một nhóm có tổ chức cụ thể, như đội thám hiểm hoặc đơn vị cứu hộ."},"8681":{"word":"đại tràng","meaning":"Một cơ quan dày, hình ống ở phần dưới bụng giúp loại bỏ nước khỏi thức ăn không tiêu hóa trước khi rời khỏi cơ thể."},"8682":{"word":"bát","meaning":"Một vật dụng hình tròn và sâu lòng dùng để đựng thức ăn hoặc đồ uống."},"8683":{"word":"tính đại chúng","meaning":"Phẩm chất khiến một thứ gì đó, như bài hát hay sản phẩm, được nhiều người bình thường yêu thích và chú ý rộng rãi."},"8684":{"word":"đáng kể","meaning":"Với mức độ hoặc phạm vi lớn, thường dùng để chỉ sự thay đổi, tăng giảm đáng kể."},"8685":{"word":"khu phố đại học","meaning":"Một khu vực trong thị trấn hoặc thành phố có nhiều trường học nơi người trẻ tuổi học tập và thường có nhiều cửa hàng, nhà hàng, quán cà phê phục vụ họ."},"8686":{"word":"đối kháng","meaning":"Hành động chống lại ai đó hoặc cái gì đó, thường bằng cách phản công hoặc từ chối đồng ý với họ."},"8687":{"word":"châm lửa","meaning":"Làm cho một vật bắt đầu cháy bằng cách dùng lửa hoặc tia điện chạm vào."},"8688":{"word":"hơn nữa","meaning":"Từ dùng để thêm một thông tin hoặc lý do, thường làm tăng cường ý nghĩa của điều đã nói."},"8689":{"word":"càng hơn","meaning":"Diễn tả mức độ hoặc cường độ của một điều gì đó cao hơn hẳn so với trước đây."},"8690":{"word":"mò mẫm","meaning":"Dùng tay chạm hoặc tìm kiếm xung quanh để tìm hay kiểm tra một vật gì đó, đặc biệt trong bóng tối."},"8691":{"word":"chậm","meaning":"Di chuyển, phát triển hoặc diễn ra với tốc độ không nhanh, thường là chậm."},"8692":{"word":"thỉnh thoảng","meaning":"Xảy ra hoặc xuất hiện không thường xuyên, chỉ vào một số thời điểm nhất định."},"8693":{"word":"đống","meaning":"Một khối lượng lớn gồm nhiều vật được chất chồng lên nhau ở một chỗ."},"8694":{"word":"đầy bụng","meaning":"Cảm thấy khó chịu ở bụng, bụng căng tức do có nhiều hơi hoặc thức ăn bên trong."},"8695":{"word":"đức tính","meaning":"Một đặc điểm tính cách tốt đẹp, đáng ngưỡng mộ mà một người thể hiện qua hành động."},"8696":{"word":"hậu đậu","meaning":"Hành động một cách vội vàng, thiếu cẩn thận, thường mắc lỗi hoặc quên việc."},"8697":{"word":"giật mình","meaning":"Diễn tả sự việc xảy ra bất ngờ, gây ra cảm giác sợ hãi hoặc lo lắng đột ngột."},"8698":{"word":"quà tặng kèm","meaning":"Một món đồ được tặng thêm miễn phí ngoài sản phẩm chính hoặc số lượng đã thanh toán."},"8699":{"word":"tấn công, xông vào","meaning":"Nhanh chóng lao về phía trước và trực tiếp đối đầu với ai đó hoặc cái gì đó một cách mạnh mẽ, thường là hung hăng."},"8700":{"word":"lao vào, gây sự","meaning":"Nhanh chóng và thù địch di chuyển về phía người hoặc động vật khác, thường là để đánh nhau."},"8701":{"word":"làm ấm, đun nóng","meaning":"Làm tăng nhiệt độ của một chất, khiến nó bớt lạnh hoặc không còn lạnh."},"8702":{"word":"a dua, làm theo","meaning":"Thực hiện hành động hoặc cư xử theo cách tương tự như những người xung quanh, thường là không suy nghĩ nhiều."},"8703":{"word":"vóc dáng, thân hình","meaning":"Khối lượng và thể tích tổng thể của cơ thể một sinh vật sống."},"8704":{"word":"ập đến, xảy đến (tai họa)","meaning":"Tai họa hoặc điều xấu xảy ra dồn dập, bất ngờ."},"8705":{"word":"mức độ, giới hạn","meaning":"Một điểm hoặc giới hạn cụ thể trong một phạm vi, cho biết điều gì đó đi xa đến đâu hoặc có bao nhiêu."},"8706":{"word":"đạo đức","meaning":"Tập hợp các nguyên tắc hướng dẫn hành vi của một người, thể hiện điều gì được coi là đúng đắn và chấp nhận được trong xã hội."},"8707":{"word":"tính đạo đức, phẩm chất đạo đức","meaning":"Phẩm chất trong hành vi của một người phù hợp với các nguyên tắc hành vi đúng đắn được xã hội chấp nhận."},"8708":{"word":"có đạo đức, thuộc về đạo đức","meaning":"Liên quan đến các nguyên tắc định nghĩa hành động đúng đắn và chấp nhận được của con người."},"8709":{"word":"sự ra đời, sự xuất hiện","meaning":"Thời điểm một điều gì đó mới mẻ và quan trọng bắt đầu hoặc xuất hiện."},"8710":{"word":"đạo lý, bổn phận","meaning":"Một quy tắc cơ bản hoặc một cách hành động được mong đợi mà một người được kỳ vọng phải tuân theo."},"8711":{"word":"tỉnh lập","meaning":"Chỉ một tổ chức hay cơ sở do tỉnh quản lý hoặc hỗ trợ."},"8712":{"word":"đảm nhiệm hết","meaning":"Tự mình nhận lãnh và xử lý hoàn toàn mọi phần của một công việc hay vai trò mà không cần sự giúp đỡ từ người khác."},"8713":{"word":"sự thúc đẩy","meaning":"Hành động lập kế hoạch và thực hiện các bước để làm cho điều gì đó phát triển hoặc đạt được một mục tiêu nhất định."},"8714":{"word":"cú nhảy","meaning":"Hành động dồn sức nhảy bổng lên không trung một cách mạnh mẽ."},"8715":{"word":"khắp nơi","meaning":"Có mặt ở nhiều địa điểm khác nhau, bao phủ một khu vực rộng lớn hoặc xuất hiện ở vô số nơi."},"8716":{"word":"sự đào thải","meaning":"Trường hợp một số vật bị loại bỏ hoặc biến mất vì không đủ mạnh hoặc không phù hợp, chỉ còn lại những cái khác."},"8717":{"word":"người cao tuổi sống một mình","meaning":"Người cao tuổi sống một mình, không ở chung nhà với bất kỳ ai khác."},"8718":{"word":"rắn độc","meaning":"Loài bò sát dài, trườn, có thể tiêm chất lỏng độc hại vào sinh vật khác bằng vết cắn."},"8719":{"word":"tự cho mình là đúng","meaning":"Mô tả người tin chắc rằng quan điểm của mình luôn đúng và thường không quan tâm đến suy nghĩ của người khác."},"8720":{"word":"độc tính","meaning":"Tính chất của một chất có thể gây hại nghiêm trọng hoặc gây chết người nếu sinh vật sống chạm vào, nuốt phải hoặc hít phải."},"8721":{"word":"độc lập","meaning":"Mô tả cái gì đó hành động, tồn tại hoặc vận hành hoàn toàn độc lập, không phụ thuộc hay bị kiểm soát bởi bất kỳ thứ gì khác."},"8722":{"word":"chế độ độc tài","meaning":"Hình thức chính phủ mà trong đó một người cai trị có quyền lực tuyệt đối và toàn diện, kiểm soát mọi thứ mà không cho phép người dân lựa chọn hay phản đối."},"8723":{"word":"kẻ độc tài","meaning":"Người nắm giữ toàn bộ quyền lực trong một quốc gia, thường cai trị bằng vũ lực."},"8724":{"word":"độc quyền","meaning":"Tình huống thị trường mà chỉ một doanh nghiệp cung cấp một sản phẩm hoặc dịch vụ nhất định."},"8725":{"word":"tính độc đáo","meaning":"Phẩm chất hoàn toàn mới mẻ và khác biệt, thể hiện những ý tưởng chưa từng thấy."},"8726":{"word":"khăng khít","meaning":"Mô tả mối quan hệ giữa người với người rất bền chặt và ấm áp."},"8727":{"word":"nhìn lại","meaning":"Quay đầu để nhìn vật hoặc người đang ở phía sau."},"8728":{"word":"đột biến","meaning":"Sự thay đổi bất ngờ trong vật liệu di truyền của một sinh vật sống."},"8729":{"word":"đột phá","meaning":"Thành công bất ngờ trong việc vượt qua trở ngại hoặc giải quyết vấn đề."},"8730":{"word":"Tokyo","meaning":"Thủ đô của Nhật Bản, nằm ở vùng Kanto."},"8731":{"word":"bình đẳng","meaning":"Trạng thái mà tất cả mọi người có giá trị, quyền hoặc cơ hội như nhau."},"8732":{"word":"động lực","meaning":"Năng lượng hoặc lực đẩy làm cho máy móc hoặc phương tiện hoạt động."},"8733":{"word":"động mạch","meaning":"Ống lớn trong cơ thể mang máu giàu oxy từ tim đến các bộ phận khác."},"8734":{"word":"huy chương đồng","meaning":"Một huy chương màu đồng được trao cho người đạt vị trí thứ ba trong một sự kiện thể thao."},"8735":{"word":"hỏi một đằng trả lời một nẻo","meaning":"Đây là lời đáp hay nhận xét hoàn toàn không đúng trọng tâm câu hỏi hoặc chủ đề đang được thảo luận."},"8736":{"word":"đồng bệnh tương lân","meaning":"Là việc những người có cùng hoàn cảnh khó khăn hoặc đau khổ mà thông cảm cho nhau."},"8737":{"word":"đồng sàng dị mộng","meaning":"Là tình trạng nhiều người cùng ở trong một hoàn cảnh nhưng lại có suy nghĩ hoặc ý định khác nhau."},"8738":{"word":"cùng họ","meaning":"Chỉ việc có cùng họ với người khác."},"8739":{"word":"phiên dịch đồng thời","meaning":"Là quá trình lời nói của người phát biểu được người khác dịch ngay lập tức sang một ngôn ngữ khác."},"8740":{"word":"sự rung lắc","meaning":"Là chuyển động qua lại hoặc lên xuống, hoặc tình trạng không ổn định, bất an."},"8741":{"word":"năng động","meaning":"Mô tả điều gì đó luôn thay đổi, phát triển hoặc đầy năng lượng và hoạt động."},"8742":{"word":"dongjeong","meaning":"Là một mảnh vải trắng mỏng, cứng được gắn vào phần cổ áo (git) của áo jeogori truyền thống Hàn Quốc."},"8743":{"word":"tính đồng nhất","meaning":"Là đặc điểm của một nhóm sự vật hoặc con người có tính chất, loại hình hoặc phẩm chất rất giống nhau."},"8744":{"word":"sự tham gia chung","meaning":"Là hành động cùng tham gia vào một hoạt động, sự kiện hoặc nỗ lực với những người khác."},"8745":{"word":"xu hướng","meaning":"Là sự thay đổi hoặc phát triển chung của một vấn đề trong một khoảng thời gian."},"8746":{"word":"người có cùng sở thích","meaning":"Là người cùng chia sẻ một sở thích với những người khác và cùng nhau tận hưởng nó."},"8747":{"word":"nhắc đi nhắc lại","meaning":"Nói đi nói lại cùng một điều nhiều lần."},"8748":{"word":"suy ngẫm","meaning":"Suy nghĩ kỹ càng về những kinh nghiệm, lời nói hay ý tưởng trong quá khứ."},"8749":{"word":"phụ âm căng","meaning":"Một loại âm thanh đặc biệt trong tiếng Hàn được phát âm bằng cách siết chặt cơ cổ họng và miệng."},"8750":{"word":"sự nổi bật","meaning":"Tình trạng được chú ý hoặc công nhận cao nhờ kỹ năng hoặc thành tích vượt trội trong một nhóm."},"8751":{"word":"khắp nơi","meaning":"Mô tả một điều gì đó bao gồm hoặc ảnh hưởng đến nhiều địa điểm, người hoặc chủ đề khác nhau."},"8752":{"word":"dày dặn","meaning":"Miêu tả một vật có độ dày lớn đáng kể giữa hai mặt chính của nó."},"8753":{"word":"đê","meaning":"Một gò đất dài được làm từ đá hoặc đất, được xây dựng để ngăn nước suối hoặc hồ tràn ra."},"8754":{"word":"ngồi quây quần","meaning":"Một nhóm người ngồi xuống tạo thành hình tròn."},"8755":{"word":"tròn trịa","meaning":"Miêu tả một vật có hình dạng tròn hoặc hình cầu."},"8756":{"word":"bồng bềnh","meaning":"Mô tả chuyển động nhẹ nhàng, êm ái của một vật lơ lửng trong nước hoặc không khí."},"8757":{"word":"bị bao phủ","meaning":"Khi toàn bộ bề mặt bị che lấp hoàn toàn dưới một lớp vật chất nào đó."},"8758":{"word":"nhìn lại","meaning":"Quay đầu hoặc cơ thể để nhìn cái gì đó ở phía sau."},"8759":{"word":"bị đảo lộn","meaning":"Vị trí hoặc thứ tự của cái gì đó trở nên hoàn toàn đối lập hoặc bị đổi chỗ."},"8760":{"word":"bị lẫn lộn","meaning":"Nhiều thứ khác nhau bị trộn lẫn vào nhau một cách lộn xộn hoặc không có trật tự."},"8761":{"word":"bị rối tung","meaning":"Nhiều vật thể dài hoặc nhiều thứ bị xoắn vào nhau tạo thành một mớ phức tạp, rối rắm hoặc bị kẹt cứng."},"8762":{"word":"lục lọi","meaning":"Dùng tay di chuyển các thứ bên trong một vật chứa để tìm kiếm cái gì đó."},"8763":{"word":"lộn xộn","meaning":"Tình trạng mọi thứ ở trong sự vô tổ chức và hỗn loạn hoàn toàn."},"8764":{"word":"đuổi theo","meaning":"Chạy nhanh theo ai đó hoặc cái gì đó với ý định bắt lấy họ/nó."},"8765":{"word":"gáy","meaning":"Phần tròn phía sau hộp sọ của một người, đối diện với khuôn mặt."},"8766":{"word":"bị vặn vẹo","meaning":"Một vật thể hoặc cơ thể bị bẻ cong hoặc xoắn mạnh mẽ khỏi hình dạng thẳng hoặc bình thường ban đầu của nó."},"8767":{"word":"sự hỗ trợ","meaning":"Hành động giúp đỡ và cung cấp mọi thứ cần thiết để ai đó sống hoặc thành công."},"8768":{"word":"việc sau này","meaning":"Những điều sẽ xảy ra sau một sự kiện nào đó."},"8769":{"word":"vị trí thứ yếu","meaning":"Một vị trí hoặc tình huống mà ai đó hoặc cái gì đó được coi là ít quan trọng hơn và không được chú ý."},"8770":{"word":"lăn lóc","meaning":"Di chuyển cơ thể trên một bề mặt bằng cách lật qua lật lại hoặc từ đầu này sang đầu kia."},"8771":{"word":"nằm ngửa ra","meaning":"Đặt cơ thể nằm ngang trên một bề mặt phẳng, thường là trong tư thế thư giãn."},"8772":{"word":"rủ xuống","meaning":"Để thứ gì đó rủ hoặc trải dài xuống từ một nơi cao hơn, thường tạo ra một lớp che phủ hoặc bóng râm."},"8773":{"word":"bướng bỉnh","meaning":"Không muốn thay đổi suy nghĩ hoặc hành động của mình, thường khăng khăng làm theo ý mình."},"8774":{"word":"ghi điểm","meaning":"Hành động giành được một dấu hiệu hoặc đơn vị giá trị trong một trò chơi hoặc cuộc thi, thường được hiển thị trên bảng điểm."},"8775":{"word":"đông đúc","meaning":"Một nơi chứa đầy những sinh vật đang di chuyển, tạo ra cảnh tượng bận rộn hoặc hỗn loạn."},"8776":{"word":"phấn khích","meaning":"Tinh thần hoặc không khí không ổn định và có chút phấn khích."},"8777":{"word":"ra vào liên tục","meaning":"Vào một nơi rồi lại ra khỏi đó, thực hiện hành động này nhiều lần trong một khoảng thời gian."},"8778":{"word":"nhắc đi nhắc lại","meaning":"Nói về một chủ đề hoặc vấn đề cụ thể nhiều lần, thường là để nhấn mạnh hoặc gây khó chịu."},"8779":{"word":"nhấp nhô","meaning":"Một phần cơ thể hoặc bề mặt di chuyển lên xuống nhẹ nhàng và lặp đi lặp lại, thể hiện sự bồn chồn hoặc cảm xúc."},"8780":{"word":"đúng y","meaning":"Một cái gì đó hoàn toàn chính xác như dự đoán hoặc trùng khớp hoàn hảo với cái khác khi so sánh."},"8781":{"word":"đầy ắp","meaning":"Một không gian hoặc vật chứa trở nên hoàn toàn bị chiếm giữ bởi một chất hoặc vật thể, không còn chỗ trống."},"8782":{"word":"đưa vào","meaning":"Di chuyển một vật hoặc một người từ khu vực bên ngoài vào không gian bên trong, đặt nó trong một ranh giới."},"8783":{"word":"nhìn thấy rõ bên trong","meaning":"Phần bên trong của một vật hay không gian được nhìn thấy rõ ràng từ bên ngoài."},"8784":{"word":"xông vào","meaning":"Vào một nơi nào đó một cách rất nhanh, mạnh bạo, thường không có sự cho phép hay báo trước."},"8785":{"word":"hít vào","meaning":"Đưa không khí, khói hoặc khí khác vào phổi qua miệng hoặc mũi."},"8786":{"word":"uống ực","meaning":"Uống một lượng lớn chất lỏng một cách nhanh chóng và có tiếng động."},"8787":{"word":"vén lên","meaning":"Nhấc hoặc vén một vật gì đó lên để lộ ra cái ở bên dưới hoặc bên trong."},"8788":{"word":"đèn","meaning":"Thiết bị dùng để phát ra ánh sáng."},"8789":{"word":"xương sống","meaning":"Cột xương nhỏ chạy dọc giữa lưng ở người và nhiều loài động vật, có chức năng nâng đỡ cơ thể và bảo vệ các dây thần kinh."},"8790":{"word":"cấp bậc","meaning":"Hệ thống dùng để phân loại mức độ tốt, xấu, cao hay thấp."},"8791":{"word":"cửa ngõ thành công","meaning":"Cơ hội hoặc sự kiện quan trọng cho phép một người đạt được vị trí xã hội cao hơn, thành công lớn hoặc trở nên nổi tiếng."},"8792":{"word":"sự đăng ký","meaning":"Việc ghi chép, đưa tên hoặc mục nào đó vào một tài liệu, hồ sơ chính thức hay một ấn phẩm."},"8793":{"word":"các nơi như","meaning":"Từ dùng để chỉ ra rằng danh sách các địa điểm được liệt kê còn bao gồm những khu vực tương tự khác không được nhắc đến."},"8794":{"word":"quay lưng lại","meaning":"Xoay lưng về phía một người hoặc tình huống, thường để thể hiện sự từ chối ủng hộ hoặc không muốn đối phó."},"8795":{"word":"đặt chân, giẫm lên","meaning":"Đặt chân lên một bề mặt một cách vững chắc, thường để giữ thăng bằng hoặc bắt đầu di chuyển."},"8796":{"word":"cô lập, loại trừ","meaning":"Tách biệt hoặc khiến người khác khó chịu vì không thích họ."},"8797":{"word":"đi theo, đi cùng","meaning":"Bắt đầu một hành trình hoặc hoạt động bằng cách đi theo người khác."},"8798":{"word":"đáng thương, tội nghiệp","meaning":"Ở trong tình huống rất đáng buồn, khó khăn khiến người khác cảm thấy thông cảm."},"8799":{"word":"đặc biệt, cụ thể là","meaning":"Dùng để nhấn mạnh tính rõ ràng, chính xác của điều gì đó, thường khi nói rằng không có gì khác biệt."},"8800":{"word":"đúng lúc, vừa kịp lúc","meaning":"Diễn tả một sự việc xảy ra vào đúng thời điểm hoàn hảo, không chậm trễ cũng không quá sớm."},"8801":{"word":"đùn đẩy, đổ lỗi","meaning":"Chuyển giao một nhiệm vụ, trách nhiệm hoặc lỗi lầm không mong muốn từ mình sang người khác."},"8802":{"word":"trôi nổi, lềnh bềnh","meaning":"Một vật nằm trên mặt nước hoặc di chuyển trong không khí mà không chìm xuống hay chạm đất."},"8803":{"word":"lang thang, phiêu bạt","meaning":"Một người hoặc con vật di chuyển từ nơi này sang nơi khác mà không có hướng đi hay đích đến cụ thể."},"8804":{"word":"bị đẩy, bị xô đẩy","meaning":"Bị một lực bên ngoài tác động, khiến phải di chuyển khỏi vị trí hiện tại."},"8805":{"word":"cúi xuống, nhìn xuống","meaning":"Hướng cái nhìn hoặc đầu xuống dưới."},"8806":{"word":"nổi danh, lừng danh","meaning":"Tên tuổi hoặc thành tựu của một người trở nên được nhiều người biết đến và tôn trọng."},"8807":{"word":"rũ bỏ, gạt bỏ","meaning":"Làm cho một điều gì đó, thường là lo lắng hay cảm xúc tiêu cực, biến mất."},"8808":{"word":"mở ra (mắt)","meaning":"Mắt đang nhắm bỗng nhiên mở ra."},"8809":{"word":"xé ra, bóc ra","meaning":"Dùng tay hoặc dụng cụ kéo mạnh để tách một phần ra khỏi vật thể lớn hơn."},"8810":{"word":"cách viết khoảng trắng","meaning":"Khoảng trống để lại giữa các từ trong văn bản viết để dễ đọc hơn."},"8811":{"word":"lãng mạn","meaning":"Mang tính chất gợi cảm giác yêu đương, dịu dàng và kết nối đặc biệt giữa hai người."},"8812":{"word":"liên đoàn, giải đấu","meaning":"Một nhóm các đội thể thao hoặc câu lạc bộ thi đấu với nhau trong một loạt trận để xác định nhà vô địch."},"8813":{"word":"vợ (người vợ lớn tuổi)","meaning":"Từ thân mật dùng để chỉ người vợ đã qua tuổi trung niên."},"8814":{"word":"từ chối, khước từ","meaning":"Bày tỏ sự không sẵn lòng chấp nhận một lời đề nghị, lời mời hoặc yêu cầu từ người khác."},"8815":{"word":"bất đắc dĩ, miễn cưỡng","meaning":"Làm việc gì đó một cách chậm chạp hoặc do dự vì không muốn nhưng cảm thấy bắt buộc phải làm."},"8816":{"word":"gây mê, gây tê","meaning":"Một thủ thuật y tế làm cho một người hoặc một phần cơ thể không cảm thấy đau trong phẫu thuật hoặc điều trị."},"8817":{"word":"hùng mạnh, vô cùng mạnh mẽ","meaning":"Sở hữu một lượng lớn sức mạnh, ảnh hưởng hoặc khả năng cực kỳ lớn, khó có thể vượt qua hoặc chống lại."},"8818":{"word":"bế tắc, đường cùng","meaning":"Một con đường không có lối thoát ở cuối, khiến việc tiến xa hơn là không thể."},"8819":{"word":"gậy, que","meaning":"Một vật dài, mỏng, thường làm bằng gỗ hoặc vật liệu cứng khác, dùng để chống đỡ, đánh hoặc mang vác."},"8820":{"word":"to lớn, khổng lồ","meaning":"Có kích thước, số lượng hoặc mức độ lớn bất thường, vượt xa mức bình thường."},"8821":{"word":"bất kể, không phân biệt","meaning":"Áp dụng cho mọi người hoặc mọi vật theo cùng một cách, không phân biệt loại hình, tuổi tác hay địa vị xã hội."},"8822":{"word":"sự khăng khăng, sự cứng đầu","meaning":"Hành động với ý chí kiên quyết, không chịu nghe lời người khác hay thay đổi kế hoạch."},"8823":{"word":"giai đoạn cuối, chặng cuối","meaning":"Phần cuối cùng của một quá trình hoặc sự kiện, ngay trước khi nó hoàn thành."},"8824":{"word":"ngang tài ngang sức, một chín một mười","meaning":"Tình trạng các sự vật hầu như không có sự khác biệt, khiến khó có thể biết cái nào tốt hơn."},"8825":{"word":"một cách mơ hồ","meaning":"Thực hiện việc gì đó (như suy nghĩ, ghi nhớ) mà không có chi tiết rõ ràng hoặc thông tin cụ thể."},"8826":{"word":"trọng đại, quan trọng","meaning":"Mô tả một nhiệm vụ hoặc nghĩa vụ vô cùng quan trọng và đòi hỏi rất nhiều sự chú ý hoặc nỗ lực."},"8827":{"word":"trôi chảy, không ngừng nghỉ","meaning":"Thực hiện việc gì đó, như nói, một cách liên tục và dễ dàng mà không gặp bất kỳ trở ngại nào."},"8828":{"word":"sự tận hưởng trọn vẹn","meaning":"Cảm giác hài lòng sâu sắc khi trải nghiệm điều gì đó một cách hoàn toàn và không chút do dự."},"8829":{"word":"mọi việc, mọi sự","meaning":"Chỉ tất cả các vấn đề hoặc tình huống theo nghĩa tổng thể và toàn diện."},"8830":{"word":"hoan hô, vạn tuế","meaning":"Tiếng hô lớn của nhiều người để thể hiện sự ủng hộ mạnh mẽ, niềm vui hoặc mong muốn điều gì đó tồn tại rất lâu dài."},"8831":{"word":"Sự lan rộng, sự tràn lan","meaning":"Tình trạng một điều gì đó, thường là tiêu cực, tồn tại hoặc lan rộng khắp một khu vực hoặc trong nhiều người."},"8832":{"word":"Sự nhất trí, sự đồng lòng","meaning":"Tình trạng tất cả mọi người trong một nhóm hoàn toàn có cùng ý kiến hoặc quyết định."},"8833":{"word":"Anh cả, trưởng nam","meaning":"Người anh lớn nhất trong số các anh em trai."},"8834":{"word":"Cấp thấp nhất, cuối cùng","meaning":"Phần cuối cùng hoặc vị trí thấp nhất của một thứ gì đó, thường là trong một tổ chức hay hệ thống."},"8835":{"word":"Khả năng nói, lời nói đầu tiên","meaning":"Khả năng bắt đầu nói hoặc những lời nói đầu tiên mà ai đó thốt ra."},"8836":{"word":"Do, bởi, vì","meaning":"Một việc gì đó xảy ra như là kết quả trực tiếp của một hành động hoặc điều kiện cụ thể trước đó."},"8837":{"word":"Tài ăn nói, khả năng diễn đạt","meaning":"Kỹ năng diễn đạt bản thân một cách rõ ràng và thuyết phục bằng lời nói."},"8838":{"word":"Rắc rối, sự phiền phức","meaning":"Tình huống gây ra khó khăn, tranh cãi hoặc làm gián đoạn trạng thái yên bình."},"8839":{"word":"Lưới","meaning":"Vật liệu được làm từ các sợi hoặc dây đan vào nhau, tạo thành mạng lưới các khoảng trống, thường dùng để bắt cá hoặc che phủ vật thể."},"8840":{"word":"Sự nhục nhã, sự xấu hổ","meaning":"Cảm giác xấu hổ hoặc bẽ mặt trước công chúng mạnh mẽ, thể hiện rõ qua vẻ mặt hoặc hành động của một người sau khi bị làm cho trông thật ngớ ngẩn."},"8841":{"word":"Kính thiên văn, ống nhòm","meaning":"Một thiết bị quang học sử dụng thấu kính và gương để làm cho các vật thể ở xa, như sao hoặc hành tinh, xuất hiện lớn hơn và gần hơn khi nhìn qua nó."},"8842":{"word":"Cái búa","meaning":"Một dụng cụ có đầu nặng, rắn chắc, thường làm bằng kim loại, gắn vào một tay cầm, dùng để đập các vật hoặc đóng đinh."},"8843":{"word":"tương đương","meaning":"Có kích thước, số lượng, giá trị hoặc tầm quan trọng giống hệt nhau."},"8844":{"word":"va chạm, giao đấu","meaning":"Hai vật hoặc người tiếp xúc trực tiếp, thường là mạnh mẽ, như trong một cuộc vật lộn hoặc chiến đấu."},"8845":{"word":"khớp chính xác, hợp lý","meaning":"Mọi phần của cái gì đó, như các con số trong phép tính hoặc chi tiết câu chuyện, khớp hoàn hảo và hoàn toàn hợp lý."},"8846":{"word":"hưởng ứng, tán đồng","meaning":"Một lời nói hoặc hành động thể hiện sự hiểu, xác nhận hoặc ủng hộ điều người khác đang nói."},"8847":{"word":"đặt làm riêng, may đo","meaning":"Được tạo ra hoặc điều chỉnh đặc biệt cho một người cụ thể, theo số đo và sở thích cá nhân của họ."},"8848":{"word":"tờ, tấm","meaning":"Từ dùng để đếm các vật mỏng và phẳng như giấy, vé."},"8849":{"word":"định, đánh giá","meaning":"Xác định và ghi lại giá trị, điểm số hoặc thứ hạng cho một cái gì đó."},"8850":{"word":"quản lý","meaning":"Người có quyền kiểm soát và giám sát một doanh nghiệp, đội nhóm hoặc sự nghiệp của một người."},"8851":{"word":"nút thắt","meaning":"Một mối buộc được tạo ra bằng cách xoắn và buộc các sợi dây, chỉ hoặc vải lại với nhau."},"8852":{"word":"say mê, cuốn hút","meaning":"Cảm giác bị mê hoặc hoặc quyến rũ mạnh mẽ bởi ai đó hoặc điều gì đó."},"8853":{"word":"san lấp","meaning":"Hành động lấp đầy biển, vùng đất thấp hoặc hồ chứa bằng đá, đất, cát."},"8854":{"word":"chôn cất","meaning":"Hành động chôn một thi thể hoặc hài cốt xuống đất."},"8855":{"word":"sự chuyên tâm","meaning":"Tình trạng tập trung hết sức lực và tinh thần vào một việc gì đó."},"8856":{"word":"sinh khí","meaning":"Năng lượng hoặc tinh thần làm cho một người có sức sống và hoạt động."},"8857":{"word":"ngữ cảnh","meaning":"Tập hợp các tình huống, sự kiện xung quanh một vấn đề giúp hiểu rõ hơn về nó."},"8858":{"word":"mạch đập","meaning":"Sự co bóp nhịp nhàng của tim tạo ra sóng truyền qua động mạch mà ta có thể cảm nhận."},"8859":{"word":"lượn lờ","meaning":"Di chuyển vòng quanh một vật hoặc một vị trí nào đó."},"8860":{"word":"dáng vẻ thanh lịch","meaning":"Vẻ đẹp và sự duyên dáng toát ra từ trang phục và cách ăn mặc của một người."},"8861":{"word":"mãnh liệt","meaning":"Biểu hiện sức mạnh, tốc độ hoặc ý chí một cách mạnh mẽ và quyết liệt."},"8862":{"word":"kết trái","meaning":"Đối với cây cối, là quá trình ra hoa và hình thành quả."},"8863":{"word":"ngậm","meaning":"Giữ một thứ gì đó trong miệng mà không nuốt."},"8864":{"word":"đầu giường","meaning":"Vị trí ngay cạnh phần đầu của giường nơi người nằm thường đặt đầu."},"8865":{"word":"mây đen","meaning":"Những đám mây có màu sẫm thường xuất hiện trước khi trời mưa hoặc tuyết."},"8866":{"word":"mù lòa","meaning":"Tình trạng không thể nhìn thấy được bằng mắt."},"8867":{"word":"có phong cách","meaning":"Có vẻ ngoài đẹp đẽ, thu hút và tinh tế."},"8868":{"word":"bị bầm tím","meaning":"Da bị đổi màu thành xanh hoặc tím do mạch máu dưới da bị vỡ vì va chạm."},"8869":{"word":"diện mạo","meaning":"Vẻ ngoài, đặc điểm hay khía cạnh cụ thể mà một người hay vật thể thể hiện ra."},"8870":{"word":"miễn dịch","meaning":"Hiện tượng cơ thể tạo kháng thể chống lại vi trùng, vi rút, giúp không bị mắc bệnh."},"8871":{"word":"thăm gặp","meaning":"Cuộc gặp gỡ đã được sắp xếp để được phép nhìn thấy người đang ở bệnh viện, nhà tù hoặc nơi tương tự."},"8872":{"word":"nơi phong thủy tốt","meaning":"Địa điểm tốt để xây nhà hoặc làm mộ, được tin là mang lại may mắn cho con cháu theo thuyết phong thủy."},"8873":{"word":"rõ ràng","meaning":"Được diễn đạt hoặc trình bày một cách rất dễ hiểu, không có sự nhầm lẫn hay mơ hồ."},"8874":{"word":"danh nghĩa","meaning":"Lý do được đưa ra để che giấu mục đích thực sự, hoặc vị trí chỉ tồn tại trên danh nghĩa mà không có quyền lực thực tế."},"8875":{"word":"trường danh giá","meaning":"Một trường học có truyền thống, uy tín và chất lượng được nhiều người công nhận."},"8876":{"word":"rõ ràng","meaning":"Rất dễ thấy, dễ nhận biết hoặc dễ hiểu đến mức không có nghi ngờ gì về sự thật hay sự tồn tại của nó."},"8877":{"word":"an nghỉ của người đã khuất","meaning":"Lời cầu nguyện hay mong ước cho linh hồn của người đã khuất được yên nghỉ và hưởng phước lành."},"8878":{"word":"lý do chính đáng","meaning":"Lý do hoặc nguyên nhân hợp lệ được đưa ra để giải thích tại sao một hành động hoặc tình huống là đúng, công bằng hoặc cần thiết."},"8879":{"word":"danh lam thắng cảnh","meaning":"Nơi có cảnh đẹp tự nhiên nổi bật hoặc giá trị lịch sử quan trọng, thu hút nhiều người đến tham quan."},"8880":{"word":"danh xứng với thực","meaning":"Tình trạng mà đặc điểm, khả năng hoặc chất lượng thực tế của một cái gì đó hoàn toàn phù hợp với danh tiếng hoặc tên gọi của nó."},"8881":{"word":"trúng đích","meaning":"Hành động đánh trúng một mục tiêu đã định một cách chính xác."},"8882":{"word":"tên gọi","meaning":"Từ hoặc cụm từ cụ thể dùng để nhận diện một người, địa điểm hoặc vật thể."},"8883":{"word":"lửa trại","meaning":"Một đống lửa lớn được đốt ngoài trời, thường để sưởi ấm hoặc phục vụ một buổi tụ tập."},"8884":{"word":"sự tìm kiếm","meaning":"Hoạt động xem xét cẩn thận nhiều khả năng khác nhau để tìm ra một kế hoạch hoặc phương pháp tốt."},"8885":{"word":"cạnh","meaning":"Đường hoặc điểm nơi hai hay nhiều bề mặt hoặc mặt bên của một vật thể gặp nhau."},"8886":{"word":"mâu thuẫn","meaning":"Tình trạng hai ý tưởng hoặc hành động cùng tồn tại nhưng lại hoàn toàn đối lập nhau, khiến cả hai dường như không thể xảy ra."},"8887":{"word":"sự xúc phạm","meaning":"Những lời nói hoặc hành động được dùng để làm cho ai đó cảm thấy rất tệ hoặc vô giá trị."},"8888":{"word":"sữa mẹ","meaning":"Thức ăn lỏng tự nhiên được cơ thể người mẹ sản xuất để nuôi con."},"8889":{"word":"khắc nghiệt","meaning":"Hành động hoặc nói chuyện một cách rất nghiêm khắc và tàn nhẫn, thường gây ra sự bất hạnh hoặc đau khổ cho người khác."},"8890":{"word":"góc phố","meaning":"Điểm cụ thể nơi hai con đường hoặc hai mặt của một tòa nhà gặp nhau, tạo ra một khúc cua."},"8891":{"word":"mô típ","meaning":"Một hình ảnh, ý tưởng hay chủ đề được lặp lại nhiều lần trong một tác phẩm nghệ thuật, có vai trò quan trọng."},"8892":{"word":"mơ hồ","meaning":"Không rõ ràng, không minh bạch, khó hiểu hoặc không thể xác định chính xác."},"8893":{"word":"gáy","meaning":"Phần phía sau của cổ, nơi tóc thường bắt đầu mọc xuống từ đầu."},"8894":{"word":"sụp đổ","meaning":"Tình trạng mất hết quyền lực, địa vị, sự giàu có, dẫn đến sự tàn lụi hoàn toàn."},"8895":{"word":"đổ xô đến","meaning":"Nhiều người hoặc động vật cùng nhau di chuyển nhanh chóng thành nhóm đến một nơi nào đó."},"8896":{"word":"thúc đẩy","meaning":"Làm cho cái gì đó hoặc ai đó tiến triển hoặc di chuyển theo một hướng cụ thể, hoặc đạt đến một trạng thái nào đó."},"8897":{"word":"xua đuổi","meaning":"Dùng sức mạnh để buộc ai đó hoặc cái gì đó phải rời khỏi một nơi."},"8898":{"word":"dồn vào","meaning":"Buộc ai đó hoặc cái gì đó vào một không gian hoặc một tình huống nhất định."},"8899":{"word":"thở dốc","meaning":"Thở nhanh và mạnh, thường là do mệt mỏi sau khi vận động nhiều hoặc khi bị bất ngờ."},"8900":{"word":"ập đến","meaning":"Xảy ra một cách đột ngột và dữ dội, thường là về thời tiết hoặc một loạt các sự việc mạnh mẽ."},"8901":{"word":"sự đắm chìm","meaning":"Trạng thái tập trung cao độ, hoàn toàn đắm chìm vào một hoạt động hoặc cảm xúc nào đó, quên đi mọi thứ xung quanh."},"8902":{"word":"vóc dáng","meaning":"Kích thước và hình dạng tổng thể của cơ thể người hoặc động vật."},"8903":{"word":"không vừa ý","meaning":"Có vẻ không hài lòng, không chấp thuận hoặc hơi khó chịu."},"8904":{"word":"nét hấp dẫn","meaning":"Đặc điểm đặc biệt, thú vị làm cho một điều gì đó rất thu hút và dễ chịu khi trải nghiệm."},"8905":{"word":"nghĩa địa","meaning":"Nơi chôn cất thi thể hoặc di hài của người đã khuất dưới lòng đất."},"8906":{"word":"lạ lùng","meaning":"Có một phẩm chất bất thường hoặc đáng ngạc nhiên, khác với những gì mong đợi."},"8907":{"word":"không ô nhiễm","meaning":"Không chứa bất kỳ chất độc hại hoặc tạp chất nào, đảm bảo sạch sẽ và an toàn."},"8908":{"word":"vô tận","meaning":"Rất nhiều hoặc rộng lớn đến mức dường như không có giới hạn và không bao giờ cạn kiệt."},"8909":{"word":"sự uể oải","meaning":"Trạng thái thiếu năng lượng, thiếu nhiệt huyết, không có động lực và không quan tâm đến hoạt động."},"8910":{"word":"đống","meaning":"Một tập hợp lớn, lộn xộn các vật thể hoặc vật liệu được chất lên nhau."},"8911":{"word":"đáng kể","meaning":"Ở một mức độ đáng chú ý hoặc đáng kể, thường cho thấy một lượng lớn nỗ lực hoặc thay đổi."},"8912":{"word":"nhanh chóng","meaning":"Mô tả một sinh vật, như trẻ em hoặc thực vật, đang phát triển nhanh chóng và lớn lên một cách khỏe mạnh."},"8913":{"word":"vũ lực","meaning":"Sức mạnh, vũ khí và nhân sự được một quân đội hoặc quốc gia sử dụng để phòng thủ hoặc chiến đấu."},"8914":{"word":"sự thô lỗ","meaning":"Hành vi hoặc lời nói thể hiện sự thiếu tôn trọng hoặc thiếu cân nhắc đối với người khác, thường gây xúc phạm."},"8915":{"word":"buồn chán","meaning":"Cảm thấy không có gì thú vị để làm, khiến thời gian trôi qua rất chậm chạp."},"8916":{"word":"mềm, nhão","meaning":"Chỉ vật gì dễ biến dạng, nhũn ra khi chạm vào, ấn hoặc cắt."},"8917":{"word":"chín muồi","meaning":"Trái cây hoặc cây trồng đã phát triển đầy đủ màu sắc, hương vị và kết cấu, sẵn sàng để ăn hoặc thu hoạch."},"8918":{"word":"bất chấp, liều mình","meaning":"Thực hiện một việc gì đó hoặc đi đến một nơi nào đó dù biết rằng có thể gặp khó khăn, nguy hiểm hoặc tổn hại."},"8919":{"word":"nhóm, đàn","meaning":"Một tập hợp nhiều người hoặc động vật di chuyển gần nhau hoặc xuất hiện dưới dạng một nhóm lớn."},"8920":{"word":"liều lĩnh, thiếu suy nghĩ","meaning":"Chỉ hành động hoặc người thực hiện mà không cân nhắc kỹ lưỡng những nguy hiểm hoặc kết quả tiêu cực có thể xảy ra."},"8921":{"word":"sống lâu không bệnh tật","meaning":"Cuộc sống kéo dài nhiều năm mà không mắc bệnh tật hoặc sức khỏe kém."},"8922":{"word":"um tùm, rậm rạp","meaning":"Chỉ cây cối hoặc thảm thực vật mọc rất dày đặc và phong phú, bao phủ một khu vực rộng lớn."},"8923":{"word":"vô số, vô kể","meaning":"Chỉ một số lượng lớn đến mức không thể xác định hoặc nêu ra tổng số chính xác."},"8924":{"word":"vô số, vô kể","meaning":"Trạng từ diễn tả việc gì đó xảy ra hoặc tồn tại với số lượng lớn đến mức không thể đong đếm chính xác."},"8925":{"word":"thờ ơ, vô tâm","meaning":"Trạng từ mô tả hành động được thực hiện mà không có sự tập trung hoặc cảm xúc mạnh mẽ, như thể tâm trí đang ở nơi khác."},"8926":{"word":"im lặng, không lời","meaning":"Tình trạng không có âm thanh hoặc lời nói nào được nghe thấy."},"8927":{"word":"vật vô dụng","meaning":"Một vật không có bất kỳ mục đích hoặc chức năng thực tế nào cả."},"8928":{"word":"không có kế hoạch","meaning":"Hành động mà không có suy nghĩ, chuẩn bị hay chiến lược cụ thể từ trước."},"8929":{"word":"không phân biệt","meaning":"Một hành động hoặc quyết định không phân biệt đối xử, áp dụng cho mọi người hoặc mọi thứ như nhau mà không chọn lọc."},"8930":{"word":"vô hạn","meaning":"Tả thứ gì đó tiếp diễn mãi mãi mà không có điểm dừng hoặc giới hạn."},"8931":{"word":"vô hình","meaning":"Tả thứ gì đó không thể chạm, giữ hoặc nhìn thấy bằng mắt thường."},"8932":{"word":"mặc niệm","meaning":"Mọi người đứng im lặng và không nói trong một thời gian ngắn, thường cúi đầu, để tưởng nhớ hoặc tôn vinh ai đó."},"8933":{"word":"nặng trịch","meaning":"Tả một vật có khối lượng lớn, cần nhiều sức để nâng hoặc giữ."},"8934":{"word":"ủ","meaning":"Cố ý cất giữ và không sử dụng hoặc tiêu thụ thứ gì đó trong một thời gian dài để nó phát triển những đặc tính cụ thể."},"8935":{"word":"ban xã hội","meaning":"Một lĩnh vực học thuật tập trung vào văn hóa, lịch sử, ngôn ngữ và ý tưởng triết học của con người, thường thấy ở các trường đại học."},"8936":{"word":"giới văn học","meaning":"Cộng đồng xã hội của những người viết, xuất bản và phê bình sách, thơ ca và các tác phẩm sáng tạo khác."},"8937":{"word":"viếng tang","meaning":"Hành động đến đám tang hoặc nhà tang quyến để an ủi và bày tỏ lòng kính trọng đối với người đã khuất."},"8938":{"word":"lời chào hỏi","meaning":"Một tập hợp các từ hoặc hành động lịch sự được trao đổi với ai đó để công nhận sự hiện diện của họ hoặc để hỏi thăm sức khỏe hoặc tình hình hiện tại."},"8939":{"word":"chà xát","meaning":"Dùng tay hoặc vật gì đó cọ đi cọ lại nhiều lần trên một bề mặt."},"8940":{"word":"mang tính văn học","meaning":"Có liên quan đến nghệ thuật viết và nghiên cứu các tác phẩm sáng tạo như sách, thơ, kịch."},"8941":{"word":"tài liệu","meaning":"Tập hợp các tài liệu in ấn hoặc kỹ thuật số, như sách, bài báo hoặc giấy tờ lịch sử, dùng để nghiên cứu hoặc cung cấp thông tin."},"8942":{"word":"ngây người","meaning":"Mô tả cách một người nhìn vào cái gì đó trong thời gian dài với vẻ mặt bất động, không biểu lộ nhiều cảm xúc hay suy nghĩ."},"8943":{"word":"nhuộm","meaning":"Thay đổi màu sắc tự nhiên của một vật thể, như vải hoặc tóc, bằng cách ngâm trong chất lỏng hoặc thoa một chất lên."},"8944":{"word":"rút lui","meaning":"Di chuyển lùi lại hoặc rời khỏi một vị trí, một nhóm hoặc một cuộc đối đầu."},"8945":{"word":"trả lại","meaning":"Giao lại một món hàng đã mua cho người bán và nhận lại số tiền đã trả cho nó."},"8946":{"word":"vật lý","meaning":"Liên quan đến thế giới tự nhiên và những thứ có thể nhìn thấy, chạm vào hoặc đo lường được, như sự thay đổi về hình dạng hoặc vị trí."},"8947":{"word":"vật tư","meaning":"Các mặt hàng và vật liệu được chuẩn bị sẵn hoặc cung cấp cho mọi người sử dụng, chẳng hạn như thực phẩm, công cụ hoặc quần áo."},"8948":{"word":"vật thể","meaning":"Một vật không sống có hình dạng xác định và có thể nhìn thấy hoặc chạm vào."},"8949":{"word":"vị giác","meaning":"Khả năng của con người để nhận biết và phân biệt các hương vị khác nhau trong thức ăn hoặc đồ uống bằng lưỡi."},"8950":{"word":"người đàn ông đẹp trai","meaning":"Một người đàn ông có khuôn mặt và ngoại hình được coi là rất hấp dẫn và đẹp."},"8951":{"word":"sự thiếu hụt, không đạt đủ","meaning":"Tình trạng số lượng thực tế thấp hơn so với yêu cầu, kế hoạch hoặc mong muốn."},"8952":{"word":"đức tính tốt, đức hạnh","meaning":"Phẩm chất tốt đẹp hoặc cách hành xử thể hiện chuẩn mực đạo đức cao và được mọi người tôn trọng."},"8953":{"word":"tinh tế, tế nhị, khó nhận ra","meaning":"Mô tả một điều gì đó quá nhỏ, quá mờ nhạt đến mức khó nhìn, nghe, cảm nhận hoặc mô tả rõ ràng."},"8954":{"word":"lễ Misa, lễ Mi-sa","meaning":"Nghi thức và lễ bái công cộng được cử hành trong Giáo hội Công giáo, thường do linh mục chủ trì."},"8955":{"word":"chưa thành thục, non nớt, thiếu kinh nghiệm","meaning":"Mô tả người thiếu huấn luyện hoặc kinh nghiệm để làm tốt việc gì đó, hoặc người trẻ tuổi vẫn còn hành xử như trẻ con."},"8956":{"word":"nghệ sĩ (tạo hình), họa sĩ","meaning":"Người tạo ra các tác phẩm nghệ thuật thị giác đẹp như tranh vẽ, bản vẽ, điêu khắc hoặc các tác phẩm sáng tạo khác."},"8957":{"word":"yếu ớt, mờ nhạt, nhỏ bé","meaning":"Mô tả một điều gì đó rất nhỏ, yếu ớt hoặc có rất ít sức mạnh, khó nhận ra."},"8958":{"word":"nứt ra, rách toạc, vỡ tung","meaning":"Mô tả khi một vật gì đó như túi xách hoặc quần áo bị kéo căng quá mức, sau đó nứt hoặc rách toạc ra do quá đầy hoặc chịu áp lực lớn."},"8959":{"word":"chưa định, chưa quyết định","meaning":"Mô tả một lựa chọn, kế hoạch hoặc ngày tháng chưa được đưa ra hoặc hoàn tất, khiến kết quả của nó vẫn chưa được biết."},"8960":{"word":"điều chưa biết, sự chưa biết","meaning":"Chỉ một nơi, tình huống hoặc sự thật mà chưa ai từng tìm hiểu, khám phá hoặc hiểu rõ trước đây."},"8961":{"word":"mẹ đơn thân, mẹ chưa kết hôn","meaning":"Người phụ nữ tự mình nuôi dưỡng một đứa con sinh ra ngoài giá thú."},"8962":{"word":"chưa đủ, thiếu sót, chưa đạt yêu cầu","meaning":"Khi một điều gì đó quá ít hoặc quá yếu để đạt được điều cần thiết."},"8963":{"word":"tư nhân","meaning":"Phần của xã hội hoặc kinh doanh không do chính phủ kiểm soát."},"8964":{"word":"tổ chức phi chính phủ","meaning":"Một nhóm người hoạt động vì mục tiêu chung nhưng không thuộc sự quản lý của chính phủ."},"8965":{"word":"xấu hổ, ngượng ngùng","meaning":"Cảm thấy rất khó chịu hoặc xấu hổ khi ở trong một tình huống nào đó."},"8966":{"word":"chủ nghĩa dân tộc","meaning":"Tư tưởng tự hào mạnh mẽ về đất nước mình và tin rằng nó tốt hơn các quốc gia khác."},"8967":{"word":"dân chủ","meaning":"Hệ thống chính phủ mà người dân bầu cử lãnh đạo và mọi người đều có quyền bình đẳng."},"8968":{"word":"mang tính dân chủ","meaning":"Mô tả cách làm việc mọi người đều được lắng nghe và quyết định được đưa ra một cách công bằng."},"8969":{"word":"dân chủ hóa","meaning":"Quá trình một quốc gia hoặc hệ thống trở nên có nhiều tự do hơn và người dân có thể bầu cử lãnh đạo."},"8970":{"word":"nhanh nhẹn, lanh lẹ","meaning":"Di chuyển cơ thể rất nhanh chóng và dễ dàng, có thể thay đổi hướng mà không gặp khó khăn."},"8971":{"word":"mật độ","meaning":"Sự đo lường mức độ vật chất được gói gọn trong một không gian nhất định."},"8972":{"word":"bị đẩy ra","meaning":"Bị buộc phải di chuyển lùi hoặc rời khỏi một vị trí nào đó bởi người hoặc vật khác."},"8973":{"word":"ùa vào, tràn vào","meaning":"Nhiều người hoặc nhiều thứ cùng lúc di chuyển vào một nơi một cách nhanh chóng."},"8974":{"word":"rừng rậm, rừng nhiệt đới","meaning":"Một khu rừng dày đặc, hoang dã ở các vùng ấm áp, ẩm ướt, nơi cây cối mọc rất sát nhau và cao lớn."},"8975":{"word":"đẩy tới, dồn ép","meaning":"Dùng sức đẩy mạnh hoặc ép buộc ai/cái gì đó tiến lên hoặc di chuyển vào một vị trí nhất định."},"8976":{"word":"ủng hộ, hỗ trợ","meaning":"Giúp đỡ, hỗ trợ ai đó hoặc điều gì đó để họ có thể thành công hoặc đạt được một vị trí."},"8977":{"word":"gần gũi, sát","meaning":"Tình trạng hai hoặc nhiều vật thể ở rất gần nhau, hầu như không có khoảng cách."},"8978":{"word":"bám sát, áp sát","meaning":"Tình trạng một vật dính chặt vào bề mặt của vật khác mà không có khoảng trống hay khe hở."},"8979":{"word":"phân bón lót, nền tảng","meaning":"Chất liệu bón vào đất giúp cây trồng phát triển hoặc là yếu tố cơ bản hỗ trợ sự khởi đầu và phát triển của một kế hoạch lớn hơn."},"8980":{"word":"đế giày","meaning":"Phần phẳng, cứng ở dưới cùng của chiếc giày, tiếp xúc với mặt đất."},"8981":{"word":"phai màu","meaning":"Màu sắc trên vật thể dần mất đi độ sáng hoặc cường độ, trở nên nhạt hơn theo thời gian."},"8982":{"word":"bận rộn, vội vã","meaning":"Thực hiện nhiều việc hoặc di chuyển nhanh chóng, thường trong tình trạng khẩn cấp và ít thời gian nghỉ ngơi."},"8983":{"word":"khô cong","meaning":"Trở nên hoàn toàn khô ráo, không còn chút độ ẩm nào."},"8984":{"word":"con gián","meaning":"Một loài côn trùng thân dẹt, màu nâu sẫm, di chuyển nhanh, thường thấy ở những nơi ấm áp, ẩm ướt như nhà bếp."},"8985":{"word":"nhịp điệu, phách","meaning":"Nhịp điệu hoặc mô hình âm thanh lặp đi lặp lại đều đặn trong âm nhạc mà mọi người có thể vỗ tay hoặc dậm chân theo."},"8986":{"word":"tước đoạt, thu hồi","meaning":"Hành động tước bỏ một quyền, danh hiệu hoặc tài sản quan trọng khỏi một người hoặc một nhóm một cách cưỡng bức."},"8987":{"word":"ác cảm","meaning":"Cảm giác không thích hoặc chống đối mạnh mẽ đối với ai đó hay một ý tưởng."},"8988":{"word":"nửa ngày","meaning":"Khoảng thời gian bằng một nửa của một ngày, tức là buổi sáng hoặc buổi chiều."},"8989":{"word":"bán đảo","meaning":"Vùng đất ba mặt giáp biển, một mặt còn lại nối liền với đất liền."},"8990":{"word":"chất bán dẫn","meaning":"Vật liệu hoặc linh kiện điện tử có khả năng kiểm soát dòng điện, dùng để chế tạo chip."},"8991":{"word":"phản biện","meaning":"Lý lẽ hoặc lập luận đưa ra để bác bỏ một quan điểm hoặc tuyên bố trước đó."},"8992":{"word":"hiềm khích","meaning":"Tình trạng bất hòa, tranh cãi kéo dài giữa những người, gây ra mối quan hệ xấu."},"8993":{"word":"hỏi lại","meaning":"Việc đặt câu hỏi ngược lại cho người vừa hỏi mình."},"8994":{"word":"nửa thế kỷ","meaning":"Khoảng thời gian kéo dài chính xác năm mươi năm."},"8995":{"word":"tắm ngâm nửa người","meaning":"Hình thức tắm bằng cách ngâm phần thân dưới rốn vào nước ấm."},"8996":{"word":"nhạc đệm","meaning":"Âm nhạc được chơi để hỗ trợ giai điệu chính hoặc người biểu diễn."},"8997":{"word":"phạm luật","meaning":"Hành động vi phạm quy tắc trong thể thao hoặc trò chơi, dẫn đến bị phạt."},"8998":{"word":"tôn kính","meaning":"Coi trọng, kính nể và chăm sóc tận tình một người hoặc một điều gì đó."},"8999":{"word":"bị phát hiện","meaning":"Sự việc giấu kín hoặc bí mật đột nhiên bị người khác biết hoặc nhìn thấy."},"9000":{"word":"khai quật","meaning":"Việc đào bới một cách cẩn thận để tìm và lấy ra những đồ vật, kiến trúc hoặc di tích cổ từ lòng đất."},"9001":{"word":"khởi đầu, nguồn gốc","meaning":"Sự kiện hoặc tình huống đầu tiên gây ra một chuỗi sự kiện hoặc quá trình lớn hơn."},"9002":{"word":"nhón chân","meaning":"Hành động đứng trên đầu ngón chân để tăng chiều cao hoặc đi lại nhẹ nhàng."},"9003":{"word":"bổ nhiệm, ban hành","meaning":"Thông báo chính thức từ cơ quan có thẩm quyền về việc ai đó nhận công việc mới, chuyển địa điểm hoặc một văn bản, quy định mới bắt đầu có hiệu lực."},"9004":{"word":"phát bệnh, khởi bệnh","meaning":"Sự bắt đầu đột ngột của một tình trạng sức khỏe cụ thể hoặc vấn đề y tế ở một người hoặc một nhóm."},"9005":{"word":"ý tưởng, tư duy","meaning":"Hành động nảy ra một suy nghĩ hoặc ý tưởng thu được theo cách đó."},"9006":{"word":"kiếm sống","meaning":"Những hành động mà một người thực hiện thường xuyên để có đủ tiền mua thức ăn và các nhu yếu phẩm hàng ngày."},"9007":{"word":"dây thừng","meaning":"Một sợi dây dài, rất chắc và dày, được tạo ra bằng cách xoắn nhiều sợi nhỏ hơn lại với nhau, dùng để buộc hoặc kéo các vật nặng."},"9008":{"word":"đánh rắm, xì hơi","meaning":"Sự thoát khí đột ngột từ ruột ra ngoài qua hậu môn, đôi khi tạo ra tiếng động và thường có mùi đặc trưng."},"9009":{"word":"phòng chống tội phạm","meaning":"Các hành động, hệ thống và biện pháp được thiết lập để ngăn chặn các hoạt động bất hợp pháp hoặc có hại xảy ra trong một khu vực cụ thể."},"9010":{"word":"phóng xạ","meaning":"Một yếu tố phóng xạ như rađi, urani, v.v., phân rã thành các hạt nhỏ và phát ra sóng điện từ có hại cho cơ thể con người."},"9011":{"word":"phòng thủ","meaning":"Hành động chống lại một cuộc tấn công hoặc bảo vệ bản thân/người khác khỏi nguy hiểm."},"9012":{"word":"phương ngữ","meaning":"Một dạng ngôn ngữ đặc trưng được sử dụng bởi người dân ở một khu vực nhất định, khác với ngôn ngữ chuẩn."},"9013":{"word":"bỏ mặc","meaning":"Hành động để một người hay một vật không được chăm sóc, khiến nó ở trong tình trạng không mong muốn."},"9014":{"word":"phương châm","meaning":"Một tập hợp các nguyên tắc hoặc quy tắc rõ ràng được thiết lập để định hướng hành động hoặc đưa ra quyết định."},"9015":{"word":"khiên","meaning":"Một vật dụng thường bằng phẳng, được cầm tay hoặc đeo vào tay để bảo vệ cơ thể khỏi bị tấn công."},"9016":{"word":"bồi thường","meaning":"Việc đền bù cho một mất mát, tổn thương hoặc thiệt hại mà ai đó đã phải chịu, thường bằng tiền."},"9017":{"word":"bài tiết","meaning":"Quá trình các sinh vật sống loại bỏ chất thải và các chất dư thừa ra khỏi cơ thể."},"9018":{"word":"phản bội","meaning":"Hành động không trung thành, phá vỡ lòng tin hoặc chống lại bạn bè, đồng minh hay lời hứa."},"9019":{"word":"vai diễn","meaning":"Nhân vật mà một diễn viên đảm nhận trong vở kịch, phim hoặc chương trình truyền hình."},"9020":{"word":"loại trừ","meaning":"Hành động giữ một người hoặc một vật ra khỏi một nhóm, hoạt động hoặc sự cân nhắc."},"9021":{"word":"sản sinh","meaning":"Hành động tạo ra hoặc gửi ra một số lượng lớn người có kỹ năng hoặc vật chất (như khói, khí) từ một nguồn nào đó."},"9022":{"word":"độc quyền","meaning":"Miêu tả một cái gì đó hoặc ai đó giữ người khác ở ngoài, chỉ cho phép một số người hoặc vật nhất định tham gia."},"9023":{"word":"Sự phân phát","meaning":"Hành động phát tán, gửi đi các vật phẩm như sách, tờ rơi, hàng hóa đến nhiều người hoặc nhiều nơi."},"9024":{"word":"Sự lang thang","meaning":"Hành động đi lại chậm rãi, không có mục đích hay đích đến rõ ràng, thường là ở một khu vực nhất định."},"9025":{"word":"Hậu trường","meaning":"Mặt sau của một sự vật, một nhóm người, hoặc dùng để chỉ lực lượng ẩn sau một sự việc nào đó."},"9026":{"word":"Bách niên giai lão","meaning":"Vợ chồng sống bên nhau hạnh phúc, hòa thuận cho đến già."},"9027":{"word":"Điểm nhấn","meaning":"Phần xuất sắc nhất, thú vị nhất của một sự kiện, trải nghiệm hay bộ sưu tập, nổi bật hơn tất cả những phần khác."},"9028":{"word":"Người thất nghiệp","meaning":"Người không có việc làm, sống dựa vào tiền tiết kiệm hoặc trợ cấp."},"9029":{"word":"Giấy trắng","meaning":"Một tờ giấy có màu trắng, chưa được viết hoặc in gì lên đó."},"9030":{"word":"Bệnh bạch cầu","meaning":"Một căn bệnh nặng khi cơ thể sản xuất quá nhiều tế bào bạch cầu bất thường trong máu, gây suy yếu và dễ mắc bệnh."},"9031":{"word":"Sự thịnh vượng","meaning":"Tình trạng một nhóm người, động vật hoặc thực vật phát triển đông đảo và mạnh mẽ, thể hiện sự thành công và sung túc lớn."},"9032":{"word":"Sự sinh sản","meaning":"Quá trình các sinh vật sống tạo ra nhiều cá thể cùng loại, làm tăng số lượng của chúng."},"9033":{"word":"Sự phồn vinh","meaning":"Tình trạng một quốc gia hoặc cộng đồng có sự giàu có, thành công lớn và mức sống cao, với những dấu hiệu rõ rệt của sự phát triển và sung túc."},"9034":{"word":"Loáng một cái","meaning":"Từ dùng để diễn tả sự việc xảy ra hoặc xuất hiện rất nhanh, thường kèm theo ánh sáng chớp nhoáng hoặc chuyển động mau lẹ."},"9035":{"word":"sự thịnh vượng","meaning":"Trạng thái công việc kinh doanh hoặc tổ chức phát triển mạnh mẽ và thành công, tạo ra nhiều tiền."},"9036":{"word":"đồng bằng","meaning":"Một vùng đất rộng lớn, bằng phẳng, thường là đất trống hoặc có cây cỏ, ít cây cối hay đồi núi."},"9037":{"word":"phạm trù","meaning":"Một nhóm hoặc loại các sự vật, hiện tượng có chung những đặc điểm nhất định."},"9038":{"word":"vi phạm","meaning":"Thực hiện một hành động đi ngược lại quy tắc, luật pháp hoặc đạo đức, gây ra lỗi lầm."},"9039":{"word":"hành vi phạm tội","meaning":"Hành động trái pháp luật do một người thực hiện, có thể bị trừng phạt nghiêm khắc."},"9040":{"word":"luật sư","meaning":"Người có kiến thức sâu rộng về luật pháp và làm việc trong lĩnh vực liên quan đến luật pháp."},"9041":{"word":"dự luật","meaning":"Một đề xuất chính thức bằng văn bản về một quy định hoặc luật mới, được trình lên cơ quan lập pháp để thảo luận và bỏ phiếu."},"9042":{"word":"tòa án","meaning":"Nơi diễn ra các phiên xét xử pháp lý, nơi thẩm phán lắng nghe các vụ án và các bên trình bày bằng chứng."},"9043":{"word":"bạn bè","meaning":"Người mà bạn thích dành thời gian cùng, tin tưởng và chia sẻ mọi điều."},"9044":{"word":"dự án mạo hiểm","meaning":"Một dự án kinh doanh mới hoặc khởi nghiệp có rủi ro cao nhưng cũng có tiềm năng thành công lớn."},"9045":{"word":"nung nấu (ý định)","meaning":"Chuẩn bị tinh thần hoặc thể chất cho một hành động sẽ xảy ra sau này, thường với quyết tâm mạnh mẽ."},"9046":{"word":"bích họa","meaning":"Một bức tranh lớn được vẽ trực tiếp lên tường hoặc trần nhà."},"9047":{"word":"bờ","meaning":"Phần đất nằm dọc theo mép một vùng nước lớn như sông, hồ."},"9048":{"word":"sự thất thường","meaning":"Sự thay đổi bất ngờ và không giải thích được trong tâm trạng hoặc hành động của một người."},"9049":{"word":"ngoại ô","meaning":"Khu vực bên ngoài của một thị trấn hoặc thành phố, nằm xa trung tâm của nó."},"9050":{"word":"sự biến đổi","meaning":"Sự thay đổi hoàn toàn về diện mạo, bản chất hoặc đặc điểm của một cái gì đó theo thời gian."},"9051":{"word":"kém chất lượng","meaning":"Diễn tả một cái gì đó có chất lượng không tốt, không đủ dùng hoặc trông cũ kỹ, sờn rách."},"9052":{"word":"biến số","meaning":"Một yếu tố trong một tình huống không cố định và có thể mang các trạng thái hoặc giá trị khác nhau, ảnh hưởng rõ rệt đến kết quả."},"9053":{"word":"sự biến chuyển","meaning":"Quá trình một cái gì đó dần dần phát triển hoặc thay đổi từ trạng thái hoặc hình thức này sang trạng thái hoặc hình thức khác trong một khoảng thời gian."},"9054":{"word":"sự biến dạng","meaning":"Sự thay đổi về hình dạng, cấu trúc hoặc vẻ ngoài của một vật thể, thường là so với hình dạng ban đầu của nó."},"9055":{"word":"sự biện hộ","meaning":"Hành động nói để hỗ trợ một người bị buộc tội hoặc sai phạm trong một thủ tục pháp lý."},"9056":{"word":"sự thay đổi khôn lường","meaning":"Diễn tả một cái gì đó liên tục thay đổi vẻ ngoài, bản chất hoặc trạng thái của nó từ lúc này sang lúc khác hoặc theo thời gian."},"9057":{"word":"sự riêng biệt","meaning":"Một cái gì đó khác biệt và không liên quan đến một cái khác, được xem xét một mình mà không có sự kết nối."},"9058":{"word":"khoảnh khắc bất ngờ","meaning":"Một khoảnh khắc ngắn ngủi, bất ngờ mà không thể dự đoán trước."},"9059":{"word":"tất tần tật","meaning":"Diễn tả nhiều loại sự vật, sự việc khác nhau, thường là những thứ lạ lùng, bất ngờ."},"9060":{"word":"khu điều trị","meaning":"Một bộ phận trong bệnh viện được phân chia theo loại bệnh hoặc giới tính của bệnh nhân."},"9061":{"word":"giường bệnh","meaning":"Giường dành cho người ốm nằm nghỉ ngơi và hồi phục sức khỏe, thường là ở bệnh viện hoặc ở nhà."},"9062":{"word":"bệnh tình","meaning":"Trạng thái sức khỏe của bệnh nhân, thể hiện dấu hiệu bệnh đang thuyên giảm hay nặng hơn."},"9063":{"word":"có tính bệnh lý","meaning":"Chỉ một hành vi hoặc trạng thái tinh thần cực đoan hoặc không lành mạnh, giống như một căn bệnh thể chất."},"9064":{"word":"thực hiện song song","meaning":"Hành động thực hiện hai hoạt động hoặc nhiệm vụ khác nhau cùng một lúc, thường là phát triển hoặc tiến triển bên cạnh nhau."},"9065":{"word":"y tế công cộng","meaning":"Các hoạt động và điều kiện liên quan đến việc giữ gìn sức khỏe, vệ sinh để phòng ngừa bệnh tật và tăng cường thể chất."},"9066":{"word":"đền đáp","meaning":"Hành động trả ơn ai đó vì những ân huệ của họ bằng lòng biết ơn."},"9067":{"word":"tạm hoãn","meaning":"Hành động quyết định giải quyết một việc gì đó sau, hoặc trì hoãn một hành động hay quyết định trong một khoảng thời gian."},"9068":{"word":"báu vật","meaning":"Vật phẩm rất có giá trị hoặc quý giá, hoặc người được coi là cực kỳ quan trọng và yêu quý."},"9069":{"word":"trả thù","meaning":"Hành động gây ra thiệt hại tương đương cho ai đó để trả đũa lại thiệt hại mà mình đã nhận từ họ."},"9070":{"word":"sở hữu","meaning":"Trạng thái có một thứ gì đó thuộc về mình hoặc nằm dưới sự kiểm soát trực tiếp của mình."},"9071":{"word":"trại mồ côi","meaning":"Nơi trẻ em không có cha mẹ hoặc người thân chăm sóc được nuôi dưỡng."},"9072":{"word":"tầm thường","meaning":"Mô tả một vật, sự việc rất nhỏ bé, bình thường, không đặc biệt nên có giá trị hoặc tầm quan trọng rất ít."},"9073":{"word":"tiền trợ cấp","meaning":"Khoản tiền do chính phủ hoặc tổ chức cấp để hỗ trợ một doanh nghiệp hoặc cá nhân chi trả cho một việc gì đó."},"9074":{"word":"bổ sung","meaning":"Đặt thêm cái gì đó vào một lượng đã có hoặc cung cấp thêm tiền, đồ vật để làm cho cái gì đó hoàn chỉnh hoặc tốt hơn."},"9075":{"word":"người giám hộ","meaning":"Người lớn chịu trách nhiệm pháp lý để chăm sóc trẻ em hoặc người không thể tự chăm sóc bản thân, đưa ra quyết định thay mặt họ."},"9076":{"word":"trở lại","meaning":"Hành động quay lại một nơi, vị trí hoặc trạng thái trước đó sau khi đã rời đi hoặc ở một trạng thái khác."},"9077":{"word":"phúc lợi","meaning":"Tình trạng khỏe mạnh, thoải mái và hạnh phúc, thường dùng để chỉ điều kiện sống tốt đẹp chung của một nhóm người hoặc xã hội."},"9078":{"word":"bụng","meaning":"Phần phía trước của cơ thể người nằm giữa ngực và hông."},"9079":{"word":"nhiều","meaning":"Mô tả cái gì đó bao gồm hơn một mục, số lượng hoặc trường hợp, chứ không phải chỉ một."},"9080":{"word":"trang phục","meaning":"Cách ăn mặc, bề ngoài của một người khi đã mặc quần áo."},"9081":{"word":"sao chép","meaning":"Quá trình tạo ra một thứ giống hệt bản gốc, hoặc một thứ được tạo ra bằng cách đó."},"9082":{"word":"sự vâng lời","meaning":"Tình trạng một người hoặc động vật hành động đúng như được hướng dẫn, tuân theo mọi mệnh lệnh hoặc quy tắc."},"9083":{"word":"phức tạp","meaning":"Diễn tả một sự vật, hiện tượng được tạo thành từ nhiều yếu tố khác nhau hoặc có nhiều khía cạnh đan xen."},"9084":{"word":"sự khởi động mạnh mẽ","meaning":"Việc một quá trình hoặc hoạt động bắt đầu diễn ra một cách mạnh mẽ, nhanh chóng và rõ ràng."},"9085":{"word":"bản chất","meaning":"Tính cách hoặc tinh thần cơ bản của một người hoặc sự vật, được thể hiện qua hành động hoặc cách họ tồn tại."},"9086":{"word":"vốn gốc","meaning":"Số tiền ban đầu đã được đầu tư hoặc chi tiêu cho một việc gì đó, chưa tính lãi hay lỗ."},"9087":{"word":"đỉnh núi","meaning":"Phần cao nhất của một ngọn núi."},"9088":{"word":"bỏ qua","meaning":"Quyết định không trừng phạt ai đó vì một lỗi lầm hoặc đối xử với họ nhẹ nhàng hơn bình thường."},"9089":{"word":"sự bổ sung","meaning":"Hành động thêm một cái gì đó vào một món đồ hoặc nhóm đã có sẵn, làm cho nó lớn hơn hoặc cung cấp một tính năng mới."},"9090":{"word":"sự làm nổi bật","meaning":"Hành động làm cho một cái gì đó trở nên rõ ràng hoặc nhấn mạnh nó để nó nổi bật và thu hút sự chú ý."},"9091":{"word":"cáo phó","meaning":"Thông báo bằng văn bản, thường được đăng trên báo, về việc một người qua đời và đôi khi bao gồm thông tin về cuộc đời họ."},"9092":{"word":"đụng phải","meaning":"Chạm mạnh vào cái gì đó một cách vật lý hoặc đột ngột gặp phải một tình huống hay vấn đề khó khăn."},"9093":{"word":"không công bằng","meaning":"Diễn tả một tình huống hoặc hành động không công bằng hoặc không đúng, thường khiến ai đó cảm thấy bị đối xử sai."},"9094":{"word":"phá sản","meaning":"Tình trạng một công ty hoặc cá nhân không thể thanh toán các nghĩa vụ tài chính của mình, thường dẫn đến việc phân chia tài sản còn lại theo luật pháp."},"9095":{"word":"phá sản","meaning":"Một công ty hoặc cá nhân không thể thanh toán các khoản nợ của mình và phải ngừng hoạt động."},"9096":{"word":"bất đắc dĩ","meaning":"Phải làm một điều gì đó vì không còn sự lựa chọn nào khác."},"9097":{"word":"xin vui lòng","meaning":"Dùng để bày tỏ một lời thỉnh cầu hoặc mong muốn mạnh mẽ và chân thành."},"9098":{"word":"kêu lên","meaning":"Phát ra tiếng kêu hoặc tiếng nói rất to, thường là với cảm xúc mạnh mẽ."},"9099":{"word":"sai khiến","meaning":"Yêu cầu người khác thực hiện nhiều công việc, thường là những công việc khó khăn hoặc mệt mỏi."},"9100":{"word":"trực thuộc","meaning":"Chỉ một tổ chức, cơ sở hoặc bộ phận nhỏ hơn được gắn kết hoặc liên kết hoạt động với một tổ chức chính lớn hơn."},"9101":{"word":"yếu kém","meaning":"Tình trạng yếu ớt, không ổn định hoặc không đủ khỏe mạnh để chống đỡ hay hoạt động tốt."},"9102":{"word":"nuôi dưỡng","meaning":"Hành động cung cấp tiền bạc, thức ăn và nơi ở cho các thành viên gia đình không thể tự lo liệu được."},"9103":{"word":"đáp ứng","meaning":"Việc đạt được kết quả hoặc thể hiện hiệu suất đúng như những gì người khác đã mong đợi hoặc hy vọng."},"9104":{"word":"nhậm chức","meaning":"Hành động đến một địa điểm mới để chính thức bắt đầu làm việc ở một vị trí hoặc chức vụ mới."},"9105":{"word":"vắng mặt","meaning":"Tình trạng một người hoặc một thứ gì đó không có mặt ở một nơi cụ thể hoặc không tồn tại như mong đợi."},"9106":{"word":"trì trệ","meaning":"Tình trạng động lực hoặc sức mạnh để thúc đẩy một việc gì đó phát triển theo hướng tốt không được hoạt động tích cực."},"9107":{"word":"gắn","meaning":"Hành động gắn một vật vào một bề mặt hoặc đối tượng khác."},"9108":{"word":"khơi gợi","meaning":"Nói hoặc làm gì đó để khuyến khích hoặc thúc đẩy người khác làm một việc gì đó."},"9109":{"word":"dìu đỡ","meaning":"Hành động một người đỡ tay hoặc thân người khác để giúp họ đi lại hoặc đứng vững khi yếu."},"9110":{"word":"thối rữa","meaning":"Quá trình vật chất hữu cơ như thức ăn bị phân hủy, thay đổi hình dạng, mùi và trở nên không dùng được."},"9111":{"word":"làm phồng","meaning":"Làm cho một vật gì đó trở nên lớn hơn, phồng hơn."},"9112":{"word":"thể tích","meaning":"Lượng không gian ba chiều mà một vật hoặc chất chiếm giữ."},"9113":{"word":"hồi sinh","meaning":"Hành động một cái gì đó được cho là đã mất, chết hoặc không hoạt động trở lại tồn tại hoặc trở nên hoạt động."},"9114":{"word":"khích lệ","meaning":"Nói hoặc làm điều gì đó để khiến ai đó cảm thấy dũng cảm, hy vọng hoặc tự tin hơn."},"9115":{"word":"khích lệ","meaning":"Nói hoặc làm gì đó để khiến người khác cảm thấy mạnh mẽ hơn về tinh thần hoặc sẵn sàng hành động hơn."},"9116":{"word":"dâng trào","meaning":"Khi một cảm xúc mạnh mẽ như buồn bã hoặc tức giận đột ngột tràn ngập cơ thể và tâm trí."},"9117":{"word":"tấp nập","meaning":"Có nhiều người tụ tập ở một nơi và nói chuyện ồn ào, lộn xộn."},"9118":{"word":"phân biệt","meaning":"Khả năng nhìn hoặc hiểu sự khác biệt giữa hai hoặc nhiều sự vật, đặc biệt là để chọn cái đúng hoặc sai."},"9119":{"word":"quý","meaning":"Khoảng thời gian ba tháng, là một trong bốn phần của một năm."},"9120":{"word":"phân công, chia sẻ","meaning":"Việc cùng nhau chia sẻ, gánh vác một phần công việc hay trách nhiệm."},"9121":{"word":"phân phối, phân chia","meaning":"Hành động chia đều hoặc cấp phát các vật phẩm, tiền bạc cho nhiều người hoặc rải ra nhiều nơi."},"9122":{"word":"phân biệt, nhận định","meaning":"Khả năng suy nghĩ rõ ràng để nhận biết, phân biệt điều đúng sai, tốt xấu."},"9123":{"word":"nhiều ý kiến trái chiều, xôn xao","meaning":"Khi nhiều ý kiến hoặc quan điểm khác nhau được bày tỏ về một vấn đề, thể hiện sự bất đồng."},"9124":{"word":"phân tán","meaning":"Quá trình di chuyển vật hoặc người ra xa một điểm trung tâm và lan rộng ra một khu vực rộng hơn."},"9125":{"word":"chia rẽ, phân chia","meaning":"Tình trạng một nhóm người hoặc một thể thống nhất bị chia tách thành các phần riêng biệt, thường là đối lập."},"9126":{"word":"sữa bột","meaning":"Một loại thực phẩm khô màu trắng làm từ sữa lỏng, dùng để pha với nước cho trẻ sơ sinh uống."},"9127":{"word":"tranh chấp, xung đột","meaning":"Một sự bất đồng hoặc tranh cãi nghiêm trọng giữa hai hoặc nhiều người/nhóm, thường kéo dài."},"9128":{"word":"phun trào, bùng phát","meaning":"Sự giải phóng đột ngột và mạnh mẽ của thứ gì đó, ví dụ như khí, khói hay chất lỏng, từ bên trong ra bên ngoài."},"9129":{"word":"bực bội, tức tối","meaning":"Cảm thấy rất tức giận và thất vọng vì một thất bại, một mất mát hoặc một tình huống không công bằng."},"9130":{"word":"phân hủy, tháo rời","meaning":"Khi một chất hoặc vật thể tách rời thành nhiều mảnh hoặc yếu tố nhỏ hơn, đơn giản hơn."},"9131":{"word":"kinh Phật","meaning":"Những văn bản ghi lại các nguyên lý và giáo lý cơ bản của đạo Phật."},"9132":{"word":"chỉ","meaning":"Từ dùng để chỉ một số lượng hoặc thời gian rất nhỏ, giới hạn."},"9133":{"word":"gọi đến","meaning":"Phát ra tiếng động hoặc ra lệnh để ai đó đến gần hoặc xuất hiện tại một nơi."},"9134":{"word":"không rõ","meaning":"Tình trạng sự thật hoặc nguyên nhân về một việc nào đó bị che giấu hoặc không có, khiến không thể nhận diện hay xác định."},"9135":{"word":"đất hoang","meaning":"Vùng đất khô cằn và bạc màu, nơi cây cối không thể sống được."},"9136":{"word":"không rõ ràng","meaning":"Có chi tiết hoặc thông tin không rõ ràng, khiến khó hiểu hoặc nhìn thấy một cách chính xác."},"9137":{"word":"đột ngột","meaning":"Từ diễn tả hành động hoặc sự việc xảy ra rất nhanh và bất ngờ, không có báo trước."},"9138":{"word":"sự bất ổn","meaning":"Trạng thái mà một cái gì đó không vững chắc, ổn định hoặc cân bằng, dễ thay đổi vị trí hoặc sụp đổ."},"9139":{"word":"truyền vào","meaning":"Khiến một cảm giác hoặc phẩm chất cụ thể đi vào và trở thành một phần của điều gì đó."},"9140":{"word":"sự vắng mặt","meaning":"Hành động không có mặt tại một nơi hoặc sự kiện mà người ta được mong đợi."},"9141":{"word":"sự bất hòa","meaning":"Tình trạng mọi người tranh cãi hoặc bất đồng mạnh mẽ, gây căng thẳng và thiếu quan hệ thân thiện."},"9142":{"word":"suy thoái","meaning":"Giai đoạn khi các doanh nghiệp bán ít hàng, nhiều người mất việc và nền kinh tế chung chậm lại, gây khó khăn tài chính."},"9143":{"word":"con bất hiếu","meaning":"Người con không vâng lời, không hiếu thảo, không chăm sóc cha mẹ mình."},"9144":{"word":"bùng nổ, cơn sốt","meaning":"Sự tăng vọt hoặc phát triển mạnh mẽ đột ngột về một cái gì đó."},"9145":{"word":"bị giữ, bị nắm giữ","meaning":"Bị ai đó nắm lấy hoặc giữ lại, khiến không thể di chuyển hoặc rời đi."},"9146":{"word":"hèn nhát, nhát gan","meaning":"Không có lòng dũng cảm khi đối mặt với nguy hiểm hay thử thách, thường thể hiện qua việc lùi bước hay tránh đối đầu."},"9147":{"word":"hèn hạ, luồn cúi","meaning":"Cư xử một cách quá mức khiêm tốn hoặc nịnh hót để làm hài lòng người có quyền lực hơn."},"9148":{"word":"bi kịch, bi thảm","meaning":"Có tính chất gây ra nỗi buồn sâu sắc, thường liên quan đến tai họa hoặc kết cục không may mắn."},"9149":{"word":"ngang bằng, sánh ngang","meaning":"Có chất lượng hoặc giá trị tương đương với cái khác, có thể so sánh ngang hàng."},"9150":{"word":"không chỉ, chẳng những","meaning":"Dùng để nhấn mạnh rằng một điều gì đó đúng không chỉ với một đối tượng cụ thể mà còn với nhiều đối tượng khác."},"9151":{"word":"tanh, hôi tanh","meaning":"Có mùi khó chịu, nồng gắt, thường giống mùi hải sản sống hoặc thịt ôi."},"9152":{"word":"bí mật, kín đáo","meaning":"Có vẻ giấu giếm, không muốn cho người khác biết thông tin hay sự việc nào đó."},"9153":{"word":"phỉ báng, vu khống","meaning":"Hành vi nói xấu hoặc đưa ra những lời lẽ không đúng sự thật nhằm hạ thấp danh dự, uy tín của người khác."},"9154":{"word":"sự bay lượn, sự cất cánh","meaning":"Hành động di chuyển trong không trung, thường là bay lên cao hoặc bay nhanh lên phía trên như chim."},"9155":{"word":"từ tục tĩu","meaning":"Đây là những từ ngữ thô tục, không lịch sự, không phù hợp để nói trong những tình huống trang trọng hoặc với người đáng kính."},"9156":{"word":"nghiêng, xiên","meaning":"Ở trong tư thế không thẳng đứng hoặc bằng phẳng, mà bị lệch hoặc nghiêng về một phía."},"9157":{"word":"nhảy vọt, vượt bậc","meaning":"Diễn tả sự thay đổi hay phát triển xảy ra rất nhanh chóng và đạt được tiến bộ lớn."},"9158":{"word":"viêm mũi","meaning":"Một tình trạng y tế khiến lớp niêm mạc bên trong mũi bị sưng và kích ứng, gây hắt hơi, sổ mũi và nghẹt mũi."},"9159":{"word":"sự chế nhạo, sự cười nhạo","meaning":"Tiếng cười, biểu cảm khuôn mặt hoặc lời nói bất kính nhằm thể hiện rằng ai đó hoặc điều gì đó bị coi là ngốc nghếch hoặc yếu kém."},"9160":{"word":"khẩu vị, sự thèm ăn","meaning":"Mong muốn hoặc cảm giác muốn ăn một món gì đó."},"9161":{"word":"tầm nhìn","meaning":"Một ý tưởng hoặc hình ảnh rõ ràng trong tâm trí về những gì một người hoặc một tổ chức hy vọng đạt được trong tương lai."},"9162":{"word":"bất thường, dị thường","meaning":"Khác biệt rất nhiều so với những gì thường được mong đợi hoặc nhìn thấy phổ biến, trông hoặc hành động không giống những thứ cùng loại."},"9163":{"word":"thảm khốc, bi thảm, khốn khổ","meaning":"Ở trong trạng thái cực kỳ bất hạnh và đau khổ, thường biểu hiện sự đau buồn hoặc sống trong điều kiện rất khó khăn."},"9164":{"word":"trang thiết bị, vật dụng","meaning":"Những đồ vật như bàn, ghế, máy tính hoặc bút được sử dụng và cất giữ tại nơi làm việc hoặc trong một tòa nhà."},"9165":{"word":"sự coi thường, sự hạ thấp","meaning":"Hành động hoặc lời nói thể hiện rằng một người, một nhóm hoặc một vật có ít giá trị hoặc tầm quan trọng."},"9166":{"word":"sự nghèo đói, đói nghèo","meaning":"Tình trạng một người hoặc một nhóm người có rất ít tiền và thiếu thốn những thứ cơ bản như thức ăn, chỗ ở hay quần áo."},"9167":{"word":"người nghèo","meaning":"Những người sống trong điều kiện thiếu thốn về tiền bạc và nhu yếu phẩm cơ bản như thức ăn, chỗ ở."},"9168":{"word":"giàu nghèo","meaning":"Tình trạng phân chia hoặc đối lập trong xã hội giữa người có nhiều tiền và tài nguyên với người có rất ít."},"9169":{"word":"sự nghèo nàn","meaning":"Tình trạng một cái gì đó, như nội dung hoặc tài nguyên, có rất ít về số lượng, chất lượng hay sức mạnh."},"9170":{"word":"người trắng tay","meaning":"Người không còn tiền bạc hay tài sản đáng giá nào."},"9171":{"word":"kẽ hở","meaning":"Một khoảng trống nhỏ hoặc lỗ hổng được tìm thấy giữa hai vật thể hoặc bề mặt."},"9172":{"word":"tỉ mỉ","meaning":"Mô tả một kế hoạch hay công việc không có lỗi, thiếu sót hay điểm yếu."},"9173":{"word":"một cách tỉ mỉ","meaning":"Theo cách không để lại bất kỳ khoảng trống, sai sót hay điểm chưa được giải quyết nào."},"9174":{"word":"bệnh thiếu máu","meaning":"Một tình trạng y tế khi máu của một người không có đủ hồng cầu khỏe mạnh, khiến họ trông nhợt nhạt và cảm thấy rất mệt mỏi hoặc chóng mặt."},"9175":{"word":"chải tóc cho","meaning":"Dùng lược để chải hoặc làm mượt tóc cho người khác."},"9176":{"word":"dòng mưa","meaning":"Những dòng nước dài, mỏng rơi từ bầu trời trong trận mưa lớn."},"9177":{"word":"tảng băng trôi","meaning":"Một khối băng lớn, rắn chắc nổi trên đại dương, chỉ có một phần nhỏ có thể nhìn thấy được trên mặt nước."},"9178":{"word":"được nặn","meaning":"Được định hình hoặc tạo thành một dạng cụ thể, thường từ nguyên liệu thô như đất sét, thông qua việc xử lý cẩn thận."},"9179":{"word":"chật cứng","meaning":"Nói về tình trạng nhiều thứ được ép sát lại với nhau, gần như không để lại khoảng trống nào."},"9180":{"word":"le lói","meaning":"Trong trạng thái hơi sáng khi ánh sáng chiếu xuyên qua bóng tối."},"9181":{"word":"tẩu tán","meaning":"Lén lút lấy tiền, hàng hóa hoặc thông tin thuộc về một tổ chức và chuyển chúng đến một địa điểm khác, thường là bí mật."},"9182":{"word":"tai nạn bỏ chạy","meaning":"Một vụ tai nạn mà người lái xe gây va chạm rồi bỏ chạy nhanh chóng mà không dừng lại giúp đỡ hoặc xác định danh tính."},"9183":{"word":"vượt mặt","meaning":"Biểu diễn hoặc đạt được điều gì đó một cách khéo léo đến mức trông giỏi ngang hoặc thậm chí tốt hơn một người thường được coi là chuyên gia hoặc người lớn tuổi."},"9184":{"word":"trơ trẽn","meaning":"Hành động hoặc nói mà không thể hiện bất kỳ sự hối tiếc hay tội lỗi nào, ngay cả khi đã rõ ràng làm điều gì đó sai trái hoặc thô lỗ."},"9185":{"word":"rõ ràng","meaning":"Mô tả điều gì đó dễ dàng nhìn thấy, hiểu hoặc biết mà không có bất kỳ nghi ngờ hay nhầm lẫn nào."},"9186":{"word":"vươn ra","meaning":"Khiến một vật thể vật lý, như cánh tay hoặc cành cây, di chuyển ra ngoài khỏi phần chính của nó, làm cho nó dài hơn hoặc vươn xa hơn."},"9187":{"word":"bám rễ","meaning":"Khi phần dưới lòng đất của cây phát triển chắc chắn vào đất, hoặc một ý tưởng, thói quen trở nên vững chắc tại một nơi."},"9188":{"word":"phun","meaning":"Đẩy chất lỏng hoặc khí ra khỏi một thứ gì đó."},"9189":{"word":"phun ra","meaning":"Đẩy chất lỏng hoặc khí ra khỏi một thứ gì đó."},"9190":{"word":"điểm mù","meaning":"Một khu vực bị che khuất khỏi tầm nhìn, đặc biệt là từ gương chiếu hậu của người lái xe hoặc camera an ninh, hoặc một tình huống không được các quy tắc hoặc dịch vụ hiện có bao phủ."},"9191":{"word":"Hình tứ giác","meaning":"Một hình học phẳng có bốn cạnh và bốn góc."},"9192":{"word":"Bắn súng","meaning":"Hành động nhắm và bắn một loại vũ khí như súng hoặc cung vào mục tiêu."},"9193":{"word":"Năng lực tư duy","meaning":"Khả năng tinh thần của một người để hiểu thông tin, giải quyết vấn đề, đưa ra quyết định hoặc tạo ra ý tưởng mới."},"9194":{"word":"Người chèo thuyền","meaning":"Người có công việc là lái hoặc chèo một chiếc thuyền nhỏ, vận chuyển người hoặc hàng hóa qua sông nước."},"9195":{"word":"Tinh thần","meaning":"Mức độ hăng hái, quyết tâm và cảm xúc tích cực của một nhóm người, đặc biệt khi làm việc cùng nhau hoặc đối mặt với tình huống khó khăn."},"9196":{"word":"Bị bắt giữ, bị cuốn hút","meaning":"Bị ai đó hoặc một nhóm người bắt giữ trái với ý muốn, hoặc bị một điều gì đó rất thú vị thu hút hoàn toàn sự chú ý."},"9197":{"word":"Lý lẽ, lẽ phải","meaning":"Khả năng suy nghĩ rõ ràng về một tình huống và đưa ra lựa chọn đúng đắn."},"9198":{"word":"Tứ diện sở ca","meaning":"Tình huống một người đối mặt với rắc rối hoặc nguy hiểm từ mọi phía, không có lối thoát."},"9199":{"word":"Khá, hẳn","meaning":"Dùng để diễn tả điều gì đó khác biệt hoặc mãnh liệt một cách đáng kể."},"9200":{"word":"Tư pháp","meaning":"Thuộc về tòa án, thẩm phán và hệ thống giải thích, thực thi luật pháp."},"9201":{"word":"Ngành tư pháp","meaning":"Nhánh của chính phủ gồm các tòa án và những người làm việc trong đó, chịu trách nhiệm quản lý công lý và giải thích luật pháp."},"9202":{"word":"Từng việc một, mọi việc","meaning":"Diễn ra hoặc được thực hiện liên quan đến từng vấn đề hoặc tình huống cụ thể."},"9203":{"word":"nhà tư tưởng","meaning":"Người chuyên suy nghĩ sâu sắc về các ý tưởng quan trọng và phát triển những quan điểm, triết lý mới."},"9204":{"word":"lâu đài trên cát","meaning":"Một kế hoạch hoặc công trình trông hoành tráng nhưng thực chất không vững chắc và sẽ sụp đổ vì thiếu nền tảng."},"9205":{"word":"sự suy tư, suy ngẫm","meaning":"Hành động suy nghĩ sâu sắc và cẩn thận về một vấn đề, thường trong im lặng và nghiêm túc."},"9206":{"word":"sợi xích, dây xích","meaning":"Một chuỗi các vòng kim loại nối liền nhau, thường dùng để buộc hoặc giữ vật gì đó."},"9207":{"word":"quanh năm, bốn mùa","meaning":"Diễn ra hoặc tồn tại liên tục trong suốt tất cả các mùa của một năm."},"9208":{"word":"thực tế, có tính hiện thực","meaning":"Miêu tả mọi thứ đúng như chúng xuất hiện hoặc tồn tại trong thế giới, không lý tưởng hóa hay hư cấu."},"9209":{"word":"sự từ chối, sự nhường nhịn","meaning":"Hành động lịch sự nói không với một lời đề nghị, lời mời hoặc yêu cầu."},"9210":{"word":"chủ doanh nghiệp, chủ kinh doanh","meaning":"Người sở hữu và quản lý một doanh nghiệp hoặc công ty thương mại."},"9211":{"word":"xa xỉ, hoang phí","meaning":"Chi tiêu rất nhiều tiền vào những món đồ hoặc trải nghiệm đắt tiền, không cần thiết, thường vượt quá mức cần thiết."},"9212":{"word":"sự từ chức, sự rút lui","meaning":"Hành động một người chính thức thông báo tự nguyện rời khỏi công việc hoặc vai trò chính thức của mình."},"9213":{"word":"lẽ phải cuối cùng sẽ thắng","meaning":"Tình trạng mà lẽ phải, sự thật sẽ chiến thắng hoặc được thiết lập vào cuối cùng."},"9214":{"word":"chủ nghĩa xã hội","meaning":"Một hệ thống kinh tế và chính trị trong đó chính phủ hoặc cộng đồng sở hữu và quản lý các doanh nghiệp và tài nguyên chính vì lợi ích của tất cả công dân."},"9215":{"word":"sau khi chết","meaning":"Khoảng thời gian sau khi một người qua đời."},"9216":{"word":"vùng núi","meaning":"Nơi có nhiều thung lũng giữa các ngọn núi."},"9217":{"word":"sảng khoái","meaning":"Có cảm giác sạch sẽ, nhẹ nhàng và dễ chịu như sau khi tắm hoặc ở trong một không gian mới dọn dẹp."},"9218":{"word":"rừng","meaning":"Một khu vực đất rộng lớn được bao phủ dày đặc bởi nhiều cây cối, bụi rậm và các loại thực vật khác."},"9219":{"word":"mất tập trung","meaning":"Không thể tập trung vào một việc, thường xuyên nhìn ngó xung quanh hoặc di chuyển không yên."},"9220":{"word":"dãy núi","meaning":"Một chuỗi dài liên tục các ngọn núi và đồi nối liền nhau, tạo thành một dạng địa hình cao kéo dài."},"9221":{"word":"sản phụ","meaning":"Người phụ nữ vừa mới sinh em bé."},"9222":{"word":"sản vật","meaning":"Một vật phẩm hoặc kết quả tự nhiên sinh ra từ một thứ khác, như cá từ đại dương hoặc thành tựu từ sự chăm chỉ."},"9223":{"word":"tính axit","meaning":"Một thuộc tính hóa học của chất khiến nó có thể phản ứng mạnh với các vật liệu khác, thường gây cảm giác bỏng rát hoặc làm giấy quỳ chuyển màu đỏ."},"9224":{"word":"trực thuộc","meaning":"Miêu tả một tổ chức hoặc nhóm nhỏ hơn hoạt động như một phần và chịu sự giám sát của một cơ quan chủ quản lớn hơn."},"9225":{"word":"khử trùng","meaning":"Quá trình sử dụng nhiệt, hóa chất hoặc các phương pháp khác để loại bỏ hoặc tiêu diệt tất cả vi sinh vật sống khỏi một vật phẩm hoặc bề mặt."},"9226":{"word":"giết người","meaning":"Hành động cố ý và trái pháp luật tước đoạt mạng sống của người khác."},"9227":{"word":"tam giác","meaning":"Tam giác là một hình phẳng có ba cạnh và ba góc."},"9228":{"word":"tắm rừng","meaning":"Tắm rừng là hoạt động thư giãn trong rừng để cải thiện sức khỏe thể chất và tinh thần."},"9229":{"word":"đợt nắng nóng gay gắt nhất mùa hè","meaning":"Đây là khoảng thời gian trong mùa hè khi nhiệt độ không khí cực kỳ cao và gây khó chịu."},"9230":{"word":"tang","meaning":"Tang là trạng thái đau buồn và các nghi lễ liên quan đến sự qua đời của một người thân."},"9231":{"word":"giao dịch thương mại","meaning":"Giao dịch thương mại là hoạt động trao đổi hàng hóa hoặc dịch vụ để lấy tiền giữa các bên."},"9232":{"word":"tương đương","meaning":"Tương đương nghĩa là có giá trị hoặc số lượng bằng nhau."},"9233":{"word":"đối lập","meaning":"Đối lập là khi hai điều hoàn toàn chống lại nhau hoặc đi theo hướng khác biệt."},"9234":{"word":"đoàn tụ","meaning":"Đoàn tụ là việc những người đã xa cách lâu ngày gặp lại nhau."},"9235":{"word":"chi tiết","meaning":"Chi tiết là việc bao gồm nhiều thông tin nhỏ và mô tả cụ thể về một điều gì đó."},"9236":{"word":"thừa kế","meaning":"Thừa kế là hành động chuyển giao hoặc tiếp nhận tài sản của một người sau khi họ qua đời."},"9237":{"word":"xu hướng tăng","meaning":"Xu hướng tăng là một hướng đi hoặc mô hình trong đó một điều gì đó liên tục tăng lên."},"9238":{"word":"đau lòng","meaning":"Đau lòng là cảm giác buồn bã sâu sắc và đau khổ tinh thần sau một sự kiện không may."},"9239":{"word":"Kiệu tang","meaning":"Vật dùng để chở thi thể người chết trong đám tang khi rước đi chôn cất."},"9240":{"word":"Sự thông dụng","meaning":"Tình trạng được nhiều người dùng hoặc sử dụng thường xuyên trong nhiều trường hợp."},"9241":{"word":"Vị trí cao","meaning":"Một cấp bậc hoặc thứ hạng cao."},"9242":{"word":"Hạng trên","meaning":"Phạm vi hoặc nhóm người thuộc các thứ hạng hoặc vị trí cao."},"9243":{"word":"Sự tương ứng","meaning":"Mối liên hệ hoặc sự phù hợp trực tiếp giữa hai hay nhiều điều."},"9244":{"word":"Khác biệt","meaning":"Hai hoặc nhiều vật có đặc điểm riêng biệt và không giống nhau."},"9245":{"word":"Thương nhân","meaning":"Người làm nghề mua bán hàng hóa cho khách hàng."},"9246":{"word":"Bằng khen","meaning":"Giấy tờ hoặc vật phẩm chính thức được trao cho ai đó để công nhận thành tích hoặc chiến thắng của họ."},"9247":{"word":"Người thường trú","meaning":"Người liên tục sống ở một nơi cụ thể hoặc làm việc ổn định tại một địa điểm nhất định."},"9248":{"word":"Thân trên","meaning":"Phần cơ thể của người hoặc động vật từ eo trở lên, bao gồm đầu, cổ, ngực và cánh tay."},"9249":{"word":"Lẫn nhau","meaning":"Điều mà hai hoặc nhiều người/nhóm làm hoặc cảm nhận đối với nhau."},"9250":{"word":"Khắp mọi ngóc ngách","meaning":"Hành động kiểm tra hoặc tìm kiếm một khu vực một cách đầy đủ, xem xét từng phần nhỏ hoặc chi tiết."},"9251":{"word":"cảm thấy mới mẻ","meaning":"Cảm nhận lại một điều gì đó đã biết từ trước nhưng nay lại thấy rõ ràng và mới mẻ như lần đầu."},"9252":{"word":"họa phúc khôn lường","meaning":"Ý nói cuộc đời khó đoán, điều xấu có thể hóa thành tốt và điều tốt có thể hóa thành xấu."},"9253":{"word":"màu sắc","meaning":"Một đặc tính của vật thể mà mắt nhìn thấy được, tạo ra các gam màu như đỏ, xanh, vàng."},"9254":{"word":"sinh kế","meaning":"Cách thức con người kiếm tiền hoặc tạo ra nguồn sống để duy trì bản thân và gia đình."},"9255":{"word":"sống chết","meaning":"Trạng thái còn sống hay đã chết của một người hoặc sinh vật."},"9256":{"word":"năng suất","meaning":"Tỷ lệ sản phẩm được tạo ra hoặc công việc được hoàn thành so với thời gian và công sức bỏ ra."},"9257":{"word":"nhà sản xuất","meaning":"Người, công ty hoặc quốc gia tạo ra hàng hóa hoặc cung cấp dịch vụ cho người khác sử dụng."},"9258":{"word":"hiệu quả","meaning":"Chỉ một nỗ lực hay hoạt động mang lại nhiều kết quả tốt hoặc tạo ra điều gì đó có ích."},"9259":{"word":"nơi sản xuất","meaning":"Địa điểm cụ thể như nông trại, nhà máy nơi một loại hàng hóa, cây trồng hoặc vật phẩm được sản xuất."},"9260":{"word":"sự hình thành","meaning":"Quá trình một điều gì đó mới bắt đầu xuất hiện hoặc hình thành."},"9261":{"word":"lạ lẫm","meaning":"Cảm thấy xa lạ, không quen biết vì chưa từng nhìn thấy, nghe nói hay trải nghiệm trước đó."},"9262":{"word":"sinh thái","meaning":"Mối quan hệ giữa sinh vật với môi trường sống xung quanh chúng."},"9263":{"word":"Nhu yếu phẩm","meaning":"Những đồ vật cần thiết cho cuộc sống hằng ngày của con người như thực phẩm, quần áo, nước uống."},"9264":{"word":"Khó khăn tài chính","meaning":"Tình trạng khó khăn, thiếu thốn về tiền bạc hoặc vật chất trong cuộc sống hàng ngày."},"9265":{"word":"Khu vực sinh hoạt","meaning":"Khu vực địa lý nơi một người thường xuyên thực hiện các hoạt động hàng ngày như làm việc, mua sắm, học tập."},"9266":{"word":"Phương Tây","meaning":"Nhóm các quốc gia và nền văn hóa thuộc châu Âu và Bắc Mỹ."},"9267":{"word":"Lời mở đầu","meaning":"Phần đầu tiên của một bài nói, cuốn sách hoặc buổi biểu diễn, giúp người nghe hoặc độc giả chuẩn bị cho nội dung tiếp theo."},"9268":{"word":"Bình dân","meaning":"Liên quan đến những thứ, món ăn hoặc lối sống đặc trưng của người dân thường trong xã hội."},"9269":{"word":"Lảng vảng","meaning":"Đi lại chậm chạp và không mục đích trong một khu vực nhỏ, thường là đang chờ đợi hoặc tìm kiếm điều gì đó."},"9270":{"word":"Không ngần ngại","meaning":"Hành động một cách nhanh chóng và dứt khoát mà không có bất kỳ sự chần chừ hay e ngại nào."},"9271":{"word":"Thư","meaning":"Một văn bản viết tay hoặc đánh máy được gửi đi để thông báo, chia sẻ thông tin với người khác."},"9272":{"word":"Thứ bậc","meaning":"Một hệ thống hoặc cách sắp xếp trong đó người hoặc vật được đặt theo thứ tự từ cao nhất đến thấp nhất dựa trên tầm quan trọng, quyền lực hoặc địa vị."},"9273":{"word":"Bài phê bình sách","meaning":"Một bài viết hoặc báo cáo mô tả và đánh giá một tác phẩm văn học đã xuất bản."},"9274":{"word":"Thiện","meaning":"Những hành động hoặc phẩm chất tốt đẹp, phù hợp với đạo đức và mang lại lợi ích cho người khác."},"9275":{"word":"tuyên án, phán quyết","meaning":"Đây là một lời công bố hoặc phán quyết chính thức được đưa ra bởi một cơ quan có thẩm quyền, thường trong môi trường tòa án."},"9276":{"word":"truyền giáo","meaning":"Là các hoạt động được thực hiện bởi những người theo đạo để truyền bá niềm tin của họ cho người khác, thường ở những nơi xa xôi."},"9277":{"word":"nhà truyền giáo","meaning":"Là người đi đến một khu vực hoặc quốc gia khác để truyền bá đức tin tôn giáo và giúp đỡ cộng đồng địa phương."},"9278":{"word":"mang tính kích động","meaning":"Mô tả lời nói hoặc hành động nhằm kích động cảm xúc mạnh mẽ trong một nhóm người, thường là sự tức giận hoặc nổi loạn."},"9279":{"word":"sẵn lòng, ngay lập tức","meaning":"Làm điều gì đó một cách nhanh chóng và không cần phải được yêu cầu nhiều lần, thể hiện sự sẵn lòng tức thì."},"9280":{"word":"nho sĩ","meaning":"Là một người có học thức, đặc biệt trong lịch sử Hàn Quốc, đã nghiên cứu văn học cổ điển và tuân thủ các nguyên tắc đạo đức."},"9281":{"word":"mang tính giật gân, khêu gợi","meaning":"Đề cập đến một thứ gì đó, như tin tức hoặc hình ảnh, nhằm kích thích hoặc gây sốc cảm xúc của mọi người, thường bằng cách tập trung vào tình dục, tội phạm hoặc bê bối."},"9282":{"word":"tổ tiên","meaning":"Là một người trong gia đình bạn đã sống nhiều thế hệ trước, rất lâu trước cha mẹ và ông bà của bạn."},"9283":{"word":"bầu chọn, tuyển chọn","meaning":"Là quá trình mọi người chính thức chọn một lãnh đạo hoặc đại diện bằng cách bỏ phiếu hoặc giơ tay."},"9284":{"word":"gây chấn động, gây sốt","meaning":"Mô tả một điều gì đó nhanh chóng trở nên cực kỳ phổ biến hoặc gây ra một phản ứng rất mạnh mẽ, lan rộng, giống như một cơn bão bất ngờ."},"9285":{"word":"lương thiện, tốt bụng","meaning":"Có bản chất hiền lành và quan tâm, thường dẫn đến việc hành động giúp đỡ và chu đáo đối với người khác."},"9286":{"word":"trước đó, tiền nhiệm","meaning":"Mô tả điều gì đó đến hoặc xảy ra ngay trước một sự kiện hoặc mục khác trong một chuỗi."},"9287":{"word":"vội vàng","meaning":"Thực hiện một việc gì đó quá nhanh hoặc không cẩn thận, không suy nghĩ kỹ về hậu quả xấu có thể xảy ra."},"9288":{"word":"thuyết","meaning":"Là một hậu tố được dùng để chỉ một học thuyết, một tập hợp các ý kiến giải thích về một vấn đề nào đó."},"9289":{"word":"bài thuyết giáo","meaning":"Một bài phát biểu được đưa ra bởi một nhà lãnh đạo tôn giáo, thường là trong nhà thờ, để dạy mọi người về đức tin và cách cư xử đúng đắn."},"9290":{"word":"ngay cả khi","meaning":"Được dùng để giới thiệu một tình huống hoặc điều kiện có thể xảy ra, nhấn mạnh rằng một điều gì đó sẽ vẫn đúng bất kể khả năng đó."},"9291":{"word":"thiết bị","meaning":"Các công cụ, máy móc hoặc hệ thống cần thiết được lắp đặt trong một tòa nhà hoặc khu vực để phục vụ một chức năng hoặc hoạt động cụ thể."},"9292":{"word":"họa vô đơn chí","meaning":"Tình trạng tai họa dồn dập, khó khăn chồng chất lên nhau, khiến mọi thứ trở nên tồi tệ hơn."},"9293":{"word":"nỗi buồn tủi","meaning":"Cảm giác buồn bã và đau khổ sâu sắc, thường do mất mát hoặc bị đối xử bất công, khiến người ta muốn khóc."},"9294":{"word":"sợi","meaning":"Một vật liệu rất mỏng, giống sợi chỉ, thường được xe thành sợi để làm vải hoặc dùng để tăng cường độ bền cho các vật liệu khác."},"9295":{"word":"chất xơ","meaning":"Các bộ phận của thực phẩm thực vật như rau và ngũ cốc không thể tiêu hóa được, giúp di chuyển thức ăn qua cơ thể và giữ cho đường ruột khỏe mạnh."},"9296":{"word":"sự an bài của tạo hóa","meaning":"Một niềm tin vào một quyền năng tiềm ẩn, thường được coi là thần thánh hoặc tự nhiên, kiểm soát hoặc hướng dẫn các sự kiện trên thế giới theo một kết quả nhất định."},"9297":{"word":"việc mời","meaning":"Hành động mời ai đó tham gia một sự kiện và xác nhận sự đồng ý của họ."},"9298":{"word":"dây thanh âm","meaning":"Hai nếp gấp mô nhỏ nằm bên trong cổ họng rung động để tạo ra âm thanh khi không khí đi qua chúng."},"9299":{"word":"Tỉ lệ giới tính","meaning":"Số lượng nam và nữ được so sánh với nhau trong một nhóm hoặc dân số cụ thể."},"9300":{"word":"Thành công, thành tựu","meaning":"Việc một kế hoạch, nỗ lực hoặc thỏa thuận được hoàn thành và diễn ra đúng như dự định."},"9301":{"word":"Giai đoạn trưởng thành","meaning":"Khoảng thời gian mà một người, động vật hoặc thực vật phát triển lớn hơn, thay đổi và đạt đến độ trưởng thành."},"9302":{"word":"Theo thứ tự điểm số","meaning":"Cách sắp xếp mọi thứ hoặc mọi người dựa trên kết quả học tập hoặc bài kiểm tra, thường từ cao đến thấp."},"9303":{"word":"Phân biệt giới tính","meaning":"Sự đối xử không công bằng với một người vì họ là nam hay nữ, bao gồm cả việc hạn chế cơ hội hoặc thiếu tôn trọng."},"9304":{"word":"Mức độ thành tích","meaning":"Sự đánh giá mức độ một người đã học được hoặc hoàn thành nhiệm vụ, mục tiêu trong một lĩnh vực cụ thể."},"9305":{"word":"Tính cách, phẩm chất","meaning":"Những đặc điểm về cách suy nghĩ, cảm nhận và hành xử điển hình làm nên sự độc đáo của một người."},"9306":{"word":"Nguyên vẹn, lành lặn","meaning":"Tình trạng hoàn chỉnh, khỏe mạnh và không bị hư hại, không có vết nứt, thương tích hoặc bộ phận nào bị thiếu."},"9307":{"word":"Sự thúc giục, cằn nhằn","meaning":"Hành động liên tục yêu cầu, bảo hoặc phàn nàn với ai đó để họ làm gì, thường là cho đến khi họ chấp nhận."},"9308":{"word":"Thuế","meaning":"Khoản tiền mà người dân hoặc công ty có nghĩa vụ pháp lý phải nộp cho chính phủ để tài trợ cho các dịch vụ công cộng."},"9309":{"word":"Thế lực, quyền lực","meaning":"Khả năng của một người, nhóm hoặc quốc gia trong việc kiểm soát hoặc tác động đến hành động, quyết định của người khác."},"9310":{"word":"Hải quan","meaning":"Cơ quan chính phủ tại biên giới, sân bay hoặc cảng biển, nơi các quan chức kiểm tra hành khách và hàng hóa ra vào đất nước."},"9311":{"word":"chi tiết, tỉ mỉ","meaning":"Rất kỹ lưỡng, tỉ mỉ trong từng chi tiết nhỏ."},"9312":{"word":"chu đáo, kỹ lưỡng","meaning":"Rất cẩn thận, chú ý đến từng chi tiết dù nhỏ nhặt nhất, không bỏ sót điều gì."},"9313":{"word":"thế thái, xu thế xã hội","meaning":"Những phong tục, hành vi và tư tưởng chung phổ biến trong xã hội vào một thời kỳ nhất định."},"9314":{"word":"tế bào","meaning":"Đơn vị cấu tạo nhỏ nhất của mọi sinh vật, thường rất nhỏ không thể nhìn thấy bằng mắt thường."},"9315":{"word":"cảm biến","meaning":"Thiết bị phát hiện sự thay đổi về ánh sáng, nhiệt độ, âm thanh hoặc chuyển động và kích hoạt phản ứng của máy móc khác."},"9316":{"word":"náo động, xôn xao","meaning":"Tình trạng ồn ào, lộn xộn đột ngột do nhiều người cùng di chuyển hoặc nói chuyện lớn tiếng."},"9317":{"word":"ồn ào, huyên náo","meaning":"Có nhiều âm thanh hoặc giọng nói lớn, thường do nhiều người cùng hoạt động hoặc nói chuyện."},"9318":{"word":"số lượng nhỏ, ít","meaning":"Một lượng rất ít, không đáng kể."},"9319":{"word":"biến mất, tiêu diệt, tuyệt chủng","meaning":"Tình trạng cái gì đó hoàn toàn không còn tồn tại hoặc không thể nhìn thấy ở bất cứ đâu."},"9320":{"word":"chính kiến, niềm tin","meaning":"Quan điểm hoặc ý kiến mạnh mẽ, vững chắc mà một người kiên định giữ trong lòng, định hướng hành động và lời nói của họ."},"9321":{"word":"mất mát, tiêu hủy, bị cháy rụi","meaning":"Sự kiện một vật bị phá hủy hoàn toàn, bị đốt cháy hoặc biến mất, không thể nhìn thấy hay sử dụng được nữa."},"9322":{"word":"nhi khoa, trẻ em","meaning":"Liên quan đến trẻ nhỏ, đặc biệt là trẻ sơ sinh và trẻ mới biết đi, hoặc việc chăm sóc y tế và bệnh tật của chúng."},"9323":{"word":"tri thức","meaning":"Sự hiểu biết, năng lực và phẩm chất cần thiết trong một lĩnh vực cụ thể."},"9324":{"word":"sự cô lập","meaning":"Cảm giác bị tách biệt, không thuộc về một nhóm hoặc xã hội, hoặc bị bỏ qua."},"9325":{"word":"cái gọi là","meaning":"Dùng để chỉ một điều mà mọi người thường gọi như vậy, nhưng thực tế có thể không hoàn toàn đúng như tên gọi."},"9326":{"word":"ruột non","meaning":"Một đoạn ruột dài, cuộn tròn trong bụng, có nhiệm vụ hấp thụ hầu hết chất dinh dưỡng từ thức ăn."},"9327":{"word":"sự mang theo","meaning":"Hành động giữ hoặc mang một vật gì đó bên người hoặc dưới quyền kiểm soát trực tiếp."},"9328":{"word":"phần mềm","meaning":"Tập hợp các chương trình và dữ liệu hướng dẫn máy tính hoặc thiết bị điện tử hoạt động, tồn tại dưới dạng thông tin số."},"9329":{"word":"bình chữa cháy","meaning":"Thiết bị hình trụ màu đỏ dùng để phun chất đặc biệt nhằm dập tắt lửa."},"9330":{"word":"tin nóng","meaning":"Bản tin quan trọng về sự kiện vừa xảy ra, được phát sóng ngay lập tức, đôi khi gián đoạn các chương trình khác."},"9331":{"word":"quan niệm dân gian","meaning":"Một ý tưởng hay câu chuyện phổ biến mà nhiều người tin là đúng, thường truyền miệng mà không có bằng chứng chắc chắn."},"9332":{"word":"thuộc tính","meaning":"Một phẩm chất, đặc điểm hoặc tính năng riêng biệt của một người, vật thể hoặc khái niệm."},"9333":{"word":"ý đồ ngầm","meaning":"Lý do kín đáo hoặc mục đích bí mật đằng sau hành động của ai đó, khác với những gì họ công khai."},"9334":{"word":"thấu đáo","meaning":"Một cách kỹ lưỡng, đầy đủ mọi khía cạnh, kể cả những phần không dễ nhìn thấy."},"9335":{"word":"bất lực","meaning":"Tình trạng hoàn toàn không có cách nào để hành động hoặc thay đổi tình hình khó khăn."},"9336":{"word":"mánh khóe","meaning":"Hành động hoặc kế hoạch tinh ranh nhằm lừa dối người khác hoặc khiến họ tin vào điều không có thật."},"9337":{"word":"sự chỉ trỏ","meaning":"Hành động dùng ngón tay chỉ vào người hoặc vật, thường là để khiển trách hoặc biểu lộ sự không đồng tình một cách công khai."},"9338":{"word":"chạm vào","meaning":"Dùng tay chạm hoặc sờ vào một vật gì đó."},"9339":{"word":"tay nghề nấu ăn","meaning":"Kỹ năng đặc biệt hoặc nét riêng của một người khiến món ăn họ chế biến trở nên rất ngon."},"9340":{"word":"sự thua kém","meaning":"Tình trạng không bằng hoặc có nhược điểm rõ rệt khi so sánh với cái khác."},"9341":{"word":"tự tay","meaning":"Tự mình làm một việc gì đó bằng tay, không nhờ cậy người khác hay máy móc."},"9342":{"word":"sự nắm giữ","meaning":"Sức nắm chặt của bàn tay quanh vật gì, hoặc quyền kiểm soát vững chắc của một người đối với tình huống."},"9343":{"word":"bàn chải","meaning":"Dụng cụ gồm nhiều sợi lông hoặc dây cứng gắn vào cán, dùng để cọ rửa, phết chất lỏng hoặc làm mịn bề mặt."},"9344":{"word":"hấp dẫn","meaning":"Cảm thấy bị thu hút mạnh mẽ bởi một ý tưởng, đề nghị hoặc gợi ý vì nó có vẻ rất hấp dẫn hoặc có lợi."},"9345":{"word":"trào ra","meaning":"Đột ngột xuất hiện hoặc chảy ra từ bên trong/dưới bề mặt, như nước từ lòng đất hay cảm xúc mạnh từ trong lòng người."},"9346":{"word":"vạc","meaning":"Dụng cụ nấu ăn bằng kim loại, lớn, tròn, sâu, có nắp, dùng để nấu thức ăn, đặc biệt là trên bếp lửa hoặc lò."},"9347":{"word":"đổ dồn","meaning":"Hiện tượng nhiều thứ hoặc nhiều người cùng lúc ập đến, dồn dập, thường gây quá tải."},"9348":{"word":"suy thoái","meaning":"Tình trạng một cái gì đó dần trở nên yếu đi, kém phát triển hơn hoặc mất đi tầm quan trọng theo thời gian."},"9349":{"word":"thừa nhận","meaning":"Hành động chấp nhận rằng một điều gì đó là đúng hoặc hợp lý sau khi xem xét, thường thể hiện bằng cách gật đầu hoặc xác nhận bằng lời."},"9350":{"word":"nữ tu","meaning":"Người phụ nữ dâng hiến cuộc đời mình cho việc phụng sự tôn giáo, thường sống trong một cộng đồng và mặc trang phục đặc biệt."},"9351":{"word":"hay nói","meaning":"Tính cách của người thường nói rất nhiều điều, thường là một cách sôi nổi hoặc vui vẻ."},"9352":{"word":"tu hành","meaning":"Việc rèn luyện thân tâm để đạt được giác ngộ hoặc một mục tiêu tôn giáo, thường bao gồm khổ hạnh và kỷ luật nghiêm ngặt."},"9353":{"word":"đầy rẫy","meaning":"Tồn tại với số lượng hoặc khối lượng lớn, thường nhiều hơn mức cần thiết hoặc mong đợi."},"9354":{"word":"thanh tú","meaning":"Có vẻ ngoài rất dễ chịu và thu hút, thường mang nét thanh thoát và tinh tế."},"9355":{"word":"thiết lập","meaning":"Hành động tạo ra, thành lập hoặc xây dựng một cái gì đó mới, chẳng hạn như một kế hoạch hoặc một tổ chức."},"9356":{"word":"cây cối","meaning":"Các loài thực vật thân gỗ lớn có thân chính hoặc gốc và nhiều cành, được bao phủ bởi lá."},"9357":{"word":"chăm sóc","meaning":"Hành động cung cấp sự giúp đỡ và đáp ứng các nhu cầu của ai đó, đặc biệt là người ốm hoặc người già."},"9358":{"word":"thủ đoạn","meaning":"Một cách thức hoặc kỹ thuật cụ thể được sử dụng để làm điều gì đó, thường là một cách khéo léo hoặc lừa dối."},"9359":{"word":"thụ phấn","meaning":"Hiện tượng phấn hoa di chuyển từ nhị hoa sang nhụy hoa để cây có thể kết trái."},"9360":{"word":"phòng thủ","meaning":"Hành động bảo vệ một cái gì đó hoặc ai đó khỏi bị tấn công hoặc gây hại, thường trong thể thao hoặc quân sự."},"9361":{"word":"điều tra viên","meaning":"Người có nhiệm vụ kiểm tra kỹ lưỡng các sự thật, bằng chứng và con người để khám phá sự thật về một tội phạm hoặc tình huống."},"9362":{"word":"ngành thủy sản","meaning":"Công việc tổ chức đánh bắt cá và các loài động vật biển khác, chế biến chúng, và sau đó đưa đến người mua."},"9363":{"word":"đáng ngờ","meaning":"Khi một người hoặc sự vật có vẻ lạ lùng hoặc sai trái, khiến bạn nghĩ rằng điều gì đó xấu có thể đang xảy ra."},"9364":{"word":"tìm kiếm","meaning":"Hành động tìm kiếm cẩn thận và kỹ lưỡng một thứ gì đó bị mất, giấu kín, hoặc một người mất tích."},"9365":{"word":"hỏi thăm khắp nơi","meaning":"Hành động nói chuyện với nhiều người khác nhau ở nhiều nơi để tìm hiểu thông tin hoặc vị trí của ai đó hay cái gì đó."},"9366":{"word":"vận chuyển","meaning":"Việc di chuyển người hoặc vật phẩm từ một địa điểm này đến một địa điểm khác, thường bằng phương tiện, tàu hoặc máy bay."},"9367":{"word":"tài xoay xở","meaning":"Khả năng đặc biệt hoặc sự khéo léo mà một người thể hiện khi quản lý tình huống hoặc hoàn thành công việc một cách hiệu quả."},"9368":{"word":"sức chứa","meaning":"Lượng không gian lớn nhất hoặc số lượng người mà một địa điểm hay vật thể có thể chứa hoặc tiếp nhận."},"9369":{"word":"người tiếp nhận","meaning":"Người nhận được một thứ gì đó, hoặc người bị giam giữ trong một nơi hạn chế như bệnh viện hay nhà tù."},"9370":{"word":"dễ dàng","meaning":"Khi một việc gì đó có thể được thực hiện mà không gặp nhiều rắc rối hay khó khăn, khiến nhiệm vụ trở nên nhẹ nhàng."},"9371":{"word":"người bị lũ lụt","meaning":"Người phải chịu thiệt hại do lũ lụt, mưa bão gây ra."},"9372":{"word":"ngại ngùng","meaning":"Cảm thấy không thoải mái hoặc bối rối khi gặp người lạ hoặc trong các tình huống xã hội."},"9373":{"word":"dưới nước","meaning":"Địa điểm hoặc hoạt động tồn tại hoặc diễn ra bên dưới bề mặt của một vùng nước."},"9374":{"word":"thu chi","meaning":"Kết quả tài chính của một hoạt động kinh doanh, cho thấy tiền thu vào nhiều hơn hay ít hơn tiền chi ra."},"9375":{"word":"nhiều lần","meaning":"Xảy ra trong một số dịp riêng biệt, thường là hơn hai lần nhưng không quá nhiều."},"9376":{"word":"sự xấu hổ","meaning":"Cảm giác nhục nhã hoặc đau khổ do nhận thức về hành vi sai trái hoặc ngốc nghếch của bản thân."},"9377":{"word":"con đực","meaning":"Một loài động vật có cơ quan sinh sản để thụ tinh trứng, khác với loài động vật tạo ra trứng."},"9378":{"word":"chiều ngang","meaning":"Một đường thẳng hoặc bề mặt phẳng nằm ngang hoàn hảo, giống như mặt đất hoặc mặt nước tĩnh, không chạy lên xuống."},"9379":{"word":"đường chân trời","meaning":"Một đường tạo thành ranh giới giữa biển và bầu trời."},"9380":{"word":"truyền máu","meaning":"Thủ thuật y tế đưa máu từ người này vào cơ thể người khác thông qua ống và kim tiêm, thường là vào tĩnh mạch."},"9381":{"word":"người thụ hưởng","meaning":"Một người nhận tiền, tài sản hoặc giải thưởng từ người khác, thường là do di chúc, hợp đồng bảo hiểm hoặc chương trình đặc biệt."},"9382":{"word":"ống nghe điện thoại","meaning":"Phần cầm tay của một chiếc điện thoại kiểu cũ mà bạn nhấc lên để nghe và nói vào."},"9383":{"word":"kẻ khờ khạo","meaning":"Người ngu ngốc, không hiểu biết nhiều về thế sự."},"9384":{"word":"sự nhanh nhạy","meaning":"Khả năng phản ứng hoặc di chuyển cơ thể nhanh chóng và mạnh mẽ trong một khoảnh khắc đột ngột."},"9385":{"word":"tính thuần khiết","meaning":"Phẩm chất của cái gì đó hoàn toàn sạch sẽ, không pha trộn, hoặc không có khuyết điểm hay yếu tố nhân tạo."},"9386":{"word":"sự thích nghi","meaning":"Việc thay đổi hành vi hoặc diện mạo để phù hợp hơn với một tình huống hoặc môi trường mới."},"9387":{"word":"hoàn toàn","meaning":"Diễn tả rằng một điều gì đó là duy nhất hoặc trọn vẹn theo một cách nào đó, không có bất kỳ yếu tố khác biệt nào."},"9388":{"word":"thuận lợi","meaning":"Một quá trình hoặc tình huống diễn ra dễ dàng, liên tục mà không gặp khó khăn hay trở ngại nào."},"9389":{"word":"hệ tuần hoàn","meaning":"Hệ thống các cơ quan và mạch máu, bao gồm tim, máu và mạch máu, có chức năng vận chuyển máu khắp cơ thể."},"9390":{"word":"nín thở","meaning":"Ngừng đưa không khí vào phổi trong một thời gian ngắn, thường là để giữ im lặng hoặc tập trung cao độ."},"9391":{"word":"cao cả","meaning":"Có phẩm chất vĩ đại, nghiêm túc và tạo cảm hứng ngưỡng mộ sâu sắc hoặc sự kính sợ."},"9392":{"word":"nước cơm cháy","meaning":"Nước được đun sôi trong nồi sau khi đã lấy cơm ra, thường có vị hơi cháy."},"9393":{"word":"sự sùng bái","meaning":"Hành động thể hiện tình yêu, sự tôn kính và lòng thành kính sâu sắc đối với thần thánh, vật linh thiêng hoặc người được ngưỡng mộ."},"9394":{"word":"dễ dàng","meaning":"Diễn tả việc gì đó được thực hiện hoặc xảy ra mà không cần nhiều nỗ lực hay khó khăn."},"9395":{"word":"tan biến","meaning":"Một thứ gì đó dần dần trở nên không còn nhìn thấy được hoặc yếu đi cho đến khi biến mất hoàn toàn."},"9396":{"word":"thấm vào","meaning":"Chất lỏng, khí hoặc mùi hương từ từ lan rộng và đi vào bên trong một vật khác."},"9397":{"word":"ngấm vào","meaning":"Chất lỏng dần dần chảy hoặc ngấm vào bên trong một thứ gì đó."},"9398":{"word":"một cách lén lút","meaning":"Thực hiện một hành động nào đó một cách kín đáo, không để người khác biết."},"9399":{"word":"một cách khẽ khàng","meaning":"Thực hiện một hành động một cách nhẹ nhàng, tinh tế để không bị người khác chú ý."},"9400":{"word":"tập tính","meaning":"Một tính chất đã trở thành thói quen hoặc hành vi đặc trưng của một người hay loài vật."},"9401":{"word":"nhà sư","meaning":"Người tu hành sống trong chùa, thường mặc áo cà sa và cạo trọc đầu."},"9402":{"word":"cưỡi ngựa","meaning":"Hoạt động ngồi trên lưng một con vật lớn bốn chân và điều khiển chuyển động của nó."},"9403":{"word":"thắng lợi liên tiếp","meaning":"Tình huống một người hoặc một đội liên tục giành chiến thắng mà không hề thua cuộc."},"9404":{"word":"sự chấp thuận","meaning":"Một tuyên bố hoặc hành động chính thức cho thấy một điều gì đó được phép hoặc được chấp nhận."},"9405":{"word":"người chiến thắng","meaning":"Người đã đánh bại người khác trong một cuộc thi hoặc cạnh tranh và được công nhận là người đứng đầu."},"9406":{"word":"xem","meaning":"Hậu tố được gắn vào sau một số từ để chỉ cách nhìn nhận, đối xử hoặc mức độ chú ý của chủ thể đối với một người hay sự vật cụ thể."},"9407":{"word":"khoảng thời gian","meaning":"Một khoảng thời gian cụ thể trong ngày hoặc một khu vực địa lý có cùng múi giờ."},"9408":{"word":"khẩn cấp","meaning":"Một cách nhanh chóng và ngay lập tức vì việc đó rất quan trọng."},"9409":{"word":"quá sớm","meaning":"Xảy ra hoặc được thực hiện quá sớm, trước thời điểm thích hợp."},"9410":{"word":"cử chỉ, giả vờ","meaning":"Một hành động hoặc cử động cơ thể được thực hiện để cho thấy điều gì đó, thường là giả vờ hoặc không làm thật."},"9411":{"word":"mang tính thời đại","meaning":"Cái gì đó thuộc về hoặc đại diện cho cách mọi thứ diễn ra trong một giai đoạn lịch sử cụ thể."},"9412":{"word":"thử thách, gian nan","meaning":"Một trải nghiệm rất khó khăn và khó chịu nhằm kiểm tra sức mạnh hoặc sự kiên nhẫn của một người."},"9413":{"word":"nỗi lo, sự buồn rầu","meaning":"Trạng thái bận lòng hoặc suy nghĩ liên tục về những khó khăn, vấn đề, thường thể hiện qua nét mặt."},"9414":{"word":"ủ rũ, buồn rầu","meaning":"Ít nói, với vẻ mặt không hài lòng hoặc buồn bã."},"9415":{"word":"đúng sai, phải trái","meaning":"Những điều đúng và sai, phải và trái."},"9416":{"word":"gợi ý, ám chỉ","meaning":"Gợi mở điều gì đó hoặc làm cho nó được biết đến một cách gián tiếp, chứ không nói rõ ràng."},"9417":{"word":"trao giải, vinh danh","meaning":"Hành động trao một phần thưởng đặc biệt hoặc sự công nhận cho người đã đạt được thành tích lớn."},"9418":{"word":"từng khoảnh khắc, từng giây từng phút","meaning":"Mọi thứ thay đổi hoặc xảy ra liên tục không ngừng, khác biệt trong từng khoảnh khắc nhỏ."},"9419":{"word":"thi thể","meaning":"Thân thể của một người đã chết."},"9420":{"word":"vừa mừng vừa tiếc","meaning":"Có cảm giác mâu thuẫn giữa việc vui vì tình huống không mong muốn đã kết thúc và buồn vì sự vắng mặt của nó."},"9421":{"word":"thẳng thắn","meaning":"Tính cách hành động nhanh chóng, rõ ràng, nói ra suy nghĩ một cách cởi mở và không do dự."},"9422":{"word":"thừa nhận","meaning":"Hành động nói ra rằng một điều gì đó là sự thật, đặc biệt là một hành vi phạm tội."},"9423":{"word":"thi vị","meaning":"Mang những đặc điểm giống như ngôn ngữ và hình ảnh đặc biệt trong thơ ca, gợi lên cảm xúc mạnh mẽ hoặc vẻ đẹp."},"9424":{"word":"sự sửa chữa","meaning":"Hành động thay đổi một điều gì đó sai hoặc không chính xác để làm cho nó đúng đắn."},"9425":{"word":"trước sau như một","meaning":"Một hành động hoặc trạng thái duy trì như cũ mà không thay đổi từ đầu đến cuối."},"9426":{"word":"sự phục vụ","meaning":"Hành động ở gần ai đó để cung cấp sự trợ giúp, như mang thức ăn hoặc đồ vật họ yêu cầu."},"9427":{"word":"mùa","meaning":"Một khoảng thời gian mà một hoạt động nhất định diễn ra sôi nổi nhất hoặc là thời điểm thích hợp để thực hiện một hoạt động."},"9428":{"word":"thử và sai","meaning":"Hành động lặp đi lặp lại việc thử nhưng thất bại, qua đó tiếp cận gần hơn với phương pháp đúng để đạt được mục tiêu."},"9429":{"word":"thực đơn","meaning":"Một bảng liệt kê các loại thức ăn sẽ được ăn và thứ tự ăn."},"9430":{"word":"nạn đói","meaning":"Tình trạng không có đủ lương thực để con người duy trì sự sống, dẫn đến nạn đói lan rộng."},"9431":{"word":"thuộc địa","meaning":"Một vùng đất bị kiểm soát về chính trị bởi một quốc gia mạnh ở xa."},"9432":{"word":"dùng để ăn","meaning":"An toàn và thích hợp để con người hoặc động vật ăn vào để nuôi dưỡng cơ thể."},"9433":{"word":"mồ hôi lạnh","meaning":"Mồ hôi tiết ra trên da do sợ hãi, lo lắng hoặc bệnh tật, không phải do vận động hay nóng."},"9434":{"word":"sự hưng phấn","meaning":"Cảm giác rất vui vẻ, phấn khích và nhiệt tình, khiến người ta muốn hát hay nhảy múa."},"9435":{"word":"huyền bí","meaning":"Rất khó hoặc không thể giải thích hay hiểu được hoàn toàn, thường tạo ra cảm giác kỳ diệu."},"9436":{"word":"thông tin cá nhân","meaning":"Những dữ kiện về danh tính của một cá nhân như tên, tuổi, ngày sinh và cách thức liên lạc."},"9437":{"word":"sự thành lập mới","meaning":"Việc thiết lập hoặc mở một cái gì đó lần đầu tiên, làm cho nó có sẵn để sử dụng."},"9438":{"word":"ân huệ","meaning":"Tình huống nhận được sự giúp đỡ đáng kể từ người khác, khiến mình cảm thấy mắc nợ người đó."},"9439":{"word":"tiếng rên","meaning":"Âm thanh trầm thấp mà một người tạo ra, thường là do đau đớn, buồn bã hoặc khó chịu."},"9440":{"word":"lòng tin","meaning":"Niềm tin mạnh mẽ vào sự trung thực và đáng tin cậy của ai đó, khiến bạn cảm thấy an toàn khi dựa vào họ."},"9441":{"word":"tân binh","meaning":"Một người mới bắt đầu một hoạt động, công việc hoặc lĩnh vực cụ thể."},"9442":{"word":"sự tin cậy","meaning":"Niềm tin mạnh mẽ vào khả năng, sự trung thực hoặc ý định tốt của ai đó, khiến bạn chắc chắn họ sẽ hành động đúng."},"9443":{"word":"tín đồ","meaning":"Người tin theo và ủng hộ một tôn giáo, triết lý hoặc ý tưởng cụ thể."},"9444":{"word":"chủng mới","meaning":"Cái gì đó mới xuất hiện hoặc được nhận dạng, khác với các dạng đã có."},"9445":{"word":"sự trao đổi chất","meaning":"Quá trình hóa học trong cơ thể sống biến thức ăn thành năng lượng và tạo ra các tế bào mới."},"9446":{"word":"tính đàn hồi","meaning":"Đặc tính vật lý của vật liệu cho phép nó kéo dài khi bị kéo và sau đó trở lại hình dạng ban đầu."},"9447":{"word":"thần hạ","meaning":"Người phục vụ và tuân lệnh vua hoặc hoàng hậu trong thời phong kiến."},"9448":{"word":"manh mối","meaning":"Một mẩu thông tin hoặc vật giúp giải quyết một tình huống khó khăn hay tìm ra câu trả lời cho một vấn đề."},"9449":{"word":"thực trạng","meaning":"Tình trạng thực sự của sự vật như chúng vốn có, có thể khác với những gì mọi người nghĩ."},"9450":{"word":"thực tế","meaning":"Thế giới vật chất và các sự kiện thực sự tồn tại và xảy ra."},"9451":{"word":"ngoài trời","meaning":"Khu vực bên ngoài một tòa nhà, nơi không gian mở và tiếp xúc với môi trường tự nhiên."},"9452":{"word":"sự áp dụng vào thực tế","meaning":"Hành động biến một ý tưởng, phát minh hoặc phương pháp trở nên hữu dụng và sẵn có cho các hoạt động hàng ngày."},"9453":{"word":"tình hình thực tế","meaning":"Điều kiện hoặc trạng thái thực sự của sự vật như chúng tồn tại, không phải như tưởng tượng."},"9454":{"word":"thực chất","meaning":"Bản chất thật và cơ bản hoặc phần cốt lõi của một cái gì đó, không phải vẻ bề ngoài của nó."},"9455":{"word":"thực chất","meaning":"Có ý nghĩa hoặc tác dụng cụ thể, hữu ích trong thế giới thực."},"9456":{"word":"thực tiễn","meaning":"Có phương pháp hoặc hoạt động tập trung vào việc áp dụng kiến thức và lý thuyết thông qua hành động."},"9457":{"word":"tâm trạng","meaning":"Tập hợp những suy nghĩ và cảm xúc mà một người đang cảm thấy tại một thời điểm nhất định."},"9458":{"word":"bản tính","meaning":"Bản chất và phẩm chất cốt lõi định hình cách một người thường suy nghĩ, cảm nhận và hành động."},"9459":{"word":"xem xét, thẩm định","meaning":"Hành động kiểm tra kỹ lưỡng chất lượng hoặc tính khả thi của một nội dung, vấn đề nào đó."},"9460":{"word":"tim và máu","meaning":"Chất lỏng màu đỏ chảy trong cơ thể, thiết yếu cho sự sống, và cơ quan trung tâm bơm chất lỏng đó."},"9461":{"word":"chuyên sâu","meaning":"Quá trình làm cho một điều gì đó trở nên mạnh mẽ, kỹ lưỡng hoặc sâu sắc hơn về tác dụng hoặc sự hiểu biết."},"9462":{"word":"cực kỳ","meaning":"Ở một mức độ rất đáng kể hoặc đến mức tối đa, thường chỉ một cảm xúc mạnh mẽ hoặc một tác động lớn."},"9463":{"word":"chung tay góp sức","meaning":"Nguyên tắc nhiều người mỗi người đóng góp một phần nhỏ để cùng nhau hoàn thành một công việc lớn."},"9464":{"word":"tươi mới","meaning":"Trông rất sạch sẽ, khỏe mạnh và tràn đầy sức sống, thường được dùng để miêu tả cây cối, trái cây hoặc không khí."},"9465":{"word":"se lạnh","meaning":"Có nhiệt độ thấp, tạo cảm giác mát mẻ và hơi khó chịu, thường khiến người ta rùng mình."},"9466":{"word":"hoàn toàn","meaning":"Từ dùng để diễn tả một hành động mà điều gì đó bị loại bỏ hoặc chấm dứt hoàn toàn, không để lại gì."},"9467":{"word":"nảy mầm, nảy sinh","meaning":"Chỉ việc mầm cây nhú lên khỏi mặt đất hoặc một ý nghĩ, tình cảm mới bắt đầu hình thành."},"9468":{"word":"hai bên, song phương","meaning":"Chỉ hai nhóm hoặc hai cá nhân riêng biệt cùng tham gia vào một hành động hoặc sự kiện."},"9469":{"word":"cặp song hành, đối thủ ngang tài","meaning":"(Ví von) Chỉ hai người có năng lực xuất sắc và tương đương nhau."},"9470":{"word":"nghiêng về, dồn về","meaning":"Chỉ việc trọng lượng hoặc sự chú ý của cái gì đó tập trung về một phía hoặc một hướng."},"9471":{"word":"hơi đắng, chát","meaning":"Có vị hơi đắng hoặc cảm giác chát ở đầu lưỡi."},"9472":{"word":"không tiếc, hào phóng","meaning":"Chỉ việc cho đi hoặc chia sẻ một cách rộng rãi, không hề giữ lại bất cứ điều gì."},"9473":{"word":"một cách hào phóng, không tiếc nuối","meaning":"Diễn tả hành động làm gì đó hoặc cho đi mà không chút do dự hay muốn giữ lại."},"9474":{"word":"ấm cúng, dễ chịu","meaning":"Mô tả một nơi nhỏ, ấm áp và rất thoải mái, khiến người ta cảm thấy thư giãn và an toàn."},"9475":{"word":"xa xăm, mờ mịt","meaning":"Chỉ việc một thứ gì đó ở rất xa trong không gian hoặc thời gian, khó có thể nhìn thấy hoặc nhớ rõ."},"9476":{"word":"mặc kệ, bất chấp","meaning":"Diễn tả việc một người tiếp tục làm gì đó mà không bị ảnh hưởng hay quan tâm đến ý kiến hoặc hành động của người khác."},"9477":{"word":"bằng mọi cách, xin vui lòng","meaning":"Từ dùng để bày tỏ một yêu cầu nghiêm túc, mong muốn mọi nỗ lực được thực hiện để đảm bảo điều gì đó xảy ra."},"9478":{"word":"nịnh hót, xu nịnh","meaning":"Lời khen ngợi quá mức, thường không chân thành, nhằm mục đích lấy lòng hoặc đạt được lợi ích cá nhân."},"9479":{"word":"cha","meaning":"Người đàn ông là người sinh ra con mình."},"9480":{"word":"chót vót, nguy hiểm","meaning":"Trong tình trạng rất nguy hiểm, không ổn định, gần như thất bại."},"9481":{"word":"bao quát, bao gồm","meaning":"Gom nhiều thứ hoặc ý tưởng khác nhau vào một nhóm hoặc hệ thống thống nhất."},"9482":{"word":"chóng mặt, choáng váng","meaning":"Cảm thấy đầu đột ngột quay cuồng, thường kèm theo cảm giác choáng váng hoặc mất thăng bằng trong chốc lát."},"9483":{"word":"ác ý, thù hằn","meaning":"Mong muốn sâu sắc gây hại hoặc đau đớn cho người khác, thường thể hiện qua lời nói hoặc hành động độc ác."},"9484":{"word":"ác tính, độc hại","meaning":"Miêu tả một thứ rất có hại và lây lan nhanh chóng, thường gây ra thiệt hại hoặc nguy hiểm nghiêm trọng."},"9485":{"word":"vai phản diện","meaning":"Vai diễn của nhân vật xấu xa trong kịch, phim ảnh, v.v.; hoặc người đóng vai đó."},"9486":{"word":"độc ác, xấu xa","meaning":"Có tính cách cố ý gây ra tổn hại hoặc đau khổ lớn cho người khác."},"9487":{"word":"sự cố gắng hết sức","meaning":"Sự nỗ lực rất lớn về thể chất hoặc tinh thần để hoàn thành một việc cực kỳ khó khăn."},"9488":{"word":"đề mục, chủ đề","meaning":"Một chủ đề cụ thể được đưa ra để thảo luận hoặc quyết định trong một cuộc họp chính thức."},"9489":{"word":"sự sốt ruột, sự bồn chồn","meaning":"Cảm giác lo lắng hoặc bồn chồn do phải chờ đợi điều gì đó, thường thể hiện qua hành động không yên."},"9490":{"word":"sự an nhàn, sự thoải mái","meaning":"Cảm giác dễ chịu khi được thư giãn và hài lòng về thể chất, không có lo lắng hay khó khăn."},"9491":{"word":"An tử","meaning":"Hành động giúp bệnh nhân mắc bệnh nan y không còn hi vọng sống chấm dứt cuộc đời để thoát khỏi đau đớn, sau khi có sự đồng ý của bệnh nhân hoặc gia đình."},"9492":{"word":"Nhãn quan","meaning":"Khả năng đặc biệt để đánh giá chính xác chất lượng, giá trị hoặc bản chất thực sự của sự vật hay con người."},"9493":{"word":"Đáng thương, tội nghiệp","meaning":"Cảm thấy lo lắng sâu sắc và dịu dàng đối với ai đó trông yếu ớt, buồn bã hoặc đang trong hoàn cảnh khó khăn."},"9494":{"word":"Thụ động, an phận","meaning":"Thể hiện thái độ thư giãn và không lo lắng, thường không chuẩn bị cho những khó khăn có thể xảy ra hoặc không nỗ lực đủ."},"9495":{"word":"An nhàn, an phận","meaning":"Tình trạng quá hài lòng với hoàn cảnh hiện tại, dẫn đến thiếu nỗ lực hoặc chuẩn bị cho những thử thách."},"9496":{"word":"Bồn chồn, sốt ruột","meaning":"Hành động cử động các bộ phận cơ thể một cách nhỏ, nhanh hoặc lo lắng, hoặc đi đi lại lại vì lo lắng hay phấn khích."},"9497":{"word":"An phận","meaning":"Tình trạng quá hài lòng với hoàn cảnh hiện tại, dẫn đến thiếu nỗ lực hoặc chuẩn bị cho những thử thách."},"9498":{"word":"Môi giới, giới thiệu","meaning":"Hành động giúp đỡ các cá nhân hoặc nhóm kết nối hoặc tìm thấy các cơ hội phù hợp, chẳng hạn như việc làm hoặc thỏa thuận."},"9499":{"word":"Nhận ra, phát hiện ra","meaning":"Đột nhiên nhận thức được điều gì đó không rõ ràng, thường là qua quan sát kỹ hoặc có trực giác."},"9500":{"word":"Khả năng ghi nhớ","meaning":"Khả năng tinh thần của một người để học và ghi nhớ thông tin một cách chính xác, ví dụ như sự kiện hoặc con số."},"9501":{"word":"Gợi ý, ám chỉ","meaning":"Một dấu hiệu tinh tế hoặc lời nói gián tiếp khiến ai đó nghĩ đến một ý tưởng hoặc khả năng mà không nói thẳng ra."},"9502":{"word":"Con cái (động vật)","meaning":"Một loài động vật có khả năng sinh học để đẻ con hoặc trứng."},"9503":{"word":"mật mã","meaning":"Hệ thống các từ, số hoặc ký hiệu bí mật dùng để che giấu ý nghĩa của một thông điệp."},"9504":{"word":"thời kỳ đen tối","meaning":"Giai đoạn lịch sử mà một xã hội phải trải qua nhiều khó khăn, thiếu phát triển hoặc bất hạnh."},"9505":{"word":"áp đảo","meaning":"Tình trạng mạnh hơn hoặc lớn hơn rất nhiều so với cái khác, khiến nó bị đánh bại hoặc kiểm soát hoàn toàn."},"9506":{"word":"có tính áp đảo","meaning":"Diễn tả điều gì đó vượt trội hoặc lớn hơn rất nhiều về số lượng hoặc sức mạnh, khiến người khác không thể chống lại hoặc so sánh."},"9507":{"word":"áp lực","meaning":"Cảm giác nặng nề về trách nhiệm hoặc những yêu cầu khẩn cấp khiến một người cảm thấy căng thẳng hoặc lo lắng."},"9508":{"word":"sự nén","meaning":"Hành động làm cho cái gì đó nhỏ hơn hoặc gọn hơn bằng cách ép nó lại vào một không gian chật hơn."},"9509":{"word":"tranh nhau","meaning":"Cố gắng hết sức để là người đầu tiên làm gì đó hoặc đạt được mục tiêu trước bất kỳ ai khác."},"9510":{"word":"đẩy sớm","meaning":"Di chuyển thời gian dự kiến của một sự kiện hoặc công việc để nó diễn ra sớm hơn so với kế hoạch ban đầu."},"9511":{"word":"vị trí dẫn đầu","meaning":"Vị trí ở phía trước nhất của một nhóm, hoặc vai trò chính mà ai đó đảm nhận trong việc khởi xướng một hành động hoặc phong trào."},"9512":{"word":"nâng niu","meaning":"Diễn tả cách ai đó chăm sóc một người hoặc vật với tình yêu thương và sự chú ý tột độ, như thể nó rất đặc biệt."},"9513":{"word":"sự gắn bó","meaning":"Cảm giác yêu mến hoặc gắn bó mạnh mẽ đối với một người, động vật hoặc vật thể, khiến bạn muốn giữ chúng ở gần."},"9514":{"word":"bài hát yêu thích","meaning":"Một giai điệu và lời bài hát cụ thể mà ai đó thích hát hoặc nghe hơn bất kỳ bài nào khác."},"9515":{"word":"ban đầu","meaning":"Là giai đoạn hoặc thời điểm đầu tiên khi một điều gì đó mới bắt đầu hoặc được nghĩ đến."},"9516":{"word":"thiết tha, bâng khuâng","meaning":"Diễn tả cảm xúc yêu mến sâu sắc xen lẫn sự buồn bã nhẹ nhàng hoặc nỗi nhớ nhung."},"9517":{"word":"dạ quang","meaning":"Là vật liệu có khả năng phát ra ánh sáng dịu sau khi hấp thụ ánh sáng, ngay cả khi không có nguồn sáng khác."},"9518":{"word":"sự gây ra","meaning":"Hành động làm phát sinh hoặc khởi đầu một tình huống hay sự kiện không mong muốn."},"9519":{"word":"bị mắng, bị la rầy","meaning":"Bị người khác nói chuyện một cách giận dữ vì đã làm sai điều gì đó."},"9520":{"word":"đảng đối lập","meaning":"Là một đảng chính trị hiện không nắm quyền điều hành đất nước."},"9521":{"word":"thuốc, dược phẩm","meaning":"Là một chất được đưa vào cơ thể để chữa bệnh, giảm đau hoặc thay đổi chức năng sinh lý."},"9522":{"word":"xu hướng giảm, thế yếu","meaning":"Tình trạng giá cả hoặc giá trị trong hệ thống tài chính liên tục có xu hướng giảm xuống."},"9523":{"word":"nhỏ nhoi, khiêm tốn","meaning":"Diễn tả một vật không lớn, không sang trọng, thường được tặng như một món quà đơn giản."},"9524":{"word":"sự cướp bóc, sự hôi của","meaning":"Hành động tước đoạt một cách bạo lực các vật phẩm có giá trị từ một nơi hoặc một người, thường xảy ra trong xung đột hoặc xâm lược."},"9525":{"word":"người ích kỷ, người tư lợi","meaning":"Người chỉ hành động vì lợi ích của bản thân, thường bỏ qua sự đối xử công bằng hoặc nhu cầu của người khác."},"9526":{"word":"diện mạo, hình thái","meaning":"Là hình thức hoặc trạng thái cụ thể mà một sự vật, sự việc biểu hiện ra tại một thời điểm hoặc trong điều kiện nhất định."},"9527":{"word":"đào tạo, bồi dưỡng","meaning":"Quá trình giúp ai đó học hỏi và cải thiện kỹ năng, kiến thức để có thể đảm nhận một vai trò cụ thể."},"9528":{"word":"bình đẳng giới","meaning":"Tình trạng mọi cá nhân được đối xử và có cơ hội như nhau, không phân biệt giới tính."},"9529":{"word":"lương thực, thực phẩm dự trữ","meaning":"Thức ăn và những vật phẩm thiết yếu được tích trữ để duy trì sự sống."},"9530":{"word":"chất lượng tốt","meaning":"Tình trạng có phẩm chất hoặc giá trị cao."},"9531":{"word":"hai bên, đôi bên","meaning":"Hai nhóm hoặc cá nhân đối lập tham gia vào một cuộc thảo luận, đàm phán hoặc xung đột."},"9532":{"word":"coi thường, đánh giá thấp","meaning":"Nghĩ rằng ai đó hoặc điều gì đó kém khả năng, kém quan trọng hoặc kém giá trị hơn thực tế."},"9533":{"word":"sắc thái","meaning":"Cảm xúc tinh tế hoặc những ý tưởng bổ sung mà một từ hoặc cụm từ gợi ra ngoài nghĩa đen của nó."},"9534":{"word":"răng hàm","meaning":"Một chiếc răng lớn, có mặt nhai phẳng nằm ở phía sau miệng, dùng để nghiền thức ăn."},"9535":{"word":"không sai lệch","meaning":"Điều gì đó xảy ra chính xác như mong đợi hoặc đã hứa, mọi lúc."},"9536":{"word":"lờ mờ, nhập nhoạng","meaning":"Ánh sáng yếu dần, khiến khó nhìn rõ, thường là khi chiều tối đến."},"9537":{"word":"lờ mờ, mơ hồ","meaning":"Ghi nhớ hoặc nhìn thấy điều gì đó chỉ một phần hoặc hơi hơi, không hoàn toàn chi tiết hoặc rõ ràng."},"9538":{"word":"đọng lại, ứ đọng","meaning":"Chất lỏng hình thành trong mắt và tích tụ ở đó, thường xuất hiện ở mí mắt dưới."},"9539":{"word":"bối rối, ngơ ngác","meaning":"Cảm thấy rất ngạc nhiên và không thể hiểu được chuyện gì đang xảy ra, thường biểu hiện bằng vẻ mặt lạ lùng."},"9540":{"word":"khổng lồ, to lớn","meaning":"Rất lớn về kích thước, số lượng hoặc mức độ, vượt xa mức bình thường."},"9541":{"word":"ngư dân","meaning":"Người đánh bắt hải sản ở biển hoặc hồ để kiếm sống, hoặc cộng đồng người làm nghề này ở một khu vực nhất định."},"9542":{"word":"ngư ông đắc lợi","meaning":"Tình huống một bên thứ ba nhận được lợi ích bất ngờ do hai bên khác đang tranh chấp hoặc cạnh tranh với nhau."},"9543":{"word":"vụng về, lóng ngóng","meaning":"Thực hiện một hành động không khéo léo, thiếu sự phối hợp hoặc không tự nhiên, trông như chưa được luyện tập kỹ."},"9544":{"word":"lộn xộn, bừa bộn","meaning":"Chỉ một nơi đồ đạc bị vứt lung tung không theo trật tự, hoặc một tình huống cảm thấy rối ren và hỗn loạn."},"9545":{"word":"ngữ điệu, giọng điệu","meaning":"Chất lượng hoặc cách thức đặc biệt trong lời nói của một người, thể hiện cảm xúc hoặc thái độ của họ."},"9546":{"word":"làm lộn xộn, làm rối loạn","meaning":"Khiến một nơi trở nên bừa bộn do vứt đồ đạc lung tung, hoặc làm cho một người cảm thấy bối rối, khó chịu."},"9547":{"word":"lẽ thường, sự hợp lý (thường dùng trong phủ định)","meaning":"Sự hiểu biết cơ bản hoặc trí tuệ thực tế mà hầu hết mọi người đều có và dùng để đưa ra các quyết định hợp lý."},"9548":{"word":"vô lý, nực cười","meaning":"Rất không hợp lý hoặc phi logic đến mức gây sốc hoặc hoàn toàn không thể hiểu được."},"9549":{"word":"cách nói, giọng điệu","meaning":"Cách một người nói, bao gồm việc lựa chọn từ ngữ và âm thanh giọng nói, thể hiện cảm xúc hoặc thái độ của họ."},"9550":{"word":"cứng cáp, mạnh mẽ","meaning":"Cứng rắn, khó gãy hoặc uốn cong, hoặc ý chí, tính cách kiên cường, mạnh mẽ."},"9551":{"word":"mưa như trút","meaning":"Lượng nước mưa rất lớn đổ xuống một cách nhanh chóng và liên tục."},"9552":{"word":"sự đàn áp","meaning":"Tình trạng một nhóm người bị giữ lại hoặc đối xử tệ bởi luật lệ hay quyền lực không công bằng, hạn chế tự do của họ."},"9553":{"word":"sự cố chấp","meaning":"Lời nói hoặc hành động vô lý, bướng bỉnh, hoặc trái với lẽ tự nhiên, thường là do áp đặt."},"9554":{"word":"thoáng qua","meaning":"Nhìn hoặc hiểu một điều gì đó rất nhanh chỉ trong chốc lát, không nhìn kỹ hoặc cẩn thận."},"9555":{"word":"cơ quan báo chí","meaning":"Tổ chức thu thập và đưa tin tức đến công chúng thông qua báo chí, truyền hình, phát thanh hoặc internet."},"9556":{"word":"lời nói và hành động","meaning":"Cách một người nói và hành xử, thể hiện tính cách hoặc ý định của họ."},"9557":{"word":"bị đánh","meaning":"Bị người khác đánh bằng tay hoặc vật cứng một hay nhiều lần."},"9558":{"word":"tinh thần","meaning":"Tính cách sâu sắc, cốt lõi hoặc sức mạnh sống còn của một người hoặc một nhóm, đại diện cho sức mạnh nội tại và bản sắc của họ."},"9559":{"word":"nói ấp úng","meaning":"Nói không rõ ràng hoặc mơ hồ, thường là để tránh trả lời trực tiếp hoặc che giấu thông tin."},"9560":{"word":"thoáng qua","meaning":"Nhìn hoặc nghe một cái gì đó trong một thời gian rất ngắn, không chi tiết hoặc rõ ràng."},"9561":{"word":"bị ràng buộc","meaning":"Bị gắn bó chặt chẽ hoặc bị giới hạn bởi các quy tắc, phong tục hoặc cảm xúc, khiến khó hành động tự do."},"9562":{"word":"lòng dũng cảm","meaning":"Ý nghĩ hoặc sự sẵn lòng trong tâm trí để làm một việc gì đó khó khăn hoặc đáng sợ."},"9563":{"word":"nghiêm ngặt","meaning":"Tả sự kiểm soát, quy tắc hay hình phạt rất chặt chẽ và nghiêm túc."},"9564":{"word":"ngón tay cái","meaning":"Ngón tay to nhất và ngắn nhất trên bàn tay, nằm tách biệt với bốn ngón kia."},"9565":{"word":"cơ sở kinh doanh","meaning":"Nơi tập trung các cửa hàng hoặc cơ sở kinh doanh nhỏ."},"9566":{"word":"người kinh doanh","meaning":"Người làm việc hoặc kinh doanh trong một lĩnh vực, ngành nghề cụ thể."},"9567":{"word":"loại hình kinh doanh","meaning":"Một loại hình hoạt động thương mại hoặc ngành nghề cụ thể."},"9568":{"word":"đi ngược chiều","meaning":"Hai hay nhiều vật thể di chuyển theo các hướng khác nhau, không cùng hướng."},"9569":{"word":"lê lết chầm chậm","meaning":"Di chuyển về phía trước bằng tay và đầu gối một cách chậm rãi, từng chút một."},"9570":{"word":"đông lại","meaning":"Chất lỏng hoặc chất mềm chuyển sang trạng thái đặc hơn, cứng hơn, tạo thành khối dính hoặc cục."},"9571":{"word":"sơ sài","meaning":"Không được gọn gàng, ngăn nắp, các bộ phận rời rạc hoặc sắp xếp kém."},"9572":{"word":"bị rối","meaning":"Các vật dài, mỏng như dây, sợi hay tóc bị xoắn vào nhau thành một mớ lộn xộn."},"9573":{"word":"lật đổ","meaning":"Làm cho vật gì đó như bàn hoặc chén bị lật nghiêng, lật úp, thường khiến đồ bên trong rơi ra."},"9574":{"word":"bao vây","meaning":"Đặt người hoặc vật xung quanh một cái gì đó hoặc ai đó, tạo thành một vòng tròn bao kín hoàn toàn."},"9575":{"word":"đảng cầm quyền","meaning":"Đây là đảng chính trị đang nắm giữ quyền lực và điều hành chính phủ của một quốc gia."},"9576":{"word":"nữ (dùng cho chức danh chuyên nghiệp)","meaning":"Từ dùng để chỉ người phụ nữ làm một nghề nghiệp chuyên môn nhất định, ví dụ như nhà văn hay họa sĩ."},"9577":{"word":"yếu ớt, mỏng manh","meaning":"Chỉ cái gì đó mềm mại, nhạy cảm, dễ bị tổn thương hoặc hư hại."},"9578":{"word":"hình mẫu phụ nữ","meaning":"Đây là hình ảnh, kiểu mẫu tiêu biểu hoặc mong muốn về cách một người phụ nữ nên trông như thế nào hoặc hành xử ra sao trong xã hội."},"9579":{"word":"nữ tính","meaning":"Mô tả những đặc điểm, hành vi hoặc vẻ ngoài truyền thống được liên kết với phụ nữ và các bé gái."},"9580":{"word":"bé gái","meaning":"Chỉ một đứa trẻ sơ sinh hoặc nhỏ tuổi được xác định là con gái."},"9581":{"word":"các đảng cầm quyền và đối lập","meaning":"Thuật ngữ này chỉ chung cả đảng đang nắm quyền điều hành chính phủ và các đảng chính trị khác không cầm quyền trong một hệ thống chính trị quốc gia."},"9582":{"word":"mất (người thân)","meaning":"Trải qua việc một thành viên thân thiết trong gia đình qua đời, không còn hiện diện về mặt thể chất nữa."},"9583":{"word":"chỗ trống, khả năng","meaning":"Một không gian hoặc cơ hội có sẵn cho phép các lựa chọn hoặc khả năng khác nhau được xem xét."},"9584":{"word":"hậu quả, dư chấn","meaning":"Ảnh hưởng hoặc kết quả kéo theo một sự kiện lớn, thường là không mong muốn."},"9585":{"word":"buồn nôn, ghê tởm","meaning":"Cực kỳ khó chịu, khiến một người cảm thấy bệnh và muốn nôn mửa."},"9586":{"word":"nghịch cảnh, khó khăn","meaning":"Một tình huống rất khó khăn hoặc thử thách, tạo ra vấn đề và gây khó khăn trong việc đạt được điều gì đó."},"9587":{"word":"từ trước đến nay","meaning":"Diễn tả tất cả những người hoặc vật cùng loại đã xuất hiện liên tiếp từ một điểm bắt đầu cho đến hiện tại."},"9588":{"word":"cử tạ","meaning":"Một môn thể thao mà người chơi cố gắng nâng những vật nặng có đĩa tròn lên trên đầu."},"9589":{"word":"năng động","meaning":"Diễn tả cái gì đó thể hiện nhiều năng lượng, sự chuyển động và thay đổi liên tục."},"9590":{"word":"năng lực","meaning":"Khả năng và sức mạnh tự nhiên hoặc được học hỏi của một người để thực hiện nhiệm vụ hoặc đạt được mục tiêu một cách hiệu quả."},"9591":{"word":"đặt mình vào vị trí người khác","meaning":"Việc xem xét một vấn đề hoặc tình huống bằng cách tưởng tượng mình là người khác có liên quan và suy nghĩ về cảm xúc hoặc quan điểm của họ."},"9592":{"word":"phản tác dụng","meaning":"Một kết quả xấu không mong muốn xảy ra khi một hành động hoặc kế hoạch gây ra vấn đề thay vì đạt được kết quả tốt mong muốn."},"9593":{"word":"liên kết","meaning":"Khi hai hoặc nhiều thứ được nối lại hoặc liên quan với nhau theo cách tạo ra một con đường hoặc mối quan hệ liên tục giữa chúng."},"9594":{"word":"niên đại","meaning":"Một khoảng thời gian cụ thể, thường là dài, được đánh dấu bằng các sự kiện hoặc đặc điểm độc đáo làm nó khác biệt."},"9595":{"word":"nhiên liệu","meaning":"Bất kỳ vật liệu nào, chẳng hạn như xăng, than, hoặc gỗ, được đốt cháy hoặc tiêu thụ để tạo ra năng lượng cho động cơ hoặc sưởi ấm."},"9596":{"word":"hiệu suất nhiên liệu","meaning":"Một thước đo quãng đường mà phương tiện có thể đi được khi sử dụng một lượng nhiên liệu cụ thể, cho thấy nó tiêu thụ nhiều hay ít để di chuyển."},"9597":{"word":"hơn tuổi","meaning":"Tình trạng có nhiều tuổi hơn một người khác."},"9598":{"word":"yếu đuối","meaning":"Một người hoặc vật tinh tế, dễ bị tổn thương hoặc dễ vỡ."},"9599":{"word":"lưu luyến","meaning":"Không muốn buông bỏ hoặc rời xa một điều gì đó."},"9600":{"word":"liên tiếp","meaning":"Sự việc hoặc hiện tượng xảy ra kế tiếp nhau không ngừng."},"9601":{"word":"người lớn tuổi","meaning":"Người có tuổi tác lớn hơn so với người khác."},"9602":{"word":"đăng nhiều kỳ","meaning":"Việc xuất bản một tác phẩm như truyện hoặc bài viết thành nhiều phần riêng biệt theo định kỳ."},"9603":{"word":"đầu năm","meaning":"Khoảng thời gian bắt đầu của một năm, thường là tháng Giêng."},"9604":{"word":"liệt kê","meaning":"Hành động kể ra từng mục, từng sự việc một cách rõ ràng và có thứ tự."},"9605":{"word":"cuồng nhiệt","meaning":"Trạng thái cực kỳ phấn khích, nhiệt tình và say mê của nhiều người."},"9606":{"word":"sôi nổi","meaning":"Mô tả một cuộc thảo luận hoặc sự kiện diễn ra đầy năng lượng và cảm xúc mạnh mẽ."},"9607":{"word":"khát khao","meaning":"Một ước muốn rất sâu sắc và mãnh liệt đối với điều gì đó."},"9608":{"word":"lặn","meaning":"(Trong di truyền học) Đặc tính chỉ biểu hiện ra bên ngoài khi không có gen trội."},"9609":{"word":"nhiệt tình","meaning":"Thể hiện rất nhiều năng lượng, sự quan tâm và sự cống hiến đối với một hoạt động hoặc mục đích."},"9610":{"word":"tồi tệ","meaning":"Mô tả một tình huống hoặc điều kiện rất xấu, thiếu thốn hoặc chất lượng cực kỳ thấp."},"9611":{"word":"cơn sốt, trào lưu","meaning":"Sự hứng thú hoặc quan tâm mãnh liệt, lan rộng nhanh chóng trong cộng đồng về một điều gì đó."},"9612":{"word":"sự lưu tâm, sự cân nhắc","meaning":"Trạng thái suy nghĩ kỹ lưỡng hoặc giữ một điều gì đó trong tâm trí khi lên kế hoạch hay quyết định."},"9613":{"word":"sự lo lắng, nỗi lo","meaning":"Cảm giác không yên lòng hoặc hơi lo lắng về một sự kiện hoặc tình huống tiêu cực có thể xảy ra trong tương lai."},"9614":{"word":"khát vọng, nguyện vọng","meaning":"Một mong muốn rất mạnh mẽ và nghiêm túc để điều gì đó trở thành hiện thực, thường được nhiều người cùng cảm thấy."},"9615":{"word":"viêm, sưng viêm","meaning":"Tình trạng một bộ phận cơ thể sưng lên, đỏ, nóng và đau, thường do chấn thương hoặc bệnh tật."},"9616":{"word":"lòng tự trọng, sự xấu hổ","meaning":"Cảm giác xấu hổ hoặc tội lỗi khiến một người cảm thấy tồi tệ về hành động của mình, thường khiến họ không thể đối mặt với người khác."},"9617":{"word":"vinh quang, danh dự","meaning":"Mức độ tôn trọng, khen ngợi công khai hoặc danh tiếng rất cao đến từ một thành tựu vĩ đại hoặc hành động đáng ngưỡng mộ."},"9618":{"word":"y hệt, không sai chút nào","meaning":"Miêu tả một điều gì đó chính xác như mong đợi hoặc chính xác giống hệt một điều khác, không để lại chút nghi ngờ nào."},"9619":{"word":"lợi nhuận, kiếm lời","meaning":"Hành động hoặc mục tiêu kiếm tiền bằng cách bán sản phẩm hoặc cung cấp dịch vụ với giá cao hơn chi phí."},"9620":{"word":"lý do, nguyên nhân","meaning":"Nguyên nhân hoặc lời giải thích cho việc tại sao điều gì đó xảy ra, mà thường không được ai đó biết hoặc hiểu rõ."},"9621":{"word":"văn bản tiếng Anh, chữ tiếng Anh","meaning":"Các từ hoặc câu được viết bằng ngôn ngữ được nói ở các quốc gia như Vương quốc Anh hoặc Hoa Kỳ."},"9622":{"word":"người nghèo khổ, dân nghèo","meaning":"Những người có rất ít tiền bạc và tài nguyên, thường phải vật lộn để đáp ứng các nhu cầu cơ bản như thức ăn và chỗ ở."},"9623":{"word":"chuyên gia dinh dưỡng","meaning":"Người có chuyên môn về dinh dưỡng, đưa ra lời khuyên về chế độ ăn uống lành mạnh để giữ gìn sức khỏe."},"9624":{"word":"tuyển mộ","meaning":"Hành động tìm kiếm và đưa các thành viên mới như cầu thủ hay nhân viên vào một đội hay tổ chức."},"9625":{"word":"lệnh","meaning":"Giấy tờ chính thức do tòa án cấp, cho phép cơ quan thực thi pháp luật thực hiện một hành động cụ thể như khám xét hay bắt giữ."},"9626":{"word":"thần đồng","meaning":"Người trẻ tuổi có tài năng hoặc trí thông minh phi thường so với tuổi của họ trong một lĩnh vực cụ thể."},"9627":{"word":"lãnh thổ","meaning":"Một khu vực đất đai được kiểm soát bởi một quốc gia, bang hoặc chính phủ cụ thể."},"9628":{"word":"tiên đoán","meaning":"Hành động nhìn thấy hoặc nói trước những gì sẽ xảy ra trong tương lai, thường dựa trên các dấu hiệu hiện tại."},"9629":{"word":"sắc bén","meaning":"Có lưỡi rất mỏng hoặc đầu rất nhọn, có thể dễ dàng cắt hoặc đâm xuyên mọi thứ."},"9630":{"word":"buổi lễ thờ phượng","meaning":"Buổi họp mặt chính thức của một nhóm người tại nơi linh thiêng để cầu nguyện, hát thánh ca hoặc nghe giảng giáo lý tôn giáo."},"9631":{"word":"thông thường","meaning":"Một điều hay sự việc quen thuộc, không đặc biệt hay bất ngờ, và thường xuyên xảy ra."},"9632":{"word":"Chúa Giê-su","meaning":"Người sáng lập Kitô giáo, được các tín đồ coi là Con Thiên Chúa và Đấng Cứu Thế."},"9633":{"word":"tính nghệ thuật","meaning":"Những đặc điểm của một tác phẩm hội họa, âm nhạc hay biểu diễn khiến nó đẹp đẽ, biểu cảm và được thực hiện một cách khéo léo, tạo ra tác động cảm xúc mạnh mẽ."},"9634":{"word":"phép tắc","meaning":"Các quy tắc ứng xử lịch sự thông thường trong xã hội, thể hiện sự tôn trọng đối với người khác qua hành động và lời nói."},"9635":{"word":"nghệ thuật và thể dục thể thao","meaning":"Các môn học ở trường liên quan đến hoạt động sáng tạo như vẽ, âm nhạc, diễn xuất và các bài tập thể thao, vận động cơ thể."},"9636":{"word":"tính ương ngạnh","meaning":"Thái độ bướng bỉnh, không chịu thua kém dù không có năng lực hoặc khả năng."},"9637":{"word":"đường dốc lên","meaning":"Con đường có địa hình nghiêng lên cao, đi lên dốc."},"9638":{"word":"cánh tay phải","meaning":"Bộ phận cơ thể ở phía bên phải mà hầu hết mọi người dùng để viết hoặc ném, đối diện với cánh tay trái."},"9639":{"word":"ấm cúng","meaning":"Cảm giác hoặc bầu không khí dễ chịu, riêng tư, thoải mái và ấm áp, đặc biệt là cho một nhóm nhỏ người."},"9640":{"word":"đến mức nào","meaning":"Dùng để diễn tả một sự việc đạt đến mức độ cực kỳ cao, thường khi người nói có cảm xúc mạnh như thất vọng hoặc ngạc nhiên."},"9641":{"word":"sân thượng","meaning":"Phần mái bằng của một tòa nhà hiện đại, được làm phẳng để có thể sử dụng cho nhiều mục đích khác nhau."},"9642":{"word":"khí nhà kính","meaning":"Các loại khí trong không khí Trái Đất có khả năng giữ nhiệt từ mặt trời, làm cho hành tinh ấm hơn giống như bức tường kính của một nhà kính trồng cây."},"9643":{"word":"nguyên vẹn","meaning":"Một vật thể hoặc cấu trúc còn đầy đủ, không bị hư hại hay thiếu bất kỳ bộ phận nào."},"9644":{"word":"đúng đắn","meaning":"Làm điều gì đó một cách đúng đắn, chính xác hoặc phù hợp với tình huống, không mắc lỗi hay sai sót."},"9645":{"word":"cổ áo","meaning":"Dải vải trên áo sơ mi, áo khoác hoặc áo choàng được gấp lại hoặc dựng đứng gần cổ."},"9646":{"word":"vạt áo","meaning":"Phần mép dưới của một bộ quần áo, đặc biệt là váy hoặc áo, thường rủ xuống."},"9647":{"word":"túm tụm","meaning":"Chỉ trạng thái nhiều vật nhỏ hoặc người tập trung lại gần nhau, tạo thành hình dáng không đều."},"9648":{"word":"thoai thoải","meaning":"Có độ dốc không cao, lên xuống nhẹ nhàng, dễ đi lại."},"9649":{"word":"hoàn thành chặng đua","meaning":"Việc chạy hết toàn bộ quãng đường của một cuộc thi đấu thể thao và vượt qua vạch đích."},"9650":{"word":"sự nới lỏng","meaning":"Việc làm cho quy định bớt nghiêm ngặt hoặc làm cho tình hình khó khăn trở nên nhẹ nhàng hơn."},"9651":{"word":"sự tranh cãi","meaning":"Tình huống mọi người liên tục thảo luận về một chủ đề, đưa ra cả quan điểm ủng hộ và phản đối."},"9652":{"word":"hoàng cung","meaning":"Một tòa nhà rất lớn và lộng lẫy, là nơi ở chính thức của vua, hoàng hậu hoặc hoàng đế."},"9653":{"word":"vương quyền","meaning":"Quyền lực và quyền cai trị mà một vị vua hoặc nữ hoàng sở hữu đối với đất nước và thần dân của họ."},"9654":{"word":"ngai vàng","meaning":"Vị trí người cai trị tối cao trong một vương quốc, thường được biểu tượng bằng chiếc ghế đặc biệt nơi nhà vua ngồi."},"9655":{"word":"triều đại","meaning":"Một chuỗi các vị vua thuộc cùng một gia đình cai trị một quốc gia; hoặc thời kỳ mà những vị vua đó cai trị."},"9656":{"word":"sự bóp méo","meaning":"Hành động làm sai lệch sự thật, ý tưởng hoặc hình ảnh để chúng trông khác đi so với hình dạng ban đầu hoặc đúng bản chất."},"9657":{"word":"nhỏ bé","meaning":"Có vóc dáng nhỏ hơn hoặc yếu ớt hơn đáng kể so với mức bình thường, khiến trông có vẻ mảnh mai hoặc yếu ớt."},"9658":{"word":"Bộ Ngoại giao","meaning":"Một bộ phận của chính phủ chịu trách nhiệm xử lý các mối quan hệ và thỏa thuận của một quốc gia với các nước khác và các quan chức của họ."},"9659":{"word":"tin tức nước ngoài","meaning":"Thông tin hoặc báo cáo về các sự kiện, con người hay tình hình ở nước ngoài."},"9660":{"word":"ngoài mềm trong cứng","meaning":"Người có vẻ ngoài hiền lành, ôn hòa nhưng bên trong lại mạnh mẽ, kiên cường và quyết đoán."},"9661":{"word":"bên ngoài","meaning":"Thuộc về bề mặt hoặc đến từ bên ngoài một đối tượng, người hoặc tình huống cụ thể."},"9662":{"word":"hàng ngoại","meaning":"Sản phẩm được sản xuất hoặc lắp ráp ở một quốc gia khác với quốc gia mà nó được mua hoặc sử dụng."},"9663":{"word":"ngoại hình","meaning":"Hình dạng, hình thức và vẻ tổng thể có thể nhìn thấy được của một vật thể hoặc người khi nhìn từ bên ngoài."},"9664":{"word":"mang tính bề ngoài","meaning":"Mô tả điều gì đó có thể nhìn thấy hoặc đáng chú ý ở bề mặt, hoặc liên quan đến khía cạnh bên ngoài của một người hay vật."},"9665":{"word":"ngoại hối","meaning":"Hệ thống liên quan đến việc chuyển đổi tiền tệ của một quốc gia sang tiền tệ của quốc gia khác, thường là cho thương mại hoặc đầu tư quốc tế."},"9666":{"word":"điều kiện","meaning":"Một điều cụ thể cần phải có hoặc hoàn thành để một việc khác được coi là hợp lệ hoặc hoàn chỉnh."},"9667":{"word":"ồn ào","meaning":"Tình huống có nhiều âm thanh lớn và hoạt động hoặc sự hưng phấn đáng chú ý, thường là quá mức."},"9668":{"word":"điều dưỡng","meaning":"Khoảng thời gian một người nghỉ ngơi và được chăm sóc để phục hồi sức khỏe sau một trận ốm hoặc chấn thương."},"9669":{"word":"viện dưỡng lão","meaning":"Cơ sở có đầy đủ tiện nghi cho phép người ốm chăm sóc sức khỏe và nhận được sự chăm sóc y tế trong khi nghỉ ngơi."},"9670":{"word":"điểm chính","meaning":"Ý tưởng hoặc thông tin quan trọng nhất trong một cuộc trò chuyện, văn bản hoặc bài nói, mà mọi thứ khác đều hỗ trợ."},"9671":{"word":"tóm lại","meaning":"Dùng để kết luận hoặc tóm tắt ý chính của một vấn đề sau khi đã giải thích dài dòng."},"9672":{"word":"du thuyền","meaning":"Một loại thuyền nhỏ, nhẹ, nhanh, dùng để đi dạo, du ngoạn hoặc đua."},"9673":{"word":"ví dụ sử dụng","meaning":"Câu hoặc cụm từ cho thấy rõ cách một từ hoặc cụm từ được dùng trong thực tế."},"9674":{"word":"dung mạo","meaning":"Tổng thể vẻ ngoài của một người, bao gồm khuôn mặt, hình dáng cơ thể và cách ăn mặc."},"9675":{"word":"cách dùng","meaning":"Cách thức hoặc hướng dẫn cụ thể để áp dụng hoặc vận hành một thứ gì đó."},"9676":{"word":"nghi phạm","meaning":"Người bị cảnh sát hoặc người khác nghi ngờ đã phạm tội nhưng chưa có bằng chứng xác thực."},"9677":{"word":"dễ dàng","meaning":"Miêu tả một công việc hoặc quá trình có thể thực hiện được mà không cần nhiều nỗ lực hay khó khăn."},"9678":{"word":"tài giỏi","meaning":"Miêu tả người rất giỏi làm việc khó, hoặc cái gì đó rất hiệu quả để đạt được kết quả mong muốn."},"9679":{"word":"rậm rạp","meaning":"Miêu tả một khu vực cây cối, thực vật mọc rất dày đặc, che phủ một không gian rộng."},"9680":{"word":"não phải","meaning":"Phần não bộ nằm ở bên phải đầu, có nhiệm vụ điều khiển nửa bên trái của cơ thể."},"9681":{"word":"sừng sững","meaning":"Ở trạng thái vươn cao, nổi bật một cách vững chãi và ấn tượng."},"9682":{"word":"tỏa ra","meaning":"Diễn tả một cảm xúc, hương vị hay phẩm chất dần dần xuất hiện từ bên trong và trở nên rõ rệt."},"9683":{"word":"vang dội","meaning":"Một âm thanh rất mạnh mẽ, rõ ràng và có thể lan truyền xa, thường lấp đầy cả không gian."},"9684":{"word":"ngẫu nhiên","meaning":"Chỉ sự việc xảy ra đột ngột, không được dự tính hay sắp đặt trước."},"9685":{"word":"ưu tiên","meaning":"Là điều quan trọng nhất cần được thực hiện hoặc xử lý trước những điều khác."},"9686":{"word":"tính trội","meaning":"Trong di truyền học, chỉ đặc tính luôn biểu hiện ở sinh vật khi gen tương ứng của nó có mặt."},"9687":{"word":"ưu thế","meaning":"Trạng thái một cá nhân, nhóm hay sự vật có sức mạnh, khả năng vượt trội hoặc kiểm soát hơn những cái khác."},"9688":{"word":"lố bịch","meaning":"Mang tính chất rất kỳ lạ và gây cười vì vẻ ngoài hoặc cách hành xử ngớ ngẩn."},"9689":{"word":"thăng trầm","meaning":"Một chuỗi các sự kiện bất ngờ, khó khăn hoặc thay đổi khiến một quá trình hoặc hành trình trở nên phức tạp và gập ghềnh."},"9690":{"word":"ưu nhược","meaning":"Tình trạng tốt hơn hoặc kém hơn, mạnh hơn hoặc yếu hơn so với người hoặc vật khác."},"9691":{"word":"ưu việt","meaning":"Trạng thái hoặc cảm giác có chất lượng, thứ hạng hoặc khả năng cao hơn người khác."},"9692":{"word":"lợi thế","meaning":"Vị trí tốt hơn hoặc thuận lợi hơn những người khác, mang lại cho một cá nhân hay nhóm cơ hội thành công lớn hơn."},"9693":{"word":"chất phác","meaning":"Chỉ tính cách chất phác, thật thà nhưng đôi khi cứng nhắc hoặc thiếu linh hoạt."},"9694":{"word":"cánh hữu","meaning":"Một trong những nhóm hoặc hệ tư tưởng chính trị chủ yếu, thường ủng hộ truyền thống và giảm sự can thiệp của chính phủ."},"9695":{"word":"thân thiện","meaning":"Có tình cảm, thái độ tốt bụng, sẵn lòng giúp đỡ người khác."},"9696":{"word":"mọc lên như nấm","meaning":"Diễn tả nhiều thứ xuất hiện hoặc tăng lên về số lượng rất nhanh, giống như nấm mọc sau mưa."},"9697":{"word":"vận hành, điều hành","meaning":"Quá trình điều khiển và sử dụng một cái gì đó, như một doanh nghiệp hay hệ thống, để nó hoạt động hiệu quả."},"9698":{"word":"chuyến bay, chuyến đi (tàu)","meaning":"Hành động điều khiển tàu thuyền trên mặt nước hoặc máy bay trên không từ nơi này đến nơi khác."},"9699":{"word":"tim đập thình thịch","meaning":"Tim cứ đập liên hồi vì giật mình hoặc sợ hãi bởi một điều gì đó."},"9700":{"word":"rơm rớm nước mắt","meaning":"Biểu hiện những dấu hiệu buồn bã, như môi run rẩy hoặc mắt ướt nhòe, như thể nước mắt sắp trào ra."},"9701":{"word":"gào thét, tru tréo","meaning":"Phát ra tiếng kêu lớn, kéo dài, thường biểu hiện sự đau buồn hoặc đau đớn tột độ, như tiếng kêu của động vật gặp nạn."},"9702":{"word":"rậm rạp, um tùm","meaning":"Diễn tả một khu vực có nhiều cây cối mọc san sát nhau, tạo nên vẻ dày đặc và xanh tốt."},"9703":{"word":"gồ ghề, lồi lõm","meaning":"Mô tả cách một bề mặt không bằng phẳng, có chỗ lồi chỗ lõm."},"9704":{"word":"gồ ghề, không bằng phẳng","meaning":"Miêu tả một bề mặt không nhẵn, có nhiều chỗ nhô lên và lõm xuống, không bằng phẳng."},"9705":{"word":"co rúm, rụt người lại","meaning":"Kéo tay và chân sát vào người, làm cho cơ thể nhỏ lại, thường là do lạnh hoặc sợ hãi."},"9706":{"word":"nắm chặt, vồ lấy","meaning":"Nhanh chóng nắm giữ một vật gì đó thật chặt bằng tay, như thể muốn ngăn không cho nó thoát ra."},"9707":{"word":"nắm chặt","meaning":"Giữ một vật gì đó rất chặt trong tay, thường là với các ngón tay siết chặt lại."},"9708":{"word":"vượt quá","meaning":"Có số lượng hoặc mức độ lớn hơn một giới hạn hoặc tiêu chuẩn cụ thể."},"9709":{"word":"ồn ào, xôn xao","meaning":"Diễn tả âm thanh hoặc cách nhiều người cùng nói chuyện ồn ào với giọng thấp."},"9710":{"word":"hùng vĩ, tráng lệ","meaning":"Miêu tả cái gì đó rất lớn, ấn tượng và đẹp đẽ, gây cảm giác choáng ngợp, kinh ngạc."},"9711":{"word":"co ro, cuộn mình","meaning":"Gập người xuống bằng cách uốn cong đầu gối và kéo các chi sát lại, thường để làm cho cơ thể nhỏ lại hoặc giữ ấm."},"9712":{"word":"nguyên-, sơ-","meaning":"Thành tố đứng ở đầu từ, biểu thị một vật gì đó ở dạng ban đầu hoặc chưa được thay đổi hay xử lý."},"9713":{"word":"-viên, -nguyên","meaning":"Thành tố đứng ở cuối từ, thường chỉ một nơi cụ thể nơi mọi người tụ tập vì một mục đích hoặc một khu đất được trồng trọt."},"9714":{"word":"giá vốn, giá thành","meaning":"Tổng số tiền mà một công ty bỏ ra để sản xuất một mặt hàng hoặc dịch vụ trước khi bán."},"9715":{"word":"từ xa","meaning":"Miêu tả một cái gì đó xảy ra hoặc được kiểm soát từ một khoảng cách xa, không phải ở gần."},"9716":{"word":"nguyên đơn","meaning":"Người khởi kiện, người đưa vụ việc ra tòa án."},"9717":{"word":"tiền gốc, vốn gốc","meaning":"Số tiền ban đầu được vay hoặc cho vay, không bao gồm tiền lãi phát sinh."},"9718":{"word":"động lực, sức đẩy","meaning":"Thứ tạo ra sức mạnh hoặc lực thúc đẩy mạnh mẽ cần thiết để một máy móc hoạt động hoặc một tình huống phát triển."},"9719":{"word":"nguyên liệu","meaning":"Vật liệu cơ bản được lấy từ tự nhiên hoặc nông nghiệp để sản xuất ra các sản phẩm khác."},"9720":{"word":"màu cơ bản","meaning":"Mô tả màu sắc rất thuần khiết và tươi sáng, chưa pha trộn, ví dụ như đỏ, xanh lam, vàng."},"9721":{"word":"nguyên thủy","meaning":"Giai đoạn sớm nhất hoặc ban đầu của một sự vật, sự việc nào đó."},"9722":{"word":"lực ly tâm","meaning":"Lực làm cho vật thể chuyển động cong có xu hướng văng ra xa tâm quay."},"9723":{"word":"người bản ngữ","meaning":"Người đã học và sử dụng một ngôn ngữ cụ thể từ nhỏ ở nơi mà ngôn ngữ đó là chính."},"9724":{"word":"viện trợ","meaning":"Sự giúp đỡ hoặc hỗ trợ, thường dưới dạng tiền bạc, lương thực, vật tư, được cung cấp cho một quốc gia hay nhóm người khác."},"9725":{"word":"người bản địa","meaning":"Những nhóm người đầu tiên sinh sống và hình thành văn hóa trên một vùng đất nhất định trước khi những người khác đến định cư."},"9726":{"word":"nguyên bản","meaning":"Hình dạng, thiết kế hoặc trạng thái ban đầu của một vật trước khi nó bị thay đổi."},"9727":{"word":"thông suốt","meaning":"Trạng thái mà một quá trình hay sự giao tiếp diễn ra dễ dàng, không gặp trở ngại."},"9728":{"word":"hàng tháng","meaning":"Mô tả một ấn phẩm hay báo cáo được xuất bản hoặc xuất hiện mỗi tháng một lần."},"9729":{"word":"ngày nghỉ hàng tháng","meaning":"Ngày nghỉ làm việc có lương mà người lao động được phép hưởng một lần mỗi tháng."},"9730":{"word":"sức khỏe và hạnh phúc","meaning":"Trạng thái cảm thấy khỏe mạnh, hạnh phúc và thoải mái tổng thể trong cuộc sống."},"9731":{"word":"trật tự cấp bậc","meaning":"Một hệ thống trong đó con người hoặc sự vật được sắp xếp theo các cấp độ quan trọng hoặc quyền lực khác nhau."},"9732":{"word":"nguy kịch","meaning":"Tình trạng sức khỏe cực kỳ kém và tính mạng đang gặp nguy hiểm lớn."},"9733":{"word":"uy lực","meaning":"Sức mạnh hoặc năng lực mãnh liệt của một thứ gì đó, có thể tạo ra những ảnh hưởng hoặc thay đổi lớn."},"9734":{"word":"vị thế","meaning":"Mức độ tôn trọng, tầm quan trọng hoặc ảnh hưởng mà một người hay một vật có được so với những người khác."},"9735":{"word":"hợp vệ sinh","meaning":"Miêu tả cái gì đó rất sạch sẽ và ngăn ngừa sự lây lan của vi trùng hoặc bệnh tật."},"9736":{"word":"vệ tinh","meaning":"Các thiên thể trong vũ trụ quay quanh các hành tinh."},"9737":{"word":"sự an ủi","meaning":"Cảm giác bình yên và nhẹ nhõm dễ chịu khi ai đó buồn bã, lo lắng hoặc đau khổ."},"9738":{"word":"ung thư dạ dày","meaning":"Bệnh nghiêm trọng khi các tế bào có hại phát triển ngoài tầm kiểm soát bên trong dạ dày."},"9739":{"word":"ủy viên","meaning":"Người được bầu hoặc bổ nhiệm để chịu trách nhiệm thực hiện một việc gì đó cho một mục đích đặc biệt trong một nhóm."},"9740":{"word":"vĩ nhân","meaning":"Cá nhân đã đạt được những điều phi thường và được nhiều người kính trọng, ngưỡng mộ rộng rãi."},"9741":{"word":"một kẻ (miệt thị)","meaning":"Từ miệt thị dùng để chỉ một người đàn ông hoặc phụ nữ, thường ngụ ý họ vô giá trị hoặc đáng khinh."},"9742":{"word":"sự giả mạo","meaning":"Hành động bất hợp pháp tạo ra một bản sao sai lệch của tiền bạc, tài liệu hoặc tranh vẽ để lừa dối người khác."},"9743":{"word":"sự teo lại, sự thu hẹp","meaning":"Đây là quá trình một bộ phận nào đó, như tế bào hoặc nền kinh tế, trở nên nhỏ hơn, yếu hơn hoặc ít hoạt động hơn theo thời gian."},"9744":{"word":"nguy hiểm, bấp bênh","meaning":"Từ này dùng để miêu tả một tình huống hoặc đối tượng rất không ổn định, nguy hiểm và có khả năng đổ vỡ hoặc bị hư hại nghiêm trọng."},"9745":{"word":"cảm giác xa lạ, cảm giác bất hòa","meaning":"Đây là cảm giác khó chịu hoặc lúng túng khi điều gì đó có vẻ rất khác biệt hoặc lạc lõng so với môi trường xung quanh hay những người khác."},"9746":{"word":"sự tồn tại, có","meaning":"Đây là trạng thái của việc có thật, hiện diện thực sự hoặc xảy ra trong thế giới."},"9747":{"word":"giá dầu","meaning":"Đây là số tiền cần thiết để mua dầu mỏ, một loại chất lỏng đen được lấy từ lòng đất và dùng để sản xuất nhiên liệu."},"9748":{"word":"sự tiếc nuối, điều đáng tiếc","meaning":"Đây là cảm giác buồn bã, thất vọng hoặc hối tiếc về điều gì đó đã xảy ra hoặc điều gì đó mình đã làm."},"9749":{"word":"hài cốt, xương cốt","meaning":"Đây là những bộ xương còn lại sau khi thi thể người chết được hỏa táng, hoặc xương được tìm thấy trong mộ."},"9750":{"word":"cử tri","meaning":"Người này là một công dân được pháp luật cho phép chọn ra các nhà lãnh đạo bằng cách bỏ phiếu trong một cuộc bầu cử."},"9751":{"word":"kì cục, quá mức, phô trương","meaning":"Từ này miêu tả một cách hành động hoặc vẻ ngoài rất khoa trương và thu hút nhiều sự chú ý, đôi khi một cách khó chịu."},"9752":{"word":"tình đoàn kết, sự gắn kết","meaning":"Đây là một cảm giác mạnh mẽ về sự gần gũi, thống nhất và kết nối chung mà mọi người cảm thấy với nhau."},"9753":{"word":"môn võ Judo","meaning":"Đây là một môn võ thuật Nhật Bản trong đó hai người, mặc trang phục màu trắng, cố gắng vật hoặc đè đối phương xuống đất."},"9754":{"word":"đặc biệt, riêng, kì lạ","meaning":"Từ này miêu tả cách điều gì đó xảy ra một cách độc đáo hoặc đáng chú ý rõ rệt so với những thời điểm hay điều khác."},"9755":{"word":"sự lưu động","meaning":"Trạng thái di chuyển không cố định từ nơi này sang nơi khác của người hoặc vật."},"9756":{"word":"linh hoạt","meaning":"Chỉ tình huống, kế hoạch hoặc vật thể có thể dễ dàng thay đổi hình dạng, vị trí hoặc đặc tính."},"9757":{"word":"tiền lệ","meaning":"Sự việc hoặc hành động đã xảy ra trước đó, dùng làm ví dụ hoặc quy tắc cho tình huống tương tự sau này."},"9758":{"word":"sự gây ra","meaning":"Hành động làm cho một điều gì đó bắt đầu hoặc xuất hiện, thường dẫn đến một kết quả hoặc phản ứng cụ thể."},"9759":{"word":"hữu bị vô hoạn","meaning":"Một câu nói mang ý nghĩa rằng nếu chuẩn bị kỹ lưỡng trước các khó khăn tiềm tàng, sẽ tránh được những vấn đề trong tương lai."},"9760":{"word":"di chúc","meaning":"Văn bản ghi lại ý nguyện của một người để lại sau khi qua đời."},"9761":{"word":"vận động tranh cử","meaning":"Bài phát biểu công khai của ứng cử viên chính trị nhằm thuyết phục cử tri bỏ phiếu cho mình."},"9762":{"word":"uyên bác","meaning":"Chỉ một người có nhiều thông tin, kiến thức và sự hiểu biết sâu rộng về nhiều lĩnh vực khác nhau."},"9763":{"word":"di ngôn","meaning":"Hành động để lại lời dặn dò khi sắp qua đời, hoặc những lời dặn dò đó."},"9764":{"word":"tin đồn vô căn cứ","meaning":"Thông tin được truyền miệng mà không dựa trên sự thật hoặc bằng chứng."},"9765":{"word":"tính linh hoạt","meaning":"Khả năng của cơ thể, vật thể hoặc kế hoạch dễ dàng uốn cong, kéo giãn hoặc thích nghi với điều kiện mới."},"9766":{"word":"ngưu tầm ngưu mã tầm mã","meaning":"Một câu nói mang ý nghĩa rằng những người có đặc điểm, sở thích hoặc hoàn cảnh tương đồng thường có xu hướng tụ tập hoặc kết giao với nhau."},"9767":{"word":"độc nhất vô nhị","meaning":"Diễn tả sự vật, sự việc chỉ có một, không có cái thứ hai hay tương tự."},"9768":{"word":"sự chảy vào","meaning":"Hiện tượng chất lỏng, tiền bạc hoặc người di chuyển vào một địa điểm hoặc hệ thống cụ thể."},"9769":{"word":"sự di truyền","meaning":"Quá trình các đặc điểm, tính cách hoặc hành vi được truyền từ cha mẹ sang con cái."},"9770":{"word":"bệnh di truyền","meaning":"Bệnh lý truyền từ cha mẹ hoặc thành viên lớn tuổi trong gia đình sang con cái, ảnh hưởng đến cơ thể hoặc tâm trí từ khi sinh ra."},"9771":{"word":"sự lưu loát","meaning":"Khả năng nói một ngôn ngữ rõ ràng và nhanh chóng mà không gặp nhiều khó khăn hay ngập ngừng."},"9772":{"word":"sự thu hút","meaning":"Hành động mang một sự kiện lớn, cuộc thi hoặc một khoản tiền lớn đến một địa điểm hoặc thành phố cụ thể."},"9773":{"word":"sự phát tán","meaning":"Hành động chia sẻ thông tin, thường là sai lệch hoặc có hại, đến nhiều người bằng cách kể hoặc đăng tải trực tuyến."},"9774":{"word":"Nho học","meaning":"Hệ thống tư tưởng, đạo đức và triết học do Khổng Tử sáng lập, có ảnh hưởng sâu rộng đến văn hóa Đông Á."},"9775":{"word":"bài hát thịnh hành","meaning":"Một bài hát rất được yêu thích trong một giai đoạn cụ thể, được nhiều người nghe và hát."},"9776":{"word":"chi phí giải trí","meaning":"Khoản tiền một người chi tiêu cho các hoạt động vui chơi giải trí như đi tiệc, nhà hàng hay xem biểu diễn."},"9777":{"word":"sự vui chơi","meaning":"Hoạt động con người làm chỉ để giải trí, thường liên quan đến vận động, tiếng cười hoặc tương tác nhẹ nhàng."},"9778":{"word":"đường bộ","meaning":"Con đường hoặc tuyến đường di chuyển qua mặt đất, như đường xá hay lối mòn, thay vì qua nước hoặc trên không."},"9779":{"word":"đạo đức","meaning":"Liên quan đến những nguyên tắc, giá trị đúng đắn, công bằng và tôn trọng người khác trong hành vi và quyết định."},"9780":{"word":"nhịp điệu, động tác nhịp nhàng","meaning":"Chuỗi các chuyển động cơ thể nhẹ nhàng, uyển chuyển theo một khuôn mẫu hoặc nhịp điệu đều đặn, thường là theo nhạc."},"9781":{"word":"tính linh hoạt, sự thích nghi","meaning":"Khả năng thay đổi hoặc điều chỉnh dễ dàng cho phù hợp với từng tình huống khác nhau."},"9782":{"word":"hợp nhất, dung hợp","meaning":"Quá trình hai hoặc nhiều thứ riêng biệt kết hợp lại với nhau để tạo thành một thể thống nhất mới."},"9783":{"word":"khoe khoang, vênh váo","meaning":"Đi lại một cách tự tin, tỏ vẻ kiêu ngạo hoặc nói về bản thân theo cách tự cho mình là hơn người khác."},"9784":{"word":"ngấm ngầm, âm thầm","meaning":"Một cách từ từ, kín đáo, không công khai nhưng vẫn diễn ra đều đặn, liên tục."},"9785":{"word":"huy chương bạc","meaning":"Huy chương làm bằng bạc, thường được trao cho người đạt vị trí thứ hai trong một sự kiện thể thao hoặc cuộc thi."},"9786":{"word":"ân sư","meaning":"Người thầy đã từng dạy dỗ mình và khiến mình biết ơn."},"9787":{"word":"dịu nhẹ, thoang thoảng","meaning":"Diễn tả ánh sáng không quá chói, âm thanh hoặc mùi hương không quá nồng, tạo cảm giác dễ chịu, thư thái."},"9788":{"word":"âm (trong âm dương)","meaning":"Trong triết học phương Đông cổ đại, là một trong hai thế lực đối lập nhưng bổ sung cho nhau (âm và dương), thường tượng trưng cho phần tối, tĩnh lặng và mát mẻ."},"9789":{"word":"âm mưu","meaning":"Kế hoạch bí mật được một nhóm người lập ra để thực hiện điều gì đó có hại hoặc bất hợp pháp."},"9790":{"word":"âm thanh, âm học","meaning":"Cách một căn phòng hoặc không gian truyền và khuếch đại âm thanh, hoặc các tiếng động cụ thể được sử dụng trong một buổi biểu diễn."},"9791":{"word":"nghĩa","meaning":"Một nguyên tắc hoặc giá trị đạo đức mà một người nên tuân theo, thường liên quan đến sự trung thành và chính nghĩa."},"9792":{"word":"có chủ ý","meaning":"Diễn tả hành động được thực hiện một cách có mục đích, không phải ngẫu nhiên."},"9793":{"word":"mang tính nghi thức","meaning":"Diễn tả một hành động hoặc sự kiện tuân theo các phong tục, truyền thống đã được thiết lập, thường là vì bổn phận chứ không phải cảm xúc sâu sắc."},"9794":{"word":"yêu cầu","meaning":"Hành động một người chính thức đề nghị người khác hoặc một nhóm làm một công việc cụ thể hoặc cung cấp sự giúp đỡ."},"9795":{"word":"nghĩa khí","meaning":"Nguyên tắc đạo đức mà một người nên tuân theo, đặc biệt là lòng trung thành và tinh thần chính nghĩa."},"9796":{"word":"đời sống ăn mặc","meaning":"Tất cả các hoạt động và lựa chọn hàng ngày của một người liên quan đến trang phục mà họ mặc."},"9797":{"word":"y thuật","meaning":"Khả năng và kiến thức mà một bác sĩ có để chữa bệnh hoặc điều trị vết thương cho con người."},"9798":{"word":"có ý thức","meaning":"Diễn tả một hành động hoặc suy nghĩ mà một người hoàn toàn nhận thức được và thực hiện với sự cân nhắc cẩn thận."},"9799":{"word":"nghi ngờ","meaning":"Cảm thấy bối rối hoặc nghi ngờ về một điều gì đó có vẻ lạ lùng hoặc khó hiểu."},"9800":{"word":"đầy nhiệt huyết","meaning":"Thể hiện sự quan tâm và năng lượng mạnh mẽ để làm điều gì đó, thường với sự hào hứng lớn."},"9801":{"word":"nghị sĩ","meaning":"Một người là thành viên của Quốc hội hoặc hội đồng địa phương, có quyền quyết định về một vấn đề nhất định."},"9802":{"word":"chững chạc","meaning":"Hành động một cách bình tĩnh, nghiêm túc và hợp lý, thể hiện sự phán đoán tốt, thường giống như người lớn."},"9803":{"word":"mức độ phụ thuộc","meaning":"Tỷ lệ hoặc mức độ mà một người hay vật cần sự giúp đỡ hoặc hỗ trợ từ người hoặc vật khác."},"9804":{"word":"có tính phụ thuộc","meaning":"Có tính chất cần sự giúp đỡ hoặc hỗ trợ từ người khác để hoạt động hoặc tồn tại, không thể tự mình làm mọi việc."},"9805":{"word":"mang tính y học","meaning":"Liên quan đến việc nghiên cứu hoặc thực hành phòng ngừa, điều trị hoặc chữa khỏi bệnh tật và chấn thương."},"9806":{"word":"ý định","meaning":"Điều mong muốn hoặc quyết định trong tâm trí một người để thực hiện hoặc đạt được điều gì đó."},"9807":{"word":"sự nghi ngờ","meaning":"Cảm giác mạnh mẽ rằng có điều gì đó đang bị che giấu hoặc không đúng, khiến người ta nhìn một tình huống với sự hoài nghi."},"9808":{"word":"quốc hội","meaning":"Cơ quan lập pháp gồm các quan chức được bầu ra để thảo luận và ban hành luật pháp cho một quốc gia."},"9809":{"word":"bất đồng quan điểm","meaning":"Một ý kiến hoặc niềm tin không đồng nhất với ý kiến hoặc niềm tin của người khác về một vấn đề nào đó."},"9810":{"word":"rực cháy","meaning":"Chiếu sáng với ánh sáng rất mạnh, nóng bỏng, thường trông như đang rung động với năng lượng mãnh liệt."},"9811":{"word":"tính ích kỷ","meaning":"Thói quen chỉ nghĩ về những gì mình muốn hoặc cần mà không xem xét đến người khác."},"9812":{"word":"bị cuốn hút","meaning":"Di chuyển về phía trước vì có ai đó hoặc điều gì đó đang hướng dẫn hoặc kéo mình đi."},"9813":{"word":"đội (trên đầu)","meaning":"Đặt hoặc giữ vật gì đó trên đầu mình để mang đi."},"9814":{"word":"thỉnh thoảng","meaning":"Xảy ra chỉ một vài lần, không thường xuyên hoặc không theo khoảng thời gian đều đặn."},"9815":{"word":"lý lịch","meaning":"Toàn bộ quá trình học tập, công việc, kinh nghiệm của một người."},"9816":{"word":"bất thường","meaning":"Xảy ra rất hiếm khi và khác biệt đáng ngạc nhiên so với điều bình thường."},"9817":{"word":"chẳng hạn","meaning":"Dùng để đưa ra một điều hoặc tình huống cụ thể nhằm giải thích rõ hơn điều đang nói."},"9818":{"word":"mặt sau","meaning":"Phần mặt phía sau hoặc phía đối diện với mặt chính của một vật."},"9819":{"word":"sự đóng góp","meaning":"Hành động hoặc điều gì đó được đưa ra để giúp một nhóm hoặc dự án thành công."},"9820":{"word":"gia đình ly tán","meaning":"Những người thân không thể sống cùng hoặc gặp gỡ nhau do chiến tranh hay sự chia cắt đất nước."},"9821":{"word":"lý tưởng","meaning":"Trạng thái hoặc hình thức hoàn hảo nhất, tốt đẹp nhất có thể tưởng tượng được."},"9822":{"word":"độc đáo","meaning":"Khác biệt đáng kể so với những gì quen thuộc hoặc thông thường, thường theo một cách thú vị."},"9823":{"word":"sương","meaning":"Giọt nước nhỏ li ti hình thành từ hơi nước trong không khí khi nhiệt độ giảm xuống hoặc chạm vào vật lạnh."},"9824":{"word":"cấy ghép","meaning":"Việc chuyển cây, mô hoặc nội tạng từ nơi này sang nơi khác."},"9825":{"word":"tâm đầu ý hợp","meaning":"Cảm giác hiểu được suy nghĩ hoặc cảm xúc của người khác mà không cần lời nói hay giải thích."},"9826":{"word":"thừa kế","meaning":"Nhận lấy một vai trò, kỹ năng hoặc truyền thống từ người đã có trước đó."},"9827":{"word":"Nếu có thể","meaning":"Diễn tả rằng nếu tình hình cho phép, một lựa chọn nào đó sẽ tốt hơn hoặc đáng mong muốn hơn."},"9828":{"word":"Lợi nhuận","meaning":"Số tiền doanh nghiệp còn lại sau khi đã thanh toán tất cả các chi phí như hóa đơn và tiền lương."},"9829":{"word":"Ý kiến phản đối","meaning":"Một lời tuyên bố hoặc bày tỏ chính thức thể hiện sự không đồng ý với một đề xuất, ý tưởng hoặc quyết định."},"9830":{"word":"Lợi thế","meaning":"Một đặc điểm hoặc hoàn cảnh có lợi, giúp ai đó hoặc điều gì đó ở vị trí tốt hơn so với những người khác."},"9831":{"word":"Từ trước đến nay","meaning":"Diễn tả một hành động hoặc trạng thái đã diễn ra liên tục từ một thời điểm trong quá khứ cho đến chính khoảnh khắc hiện tại."},"9832":{"word":"Sự di cư","meaning":"Hành động chuyển từ nơi này sang nơi khác để sinh sống vĩnh viễn, thường là giữa các quốc gia hoặc vùng miền."},"9833":{"word":"Người di cư","meaning":"Một người di chuyển từ khu vực hoặc quốc gia quê hương của họ để định cư ở một khu vực hoặc quốc gia khác."},"9834":{"word":"Tỷ lệ nghỉ việc","meaning":"Một chỉ số đo lường số lượng nhân viên rời khỏi một công ty và được thay thế bằng nhân viên mới trong một khoảng thời gian nhất định."},"9835":{"word":"Sự chệch hướng","meaning":"Hành động di chuyển hoặc đi chệch khỏi một lộ trình, tiêu chuẩn dự kiến hoặc một nhóm."},"9836":{"word":"Lợi ích","meaning":"Điều gì đó mang lại lợi nhuận, quyền lợi hoặc sự thuận lợi cho một cá nhân, nhóm hay tổ chức."},"9837":{"word":"Sự thực hiện","meaning":"Quá trình biến một kế hoạch, thỏa thuận hoặc lời hứa thành hành động và làm cho nó xảy ra."},"9838":{"word":"Sự ẩn danh","meaning":"Tình trạng mà tên thật hoặc danh tính của một người được giữ kín hoàn toàn khỏi công chúng hoặc những cá nhân khác."},"9839":{"word":"hài hước, dí dỏm","meaning":"Có tính cách hoặc biểu hiện gây cười, mang lại sự vui vẻ cho người khác."},"9840":{"word":"-người","meaning":"Một hậu tố dùng sau tên quốc gia hay khu vực để chỉ người dân thuộc quốc gia hoặc khu vực đó."},"9841":{"word":"tình người, nhân tính","meaning":"Tính cách ấm áp, nhân ái, biết quan tâm đến người khác khiến người đó dễ gần và đáng mến."},"9842":{"word":"chi phí nhân công, tiền công","meaning":"Tổng số tiền mà một doanh nghiệp chi trả cho người lao động để thuê họ làm việc."},"9843":{"word":"thuộc về nhân cách, cá nhân","meaning":"Liên quan đến tính cách, tư duy và phẩm chất đặc trưng của một con người."},"9844":{"word":"nhân tạo","meaning":"Được tạo ra bởi con người, không phải tự nhiên có sẵn trong thế giới."},"9845":{"word":"nhân quyền","meaning":"Những quyền và tự do cơ bản mà mọi người đều có, chỉ vì họ là con người."},"9846":{"word":"sự kiên nhẫn, lòng kiên trì","meaning":"Khả năng giữ bình tĩnh khi phải chờ đợi lâu hoặc tiếp tục làm việc khó khăn mà không bỏ cuộc."},"9847":{"word":"nhân đạo","meaning":"Liên quan đến các hành động hoặc nỗ lực nhằm giúp đỡ những người đang gặp khó khăn hoặc đau khổ."},"9848":{"word":"nhân văn học","meaning":"Các lĩnh vực học thuật nghiên cứu về văn hóa, lịch sử, ngôn ngữ, văn học và tư tưởng của con người."},"9849":{"word":"biển người, đông nghịt người","meaning":"Tình trạng có rất nhiều người tập trung đông đúc tại một địa điểm, tạo thành một đám đông dày đặc."},"9850":{"word":"quan niệm sống, nhân sinh quan","meaning":"Hệ thống niềm tin và tư tưởng định hình cách một người nhìn nhận và phản ứng với mọi điều xảy ra trong cuộc sống của họ."},"9851":{"word":"nhân tạo","meaning":"Do con người tạo ra hoặc thay đổi có chủ ý, không tự nhiên."},"9852":{"word":"cá nhân, nhân sự","meaning":"Liên quan đến thông tin của một người hoặc nhóm người làm việc cùng nhau."},"9853":{"word":"độ nhận diện","meaning":"Mức độ một người, sản phẩm hay tổ chức được nhiều người biết đến và nhận ra."},"9854":{"word":"rút tiền","meaning":"Hành động lấy tiền ra khỏi tài khoản ngân hàng."},"9855":{"word":"ngày (trong từ ghép)","meaning":"Hậu tố chỉ một khoảng thời gian 24 giờ, thường dùng để đánh dấu sự kiện đặc biệt."},"9856":{"word":"công việc, khối lượng công việc","meaning":"Số lượng hoạt động hoặc nhiệm vụ mà một người hoặc một nhóm cần hoàn thành."},"9857":{"word":"tính nhất quán","meaning":"Trạng thái duy trì sự ổn định, không thay đổi về phương pháp hoặc thái độ từ đầu đến cuối."},"9858":{"word":"làm cho nhận ra, thức tỉnh","meaning":"Giúp ai đó đột nhiên nhìn thấy hoặc hiểu ra một sự thật quan trọng mà họ chưa nhận ra trước đây."},"9859":{"word":"ý chí kiên định, một lòng","meaning":"Suy nghĩ duy nhất hoặc tâm trí kiên định không thay đổi từ đầu đến cuối."},"9860":{"word":"một đối một","meaning":"Trạng thái hai bên đối mặt trực tiếp, mỗi bên có phần hoặc quyền ngang nhau."},"9861":{"word":"một loạt, một chuỗi","meaning":"Một số mục hoặc sự kiện tương tự xảy ra liên tiếp theo một thứ tự có kết nối."},"9862":{"word":"ví dụ (minh họa)","meaning":"Một sự vật hoặc trường hợp cụ thể được đưa ra để đại diện cho một nhóm lớn hơn hoặc ý tưởng."},"9863":{"word":"hoàng hôn","meaning":"Thời điểm mặt trời khuất dần phía chân trời vào cuối ngày."},"9864":{"word":"coi là việc chính","meaning":"Coi một việc gì đó như công việc chính để thường xuyên làm."},"9865":{"word":"sự thường nhật hóa","meaning":"Việc một hoạt động hoặc sự kiện trở thành phần thường xuyên, quen thuộc trong cuộc sống hàng ngày."},"9866":{"word":"thành viên","meaning":"Một người là bộ phận cấu thành của một nhóm, tổ chức hoặc gia đình cụ thể."},"9867":{"word":"một lượng nhất định","meaning":"Một số lượng, mức độ hoặc khối lượng được xác định hoặc quy định cụ thể."},"9868":{"word":"đồng loạt","meaning":"Nhiều người hoặc vật cùng thực hiện một hành động tại đúng một thời điểm."},"9869":{"word":"từ sớm","meaning":"Xảy ra hoặc được hoàn thành sớm hơn đáng kể so với thời gian thông thường hoặc dự kiến."},"9870":{"word":"gọi là","meaning":"Dùng một từ hoặc cụm từ cụ thể để gọi hoặc nhận diện cái gì đó một cách trang trọng."},"9871":{"word":"sự sai lệch","meaning":"Hành động hoặc hành vi đi chệch khỏi những gì được coi là bình thường, tiêu chuẩn hoặc đúng đắn."},"9872":{"word":"nơi làm việc","meaning":"Địa điểm cụ thể mà mọi người đến để thực hiện các nhiệm vụ hoặc công việc chuyên môn của họ."},"9873":{"word":"một phần","meaning":"Một bộ phận hoặc khía cạnh riêng biệt góp phần tạo nên một kế hoạch, dự án hoặc hệ thống lớn hơn."},"9874":{"word":"nhiệm kỳ","meaning":"Khoảng thời gian cụ thể một người được phép giữ một chức vụ trong chính phủ hoặc tổ chức."},"9875":{"word":"tiền thuê","meaning":"Số tiền phải trả định kỳ để sử dụng nhà, đất hoặc không gian của người khác."},"9876":{"word":"bổ nhiệm","meaning":"Hành động chính thức chọn và giao một người vào một chức vụ hoặc nhiệm vụ."},"9877":{"word":"thai phụ","meaning":"Người phụ nữ đang có em bé phát triển bên trong cơ thể."},"9878":{"word":"lâm nghiệp","meaning":"Ngành công nghiệp bảo tồn, trồng rừng và khai thác rừng để tạo ra lợi ích kinh tế."},"9879":{"word":"tuyển dụng","meaning":"Việc một người được chính thức lựa chọn và trao một công việc hoặc vị trí cụ thể."},"9880":{"word":"nhà quản lý cấp cao","meaning":"Người quản lý cấp cao trong một công ty hoặc tổ chức, có quyền đưa ra các quyết định quan trọng."},"9881":{"word":"giờ lâm chung","meaning":"Giai đoạn cuối cùng của cuộc đời một người, khi họ yếu ớt và thường có gia đình bên cạnh."},"9882":{"word":"đối mặt","meaning":"Đứng trực tiếp trước một tình huống, thử thách hoặc nhiệm vụ, sẵn sàng hành động."},"9883":{"word":"đoạt giải","meaning":"Hành động giành được vị trí cao hoặc nhận giải thưởng trong một cuộc thi."},"9884":{"word":"nhận nuôi","meaning":"Việc trở thành con của người không phải cha mẹ ruột hoặc chấp nhận một người làm con mình thông qua thủ tục pháp lý."},"9885":{"word":"chứng minh","meaning":"Hành động trình bày sự thật hoặc bằng chứng để cho thấy rõ ràng một điều gì đó là đúng."},"9886":{"word":"liên tiếp","meaning":"Nhiều sự việc xuất hiện hoặc xảy ra liên tục, ngay sau nhau mà không có gián đoạn."},"9887":{"word":"tự mình","meaning":"Liên quan đến việc một cá nhân tự làm cho mình hoặc thuộc về riêng cá nhân đó."},"9888":{"word":"tự giác","meaning":"Khoảnh khắc một người hiểu rõ ràng suy nghĩ, cảm xúc hoặc tình hình hiện tại của bản thân."},"9889":{"word":"sỏi","meaning":"Viên đá nhỏ tròn và nhẵn do bị mài mòn ở lòng sông hoặc đáy biển."},"9890":{"word":"nhỏ nhắn","meaning":"Có kích thước hơi nhỏ hơn mức trung bình, trông khá gọn gàng hoặc bé đi."},"9891":{"word":"tự cung tự cấp","meaning":"Tình trạng một người hoặc một nhóm có thể tự sản xuất tất cả thức ăn, hàng hóa và tài nguyên cần thiết mà không phụ thuộc vào người khác."},"9892":{"word":"ích kỷ","meaning":"Mô tả người luôn đặt nhu cầu và mong muốn của bản thân lên hàng đầu, thường không để ý hoặc quan tâm đến người khác."},"9893":{"word":"tự lập","meaning":"Tình trạng một người có thể sống độc lập và tự nuôi sống bản thân mà không cần sự giúp đỡ từ người khác."},"9894":{"word":"tự mãn","meaning":"Cảm giác vui sướng hoặc ngưỡng mộ quá mức mà một người dành cho khả năng hoặc ngoại hình của bản thân, thường khiến họ nghĩ mình giỏi hơn người khác."},"9895":{"word":"cố vấn","meaning":"Hành động nhận ý kiến hoặc hướng dẫn chuyên môn từ người có kiến thức về một chủ đề cụ thể."},"9896":{"word":"tự nguyện","meaning":"Hành động được thực hiện vì một người tự chọn làm, không phải vì người khác bắt buộc."},"9897":{"word":"thú tội","meaning":"Lời nói mà một người nói với người khác rằng họ đã làm điều gì đó sai trái hoặc vi phạm quy tắc."},"9898":{"word":"chủ nghĩa tư bản","meaning":"Hệ thống trong đó người dân và các công ty sở hữu đất đai, nhà máy và doanh nghiệp, sản xuất hàng hóa để bán lấy tiền."},"9899":{"word":"Tài sản","meaning":"Vật có giá trị thuộc sở hữu của một người hoặc công ty, mang lại lợi ích trong tương lai."},"9900":{"word":"Đầu thú","meaning":"Việc một người đã phạm tội tự đi đến cơ quan công an hoặc chính quyền để thừa nhận hành vi của mình."},"9901":{"word":"Tự thân lập nghiệp","meaning":"Việc tự mình làm ra nhiều tiền và xây dựng sự nghiệp mà không cần tài sản thừa kế từ cha mẹ."},"9902":{"word":"Tự tin","meaning":"Có niềm tin rằng mình có thể đạt được điều gì đó một cách thỏa đáng bằng chính khả năng của mình."},"9903":{"word":"Cái tôi","meaning":"Phần cốt lõi trong con người, bao gồm suy nghĩ, cảm xúc và cách một người nhìn nhận bản thân như một cá thể."},"9904":{"word":"Tự hiện thực hóa bản thân","meaning":"Quá trình một người khám phá và phát triển đầy đủ tài năng đặc biệt cùng tính cách thật của mình để sống một cuộc đời ý nghĩa."},"9905":{"word":"Phóng khoáng","meaning":"Một người sống không bị ràng buộc bởi nhiều quy tắc hay lo lắng, hành động tự nhiên và thể hiện bản thân một cách cởi mở."},"9906":{"word":"Tự do tùy ý","meaning":"Khả năng làm điều gì đó rất dễ dàng và khéo léo, thay đổi theo ý muốn mà không gặp khó khăn nào."},"9907":{"word":"Tự chủ","meaning":"Quyền lực cho phép một người hoặc một nhóm tự đưa ra lựa chọn và quy tắc của riêng mình mà không bị người khác kiểm soát."},"9908":{"word":"Tự chủ","meaning":"Diễn tả một người hoặc một nhóm tự đưa ra lựa chọn và quy tắc của riêng mình, không bị người khác kiểm soát."},"9909":{"word":"Bài hát ru","meaning":"Một bài hát êm dịu, nhẹ nhàng mà cha mẹ hoặc người chăm sóc hát cho em bé hoặc trẻ nhỏ nghe để giúp chúng ngủ."},"9910":{"word":"Vật liệu","meaning":"Các loại đồ dùng khác nhau như gỗ, kim loại, vải hoặc đá được dùng để xây dựng hoặc tạo ra thứ gì đó."},"9911":{"word":"tố chất","meaning":"Những khả năng, phẩm chất tốt đẹp tự nhiên hoặc điểm mạnh mà một người có để phù hợp với một công việc hay vai trò nào đó."},"9912":{"word":"đầu đuôi câu chuyện","meaning":"Toàn bộ các sự việc liên quan của một tình huống hoặc biến cố, được kể từ lúc bắt đầu cho đến khi kết thúc."},"9913":{"word":"dấu vết","meaning":"Dấu hiệu hoặc tàn dư còn lại của một sự việc, con người hoặc vật thể đã qua."},"9914":{"word":"suýt nữa","meaning":"Diễn tả tình huống một kết quả xấu có thể dễ dàng xảy ra nếu không cẩn thận hoặc mắc phải sai lầm nhỏ."},"9915":{"word":"suýt nữa thì","meaning":"Diễn tả một sự kiện hoặc kết quả tiêu cực đã rất gần kề việc xảy ra nhưng đã được ngăn chặn vào phút cuối."},"9916":{"word":"dáng vẻ","meaning":"Vẻ ngoài hoặc phong thái đẹp đẽ, thường dùng để chỉ phụ nữ."},"9917":{"word":"quyết định","meaning":"Một sự cam kết vững chắc trong tâm trí để làm điều gì đó hoặc một kế hoạch mà một người đã định sẵn."},"9918":{"word":"nhỏ li ti","meaning":"Mô tả một vật được làm từ các hạt rất nhỏ hoặc có các bộ phận cực kỳ bé, như đường hoặc cát."},"9919":{"word":"yên ắng","meaning":"Mô tả trạng thái không có tiếng động hoặc chuyển động, như mặt nước phẳng lặng hay căn phòng không có tiếng ồn."},"9920":{"word":"tiềm năng","meaning":"Khả năng hoặc phẩm chất tiềm ẩn trong ai đó hoặc điều gì đó mà chưa được phát triển nhưng có thể trở nên vĩ đại trong tương lai."},"9921":{"word":"tạp nham","meaning":"Mô tả một tập hợp nhiều loại vật khác nhau không liên quan đến nhau, như các món đồ lặt vặt trong ngăn kéo."},"9922":{"word":"đường dài","meaning":"Một khoảng không gian lớn giữa hai điểm, đòi hỏi một lượng thời gian hoặc nỗ lực đáng kể để di chuyển qua."},"9923":{"word":"sự cam đoan","meaning":"Lời hứa tự tin rằng điều gì đó chắc chắn sẽ xảy ra hoặc là đúng."},"9924":{"word":"sự khuyến khích","meaning":"Hành động khuyên bảo hoặc động viên người khác làm những việc tốt."},"9925":{"word":"người chủ mưu","meaning":"Người trực tiếp gây ra hoặc khởi xướng một sự việc cụ thể, đặc biệt là sự việc tiêu cực."},"9926":{"word":"đồ trang sức","meaning":"Vật dụng đeo trên người hoặc trang phục như đồ trang sức, kẹp tóc để làm tăng vẻ đẹp."},"9927":{"word":"sự kiểm soát","meaning":"Hành động giành hoặc duy trì quyền kiểm soát hoàn toàn một tình huống, đối tượng hoặc nhóm người."},"9928":{"word":"tôn ti trật tự","meaning":"Nguyên tắc xã hội truyền thống mà người trẻ thể hiện sự tôn kính và lịch sự với người lớn tuổi hơn."},"9929":{"word":"thợ thủ công","meaning":"Người có kỹ năng cao, làm ra những vật dụng bằng tay với sự tỉ mỉ và kiến thức chuyên sâu."},"9930":{"word":"về sau","meaning":"Tại một thời điểm chưa đến nhưng chắc chắn sẽ tới."},"9931":{"word":"sự trở lại","meaning":"Sự quay trở lại trạng thái thành công hoặc mạnh mẽ, thường sau một thời gian khó khăn hoặc vắng bóng."},"9932":{"word":"trò hề dễ thương","meaning":"Những hành động hoặc cử chỉ vui đùa, ngộ nghĩnh, thường của trẻ con hoặc thú cưng để làm người khác vui lòng."},"9933":{"word":"tài chính","meaning":"Việc quản lý tiền bạc của một tổ chức hoặc cá nhân, bao gồm cách thức thu, phân bổ và theo dõi các khoản tiền."},"9934":{"word":"sự trồng trọt","meaning":"Quá trình trồng cây hoặc cây trồng, bao gồm chuẩn bị đất, gieo hạt và chăm sóc chúng cho đến khi thu hoạch."},"9935":{"word":"thảm họa","meaning":"Một sự kiện tồi tệ, bất ngờ gây ra sự hủy diệt hoặc đau khổ lớn cho con người và môi trường."},"9936":{"word":"tài nữ","meaning":"Người phụ nữ trẻ tuổi có nhiều tài năng."},"9937":{"word":"tài chính công","meaning":"Việc quản lý tiền bạc và nguồn lực của chính phủ hoặc một tổ chức công lớn, bao gồm thu nhập và chi tiêu."},"9938":{"word":"tại chức","meaning":"Trạng thái đang làm việc trong một vị trí hoặc vai trò cụ thể tại một công ty hoặc tổ chức."},"9939":{"word":"hóm hỉnh","meaning":"Khả năng sử dụng từ ngữ một cách thông minh và nhanh nhạy, thường tạo ra những nhận xét hài hước."},"9940":{"word":"kỹ thuật đầu tư","meaning":"Các phương pháp và kế hoạch mà mọi người sử dụng để quản lý và phát triển tiền bạc của mình, với hy vọng gia tăng tài sản."},"9941":{"word":"tái hiện","meaning":"Hành động thể hiện hoặc trình diễn lại một sự kiện hoặc tình huống trong quá khứ."},"9942":{"word":"phục hồi chức năng","meaning":"Quá trình giúp một người lấy lại khả năng thể chất hoặc tinh thần sau chấn thương hoặc bệnh tật."},"9943":{"word":"nhanh nhẹn","meaning":"Di chuyển rất nhanh và linh hoạt, thường theo cách nhẹ nhàng và khéo léo để tránh chướng ngại vật."},"9944":{"word":"vấn đề tranh cãi","meaning":"Một chủ đề hoặc vấn đề cụ thể gây ra sự phản đối mạnh mẽ giữa các cá nhân hoặc nhóm."},"9945":{"word":"phụ bạc","meaning":"Làm trái lời hứa hoặc sự tin tưởng đã dành cho ai đó, hoặc quay lưng lại với người đang phụ thuộc vào mình."},"9946":{"word":"tác phẩm","meaning":"Một cuốn sách hoặc công trình văn học được viết bởi một tác giả."},"9947":{"word":"thu nhập thấp","meaning":"Mức thu nhập nhỏ hơn hoặc ít hơn so với mức trung bình."},"9948":{"word":"thế giới bên kia","meaning":"Thế giới tâm linh mà linh hồn con người được cho là sẽ đến sau khi cơ thể ngừng sống."},"9949":{"word":"bản quyền","meaning":"Quyền đối với một tác phẩm thuộc về tác giả hoặc người thừa kế quyền đó."},"9950":{"word":"thấp, chậm","meaning":"Tình trạng số lượng, tỉ lệ hoặc mức độ hoạt động thấp hơn hoặc chậm hơn nhiều so với dự kiến."},"9951":{"word":"sự kháng cự","meaning":"Hành động đẩy lùi hoặc giữ vững lập trường chống lại một lực lượng, một ý tưởng hoặc một hành động."},"9952":{"word":"sự cản trở","meaning":"Điều gì đó ngăn chặn tiến trình hoặc khiến một hành động hay quá trình khó tiến triển hơn."},"9953":{"word":"sự thù địch","meaning":"Hành động coi và đối xử với ai đó như kẻ thù."},"9954":{"word":"đường xích đạo","meaning":"Một đường tròn tưởng tượng vẽ quanh giữa Trái Đất, chia nó thành hai nửa bắc và nam."},"9955":{"word":"sự phát hiện","meaning":"Hành động tìm thấy và tiết lộ những điều đã bị giấu kín hoặc giữ bí mật, như tội phạm hoặc sai lầm."},"9956":{"word":"khả năng thích nghi","meaning":"Khả năng thay đổi hành vi hoặc lối sống để phù hợp với điều kiện mới hoặc khác biệt."},"9957":{"word":"không ít","meaning":"Có số lượng hoặc mức độ không nhỏ."},"9958":{"word":"thích hợp","meaning":"Tình trạng hoàn toàn đúng hoặc cực kỳ phù hợp cho một tình huống hoặc mục đích cụ thể."},"9959":{"word":"trận đấu","meaning":"Đây là hậu tố đứng sau danh từ, chỉ một cuộc thi đấu, tranh tài giữa hai hay nhiều bên."},"9960":{"word":"bước ngoặt","meaning":"Một thời điểm quan trọng đánh dấu sự thay đổi lớn trong sự việc hoặc cuộc đời."},"9961":{"word":"tiểu sử","meaning":"Một tác phẩm ghi lại cuộc đời và những sự kiện chính của một nhân vật."},"9962":{"word":"sự chuyên tâm","meaning":"Việc dồn hết năng lượng và sự chú ý vào một công việc hoặc mục đích duy nhất."},"9963":{"word":"sự chuyên trách","meaning":"Tình trạng một cá nhân hoặc một nhóm được giao trách nhiệm duy nhất cho một công việc hoặc lĩnh vực cụ thể."},"9964":{"word":"chạy điện","meaning":"Miêu tả máy móc hoặc thiết bị hoạt động nhờ năng lượng điện."},"9965":{"word":"sự truyền lại","meaning":"Đặc điểm của một câu chuyện, phong tục hoặc kiến thức được truyền từ thế hệ trước sang thế hệ sau trong thời gian dài."},"9966":{"word":"có tính chiến lược","meaning":"Mô tả một kế hoạch hoặc hành động được suy nghĩ kỹ lưỡng để đạt được mục tiêu lớn hoặc lợi thế quan trọng."},"9967":{"word":"toàn lực","meaning":"Toàn bộ sức mạnh thể chất hoặc tinh thần mà một người có để thực hiện một hành động."},"9968":{"word":"đài quan sát","meaning":"Một công trình được xây dựng ở vị trí cao để ngắm cảnh từ xa."},"9969":{"word":"toàn bộ","meaning":"Toàn bộ bề mặt hoặc phạm vi của một vật gì đó, hoặc trang đầu tiên của một tờ báo."},"9970":{"word":"toàn diện","meaning":"Mô tả một sự việc bao gồm tất cả các bộ phận hoặc khía cạnh, không bỏ sót bất kỳ điều gì."},"9971":{"word":"chưa từng có, vô tiền khoáng hậu","meaning":"Là điều chưa từng xảy ra hay tồn tại từ trước đến nay và có thể sẽ không xảy ra nữa trong tương lai."},"9972":{"word":"chuyên môn","meaning":"Lĩnh vực nghiên cứu hoặc công việc mà chỉ có người có nhiều kiến thức và kinh nghiệm mới có thể thực hiện, hoặc bản thân lĩnh vực đó."},"9973":{"word":"hiệp một, nửa đầu","meaning":"Phần đầu của một khoảng thời gian, cuộc thi đấu hoặc buổi biểu diễn, trước khi có nghỉ giải lao hoặc chia thành phần sau."},"9974":{"word":"phần đầu, nửa đầu","meaning":"Đoạn mở đầu của một cuốn sách, bộ phim hoặc sự kiện, trước các phần giữa hoặc cuối."},"9975":{"word":"tổng thể, toàn diện","meaning":"Nói về việc bao gồm hoặc xem xét tất cả các yếu tố hoặc khía cạnh của một tình huống hoặc chủ đề."},"9976":{"word":"thời hoàng kim, thời kỳ đỉnh cao","meaning":"Khoảng thời gian mà một người hoặc một thứ gì đó đạt được thành công, sự nổi tiếng hoặc quyền lực lớn nhất."},"9977":{"word":"giá thuê nhà jeonse","meaning":"Số tiền lớn mà người thuê nhà trả cho chủ nhà một lần duy nhất thay vì tiền thuê hàng tháng, sẽ được hoàn trả khi họ chuyển đi."},"9978":{"word":"toàn thân, cả người","meaning":"Hình thể đầy đủ của một người hoặc con vật, bao gồm tất cả các bộ phận từ đầu đến chân."},"9979":{"word":"nghề chính, công việc toàn thời gian","meaning":"Công việc hoặc hoạt động chính mà một người dành toàn bộ hoặc phần lớn thời gian làm việc để kiếm tiền."},"9980":{"word":"toàn bộ khu vực, khắp nơi","meaning":"Toàn bộ phạm vi của một vùng hoặc không gian cụ thể, bao gồm mọi phần bên trong ranh giới của nó."},"9981":{"word":"tài sản độc quyền, quyền sở hữu riêng","meaning":"Vật phẩm, quyền lợi hoặc đặc điểm chỉ thuộc về một người hoặc nhóm cụ thể mà không ai khác có."},"9982":{"word":"sự run rẩy, sự rùng mình (vì sợ hãi/thích thú)","meaning":"Cảm giác mạnh mẽ, đột ngột của sự phấn khích, sợ hãi hoặc cảm xúc mãnh liệt khiến cơ thể người run rẩy nhẹ hoặc sởn gai ốc."},"9983":{"word":"Cựu chức vụ","meaning":"Chức vụ hoặc nghề nghiệp mà một người đã từng đảm nhiệm trong quá khứ và hiện tại không còn làm nữa."},"9984":{"word":"Trận chiến","meaning":"Cuộc đối đầu bạo lực có tổ chức giữa hai nhóm lực lượng vũ trang đối lập nhằm mục đích đánh bại bên kia."},"9985":{"word":"Truyền bá","meaning":"Sự di chuyển của cái gì đó, như một ý tưởng hoặc tín hiệu, từ một nguồn để đến nhiều nơi hoặc nhiều người khác nhau."},"9986":{"word":"Điển hình","meaning":"Một ví dụ tiêu biểu nhất, thể hiện rõ đặc điểm của những thứ cùng loại."},"9987":{"word":"Chuyển họa thành phúc","meaning":"Tình huống khi một sự kiện không may mắn, xui xẻo lại biến thành vận may, điều tốt lành."},"9988":{"word":"Thời kỳ chuyển đổi","meaning":"Một khoảng thời gian cụ thể khi một sự thay đổi đáng kể xảy ra, khiến mọi thứ chuyển sang một hướng hoàn toàn mới và khác biệt."},"9989":{"word":"Tiết giảm","meaning":"Hành động làm giảm số lượng hoặc chi phí của một thứ gì đó, chẳng hạn như năng lượng hoặc chi phí."},"9990":{"word":"Trộm cắp","meaning":"Hành vi lén lút chiếm đoạt tài sản của người khác một cách trái pháp luật."},"9991":{"word":"Tự động","meaning":"Diễn tả một hành động hoặc sự việc xảy ra một cách tự động, không cần suy nghĩ có ý thức hay tác động bên ngoài."},"9992":{"word":"Khẩn thiết","meaning":"Miêu tả một nhu cầu hoặc cảm xúc vô cùng mạnh mẽ và cấp thiết, đòi hỏi hành động hoặc sự giúp đỡ nhanh chóng."},"9993":{"word":"Tiết kiệm điện","meaning":"Hành động sử dụng ít điện năng hơn hoặc tắt các thiết bị điện để giảm mức tiêu thụ."},"9994":{"word":"Tiết chế","meaning":"Khả năng ngăn bản thân hành động theo những mong muốn đột ngột hoặc cảm xúc mãnh liệt, giữ cho hành vi của mình được kiềm chế."},"9995":{"word":"thân thiết","meaning":"Mô tả mối quan hệ giữa những người có tình cảm sâu sắc, gần gũi và hiểu nhau rõ."},"9996":{"word":"bói toán","meaning":"Hoạt động dự đoán tương lai hoặc tìm câu trả lời bằng các phương pháp đặc biệt."},"9997":{"word":"chiếm đóng","meaning":"Hành động một quân đội dùng vũ lực kiểm soát và cai quản một vùng lãnh thổ."},"9998":{"word":"thị phần","meaning":"Tỷ lệ phần trăm tổng doanh số hoặc hoạt động kinh doanh mà một công ty hoặc sản phẩm chiếm giữ trong một ngành cụ thể."},"9999":{"word":"dần dần","meaning":"Diễn tả một quá trình hoặc sự thay đổi diễn ra chậm rãi, từng bước nhỏ liên tục chứ không phải đột ngột."},"10000":{"word":"cửa hàng","meaning":"Một căn phòng hoặc tòa nhà dùng để trưng bày và bán hàng hóa cho người mua."},"10001":{"word":"tiếp đãi","meaning":"Việc đón tiếp khách bằng cách mời ăn uống và tạo môi trường thoải mái, thân thiện."},"10002":{"word":"trận đấu gây cấn","meaning":"Một trận đấu hay cuộc thi mà các đối thủ ngang tài ngang sức, khó đoán người thắng cuộc."},"10003":{"word":"tiêm chủng","meaning":"Việc đưa một lượng nhỏ chất bảo vệ vào cơ thể bằng kim tiêm để phòng ngừa bệnh."},"10004":{"word":"tình cảm ấm áp","meaning":"Cảm xúc dễ chịu khiến người ta yêu mến và thấy thoải mái về ai đó hoặc điều gì đó."},"10005":{"word":"giới chính trị","meaning":"Nhóm những người tham gia vào việc điều hành đất nước, làm luật và tranh cử các chức vụ công."},"10006":{"word":"tinh xảo","meaning":"Mô tả cái gì đó được làm hoặc thực hiện với sự tỉ mỉ, cẩn thận đến từng chi tiết nhỏ."},"10007":{"word":"chính quyền","meaning":"Quyền lực mà một nhóm người hoặc một lãnh đạo có để kiểm soát và quản lý một quốc gia."},"10008":{"word":"chính quy","meaning":"Theo một quy tắc, lịch trình cố định hoặc tiêu chuẩn đã được thiết lập."},"10009":{"word":"tuổi nghỉ hưu","meaning":"Độ tuổi quy định mà một người được phép hoặc phải ngừng làm việc vĩnh viễn."},"10010":{"word":"chính đáng","meaning":"Đúng đắn và công bằng, được ủng hộ bởi những lý do mạnh mẽ và hợp lý."},"10011":{"word":"chính xác, tinh vi","meaning":"Sự cực kỳ chính xác và tỉ mỉ, đặc biệt khi đo lường hoặc tạo ra thứ gì đó."},"10012":{"word":"chinh phục","meaning":"Hành động một quân đội hoặc quốc gia giành quyền kiểm soát một vùng đất hoặc người dân bằng vũ lực."},"10013":{"word":"bảo trì, chỉnh sửa","meaning":"Quá trình kiểm tra, sửa chữa hoặc cải thiện cẩn thận thiết bị, hệ thống hoặc quy tắc để đảm bảo chúng hoạt động tốt."},"10014":{"word":"hình vuông","meaning":"Một hình chữ nhật có bốn cạnh bằng nhau và bốn góc vuông."},"10015":{"word":"bình thường hóa","meaning":"Quá trình đưa một tình huống, mối quan hệ hoặc điều kiện trở lại trạng thái ổn định, bình thường."},"10016":{"word":"thuộc về cảm xúc","meaning":"Mô tả điều gì đó liên quan hoặc gây ra những phản ứng nội tâm mạnh mẽ như vui, buồn, giận, lo lắng."},"10017":{"word":"tình thế, tình hình","meaning":"Tập hợp các sự kiện và tình hình hiện có tại một thời điểm và địa điểm cụ thể."},"10018":{"word":"nghị lực, sức mạnh tinh thần","meaning":"Khả năng của tâm trí một người để giữ vững quyết tâm và vượt qua khó khăn."},"10019":{"word":"có trật tự","meaning":"Sắp xếp một cách gọn gàng, rõ ràng và có thứ tự."},"10020":{"word":"nhiệt huyết","meaning":"Một cảm xúc mạnh mẽ, đầy nhiệt tình khiến một người hành động với năng lượng lớn."},"10021":{"word":"nồng nhiệt","meaning":"Thể hiện những cảm xúc hoặc niềm tin rất mạnh mẽ và đầy năng lượng."},"10022":{"word":"tĩnh","meaning":"Không di chuyển, không thay đổi và giữ nguyên vị trí."},"10023":{"word":"sự tĩnh lặng","meaning":"Tình trạng không có âm thanh và chuyển động trong một không gian nào đó."},"10024":{"word":"đỉnh điểm","meaning":"Mức độ hoặc điểm cao nhất mà một cái gì đó có thể đạt tới."},"10025":{"word":"công bằng, chính trực","meaning":"Cạnh tranh hoặc hành động một cách hoàn toàn trung thực, đúng đắn và tuân thủ mọi quy tắc."},"10026":{"word":"mang tính chính sách","meaning":"Liên quan đến các quy tắc, kế hoạch hoặc hành động chính thức được chính phủ hoặc một nhóm đưa ra."},"10027":{"word":"bản chất","meaning":"Những phẩm chất, niềm tin hoặc đặc điểm riêng biệt tạo nên một người hoặc một vật thể."},"10028":{"word":"thời kỳ đình trệ","meaning":"Một khoảng thời gian cụ thể không có sự tăng trưởng hoặc tiến bộ, mọi thứ vẫn không thay đổi."},"10029":{"word":"bản sắc","meaning":"Cảm nhận về việc một người hoặc một nhóm là ai, dựa trên tính cách, văn hóa và kinh nghiệm của họ."},"10030":{"word":"chính thống","meaning":"Thật sự nguyên bản và tuân theo các phương pháp hoặc niềm tin truyền thống hoặc được chấp nhận rộng rãi."},"10031":{"word":"thanh lọc","meaning":"Việc loại bỏ chất bẩn hoặc không trong sạch để làm cho một thứ gì đó trở nên sạch sẽ, tinh khiết hơn."},"10032":{"word":"ngả ra sau","meaning":"Di chuyển một vật hoặc một bộ phận cơ thể lên trên và ra xa phía trước."},"10033":{"word":"riêng rẽ","meaning":"Các sự vật hoặc con người có hành động, đặc điểm khác biệt và tách rời nhau."},"10034":{"word":"có tính thể chế","meaning":"Liên quan đến các quy tắc, hệ thống chính thức hoặc tổ chức đã được thiết lập, được công nhận và tuân theo."},"10035":{"word":"đề xuất","meaning":"Một ý tưởng hoặc kế hoạch được đưa ra để người khác xem xét và quyết định."},"10036":{"word":"chế tài","meaning":"Một hành động hoặc quy định chính thức được áp dụng để trừng phạt hoặc giới hạn hoạt động của một quốc gia, tổ chức hay cá nhân."},"10037":{"word":"ban hành","meaning":"Hành động chính thức tạo ra một luật, quy tắc hoặc quy định mới để có thể được tuân thủ."},"10038":{"word":"vượt qua","meaning":"Xử lý một điều gì đó để nó không còn gây phiền toái hoặc cản trở mình nữa."},"10039":{"word":"thống trị","meaning":"Hành động giành quyền kiểm soát hoàn toàn một khu vực hoặc giành giải thưởng cao nhất trong một cuộc thi."},"10040":{"word":"nóng vội","meaning":"Có biểu hiện khó chịu hoặc bồn chồn vì phải chờ đợi hoặc muốn mọi việc diễn ra nhanh hơn."},"10041":{"word":"lắp ráp","meaning":"Quá trình kết nối nhiều bộ phận riêng lẻ lại với nhau để tạo thành một vật thể hoàn chỉnh."},"10042":{"word":"hồi hộp","meaning":"Cảm thấy lo sợ và không yên tâm, thường biểu hiện bằng các dấu hiệu bên ngoài, vì không biết điều gì sẽ xảy ra tiếp theo."},"10043":{"word":"sớm muộn","meaning":"Diễn tả một việc sẽ xảy ra vào một thời điểm nào đó trong tương lai gần, không lâu sau."},"10044":{"word":"viếng tang","meaning":"Hành động đến dự đám tang hoặc thăm hỏi gia đình người đã mất để bày tỏ lòng tiếc thương."},"10045":{"word":"khách viếng tang","meaning":"Người đến dự đám tang hoặc lễ tưởng niệm để bày tỏ lòng tiếc thương đối với người đã khuất."},"10046":{"word":"ông bà","meaning":"Cha mẹ của cha hoặc mẹ mình."},"10047":{"word":"ngành đóng tàu","meaning":"Ngành kinh doanh và công việc thiết kế, đóng các phương tiện vận tải đường thủy lớn như tàu chở hàng, tàu khách."},"10048":{"word":"sự tạo dựng","meaning":"Hành động làm ra hoặc sắp xếp để một điều gì đó tồn tại hoặc một không khí, tình huống cụ thể hình thành."},"10049":{"word":"thuế","meaning":"Khoản tiền được chính phủ thu từ người dân hoặc công ty để chi trả cho các dịch vụ công cộng."},"10050":{"word":"rón rén","meaning":"Di chuyển hoặc hành động rất chậm và cẩn thận để tránh nguy hiểm hoặc gây ra tiếng động."},"10051":{"word":"vai phụ","meaning":"Trong sân khấu hoặc điện ảnh, vai trò hỗ trợ nhân vật chính trong cốt truyện, hoặc diễn viên đảm nhận vai trò đó."},"10052":{"word":"lời chia buồn","meaning":"Lời bày tỏ sự buồn bã sâu sắc và đồng cảm với người đã trải qua mất mát lớn, thường được nói hoặc viết ra."},"10053":{"word":"thao tác","meaning":"Hành động điều khiển hoặc sử dụng một máy móc, thiết bị theo các bước cụ thể để nó hoạt động."},"10054":{"word":"sự thúc đẩy","meaning":"Hành động khuyến khích hoặc làm cho một điều tiêu cực trở nên tồi tệ hơn."},"10055":{"word":"đua thuyền","meaning":"Môn thể thao ngồi trên thuyền dài, hẹp và dùng mái chèo để đẩy thuyền đi trên mặt nước."},"10056":{"word":"điều chỉnh","meaning":"Hành động thay đổi các ý tưởng hoặc bộ phận khác nhau một chút để chúng phù hợp với nhau hoặc trở nên dễ chấp nhận."},"10057":{"word":"điều khiển","meaning":"Hành động điều khiển một cỗ máy như máy bay, tàu thủy, v.v., để làm cho nó di chuyển."},"10058":{"word":"có tổ chức","meaning":"Mô tả các hành động hoặc hoạt động được thực hiện bởi một nhóm người có kế hoạch rõ ràng và phân công nhiệm vụ để đạt được mục tiêu cụ thể."},"10059":{"word":"dấu hiệu","meaning":"Một sự kiện nhỏ hoặc chi tiết có thể nhìn thấy xuất hiện, gợi ý về những gì có thể xảy ra trong tương lai."},"10060":{"word":"biện pháp","meaning":"Điều được thực hiện một cách cố ý để giải quyết một vấn đề hoặc đối phó với một tình huống."},"10061":{"word":"vẻ đẹp tạo hình","meaning":"Vẻ đẹp dễ chịu đến từ cách một vật thể hoặc cấu trúc được tạo hình và thiết kế."},"10062":{"word":"hài hòa","meaning":"Khi các bộ phận hoặc yếu tố khác nhau kết hợp tốt với nhau mà không xung đột, tạo nên một tổng thể dễ chịu và ổn định."},"10063":{"word":"tộc","meaning":"Một phần từ được thêm vào cuối tên địa danh hoặc khu vực để chỉ một nhóm người có chung nền văn hóa hoặc nguồn gốc từ nơi đó."},"10064":{"word":"đủ","meaning":"Có đúng lượng cần thiết của một thứ gì đó, không cần nhiều hơn hay ít hơn."},"10065":{"word":"phẩm giá","meaning":"Phẩm chất đáng được tôn trọng và thể hiện phong thái điềm tĩnh, nghiêm túc khiến người khác đối xử với mình bằng sự kính trọng."},"10066":{"word":"đột nhiên","meaning":"Xảy ra rất nhanh và không có bất kỳ cảnh báo nào, làm mọi người liên quan đều ngạc nhiên."},"10067":{"word":"kết thúc","meaning":"Một sự kiện, quá trình hay công việc đạt đến giai đoạn cuối cùng và dừng hẳn lại."},"10068":{"word":"hoạt động","meaning":"Việc dành thời gian và nỗ lực để làm một công việc hay nghề nghiệp cụ thể."},"10069":{"word":"người làm việc","meaning":"Người thực hiện một loại công việc hoặc nhiệm vụ cụ thể trong một ngành hoặc lĩnh vực."},"10070":{"word":"trước đây","meaning":"Chỉ những việc đã tồn tại hoặc xảy ra vào một thời điểm trong quá khứ, trước hiện tại."},"10071":{"word":"toàn diện","meaning":"Mô tả cái gì đó bao gồm nhiều yếu tố hoặc bao trùm tất cả các khía cạnh quan trọng của một chủ đề."},"10072":{"word":"não trái","meaning":"Một nửa bộ não người nằm ở phía bên trái của đầu."},"10073":{"word":"tọa đàm","meaning":"Một cuộc họp mà nhiều người cùng ngồi lại, thường là quanh một bàn tròn, để thảo luận công khai về một chủ đề cụ thể."},"10074":{"word":"cánh tả","meaning":"Một nhóm hoặc tư tưởng chính trị ủng hộ bình đẳng xã hội và cải cách tiến bộ, thường được coi là đối lập với quan điểm bảo thủ."},"10075":{"word":"có lỗi","meaning":"Cảm thấy hối hận hoặc áy náy như thể đã làm điều gì sai."},"10076":{"word":"tội nhân","meaning":"Một người đã phạm tội hoặc bị kết tội."},"10077":{"word":"chủ quyền","meaning":"Quyền lực và thẩm quyền hoàn toàn của một quốc gia để tự quản lý mà không bị các quốc gia khác kiểm soát."},"10078":{"word":"chủ lực","meaning":"Phần hoặc yếu tố quan trọng nhất mà một tổ chức hay cá nhân tập trung nỗ lực vào đó."},"10079":{"word":"thủ phạm chính","meaning":"Người đã thực hiện hành vi phạm tội theo kế hoạch của mình."},"10080":{"word":"đời sống nhà ở","meaning":"Các khía cạnh sinh hoạt hàng ngày liên quan đến việc sống trong một ngôi nhà, bao gồm loại hình nhà ở và các hoạt động gia đình."},"10081":{"word":"sự sắp xếp","meaning":"Hành động giúp đỡ người khác gặp gỡ, đạt được thỏa thuận hoặc tổ chức một sự kiện."},"10082":{"word":"nhân vật chính","meaning":"Vai trò trung tâm hoặc người đóng vai trò quan trọng trong một sự việc."},"10083":{"word":"cầu thủ chính thức","meaning":"Thành viên đội thể thao được chọn để thi đấu ngay từ đầu trận đấu."},"10084":{"word":"sự kiểm soát","meaning":"Hành động giải quyết tốt hoặc kiềm chế được những điều phiền phức hay gánh nặng."},"10085":{"word":"sự tổ chức","meaning":"Hành động một tổ chức hoặc cá nhân đứng ra tổ chức và hỗ trợ tài chính cho một sự kiện hoặc cuộc họp."},"10086":{"word":"sự tuân thủ","meaning":"Hành động thực hiện đúng theo quy tắc, luật lệ hoặc hướng dẫn đã được ban hành."},"10087":{"word":"công nghiệp nặng","meaning":"Loại hình sản xuất sử dụng máy móc và cơ sở vật chất quy mô lớn để tạo ra các sản phẩm cồng kềnh như thép, tàu thủy hoặc thiết bị xây dựng."},"10088":{"word":"sự trọng đại","meaning":"Tính chất có ảnh hưởng rất lớn đến con người hoặc tình huống, khiến nó trở nên quan trọng hoặc nghiêm trọng."},"10089":{"word":"giữa chừng","meaning":"Thời điểm hoặc địa điểm khi một công việc hoặc hành trình đã được thực hiện một phần nhưng chưa hoàn thành."},"10090":{"word":"trọng lực","meaning":"Một lực tự nhiên, vô hình hút mọi vật thể vật lý về phía trung tâm của một khối lớn, như hành tinh, khiến chúng rơi xuống."},"10091":{"word":"trung lập","meaning":"Tình trạng không đứng về hay ủng hộ bất cứ bên nào trong một cuộc tranh cãi hay xung đột."},"10092":{"word":"bệnh nặng","meaning":"Tình trạng bệnh tật nghiêm trọng, gây ảnh hưởng xấu đến sức khỏe và có thể nguy hiểm đến tính mạng."},"10093":{"word":"tầng lớp trung lưu","meaning":"Nhóm người trong xã hội có công việc ổn định, thu nhập khá, thường sở hữu nhà cửa nhưng không quá giàu có."},"10094":{"word":"vừa và nhỏ","meaning":"Từ dùng để chỉ quy mô không quá lớn nhưng cũng không quá bé, thường dùng cho doanh nghiệp hoặc thành phố."},"10095":{"word":"trọng tâm","meaning":"Phần hay khía cạnh được chú ý hoặc đặt tầm quan trọng hàng đầu trong một vấn đề."},"10096":{"word":"trọng tâm","meaning":"Chỉ việc tập trung vào một lĩnh vực hay mục tiêu cụ thể nào đó hơn các lĩnh vực khác."},"10097":{"word":"bệnh nặng","meaning":"Tình trạng bệnh tật rất nguy hiểm, có thể đe dọa tính mạng và cần được chăm sóc đặc biệt."},"10098":{"word":"san sát","meaning":"Mô tả nhiều thứ, như nhà cửa hay cây cối, được sắp xếp sát cạnh nhau một cách dày đặc và có trật tự."},"10099":{"word":"nước ép","meaning":"Chất lỏng dạng nước được chiết xuất từ trái cây hoặc rau củ tươi."},"10100":{"word":"xu hướng tăng","meaning":"Một kiểu mẫu nhận thấy được khi một lượng hoặc số lượng tiếp tục tăng lên theo thời gian."},"10101":{"word":"gia tăng","meaning":"Hành động làm cho số lượng, quy mô hoặc cường độ của một thứ trở nên lớn hơn."},"10102":{"word":"sự bay hơi","meaning":"Quá trình chất lỏng dần biến thành khí và tan vào không khí xung quanh, thường do nhiệt độ."},"10103":{"word":"Tăng cường nhân sự","meaning":"Việc thêm người vào một nhóm hoặc tổ chức để tăng số lượng thành viên."},"10104":{"word":"Trao tặng","meaning":"Hành động chính thức trao hoặc tặng một món đồ, thường là món đồ đặc biệt, cho người khác hoặc một nhóm người."},"10105":{"word":"Nâng cao, Thúc đẩy","meaning":"Quá trình làm cho cái gì đó trở nên mạnh mẽ hơn, tích cực hơn hoặc phổ biến rộng rãi hơn."},"10106":{"word":"Hội chứng","meaning":"Một nhóm các triệu chứng cùng nhau chỉ ra một bệnh, tình trạng, v.v., mà nguyên nhân trực tiếp chưa rõ ràng."},"10107":{"word":"Sức bền, Sức chịu đựng","meaning":"Khả năng của một người hoặc động vật tiếp tục thực hiện một hoạt động khó khăn về thể chất hoặc tinh thần trong thời gian dài mà không kiệt sức."},"10108":{"word":"Nhẹ nhàng mà chắc chắn","meaning":"Miêu tả một hành động được thực hiện với một áp lực nhất quán, có kiểm soát, không quá nhẹ cũng không quá mạnh."},"10109":{"word":"Tột cùng, Hết mực","meaning":"Diễn tả một hành động hoặc cảm xúc vô cùng sâu sắc, chân thành và hoàn toàn dâng hiến."},"10110":{"word":"Luyên thuyên, Ba hoa","meaning":"Nói liên tục một cách nhanh chóng, thường là ồn ào, về những chuyện không quan trọng."},"10111":{"word":"Khu vực, Vùng","meaning":"Một phần đất riêng biệt có những đặc điểm cụ thể hoặc được dành cho một mục đích nhất định."},"10112":{"word":"Kinh khủng, Dữ dội","meaning":"Miêu tả mức độ cực kỳ mạnh, tệ hoặc gay gắt của một sự việc, cảm giác, mùi vị nào đó."},"10113":{"word":"Đường kính","meaning":"Một đường thẳng nối hai điểm trên chu vi của hình tròn hoặc hình cầu, đi qua tâm, hoặc chiều dài của đường thẳng đó."},"10114":{"word":"Thuộc về địa lý","meaning":"Liên quan đến các đặc điểm tự nhiên của bề mặt Trái Đất như núi, sông, và sự phân bố đất liền, biển cả."},"10115":{"word":"nguyện vọng","meaning":"Sự mong muốn mạnh mẽ hoặc lựa chọn ưu tiên cho tương lai, như vị trí, trường học hoặc ngành học."},"10116":{"word":"đoạn văn","meaning":"Một phần văn bản hoặc câu hỏi được trích ra từ một bài viết hoặc sách giáo khoa."},"10117":{"word":"vân tay","meaning":"Dấu vết đặc biệt của các đường xoắn trên đầu ngón tay người, dùng để nhận dạng cá nhân."},"10118":{"word":"sự thống trị","meaning":"Hành động kiểm soát hoặc có toàn quyền lực đối với một nơi hoặc một nhóm người."},"10119":{"word":"có tính chi phối","meaning":"Mô tả cái gì đó mạnh hơn, có ảnh hưởng lớn hơn hoặc phổ biến hơn những thứ khác trong một tình huống cụ thể."},"10120":{"word":"trí tuệ","meaning":"Khả năng của con người để học hỏi, hiểu biết, suy luận và áp dụng kiến thức để giải quyết vấn đề."},"10121":{"word":"tiền hỗ trợ","meaning":"Số tiền do một tổ chức hoặc chính phủ cung cấp để giúp đỡ ai đó hoặc cho một dự án cụ thể."},"10122":{"word":"người quen","meaning":"Một người mà mình quen biết qua loa, không có mối quan hệ thân thiết."},"10123":{"word":"có tính trí tuệ","meaning":"Liên quan đến tư duy sâu sắc, việc học hỏi hoặc nghiên cứu các chủ đề phức tạp."},"10124":{"word":"tỉ lệ ủng hộ","meaning":"Một con số hoặc tỉ lệ phần trăm thể hiện mức độ ủng hộ mà một người hoặc ý tưởng nhận được từ công chúng."},"10125":{"word":"hướng dẫn","meaning":"Một tập hợp các gợi ý hoặc chỉ dẫn về cách mọi người nên hành động hoặc những gì họ nên làm."},"10126":{"word":"định hướng","meaning":"Hướng đi hoặc trọng tâm chung mà một người hay một nhóm theo đuổi để đạt được mục tiêu hoặc lý tưởng cụ thể."},"10127":{"word":"chỉ huy","meaning":"Hành động điều khiển, dẫn dắt một nhóm người để đạt được mục tiêu một cách hiệu quả."},"10128":{"word":"giao dịch trực tiếp","meaning":"Việc mua bán hàng hóa trực tiếp giữa người sản xuất và người tiêu dùng mà không qua trung gian."},"10129":{"word":"trực giác","meaning":"Khả năng hiểu hoặc biết điều gì đó là thật một cách đột ngột mà không cần suy nghĩ logic hay có bằng chứng."},"10130":{"word":"đối mặt","meaning":"Trực tiếp đứng trước hoặc giải quyết một tình huống, vấn đề khó khăn."},"10131":{"word":"nhiệm vụ","meaning":"Công việc hoặc trách nhiệm mà một người phải đảm nhận dựa trên chức vụ hoặc vị trí của mình."},"10132":{"word":"hình chữ nhật","meaning":"Hình phẳng có bốn cạnh thẳng, các cạnh đối diện có chiều dài bằng nhau và bốn góc đều là góc vuông."},"10133":{"word":"trực thuộc","meaning":"Mối quan hệ mà một người báo cáo hoặc được quản lý trực tiếp bởi người khác, không qua bất kỳ trung gian nào."},"10134":{"word":"-đoàn","meaning":"Hậu tố dùng để chỉ một nhóm người cùng làm việc hoặc tập hợp vì một mục đích cụ thể."},"10135":{"word":"tiến bộ","meaning":"Sự phát triển đi lên, trở nên tốt hơn về điều kiện, kiến thức hoặc khả năng theo thời gian."},"10136":{"word":"cấp tiến","meaning":"Thuộc về những ý tưởng hoặc con người ủng hộ sự thay đổi và cải tiến xã hội mới mẻ thay vì giữ nguyên các cách làm cũ."},"10137":{"word":"chân tướng","meaning":"Toàn bộ sự thật hoặc tình hình thực tế của một sự việc, vấn đề nào đó."},"10138":{"word":"trưng bày","meaning":"Việc sắp xếp hàng hóa hoặc vật phẩm một cách rõ ràng và hấp dẫn để mọi người có thể nhìn thấy."},"10139":{"word":"lẽ ra","meaning":"Diễn tả một thời điểm đã xảy ra trước thời điểm hiện tại, thường có ý hối tiếc hoặc đáng lẽ nên làm sớm hơn."},"10140":{"word":"tiến triển","meaning":"Sự việc tiến lên phía trước, tốt đẹp hơn hoặc đạt được mục tiêu nào đó."},"10141":{"word":"thật sự","meaning":"Diễn tả một cảm xúc hay hành động xuất phát từ tấm lòng, không giả dối."},"10142":{"word":"sự lắng xuống","meaning":"Quá trình các cảm xúc mạnh mẽ hoặc tình hình hỗn loạn dần trở nên yên tĩnh, bớt căng thẳng hoặc chấm dứt vấn đề."},"10143":{"word":"cầu tiến","meaning":"Diễn tả người hoặc tư tưởng chủ động tìm kiếm phương pháp mới, dám tiến lên phía trước thay vì giữ nguyên cách cũ."},"10144":{"word":"kỳ cảnh","meaning":"Một cảnh tượng rất khác thường hoặc độc đáo, thu hút sự chú ý của mọi người vì quá thú vị."},"10145":{"word":"sự xúc tiến","meaning":"Hành động tích cực giúp đỡ một cái gì đó phát triển, cải thiện hoặc trở nên năng động và thành công hơn."},"10146":{"word":"khối lượng","meaning":"Lượng vật chất vật lí mà một vật thể chứa, làm cho nó có trọng lượng và cản trở sự thay đổi trong chuyển động của nó."},"10147":{"word":"chất vấn","meaning":"Hành động chính thức hỏi ai đó để biết thông tin hoặc giải thích về một chủ đề cụ thể."},"10148":{"word":"vác","meaning":"Đặt một vật nặng hoặc vật chứa qua vai và lưng để vận chuyển từ nơi này sang nơi khác."},"10149":{"word":"(hậu tố) tập","meaning":"Hậu tố dùng để chỉ sự tập hợp hoặc nhóm các vật phẩm tương tự, thường là các tác phẩm sáng tạo như truyện hoặc bài hát, được đóng chung lại."},"10150":{"word":"bà xã","meaning":"Cách nói thông thường và có phần thân mật để gọi người phụ nữ đã kết hôn với mình, người cùng chia sẻ một mái nhà."},"10151":{"word":"việc viết lách","meaning":"Hoạt động sáng tạo một văn bản dài như sách hoặc bài báo."},"10152":{"word":"cuộc tập hợp","meaning":"Một buổi tụ họp đông người có kế hoạch để thảo luận, phản đối hoặc kỷ niệm một mục đích cụ thể."},"10153":{"word":"tinh nghịch","meaning":"Chỉ tính cách thích trêu đùa, chơi khăm người khác một cách vui vẻ, thường gây khó chịu nhỏ."},"10154":{"word":"giẫm đạp","meaning":"Dùng chân giẫm lên cái gì đó liên tục và mạnh, thường làm hư hại hoặc nghiền nát."},"10155":{"word":"án tù","meaning":"Hình phạt do tòa án tuyên, buộc người phạm tội phải ở trong tù một khoảng thời gian."},"10156":{"word":"dớp","meaning":"Một điều hoặc một người được cho là mang lại sự xui xẻo hay vận rủi."},"10157":{"word":"cấu trúc","meaning":"Cách sắp xếp các bộ phận riêng lẻ để tạo thành một tổng thể hoàn chỉnh."},"10158":{"word":"khá ngắn","meaning":"Có độ dài tương đối ngắn."},"10159":{"word":"lườm","meaning":"Nhìn ai đó với ánh mắt giận dữ hoặc không hài lòng."},"10160":{"word":"lúng túng","meaning":"Cảm thấy căng thẳng và không biết phải làm gì, thường thể hiện sự bối rối."},"10161":{"word":"khom người","meaning":"Gập đầu gối và hạ thấp cơ thể xuống gần mặt đất."},"10162":{"word":"ngồi xổm","meaning":"Hạ thấp cơ thể bằng cách gập sâu đầu gối, mông gần sát mặt đất."},"10163":{"word":"thấm đẫm","meaning":"Bị chất lỏng như mồ hôi hoặc bụi bẩn thấm sâu, khiến vật trở nên cũ kỹ hoặc dơ bẩn."},"10164":{"word":"uể oải, nhức mỏi","meaning":"Cảm thấy toàn thân khó chịu, đau nhức nhẹ và nặng nề, khiến việc cử động trở nên khó khăn."},"10165":{"word":"bị đâm, bị châm","meaning":"Bị vật sắc nhọn đâm thủng hoặc xuyên qua, gây ra một vết thương nhỏ."},"10166":{"word":"giã, nghiền","meaning":"Dùng công cụ nặng đập mạnh nhiều lần vào một vật để nghiền nát thành mảnh nhỏ hoặc bột."},"10167":{"word":"gọn gàng, ngăn nắp","meaning":"Theo cách thức các đồ vật được xếp chồng hoặc sắp xếp thành một đống gọn gàng, trật tự."},"10168":{"word":"thứ trưởng","meaning":"Một quan chức cấp cao trong chính phủ, đứng dưới bộ trưởng và hỗ trợ bộ trưởng trong công việc."},"10169":{"word":"chần chừ, trì hoãn liên tục","meaning":"Liên tục hoãn lại một việc gì đó, luôn chọn làm vào lúc khác thay vì ngay lập tức."},"10170":{"word":"trở ngại, trục trặc","meaning":"Một sự kiện hoặc khó khăn không mong muốn làm gián đoạn kế hoạch hoặc quá trình, ngăn cản nó tiếp diễn suôn sẻ."},"10171":{"word":"hạ cánh","meaning":"Hành động của một phương tiện bay, như máy bay, từ trên trời an toàn đáp xuống một bề mặt."},"10172":{"word":"chăm chỉ, đáng tin cậy","meaning":"Luôn chuyên tâm thực hiện công việc một cách cẩn thận và nghiêm túc, thể hiện sự đáng tin cậy."},"10173":{"word":"sai sót, nhầm lẫn","meaning":"Một hành động hoặc phán đoán sai lầm, khác với những gì đúng đắn, chính xác hoặc dự định."},"10174":{"word":"rực rỡ, chói lọi","meaning":"Ở trạng thái ánh sáng rực rỡ hoặc nhiều ánh sáng cùng chiếu sáng, tạo cảm giác lấp lánh, huy hoàng."},"10175":{"word":"tán thành và phản đối","meaning":"Ý kiến đồng tình hoặc phản đối về một vấn đề, kế hoạch hay ý tưởng nào đó."},"10176":{"word":"lời khen ngợi","meaning":"Lời nói hoặc hành động thể hiện sự tán dương và tôn trọng sâu sắc đối với ai đó hoặc điều gì đó."},"10177":{"word":"thánh ca","meaning":"Bài hát ca ngợi tình yêu và phước lành của Chúa trong đạo Thiên Chúa giáo."},"10178":{"word":"sự can thiệp","meaning":"Hành động xen vào việc của người khác khi không được yêu cầu hoặc không mong muốn."},"10179":{"word":"sự lễ bái","meaning":"Hành động cúi lạy hoặc thờ cúng trước một vị thần linh, đền miếu."},"10180":{"word":"xanh xao, nhợt nhạt","meaning":"Da mất đi màu sắc bình thường, trông rất nhạt, thường do ốm yếu hoặc sợ hãi."},"10181":{"word":"tính sáng tạo","meaning":"Khả năng nghĩ ra những ý tưởng mới mẻ, độc đáo và thông minh hoặc cách tạo ra mọi thứ."},"10182":{"word":"tác phẩm sáng tạo","meaning":"Một tác phẩm nghệ thuật mới mẻ, độc đáo do chính mình tạo ra mà không sao chép người khác."},"10183":{"word":"sự tạo ra, sự sáng tạo","meaning":"Hành động mang một cái gì đó mới, như việc làm hoặc giá trị, vào sự tồn tại."},"10184":{"word":"chưa, vẫn còn","meaning":"Từ này dùng để chỉ một hành động hoặc trạng thái chưa hoàn thành hoặc chưa đạt đến mức độ mong muốn."},"10185":{"word":"nhận ra, nhận thấy","meaning":"Đột nhiên nhận biết điều gì đó bằng cách hiểu những dấu hiệu hoặc gợi ý tinh tế."},"10186":{"word":"nhà vợ, bên vợ","meaning":"Ngôi nhà nơi người vợ đã sống với bố mẹ và người thân trước khi kết hôn."},"10187":{"word":"thảm hại","meaning":"Tả cảnh một người hoặc một tình huống cô đơn, bất hạnh đến mức khiến người khác cảm thấy rất buồn thương."},"10188":{"word":"mái hiên","meaning":"Phần mái nhà chìa ra khỏi tường để che mưa nắng."},"10189":{"word":"hoàn cảnh","meaning":"Tình hình cụ thể bao gồm các sự kiện, yếu tố xung quanh một người hoặc một nhóm vào một thời điểm nhất định."},"10190":{"word":"chùng xuống","meaning":"Treo thấp xuống hoặc trở nên lỏng lẻo, thấp hơn vị trí bình thường, như mí mắt mệt mỏi hay vải cũ."},"10191":{"word":"thảm khốc","meaning":"Tả một cảnh tượng hoặc sự kiện rất khủng khiếp, thường liên quan đến tổn thương nặng nề hoặc sự tàn phá, gây ra nỗi kinh hoàng lớn."},"10192":{"word":"cột sống","meaning":"Chuỗi xương dài chạy dọc giữa lưng của người hoặc động vật, có chức năng nâng đỡ và bảo vệ hệ thần kinh."},"10193":{"word":"lều","meaning":"Một cấu trúc được dựng bằng cọc và phủ vải để che gió, mưa, nắng."},"10194":{"word":"may mắn tột cùng","meaning":"Cảm giác hạnh phúc và bình yên tột độ khi một tình huống rất tồi tệ hoặc nguy hiểm đã được tránh khỏi thành công."},"10195":{"word":"thiên bẩm","meaning":"Mô tả một kỹ năng hoặc phẩm chất mà một người có được ngay từ khi sinh ra, không cần phải học hỏi."},"10196":{"word":"trời đất","meaning":"Toàn bộ không gian phía trên chúng ta nơi có sao và mây, và mặt đất chúng ta đứng, thường dùng để tả số lượng hoặc quy mô rất lớn."},"10197":{"word":"hèn mọn","meaning":"Tả địa vị xã hội của một người rất thấp kém, hoặc hành vi, lời nói của ai đó thô lỗ và thiếu tinh tế."},"10198":{"word":"thép","meaning":"Một kim loại màu xám rất cứng và bền, được làm từ sắt và carbon, dùng để chế tạo ô tô, xây dựng và nhiều máy móc khác."},"10199":{"word":"Phá dỡ","meaning":"Việc phá bỏ hoàn toàn một tòa nhà hoặc công trình cũ."},"10200":{"word":"Chim di cư","meaning":"Loại chim bay đường dài từ vùng này sang vùng khác theo mùa để tìm kiếm thời tiết ấm áp hoặc thức ăn."},"10201":{"word":"Rút quân","meaning":"Hành động quân đội hoặc một nhóm người rời khỏi nơi họ đang chiếm đóng hoặc chiến đấu."},"10202":{"word":"Tiên tiến","meaning":"Mô tả công nghệ hoặc phương pháp mới nhất, sáng tạo nhất, đại diện cho mức độ phát triển cao nhất."},"10203":{"word":"Gay gắt","meaning":"Mô tả một xung đột hoặc vấn đề rất mạnh mẽ, chia rẽ rõ ràng, với các bên đối lập bất đồng sâu sắc."},"10204":{"word":"Khán giả","meaning":"Một nhóm người tụ tập để xem một buổi biểu diễn, hòa nhạc, bài phát biểu hoặc sự kiện công cộng khác."},"10205":{"word":"Trong cơ thể","meaning":"Mô tả thứ gì đó nằm hoặc xảy ra bên trong cấu trúc vật lý của một sinh vật sống."},"10206":{"word":"Phạt thể xác","meaning":"Một hình thức kỷ luật liên quan đến việc làm đau về thể chất ai đó, như đánh đập, để buộc họ cư xử theo cách nhất định."},"10207":{"word":"Chế độ","meaning":"Một cách tổ chức cụ thể của một chính phủ hoặc xã hội, bao gồm các quy tắc, luật pháp và cách kiểm soát quyền lực."},"10208":{"word":"Bắt giữ","meaning":"Hành động cảnh sát đưa một người đi và giam giữ họ vì bị cho là đã vi phạm pháp luật."},"10209":{"word":"Nhà tranh mái lá","meaning":"Một ngôi nhà có mái được lợp bằng bó rơm, sậy, v.v."},"10210":{"word":"Siêu năng lực","meaning":"Một khả năng đặc biệt, phi thường mà một người có, như khả năng bay hoặc di chuyển đồ vật mà không chạm vào chúng."},"10211":{"word":"gây ra, dẫn đến","meaning":"Hành động một sự kiện hay hành động nào đó khiến điều khác bắt đầu hoặc xảy ra, thường là điều tiêu cực như vấn đề."},"10212":{"word":"siêu việt, vượt qua","meaning":"Hành động vượt xa những gì bình thường, mong đợi hoặc có thể trong một giới hạn nhất định."},"10213":{"word":"siêu việt, vượt trần","meaning":"Mô tả cái gì đó tồn tại hoặc được cảm nhận là vượt xa thế giới, kinh nghiệm hoặc sự hiểu biết thông thường của con người."},"10214":{"word":"giai đoạn đầu, thời kỳ đầu","meaning":"Giai đoạn đầu tiên của sự tồn tại hoặc phát triển của một cái gì đó, khi nó vừa mới bắt đầu."},"10215":{"word":"xúc giác","meaning":"Khả năng của cơ thể, đặc biệt là da, cảm nhận các vật thể và kết cấu như nóng, lạnh, mịn hoặc thô ráp."},"10216":{"word":"xúc tiến, thúc đẩy","meaning":"Hành động làm cho một quá trình hoặc sự phát triển xảy ra nhanh hơn hoặc dễ dàng hơn bình thường."},"10217":{"word":"ẩm ướt","meaning":"Cảm thấy hoặc trông hơi ướt vì độ ẩm."},"10218":{"word":"tổng số, tổng cộng","meaning":"Toàn bộ số lượng của một cái gì đó khi tất cả các phần hoặc giá trị riêng lẻ của nó được cộng lại."},"10219":{"word":"tổng thể, toàn diện","meaning":"Mô tả cái gì đó bao gồm mọi phần hoặc khía cạnh của một tình huống hoặc chủ đề, xem xét mọi thứ cùng nhau."},"10220":{"word":"độ tuổi cao nhất","meaning":"Độ tuổi cao nhất trong một nhóm hoặc cuộc gặp gỡ nhất định."},"10221":{"word":"cao trào, đỉnh điểm","meaning":"Trạng thái của một bầu không khí, cảm xúc, v.v., đạt đến điểm cao nhất."},"10222":{"word":"tệ nhất, tồi tệ nhất","meaning":"Mức độ chất lượng hoặc tình trạng thấp nhất có thể, thể hiện kết quả hoặc tình huống ít thuận lợi nhất."},"10223":{"word":"trẻ nhất","meaning":"Người có số tuổi ít nhất trong một nhóm người hoặc lĩnh vực cụ thể."},"10224":{"word":"tối ưu","meaning":"Chỉ điều kiện, tình huống hoặc phương pháp tốt nhất, lý tưởng nhất cho một mục đích hoặc nhiệm vụ cụ thể."},"10225":{"word":"tiên tiến nhất","meaning":"Miêu tả công nghệ, thiết bị hoặc phương pháp mới nhất, sáng tạo nhất hiện có, đại diện cho những phát triển mới nhất."},"10226":{"word":"cuối cùng","meaning":"Điểm kết thúc của một chuỗi sự kiện hoặc quá trình, đánh dấu điểm cuối cùng mà sau đó không còn gì tiếp diễn hoặc tồn tại."},"10227":{"word":"truy đuổi","meaning":"Hành động chạy hoặc di chuyển nhanh theo sau ai đó hoặc thứ gì đó để bắt kịp họ."},"10228":{"word":"chọn lọc","meaning":"Kiểm tra kỹ lưỡng một nhóm các vật phẩm hoặc người và chỉ chọn ra những cái mong muốn hoặc tốt nhất."},"10229":{"word":"tưởng niệm","meaning":"Tình trạng suy nghĩ và nhớ thương những người đã khuất."},"10230":{"word":"trừu tượng","meaning":"Miêu tả điều gì đó thể hiện một ý tưởng hoặc cảm xúc thay vì một hình ảnh rõ ràng về một vật thể hoặc người thật."},"10231":{"word":"xu hướng","meaning":"Cách một tình hình, con số hoặc điều kiện thay đổi hoặc phát triển theo thời gian, thường cho thấy một quy luật."},"10232":{"word":"truy tìm","meaning":"Hành động tìm kiếm ai đó hoặc thứ gì đó bằng cách theo dõi kỹ lưỡng các chuyển động hoặc tìm kiếm dấu hiệu vật lý của họ."},"10233":{"word":"ước tính","meaning":"Một phép tính hoặc niềm tin về điều gì đó, được đưa ra bằng cách xem xét thông tin có sẵn nhưng không có bằng chứng chính xác."},"10234":{"word":"ẩm ướt","meaning":"Có cảm giác hoặc trông ẩm ướt do có độ ẩm."},"10235":{"word":"xuất quân","meaning":"Việc cảnh sát, lính cứu hỏa hoặc đội ngũ khẩn cấp nhanh chóng rời khỏi trụ sở để đến xử lý một tình huống cấp bách."},"10236":{"word":"ứng cử","meaning":"Việc một người công khai tuyên bố muốn được xem xét cho một vị trí trong chính phủ hoặc một tổ chức."},"10237":{"word":"ra mắt","meaning":"Sự kiện chính thức một tổ chức, dự án hoặc chính phủ mới bắt đầu hoạt động hoặc tồn tại."},"10238":{"word":"thăng tiến","meaning":"Trạng thái đạt được vị trí xã hội cao hoặc trở nên nổi tiếng, được công nhận."},"10239":{"word":"ra đề thi","meaning":"Việc giáo viên hoặc chuyên gia tạo ra và viết các câu hỏi mà học sinh phải trả lời trong một bài kiểm tra chính thức."},"10240":{"word":"gửi tác phẩm","meaning":"Hành động mang hoặc gửi một tác phẩm nghệ thuật sáng tạo (như tranh, điêu khắc) đến một sự kiện công cộng để mọi người chiêm ngưỡng."},"10241":{"word":"chảy máu","meaning":"Hiện tượng chất lỏng màu đỏ trong cơ thể liên tục chảy ra từ vết thương hoặc lỗ hở trên cơ thể người hoặc động vật."},"10242":{"word":"sự đầy đủ","meaning":"Chất lượng của việc có nhiều sự kiện, chi tiết hoặc ý tưởng quan trọng, làm cho cái gì đó hoàn chỉnh và có giá trị."},"10243":{"word":"tận tâm","meaning":"Thực hiện điều gì đó với sự tận tâm và cẩn thận, đúng như đã hứa hoặc yêu cầu, thể hiện cam kết mạnh mẽ."},"10244":{"word":"sự dễ bị tổn thương","meaning":"Trạng thái dễ dàng bị tổn hại, hư hỏng hoặc ảnh hưởng tiêu cực bởi một yếu tố nào đó."},"10245":{"word":"nhậm chức","meaning":"Hành động chính thức bắt đầu đảm nhiệm một công việc hoặc nhiệm vụ mới sau khi được bầu hoặc bổ nhiệm."},"10246":{"word":"mục đích","meaning":"Ý tưởng chính hoặc lý do cơ bản giải thích tại sao một hành động, kế hoạch hoặc tuyên bố cụ thể được thực hiện."},"10247":{"word":"nhập học","meaning":"Việc trẻ em bắt đầu đến trường học để tiếp nhận giáo dục."},"10248":{"word":"đo lường","meaning":"Hành động xác định số lượng, kích thước hoặc mức độ của một thứ gì đó bằng cách so sánh với một đơn vị tiêu chuẩn."},"10249":{"word":"giá trị (hậu tố)","meaning":"Hậu tố chỉ một con số hoặc mức độ thể hiện số lượng hoặc mức độ của một cái gì đó, thường ở điểm cao nhất hoặc thấp nhất."},"10250":{"word":"lao tới, vọt lên","meaning":"Di chuyển rất nhanh và mạnh mẽ theo một hướng nhất định, thường là hướng lên trên hoặc đến một điểm được chỉ định."},"10251":{"word":"bệnh mất trí nhớ","meaning":"Một căn bệnh nghiêm trọng, thường gặp ở người lớn tuổi, khiến trí nhớ và khả năng suy nghĩ của người bệnh suy giảm dần, gây khó khăn trong sinh hoạt hàng ngày."},"10252":{"word":"chí mạng, gây chết người","meaning":"Miêu tả cái gì đó gây ra cái chết hoặc gây ra thiệt hại nghiêm trọng đến mức không thể phục hồi được."},"10253":{"word":"dâng lên, trỗi lên","meaning":"Mạnh mẽ dâng lên hoặc trỗi dậy từ dưới lên trên."},"10254":{"word":"vụt lên, vọt lên","meaning":"Di chuyển hoặc vươn nhanh và đột ngột lên cao trong không khí hoặc đến một vị trí cao hơn."},"10255":{"word":"trị an, an ninh công cộng","meaning":"Tình trạng bình yên và an toàn của một quốc gia hoặc khu vực nơi luật pháp được tuân thủ và người dân được bảo vệ khỏi tội phạm và tổn hại."},"10256":{"word":"gay gắt, ác liệt","meaning":"Miêu tả một tình huống, ví dụ như một cuộc cạnh tranh hay chiến đấu, nơi có sự đấu tranh rất mạnh mẽ và quyết liệt giữa các bên đối lập."},"10257":{"word":"sỉ nhục, nhục nhã","meaning":"Cảm giác xấu hổ sâu sắc hoặc sự mất danh dự công khai, thường do một sự kiện đáng hổ thẹn hoặc một hành động sai trái gây ra."},"10258":{"word":"thiên vị, nghiêng về","meaning":"Có xu hướng nghiêng về một phía, hoặc ủng hộ không công bằng một người, ý tưởng, hoặc nhóm này hơn nhóm khác."},"10259":{"word":"chữa trị, hồi phục","meaning":"Quá trình bệnh tật hoặc vết thương dần hồi phục và khỏe mạnh trở lại."},"10260":{"word":"chú trọng, tập trung","meaning":"Hành động tập trung sự quan tâm đặc biệt vào một phần hoặc khía cạnh nào đó của vấn đề."},"10261":{"word":"giơ lên, ngẩng lên","meaning":"Nâng một vật hoặc một bộ phận cơ thể như đầu, tay lên vị trí cao hơn."},"10262":{"word":"tình hữu nghị, tình thân hữu","meaning":"Mối quan hệ thân thiết, ấm áp giữa những người có sự gắn bó, tin tưởng và hỗ trợ lẫn nhau."},"10263":{"word":"thân quen, quen thuộc","meaning":"Diễn tả việc một người hoặc vật nào đó trở nên quen thuộc, thoải mái với một người khác do thường xuyên tiếp xúc."},"10264":{"word":"sự hòa hợp, tính thân thiện","meaning":"Sự tương đồng hoặc hài hòa rõ ràng, kết nối một vật này với vật khác, ví dụ như thiết kế hòa hợp với thiên nhiên."},"10265":{"word":"khả năng hòa đồng, sự thân thiện","meaning":"Khả năng một người dễ dàng hòa nhập với người khác và kết bạn mới."},"10266":{"word":"bảy lần ngã tám lần đứng dậy, kiên cường không bỏ cuộc","meaning":"Thái độ tiếp tục cố gắng đứng dậy mỗi khi trải qua thất bại hoặc vấp ngã."},"10267":{"word":"xâm phạm, xâm lấn","meaning":"Hành động từ từ chiếm lấy không gian, đất đai hoặc quyền lợi của người khác mà không được phép."},"10268":{"word":"xâm nhập, xâm lược","meaning":"Hành động một đội quân hoặc nhóm người ép buộc tiến vào lãnh thổ hoặc tòa nhà không thuộc về họ."},"10269":{"word":"thời kỳ suy thoái","meaning":"Giai đoạn nền kinh tế yếu kém, các doanh nghiệp kinh doanh thua lỗ và nhiều người bị mất việc làm."},"10270":{"word":"gọi là, xưng là","meaning":"Đặt một danh hiệu hoặc tên gọi cụ thể cho ai đó hoặc một cái gì đó, thường bằng lời nói hoặc văn bản."},"10271":{"word":"đào, bới","meaning":"Lấy thứ gì đó ra khỏi lòng đất bằng cách đào bới."},"10272":{"word":"tra hỏi, gặng hỏi","meaning":"Hỏi đi hỏi lại nhiều lần một cách quyết liệt để tìm ra thông tin hoặc lý do bị giấu kín."},"10273":{"word":"cắm trại","meaning":"Hoạt động ngoài trời ngủ qua đêm trong lều hoặc nơi trú ẩn tạm thời, thường nấu ăn trên lửa."},"10274":{"word":"thể trạng, tình trạng sức khỏe","meaning":"Sức khỏe và năng lượng tổng thể của cơ thể một người tại một thời điểm cụ thể."},"10275":{"word":"huấn luyện viên","meaning":"Người hướng dẫn và đào tạo vận động viên hoặc người biểu diễn để giúp họ cải thiện kỹ năng và chiến lược."},"10276":{"word":"sống mũi","meaning":"Phần cứng, có xương của mũi người, kéo dài xuống từ giữa hai mắt."},"10277":{"word":"khoái cảm","meaning":"Cảm giác rất dễ chịu."},"10278":{"word":"khoái lạc","meaning":"Cảm giác thỏa mãn mạnh mẽ, dễ chịu khiến một người mỉm cười hoặc cảm thấy hài lòng."},"10279":{"word":"khoác lác, nói khoác","meaning":"Nói về khả năng hoặc thành tích của bản thân một cách tự tin thái quá, thường là đưa ra những lời hứa khó thực hiện."},"10280":{"word":"đòn giáng, cú sốc","meaning":"Một cú sốc mạnh hoặc tác động tiêu cực nghiêm trọng ảnh hưởng đến ai đó hoặc cái gì đó về mặt thể chất hoặc tinh thần."},"10281":{"word":"tính hợp lệ, tính xác đáng","meaning":"Chất lượng của một ý tưởng hoặc tuyên bố được hỗ trợ mạnh mẽ bởi các sự kiện và lý do xác đáng, khiến nó đứng vững trước sự kiểm tra."},"10282":{"word":"hợp lệ, xác đáng","meaning":"Một tuyên bố hoặc ý tưởng được hỗ trợ mạnh mẽ bởi các sự kiện hoặc logic, được coi là đúng và không thể dễ dàng bác bỏ."},"10283":{"word":"bài học từ sai lầm của người khác","meaning":"Việc lấy những hành vi không tốt hoặc lỗi lầm của người khác làm kinh nghiệm để tự kiểm điểm và sửa chữa bản thân mình."},"10284":{"word":"khuyên răn","meaning":"Nói chuyện một cách nhẹ nhàng nhưng kiên quyết để chỉ ra lỗi lầm và hướng dẫn ai đó cải thiện hành vi của họ."},"10285":{"word":"thỏa hiệp","meaning":"Sự đồng ý đạt được khi hai bên đối lập đều nhượng bộ một phần yêu cầu của mình để có thể thống nhất một giải pháp chung."},"10286":{"word":"toang","meaning":"Diễn tả một hành động xảy ra bất ngờ và rõ ràng, như âm thanh dứt khoát khi vật thể va chạm hoặc một không gian được mở ra hoàn toàn."},"10287":{"word":"xuất sắc","meaning":"Miêu tả ai đó hoặc cái gì đó có kỹ năng đặc biệt hoặc chất lượng rất cao, khiến họ nổi bật và vượt trội hơn so với những người khác."},"10288":{"word":"độ đàn hồi","meaning":"Đặc tính vật lý của một vật liệu hoặc cơ thể cho phép nó co giãn hoặc thay đổi hình dạng dưới áp lực, sau đó nhanh chóng trở lại hình dạng ban đầu."},"10289":{"word":"tiếng kêu cảm thán","meaning":"Một âm thanh đột ngột, rõ ràng mà ai đó phát ra để thể hiện cảm xúc mạnh như bất ngờ, sốc hoặc ngưỡng mộ."},"10290":{"word":"tiếng thở dài","meaning":"Một hơi thở dài, có thể nghe được mà ai đó phát ra để thể hiện cảm giác buồn bã, hối tiếc hoặc mệt mỏi."},"10291":{"word":"sự đàn áp","meaning":"Hành động một nhóm hoặc chính phủ có quyền lực đối xử khắc nghiệt và bất công với người dân, thường bằng cách sử dụng vũ lực để hạn chế tự do và quyền của họ."},"10292":{"word":"săn chắc","meaning":"Miêu tả cái gì đó, như cơ bắp hoặc cấu trúc, rất khỏe, gọn và không dễ bị biến dạng khi chạm vào hoặc đẩy."},"10293":{"word":"một cách vững chắc","meaning":"Diễn tả một hành động được thực hiện theo cách làm cho cái gì đó rất chắc chắn, an toàn và ổn định, không dễ bị di chuyển hoặc hủy bỏ."},"10294":{"word":"hậu-, phi-","meaning":"Một tiền tố được thêm vào đầu một từ khác, cho biết điều gì đó xảy ra sau một sự kiện hoặc giai đoạn cụ thể, hoặc điều gì đó đang bị loại bỏ hoặc hủy bỏ."},"10295":{"word":"sự tìm tòi","meaning":"Quá trình tìm hiểu kỹ lưỡng và có hệ thống về một chủ đề hoặc lĩnh vực để thu thập kiến thức mới hoặc tìm ra câu trả lời."},"10296":{"word":"thai giáo","meaning":"Việc người mẹ mang thai luôn suy nghĩ tốt đẹp và giữ gìn lời ăn tiếng nói để mang lại ảnh hưởng tốt cho thai nhi."},"10297":{"word":"sự lĩnh hội","meaning":"Việc hiểu và nắm vững một kĩ năng hay phương pháp bí mật thông qua học hỏi hoặc luyện tập."},"10298":{"word":"vô lý","meaning":"Nói về một điều gì đó không có cơ sở logic hay căn cứ thực tế, khiến cho người khác khó có thể tin được."},"10299":{"word":"mảnh đất","meaning":"Mảnh đất phù hợp để xây dựng nhà cửa."},"10300":{"word":"làm nổ","meaning":"Tác động vào bề mặt của vật gì đó khiến nó vỡ tung hoặc bật mở ra."},"10301":{"word":"thiếu thốn nghiêm trọng","meaning":"Chỉ mức độ thiếu hụt một cách trầm trọng, đến mức bất ngờ và không thể chấp nhận được so với yêu cầu."},"10302":{"word":"bịch","meaning":"Diễn tả âm thanh hoặc hành động của vật nặng và mềm bất ngờ rơi hoặc ngồi xuống một cách nhanh chóng."},"10303":{"word":"giãi bày","meaning":"Nói ra một cách cởi mở về một bí mật hay chuyện riêng tư mà mình đã giữ kín."},"10304":{"word":"viền","meaning":"Đường kẻ liên tục hoặc dải rõ ràng đánh dấu giới hạn bên ngoài hoặc phần bao quanh của một vật thể hay khu vực."},"10305":{"word":"lách tách","meaning":"Diễn tả âm thanh hoặc hành động của những vật nhỏ nổ hoặc bật mở liên tục."},"10306":{"word":"đích đáng","meaning":"Diễn tả mức độ đầy đủ, thỏa đáng hoặc nghiêm trọng khi phải chịu đựng điều gì đó (thường là tiêu cực như bị mắng, bị phạt)."},"10307":{"word":"quan niệm phổ biến","meaning":"Quan niệm hoặc niềm tin được nhiều người chấp nhận trong xã hội."},"10308":{"word":"thông báo","meaning":"Tin tức hoặc thông tin được truyền đạt chính thức đến một người."},"10309":{"word":"thương mại","meaning":"Hoạt động mua bán hàng hóa và dịch vụ giữa các cá nhân, doanh nghiệp hoặc quốc gia."},"10310":{"word":"tính thông tục","meaning":"Tính chất phổ biến, được số đông ưa chuộng nhưng đôi khi thiếu chiều sâu hoặc sự độc đáo."},"10311":{"word":"sự thông dụng","meaning":"Trạng thái được chấp nhận và sử dụng rộng rãi bởi nhiều người trong một phạm vi nhất định."},"10312":{"word":"toàn bộ","meaning":"Toàn bộ một vật thể hoặc một phần mà không bị chia tách."},"10313":{"word":"sự cai trị","meaning":"Hành động cai quản, điều hành một quốc gia hoặc một nhóm người, đưa ra luật lệ và quyết định."},"10314":{"word":"thỏa mãn, sảng khoái","meaning":"Cảm thấy rất vui mừng, nhẹ nhõm hoặc hả hê khi một việc khó khăn được hoàn thành hoặc một điều sai trái được giải quyết."},"10315":{"word":"gộp chung","meaning":"Gộp tất cả các yếu tố hoặc bộ phận riêng lẻ lại thành một tổng thể duy nhất."},"10316":{"word":"thông gió","meaning":"Hành động cho không khí lưu thông qua một không gian để thay đổi không khí cũ bằng không khí trong lành."},"10317":{"word":"thôi nhiệm","meaning":"Việc một người chính thức rời bỏ một chức vụ cấp cao hoặc công việc sau khi hoàn thành nhiệm kỳ hoặc đủ thời gian phục vụ."},"10318":{"word":"từ chức","meaning":"Việc một người ở vị trí chính thức cao cấp từ bỏ công việc hoặc vai trò của mình, thường do áp lực hoặc trách nhiệm."},"10319":{"word":"đầu cơ","meaning":"Hoạt động mua bán hàng hóa, cổ phiếu hoặc tài sản không phải để sử dụng mà để bán lại kiếm lời nhanh chóng từ sự thay đổi giá."},"10320":{"word":"thô kệch","meaning":"Miêu tả vật gì đó hoặc đôi tay có vẻ ngoài không tinh tế, chắc khỏe nhưng thiếu đi sự mềm mại, tinh xảo."},"10321":{"word":"chống chọi với bệnh tật","meaning":"Giai đoạn dài và khó khăn khi một người bệnh phải điều trị y tế và cố gắng hết sức để phục hồi từ một căn bệnh nặng."},"10322":{"word":"đưa vào","meaning":"Hành động đặt cái gì đó, như tiền giấy, vào một khe hở hoặc hệ thống để sử dụng."},"10323":{"word":"đấu tranh","meaning":"Sự nỗ lực lâu dài và kiên quyết của các cá nhân hoặc nhóm để vượt qua khó khăn hoặc đạt được mục tiêu, thường là chống lại sự phản đối mạnh mẽ."},"10324":{"word":"mè nheo","meaning":"Hành động của một người, đặc biệt là trẻ nhỏ, bày tỏ sự không hài lòng bằng cách nói những lời khó chịu hoặc làm những tiếng động nhỏ."},"10325":{"word":"kiên định","meaning":"Miêu tả tư tưởng, ý chí, tình cảm rất mạnh mẽ, vững vàng và không dễ thay đổi."},"10326":{"word":"nảy mầm","meaning":"Khi một phần nhỏ, mới của cây bắt đầu nhú ra từ hạt, đất hoặc cành."},"10327":{"word":"mở đường","meaning":"Loại bỏ chướng ngại vật để tạo ra một lối đi hoặc con đường thông suốt, cho phép người hoặc vật di chuyển qua."},"10328":{"word":"ợ hơi","meaning":"Hành động khí trong dạ dày thoát ra ngoài qua miệng; hoặc khí đó."},"10329":{"word":"bới móc","meaning":"Hành động phàn nàn hoặc gây rắc rối một cách vô cớ bằng cách phóng đại một lỗi nhỏ, hoặc sự phàn nàn, rắc rối đó."},"10330":{"word":"đặc quyền","meaning":"Quyền lợi đặc biệt, sự cho phép riêng hoặc cơ hội duy nhất mà chỉ một số người nhất định có được do địa vị hoặc vị trí của họ."},"10331":{"word":"tính đặc thù","meaning":"Tính chất riêng biệt, khác với những cái khác, làm cho một cái gì đó trở nên đặc biệt."},"10332":{"word":"đặc tính","meaning":"Một đặc điểm riêng biệt hoặc tính chất nổi bật giúp nhận dạng hoặc mô tả một người, vật, hay hiện tượng."},"10333":{"word":"chuyên mục đặc biệt","meaning":"Một bài báo, chương trình truyền hình hoặc phần của tạp chí tập trung sâu vào một chủ đề cụ thể, thường dài và chi tiết hơn bình thường."},"10334":{"word":"đặc trưng","meaning":"Có những đặc điểm tiêu biểu, giúp nhận ra một người, vật hoặc hiện tượng cụ thể."},"10335":{"word":"bằng sáng chế","meaning":"Văn bản chính thức của chính phủ cấp quyền độc quyền sản xuất, sử dụng hoặc bán một phát minh trong một khoảng thời gian nhất định."},"10336":{"word":"đặc ân","meaning":"Sự giúp đỡ hoặc lợi ích đặc biệt mà một người nhận được, không phải ai cũng có."},"10337":{"word":"vững chắc","meaning":"Với cách thức chắc chắn, bền vững, khó bị phá vỡ hoặc di chuyển."},"10338":{"word":"khuôn","meaning":"Một cấu trúc cứng bao quanh vật gì đó hoặc dùng để tạo hình cụ thể cho một vật liệu."},"10339":{"word":"bịt kín","meaning":"Ngăn chặn hoàn toàn một lỗ hở hoặc lối đi, không cho bất cứ thứ gì lọt vào hoặc thoát ra."},"10340":{"word":"chôn chân","meaning":"Ở yên một chỗ, không ra ngoài, thường là trong phòng hoặc trong nhà."},"10341":{"word":"khe hở","meaning":"Một không gian nhỏ, hẹp hoặc lỗ trống tồn tại giữa hai vật thể hoặc bề mặt."},"10342":{"word":"cãi vặt","meaning":"Tranh cãi với ai đó nhiều lần về những điều nhỏ nhặt, không quan trọng, thường bằng những lời lẽ nhanh và ngắn gọn."},"10343":{"word":"hạt bụi","meaning":"Đây là một mảnh vật chất rất nhỏ, có thể bay lơ lửng trong không khí hoặc đọng lại trên bề mặt."},"10344":{"word":"đột phá","meaning":"Từ này dùng để mô tả một điều gì đó rất khác thường, không theo quy tắc hay truyền thống, thường gây ngạc nhiên."},"10345":{"word":"phái cử","meaning":"Đây là hành động cử người đến một địa điểm cụ thể để thực hiện một mục đích hoặc nhiệm vụ nhất định."},"10346":{"word":"ảnh hưởng lan rộng","meaning":"Đây là một tình huống khi một sự kiện tạo ra một chuỗi các hậu quả lan rộng và ảnh hưởng đến nhiều thứ khác."},"10347":{"word":"đào lên","meaning":"Đây là hành động loại bỏ thứ gì đó ra khỏi mặt đất hoặc sâu bên trong vật liệu khác bằng cách tạo một cái hố."},"10348":{"word":"thăng trầm","meaning":"Từ này mô tả một khoảng thời gian hoặc cuộc đời của một người có nhiều trải nghiệm đáng kể và đa dạng, cả tích cực lẫn thử thách."},"10349":{"word":"hủy diệt","meaning":"Đây là trạng thái sụp đổ hoàn toàn, hư hại nghiêm trọng hoặc bị xóa sổ, khi một thứ gì đó hoàn toàn tan vỡ hoặc kết thúc."},"10350":{"word":"sóng gợn","meaning":"Đây là làn sóng lan rộng trên mặt nước, hoặc hậu quả sâu rộng từ một sự kiện cụ thể."},"10351":{"word":"đình công","meaning":"Đây là khoảng thời gian một nhóm nhân viên ngừng làm việc để phản đối điều kiện lao động hoặc yêu cầu tăng lương."},"10352":{"word":"ống","meaning":"Đây là một vật hình trụ rỗng bên trong, dùng để dẫn nước, khí đốt, v.v."},"10353":{"word":"bước sóng","meaning":"Trong sóng vô tuyến hoặc sóng âm thanh, đây là khoảng cách giữa hai điểm lân cận cùng pha."},"10354":{"word":"đào bới","meaning":"Đây là hành động loại bỏ đất hoặc vật liệu khác một cách thô bạo và nhanh chóng để tìm ra thứ gì đó bị giấu kín, hoặc để phơi bày thông tin bí mật."},"10355":{"word":"phán quyết","meaning":"Quyết định chính thức của thẩm phán hoặc bồi thẩm đoàn tại tòa án, tuyên bố có tội hay vô tội."},"10356":{"word":"sự sáng tỏ","meaning":"Việc một sự thật hay vấn đề nào đó cuối cùng được làm rõ và được biết đến."},"10357":{"word":"hoàn toàn khác biệt","meaning":"Có sự khác biệt lớn, không có điểm tương đồng hay giống nhau chút nào."},"10358":{"word":"phán định","meaning":"Quyết định cuối cùng được đưa ra sau khi xem xét kỹ lưỡng các sự thật hoặc bằng chứng, thường bởi một người có thẩm quyền hoặc chuyên gia."},"10359":{"word":"khuyến mãi, xúc tiến bán hàng","meaning":"Các hoạt động nhằm khuyến khích khách hàng mua sản phẩm hoặc dịch vụ, như quảng cáo, giảm giá hoặc tặng quà."},"10360":{"word":"người đa tài","meaning":"Người giỏi nhiều mặt, làm được nhiều việc và đạt được thành công trong hầu hết mọi lĩnh vực."},"10361":{"word":"số phận, vận mệnh","meaning":"Con đường và chuỗi sự kiện được cho là đã định sẵn cho cuộc đời mỗi người."},"10362":{"word":"phe cánh, nhóm","meaning":"Một nhóm nhỏ người tập hợp lại vì có chung lợi ích hoặc mục đích."},"10363":{"word":"khí phách, sự hăng hái","meaning":"Tinh thần mạnh mẽ, dũng cảm và đầy nhiệt huyết để đạt được mục tiêu, thường thấy ở tuổi trẻ."},"10364":{"word":"sự thất bại","meaning":"Tình trạng bị đánh bại trong một cuộc thi đấu, cuộc chiến hoặc cuộc tranh giành, không giành được chiến thắng."},"10365":{"word":"người thua cuộc","meaning":"Người hoặc đội bị đánh bại trong một cuộc thi đấu, tranh chấp hoặc xung đột."},"10366":{"word":"mẫu, mô hình","meaning":"Một cách thức lặp đi lặp lại hoặc một trình tự có thể quan sát được trong cách một sự việc diễn ra."},"10367":{"word":"vứt bỏ, quăng bỏ","meaning":"Vứt cái gì đó đi một cách không cẩn thận, thường là với ý định từ bỏ hoặc không quan tâm."},"10368":{"word":"sự bành trướng, sự giãn nở","meaning":"Hiện tượng một vật thể trở nên lớn hơn về kích thước, thể tích hoặc phạm vi, từ một điểm trung tâm lan ra ngoài."},"10369":{"word":"căng, căng chặt","meaning":"Trạng thái của dây, sợi hoặc vải được kéo thẳng và chặt, không còn lỏng lẻo hay chùng xuống."},"10370":{"word":"trút xuống, đổ xuống","meaning":"Mưa hoặc tuyết rơi từ trên trời xuống rất nhiều và liên tục."},"10371":{"word":"bật nhảy, chồm lên","meaning":"Mô tả hành động một người hoặc con vật nhanh chóng lấy đà bật người lên khỏi mặt đất và lên cao."},"10372":{"word":"sùng sục, sôi sùng sục","meaning":"Từ miêu tả trạng thái một lượng lớn nước, dầu, v.v., sôi mạnh và liên tục, phát ra tiếng ồn."},"10373":{"word":"chim cánh cụt","meaning":"Một loài chim lớn không biết bay, có lông màu đen trắng, sống ở vùng lạnh và di chuyển bằng những bước ngắn trong tư thế thẳng đứng."},"10374":{"word":"bênh vực, đứng về phía","meaning":"Thể hiện sự ủng hộ mạnh mẽ cho một người hoặc một nhóm trong một cuộc tranh luận hoặc bất đồng."},"10375":{"word":"việc chuyển trường/chuyển ngành","meaning":"Hành động chuyển từ một cơ sở giáo dục này sang một cơ sở giáo dục khác và chính thức gia nhập."},"10376":{"word":"có tính thiên vị, không công bằng","meaning":"Miêu tả thông tin hoặc ý kiến ủng hộ một cách không công bằng một nhóm hoặc ý tưởng so với những nhóm khác, không trung lập."},"10377":{"word":"sự bình luận, bài bình luận","meaning":"Hành động đánh giá và nhận xét về giá trị, cái đúng cái sai, điểm mạnh điểm yếu của một đối tượng, hoặc một bài viết như vậy."},"10378":{"word":"mặt phẳng","meaning":"Một khu vực hoàn toàn đều và nhẵn, trải rộng theo hai chiều mà không có bất kỳ chỗ lồi lõm hay đường cong nào."},"10379":{"word":"đồng bằng","meaning":"Một vùng đất rộng lớn có bề mặt phẳng, không có đồi núi."},"10380":{"word":"sự bình yên","meaning":"Trạng thái yên tĩnh, không có điều gì gây xáo động đến tâm trí hoặc môi trường xung quanh."},"10381":{"word":"dễ, đơn giản","meaning":"Dễ hiểu hoặc dễ thực hiện mà không cần nhiều nỗ lực."},"10382":{"word":"bằng phẳng","meaning":"Bề mặt không có chỗ lồi lõm, không nghiêng lệch, hoàn toàn mịn màng."},"10383":{"word":"mang tính hòa bình","meaning":"Liên quan đến việc giải quyết vấn đề mà không dùng bạo lực, xung đột, nhằm đạt được sự đồng thuận êm đẹp."},"10384":{"word":"chất thải, rác thải","meaning":"Những vật liệu hoặc đồ vật mà con người không còn cần hoặc muốn dùng nữa và vứt bỏ đi."},"10385":{"word":"viêm phổi","meaning":"Một bệnh nặng gây viêm nhiễm phổi, dẫn đến ho, sốt và khó thở."},"10386":{"word":"lễ bế mạc","meaning":"Buổi lễ công khai chính thức diễn ra để kết thúc một sự kiện lớn như cuộc thi hoặc lễ hội."},"10387":{"word":"sự đóng cửa, sự phong tỏa","meaning":"Hành động đóng hoàn toàn hoặc chặn lối vào một địa điểm, doanh nghiệp, ngăn không cho ai vào hoặc sử dụng."},"10388":{"word":"mang tính khép kín","meaning":"Miêu tả một nơi hoặc nhóm người ngăn cản mạnh mẽ người ngoài tham gia hoặc vào được."},"10389":{"word":"giờ đóng cửa","meaning":"Thời điểm cụ thể khi một doanh nghiệp hoặc nơi công cộng ngừng cho khách vào và chuẩn bị đóng cửa trong ngày."},"10390":{"word":"tác hại, tai hại","meaning":"Một nhược điểm rõ ràng hoặc tổn thất về mặt vật chất gây ra bởi một điều gì đó."},"10391":{"word":"hoang tàn, tàn tích","meaning":"Những phần còn lại đổ nát của một công trình hoặc thành phố sau khi bị phá hủy nghiêm trọng."},"10392":{"word":"dung tích phổi","meaning":"Tổng lượng không khí mà phổi có thể chứa khi hít vào đầy."},"10393":{"word":"hoài bão, khát vọng","meaning":"Một mục tiêu lớn lao hoặc ước mơ trong tương lai mà ai đó cố gắng đạt được."},"10394":{"word":"bao dung, độ lượng","meaning":"Sự hiểu biết và chấp nhận người khác với tấm lòng rộng mở."},"10395":{"word":"ném bom, oanh tạc","meaning":"Hành động máy bay quân sự thả bom xuống một khu vực mục tiêu."},"10396":{"word":"tăng vọt, tăng mạnh","meaning":"Sự tăng giá hoặc số lượng đột ngột và rất nhanh chóng của một cái gì đó."},"10397":{"word":"giảm mạnh, sụt giá","meaning":"Sự giảm giá hoặc số lượng đột ngột và rất nhanh chóng của một cái gì đó."},"10398":{"word":"vạch trần, phơi bày","meaning":"Hành động công khai thông tin bí mật hoặc chưa được biết đến."},"10399":{"word":"nắng nóng gay gắt, đợt nắng nóng","meaning":"Một khoảng thời gian dài thời tiết nóng bức bất thường và khó chịu."},"10400":{"word":"cho nổ, phá hủy bằng chất nổ","meaning":"Hành động dùng chất nổ để làm một vật thể bị vỡ tung ra đột ngột."},"10401":{"word":"bão, giông bão","meaning":"Một đợt thời tiết rất xấu với gió mạnh, mưa lớn hoặc tuyết."},"10402":{"word":"hành hung, bạo hành","meaning":"Hành động dùng vũ lực gây hại đến thân thể của người khác."},"10403":{"word":"trôi dạt","meaning":"Tình trạng bị nước hoặc gió cuốn đi mà không có phương hướng hay sự kiểm soát nào."},"10404":{"word":"hời hợt","meaning":"Chỉ cái gì đó chỉ ở lớp bên ngoài, không đi sâu vào bên trong, thiếu chiều sâu."},"10405":{"word":"bày tỏ","meaning":"Hành động làm cho suy nghĩ, cảm xúc hoặc ý định của mình được người khác biết rõ, thường bằng lời nói hoặc văn bản."},"10406":{"word":"chủ trương","meaning":"Hành động công khai nói rằng mình ủng hộ một ý tưởng hoặc nguyên tắc cụ thể như là điều mình tin tưởng."},"10407":{"word":"mẫu","meaning":"Một lượng nhỏ hoặc một phần của một vật lớn hơn được thu thập để cho thấy toàn bộ nhóm trông như thế nào."},"10408":{"word":"khẩu hiệu","meaning":"Một câu nói hoặc thông điệp ngắn gọn thể hiện một lập trường một cách đơn giản và dễ nhớ."},"10409":{"word":"mục tiêu","meaning":"Một vật thể hoặc nơi mà mọi người cố gắng đánh trúng hoặc đạt tới, như hồng tâm trong bắn cung."},"10410":{"word":"ấm cúng","meaning":"Diễn tả cảm giác hoặc nơi dễ chịu, mềm mại, nhẹ nhàng và mang lại sự an ủi, thoải mái."},"10411":{"word":"cằn nhằn","meaning":"Hành động nói về sự không hài lòng hoặc lời phàn nàn của mình một cách nhỏ nhẹ, liên tục."},"10412":{"word":"bạc đãi","meaning":"Hành động cư xử một cách không thân thiện và không chào đón đối với ai đó, thể hiện ít sự tôn trọng hoặc quan tâm."},"10413":{"word":"cỏ","meaning":"Loại thực vật thân mềm, lá nhỏ, màu xanh mọc thành từng đám trên mặt đất."},"10414":{"word":"giải quyết","meaning":"Tìm ra câu trả lời hoặc phương pháp thành công để làm cho một tình huống hoặc vấn đề khó khăn trở nên dễ hiểu và rõ ràng."},"10415":{"word":"thả ra","meaning":"Cho phép vật gì đó đã bị buộc, bị nhốt có thể tự do đi khỏi."},"10416":{"word":"phẩm cách","meaning":"Giá trị, phẩm chất thể hiện qua lời nói, hành động, thái độ của một người, khiến người khác phải tôn trọng và ngưỡng mộ."},"10417":{"word":"phẩm giá","meaning":"Phẩm chất cao quý và thanh lịch mà một người cần có."},"10418":{"word":"giống","meaning":"Loại hoặc chủng của động vật, thực vật hoặc hàng hóa."},"10419":{"word":"phẩm hạnh","meaning":"Cách một người hành động hoặc ứng xử, đặc biệt là những hành động và thái độ họ thể hiện ra bên ngoài với người khác."},"10420":{"word":"tươi trẻ","meaning":"Mang vẻ mới mẻ, trẻ trung, chưa có kinh nghiệm và đầy sức sống."},"10421":{"word":"châm biếm","meaning":"Lối viết, vẽ hoặc trình diễn sử dụng sự hài hước, phóng đại hay mỉa mai để chỉ ra và chế giễu sự ngốc nghếch của con người hoặc các vấn đề xã hội."},"10422":{"word":"khuynh hướng","meaning":"Một hình mẫu hành động hoặc niềm tin lan rộng trong một nhóm người, khiến họ thường hành động hoặc suy nghĩ theo cách tương tự."},"10423":{"word":"phong phú","meaning":"Diễn tả tình trạng tài nguyên hoặc vật phẩm có số lượng lớn, tràn đầy hoặc vượt xa những gì cần thiết."},"10424":{"word":"phong thổ","meaning":"Đặc điểm môi trường tự nhiên của một vùng, bao gồm thời tiết điển hình, hoặc thói quen và quan niệm được chấp nhận rộng rãi trong một xã hội."},"10425":{"word":"bị đơn","meaning":"Trong một tranh chấp pháp lý, là người bị kiện và phải ra tòa để trả lời."},"10426":{"word":"bị cáo","meaning":"Người bị chính thức buộc tội hình sự và phải ra tòa để đối mặt với các cáo buộc đó."},"10427":{"word":"bày tỏ","meaning":"Hành động thể hiện rõ ràng suy nghĩ, cảm xúc hoặc quan điểm của mình cho người khác biết."},"10428":{"word":"bị sát hại","meaning":"Việc một người bị người khác tấn công và mất mạng một cách bạo lực."},"10429":{"word":"đôi bên","meaning":"Diễn tả tình huống mà cả hai bên liên quan đều ở trong trạng thái tương tự hoặc bị ảnh hưởng như nhau."},"10430":{"word":"tất yếu","meaning":"Diễn tả một sự việc hoặc kết quả chắc chắn sẽ xảy ra và không thể ngăn cản hay thay đổi được."},"10431":{"word":"tác giả","meaning":"Người đã viết ra một cuốn sách, bài báo hoặc bất kỳ tác phẩm văn bản nào khác."},"10432":{"word":"mạch máu","meaning":"Một ống trong cơ thể mà máu chảy qua."},"10433":{"word":"đồng loạt","meaning":"Diễn tả tình huống mọi thành viên trong một nhóm đều thể hiện đặc điểm hoặc thực hiện hành động giống hệt nhau."},"10434":{"word":"xu hướng giảm","meaning":"Một sự chuyển động liên tục trong đó một lượng, giá cả hoặc mức độ giảm rõ rệt trong một khoảng thời gian dài."},"10435":{"word":"càng sớm càng tốt","meaning":"Diễn tả việc hoàn thành một hành động hoặc nhiệm vụ mà không chờ đợi, thực hiện ngay khi có thể."},"10436":{"word":"hạ lưu","meaning":"Phần dưới của một con sông hoặc suối."},"10437":{"word":"huống hồ","meaning":"Dùng để giới thiệu một tình huống hoặc ý tưởng còn nổi bật hoặc rõ ràng hơn so với điều đã được đề cập trước đó."},"10438":{"word":"hạ thân","meaning":"Phần cơ thể của một người bao gồm hông, chân và bàn chân, nằm dưới thắt lưng."},"10439":{"word":"lời than phiền","meaning":"Diễn tả việc một người nói với người khác về nỗi bất hạnh sâu sắc hoặc sự đối xử không công bằng của mình, thường trong tâm trạng đau khổ."},"10440":{"word":"không ngừng","meaning":"Diễn tả một hành động diễn ra trong một thời gian rất dài mà không dừng lại, hoặc không có nhiều suy nghĩ hay mục đích."},"10441":{"word":"hạng thấp","meaning":"Vị trí hoặc thứ hạng thấp."},"10442":{"word":"người hầu","meaning":"Người có công việc là làm việc trong nhà người khác, làm các công việc vặt như dọn dẹp hoặc nấu ăn."},"10443":{"word":"dòng sông","meaning":"Dòng nước tự nhiên chảy liên tục qua đất liền, như một đường thủy nhỏ hẹp."},"10444":{"word":"giới học thuật","meaning":"Toàn bộ các trường đại học, cao đẳng, viện nghiên cứu cùng với các học giả và giáo viên làm việc trong đó."},"10445":{"word":"ngược đãi","meaning":"Hành động làm tổn thương ai đó hoặc cái gì đó về thể chất hoặc tinh thần, hoặc đối xử với họ một cách rất khắc nghiệt và vô nhân đạo."},"10446":{"word":"mang tính học thuật","meaning":"Diễn tả điều gì đó liên quan đến việc nghiên cứu cẩn thận, kiến thức sâu rộng hoặc công việc được thực hiện bởi các giáo sư và sinh viên trong các trường đại học."},"10447":{"word":"thảm sát","meaning":"Hành động giết hại nhiều người cùng một lúc một cách tàn bạo và bạo lực."},"10448":{"word":"học thuật","meaning":"Các hoạt động, bài viết và thảo luận liên quan đến việc học hỏi sâu rộng và kiến thức nâng cao, thường diễn ra trong các trường đại học."},"10449":{"word":"học thức","meaning":"Kiến thức thu được qua việc học tập."},"10450":{"word":"chỉ là","meaning":"Diễn tả điều gì đó không hơn gì những gì được nhắc đến, gợi ý rằng nó nhỏ bé, không quan trọng hoặc không đặc biệt."},"10451":{"word":"nhất quán, không thay đổi","meaning":"Luôn giữ nguyên trạng thái, chất lượng, thái độ hoặc hành vi mà không có sự thay đổi hay khác biệt."},"10452":{"word":"một cách nhất quán, không thay đổi","meaning":"Diễn tả việc thực hiện hành động luôn giữ nguyên, không có sự thay đổi về hành vi hay chất lượng."},"10453":{"word":"bánh kẹo truyền thống Hàn Quốc","meaning":"Là loại đồ ăn trang trí đẹp mắt và ngon miệng được làm ở Hàn Quốc, thường từ bột, mật ong hoặc gạo và có nhiều hình dạng khác nhau."},"10454":{"word":"hết sức, hết mức","meaning":"Diễn tả việc làm gì đó bằng tất cả nỗ lực, năng lượng hoặc nhiệt huyết có thể, đạt đến mức cao nhất."},"10455":{"word":"chỉ là, đơn thuần là","meaning":"Dùng để diễn tả một điều gì đó chỉ là như đã nói, thường ám chỉ sự tầm thường hoặc đáng thất vọng so với mong đợi."},"10456":{"word":"giới hạn","meaning":"Một ranh giới cụ thể đánh dấu số lượng hoặc mức độ lớn nhất có thể chấp nhận được của một điều gì đó."},"10457":{"word":"phần, suất","meaning":"Một phần lợi ích hoặc nhiệm vụ lớn được phân bổ cho một người."},"10458":{"word":"một trận, một hồi","meaning":"Một đợt hoạt động mạnh mẽ hoặc một giai đoạn ngắn, sôi nổi, ví dụ như nhiều người cùng cười lớn."},"10459":{"word":"một mực, kiên quyết","meaning":"Thực hiện một điều gì đó với ý chí mạnh mẽ đến mức không nhượng bộ hoặc thay đổi suy nghĩ."},"10460":{"word":"đáng thương hại, thảm hại","meaning":"Yếu kém, ngu ngốc hoặc thất bại đến mức khiến người khác cảm thấy thương hại hoặc thất vọng."},"10461":{"word":"giới hạn, hạn chế","meaning":"Thiết lập một ranh giới hoặc đặt ra một giới hạn về kích thước, số lượng hoặc mức độ của một điều gì đó."},"10462":{"word":"than thở, than vãn","meaning":"Sự bày tỏ bằng lời nói về nỗi buồn sâu sắc, sự hối tiếc hoặc thất vọng, thường liên quan đến số phận không may mắn hoặc một sự kiện buồn."},"10463":{"word":"mẻ lớn","meaning":"Một khoản tiền hoặc thành công lớn đạt được một cách bất ngờ, thường từ một phi vụ liều lĩnh duy nhất."},"10464":{"word":"đợt rét đậm","meaning":"Thời kỳ nhiệt độ thấp bất thường kéo dài và lan rộng trên một khu vực lớn."},"10465":{"word":"giới hạn","meaning":"Chỉ áp dụng hoặc có sẵn cho một nhóm, người hoặc danh mục cụ thể."},"10466":{"word":"cào","meaning":"Dùng móng tay hoặc móng vuốt sắc nhọn làm những vết mỏng hoặc vết cắt nông trên da hoặc bề mặt."},"10467":{"word":"tiếng hô","meaning":"Âm thanh lớn, mạnh mẽ do nhiều người cùng nói hoặc la hét, thường thể hiện cảm xúc mạnh mẽ."},"10468":{"word":"hàm ý","meaning":"Một ý nghĩa hoặc thông điệp ẩn giấu đằng sau một hành vi, văn bản, v.v., mà không được bộc lộ ra bên ngoài."},"10469":{"word":"người đi không về","meaning":"Người được cử đi làm việc hoặc nhiệm vụ nhưng sau đó không quay trở lại điểm xuất phát."},"10470":{"word":"phù hợp","meaning":"Phù hợp, thích hợp hoặc đúng đắn cho một tình huống hoặc mục đích cụ thể."},"10471":{"word":"liên hợp","meaning":"Trạng thái hai hoặc nhiều nhóm hoặc cá nhân cùng nhau thực hiện một việc gì đó."},"10472":{"word":"hợp lưu","meaning":"Trạng thái nhiều dòng nước hợp lại chảy vào một con sông, biển, v.v.; hoặc dòng nước như vậy."},"10473":{"word":"hợp pháp","meaning":"Điều gì đó được cho phép hoặc công nhận theo các quy tắc và quy định chính thức của một quốc gia hoặc hệ thống."},"10474":{"word":"tổng hợp","meaning":"Hành động kết hợp các bộ phận hoặc yếu tố khác nhau lại với nhau để tạo thành một vật phẩm hoặc chất mới, duy nhất."},"10475":{"word":"hậu môn","meaning":"Hậu môn là lỗ mở ở cuối đường tiêu hóa, nơi chất thải rắn ra khỏi cơ thể."},"10476":{"word":"thuốc kháng sinh","meaning":"Thuốc kháng sinh là loại thuốc được bác sĩ kê đơn để diệt vi khuẩn có hại và ngăn ngừa nhiễm trùng lây lan trong cơ thể."},"10477":{"word":"chum, vại","meaning":"Chum hay vại là đồ đựng hình tròn, thường làm bằng đất sét nung hoặc gốm sứ, dùng để chứa thức ăn, chất lỏng hoặc các vật dụng khác."},"10478":{"word":"chống ung thư","meaning":"Chống ung thư là loại hình chăm sóc y tế hoặc chất có tác dụng ngăn chặn sự phát triển và lây lan của các tế bào có hại trong cơ thể."},"10479":{"word":"giải độc, thải độc","meaning":"Giải độc là quá trình tự nhiên hoặc y tế loại bỏ các chất có hại, như chất độc hoặc chất thải, ra khỏi cơ thể sống."},"10480":{"word":"giải mã, giải đọc","meaning":"Giải mã là hành động tìm ra ý nghĩa của văn bản khó, biểu tượng phức tạp hoặc thông điệp mã hóa để có thể hiểu được."},"10481":{"word":"uyên bác, thông thái","meaning":"Uyên bác là có kiến thức rất rộng và sâu sắc về nhiều chủ đề khác nhau hoặc một lĩnh vực cụ thể."},"10482":{"word":"độ cao so với mặt nước biển","meaning":"Độ cao so với mặt nước biển là số đo cho biết một địa điểm hoặc vật thể cao bao nhiêu khi so sánh với chiều cao trung bình của mặt nước biển."},"10483":{"word":"phân tích, giải thích","meaning":"Phân tích là hành động xem xét cẩn thận thông tin, số liệu hoặc từ ngữ để tìm ra ý nghĩa hoặc hiểu chúng theo một cách nhất định."},"10484":{"word":"hủy bỏ hợp đồng, chấm dứt hợp đồng","meaning":"Hủy bỏ hợp đồng là hành động chính thức chấm dứt một thỏa thuận hoặc dịch vụ bằng văn bản trước ngày kết thúc dự kiến, thường bằng một văn bản đã ký."},"10485":{"word":"sóng thần","meaning":"Sóng thần là một đợt sóng biển khổng lồ và mạnh mẽ, thường do động đất dưới đáy biển gây ra, di chuyển trên biển và có thể gây thiệt hại lớn khi đổ bộ vào đất liền."},"10486":{"word":"gỡ bỏ, bãi bỏ","meaning":"Gỡ bỏ là hành động loại bỏ một hạn chế, quy tắc, cảnh báo hoặc nghĩa vụ hiện có, cho phép một điều gì đó trở nên tự do hoặc bình thường trở lại."},"10487":{"word":"sa thải","meaning":"Việc chấm dứt hợp đồng lao động của một người do người sử dụng lao động quyết định."},"10488":{"word":"giải thể","meaning":"Hành động chia tách hoặc phá vỡ một tổ chức, nhóm, hoặc cấu trúc để nó không còn hoạt động như một đơn vị thống nhất."},"10489":{"word":"hài hước","meaning":"Miêu tả cái gì đó vui vẻ, dí dỏm, làm cho người khác cười hoặc mỉm cười."},"10490":{"word":"hạt nhân hóa gia đình","meaning":"Quá trình các hộ gia đình ngày càng chỉ bao gồm cha mẹ và con cái, thay vì nhiều thế hệ cùng sống chung."},"10491":{"word":"cốt lõi","meaning":"Cái gì đó quan trọng nhất hoặc là phần cơ bản nhất của một sự vật, đóng vai trò là trọng tâm chính."},"10492":{"word":"gạo mới gặt","meaning":"Hạt gạo vừa mới được thu hoạch từ cánh đồng sau khi lúa đã trưởng thành."},"10493":{"word":"đoàn diễu hành","meaning":"Một nhóm người hoặc xe cộ di chuyển cùng nhau thành một hàng dài, đặc biệt là trong một sự kiện đặc biệt."},"10494":{"word":"tung tích","meaning":"Vị trí cụ thể mà một người hoặc một vật có thể được tìm thấy vào một thời điểm nhất định."},"10495":{"word":"cách hành xử","meaning":"Cách một người thể hiện mình hoặc đóng vai trò nhất định trong xã hội, đôi khi là làm ra vẻ."},"10496":{"word":"hành tung","meaning":"Chuỗi các địa điểm mà một người đã đi qua hoặc những hành động mà họ đã thực hiện, có thể được theo dõi hoặc khám phá."},"10497":{"word":"ngành hành pháp","meaning":"Bộ phận của chính phủ chịu trách nhiệm thực thi pháp luật và quản lý công việc hàng ngày của một quốc gia."},"10498":{"word":"cuộc diễu hành","meaning":"Một nhóm người đi bộ cùng nhau một cách có tổ chức, thường có âm nhạc hoặc biểu ngữ, để biểu thị công khai hoặc phản đối."},"10499":{"word":"vội vàng","meaning":"Thực hiện một hành động nào đó một cách rất nhanh chóng và không kịp suy nghĩ kỹ, thường là do thiếu thời gian."},"10500":{"word":"hư cấu","meaning":"Một câu chuyện hay sự kiện được tạo ra từ trí tưởng tượng, không có thật trong đời sống."},"10501":{"word":"cơn đói","meaning":"Cảm giác khó chịu trong cơ thể, thường là ở dạ dày, báo hiệu cần ăn."},"10502":{"word":"cuống quýt","meaning":"Di chuyển hoặc hành động một cách vội vã, lúng túng, rối loạn vì lo lắng hoặc bị áp lực."},"10503":{"word":"tồi tàn","meaning":"Ở trong tình trạng cũ kỹ, xuống cấp và đã bị hư hỏng nhiều."},"10504":{"word":"sự vô nghĩa","meaning":"Cảm giác rằng một điều gì đó hoàn toàn vô nghĩa, không có giá trị lâu dài, gây ra sự thất vọng sâu sắc."},"10505":{"word":"sự hư vô","meaning":"Một cảm giác sâu sắc rằng cuộc sống hoặc sự tồn tại thiếu đi mục đích, ý nghĩa hay giá trị, như thể mọi thứ đều không quan trọng."},"10506":{"word":"phá dỡ","meaning":"Cố ý phá hủy, làm sụp đổ một công trình xây dựng như tòa nhà, bức tường."},"10507":{"word":"sơ sài","meaning":"Khi một việc gì đó được quản lý, bảo quản không tốt, thiếu chặt chẽ, khiến nó trở nên xuống cấp, lộn xộn."},"10508":{"word":"hụt hẫng","meaning":"Trạng thái con người cảm thấy hoàn toàn trống rỗng, cạn kiệt mọi năng lượng và hy vọng, thường sau khi một nỗ lực lớn thất bại."},"10509":{"word":"phổi","meaning":"Hai cơ quan chính nằm trong lồng ngực, có chức năng đưa oxy vào và thải cacbon dioxit ra khỏi cơ thể khi hít thở."},"10510":{"word":"hiến pháp","meaning":"Tập hợp các luật và nguyên tắc cơ bản cao nhất của một quốc gia, dùng để thành lập chính phủ và bảo vệ quyền công dân."},"10511":{"word":"sự cống hiến","meaning":"Hành động dồn hết thời gian, công sức và tâm huyết cho một người, một mục đích hoặc một nhiệm vụ nào đó."},"10512":{"word":"tận tâm, cống hiến","meaning":"Diễn tả thái độ hoặc hành động dồn hết thời gian, công sức và tâm huyết cho một người hoặc một việc nào đó."},"10513":{"word":"giá rẻ mạt","meaning":"Mức giá rất thấp, rẻ hơn nhiều so với giá trị thực hoặc giá trị mong đợi của một món hàng."},"10514":{"word":"phá dỡ, dỡ bỏ","meaning":"Tháo gỡ, làm sập một công trình xây dựng như nhà cửa, hoặc các thứ chất chồng lên."},"10515":{"word":"nói xấu, bôi nhọ","meaning":"Nói những điều không hay, thường là sai sự thật, về người khác nhằm làm tổn hại danh tiếng của họ."},"10516":{"word":"hổn hển, thở dốc","meaning":"Diễn tả trạng thái thở nhanh và nặng nề, thường có vẻ khó nhọc, sau khi chạy hoặc vận động mạnh."},"10517":{"word":"gian nan, hiểm trở","meaning":"Miêu tả một con đường, một hành trình đầy chướng ngại vật, khó đi, hoặc một tình huống nhiều thử thách khắc nghiệt."},"10518":{"word":"hiểm ác, khắc nghiệt","meaning":"Miêu tả cảnh quan có địa hình dốc, hiểm trở, trông nguy hiểm, hoặc vẻ mặt của người nào đó trông nghiêm nghị, đáng sợ."},"10519":{"word":"vô ích, uổng công","meaning":"Diễn tả hành động hoặc nỗ lực không mang lại kết quả mong muốn hoặc thành công, khiến thời gian và công sức bỏ ra bị lãng phí."},"10520":{"word":"thoát khỏi, thoát ra","meaning":"Thành công trong việc rời bỏ hoặc giải thoát khỏi một tình huống khó khăn, một trạng thái hoặc một cảm xúc tiêu cực mạnh mẽ."},"10521":{"word":"lục lọi, bới tung","meaning":"Tìm kiếm một thứ gì đó bằng cách di chuyển các đồ vật một cách nhanh chóng và lộn xộn, thường gây ra sự bừa bộn."},"10522":{"word":"rẽ, vượt qua","meaning":"Tiến về phía trước bằng cách dùng sức tách ra hoặc tạo ra một con đường xuyên qua thứ gì đó dày đặc hoặc chắn lối, như cỏ cao, dòng nước hay đám đông."},"10523":{"word":"lãng phí, hoang phí","meaning":"Chỉ việc sử dụng tiền bạc hay tài nguyên một cách nhanh chóng và không cẩn thận, thường khiến chúng cạn kiệt sớm."},"10524":{"word":"tráng, súc, rửa sạch","meaning":"Cho nước sạch chảy qua một vật gì đó để rửa trôi xà phòng hoặc bụi bẩn còn sót lại."},"10525":{"word":"đổi mới, cách tân, sự đổi mới","meaning":"Một ý tưởng, phương pháp hoặc sản phẩm mới quan trọng làm thay đổi cách thức mọi việc được thực hiện hoặc nhìn nhận, thường mang lại kết quả tốt hơn."},"10526":{"word":"mang tính đổi mới, sáng tạo","meaning":"Mô tả một cái gì đó, như công nghệ hoặc ý tưởng, rất mới mẻ, sáng tạo và thay đổi những cách làm hiện có theo hướng tốt hơn."},"10527":{"word":"hiện, đương, đương nhiệm","meaning":"Chỉ một điều gì đó đang diễn ra hoặc tồn tại vào chính thời điểm hiện tại."},"10528":{"word":"chóng mặt, hoa mắt","meaning":"Cảm giác mà môi trường xung quanh dường như quay tròn hoặc lắc lư, khiến một người khó giữ thăng bằng và đôi khi gây cảm giác muốn ngất xỉu."},"10529":{"word":"người vợ hiền, mẹ đảm đang","meaning":"Một người phụ nữ khéo léo quản lý gia đình và nhà cửa, cẩn thận hướng dẫn con cái và hỗ trợ bạn đời theo cách được xã hội truyền thống ngưỡng mộ."},"10530":{"word":"vấn đề tồn đọng, vấn đề cấp bách","meaning":"Một vấn đề chưa được giải quyết hoặc đang cần được xử lý ngay."},"10531":{"word":"đáng kể, rõ rệt, nổi bật","meaning":"Mô tả một điều gì đó rất rõ ràng và dễ nhìn thấy hoặc nhận ra, nổi bật đáng kể so với những thứ khác."},"10532":{"word":"một cách đáng kể, rõ rệt","meaning":"Mô tả một hành động hoặc sự thay đổi rất dễ quan sát vì nó diễn ra ở mức độ lớn và đáng chú ý."},"10533":{"word":"chức vụ hiện tại, vị trí hiện tại","meaning":"Công việc hoặc vai trò hiện tại mà một người đang đảm nhiệm."},"10534":{"word":"huyết thống, quan hệ huyết thống","meaning":"Một mối quan hệ được hình thành dựa trên dòng máu, giữa những người có chung tổ tiên."},"10535":{"word":"ghê tởm, căm ghét","meaning":"Cảm giác rất ghét bỏ, khó chịu hoặc chán ghét mãnh liệt đối với cái gì đó."},"10536":{"word":"nghi ngờ, nghi vấn","meaning":"Cảm giác hoặc niềm tin rằng ai đó đã làm điều gì sai trái, đặc biệt là một tội ác, dựa trên dấu hiệu nhưng chưa có bằng chứng rõ ràng."},"10537":{"word":"tinh thần hợp tác","meaning":"Mong muốn chung của mọi người trong việc cùng nhau làm việc, giúp đỡ lẫn nhau để đạt được một mục tiêu chung."},"10538":{"word":"đe dọa, hăm dọa","meaning":"Lời nói hoặc hành động thể hiện ý định gây hại hoặc rắc rối cho ai đó nếu họ không tuân theo một yêu cầu."},"10539":{"word":"đàm phán, thương lượng","meaning":"Cuộc thảo luận chính thức giữa hai hoặc nhiều bên để tìm kiếm sự thỏa hiệp và đạt được sự hiểu biết chung."},"10540":{"word":"hiệp ước, thỏa thuận","meaning":"Một sự hiểu biết hoặc cam kết chính thức được tạo ra giữa hai hoặc nhiều nhóm, tổ chức hoặc quốc gia, thường được ghi lại bằng văn bản."},"10541":{"word":"thảo luận, bàn bạc","meaning":"Cùng nhau nói chuyện để thống nhất một vấn đề hay điều kiện nào đó."},"10542":{"word":"hiệp định, hiệp ước","meaning":"Văn bản chính thức được ký kết giữa hai hoặc nhiều bên, thể hiện sự thống nhất về các quy tắc hoặc hành động chung."},"10543":{"word":"hợp tác, cộng tác","meaning":"Hành động mọi người hoặc các nhóm cùng nhau làm việc và giúp đỡ lẫn nhau để đạt được mục tiêu chung."},"10544":{"word":"cảnh sát hình sự, thám tử","meaning":"Một sĩ quan cảnh sát thường mặc thường phục, chuyên điều tra, tìm kiếm manh mối và bắt giữ tội phạm."},"10545":{"word":"hình dạng, hình dáng","meaning":"Đường nét bên ngoài hoặc vẻ bề ngoài của một vật thể vật lý, thể hiện cấu trúc hoặc đường viền của nó."},"10546":{"word":"miêu tả, hình dung","meaning":"Dùng lời nói để diễn tả về hình dáng, âm thanh hoặc cảm giác của một vật hay tình huống nào đó."},"10547":{"word":"gay gắt","meaning":"Có tính chất nghiêm trọng, khó khăn, gây đau đớn hoặc tác động mạnh."},"10548":{"word":"sự cường điệu","meaning":"Thái độ hoặc hành động tỏ ra quá phấn khích, cường điệu về một việc không thực sự quan trọng."},"10549":{"word":"lời kêu gọi","meaning":"Một yêu cầu mạnh mẽ và đầy cảm xúc, gửi đến nhiều người để xin giúp đỡ, thông cảm hoặc hành động."},"10550":{"word":"sự hưởng ứng","meaning":"Sự thể hiện sự đồng tình, ủng hộ hoặc nhiệt tình thông qua hành động đáp lại tích cực."},"10551":{"word":"thiện chí","meaning":"Tình cảm hoặc thái độ thân thiện, sẵn lòng giúp đỡ mà một người dành cho người khác."},"10552":{"word":"có thiện chí","meaning":"Có thái độ tán thành, ý kiến tích cực hoặc tạo ra những điều kiện thuận lợi, phù hợp."},"10553":{"word":"sự cải thiện","meaning":"Tình hình hoặc trạng thái thay đổi theo chiều hướng tốt đẹp hơn."},"10554":{"word":"yên tĩnh vắng vẻ","meaning":"Chỉ một nơi hoặc không gian vắng lặng, yên bình và riêng tư, ít người qua lại hoặc không có tiếng ồn."},"10555":{"word":"tình trạng tốt","meaning":"Một tình hình hoặc trạng thái thuận lợi, tốt đẹp."},"10556":{"word":"đánh giá tích cực","meaning":"Lời nhận xét hoặc đánh giá công khai thể hiện sự tán thành và ngưỡng mộ sâu sắc đối với một điều gì đó."},"10557":{"word":"thời kỳ thịnh vượng","meaning":"Giai đoạn kinh tế phát triển mạnh mẽ, doanh nghiệp làm ăn phát đạt, nhiều việc làm và thị trường sôi động."},"10558":{"word":"phòng khi","meaning":"Dùng để diễn tả việc làm hoặc suy nghĩ chuẩn bị cho một sự kiện hoặc tình huống có thể xảy ra trong tương lai."},"10559":{"word":"phê bình gay gắt","meaning":"Sự đánh giá một người hoặc một tác phẩm một cách rất nghiêm khắc và tiêu cực."},"10560":{"word":"sự nhầm lẫn","meaning":"Tình trạng không thể hiểu rõ ràng hoặc phân biệt giữa những điều khác nhau."},"10561":{"word":"sự pha trộn","meaning":"Một chất hoặc nhóm vật phẩm được tạo ra bằng cách kết hợp hai hay nhiều thứ khác nhau."},"10562":{"word":"nhẹ nhõm","meaning":"Cảm thấy vui vẻ như thể một gánh nặng hay lo lắng lớn đã được loại bỏ khỏi tâm trí."},"10563":{"word":"cú home run","meaning":"Trong bóng chày, cú đánh bóng đi xa cho phép người đánh chạy hết các gôn và ghi điểm mà không bị dừng lại."},"10564":{"word":"tai họa","meaning":"Sự kiện không may hoặc thảm họa gây ra thiệt hại hoặc rủi ro lớn."},"10565":{"word":"đề tài chính","meaning":"Điều chính mà mọi người đang thảo luận, suy nghĩ hoặc tập trung sự chú ý vào."},"10566":{"word":"sự hòa thuận","meaning":"Tình trạng yên bình mà mọi người, đặc biệt trong gia đình, sống hòa hợp và không có bất đồng."},"10567":{"word":"hàng hóa","meaning":"Các mặt hàng lớn hoặc vật phẩm được vận chuyển bằng phương tiện như tàu, máy bay hoặc xe tải."},"10568":{"word":"mũi tên","meaning":"Một cây gậy mỏng, thẳng với đầu nhọn ở một đầu và lông vũ ở đầu kia, được thiết kế để bắn từ cung."},"10569":{"word":"người nói","meaning":"Người truyền đạt suy nghĩ hoặc thông tin bằng cách tạo ra âm thanh bằng giọng nói của mình."},"10570":{"word":"kiên định","meaning":"Có một niềm tin hoặc quyết định mạnh mẽ và không thay đổi, không dễ bị người khác lay chuyển."},"10571":{"word":"sự thiết lập","meaning":"Việc tạo ra hoặc bắt đầu một hệ thống, quy tắc hay tổ chức nào đó một cách vững chắc và bền vững."},"10572":{"word":"rõ ràng","meaning":"Một cách dễ dàng để nhận thấy, nghe thấy hoặc hiểu được, không còn nghi ngờ gì nữa."},"10573":{"word":"sự mở rộng","meaning":"Quá trình làm cho một cái gì đó lớn hơn về kích thước, số lượng hoặc phạm vi, thường bằng cách thêm các bộ phận hoặc nguồn lực."},"10574":{"word":"sự hoàn trả","meaning":"Hành động trả lại hoặc trao tặng một cái gì đó cho nơi hoặc nhóm mà nó đã xuất phát hoặc nơi nó nên được trao."},"10575":{"word":"hoan hô","meaning":"Mọi người tạo ra âm thanh lớn bằng giọng nói, thường giơ tay lên, để bày tỏ sự tán thành mạnh mẽ, niềm vui hoặc sự phấn khích."},"10576":{"word":"sức sống","meaning":"Cảm giác mạnh mẽ tràn đầy năng lượng về thể chất và tinh thần, cho phép một người hoặc một vật hoạt động rất tích cực."},"10577":{"word":"nguồn sinh lực","meaning":"Một cái gì đó mang lại cho một người hoặc một tình huống năng lượng thể chất hoặc tinh thần mạnh mẽ và làm cho nó hoạt động và thú vị hơn."},"10578":{"word":"chữ in","meaning":"Những khối nhỏ, cứng, thường làm bằng kim loại, có hình ảnh chữ cái hoặc ký hiệu nổi lên trên một bề mặt, dùng để in mực lên giấy."},"10579":{"word":"thời kỳ vàng son","meaning":"Giai đoạn tốt đẹp nhất trong cuộc đời một người, khi người đó đạt đến đỉnh cao nhất của mình."},"10580":{"word":"vội vàng","meaning":"Làm điều gì đó rất đột ngột và nhanh chóng, thường là không suy nghĩ kỹ, vì một tình huống khẩn cấp hoặc sự sợ hãi."},"10581":{"word":"hoang vắng","meaning":"Một nơi trông rất trống trải và cô đơn, có ít hoặc không có cây cối, người hoặc dấu hiệu của sự sống, thường khiến người ta cảm thấy buồn bã."},"10582":{"word":"hoàng đế","meaning":"Một nhà lãnh đạo nam giới cai trị một lãnh thổ rất lớn với nhiều vùng và dân tộc khác nhau, thường có vị trí cao nhất trong một quốc gia."},"10583":{"word":"hoàng hôn","meaning":"Thời điểm mặt trời lặn, trời bắt đầu tối dần nhưng vẫn còn ánh sáng."},"10584":{"word":"họp báo","meaning":"Buổi gặp mặt chính thức để một người trả lời câu hỏi từ nhiều phóng viên về một chủ đề cụ thể."},"10585":{"word":"kế toán","meaning":"Công việc ghi chép, kiểm tra cẩn thận tiền bạc mà một doanh nghiệp hay cá nhân chi tiêu và nhận được."},"10586":{"word":"đà phục hồi","meaning":"Một xu hướng đáng chú ý khi một điều gì đó yếu kém bắt đầu trở nên tốt hơn hoặc mạnh hơn theo thời gian."},"10587":{"word":"thu hồi","meaning":"Hành động tìm và mang về thứ gì đó đã bị thất lạc, cho mượn hoặc phân phát trước đó."},"10588":{"word":"hoài nghi","meaning":"Diễn tả một người thường tỏ ra nghi ngờ hoặc không dễ tin vào điều gì đó, cần thêm bằng chứng để thuyết phục."},"10589":{"word":"né tránh","meaning":"Hành động tránh xa một người, tình huống hoặc nghĩa vụ mà mình không muốn đối mặt hay giải quyết."},"10590":{"word":"đột phá","meaning":"Diễn tả một sự kiện hoặc khám phá mới rất quan trọng, gây ra thay đổi lớn và khởi đầu một thời kỳ khác."},"10591":{"word":"đạt được","meaning":"Hành động lấy được hoặc giành quyền sở hữu một thứ gì đó, thường là vật có giá trị hoặc giải thưởng."},"10592":{"word":"nói lảm nhảm","meaning":"Lời nói hoặc bài viết lộn xộn, khó hiểu và thiếu ý nghĩa rõ ràng."},"10593":{"word":"hiệu lực","meaning":"Tình trạng có khả năng mang lại kết quả tốt hoặc có giá trị, tác dụng."},"10594":{"word":"tính hữu ích","meaning":"Phẩm chất của một thứ khiến nó tốt cho một mục đích hoặc nhiệm vụ cụ thể, mang lại lợi ích nào đó."},"10595":{"word":"khứu giác","meaning":"Khả năng của con người hoặc động vật nhận biết và phân biệt mùi bằng mũi."},"10596":{"word":"thế hệ mai sau","meaning":"Toàn bộ những người sẽ được sinh ra và sống trong khoảng thời gian sau hiện tại."},"10597":{"word":"nhẹ nhõm","meaning":"Cảm thấy nhẹ nhàng và bình tĩnh sau khi một tình huống khó khăn hay gánh nặng lo âu đã kết thúc."},"10598":{"word":"nửa sau","meaning":"Phần thứ hai hoặc phần cuối cùng của một khoảng thời gian, sự kiện hoặc đối tượng cụ thể."},"10599":{"word":"ứng cử viên","meaning":"Người tìm kiếm hoặc được đề xuất cho một vị trí chính thức, giải thưởng hoặc vai trò đặc biệt."},"10600":{"word":"tiếp theo","meaning":"Một hành động hoặc sự kiện xảy ra tiếp theo trong một chuỗi, thường là kết quả hoặc sự tiếp tục của điều đã xảy ra trước đó."},"10601":{"word":"nhà tài trợ","meaning":"Một người hoặc tổ chức cung cấp tiền hoặc giúp đỡ cho một cá nhân, một dự án hoặc một sự kiện."},"10602":{"word":"di chứng","meaning":"Một vấn đề hoặc tình trạng kéo dài xuất hiện sau này, là hậu quả trực tiếp của một bệnh tật, chấn thương hoặc sự kiện trước đó."},"10603":{"word":"người kế nhiệm","meaning":"Người đảm nhận một công việc, vị trí hoặc vai trò từ một người khác đã từng nắm giữ nó trước đây."},"10604":{"word":"lùi (xe)","meaning":"Hành động di chuyển xe hoặc phương tiện về phía sau."},"10605":{"word":"rút lui","meaning":"Hành động di chuyển lùi lại hoặc rút khỏi một vị trí, thường là do nguy hiểm hoặc tình huống khó khăn."},"10606":{"word":"lướt qua","meaning":"Đọc hoặc nhìn nhanh qua một cái gì đó mà không xem xét chi tiết."},"10607":{"word":"đọc lướt","meaning":"Đọc một tài liệu hoặc sách thật nhanh để tìm ý chính mà không đọc từng chữ."},"10608":{"word":"nhìn trộm","meaning":"Nhìn nhanh chóng và bí mật vào cái gì đó hoặc ai đó, thường là để tránh bị phát hiện."},"10609":{"word":"sáng sủa","meaning":"Một nơi hoặc vật thể có nhiều ánh sáng, khiến mọi thứ trở nên dễ nhìn thấy."},"10610":{"word":"cong","meaning":"Từ trạng thái thẳng trở thành cong hoặc làm cho nó cong đi."},"10611":{"word":"vung","meaning":"Di chuyển một vật dài, như vũ khí hoặc công cụ, nhanh chóng trong không khí bằng tay."},"10612":{"word":"bị cuốn vào","meaning":"Bị lôi kéo vào một tình huống khó khăn hoặc phức tạp, như một cuộc chiến hay tranh cãi, một cách không tự nguyện."},"10613":{"word":"khuấy","meaning":"Di chuyển thìa hoặc que trong chất lỏng hoặc hỗn hợp mềm để trộn hoặc làm nó di chuyển."},"10614":{"word":"bị bao trùm","meaning":"Bị che phủ hoặc bao quanh hoàn toàn bởi một lượng lớn cái gì đó, như lửa, khói hoặc nước."},"10615":{"word":"càn quét","meaning":"Di chuyển mạnh mẽ và nhanh chóng qua một khu vực rộng lớn, thường phá hủy hoặc thay đổi mọi thứ trên đường đi."},"10616":{"word":"bị cuốn đi","meaning":"Bị nước, lửa, gió, v.v. hoàn toàn cuốn trôi và đẩy đi."},"10617":{"word":"di động","meaning":"Mô tả một vật nhỏ và nhẹ, đủ để một người có thể dễ dàng mang đi từ nơi này đến nơi khác."},"10618":{"word":"ngày nghỉ","meaning":"Trạng thái không thực hiện nhiệm vụ và nghỉ ngơi trong một ngày hoặc một khoảng thời gian."},"10619":{"word":"ngừng bắn","meaning":"Một thỏa thuận tạm thời giữa các bên tham chiến nhằm ngừng giao tranh."},"10620":{"word":"nghỉ phép tạm thời","meaning":"Tình trạng tạm thời nghỉ làm một thời gian nhất định để giải quyết việc riêng hoặc nghỉ ngơi."},"10621":{"word":"xui xẻo, không may mắn","meaning":"Dễ gặp điều không may hoặc điềm xấu."},"10622":{"word":"nức nở","meaning":"Khóc thành tiếng to, từng chập, thường kèm theo tiếng nấc và vai rung lên."},"10623":{"word":"lãi, lợi nhuận","meaning":"Tình trạng thu nhập của một doanh nghiệp hoặc tổ chức nhiều hơn chi phí bỏ ra."},"10624":{"word":"liếc xéo, lườm","meaning":"Nhìn ai đó bằng ánh mắt giận dữ, khó chịu mà không quay mặt hẳn."},"10625":{"word":"chảy vào, đổ vào","meaning":"Dòng nước hoặc chất lỏng di chuyển vào một nơi nào đó."},"10626":{"word":"y hệt, giống như","meaning":"Diễn tả hai vật thể hoặc sự vật có vẻ ngoài cực kỳ giống nhau."},"10627":{"word":"phung phí, hoang phí","meaning":"Tiêu tiền bạc hoặc tài nguyên một cách bừa bãi, không suy nghĩ đến tương lai."},"10628":{"word":"hiếm, quý hiếm","meaning":"Rất ít khi được tìm thấy hoặc nhìn thấy, khiến nó trở nên đặc biệt hoặc bất thường."},"10629":{"word":"mờ nhạt, lờ mờ","meaning":"Trông không rõ ràng hoặc khó nhìn thấy vì thiếu ánh sáng."},"10630":{"word":"thưa thớt, mỏng manh","meaning":"Có số lượng rất ít, rải rác hoặc khả năng xảy ra rất thấp."},"10631":{"word":"kỳ lạ","meaning":"Rất khác thường, hiếm gặp, khiến người khác cảm thấy ngạc nhiên."},"10632":{"word":"liếc nhìn","meaning":"Liên tục quay nhanh mắt nhìn sang một phía trong chốc lát rồi lại nhìn đi chỗ khác."},"10633":{"word":"thoáng nhìn","meaning":"Diễn tả việc nhìn thấy cái gì đó rất nhanh và chỉ trong một khoảnh khắc."},"10634":{"word":"vất vả","meaning":"Rất vất vả, khó nhọc, tiêu tốn nhiều sức lực và tinh thần."},"10635":{"word":"nhờ có","meaning":"Đạt được thành quả hoặc tiếp tục công việc nhờ vào sự giúp đỡ, ủng hộ từ người khác."}};

window.TOPIK_LANG_VI = TOPIK_LANG_VI;
